/* ============================================================
   Procedure: [dbo].[usp_mob_GetNotifitionListByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_mob_GetNotifitionListByUserId(
	@UserId bigint = 38940,
	@OffsetValue int  = 0,  
	@PageSize int  = 100  
)
as
begin
	--declare 
	--	@UserId bigint = 38940,
	--	@OffsetValue int  = 0,  
	--	@PageSize int  = 100  

	select 
		ROW_NUMBER() over( order by id desc ) as sno,
		count(*) over() as totalRecord,
		id, createdon, content
	from notificationhistory with(nolock) where n_userid = @UserId
	order by 1 
	offset @OffsetValue rows fetch next @PageSize rows only

end



GO

/* ============================================================
   Procedure: [dbo].[usp_mob_GetPredefinedSearchNameList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_mob_GetPredefinedSearchNameList](
	@EntityName nvarchar(50)
)
as
begin
	--declare  @EntityName nvarchar(50) = 'Lead'

	if(isnull(@EntityName, '') = '')
	begin
		set @EntityName = 'Lead'
	end

	select ID, CriteriaName, CriteriaType from tbl_SearchCriteria(nolock) 
		where IsActive = 1 and CriteriaType = @EntityName  and ParentID = 0
end



