SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_mob_GetSearchPageFieldsList](
	@UserId bigint,
	@PageName nvarchar(200)
)
as
begin
	if(isnull(@PageName, '') != '')
	begin

	select ID, DisplayName, FieldName [Text], DataType Code from tbl_SearchPageFields(nolock) 
		where IsActive = 1 and PageName = @PageName
		end

end



