CREATE   PROCEDURE [dbo].[usp_mob_GetTaskAppointmentById](  
 @TaskId bigint = 0,  
 @UserId bigint,  
 @rectype varchar(20)= 'virtualapt'  
)  
as 
begin  

 --declare 
	--@TaskId bigint=10481,
	--@UserId bigint=34594,
	--@rectype varchar(20)='physicalapt'  
   
 declare @LeadId bigint, @CreatedBy bigint, @AssignedTo bigint, @TaskTypeId bigint, @OutocmeId bigint, @IsTask bit = 1, @ParentId bigint;  
 select @LeadId = LeadId, @CreatedBy = CreatedBy, @AssignedTo = AssignedTo, @OutocmeId = OutcomesId, @IsTask = IsTask  
  from tbl_tsk_TaskHistory(nolock) t where id = @TaskId  
  
 select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId  
  
if(@rectype = 'virtualapt' or @rectype = '')  
Begin

 select @LeadId = LeadId, @CreatedBy = CreatedBy, @AssignedTo = AssignedTo, @OutocmeId = OutcomesId, @IsTask = IsTask  
  from tbl_tsk_TaskHistory(nolock) t where id = @TaskId  
  

 -- Task Detail  
 select t.Id, 
 0 as [GeoEntitySiteId],
 t.Title, t.Description, t.Remarks, t.StartDate, t.EndDate, t.CreatedOn, t.IsTask, t.IsAppointment, t.Address, t.Latitude, t.Longitude, t.CompleteAddress, t.Status,  
   o.User_Id as OwnerId,  
   o.FName as OwnerFirstName,  
   o.LName as OwnerLastName,  
   o.User_Login as OwnerUserLogin,  
   o.Image as OwnerImage,  
   c.User_Id as CreatorId,  
   c.FName as CreatorFirstName,  
   c.LName as CreatorLastName,  
