   isnull(tap.has_remove, 0) as IsRemoval,  
   isnull(tap.has_edit,0) IsEdit,  
   isnull(tap.has_view,0) IsView,  
   isnull(tap.has_completion,0) IsCompletion,  
   isnull(tap.has_comment,0) IsComment,
   tap.AuthTypeCheckIn,
   tap.AuthTypeCheckOut,
