   tap.CheckIn_SendSMS,
   tap.CheckIn_SendWhatsApp,
   tap.CheckOut_SendMail,
   tap.CheckOut_SendSMS,
   tap.CheckOut_SendWhatsApp,
         tap.SurveyJsCheckInFormId,
   tap.SurveyJsCheckOutFormId,
-- inside your SELECT list (replace earlier CASEs for CheckIn/CheckOut)
-- CheckIn: choose explicit form id or survey-js form id; fetch name and url from WebFormTbl
CASE 
    WHEN tap.CheckInFormId IS NOT NULL THEN tap.CheckInFormId
   WHEN tap.SurveyJsCheckInFormId IS NOT NULL THEN tap.SurveyJsCheckInFormId
    ELSE NULL
END AS CheckInFormId,
CASE 
    WHEN tap.CheckInFormId IS NOT NULL THEN wfrm.FormName
    WHEN tap.SurveyJsCheckInFormId IS NOT NULL THEN wfrm.FormName
    ELSE NULL
END AS CheckInFormName,
CASE
    WHEN tap.CheckInFormId IS NOT NULL THEN wfrm.url_script
    WHEN tap.SurveyJsCheckInFormId IS NOT NULL THEN wfrm.url_script
    ELSE NULL
END AS CheckInFormUrl,

-- CheckOut: choose explicit form id or survey-js form id; fetch name and url from WebFormTbl
CASE 
    WHEN tap.CheckOutFormId IS NOT NULL THEN tap.CheckOutFormId
    WHEN tap.SurveyJsCheckOutFormId IS NOT NULL THEN tap.SurveyJsCheckOutFormId
    ELSE NULL
END AS CheckOutFormId,
CASE 
    WHEN tap.CheckOutFormId IS NOT NULL THEN wfrmout.FormName
    WHEN tap.SurveyJsCheckOutFormId IS NOT NULL THEN wfrmout.FormName
    ELSE NULL
END AS CheckOutFormName,
CASE
    WHEN tap.CheckOutFormId IS NOT NULL THEN wfrmout.url_script
    WHEN tap.SurveyJsCheckOutFormId IS NOT NULL THEN wfrmout.url_script
    ELSE NULL
END AS CheckOutFormUrl,


   @ParentId as ParentId  
  from tbl_tsk_TaskHistory(nolock) t   
   left join User_Detail(nolock) o on t.AssignedTo = o.User_ID  
   left join User_Detail(nolock) c on t.CreatedBy = c.User_ID  
   left join UserLeads(nolock) l on t.LeadId = l.ID  
   left join tbl_tsk_UserTaskMaster(nolock) tm on t.TaskId = tm.Id  
   left join tbl_tsk_UserOutcomeMaster(nolock) om on t.OutcomesId = om.Id  
   left join tbl_tsk_TaskActionPermission(nolock) tap on t.TaskId = tap.task_type_id  
   LEFT JOIN WebFormTbl (NOLOCK) wfrm
        ON tap.CheckInFormId = wfrm.FormId
			 LEFT JOIN WebFormTbl (NOLOCK) wfrmout
        ON tap.CheckOutFormId = wfrmout.FormId
  where t.id = @TaskId   
  
 -- Outcome Liest  
 exec usp_mk_OutcomeListByTaskId @TaskId, @UserId  
  
 -- Task Type List  
 if(@IsTask = 1)  
 begin  
  select * from tbl_tsk_UserTaskMaster(nolock) where id <> 8 and ParentId in (0, @ParentId)  
 end  
 else  
 begin  
  select * from tbl_tsk_UserTaskMaster(nolock) where id = 8  
 end  
  
 -- Attachment List  
 select a.Id, a.FileName, a.Remarks, a.CreatedOn, ud.User_ID, ud.FName, ud.LName, ud.User_Login, ud.Image from tbl_tsk_AttachmentDetails(nolock) a   
  inner join User_Detail(nolock) ud on a.CreatedBy = ud.User_ID  
  where TaskId = iif(@TaskId = 0,  -1, @TaskId)  
  
  
