    WHEN tap.SurveyJsCheckOutFormId IS NOT NULL THEN wfrmout.url_script
    ELSE NULL
END AS CheckOutFormUrl,



   @ParentId as ParentId  

  from TBL_ET_PhysicalAppointment (nolock) phap  
	left join TBL_ET_GeoEntitySiteMaster gesm (nolock) on phap.GeoEntitySiteId = gesm.GeoEntitySiteId  
