	phap.PhysicalAppointmentId Id, phap.GeoEntitySiteId, phap.Title, phap.Description, phap.Remarks, phap.StartDate, phap.EndDate, phap.CreatedDate CreatedOn, 0 IsTask, 1 IsAppointment, phap.Address, gesm.Latitude, gesm.Longitude, phap.CompleteAddress, phap.Status,  
   o.User_Id as OwnerId,  
   o.FName as OwnerFirstName,  
   o.LName as OwnerLastName,  
   o.User_Login as OwnerUserLogin,  
   o.Image as OwnerImage,  
   c.User_Id as CreatorId,  
   c.FName as CreatorFirstName,  
   c.LName as CreatorLastName,  
   c.User_Login as CreatorUserLogin,  
   c.Image as CreatorImage,  
