   tap.SurveyJsCheckOutFormId,
-- inside your SELECT list (replace earlier CASEs for CheckIn/CheckOut)
-- CheckIn: choose explicit form id or survey-js form id; fetch name and url from WebFormTbl
CASE 
    WHEN tap.CheckInFormId IS NOT NULL THEN tap.CheckInFormId
   WHEN tap.SurveyJsCheckInFormId IS NOT NULL THEN tap.SurveyJsCheckInFormId
    ELSE NULL
END AS CheckInFormId,
CASE 
    WHEN tap.CheckInFormId IS NOT NULL THEN wfrm.FormName
    WHEN tap.SurveyJsCheckInFormId IS NOT NULL THEN wfrm.FormName
    ELSE NULL
END AS CheckInFormName,
CASE
    WHEN tap.CheckInFormId IS NOT NULL THEN wfrm.url_script
    WHEN tap.SurveyJsCheckInFormId IS NOT NULL THEN wfrm.url_script
    ELSE NULL
END AS CheckInFormUrl,

-- CheckOut: choose explicit form id or survey-js form id; fetch name and url from WebFormTbl
CASE 
    WHEN tap.CheckOutFormId IS NOT NULL THEN tap.CheckOutFormId
    WHEN tap.SurveyJsCheckOutFormId IS NOT NULL THEN tap.SurveyJsCheckOutFormId
    ELSE NULL
END AS CheckOutFormId,
CASE 
    WHEN tap.CheckOutFormId IS NOT NULL THEN wfrmout.FormName
    WHEN tap.SurveyJsCheckOutFormId IS NOT NULL THEN wfrmout.FormName
    ELSE NULL
END AS CheckOutFormName,
CASE
    WHEN tap.CheckOutFormId IS NOT NULL THEN wfrmout.url_script
    WHEN tap.SurveyJsCheckOutFormId IS NOT NULL THEN wfrmout.url_script
    ELSE NULL
END AS CheckOutFormUrl,



   @ParentId as ParentId  

  from TBL_ET_PhysicalAppointment (nolock) phap  
	left join TBL_ET_GeoEntitySiteMaster gesm (nolock) on phap.GeoEntitySiteId = gesm.GeoEntitySiteId  
