/* ============================================================
   Procedure: [dbo].[usp_mob_GetTaskListByLeadId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_mob_GetTaskListByLeadId (
	@UserId bigint,
	@LeadId bigint,
	@Mode char(1)
)
as
begin

	--select * from tbl_tsk_TaskHistory(nolock) where CreatedBy = 32222 and IsTask  = 1
	--declare @UserId bigint = 32222, @LeadId bigint = 674893, @Mode char(1) = 'A'
	

	select tsk.id, tsk.Title, tsk.StartDate, tsk.EndDate, 
			tsk.LeadId, ul.PersonName, 
			ul.ProfileImgFileName as PersonImage, 
			o.OutcomeName as Outcome,
			o.Indent as Intent,
			tsk.AgentId, ud.Image as AgentImage,
			trim(concat(trim(cast(ud.FName as nvarchar)), ' ', trim(cast(ud.LName as nvarchar)))) as AgentName, 
			(case 
				when LOWER(tsk.Status) = 'completed' then 'Completed' else ( case 
					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) > CAST(GETDATE() as date) then 'Scheduled' 
					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) < CAST(GETDATE() as date) then 'Over Due' 
					else 'Due Today' end
				) end
			) as TaskStatus,
			ud.ParentID as ParentId,
			IsEditable,
			IsRemoval

		from ( 
			select th.id, th.Title, th.StartDate, th.EndDate, th.Status, th.CreatedBy as AgentId, th.LeadId, th.OutcomesId, th.IsTask, 
					iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
				from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and th.CreatedBy = @UserId and th.LeadId  = @LeadId
		union 
			select th.id, Title, StartDate, EndDate, th.Status, th.AssignedTo as AgentId, th.LeadId, th.OutcomesId, th.IsTask,
					iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
				from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and th.AssignedTo = @UserId  and th.LeadId  = @LeadId
		union 
			select th.id, Title, StartDate, EndDate, th.Status, tcm.User_ID as AgentId, th.LeadId , th.OutcomesId, th.IsTask,
					iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
				from tbl_tsk_TaskHistory(nolock) th inner join tbl_tsk_CollaborationUserMapping(NOLOCK)
				tcm on th.Id = tcm.TaskHistoryId where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and tcm.User_Id = @UserId and th.CreatedBy = @UserId  and th.LeadId  = @LeadId
	) tsk inner join UserLeads(nolock) ul on tsk.LeadId = ul.ID 
		inner join User_Detail(nolock) ud on tsk.AgentId = ud.User_ID
		left join tbl_tsk_UserOutcomeMaster(nolock) o on tsk.OutcomesId  = o.Id

		order by id asc

end



GO

