	@FilterText nvarchar(max)= '',
	@SearchText nvarchar(max)= '',
	@Mode char(1)='A',
	@OffsetValue int =0,
	@PagingSize int = 100
)
as
begin

--Declare	@UserId bigint = 34594 ,
--	@FullText Varchar(100)= '',
