--	@OffsetValue int =0,
--	@PagingSize int = 100


Declare	@LeadId bigint = 0
if(@FullText != '')
Begin
set @FullText = ' and tsk.Title like ''%'+ @FullText +'%'''
 set @FilterText = '';
 set @SearchText = '';
End
if(@FilterText != '')
Begin
 set @FilterText = ' and ' + @FilterText 
 set @FullText = '';
 set @SearchText = '';
End
if(@SearchText != '')
Begin
 set @SearchText = ' and TaskStatusText like ''%' + @SearchText + '%'''
 set @FullText = '';
 set @FilterText = '';
End
Declare @TypeName varchar(15)= ''
if(@Mode='A')
Begin
 set @TypeName = 'Appointments'
End
else
Begin
 set @TypeName = 'Tasks'
End
	--select * from tbl_tsk_TaskHistory(nolock) where CreatedBy = 32222 and IsTask = 1
	--declare @UserId bigint = 32222, @LeadId bigint = 674893, @Mode char(1) = 'A'
Declare @query1 nvarchar(max)
Declare @query2 nvarchar(max)
Declare @query3 nvarchar(max) 

set @query1 = 'select count(id) over() as TotalRow, * from (select * from (select rectype= ''virtualapt'', tsk.id, tsk.Title, tsk.StartDate, tsk.EndDate, tsk.LeadId, ul.PersonName, (ul.ProfileImgFileName) as PersonImage, o.OutcomeName as Outcome, o.Indent as Intent, ul.LeadNo, ud.Image as AgentImage, trim(concat(trim(cast(ud.FName as nvarchar)), '' '', trim(cast(ud.LName as nvarchar)))) as AgentName, 
			(case 
				when LOWER(tsk.Status) = ''completed'' then ''Completed'' else ( case 
					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) > CAST(GETDATE() as date) then ''Scheduled'' 
					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) < CAST(GETDATE() as date) then ''Over Due'' 
					else ''Due Today'' end
				) end
			) as TaskStatus, (case when ((LOWER(tsk.Status) = ''completed'') and (cast(ud.User_ID as varchar) = '+cast(@UserId as nvarchar)+')) then ''My completed ' + @TypeName +'''
			when ((LOWER(tsk.Status) = ''completed'') and (cast(ud.User_ID as varchar) != '+cast(@UserId as nvarchar)+')) then ''Completed''
				else (dbo.fn_TaskAppointmentStatus(tsk.StartDate,tsk.EndDate,tsk.IsTask,ud.User_ID,' + cast(@UserId as nvarchar) + ',o.OutcomeName,''' + cast(@Mode as nvarchar) + ''')) end 
			) as TaskStatusText, ' 

set @query2 = ' ud.ParentID as ParentId, concat(ul.MobileNo, iif(ul.MobileNo1 <> '''', concat('', '', ul.MobileNo1), ''''), iif(ul.MobileNo2 <> '''', concat('', '', ul.MobileNo2), '''')) as CsvMobileNo,concat(ul.EmailId, iif(ul.EmailId1 <> '''', concat('', '', ul.EmailId1), ''''), iif(ul.EmailId2 <> '''', concat('', '', ul.EmailId2), '''')) as CsvEmailId, IsEditable, IsRemoval, IsTask
		from (select th.id, th.Title, th.StartDate, th.EndDate, th.Status, th.CreatedBy as AgentId, th.LeadId, th.OutcomesId, th.IsTask, 
				 iif( '+ cast(@UserId as nvarchar) +' in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
				from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = (case when ''' + cast(@Mode as nvarchar) + ''' = ''T'' and th.IsTask = 1 then 1 when ''' + cast(@Mode as nvarchar) + ''' = ''A'' and th.IsAppointment = 1 then 1 when ''' + cast(@Mode as nvarchar) + ''' = ''C'' and th.TaskId = 4 then 1 else 0 end) 
				and th.CreatedBy = ''' + cast(@UserId as nvarchar) + ''' and th.LeadId = (Case when ' + cast(@LeadId as nvarchar) + ' = 0 then th.LeadId else ' + cast(@LeadId as nvarchar) + ' end)
		union 
			select th.id, Title, StartDate, EndDate, th.Status, th.AssignedTo as AgentId, th.LeadId, th.OutcomesId, th.IsTask,
					iif(' + cast(@UserId as nvarchar) + ' in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
				from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = ( case when ''' + cast(@Mode as nvarchar) + ''' = ''T'' and th.IsTask = 1 then 1 when ''' + cast(@Mode as nvarchar) + ''' = ''A'' and th.IsAppointment = 1 then 1 when ''' + cast(@Mode as nvarchar) + ''' = ''C'' and th.TaskId = 4 then 1 else 0 end) 
				and th.AssignedTo = ''' + cast(@UserId as nvarchar) + ''' and th.LeadId = (Case when ''' + cast(@LeadId as nvarchar) + ''' = 0 then th.LeadId else ''' + cast(@LeadId as nvarchar) + ''' end)
		union 
			select th.id, Title, StartDate, EndDate, th.Status, tcm.User_ID as AgentId, th.LeadId , th.OutcomesId, th.IsTask,
					iif('+cast(@UserId as nvarchar)+' in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
				from tbl_tsk_TaskHistory(nolock) th inner join tbl_tsk_CollaborationUserMapping(NOLOCK)
				tcm on th.Id = tcm.TaskHistoryId where th.IsActive = 1 
				and 1 = (case when '''+cast(@Mode as nvarchar)+'''=''T'' and th.IsTask = 1 then 1 when '''+cast(@Mode as nvarchar)+''' = ''A'' and th.IsAppointment = 1 then 1 when ''' +cast(@Mode as nvarchar)+ '''=''C'' and th.TaskId = 4 then 1 else 0 end ) 
				and tcm.User_Id = ' +cast(@UserId as nvarchar)+ ' and th.CreatedBy=' + cast(@UserId as nvarchar)+ ' and th.LeadId = (Case when ' + cast(@LeadId as nvarchar) + ' = 0 then th.LeadId else ' + cast(@LeadId as nvarchar) + ' end)
	) tsk inner join UserLeads(nolock) ul on tsk.LeadId = ul.ID 
	inner join User_Detail(nolock) ud on tsk.AgentId = ud.User_ID
	left join tbl_tsk_UserOutcomeMaster(nolock) o on tsk.OutcomesId = o.Id
	where (1=1) '+@FullText+' )t
	where (1=1)  '+@FilterText+' '+@SearchText +')tt1 '
	
drop table if exists #TempApt
CREATE TABLE #TempApt (
    TotalRow int,
	rectype varchar(20),
	id bigint,
	Title varchar(200),
	StartDate datetime,
	EndDate datetime,
	LeadId bigint,
	PersonName varchar(150),
