	ParentId bigint,
CsvMobileNo  varchar(200),
CsvEmailId  varchar(200),
IsEditable int,
IsRemoval int,
IsTask bit)

Declare @query5 nvarchar(max) 
set @query5 = '	order by id asc 
	 OFFSET '+cast(@OffsetValue as nvarchar)+' Rows FETCH NEXT ' + cast(@PagingSize as nvarchar) +' ROWS ONLY '
 
Declare @query4 nvarchar(max)

