--	where (tsk.CreatedBy = ' + cast(@UserId as varchar(20)) + ' or tsk.CreatedBy = ' + cast(@UserId as varchar(20)) + ') ' + @FullText + ' )
--	 tt where (1=1)  '+@FilterText+' '+@SearchText +' '

--insert into #TempApt (TotalRow, rectype, id, Title, StartDate, EndDate, LeadId, PersonName, PersonImage, Outcome, Intent, LeadNo,
