select count(tm.TicketId) over() as TotalRow, [dbo].[fn_getusertimefromindiantime](@ParentId, tm.AssignedDateTime) AS [AssignedDateTime],        
     [dbo].[fn_getusertimefromindiantime](@ParentId,tm.resolved_dt) AS [resolved_dt], tm.TicketID,tm.User_id,[tm].ParentID,[tm].TicketNo,    
  [tm].Requester,[tm].Subject,[tm].Description,[tm].Status,[tm].Remarks,[tm].Note,[tm].Date_Created,    
