/* ============================================================
   Procedure: [dbo].[usp_mob_InsertCallSchedule]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_InsertCallSchedule](
	@Title nvarchar(255),
	@MobileCountryCode varchar(10),
	@MobileNo nvarchar(255),
	@ScheduleDateTime datetime,
	@GatewayId int,
	@CreatedBy bigint
)
as
begin

--declare 
--	@Title nvarchar(255),
--	@MobileCountryCode varchar(10),
--	@MobileNo nvarchar(255),
--	@ScheduleDateTime datetime,
--	@GatewayId int,
--	@CreatedBy bigint

--select @Title=N'+91 9586473400',@MobileCountryCode=N'+91',@MobileNo=N'9586473400',@ScheduleDateTime='2026-03-31 17:45:00',@GatewayId=0,@CreatedBy=34594


   Declare @ParentId bigint
   

   set @ParentId = dbo.ufn_GetUserParentId(@CreatedBy)

   Declare @GatewayIdCheck  int = 0
   
   Declare @EntityType varchar(10) = ''
   Declare @EntityId bigint = 0



if Exists(select 1 from UserLeads(nolock) where ParentID = @ParentId and (	
	MobileNo like '%'+@MobileNo+'%' or MobileNo1 like '%'+@MobileNo+'%' or MobileNo2 like '%'+@MobileNo+'%'
))
Begin
set @EntityId = isnull((select top 1 Id from UserLeads(nolock) where ParentID = @ParentId and ( MobileNo like '%'+@MobileNo+'%' or MobileNo1 like '%'+@MobileNo+'%' or MobileNo2 like '%'+@MobileNo+'%')), 0)
set @EntityType = 'lead'
End
else if Exists(select 1 from UserEnquiry(nolock) where ParentID = @ParentId and (MobileNo like '%'+@MobileNo+'%' or MobileNo1 like '%'+@MobileNo+'%' or MobileNo2 like '%'+@MobileNo+'%'))
Begin
set @EntityId = isnull((select top 1 EnquiryID from UserEnquiry(nolock) where ParentID = @ParentId 
	AND (MobileNo like '%'+@MobileNo+'%' or MobileNo1 like '%'+@MobileNo+'%' or MobileNo2 like '%'+@MobileNo+'%')), 0)
set @EntityType = 'enquiry'
End
else
Begin
	set @EntityType = ''
   set @EntityId = 0
End
 if(@GatewayId = -1)
   Begin
       IF(EXISTS ( SELECT 1 FROM tbl_voip_ParentServiceMapping(NOLOCK) WHERE parent_id = @ParentId AND is_active = 1 ))
       BEGIN
        IF(EXISTS( SELECT 1 FROM tbl_voip_userAgentSetting(NOLOCK) WHERE user_id = @CreatedBy AND is_active = 1 ))
        BEGIN
		set @GatewayIdCheck = isnull((SELECT top 1 tvsp.id FROM tbl_voip_ParentServiceMapping(NOLOCK) tvpg
			inner join tbl_voip_userAgentSetting(NOLOCK) tvag on tvpg.id = tvag.psmap_id
			inner join tbl_voip_ServiceProvider tvsp on tvpg.srv_pro_id = tvsp.Id
		   WHERE user_id = @CreatedBy), 0) 
		End
  	   End
   End
   if(@GatewayId = 0)
   Begin
	   set @GatewayIdCheck = @GatewayId;
   End
   
	insert into CallLog(callname, customercountrycode, Customernumber, callscheduledfor, gatewayid, callcreatedby, callcreatedon, parentid, agentuserid, customerentityid, customerentity)
		values (@Title, @MobileCountryCode, @MobileNo, @ScheduleDateTime, @GatewayIdCheck, @CreatedBy, getDate(), @ParentId, @CreatedBy, @EntityId, @EntityType)
end



GO

/* ============================================================
   Procedure: [dbo].[usp_mob_InsertUpdateLeadCustomField]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_mob_InsertUpdateLeadCustomField(
	@customLeadField customleads1 readonly
)
as
begin
	
	drop table if exists #customLeadField

	select *, cast(0 as bit) as isProcess into #customLeadField from @customLeadField

	while(exists(select 1 from #customLeadField where isProcess = 0))
	begin
		declare @fieldId bigint, @leadId bigint, @enquiryId bigint, @fieldValue varchar(100);
		select @fieldId = fieldID, @enquiryId = EnquiryID, @leadId = LeadID, @fieldValue = fieldvalue from #customLeadField where isProcess = 0;

		if(exists(select * from customfieldLeadvalue(nolock) where LeadID = @leadId and fieldID = @fieldId))
		begin
			update customfieldLeadvalue set fieldvalue = @fieldValue where LeadID = @leadId and fieldID = @fieldId 
		end
		else
		begin
			insert into customfieldLeadvalue ( EnquiryID, LeadID, fieldID, fieldvalue )
				values( @enquiryId, @leadId, @fieldId, @fieldValue )
		end
		update #customLeadField set isProcess = 1 where LeadID = @leadId and fieldID = @fieldId
	end
end



GO

/* ============================================================
   Procedure: [dbo].[usp_mob_LeadActivityListById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_mob_LeadActivityListById(
	@LeadId bigint,
	@ActivityTypes nvarchar(max),
	@FromDate datetime,
	@EndDate datetime
)
as
begin
	--declare 
	--	@LeadId bigint = 1869807,
	--	@ActivityTypes nvarchar(max) = 'lifecycle,Chat',
	--	@FromDate datetime = '',
	--	@EndDate datetime = ''

	select 
		leh.HistoryID, leh.UserID, ud.User_Login, ud.FName,
		ud.LName, ud.Image, ul.ID as LeadId, ul.PersonName,
		ul.ProfileImgFileName, ul.ParentID,
		leh.EventDescription, leh.EventDate,
		leh.IPAddress, leh.EventID, am.EventName,
		am.EventType
	from tbl_LeadEventHistory(nolock) leh
		inner join UserLeads(nolock) ul on leh.LeadID = ul.Id 
		inner join User_Detail(nolock) ud on ud.User_Id = leh.UserID
		inner join ActivityMaster(nolock) am on am.ID = leh.EventID
		where leh.LeadID = @LeadId
			and 1 = ( case when isnull(@ActivityTypes, '') = '' then 1 
				when isnull(@ActivityTypes, '') <> '' and trim(am.EventType) in (
				select trim([value]) from fn_Split(@ActivityTypes, ',')) then 1 else 0 end
			)
			and 1 = ( case when isnull(@FromDate, '') = '' then 1
				when isnull(@EndDate, '') = '' then 1
				when cast(leh.EventDate as date) between 
					cast(@FromDate as date) and cast(@EndDate as date) then 1
				else 0 end )
		order by leh.Historyid desc
end



GO

