			as DealOwner, e.Amount, ps.Probability, ps.CreatedDate, ps.Createdby, e.Remarks, e.EstimatedClosureDate, ul.ProfileImgFileName as Image,
			ul.PersonName LeadPersonName, concat(MobileNo, iif(MobileNo1 <> '', concat('', 
'', MobileNo1), ''), iif(MobileNo2 <> '', concat('', '', MobileNo2), '')) as CsvMobileNo,concat(EmailId, iif(EmailId1 <> '', concat('', '', EmailId1), ''), iif(EmailId2 <> '', concat('', '', EmailId2), '')) as CsvEmailId, ul.ParentId, e.LeadId, ul.LeadNo
		 from PipelineStages(nolock) ps inner join
			Pipeline_Master(nolock) pm on ps.PipelineID = pm.ID
			inner join LeadPipelineMapping(nolock) e on pm.ID = e.PipelineID and e.PipeLineStage = ps.ID
			inner join User_Detail(nolock) do on e.DealOwner = do.User_ID
			inner join UserLeads(nolock) ul on e.LeadID = ul.Id
		where isnull(ps.Isdeleted,0) = 0 and e.LeadID =  @LeadId order by [Sequence] asc    

	--select ps.ID, pm.Name as PipelineName, ps.Name as StageName, 
