	--		Pipeline_Master(nolock) pm on ps.PipelineID = pm.ID
	--		inner join LeadPipelineMapping(nolock) e on pm.ID = e.PipelineID and e.PipeLineStage = ps.ID
	--		inner join User_Detail(nolock) do on e.DealOwner = do.User_ID
	--	where isnull(ps.Isdeleted,0) = 0 and e.LeadID =  @LeadId order by [Sequence] asc    
end



