/* ============================================================
   Procedure: [dbo].[usp_mob_LeadEnquirySetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_LeadEnquirySetting]    
(    
 @id bigint = 0,    
 @default_search nvarchar(255),    
 @primary_sort nvarchar(255),    
 @secondary_sort nvarchar(255),    
 @search_fields nvarchar(MAX),    
 @platform_name nvarchar(255),    
 @display_fields nvarchar(MAX) = '',    
 @entity_type nvarchar(50) = '',    
 @synced_at datetime = null,    
 @order_by nvarchar(10)= '',    
 @user_id bigint    
)    
AS    
Begin    
   DECLARE @activity VARCHAR(MAX) = ''  
 ,@action VARCHAR(1) = ''  
 ,@rowJson NVARCHAR(MAX) = ''    
 IF EXISTS(SELECT 1 FROM tbl_mob_LeadEnquirySetting(nolock) WHERE user_id = @user_id and entity_type = @entity_type)
  AND NOT (@id IN (23,24)) --AND @entity_type IN ('lead','enquiry'))
 --and default_search = @default_search and entity_type = @entity_type and id=@id)          
 BEGIN    
  UPDATE tbl_mob_LeadEnquirySetting set default_search = @default_search, primary_sort = @primary_sort, secondary_sort = @secondary_sort, search_fields = @search_fields, platform_name = @platform_name, display_fields = @display_fields, entity_type =@entity_type, user_id = @user_id, synced_at = @synced_at, modified_on = GETDATE(), order_by = @order_by where id = @id    
  select 'Record Updated' [Status], @id id  
   SET @rowJson = (  
    SELECT *  
    FROM tbl_mob_LeadEnquirySetting WITH (NOLOCK)  
    WHERE id = @id  
    FOR JSON AUTO  
     ,INCLUDE_NULL_VALUES  
    )  
  SET @activity = 'API_Updt_LeadEnqSttng'  
  SET @action = 'U'   
 END    
 else    
 Begin    
  INSERT INTO tbl_mob_LeadEnquirySetting(default_search, primary_sort, secondary_sort, search_fields, platform_name, display_fields, entity_type, user_id, synced_at, created_on, order_by)            
  VALUES (@default_search, @primary_sort, @secondary_sort, @search_fields, @platform_name, @display_fields, @entity_type, @user_id, @synced_at, GETDATE(), @order_by)            
      
  set @id = SCOPE_IDENTITY()      
  select 'Record Saved' [Status], @id id     
   SET @rowJson = (  
    SELECT *  
    FROM tbl_mob_LeadEnquirySetting WITH (NOLOCK)  
    WHERE id = @id  
    FOR JSON AUTO  
     ,INCLUDE_NULL_VALUES  
    )  
  SET @activity = 'API_Inst_LeadEnqSttng'  
  SET @action = 'I'  
 End      
 IF @rowJson IS NOT NULL  
BEGIN  
 EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @user_id  
  ,@Activity_type = @activity  
  ,@ActionType = @action  
  ,@RowJson = @rowJson  
  ,@Table_name = 'tbl_mob_LeadEnquirySetting'  
END  
End 



------------------------------------------------------------------------------------



GO

/* ============================================================
   Procedure: [dbo].[usp_mob_LeadEnquirySettingByUserIdEntityType]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_mob_LeadEnquirySettingByUserIdEntityType]   --47825,'lead'
(    
    @UserId BIGINT,     
    @Entity_Name VARCHAR(20)     
)    
AS    
BEGIN    
    --declare
	 -- @UserId BIGINT=47825,     
     --@Entity_Name VARCHAR(20)='lead'   
    DECLARE @ParentId BIGINT, 
            @fieldName NVARCHAR(MAX), 
            @TimeZoneName NVARCHAR(255);    
    
    DECLARE @UserIdTeamLst VARCHAR(MAX) = ''     
    DECLARE @tbluser TABLE (User_ID BIGINT, Name VARCHAR(100), Image VARCHAR(100))    
    DECLARE @IsAdmin BIT = 0         

    -- Get user details
    SELECT  
        @IsAdmin = ISNULL(IsAdmin,0),     
        @ParentId = ParentID,     
        @TimeZoneName = ISNULL(TimeZone, 'india standard time')    
    FROM User_Detail (NOLOCK) 
    WHERE User_ID = @UserId     

    -- Load team users
    IF (@IsAdmin = 1)    
    BEGIN    
        SET @UserId = 0    
        INSERT INTO @tbluser    
        EXEC Use_GetUserDetails @ParentId    
    END   
    ELSE    
    BEGIN 
        INSERT INTO @tbluser   
        EXEC Use_GetUserDetails @UserID   
    END   
    
    -- Build comma list
    SELECT @UserIdTeamLst = ISNULL(STRING_AGG(User_ID,','),'') 
    FROM @tbluser 

    -----------------------------------------------------
    -- Always return only one resultset
    -----------------------------------------------------
    IF EXISTS (SELECT 1 
               FROM tbl_mob_LeadEnquirySetting (NOLOCK) 
               WHERE entity_type = @Entity_Name 
                 AND user_id IN (SELECT User_Id FROM @tbluser))
    BEGIN
        -- User/team-specific settings
        SELECT TOP 1
               id, default_search, primary_sort, secondary_sort, search_fields, 
               platform_name, display_fields, entity_type, 
               [dbo].[fn_getusertimefromindiantime](@ParentId, synced_at) synced_at, 
               [dbo].[fn_getusertimefromindiantime](@ParentId, created_on) created_on, 
               [dbo].[fn_getusertimefromindiantime](@ParentId, 
                    CASE WHEN modified_on IS NULL THEN created_on ELSE modified_on END
               ) modified_on, 
               order_by
        FROM tbl_mob_LeadEnquirySetting (NOLOCK)
        WHERE entity_type = @Entity_Name 
          AND user_id IN (SELECT User_Id FROM @tbluser)
        ORDER BY id DESC;   -- or your preferred rule
    END
    ELSE
    BEGIN

	   -- Default settings (no user-specific record found)
    SELECT 
           0 AS id, 
           '' AS default_search, 
           '' AS primary_sort, 
           '' AS secondary_sort, 
           '' AS search_fields, 
           '' AS platform_name, 
           '' AS display_fields, 
           @Entity_Name AS entity_type, 
           NULL AS synced_at, 
           NULL AS created_on, 
           NULL AS modified_on, 
           '' AS order_by
	        
			/*
	     -- Default settings
        SELECT TOP 1
               id, default_search, primary_sort, secondary_sort, search_fields, 
               platform_name, display_fields, entity_type, 
               [dbo].[fn_getusertimefromindiantime](@ParentId, synced_at) synced_at, 
               [dbo].[fn_getusertimefromindiantime](@ParentId, created_on) created_on, 
               [dbo].[fn_getusertimefromindiantime](@ParentId, 
                    CASE WHEN modified_on IS NULL THEN created_on ELSE modified_on END
               ) modified_on, 
               order_by 
			*/
        --FROM tbl_mob_LeadEnquirySetting (NOLOCK)
        --WHERE entity_type = @Entity_Name 
          --AND user_id is null;  -- default record
    END
END



