/* ============================================================
   Procedure: [dbo].[usp_mob_MarkCalllogAsCompleted]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
CREATE   PROCEDURE [dbo].[usp_mob_MarkCalllogAsCompleted](  
 @RecordingUrl nvarchar(max) = null,      
 @CallLogId bigint,      
 @OutcomeId bigint = null,      
 @Remarks nvarchar(max) = null,    
 @UserID   BIGINT   = null
)      
as  
begin
	begin try  
	 --declare       
	 -- @RecordingUrl nvarchar(max),      
	 -- @CallLogId bigint,      
	 -- @OutcomeId bigint,      
	 -- @Remarks nvarchar(max),     
	 --  @UserId bigint  
	 update CallLog set      
		recordurl = case when isnull(@RecordingUrl, '') <> ''      
		then @RecordingUrl else recordurl end,      
		outcomeid = @OutcomeId,      
		remarks = @Remarks      
	where Id  = @CallLogId   
	
	if(isnull(@UserID, 0) > 0)
	begin
		declare  
		 @EventName nvarchar(max),  
		 @EventTemplate nvarchar(max),  
		 @customerentity nvarchar(max),  
		 @customerentityid bigint,  
		 @callname nvarchar(max),  
		 @callstarttime datetime,  
		 @agentuserid bigint,  
		 @EventDescripition nvarchar(max),  
		 @Direction nvarchar(max),  
		 @ParentID bigint,  
		 @user_login nvarchar(255),  
		 @outcomename nvarchar(255)  
   
		select @customerentity=customerentity,@customerentityid=customerentityid,@callname=callname,@outcomeid=outcomeid,@remarks=remarks,  
		@callstarttime=callstarttime,@agentuserid=agentuserid,@ParentID=ParentID from CallLog  (nolock) where id=@CallLogId   
		select @outcomename=outcomename from tbl_CallLogOutcomeMaster where id=@OutcomeId  
		select @user_login=user_login from User_Detail (Nolock) where user_id=@Userid   
		set @EventDescripition = concat('A new outcome ', @outcomename, 'with remarks', @remarks,'was mentioned ',@Direction,' against call named',@callname,  
		'started on',@callstarttime,'agent name:',@user_login)  
		if(@customerentity ='lead')  
		begin  
		select  @EventName = 'Call outcome marked for a lead'   
		end  
		else  
		begin  
		select  @EventName = 'Call outcome marked for a enquiry'  
		end  
		exec UspSaveEntityActivity_withid  
		@customerentity,@customerentityid,@UserID,@ParentID,@EventDescripition,@EventName,'Calllog',@CallLogId  
	end
	end try      
		begin catch  
		exec usp_InsertErrorInfo  
	end catch  
end



