SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_ProductSuggestions] --34594,'a'
 (	
    @UserId bigint,
	@Term nvarchar(255)
 )
as
begin
	--declare 
	--@UserId bigint = 34594,
	--@Term nvarchar(255) = 'pa'

	declare @ParentId bigint = ( select ParentID from User_Detail(nolock) where User_ID = @UserId )
	exec Usp_createProductMasterTable @ParentID

	Declare @Query nvarchar(max) = concat( N' select top 10 ProductID, Name, FullPath, Description, Price 
	from tbl_ProductMaster_',Cast(@ParentID as nvarchar(max)),' (nolock) 
	where UserID = ',Cast(@ParentID as nvarchar(max)),' and IsActive = 1 and name like ''%'+ @Term+'%''
	order by Name asc ')

	print @Query
	exec sp_executesql @Query

end



