/* ============================================================
   Procedure: [dbo].[usp_mob_SendEmail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_SendEmail](
	@EntityId bigint,
	@AccountId bigint,
	@SenderName nvarchar(50) = '',
	@Subject nvarchar(500),
	@MessageId nvarchar(255),
	@UserId bigint,
	@Message nvarchar(4000),
	@EmailIds nvarchar(max),
	@ReplyTo nvarchar(max),
	@FromMailId nvarchar(max),
	@EntityType nvarchar(50) = 'enquiry',
	@MailAction nvarchar(50) = 'compose'
)
as
begin	
	
	declare @isEmailId bit = 0, @isEmailId1 bit = 0, @isEmailId2 bit = 0;

	if(@EntityType = 'enquiry')
	begin
		select 
			@isEmailId = iif(EmailID in ( select [value] from fn_Split(@EmailIds, ',' )), 1, 0),
			@isEmailId1 = iif(EmailID1 in ( select [value] from fn_Split(@EmailIds, ',' )), 1, 0),
			@isEmailId2 =  iif(EmailID2 in ( select [value] from fn_Split(@EmailIds, ',' )), 1, 0)
		from UserEnquiry(nolock) where EnquiryID = @EntityId
	end

	if(@EntityType = 'lead')
	begin
		select 
			@isEmailId = iif(EmailID in ( select [value] from fn_Split(@EmailIds, ',' )), 1, 0),
			@isEmailId1 = iif(EmailID1 in ( select [value] from fn_Split(@EmailIds, ',' )), 1, 0),
			@isEmailId2 =  iif(EmailID2 in ( select [value] from fn_Split(@EmailIds, ',' )), 1, 0)
		from UserLeads(nolock) where Id = @EntityId
	end

	if(@isEmailId = 0 and @isEmailId1 = 0 and @isEmailId2 = 0)
	begin
		select concat('EmailId No doesn''t belong to provided ', @EntityType, ' detail')
	end
	else
	begin
		if(@EntityType = 'enquiry' )
		begin
			if(@MailAction = 'compose')
			begin
				exec usp_SendMailFromEnquiry_FromMailID @EntityId, @AccountId, @Subject, @Message, @SenderName, @ReplyTo, @isEmailId, @isEmailId1, @isEmailId2, @Userid, @FromMailId
			end
			else
			begin
				exec usp_SendMailFromEnquiry_WithTemplateID_FromMailID @EntityId, @AccountId, @Subject, @MessageId, @SenderName, @ReplyTo, @isEmailId, @isEmailId1, @isEmailId2, @Userid, @FromMailId
			end
		end


		if(@EntityType = 'lead')
		begin
			if(@MailAction = 'compose')
			begin
				exec usp_SendMailFromLeads_FromMailID @EntityId, @AccountId, @Subject, @Message, @SenderName, @ReplyTo, @isEmailId, @isEmailId1, @isEmailId2, @UserId, @FromMailId
			end
			else
			begin
				exec usp_SendMailFromLeads_WithTemplateID_FromMailID @EntityId, @AccountId, @Subject, @MessageId, @SenderName, @ReplyTo, @isEmailId, @isEmailId1, @isEmailId2, @UserId, @FromMailId
			end
		end
	end

	-- Compose
	-- usp_SendMailFromEnquiry_WithTemplateID_FromMailID
end



GO

