   Procedure: [dbo].[usp_mob_SendSMS]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_SendSMS](
	@EntityId bigint,
	@AccountId bigint,
	@SenderId nvarchar(50),
	@TemplateId nvarchar(255),
	@IsUnicode bit = 0,
	@UserId bigint,
	@Message nvarchar(4000),
	@MobileNos nvarchar(max),
	@EntityType nvarchar(50) = 'enquiry'
)
as
begin
	--declare 
	--	@EnquiryId bigint,
	--	@AccountId bigint,
	--	@SenderId nvarchar(50),
	--	@TemplateId nvarchar(255),
	--	@MobileNo nvarchar(max),
	--	@IsUnicode bit = 0,
	--	@UserId bigint,
	--	@Message nvarchar(4000),
	--	@MobileNos nvarchar(max)

	declare @isMobileNo bit = 0, @isMobileNo1 bit = 0, @isMobileNo2 bit = 0;

	if(@EntityType = 'enquiry')
	begin
		select 
				@isMobileNo = iif(MobileNo in ( select [value] from fn_Split(@MobileNos, ',' )), 1, 0),
				@isMobileNo1 = iif(MobileNo1 in ( select [value] from fn_Split(@MobileNos, ',' )), 1, 0),
				@isMobileNo2 =  iif(MobileNo2 in ( select [value] from fn_Split(@MobileNos, ',' )), 1, 0)
			from UserEnquiry(nolock) where EnquiryID = @EntityId
	end

	if(@EntityType = 'lead')
	begin
		select 
				@isMobileNo = iif(MobileNo in ( select [value] from fn_Split(@MobileNos, ',' )), 1, 0),
				@isMobileNo1 = iif(MobileNo1 in ( select [value] from fn_Split(@MobileNos, ',' )), 1, 0),
				@isMobileNo2 =  iif(MobileNo2 in ( select [value] from fn_Split(@MobileNos, ',' )), 1, 0)
			from UserLeads(nolock) where Id = @EntityId
	end

	if(@isMobileNo = 0 and @isMobileNo1 = 0 and @isMobileNo2 = 0)
	begin
		select concat('Mobile No doesn''t belong to provided ', @EntityType, ' detail')
	end
	else
	begin
		if(@EntityType = 'enquiry')
		begin
			exec usp_IntindSMSFromEnquiry_WithDLTTemplateID @EntityId, @AccountId, @SenderId, @Message, @IsUnicode, @isMobileNo, @isMobileNo1, @isMobileNo2, @TemplateId, @UserId
		end
		
		if(@EntityType = 'lead')
		begin
			exec usp_IntindSMSFromlLead_WithDLTTemplateID @EntityId, @AccountId, @SenderId, @Message, @IsUnicode, @isMobileNo, @isMobileNo1, @isMobileNo2, @TemplateId, @UserId
		end
	end
end



