/* ============================================================
   Procedure: [dbo].[usp_mob_UpdateSimCalllog]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_UpdateSimCalllog] (  
 @CallLogId bigint,  
 @UserId bigint,  
 @AgentNumber nvarchar(50),  
 @AgentCountryCode nvarchar(20),  
 @AgentPickupTime datetime = null,  
 @CallStartTime datetime = null,  
 @CallEndTime datetime = null,  
 @CallPickupTime datetime = null,  
 @CallDurationSeconds int,  
 @AgentDisposition nvarchar(50),  
 @CustomerDisposition nvarchar(50),  
 @RecordingUrl nvarchar(max) = null,  
 @OutcomeId bigint,  
 @Remarks nvarchar(max)  
)  
as  
begin  
 --declare   
 -- @CallLogId bigint,  
 -- @UserId bigint,  
 -- @AgentNumber nvarchar(50),  
 -- @AgentCountryCode nvarchar(20),  
 -- @AgentPickupTime datetime,  
 -- @CallStartTime datetime = null,  
 -- @CallEndTime datetime = null,  
 -- @CallPickupTime datetime = null,  
 -- @CallDurationSeconds int,  
 -- @AgentDisposition nvarchar(50),  
 -- @CustomerDisposition nvarchar(50),  
 -- @RecordingUrl nvarchar(max) = null,  
 -- @OutcomeId bigint,  
 -- @Remarks nvarchar(max)  
  
 update CallLog set  
  Agentnumber = case when isnull(@AgentNumber, '') <> '' then  @AgentNumber else Agentnumber end,  
  
  agentcountrycode  = case when isnull(@AgentCountryCode, '') <> '' then  @AgentCountryCode else agentcountrycode end,  
  
  Callstarttime  = case when isnull(@CallStartTime, '') <> '' then  @CallStartTime else Callstarttime end,  
  
  Callendtime  = case when isnull(@CallEndTime, '') <> '' then  @CallEndTime else Callendtime end,  

  Agentpickuptime  = case when isnull(@AgentPickupTime, '') = '' 
						then  IIF(isnull(@AgentPickupTime, '') = '', @CallStartTime, @AgentPickupTime )
					else Agentpickuptime end, 

  Customerpickuptime  =  case when isnull(@CallPickupTime, '') = '' 
						then  IIF(isnull(@CallPickupTime, '') = '',@CallStartTime, @CallStartTime )
					else Customerpickuptime end, 

  Calldurationseconds  = ( case when isnull(@CallStartTime, '') <> '' and  isnull(@CallEndTime, '') <> ''
								then datediff(second, @CallStartTime, @CallEndTime)
							else Calldurationseconds end),  
  agentcalldisposition  = case when isnull(@AgentDisposition, '') <> '' then  @AgentDisposition else agentcalldisposition end,  
  
  customercalldisposition  = case when isnull(@CustomerDisposition, '') <> '' then  @CustomerDisposition else customercalldisposition end,  
  
  recordurl  = case when isnull(@RecordingUrl, '') <> '' then  @RecordingUrl else recordurl end,
  
  outcomeid  = case when isnull(@OutcomeId, '') <> '' then  @OutcomeId else outcomeid end,  
  
  remarks  = case when isnull(@Remarks, '') <> '' then  @Remarks else remarks end  

	 where id = @CallLogId and callcreatedby = @UserId  
end



