/* ============================================================
   Procedure: [dbo].[usp_ModifiedLeadgenToEnquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ModifiedLeadgenToEnquiry]      
	@LeadgenId NVARCHAR(200),    
	@SourceCode NVARCHAR(200),    
	@MediumCode BIGINT,    
	@CampaignCode BIGINT,    
	@ParentId BIGINT,    
	@LeadgenAutoId BIGINT,    
	@ModifiedLead fbLeadEnquiry READONLY 
AS      
BEGIN 


	--declare 
	--	@ModifiedLead dbo.fbLeadEnquiry,
	--	@LeadgenId NVARCHAR(200) = N'120531757632957',
	--	@SourceCode NVARCHAR(200) =N'567596',
	--	@MediumCode BIGINT= N'396166',
	--	@CampaignCode BIGINT = N'58576',
	--	@ParentId BIGINT = 41644,
	--	@LeadgenAutoId BIGINT = 545111

	--insert into @ModifiedLead values(1,N'PersonName',N'Gaurav Gupta')
	--insert into @ModifiedLead values(2,N'Apartment_Looking_For',N'1_bhk')
	--insert into @ModifiedLead values(3,N'MobileNo',N'9917681429')
	--insert into @ModifiedLead values(4,N'EmailID',N'hotelambicapalacemussoorie@gmail.com')


	drop table if exists #tempMoEnquiry
	drop table if exists #customEnquiryFieldMo
	drop table if exists #tempEnquiryMainFieldMo
	drop table if exists #tempCustomEnquiryFieldMo
	drop table if exists #fbLeadDataMo
	drop table if exists #tempLeadMo

 --IF OBJECT_ID('tempdb..#tempMoEnquiry') = NULL BEGIN DROP TABLE #tempMoEnquiry END      
 --IF OBJECT_ID('tempdb..#customEnquiryFieldMo') = NULL BEGIN DROP TABLE #customEnquiryFieldMo END      
 --IF OBJECT_ID('tempdb..#tempEnquiryMainFieldMo') = NULL BEGIN DROP TABLE #tempEnquiryMainFieldMo END      
 --IF OBJECT_ID('tempdb..#tempCustomEnquiryFieldMo') = NULL BEGIN DROP TABLE #tempCustomEnquiryFieldMo END       
 --IF OBJECT_ID('tempdb..#fbLeadDataMo') = NULL BEGIN DROP TABLE #fbLeadDataMo END      
 --IF OBJECT_ID('tempdb..#tempLeadMo') = NULL BEGIN DROP TABLE #tempLeadMo END      
      
declare @isleadcreated int=0  
 DECLARE @RowJson NVARCHAR(MAX),  @FbLeadgenId NVARCHAR(200), @FbFormId NVARCHAR(200), @Cnt INT  = 1, @RowCount INT, @EnquiryId BIGINT, @QUERY NVARCHAR(MAX) = '', @ParamDef NVARCHAR(500) = '', @AutoLeadDistribution BIT, @tempEnquiryId BIGINT = 1,   
 @LeadValueRow NVARCHAR(MAX), @fbFeildName NVARCHAR(200), @enquiryFeildName NVARCHAR(200), @enquiryFeildDataType NVARCHAR(200)    
      
 --SELECTING ROW      
 --SELECT @LeadgenAutoId = Id, @FbLeadgenId = LeadgenId, @RowJson = JsonData FROM inserted      
 SELECT @LeadgenAutoId = Id, @FbLeadgenId = LeadgenId, @RowJson = JsonData FROM tbl_fb_FacebookLeadJson(nolock) where LeadgenId = @LeadgenId      
       
 BEGIN TRY      
  -- GETTING PARENT ID AND FROM ID      
       
   SELECT @ParentId = FP.ParentId, @FbFormId = FWJ.FbForm_Id FROM tbl_fb_FacebookLeadJson(nolock) FLJ       
    INNER JOIN tbl_fb_WebhookJsonData(nolock) FWJ ON FLJ.LeadgenId = FWJ.FbLeadgen_Id      
    INNER JOIN tbl_fb_FacebookPages(nolock) FP on FWJ.FbPageId = FP.FbPageId WHERE FLJ.LeadgenId = @FbLeadgenId;    
     
    SELECT @RowCount = COUNT(*) FROM @ModifiedLead      
    
   SELECT * INTO #tempEnquiryMainFieldMo FROM UserEnquiry WHERE EnquiryID < 0      
   SET IDENTITY_INSERT #tempEnquiryMainFieldMo ON      
   INSERT INTO #tempEnquiryMainFieldMo (EnquiryID, SourceName, MediumName, CampaignName, ParentID, IsOpen, IsduplicateEmail, IsduplicateMobile, CreatedDate,CreatedBy) VALUES ( @tempEnquiryId, @SourceCode, @MediumCode, @CampaignCode, @ParentId, 1, 0, 0,getdate(),@ParentId)    
   SET IDENTITY_INSERT #tempEnquiryMainFieldMo OFF      
      
   CREATE TABLE #tempCustomEnquiryFieldMo      
   (      
    fieldID BIGINT,      
    fieldvalue SQL_VARIANT      
   )      
         
   WHILE( @Cnt <= @RowCount)      
   BEGIN      
    DECLARE @ColName NVARCHAR(500) = '',  @ColValue NVARCHAR(500) = ''      
      
    SELECT @ColName = colName, @ColValue = colValue From @ModifiedLead WHERE Id = @Cnt      
    
 PRINT @ColName    
      
    SELECT @enquiryFeildDataType = DATA_TYPE FROM INFORMATION_SCHEMA.COLUMNS WHERE  TABLE_NAME = 'UserEnquiry' AND COLUMN_NAME  = @ColName       
          
    IF(COL_LENGTH('dbo.UserEnquiry', @ColName) IS NOT NULL)      
     BEGIN      
      IF(LTRIM(RTRIM(@ColName)) = 'MobileNo' OR LTRIM(RTRIM(@ColName)) = 'MobileNo1' OR LTRIM(RTRIM(@ColName)) = 'MobileNo1')      
       BEGIN      
        DECLARE @Mobile NVARCHAR(50) = @ColValue, @CountryCount INT, @Start INT = 1, @CountryCode NVARCHAR(10) = '', @MobileNo_Checked BIGINT = 0      
        SELECT @CountryCount = MAX(Country_ID) FROM m_country1(nolock)      
        WHILE(@Start< @CountryCount)      
        BEGIN      
         IF(EXISTS(SELECT * FROM m_country1(nolock) WHERE Country_ID = @Start))      
          BEGIN      
           DECLARE @PatterCountryCode NVARCHAR(10), @CountryCodeLen INT = 0;      
            SELECT @PatterCountryCode = CountryCode, @CountryCodeLen = LEN(CountryCode) FROM m_country1(nolock) WHERE Country_ID = @Start      
      IF(LTRIM(RTRIM(@PatterCountryCode)) = SUBSTRING(LTRIM(RTRIM(@Mobile)), 0, @CountryCodeLen + 1))      
      BEGIN      
    SET @CountryCode = @PatterCountryCode      
    SET @MobileNo_Checked = SUBSTRING(@Mobile, @CountryCodeLen + 1, LEN(@Mobile) + 1)      
    --PRINT 'Matched'      
    BREAK      
      END      
     END      
     SET @Start = @Start + 1      
   END      
   UPDATE #tempEnquiryMainFieldMo       
   SET CountryCode = case when @ColName = 'MobileNo' then @CountryCode else CountryCode end,       
    CountryCode1 = case when @ColName = 'MobileNo1' then @CountryCode else CountryCode1 end,       
    CountryCode2 = case when @ColName = 'MobileNo2' then @CountryCode else CountryCode2 end,       
    MobileNo = case when @ColName = 'MobileNo' then @MobileNo_Checked else MobileNo end,      
    MobileNo1 = case when @ColName = 'MobileNo1' then @MobileNo_Checked else MobileNo1 end,      
    MobileNo2 = case when @ColName = 'MobileNo2' then @MobileNo_Checked else MobileNo2 end      
   WHERE EnquiryID = @tempEnquiryId      
            
       END      
      ELSE      
       BEGIN      
        SET @QUERY = 'UPDATE #tempEnquiryMainFieldMo SET ' + @ColName +' =  '      
        SET @QUERY += CASE WHEN @enquiryFeildDataType = 'int'      
         OR @enquiryFeildDataType = 'bigint'       
         OR @enquiryFeildDataType = 'float'      
         OR @enquiryFeildDataType = 'numeric'      
         OR @enquiryFeildDataType = 'decimal'      
         OR @enquiryFeildDataType = 'money'      
          THEN @ColValue +'  WHERE EnquiryID = '+CAST(@tempEnquiryId AS NVARCHAR)      
         ELSE      
         '''' + @ColValue +'''  WHERE EnquiryID = ' + CAST(@tempEnquiryId AS NVARCHAR)      
         END       
         --print @QUERY      
         execute sp_executesql @QUERY      
       END      
     END      
    ELSE      
     BEGIN      
      DECLARE @CustomFieldId BIGINT = 0      
      SELECT @CustomFieldId = field_ID FROM customfields WHERE ParentID = @ParentId and fieldname = @ColName    
      INSERT INTO #tempCustomEnquiryFieldMo (fieldID, fieldvalue) VALUES (@CustomFieldId, @ColValue)      
     END      
      
    --PRINT @LeadValueRow      
    SET @Cnt = @Cnt + 1      
   END      
      
   DECLARE @leadn1 BIGINT = 0      
   SELECT * INTO  #tempLeadMo FROM (              
    SELECT leadno, isnull(mobileno,'0') AS [mobile], '1' AS [email] FROM UserLeads(NOLOCK) WHERE ParentID=@ParentID and MobileNo<>''                              
    union                              
    select leadno, isnull(mobileno1,'0') as [mobile],'1' as [email] from UserLeads(nolock) where ParentID=@ParentID and MobileNo1<>''                              
    union                              
    select leadno, isnull(mobileno2,'0') as [mobile],'1' as [email] from UserLeads(nolock) where ParentID=@ParentID and MobileNo2<>''                              
    union                              
    select leadno, '0' as [mobile],isnull(nullif(emailid,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID   and emailid<>''                            
    union                              
    select leadno, '0' as [mobile],isnull(nullif(emailid1,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID  and emailid1<>''                                             
    union                              
    select leadno, '0' as [mobile],isnull(nullif(emailid2,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID  and emailid2<>''                                 
   ) lc      
        
   set @leadn1 = isnull( ( select top 1 t.leadno from #tempLeadMo t INNER JOIN UserEnquiry e on            
    (      
     t.mobile = e.MobileNo or t.mobile = e.MobileNo1 or t.mobile = e.MobileNo2 or t.email = e.EmailID or t.email = e.EmailID1 or t.email = e.EmailID2      
    ) WHERE e.EnquiryID = @tempEnquiryId       
    ), 0 )      
      
  BEGIN TRANSACTION      
     DECLARE @RC bigint=0      
    INSERT INTO UserEnquiry (PersonName,  CompanyName,  MobileNo,  MobileNo1,  MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1,   
 CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, CreatedDate, CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName )       
   SELECT PersonName,  CompanyName,  MobileNo,  MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1,   
   CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, CreatedDate, CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName       
   FROM #tempEnquiryMainFieldMo   Where isnull(PersonName, '') != '' and (isnull(MobileNo, '') != '' OR isnull(EmailID, '') != '') and ISNULL(SourceName, '') != ''      
    Select @RC = @@ROWCOUNT      
      
    
    
   SET @EnquiryId = SCOPE_IDENTITY()      
 IF(@EnquiryId > 0 and @RC > 0)      
  BEGIN     
     PRINT 'Entered'    
    
     INSERT INTO customfieldEnquiryvalue  ( EnquiryID, fieldID, fieldvalue )      
   SELECT @EnquiryId, fieldID, fieldvalue FROM #tempCustomEnquiryFieldMo      
      
     INSERT INTO parsedenquiries(rawenquiryid, enquiryid, parentid, EnquirySource) VALUES (@LeadgenAutoId, @EnquiryId, @ParentId, 'Facebook leadgen')      
     --Auto Lead Distribution section start      
   SET @AutoLeadDistribution = isnull((SELECT isnull(AutoLeadDistribution,0) FROM CRMCampaignSettings(nolock) WHERE UserID = @ParentId),0)      
   IF (@AutoLeadDistribution = 1 and @leadn1=0)                                    
   BEGIN                         
    SET @Leadn1 = isnull((select MAX(LeadNo) FROM UserLeads WHERE  ParentID = @ParentID),0)+1                                              
      
	SET Context_Info 0x55555
	
	  INSERT INTO userleads (LeadNo, PersonName, MobileNo, EmailID, MobileNo1, EmailID1, City, State, Country, CountryCode,   
		 CountryCode1, ResidentialAddress, OfficeAddress, CompanyName, AssignedTo, SourceName, ParentID, Remarks, CreatedOn, CreatedBy)   
			SELECT @leadn1, substring(PersonName,1,100), MobileNo, EmailID, MobileNo1, EmailID1, City, State, Country, CountryCode,   
		 CountryCode1, ResidentialAddress, OfficeAddress, CompanyName,   
		 (SELECT TOP 1 VALUE FROM fn_Split((SELECT agents FROM CRMCampaignSettings WHERE userid=@ParentId),'#') ORDER BY NEWID()),   
		 SourceName, @ParentId,'',GETDATE(), @ParentId FROM UserEnquiry where EnquiryID = @EnquiryId       
      
			  DECLARE @LeadId BIGINT;      
			  SET @LeadId = SCOPE_IDENTITY()      
			  set @isleadcreated=1  
	
			declare @csvLeadId nvarchar(max) = '', @CsvID nvarchar(max) = ''

			select @csvLeadId = @LeadId

			Exec MySMS.dbo.usp_ExecLeadTriggerTasks @csvLeadId
    
			if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end

			create table #outputLeadInteraction(id bigint)  

			insert into MySMS.dbo.leadinteractionhistory(LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,
			followupdate,id_lead)
				output inserted.ID into #outputLeadInteraction
			select LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,
			followupdate,ul.id
				from MySMS.dbo.userleads(nolock) ul inner join 
					dbo.fn_Split(@csvLeadId,  ',') cui on ul.ID = cui.[value]
	
			select @CsvID = STRING_AGG(CONVERT(NVARCHAR(max), ID),',') From #outputLeadInteraction

			Exec MySMS.dbo.usp_ExecLeadInteractionTriggerTasks @CsvID

   SET Context_Info 0x


     INSERT INTO customfieldLeadvalue ( EnquiryID, fieldID, fieldvalue, LeadID )      
      SELECT @EnquiryId, fieldID, fieldvalue, @LeadId FROM #tempCustomEnquiryFieldMo      
      
     UPDATE UserEnquiry  SET LeadNo = CASE WHEN @LeadN1<>0 THEN @leadn1 ELSE null END, 
	 IsOpen= case when @isleadcreated=1 then 0 else 1 end WHERE EnquiryID=@EnquiryId      
          
    Insert into  tbl_MergeLeadsEnquiry(EnquiryNo ,LeadNo,IsOpen)   
 values (@EnquiryID,@Leadn1,case when @isleadcreated=1 then 0 else 1 end)      
  end      
   --Auto Lead Distribution section end           
   --UPDATING tbl_fb_FacebookLeadJson table after successfully completed all work      
 UPDATE tbl_fb_FacebookLeadJson SET IsProccesed = 1, LastProccessedOn = GETDATE(), FailedReason='', EnquiryId = @EnquiryId WHERE LeadgenId = @FbLeadgenId      
  END    
   SELECT 1      
      
  --SAVING ALL WORK      
  COMMIT TRANSACTION      
 END TRY      
 BEGIN CATCH      
  ROLLBACK TRANSACTION      
  SELECT ERROR_NUMBER() AS ErrorNumber, ERROR_SEVERITY() AS ErrorSeverity, ERROR_STATE() AS ErrorState, ERROR_PROCEDURE() AS ErrorProcedure, ERROR_LINE() AS ErrorLine, ERROR_MESSAGE() AS ErrorMessage;         
       
   UPDATE tbl_fb_FacebookLeadJson SET IsProccesed = 0, FailedReason = ERROR_MESSAGE(), LastProccessedOn = GETDATE()  WHERE LeadgenId = @FbLeadgenId      
      
   SELECT 0      
 END CATCH    
 
drop table if exists #tempMoEnquiry
drop table if exists #customEnquiryFieldMo
drop table if exists #tempEnquiryMainFieldMo
drop table if exists #tempCustomEnquiryFieldMo
drop table if exists #fbLeadDataMo
drop table if exists #tempLeadMo
      
       
END



GO

