   Procedure: [dbo].[USP_MONITORMAIL_SEND]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE   [dbo].[USP_MONITORMAIL_SEND]        
(
@BATCHID VARCHAR(MAX),
@IsMonitor BIT
)    
AS 
BEGIN               
SET NOCOUNT ON         
  IF(@BATCHID<>'')
    BEGIN
		 UPDATE EmailsFilter SET IsMonitor =@IsMonitor
		 WHERE Mail_BatchID IN(SELECT fs.[value]  FROM  dbo.fn_Split(@BATCHID, ',') fs) AND ISNULL(IsMonitor,0)=0
	END            
END

 

     
 
 
 



GO

/* ============================================================
   Procedure: [dbo].[USP_MONITORMAIL_STOP]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE   [dbo].[USP_MONITORMAIL_STOP]        
(
@BATCHID VARCHAR(MAX)
)    
AS 
BEGIN               
SET NOCOUNT ON         
  IF(@BATCHID<>'')
    BEGIN
    	 INSERT INTO EmailsFilter_Monitor(
    	 	    Mail_GUID,
				Mail_FromEmail,
				Mail_ToEmail,
				Mail_Subject,
				Mail_TempleteName,
				Messages,
				Mail_InsertedDate,
				Mail_UserID,
				ReplyTo,
				Mail_BatchID,
				Mail_Priority,
				Mail_ScheduleDate,
				Mail_Attechement,
				Mail_TempleteBody,
				IsMonitor)
		 SELECT Mail_GUID,
				Mail_FromEmail,
				Mail_ToEmail,
				Mail_Subject,
				Mail_TempleteName,
				Messages,
				Mail_InsertedDate,
				Mail_UserID,
				ReplyTo,
				Mail_BatchID,
				Mail_Priority,
				Mail_ScheduleDate,
				Mail_Attechement,
				Mail_TempleteBody,
				IsMonitor
		 FROM EmailsFilter
		 WHERE Mail_BatchID IN(SELECT fs.[value]  FROM  dbo.fn_Split(@BATCHID, ',') fs) 
		 
		 DELETE FROM EmailsFilter  WHERE Mail_BatchID IN(SELECT fs.[value]  FROM  dbo.fn_Split(@BATCHID, ',') fs)
		 
	END            
END




