CREATE   PROC USP_MOVE_QUEUE_TO_DNDQUEUE
AS
BEGIN
DECLARE @TEMPTABLE TABLE                                    
(                                    
  MessageID BIGINT,                                    
  Mobile VARCHAR(20),                                    
  Message NVARCHAR(4000),                                  
  SenderID VARCHAR(50),                                  
  SmppID varchar(20) ,                                  
