  SenderID VARCHAR(50),                                  
  SmppID varchar(20) ,                                  
  U_ID BIGINT,                                
  IsUnicode bit,                                 
   priority tinyint ,                    
BATCHID bigint,     --MANOJ 07 02 2010              
Operator char(6),    
MessageInsertDate datetime, 
IsDND int ,
Isallowdnd tinyint                    
)          
          --MANOJ 07 02 2010 BatchId added                          
INSERT INTO @TEMPTABLE SELECT TOP(500) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,1,BATCHID,Operator,MessageInsertDate,IsDND,Isallowdnd FROM  dbo.MessageQueue
INSERT INTO @TEMPTABLE2 SELECT TOP(500) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,priority,BATCHID,Operator,MessageInsertDate,IsDND,Isallowdnd FROM  dbo.messagequeueairtelpri

DELETE MessageQueue FROM MessageQueue MQ JOIN @TEMPTABLE TT ON MQ.MESSAGEID=TT.MESSAGEID 
