/* ============================================================
   Procedure: [dbo].[USP_MOVE_STOPED_DATA]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROC USP_MOVE_STOPED_DATA      
AS      
DECLARE @USERID INT,                
@BATCHID BIGINT,                      
@PRIORITY TINYINT,                      
@ALLOWDND TINYINT,                  
@ScheduleDate VARCHAR(50),                  
@ScheduleTime VARCHAR(50),              
@IsUnicode bit,            
@PageName nvarchar(50),            
@UserFilter varchar(20),        
@TableName varchar(100),      
@ROW_COUNT BIGINT  ,      
@MESSAGE_LEN_TEMP BIGINT ,      
@MESSAGE_LEN_MAXLEN BIGINT  ,      
@QUERY NVARCHAR(MAX) ,      
@QUERY_2 NVARCHAR(MAX) ,      
@QUERY_COUNT NVARCHAR(MAX),  
@QUERY_DROP nvarchar(MAX)    
      
SET @QUERY='select TOP(1) @TableName=table_name from INFORMATION_SCHEMA.COLUMNS where table_name like ''R201%''      
and table_name not in       
(select tableName  from batchinfo WITH(NOLOCK) )'      
      
      
EXEC SP_EXECUTESQL @QUERY, N'@TableName VARCHAR(100) OUTPUT', @TableName   OUTPUT      
IF @TableName<>''      
BEGIN      
SET @QUERY_COUNT='SELECT @ROW_COUNT=COUNT(BATCHID) FROM '+ @TableName+' '      
      
EXEC SP_EXECUTESQL @QUERY_COUNT, N'@ROW_COUNT BIGINT OUTPUT',@ROW_COUNT  OUTPUT      


      
if @ROW_COUNT=0
BEGIN
set @QUERY_DROP='drop table '+ @TableName+''

EXEC SP_EXECUTESQL @QUERY_DROP
END
--SELECT @TableName      
SET @QUERY_2='SELECT  TOP(1)      
@BATCHID=BatchID,      
@ALLOWDND=IsAllowDND,      
@ScheduleDate=ScheduledDate,      
@ScheduleTime=ScheduledTime,      
@USERID=U_ID,      
@IsUnicode=IsUniCode,      
@PRIORITY=IsPrority,      
@PageName=''api''      
FROM '+@TableName+''      
      
--SELECT @QUERY_2      
      
EXEC SP_EXECUTESQL @QUERY_2, N'@BATCHID BIGINT OUTPUT,                      
@ALLOWDND TINYINT OUTPUT,             
@ScheduleDate VARCHAR(50) OUTPUT,                   
@ScheduleTime VARCHAR(50) OUTPUT,         
@USERID INT OUTPUT,                      
@IsUnicode bit OUTPUT,        
@PRIORITY TINYINT OUTPUT,                       
@PageName nvarchar(50) OUTPUT',@BATCHID  OUTPUT,                      
@ALLOWDND  OUTPUT,             
@ScheduleDate  OUTPUT,                   
@ScheduleTime  OUTPUT,         
@USERID  OUTPUT,                      
@IsUnicode  OUTPUT,        
@PRIORITY  OUTPUT,                       
@PageName  OUTPUT          
      
SELECT TOP(1) @UserFilter=UserFilter FROM USER_DETAIL WITH(NOLOCK) WHERE USER_ID=@USERID      
--      
--SELECT @USERID,                  
--@BATCHID,      
--@ROW_COUNT,                    
--@PRIORITY,                      
--@ALLOWDND,                  
--@ScheduleDate,                 
--@ScheduleTime,           
--@IsUnicode,         
--@PageName,         
--@UserFilter,      
--@TableName       
      
EXEC USP_INSERTINTOBATCHINFONewTestNew @USERID,                  
@BATCHID,      
@ROW_COUNT,                    
@PRIORITY,                      
@ALLOWDND,                  
@ScheduleDate,                 
@ScheduleTime,           
@IsUnicode,         
@PageName,         
@UserFilter,      
@TableName       
END      
    
    
    
update batchinfo set isprocess=null    
 where tablename in (    
Select name  from sys.objects where type_desc='USER_TABLE'  
and name  like 'R201%'  and datediff(mi,create_date,getdate())>20     
) and isprocess is not null    


GO

