/****************************************************************************     
     
SP_Name        : [Usp_MoveAllSpamInMessageFailedbySenderID]                         
Author         : Mukesh     
Created ON     : 25/12/2009 04:30 PM            
Version        : 1      
Alter BY       :              
Alter Date     :    
Location       : PELSOFT      
SP Description ; Proc is selecting records from  MessageSpam  
               : proc is also inserting records into MessageFailed  
               :proc is also deleting records from MessageSpam  
                                
****************************************************************************/   
CREATE   PROC [dbo].[Usp_MoveAllSpamInMessageFailedbySenderID]                 
@UserID int,       
@SenderID varchar(20)                
as                
SET NOCOUNT ON              
begin transaction               
set nocount on         
select count (MessageSpamID)  from MessageSpam where SenderID=@SenderID                    
insert into MessageFailed(MessageID,MessageBatchID,Mobile,[Message],SenderID,U_ID,FailureClause) select MessageID,0,Mobile,[Message],SenderID,U_ID,'SpamMessage' from dbo.MessageSpam where SenderID=@SenderID                
delete from MessageSpam where U_Id=@UserID and SenderID=@SenderID                
if @@error<>0                
begin                
  -- Rollback the transaction                
    ROLLBACK                
    -- Raise an error and return                
    RAISERROR ('Please try again.', 16, 1)                
    RETURN                
end                
if @@error=0                
begin                
commit transaction                
end       




GO

