CREATE   PROC [dbo].[Usp_MoveAllStopedMessageToFailedbyMessageStorageId1] --'134,135,136'           
@MsgID varchar(2000)        
as            
begin transaction           
set nocount on         
Declare @sqlInsert nvarchar(4000)                              
declare @sqlDelete nvarchar(4000)        
set @sqlInsert= 'insert into MessageFailed(MessageID,MessageBatchID,Mobile,[Message],SenderID,U_ID) select MessageID,MessageBatchID,Mobile,[Message],SenderID,U_ID from MessageStopped where MessageStorageID in '            
set @sqlInsert=@sqlInsert + '(' + @MsgID + ')'        
set @sqlDelete='delete from MessageStopped where MessageStorageID in '        
set @sqlDelete=@sqlDelete + '(' + @MsgID + ')'        
exec(@sqlInsert)        
exec(@sqlDelete)       
if @@error<>0            
begin            
  -- Rollback the transaction            
    ROLLBACK            
    -- Raise an error and return            
    RAISERROR ('Please try again.', 16, 1)            
    RETURN            
end            
if @@error=0            
begin            
commit transaction           
end     
   



