/* ============================================================
   Procedure: [dbo].[usp_MoveDeleteOldSubscriptionData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_MoveDeleteOldSubscriptionData
(
	@Mode varchar(10)='Delete',
	@CutOffDays int=60
)
AS
Begin

	Drop table if exists #tempOldSubscription

	select * 
	into #tempOldSubscription 
	from Price_UserSubscriptionDetails where isnewplan=1 and PlanEndDate < dateadd(d,-@CutOffDays,getdate())

	If(@Mode='Move')
	Begin

		INSERT INTO [MySMSReport].[dbo].[customfieldLeadvalue_OldData]
			   ([recordID],[LeadID],[EnquiryID],[fieldID],[fieldvalue],[CreatedDate])
		select LEH.[recordID],LEH.[LeadID],LEH.[EnquiryID],LEH.[fieldID],LEH.[fieldvalue],LEH.[CreatedDate]
		from customfieldLeadvalue(nolock) LEH inner join UserLeads(nolock) UL
		on	LEH.LeadId=UL.ID inner join #tempOldSubscription(nolock) OS
		on  UL.ParentID=OS.UserID

		Set identity_insert [MySMSReport].[dbo].[UserLeads_OldData] ON

		INSERT INTO [MySMSReport].[dbo].[UserLeads_OldData]
			   ([ID],[LeadNo],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks],[Products],[AmountPaid],[CreatedOn],[CreatedBy],[ModifiedOn],[ModifiedBy],[FollowupDate],[LeadImage],[temp_id],[img_ext],[ProfileImgFileName],[enquirysource],[WhatsAppNoColName],[LastFollowupCreatedBy],[whereAddress],[latitude],[longitude],[LastFollowupCreatedOn],[IsScoreeligible],[ProductsJson])
		Select [ID],[LeadNo],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks],[Products],[AmountPaid],[CreatedOn],[CreatedBy],[ModifiedOn],[ModifiedBy],[FollowupDate],[LeadImage],[temp_id],[img_ext],[ProfileImgFileName],[enquirysource],[WhatsAppNoColName],[LastFollowupCreatedBy],[whereAddress],[latitude],[longitude],[LastFollowupCreatedOn],[IsScoreeligible],[ProductsJson]
		From UserLeads(nolock) 
		Where ParentId in (Select Userid From #tempOldSubscription)

		Set identity_insert [MySMSReport].[dbo].[UserLeads_OldData] OFF
	   


		INSERT INTO [MySMSReport].[dbo].[customfieldEnquiryvalue_OldData]
			   ([recordID],[EnquiryID],[fieldID],[fieldvalue])
		select LEH.[recordID],LEH.[EnquiryID],LEH.[fieldID],LEH.[fieldvalue]
		from customfieldEnquiryvalue(nolock) LEH inner join UserEnquiry(nolock) UE
		on	LEH.EnquiryID=UE.EnquiryID inner join #tempOldSubscription(nolock) OS
		on  UE.ParentID=OS.UserID



		Set identity_insert [MySMSReport].[dbo].[UserEnquiry_OldData] ON

		INSERT INTO [MySMSReport].[dbo].[UserEnquiry_OldData]
			   ([EnquiryId],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],[IsOpen],[LeadNo],[img_ext],[ProfileImgFileName],[enquirysource],[WhatsAppNoColName],[whereAddress],[latitude],[longitude],[IsduplicateEmail],[IsduplicateMobile],[Owner],[Stages],[Remark]
			   ,[ReminderDate],[StagesId])
		Select [EnquiryId],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],[IsOpen],[LeadNo],[img_ext],[ProfileImgFileName],[enquirysource]
			   ,[WhatsAppNoColName],[whereAddress],[latitude],[longitude],[IsduplicateEmail],[IsduplicateMobile],[Owner],[Stages],[Remark]
			   ,[ReminderDate],[StagesId] 
		From UserEnquiry(nolock) 
		Where ParentId in (Select Userid From #tempOldSubscription)		

		Set identity_insert [MySMSReport].[dbo].[UserEnquiry_OldData] OFF

	End

	delete LEH
	from tbl_LeadEventHistory LEH inner join UserLeads(nolock) UL
	on	LEH.LeadID=UL.ID inner join #tempOldSubscription(nolock) OS
	on  UL.ParentID=OS.UserID

	delete LEH
	from LeadInteractionHistory LEH inner join UserLeads(nolock) UL
	on	LEH.ID_Lead=UL.ID inner join #tempOldSubscription(nolock) OS
	on  UL.ParentID=OS.UserID

	delete LEH
	from customfieldLeadvalue LEH inner join UserLeads(nolock) UL
	on	LEH.LeadId=UL.ID inner join #tempOldSubscription(nolock) OS
	on  UL.ParentID=OS.UserID


	SET Context_Info 0x55555  
	delete From UserLeads Where ParentId in (Select Userid From #tempOldSubscription)
	SET Context_Info 0x  
	   
	delete LEH
	from tbl_EnquiryEventHistory LEH inner join UserEnquiry(nolock) UE
	on	LEH.EnquiryID=UE.EnquiryID inner join #tempOldSubscription(nolock) OS
	on  UE.ParentID=OS.UserID

	delete LEH
	from customfieldEnquiryvalue LEH inner join UserEnquiry(nolock) UE
	on	LEH.EnquiryID=UE.EnquiryID inner join #tempOldSubscription(nolock) OS
	on  UE.ParentID=OS.UserID


	SET Context_Info 0x55555  
	delete From UserEnquiry Where ParentId in (Select Userid From #tempOldSubscription)
	SET Context_Info 0x  

end



GO

