CREATE   PROCEDURE [dbo].[usp_movefailRecordtempToqueue] -- '0x00000401' 
@refError nVarchar(100) 
AS 
BEGIN 
BEGIN TRY 
 
 SELECT SubReference INTO #TemptableMove FROM SubmitDetail WHERE IsNull(subreference,'') != '' and 
 Resultcode=@refError and isnull(IsSent,0)=0 AND datediff(d,InsertDate, getdate()) = 0 
 
 INSERT INTO MessageSource(MessageID,Mobile,[Message],SenderID,SmppID,MessageInsertDate,priority,U_ID,IsUniCode,IsDND,Operator,MessageBatchID,Isallowdnd) 
 SELECT Messageid, Substring(Mobile,3,10) ,[Message],SenderID,1,MessageInsertDate,1, IsNull(U_ID,1),isnull(IsUniCode,0) ,0,IsNull(Operator,'UI'),BatchID,1 
 FROM mysmstrans.dbo.MessageDeliveryStatusTemp md JOIN #temptableMove tmp 
 ON md.MessageRefID=tmp.SubReference 
 
--insert into MessageDeliveryStatusTemp401Move 
--Select * FROM MessageDeliveryStatusTemp md JOIN SubmitDetail tmp 
-- ON md.MessageRefID=tmp.SubReference WHERE IsNull(tmp.subreference,'') != '' 
-- AND tmp.Resultcode=@refError and isnull(tmp.IsSent,0)=0 AND datediff(d,tmp.InsertDate, getdate()) = 0 
 
 
 delete md FROM mysmstrans.dbo.MessageDeliveryStatusTemp md JOIN SubmitDetail tmp 
 ON md.MessageRefID=tmp.SubReference WHERE IsNull(tmp.subreference,'') != '' 
 AND tmp.Resultcode=@refError and isnull(tmp.IsSent,0)=0 AND datediff(d,tmp.InsertDate, getdate()) = 0 
 
 UPDATE SubmitDetail 
 SET issent=1 
 where Resultcode=@refError and isnull(IsSent,0)=0 AND datediff(d,InsertDate, getdate()) = 0 
 
-- 
-- UPDATE sD 
-- SET issent=1 
-- FROM SubmitDetail sD 
-- JOIN #temptableMove tTM 
-- ON sD.SubReference = tTM.SubReference 
-- 
 
 
-- DELETE MessageDeliveryStatusTemp 
-- FROM MessageDeliveryStatusTemp mD 
-- JOIN #temptableMove tMP 
-- ON mD.MessageRefID=tMP.SubReference 
 
 
END TRY 
BEGIN CATCH 
 EXEC USP_InsertErrorInfo 
END CATCH 
END 



GO

