/* ============================================================
   Procedure: [dbo].[USP_MOVEFROMMONITORTOSOURCETABLE_TEST_async]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[USP_MOVEFROMMONITORTOSOURCETABLE_TEST_async] --1997160,''     
@BATCHID VARCHAR(MAX),     
@FILTERMODE CHAR(5),     
@ACCOUNT VARCHAR(20)  ,@error_description nvarchar(max) output   
AS     
--BEGIN TRANSACTION     
begin     
SET NOCOUNT ON 
--declare @BATCHID VARCHAR(MAX)=154045511,     
--@FILTERMODE CHAR(5)='10',     
--@ACCOUNT VARCHAR(20)='mtix-tr'  ,@error_description nvarchar(max) 
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Entered proc to move sms to outbox for batch : ',@batchid);

drop table if exists #temp
drop table if exists #messagemonitor
drop table if exists #link_smsmobile
drop table if exists #clientmobile


DECLARE @SQLINSERT NVARCHAR(MAX)     
DECLARE @SQLUPDATE NVARCHAR(MAX)     
DECLARE @SQLDELETE NVARCHAR(MAX)     
DECLARE @QUERYTEMP NVARCHAR(MAX)  ,@u_id bigint ,@count_m int,@totalcount int,@from bigint,@to bigint,@shorturl bit=0 ,@mm_id int 
DECLARE  @QUERY NVARCHAR(MAX) ,@personalized int=0 ,@queryForPersonalization  nvarchar(max),@samemessage int,@error nvarchar(1000)
,@dlt_id nvarchar(50),@pe_id nvarchar(50),@route varchar(20),@isflash int=0,@messagetext nvarchar(4000)='',@start_messagingid bigint,
@deleted int,@remaining int,@startingtotal int,@smsoutboxid bigint
DECLARE @payload NVARCHAR(MAX);
DECLARE @SMPPID NVARCHAR(2)  
declare @batch_size int=5000
SELECT TOP 1 @SMPPID=SMPPID FROM USER_DETAIL with (nolock) WHERE USERFILTER=@ACCOUNT AND (SMPPID=1 OR SMPPID=2)   

select value into #temp from dbo.fn_split(@batchid,',')     

select @u_id=dbo.ufn_getuserparentid(userid) from batchinfo(nolock) where batchid=@batchid

IF @FILTERMODE != ''     
BEGIN     
update b set filtermode=@filtermode,dbtype=7,userfilter=@account,batchmonitordate=getdate()     
from batchinfo b join #temp t on t.value=b.batchid     
END     
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   u_id : ',@u_id);

if 1=1--@u_id<>33819
begin
begin try

select @dlt_id=DLT_TemplateID,@isflash=flash,@route=[dbo].[fn_getuserfilter_real](@u_id) from DLT_Template_MSG(nolock)  where batchid=@batchid
select @pe_id=pe_id from DLTdetails (nolock)  where parentid=@u_id
if isnull(@pe_id,'')='' or isnull(@dlt_id,'')=''
begin
select @error=case when isnull(@pe_id,'')='' then 'PE_ID ' else 'DLT_ID ' end+ 'is invalid.' 
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   batch ',@batchid ,' has invalid pe_id or dlt_id : ',@error);
update MessageDeliveryStatus set MessageStatus='Not Sent' ,StatusDescription=@error,StatusCompletedTime=getdate() where batchid=@batchid
return;
end

select * into #messagemonitor from MessageMonitor where MessageMonitorID=0
select * into #link_smsmobile from Link_smsMobile where mobile_url_id=0

select @startingtotal=count(1),@remaining=count(1),@deleted=0 from MessageMonitor(nolock) where batchid=@BATCHID

if exists(select 1 from Link_smsUrl_dtl(nolock) where batchid=@BatchID)
begin
select @personalized=1
select @shorturl=1
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid,' has link tracking');
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] MessageMonitor count: Starting Total ',@startingtotal,' , Remaining: ',@remaining,' Deleted: ',@deleted);

insert into #link_smsmobile(Mobile,Final_url,MessageID,shorturl,longurl,batchid)
select Mobile,Final_url,MessageID,shorturl,longurl,batchid from Link_smsMobile(nolock) where batchid=@batchid
declare @lid int=@@rowcount
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ', shorturl exists for message count: ',@lid);
--select top 10 * from #link_smsmobile order by messageid
end
else
begin
SELECT @count_m=COUNT(DISTINCT message)
    FROM   MessageMonitor (nolock)                                     
    WHERE  batchid = @batchid 
select @personalized=case when @count_m>1 then 1 else 0 end
end

if @personalized=0
begin
select top 1 @messagetext=message from messagemonitor(nolock)  WHERE  batchid = @batchid 
end

PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ', @u_id:',@u_id,',@dlt_id: ',@dlt_id,
',@route: ', @route,',@pe_id: ',@pe_id, ', @personalized ',@personalized)


PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ', executing Usp_GetPremiumCount_new_from_monitor started ')
exec Usp_GetPremiumCount_new_from_monitor @batchid
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ', executing Usp_GetPremiumCount_new_from_monitor done ')

select @totalcount=count(1),@from=0,@start_messagingid=min(messageid)  ,@to=max(messageid) from MessageMonitor(nolock) where batchid=@batchid
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ', Count after premium deduction ',@totalcount, ', @from: ',@from, ', @to ',@to)


if exists (select 1 from Messagemonitor(nolock) m join clientmobile c(nolock) on m.mobile=c.mobile where m.batchid=@batchid)
begin
select
MessageID,SenderID,SmppID,isnull(Isallowdnd,0) Isallowdnd,m.mobile,message,batchid,0 isunicode,getdate() as messageinsertdate,priority,u_id,isnull(Isallowdnd,0) isdnd 
into #clientmobile
from Messagemonitor(nolock) m join clientmobile c(nolock) on m.mobile=c.mobile where batchid=@batchid
select @mm_id=@@Rowcount
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ', records inserted in #clientmobile : ',@mm_id)

if @shorturl=1
begin

update m set message=rtrim(ltrim(REPLACE(message,longurl, shorturl+'/'+Final_url)))   from #clientmobile m 
join #link_smsmobile l on 
(l.MessageID=m.messageid or cast(l.batchid as nvarchar)+cast(l.messageid as nvarchar)=m.messageid  ) 
select @mm_id=@@ROWCOUNT

PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ', records updated in #clientmobile : ',@mm_id)

update #clientmobile set isunicode=isnull(dbo.fn_IsUnicode(message),0)
select @mm_id=@@ROWCOUNT
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ', unicode updated in #clientmobile : ',@mm_id)
end

SELECT @payload = cast((
    SELECT  
        TOP 1
		@batchid batchid,
        rtrim(ltrim(SenderID)) as senderid,
        2 smppid,
        u_id,
		isnull(@PE_ID,'') PE_ID,
		isnull(@DLT_ID,'0') DLT_TemplateID,
		@route  as [Route],
        Priority,
        IsAllowDND isdnd,
		@isflash isflash,
		@messagetext Message,
        '' operator,
		case when @personalized=0 then 1 else 0 end SameMessage,
        isallowdnd,
        cast((
            SELECT 
				right(MessageID,9) usertag,
				messageid,
                '91' + rtrim(ltrim(Mobile)) Mobile,
                message,
				IsUnicode
            FROM   #clientmobile with (nolock)
            WHERE  batchid = @batchid
              FOR JSON PATH
        ) as nvarchar(max)) AS recipients
    FROM #clientmobile with (nolock)
    WHERE batchid = @batchid 
FOR JSON PATH, WITHOUT_ARRAY_WRAPPER) as nvarchar(max));

PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Payload prepared for #clientmobile in Batch: ',@batchid)


begin tran
INSERT INTO smsoutbox (QueueName,batchid, payload)
VALUES ('SMS_RMQ2',@batchid, @payload);
select @smsoutboxid=scope_identity()
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Inserted in smsoutbox, id created: ',@smsoutboxid,', Batch: ',@batchid,', @start_messagingid: ',@start_messagingid, ',  @from (till): ',@from,', @to: ',@to)

delete m from Messagemonitor m join #clientmobile o on m.mobile=o.mobile  --o.messageid=m.messageid 
and o.batchid=m.batchid
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   deleted from Messagemonitor, Batch: ',@batchid,', @start_messagingid: ',@start_messagingid, ',  @from (till): ',@from,', @to: ',@to)

delete m from #clientmobile m 
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   deleted from #clientmobile, Batch: ',@batchid,', @start_messagingid: ',@start_messagingid, ',  @from (till): ',@from,', @to: ',@to)


select @remaining=count(1)from Messagemonitor(nolock) where batchid=@BATCHID
select @deleted=@startingtotal-@remaining
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] Messagemonitor count after clientmobile: Starting Total ',@startingtotal,' , Remaining: ',@remaining,' Deleted: ',@deleted);
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] TRAN COMMITED for clientmobile new totalcount: ',@remaining)

commit
if @@TRANCOUNT>0
begin
Rollback
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] TRAN ROLLBACK for clientmobile  new totalcount: ',@totalcount)

end
end

select @totalcount=count(1),@from=0,@start_messagingid=min(messageid)  ,@to=max(messageid) from Messagemonitor(nolock) where BatchID=@batchid
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ', Count after client mobile ',@totalcount, ', @from: ',@from, ', @to ',@to)





while @totalcount>0 --and @from<=@to
begin
--select top (@batch_size) MessageID,SenderID,SmppID,isnull(Isallowdnd,0),mobile,message,batchid,0,getdate(),priority,u_id,isnull(Isallowdnd,0) from MessageMonitor(nolock) where batchid=@batchid and MessageID>@from order by MessageID

insert into #messagemonitor(MessageID,SenderID,SmppID,Isallowdnd,mobile,message,batchid,isunicode,MessageInsertDate,priority,u_id,isdnd)
select top (@batch_size) MessageID,SenderID,SmppID,isnull(Isallowdnd,0),mobile,message,batchid,0,getdate(),priority,u_id,isnull(Isallowdnd,0) from MessageMonitor(nolock) where batchid=@batchid and MessageID>@from order by MessageID
select @mm_id=@@ROWCOUNT
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ', records inserted in #messagemonitor : ',@mm_id,', @start_messagingid: ',@start_messagingid, ', @from: ',@from,', @to: ',@to)


if @shorturl=1
begin
--select top 10 * from #messagemonitor order by messageid
--select top 10 * from #link_smsmobile order by messageid

--select top 10 rtrim(ltrim(REPLACE(message,longurl, shorturl+'/'+Final_url))) modifiedmessage ,m.* from  #messagemonitor m join #link_smsmobile l on 
--(l.MessageID=m.messageid or cast(l.batchid as nvarchar)+cast(l.messageid as nvarchar)=m.messageid  ) 
update m set message=rtrim(ltrim(REPLACE(message,longurl, shorturl+'/'+Final_url)))   from #messagemonitor m 
join #link_smsmobile l on 
(l.MessageID=m.messageid or cast(l.batchid as nvarchar)+cast(l.messageid as nvarchar)=m.messageid  ) 
select @mm_id=@@ROWCOUNT

PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ', records updated in #messagemonitor : ',@mm_id)

update #messagemonitor set isunicode=isnull(dbo.fn_IsUnicode(message),0)
select @mm_id=@@ROWCOUNT
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ', unicode updated in #messagemonitor : ',@mm_id)
--select top 10 * from #messagemonitor

end

if @FILTERMODE<10 and not exists(select 1 from PremiumMessage(nolock) where BatchID=@batchid)
begin
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ',Again executing Usp_GetPremiumCount_new_from_monitor started ')
exec Usp_GetPremiumCount_new_from_monitor @batchid
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Batch: ',@batchid, ',Again executing Usp_GetPremiumCount_new_from_monitor done ')
end


SELECT @payload = cast((
    SELECT  
        TOP 1
		@batchid batchid,
        rtrim(ltrim(SenderID)) as senderid,
        2 smppid,
        u_id,
		isnull(@PE_ID,'') PE_ID,
		isnull(@DLT_ID,'0') DLT_TemplateID,
		@route  as [Route],
        Priority,
        IsAllowDND isdnd,
		@isflash isflash,
		@messagetext Message,
        '' operator,
		case when @personalized=0 then 1 else 0 end SameMessage,
        isallowdnd,
        cast((
            SELECT 
				right(MessageID,9) usertag,
				messageid,
                '91' + rtrim(ltrim(Mobile)) Mobile,
                message,
				IsUnicode
            FROM   #messagemonitor with (nolock)
            WHERE  batchid = @batchid
              FOR JSON PATH
        ) as nvarchar(max)) AS recipients
    FROM #messagemonitor with (nolock)
    WHERE batchid = @batchid 
FOR JSON PATH, WITHOUT_ARRAY_WRAPPER) as nvarchar(max));
select @from=max(messageid) from #messagemonitor

PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Payload prepared for Batch: ',@batchid,', @start_messagingid: ',@start_messagingid, ',new @from (till): ',@from,', @to: ',@to)


begin tran
INSERT INTO smsoutbox (QueueName,batchid, payload)
VALUES ('SMS_RMQ1',@batchid, @payload);
select @smsoutboxid=scope_identity()
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   Inserted in smsoutbox, id created: ',@smsoutboxid,', Batch: ',@batchid,', @start_messagingid: ',@start_messagingid, ',  @from (till): ',@from,', @to: ',@to)


delete m from messagemonitor m join #messagemonitor o on o.messageid=m.messageid and o.batchid=m.batchid

PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   deleted from messagemonitor, Batch: ',@batchid,', @start_messagingid: ',@start_messagingid, ',  @from (till): ',@from,', @to: ',@to)

delete m from #messagemonitor m 
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), ']   deleted from #messagemonitor, Batch: ',@batchid,', @start_messagingid: ',@start_messagingid, ',  @from (till): ',@from,', @to: ',@to)


select @remaining=count(1)from MessageMonitor(nolock) where batchid=@BATCHID
select @deleted=@startingtotal-@remaining
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] MessageMonitor count: Starting Total ',@startingtotal,' , Remaining: ',@remaining,' Deleted: ',@deleted);

PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] TRAN COMMITED  new totalcount: ',@totalcount)

commit
if @@TRANCOUNT>0
Rollback
select @totalcount=@totalcount-@batch_size
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] TRAN ROLLBACK  new totalcount: ',@totalcount)
end

delete m from messagemonitor m where batchid=@batchid


end try
begin catch
exec usp_inserterrorinfo
select @error_description=error_message()
--select @error_description
end catch

return;


end
