/* ============================================================
   Procedure: [dbo].[usp_movemessagedeliverysttustemp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_movemessagedeliverysttustemp
as
begin
declare @t6 bigint=(Select count(1) From  [MySMS].dbo.MessageDeliveryStatusTemp(nolock)
Where datediff(d,MessageInsertDate,getdate()) != 0)
select @t6
while @t6>0
begin
Insert into MySMSReport.dbo.MsgTempHistory1(MessageID , MessageRefID , Mobile , [Message] , SenderID , MessageStatus, MessageInsertDate, Priority,
SmppID , U_ID , LastError, IsUniCode, BatchID , Operator, Account, Dbtype)
Select top 1000 MessageID , MessageRefID , Mobile , [Message] , SenderID , MessageStatus, MessageInsertDate, Priority,
SmppID , U_ID , LastError, IsUniCode, BatchID , Operator, Account, isnull(Dbtype,0)
From [MySMS].dbo.MessageDeliveryStatusTemp(nolock)
Where datediff(d,MessageInsertDate,getdate()) != 0 order by  MessageDeliveryStatusID
delete t from 
(select top 1000 * from [MySMS].dbo.MessageDeliveryStatusTemp
Where datediff(d,MessageInsertDate,getdate()) != 0 order by  MessageDeliveryStatusID) t
set @t6=@t6-1000
select @t6
end
declare @t bigint=(select count(1) from MySMSReport.dbo.MsgTempHistory1(nolock) where datediff(d,MessageInsertDate,getdate()) >30)
while @t>0
begin
delete top (1000) from MySMSReport.dbo.MsgTempHistory1 where datediff(d,MessageInsertDate,getdate()) >30
select @t=@t-1000
end
end




GO

/* ============================================================
   Procedure: [dbo].[USP_MoveMessageFromCriticalQueueToRoute_SPICE]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].USP_MoveMessageFromCriticalQueueToRoute_SPICE                                                                
(                                                                
@TOTALCOUNT INT =100                                                   
)                                                                
AS                           
--VF-1,SPICE-2,DEMO:PROMOSPICE-4,TRANSSPICE-5,TRCSPICE-6,PROMOVF-7,TRANSVF-8,TRCVF-9                                                             
--1) SELECT TOP GIVEN NO OF HIGH PRIORITIES MESSAGES                                                                
BEGIN                                                              
SET NOCOUNT ON                                                              
DECLARE @TOPCOUNT INT                                                              
DECLARE @RESTCOUNTAFTERDirect INT                                                             
DECLARE @RESTCOUNTAFTERPriority  INT                                                          
SET @TOPCOUNT = @TOTALCOUNT                                                              
                            
--DELETE MessageQueueNew where mobile=''                                  
--Delete T from                                  
--(select row_number() over(partition by MessageID order by MessageID) as row_number, * from MessageQueueNew) T                                  
--where row_number > 1                                  
DECLARE @TEMPTABLE TABLE                                                              
(                                                              
  MessageID BIGINT,                                                              
  Mobile VARCHAR(20),                                                              
  Message NVARCHAR(2500),                                                            
  SenderID VARCHAR(50),                                                            
  SmppID varchar(20) ,                                                            
  U_ID BIGINT,                                                          
  IsUnicode bit,                                                           
   priority tinyint ,                                              
BATCHID bigint,     --MANOJ 07 02 2010                                        
Operator char(6)                                                    
)                                       
--exec proc_insert_into_normal_from_q1                                        
--exec proc_insert_into_pri_from_q1                                      
--exec proc_insert_into_dir_from_q1                                            
          --MANOJ 07 02 2010 BatchId added                                                    
INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,priority,                                    
BATCHID,Operator FROM  dbo.MessageQueueCritical WHERE  PRIORITY=2 and SmppID=2   and U_ID<>24502                             
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)                                     
order by convert(datetime,messageinsertdate,100)                                    
SET @RESTCOUNTAFTERDirect =@@ROWCOUNT                                                              
                                                              
IF (@RESTCOUNTAFTERDirect< @TOPCOUNT)                                                              
 BEGIN                                                              
                                                              
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT-@RESTCOUNTAFTERDirect ) MessageID,Mobile,[Message],SenderID,SmppID,                                    
 U_ID,IsUnicode,priority,BATCHID,Operator FROM  dbo.MessageQueueCritical WHERE  PRIORITY=1 and SmppID=2   and U_ID<>24502                           
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)                                   
 order by convert(datetime,messageinsertdate,100)                                      
           
     SET @RESTCOUNTAFTERPriority =@@ROWCOUNT         
                                                              
          
 IF ((@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)< @TOPCOUNT)                                                             
  BEGIN                                                          
   SET @TOPCOUNT = @TOPCOUNT-(@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)                                                             
                --MANOJ 07 02 2010 BatchId added                                           
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,                                    
 priority,BATCHID,Operator FROM  dbo.MessageQueueCritical WHERE  PRIORITY=0 and SmppID=2  and U_ID<>24502                             
 --and ltrim(rtrim(senderid)) not in (select ltrim(rtrim(f1)) from AirtelSenderID)                                   
 order by convert(datetime,messageinsertdate,100)                                    
 END                                                          
END                       
--select * into _tmpsmsdata from  @TEMPTABLE                                       
 DELETE MessageQueueCritical FROM MessageQueueCritical MQ JOIN @TEMPTABLE TT ON MQ.MESSAGEID=TT.MESSAGEID                                            
  
select distinct b.batchid,isnull(b.isflash,0) isflash into #isflash from batchinfo b join @TEMPTABLE t  
on b.BatchID=t.BATCHID  


         --MANOJ 07 02 2010 BatchId added                                                 
SELECT right(t.MessageID,9) UserTag,t.MessageId,'91' + rtrim(ltrim(t.Mobile)) as Mobile,case when longurl is not null then rtrim(ltrim(REPLACE(message,longurl, shorturl+'/'+Final_url))) else [message] end As [Message]  ,rtrim(ltrim(SenderID))                                      
As SenderID,U_ID,IsUnicode,priority,t.BATCHID,Operator,isnull(f.isflash,0) isflash  FROM @TEMPTABLE t   
left join #isflash f on f.BatchID=t.BATCHID    
left join 
(select longurl,final_url,shorturl,batchid,messageid,mobile from Link_smsMobile (nolock))
lm on lm.mobile= t.mobile and lm.batchid = t.BatchID

  
drop table #isflash  
                                                         
                                      
END 



GO

