SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


          
CREATE   PROC [dbo].[USP_MoveMessageFromCriticalQueueToRoute_SPICE_New_k_all]
(                                                                          
@TOTALCOUNT INT =200,                                                      
@div int=null             
)                                                                          
AS                                     
--VF-1,SPICE-2,DEMO:PROMOSPICE-4,TRANSSPICE-5,TRCSPICE-6,PROMOVF-7,TRANSVF-8,TRCVF-9
--1) SELECT TOP GIVEN NO OF HIGH PRIORITIES MESSAGES
BEGIN     
    
set @TOTALCOUNT=100           
SET NOCOUNT ON                                                                                                                
DECLARE @TOPCOUNT INT                                                                                                                
DECLARE @RESTCOUNTAFTERDirect INT                                                                                                               
DECLARE @RESTCOUNTAFTERPriority  INT                                                                                                            
SET @TOPCOUNT = @TOTALCOUNT                                                                                                                
                                                                              
--DELETE MessageQueueCritical where mobile=''                                                                                    
--Delete T from                                                                                    
