Totalprocessed+counted>=(TotalRecords+counted -isnull(InvalidCount,0)) and BatchProcessComplete is null then GETDATE() else null end                                                                                       
from openquery([192.168.10.3],''select * from mysms.dbo.batchinfo with (nolock)       
where batchprocesscomplete is null and batchid>='+cast(@minbatchid as nvarchar)+''') b join              
(select COUNT(mq.messageid) counted,tt.batchid from MessageQueueCritical mq  with (nolock)                                      
join Messagesent TT  with (nolock) ON MQ.messageID=TT.messageID and messagetable=''MessageQueueCritical'' and IsProcessed =1 group by tt.batchid) A on A.batchid=b.batchid                                                                  
where BatchProcessComplete is null'      
      
print @q      
