IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                        
BEGIN                                              
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms     
GOTO RETRY1 -- Go to Label RETRY                                              
END                                  
END CATCH                                          
*/                    
 delete from MessageQueueCritical  where mobile LIKE '%[^0-9 ]%'  and (messagequeueid%4)=isnull(@div,(messagequeueid%4)) -- option(maxdop 4)

/*                                 
RETRY2:                                                                                       
BEGIN TRY                                                                                    
BEGIN TRAN                                          
update b set batchprocesscomplete=GETDATE() from [mysms].dbo.batchinfo b join Messagesent tt on tt.BatchID=b.BatchID where Totalprocessed>=(TotalRecords -isnull(InvalidCount,0)) and BatchProcessComplete is null                               
    
             
 COMMIT                                                                                    
END TRY                                                                                    
                                                         
BEGIN CATCH                                                                                                                                        
IF @@TRANCOUNT>0                                                                       
ROLLBACK                                                                                    
EXECUTE USP_INSERTERRORINFO;                                 
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                              
BEGIN                                              
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                              
GOTO RETRY2 -- Go to Label RETRY                                              
END                                                                                         
END CATCH                             
*/                                                 
if exists(select 1 from MessageQueueCritical MQ with (nolock) JOIN Messagesent TT with (nolock) ON MQ.MESSAGEID=TT.MESSAGEID and tt.messagetable='MessageQueueCritical' where IsProcessed= 1)                                          
begin                              
begin tran                                                   
delete mq from MessageQueueCritical MQ JOIN Messagesent TT ON MQ.MESSAGEID=TT.MESSAGEID and tt.messagetable='MessageQueueCritical' where IsProcessed= 1   and (messagequeueid%4)=isnull(@div,(messagequeueid%4))
 -- option(maxdop 4)
--update m  set isprocessed=0 from MessageQueueCritical m where   
--not exists(select 1 from messagesent ms with (nolock) where ms.messageid=m.messageid) and   
--isprocessed=1 and DATEDIFF(mi,m_processedat,getdate())>20  and (messagequeueid%4)=isnull(@div,(messagequeueid%4))                
     
           
--Update mq set IsProcessed =0  FROM MessageQueueCritical MQ where IsProcessed=1 and (messagequeueid%4)=0                                            
commit                                                        
end                            
/*                    
update m set priority=30 from messagequeuecritical m where priority<>30 and not exists (select 1 from mysms.dbo.DLTdetails d join mysms.dbo.user_detail with (nolock) u on u.parentid=d.parentid and m.u_id=u.User_ID)      
  */                                                                                
create table #TEMPTABLETRans                                                
(                                                                                                                
  MessageID BIGINT,                                                                                                                
  Mobile VARCHAR(20),                                                                                                                
  Message NVARCHAR(2500),                                                                                                              
  SenderID VARCHAR(50),               
  SmppID varchar(20) ,                                                 
  U_ID BIGINT,                                                                         
  IsUnicode bit,                                                                               
   priority tinyint ,                                   
BATCHID bigint,     --MANOJ 07 02 2010                                                                                          
Operator char(6)                                                        
)                                                     
create index ix_#temptabletrans_messageid on #temptabletrans(MessageID);                                 
--exec proc_insert_into_normal_from_q1                                                                               
--exec proc_insert_into_pri_from_q1                                                                                        
--exec proc_insert_into_dir_from_q1                                                                                              
          --MANOJ 07 02 2010 BatchId added                                                 
INSERT INTO #TEMPTABLETRans                               
SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,priority,
BATCHID,Operator FROM  dbo.MessageQueueCritical  with (nolock) WHERE  PRIORITY=2 and SmppID=2
 and (messagequeueid%4)=isnull(@div,(messagequeueid%4))                                                            
and isprocessed=0                                  
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)                                                                                
order by convert(datetime,messageinsertdate,100)
-- option(maxdop 4)

SET @RESTCOUNTAFTERDirect =@@ROWCOUNT  
                                                                                                                
IF (@RESTCOUNTAFTERDirect< @TOPCOUNT)                                                  
 BEGIN                                                                                                                
                                                                                                       
 INSERT INTO #TEMPTABLETRans                                               
 SELECT TOP(@TOPCOUNT-@RESTCOUNTAFTERDirect ) MessageID,Mobile,[Message],SenderID,SmppID,
 U_ID,IsUnicode,priority,BATCHID,Operator FROM  dbo.MessageQueueCritical  with (nolock) WHERE  PRIORITY=1 and SmppID=2
  and (messagequeueid%4)=isnull(@div,(messagequeueid%4))
 and isprocessed=0
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)                                                                                
 order by convert(datetime,messageinsertdate,100)
 -- option(maxdop 4)
                                                                                        
 SET @RESTCOUNTAFTERPriority =@@ROWCOUNT                                                                                                             
                                                                                                
                                                                                                            
 IF ((@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)< @TOPCOUNT)                              
 BEGIN                                                                                                            
   SET @TOPCOUNT = @TOPCOUNT-(@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)                                                                   
                --MANOJ 07 02 2010 BatchId added                                                                                 
 INSERT INTO #TEMPTABLETRans SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,                                      
 priority,BATCHID,Operator FROM  dbo.MessageQueueCritical  with (nolock) WHERE  PRIORITY=0 and SmppID=2            
  and (messagequeueid%4)=isnull(@div,(messagequeueid%4))                                                                                           
 and isprocessed=0                            
 --and ltrim(rtrim(senderid)) not in (select ltrim(rtrim(f1)) from AirtelSenderID)                                                   
 order by convert(datetime,messageinsertdate,100)
  -- option(maxdop 4)
 END                                                                   
END                                                
    
select distinct t.batchid,isnull(d.flash,0) isflash, isnull(left(d.DLT_TemplateID,50),'0') DLT_TemplateID,d.total_records--,d.dlt_is_stock      
into #isflash from #TEMPTABLETRans t   with (nolock)                                    
--left join mysms.dbo.DLT_Template_MSG d with (nolock) on d.BatchID=t.BatchID                                            
left join DLT_Template_MSG d with (nolock) on d.BatchID=t.BatchID                                            
 -- option(maxdop 4)

/*  
  select distinct t.batchid,0 isflash, '0' DLT_TemplateID,1 as total_records--,d.dlt_is_stock      
into #isflash from #TEMPTABLETRans t   with (nolock)                                    
--left join mysms.dbo.DLT_Template_MSG d with (nolock) on d.BatchID=t.BatchID                                            
*/  
--delete t from #TEMPTABLETRans t join #isflash f on d.batchid=t.batchid where dlt_is_stock=1    
    
                                            
RETRY:                                                                                       
BEGIN TRY                                               
BEGIN TRAN                                                                      
--select * into _tmpsmsdata from  @TEMPTABLE                                       
Update mq  set IsProcessed =1,m_processedat=getdate()  FROM MessageQueueCritical MQ JOIN #TEMPTABLETRans TT ON MQ.MESSAGEID=TT.MESSAGEID           
where (messagequeueid%4) =isnull(@div,(messagequeueid%4))
 -- option(maxdop 4)
--DELETE MessageQueueCritical FROM MessageQueueCritical MQ JOIN #TEMPTABLETRans TT ON MQ.MESSAGEID=TT.MESSAGEID                                                         
COMMIT                                                                     
END TRY                                                                                    
                                                         
BEGIN CATCH                                                                
IF @@TRANCOUNT>0                                                                       
ROLLBACK                                                                                    
EXECUTE USP_INSERTERRORINFO;                                               
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                              
BEGIN                                              
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                              
GOTO RETRY -- Go to Label RETRY                                              
END                                                                                         
END CATCH                                           
   
 /*  
select distinct u_id UserI,isnull(PE_ID,'') PE_ID,d.parentid,EntityName into #PE       
from mysms.dbo.DLTdetails d with (nolock) right join mysms.dbo.user_detail u with (nolock) on d.parentid=u.parentid       
and d.id=(select max(id) from mysms.dbo.DLTdetails with (nolock) where parentid=d.Parentid)      
join #TEMPTABLETRans t with (nolock) on t.u_id=u.user_id      
  
*/  
select distinct u_id UserI,isnull(left(PE_ID,100),'') PE_ID,d.parentid,EntityName into #PE       
from DLTdetails d with (nolock)  
--right join mysms.dbo.user_detail u with (nolock)     
right join user_detail u with (nolock)     
on d.parentid=u.parentid       
and d.id=(select max(id) from dbo.DLTdetails with (nolock) where parentid=d.Parentid)      
join #TEMPTABLETRans t with (nolock) on t.u_id=u.user_id      
 -- option(maxdop 4)
  
/*                                                                                  
  
select distinct u_id UserI,'' PE_ID,0 parentid,'' EntityName into #PE       
from  #TEMPTABLETRans t with (nolock)-- on t.u_id=u.user_id      
*/                                                                                  
  
      
/*      
select distinct message,null as allowed into #allowedtemplates from #TEMPTABLETRans t with (nolock) left join #PE p with (nolock)  on p.useri=t.U_ID where p.PE_ID =''      
declare @tbc int=(select count(1) from #allowedtemplates),@template nvarchar(2500)      
create table #matches(matches int)      
while @tbc >0      
begin      
select top 1 @template=message from #allowedtemplates where allowed is null      
insert into #matches      
exec mysms.dbo.usp_templateallowed @template      
update a set allowed=matches from  #allowedtemplates a join #matches m on 1=1 where a.Message=@template      
truncate table #matches      
set @tbc=@tbc-1      
end      
 */      
          
insert into batchprogress(batchid,totalrecords)      
select distinct batchid,total_records from #isflash i       
where not exists (select 1 from batchprogress(nolock) where batchid=i.batchid)      
 -- option(maxdop 4)

update b set totalprocessed=isnull(totalprocessed,0)+counted,      
batchcompletetime=case when isnull(totalprocessed,0)+counted>=totalrecords then getdate() else batchcompletetime end       
from batchprogress b join       
(select batchid,count(1) counted from #TEMPTABLETRans group by batchid) t      
on t.batchid=b.batchid       
  -- option(maxdop 4)                                
      
SELECT right(t.MessageID,9) UserTag,t.MessageId,'91' + rtrim(ltrim(t.Mobile)) as Mobile,           
replace(dbo.fn_getmessagewithshorturl_m(t.Message,t.batchid,t.mobile,t.MessageID),char(13),' ') As [Message],      
--case when a.allowed=1 then 'KITAPP' when rtrim(ltrim(SenderID))='TXTSMS' then 'CONECT' else rtrim(ltrim(SenderID)) end As SenderID,            
rtrim(ltrim(SenderID)) As SenderID,      
U_ID,IsUnicode,priority,t.BATCHID,Operator,isnull(f.isflash,0) isflash,      
--case when a.allowed=1 then '1701159108398939463' else isnull(PE_ID,'') end PE_ID,      
isnull(PE_ID,'') PE_ID,      
isnull(DLT_TemplateID,'0') DLT_TemplateID      
FROM #TEMPTABLETRans t with (nolock)                                                         
left join #isflash f with (nolock) on f.BatchID=t.BATCHID                                           
left join #PE p with (nolock) on p.useri=t.U_ID      
--left join #allowedtemplates a with (nolock) on a.Message=t.Message      
where PE_id <>'' and isnull(DLT_TemplateID,'0') <>'0'      
--or a.allowed=1      
 -- option(maxdop 4)
      
update m set priority=30 from MessageQueueCritical m join #TEMPTABLETRans t on t.MessageID=m.MessageID       
left join #isflash s on s.BatchID=m.BATCHID      
left join #PE p on p.UserI=m.U_ID      
where (m.priority<>30       
and (PE_ID='' or isnull(DLT_TemplateID,'0')='0'))      
--(not exists (select 1 from mysms.dbo.DLTdetails d join mysms.dbo.user_detail u with (nolock) on u.parentid=d.parentid and m.u_id=u.User_ID)      
--or  a.allowed=0))       
 -- option(maxdop 4)
      
insert into smsbatchnotsent(batchid,PE_id,template_id,reason)      
select t.batchid,PE_id,DLT_TemplateID,case when PE_id='' then 'User DLT not available' else 'User TemplateId not available' end      
FROM #TEMPTABLETRans t  with (nolock)                                                        
left join #isflash f with (nolock) on f.BatchID=t.BATCHID                                           
left join #PE p with (nolock) on p.useri=t.U_ID      
where PE_id ='' or isnull(DLT_TemplateID,'0')='0'      
and not exists(select 1 from smsbatchnotsent with (nolock) where batchid=t.batchid)      
 -- option(maxdop 4)
      
insert into InvalidMessageQueuecritical(MessageQueuecriticalID,MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent,isprocessed,IsFlash)        
select MessageQueueID,MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent,isprocessed,IsFlash from messagequeuecritical with (nolock) where (priority>2)-- or isdnd=1)       
 -- option(maxdop 4)

delete from messagequeuecritical  where (priority>2) and MessageQueueID%4=isnull( @div,MessageQueueID%4) -- option(maxdop 4)
                                                         
--drop table #allowedtemplates      
--drop table #matches       
                                                         
drop table #PE                                          
drop table #isflash                                                        
drop table #TEMPTABLETRans                                                                                                                     
                    
                                                                                        
                                               
END   



GO

/* ============================================================
   Procedure: [dbo].[USP_MoveMessageFromQueueDND]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Created on 11Th Nov 2010      
--Added by Pawan Kumar      
CREATE   PROC [dbo].[USP_MoveMessageFromQueueDND]                                        
(                                        
@TOTALCOUNT INT =50                                  
)                                        
AS                                        
--1) SELECT TOP GIVEN NO OF HIGH PRIORITIES MESSAGES                                        
BEGIN                                      
SET NOCOUNT ON                                      
DECLARE @TOPCOUNT INT                                      
DECLARE @RESTCOUNTAFTERDirect INT                                     
DECLARE @RESTCOUNTAFTERPriority  INT                                  
SET @TOPCOUNT = @TOTALCOUNT                                      
   
--exec USP_MOVE_QUEUE_TO_DNDQUEUE                                     
          
Delete T from          
(          
select row_number() over(partition by MessageID order by MessageID) as row_number, * from MessageQueueDND          
) T          
where row_number > 1          
          
DECLARE @TEMPTABLE TABLE                                      
(                                      
  MessageID BIGINT,                                      
  Mobile VARCHAR(20),                                      
  Message NVARCHAR(4000),                                    
  SenderID VARCHAR(50),                                    
  SmppID varchar(20) ,                                    
  U_ID BIGINT,                                  
  IsUnicode bit,                                   
   priority tinyint ,                      
BATCHID bigint,     --MANOJ 07 02 2010                
Operator char(6)                            
)               
          --MANOJ 07 02 2010 BatchId added                            
INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,priority,BATCHID,Operator FROM  dbo.MessageQueueDND WHERE  PRIORITY=1           
order by convert(datetime,messageinsertdate,100)            
SET @RESTCOUNTAFTERDirect =@@ROWCOUNT                                      
                                      
IF (@RESTCOUNTAFTERDirect< @TOPCOUNT)                                      
 BEGIN                                      
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT-@RESTCOUNTAFTERDirect ) MessageID,Mobile,[Message],SenderID,SmppID, U_ID,IsUnicode,priority,BATCHID,Operator FROM  dbo.MessageQueueDND WHERE  PRIORITY=0    
 order by convert(datetime,messageinsertdate,100)              
END               
DELETE MessageQueueDND FROM MessageQueueDND MQ JOIN @TEMPTABLE TT ON MQ.MESSAGEID=TT.MESSAGEID                        --MANOJ 07 02 2010 BatchId added                         
SELECT MessageID,'91' + rtrim(ltrim(Mobile)) as Mobile,rtrim(ltrim([Message])) As [Message] ,rtrim(ltrim(SenderID)) As SenderID,U_ID,IsUnicode,priority,BATCHID,Operator  FROM @TEMPTABLE               
END 


GO

/* ============================================================
   Procedure: [dbo].[USP_MoveMessageFromQueueToCritical]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
CREATE   PROC [dbo].[USP_MoveMessageFromQueueToCritical]                                  
(                                  
@TOTALCOUNT INT =50                          
)                                  
AS                                  
--1) SELECT TOP GIVEN NO OF HIGH PRIORITIES MESSAGES                                  
BEGIN                                
SET NOCOUNT ON                                
DECLARE @TOPCOUNT INT                                
DECLARE @RESTCOUNTAFTERDirect INT                               
DECLARE @RESTCOUNTAFTERPriority  INT                            
SET @TOPCOUNT = @TOTALCOUNT                                
    
--Delete T from    
--(select row_number() over(partition by MessageID order by MessageID) as row_number, * from MessageQueueCritical) T    
--where row_number > 1    
DECLARE @TEMPTABLE TABLE                                
(                                
  MessageID BIGINT,                                
  Mobile VARCHAR(20),                                
  Message NVARCHAR(4000),                              
  SenderID VARCHAR(50),                              
  SmppID varchar(20) ,                              
  U_ID BIGINT,                            
  IsUnicode bit,                             
   priority tinyint ,                
BATCHID bigint,     --MANOJ 07 02 2010          
Operator char(6)                      
)         
--exec proc_insert_into_normal_from_q1          
--exec proc_insert_into_pri_from_q1        
--exec proc_insert_into_dir_from_q1              
          --MANOJ 07 02 2010 BatchId added                      
INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,priority,      
BATCHID,Operator FROM  dbo.MessageQueueCritical WHERE  PRIORITY=2 --and IsUnicode=0    
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)       
order by convert(datetime,messageinsertdate,100)      
SET @RESTCOUNTAFTERDirect =@@ROWCOUNT                                
                                
IF (@RESTCOUNTAFTERDirect< @TOPCOUNT)                                
 BEGIN                                
                                
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT-@RESTCOUNTAFTERDirect ) MessageID,Mobile,[Message],SenderID,SmppID,      
 U_ID,IsUnicode,priority,BATCHID,Operator FROM  dbo.MessageQueueCritical WHERE  PRIORITY=1 --and IsUnicode=0      
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)     
 order by convert(datetime,messageinsertdate,100)        
        
     SET @RESTCOUNTAFTERPriority =@@ROWCOUNT                             
                                
                            
 IF ((@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)< @TOPCOUNT)                               
  BEGIN                            
   SET @TOPCOUNT = @TOPCOUNT-(@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)                               
                --MANOJ 07 02 2010 BatchId added                
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,      
 priority,BATCHID,Operator FROM  dbo.MessageQueueCritical WHERE  PRIORITY=0   
 --and ltrim(rtrim(senderid)) not in (select ltrim(rtrim(f1)) from AirtelSenderID)     
 order by convert(datetime,messageinsertdate,100)      
 END                            
END         
   DELETE MessageQueueCritical FROM MessageQueueCritical MQ JOIN @TEMPTABLE TT ON MQ.MESSAGEID=TT.MESSAGEID              
         
         --MANOJ 07 02 2010 BatchId added                   
SELECT right(MessageID,6) UserTag,MessageId,'91' + rtrim(ltrim(Mobile)) as Mobile,rtrim(ltrim([Message])) As [Message] ,rtrim(ltrim(SenderID))        
As SenderID,U_ID,IsUnicode,priority,BATCHID,Operator  FROM @TEMPTABLE         
        
END           
    
    


GO

/* ============================================================
   Procedure: [dbo].[USP_MoveMessageFromQueueToCriticalRoute_XML_Urgent_WHLSync]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_MoveMessageFromQueueToCriticalRoute_XML_Urgent_WHLSync] --400,1                                                                        
(                                                                                                                                                          
 @TOPCOUNT INT = 5000,                
 @alphacode nvarchar(10), 
 @Mode int 
)                                                                                                                                                          
AS                                                                                                                                 
BEGIN        
--declare @TOPCOUNT INT = 5000,                
--@alphacode nvarchar(10)                                                                                                                                                   
      set @TOPCOUNT = 3000
SET NOCOUNT ON        
begin try     
    
/*    
CREATE TABLE #TempToDelete (    
    MessageID BIGINT    
);    
    
    
INSERT INTO #TempToDelete (MessageID)    
SELECT MessageID    
FROM MessageQueueCritical    
WHERE (mobile LIKE '%[^0-9 ]%' OR LEN(LTRIM(RTRIM(mobile))) <> 10)    
  AND SenderID LIKE @alphacode + '%';    
    
    
DELETE m    
FROM MessageQueueCritical m    
JOIN #TempToDelete t ON m.MessageID = t.MessageID;    
    
-- Drop the temporary table    
DROP TABLE #TempToDelete;    
*/    
    
DECLARE @BatchSize INT = 100;    
DECLARE @RowsDeleted INT = 1;    
WHILE @RowsDeleted > 0    
BEGIN    
DELETE TOP (@BatchSize) FROM [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical WITH (ROWLOCK) WHERE  MessageQueueID%6 = @Mode and  mysms.dbo.ufn_getuserparentid(u_id)=31894 and (mobile LIKE '%[^0-9 ]%' OR LEN(LTRIM(RTRIM(mobile))) <> 10)    
AND SenderID LIKE @alphacode + '%';    
SET @RowsDeleted = @@ROWCOUNT;    
END    
    
  declare @m_count int=(select count(1) from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical with(nolock) where MessageInsertDate<dateadd(d,-1,getdate()))
  while @m_count>0
   begin
     delete m from (select top 1000 * from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical with(nolock) where MessageInsertDate<dateadd(d,-1,getdate())) m
     set @m_count=@m_count-1000
  end 
	     

    
--delete from MessageQueueCritical  where (mobile LIKE '%[^0-9 ]%' or len(ltrim(rtrim(mobile)))<>10)       
-- and SenderID like @alphacode+'%'      
--option(maxdop 4) --in (2,3)                                                                                     
                
declare @senderid nvarchar(10) ,@DLT_TemplateID nvarchar(50),@isflash int , @IsUnicode bit   --,@is_stock int      
      
  update m set isprocessed =0 from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical as m with(nolock) where m.MessageQueueID%6 = @Mode and  m.U_ID=31894 and  isprocessed=1 and m_processedat<dateadd(mi,-10,getdate()) and messageinsertdate>=datediff(hh,-6,getdate()) and senderid like @alphacode+'%'     
   and not exists (select 1 from MSG_XMLAPI_Resp(nolock) where corelationid=m.messageid)     
     
select top 1 @senderid=senderid,@isflash=isnull(d.flash,0),@DLT_TemplateID= isnull(left(d.DLT_TemplateID,50),'0') , @IsUnicode = isnull(t.IsUniCode, 0)     
from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical as t with(nolock)                                                                 
 join mysms.dbo.DLT_Template_MSG d with (nolock) on d.BatchID=t.BatchID       
where t.Priority < 3 and t.MessageQueueID%6 = @Mode and mysms.dbo.ufn_getuserparentid(t.U_ID)=31894 and   SenderID like @alphacode+'%' and isnull(left(d.DLT_TemplateID,50),'0') <> '0'  and len(d.DLT_TemplateID)=19 and t.isprocessed = 0      
group by  senderid,isnull(d.flash,0),mysms.dbo.ufn_getuserparentid(t.u_id),       
isnull(left(d.DLT_TemplateID,50),'0') ,isnull(t.IsUniCode, 0)   order by count(1) desc           
option(maxdop 4)         
      
if 1=1      
begin      
DECLARE @TEMPTABLETRans TABLE                                                          
(                                                                                                    
  MessageID BIGINT,                                                                                                                                                                
  Mobile VARCHAR(20),                                                      
  Message NVARCHAR(2500),                                                                                                                                                                  
  SenderID VARCHAR(50),                                         
  SmppID varchar(20) ,                                        
  U_ID BIGINT,                                                                                                                                                                
  IsUnicode bit,                                                                                       
   priority tinyint ,                                                                 
BATCHID bigint,     --MANOJ 07 02 2010                                              
Operator char(6),      
isflash int,      
DLT_TemplateID nvarchar(50)      
)                                                                                                         
--create index ix_#temptabletrans_messageid on #temptabletrans(MessageID);                          
      
INSERT INTO @TEMPTABLETRans (MessageID,Mobile,Message,SenderID,SmppID,U_ID,IsUnicode,priority,BATCHID,Operator,isflash,DLT_TemplateID)              
SELECT TOP(@TOPCOUNT) MessageID,Mobile,  REPLACE(    
         case when t.IsUniCode = 0    
           then  REPLACE(REPLACE([Message],char(146),char(39)),char(145),char(39))    
        else    
           [Message]    
                          end    
       ,char(150),char(45)) as [Message],SenderID,SmppID,mysms.dbo.ufn_getuserparentid(t.u_id),IsUnicode,priority,t.BATCHID,Operator,@isflash,@DLT_TemplateID             
FROM  [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical as t with (nolock) join mysms.dbo.DLT_Template_MSG d with (nolock) on t.BatchID=d.BatchID where t.Priority < 3 and t.MessageQueueID%6 = @Mode and mysms.dbo.ufn_getuserparentid(t.U_ID) = 31894 and SenderID=@senderid      
and d.DLT_TemplateID=@DLT_TemplateID and isprocessed=0  and t.IsUniCode = @IsUnicode    
order by messageinsertdate-- convert(datetime,messageinsertdate,100)        
option(maxdop 4)        
            
RETRY:                                                                                                                                           
BEGIN TRY                                                                                                                           
BEGIN TRAN                                                                                                        
Update mq   set IsProcessed =1,m_processedat=getdate()  FROM [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical as MQ with(nolock) JOIN @TEMPTABLETRans TT ON MQ.MESSAGEID=TT.MESSAGEID             
 option(maxdop 4)        
COMMIT                                                     
END TRY                                                                                                                                        
                                                                                              
BEGIN CATCH                                                                             
IF @@TRANCOUNT>0                                                                                                                                        
ROLLBACK                                                                                         
EXECUTE USP_INSERTERRORINFO;                                                                                                   
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                                                                                  
BEGIN                                                                       
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                                                                                  
GOTO RETRY -- Go to Label RETRY                                                                                                  
END                                                                      
END CATCH                                                                                               
              
select distinct mysms.dbo.ufn_getuserparentid(t.u_id) UserI,isnull(left(PE_ID,100),'') PE_ID,d.parentid,EntityName into #PE                 
from mysms.dbo.DLTdetails d with (nolock)             
right join mysms.dbo.user_detail u with (nolock)          
--right join user_detail u with (nolock)               
on d.parentid=u.parentid                 
and d.id=(select max(id) from mysms.dbo.DLTdetails with (nolock) where parentid=d.Parentid)                
join @TEMPTABLETRans t  on mysms.dbo.ufn_getuserparentid(t.u_id)= mysms.dbo.ufn_getuserparentid(u.user_id)                
            
              
insert into [10.0.0.135].[MysmsTrans].[dbo].batchprogress(batchid,totalrecords)              
select distinct batchid,count(1) from @TEMPTABLETRans i               
where not exists (select 1 from [10.0.0.135].[MysmsTrans].[dbo].batchprogress with(nolock) where batchid=i.batchid)  group by batchid            
option(maxdop 4)        
              
update b  set totalprocessed=isnull(totalprocessed,0)+counted,              
batchcompletetime=case when isnull(totalprocessed,0)+counted>=totalrecords then getdate() else batchcompletetime end               
from [10.0.0.135].[MysmsTrans].[dbo].batchprogress as b with(nolock) join               
(select batchid,count(1) counted from @TEMPTABLETRans group by batchid) t              
on t.batchid=b.batchid              
option(maxdop 4)             
                                            
                
SELECT right(t.MessageID,9) UserTag,t.MessageId,'91' + rtrim(ltrim(t.Mobile)) as Mobile,                                         
  
  Replace(replace(dbo.fn_getmessagewithshorturl_m(t.Message,t.batchid,t.mobile,t.MessageID),char(13),' '),'{#var#}','')
  
   As [Message],                
case --when a.allowed=1 then 'KITKIT'               
when rtrim(ltrim(SenderID))='TXTSMS' then 'CONECT' else rtrim(ltrim(SenderID)) end As       
SenderID,                      

 U_ID,
  --IsUnicode
  --(
  --  case when isnull(t.Message,'') != cast(isnull(t.Message,'') as varchar(2500))
	 --    then 1
		-- else 0
		-- end
  --) as IsUnicode
  dbo.fn_IsUnicode(t.Message) as IsUnicode 
,priority,t.BATCHID,Operator,isnull(isflash,0) isflash                
,isnull(PE_ID,'') PE_ID,isnull(DLT_TemplateID,'0') DLT_TemplateID                
FROM @TEMPTABLETRans t                                                                   
left join #PE p on mysms.dbo.ufn_getuserparentid(p.useri)=mysms.dbo.ufn_getuserparentid(t.U_ID)                
--left join #allowedtemplates a on a.Message=t.Message                
where PE_id <>'' and isnull(DLT_TemplateID,'0')<>'0'                
--or a.allowed=1                
 option(maxdop 4)              
 /*             
update m  set priority=30 from MessageQueueCritical m join #TEMPTABLETRans t on t.MessageID=m.MessageID                 
left join #PE p on p.UserI=t.U_ID                
where (m.priority<>30               
and (PE_ID='' or isnull(DLT_TemplateID,'0')='0'))                
 option(maxdop 4)                
   */        
update m  set priority=30 from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical as m with(nolock)    
 join mysms.dbo.DLT_Template_MSG d with (nolock) on d.BatchID=m.BatchID       
 join #PE p on mysms.dbo.ufn_getuserparentid(p.UserI)=mysms.dbo.ufn_getuserparentid(m.U_ID)                
where   m.MessageQueueID%6 = @Mode and  mysms.dbo.ufn_getuserparentid(m.U_ID)=31894 and  (m.priority<>30               
and (PE_ID='' or isnull(DLT_TemplateID,'0')='0') or len(DLT_templateid)>19  )  and m.senderid like @alphacode+'%'              
 option(maxdop 4)          
    
    
insert into [10.0.0.135].[MysmsTrans].[dbo].smsbatchnotsent(batchid,PE_id,template_id,reason)                
select t.batchid,PE_id,DLT_TemplateID,case when PE_id='' then 'User DLT not available' else 'User TemplateId not available' end                
FROM @TEMPTABLETRans t                                                                   
left join #PE p on mysms.dbo.ufn_getuserparentid(p.useri)= mysms.dbo.ufn_getuserparentid(t.U_ID)                
where PE_id ='' or isnull(DLT_TemplateID,'0')='0'                
and not exists(select 1 from [10.0.0.135].[MysmsTrans].[dbo].smsbatchnotsent with(nolock) where batchid=t.batchid)                
 option(maxdop 4)        
         
insert into [10.0.0.135].[MysmsTrans].[dbo].invalidMessageQueueCritical(MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent,isprocessed,                  
IsFlash)                  
select MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,mysms.dbo.ufn_getuserparentid(u_id),IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent,isprocessed,                  
IsFlash from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical with(nolock) where  MessageQueueID%6 = @Mode and mysms.dbo.ufn_getuserparentid(u_id)=31894 and (priority>2 or isdnd=1) and SenderID like @alphacode+'%'      
 option(maxdop 4)        
      
select @RowsDeleted = 1;    
WHILE @RowsDeleted > 0    
BEGIN    
DELETE TOP (@BatchSize)     
            FROM [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical WITH (ROWLOCK)    
            WHERE MessageQueueID%6 = @Mode and  mysms.dbo.ufn_getuserparentid(u_id)=31894 and (priority>2 or isdnd=1)  and SenderID like @alphacode+'%' option(maxdop 4)                         
SET @RowsDeleted = @@ROWCOUNT;    
END      
    
                                                  
--drop table #allowedtemplates                
drop table if exists #matches                
                
                
                                  
drop table if exists #PE                                                    
drop table if exists #isflash                                                                  
--drop table if exists #TEMPTABLETRans                                                                                                                               
end      
      
end try                
begin catch                
exec usp_InsertErrorInfo                
end catch                
END                    
--alter table messagequeuenew alter column messagequeueid bigint        
      
      
--declare @a nvarchar(10)='[a-s]'      
--select top 10 * from MessageQueueNew(nolock) where senderid like @a+'%' 


GO

/* ============================================================
   Procedure: [dbo].[USP_MoveMessageFromQueueToCriticalRoute_XML_WHLSync]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_MoveMessageFromQueueToCriticalRoute_XML_WHLSync] --400,1                                                                        
(                                                                                                                                                          
@TOPCOUNT INT = 5000,                
@alphacode nvarchar(10)                                                                                                                                                   
)                                                                                                                                                          
AS                                                                                                                                 
BEGIN        
--declare @TOPCOUNT INT = 5000,                
--@alphacode nvarchar(10)                                                                                                                                                   
      set @TOPCOUNT = 3000
SET NOCOUNT ON        
begin try     
    
/*    
CREATE TABLE #TempToDelete (    
    MessageID BIGINT    
);    
    
    
INSERT INTO #TempToDelete (MessageID)    
SELECT MessageID    
FROM MessageQueueCritical    
WHERE (mobile LIKE '%[^0-9 ]%' OR LEN(LTRIM(RTRIM(mobile))) <> 10)    
  AND SenderID LIKE @alphacode + '%';    
    
    
DELETE m    
FROM MessageQueueCritical m    
JOIN #TempToDelete t ON m.MessageID = t.MessageID;    
    
-- Drop the temporary table    
DROP TABLE #TempToDelete;    
*/    
    
DECLARE @BatchSize INT = 100;    
DECLARE @RowsDeleted INT = 1;    
WHILE @RowsDeleted > 0    
BEGIN    
DELETE TOP (@BatchSize) FROM [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical WITH (ROWLOCK) WHERE u_id <> 31894 and (mobile LIKE '%[^0-9 ]%' OR LEN(LTRIM(RTRIM(mobile))) <> 10)    
AND SenderID LIKE @alphacode + '%';    
SET @RowsDeleted = @@ROWCOUNT;    
END    
    
    
    declare @m_count int=(select count(1) from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical with(nolock) where MessageInsertDate<dateadd(d,-1,getdate()))
  while @m_count>0
  begin
  delete m from (select top 1000 * from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical with(nolock) where MessageInsertDate<dateadd(d,-1,getdate())) m
  set @m_count=@m_count-1000
  end
    
--delete from MessageQueueCritical  where (mobile LIKE '%[^0-9 ]%' or len(ltrim(rtrim(mobile)))<>10)       
-- and SenderID like @alphacode+'%'      
--option(maxdop 4) --in (2,3)                                                                                     
                
declare @senderid nvarchar(10) ,@DLT_TemplateID nvarchar(50),@isflash int , @IsUnicode bit   --,@is_stock int      
      
  update m set isprocessed =0 from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical as m with(nolock) where m.u_id <> 31894 and isprocessed=1 and m_processedat<dateadd(mi,-10,getdate()) and messageinsertdate>=datediff(hh,-6,getdate()) and senderid like @alphacode+'%'     
   and not exists (select 1 from MSG_XMLAPI_Resp(nolock) where corelationid=m.messageid)     
     
select top 1 @senderid=senderid,@isflash=isnull(d.flash,0),@DLT_TemplateID= isnull(left(d.DLT_TemplateID,50),'0') , @IsUnicode = isnull(t.IsUniCode, 0)     
from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical as t with(nolock)                                                                 
 join mysms.dbo.DLT_Template_MSG d with (nolock) on d.BatchID=t.BatchID       
where  t.U_ID <> 31894 and  SenderID like @alphacode+'%' and isnull(left(d.DLT_TemplateID,50),'0') <> '0'  and len(d.DLT_TemplateID)=19 and t.isprocessed = 0      
group by  senderid,isnull(d.flash,0),mysms.dbo.ufn_getuserparentid(t.u_id),       
isnull(left(d.DLT_TemplateID,50),'0') ,isnull(t.IsUniCode, 0)   order by count(1) desc           
option(maxdop 4)         
      
if 1=1      
begin      
DECLARE @TEMPTABLETRans TABLE                                                          
(                                                                                                    
  MessageID BIGINT,                                                                                                                                                                
  Mobile VARCHAR(20),                                                      
  Message NVARCHAR(2500),                                                                                                                                                                  
  SenderID VARCHAR(50),                                         
  SmppID varchar(20) ,                                        
  U_ID BIGINT,                                                                                                                                                                
  IsUnicode bit,                                                                                       
   priority tinyint ,                                                                 
BATCHID bigint,     --MANOJ 07 02 2010                                              
Operator char(6),      
isflash int,      
DLT_TemplateID nvarchar(50)      
)                                                                                                         
--create index ix_#temptabletrans_messageid on #temptabletrans(MessageID);                          
      
INSERT INTO @TEMPTABLETRans (MessageID,Mobile,Message,SenderID,SmppID,U_ID,IsUnicode,priority,BATCHID,Operator,isflash,DLT_TemplateID)              
SELECT TOP(@TOPCOUNT) MessageID,Mobile,  REPLACE(    
         case when t.IsUniCode = 0    
           then  REPLACE(REPLACE([Message],char(146),char(39)),char(145),char(39))    
        else    
           [Message]    
                          end    
       ,char(150),char(45)) as [Message],SenderID,SmppID,mysms.dbo.ufn_getuserparentid(t.u_id),IsUnicode,priority,t.BATCHID,Operator,@isflash,@DLT_TemplateID             
FROM  [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical as t with (nolock) join mysms.dbo.DLT_Template_MSG d with (nolock) on t.BatchID=d.BatchID where t.U_ID <> 31894 and SenderID=@senderid      
and d.DLT_TemplateID=@DLT_TemplateID and isprocessed=0  and t.IsUniCode = @IsUnicode    
order by messageinsertdate-- convert(datetime,messageinsertdate,100)        
option(maxdop 4)        
            
RETRY:                                                                                                                                           
BEGIN TRY                                                                                                                           
BEGIN TRAN                                                                                                        
Update mq   set IsProcessed =1,m_processedat=getdate()  FROM [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical as MQ with(nolock) JOIN @TEMPTABLETRans TT ON MQ.MESSAGEID=TT.MESSAGEID             
 option(maxdop 4)        
COMMIT                                                     
END TRY                                                                                                                                        
                                                                                              
BEGIN CATCH                                                                             
IF @@TRANCOUNT>0                                                                                                                                        
ROLLBACK                                                                                         
EXECUTE USP_INSERTERRORINFO;                                                                                                   
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                                                                                  
BEGIN                                                                       
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                                                                                  
GOTO RETRY -- Go to Label RETRY                                                                                                  
END                                                                      
END CATCH                                                                                               
              
select distinct mysms.dbo.ufn_getuserparentid(t.u_id) UserI,isnull(left(PE_ID,100),'') PE_ID,d.parentid,EntityName into #PE                 
from mysms.dbo.DLTdetails d with (nolock)             
right join mysms.dbo.user_detail u with (nolock)          
--right join user_detail u with (nolock)               
on d.parentid=u.parentid                 
and d.id=(select max(id) from mysms.dbo.DLTdetails with (nolock) where parentid=d.Parentid)                
join @TEMPTABLETRans t  on t.u_id=u.user_id                
            
              
insert into [10.0.0.135].[MysmsTrans].[dbo].batchprogress(batchid,totalrecords)              
select distinct batchid,count(1) from @TEMPTABLETRans i               
where not exists (select 1 from [10.0.0.135].[MysmsTrans].[dbo].batchprogress with(nolock) where batchid=i.batchid)  group by batchid            
option(maxdop 4)        
              
update b  set totalprocessed=isnull(totalprocessed,0)+counted,              
batchcompletetime=case when isnull(totalprocessed,0)+counted>=totalrecords then getdate() else batchcompletetime end               
from [10.0.0.135].[MysmsTrans].[dbo].batchprogress as b with(nolock) join               
(select batchid,count(1) counted from @TEMPTABLETRans group by batchid) t              
on t.batchid=b.batchid              
option(maxdop 4)             
                                            
                
SELECT right(t.MessageID,9) UserTag,t.MessageId,'91' + rtrim(ltrim(t.Mobile)) as Mobile,                                         

   Replace(replace(dbo.fn_getmessagewithshorturl_m(t.Message,t.batchid,t.mobile,t.MessageID),char(13),' '),'{#var#}','')

   As [Message],                
case --when a.allowed=1 then 'KITKIT'               
when rtrim(ltrim(SenderID))='TXTSMS' then 'CONECT' else rtrim(ltrim(SenderID)) end As       
SenderID,                      
U_ID,
 /* (
    case when isnull(t.Message,'') != cast(isnull(t.Message,'') as varchar(2500))
	     then 1
		 else 0
		 end
  ) as IsUnicode
  */
 dbo.fn_IsUnicode(t.Message) as IsUnicode 
,priority,t.BATCHID,Operator,isnull(isflash,0) isflash                
,isnull(PE_ID,'') PE_ID,isnull(DLT_TemplateID,'0') DLT_TemplateID                
FROM @TEMPTABLETRans t                                                                   
left join #PE p on p.useri=t.U_ID                
--left join #allowedtemplates a on a.Message=t.Message                
where PE_id <>'' and isnull(DLT_TemplateID,'0')<>'0'                
--or a.allowed=1                
 option(maxdop 4)              
 /*             
update m  set priority=30 from MessageQueueCritical m join #TEMPTABLETRans t on t.MessageID=m.MessageID                 
left join #PE p on p.UserI=t.U_ID                
where (m.priority<>30               
and (PE_ID='' or isnull(DLT_TemplateID,'0')='0'))                
 option(maxdop 4)                
   */        
update m  set priority=30 from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical as m with(nolock)    
 join mysms.dbo.DLT_Template_MSG d with (nolock) on d.BatchID=m.BatchID       
 join #PE p on p.UserI=m.U_ID                
where m.U_ID <> 31894 and (m.priority<>30               
and (PE_ID='' or isnull(DLT_TemplateID,'0')='0') or len(DLT_templateid)>19  )  and m.senderid like @alphacode+'%'              
 option(maxdop 4)          
    
    
insert into [10.0.0.135].[MysmsTrans].[dbo].smsbatchnotsent(batchid,PE_id,template_id,reason)                
select t.batchid,PE_id,DLT_TemplateID,case when PE_id='' then 'User DLT not available' else 'User TemplateId not available' end                
FROM @TEMPTABLETRans t                                                                   
left join #PE p on p.useri=t.U_ID                
where PE_id ='' or isnull(DLT_TemplateID,'0')='0'                
and not exists(select 1 from [10.0.0.135].[MysmsTrans].[dbo].smsbatchnotsent with(nolock) where batchid=t.batchid)                
 option(maxdop 4)        
         
insert into [10.0.0.135].[MysmsTrans].[dbo].invalidMessageQueueCritical(MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent,isprocessed,                  
IsFlash)                  
select MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,mysms.dbo.ufn_getuserparentid(u_id),IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent,isprocessed,                  
IsFlash from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical with (nolock) where u_id <> 31894 and (priority>2 or isdnd=1) and SenderID like @alphacode+'%'      
 option(maxdop 4)        
      
select @RowsDeleted = 1;    
WHILE @RowsDeleted > 0    
BEGIN    
DELETE TOP (@BatchSize)     
            FROM [10.0.0.135].[MysmsTrans].[dbo].MessageQueueCritical WITH (ROWLOCK)    
            WHERE u_id <> 31894 and  (priority>2 or isdnd=1)  and SenderID like @alphacode+'%' option(maxdop 4)                         
SET @RowsDeleted = @@ROWCOUNT;    
END      
    
                                                  
--drop table #allowedtemplates                
drop table if exists #matches                
                
                
                                  
drop table if exists #PE                                                    
drop table if exists #isflash                                                                  
--drop table if exists #TEMPTABLETRans                                                                                                                               
end      
      
end try                
begin catch                
exec usp_InsertErrorInfo                
end catch                
END                    
--alter table messagequeuenew alter column messagequeueid bigint        
      
      
--declare @a nvarchar(10)='[a-s]'      
--select top 10 * from MessageQueueNew(nolock) where senderid like @a+'%' 


