/* ============================================================
   Procedure: [dbo].[USP_MoveMessageFromQueueToDemo_TRANS]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_MoveMessageFromQueueToDemo_TRANS]                                    
(                                    
@TOTALCOUNT INT =200                              
)                                    
AS            
--VF-1,SPICE-2,DEMO:PROMOSPICE-4,TRANSSPICE-5,TRCSPICE-6,PROMOVF-7,TRANSVF-8,TRCVF-9                        
--1) SELECT TOP GIVEN NO OF HIGH PRIORITIES MESSAGES                                    
BEGIN                                  
SET NOCOUNT ON                                  
DECLARE @TOPCOUNT INT                                  
DECLARE @RESTCOUNTAFTERDirect INT                                 
DECLARE @RESTCOUNTAFTERPriority  INT                              
SET @TOPCOUNT = @TOTALCOUNT                                  
                                  
DECLARE @TEMPTABLE TABLE                                  
(                                  
  MessageID BIGINT,                                  
  Mobile VARCHAR(20),                                  
  Message NVARCHAR(4000),                                
  SenderID VARCHAR(50),                                
  SmppID varchar(20) ,                                
  U_ID BIGINT,                              
  IsUnicode bit,                               
   priority tinyint ,                  
BATCHID bigint,          
Operator char(6)     --MANOJ 07 02 2010                          
)                                  
  --exec proc_insert_into_air2          
  --exec proc_insert_into_mq1from2          
          --MANOJ 07 02 2010 BATCHID,Operator added                        
INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,priority,          
BATCHID,Operator FROM  dbo.MESSAGEQUEUEDEMO_TRANS WHERE  PRIORITY=2 and SmppID=8       
order by convert(datetime,messageinsertdate,100)         
                                  
SET @RESTCOUNTAFTERDirect =@@ROWCOUNT              
                                  
IF (@RESTCOUNTAFTERDirect< @TOPCOUNT)                                  
 BEGIN                                  
                                  
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT-@RESTCOUNTAFTERDirect ) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,          
 IsUnicode,priority,BATCHID,Operator FROM  dbo.MESSAGEQUEUEDEMO_TRANS WHERE  PRIORITY=1 and SmppID=8       
 order by convert(datetime,messageinsertdate,100)         
     SET @RESTCOUNTAFTERPriority =@@ROWCOUNT                               
                          
 IF ((@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)< @TOPCOUNT)                                 
  BEGIN                              
   SET @TOPCOUNT = @TOPCOUNT-(@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)                                 
                --MANOJ 07 02 2010 BATCHID,Operator added                  
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,priority,          
 BATCHID,Operator FROM  dbo.MESSAGEQUEUEDEMO_TRANS WHERE  PRIORITY=0 and SmppID=8       
 order by convert(datetime,messageinsertdate,100)         
                                   
 END            
                            
END           
   DELETE MESSAGEQUEUEDEMO_TRANS FROM MESSAGEQUEUEDEMO_TRANS MQ JOIN @TEMPTABLE TT ON MQ.MESSAGEID=TT.MESSAGEID                
                            
         --MANOJ 07 02 2010 BATCHID,Operator added                     
SELECT right(MessageID,6) UserTag,MessageID,'91' + rtrim(ltrim(Mobile)) as Mobile,rtrim(ltrim([Message])) As [Message] ,rtrim(ltrim(SenderID))          
As SenderID,U_ID,IsUnicode,priority,BATCHID,Operator  FROM @TEMPTABLE           
          
END             


GO

