SET @RESTCOUNTAFTERDirect =@@ROWCOUNT                      
                                          
IF (@RESTCOUNTAFTERDirect< @TOPCOUNT)                                          
 BEGIN                                          
                                          
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT-@RESTCOUNTAFTERDirect ) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,                  
 IsUnicode,priority,BATCHID,Operator FROM  dbo.MESSAGEQUEUEDEMO_TRANS WHERE  PRIORITY=1 and SmppID=5               
 order by convert(datetime,messageinsertdate,100)                 
     SET @RESTCOUNTAFTERPriority =@@ROWCOUNT                                       
                                  
