   DELETE MESSAGEQUEUEDEMO_TRANS FROM MESSAGEQUEUEDEMO_TRANS MQ JOIN @TEMPTABLE TT ON MQ.MESSAGEID=TT.MESSAGEID                        
   
   
         --MANOJ 07 02 2010 BATCHID,Operator added                             
select distinct b.batchid,isnull(b.isflash,0) isflash into #isflash from batchinfo b (nolock) join @TEMPTABLE t  
on b.BatchID=t.BATCHID  
         --MANOJ 07 02 2010 BatchId added                         
SELECT right(t.MessageID,6) UserTag,t.MessageID,'91' + rtrim(ltrim(t.Mobile)) as Mobile,case when longurl is not null then rtrim(ltrim(REPLACE(message,longurl, shorturl+'/'+Final_url))) else [message] end As [Message]  ,rtrim(ltrim(SenderID))              
As SenderID,U_ID,IsUnicode,priority,t.BATCHID,Operator,isnull(f.isflash,0) isflash  FROM @TEMPTABLE t   
left join #isflash f on f.BatchID=t.BATCHID  
left join 
(select longurl,final_url,shorturl,batchid,messageid,mobile from Link_smsMobile (nolock))
lm on lm.mobile= t.mobile and lm.batchid = t.BatchID  
  
drop table #isflash                   
                  
END 


