/* ============================================================
   Procedure: [dbo].[USP_MoveMessageFromQueueToPromotionRoute_XML_WHLSync]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_MoveMessageFromQueueToPromotionRoute_XML_WHLSync] --400,1                                                                          
(                                                                                                                                                            
@TOPCOUNT INT = 5000,                  
@alphacode nvarchar(10)                                                                                                                                                     
)                                                                                                                                                            
AS                                                                                                                                   
BEGIN          
--declare @TOPCOUNT INT = 5000,                  
--@alphacode nvarchar(10)                                                                                                                                                     
        
SET NOCOUNT ON          
begin try       
    
DECLARE @BatchSize INT = 100;    
DECLARE @RowsDeleted INT = 1;    
WHILE @RowsDeleted > 0    
BEGIN    
DELETE TOP (@BatchSize) FROM [10.0.0.135].[MysmsTrans].[dbo].MessageQueueProRoute WHERE (mobile LIKE '%[^0-9 ]%' OR LEN(LTRIM(RTRIM(mobile))) <> 10)    
AND SenderID LIKE @alphacode + '%';    
SET @RowsDeleted = @@ROWCOUNT;    
END    
    
    
  declare @m_count int=(select count(1) from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueProRoute with(nolock) where MessageInsertDate<dateadd(d,-1,getdate()))
  while @m_count>0
    begin
      delete m from (select top 1000 * from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueProRoute with(nolock) where MessageInsertDate<dateadd(d,-1,getdate())) m
      set @m_count=@m_count-1000
    end 


    
/*      
CREATE TABLE #TempToDelete (      
    MessageID BIGINT      
);      
      
      
INSERT INTO #TempToDelete (MessageID)      
SELECT MessageID      
FROM MessageQueueProRoute      
WHERE (mobile LIKE '%[^0-9 ]%' OR LEN(LTRIM(RTRIM(mobile))) <> 10)      
  AND ltrim(rtrim(senderid))    
    LIKE @alphacode + '%';      
      
      
DELETE m      
FROM MessageQueueProRoute m      
JOIN #TempToDelete t ON m.MessageID = t.MessageID;      
      
-- Drop the temporary table      
DROP TABLE #TempToDelete;      
*/      
      
      
--delete from MessageQueueProRoute  where (mobile LIKE '%[^0-9 ]%' or len(ltrim(rtrim(mobile)))<>10)         
-- and SenderID like @alphacode+'%'        
--option(maxdop 4) --in (2,3)                                                                                       
                  
declare @senderid nvarchar(10) ,@DLT_TemplateID nvarchar(50),@isflash int , @IsUnicode bit   --,@is_stock int        
        
 update m set isprocessed =0 from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueProRoute as m with(nolock) where isprocessed=1 and m_processedat<dateadd(mi,-10,getdate())  and messageinsertdate>=datediff(hh,-6,getdate()) and senderid like @alphacode+'%'       
and not exists (select 1 from MSG_XMLAPI_Resp(nolock) where corelationid=m.messageid)       
      
      
select top 1 @senderid=ltrim(rtrim(senderid)),@isflash=isnull(d.flash,0),@DLT_TemplateID= isnull(left(d.DLT_TemplateID,50),'0') , @IsUnicode = isnull(t.IsUniCode, 0)        
from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueProRoute as t with(nolock)                                                                    
 join mysms.dbo.DLT_Template_MSG d with (nolock) on d.BatchID=t.BatchID         
where SenderID like @alphacode+'%' and isnull(left(d.DLT_TemplateID,50),'0') <> '0' and len(d.DLT_TemplateID)=19 
and isprocessed=0
group by  senderid,isnull(d.flash,0),mysms.dbo.ufn_getuserparentid(u_id),         
isnull(left(d.DLT_TemplateID,50),'0'), isnull(t.IsUniCode, 0)  order by count(1) desc             
option(maxdop 4)           
        
if 1=1        
begin        
DECLARE @TEMPTABLETRans TABLE                                                          
(                                                                                                      
  MessageID BIGINT,                                                                                                                                                                  
  Mobile VARCHAR(20),                                                        
  Message NVARCHAR(2500),                   
  SenderID VARCHAR(50),                                            
  SmppID varchar(20) ,                                                                                                                         
  U_ID BIGINT,                                                                                                                                                                  
  IsUnicode bit,                                                                                         
   priority tinyint ,                                       
BATCHID bigint,     --MANOJ 07 02 2010                                                
Operator char(6),        
isflash int,        
DLT_TemplateID nvarchar(50)        
)                                                                                                           
--create index ix_#temptabletrans_messageid on #temptabletrans(MessageID);                            
        
INSERT INTO @TEMPTABLETRans (MessageID,Mobile,Message,SenderID,SmppID,U_ID,IsUnicode,priority,BATCHID,Operator,isflash,DLT_TemplateID)                
SELECT TOP(@TOPCOUNT) MessageID,Mobile, REPLACE(    
         case when t.IsUniCode = 0    
           then  REPLACE(REPLACE([Message],char(146),char(39)),char(145),char(39))    
        else    
           [Message]    
                          end    
       ,char(150),char(45)) as [Message],SenderID,SmppID,mysms.dbo.ufn_getuserparentid(u_id),IsUnicode,priority,t.BATCHID,Operator,@isflash,@DLT_TemplateID               
FROM  [10.0.0.135].[MysmsTrans].[dbo].MessageQueueProRoute as t with(nolock) join mysms.dbo.DLT_Template_MSG d with (nolock) on t.BatchID=d.BatchID where ltrim(rtrim(senderid))=@senderid        
and d.DLT_TemplateID=@DLT_TemplateID and isprocessed=0  and t.IsUniCode = @IsUnicode        
order by messageinsertdate-- convert(datetime,messageinsertdate,100)          
option(maxdop 4)          
              
RETRY:                                                                                                                                             
BEGIN TRY                                                                                                                             
BEGIN TRAN                                                                                                          
Update mq   set IsProcessed =1,m_processedat=getdate()  FROM [10.0.0.135].[MysmsTrans].[dbo].MessageQueueProRoute as MQ with(nolock)  JOIN @TEMPTABLETRans TT ON MQ.MESSAGEID=TT.MESSAGEID               
 option(maxdop 4)          
COMMIT                                                       
END TRY                                                                                                                                          
                                                                                                
BEGIN CATCH                                                                               
IF @@TRANCOUNT>0                                                                                                                                          
ROLLBACK                                                                                           
EXECUTE USP_INSERTERRORINFO;                                                                                                     
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                                                                                    
BEGIN                                                                         
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                                                                                    
GOTO RETRY -- Go to Label RETRY                                                                                                    
END                                                                        
END CATCH                                                                                                 
                
select distinct mysms.dbo.ufn_getuserparentid(u_id) UserI,isnull(left(PE_ID,100),'') PE_ID,d.parentid,EntityName into #PE                   
from mysms.dbo.DLTdetails d with (nolock)               
right join mysms.dbo.user_detail u with (nolock)                 
--right join user_detail u with (nolock)                 
on d.parentid=u.parentid                   
and d.id=(select max(id) from mysms.dbo.DLTdetails with (nolock) where parentid=d.Parentid)                  
join @TEMPTABLETRans t  
 --on t.u_id=u.user_id                  
 on  mysms.dbo.ufn_getuserparentid(t.u_id)= mysms.dbo.ufn_getuserparentid(u.user_id)               
                
insert into [10.0.0.135].[MysmsTrans].[dbo].batchprogress(batchid,totalrecords)                
select distinct batchid,count(1) from @TEMPTABLETRans i                 
where not exists (select 1 from [10.0.0.135].[MysmsTrans].[dbo].batchprogress with(nolock) where batchid=i.batchid)  group by batchid              
option(maxdop 4)          
                
update b  set totalprocessed=isnull(totalprocessed,0)+counted,                
batchcompletetime=case when isnull(totalprocessed,0)+counted>=totalrecords then getdate() else batchcompletetime end                 
from [10.0.0.135].[MysmsTrans].[dbo].batchprogress as b with(nolock) join                 
(select batchid,count(1) counted from @TEMPTABLETRans group by batchid) t                
on t.batchid=b.batchid                
option(maxdop 4)               
                                              
                  
SELECT right(t.MessageID,9) UserTag,t.MessageId,'91' + rtrim(ltrim(t.Mobile)) as Mobile,                                           
  Replace(replace(dbo.fn_getmessagewithshorturl_m(t.Message,t.batchid,t.mobile,t.MessageID),char(13),' '),'{#var#}','')
   As [Message],                  
--case --when a.allowed=1 then 'KITKIT'                 
--when rtrim(ltrim(SenderID))='TXTSMS' then 'CONECT' else rtrim(ltrim(SenderID)) end As         
rtrim(ltrim(SenderID)) as SenderID,                        
U_ID,
  --IsUnicode
  -- (
  --  case when isnull(t.Message,'') != cast(isnull(t.Message,'') as varchar(2500))
	 --    then 1
		-- else 0
		-- end
  --) as IsUnicode
  dbo.fn_IsUnicode(t.Message) as IsUnicode 

,priority,t.BATCHID,Operator,isnull(isflash,0) isflash                  
,isnull(PE_ID,'') PE_ID,isnull(DLT_TemplateID,'0') DLT_TemplateID                  
FROM @TEMPTABLETRans t                                                                     
left join #PE p
  --on p.useri=t.U_ID                  
  on mysms.dbo.ufn_getuserparentid(p.useri) =  mysms.dbo.ufn_getuserparentid(t.U_ID)
--left join #allowedtemplates a on a.Message=t.Message                  
where PE_id <>'' and isnull(DLT_TemplateID,'0')<>'0'                  
--or a.allowed=1                  
 option(maxdop 4)                
       
 /*      
update m  set priority=30 from MessageQueueProRoute m join #TEMPTABLETRans t on t.MessageID=m.MessageID                   
left join #PE p on p.UserI=t.U_ID                  
where (m.priority<>30                 
and (PE_ID='' or isnull(DLT_TemplateID,'0')='0'))                  
 option(maxdop 4)                  
 */      
      
 update m  set priority=30 from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueProRoute as m with(nolock)       
 join mysms.dbo.DLT_Template_MSG d with (nolock) on d.BatchID=m.BatchID         
 join #PE p 
  --on p.UserI=m.U_ID                  
  on mysms.dbo.ufn_getuserparentid(p.useri) =  mysms.dbo.ufn_getuserparentid(m.U_ID)
where (m.priority<>30                 
and (PE_ID='' or isnull(DLT_TemplateID,'0')='0')  or len(DLT_templateid)>19  )  and m.senderid like @alphacode+'%'                
 option(maxdop 4)        
      
      
      
insert into [10.0.0.135].[MysmsTrans].[dbo].smsbatchnotsent(batchid,PE_id,template_id,reason)                  
select t.batchid,PE_id,DLT_TemplateID,case when PE_id='' then 'User DLT not available' else 'User TemplateId not available' end                  
FROM @TEMPTABLETRans t                                                                     
left join #PE p 
  --on p.useri=t.U_ID                  
   on mysms.dbo.ufn_getuserparentid(p.useri) =  mysms.dbo.ufn_getuserparentid(t.U_ID)
where PE_id ='' or isnull(DLT_TemplateID,'0')='0'                  
and not exists(select 1 from [10.0.0.135].[MysmsTrans].[dbo].smsbatchnotsent with (nolock) where batchid=t.batchid)                  
 option(maxdop 4)          
           
insert into [10.0.0.135].[MysmsTrans].[dbo].InvalidMessageQueueTrcRoute(MessageQueueID,MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent,isprocessed,                    
IsFlash)                    
select MessageQueueID,MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,mysms.dbo.ufn_getuserparentid(u_id),IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent,isprocessed,     
IsFlash from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueProRoute with (nolock) where (priority>2 or isdnd=1) and SenderID like @alphacode+'%'        
 option(maxdop 4)          
       
   select @RowsDeleted = 1;    
WHILE @RowsDeleted > 0    
BEGIN    
DELETE TOP (@BatchSize)     
            FROM [10.0.0.135].[MysmsTrans].[dbo].MessageQueueProRoute with(rowlock) 
            WHERE (priority>2 or isdnd=1)  and SenderID like @alphacode+'%' option(maxdop 4)                         
SET @RowsDeleted = @@ROWCOUNT;    
END      
    
 --delete from MessageQueueProRoute  where (priority>2 or isdnd=1)  and SenderID like @alphacode+'%' option(maxdop 4)                           
                                                    
--drop table #allowedtemplates                  
drop table if exists #matches                  
                  
                  
                                                                     
drop table if exists #PE                                                      
drop table if exists #isflash                                                                    
--drop table if exists #TEMPTABLETRans                                                                                                                                 
end        
        
end try                  
begin catch                  
exec usp_InsertErrorInfo                  
end catch                  
END 


GO

