delete from MessageQueueProRoute where (mobile LIKE '%[^0-9 ]%' or len(ltrim(rtrim(mobile)))<>10) -- option(maxdop 1)  --and messagequeueid%4=@div--in (2,3)                                                                         
    
if exists(select 1 from MessageQueueProRoute MQ JOIN Messagesent TT ON MQ.MESSAGEID=TT.MESSAGEID and tt.messagetable='MessageQueueProRoute' where IsProcessed= 1)
begin                                                   
begin tran                                                                                           
delete mq from MessageQueueProRoute MQ JOIN Messagesent TT ON MQ.MESSAGEID=TT.MESSAGEID and tt.messagetable='MessageQueueProRoute' where IsProcessed= 1 -- option(maxdop 1)  --and messagequeueid%4=@div--in (2,3) --,0)                                                          
  
              
update m set isprocessed=0 from MessageQueueProRoute m with (nolock) where not exists(select 1 from messagesent ms where ms.messageid=m.messageid) and isprocessed=1 and DATEDIFF(mi,messageinsertdate,getdate())>10 -- option(maxdop 1) --and messagequeueid%4=@div--in (2,3) --,0)                
commit                             
end                                                                   
    
create table #TEMPTABLETRans                                             
(                                                                                        
  MessageID BIGINT,                                                                                                                                                    
  Mobile VARCHAR(20),                                          
  Message NVARCHAR(2500),                                                                                                                                                      
  SenderID VARCHAR(50),                                                                                                                                                  
  SmppID varchar(20) ,                                                                                                           
  U_ID BIGINT,                                                                                                                                                    
  IsUnicode bit,                                                                                                                                                     
   priority tinyint ,                                                                                                       
BATCHID bigint,     --MANOJ 07 02 2010                                                         
Operator char(6)                                                                                                                                      
)                                                                                             
create index ix_#temptabletrans_messageid on #temptabletrans(MessageID);                                                                                        
INSERT INTO #TEMPTABLETRans SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,priority,                              
BATCHID,Operator FROM  dbo.MessageQueueProRoute  with (nolock) WHERE  PRIORITY=2 and SmppID=2   --and messagequeueid%4=@div--in (2,3) --,0)        
and isprocessed=0                                                                                  
order by convert(datetime,messageinsertdate,100)       
 -- option(maxdop 1)

SET @RESTCOUNTAFTERDirect =@@ROWCOUNT                                                       
                                                                                                                                   
IF (@RESTCOUNTAFTERDirect< @TOPCOUNT)                                                                                        
 BEGIN                                                                                                                                             
 
 INSERT INTO #TEMPTABLETRans                                                                                       
 SELECT TOP(@TOPCOUNT-@RESTCOUNTAFTERDirect ) MessageID,Mobile,[Message],SenderID,SmppID,                                                          
 U_ID,IsUnicode,priority,BATCHID,Operator FROM  dbo.MessageQueueProRoute  with (nolock) WHERE  PRIORITY=1 and SmppID=2  --and messagequeueid%4=@div--in (2,3) --,0)                            
  and isprocessed=0                                
 order by convert(datetime,messageinsertdate,100)
  -- option(maxdop 1)
                                                                      
     SET @RESTCOUNTAFTERPriority =@@ROWCOUNT                                                                                                                                                     
                                                                                                    
                                                                                                                                                    
 IF ((@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)< @TOPCOUNT)                                                                                  
  BEGIN                                                                                                                                                    
   SET @TOPCOUNT = @TOPCOUNT-(@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)                                                                                                                                                       
                --MANOJ 07 02 2010 BatchId added                                                                                                      
 INSERT INTO #TEMPTABLETRans SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,
 priority,BATCHID,Operator FROM  dbo.MessageQueueProRoute  with (nolock) WHERE  PRIORITY=0 and SmppID=2  -- and messagequeueid%4=@div--in (2,3) --,0)                              
 and isprocessed=0                                                                                     
 order by convert(datetime,messageinsertdate,100)
  -- option(maxdop 1)

 END                                                                                                                                                    
END                                                                                                                                                        
RETRY:                                                                                                                               
BEGIN TRY                                                                                                               
BEGIN TRAN                                                                                            
Update mq set IsProcessed =1  FROM MessageQueueProRoute MQ JOIN #TEMPTABLETRans TT ON MQ.MESSAGEID=TT.MESSAGEID -- option(maxdop 1) --where messagequeueid%4=@div--in (2,3) --,0)                                                                                       
COMMIT                                         
END TRY                                                                                                                            
                                                                                  
BEGIN CATCH                                                                 
IF @@TRANCOUNT>0                                                                                                                            
ROLLBACK                                                                             
EXECUTE USP_INSERTERRORINFO;                                                                                       
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                                                                      
BEGIN                                                           
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                                                                      
GOTO RETRY -- Go to Label RETRY                                                                                      
END                                                          
END CATCH                                                                                   
                                                                
select distinct t.batchid,isnull(d.flash,0) isflash, isnull(d.DLT_TemplateID,'0') DLT_TemplateID,d.total_records     
into #isflash from #TEMPTABLETRans t                                                      
left join mysms.dbo.DLT_Template_MSG d on d.BatchID=t.BatchID
 -- option(maxdop 1)
    
select distinct u_id UserI,isnull(PE_ID,'') PE_ID,d.parentid,EntityName into #PE     
from mysms.dbo.DLTdetails d with (nolock) right join mysms.dbo.user_detail u with (nolock) on d.parentid=u.parentid     
and d.id=(select max(id) from mysms.dbo.DLTdetails where parentid=d.Parentid)    
join #TEMPTABLETRans t with (nolock) on t.u_id=u.user_id    
 -- option(maxdop 1)
    
