insert into batchprogress(batchid,totalrecords)  
select distinct batchid,total_records from #isflash i   
where not exists (select 1 from batchprogress where batchid=i.batchid)  
 -- option(maxdop 1)
  
update b set totalprocessed=isnull(totalprocessed,0)+counted,  
batchcompletetime=case when isnull(totalprocessed,0)+counted>=totalrecords then getdate() else batchcompletetime end   
from batchprogress b join   
(select batchid,count(1) counted from #TEMPTABLETRans group by batchid) t  
on t.batchid=b.batchid  
 -- option(maxdop 1)
  
SELECT right(t.MessageID,9) UserTag,t.MessageId,'91' + rtrim(ltrim(t.Mobile)) as Mobile,                             
dbo.fn_getmessagewithshorturl_m(t.Message,t.batchid,t.mobile,t.MessageID) As [Message],    
--case when a.allowed=1 then 'KITKIT' when rtrim(ltrim(SenderID))='TXTSMS' then 'CONECT' else rtrim(ltrim(SenderID)) end As SenderID,          
rtrim(ltrim(SenderID)) As SenderID,U_ID,IsUnicode,priority,t.BATCHID,Operator,isnull(f.isflash,0) isflash,  
--case when a.allowed=1 then '1701159108398939463' else isnull(PE_ID,'') end PE_ID,  
isnull(PE_ID,'') as PE_ID,  
isnull(DLT_TemplateID,'0') DLT_TemplateID    
FROM #TEMPTABLETRans t                                                       
left join #isflash f on f.BatchID=t.BATCHID                                        
left join #PE p on p.useri=t.U_ID    
--left join #allowedtemplates a on a.Message=t.Message    
where PE_id <>'' and isnull(DLT_TemplateID,'0')<>'0'    
--or a.allowed=1    
 -- option(maxdop 1)
    
update m set priority=30 from MessageQueueProRoute m join #TEMPTABLETRans t on t.MessageID=m.MessageID     
left join #isflash s on s.BatchID=t.BATCHID    
left join #pe p on p.UserI=t.U_ID  
where (m.priority<>30 --and messagequeueid%4=@div    
and (PE_ID='' or isnull(DLT_TemplateID,'0')='0'  ))  
--(not exists (select 1 from mysms.dbo.DLTdetails d join mysms.dbo.user_detail u with (nolock) on u.parentid=d.parentid and m.u_id=u.User_ID)  --or  a.allowed=0))     
--or isnull(DLT_TemplateID,'0')='0'    
--))    
 -- option(maxdop 1)
    
    
insert into smsbatchnotsent(batchid,PE_id,template_id,reason)    
select t.batchid,PE_id,DLT_TemplateID,case when PE_id='' then 'User DLT not available' else 'User TemplateId not available' end    
FROM #TEMPTABLETRans t                                                       
left join #isflash f on f.BatchID=t.BATCHID                                         
left join #PE p on p.useri=t.U_ID    
where PE_id ='' or isnull(DLT_TemplateID,'0')='0'    
and not exists(select 1 from smsbatchnotsent where batchid=t.batchid)    
 -- option(maxdop 1)    
    
insert into InvalidMessageQueue(MessageQueueID,MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent,isprocessed,IsFlash)      
select MessageQueueID,MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent,isprocessed,IsFlash from MessageQueueProRoute with (nolock) where (priority>2 or isdnd=1) -- option(maxdop 1) --and messagequeueid%4=@div
      
delete from MessageQueueProRoute where (priority>2 or isdnd=1) -- option(maxdop 1) --and messagequeueid%4=@div
                                                       
--drop table #allowedtemplates    
--drop table #matches    
    
    
                                                       
drop table #PE                                        
drop table #isflash                                                      
drop table #TEMPTABLETRans               
end    



GO

/* ============================================================
   Procedure: [dbo].[USP_MoveMessageFromQueueToProRoute2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
CREATE   PROC [dbo].[USP_MoveMessageFromQueueToProRoute2]                                  
(                                  
@TOTALCOUNT INT =50                           
)                                  
AS                                  
--1) SELECT TOP GIVEN NO OF HIGH PRIORITIES MESSAGES                                  
BEGIN                                
SET NOCOUNT ON                                
DECLARE @TOPCOUNT INT                                
DECLARE @RESTCOUNTAFTERDirect INT                               
DECLARE @RESTCOUNTAFTERPriority  INT                            
SET @TOPCOUNT = @TOTALCOUNT                                
    
Delete T from    
(select row_number() over(partition by MessageID order by MessageID) as row_number, * from MessageQueueProRoute2) T    
where row_number > 1    
DECLARE @TEMPTABLE TABLE                                
(                                
  MessageID BIGINT,                                
  Mobile VARCHAR(20),                                
  Message NVARCHAR(4000),                              
  SenderID VARCHAR(50),                              
  SmppID varchar(20) ,                              
  U_ID BIGINT,                            
  IsUnicode bit,                             
   priority tinyint ,                
BATCHID bigint,     --MANOJ 07 02 2010          
Operator char(6)                      
)         
--exec proc_insert_into_normal_from_q1          
--exec proc_insert_into_pri_from_q1        
--exec proc_insert_into_dir_from_q1              
          --MANOJ 07 02 2010 BatchId added                      
INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,priority,      
BATCHID,Operator FROM  dbo.MessageQueueProRoute2 WHERE  PRIORITY=2 --and IsUnicode=0    
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)       
order by convert(datetime,messageinsertdate,100)      
SET @RESTCOUNTAFTERDirect =@@ROWCOUNT                                
                                
IF (@RESTCOUNTAFTERDirect< @TOPCOUNT)                                
 BEGIN                                
                                
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT-@RESTCOUNTAFTERDirect ) MessageID,Mobile,[Message],SenderID,SmppID,      
 U_ID,IsUnicode,priority,BATCHID,Operator FROM  dbo.MessageQueueProRoute2 WHERE  PRIORITY=1 --and IsUnicode=0      
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)     
 order by convert(datetime,messageinsertdate,100)        
        
     SET @RESTCOUNTAFTERPriority =@@ROWCOUNT                             
                                
                            
 IF ((@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)< @TOPCOUNT)                               
  BEGIN                            
   SET @TOPCOUNT = @TOPCOUNT-(@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)                               
                --MANOJ 07 02 2010 BatchId added                
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,      
 priority,BATCHID,Operator FROM  dbo.MessageQueueProRoute2 WHERE  PRIORITY=0   
 --and ltrim(rtrim(senderid)) not in (select ltrim(rtrim(f1)) from AirtelSenderID)     
 order by convert(datetime,messageinsertdate,100)      
 END                            
END         
   DELETE MessageQueueProRoute2 FROM MessageQueueProRoute2 MQ JOIN @TEMPTABLE TT ON MQ.MESSAGEID=TT.MESSAGEID              
         
         --MANOJ 07 02 2010 BatchId added                   
SELECT right(MessageID,6) UserTag,MessageID,'91' + rtrim(ltrim(Mobile)) as Mobile,rtrim(ltrim([Message])) As [Message] ,rtrim(ltrim(SenderID))        
As SenderID,U_ID,IsUnicode,priority,BATCHID,Operator  FROM @TEMPTABLE         
        
END           
    
    


