/* ============================================================
   Procedure: [dbo].[USP_MoveMessageFromQueueToTata]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROC [dbo].[USP_MoveMessageFromQueueToTata]                                
(                                
@TOTALCOUNT INT =100                         
)                                
AS                                
--1) SELECT TOP GIVEN NO OF HIGH PRIORITIES MESSAGES                                
BEGIN                              
SET NOCOUNT ON                              
DECLARE @TOPCOUNT INT                              
DECLARE @RESTCOUNTAFTERDirect INT                             
DECLARE @RESTCOUNTAFTERPriority  INT                          
SET @TOPCOUNT = @TOTALCOUNT                              
  
Delete T from  
(select row_number() over(partition by MessageID order by MessageID) as row_number, * from MessageQueue) T  
where row_number > 1  
DECLARE @TEMPTABLE TABLE                              
(                              
  MessageID BIGINT,                              
  Mobile VARCHAR(20),                              
  Message NVARCHAR(4000),                            
  SenderID VARCHAR(50),                            
  SmppID varchar(20) ,                            
  U_ID BIGINT,                          
  IsUnicode bit,                           
   priority tinyint ,              
BATCHID bigint,     --MANOJ 07 02 2010        
Operator char(6)                    
)       
--exec proc_insert_into_normal_from_q1        
--exec proc_insert_into_pri_from_q1      
--exec proc_insert_into_dir_from_q1            
          --MANOJ 07 02 2010 BatchId added                    
INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,priority,    
BATCHID,Operator FROM  dbo.MessageQueue WHERE  PRIORITY=2 --and IsUnicode=0  
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)     
order by convert(datetime,messageinsertdate,100)    
SET @RESTCOUNTAFTERDirect =@@ROWCOUNT                              
                              
IF (@RESTCOUNTAFTERDirect< @TOPCOUNT)                              
 BEGIN                              
                              
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT-@RESTCOUNTAFTERDirect ) MessageID,Mobile,[Message],SenderID,SmppID,    
 U_ID,IsUnicode,priority,BATCHID,Operator FROM  dbo.MessageQueue WHERE  PRIORITY=1 --and IsUnicode=0    
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)   
 order by convert(datetime,messageinsertdate,100)      
      
     SET @RESTCOUNTAFTERPriority =@@ROWCOUNT                           
                              
                          
 IF ((@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)< @TOPCOUNT)                             
  BEGIN                          
   SET @TOPCOUNT = @TOPCOUNT-(@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)                             
                --MANOJ 07 02 2010 BatchId added              
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,    
 priority,BATCHID,Operator FROM  dbo.MessageQueue WHERE  PRIORITY=0 
 --and ltrim(rtrim(senderid)) not in (select ltrim(rtrim(f1)) from AirtelSenderID)   
 order by convert(datetime,messageinsertdate,100)    
 END                          
END       
   DELETE MessageQueue FROM MessageQueue MQ JOIN @TEMPTABLE TT ON MQ.MESSAGEID=TT.MESSAGEID            
       
         --MANOJ 07 02 2010 BatchId added                 
SELECT MessageID,'91' + rtrim(ltrim(Mobile)) as Mobile,rtrim(ltrim([Message])) As [Message] ,rtrim(ltrim(SenderID))      
As SenderID,U_ID,IsUnicode,priority,BATCHID,Operator  FROM @TEMPTABLE       
      
END         
  
  



GO

