/* ============================================================
   Procedure: [dbo].[USP_MoveMessageFromQueueToTransRoute_XML_priority1_WHLSync]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_MoveMessageFromQueueToTransRoute_XML_priority1_WHLSync] --400,1                                                            
(                                                                                                                                                          
@TOPCOUNT INT = 5000,                
@alphacode nvarchar(10)                                                                                                                                                   
)                                                                                                                                                          
AS                                                                                                                                 
BEGIN        
--declare TOPCOUNT INT = 5000,                
--@alphacode nvarchar(10)                                                                                                                                                   
      set @TOPCOUNT = 3000
	  --set @TOPCOUNT = 50
SET NOCOUNT ON        
begin try        
DECLARE @BatchSize INT = 100;    
DECLARE @RowsDeleted INT = 1;    
WHILE @RowsDeleted > 0    
BEGIN    
DELETE TOP (@BatchSize) FROM [10.0.0.135].[MysmsTrans].[dbo].messagequeuenew  WHERE (mobile LIKE '%[^0-9 ]%' OR LEN(LTRIM(RTRIM(mobile))) <> 10)    
AND SenderID LIKE @alphacode + '%' and priority=1 --and u_id <> 34594 ;    
SET @RowsDeleted = @@ROWCOUNT;    
END    
    
	 
  declare @m_count int=(select count(1) from [10.0.0.135].[MysmsTrans].[dbo].messagequeuenew with(nolock) where MessageInsertDate<dateadd(d,-1,getdate()))
  while @m_count>0
  begin
  delete m from (select top 1000 * from [10.0.0.135].[MysmsTrans].[dbo].messagequeuenew with(nolock) where MessageInsertDate<dateadd(d,-1,getdate())) m
  set @m_count=@m_count-1000
  end


/*    
CREATE TABLE #TempToDelete (    
    MessageID BIGINT    
);    
    
INSERT INTO #TempToDelete (MessageID)    
SELECT MessageID    
FROM messagequeuenew    
WHERE (mobile LIKE '%[^0-9 ]%' OR LEN(LTRIM(RTRIM(mobile))) <> 10)    
  AND SenderID LIKE @alphacode + '%';    
    
DELETE m    
FROM messagequeuenew m    
JOIN #TempToDelete t ON m.MessageID = t.MessageID;    
    
DROP TABLE #TempToDelete;    
*/    
--delete from messagequeuenew  where (mobile LIKE '%[^0-9 ]%' or len(ltrim(rtrim(mobile)))<>10)       
-- and SenderID like @alphacode+'%'      
--option(maxdop 4) --in (2,3)                                                                                     
                
declare @senderid nvarchar(10) ,@DLT_TemplateID nvarchar(50),@isflash int,@is_stock int  , @IsUnicode bit       
      
  update m set isprocessed =0 from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueNew as m with(nolock) where isprocessed=1 and m_processedat<dateadd(mi,-10,getdate()) and priority=1 and messageinsertdate>=datediff(hh,-6,getdate()) and senderid like @alphacode+'%'     
   and not exists (select 1 from MSG_XMLAPI_Resp(nolock) where corelationid=m.messageid) --and m.U_ID <> 34594      
    
PICK_MESSAGE:      
    
select top 1 @senderid=ltrim(rtrim(senderid)),@isflash=isnull(d.flash,0),@DLT_TemplateID= isnull(left(d.DLT_TemplateID,50),'0'),@is_stock=      
d.dlt_is_stock , @IsUnicode = isnull(t.IsUniCode, 0)       
from [10.0.0.135].[MysmsTrans].[dbo].messagequeuenew as t with(nolock)                                                                  
join mysms.dbo.DLT_Template_MSG d with (nolock) on d.BatchID=t.BatchID       
where  
  SenderID like @alphacode+'%'   --and t.U_ID <> 34594 
  and isprocessed=0   
  and priority =1  
  and  
  isnull(left(d.DLT_TemplateID,50),'0') <> '0'  and len(d.DLT_TemplateID)=19  
    and t.isprocessed=0 
	and 1=case when d.DLT_TemplateID='1707161806613841759' and exists (select 1 from mysms.dbo.Link_smsMobilefromclone with(nolock) where batchid=d.batchid)
	then 1 when d.DLT_TemplateID='1707161806613841759' and not exists (select 1 from mysms.dbo.Link_smsMobilefromclone with(nolock) where batchid=d.batchid)
	then
	0 else 1 end 
  
order by MessageInsertDate     
  
  
option(maxdop 4)         
      
if @is_stock=1      
begin      
create table #isstock(messageid bigint)      
insert into [10.0.0.135].[MysmsTrans].[dbo].messagequeuestock(MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,        
issent,IsFlash,isprocessed) 
  -- output inserted.MessageID as messageid into #isstock            
select MessageID,Mobile,[Message],SenderID,SmppID,getdate(),1,U_ID,IsUnicode,1,Operator,t.BATCHID,1,0,isflash,0            
from  [10.0.0.135].[MysmsTrans].[dbo].MessageQueueNew as t with (nolock) join mysms.dbo.DLT_Template_MSG as d with (nolock) on t.BatchID=d.BatchID where ltrim(rtrim(senderid))=@senderid      
and d.DLT_TemplateID=@DLT_TemplateID and isprocessed=0 and t.IsUniCode = @IsUnicode and Priority=1 --and t.U_ID <> 34594     
 option(maxdop 4)        

   insert into #isstock(messageid)            
   select MessageID           
    from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueNew as t with (nolock) join mysms.dbo.DLT_Template_MSG as d with (nolock) on t.BatchID=d.BatchID where ltrim(rtrim(senderid))=@senderid      
and d.DLT_TemplateID=@DLT_TemplateID and isprocessed=0 and t.IsUniCode = @IsUnicode and Priority=1 --and t.U_ID <> 34594     
 option(maxdop 4)        
  
select @RowsDeleted=1    
 WHILE @RowsDeleted > 0    
 BEGIN    
            DELETE TOP (@BatchSize) m    
            FROM [10.0.0.135].[MysmsTrans].[dbo].messagequeuenew as m with(nolock)   
            JOIN #isstock t ON m.messageid = t.messageid    
            WHERE senderid = @senderid  and Priority=1 ;    
    
            SET @RowsDeleted = @@ROWCOUNT;    
        END    
    
DROP TABLE #isstock;    
    
GOTO PICK_MESSAGE      
end      
      
else      
begin      
declare  @TEMPTABLETRans Table                                                         
(                                                                                                    
  MessageID BIGINT,                                                                                                                                                                
  Mobile VARCHAR(20),                                                      
  Message NVARCHAR(2500),                                                                                                                                                                  
  SenderID VARCHAR(50),                                                                                                                                                              
  SmppID varchar(20) ,                                                                                                                       
  U_ID BIGINT,                                                                                                                                                                
  IsUnicode bit,                                                                                       
   priority tinyint ,                                                                 
BATCHID bigint,     --MANOJ 07 02 2010                                              
Operator char(6),      
isflash int,      
DLT_TemplateID nvarchar(50)      
)                                                                                                         
--create index ix_#temptabletrans_messageid on #temptabletrans(MessageID);                          
      
INSERT INTO @TEMPTABLETRans (MessageID,Mobile,Message,SenderID,SmppID,U_ID,IsUnicode,priority,BATCHID,Operator,isflash,DLT_TemplateID)              
SELECT TOP(@TOPCOUNT) MessageID,Mobile, REPLACE(    
         case when t.IsUniCode = 0    
           then  REPLACE(REPLACE([Message],char(146),char(39)),char(145),char(39))    
        else    
           [Message]    
                          end    
       ,char(150),char(45)) as [Message],SenderID,SmppID,mysms.dbo.ufn_getuserparentid(u_id),IsUnicode,priority,t.BATCHID,Operator,@isflash,@DLT_TemplateID             
FROM  [10.0.0.135].[MysmsTrans].[dbo].MessageQueueNew as t with (nolock) join mysms.dbo.DLT_Template_MSG as d with (nolock) on t.BatchID=d.BatchID where ltrim(rtrim(senderid))=@senderid      
