SET @RowsDeleted = @@ROWCOUNT;    
END    
    
  
  
  declare @m_count int=(select count(1) from [10.0.0.135].[MysmsTrans].[dbo].messagequeuenew  with(nolock) where MessageInsertDate<dateadd(d,-1,getdate()))
  while @m_count>0
  begin
  delete m from (select top 1000 * from [10.0.0.135].[MysmsTrans].[dbo].messagequeuenew with(nolock) where MessageInsertDate<dateadd(d,-1,getdate())) m
  set @m_count=@m_count-1000
  end
    
