  declare @senderid nvarchar(10) ,@DLT_TemplateID nvarchar(50),@isflash int,@is_stock int  , @IsUnicode bit     
  update m set isprocessed =0 from [10.0.0.135].[MysmsTrans].[dbo].MessageQueueNew as m with(nolock) where isprocessed=1 and m_processedat<dateadd(mi,-10,getdate()) and priority=2 and messageinsertdate>=datediff(hh,-6,getdate()) and senderid like @alphacode+'%'     
