	from  [10.0.0.135].[MysmsTrans].[dbo].MessageQueueNew as t with(nolock) join mysms.dbo.DLT_Template_MSG d with (nolock) on t.BatchID=d.BatchID where ltrim(rtrim(senderid))=@senderid      
	and d.DLT_TemplateID=@DLT_TemplateID and isprocessed=0 and t.IsUniCode = @IsUnicode and Priority=2     
	 option(maxdop 4)        
	  



