 WHILE @RowsDeleted > 0    
 BEGIN    
            DELETE TOP (@BatchSize) m    
        FROM [10.0.0.135].[MysmsTrans].[dbo].messagequeuenew m     
            JOIN #isstock t ON m.messageid = t.messageid    
            WHERE senderid = @senderid  and Priority=2 ;    
    
            SET @RowsDeleted = @@ROWCOUNT;    
        END    
        
--delete m from messagequeuenew m join #isstock t on m.messageid=t.messageid where senderid=@senderid option(maxdop 4)       
DROP TABLE #isstock;    
    
GOTO PICK_MESSAGE      
