,priority,t.BATCHID,Operator,isnull(isflash,0) isflash                
,isnull(PE_ID,'') PE_ID,isnull(DLT_TemplateID,'0') DLT_TemplateID                
FROM @TEMPTABLETRans t                                                                   
left join #PE p on mysms.dbo.ufn_getuserparentid(p.useri) =  mysms.dbo.ufn_getuserparentid(t.U_ID)                  
--left join #allowedtemplates a on a.Message=t.Message                
where PE_id <>'' and isnull(DLT_TemplateID,'0')<>'0'   --and t.U_ID = 34594                
--or a.allowed=1                
 option(maxdop 4)              
     
 /*    
update m  set priority=30 from messagequeuenew m join @TEMPTABLETRans t on t.MessageID=m.MessageID                 
left join #PE p on p.UserI=t.U_ID                
where (m.priority<>30               
and (PE_ID='' or isnull(DLT_TemplateID,'0')='0'))                
 option(maxdop 4)      
 */    
 --removed updloack by Abhinav Tiwari(DBA) 1 Sept 2023   
update m  set priority=30 from [10.0.0.135].[MysmsTrans].[dbo].messagequeuenew m with(nolock)   
left join mysms.dbo.DLT_Template_MSG d with (nolock) on d.BatchID=m.BatchID       
left join #PE p on mysms.dbo.ufn_getuserparentid(p.UserI)  = mysms.dbo.ufn_getuserparentid(m.U_ID)                   
where m.messageinsertdate<dateadd(hh,-1,getdate()) and  m.Priority=0 and (m.priority<>30               
and (PE_ID='' or isnull(DLT_TemplateID,'0')='0') or len(DLT_templateid)>19 )  and m.senderid like @alphacode+'%'
      --and m.u_id = 34594      
 --option(maxdop 4)     
    
                
insert into [10.0.0.135].[MysmsTrans].[dbo].smsbatchnotsent(batchid,PE_id,template_id,reason)                
select t.batchid,PE_id,DLT_TemplateID,case when PE_id='' then 'User DLT not available' else 'User TemplateId not available' end                
FROM @TEMPTABLETRans t                                                                   
left join #PE p on  mysms.dbo.ufn_getuserparentid(p.useri) = mysms.dbo.ufn_getuserparentid(t.U_ID)                   
where PE_id ='' or isnull(DLT_TemplateID,'0')='0' --and t.U_ID = 34594                
and not exists(select 1 from [10.0.0.135].[MysmsTrans].[dbo].smsbatchnotsent as s with (nolock) where batchid=t.batchid)                
 option(maxdop 4)        
         
insert into [10.0.0.135].[MysmsTrans].[dbo].InvalidMessageQueue2(MessageQueueID,MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent,isprocessed,                  
IsFlash)                  
select MessageQueueID,MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority , mysms.dbo.ufn_getuserparentid(U_ID) as  U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent,isprocessed,                  
IsFlash from [10.0.0.135].[MysmsTrans].[dbo].messagequeuenew with (nolock) where (priority>2 or isdnd=1) and SenderID like @alphacode+'%'
     --and u_id = 34594     
 option(maxdop 4)        
       
   select @RowsDeleted = 1;    
WHILE @RowsDeleted > 0    
BEGIN    
DELETE TOP (@BatchSize)     
            FROM [10.0.0.135].[MysmsTrans].[dbo].messagequeuenew WITH (ROWLOCK)    
            WHERE (priority>2 or isdnd=1)  and SenderID like @alphacode+'%'  --and u_id = 34594
			option(maxdop 4)                         
SET @RowsDeleted = @@ROWCOUNT;    
END      
    
 --delete from messagequeuenew  where (priority>2 or isdnd=1)  and SenderID like @alphacode+'%' option(maxdop 4)                         
                                                  
--drop table #allowedtemplates                
drop table if exists #matches                
                
                
                                                                   
drop table if exists #PE                                                    
drop table if exists #isflash                                                                  
--drop table if exists @TEMPTABLETRans                                                                                                                               
end      
      
end try                
begin catch                
exec usp_InsertErrorInfo                
end catch                
END                    
--alter table messagequeuenew alter column messagequeueid bigint        
      
      
--declare @a nvarchar(10)='[a-s]'      
--select top 10 * from MessageQueueNew(nolock) where senderid like @a+'%' 


