  U_ID BIGINT,                                                                  
  IsUnicode bit,                                                                   
   priority tinyint ,                                                      
BATCHID bigint,     --MANOJ 07 02 2010                                                
Operator char(6) ,                          
messageinsertdate  datetime                                                         
)          
create index ix_#temptable_messageid on #TEMPTABLE(MessageID);                                                       
--exec proc_insert_into_normal_from_q1                                                
--exec proc_insert_into_pri_from_q1                                              
--exec proc_insert_into_dir_from_q1                                                    
          --MANOJ 07 02 2010 BatchId added                           
--If CONVERT(TIME,GETDATE()) between '09:00' and '21:00'                          
--begin                                                           
INSERT INTO #TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,priority,                                            
BATCHID,Operator,                          
messageinsertdate FROM  dbo.MessageQueueTrcRoute with (nolock) WHERE  PRIORITY=2 and SmppID=2  and (messagequeueid%4)=0       and U_ID<>24502
--and (messagequeueid -floor(messagequeueid/cast(2 as float))*2)=0                                             
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)                                             
order by messageinsertdate--convert(datetime,messageinsertdate,100)                                            
SET @RESTCOUNTAFTERDirect =@@ROWCOUNT                                                                      
                                                  
IF (@RESTCOUNTAFTERDirect< @TOPCOUNT)                                                          
 BEGIN                                                                      
                                                                     
 INSERT INTO #TEMPTABLE SELECT TOP(@TOPCOUNT-@RESTCOUNTAFTERDirect ) MessageID,Mobile,[Message],SenderID,SmppID,                                            
 U_ID,IsUnicode,priority,BATCHID,Operator,                          
messageinsertdate FROM  dbo.MessageQueueTrcRoute with (nolock) WHERE  PRIORITY=1 and SmppID=2  and (messagequeueid%4)=0      and U_ID<>24502  
--and (messagequeueid -floor(messagequeueid/cast(2 as float))*2)=0                                         
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)                                           
 order by messageinsertdate--convert(datetime,messageinsertdate,100)                       
                                              
