                --MANOJ 07 02 2010 BatchId added                                                      
 INSERT INTO #TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,                                            
 priority,BATCHID,Operator,                          
messageinsertdate FROM  dbo.MessageQueueTrcRoute with (nolock) WHERE  PRIORITY=0  and SmppID=2  and (messagequeueid%4)=0    and U_ID<>24502     
--and (messagequeueid -floor(messagequeueid/cast(2 as float))*2)=0                                     
 --and ltrim(rtrim(senderid)) not in (select ltrim(rtrim(f1)) from AirtelSenderID)                                           
 order by messageinsertdate--convert(datetime,messageinsertdate,100)                                            
 END                                                             
END                                               
 DELETE MessageQueueTrcRoute FROM MessageQueueTrcRoute MQ JOIN #TEMPTABLE TT ON MQ.MESSAGEID=TT.MESSAGEID                          
--end       
      
select distinct b.batchid,isnull(b.isflash,0) isflash into #isflash from batchinfo b join #TEMPTABLE t      
on b.BatchID=t.BATCHID                 

                                               
         --MANOJ 07 02 2010 BatchId added                                                         
SELECT right(t.MessageID,6) UserTag,t.MessageID,'91' + rtrim(ltrim(t.Mobile)) as Mobile,                      
case when longurl is not null then rtrim(ltrim(REPLACE(message,longurl, shorturl+'/'+Final_url))) else [message] end As [Message]  ,                      
case when rtrim(ltrim(SenderID))='TXTSMS' OR rtrim(ltrim(SenderID))='SMSTXT'  then 'NONAME' else rtrim(ltrim(SenderID)) end                                                    
As SenderID,U_ID,IsUnicode,priority,t.BATCHID,Operator,isnull(f.isflash,0) isflash FROM #TEMPTABLE t       
left join #isflash f on f.BatchID=t.BATCHID
left join 
(select longurl,final_url,shorturl,batchid,messageid,mobile from Link_smsMobile (nolock))
lm on lm.mobile= t.mobile and lm.batchid = t.BatchID        
      
drop table #isflash      
drop table #TEMPTABLE                                              
                                              
END  



