--begin                                                           
INSERT INTO #TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,IsUnicode,priority,                                            
BATCHID,Operator,                          
messageinsertdate FROM  dbo.MessageQueueTrcRoute with (nolock) WHERE  PRIORITY=2 and SmppID=2  and (messagequeueid%4)=3  and U_ID<>24502      
--and (messagequeueid -floor(messagequeueid/cast(2 as float))*2)=0                                             
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)                                             
order by messageinsertdate--convert(datetime,messageinsertdate,100)                                            
SET @RESTCOUNTAFTERDirect =@@ROWCOUNT                                                                      
                                                  
IF (@RESTCOUNTAFTERDirect< @TOPCOUNT)                                                          
 BEGIN                                                                      
                                                                     
 INSERT INTO #TEMPTABLE SELECT TOP(@TOPCOUNT-@RESTCOUNTAFTERDirect ) MessageID,Mobile,[Message],SenderID,SmppID,                                            
 U_ID,IsUnicode,priority,BATCHID,Operator,                          
messageinsertdate FROM  dbo.MessageQueueTrcRoute with (nolock) WHERE  PRIORITY=1 and SmppID=2  and (messagequeueid%4)=3    and U_ID<>24502    
--and (messagequeueid -floor(messagequeueid/cast(2 as float))*2)=0                                         
--and ltrim(rtrim(senderid)) not in (select f1 from AirtelSenderID)                                           
 order by messageinsertdate--convert(datetime,messageinsertdate,100)                       
                                              
