/* ============================================================
   Procedure: [dbo].[usp_movemessagestatustothirtydays]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_movemessagestatustothirtydays]      
as      
begin      
      
declare @t0 bigint=(Select count(1) From MySMS.dbo.MessageDeliveryStatus(nolock)       
     Where cast(MessageInsertDAte as date)<>cast(getdate() as date))      
      
select @t0      
drop table if exists #msdids  
create table #msdids(id bigint)      
while @t0>0      
      
 begin    
 RETRY1:                                                                         
BEGIN TRY                                                                      
BEGIN TRAN      
  Insert into  [MySMS].dbo.ThirtydaysHistory(MessageID,MessageRefID,Mobile,Message,SenderID,MessageStatus,MessageInsertDate,      
             Priority,U_ID,LastError,IsUniCode,BatchID,Operator,Dbtype,IsDND,Isallowdnd,StatusCompletedTime,StatusCompletedTimeSecs,
StatusDescription,ProviderReference)   
    output inserted.messageid as id into #msdids  
  Select  top 10000 MessageID,MessageRefID,Mobile,Message,SenderID,MessageStatus,MessageInsertDate,Priority,U_ID,      
  LastError,IsUniCode,BatchID,Operator,Dbtype,IsDND,Isallowdnd,StatusCompletedTime,StatusCompletedTimeSecs,
StatusDescription,ProviderReference      
  From  [MySMS].dbo.MessageDeliveryStatus(nolock)      
  Where cast(MessageInsertDAte as date)<>cast(getdate() as date)      
  order by MessageDeliveryStatusid      
      
  delete t from     MessageDeliveryStatus t join #msdids m on t.messageid=m.id  
  --(select top 10000 * from[MySMS].dbo.MessageDeliveryStatus(nolock)       
  -- Where cast(MessageInsertDAte as date)<>cast(getdate() as date)      
  -- order by MessageDeliveryStatusid      
  --) t      
    
  truncate table #msdids  
  set @t0=(Select count(1) From MySMS.dbo.MessageDeliveryStatus(nolock)       
     Where cast(MessageInsertDAte as date)<>cast(getdate() as date))      
      
  select @t0      
  COMMIT                                                                      
END TRY                                                                      
                                           
BEGIN CATCH                                                                                                                          
IF @@TRANCOUNT>0                                                         
ROLLBACK                                                                      
EXECUTE USP_INSERTERRORINFO;                     
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number          
BEGIN                                
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                         
GOTO RETRY1 -- Go to Label RETRY                                
END                                                             
END CATCH        
      
 end      
      
end


GO

