/* ============================================================
   Procedure: [dbo].[USP_MOVEMSGFROMQ_AIRTOTATAPRI]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [DBO].[USP_MOVEMSGFROMQ_AIRTOTATAPRI]                              
(                              
@TOTALCOUNT INT =100                        
)                              
AS                              
--1) SELECT TOP GIVEN NO OF HIGH PRIORITIES MESSAGES                              
BEGIN                            
SET NOCOUNT ON                            
DECLARE @TOPCOUNT INT                            
DECLARE @RESTCOUNTAFTERDIRECT INT                           
DECLARE @RESTCOUNTAFTERPRIORITY  INT         
DECLARE @RESTCOUNTAFTERSMPPID2  INT         
SET @TOPCOUNT = @TOTALCOUNT                            
                            
DECLARE @TEMPTABLE TABLE                            
(                            
	MESSAGEID BIGINT,                            
	MOBILE VARCHAR(20),                            
	MESSAGE NVARCHAR(4000),                          
	SENDERID VARCHAR(50),                          
	SMPPID VARCHAR(20) ,                          
	U_ID BIGINT,                        
	ISUNICODE BIT,                         
	PRIORITY TINYINT ,            
	BATCHID BIGINT,        
	OPERATOR CHAR(6)    --MANOJ 07 02 2010                    
)                            
 --EXEC PROC_INSERT_INTO_NORMAL_FROM_AIRPRI        
	INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID,ISUNICODE,PRIORITY,	BATCHID,OPERATOR FROM  DBO.MESSAGEQUEUEAIRTELPRI WHERE  PRIORITY=2 
	ORDER BY CONVERT(DATETIME,MESSAGEINSERTDATE,100)                              
	SET @RESTCOUNTAFTERDIRECT =@@ROWCOUNT        
	IF (@RESTCOUNTAFTERDIRECT< @TOPCOUNT)                            
		BEGIN                            
			INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT-@RESTCOUNTAFTERDIRECT ) MESSAGEID,MOBILE,[MESSAGE],SENDERID,			SMPPID,U_ID, ISUNICODE,PRIORITY,BATCHID,OPERATOR FROM  DBO.MESSAGEQUEUEAIRTELPRI WHERE PRIORITY=1 
			ORDER BY CONVERT(DATETIME,MESSAGEINSERTDATE,100)   
			SET @RESTCOUNTAFTERPRIORITY =@@ROWCOUNT                         
			IF((@RESTCOUNTAFTERDIRECT +@RESTCOUNTAFTERPRIORITY)< @TOPCOUNT)                           
				BEGIN                        
					SET @TOPCOUNT = @TOPCOUNT-(@RESTCOUNTAFTERDIRECT +@RESTCOUNTAFTERPRIORITY)                       					INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID,						ISUNICODE,PRIORITY,BATCHID,OPERATOR FROM  DBO.MESSAGEQUEUEAIRTELPRI WHERE PRIORITY=0 
					ORDER BY CONVERT(DATETIME,MESSAGEINSERTDATE,100)   
				END           
		END              
	DELETE MESSAGEQUEUEAIRTELPRI FROM MESSAGEQUEUEAIRTELPRI MQ JOIN @TEMPTABLE TT ON MQ.MESSAGEID=TT.MESSAGEID                         
	SELECT MESSAGEID,'91' + RTRIM(LTRIM(MOBILE)) AS MOBILE,RTRIM(LTRIM([MESSAGE])) AS [MESSAGE] ,RTRIM(LTRIM			(SENDERID))  AS SENDERID,U_ID,ISUNICODE,PRIORITY,BATCHID,OPERATOR  FROM @TEMPTABLE         
END 


