/* ============================================================
   Procedure: [dbo].[Usp_MovePremiumMessageToQueue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC Usp_MovePremiumMessageToQueue --7407,'WEAVES',10  
(  
@U_id Int,  
@senderid Varchar(20),  
@count Int  
)  
As  
Declare @query varchar(MAX)  
Declare @query1 varchar(MAX)  
DECLARE  @RowcountTemp BIGINT  
Begin  
Set @query='select top(' +convert(varchar,@count,12)+ ') MessageID,Mobile,[Message],SENDerID,smppid,1,U_ID,IsUniCode,                           
IsDND,Operator,Isallowdnd,BatchID from premiummessage where U_id='+convert(varchar,@U_id,12)+' and SenderID='''+@Senderid+''''  
Set @query1='select top(' +convert(varchar,@count,12)+ ') MessageID from premiummessage where U_id='+convert(varchar,@U_id,12)+' and SenderID='''+@Senderid+''''  
  
declare @tmptable table   
(  
MessageID varchar(20)  
)  
insert into @tmptable(MessageID) exec (@query1)  
insert into MessageQueueAirtelPri(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                 
IsDND,Operator,Isallowdnd,BatchID) exec (@query)  
Delete premiummessage from premiummessage p inner join @tmptable tmp on p.MessageID=tmp.MessageID and p.U_id=@U_id and p.SenderID=@Senderid  
SET @RowcountTemp =@@ROWCOUNT  
select @RowcountTemp  
End


GO

