/* ============================================================
   Procedure: [dbo].[usp_movereceivedeliverydata]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_movereceivedeliverydata
as
begin
declare @c bigint=(select count(1) From  [MySMS].dbo.ReceiveDeliveryData(nolock)  
Where datediff(d,CreatedDate,getdate()) != 0 )
while @c>0
begin
Insert into  [MySMSReport].dbo.ReceiveDeliveryDataHistory(Mobile,SenderID,[Submit Date],[Done Date],StatusWithErr,Processed,Messagetext,CreatedDate,SubmitRefID,Error )  
Select top 1000 Mobile,SenderID,[Submit Date],[Done Date],StatusWithErr,Processed,Messagetext,CreatedDate,SubmitRefID,Error   
From  [MySMS].dbo.ReceiveDeliveryData(nolock)  
Where datediff(d,CreatedDate,getdate()) != 0  order by id
Delete a from (select top (1000) * from [MySMS].dbo.ReceiveDeliveryData Where datediff(d,CreatedDate,getdate()) != 0  order by id) A
select @c=@C-1000
end
declare @c1 bigint=(select count(1) From  [MySMSReport].dbo.ReceiveDeliveryDataHistory(nolock)  
Where datediff(d,CreatedDate,getdate()) > 30 )
while @c1>0
begin
delete top (1000) from [MySMSReport].dbo.ReceiveDeliveryDataHistory  
Where datediff(d,CreatedDate,getdate()) > 30
select @c1=@c1-1000
end
--exec [MySMS].dbo.USP_INSERT_OPERATOR_DETAILS
--exec [MySMS].dbo.usp_get_daily_operator_status2
end


GO

