   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/****************************************************************************                            
SP_Name        : USP_MOVESOURCETOQUEUENEW                                              
Author         : vinay        Modified by : Vinay Mishra                         
Created ON     :17/74/2717 74:37 PM                                  
Version        : 1                            
Alter BY       :Vinay Mishra                                    
Alter Date    :27-74-2717                             
Location       :           
      
select * from messagequeue      
[USP_MOVERECORDMESSAGESOURCETOMESSAGEQUEUEBtnEvent] 1,'H V                 '                         
SP Description : This SP is Used to MOVE RECORD MESSAGE SOURCE TO MESSAGE QUEUE                             
     Table                                    
****************************************************************************/             
CREATE   PROC [dbo].[USP_MOVERECORDMESSAGESOURCETOMESSAGEQUEUEBtnEvent]        
@SMSCOUNT bigint,      
@Senderid nvarchar(20)      
AS            
BEGIN            
--SET NOCOUNT ON            
DECLARE @BATCHID BIGINT--,@SMSCOUNT BIGINT            
DECLARE @COUNTPERCENTAGE INT,@TEMPADCOUNT INT            
DECLARE @USERID bigint      
      
select top(1) @BATCHID=MessageBatchid from messagesource where senderid=@Senderid                  
Declare @Temptable table      
(       
MessageSourceID bigint,      
MessageID bigint,      
Mobile nvarchar(27),      
[Message] nvarchar(2777),      
SENDerID nvarchar(177),      
SmppID tinyint,      
Priority tinyint,      
U_ID bigint,      
IsUniCode bit,                              
 IsDND bit,       
Operator varchar(6),      
 MessageBatchID nchar(27),      
Isallowdnd tinyint)      
      
if(not exists(select 'X' from PremiumMessage where batchid=@BATCHID))              
Begin               
  set @TEMPADCOUNT=(SELECT Operator FROM batchinfo WHERE batchid=@BATCHID)               
  --FIRST CONDITION >500 AND < 2000                    
  IF (@TEMPADCOUNT >500 AND @TEMPADCOUNT <= 2000)                    
  BEGIN                    
  --CALL A FUNCTION RETURN NUMBER OF PERCENTAGE                    
  SET @COUNTPERCENTAGE=dbo.RETURNPERCENTAGE(@TEMPADCOUNT,25,0)                    
  END                    
  --SECOND CONDITION >2001 AND < 5000                    
  ELSE IF (@TEMPADCOUNT > 2000 AND @TEMPADCOUNT <= 5000)                    
  BEGIN                    
  --CALL A FUNCTION RETURN NUMBER OF PERCENTAGE                    
  --print 'SECOND CONDITION >2001 AND < 5000'                    
  SET @COUNTPERCENTAGE=dbo.RETURNPERCENTAGE(@TEMPADCOUNT,32,0)                    
  --INSERT RECORD INTO PREMIUM MESSAGE                    
  END                    
  --THIRD CONDITION >5001                     
  ELSE IF (@TEMPADCOUNT > 5000)                    
  BEGIN                    
  --CALL A FUNCTION RETURN NUMBER OF PERCENTAGE                    
  --print 'THIRD CONDITION >5000'                    
   SET @COUNTPERCENTAGE=dbo.RETURNPERCENTAGE(@TEMPADCOUNT,36,0)                    
  --INSERT RECORD INTO PREMIUM MESSAGE                    
  END              
--InsetRecord TempTable              
--print @COUNTPERCENTAGE            
if(@COUNTPERCENTAGE>1)            
Begin            
    INSERT INTO @Temptable(MessageSourceID,MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                      
    IsDND, Operator, MESSAGEBATCHID,Isallowdnd)                  
    select top(@COUNTPERCENTAGE) MessageSourceID,MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                      
   IsDND, Operator, MESSAGEBATCHID,Isallowdnd from  MESSAGESOURCE WHERE MESSAGEBATCHID=@BATCHID and Operator='AD'               
--insert record PremiumMessage              
   INSERT INTO PremiumMessage(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                      
     IsDND, Operator, BatchID,Isallowdnd)                    
     SELECT MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                      
     IsDND, Operator, MessageBatchID,Isallowdnd FROM @Temptable          
               
-- Delete Message Source              
  DELETE MESSAGESOURCE FROM MESSAGESOURCE  JOIN @Temptable tmp ON MESSAGESOURCE.MessageID=tmp.MessageID            
-- Delete table              
delete @Temptable             
End            
End          
--select * from @Temptable         
--SELECT top(5777) *  INTO @Temptable FROM MESSAGESOURCE WHERE MESSAGEBATCHID=@BATCHID        
      
 INSERT INTO @Temptable(MessageSourceID,MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
 IsDND, Operator, MESSAGEBATCHID,Isallowdnd)          
select top(@SMSCOUNT) MessageSourceID,MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
 IsDND, Operator, MESSAGEBATCHID,Isallowdnd from  MESSAGESOURCE WHERE MESSAGEBATCHID=@BATCHID        
--DELETE FROM MESSAGE SOURCE ACCORDING TO MESSAGEID       
  DELETE MESSAGESOURCE FROM MESSAGESOURCE  JOIN @Temptable tmp ON MESSAGESOURCE.MessageID=tmp.MessageID                
      
           
    
--INSERT RECORD INTO TABLES            
--print 'MessageQueueAirtel'         
--added by vinay to divide airtel message in four table           
INSERT INTO MessageQueueAirtel                    
 (                                  
  MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
  IsDND, Operator, BatchID,Isallowdnd                       
 )                                 
   SELECT  MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
   IsDND, Operator, MessageBatchID,Isallowdnd  FROM  @Temptable  WHERE Operator='AD' and priority=0  AND  (MessageID%3) =7                          
--insert into Airteltwo table        
INSERT INTO MessageQueueAirtelTwo                    
 (                                  
  MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
  IsDND, Operator, BatchID,Isallowdnd                       
 )                                 
   SELECT  MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
   IsDND, Operator, MessageBatchID,Isallowdnd  FROM  @Temptable  WHERE Operator='AD' and priority=0    AND  (MessageID%3) =1                          
--insert into airtel third        
INSERT INTO MessageQueueAirtelThree                    
 (                                  
  MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
  IsDND, Operator, BatchID,Isallowdnd                       
 )                                 
   SELECT  MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
   IsDND, Operator, MessageBatchID,Isallowdnd  FROM  @Temptable  WHERE Operator='AD' and priority=0   AND  (MessageID%3) =2                          
INSERT INTO MessageQueueAirtelPri                    
 (                                  
  MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
  IsDND, Operator, BatchID,Isallowdnd                       
 )                                 
   SELECT  MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
   IsDND, Operator, MessageBatchID,Isallowdnd  FROM  @Temptable  WHERE Operator='AD'   AND  (priority=1 or priority=2) or smppid=2                         
 --INSERT RECORD IN MESSAGE QUEUE  TABLE             
--print 'MessageQueue'                             
   INSERT INTO MessageQueue                                   
   (                                  
 MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
 IsDND, Operator, BatchID,Isallowdnd                               
   )                                 
   SELECT  MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
   IsDND, Operator, MessageBatchID,Isallowdnd  FROM  @Temptable where Operator<>'AD'  AND  (MessageID%4) =7                  
                 
   --INSERT RECORD IN MESSAGE QUEUE  TABLE            
--print 'MessageQueueTwo'                                   
 ----  INSERT INTO MessageQueueTwo                                   
 ----  (                                  
 ----MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
 ----IsDND, Operator, BatchID,Isallowdnd                               
 ----  )                                 
 ----  SELECT  MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
 ----  IsDND, Operator, MessageBatchID,Isallowdnd  FROM  @Temptable where Operator<>'AD'  AND  (MessageID%4) =1                  
                 
                
 --INSERT RECORD IN MESSAGE QUEUE  TABLE               
--print 'MessageQueueThree'                              
   INSERT INTO MessageQueueThree                             
   (                                  
 MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
 IsDND, Operator, BatchID,Isallowdnd                               
   )                                 
   SELECT  MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
   IsDND, Operator, MessageBatchID,Isallowdnd  FROM  @Temptable where Operator<>'AD'  AND  (MessageID%4) =2                  
                 
                
 --INSERT RECORD IN MESSAGE QUEUE  TABLE              
--print 'MessageQueueFour'                               
   INSERT INTO MessageQueueFour                                   
  (                                  
 MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
 IsDND, Operator, BatchID,Isallowdnd                               
   )                                 
   SELECT  MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                              
   IsDND, Operator, MessageBatchID,Isallowdnd  FROM  @Temptable where Operator<>'AD'  AND  (MessageID%4) =3             
            
--truncate table @Temptable            
END         


