/* ============================================================
   Procedure: [dbo].[USP_MoveRecordQueueToMessageStopped]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_MoveRecordQueueToMessageStopped] --'messagequeue',4334143  
@TableName nvarchar(300),  
@Batchid nvarchar(300)  
as  
Begin  
Declare @Query nvarchar(3000)  
Declare @DeleteQuery nvarchar(3000)  
set @Query='select messageid,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,isnull(Isallowdnd,0)  from '+@TableName+' where batchid='+@Batchid+''  
set @DeleteQuery='delete '+@TableName+' where batchid='+@Batchid+''  
insert into MessageStopped (messageid,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,MessageBatchID,Isallowdnd)  
Exec (@Query)  
exec (@DeleteQuery)  
  
End


GO

/* ============================================================
   Procedure: [dbo].[Usp_MoveSelectedDndNumberCloneTable]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
--Created by vinay Move TempMessageSource from CloneOfTempMessageSource    
CREATE   PROC [dbo].[Usp_MoveSelectedDndNumberCloneTable]        
@MsgID varchar(max),    
@IsAllow char(5)        
as          
begin transaction         
set nocount on   
Declare @smppid char(5)     
Declare @sqlInsert nvarchar(max)                            
declare @sqlDelete nvarchar(max)      
if @IsAllow = '1'  
   begin  
     set @smppid='3'    
   end  
   else  
    begin  
     set @smppid='1'  
    end  
set @sqlInsert= 'insert into CloneOfTempMessageSource(MessageID,Mobile,Message,SenderID,SmppID,Priority,User_ID,Unicode)     
select MessageID,Mobile,Message,SenderID,'+@smppid+',Priority,User_ID,Unicode from dbo.TempMessageSource where MessageID in '          
set @sqlInsert=@sqlInsert + '(' + @MsgID + ')'      
exec(@sqlInsert)      
if @@error<>0          
begin          
  -- Rollback the transaction          
    ROLLBACK          
    -- Raise an error and return          
    RAISERROR ('Please try again.', 16, 1)          
    RETURN          
end    
set @sqlDelete='delete from TempMessageSource where MessageID in '      
set @sqlDelete=@sqlDelete + '(' + @MsgID + ')'   
exec(@sqlDelete)      
if @@error=0          
begin          
commit transaction        
end





GO

/* ============================================================
