   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [DBO].[USP_MOVESELECTEDMONITORTOSOURCETABLE]          
@BATCHID VARCHAR(MAX),      
@FILTERMODE CHAR(5)
AS            
BEGIN TRANSACTION           
SET NOCOUNT ON     
DECLARE @SQLINSERT NVARCHAR(MAX) 
DECLARE @SQLUPDATE NVARCHAR(MAX)                             
DECLARE @SQLDELETE NVARCHAR(MAX)        
IF @FILTERMODE != ''    
BEGIN    
SET @SQLUPDATE='UPDATE BATCHINFO SET FILTERMODE=@FILTERMODE WHERE BATCHID IN '
SET @SQLUPDATE=@SQLUPDATE + '(' + @BATCHID + ')' 
EXEC(@SQLUPDATE)        
END 
SET @SQLINSERT= 'INSERT INTO MESSAGESOURCE([MESSAGEID],[MOBILE],[MESSAGE],MESSAGEBATCHID,[U_ID],[SENDERID],[SMPPID],[MESSAGEINSERTDATE],[ISUNICODE],[ISDND],[OPERATOR],[PRIORITY],ISALLOWDND[USERFILTER])       
SELECT [MESSAGEID],[MOBILE],[MESSAGE],[BATCHID],[U_ID],[SENDERID],[SMPPID],[MESSAGEINSERTDATE],[ISUNICODE],[ISDND],[OPERATOR],[PRIORITY],[ISALLOWDND],''MTIX_TR'' FROM DBO.MESSAGEMONITOR WHERE BATCHID IN '            
SET @SQLINSERT=@SQLINSERT + '(' + @BATCHID + ')'        
EXEC(@SQLINSERT)        
IF @@ERROR<>0            
BEGIN            
-- ROLLBACK THE TRANSACTION            
ROLLBACK            
-- RAISE AN ERROR AND RETURN            
RAISERROR ('PLEASE TRY AGAIN.', 16, 1)            
RETURN            
END      
SET @SQLDELETE='DELETE FROM MESSAGEMONITOR WHERE BATCHID IN '        
SET @SQLDELETE=@SQLDELETE + '(' + @BATCHID + ')'     
EXEC(@SQLDELETE)        
IF @@ERROR=0            
BEGIN            
COMMIT TRANSACTION          
END  



