/* ============================================================
   Procedure: [dbo].[usp_movethirtydaystosixdays7]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_movethirtydaystosixdays7    
as    
begin    
declare @t1 bigint=(Select count(1) From MySMS.dbo.ThirtyDaysHistory(nolock) Where datediff(d,MessageInsertDAte,getdate())> 30)    
select @t1    
while @t1>0    
begin   
SET XACT_ABORT ON ;           
RETRY:                                                   
BEGIN TRY                                                
BEGIN TRAN    
Insert into  [MySMSReport].dbo.SiXdaysHistory7(MessageID , Mobile , [Message] , SenderID , MessageStatus,    
MessageInsertDAte , U_ID , LastError, BatchID , IsDND , Operator , IsallowDND , Priority, dbtype,StatusCompletedTime,
StatusCompletedTimeSecs,StatusDescription,ProviderReference)  
Select  top 1000 MessageID , Mobile , [Message] , SenderID , MessageStatus,    
MessageInsertDAte , U_ID , LastError, BatchID , IsDND , Operator , IsallowDND , Priority, dbtype,StatusCompletedTime,
StatusCompletedTimeSecs,StatusDescription ,ProviderReference  
From  MySMS.dbo.ThirtyDaysHistory(nolock)Where datediff(d,MessageInsertDAte,getdate()) >30    
 order by ThirtyDaysHistoryid    
delete t from     
(select top 1000 * from MySMS.dbo.ThirtyDaysHistory(nolock)Where datediff(d,MessageInsertDAte,getdate()) >30    
 order by ThirtyDaysHistoryid) t    
set @t1=@t1-1000    
select @t1    
COMMIT                                                
END TRY                                                
                      
BEGIN CATCH                                                                                                    
IF @@TRANCOUNT>0                                                
ROLLBACK                                                
EXECUTE USP_INSERTERRORINFO;           
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number          
BEGIN          
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms          
GOTO RETRY -- Go to Label RETRY          
END                                                     
END CATCH           
end    
    
end



GO

/* ============================================================
   Procedure: [dbo].[USP_NormalALLOWMessage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/**************************      
This SP use for Normal Allow Messages of DNDMonitor and Spam      
created By Abhishek      
*************************/      
CREATE   PROC USP_NormalALLOWMessage          
@tableName varchar(200),          
@senderid varchar(100)          
as          
BEGIN          
if(@tableName='MessageMonitor')          
BEGIN          
insert into MessageSource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                           
IsDND,Operator,Isallowdnd,MessageBatchID,messageInsertDate) SELECT MessageID,Mobile,[Message],SENDerID,2,Priority,U_ID,IsUniCode,                                     
IsDND,Operator,2,BatchID,messageInsertDate FROM MessageMonitor WHERE senderid=@senderid and isnull(Priority,0)=1      
    
insert into MessageSource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                           
IsDND,Operator,Isallowdnd,MessageBatchID,messageInsertDate) SELECT MessageID,Mobile,[Message],SENDerID,2,Priority,U_ID,IsUniCode,                                     
IsDND,Operator,2,BatchID,messageInsertDate FROM MessageMonitor WHERE senderid=@senderid and isnull(Priority,0)=0        
    
delete From MessageMonitor where senderid=@senderid          
END          
          
IF @tableName='MessageSpam'          
BEGIN          
insert into MessageSource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                           
IsDND,Operator,Isallowdnd,MessageBatchID,messageInsertDate) SELECT MessageID,Mobile,[Message],SENDerID,2,Priority,U_ID,IsUniCode,                                     
IsDND,Operator,2,BatchID,messageInsertDate FROM MessageSpam WHERE senderid=@senderid  and isnull(Priority,0)=1      
    
insert into MessageSource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                           
IsDND,Operator,Isallowdnd,MessageBatchID,messageInsertDate) SELECT MessageID,Mobile,[Message],SENDerID,2,Priority,U_ID,IsUniCode,                                     
IsDND,Operator,2,BatchID,messageInsertDate FROM MessageSpam WHERE senderid=@senderid  and isnull(Priority,0)=0         
    
delete From MessageSpam where senderid=@senderid          
          
END          
END 


GO

/* ============================================================
   Procedure: [dbo].[USP_NotALLOWMessage]
