SET QUOTED_IDENTIFIER ON

CREATE   PROC USP_NotALLOWMessage  --'MessageSpam','AIOC2011'            
@tableName varchar(200),            
@senderid varchar(100)            
as            
BEGIN            
if(@tableName='MessageMonitor')            
BEGIN            
insert into messagesource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                              
IsDND,Operator,Isallowdnd,MessageBatchID) SELECT MessageID,Mobile,[Message],SENDerID,1,0,U_ID,isnull(IsUniCode,0),                                                              
IsDND,Operator,Isallowdnd,BatchID FROM MessageMonitor WHERE    isnull(ISDND,0)=0 and  ltrim(senderid)=@senderid            
            
insert into MessageDND(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                              
IsDND,Operator,BatchID) SELECT MessageID,Mobile,[Message],SENDerID,1,Priority,U_ID,isnull(IsUniCode,0),                                                              
IsDND,Operator,BatchID FROM MessageMonitor WHERE isnull(ISDND,0)=1 and  ltrim(senderid)=@senderid            
            
delete From MessageMonitor where ltrim(senderid)=@senderid            
            
END            
            
IF @tableName='MessageSpam'            
BEGIN            
insert into messagesource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                              
IsDND,Operator,Isallowdnd,MessageBatchID) SELECT MessageID,Mobile,[Message],SENDerID,1,0,U_ID,isnull(IsUniCode,0),                                                              
IsDND,Operator,Isallowdnd,BatchID FROM MessageSpam WHERE  isnull(ISDND,0)=0 and  ltrim(senderid)=@senderid            
            
insert into MessageDND(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                              
IsDND,Operator,BatchID) SELECT MessageID,Mobile,[Message],SENDerID,1,Priority,U_ID,isnull(IsUniCode,0),                                                              
IsDND,Operator,BatchID FROM MessageSpam WHERE isnull(ISDND,0)=1 and ltrim(senderid)=@senderid            
            
delete From MessageSpam where ltrim(senderid)=@senderid            
            
END            
END 


