CREATE   PROCEDURE usp_notificationexceptions  
(@parentid bigint,@Eventtype nvarchar(100),@isactive int,@mode nvarchar(100))  
as  
begin  
if exists(select 1 from notificationexceptions(nolock) where parentid=@parentid and mode=@mode and eventtype=@eventtype)  
begin  
update notificationexceptions set isactive=@isactive where parentid=@parentid and mode=@mode and eventtype=@eventtype  
print 'Record updated'
end  
else
begin  
insert into notificationexceptions(Parentid,Eventtype,isactive,mode)  
select @parentid,@eventtype,@isactive,@mode 
print 'Record created' 
end
end


