/* ============================================================
   Procedure: [dbo].[usp_obd_CallDeductedReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_obd_CallDeductedReport]
as
begin
	declare @CurrentDate datetime = getdate()

	declare 
		@HtmlWrapperStart nvarchar(max) = '<html><body>',
		@Body1 nvarchar(max),
		@Body2 nvarchar(max), 
		@Body3 nvarchar(max),
		@Body4 nvarchar(max),
		@HtmlWrapperEnd nvarchar(max) = '</body></html>'



	set @Body1 ='<H1>Kit19-80 and Mobile Like No: Cost Report '+cast (cast(getdate() as date) as nvarchar)      
	+'</H1><table border = 2><tr>      
	<th>Period</th><th>ProviderName</th><th>TotalCalls</th><th>Deducted</th>      
	<th>NotDeducted</th><th>CostApplied</th></tr>' 

	set @Body1 = @Body1 + CAST(( select 
		t.Period as 'td', '',
		t.ProviderName as 'td', '',
		t.TotalCalls as 'td', '',
		t.Deducted as 'td', '',
		t.NotDeducted as 'td', '',
		t.CostApplied as 'td', ''
	from ( select 
		format(cast(ei.created_on as date), 'dd-MMM-yyyy') as [Period], 
		ProviderName,
		count(1) as TotalCalls,
		sum(case when isnull(ic.Debits, 0 ) > 0 then 1 else 0 end) as [Deducted],
		sum(case when isnull(ic.Debits, 0 ) = 0 then 1 else 0 end) as [NotDeducted],
		sum(isnull(ic.Debits, 0)) as [CostApplied]
	from tbl_voip_endpointInteraction(nolock) ei
		left join IntCredit_Details(nolock) ic on ei.kei_IntCreditId = ic.Credit_ID
		where cast(ei.created_on as date) = cast(@CurrentDate as date) 
		group by cast(ei.created_on as date), ProviderName
	union 
	select 
		FORMAT(ei.created_on, 'MMM-yyyy') as [Period], 
		ProviderName,
		count(1) as TotalCalls,
		sum(case when isnull(ic.Debits, 0 ) > 0 then 1 else 0 end) as [Deducted],
		sum(case when isnull(ic.Debits, 0 ) = 0 then 1 else 0 end) as [NotDeducted],
		sum(isnull(ic.Debits, 0)) as [CostApplied]
	from tbl_voip_endpointInteraction(nolock) ei
		left join IntCredit_Details(nolock) ic on ei.kei_IntCreditId = ic.Credit_ID
		where 
			FORMAT(ei.created_on, 'MMM-yyyy') =  FORMAT(@CurrentDate, 'MMM-yyyy') 
		group by FORMAT(ei.created_on, 'MMM-yyyy'), ProviderName

	) t FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX)) + '</table>'

	print @Body1

	set @Body2 ='<H1>Kit19-80 and Mobile Like No: Cost Report User Wise </H1><table border = 2><tr>      
	<th>Period</th><th>UserLogin</th><th>ProviderName</th><th>TotalCalls</th><th>Deducted</th>      
	<th>NotDeducted</th><th>CostApplied</th></tr>' 

	set @Body2 = @Body2 + CAST(( select 
		format(cast(ei.created_on as date), 'dd-MMM-yyyy') as 'td', '', 
		ud.User_Login as 'td', '',
		ProviderName as 'td', '',
		count(1)  as 'td', '',
		sum(case when isnull(ic.Debits, 0 ) > 0 then 1 else 0 end) as 'td', '',
		sum(case when isnull(ic.Debits, 0 ) = 0 then 1 else 0 end) as 'td', '',
		sum(isnull(ic.Debits, 0)) as 'td', ''
	from tbl_voip_endpointInteraction(nolock) ei
			inner join User_Detail(nolock) ud on ei.tei_parentid = ud.User_ID
		left join IntCredit_Details(nolock) ic on ei.kei_IntCreditId = ic.Credit_ID
		where cast(ei.created_on as date) = cast(getdate() as date)
		group by cast(ei.created_on as date), ei.tei_parentid, ud.User_Login, ProviderName
	FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX)) + '</table>'

	print @Body2

	set @Body3 ='<H1>IVR Flow Cost Deducted Rport ' + +cast (cast(getdate() as date) as nvarchar)
		+ '</H1><table border = 2><tr><th>Period</th><th>CostApplied</th><th>TotalContacts</th></tr>' 

	set @Body3 = @Body3 + CAST(( select 
		ir.Period as 'td', '',
		ir.CostApplied as 'td', '',
		ir.TotalContact  as 'td', ''
	from ( select 
		format(cast(ivr.ScheduleOn as date), 'dd-MMM-yyyy') as [Period],
		sum(ivr.Debits) as CostApplied,
		sum(ivr.TotalContact) as [TotalContact]
	from ( select isd.id, cast(isd.ScheduleOn as date) [ScheduleOn], isd.ParentId, icd.Debits,
		icd.Credits, (select top 1 count(1) 
			from tbl_obd_IvrDesignDataContact(nolock) c 
		where c.IvrDesignId = isd.id) as [TotalContact]
	from tbl_obd_IvrScheduleData(nolock) isd
		left join IntCredit_Details(nolock) icd on isd.ParentId = icd.User_ID and isd.Id = icd.BatchId
	where cast(isd.CreatedOn as date) > '20230630' ) ivr
		left join User_Detail(nolock) ud on ivr.ParentId = ud.User_ID
	where ivr.ScheduleOn = cast(@CurrentDate as date)
	group by ivr.ScheduleOn
	union
	select 
		FORMAT(ivr.ScheduleOn, 'MMM-yyyy') as [Period], 
		sum(ivr.Debits) as CostApplied,
		sum(ivr.TotalContact) as [TotalContact]
	from ( select isd.id, cast(isd.ScheduleOn as date) [ScheduleOn], isd.ParentId, icd.Debits,
		icd.Credits, (select top 1 count(1) 
			from tbl_obd_IvrDesignDataContact(nolock) c 
		where c.IvrDesignId = isd.id) as [TotalContact]
	from tbl_obd_IvrScheduleData(nolock) isd
		left join IntCredit_Details(nolock) icd on isd.ParentId = icd.User_ID and isd.Id = icd.BatchId
	where cast(isd.CreatedOn as date) > '20230630' ) ivr
		left join User_Detail(nolock) ud on ivr.ParentId = ud.User_ID
	where FORMAT(ivr.ScheduleOn, 'MMM-yyyy') =  FORMAT(@CurrentDate, 'MMM-yyyy') 
	group by FORMAT(ivr.ScheduleOn, 'MMM-yyyy')
	) ir FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX)) + '</table>'
		
	print @Body3

	set @Body4 ='<H1>Kit19-80: Cost & Report User Wise </H1><table border = 2><tr>      
	<th>Period</th><th>TotalRequest</th><th>WebhookReceived</th><th>WebhookNotReceived</th><th>CostDeducted</th>      
	<th>NotDeducted</th></tr>' 

	print @CurrentDate
	set @Body4 = @Body4 + CAST(( select 
		cast( ei.created_on as date) as 'td', '',
		COUNT(1)  as 'td', '',
		sum(case when isnull(pt.UniqueIdentity, '') = '' then 0 else 1 end)  as 'td', '',
		sum(case when isnull(pt.UniqueIdentity, '') <> '' then 0 else 1 end)  as 'td', '',
		sum(case when isnull(ic.Credit_ID, '') = '' then 0 else 1 end)  as 'td', '',
		sum(case when isnull(ic.Credit_ID, '') <> '' then 0 else 1 end) as 'td', '',
		sum(isnull(ic.Debits, 0))  as 'td', ''
		--tei_parentid, ProviderName, kei_IntCreditId, ic.Debits,  pt.*
		from tbl_voip_endpointInteraction(nolock) ei 
		left join ( select 
			UniqueIdentity, MobileCallAgentStart, MobileCallCustomerStart, MobileCallEnd
			from (  select mode, UniqueIdentity, Count(1) as [countValue] from tbl_voip_Kit19Webhooks(nolock) w
				where cast(w.created_on as date) = cast(@CurrentDate as date) group by mode, UniqueIdentity 
			) as pw PIVOT ( max(countValue)
				FOR mode in (MobileCallAgentStart, MobileCallCustomerStart, MobileCallEnd)
		) as pvt ) pt on ei.id = pt.UniqueIdentity
		left join IntCredit_Details(nolock) ic on ei.kei_IntCreditId = ic.Credit_ID
		where cast( ei.created_on as date)  = cast(@CurrentDate as date) and ei.ProviderName = 'Kit19 80'
		group by cast( ei.created_on as date) FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX)) + '</table>'

	print @Body4

	drop table if exists #t
	select id, CAST(0 as bit) as [isprocess] into #t from tbl_voip_endpointInteraction(nolock) w where w.ProviderName = 'Kit19 80'
	and cast(w.created_on as date) = @CurrentDate and isnull(kei_IntCreditId, 0) = 0

	while(exists(select 1 from #t where isprocess = 0))
	begin
		declare @id bigint = 0, @isprocess int = 0
		select top 1 @id = id, @isprocess = isprocess from #t where isprocess = 0
		print @id
		exec usp_voip_DedectCallChargeKit1980 @id
		update #t set isprocess = 1 where id = @id
	end




	set @HtmlWrapperStart = 
		isnull(@HtmlWrapperStart, '') +
		isnull(@Body1, '') + 
		isnull(@Body2, '') + 
		isnull(@Body3, '') + 
		isnull(@Body4, '') + 
		isnull(@HtmlWrapperEnd, '')
	


	EXEC usp_enqueueemail              
	@profile_name='Alerts',               
	@recipients='csshukla@pelsoftlabs.in',              
	@blind_copy_recipients='karuna@pelsoftlabs.in;mukesh-kumar@pelsoftlabs.in',              
	@subject='Click2Call & Voice IVR Amount Deducted Report',              
	@body = @HtmlWrapperStart,              
	@body_format ='HTML',    
	@from_address='Click2Call & Voice IVR Amount Deducted Report <noreply@kit19.com>';   


end



GO

/* ============================================================
   Procedure: [dbo].[usp_obd_CallDeductedReport_KK]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
/*  
Revision : 1  
 Author : DBA  
 Date : 2025-08-12  
 Remarks : Queries modified to use the indexes properly  
*/  
CREATE   PROCEDURE [dbo].[usp_obd_CallDeductedReport_KK]  
as  
begin  
 declare @CurrentDate datetime = getdate()  
  
  
 /*   
 Added By DBA   
 Date: 2025-08-12  
 */  
 DECLARE @from_dt DATETIME  
 DECLARE @to_dt DATETIME  
  
 DECLARE @from_month_dt DATETIME  
 DECLARE @to_month_dt DATETIME  
  
 SELECT @from_dt = CAST(CAST(@CurrentDate AS DATE) AS DATETIME)  
 SELECT @to_dt = DATEADD(DAY, 1, @from_dt)  
  
 SELECT   
   @from_month_dt = DATEADD(DAY, 1, EOMONTH(@CurrentDate, -1))  
  ,@to_month_dt = DATEADD(day, 1, EOMONTH(@CurrentDate));  
   
 declare   
  @HtmlWrapperStart nvarchar(max) = '<html><body>',  
  @Body1 nvarchar(max),  
  @Body2 nvarchar(max),   
  @Body3 nvarchar(max),  
  @Body4 nvarchar(max),  
  @HtmlWrapperEnd nvarchar(max) = '</body></html>'  
  
  
  
 set @Body1 ='<H1>Kit19-80 and Mobile Like No: Cost Report '+cast (cast(getdate() as date) as nvarchar)        
 +'</H1><table border = 2><tr>        
 <th>Period</th><th>ProviderName</th><th>TotalCalls</th><th>Deducted</th>        
 <th>NotDeducted</th><th>CostApplied</th></tr>'   
  
  
 set @Body1 = @Body1 + CAST(( select   
  t.Period as 'td', '',  
  t.ProviderName as 'td', '',  
  t.TotalCalls as 'td', '',  
  t.Deducted as 'td', '',  
  t.NotDeducted as 'td', '',  
  t.CostApplied as 'td', ''  
 from ( select   
  format(cast(ei.created_on as date), 'dd-MMM-yyyy') as [Period],   
  ProviderName,  
  count(1) as TotalCalls,  
  sum(case when isnull(ic.Debits, 0 ) > 0 then 1 else 0 end) as [Deducted],  
  sum(case when isnull(ic.Debits, 0 ) = 0 then 1 else 0 end) as [NotDeducted],  
  sum(isnull(ic.Debits, 0)) as [CostApplied]  
 from tbl_voip_endpointInteraction(nolock) ei  
  left join IntCredit_Details(nolock) ic on ei.kei_IntCreditId = ic.Credit_ID  
  --where cast(ei.created_on as date) = cast(@CurrentDate as date)   
  WHERE ei.created_on BETWEEN @from_dt AND @to_dt -- DBA  
  group by cast(ei.created_on as date), ProviderName  
 union   
 select   
  FORMAT(ei.created_on, 'MMM-yyyy') as [Period],   
  ProviderName,  
  count(1) as TotalCalls,  
  sum(case when isnull(ic.Debits, 0 ) > 0 then 1 else 0 end) as [Deducted],  
  sum(case when isnull(ic.Debits, 0 ) = 0 then 1 else 0 end) as [NotDeducted],  
  sum(isnull(ic.Debits, 0)) as [CostApplied]  
 from tbl_voip_endpointInteraction(nolock) ei  
  left join IntCredit_Details(nolock) ic on ei.kei_IntCreditId = ic.Credit_ID  
  --where   
  -- FORMAT(ei.created_on, 'MMM-yyyy') =  FORMAT(@CurrentDate, 'MMM-yyyy')   
  WHERE ei.created_on BETWEEN @from_month_dt AND @to_month_dt -- DBA  
  group by FORMAT(ei.created_on, 'MMM-yyyy'), ProviderName  
  
 ) t FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX)) + '</table>'  
  
 print @Body1  
  
 set @Body2 ='<H1>Kit19-80 and Mobile Like No: Cost Report User Wise </H1><table border = 2><tr>        
 <th>Period</th><th>UserLogin</th><th>ProviderName</th><th>TotalCalls</th><th>Deducted</th>        
 <th>NotDeducted</th><th>CostApplied</th></tr>'   
  
 set @Body2 = @Body2 + CAST(( select   
  format(cast(ei.created_on as date), 'dd-MMM-yyyy') as 'td', '',   
  ud.User_Login as 'td', '',  
  ProviderName as 'td', '',  
  count(1)  as 'td', '',  
  sum(case when isnull(ic.Debits, 0 ) > 0 then 1 else 0 end) as 'td', '',  
  sum(case when isnull(ic.Debits, 0 ) = 0 then 1 else 0 end) as 'td', '',  
  sum(isnull(ic.Debits, 0)) as 'td', ''  
 from tbl_voip_endpointInteraction(nolock) ei  
   inner join User_Detail(nolock) ud on ei.tei_parentid = ud.User_ID  
  left join IntCredit_Details(nolock) ic on ei.kei_IntCreditId = ic.Credit_ID  
  --where cast(ei.created_on as date) = cast(getdate() as date)  
  WHERE ei.created_on BETWEEN @from_month_dt AND @to_month_dt -- DBA  
  group by cast(ei.created_on as date), ei.tei_parentid, ud.User_Login, ProviderName  
 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX)) + '</table>'  
  
 print @Body2  
  
   
 set @Body3 ='<H1>IVR Flow Cost Deducted Rport ' + +cast (cast(getdate() as date) as nvarchar)  
  + '</H1><table border = 2><tr><th>Period</th><th>CostApplied</th><th>TotalContacts</th></tr>'   
  
  
 set @Body3 = @Body3 + CAST(( select   
  ir.Period as 'td', '',  
  ir.CostApplied as 'td', '',  
  ir.TotalContact  as 'td', ''  
 from ( select   
  format(cast(ivr.ScheduleOn as date), 'dd-MMM-yyyy') as [Period],  
  sum(ivr.Debits) as CostApplied,  
  sum(ivr.TotalContact) as [TotalContact]  
 from ( select isd.id, cast(isd.ScheduleOn as date) [ScheduleOn], isd.ParentId, icd.Debits,  
  icd.Credits, (select top 1 count(1)   
   from tbl_obd_IvrDesignDataContact(nolock) c   
  where c.IvrDesignId = isd.id) as [TotalContact]  
 from tbl_obd_IvrScheduleData(nolock) isd  
  left join IntCredit_Details(nolock) icd on isd.ParentId = icd.User_ID and isd.Id = icd.BatchId  
 where cast(isd.CreatedOn as date) > '20230630' ) ivr  
  left join User_Detail(nolock) ud on ivr.ParentId = ud.User_ID  
 where ivr.ScheduleOn = cast(@CurrentDate as date)  
 group by ivr.ScheduleOn  
 union  
 select   
  FORMAT(ivr.ScheduleOn, 'MMM-yyyy') as [Period],   
  sum(ivr.Debits) as CostApplied,  
  sum(ivr.TotalContact) as [TotalContact]  
 from ( select isd.id, cast(isd.ScheduleOn as date) [ScheduleOn], isd.ParentId, icd.Debits,  
  icd.Credits, (select top 1 count(1)   
   from tbl_obd_IvrDesignDataContact(nolock) c   
  where c.IvrDesignId = isd.id) as [TotalContact]  
 from tbl_obd_IvrScheduleData(nolock) isd  
  left join IntCredit_Details(nolock) icd on isd.ParentId = icd.User_ID and isd.Id = icd.BatchId  
 where cast(isd.CreatedOn as date) > '20230630' ) ivr  
  left join User_Detail(nolock) ud on ivr.ParentId = ud.User_ID  
 where FORMAT(ivr.ScheduleOn, 'MMM-yyyy') =  FORMAT(@CurrentDate, 'MMM-yyyy')   
 group by FORMAT(ivr.ScheduleOn, 'MMM-yyyy')  
 ) ir FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX)) + '</table>'  
    
 print @Body3  
  
   
 set @Body4 ='<H1>Kit19-80: Cost & Report User Wise </H1><table border = 2><tr>        
 <th>Period</th><th>TotalRequest</th><th>WebhookReceived</th><th>WebhookNotReceived</th><th>CostDeducted</th>        
 <th>NotDeducted</th></tr>'   
  
 print @CurrentDate  
  
 DROP TABLE IF EXISTS #tPvt  
  
  select   
    UniqueIdentity, MobileCallAgentStart, MobileCallCustomerStart, MobileCallEnd  
  INTO #tPvt  
     from (    
      select mode, UniqueIdentity, Count(1) as [countValue] from tbl_voip_Kit19Webhooks(nolock) w  
      --where cast(w.created_on as date) = cast(@CurrentDate as date)   
      WHERE w.created_on BETWEEN @from_dt AND @to_dt -- DBA  
      group by mode, UniqueIdentity   
     ) as pw PIVOT ( max(countValue)  
      FOR mode in (MobileCallAgentStart, MobileCallCustomerStart, MobileCallEnd)  
    ) as pvt  
  
 set @Body4 = @Body4 + CAST(( select   
  cast( ei.created_on as date) as 'td', '',  
  COUNT(1)  as 'td', '',  
  sum(case when isnull(pt.UniqueIdentity, '') = '' then 0 else 1 end)  as 'td', '',  
  sum(case when isnull(pt.UniqueIdentity, '') <> '' then 0 else 1 end)  as 'td', '',  
  sum(case when isnull(ic.Credit_ID, '') = '' then 0 else 1 end)  as 'td', '',  
  sum(case when isnull(ic.Credit_ID, '') <> '' then 0 else 1 end) as 'td', '',  
  sum(isnull(ic.Debits, 0))  as 'td', ''  
  --tei_parentid, ProviderName, kei_IntCreditId, ic.Debits,  pt.*  
  from tbl_voip_endpointInteraction(nolock) ei   
  /*  
  left join (   
  select   
   UniqueIdentity, MobileCallAgentStart, MobileCallCustomerStart, MobileCallEnd  
   from (  select mode, UniqueIdentity, Count(1) as [countValue] from tbl_voip_Kit19Webhooks(nolock) w  
    --where cast(w.created_on as date) = cast(@CurrentDate as date)   
    WHERE w.created_on BETWEEN @from_dt AND @to_dt -- DBA  
    group by mode, UniqueIdentity   
   ) as pw PIVOT ( max(countValue)  
    FOR mode in (MobileCallAgentStart, MobileCallCustomerStart, MobileCallEnd)  
  ) as pvt )   
  */  
  left join #tPvt AS pt on ei.id = pt.UniqueIdentity  
  left join IntCredit_Details(nolock) ic on ei.kei_IntCreditId = ic.Credit_ID  
  --where cast( ei.created_on as date)  = cast(@CurrentDate as date)   
  WHERE ei.created_on BETWEEN @from_dt AND @to_dt -- DBA  
  and ei.ProviderName = 'Kit19 80'  
  group by cast( ei.created_on as date) FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX)) + '</table>'  
  
 print @Body4  
  
 drop table if exists #t  
 select id, CAST(0 as bit) as [isprocess] into #t from tbl_voip_endpointInteraction(nolock) w where w.ProviderName = 'Kit19 80'  
 and cast(w.created_on as date) = @CurrentDate and isnull(kei_IntCreditId, 0) = 0  
  
 --while(exists(select 1 from #t where isprocess = 0))  
 --begin  
 -- declare @id bigint = 0, @isprocess int = 0  
 -- select top 1 @id = id, @isprocess = isprocess from #t where isprocess = 0  
 -- print @id  
 -- exec usp_voip_DedectCallChargeKit1980 @id  
 -- update #t set isprocess = 1 where id = @id  
 --end  
  
  
  
  
 set @HtmlWrapperStart =   
  isnull(@HtmlWrapperStart, '') +  
  isnull(@Body1, '') +   
  isnull(@Body2, '') +   
  isnull(@Body3, '') +   
  isnull(@Body4, '') +   
  isnull(@HtmlWrapperEnd, '')  
   
  
  
 EXEC usp_enqueueemail                
 @profile_name='Alerts',                 
 @recipients='csshukla@pelsoftlabs.in',                
 @blind_copy_recipients='karuna@pelsoftlabs.in;mukesh-kumar@pelsoftlabs.in',                
 @subject='Click2Call & Voice IVR Amount Deducted Report',                
 @body = @HtmlWrapperStart,                
 @body_format ='HTML',      
 @from_address='Click2Call & Voice IVR Amount Deducted Report <noreply@kit19.com>';     
   
  
end  
  


