/* ============================================================
   Procedure: [dbo].[usp_obd_DeleteObdBroadcast]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_obd_DeleteObdBroadcast(
	@BatchId bigint,
	@UserId bigint
)
as
begin
begin transaction
begin try
if(isnull(@BatchId, 0) > 0)
	begin
		if(exists(select * from  tbl_obd_ScheduleRecord(nolock) where Processed = 0))
		begin
			update tbl_obd_ScheduleRecord set is_deleted  = 1, deleted_by = @UserId, deleted_on = GETDATE() where BatchId = @BatchId
			
			declare @Cost decimal(18,4) = 0 - (select sum(Price) from tbl_obd_ScheduleRecord(nolock) where BatchId = @BatchId)
			declare @MId bigint, @ParentId bigint 

			select top 1 @ParentId = ParentId from tbl_obd_ScheduleRecord(nolock) where BatchId = @BatchId

			select  @MId = M_ID from User_Detail(nolock) where ParentID = @ParentId;
			declare @Remarks nvarchar(max) = concat('Amount Refunded for Voice Broadcast of BatchId ', cast(@BatchId as nvarchar))
			exec proc_UpdateIntCreditDetail_new 
					@M_ID = @MId,
					@User_ID = @UserId,
					@Price = @Cost,
					@BATCHID = @BatchId,
					@remark = @Remarks,
					@typecredit = 1
		end
	end
	commit transaction
end try
begin catch
	rollback transaction
	exec usp_InsertErrorInfo
end catch
end




GO

