/* ============================================================
   Procedure: [dbo].[usp_obd_GetAudioFileDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE usp_obd_GetAudioFileDetails(
	@UserId bigint,
	@OffsetValue int = 0, 
	@PazeSize int = 20
)
as
begin
	declare @ParentId bigint  = (select ParentId from User_Detail(nolock) where User_ID = @UserId )
	select 
		count(al.id) over() as TotalRow,
		al.id as FileId,
		al.filename,
		al.filepath,
		al.filesize,
		al.duration,
		al.created_on,
		al.status,
		al.created_by,
		al.parent_id,
		concat(isnull(cu.FName, ''), ' ', isnull(cu.LName, ''), '(', cu.User_Login, ')') as CreatedName
	from tbl_obd_AudioLibrary(nolock) al
		inner join User_Detail(nolock) cu on al.created_by = cu.User_ID
		where al.parent_id = @ParentId and al.is_deleted = 0
	 order by al.created_on desc offset @OffsetValue rows fetch next @PazeSize rows only
end


GO

