/* ============================================================
   Procedure: [dbo].[usp_obd_GetScheduledOBDs]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_obd_GetScheduledOBDs(
	@BatchId bigint,
	@OffsetValue int = 0,
	@PagingSize int = 10000
)
as
begin

	drop table if exists #tempMobiles

	select ObdId, BatchId, CountryCode, DidNo, MobileNo, VoiceDuration, IsPrority, Processed, Price, UserId, VoiceInsertDate, VoiceType, ScheduleDate, VoiceStatus, Route, ParentId, JobId, CampaignId, VoiceSource, VoicePath, ProcessAt, VoiceStatusTime, AttemptCount, AudioLibraryId, BatchStartTime, BatchEndTime, CampaignName into #tempMobiles
	from tbl_obd_ScheduleRecord(nolock) where  BatchId = @BatchId
	 order by ObdId 
		offset @OffsetValue rows fetch next @PagingSize rows only;

	update sr set sr.PickedTime = GETDATE(), sr.Processed = 2 from tbl_obd_ScheduleRecord sr
		inner join  #tempMobiles t on sr.ObdId = t.ObdId
		 where sr.ObdId = t.ObdId

	select * from #tempMobiles
end


GO

/* ============================================================
   Procedure: [dbo].[usp_obd_GetUnproccessBroadcast]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_obd_GetUnproccessBroadcast  
as  
begin  
 drop table if exists #tempVoice  
 select s.Id, s.ContactType, s.ContactNubmers, s.ContactGroups, s.ContactCsv,   
 s.ScheduleOn, d.design_name, d.design_json, a.id as [AudioId], a.filename as [AudioName],  
 CampaignName, [Route], CampaignId  
  into #tempVoice  
 from tbl_obd_IvrScheduleData(nolock) s  
  left join tbl_voip_IvrDesign(nolock) d on s.IvrDesignId = d.id  
  left join tbl_obd_AudioLibrary(nolock) a on s.AudioFileId = a.id  
  where s.IsActive = 1 and s.IsDeleted = 0  and s.IsProccess = 0   
  and s.ScheduleOn < getdate()  
   
 update s set s.IsProccess = 2 from #tempVoice t  
  inner join tbl_obd_IvrScheduleData(nolock) s on t.Id = s.Id  
  
 select * from #tempVoice  
end  



GO

