/* ============================================================
   Procedure: [dbo].[usp_obd_IvrSaveProccessedNo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE   PROCEDURE [dbo].[usp_obd_IvrSaveProccessedNo](    
 @dtMobileNo dtIvrMobileNos readonly,    
 @AudioDurations decimal(18, 4),    
 @ResponseTimeout int,    
 @CamplainId bigint,    
 @BroadcastId bigint    
)    
as    
begin    
    
 --declare     
 -- @dtMobileNo as dtIvrMobileNos,    
 -- @AudioDurations decimal(18, 4) = 33.5296,    
 -- @BroadcastId bigint = 1,    
 -- @ResponseTimeout int  = 10,    
 -- @CamplainId bigint = 15850    
      
    
 --insert into @dtMobileNo values(1,N'98215492374')    
    
 --select * from @dtMobileNo    
    
    
 declare @ParentId bigint, @FileName nvarchar(255), @FilePath nvarchar(2000), @VoiceDuration decimal(18, 4),    
  @Pulse int, @Price decimal(18,4),@Cost decimal(18,4),@aPulse int, @mCount int, @BatchId bigint, @TotalBalance decimal(18, 4), @UserId bigint, @ScheduleDateTime datetime, @Route nvarchar(255), @CampainName nvarchar(255),    
  @CampainId bigint, @MId bigint    
    
 update tbl_obd_IvrScheduleData set CampaignId  = @CamplainId where id = @BroadcastId    
    
 select @UserId = CreatedBy, @ParentId = ParentId, @ScheduleDateTime = isnull(ScheduleOn, dateadd(MINUTE, -1, getdate())), @Route = [Route], @CampainName = CampaignName from tbl_obd_IvrScheduleData(nolock) where id = @BroadcastId    
     
 --insert into GetBatchRecord (User_id,RandNum) values( @UserId, FLOOR(RAND()* 100000))                  
 select @BatchId= @BroadcastId    
 --delete from GetBatchRecord  where BatchID=@BatchId     
    
 select @ParentId = ParentID, @MId = M_ID from User_Detail(nolock) where User_ID = @UserId    
 select @VoiceDuration = @AudioDurations + @ResponseTimeout    
    
 set @mCount = ( select COUNT(*) from @dtMobileNo )     
    
 select top 1 @Pulse = pulse_sec, @Price=price from tbl_obd_Base_Price(nolock)    
 where service_type = 'broadcast' and ( ParentId = @ParentId or ParentId = 0 ) order by parentid desc    
    
 set @aPulse = ceiling(@VoiceDuration/cast(@Pulse as float))    
    
 set @Cost = @aPulse * @Price * @mCount    
     
 select  @TotalBalance = balance FROM IntCredit_Details c with (nolock) where user_ID=@parentid and Credit_ID=(select max(credit_id) from IntCredit_Details c1 with (nolock)  where c.user_id=c1.User_ID)    
    
 --select @Cost, @TotalBalance   

 DECLARE @avilablebalance decimal(18, 4)    
 EXEC @avilablebalance = dbo.GetAvailableBalanceForService @parentid, 1 
    
 if(@cost>0 and @Cost <= @avilablebalance)    
 begin    
     
 declare @Remarks nvarchar(max) = concat('Amount Deducted for Voice Broadcast of IvrFlow BroadcastId ', cast(@BatchId as nvarchar), ' Scheduled at ', format(@ScheduleDateTime, 'dd-MMM-yyyy HH:mms:ss'))    
    
  exec proc_UpdateIntCreditDetail_new     
   @M_ID = @MId,    
   @User_ID = @UserId,    
   @Price = @Cost,    
   @BATCHID = @BatchId,    
   @remark = @Remarks,    
   @typecredit = 1    
    
  --proc_UpdateIntCreditDetail_new procedure with remarks     
    
  insert into tbl_obd_IvrDesignDataContact(IvrDesignId, CountryCode, MobileNo, VoiceDuration, IsPrority, Processed, Price, UserId, VoiceInsertDate, VoiceType, ScheduleDate, Route, ParentId, CampaignId, CampaignName)    
  select @BatchId, '', mobileno, @AudioDurations, 2, 1, @Price, @UserId, GETDATE(), '', @ScheduleDateTime, @Route, @ParentId, @CamplainId, @CampainName    
  from @dtMobileNo    
    
     
  select 1 as code, 'Data submitted successfully' as remarks    
 end    
 else    
 begin    
  select 0 as code, 'Balance is not sufficient.' as remarks    
 end    
     
end 



GO

