CREATE   PROCEDURE usp_obd_SaveIvrScheduleData(      
 @IvrDesignId bigint = null,      
 @AudioFileId bigint = null,      
 @ScheduleOn datetime,      
 @ContactType nvarchar(25),      
 @ContactNubmers nvarchar(max),      
 @ContactGroups nvarchar(max),      
