/* ============================================================
   Procedure: [dbo].[usp_obd_SaveObdBroadcast]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
CREATE   PROCEDURE [dbo].[usp_obd_SaveObdBroadcast](  
 @UserId bigint,  
 @MId bigint,  
 @DnidNumber nvarchar(50),  
 @ScheduleDateTime datetime = null,  
 @FileId bigint,  
 @Route nvarchar(10),  
 @ObdMoblieNos ObdSaveType readonly  
)  
as  
begin  
 declare @ParentId bigint, @FileName nvarchar(255), @FilePath nvarchar(2000), @VoiceDuration decimal(18, 4),  
  @Pulse int, @Price decimal(18,4),@Cost decimal(18,4),@aPulse int, @mCount int, @BatchId bigint, @TotalBalance decimal(18, 4), @avilableBalance decimal(18, 4)  
   
 insert into GetBatchRecord (User_id,RandNum) values( @UserId, FLOOR(RAND()* 100000))                
 select @BatchId=SCOPE_IDENTITY()  
 delete from GetBatchRecord  where BatchID=@BatchId   
  
 select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId  
 select @FileName = filename, @FilePath = filepath, @VoiceDuration = duration from tbl_obd_AudioLibrary(nolock) where id = @FileId;  
  
 set @mCount = ( select COUNT(*) from @ObdMoblieNos )   
  
 select top 1 @Pulse = pulse_sec, @Price=price from tbl_obd_Base_Price(nolock)  
  where service_type = 'broadcast' and (ParentId = @ParentId or ParentId = 0) order by parentid desc  
  
 set @aPulse = ceiling(@VoiceDuration/cast(@Pulse as float))  
  
 set @Cost = @aPulse * @Price * @mCount  
  
  DECLARE @abilableBalance as decimal(18,4) = 0  
  set @abilableBalance = dbo.GetAvailableBalanceForService(@parentid, 1)  
  
 select top 1 @TotalBalance = balance FROM IntCredit_Details c with (nolock)   
    where user_ID=@parentid order by Credit_ID desc
  
 if(@Cost <= @abilableBalance)  
 begin  
  declare @Remarks nvarchar(max) = concat('Amount Deducted for Voice Broadcast of Batchid ', cast(@BatchId as nvarchar))  
  
  exec proc_UpdateIntCreditDetail_new   
   @M_ID = @MId,  
   @User_ID = @UserId,  
   @Price = @Cost,  
   @BATCHID = @BatchId,  
   @remark = @Remarks,  
   @typecredit = 1  
  
  --proc_UpdateIntCreditDetail_new procedure with remarks   
  
  insert into tbl_obd_ScheduleRecord(BatchId, CountryCode, DidNo, MobileNo, VoiceDuration, IsPrority, Processed, Price, UserId, VoiceInsertDate, VoiceType, ScheduleDate, VoiceStatus, Route,   
        ParentId, CampaignId, VoiceSource, VoicePath, AttemptCount, AudioLibraryId, CampaignName)  
  select @BatchId, '', @DnidNumber, MobileNos, @VoiceDuration, 2, 0, @Price, @UserId, GETDATE(), '', isnull(@ScheduleDateTime, dateadd(MINUTE, -1, getdate())), '', @Route,   
      @ParentId, null, '', @FilePath, 0, @FileId, Concat('Kit19', format(getdate(), 'yyMMddHHmmssfff')) from @ObdMoblieNos  
    
  select 1 as code, 'Data submited successfully' as remarks  
 end  
 else  
 begin  
  select 0 as code, 'Balance is not sufficient.' as remarks  
 end  
  
end  


GO

/* ============================================================
   Procedure: [dbo].[usp_obd_UnprocessCallReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_obd_UnprocessCallReport]  
as  
begin  

	drop table if exists #tempCR

	select BatchId, CampaignId, CampaignName, ScheduleDate
		into #tempCR
	from tbl_obd_ScheduleRecord(nolock) where   
		--ScheduleDate > '20230614' and 
		Processed = 1 and 
		isnull(VoiceStatus, 0) = 0 and 
		isnull(AttemptCount, 0) < 5 and ISNULL(CallStatus, '') = '' and 
		1 = case when isnull(AttemptCount, 0) = 0 and
			DATEDIFF(HOUR, COALESCE(ReportProcessDate, ScheduleDate), getdate()) >= (isnull(AttemptCount, 0) + 1) 
				then 1 else 0 end 

	group by BatchId, CampaignId, CampaignName, ScheduleDate   

	update s set
		s.AttemptCount = isnull(s.AttemptCount, 0) + 1,
		s.ReportProcessDate = getdate()
	from tbl_obd_ScheduleRecord(nolock) s
		inner join #tempCR t on s.BatchId = t.BatchId

	select * from #tempCR

end 



