/* ============================================================
   Procedure: [dbo].[usp_obd_UpdateObdCallStatusReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_obd_UpdateObdCallStatusReport](
	@tblObdReportType tblObdReportType readonly,
	@CampaignId bigint
)
as
begin
	
	--declare @tblObdReportType as tblObdReportType,
	--@CampaignId bigint = N'15767'
	--insert into @tblObdReportType values(N'09315028189',N'Kit19230615204149053',N'Kit19230615204149053',N'ANSWERED','2023-06-15 20:41:23','2023-06-15 20:41:44','2023-06-15 20:42:03',21,19,N'8071859767',1,N'',N'',N'',N'',N'')
	
	
	if(exists(select * from @tblObdReportType))
	begin

		drop table if exists #tempRepot
		
		select * into #tempRepot from (
			select st.*, mt.MobileNo, mt.ObdId, mt.CampaignId from (
				select ROW_NUMBER()over(partition by Phone, Campaign order by Phone desc) sno, *
				from @tblObdReportType
			) st
			inner join (
				select ROW_NUMBER()over(partition by MobileNo,CampaignId order by MobileNo desc) sno, ObdId, MobileNo, CampaignId, CampaignName from tbl_obd_ScheduleRecord
				where CampaignId = @CampaignId
			 ) mt on st.sno = mt.sno and trim('0' from st.Phone) = trim('0' from mt.MobileNo) and st.Campaign = mt.CampaignName
		) a

		update o set  
			o.CallStatus = t.CallStatus,
			o.CallStartTime = t.CallStartTime,
			o.CallAnsdTime = t.CallAnsdTime,
			o.CallEndTime = t.CallEndTime,
			o.RingTime = t.RingTime,
			o.TalkTime = t.TalkTime,
			o.CallerID = t.CallerID,
			o.RetryNo = t.RetryNo,
			o.HangupReason = t.HangupReason,
			o.DTMFKeyPress = t.DTMFKeyPress,
			o.DTMFPressTime = t.DTMFPressTime,
			o.SMS1Status = t.SMS1Status,
			o.SMS2Status = t.SMS2Status,
			o.VoiceStatus = case when isnull(t.CallStatus, '') <> '' then 1 else 1 end,
			o.ReportProcessDate = getdate()
		from #tempRepot t inner join 		 
			tbl_obd_ScheduleRecord(nolock) o on t.ObdId = o.ObdId


	end
end



GO

