SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_obd_UpdateScheduledObdStatus(
	@tblObdStatus tblObdStatus readonly,
	@CampaingnId bigint
)
as
begin
	update sr set 
		sr.Processed = os.Processed,
		sr.ProcessAt = getdate(),
		sr.CampaignId = @CampaingnId
	from tbl_obd_ScheduleRecord sr 
		inner join @tblObdStatus os on sr.ObdId = os.ObdId
			where sr.ObdId = os.ObdId
end



