/* ============================================================
   Procedure: [dbo].[usp_obj_GetBatchRecords]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_obj_GetBatchRecords
as
begin
	select top 1 BatchId, Count(1) as [RecordCount]  
		from tbl_obd_ScheduleRecord(nolock) where 
		datediff(MINUTE,  getdate(), ScheduleDate ) <= 10 
		and is_deleted = 0
		and (
		Processed = 0 or (
			Processed = 2 and (
				DATEDIFF(HOUR, PickedTime, getdate())  > 2 
			and DATEDIFF(HOUR, PickedTime, getdate()) < 10
		)))
	group by BatchId

end


GO

