/* ============================================================
   Procedure: [dbo].[usp_onetimecreditadjust]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_onetimecreditadjust]  
as  
begin  
DECLARE @body NVARCHAR(MAX)  
SET @body = 'SMS Accounts adjustment started at ' + CAST(getdate() as nvarchar(25))  
EXEC usp_enqueueemail  
@profile_name='Alerts',   
@recipients='karuna@pelsoftlabs.in',  
@blind_copy_recipients='csshukla@pelsoftlabs.in',  
@subject='SMS Accounts adjustment start',  
@body = @body,  
@body_format ='HTML'  
  
  
--Keep a backup of last credits  
select getdate() as LastCreditAsOn,c.* into CreditBackup150518 from credit_details c (nolock)   
where Credit_ID=(select MAX(credit_id)from credit_details(nolock) cd where cd.User_ID=c.User_ID)  
  
--Add credits of scheduled sms--  
insert into credit_details(M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified,typecredit
   ,CreatedBy)  
select c.m_id,user_id,c.USER_ID,0,t.totalrecords,balance+t.totalrecords,99999,GETDATE(),DATEADD(yy,100,getdate()),GETDATE(),GETDATE(),'shekhar',GETDATE(),'Credit added for SMS scheduled after 15 May 2018',c.User_ID from credit_details c (nolock)  
join (select userid,SUM(totalrecords) totalrecords from batchinfo where Replace(CONVERT(VARCHAR(20), Cast(scheduleddate AS DATETIME), 120), '-', '/')>GETDATE() and ISDATE(scheduleddate)=1 and substring(scheduleddate,1,4)='2018' group by UserID) t on t.UserID=c.User_ID  
where Credit_ID=(select MAX(credit_id)from credit_details(nolock) cd where cd.User_ID=c.User_ID) --order by Balance desc  
  
--Adjust balance by debiting 35% for non super resellers  
insert into credit_details(M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified,typecredit
,CreatedBy)  
select c.m_id,r.user_id,c.USER_ID,case when balance>0 then floor(35/cast(100 as float)*(balance)) else 0 end,0,case when Balance>0 then balance-floor(35/cast(100 as float)*(balance)) else Balance end,99999,GETDATE(),DATEADD(yy,100,getdate()),GETDATE(),GETDATE(),'shekhar',GETDATE(),'Credit adjust due to operator price hike-15May2018',c.USER_ID from credit_details c(nolock) left join reseller_detail r on r.Reseller_ID=c.M_ID  
where Credit_ID=(select MAX(credit_id)from credit_details(nolock) cd where cd.User_ID=c.User_ID)-- order by Balance desc  
  
--Adjust balance by debiting 35% for super resellers  
insert into credit_details(M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified,typecredit
,CreatedBy)  
select c.m_id,r.user_id,c.USER_ID,case when balance>0 then floor(35/cast(100 as float)*(balance)) else 0 end,0,case when Balance>0 then balance-floor(35/cast(100 as float)*(balance)) else Balance end,99999,GETDATE(),DATEADD(yy,100,getdate()),GETDATE(),GETDATE(),'shekhar',GETDATE(),'Credit adjust due to operator price hike-15May2018',c.User_ID from SuperResellerCredit_Details c (nolock) left join reseller_detail r on r.Reseller_ID=c.M_ID  
where Credit_ID=(select MAX(credit_id)from SuperResellerCredit_Details(nolock) cd where cd.User_ID=c.User_ID) --order by Balance desc  
  
--Deducting back the scheduled sms credits  
insert into credit_details(M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified,typecredit
  ,CreatedBy)  
select c.m_id,user_id,c.USER_ID,case when balance-t.totalrecords >=0 then t.totalrecords else Balance end,0,case when balance-t.totalrecords >=0 then balance-t.totalrecords else 0 end,99999,GETDATE(),DATEADD(yy,100,getdate()),GETDATE(),GETDATE(),'shekhar'
,GETDATE(),'Credit deducted from new balance for scheduled SMS',c.User_ID from credit_details c (nolock)  
join (select userid,SUM(totalrecords) totalrecords from batchinfo where Replace(CONVERT(VARCHAR(20), Cast(scheduleddate AS DATETIME), 120), '-', '/')>GETDATE() and ISDATE(scheduleddate)=1 and substring(scheduleddate,1,4)='2018' group by UserID) t on t.UserID=c.User_ID  
where Credit_ID=(select MAX(credit_id)from credit_details(nolock) cd where cd.User_ID=c.User_ID) order by Balance desc  
  
SET @body = 'SMS Accounts adjusted successfully at '+ CAST(getdate() as nvarchar(25))  
EXEC usp_enqueueemail  
@profile_name='Alerts',   
@recipients='karuna@pelsoftlabs.in',  
@blind_copy_recipients='csshukla@pelsoftlabs.in',  
@subject='SMS Accounts adjustment done',  
@body = @body,  
@body_format ='HTML'  
end



GO

/* ============================================================
   Procedure: [dbo].[Usp_OnlinePaymentforsms]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

        
-- Author:  Deepak kumar        
-- Create date: 30oct 2014        
-- Description: online paymet details        
-- =============================================        
CREATE   PROCEDURE [Usp_OnlinePaymentforsms] --19768  
@userid varchar(10)        
AS        
BEGIN        
 if EXISTS ( SELECT 'X' FROM User_Detail WHERE  User_ID=@userid)        
 BEGIN    
 DECLARE @MYRANDOMNO INT;        
  DECLARE @INVOICENO NVARCHAR(13);        
  SET @INVOICENO = CONVERT(VARCHAR(10), RIGHT(NEWID(),10))        
  SET @MYRANDOMNO=(SELECT 10000 + CONVERT(INT, (99000-10000+1)*RAND()))         
  --chandu    
 declare @quant varchar(100)  
 select top(1) @quant=PD.Quintity from PackageDetail PD inner join User_Detail US   on US.User_ID=PD.User_id where  PD.User_ID=@userid  
 insert into AdToCart(userid,totaldata,isremove)values(@userid,@quant,0)  
 declare @cartid bigint    
 select @cartid=[cart Id] from AdToCart where UserID=@userid AND IsRemove=0    
 select top(1)US.FName,US.User_ID,@cartid as CartId ,'Data_'+@INVOICENO as InvoiceNo ,'Sms19'as LinkStatus,CAST(CAST(US.Mobile AS DECIMAL(20))AS VARCHAR(20)) as Mobile ,PD.Quintity,US.[FName]+' '+isnull(US.[LName],'') AS NAME ,PD.totalPrice,isnull(US.Address,'') Address,US.EMail from PackageDetail PD inner join User_Detail US   on US.User_ID=PD.User_id where  PD.User_ID=@userid  
 END        
 END   
     
     
     
  
  
  
  
       
    
  
  
  


GO

