/* ============================================================
   Procedure: [dbo].[USP_OPENDND_CheckBoxDisable]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/****************************************************************************                        
SP_Name        : USP_OPENDND_CheckBoxDisable                                           
Author         : Kushagra Bansal                        
Created ON     : 27/6/2012 06:30 PM                                            
Location       : OpenDND.cs                         
SP Description : This SP is Used to check weather message is delivered or not so that to disable the button                     
****************************************************************************/                           
              
        
CREATE   PROC [dbo].[USP_OPENDND_CheckBoxDisable] --'','',''    
      
      
                  
@mobile varchar(max),                
@U_ID Bigint,                
@message varchar(max)                
                 
AS      
      
DECLARE @result int,@Message_Like varchar(max),@MessageStatus  varchar(50)        
      
      
BEGIN          
          
SET @Message_Like='%'+(select Substring(@message,1,69))+'%'      
  --I make a change here By replacing MessageDeliveryStatus by MessageDeliveryStatusTemp on 12/09/2012
--SET @MessageStatus= isnull((SELECT DISTINCT MessageStatus FROM [dbo].MessageDeliveryStatus WHERE '0'+mobile IN (SELECT value as mobile from fn_Split(@mobile,',')) AND U_ID=@U_ID AND Message LIKE  @Message_Like AND MessageStatus='Deliverd'),'0')    
SET @MessageStatus= isnull((SELECT DISTINCT MessageStatus FROM [dbo].MessageDeliveryStatusTemp WHERE '0'+mobile IN (SELECT value as mobile from fn_Split(@mobile,',')) AND U_ID=@U_ID AND Message LIKE  @Message_Like AND MessageStatus='Deliverd'),'0')  
IF(@MessageStatus!='Deliverd')  
BEGIN      
     SET @MessageStatus= isnull((SELECT MessageStatus FROM [MySMSReport].[dbo].[sixdayshistory1] WHERE '0     '+ mobile IN (SELECT value as mobile from fn_Split(@mobile,',')) AND U_ID=@U_ID AND Message LIKE    
     @Message_Like  AND MessageStatus='Deliverd'),'0')  
END           
IF(@MessageStatus!='Deliverd')  
BEGIN      
     SET @MessageStatus= isnull((SELECT MessageStatus FROM [MySMSReport].[dbo].[sixdayshistory2] WHERE '0     '+mobile IN (SELECT value as mobile from fn_Split(@mobile,',')) AND U_ID=@U_ID AND Message LIKE    
     @Message_Like AND MessageStatus='Deliverd'),'0')  
END   
IF(@MessageStatus!='Deliverd')  
BEGIN      
     SET @MessageStatus= isnull((SELECT MessageStatus FROM [MySMSReport].[dbo].[sixdayshistory3] WHERE '0     '+mobile IN (SELECT value as mobile from fn_Split(@mobile,',')) AND U_ID=@U_ID AND Message LIKE    
     @Message_Like AND MessageStatus= 'Deliverd'),'0')  
END    
IF(@MessageStatus!='Deliverd')  
BEGIN      
     SET @MessageStatus= isnull((SELECT MessageStatus FROM [MySMSReport].[dbo].[sixdayshistory4] WHERE '0     '+mobile IN (SELECT value as mobile from fn_Split(@mobile,',')) AND U_ID=@U_ID AND Message LIKE    
     @Message_Like AND MessageStatus= 'Deliverd'),'0')  
END    
IF(@MessageStatus!='Deliverd')  
BEGIN      
     SET @MessageStatus= isnull((SELECT MessageStatus FROM [MySMSReport].[dbo].[sixdayshistory5] WHERE '0     '+mobile IN (SELECT value as mobile from fn_Split(@mobile,',')) AND U_ID=@U_ID AND Message LIKE    
     @Message_Like AND MessageStatus= 'Deliverd'),'0')  
END    
IF(@MessageStatus!='Deliverd')  
BEGIN      
     SET @MessageStatus= isnull((SELECT MessageStatus FROM [MySMSReport].[dbo].[sixdayshistory6] WHERE '0     '+mobile IN (SELECT value as mobile from fn_Split(@mobile,',')) AND U_ID=@U_ID AND Message LIKE    
     @Message_Like AND MessageStatus= 'Deliverd'),'0')  
END    
  
      
      
      
      
IF (@MessageStatus='Deliverd')      
      
BEGIN      
SET @result=1      
END      
      
ELSE      
BEGIN      
SET @result=0      
END      
      
SELECT @result      
      
END 


GO

/* ============================================================
   Procedure: [dbo].[USP_OpenDND_MobileDellivery]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--SELECT *  FROM MessageDeliveryStatus WHERE MessageStatus='Deliverd'          
        
        
  /****************************************************************************                      
SP_Name        : [USP_OpenDND_MobileDellivery]                                         
Author         : Kushagra Bansal                      
Created ON     : 26/6/2012 01:30 PM                                          
Location       : OpenDND.cs                       
SP Description : This SP is Used to Update the messagestatus as delivered in MessageDeliveryStatus                     
****************************************************************************/                         
            
          
          
CREATE   PROC [dbo].[USP_OpenDND_MobileDellivery] 
@U_ID int,          
@mobile nvarchar(max),      
@message varchar(max),
@batchID nvarchar(20)                
AS          
          
DECLARE @result int,@Message_Like varchar(max)          
          
BEGIN          
          
SET @Message_Like='%'+(select Substring(@message,1,69))+'%'      
         
 INSERT INTO MessageDeliveryStatusTemp(    
[MessageID] ,[Mobile],[Message],[SenderID],[MessageStatus],[MessageInsertDate],[Priority], 
[SmppID],[U_ID],[IsUniCode],[BatchID],[Operator]) select [MessageID],
[Mobile],[Message],[SenderID],'Deliverd',[MessageInsertDate],[Priority],[SmppID],[U_ID],[IsUniCode],[BatchID],
[Operator] from MessageQueueAirtelThree WHERE '0'+mobile IN (SELECT value as mobile from fn_Split(@mobile,',')) AND 
U_ID=@U_ID AND Message LIKE  @Message_Like AND BatchID=@batchID  
    
        
 SET @result=( SELECT COUNT(mobile)  AS NoOfDelivery FROM MessageDeliveryStatusTemp WHERE '0'+mobile IN 
(SELECT value as mobile from fn_Split(@mobile,',')) AND U_ID=@U_ID AND Message LIKE  @Message_Like AND 
BatchID=@batchID and MessageStatus='Deliverd')   
  
        
SELECT @result        
         
END          
          
 
    
    
    


GO

/* ============================================================
   Procedure: [dbo].[usp_OpenDnd_Transfer]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/****************************************************************************                                
SP_Name        : [usp_OpenDnd_Transfer]                                                   
Author         : Kushagra Bansal                                
Created ON     : 25/6/2012 01:30 PM                                                    
Location       : OpenDND.cs                                 
SP Description : This SP is Used to search the requier information for page openDND according to date inserted                              
****************************************************************************/                                   
                      
                
CREATE   PROC [dbo].[usp_OpenDnd_Transfer] 



                     
@U_ID int,                            
@mobile nvarchar(max),            
@message nvarchar(max),  
@Date  nvarchar(15),
@batchID nvarchar(20)         
  
AS  
DECLARE @Message_Like nvarchar(max)  
  
 SET @Message_Like='%'+(select Substring(@message,1,69))+'%'  
 

SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,MessageInsertDate,[Priority],U_ID,IsDND,Operator,IsUniCode,Isallowdnd,getdate() AS Inserted_Date INTO #temp1 FROM MessageQueueAirtelThree WHERE U_ID = @U_ID AND message LIKE @Message_Like AND '0'+mobile IN (SELECT value as mobile from fn_Split(@mobile,',')) AND BatchID=@batchID  
  
  
  INSERT INTO messagestopped(MessageID,[MessageBatchID],Mobile,[Message],SenderID,SmppID,MessageInsertDate,[Priority],U_ID,IsDND,Operator,IsUniCode,Isallowdnd,Inserted_Date) SELECT * FROM #temp1
  
  DELETE MessageQueueAirtelThree WHERE U_ID = @U_ID AND message LIKE @Message_Like AND '0'+mobile IN (SELECT value as mobile from fn_Split(@mobile,',')) AND BatchID=@batchID  
  

SELECT COUNT(*) AS RowsTransfer FROM #temp1


 



GO

