CREATE   PROC [dbo].[USP_packageDetailFindRecordPrice] --316,'','','','ALL'  
@UserID nvarchar(100),    
@id nvarchar(100),    
@quintity nvarchar(100),    
@price nvarchar(100),    
@page nvarchar(200)    
as    
Declare @whereClause nvarchar(max)    
Declare @query nvarchar(max)    
set @whereClause=''    
    
if @id=''    
Begin    
set @whereClause=@whereClause+' 1=1  AND'    
End    
else    
begin    
set @whereClause=@whereClause+' id='+@id +'and'    
End    
    
if @quintity=''    
Begin    
set @whereClause=@whereClause+' 1=1  AND'    
End    
else    
begin    
set @whereClause=@whereClause+' quintity='+@quintity +'and'    
End    
    
if @price=''    
Begin    
set @whereClause=@whereClause+' 1=1 '    
End    
else    
begin    
set @whereClause=@whereClause+' price='+@price+' '    
End    
    
if(@page='All')    
Begin    
set @query='select * from packageDetail where user_id='''+@UserID+''' AND '+ @whereClause +' order by quintity'   
End    
Else    
Begin    
set @query='select * from packageDetail where user_id='''+@UserID+''' AND '+ @whereClause+' and page=''Blog'' order by quintity'    
End    
print (@query)    
exec (@query)




