CREATE   PROCEDURE [dbo].[usp_partner_loginCheck] (    
    @user_id nvarchar(50),        
    @password nvarchar(50),        
    @url nvarchar(255)        
)                                        
AS    
BEGIN    
    
    
 --declare    
 --@user_id varchar(50) = 'kmukesh343', @password varchar(50) = '770940', @url varchar(255) = 'teamchat.sms19.com'    
 --@user_id varchar(50) = 'Lydapvt', @password varchar(50) = '25427', @url varchar(255) = 'www.linkwave.in'    
     
 --@user_id varchar(50) = 'internal', @password varchar(50) = 'kitever1', @url varchar(255) = 'www.kit19.com'    
 --@user_id varchar(50) = 'internal', @password varchar(50) = 'kitever1', @url varchar(255) = 'www.demo.newpartner.co.in'    
    
 --@user_id varchar(50) = '16301-niyati vats', @password varchar(50) = '9317', @url varchar(255) = 'www.kit19.com'    
 --@user_id varchar(50) = '16301-niyati vats', @password varchar(50) = '9317', @url varchar(255) = 'www.demo.newpartner.co.in'    
    
     
 --@user_id varchar(50) = '16301-niyati vats', @password varchar(50) = '9317', @url varchar(255) = 'www.kit19.com'    
 --@user_id varchar(50) = 'neuroentclinic', @password varchar(50) = '1954', @url varchar(255) = 'www.kit19.com'    
     
 declare @type varchar(2),@turl varchar(50)='', @UserId bigint, @ParentId bigint, @View bit = 0, @M_ID bigint = 0, @resellerId bigint = 0    
     
  if(@url like '%localhost%' or @url like '%kit19.com' or @url like '%kit19web.azurewebsites.net' or @url like '%sms19.com')    
  begin    
  set @url  = 'www.kit19.com'    
  end    
    
  drop table if exists #allowDomain    
  create table #allowDomain(    
  resellerId bigint,    
  doaminName nvarchar(255)    
  )    
    
 select @url = replace(replace(replace(@url, 'https://', ''), 'www.', ''), 'http.', '')     
    
 if(exists(     
  select 1 from User_Detail(nolock) ud     
   where ud.User_Login COLLATE SQL_Latin1_General_CP1_CS_AS = @user_id     
  and ud.Pwd COLLATE SQL_Latin1_General_CP1_CS_AS = @password and [Status] = 1 --and isverify = 1   
 ))    
 begin    
  print 'exists'    
  select top 1  @UserId = User_ID, @ParentId = ParentID, @M_ID = M_ID from User_Detail(nolock) ud     
   where ud.User_Login = @user_id and ud.Pwd = @password and  [Status] = 1 --and isverify = 1  
   order by User_ID desc    
    
  insert into #allowDomain (resellerId, doaminName)    
  select Reseller_ID, replace(replace(replace(Domain, 'https://', ''), 'www.', ''), 'http://', '')     
   from Reseller_Detail(nolock) where  User_ID = @ParentId or Reseller_ID  = @M_ID    
      
  if(dbo.fn_userdomain(@ParentId) in ('', 'https://', 'http://' ))    
  begin    
   insert into #allowDomain (resellerId, doaminName)    
   select dbo.fn_getusermid(dbo.fn_userimmediatepartner(@ParentId)),     
    replace(replace(replace(dbo.fn_userdomain(dbo.fn_userimmediatepartner(@ParentId)),    
    'https://', ''), 'www.', ''), 'http://', '')     
  end    
    
    
  if(exists(select * from #allowDomain where doaminName = @url))    
  begin    
       
   select top 1 @resellerId = resellerId from #allowDomain where doaminName = @url    
       
   select top 1 @View = tuam.[View] from TBL_UA_RolePermissionMappingMaster(nolock) turm          
    join TBL_UA_EntityActionMappingMaster (nolock) tuam on turm.EntityActionMappingCode = tuam.EntityActionMappingCode          
   where turm.ModuleCode in ('PAG10300','PAG10317','PAG10320','PAG10321','PAG10323','PAG10324','PAG10331') and turm.ParentId = @ParentId          
    
   select ud.User_ID, ud.User_Login,ud.Pwd, @resellerId as [Reseller_ID], @View IsLocationTracking from User_Detail(nolock) ud where User_ID = @UserId and [Status] = 1 --and isverify = 1     
    
   exec USP_TBL_ET_GetDefaultRecord @UserId       
    
  end    
  else    
  begin    
   select ud.User_ID, ud.User_Login,ud.Pwd, @resellerId as [Reseller_ID], @View IsLocationTracking from User_Detail(nolock) ud where User_ID = 0    
  end    
 end    
 else    
 begin    
  select ud.User_ID, ud.User_Login,ud.Pwd, @resellerId as [Reseller_ID], @View IsLocationTracking from User_Detail(nolock) ud where User_ID = 0    
 end    
    
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_Partner_updateReason]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_Partner_updateReason]
(        
  @BatchNotificationDetail_ID bigint,        
  @Reason nvarchar(500),        
  @SubReason nvarchar(500),      
  @RawReason nvarchar(max)      
          
)
as        
Begin     
  
 If(@Reason = 'NotRegistered')  
 Begin  
  declare @DeviceId nvarchar(1000)='',@UserId bigint=0,@AppVersion varchar(100),@OSVersion varchar(100),@OSName varchar(100),@ModelName varchar(100), @BatchNotification_Id bigint  
  
  Select @UserId=USER_ID, @BatchNotification_Id=BatchNotification_Id  
  From [tbl_APP_BatchNotificationDetail]  WITH (NOLOCK) 
  where  BatchNotificationDetail_Id =  @BatchNotificationDetail_ID  
   
  select @DeviceId=DeviceID,@AppVersion=AppVersion,@OSVersion=OSVersion,@OSName=OSName,@ModelName=ModelName  
  from User_Detail WITH (NOLOCK)  
  Where User_Id=@UserId  
  
  exec usp_insertloginhistory @UserId, null, null, @DeviceId, 'Logout', null, @AppVersion,@OSVersion,@OSName,@ModelName  
  
  Update User_Detail   
  Set  DeviceID='', OTP='', AppVersion='', OSVersion='', OSName='', ModelName=''  
    , OnField=0, Presence = case when isnull(MACAddress,'') != '' then Presence else 0 end  
  Where User_Id=@UserId  
  
  update [tbl_APP_BatchNotificationDetail]   
  set  [Reason] = @Reason ,[SubReason] = @SubReason , [RawReason] = @RawReason, LastAttemptedTime = getdate(), Retries = isnull(Retries,0)+1  
    ,IsProcessed=1  
  where BatchNotificationDetail_Id =  @BatchNotificationDetail_ID  
  
  If not exists(Select * from [tbl_APP_BatchNotificationDetail] Where BatchNotification_Id=@BatchNotification_Id and IsProcessed=0)  
  Begin  
   update [tbl_APP_BatchNotification] set IsProcessed=1 Where BatchNotification_Id=@BatchNotification_Id  
  End  
 End  
 Else  
 Begin  
  update [tbl_APP_BatchNotificationDetail]   
  set  [Reason] = @Reason ,[SubReason] = @SubReason , [RawReason] = @RawReason, LastAttemptedTime = getdate(), Retries = isnull(Retries,0)+1  
  where BatchNotificationDetail_Id =  @BatchNotificationDetail_ID  
 End  
  
End





GO

/* ============================================================
   Procedure: [dbo].[usp_PartnerUserDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_PartnerUserDetails] 
(
	@P_userId bigint,  
	@P_UserType int =  0,
	@P_Username varchar(120) ='',
	@P_SegmentId bigint  = 0,
	@Offset int = 0,  
	@PageSize int = 100      
)      
AS     
BEGIN      

	--declare   
	-- 	@P_userId bigint = 49432,  
	-- 	@P_Username varchar(255) = '',
	-- 	@P_UserType int = 0,
	--	@P_SegmentId bigint  = 0,
	-- 	@Offset int = 0, 		
	-- 	@PageSize int = 100   

	Declare @parentid  bigint ;

	set @parentid = dbo.ufn_GetUserParentId(@P_Userid);  

	 Declare @ScopeId int = 0;
	 select @ScopeId =  ScopeId from tbl_pm_RolePermissionMapping(nolock) where  roleid = (select RoleId from tbl_pm_UserRoleMapping(nolock) where UserId = @P_userId );
	 if(@P_userId= @parentid)
	 begin
	 select @ScopeId=1
	 end
	 Declare @Userlist table
	 (
		id int identity(1,1),
		userId bigint
	 )

	 print concat( 'scope id --> ', @scopeid) ;

	 if @ScopeId = 0  or @ScopeId = 3  begin
		print 'user';
	 end
	 ELSE IF @ScopeId = 1 begin
		print 'Global';
	 END
	 ELSE IF @ScopeId = 2 begin
		print 'Hirearchy';
		insert into @Userlist (userId)
		exec usp_pm_getuserHierarchy @P_userid
	 END
	 
	 --	Declare @Parentid bigint = 0 ;
		--SELECT @Parentid = dbo.ufn_GetUserParentId(@P_Userid);

        
	declare @Resellerid bigint;      
	select  @Resellerid = Reseller_ID from reseller_detail(nolock) where User_ID = dbo.ufn_GetUserParentId(@P_Userid);      
  
	declare @StartPoint int = @Offset + 1;      
	declare @EndPoint int = @Offset + @PageSize;  
      
	PRINT CONCAT( 'StartPoint' , convert(varchar(200),@StartPoint));      
	PRINT CONCAT( 'EndPoint' , convert(varchar(200),@EndPoint));
	PRINT CONCAT( 'Resellerid' , convert(varchar(200),@resellerid));      
  
	---select * from reseller_detail where M_ID = 10043 
	declare @segmentUserIds as table (
		UserId bigint
	)

	if(@P_SegmentId > 0)
	begin
		insert into @segmentUserIds
		exec usp_us_GetUserIdsBySegmentIds @userSegmentIds = @P_SegmentId, @onlyParentId = 1

	end

	;with userCTE as ( 
		select ud.user_id, ud.m_id, ud.EMail, ud.Mobile, ud.CountryCode, ud.Type[UserType], ud.Status, CONCAT(ud.User_Login, ' (',  ud.FName ,' ', ud.LName, ')') as [Name],
			ROW_NUMBER() OVER (PARTITION BY ud.M_ID ORDER BY ud.User_Login) AS RowNumber
		from  
			User_Detail(nolock) ud 
			left join reseller_detail(nolock)  rd on ud.User_ID = rd.User_ID
			where ud.M_ID = @Resellerid  and ud.User_ID = ud.ParentID 
                and 1 = ( case when @P_SegmentId > 0  
                    and exists(select 1 from @segmentUserIds s where s.UserId = ud.User_ID) then 1 
                    when @P_SegmentId = 0 then 1 else 0 end)
			    and 1 = ( case 
					when isnull( @P_UserType, 0) = 0 then 1 
					when isnull( @P_UserType, 0) = 1 and isnull(rd.Partner_Type, 0) = 0 then 1
					when isnull( @P_UserType, 0) = 2 and isnull(rd.Partner_Type, 0) = 1 then 1
					when isnull( @P_UserType, 0) = 3 and isnull(rd.Partner_Type, 0) = 2 then 1
					when isnull( @P_UserType, 0) = 4 and isnull(rd.Partner_Type, 0) = 3 then 1
				end)
			and 1 = ( case 
				when @P_Username = ''  then 1
				when ud.User_Login like '%'+ @P_Username +'%'  then 1 
				else 0 end
			)
	)  
	select   
		u.RowNumber,  
		(select count(1) from userCTE) as [TotalRow],  
		u.M_ID,
		u.user_id,   
		u.[Name],  
		u.EMail,   
		u.Mobile,
		u.CountryCode,
		u.Status,
		CONCAT( FORMAT(pud.PlanStartDate, 'dd-MMM-yyyy') ,' -- ', FORMAT(pud.PlanEndDate, 'dd-MMM-yyyy')) as subscription_detail,		
		u.UserType,
		rd.Partner_Type as [PartnerType],
		pt.TypeName as [PartnerTypeName],
		rd.Domain as [domainName],
		isnull(rd.IsDomainVerified, 0) as [IsDomainVerified],
		isnull(rd.IsImpersonate, 0) as [IsImpersonate],
		isnull(aut.AllowUserCount, 0) as [AllowUserCount],
		isnull(auc.TotalActiveUser, 0) as [TotalActiveUser],
        d.DomainCount,
		(CASE WHEN COALESCE( utc.user_login,'') <>'' THEN CONCAT( utc.user_login,'(',utc.FName, ' ', utc.LName ,')') ELSE '' END) as AssignedToUser,
		tc.assigneduser As AssignedUserId,
		dbo.ufunc_GetSMSBalance(u.m_id, u.user_id) as SMSBal,
		dbo.ufunc_GetMailBalance(u.m_id, u.user_id) as MailBal,      
		dbo.ufunc_GetWallletBalance(u.m_id, u.user_id) as walletBal   
	from userCTE u
		LEFT JOIN reseller_detail(NOLOCK)  rd on u.User_ID = rd.User_ID
		LEFT JOIN tbl_pm_PartnerTypeMaster(NOLOCK) pt on rd.Partner_Type = pt.Id
		LEFT JOIN vw_UserSubscriptionLatest(NOLOCK) pud on pud.UserID = u.User_ID
		LEFT JOIN vw_pt_AllowUserTransactionsLatest aut on u.User_ID = aut.UserId
		LEFT JOIN vw_pt_ActionUserCount(NOLOCK) auc on u.User_ID = auc.ParentId
        LEFT JOIN vw_GetResellerDomainCount(NOLOCK) d  ON rd.Reseller_ID = d.Reseller_ID
		LEFT JOIN tbl_pm_Clientusers tc(nolock) on tc.ClientUserId = u.User_ID and tc.Isactive =1
		LEFT JOIN User_Detail utc(nolock) on tc.AssignedUser = utc.User_ID
		where RowNumber between @StartPoint and @EndPoint 
		and  1= case when @ScopeId = 1 then 1 when @ScopeId =2 and   utc.User_ID in (select userid from @userlist) then 1 
		when @ScopeId in (0,3) and utc.User_ID = @P_userId then 1 else 0 end 
		order by u.RowNumber  
end   



GO

