/* ============================================================
   Procedure: [dbo].[Usp_PipelineHistoryByLeadID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_PipelineHistoryByLeadID] --4254245,0,10 --1049929,0,10  --1049601,0,10      
(      
  @LeadID bigint,      
  @offsets int = 0,          
  @pageSize int = 10        
)      
as      
  Begin      
        select  PM.Name as PipelineName, PS.Name as StageName, LPM.Probability    
  ,UDDL.User_Login +'(' + UDDL.FName +' '+ UDDL.LName +')' as DealOwnerByName,      
         UDCrt.User_Login +'('+ UDCrt.FName +' '+ UDCrt.LName +')' as CreatedByName    
        ,LPM.CreatedDate,LPM.Remarks      
       from LeadPipelineMapping as LPM with(nolock)      
  join Pipeline_Master as PM with(nolock)      
        on LPM.PipelineID = PM.ID      
        join PipelineStages as PS with(nolock)      
      on LPM.PipeLineStage = PS.ID      
  join User_Detail as UDCrt with(nolock)      
      on LPM.CreatedBy = UDCrt.User_ID      
  join User_Detail as UDDL with(nolock)      
      on LPM.DealOwner = UDDL.User_ID      
  where LPM.IsDeleted = 0      
        and LPM.LeadID = @LeadID      
     order by LPM.CreatedDate desc        
  offset @offsets rows fetch next @pageSize rows only         
  End 


GO

/* ============================================================
   Procedure: [dbo].[usp_playCRMpipelineVoice]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*  
;WITH LatestFollowup AS (  
    SELECT fd.*, ROW_NUMBER() OVER (PARTITION BY fd.EnqNo ORDER BY fd.Fid DESC) AS rn  
    FROM CRM.CRMDB.dbo.FollowUp_Details fd WITH (NOLOCK)  
    WHERE fd.Remark NOT LIKE 'Automatically%'  
)  
SELECT top 1000  
    Mobile = COALESCE(NULLIF(p.Mobile_No, ''), NULLIF(p.Mobile_No2, ''), NULLIF(p.Mobile_No3, '')),  
    DetailsJson = (  
        SELECT  
            p.EnqNo     AS enqno,  
            CASE  
    WHEN CHARINDEX(' ', LTRIM(RTRIM(ISNULL(p.Name, '')))) > 0  
      THEN LEFT(LTRIM(RTRIM(p.Name)), CHARINDEX(' ', LTRIM(RTRIM(p.Name))) - 1)  
    ELSE LTRIM(RTRIM(p.Name))  
  END AS entity_name,  
            ISNULL(p.Company_Name, '') AS Company_name,  
            ps.name AS Pipeline_StageName,  
            CASE WHEN e.CreatedDate > lf.DateCreated THEN u.Name ELSE ul.Name END AS Sales_Representative,  
            lf.DateCreated AS LastFollowupDate,  
            lf.Remark      AS LastFollowupRemarks  
        FOR JSON PATH, WITHOUT_ARRAY_WRAPPER  
    ),cast(null as datetime) as ProcessedDate into Pipelinecases  
FROM CRM.CRMDB.dbo.EnqPipelineMapping_EnqLatestRecords e WITH (NOLOCK)  
JOIN CRM.CRMDB.dbo.Pre_Enquiry p WITH (NOLOCK) ON p.EnqNo = e.EnqNo  
JOIN CRM.CRMDB.dbo.User_Login u WITH (NOLOCK) ON u.User_ID = e.DealOwner  
JOIN LatestFollowup lf ON lf.EnqNo = p.EnqNo AND lf.rn = 1  
JOIN CRM.CRMDB.dbo.User_Login ul WITH (NOLOCK) ON ul.User_Name = lf.Executive  
join CRM.CRMDB.dbo.PipelineStages ps with (nolock) on ps.id=e.PipelineStageId  
WHERE e.CreatedDate < DATEADD(DAY, -30, GETDATE())  
  AND e.IsDeleted = 0  
  AND NOT EXISTS(  
      SELECT 1 FROM CRM.CRMDB.dbo.Assign_AccountManager a WITH (NOLOCK) WHERE a.Refrence_No = e.EnqNo  
  )  
ORDER BY p.enqno;  
  
select row_number() over (partition by 1 order by json_value(DetailsJson,'$.enqno')) as Rno,json_value(DetailsJson,'$.enqno') as EnqNo, * into Pipelinecases_forVoice from CRM.CRMDB.dbo.PipelineCases_ForVoice  
  
select top 10 * from Pipelinecases_forVoice order by enqno  
select top 1000 * from Pipelinecases_forVoice  where processeddate is not null order by processeddate desc 
  
select * from user_detail(nolock) where str(mobile)='7389290311'  
  
select * from userleads(nolock) where mobileno='7389290311'  
select top 10 * from Pipelinecases_forVoice  where mobile in ('7788881800')  
alter table Pipelinecases_forVoice add attempt int  
update Pipelinecases_forVoice set attempt=1  
*/  
CREATE   PROCEDURE [dbo].[usp_playCRMpipelineVoice]  
as  
begin  
if dbo.GetAvailableBalanceForService(34594,23)>50 and (select count(1) from tbl_ai_agent_execution_outbox(nolock) where queuename like 'voice%' and json_value(payload,'$.botid')=20 and isprocessed=0 )<50
begin
if --datepart(HH,getdate()) between 11 and 18 and  
exists(select 1 from pipelinecases_forvoice(nolock) p   
where (processeddate is null) and spl_case=1) 
begin
drop table if exists #te  
create table #te(id bigint,entity_context nvarchar(max),enqno bigint,mobile varchar(20))  
  
INSERT INTO dbo.voice_bot_campaign_audience (  
    parentid,  
    vb_campaignid,  
    created_on,  
    recipient_mobile,  
    recipient_countrycode,  
    recipient_has_countrycode,  
    entity,  
    entityid,  
    entity_context,  
    picked_on,  
    executed_on,  
    last_error,  
    execution_batchid  
)  
OUTPUT INSERTED.id, inserted.entity_context,0,inserted.recipient_mobile INTO #te  
SELECT top 200  
    34594,  
    24, -- point to cloned campaign  
    GETDATE(), -- new created_on  
    mobile as recipient_mobile,  
    '+91' as recipient_countrycode,  
    0 as recipient_has_countrycode,  
    null,  
    null,  
    detailsjson,  
    null,  
    null,  
    null,  
    null  
FROM Pipelinecases_forVoice (nolock) p   
where (processeddate is null) and spl_case=1 and attempt<5 order by enqno,mobile  
  
update #te set enqno=json_value(entity_context,'$.enqno')  
update p set p.audienceid=t.id,processeddate=getdate(),attempt=isnull(attempt,0)+1 from #te t join Pipelinecases_forVoice p on (p.enqno=t.enqno  or p.Mobile=t.mobile)
--where processeddate is null

end
else 
if cast(getdate() as date)>='20260215' and datepart(HH,getdate()) between 11 and 18 and   
exists(select top 1 1 from pipelinecases_forvoice(nolock) p   
left join voice_bot_campaign_audience v on p.audienceid=v.id  
left join calllog c (nolock) on c.parentid=34594 and c.audienceid=v.id  
--left join call_summaries s (nolock) on s.calllog_id=c.id  
where --(processeddate is null or datediff(d,processeddate,getdate())>1) and isdnd=0 and c.Callendtime is null
(processeddate is null or datediff(d,processeddate,getdate())>1) and isdnd=0 and 
(c.Callendtime is null or datediff(d,processeddate,getdate())>20)
)  
--where (processeddate is null or datediff(d,processeddate,getdate())>1) and isdnd=0 and isnull(spl_case,0)=0)  
begin  
drop table if exists #t  
create table #t(id bigint,entity_context nvarchar(max),enqno bigint,mobile varchar(20))  
  
INSERT INTO dbo.voice_bot_campaign_audience (  
    parentid,  
    vb_campaignid,  
    created_on,  
    recipient_mobile,  
    recipient_countrycode,  
    recipient_has_countrycode,  
    entity,  
    entityid,  
    entity_context,  
    picked_on,  
    executed_on,  
    last_error,  
    execution_batchid  
)  
OUTPUT INSERTED.id, inserted.entity_context,0,inserted.recipient_mobile INTO #t  
SELECT top 200  
    34594,  
    24, -- point to cloned campaign  
    GETDATE(), -- new created_on  
    mobile as recipient_mobile,  
    '+91' as recipient_countrycode,  
    0 as recipient_has_countrycode,  
    null,  
    null,  
    detailsjson,  
    null,  
    null,  
    null,  
    null  
FROM Pipelinecases_forVoice (nolock) p   
left join voice_bot_campaign_audience v on p.audienceid=v.id  
left join calllog c (nolock) on c.parentid=34594 and c.audienceid=v.id  
--left join call_summaries s (nolock) on s.calllog_id=c.id  
where 
--(processeddate is null or datediff(d,processeddate,getdate())>1) and isdnd=0 and c.Callendtime is null 
(processeddate is null or datediff(d,processeddate,getdate())>1) and isdnd=0 and 
(c.Callendtime is null or datediff(d,processeddate,getdate())>20)
order by case when processeddate is null then 0 else 1 end,processeddate  
--where processeddate is null and isdnd=0 and isnull(spl_case,0)=0 order by enqno,mobile  
  
update #t set enqno=json_value(entity_context,'$.enqno')  
update p set p.audienceid=t.id,processeddate=getdate(),attempt=isnull(attempt,0)+1 from #t t join Pipelinecases_forVoice p on (p.enqno=t.enqno  or p.Mobile=t.mobile)
--where processeddate is null
end
end
end




