   Procedure: [dbo].[usp_playvoicebroadcast]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_playvoicebroadcast
as
begin
declare @t int,@total int,@id int
select @t= 100-count(1) from Kit19Cloudvoicefinaltbl where processed=0
select @total=count(1),@id=min(id) from testvoice where issent=0 
select @t,@total,@id
while @total>0 
begin
if @t>0
begin
insert into Kit19Cloudvoicefinaltbl( [dnino]
      ,[clino]
      ,[appid]
      ,[ScheduleDateTime]
      )
select top (@t) 1204862663,Mobile,90,GETDATE() from testvoice where issent=0 order by id
update testvoice set issent=1,Lastsentdate=getdate() where id<=@id+@t-1
--select @id+@t-1
WAITFOR DELAY '00:01:00'
end
select @t= 100-count(1) from Kit19Cloudvoicefinaltbl where processed=0
select @total=count(1),@id=min(id) from testvoice where issent=0
select @t,@total,@id
end
end


