/* ============================================================
   Procedure: [dbo].[usp_pm_ApproveRejectRequest]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 


CREATE   PROC [dbo].[usp_pm_ApproveRejectRequest]
(
	@P_UserId bigint ,
	@P_ReqType int ,
	@P_RecordID bigint,
	@P_Remarks varchar(2000) = ''
)
As
begin
	
	BEGIN TRY

		UPDATE TBL_PM_IMPREQUEST SET RequestStatus = @P_ReqType , Partner_remarks = @P_Remarks where ID = @P_RecordID AND  @P_UserId IN (RequestedBy,RequestedFor ,RequestedTo ) ;

		SELECT  (CASE WHEN @P_ReqType = 1 THEN 'Approved' else 'Rejected' end) + ' Success.' As Message;

			

		Declare @RequestedBy bigint, @RequestedTo  bigint, @RequestedFor bigint ,  @RequestedFromDate datetime  , @RequestedToDate datetime;

-----  activity start   -----
		--activity vars
		Declare @PartnerType int  =0;  
		DECLARE @UserName varchar(255), @PartnerUserName varchar(255) , @ChildPartnerName varchar(255);
		Declare @Eventdata varchar(max);
		---activity vars
		
		select @RequestedBy = RequestedBy ,  @RequestedTo = RequestedTo , @RequestedFor = RequestedFor, 
		@RequestedFromDate =   RequestPeriodFrom , @RequestedToDate =  RequestPeriodTo from TBL_PM_IMPREQUEST with(nolock) where ID = @P_RecordID;

		select @UserName = User_login from User_Detail with(nolock) where User_ID = @RequestedBy;
		select @PartnerUserName = User_login from User_Detail with(nolock) where User_ID = @RequestedTo;
		select @ChildPartnerName = User_login from User_Detail with(nolock) where User_ID = @RequestedFor;
		 
		SET @Eventdata = '{"#parentpartner#":"'+ @PartnerUserName +'","#childpartner#":"'+ @ChildPartnerName +'","#username#":"'+@UserName+'","#impersonationrequestfromdate#":"'+ FORMAT(@RequestedFromDate,'dd-MM-yyyy')  +'","#impersonationrequestTodate#":"'+ FORMAT(@RequestedToDate,'dd-MM-yyyy')+'"}';

		---select * from ActivityMaster  where EventName like '%partner%' 
		-- #parentpartner# accepted impersonation request by #childpartner# for #username# from #impersonationrequestfromdate# to #impersonationrequestTodate#

		IF (@P_ReqType = 1) BEGIN
			exec usp_pm_PartnerActivity  @RequestedBy, @requestedTo, @RequestedFor, 'Partner approved impersonation request',@Eventdata,'TBL_PM_IMPREQUEST',@P_RecordID;
		END
		ELSE BEGIN
			exec usp_pm_PartnerActivity  @RequestedBy, @requestedTo, @RequestedFor, 'Partner rejected impersonation request',@Eventdata,'TBL_PM_IMPREQUEST',@P_RecordID;
		END

----- activity end  ---


	END TRY
	BEGIN CATCH
		PRINT CONCAT('Error occurred: ', ERROR_MESSAGE(), ' | Error Number: ', ERROR_NUMBER(), ' | Line: ', ERROR_LINE());
		SELECT 'Error Ocurred' as Message;
	END CATCH

end



GO

/* ============================================================
   Procedure: [dbo].[usp_pm_ChangePartnerRequestsRecords]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*  
  
drop proc usp_pm_ChangePartnerRequests  36980 ,   
  
usp_pm_ChangePartnerRequestsRecords  335, 0,'17-dec-2024','24-dec-2024','{"userid":36980}',0,0,100,2  
  
tbl_PM_ChangepartnerRequest where createdby = 335  
  
*/  
CREATE   PROC usp_pm_ChangePartnerRequestsRecords  
(  
 @P_Userid int = 0,  
 @P_PartnerId bigint =0,  
 @P_RequestfromDate datetime,  
 @P_RequestToDate datetime,  
 @P_MetadataFilter nvarchar(max)='',  
 @P_Status int = 0,  
 @Offset int = 0,  
 @PageSize int = 100,  
 @P_option int= 1  
)  
AS  
BEGIN  

--declare @P_Userid int = 25787,
--	@P_PartnerId bigint =0,
--	@P_RequestfromDate datetime='4-01-2026',
--	@P_RequestToDate datetime='11-04-2026',
--	@P_MetadataFilter nvarchar(max)='',
--	@P_Status int = 0,
--	@Offset int = 0,
--	@PageSize int = 100,
--	@P_option int= 2
   
 BEGIN TRY  
  
  Declare @StartPoint int = @Offset + 1;        
  Declare @EndPoint int = @Offset + @PageSize;    
  Declare @ResellerID  bigint  = 0 , @req_partnerid bigint  =0 , @Userid bigint = 0 ;  
  PRINT CONCAT( 'StartPoint' , convert(varchar(200),@StartPoint));        
  PRINT CONCAT( 'EndPoint' , convert(varchar(200),@EndPoint));  
    
  SELECT @ResellerID = Reseller_ID from reseller_detail(nolock) where User_ID = @P_Userid  
  
  SELECT @req_partnerid  = Reseller_ID from reseller_detail(nolock) where User_ID =  @P_PartnerId  
  
  select @Userid = JSON_VALUE(VALUE,'$.userid') from OPENJSON('['+@P_MetadataFilter+']')  
  
  print concat('userid  = ',convert( varchar, @Userid));  
  
  IF (@P_option =1)  ---- REQUEST SENT   
  BEGIN  
  
   ;WITH partenerRequest as(  
   select tbl.ID as RecID, tbl.createdDate as RequestedDate, Requestforuserid, UD.User_Login AS RequestForUser, RequestedPartnerUserid, UR.User_Login AS PartnerName,  RequestStatus,  
   (CASE WHEN  RequestStatus = 0 THEN  'Requested' WHEN RequestStatus = 1 THEN 'Approved' else 'Rejected' END) As Status,  
   Remarks , ROW_NUMBER() OVER (PARTITION BY TBL.ID ORDER BY tbl.ID) AS RowNumber  
   from tbl_PM_ChangepartnerRequest tbl(nolock)  
   left join User_Detail UD (nolock) on tbl.Requestforuserid = UD.User_ID  
   left join reseller_detail rd (nolock) on tbl.RequestedPartnerUserid = rd.Reseller_ID  
   left join User_Detail UR (nolock) on ur.User_ID = rd.User_ID  
   where createdby = @P_Userid   
   AND  createdDate BETWEEN FORMAT( @P_RequestfromDate,'yyyy-MM-dd 00:00:00') AND  FORMAT(@P_RequestToDate,'yyyy-MM-dd 23:59:59')  
   AND ( CASE WHEN COALESCE(@req_partnerid,0) = 0 THEN  '1' ELSE RequestedPartnerUserid END ) =  ( CASE WHEN COALESCE( @req_partnerid,0) = 0 THEN  '1' ELSE @req_partnerid END )  
   AND ( CASE WHEN COALESCE(@Userid,0) = 0 THEN  '1' ELSE Requestforuserid END ) =  ( CASE WHEN COALESCE( @Userid,0) = 0 THEN  '1' ELSE @Userid END )  
   AND ( CASE WHEN COALESCE(@P_Status,0) = -1 THEN  '1' ELSE  RequestStatus END ) =  ( CASE WHEN COALESCE( @P_Status,0) = -1 THEN  '1' ELSE @P_Status END )  
   )  
  
   select RecID, RowNumber, (select count(1) from partenerRequest) as [TotalRow], FORMAT(RequestedDate,'dd-MM-yyyy') as RequestedDate, Requestforuserid, RequestForUser,  
   Status,RequestedPartnerUserid , PartnerName , RequestStatus , Remarks    
   from partenerRequest  
   where RowNumber between @StartPoint and @EndPoint order by RowNumber  
  
  end  
  ELSE if (@P_option =2) BEGIN  --- REQUEST RECEIVED  
     
   ;WITH partenerRequest as(  
   select tbl.ID as RecID, tbl.createdDate as RequestedDate, Requestforuserid, UD.User_Login AS RequestForUser, RequestedPartnerUserid, UR.User_Login AS PartnerName,   
    (CASE WHEN  RequestStatus = 0 THEN  'Requested' WHEN RequestStatus = 1 THEN 'Approved' else 'Rejected' END) As Status, tbl.createdby as FromPartnerId,   
   uc.User_Login as FromPartner, Remarks, ROW_NUMBER() OVER (PARTITION BY TBL.ID ORDER BY tbl.ID) AS RowNumber  
   from tbl_PM_ChangepartnerRequest tbl(nolock)  
   left join User_Detail UD (nolock) on tbl.Requestforuserid = UD.User_ID  
   left join reseller_detail rd (nolock) on tbl.RequestedPartnerUserid = rd.Reseller_ID  
   left join User_Detail UR (nolock) on ur.User_ID = rd.User_ID  
   left join User_Detail UC (nolock) on tbl.createdby = UC.User_ID  
   where RequestedPartnerUserid = @P_Userid --@ResellerID  
   AND  createdDate BETWEEN FORMAT( @P_RequestfromDate,'yyyy-MM-dd 00:00:00') AND  FORMAT(@P_RequestToDate,'yyyy-MM-dd 23:59:59')  
   AND ( CASE WHEN COALESCE(@P_PartnerId,0) = 0 THEN  '1' ELSE tbl.createdby END ) =  ( CASE WHEN COALESCE( @P_PartnerId,0) = 0 THEN  '1' ELSE @P_PartnerId END )  
   AND ( CASE WHEN COALESCE(@Userid,0) = 0 THEN  '1' ELSE Requestforuserid END ) =  ( CASE WHEN COALESCE( @Userid,0) = 0 THEN  '1' ELSE @Userid END )  
   AND ( CASE WHEN COALESCE(@P_Status,0) = -1 THEN  '1' ELSE  RequestStatus END ) =  ( CASE WHEN COALESCE( @P_Status,0) = -1 THEN  '1' ELSE @P_Status END )  
   )  
  
   select RecID, RowNumber, (select count(1) from partenerRequest) as [TotalRow], FORMAT( RequestedDate,'dd-MM-yyyy') as RequestedDate, Requestforuserid, RequestForUser , RequestedPartnerUserid , PartnerName , FromPartner,  
    Status,  Remarks  from partenerRequest  
   where RowNumber between @StartPoint and @EndPoint order by RowNumber  
  
  END  
  
  
 END TRY  
 BEGIN CATCH  
  EXEC usp_InsertErrorInfo;  
  
 END CATCH  
  
END  



GO

/* ============================================================
   Procedure: [dbo].[Usp_pm_ChangeResetPassword]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  /*
	select * from user_detail where  email = 'satya.sharma@pelsoftlabs.in' user_id = 42493
  */

CREATE   PROCEDURE Usp_pm_ChangeResetPassword
    @guid NVARCHAR(255),
	@NewPassword varchar(255) ='',
	@RepeatPassword varchar(255) ='',
	@option int = 1
AS  
BEGIN  
    BEGIN TRY  

		DECLARE @UserId  bigint =0;		
		
		IF @guid =''
		BEGIN
			Select 'Invalid link' As Message;
		END
		
		SELECT @UserId = userid from tbl_pm_resetpassword(nolock) WHERE [guid] = @guid
		
		if (@option =1) BEGIN 

			IF EXISTS (SELECT 1 FROM tbl_pm_resetpassword(nolock)  WHERE [GUID]= @GUID and isvalid = 1)
			BEGIN
			
				UPDATE [tbl_pm_resetpassword]  
				SET isvalid = 0, processedon = GETDATE()  
				WHERE guid = @guid;  

				SELECT 'Success' AS Message;
			END
			ELSE BEGIN
				SELECT 'Invalid or expired link..' AS  Message;
			END
		END

		if (@option =2) BEGIN 
			IF @NewPassword COLLATE SQL_Latin1_General_CP1_CS_AS = @RepeatPassword COLLATE SQL_Latin1_General_CP1_CS_AS
			BEGIN
				UPDATE User_Detail
				SET Pwd = @NewPassword
				WHERE User_ID = @UserId;

				
				--- update ticket portal  user .
				UPDATE tbl_tp_UserLogin 
				SET Pwd = @NewPassword
				WHERE User_ID = @UserId ;


				SELECT 'Password Reset successful.' AS  Message;
			END
			ELSE BEGIN
				SELECT 'Password does not match.' AS  Message;
			END
		END
    END TRY  
    BEGIN CATCH  
        SELECT 'Error' AS Result;  	
		exec usp_InsertErrorInfo ;
    END CATCH  

END  


GO

