SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_pm_CheckResellerUser]
(
    @User_ID INT
)
AS
BEGIN
    SET NOCOUNT ON;
 
    IF EXISTS (
        SELECT 1
        FROM reseller_detail WITH (NOLOCK)
        WHERE User_ID = @User_ID
    )
    BEGIN
        SELECT 1 AS IsExist;
    END
    ELSE
    BEGIN
        SELECT 0 AS IsExist;
    END
END



