/* ============================================================
   Procedure: [dbo].[usp_pm_GetDomainInfo_ByParentID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Created by GitHub Copilot in SSMS - review carefully before executing

CREATE   PROCEDURE [dbo].[usp_pm_GetDomainInfo_ByParentID]
(

    @ParentID bigint

)

AS

BEGIN

    SET NOCOUNT ON;
 
    /*

      Purpose: Return branding and partner user details for a given ParentID.

      Changes: Removed temporary table logic; resolve PartnerUserID via scalar function

               and pull branding values from tbl_pt_CustomizationMetadata or fall back

               to MYSMSInvoicing.dbo.settings. Explicit columns only.

    */
 
    DECLARE @PartnerUserID bigint = dbo.fn_userbrandedpartner(@ParentID);

    DECLARE @CompanyName varchar(300);
 
    SELECT @CompanyName = CompnayName

    FROM dbo.User_Detail WITH (NOLOCK)

    WHERE User_ID = @ParentID;
 
    SELECT

        d.ParentID,

        CASE

            WHEN cm.userid IS NOT NULL THEN

                CASE LOWER(JSON_VALUE(cm.jsondata, '$.Theme'))

                    WHEN 'theme 1' THEN '~/AppLogin1.aspx'

                    WHEN 'theme 2' THEN '~/AppLogin2.aspx'

                    WHEN 'theme 3' THEN '~/AppLogin3.aspx'

                    ELSE '~/AppLogin.aspx' END

            ELSE '~/ClientLogin.aspx' END AS LoginPage,

        COALESCE(JSON_VALUE(cm.jsondata, '$.HyperlinkLogo'), '') AS hyperlinkOnLogo,

        COALESCE(JSON_VALUE(cm.jsondata, '$.Slogan'), '') AS slogan,

        COALESCE(NULLIF(JSON_VALUE(cm.jsonMobileData, '$.Domain'), ''),

                 (SELECT TOP(1) s.[value] FROM MYSMSInvoicing.dbo.settings s WITH (NOLOCK) WHERE s.ParentID = @ParentID AND s.[key] = 'Domain')) AS domainName,

        JSON_VALUE(cm.jsondata, '$.PolicyUrl') AS policyUrl,

        JSON_VALUE(cm.jsondata, '$.TermUrl') AS termUrl,

        COALESCE(NULLIF(JSON_VALUE(cm.jsondata, '$.Background_ImageUrl'), ''),

                 (SELECT TOP(1) s.[value] FROM MYSMSInvoicing.dbo.settings s WITH (NOLOCK) WHERE s.ParentID = @ParentID AND s.[key] = 'BackGroundLogo')) AS backgroundImage,

        COALESCE(NULLIF(JSON_VALUE(cm.jsondata, '$.LogoUrl'), ''),

                 (SELECT TOP(1) s.[value] FROM MYSMSInvoicing.dbo.settings s WITH (NOLOCK) WHERE s.ParentID = @ParentID AND s.[key] = 'SiteLogo')) AS companyLogo,

        COALESCE(NULLIF(JSON_VALUE(cm.jsondata, '$.favicon'), ''),

                 (SELECT TOP(1) s.[value] FROM MYSMSInvoicing.dbo.settings s WITH (NOLOCK) WHERE s.ParentID = @ParentID AND s.[key] = 'Fav')) AS faviconIcon,

        CASE WHEN cm.userid IS NOT NULL THEN 'partner' ELSE 'client' END AS domainType,

        r.Reseller_ID AS ResellerId,

        @CompanyName AS CompanyName,

        JSON_VALUE(cm.jsonMobileData, '$.MobileAppLogo') AS AppLogo,

        p.User_ID AS PartnerUserID,

        p.User_Login AS PartnerUserLogin,

        p.FName AS PartnerFirstName,

        p.LName AS PartnerLastName,

        p.EMail AS PartnerEmail,

        p.Mobile AS PartnerMobile,

        p.CompnayName AS PartnerCompanyName,

        p.ParentID AS PartnerParentID

    FROM (SELECT @ParentID AS ParentID) d

    LEFT JOIN dbo.tbl_pt_CustomizationMetadata cm WITH (NOLOCK) ON cm.userid = @PartnerUserID

    LEFT JOIN dbo.User_Detail p WITH (NOLOCK) ON p.User_ID = @PartnerUserID

    LEFT JOIN dbo.reseller_detail r WITH (NOLOCK) ON r.User_ID = @PartnerUserID;

END;
 


GO

/* ============================================================
   Procedure: [dbo].[usp_pm_GetImpersonationRequest]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*

	exec usp_pm_GetImpersonationRequest 335,0,0,'2024-12-10','2024-12-19', -1,0,100,2

	select * from TBL_PM_IMPREQUEST  where requestperiodto <= '2020-01-01'

	--delete from TBL_PM_IMPREQUEST  where requestperiodto <= '2020-01-01'
*/

CREATE   PROC usp_pm_GetImpersonationRequest
(
	@P_USERID BIGINT,
	@P_ReuestedFor bigint = null,
	@P_REQUESTEDTO bigint = null,
	@P_RequestFromDate datetime = null,
	@P_RequestTodate datetime =null,
	@P_status int = 0 ,
	@Offset int = 0,  
	@PageSize int = 100,
	@P_option int = 1
)
AS
BEGIN
	
	BEGIN TRY

		 IF (@P_OPTION = 1 )
		 BEGIN

			 ;with ImpReqUsers as
			 (
				select id	FROM TBL_PM_IMPREQUEST timp(nolock) where timp.REQUESTEDBY = @P_USERID
			 )

			SELECT  ROW_NUMBER() over (order by timp.ID) AS Rownumber ,  
			(select count(1) from ImpReqUsers)  as [TotalRow], REQUESTEDBY , udb.User_Login as RequestedbyUser , 
			timp.ID as RecID,
			REQUESTEDFOR , udf.User_Login as RequestedForUser,
			REQUESTEDTO , udt.User_Login as RequestedTouser,
	   		format(REQUESTPERIODFROM,'dd-MM-yyyy') as REQUESTPERIODFROM , FORMAT( REQUESTPERIODTO,'dd-MM-yyyy') as REQUESTPERIODTO,
			(CASE WHEN REQUESTSTATUS =0 then 'Requested' WHEN REQUESTSTATUS =1 then 'Approved' ELSE 'Rejected' END) as Status,
			 FORMAT( timp.CreatedOn,'dd-MM-yyyy') as RequestedDate , timp.Partner_remarks As Remarks
			FROM TBL_PM_IMPREQUEST timp(nolock)  left join User_Detail udb(nolock) on udb.User_ID = timp.RequestedBy
			left  join User_Detail udf(nolock) on udf.User_ID = timp.RequestedFor
			left  join User_Detail udt(nolock) on udt.User_ID = timp.RequestedTo
			WHERE timp.REQUESTEDBY = @P_USERID
			AND (CASE WHEN COALESCE(@P_ReuestedFor,0) <> 0 THEN @P_ReuestedFor ELSE '1' END )= (CASE WHEN COALESCE(@P_ReuestedFor,0) <> 0 THEN REQUESTEDFOR ELSE '1' END )
			AND TIMP.CreatedOn BETWEEN format( @P_RequestFromDate , 'yyyy-MM-dd 00:00:00')  AND format( @P_RequestTodate , 'yyyy-MM-dd 23:59:59')
			--AND (CASE WHEN @P_RequestFromDate IS NOT NULL THEN @P_RequestFromDate ELSE 1 END ) >= (CASE WHEN @P_RequestFromDate IS NOT NULL THEN REQUESTPERIODFROM ELSE 1 END )
			--AND (CASE WHEN @P_RequestTodate IS NOT NULL THEN @P_RequestTodate ELSE 1 END ) <= (CASE WHEN @P_RequestTodate IS NOT NULL THEN REQUESTPERIODTO ELSE 1 END )
			AND (CASE WHEN (@P_status IS NOT NULL and @P_status <> -1) THEN @P_status ELSE '1' END )= (CASE WHEN (@P_status IS NOT NULL and @P_status <> -1) THEN REQUESTSTATUS ELSE '1' END )
		
		END
		IF (@P_OPTION = 2)
		BEGIN
			
			 ;with ImpRecvUsers as
			 (
				select id	FROM TBL_PM_IMPREQUEST timp(nolock) where timp.RequestedTo = @P_USERID
			 )

			SELECT  ROW_NUMBER() over (order by timp.ID) AS Rownumber ,  
			(select count(1) from ImpRecvUsers)  as [TotalRow], REQUESTEDBY , udb.User_Login as RequestedbyUser , 
			REQUESTEDFOR , udf.User_Login as RequestedForUser,
			REQUESTEDTO , udt.User_Login as RequestedTouser,
			timp.ID as RecID,
	   		format(REQUESTPERIODFROM,'dd-MM-yyyy') as REQUESTPERIODFROM , FORMAT( REQUESTPERIODTO,'dd-MM-yyyy') as REQUESTPERIODTO,
			(CASE WHEN REQUESTSTATUS =0 then 'Requested' WHEN REQUESTSTATUS =1 then 'Approved' ELSE 'Rejected' END) as Status,
			 FORMAT( timp.CreatedOn,'dd-MM-yyyy') as RequestedDate , timp.Remarks As Remarks
			FROM TBL_PM_IMPREQUEST timp(nolock)  left join User_Detail udb(nolock) on udb.User_ID = timp.RequestedBy
			left  join User_Detail udf(nolock) on udf.User_ID = timp.RequestedFor
			left  join User_Detail udt(nolock) on udt.User_ID = timp.RequestedTo
			WHERE timp.RequestedTo = @P_USERID
			AND (CASE WHEN COALESCE(@P_ReuestedFor,0) <> 0 THEN @P_ReuestedFor ELSE '1' END )= (CASE WHEN COALESCE(@P_ReuestedFor,0) <> 0 THEN REQUESTEDFOR ELSE '1' END )
			AND (CASE WHEN COALESCE(@P_REQUESTEDTO,0) <> 0 THEN @P_REQUESTEDTO ELSE '1' END )= (CASE WHEN COALESCE(@P_REQUESTEDTO,0) <> 0 THEN REQUESTEDBY ELSE '1' END )
			AND TIMP.CreatedOn BETWEEN  format( @P_RequestFromDate , 'yyyy-MM-dd 00:00:00')  AND format( @P_RequestTodate , 'yyyy-MM-dd 23:59:59')
			--AND (CASE WHEN @P_RequestFromDate IS NOT NULL THEN @P_RequestFromDate ELSE 1 END ) >= (CASE WHEN @P_RequestFromDate IS NOT NULL THEN REQUESTPERIODFROM ELSE 1 END )
			--AND (CASE WHEN @P_RequestTodate IS NOT NULL THEN @P_RequestTodate ELSE 1 END ) <= (CASE WHEN @P_RequestTodate IS NOT NULL THEN REQUESTPERIODTO ELSE 1 END )
			AND (CASE WHEN (@P_status IS NOT NULL and @P_status <> -1) THEN @P_status ELSE '1' END )= (CASE WHEN (@P_status IS NOT NULL and @P_status <> -1) THEN REQUESTSTATUS ELSE '1' END )
		
		END
	END TRY
	BEGIN CATCH
		PRINT CONCAT('Error occurred: ', ERROR_MESSAGE(), ' | Error Number: ', ERROR_NUMBER(), ' | Line: ', ERROR_LINE());
		Select 'Error ocurred.' As Message;
	END CATCH
	
END


GO

/* ============================================================
   Procedure: [dbo].[usp_pm_GetKycRequestList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_pm_GetKycRequestList](
	@UserId bigint,
	@SearchText nvarchar(max)  = '',
	@FromData date = null,
	@ToDate date = null,
	@Status int = 0,
	@Offsets int = 0,
	@PageSize int = 100
)
as
begin

	--declare 
	--	@UserId bigint = 335,
	--	@SearchText nvarchar(max) = '',
	--	@FromData date = null,
	--	@ToDate date = null,
	--	@Status int = 1,
	--	@Offsets int = 0,
	--	@PageSize int = 10

	declare @ResellerId bigint = 0, @StartPoint int = 0, @EndPoint int = 0
	select @ResellerId = Reseller_ID from reseller_detail(nolock) where User_ID = @UserId
    select @StartPoint = @Offsets + 1, @EndPoint = @Offsets + @PageSize

    ;with kyc as (
        select 
			row_number() over (partition by k.M_ID order by ( case k.Status
					 when 'partial' then 1 when 'Approved' then 3 when 'rejected' then 2 else 0 end) asc) as [Sno],
			k.id, k.ParentId, concat(p.User_Login, ' (', p.FName, ' ', p.LName, ')') as [ParentUserLogin], k.CreatedBy,
            format(k.CreatedOn, 'dd-MMM-yyyy HH:mm') as [CreatedOn],
            format(k.ModifiedOn, 'dd-MMM-yyyy HH:mm') as [ModifiedOn],
            k.Status
        from tbl_KycMaster(nolock) k 
			inner join User_Detail(nolock) p on k.ParentId = p.User_ID
		where k.M_ID = @ResellerId 
            and 1 = ( case
				when isnull(@FromData, '') = '' then 1
				when isnull(@ToDate, '') = '' then 1
				when cast(isnull(k.ModifiedOn, k.CreatedOn) as date) between @FromData and @ToDate then 1
				else 0 end )
            and 1 = ( case
                when @Status = 0 then 1
                when @Status = 1 and k.Status not in ('rejected', 'approved') then 1
                when @Status = 2 and k.Status = 'rejected' then 1
                when @Status = 3 and k.Status = 'approved' then 1
                else 0 end )
			and 1 = (case 
				when isnull(@SearchText, '')  = '' then 1
				when p.User_Login like '%'+@SearchText+'%' then 1
				else 0 end )
    )
    select k.Sno, (select count(1) from kyc) as [TotalRows],
		k.Id, k.ParentId, k.CreatedOn, k.ModifiedOn, k.Status, 
        k.ParentUserLogin,
        concat(c.User_Login, ' (', c.FName, ' ', c.LName, ')') as [CreatedBy],
         d.ApprovedCount, d.RejectedCount, d.PendingCount
    from kyc k        
        inner join User_Detail(nolock) c on k.CreatedBy = c.User_ID
        left join vw_pm_GetKycDocumentStatusCounts(nolock) d on k.id = d.KycId
    where k.Sno between @StartPoint and @EndPoint

end



GO

/* ============================================================
   Procedure: [dbo].[usp_pm_GetLoginDetailForImpersonator]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_pm_GetLoginDetailForImpersonator](
    @impersonatorMid BIGINT,
    @impersonatorUserId BIGINT,
    @impersonatedMid BIGINT,
    @impersonatedUserId BIGINT,
    @sessionId nvarchar(255) = null,
    @loginAction NVARCHAR(25) = 'ImpersonateUser'
)
AS
BEGIN

	 --DECLARE 
	 --	@impersonatorMid BIGINT = 12158,
	 --	@impersonatorUserId BIGINT = 62600,
	 --	@impersonatedMid BIGINT = 12158,
	 --	@impersonatedUserId BIGINT = 62616,
	 --	@sessionId nvarchar(255) = N'gout0h5by3gwfsic3tre42dr',
  --    @loginAction NVARCHAR(25) = 'ImpersonateUser' -- ImpersonateSwitch | ImpersonateUser

	IF(EXISTS(SELECT 1 FROM tbl_pm_UserImpersonateLogintDetails(NOLOCK) WHERE ImpersonatedUserId = @impersonatedUserId ))
	BEGIN
		update tbl_pm_UserImpersonateLogintDetails set SessionEndedOn = getdate() 
			where ImpersonatedUserId = @impersonatedUserId and SessionEndedOn is null
	END

    DECLARE @ImersonateId bigint = 0

    IF(@loginAction = 'ImpersonateUser')
    BEGIN
        INSERT INTO  tbl_pm_UserImpersonateLogintDetails(ImpersonatorMid, ImpersonatorUserId, ImpersonatedMid, 
            ImpersonatedUserId, SessionId, SessionStartedOn, SessionEndedOn, CreatedOn)
        SELECT @impersonatorMid, @impersonatorUserId, @impersonatedMid, @impersonatedUserId, @sessionId, getdate(), null, getdate()
        SET @ImersonateId = SCOPE_IDENTITY()


		
		
-----  activity start   -----
		--activity vars
		
		DECLARE @UserName varchar(255), @PartnerUserName varchar(255) , @ChildPartnerName varchar(255);
		Declare @Eventdata varchar(max);
		---activity vars
		
		select @UserName = User_login from User_Detail where User_ID = @impersonatorUserId;
		select @PartnerUserName = User_login from User_Detail where User_ID = @impersonatorMid;
		select @ChildPartnerName = User_login from User_Detail where User_ID = @impersonatedUserId;
		 
		SET @Eventdata = '{"#partner#":"'+ @UserName +'","#username#":"'+@ChildPartnerName+'"}';

		---select * from ActivityMaster  where EventName like '%partner%' 
		-- #partner# impersonated the user panel of user #username#

		exec usp_pm_PartnerActivity  @impersonatorUserId, @impersonatorUserId,@impersonatedUserId, 'Partner Impersonated User Panel',@Eventdata, 'tbl_pm_UserImpersonateLogintDetails',@ImersonateId;
		

----- activity end  ---



    END
	
	print concat('@impersonatedUserId => ', @impersonatedUserId)

    SELECT ud.ID, ud.M_ID, ud.User_ID, ud.User_Login, ud.FName, ud.LName, ud.EMail, ud.Mobile, ud.City, ud.[State], ud.Country, 
		ud.Type as [UserType], ud.Type as [type], ud.CompnayName, c.Country_ID as [CountryCode], IsAdmin, Timezone, c.Shortname as CountryShortName, ud.ParentID,
		ud.Priority, @ImersonateId AS [ImersonateId], rd.Partner_Type, 
		( case when ( ud.Type = 3 or ud.Type =4 ) then 'Partner' else 'User' end) As DefaultmasterPage
	FROM User_Detail(nolock) ud 
		left join reseller_detail(nolock) rd on rd.User_ID = ud.User_ID
		inner join m_country1(nolock) c on trim(ud.CountryCode) = trim(c.CountryCode)
	where isnull(isverify, 0) = 1 
		and ud.User_ID = ( CASE  @loginAction 
                    WHEN 'ImpersonateUser' THEN @impersonatedUserId
                    WHEN 'ImpersonateSwitch' THEN @impersonatorUserId
                ELSE 0 END )
END



GO

