/* ============================================================
   Procedure: [dbo].[usp_pm_getparentRoles]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_pm_getparentRoles]  --49432,3
(  
 @P_UserId bigint = 0,  
 @P_option int = 1  
)  
AS  
BEGIN  
   
 BEGIN TRY  
  
  
 drop table if exists #childusers  
  
 ;WITH cte AS                     
   (                    
   SELECT a.UserId, a.reportto, ud.User_Login as Name                    
   FROM tbl_pm_UserRoleMapping a(nolock)          
   join User_Detail ud(nolock) on ud.User_Id = a.UserId  
   WHERE a.UserId = @P_UserID                    
   UNION ALL                    
   SELECT a.UserId , a.reportto, ud.User_Login as Name                   
   FROM tbl_pm_UserRoleMapping a(nolock)  
   join User_Detail ud(nolock) on ud.User_Id = a.UserId  
   JOIN cte c ON a.ReportTo = c.UserId  
   where a.IsActive= 1  
   )                    
     
   SELECT UserId into #childusers FROM cte  
    
  Declare @Parentid bigint = 0 , @InsertedId bigint;  
  SELECT @Parentid = dbo.ufn_GetUserParentId(@P_Userid);  
  
  IF (@P_option =1 )  
  BEGIN  
     
   SELECT  tr.ID, tr.RoleName from  tbl_pm_UserRoles tr(nolock)    
   WHERE tr.ParentId in (@Parentid,0)  
  
  END  
  
  IF (@P_option = 2 )  
  BEGIN  
   ;with RoleCTE as   
   (  
    SELECT ROW_NUMBER() OVER (ORDER BY tu.RoleId) as RowNumber ,  coalesce( tu.RoleId,0) as RoleId , coalesce (tr.RoleName,'') as RoleName , Ud.User_ID  , ud.User_Login,  
        coalesce( tu.DefaultmasterPage,'')as DefaultmasterPage  from User_Detail ud(nolock)   
    left join  tbl_pm_UserRoleMapping  tu(nolock) on ud.User_ID = tu.UserId  
    left join tbl_pm_UserRoles tr(nolock) on tr.Id = tu.RoleId  
    WHERE ud.ParentId = @Parentid  and ud.Status = 1  
   )  
     
   --select  tu.RoleId , tr.RoleName , Ud.User_ID  , ud.User_Login, tu.DefaultmasterPage  from User_Detail ud   
   --left join  tbl_pm_UserRoleMapping  tu on ud.User_ID = tu.UserId  
   --left join tbl_pm_UserRoles tr on tr.Id = tu.RoleId  
   --WHERE ud.ParentId =  @Parentid  
  
   select (select count(1) from RoleCTE) as TotalRow , * from  RoleCTE   order by User_Login  ;  
  
  END  
    
  
  IF (@P_option = 3 )  
  BEGIN  
    
  ;with RoleCTE as   
   (  
    SELECT ROW_NUMBER() OVER (ORDER BY tu.RoleId) as RowNumber ,  coalesce( tu.RoleId,0) as RoleId , coalesce (tr.RoleName,'') as RoleName , Ud.User_ID  , ud.User_Login,  
        coalesce( tu.DefaultmasterPage,'')as DefaultmasterPage  from User_Detail ud(nolock)   
    left join  tbl_pm_UserRoleMapping  tu(nolock) on ud.User_ID = tu.UserId  
    left join tbl_pm_UserRoles tr(nolock) on tr.Id = tu.RoleId  
    WHERE ud.ParentId =  @Parentid  and ud.User_ID = @P_UserId  
   ) , 
    
  -- select distinct mm.Id, rp.ScopeId, rp.EntityType, rp.EntityId, mm.ModuleType, mm.Iconurl, mm.PageUrl, mm.ModuleName, mm.Title, mm.Tag , mm.ParentModuleId , R.RoleId, r.RoleName, r.User_ID, r.User_Login, r.DefaultmasterPage  
  -- from  RoleCTE r(nolock)   
  -- left join (select RoleId, ScopeId, EntityType, EntityId    from tbl_pm_RolePermissionMapping(nolock)   where entityType='Menu') rp on r.RoleId = rp.RoleId  
  -- left join tbl_pm_ModuleMaster mm(nolock) on mm.id = rp.EntityId  
  -- order by mm.Id  
  
  -- ---SELECT RoleId , ScopeId, EntityType , EntityId from  tbl_pm_RolePermissionMapping where RoleId = a.Id   
     
  --END  
  RoleFinal AS  
    (  
        SELECT * FROM RoleCTE  

        UNION ALL  

        -- special case: if user is the parent itself, assign Admin role
        SELECT 1 AS RowNumber,  
               1 AS RoleId,  
               'Admin' AS RoleName,  
               @P_UserId AS User_ID,  
               ud.User_Login,  
               'partner' AS DefaultmasterPage  
        FROM User_Detail ud (NOLOCK)  
        WHERE @Parentid = @P_UserId AND ud.User_ID = @P_UserId and ud.IsAdmin=1 and ud.Type in (3,4)
    )  

    SELECT DISTINCT  
           mm.Id,  
           rp.ScopeId,  
           rp.EntityType,  
           rp.EntityId,  
           mm.ModuleType,  
           mm.Iconurl,  
           mm.PageUrl,  
           mm.ModuleName,  
           mm.Title,  
           mm.Tag,  
           mm.ParentModuleId,  
           R.RoleId,  
           R.RoleName,  
           R.User_ID,  
           R.User_Login,  
           R.DefaultmasterPage  
    FROM RoleFinal R (NOLOCK)   
    LEFT JOIN (SELECT RoleId, ScopeId, EntityType, EntityId    
               FROM tbl_pm_RolePermissionMapping (NOLOCK)   
               WHERE EntityType='Menu') rp ON R.RoleId = rp.RoleId  
    LEFT JOIN tbl_pm_ModuleMaster mm (NOLOCK) ON mm.Id = rp.EntityId  
    ORDER BY mm.Id;  

END
 
  /*IF (@P_option = 4 )  
  BEGIN  
    
  ;with RoleCTE as   
   (  
    SELECT ROW_NUMBER() OVER (ORDER BY tu.RoleId) as RowNumber ,  coalesce( tu.RoleId,0) as RoleId , coalesce (tr.RoleName,'') as RoleName , Ud.User_ID  , ud.User_Login,  
        coalesce( tu.DefaultmasterPage,'')as DefaultmasterPage  from User_Detail ud(nolock)   
    left join  tbl_pm_UserRoleMapping  tu(nolock) on ud.User_ID = tu.UserId  
    left join tbl_pm_UserRoles tr(nolock) on tr.Id = tu.RoleId  
    WHERE ud.ParentId =  @Parentid  and ud.User_ID = @P_UserId  
   )  
    
   select distinct  rp.ScopeId, rp.EntityType, rp.EntityId, mm.ModuleActionName, module.Id, module.ModuleName, R.RoleId, r.RoleName, r.User_ID, r.User_Login, r.DefaultmasterPage  
   from  RoleCTE r(nolock)   
   left join (select RoleId, ScopeId, EntityType, EntityId    from tbl_pm_RolePermissionMapping(nolock)   where entityType='Action' ) rp on r.RoleId = rp.RoleId  
   left join tbl_pm_ModuleAction mm(nolock) on mm.id = rp.EntityId  
   left join tbl_pm_ModuleMaster module(nolock) on module.id = mm.ModuleId   
   where mm.IsActive =1   
   order by User_Login , rp.EntityType;  
  
   ---SELECT RoleId , ScopeId, EntityType , EntityId from  tbl_pm_RolePermissionMapping where RoleId = a.Id   
     
  END  */
  IF (@P_option = 4)  
BEGIN  

    ;WITH RoleCTE AS   
    (  
        SELECT ROW_NUMBER() OVER (ORDER BY tu.RoleId) AS RowNumber,  
               COALESCE(tu.RoleId,0) AS RoleId,  
               COALESCE(tr.RoleName,'') AS RoleName,  
               ud.User_ID,  
               ud.User_Login,  
               COALESCE(tu.DefaultmasterPage,'') AS DefaultmasterPage  
        FROM User_Detail ud (NOLOCK)   
        LEFT JOIN tbl_pm_UserRoleMapping tu (NOLOCK) ON ud.User_ID = tu.UserId  
        LEFT JOIN tbl_pm_UserRoles tr (NOLOCK) ON tr.Id = tu.RoleId  
        WHERE ud.ParentId = @Parentid AND ud.User_ID = @P_UserId  
    ),  
    RoleFinal AS  
    (  
        SELECT * FROM RoleCTE  

        UNION ALL  

        -- special case: if user is the parent itself, assign Admin role
        SELECT 1 AS RowNumber,  
               1 AS RoleId,  
               'Admin' AS RoleName,  
               @P_UserId AS User_ID,  
               ud.User_Login,  
               'partner' AS DefaultmasterPage  
        FROM User_Detail ud (NOLOCK)  
        WHERE @Parentid = @P_UserId  
          AND ud.User_ID = @P_UserId  
          AND ud.IsAdmin = 1  
          AND ud.Type IN (3,4)  
    )  

    SELECT DISTINCT  
           rp.ScopeId,  
           rp.EntityType,  
           rp.EntityId,  
           mm.ModuleActionName,  
           module.Id,  
           module.ModuleName,  
           R.RoleId,  
           R.RoleName,  
           R.User_ID,  
           R.User_Login,  
           R.DefaultmasterPage  
    FROM RoleFinal R (NOLOCK)   
    LEFT JOIN (SELECT RoleId, ScopeId, EntityType, EntityId    
               FROM tbl_pm_RolePermissionMapping (NOLOCK)   
               WHERE EntityType='Action') rp ON R.RoleId = rp.RoleId  
    LEFT JOIN tbl_pm_ModuleAction mm (NOLOCK) ON mm.Id = rp.EntityId  
    LEFT JOIN tbl_pm_ModuleMaster module (NOLOCK) ON module.Id = mm.ModuleId   
    WHERE mm.IsActive = 1   
    ORDER BY R.User_Login, rp.EntityType;  

END  

  IF (@P_option = 5 )  
  BEGIN  
   SELECT USERID , DefaultmasterPage from tbl_pm_UserRoleMapping where Parentid =@Parentid and UserId = @P_UserId  
  END  
  
  IF (@P_option = 6 )  
  BEGIN  
  
   --================report to user ===============  
  
   SELECT  User_ID , CONCAT(User_Login , '(', ud.FName , ' ' , ud.LName , ')' ) as User_Login  from   
   tbl_pm_UserRoleMapping t(nolock) join  
   User_Detail ud(nolock) on t.userid=ud.user_id  
   where ud.Parentid =@Parentid and ud.status=1 and t.isactive=1  
      and User_ID not in  (select userid from #childusers )  
  
   --SELECT  User_ID , CONCAT(User_Login , '(', ud.FName , ' ' , ud.LName , ')' ) as User_Login  from User_Detail ud(nolock)   
   --where Parentid =@Parentid  and User_ID <> @P_UserId   
   --and User_ID not in  ( select UserID from tbl_pm_UserRoleMapping  where ReportTo = @P_UserId union select 0 )  
  
   ----SELECT  User_ID , CONCAT(User_Login , '(', ud.FName , ' ' , ud.LName , ')' ) as User_Login  from User_Detail ud(nolock)   
   ----where Parentid = 335  and User_ID <> 28044  
   ----and User_ID not in  ( select UserID from tbl_pm_UserRoleMapping  where ReportTo = 28044 union select 0 )  
  
   --A--B--C--D   B  
  
  
  END  
  
  IF (@P_option = 7 )  
  BEGIN  
  
   --================user list===============  
   ---add user role mapping user list  
  
    
   SELECT  User_ID , CONCAT(User_Login , '(', ud.FName , ' ' , ud.LName , ')' ) as User_Login  from User_Detail ud(nolock)   
   where Parentid =@Parentid   and User_ID not in  ( select UserID from tbl_pm_UserRoleMapping )  
  
  END  
  
  IF (@P_option = 8 )  
  BEGIN  
  
   --================user list===============  
   ---edit user role mapping user list  
   SELECT  User_ID , CONCAT(User_Login , '(', ud.FName , ' ' , ud.LName , ')' ) as User_Login  from User_Detail ud(nolock)   
   where User_ID = @P_UserId    
  
  END  
  
  
 END TRY  
 BEGIN CATCH  
  EXEC usp_InsertErrorInfo;  
 END CATCH  
END  



