/* ============================================================
   Procedure: [dbo].[usp_pm_getpartnerNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*

select top 10 * from tbl_PartnerEventHistory(nolock) order by 1 desc

alter table tbl_PartnerEventHistory
add 	IsRead bit default 0

--update tbl_PartnerEventHistory set IsRead  = 0 where partneruserid = 335
usp_pm_getpartnerNotification  '335',  '01-Jan-2025' , '10-Feb-2025','',2
 


*/

CREATE   PROC usp_pm_getpartnerNotification
(
	@partneruserid bigint,
	@P_EventFromdate datetime = null,
	@P_EventTodate datetime = null,
	@P_EventName varchar(max) = '',
	@P_option int = 1
)
as
begin

	---declare @partneruserid bigint = 62600

	select @Partneruserid = [dbo].[ufn_GetUserParentId](@Partneruserid);

	if (@P_option = 1) begin 
		select a.Historyid, a.EventID ,a.EventDescription, Format(a.EventDate,'MM-dd-yyyy HH:mm:ss') as EventDate , b.EventName  from tbl_PartnerEventHistory a(nolock) 
		left join ActivityMaster b(nolock) on a.EventID = b.ID
		where (a.PartnerUserID = @partneruserid or a.PartnerParentID  = @partneruserid) --and a.IsRead = 0
		order by a.EventDate desc ;
	end
	if (@P_option = 2) begin 

	
		print (@P_EventFromdate);

        ;with partnerNotifications as
		(
			select Historyid , IsRead	FROM tbl_PartnerEventHistory a(nolock) 
			left join ActivityMaster b(nolock) on a.EventID = b.ID
			where (a.PartnerUserID = @partneruserid or a.PartnerParentID  = @partneruserid)
			AND a.EventDate BETWEEN  format( @P_EventFromdate , 'yyyy-MM-dd 00:00:00')  AND format( @P_EventTodate , 'yyyy-MM-dd 23:59:59')
			AND CASE WHEN @P_EventName = '' THEN '1' ELSE B.EventName END = CASE WHEN @P_EventName = '' THEN '1' ELSE @P_EventName END 
		)

		SELECT  ROW_NUMBER() over (order by a.Historyid) AS Rownumber ,  
		(select count(1) from partnerNotifications)  as [TotalRow], 
		(select count(1) from partnerNotifications where IsRead =0)  as [Unread], 
		 a.Historyid, a.EventID ,a.EventDescription, Format(a.EventDate,'MM-dd-yyyy HH:mm:ss') as EventDate , b.EventName  , b.EventType
		from tbl_PartnerEventHistory a(nolock) 
		left join ActivityMaster b(nolock) on a.EventID = b.ID
		where (a.PartnerUserID = @partneruserid or a.PartnerParentID  = @partneruserid) --and a.IsRead = 0
		AND a.EventDate BETWEEN  format( @P_EventFromdate , 'yyyy-MM-dd 00:00:00')  AND format( @P_EventTodate , 'yyyy-MM-dd 23:59:59')
		AND (CASE WHEN @P_EventName = '' THEN '1' ELSE B.EventName END) like (CASE WHEN @P_EventName = '' THEN '1%' ELSE '%'+@P_EventName+'%' END )
		order by a.EventDate desc ;

	end


end




