CREATE   PROCEDURE [dbo].[usp_pm_GetUserLoginByUserId]--32222
(
    @User_ID BIGINT
)
AS
BEGIN
    SET NOCOUNT ON;
 
    IF EXISTS
    (
        SELECT 1
        FROM User_Detail WITH (NOLOCK)
        WHERE User_ID = @User_ID
              AND Status = 1
    )
    BEGIN
        SELECT 
            User_Login
        FROM User_Detail WITH (NOLOCK)
        WHERE User_ID = @User_ID
              AND Status = 1;
    END
    ELSE
    BEGIN
        SELECT 'User not exist' AS Message;
    END
END



