/* ============================================================
   Procedure: [dbo].[usp_pm_LoadSavedRoleData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_pm_LoadSavedRoleData]
(
	@P_roleId bigint,
	@P_ScopeId int,
	@P_Userid int,
	@P_option int =1
)
AS
BEGIN 
	
	--declare @P_roleId bigint =1,
	--@P_ScopeId int =1,
	--@P_Userid int = 335,
	--@P_option int =4


	Declare @Parentid bigint = 0 , @InsertedId bigint;
	SELECT @Parentid = dbo.ufn_GetUserParentId(@P_Userid)

	BEGIN TRY
		IF (@P_OPTION =1) BEGIN
			select   RoleId , ScopeId, EntityType , EntityId  from tbl_pm_RolePermissionMapping where RoleId = @P_RoleId  and EntityType = 'Menu' and Parentid = @Parentid  ;
		END

		IF (@P_OPTION =2) BEGIN
			select   RoleId , ScopeId, EntityType , EntityId  from tbl_pm_RolePermissionMapping where RoleId = @P_RoleId  and EntityType = 'Action' and Parentid = @Parentid ;
		END

		if (@P_option =3) begin
			
			;with RoleCTE as 
			(
				SELECT ROW_NUMBER() OVER (ORDER BY tu.RoleId) as RowNumber ,  coalesce( tu.RoleId,0) as RoleId , coalesce (tr.RoleName,'') as RoleName , Ud.User_ID  , ud.User_Login,
		 	    coalesce(	tu.DefaultmasterPage,'')as DefaultmasterPage  from User_Detail ud(nolock) 
				left join  tbl_pm_UserRoleMapping  tu(nolock) on ud.User_ID = tu.UserId
				left join tbl_pm_UserRoles tr(nolock) on tr.Id = tu.RoleId
				WHERE ud.ParentId =  @Parentid  and ud.User_ID = @P_UserId and tr.Id = @P_roleId
			)
		
		 
			select distinct  rp.ScopeId, rp.EntityType, rp.EntityId, mm.Modulename,mm.ParentModuleId ,R.RoleId, r.RoleName, r.User_ID, r.User_Login, r.DefaultmasterPage
			from  RoleCTE r(nolock) 
			left join (select RoleId, ScopeId, EntityType, EntityId    from tbl_pm_RolePermissionMapping(nolock)   where entityType='Menu') rp on r.RoleId = rp.RoleId
			left join tbl_pm_ModuleMaster mm(nolock) on mm.id = rp.EntityId
			union
			select distinct  rp.ScopeId, rp.EntityType, rp.EntityId, mm.ModuleActionName, 0 as ParentModuleid, R.RoleId, r.RoleName, r.User_ID, r.User_Login, r.DefaultmasterPage
			from  RoleCTE r(nolock) 
			left join (select RoleId, ScopeId, EntityType, EntityId    from tbl_pm_RolePermissionMapping(nolock)   where entityType='Action') rp on r.RoleId = rp.RoleId
			left join tbl_pm_ModuleAction mm(nolock) on mm.id = rp.EntityId
			order by User_Login , rp.EntityType;


			select * from tbl_pm_RolePermissionMapping where RoleId =2

		end


		if (@P_option =4) begin
			
			;with RoleCTE as 
			(
				SELECT ROW_NUMBER() OVER (ORDER BY tr.Id) as RowNumber ,  coalesce( tr.Id,0) as RoleId , coalesce (tr.RoleName,'') as RoleName
				from  tbl_pm_UserRoles tr(nolock) 
				WHERE tr.ParentId in (  @Parentid ,0) and tr.id = @P_roleId
			)
		
			 
			select distinct  rp.ScopeId, rp.EntityType, rp.EntityId, mm.Modulename,mm.ParentModuleId ,R.RoleId, r.RoleName
			from  RoleCTE r(nolock) 
			left join (select RoleId, ScopeId, EntityType, EntityId ,Parentid   from tbl_pm_RolePermissionMapping(nolock)   where entityType='Menu') rp on r.RoleId = rp.RoleId
			left join tbl_pm_ModuleMaster mm(nolock) on mm.id = rp.EntityId
			where  (case when r.RoleId in (1,2) then '1' else  rp.Parentid end) = (case when r.RoleId in (1,2) then '1' else @Parentid end)
			union
			select distinct  rp.ScopeId, rp.EntityType, rp.EntityId, mm.ModuleActionName, 0 as ParentModuleid, R.RoleId, r.RoleName
			from  RoleCTE r(nolock) 
			left join (select RoleId, ScopeId, EntityType, EntityId ,Parentid   from tbl_pm_RolePermissionMapping(nolock)   where entityType='Action') rp on r.RoleId = rp.RoleId
			left join tbl_pm_ModuleAction mm(nolock) on mm.id = rp.EntityId
			where  (case when r.RoleId in (1,2) then '1' else  rp.Parentid end) = (case when r.RoleId in (1,2) then '1' else @Parentid end)

			--select * from tbl_pm_RolePermissionMapping where RoleId =2

		end

	END TRY
	BEGIN CATCH
		exec usp_InsertErrorInfo;

	END CATCH

END



GO

