/* ============================================================
   Procedure: [dbo].[usp_pm_OperateClientusers]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_pm_OperateClientusers]
(
	@P_clientuserId bigint,
	@P_AssignedUserid bigint,
	@P_userId bigint,
	@P_option int
)
AS
BEGIN

		--- select * from tbl_pm_Clientusers
		--- sp_help tbl_pm_Clientusers
		--- insert data in assigned user table.

	BEGIN TRY

		Declare @ParentId bigint =0;
		select @ParentId = dbo.ufn_GetUserParentId(@P_clientuserId);

		IF (@P_option =1) BEGIN

			IF EXISTS( SELECT 1 FROM tbl_pm_Clientusers WHERE ClientUserId = @P_clientuserId) begin
					update tbl_pm_Clientusers set Isactive = 0 WHERE ClientUserId = @P_clientuserId
			end

		
			INSERT INTO tbl_pm_Clientusers (ClientUserId, AssignedUser, IsActive, CreatedBy, CreatedDate)
			VALUES (@P_clientuserId, @P_AssignedUserid , 1, @P_userId, GETDATE());
		

			select 'Save Successful.' as Message;

		END

		--- select client users for for dropdown 

		IF (@P_option =2) BEGIN
			
			SELECT ud.user_id, CONCAT( ud.User_Login , '(',ud.FName ,' ',ud.LName ,')' ) as User_Login  FROM
			tbl_pm_UserRoleMapping tu left join  User_Detail ud(nolock) on tu.UserId = ud.User_ID
			WHERE tu.PARENTID =  @ParentId

		END

		--- select client users for for filter dropdown 
		IF (@P_option =3) BEGIN		
			
			
			SELECT tc.AssignedUser , tc.ClientUserId, ud.User_Login  FROM tbl_pm_Clientusers(nolock) tc 
			left join User_Detail ud on ud.User_ID = tc.AssignedUser
			WHERE tc.ClientUserId = @P_clientuserid 
		END



	END TRY
	BEGIN CATCH
		exec usp_InsertErrorInfo;
	END CATCH


END

-------------------------------------------------


GO

/* ============================================================
   Procedure: [dbo].[usp_pm_PartnerActivity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*

usp_pm_PartnerActivity  335, 0,0,'Partner Created White-Labeled Partner','{"#ParentPartnerName#":"SMS19","#ChildPartnerName#":"KMUKESH343"}','TESTTABLE', 99


====================================================================================================================================
*/

CREATE   PROC usp_pm_PartnerActivity
(
	@P_userid bigint,
	@P_Partner_userId bigint,
	@P_ChildPartneruserId bigint,
	@P_Activityname varchar(300),
	@P_Metadata nvarchar(max),
	@P_Reftable varchar(255)='',
	@P_RefID bigint = 0
)
AS
BEGIN
	
	BEGIN TRY
		Declare @Count int =0 , @sno int  =0  , @ActivityDescription nvarchar(max);
		drop table if exists #json
		select row_number()  over (partition by type order by type) sno,* into #json from openjson(@P_Metadata)

		select @Count=count(1) from #json

		SELECT @ActivityDescription  = EventTemplate FROM ActivityMaster(nolock)  WHERE EventName LIKE  '%'+  @P_Activityname +'%' ;

		----SELECT * FROM #JSON;

		while @Count > 0
		begin
			select @sno=min(sno) from #json where sno>@sno ;
			select @ActivityDescription=replace(@ActivityDescription,[key],ISNULL([value],'') collate SQL_Latin1_General_CP1_CI_AS ) from #json where sno = @sno;
			set @Count=@Count-1
		end
		print ('ACTIVITY : '+@ActivityDescription);
		EXEC [UspSavepartnerActivity_withid]  @P_Partner_userId , @P_userid , @P_ChildPartneruserId, @ActivityDescription , @P_Activityname, @P_Reftable ,@P_RefID; 
	END TRY
	BEGIN CATCH
		exec usp_InsertErrorInfo
	END CATCH
	
END



