/* ============================================================
   Procedure: [dbo].[usp_pm_partnerCustomMetadata]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*

	tbl_pt_CustomizationMetadata
	usp_pm_partnerCustomMetadata 335
*/

CREATE   PROC usp_pm_partnerCustomMetadata
(
	@P_userid bigint
)
AS
BEGIN
	
	BEGIN TRY
	
		Declare @jsondata  NVarchar(max);

		SELECT TOP 1   @jsondata = jsondata from tbl_pt_CustomizationMetadata where userid = @P_userid;

		PRINT @JSONDATA;
		--{    "USERID": "335",    "DomainName": "http://sms19.com",    "LogoUrl": "logo rest1.jpg",    "HyperlinkLogo": "https://kit19.com/assets/custom/img/favicon.ico",    "favicon": "test logo.jpg",    "Theme": "Theme 2",    "Background_ImageUrl": "logo rest1.jpg",    "TermUrl": "http://sms19.com/Partner/term-and-condition.html",    "PolicyUrl": "http://sms19.com/Partner/policy.html"  }

		
		SET @jsondata = '[' + @jsondata +']';


			CREATE TABLE #tblMeta 
				(
					USERID nvarchar(max),
					DomainName nvarchar(max),
					LogoURL nvarchar(max),
					HyperLinkOnlogo nvarchar(max),
					favicon nvarchar(max),
					Theme nvarchar(max),
					backgroundImageUrl nvarchar(max),
					TermURL nvarchar(max),
					PolicyURL nvarchar(max)
				)
		
		
				insert into #tblMeta
				select 
				JSON_VALUE(value, '$.USERID'),
				JSON_VALUE(value, '$.DomainName'),
				JSON_VALUE(value, '$.LogoUrl'),
				JSON_VALUE(value, '$.HyperLinkOnlogo'),
				JSON_VALUE(value, '$.favicon'),
				JSON_VALUE(value, '$.Theme'),
				JSON_VALUE(value, '$.backgroundImageUrl'),
				JSON_VALUE(value, '$.TermURL'),
				JSON_VALUE(value, '$.PolicyURL')
				from openjson(@jsondata);


		SELECT   USERID ,  DomainName ,  LogoUrl,  HyperLinkOnlogo,  favicon , Theme, backgroundImageUrl , TermUrl,   PolicyUrl, ud.CompnayName As CompanyName  FROM   #tblMeta tbl
		left join User_Detail ud(nolock) on tbl.USERID = ud.User_ID 

		--select  substring('http://sms19.com', charindex('://','http://sms19.com')+3,charindex('.com','http://sms19.com')-charindex('://','http://sms19.com')-3 )
		

	END TRY
	BEGIN CATCH
		PRINT CONCAT('Error occurred: ', ERROR_MESSAGE(), ' | Error Number: ', ERROR_NUMBER(), ' | Line: ', ERROR_LINE());

	END CATCH


END


