/* ============================================================
   Procedure: [dbo].[usp_pm_ResetPassword]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  /*
	
	[tbl_pm_resetpassword]
 
  */
CREATE   PROCEDURE [dbo].[usp_pm_ResetPassword]  
    @userIdentifier NVARCHAR(100)  
AS  
BEGIN  

	----Declare  @userIdentifier NVARCHAR(100)  ='kit19qa@gmail.com';
	
    Declare @message NVARCHAR(MAX)  
    DECLARE @UserId bigint  
    DECLARE @ResetGuid NVARCHAR(100)  
    DECLARE @ExpiryDate DATETIME  
    DECLARE @UserEmail NVARCHAR(100)
	
   Declare @Domainurl varchar(max),  @Resellerid bigint, @PartnerUserid bigint , @subject  varchar(100) , @msgContent varchar(max),
   @partneremail varchar(510) , @MailSource varchar(100), @batchid int


    SELECT @UserId = User_ID,  
           @UserEmail = Email ,
		   @Resellerid = M_ID
    FROM User_Detail(nolock) 
    WHERE User_Login = @userIdentifier  
        OR Email = @userIdentifier  
        OR convert( varchar(50), Mobile) = @userIdentifier  
  
    IF (@UserId IS NOT NULL)  
    BEGIN  
  
        IF  NOT EXISTS (  
            SELECT 1  
            FROM [tbl_pm_resetpassword](nolock)  
            WHERE userid = @UserId  
                AND expirydate > GETDATE()  
                AND isvalid = 1  
        )  
        BEGIN  
            SET @ResetGuid = NEWID()  
            SET @ExpiryDate = DATEADD(day, 1, GETDATE())  
            INSERT INTO [tbl_pm_resetpassword] (userid, guid, expirydate, isvalid, email)  
            VALUES (@UserId, @ResetGuid, @ExpiryDate, 1, @UserEmail)  

         
			---message content
		    exec usp_pm_getMessageHtmlText 'reset',  @UserId  , @msgContent out
			SET @msgContent = REPLACE (@msgContent,'#resetguid#',@ResetGuid);
			PRINT CONCAT('MESSAGE' ,@msgContent );

		 
			-- partner data 
			 SELECT  @PartnerUserid= User_ID from reseller_detail(nolock) where Reseller_ID = @Resellerid

			declare @partner_jsondata nvarchar(max);
			select top 1 @partner_jsondata= jsonEmaildata from tbl_pt_CustomizationMetadata(nolock) where userid = @PartnerUserid;
			SELECT @partneremail = COALESCE(JSON_VALUE(@partner_jsondata, '$.Email'), 'noreply@email19.in');
			select top 1 @partner_jsondata= jsondata from tbl_pt_CustomizationMetadata(nolock) where userid = @PartnerUserid;
			print  'partner json data --- >   '+@partner_jsondata
			
			SELECT @Domainurl = COALESCE(JSON_VALUE(@partner_jsondata, '$.DomainName'), '');
		    SET @Domainurl = 'https://' + REPLACE(REPLACE( REPLACE(@Domainurl, 'www.', ''),'https://',''),'httP://','')

			print concat('Domainurl : ', @Domainurl);

			SET @subject = 'Reset password';
	
			--SET @msgContent = 'Hi, you can reset your password by clicking the following link: ';
			--SET @msgContent = @msgContent + '<a href="' + @Domainurl + '/ChangePassword.aspx?Guid=' + CONVERT( varchar(max) ,@ResetGuid )+ '">Reset Password</a>';
			--   -- string emailBody = "Hi, you can reset your password by clicking the following link: ";
            --emailBody += "<a href='" + domain + "/Screen/Page/changepassword.aspx?Guid=" + ResetGuid + "'>Reset Password</a>";
			--print @msgContent;

			set @partneremail  = case when  coalesce( @partneremail,'') = '' then  'noreply@email19.in' else  @partneremail  end ;
			print concat('partner email = ' , @partneremail, ', receipient email =' , @UserEmail, ', PARTNER USER id = ',@PartnerUserid);

			select @message = 'Password reset link has been sent successfully.';  


			BEGIN TRY
				exec [usp_SendMails] @UserEmail, ---  receipient mail ,
					@PartnerUserid , ---  reseler id 
					@subject ,-- subject ,
					0,
					@msgContent,  --- message content 
					@partneremail,  --- partener email 
					@partneremail , --- partener email 
					'T',
					1, --priority 
					'Change password',  ---  mail source
					@batchid output    --- output variable 

					print concat('batchid = ' , @batchid);

			END TRY
			BEGIN CATCH
				exec usp_InsertErrorInfo  	
			END CATCH
				
        END  
        ELSE  
        BEGIN  
            select @message = 'A password reset link has already been sent and is still valid.';  
        END  
    END  
    ELSE  
    BEGIN  
        select @message = 'User not found.';  
    END  
    SELECT 'Inserted User_Id: ' + CAST(@UserId AS NVARCHAR(10)) AS Result, @ResetGuid AS Guid, @message AS Message;  
END  
  


GO

/* ============================================================
   Procedure: [dbo].[usp_pm_RoleOperate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*
exec usp_pm_RoleOperate 'New Role',3,335,6


UPDATE tbl_pm_UserRoles set  parentid = 0 where Id in (1,2) ;

*/
CREATE   PROCEDURE [dbo].[usp_pm_RoleOperate]
(
	@P_rolename varchar(30)='',
	@P_roleId bigint=0,
	@P_Userid bigint = 0,
	@P_option bigint =1,
	@P_search varchar(120)='',
	@Offset int = 0,  
	@PageSize int = 100     
)
AS
BEGIN

	BEGIN TRY
		
		Declare @Parentid bigint = 0 , @InsertedId bigint;
		SELECT @Parentid = dbo.ufn_GetUserParentId(@P_Userid)

		PRINT concat('Parent id', @Parentid);

		--- add user role.
		IF (@P_option =1 ) BEGIN
			--select 1
			--tbl_pm_UserRoles
			

			BEGIN TRANSACTION;

			BEGIN TRY
				IF (@P_rolename = '') 
				BEGIN
					SELECT 'Blank role Name' AS Message;
					ROLLBACK TRANSACTION;
					RETURN;
				END

				INSERT INTO tbl_pm_UserRoles 
				(RoleName, ParentId, IsActive, IsPredefined, CreatedBy, CreatedDate)
				VALUES
				(@P_rolename, @Parentid, 1, 0, @P_Userid, GETDATE());

				set @InsertedId = SCOPE_IDENTITY();
				
				INSERT INTO tbl_pm_RolePermissionMapping (RoleId, ScopeId, IsActive, EntityType, EntityId, Parentid, CreatedBy, CreatedDate)
				VALUES 
				(@Insertedid, 2, 1, 'Menu', 1, @Parentid, @P_Userid, GETDATE()),
				(@Insertedid, 2, 1, 'Action', 1, @Parentid, @P_Userid, GETDATE()),
				(@Insertedid, 2, 1, 'Action', 2, @Parentid, @P_Userid, GETDATE()),
				(@Insertedid, 2, 1, 'Action', 3, @Parentid, @P_Userid, GETDATE()),
				(@Insertedid, 2, 1, 'Action', 4, @Parentid, @P_Userid, GETDATE());

				SELECT 'Add role successful.' As Message;

				COMMIT TRANSACTION;
			END TRY
			BEGIN CATCH
				ROLLBACK TRANSACTION;
				SELECT ERROR_MESSAGE() AS Message;
			END CATCH;

		END	
		IF (@P_option =2 ) BEGIN

			if (@P_rolename = '')begin
				Select 'Blank role Name' as Message;
				return;
			end

			UPDATE tbl_pm_UserRoles set RoleName = @P_rolename, ModifiedBy = @P_Userid , ModifiedDate = GETDATE(),  IsActive =1 , IsPredefined = 0 where Id= @P_roleId and  ParentId  = @Parentid;
			SELECT 'Update successful.' As Message;

		END
		IF (@P_option =3 ) begin
			
			--- get role details

			SELECT Id, RoleName, Ispredefined ,
			(select tr.userId as UserId , ud.user_login as userLogin  from tbl_pm_UserRoleMapping(nolock) tr left join User_Detail ud(nolock) on ud.User_ID = tr.UserId  
			where RoleId = a.Id and tr.Parentid=@Parentid for JSON AUTO) as UserRoleData,
			(select count(1)  from tbl_pm_UserRoleMapping(nolock) tr left join User_Detail ud(nolock) on ud.User_ID = tr.UserId  where RoleId = a.Id and tr.Parentid = @Parentid ) as UsersCount,
			(SELECT RoleId , ScopeId, EntityType , EntityId from  tbl_pm_RolePermissionMapping(nolock) where RoleId = a.Id for JSON  AUTO)  AS Mappingdata
			FROM  tbl_pm_UserRoles a(nolock) WHERE ParentId  in( @Parentid,0) and IsActive =1 ;

			---SELECT (SELECT RoleId , ScopeId, EntityType , EntityId from  tbl_pm_RolePermissionMapping where RoleId =1 for JSON  AUTO ) AS MSG

		END

		--- copy role and permission
		IF (@P_option =4 ) begin
			BEGIN TRANSACTION;
			BEGIN TRY 
				Declare @Rolename varchar(20);
				select @Rolename  = RoleName +'-copy' from tbl_pm_UserRoles(nolock) where id = @P_roleId;

				INSERT INTO tbl_pm_UserRoles 
				(RoleName, ParentId, IsActive, IsPredefined, CreatedBy, CreatedDate) 
				VALUES 
				(@Rolename, @Parentid, 1, 0 , @P_Userid, GETDATE());

				set @InsertedId =  SCOPE_IDENTITY();
			
				INSERT INTO tbl_pm_RolePermissionMapping 
				(RoleId, ScopeId, IsActive, EntityType, EntityId, ParentId, CreatedBy, CreatedDate) 
				SELECT @InsertedId , ScopeId, IsActive, EntityType, EntityId, @Parentid, @P_Userid, GETDATE() FROM tbl_pm_RolePermissionMapping(nolock) WHERE RoleId = @P_roleId;

				COMMIT TRANSACTION;
				SELECT 'Copy successful.' As Message;

			END TRY
			BEGIN CATCH
				ROLLBACK TRANSACTION;
				SELECT ERROR_MESSAGE() AS Message;
			END CATCH
		END
		IF (@P_option =5 ) begin	
			BEGIN TRANSACTION;
			BEGIN TRY
				DELETE FROM  tbl_pm_RolePermissionMapping WHERE RoleId= @P_roleId ;
				DELETE FROM  tbl_pm_UserRoles WHERE Id= @P_roleId ;
				COMMIT TRANSACTION;
				SELECT 'Delete successful.' As Message;
			END TRY
			BEGIN CATCH
				ROLLBACK TRANSACTION;
				SELECT 'Role is already associated with the user. Remove users then delete.' AS Message;
			END CATCH
		END

		---old list
		IF (@P_option = 6 ) begin

		--				exec usp_pm_RoleOperate 'New Role',3,335,6

			Declare @UseNames varchar(max) ='' , @Createdby bigint 
			
			declare @tblusernames as Table
			(
				RoleId int,
				UserNames varchar(max),
				CreatedBy bigint
			)

			declare @maxid int , @minid int;

			select @maxid = max(RoleId) , @minid = min(RoleId) from tbl_pm_UserRoleMapping(nolock) where Parentid =@Parentid ;

			while (@minid <= @maxid)
			begin
				
				set @UseNames ='';

				if exists( select 1 from tbl_pm_UserRoleMapping(nolock) where RoleId =@minid and Parentid =@Parentid )
				begin
					select @UseNames = CONCAT( coalesce(ud.User_Login,''), '(', coalesce(ud.FName,''),' ', coalesce(ud.LName,'') , ') ,' ) + @UseNames,
					@Createdby = tu.CreatedBy
					from tbl_pm_UserRoleMapping tu(nolock) 
					left join User_Detail ud(nolock) on ud.User_ID = tu.UserId
					where tu.RoleId = @minid and tu.Parentid = @Parentid
			
					insert into @tblusernames( RoleId, UserNames , CreatedBy )
					select @minid , @UseNames , @Createdby

				end

				set @minid =@minid +1;
			end


			;with roleCTE as ( 
				SELECT  ROW_NUMBER() over (order by tr.id ) as RowNumber,  tr.Id, tr.RoleName, 
				(select count(1)  from tbl_pm_UserRoleMapping(nolock) t left join User_Detail ud(nolock) on ud.User_ID = t.UserId  where RoleId = tr.Id and t.Parentid =@Parentid ) as UsersCount,
				tuser.UserNames,
				tuser.CreatedBy,
				ud.User_Login as Createdbyuser
				FROM tbl_pm_UserRoles tr(nolock) 
				left join @tblusernames tuser on tuser.RoleId = tr.Id
				left join User_Detail ud(nolock) on ud.User_ID = tuser.CreatedBy
				WHERE tr.ParentId  in( @Parentid,0) and tr.IsActive =1 
			)


			SELECT r.RowNumber, (select count(1) from roleCTE) as [TotalRow] , Id , RoleName , UsersCount, UserNames , CreatedBy , Createdbyuser  from roleCTE r
			where RoleName like  ( case when @P_search = '' then '%'+ RoleName  +'%'  ELSE '%'+ @P_search  +'%'  END ) OR 
			UserNames like  ( case when @P_search = '' then '%'+ UserNames  +'%'  ELSE '%'+ @P_search  +'%'  END )	;


		END

		IF (@P_option =7 ) begin	

			delete FROM  tbl_pm_UserRoleMapping WHERE RoleId= @P_roleId and Parentid = @Parentid ;
			Select 'Delete successful.' As Message;

		end


		IF (@P_option = 8 )
		BEGIN
			;with RoleCTE as 
			(
				SELECT ROW_NUMBER() OVER (ORDER BY tu.RoleId) as RowNumber ,  coalesce( tu.RoleId,0) as RoleId , coalesce (tr.RoleName,'') as RoleName , Ud.User_ID  , ud.User_Login,
		 	    coalesce(	tu.DefaultmasterPage,'')as DefaultmasterPage  from User_Detail ud(nolock) 
				left join  tbl_pm_UserRoleMapping  tu(nolock) on ud.User_ID = tu.UserId
				left join tbl_pm_UserRoles tr(nolock) on tr.Id = tu.RoleId
				WHERE ud.ParentId = @Parentid  and ud.Status = 1 and RoleId = @P_roleId
			)
			
			select (select count(1) from RoleCTE) as TotalRow , * from  RoleCTE   order by User_Login  ;

		END


		IF (@P_option = 9 ) begin

			--	exec usp_pm_RoleOperate 'New Role',3,335,9

			;with roleCTE as ( 
				SELECT  ROW_NUMBER() over (order by tr.id ) as RowNumber,  tr.Id as RoleId , tuser.Id , tr.RoleName, 
				tuser.UserId,
				ud.User_Login  as UserName,
				tuser.ReportTo,
				tuser.DefaultmasterPage,
				udr.User_Login as ReportToUser
				FROM tbl_pm_UserRoles tr(nolock) 
				left join tbl_pm_UserRoleMapping tuser on tuser.RoleId = tr.Id
				left join User_Detail ud(nolock) on ud.User_ID = tuser.UserId
				left join User_Detail udr(nolock) on udr.User_ID = tuser.ReportTo
				WHERE ud.ParentId  in( @Parentid,0) and ud.Status =1 and tr.IsActive =1 
			)

			SELECT r.RowNumber, (select count(1) from roleCTE) as [TotalRow] , Id , RoleId , RoleName , UserId , UserName , ReportTo, DefaultmasterPage , ReportToUser   from roleCTE r
			where RoleName like  ( case when @P_search = '' then '%'+ RoleName  +'%'  ELSE '%'+ @P_search  +'%'  END ) OR 
			UserName like  ( case when @P_search = '' then '%'+ UserName  +'%'  ELSE '%'+ @P_search  +'%'  END ) order by RoleName	;

		END


	END TRY
	begin catch
		exec  usp_InsertErrorInfo;
	end catch


END






GO

/* ============================================================
   Procedure: [dbo].[usp_pm_SaveChangepartnerRequest]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_pm_SaveChangepartnerRequest]  
(  
@P_UserId int ,  
@P_PartnerId int,  
@P_RequestStatus int ,  
@P_Remarks varchar(1000),  
@P_LoginUserId int ,  
@P_RecordID int =0,  
@P_option int =0  
)  
AS  
BEGIN  
BEGIN TRY  
DECLARE @ResellerID bigint  = 0 , @RequestStatus varchar(50) ;   
SELECT  @ResellerID  =  M_ID from User_Detail(nolock) where User_ID = @P_UserId;  
IF (@P_option = 1)   
begin  
  IF (@P_PartnerId = @ResellerID ) BEGIN  
   Select  'Current partner id and change partner id can not be the same.' as Message;  
   RETURN;  
  END  
  IF NOT EXISTS(SELECT 1 FROM tbl_PM_ChangepartnerRequest(nolock) WHERE Requestforuserid = @P_UserId AND RequestStatus = 0   )  
  BEGIN  
   INSERT INTO tbl_PM_ChangepartnerRequest (Requestforuserid, CurrentUserPartnerID, RequestedPartnerUserid, RequestStatus, Remarks, createdby, createdDate)  
           VALUES (@P_UserId ,   @ResellerID,  @P_PartnerId ,  @P_RequestStatus, @P_Remarks , @P_LoginUserId , GETDATE() );  
   SELECT 'Change partner request sent.' As Message;  
  END  
  ELSE BEGIN  
   SELECT 'Already have a request for change partner for current user.' As Message;  
  END  
END  
------------------ Approve reject request ---------------------  
IF (@P_option = 2)   
BEGIN    
  UPDATE tbl_PM_ChangepartnerRequest set RequestStatus = @P_RequestStatus, Remarks = @P_Remarks , Modifiedby = @P_LoginUserId , ModifiedDate =GETDATE()  where ID = @P_RecordID;  
  -------------------------------------------------------------------------------------------------  
  SET @RequestStatus  =  CASE WHEN @P_RequestStatus = 1 THEN 'Approved' WHEN  @P_RequestStatus = 2 THEN 'Rejected' ELSE 'Cancelled' END;  
  DECLARE @NewResellerID bigint  = 0, @OldResellerID bigint=0
  --IF (@P_RequestStatus = 1)BEGIN  
  -- Declare @RequestForUserId  bigint =0 , @ReqPartnerId bigint  =0;  
  -- SELECT @RequestForUserId =  Requestforuserid , @ReqPartnerId = RequestedPartnerUserid  
  -- FROM tbl_PM_ChangepartnerRequest(NOLOCK) WHERE ID = @P_RecordID;  
  -- UPDATE reseller_detail SET M_ID = @ReqPartnerId  where USER_ID = @RequestForUserId   
  -- UPDATE User_Detail SET M_ID = @ReqPartnerId  where ParentID = @RequestForUserId   
  --END  
  IF (@P_RequestStatus = 1)BEGIN  
   Declare @RequestForUserId  bigint =0 , @ReqPartnerId bigint  =0;  
   SELECT @RequestForUserId =  Requestforuserid , @ReqPartnerId = RequestedPartnerUserid  
   FROM tbl_PM_ChangepartnerRequest(NOLOCK) WHERE ID = @P_RecordID;  
  select @OldResellerID=M_ID from User_Detail nolock where User_ID=@RequestForUserId
  select @NewResellerID=Reseller_ID from reseller_detail nolock where User_ID=@ReqPartnerId
 
  insert into tbl_partner_changetracking  (userid,old_mid,new_mid,configDate)values (@RequestForUserId,@OldResellerID,@NewResellerID,getdate())
 
   UPDATE reseller_detail SET M_ID = @ReqPartnerId  where USER_ID = @RequestForUserId   
   UPDATE User_Detail SET M_ID = @NewResellerID  where user_id = @RequestForUserId   
  END
 
  SELECT 'Request '+ @RequestStatus +' successful.' As Message;  
END  
------------ request again --add activity for this only ------------------------------------------------  
IF (@P_option = 3)   
BEGIN  
   --activity vars  
  Declare @InsertedId int =0;  
  DECLARE @Act_UserName varchar(255), @PartnerUserName varchar(255) , @ChildPartnerName varchar(255);  
  Declare @Eventdata nvarchar(max);  
  Declare @Partneruserid bigint ;
 
  ---activity vars  
  ---update tbl_PM_ChangepartnerRequest set RequestedPartnerUserid = 34324  WHERE id= 1 ;   
  ----  activity start   -----  
  SELECT @P_PartnerId  = RequestedPartnerUserid from tbl_PM_ChangepartnerRequest(nolock) WHERE id= @P_RecordID ;  
   select top 1 @Partneruserid = user_id from reseller_detail with(nolock) where Reseller_ID =  @P_PartnerId;
 
  select @Act_UserName = User_login from User_Detail(nolock) where User_ID = @P_UserId;  
  select @PartnerUserName = User_login from User_Detail(nolock) where User_ID =  @Partneruserid;
  select @ChildPartnerName = User_login from User_Detail(nolock) where User_ID = @P_LoginUserId;  
  SELECT  @Eventdata = '{"#username#":"'+ coalesce( @Act_UserName,'') +'","#partnername#":"'+ coalesce (@PartnerUserName,'') +'"}';  
  PRINT concat('Activity : ',@Eventdata);  
  ---select * from ActivityMaster  where EventName like '%partner%'   
  --#username# Requested change partner again to partner  #partnername#.  
  exec usp_pm_PartnerActivity  @P_LoginUserId, @P_LoginUserId, @Partneruserid, 'Partner Requseted Change partner request again',@Eventdata, 'tbl_PM_ChangepartnerRequest',@P_RecordID;  
  ----- activity end  ---  
  SELECT 'Request again.' As Message;  
END  
END TRY  
BEGIN CATCH  
  EXEC usp_InsertErrorInfo;  
END CATCH  
END  



GO

/* ============================================================
   Procedure: [dbo].[usp_pm_SaveChangepartnerRequest$]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
/*    
 tbl_PM_ChangepartnerRequest    
    
 usp_pm_SaveChangepartnerRequest  335, 0,0 , '' ,335, 1,3    
*/    
    
CREATE   PROCEDURE [dbo].[usp_pm_SaveChangepartnerRequest$]    
(    
 @P_UserId int ,    
 @P_PartnerId int,    
 @P_RequestStatus int ,    
 @P_Remarks varchar(1000),    
 @P_LoginUserId int ,    
 @P_RecordID int =0,    
 @P_option int =0    
)    
AS    
BEGIN    
     
 BEGIN TRY    
    
 DECLARE @ResellerID bigint  = 0 , @RequestStatus varchar(50) ;     
 SELECT  @ResellerID  =  M_ID from User_Detail(nolock) where User_ID = @P_UserId;    
    
 IF (@P_option = 1)     
 begin    
    
  IF (@P_PartnerId = @ResellerID ) BEGIN    
   Select  'Current partner id and change partner id can not be the same.' as Message;    
   RETURN;    
  END    
      
  IF NOT EXISTS(SELECT 1 FROM tbl_PM_ChangepartnerRequest(nolock) WHERE Requestforuserid = @P_UserId AND RequestStatus = 0   )    
  BEGIN    
   INSERT INTO tbl_PM_ChangepartnerRequest (Requestforuserid, CurrentUserPartnerID, RequestedPartnerUserid, RequestStatus, Remarks, createdby, createdDate)    
           VALUES (@P_UserId ,   @ResellerID,  @P_PartnerId ,  @P_RequestStatus, @P_Remarks , @P_LoginUserId , GETDATE() );    
    
   SELECT 'Change partner request sent.' As Message;    
  END    
  ELSE BEGIN    
   SELECT 'Already have a request for change partner for current user.' As Message;    
  END    
    
 END    
    
 ------------------ Approve reject request ---------------------    
 IF (@P_option = 2)     
 BEGIN      
  UPDATE tbl_PM_ChangepartnerRequest set RequestStatus = @P_RequestStatus, Remarks = @P_Remarks , Modifiedby = @P_LoginUserId , ModifiedDate =GETDATE()  where ID = @P_RecordID;    
      
  -------------------------------------------------------------------------------------------------    
  SET @RequestStatus  =  CASE WHEN @P_RequestStatus = 1 THEN 'Approved' WHEN  @P_RequestStatus = 2 THEN 'Rejected' ELSE 'Cancelled' END;    
    
  IF (@P_RequestStatus = 1)BEGIN    
    
   Declare @RequestForUserId  bigint =0 , @ReqPartnerId bigint  =0;    
   SELECT @RequestForUserId =  Requestforuserid , @ReqPartnerId = RequestedPartnerUserid    
   FROM tbl_PM_ChangepartnerRequest(NOLOCK) WHERE ID = @P_RecordID;    
    
   UPDATE reseller_detail SET M_ID = @ReqPartnerId  where USER_ID = @RequestForUserId     
   UPDATE User_Detail SET M_ID = @ReqPartnerId  where ParentID = @RequestForUserId     
  END    
    
  SELECT 'Request '+ @RequestStatus +' successful.' As Message;    
    
 END    
    
 ------------ request again --add activity for this only ------------------------------------------------    
 IF (@P_option = 3)     
 BEGIN    
      
   --activity vars    
  Declare @InsertedId int =0;    
  DECLARE @Act_UserName varchar(255), @PartnerUserName varchar(255) , @ChildPartnerName varchar(255);    
  Declare @Eventdata nvarchar(max);    
  Declare @Partneruserid bigint ;  
  
  ---activity vars    
  ---update tbl_PM_ChangepartnerRequest set RequestedPartnerUserid = 34324  WHERE id= 1 ;     
  ----  activity start   -----    
  SELECT @P_PartnerId  = RequestedPartnerUserid from tbl_PM_ChangepartnerRequest(nolock) WHERE id= @P_RecordID ;    
   select top 1 @Partneruserid = user_id from reseller_detail with(nolock) where Reseller_ID =  @P_PartnerId;  
  
  select @Act_UserName = User_login from User_Detail(nolock) where User_ID = @P_UserId;    
  select @PartnerUserName = User_login from User_Detail(nolock) where User_ID =  @Partneruserid;  
  select @ChildPartnerName = User_login from User_Detail(nolock) where User_ID = @P_LoginUserId;    
    
  SELECT  @Eventdata = '{"#username#":"'+ coalesce( @Act_UserName,'') +'","#partnername#":"'+ coalesce (@PartnerUserName,'') +'"}';    
    
  PRINT concat('Activity : ',@Eventdata);    
  ---select * from ActivityMaster  where EventName like '%partner%'     
  --#username# Requested change partner again to partner  #partnername#.    
  exec usp_pm_PartnerActivity  @P_LoginUserId, @P_LoginUserId, @Partneruserid, 'Partner Requseted Change partner request again',@Eventdata, 'tbl_PM_ChangepartnerRequest',@P_RecordID;    
  ----- activity end  ---    
    
  SELECT 'Request again.' As Message;    
    
 END    
    
 END TRY    
 BEGIN CATCH    
  EXEC usp_InsertErrorInfo;    
    
 END CATCH    
END    



GO

/* ============================================================
   Procedure: [dbo].[usp_pm_SaveImpRequest]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



/*
exec usp_pm_SaveImpRequest 34594 , 335 , 335 , '2024-12-05' , '2025-01-05' , 34594
*/

CREATE   PROC [dbo].[usp_pm_SaveImpRequest]
(
	@P_RequestedFor bigint,    --- request for  bronze partner users - who needs the impersonation .
	@P_RequestedBy bigint,	   --- requested by bronze partner who need the impersonation for their users.
	@P_requestedTo bigint=0,   --- requested to gold partner.
	@P_RequestedFromDate datetime,
	@P_RequestedToDate datetime,
	@P_remarks varchar(2000),
	@P_userid bigint
)
as
begin
	
	Declare @m_id  bigint ;
	Declare @InsertedID bigint;

	BEGIN TRY
		select @m_id = M_ID from User_Detail(nolock) where User_ID = @P_userid;

		select @P_requestedTo = User_ID from reseller_detail with(nolock) where Reseller_ID = @m_id;

		IF EXISTS(SELECT 1 FROM tbl_pm_ImpRequest(nolock) WHERE RequestedBy = @P_RequestedBy and RequestedFor =@P_RequestedFor and RequestedTo =@P_requestedTo  and RequestPeriodFrom between @P_RequestedFromDate and @P_RequestedToDate )
		begin
			SELECT 'Already exist request for this period' as Message;
			RETURN;
		end

		INSERT INTO tbl_pm_ImpRequest 
		(
			RequestedBy,
			RequestedFor,
			RequestedTo,
			RequestPeriodFrom,
			RequestPeriodTo,
			RequestStatus,
			Remarks,
			IsActive,
			CreatedBy,
			CreatedOn
		)
		select @P_RequestedBy , @P_RequestedFor , @P_requestedTo , @P_RequestedFromDate , @P_RequestedToDate , 0, @P_remarks, 1, @P_userid , GETDATE();


		SELECT @InsertedID = SCOPE_IDENTITY();

		Select 'Impersonation  request sent.' As Message;

		
-----  activity start   -----
		--activity vars
		Declare @PartnerType int  =0;  
		DECLARE @UserName varchar(255), @PartnerUserName varchar(255) , @ChildPartnerName varchar(255);
		Declare @Eventdata varchar(max);
		---activity vars
			
		select @UserName = User_login from User_Detail with(nolock) where User_ID = @P_RequestedBy;
		select @PartnerUserName = User_login from User_Detail with(nolock) where User_ID = @P_requestedTo;
		select @ChildPartnerName = User_login from User_Detail with(nolock) where User_ID = @P_RequestedFor;
		 
		SET @Eventdata = '{"#childpartnername#":"'+ @UserName +'","#username#":"'+ @ChildPartnerName +'","#impersonationrequestfromdate#":"'+ FORMAT(@P_RequestedFromDate,'dd-MM-yyyy')  +'","#impersonationrequestTodate#":"'+ FORMAT(@P_RequestedToDate,'dd-MM-yyyy')+'"}';

		---select * from ActivityMaster  where EventName like '%partner%' 
		-- #childpartnername# requested impersonation request for #username# from #impersonationrequestfromdate# to #impersonationrequestTodate#
		exec usp_pm_PartnerActivity  @P_userid, @P_userid, @P_RequestedFor, 'Partner placed impersonation request',@Eventdata,'tbl_pm_ImpRequest',@InsertedID;
	 
----- activity end  ---



	END TRY
	BEGIN CATCH
		PRINT CONCAT('Error occurred: ', ERROR_MESSAGE(), ' | Error Number: ', ERROR_NUMBER(), ' | Line: ', ERROR_LINE());
		Select 'Error ocurred.' As Message;
	END CATCH


END



GO

