"},{"ID":12,"name":"Impersonation Recevied","Tag":"Impersonation_Recevied"},{"ID":12,"name":"Impersonation Recevied","Tag":"Impersonation_Recevied"},{"ID":13,"name":"Settings","Tag":"Settings"},{"ID":14,"name":"Customizations","Tag":"Settings"},{"ID":14,"name":"Customizations","Tag":"Settings"},{"ID":13,"name":"Settings","Tag":"Settings"},{"ID":14,"name":"Customizations","Tag":"Settings"},{"ID":14,"name":"Customizations","Tag":"Settings"},{"ID":14,"name":"Customizations","Tag":"Settings"},{"ID":14,"name":"Customizations","Tag":"Settings"},{"ID":16,"name":"User Role mapping","Tag":"Teamroles"},{"ID":17,"name":"Role Master","Tag":"Teamroles"},{"ID":15,"name":"Team Roles","Tag":"Customizations"},{"ID":16,"name":"User Role mapping","Tag":"Teamroles"},{"ID":16,"name":"User Role mapping","Tag":"Teamroles"},{"ID":16,"name":"User Role mapping","Tag":"Teamroles"},{"ID":17,"name":"Role Master","Tag":"Teamroles"},{"ID":17,"name":"Role Master","Tag":"Teamroles"},{"ID":17,"name":"Role Master","Tag":"Teamroles"},{"ID":18,"name":"Reserve fund","Tag":"Settings"},{"ID":18,"name":"Reserve fund","Tag":"Settings"},{"ID":18,"name":"Reserve fund","Tag":"Settings"},{"ID":19,"name":"Kyc verify","Tag":"Settings"},{"ID":19,"name":"Kyc verify","Tag":"Settings"},{"ID":19,"name":"Kyc verify","Tag":"Settings"},{"ID":20,"name":"Banner","Tag":"Settings"},{"ID":20,"name":"Banner","Tag":"Settings"},{"ID":20,"name":"Banner","Tag":"Settings"},{"ID":21,"name":"Global","Tag":"master"},{"ID":21,"name":"Global","Tag":"master"}],"MenuAction":[{"Id":1,"ModuleId":1},{"Id":2,"ModuleId":1},{"Id":3,"ModuleId":1},{"Id":4,"ModuleId":1},{"Id":5,"ModuleId":2},{"Id":6,"ModuleId":2},{"Id":7,"ModuleId":2},{"Id":8,"ModuleId":2},{"Id":9,"ModuleId":2},{"Id":10,"ModuleId":2},{"Id":11,"ModuleId":2},{"Id":12,"ModuleId":2},{"Id":13,"ModuleId":2},{"Id":14,"ModuleId":2},{"Id":15,"ModuleId":2},{"Id":16,"ModuleId":2},{"Id":17,"ModuleId":2},{"Id":18,"ModuleId":2},{"Id":19,"ModuleId":2},{"Id":20,"ModuleId":2},{"Id":21,"ModuleId":2},{"Id":22,"ModuleId":2},{"Id":23,"ModuleId":3},{"Id":24,"ModuleId":3},{"Id":23,"ModuleId":3},{"Id":24,"ModuleId":3},{"Id":29,"ModuleId":8},{"Id":30,"ModuleId":9},{"Id":31,"ModuleId":9},{"Id":32,"ModuleId":9},{"Id":33,"ModuleId":10},{"Id":34,"ModuleId":11},{"Id":35,"ModuleId":11},{"Id":36,"ModuleId":11},{"Id":37,"ModuleId":12},{"Id":38,"ModuleId":12},{"Id":39,"ModuleId":12},{"Id":40,"ModuleId":14},{"Id":41,"ModuleId":16},{"Id":42,"ModuleId":16},{"Id":43,"ModuleId":16},{"Id":44,"ModuleId":17},{"Id":45,"ModuleId":18},{"Id":46,"ModuleId":19},{"Id":47,"ModuleId":19},{"Id":48,"ModuleId":20},{"Id":49,"ModuleId":20},{"Id":50,"ModuleId":20},{"Id":51,"ModuleId":20},{"Id":52,"ModuleId":21}]}'

--,@P_userid bigint = 32222;


	BEGIN TRY
		
		Declare @Scopeid int , @RoleId int , @ParentId bigint ;
		Declare @entityType varchar(20) , @entityid int = 0 ;
		DECLARE  @MaxRowNo int =0 , @MinRowNo int=0 ;


		select @Scopeid = JSON_VALUE(@P_metadata,'$.ScopeId') 
		select @RoleId = JSON_VALUE(@P_metadata,'$.UserRoleId');

		
		select @ParentId = dbo.ufn_GetUserParentId(@P_userid);


		print concat( 'scope id  --> ', @Scopeid,  'Role id - > ' , @RoleId);

		Declare @SelectedMenu table
		(
			Id int,
			[MenuName] varchar(100)
		)


		INSERT INTO @SelectedMenu
		select JSON_VALUE(VALUE,'$.ID') AS Id ,   JSON_VALUE (VALUE, '$.name') as name  from openjson(@P_metadata, '$.SelectedMenu');

		SELECT @MinRowNo = min(Id) , @MaxRowNo =  max(Id) from @SelectedMenu; 


		--DELETE FROM tbl_pm_RolePermissionMapping Where RoleId = @RoleId AND ScopeId = @Scopeid and IsActive = 1 AND EntityType = 'Menu' AND ParentId = @ParentId

		delete from tbl_pm_RolePermissionMapping Where RoleId = @RoleId 

		WHILE (@MinRowNo <= @MaxRowNo)
		BEGIN
			PRINT 'Adding row';
			PRINT CONCAT('Min Row: ', @MinRowNo,'max row -- ', @MaxRowNo);

			if exists(select 1 from tbl_pm_RolePermissionMapping Where RoleId = @RoleId and EntityId =  @MinRowNo  and IsActive = 1 AND EntityType = 'Menu' AND ParentId = @ParentId)
			begin
				print 'deleting menu for role';
				DELETE FROM tbl_pm_RolePermissionMapping Where RoleId = @RoleId and  IsActive = 1 AND EntityType = 'Menu' and EntityId =  @MinRowNo  AND ParentId = @ParentId
			end

			INSERT INTO tbl_pm_RolePermissionMapping 
			(RoleId, ScopeId, IsActive, EntityType, EntityId, ParentId, CreatedBy, CreatedDate) 
			VALUES 
			(@RoleId, @Scopeid, 1, 'Menu', @MinRowNo, @ParentId, @P_userid, GETDATE());

			

			IF (@MinRowNo = @MaxRowNo) 
			BEGIN
				BREAK;  -- Exit the loop if MinRowNo has reached MaxRowNo
			END
			ELSE 
			BEGIN
				-- Fetch the next minimum Id greater than the current MinRowNo
				SELECT TOP 1 @MinRowNo = Id  
				FROM @SelectedMenu 
				WHERE Id > @MinRowNo 
				ORDER BY Id ASC;

				-- If no more rows exist, exit the loop
				IF @MinRowNo IS NULL
					BREAK;
			END
		END


		DELETE FROM @SelectedMenu;
		
		INSERT INTO @SelectedMenu
		SELECT JSON_VALUE(VALUE,'$.Id') AS id ,   JSON_VALUE (VALUE, '$.ModuleId') as Moduleid  from openjson(@P_metadata, '$.MenuAction');

		SELECT @MinRowNo = min(Id) , @MaxRowNo =  max(Id) from @SelectedMenu; 

		Declare @ModuleId int = 0 , @LastModuleid int =0;


		WHILE (@MinRowNo <= @MaxRowNo)
		BEGIN
			PRINT 'Adding row';
			PRINT CONCAT('Min Row: ', @MinRowNo,'max row -- ', @MaxRowNo);

			select @ModuleId =  ModuleId from tbl_pm_ModuleAction b where id = @MinRowNo;

			print concat('moduleid -- ',@ModuleId);

			if ( @ModuleId <> @LastModuleid) begin

				print 'deleting';
				delete from tbl_pm_RolePermissionMapping where EntityId in ( select id from  tbl_pm_ModuleAction where ModuleId = @ModuleId) 
				and EntityType='Action' AND RoleId = @RoleId and IsActive = 1  AND ParentId = @ParentId
			end

			INSERT INTO tbl_pm_RolePermissionMapping 
			(RoleId, ScopeId, IsActive, EntityType, EntityId, ParentId, CreatedBy, CreatedDate) 
			VALUES 
			(@RoleId, @Scopeid, 1, 'Action', @MinRowNo, @ParentId, @P_userid, GETDATE());


			 set @LastModuleid =  @ModuleId;

			IF (@MinRowNo = @MaxRowNo) 
			BEGIN
				BREAK;  -- Exit the loop if MinRowNo has reached MaxRowNo
			END
			ELSE 
			BEGIN
				-- Fetch the next minimum Id greater than the current MinRowNo
				SELECT TOP 1 @MinRowNo = Id  
				FROM @SelectedMenu 
				WHERE Id > @MinRowNo 
				ORDER BY Id ASC;

				-- If no more rows exist, exit the loop
				IF @MinRowNo IS NULL
					BREAK;
			END
		END

		--select * from @SelectedMenu;
		select 'Save success' as Message;

	END TRY
	BEGIN CATCH
		select 'Error ocurred -> '+ ERROR_MESSAGE()  as Message;
		---select 'metadata -> '+ @P_metadata  as Message;
		
		exec usp_inserterrorinfo;
	END CATCH

END




