/* ============================================================
   Procedure: [dbo].[usp_pm_updateNotificationStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROC usp_pm_updateNotificationStatus  
(  
 @P_Userid bigint,  
 @P_NotificationId varchar(max),  
 @P_option int = 1  
)  
as  
begin  
  
  
 Declare @Partneruserid bigint;  
 select @Partneruserid = [dbo].[ufn_GetUserParentId](@P_Userid);  
   
 if (@P_option  = 1 )    
  begin    
   update tbl_PartnerEventHistory set IsRead =1 where convert( varchar, Historyid) in (@P_NotificationId) and (PartnerUserID = @partneruserid or PartnerParentID  = @partneruserid or   
   UserID  = @partneruserid  );    
   Select 'Notification set as Read' as Message;    
  end    
  else if (@P_option  = 2 ) begin    
   delete tbl_PartnerEventHistory where convert( varchar, Historyid) in( @P_NotificationId);    
   Select 'Notification deleted.' as Message;    
  end    
  else if (@P_option  = 3 ) begin    
   update tbl_PartnerEventHistory set IsRead =1 where  (PartnerUserID = @partneruserid or PartnerParentID  = @partneruserid  or UserID  = @partneruserid );    
   Select 'Marked notification read' as Message;    
  end    
    
end    
    


GO

/* ============================================================
   Procedure: [dbo].[usp_pm_UserForImporsonateSuggestions]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_pm_UserForImporsonateSuggestions](  
 @UserId bigint,  
 @FilterText nvarchar(255)  
)  
as  
begin  
   
	--declare   
	--	@UserId bigint = 62600,  
	--	@FilterText nvarchar(255) = ''  
  
	declare   
		@Mid bigint = 0,  
		@UserType int  = 0,  
		@PartnerType int = 0  
  
	 select @Mid = rd.Reseller_ID, @UserType = ud.Type, @PartnerType = rd.Partner_Type from User_Detail(nolock) ud  
	  left join reseller_detail(nolock) rd on ud.User_Id = rd.User_Id  
	  left join tbl_pm_PartnerTypeMaster(nolock) pt on rd.Partner_Type = pt.Id  
	 where ud.User_Id = @UserId  

  
	print concat ('@Mid => ', @Mid)  
	print concat ('@UserType => ', @UserType)  
	print concat ('@PartnerType => ', @PartnerType)  
  
	select ud.ID, ud.User_ID, ud.M_ID, 
		concat(ud.User_Login, ' (', ud.FName, ' ', ud.LName, ')') as [User_Login], 
		ud.UserType, rd.Partner_Type, pt.TypeName,  
		@Mid as [ImpersonatorMid], @UserId as [ImpersonatorUserId]  
	from User_Detail(nolock) ud  
		left join reseller_detail(nolock) rd on ud.User_Id = rd.User_Id  
		left join tbl_pm_PartnerTypeMaster(nolock) pt on rd.Partner_Type = pt.Id  
	where ud.M_ID = @Mid and isnull(isverify, 0) = 1 and 1 = ( case   
		when @UserType = 3 then 1  
		when @UserType = 4 and @PartnerType = 1 and exists (select 1 from tbl_pm_ImpRequest(nolock)   
		where RequestedTo = @UserId and RequestedFor = ud.User_ID 
			and RequestStatus = 1 and getdate() between RequestPeriodFrom and RequestPeriodTo) then 1  
		else 0 end  
	) and ud.User_Login like concat('%', @FilterText, '%')  
	order by ud.User_Login asc  
end



GO

/* ============================================================
   Procedure: [dbo].[usp_pm_UserRoleMapping]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_pm_UserRoleMapping]
(
	@P_RecId int,
	@P_Userid bigint = 0,
	@P_metadata varchar(max)='',
	@P_option int=0
)
AS
BEGIN


		Declare @Parentid bigint = 0 , @InsertedId bigint;
		SELECT @Parentid = dbo.ufn_GetUserParentId(@P_Userid);

		if (@P_option  =1)  begin

			;with RoleCTE as 
			(
				SELECT ROW_NUMBER() OVER (ORDER BY tu.RoleId) as RowNumber ,tu.Id as RecId , coalesce( tu.RoleId,0) as RoleId , coalesce (tr.RoleName,'') as RoleName , Ud.User_ID  , ud.User_Login,
		 		coalesce(	tu.DefaultmasterPage,'')as DefaultmasterPage , tu.ReportTo from User_Detail ud(nolock) 
				left join  tbl_pm_UserRoleMapping  tu(nolock) on ud.User_ID = tu.UserId
				left join tbl_pm_UserRoles tr(nolock) on tr.Id = tu.RoleId
				WHERE tu.Parentid = @Parentid and tu.Id =@P_RecId
			)
			
			select (select count(1) from RoleCTE) as TotalRow , * from  RoleCTE   order by User_Login  ;

		END

		if (@P_option =2) begin
			delete FROM  tbl_pm_UserRoleMapping WHERE Id = @P_RecId and Parentid = @Parentid
			Select 'Delete successful.' As Message;
		end



END




GO

/* ============================================================
   Procedure: [dbo].[usp_pm_VerifyEmail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROC usp_pm_VerifyEmail  
(  
 @P_userid bigint,  
 @P_ToMailid varchar(510),  
 @P_EventName varchar(120),  
 @P_verificationLink varchar(max),  
 @P_Subject varchar(250)  
)  
AS  
BEGIN  
   
 BEGIN TRY  
    
  Declare @messagebody varchar(max), @partneremail varchar(1200) , @UserEmail varchar(510), @PartnerUserid bigint , @Resellerid bigint, @batchid  bigint ;  
  
  exec usp_pm_getMessageHtmlText @P_EventName, @P_userid, @messagebody out  
  
  SET @messagebody= replace(@messagebody , '#encryptedphrase#',@P_verificationLink)  
  
  SELECT @Resellerid  = M_ID , @UserEmail = EMail FROM User_Detail(nolock)  WHERE User_ID = @P_userid  
  
  -- partner data   
    SELECT  @PartnerUserid= User_ID from reseller_detail(nolock) where Reseller_ID = @Resellerid  
  
   declare @partner_jsondata nvarchar(max);  
   select top 1 @partner_jsondata= jsonEmaildata from tbl_pt_CustomizationMetadata(nolock) where userid = @PartnerUserid;  
   SELECT @partneremail = COALESCE(JSON_VALUE(@partner_jsondata, '$.Email'), 'noreply@email19.in');  
  
  PRINT concat('partner email = ' , @partneremail, ', receipient email =' , @UserEmail, ', partner user id = ',@PartnerUserid );  
  
  BEGIN TRY  
   exec [usp_SendMails] @P_ToMailid, ---  receipient mail ,  
    @PartnerUserid , ---  reseler id   
    @P_Subject ,-- subject ,  
    0,  
    @messagebody,  --- message content   
    @partneremail,  --- partener email   
    @partneremail , --- partener email   
    'T',  
    1, --priority   
    'Verify email',  ---  mail source  
    @batchid output    --- output variable   
  
    print concat('batchid = ' , @batchid);  
  
  END TRY  
  BEGIN CATCH  
   exec usp_InsertErrorInfo     
  END CATCH  
  
 END TRY  
 BEGIN CATCH  
  exec usp_InsertErrorInfo  
  
 END CATCH  
END  
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_PredefUser_getcustomFields]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_PredefUser_getcustomFields]    
    
    @userId bigint        
    
as     
begin    
declare @parentid int = (Select ParentID from User_Detail where User_ID= @userId)    
-- declare @parentid int = 34594    
 select COLUMN_NAME as ID ,COLUMN_NAME,DATA_TYPE from INFORMATION_SCHEMA.COLUMNS where TABLE_NAME='UserEnquiry' and TABLE_CATALOG='mysms' and COLUMN_NAME not in     
 ('EnquiryID', 'ParentID', 'CreatedDate', 'CreatedBy', 'IsOpen', 'LeadNo', 'img_ext', 'ProfileImgFileName',    
 'enquirysource',  'WhatsAppNoColName', 'whereAddress', 'latitude', 'longitude','SourceName','MediumName','CampaignName' )      
union all    
SELECT cast (field_ID as varchar),fieldname,      
  (case       
   when datatype = 'd' then 'Date Time'      
   when datatype = 'f' then 'Numeric'      
   when datatype = 'v' then 'Text'       
   when datatype = 'r' then 'RadioBox'      
   when datatype = 'l' then 'List'      
   when datatype = 'c' then 'CheckBox'      
   when datatype = 'm' then 'Multiline'      
   when datatype = 's' then 'Select'      
  end ) as datatype    
 FROM customfields (NOLOCK)      
 WHERE ParentID=@parentid  and isActive=1   and datatype!='e'    
    
 end    


