/* ============================================================
   Procedure: [dbo].[Usp_PremiumMessage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--    update user_detail set filterMode=2  
--select dbo.RETURNPERCENTAGE(300,55,284)  
     -- [dbo].[Usp_PremiumMessage]    13043        
CREATE   PROC [dbo].[Usp_PremiumMessage]   -- 13095        
@BATCHID         
bigint         
as        
BEGIN        
BEGIN        
TRY         
Declare @TEMPADCOUNT bigint         
Declare @COUNTPERCENTAGE bigint        
Declare @PremiumCount bigint        
Declare @DNDNO bigint        
Declare @FilterMode int        
Declare @User_ID bigint        
Declare @NotDND bigint        
Declare @IsPriority int
Declare @Dbtype int
Declare @Temptable table         
(        
MessageSourceID  bigint,         
MessageID bigint,         
Mobile nvarchar(20),         
[Message] nvarchar(2000),         
SENDerID nvarchar(100),         
SmppID tinyint,         
Priority tinyint,         
U_ID bigint,         
IsUniCode bit,         
IsDND bit,         
Operator varchar(6),         
MessageBatchID nchar(20),         
Isallowdnd tinyint)         
/****************************************/        
SELECT top(1) @DNDNO=isnull(operator,0), @TEMPADCOUNT=TotalRecords,@User_ID=userid,@IsPriority=isprority,@Dbtype=DbType FROM batchinfo with(nolock) WHERE batchid=@BATCHID        
select top(1) @PremiumCount=count(isnull(messageid,0)) from PremiumMessage  with(nolock)  where batchid=@BATCHID and priority=0        
select top(1) @FilterMode=isnull(filterMode,1) from user_detail  with(nolock)  where user_id=@User_ID        
--set @NotDND=(@TEMPADCOUNT-@DNDNO) 

if @Dbtype=1
Begin
set @FilterMode=1
END 

 select  @TEMPADCOUNT,@PremiumCount,@FilterMode,@DNDNO,@NotDND        
if isnull(@TEMPADCOUNT,0)>138 and @IsPriority=0
Begin      
		Begin     
		IF @FilterMode=1       
		--BEGIN    
		--if @PremiumCount<(dbo.RETURNPERCENTAGE(@TEMPADCOUNT,20,@DNDNO))         
		-- Begin    
		-- SET @COUNTPERCENTAGE=((dbo.RETURNPERCENTAGE(@TEMPADCOUNT,20,@DNDNO))-@PremiumCount)        
		-- END         
		--END        
		BEGIN         
		SET @COUNTPERCENTAGE=0    
		END         
		else IF @FilterMode=2         
		BEGIN    
		      
		if @PremiumCount<(dbo.RETURNPERCENTAGE(@TEMPADCOUNT,65,@DNDNO))         
		 Begin    
		 SET @COUNTPERCENTAGE=((dbo.RETURNPERCENTAGE(@TEMPADCOUNT,65,@DNDNO))-@PremiumCount)        
		 END         
		END         
		Else IF @FilterMode=3        
		BEGIN         
		if @PremiumCount<(dbo.RETURNPERCENTAGE(@TEMPADCOUNT,75,@DNDNO))         
		Begin         
		SET @COUNTPERCENTAGE=((dbo.RETURNPERCENTAGE(@TEMPADCOUNT,75,@DNDNO))-@PremiumCount)        
		END         
		END         
		else IF @FilterMode=4        
		BEGIN         
		if @PremiumCount<(dbo.RETURNPERCENTAGE(@TEMPADCOUNT,85,@DNDNO))         
		Begin         
		SET @COUNTPERCENTAGE=((dbo.RETURNPERCENTAGE(@TEMPADCOUNT,85,@DNDNO))-@PremiumCount)        
		END         
		END         
			  select  @COUNTPERCENTAGE  
		if(@COUNTPERCENTAGE>1)         
		Begin         
		INSERT INTO @Temptable(MessageSourceID,MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,				IsUniCode,IsDND,Operator,MESSAGEBATCHID,Isallowdnd)         
		select top(@COUNTPERCENTAGE) MessageSourceID,MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,			IsUniCode,IsDND, Operator, MESSAGEBATCHID,Isallowdnd from MESSAGESOURCE  with(nolock)  WHERE					MESSAGEBATCHID=@BATCHID and messageid like '%[0,1,2,3,5,6,7,8,9]'        
		        
		INSERT INTO PremiumMessage(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,         
		IsDND, Operator, BatchID,Isallowdnd)         
		SELECT MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,         
		IsDND, Operator, MessageBatchID,Isallowdnd FROM @Temptable         
		        
		DELETE MESSAGESOURCE FROM MESSAGESOURCE JOIN @Temptable tmp ON MESSAGESOURCE.MessageID=tmp.MessageID    		        
		delete @Temptable         
		End       
END  
End         
END        
TRY         
BEGIN        
CATCH         
EXEC        
usp_InsertErrorInfo         
END        
CATCH         
END


GO

