/* ============================================================
   Procedure: [dbo].[usp_process_call_event]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_process_call_event]  
@callid NVARCHAR(255),
@eventname NVARCHAR(100),
@direction NVARCHAR(20),
@telephony_provider NVARCHAR(50),
@event_time NVARCHAR(50),
@fulljson NVARCHAR(MAX)
as
begin
/* to debug
declare @callid NVARCHAR(255),
@eventname NVARCHAR(100),
@direction NVARCHAR(20),
@telephony_provider NVARCHAR(50),
@event_time NVARCHAR(50),
@fulljson NVARCHAR(MAX)
select @callid=callid,@eventname=eventname,@direction=direction,@fulljson=fulljson,@event_time=event_time   from tbl_vb_callevents(nolock)  where id=11
*/
begin try
declare @twilio_id bigint,@call_eventid bigint,@real_callsid nvarchar(255)
if not exists (select 1 from tbl_vb_callevents(nolock) where callid=@callid and eventname=@eventname)
begin
insert into tbl_vb_callevents(callid,eventname,direction,telephony_provider,event_time,fulljson)
select @callid,@eventname,@direction,@telephony_provider ,@event_time ,@fulljson 

select @call_eventid=SCOPE_IDENTITY()
begin try
select @real_callsid =JSON_VALUE(@fulljson,'$.call_id')
end try
begin catch
exec usp_InsertErrorInfo
end catch
select top 1 @twilio_id=id from TwilioCalls(nolock) where callsid in (@callid ,isnull(@real_callsid,'')) order by id desc
if @twilio_id is not null and @eventname='disposition_status_updated'
begin
declare @call_start_time datetime,@call_end_time datetime,@call_answer_time datetime,@bill_duration int,@total_duration int,@recording_url nvarchar(1000),@call_status varchar(50),@call_connected varchar(2),@hangup_cause_key nvarchar(100)
SELECT 
    @call_start_time = start_stamp,
    @call_end_time = end_stamp,
    @call_answer_time = CASE WHEN answer_stamp = '' THEN NULL ELSE answer_stamp END,
    @bill_duration = billsec,
    @total_duration = duration,
    @recording_url = recording_url,
    @call_status = call_status,
    @call_connected = isnull(nullif(call_connected,''),0),
    @hangup_cause_key = hangup_cause_key
FROM OPENJSON(@fulljson)
WITH (
    start_stamp      DATETIME       '$.start_stamp',
    end_stamp        DATETIME       '$.end_stamp',
    answer_stamp     VARCHAR(50)    '$.answer_stamp',
    billsec          INT            '$.billsec',
    duration         INT            '$.duration',
    recording_url    NVARCHAR(1000) '$.recording_url',
    call_status      VARCHAR(50)    '$.call_status',
    call_connected   VARCHAR(10)    '$.call_connected',
    hangup_cause_key NVARCHAR(100)  '$.hangup_cause_key'
);

--SELECT 
--    @call_start_time,
--    @call_end_time,
--    @call_answer_time,
--    @bill_duration,
--    @total_duration,
--    @recording_url,
--    @call_status,
--    @call_connected,
--    @hangup_cause_key

update twiliocalls set call_end_time=@call_end_time,bill_duration=@bill_duration,call_answer_time=@call_answer_time,call_connected=case when @call_connected='1' then 1 else 0 end,
CallDuration=@total_duration,hangup_cause=@hangup_cause_key,customer_disposition=case when @direction in ('clicktocall','outbound') then @call_status else customer_disposition end,agent_disposition=case when @direction='inbound' then @call_status else agent_disposition end,recordurl=nullif(@recording_url,'') where id=@twilio_id
exec usp_updatecalllog_withreftable 'twiliocalls',@twilio_id
exec usp_vb_botcallend_twilio_deduction @real_callsid
update tbl_vb_callevents set isprocessed=1,processedon=GETDATE(),twiliocallid=@twilio_id 
where id=@call_eventid

end
else if @telephony_provider<>'twilio'
begin
update tbl_vb_callevents set isprocessed=1,processedon=GETDATE(),last_error='Record not found' where id=@call_eventid

end
end
end try
begin catch
exec usp_InsertErrorInfo
end catch
end



