/* ============================================================
   Procedure: [dbo].[usp_process_messagemonitor_tbp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_process_messagemonitor_tbp]
as
begin
declare @batchid bigint,@filtermode char(5),@account nvarchar(20),@count int,@id bigint=0,@error nvarchar(max)

PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] ✅ procedure started');
select * into  #messagemonitor_tbp from messagemonitor_tbp(nolock) where 
(isprocessed=0 or (isprocessed=2 and processstart<dateadd(mi,-10,getdate()))) and createdon>dateadd(HH,-6,getdate()) and attempts<5
select @count=count(1) from #messagemonitor_tbp
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] ✅ batches to be processed: ',@count);

while @count>0
begin
select @id=min(id) from #messagemonitor_tbp where id>@id
select @batchid=batchid, @filtermode=filtermode,@account=ACCOUNT from #messagemonitor_tbp(nolock) where id=@id
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] ✅ Now processing batch: ',@batchid);

update m set isprocessed=2,processstart=getdate() from messagemonitor_tbp m where id=@id
begin try
exec [USP_MOVEFROMMONITORTOSOURCETABLE_TEST_async] @batchid,@filtermode,@account,@error output

update messagemonitor_tbp set attempts=attempts+1,processend=getdate(),isprocessed=
case when isnull(@error,'')='' then 1 else isprocessed end,error_description=@error where id=@id
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] ✅ Batchid processed: ',@batchid);

end try
begin catch
exec usp_InsertErrorInfo
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] ✅ Batch : ',@batchid,' encountered error: ',error_message() );
update messagemonitor_tbp set attempts=attempts+1,error_description=error_message(),processend=getdate() where id=@id
end catch
set @count=@count-1
end

end


GO

