/* ============================================================
   Procedure: [dbo].[usp_ProcessAndInsertWebformHooks]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ProcessAndInsertWebformHooks]
    @EntryId BIGINT,
    @FormId  BIGINT,
    @ReplacementsJson NVARCHAR(MAX)
AS
BEGIN
    --declare 
    --    @EntryId BIGINT,
    --    @FormId  BIGINT=117,
    --    @ReplacementsJson NVARCHAR(MAX)=N'{"question32_country": "+91",
    --            "Mobile Number": "8922901010",
    --            "OD Premium": 3,
    --            "Net Premium": 3,
    --            "Final Premium": 3
    --        }'
 
    SET NOCOUNT ON;
    IF OBJECT_ID('tempdb..#HooksTmp') IS NOT NULL DROP TABLE #HooksTmp;
    CREATE TABLE #HooksTmp (
      srNo BIGINT NULL,
      Hookdesc NVARCHAR(MAX) NULL,
      baseapi NVARCHAR(MAX) NULL,
      method NVARCHAR(50) NULL
    );
    INSERT INTO #HooksTmp
    EXEC USP_getwebformApi_Tbl_fordynamicform @FormId, 2;
    DECLARE @Repl as RecursiveReplace;
 
    IF ISJSON(@ReplacementsJson) = 1
    BEGIN
        INSERT INTO @Repl(displaykey,[value])
        SELECT [key],[value] FROM OPENJSON(@ReplacementsJson);
    END
    ELSE
    BEGIN
        INSERT INTO @Repl(displaykey,[value])
        SELECT ISNULL(JSON_VALUE([value],'$.displaykey'),''), ISNULL(JSON_VALUE([value],'$.value'),'')
        FROM OPENJSON(ISNULL(@ReplacementsJson, N'[]')) WITH ([value] NVARCHAR(MAX) '$')
        WHERE ISJSON([value]) = 1;
    END
    --select * from @Repl
    declare @hookapi nvarchar(max)=(select top 1 Hookdesc from #HooksTmp)
    --update @Repl set displaykey=concat('#', trim(displaykey), '#');
    
    declare @placeholder as table (Placeholder NVARCHAR(200))

    insert into @placeholder(Placeholder)
    select TRIM('#' FROM Placeholder) from dbo.fnExtractPlaceholders(@hookapi)

    declare @newReplc as recursivereplace

    insert into @newReplc (displaykey, value)
    select p.Placeholder, ISNULL( r.value, '') from @placeholder p
        left join @Repl r on p.Placeholder = r.displaykey

    select @hookapi=dbo.fn_recursivereplace(@newReplc,@hookapi);

    update #HooksTmp set Hookdesc  = @hookapi

    DECLARE @Processed dbo.tbl_webapiType;
   
    INSERT INTO @Processed(apiid, webapi, baseapi, method)
    select srNo, Hookdesc, baseapi, method  from #HooksTmp

    EXEC USP_Insert_webFormap_respTbl_ForDynamic @EntryId, @FormId, 1, @Processed;
END


