/* ============================================================
   Procedure: [dbo].[usp_processbatch]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
    
CREATE   PROCEDURE [dbo].[usp_processbatch] @modid int  ,@ProcessedCount int=0 output   
as      
begin      
--declare @tableid int=1      
declare @BATCHID bigint=0,@TABLENAMECLONE nvarchar(100),@QUERY nvarchar(max),@totalrecords int,@count int,@processstatus int=0,@drop_tbl_query nvarchar(1000),@count_b int  ,@batchprocessed int=0    
select * into #batchinfo from batchinfo(nolock) WHERE  --PROCESSTABLE = @modid AND 
SCHEDULEDDATE <= getdate()  
AND ( ISPROCESS = 0 OR ISPROCESS IS NULL )     
--and userid=33819  
select @count_b=count(1),@ProcessedCount=0 from #batchinfo  
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] Found count batches  : ',@count_b);

while @count_b>0  
begin  
SELECT TOP 1 @BATCHID = BATCHID,@TABLENAMECLONE=TABLENAME,@totalrecords=TotalRecords FROM #BATCHINFO  WITH(NOLOCK)   
WHERE  
--PROCESSTABLE = @modid   AND SCHEDULEDDATE <= getdate()  AND ( ISPROCESS = 0 OR ISPROCESS IS NULL ) and 
batchid>@batchid    
--and userid=33819  --and batchid=154045511    
ORDER BY BATCHINFOID
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] Batch picked  : ',@batchid);

SET @QUERY='SELECT @COUNT=COUNT(BATCHID) FROM  '+@TABLENAMECLONE+' WHERE BATCHID='+CONVERT(NVARCHAR,@BATCHID)+''      
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] @QUERY prepared  : ',@QUERY);

EXEC SP_EXECUTESQL @QUERY,N'@COUNT BIGINT OUTPUT', @COUNT OUTPUT;          
select @processstatus =status from ProcessMsgLimit(nolock)      
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] Total count in batchid  : ',@count, ', Total record in batchinfo: ',@totalrecords);

IF 1=1-- (@COUNT = @totalrecords)                                                                                                        
BEGIN          
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] Now processing batchid  : ',@BATCHID);

UPDATE  BATCHINFO  SET ISPROCESS = 1  WHERE BATCHID = @BATCHID      
select @batchprocessed=@@ROWCOUNT;
if @batchprocessed>0
begin
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] Batchid updated : ',@batchid);
set @batchprocessed=0
end
else
begin
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] Batchid NOT updated : ',@batchid);

end
drop table if exists #output      
create table #output(messageid bigint)      
declare @deliveryquery nvarchar(max)  ,@clientdeliveryquery nvarchar(max)

select @clientdeliveryquery=      
concat('
if exists (select top 1 * from ', @TABLENAMECLONE,' t join clientmobile c on c.mobile=t.mobile)
begin

begin tran      
insert into messagedeliverystatus(messageid,batchid,mobile,MESSAGE,senderid,messageinsertdate,smppid,u_id,isunicode,isdnd,operator,messagestatus,isallowdnd,Priority)       
output inserted.messageid into #output       
SELECT convert(varchar,batchid)+''''+convert(varchar,messageid), batchid,t.mobile,[message],senderid,messageinsertdate,smppid,u_id,isunicode,isdnd,'''',messagestatus, isallowdnd, IsPrority      
 FROM ',@TABLENAMECLONE,' t join clientmobile c on c.mobile=t.mobile
 where batchid= ',@batchid,';  
insert into messagesource(messageid,MessageBatchID, mobile, MESSAGE, senderid, messageinsertdate, smppid, u_id, isunicode, isdnd, operator ,Priority)      
SELECT convert(varchar,t.batchid)+''''+convert(varchar,t.messageid),batchid, t.mobile, [message], senderid, messageinsertdate, smppid, u_id, isunicode, isdnd, 
'''',IsPrority FROM   ',@TABLENAMECLONE,' t       
join #output o on o.messageid=convert(varchar,t.batchid)+''''+convert(varchar,t.messageid);   
delete m from ',@TABLENAMECLONE,' m 
join #output o on o.messageid=convert(varchar,m.batchid)+''''+convert(varchar,m.messageid);      
commit
if @@Trancount>0
rollback;

end')      

PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] @clientdeliveryquery prepared : ',@clientdeliveryquery);

exec sp_executesql @clientdeliveryquery
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] @clientdeliveryquery executed : ',@clientdeliveryquery);

SET @QUERY='SELECT @COUNT=COUNT(BATCHID) FROM  '+@TABLENAMECLONE+' WHERE BATCHID='+CONVERT(NVARCHAR,@BATCHID)+''      
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] @QUERY prepared  : ',@QUERY);

EXEC SP_EXECUTESQL @QUERY,N'@COUNT BIGINT OUTPUT', @COUNT OUTPUT;          



while @count>0      
begin      
select @deliveryquery=      
concat('      
begin tran      
insert into messagedeliverystatus(messageid,batchid,mobile,MESSAGE,senderid,messageinsertdate,smppid,u_id,isunicode,isdnd,operator,messagestatus,isallowdnd,Priority)       
output inserted.messageid into #output       
SELECT top 1000 convert(varchar,batchid)+''''+convert(varchar,messageid), batchid,mobile,[message],senderid,messageinsertdate,smppid,u_id,isunicode,isdnd,'''',messagestatus, isallowdnd, IsPrority      
 FROM ',@TABLENAMECLONE,' where batchid= ',@batchid,';  
if ',@totalrecords,' >300 and ',@processstatus,' =1      
begin      
insert into messagemonitor(messageid,batchid,mobile, MESSAGE, senderid, messageinsertdate, smppid, u_id, isunicode, isdnd, operator ,Priority)      
SELECT convert(varchar,t.batchid)+''''+convert(varchar,t.messageid),batchid, mobile, [message], senderid, messageinsertdate, smppid, u_id, isunicode, isdnd, '''',IsPrority FROM   ',@TABLENAMECLONE,' t       
join #output o on o.messageid=convert(varchar,t.batchid)+''''+convert(varchar,t.messageid);                               
end      
else      
begin      
insert into messagesource(messageid,MessageBatchID, mobile, MESSAGE, senderid, messageinsertdate, smppid, u_id, isunicode, isdnd, operator ,Priority)      
SELECT convert(varchar,t.batchid)+''''+convert(varchar,t.messageid),batchid, mobile, [message], senderid, messageinsertdate, smppid, u_id, isunicode, isdnd, '''',IsPrority FROM   ',@TABLENAMECLONE,' t       
join #output o on o.messageid=convert(varchar,t.batchid)+''''+convert(varchar,t.messageid);                               
  end      
delete m from ',@TABLENAMECLONE,' m join #output o on o.messageid=convert(varchar,m.batchid)+''''+convert(varchar,m.messageid);      
truncate table #output      
commit      
if @@trancount>0      
rollback      
')      
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] @deliveryquery prepared : ',@deliveryquery);

exec sp_executesql @deliveryquery
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] @deliveryquery executed : ',@deliveryquery);
set @count=@count-1000      
end    
delete from #batchinfo where batchid=@batchid  
  
select @drop_tbl_query=    
'
if (select count(1) from messagedeliverystatus(nolock) where batchid= '+cast(@batchid as nvarchar)+' )= '+cast(@totalrecords as nvarchar)+'    
begin    
if '''+@TABLENAMECLONE+ ''' not like ''%clone%''
begin
drop table if exists '+@TABLENAMECLONE+'; 
end
else 
delete from '+@TABLENAMECLONE+' where batchid= '+cast(@batchid as nvarchar)+'; 
end'   

PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] @drop_tbl_query prepared : ',@drop_tbl_query);

exec sp_executesql @drop_tbl_query 
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] @drop_tbl_query executed : ',@drop_tbl_query);

end    
select @ProcessedCount=@ProcessedCount+1,@count_b=@count_b-1  
PRINT CONCAT('[', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss.fff'), '] processed batches : ',@ProcessedCount, ', Batches remaining: ',@count_b);

end  
      
end 


GO

/* ============================================================
   Procedure: [dbo].[usp_processcalculatedfields]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--select * from calculated_fields_process(nolock) where isprocessed=1 order by 1 desc
--update calculated_fields_process set isprocessed=0,error_desc=null where id=1093899
--select balance from mysmsinvoicing.dbo.tbl_inv_CreditNoteLedger with (nolock) where entityname=@entity and entityid=@entityid and id=@refid

--select * from calculated_fields_master
--update calculated_fields_master set calculation_expression='select balance from mysmsinvoicing.dbo.tbl_inv_CreditNoteLedger with (nolock) where entityname=''@entity'' and entityid=@entityid and id=''@refid'''

CREATE   PROCEDURE usp_processcalculatedfields
as
begin
drop table if exists #tbp
select top 20 * into #tbp from calculated_fields_process c(nolock) where isprocessed=0 and createdon>dateadd(d,-1,getdate()) and exists
(select 1 from calculated_fields_master(nolock) where impacting_event=c.icf_eventid)

--for debugging
--select * from #tbp

update c set c.isprocessed=2,processedon=getdate() from calculated_fields_process c join #tbp t on t.id=c.id
declare @id bigint=0
declare @count int=(select count(1) from #tbp),@cc int,@ccid int=0
declare @eventid int,@activityid bigint,@fieldvalue nvarchar(1000)
declare @calculationtype nvarchar(100),@sql nvarchar(max),@refid nvarchar(20),@entity nvarchar(20),@entityid bigint,@fieldid int,@parentid bigint
declare @updatedFieldValue sql_variant 
while @count>0
begin
begin try
print concat('count: ',@count)
select @id=min(id) from #tbp where id>@id
select @eventid=icf_eventid,@activityid=activityid,@sql='',@cc=0,@parentid=parentid from #tbp where id=@id
select @entity=context from ActivityMaster(nolock) where id=@eventid
if @entity='lead'
begin
select @entityid=leadid,@refid=refids from tbl_leadeventhistory(nolock) where historyid=@activityid
end
if @entity='enquiry'
begin
select @entityid=enquiryid,@refid=refids from tbl_enquiryeventhistory(nolock) where historyid=@activityid
end
select @cc=count(1) from calculated_fields_master(nolock) where impacting_event=@eventid
while @cc>0
begin
select @ccid=min(id),@sql='' from calculated_fields_master(nolock) c where impacting_event=@eventid and id>@ccid
select @calculationtype=calculation_type,@fieldid=id,@sql='select @updatedFieldValue= ('+ replace(replace(replace(calculation_expression,'@refid',@refid),'@entityid',@entityid),'@entity',@entity)+')' from calculated_fields_master(nolock) where id=@ccid
print concat('cc: ',@cc,', entity:',@entity,', entityid:',@entityid,', eventid: ',@eventid,', calculation_type:',@calculationtype,', sql:',@sql)



--sample calculation_expression: select balance from mysmsinvoicing.dbo.tbl_inv_CreditNoteLedger with (nolock) where entityname=@entity and entityid=@entityid and id=@refid
exec sp_executesql @sql, N'@updatedFieldValue sql_variant OUTPUT', @updatedFieldValue OUTPUT


PRINT CONCAT('Updated Field Value: ', CONVERT(NVARCHAR(1000), @updatedFieldValue));

-- Assign the updated field value to the @fieldvalue variable
SELECT @fieldvalue = CONVERT(NVARCHAR(1000), @updatedFieldValue);

--for debugging
--print concat('Updated Field Value: ' , cast(@updatedFieldValue as nvarchar(1000)))
--select @fieldvalue=cast(@updatedFieldValue as nvarchar(1000))
--select 'fieldvalue',@fieldvalue


if not exists (select 1 from calculated_fields(nolock) where entityid=@entityid and entity=@entity and parentid=@parentid and calculatedfield_id=@fieldid)
begin
insert into calculated_fields(entity,entityid,calculatedfield_id,field_value,last_updated,parentid)
select @entity,@entityid,@fieldid,@fieldvalue,getdate(),@parentid
end
else
begin
update calculated_fields set field_value=@fieldvalue  where entityid=@entityid and entity=@entity and parentid=@parentid and calculatedfield_id=@fieldid
end

set @cc=@cc-1
end
update c set c.isprocessed=1,processedon=getdate() from calculated_fields_process c where c.id=@id
end try
begin  catch
update c set c.isprocessed=1,processedon=getdate(),error_desc=error_message() from calculated_fields_process c where c.id=@id
exec usp_inserterrorinfo
end catch
set @count=@count-1
end

--select * from calculated_fields

end

--delete from calculated_fields
--select top 10 * from ErrorReportNew(nolock) order by 1 desc


GO

