		--		SELECT TOP 500 *
		--		FROM [EmailsfiltercampaignexecutionTEST2] AS [EC](NOLOCK)
		--		WHERE [jobid] = @jobid AND [iscompleted] = 0
		--		ORDER BY [mail_id]
		--	) [kd] JOIN [Usercampaignmaster] [Ucm](NOLOCK)
		--	ON [ucm].[ID] = [kd].[CampaignID] JOIN [UserMailTemplate] [umt](NOLOCK)
		--	ON [umt].[ID] = [ucm].[TemplateID]
		--	WHERE [Ucm].[MailReplyTo] <> '' AND ISNULL([ucm].[TemplateID], 0) <> 0
		--		  AND ( [umt].[IsLeads] = 1 OR [umt].[IsConversion] = 1 );

		--	SELECT @b=@@ROWCOUNT;
		--	SET @e_c=@e_c - @b;
		--END;
		
		PRINT concat('Step 2: Completed composing dynamic lead template content, Total Records: ', @e_c,
		', Time: ', GETDATE());

		UPDATE Kd SET [Ismessages]=1
		FROM [Usercampaignexecutionhistory] [Kd] INNER JOIN [#EmailsfiltercampaignexecutionTEST2] [A](NOLOCK)
		ON [Kd].[CampaignID] = [A].[CampaignID] AND [A].[ParentID] = [Kd].[ParentID] AND [Kd].[JobId] = @Jobid and KD.CampaignID=@Campaignid;

		UPDATE Kd SET [Kd].[Step2]=1, [Step2DateTime]=GETDATE(), [Step2Recipients]=ISNULL([A].[Step2Recipients], 0)
		FROM [Usercampaignhistory] [Kd] INNER JOIN(SELECT [campaignid], COUNT([campaignid]) AS
		[Step2Recipients], [parentid]
										FROM [EmailsfiltercampaignexecutionTEST2](NOLOCK)
										WHERE [iscompleted] = 1 AND [jobid] = @jobid and Campaignid=@Campaignid
										GROUP BY [Parentid], [campaignid]) [A]
		ON [Kd].[CampaignID] = [A].[CampaignID] AND [A].[ParentID] = [Kd].[ParentID] AND [Kd].[JobId] = @Jobid;

		PRINT concat('Step 2 complete, Time: ', GETDATE());
		PRINT 'Step 3 started';

		CREATE TABLE #outputb
		(
			[id]         INT IDENTITY(1, 1),
			[bid]        BIGINT,
			[u_id]       BIGINT,
			[campaignid] BIGINT
		);

		BEGIN TRAN;
			INSERT INTO Getbatchrecord([User_id], [RandNum])
			OUTPUT [inserted].[BatchID] AS [bId], [inserted].User_id AS [u_id], [inserted].[RandNum] AS
			[campaignid]
				   INTO #outputb
			SELECT DISTINCT
				   [Ucerm].[ParentID], [Ucerm].[CampaignID]
			FROM EmailsfiltercampaignexecutionTEST2 AS Ucerm WITH(NOLOCK)
			WHERE [jobid] = @jobid and Campaignid=@Campaignid;
			DELETE g FROM [GetBatchRecord] [g] JOIN [#outputb] [o]
					 ON [o].[bid] = [g].[BatchID];
		COMMIT;

		SELECT ROW_NUMBER() OVER(ORDER BY [Ucerm].[CampaignId], [Ucerm].[ParentId]) AS [Id], [Ucerm].[CampaignID], [Ucerm].[ParentID],[o].[bid] AS [BatchID], [Ucerm].[Mail_FromEmail], [Ucerm].[Mail_UserID] AS [UserID], [Ucerm].[ReplyTo], COUNT(*) AS [cnt], [ucerm].[ispersonalized], [ucerm].[templateid]
		INTO [#tempTable]
		FROM EmailsfiltercampaignexecutionTEST2 AS Ucerm JOIN #outputb AS o
		ON o.u_id = ucerm.parentid AND o.campaignid = ucerm.campaignid
		WHERE [Ucerm].[IsCompleted] = 1 AND [jobid] = @jobid and ucerm.CampaignID=@Campaignid and Ucerm.ispersonalized=1
		GROUP BY [Ucerm].[CampaignID], [Ucerm].[ParentID], [Ucerm].[Mail_FromEmail], [Ucerm].[Mail_UserID],
		[Ucerm].[ReplyTo], [ucerm].[ispersonalized], [o].[bid], [ucerm].[templateid];

		declare @mailcost numeric(18,4)=(select top 1 price from Price_Base_Mail_Rate(nolock) )

		SELECT [A].[UserID], [a].[CampaignID], [a].[cnt], [A].[BatchID], SUM([b].[cnt]*@mailcost) AS [RunningTotal]
		INTO [#TempTableRunningTotal3]
		FROM #tempTable AS a INNER JOIN #tempTable AS b
		ON b.CampaignID <= a.CampaignID
		GROUP BY [A].[UserID], [a].[CampaignID], [a].[cnt], [A].[BatchID]
		ORDER BY [a].[CampaignID];

		DROP TABLE IF EXISTS #outputb;

		--- Calculate credits       
		SELECT [B].[UserID], [B].[CampaignID],
								 CASE
								 WHEN [B].[Balance] >= [B].[Credits]
									 THEN 1
								 ELSE 0
								 END AS [ValidEntries]
		INTO [#tempMobile3]
		FROM(SELECT [A].[UserID], [A].[CampaignID], ( [A].[Credits] ) AS [Credits], [A].[Balance]
			 FROM(SELECT [Tt].[UserID], [TT].[RunningTotal] AS [Credits], [TT].[CampaignID], [Tt].[BatchID],
			 [dbo].[getavailablebalanceforservice]([dbo].[ufn_getuserparentid]([tt].[userid]),2) AS [Balance]
				  FROM #TempTableRunningTotal3 AS Tt) AS A
			 GROUP BY [A].[UserID], [A].[Balance], [A].[CampaignID], [A].[credits]) AS B;

		UPDATE u SET [u].[ReasonIfNotRun]='Insufficient Balance'
		FROM [UserCampaignHistory] [u] JOIN [#tempMobile3] [t]
		ON [u].[campaignid] = [t].[CampaignID]
		   AND [u].[jobid] = @jobid and u.CampaignID=@Campaignid
		WHERE [t].[validentries] = 0;

		DECLARE @dis_parentid INT, @c_id BIGINT=0, @p_id BIGINT, @sql_t1 NVARCHAR(MAX), @tname NVARCHAR(100), @Mail_BatchId bigint=0;
		CREATE TABLE #clonet
		(
			[tablename] NVARCHAR(100)
		);
		SELECT @dis_parentid=COUNT(DISTINCT [campaignid]) FROM #tempmobile3 WHERE [ValidEntries] = 1;

		WHILE @dis_parentid > 0
		BEGIN
			SELECT @c_id=MIN([campaignid]) FROM #tempmobile3(NOLOCK) WHERE [campaignid] > @c_id AND [ValidEntries] = 1;
			SELECT @p_id=[dbo].[ufn_getuserparentid]([userid]) FROM #tempmobile3 WHERE [campaignid] = @c_id;
			SELECT @Mail_BatchId=[BatchID] FROM #tempTable WHERE [campaignid] = @c_id;

			declare @InsertedCreditID bigint=0
			INSERT INTO IntCredit_Details
			(
				FromUser_ID, M_ID, User_ID, Debits, Credits, Balance,Validity, BatchID, ICD_CreatedBy,typecredit,Remarks
			) 
			select @p_id, ud.m_id, @p_id,( [c].[cnt]*@mailcost), 0, [dbo].getavailablebalanceforservice(@p_id,2) - ( [c].[cnt]*@mailcost), 99999,c.batchid, @p_id,2,'Credits utilized for sending automated mail campaign: '+cm.CampaignName 
			FROM   #tempTable AS c(NOLOCK) JOIN user_detail AS ud(NOLOCK)
			ON ud.User_ID = c.parentid join usercampaignmaster(nolock) cm on cm.id=c.campaignid
			WHERE [c].[CampaignID] = @c_id;
 
			SELECT @InsertedCreditID = SCOPE_IDENTITY();
 
			exec usp_rf_UpdateReserveFundTransaction @InsertedCreditID


			/*INSERT INTO Mailcreditdetails([ID], [M_ID], [FromUser_ID], [User_ID], [Debits], [Credits],
			[Balance], [Validity], [Default_Credit], [FromDate], [ToDate], [DateCreated], [DateUpdated],
			[EmpUpdated], [MachineName], [LastModified], [typecredit], [campaignid], [batchid])
			SELECT NEWID(), [Ud].[M_ID], @p_id, @p_id, [c].[cnt], 0, [dbo].[fn_getmailbalance](@p_id) - [c].
			[cnt], 99999, '', GETDATE(), GETDATE(), GETDATE(), GETDATE(), '', '', GETDATE(), '', 0, [c].
			[BatchID]
			FROM #tempTable AS c(NOLOCK) JOIN user_detail AS ud(NOLOCK)
			ON ud.User_ID = c.parentid
			WHERE [c].[CampaignID] = @c_id;*/

			-- print concat('Processing campaign :',@c_id,' for parentid: ',@p_id)      
			INSERT INTO #clonet([tablename])
			EXEC [usp_CreateCloneEmailTable111_New] @p_id;
			SELECT TOP 1 @tname=[tablename] FROM #clonet;
			PRINT concat('Processing campaign :', @c_id, ' for parentid: ', @p_id, ', Mail Table: ', @tname);
			Exec usp_InsertEmail @Mail_BatchId, @tname, @Email, @c_id

			--SELECT @sql_t1='insert into ' + QUOTENAME(@tname) + ' (Mail_GUID,Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor, TemplateID,Source,mailroute,count)      
			--select newid(),Efce.Mail_FromEmail,Efce.Mail_ToEmail,case when efce.ispersonalized=1 and Efce.mail_subject is not null then Efce.mail_subject else c.Mail_Subject end,Efce.Mail_TempleteName,case when efce.ispersonalized=1 and Efce.Messages is not null then cast(Efce.Messages as nvarchar(max)) else CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid,c.Messages,Efce.Mail_ToEmail) AS NVARCHAR(MAX)) end, isnull(Efce.Mail_InsertedDate,getdate()),Efce.Mail_UserID,dbo.ufn_getuserparentid(efce.mail_userid),Efce.ReplyTo,TT.BatchID,case when tt.cnt>10 then Efce.Mail_Priority when tt.cnt<=10 then 1 else 0 end,isnull(Efce.Mail_ScheduleDate,getdate()),isnull(Efce.Mail_ScheduleDate,getdate()),Efce.Mail_Attechement, case when efce.ispersonalized=1 and Efce.Messages is not null then cast(Efce.Messages as nvarchar(max)) else CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid,c.Messages,Efce.Mail_ToEmail) AS NVARCHAR(MAX)) end, (select case when status=1 and tt.cnt>plimit then 0 else 1 end from ProcessMailLimit),efce.templateid,''Campaign : ''+cast (tt.campaignid as nvarchar),''T'',1    
			 --FROM EmailsfiltercampaignexecutionTEST2 AS Efce INNER JOIN #tempMobile3 Tm ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID AND ValidEntries = 1          
			--inner join #tempTable TT on TT.campaignid=efce.campaignid      
			--left join campaignmessages c on  c.campaignid=efce.campaignid and c.jobid=efce.jobid         
			--WHERE  Efce.IsCompleted = 1 and efce.campaignid=' + CAST(@c_id AS NVARCHAR) + ' and efce.jobid= ' + CAST(@jobid AS NVARCHAR) + ';    
			SELECT @sql_t1='update ' + QUOTENAME(@tname) +
			' set count = (select count(1) from EmailsfiltercampaignexecutionTEST2 efce WHERE     
			Efce.IsCompleted = 1 and efce.campaignid=' + CAST(@c_id AS NVARCHAR) + ' and efce.jobid= ' + CAST(@jobid AS NVARCHAR) + ');  
			-- select * from ' + QUOTENAME(@tname) +' ;  
			INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,  
			BatchInsertTime,BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName      
			,IsScheduled,Email_Subject,ReplyTo,ispersonalized,Mail_Source,mailroute,bmonitor,tablename)        
			SELECT s.BatchID,s.UserID,s.Mail_FromEmail,      
			case when isnull(s.templateid,0)<>0 then       
			(select MailContent from UserMailTemplate where ID=s.TemplateID)       
			when isnull(cast(c.messages as nvarchar(max)),'''')<>''''       
			then cast(c.messages as nvarchar(max))       
			else '''' end as Message,      
			C_count,0,0,0,      
			case when C_count>10 then 0 when c_count<=10 then 1 end,                                              
			Getdate(),NULL,Getdate(),Getdate(),s.TemplateID,0,0,0,      
			case when isnull(s.templateid,0)<>0       
			then (select mailsubject from UserMailTemplate where ID=s.TemplateID)       
			when isnull(c.Mail_subject,'''')<>'''' then c.mail_subject else '''' end as Mail_Subject,      
			ReplyTo,e.ispersonalized,''Campaign :''+cast(s.campaignid as nvarchar),''T'',  
			1,''' + @tname + '''        
			FROM #tempTable s (nolock) join (select campaignid,parentid,count(1) as C_count,ispersonalized from EmailsfiltercampaignexecutionTEST2(nolock) where ispersonalized=1 and jobid='
			+ CAST(@jobid AS NVARCHAR) + ' and campaignid=' + CAST(@c_id AS NVARCHAR) +
			' group by  campaignid,parentid,ispersonalized) e  
			on e.CampaignID=s.CampaignID and e.ParentID=s.ParentID   
			left join campaignmessages c on c.batchid=s.batchid ';

			PRINT 'Sql_t1: ' + @sql_t1;
			EXEC sp_executesql @sql_t1;

			DECLARE @tbl_activity AS dbo.LeadActivitywithid_Tbltype;
			
			if exists (select 1 from EmailsfiltercampaignexecutionTEST2(NOLOCK) m WHERE [m].[entityname] ='Lead' AND ISNULL([m].[entityid], 0) <> 0 AND [m].[jobid] = @jobid AND [m].[CampaignID] = @c_id)
			begin
				INSERT INTO @tbl_activity([LeadID], [UserID], [ParentID], [EventDescription], [EventName],
				[RefTable], [refid])
				SELECT [m].[entityid], [m].[Mail_UserID], [m].[ParentID], CAST([u].[user_login] AS NVARCHAR(100))
				+ ' sent ' + CASE
							 WHEN NULLIF([cm].[TemplateID], 0) IS NOT NULL
								 THEN ' template with name"' + ISNULL([umt].[Name], 'no name') + '"'
							 ELSE ' a mail '
							 END + ' with subject "' + CASE
													   WHEN NULLIF([cm].[TemplateID], 0) IS NOT NULL
														   THEN [umt].[MailSubject]
													   WHEN [cm].[Mail_Subject] IS NOT NULL
														   THEN [cm].[Mail_Subject]
													   ELSE ISNULL(replace([m].[mail_subject], '''', '"'), '')
													   END + '" to emailid ' + CAST([m].[Mail_ToEmail] AS
													   NVARCHAR(100)) + ' through automated campaign named ' +
													   [c].[CampaignName], 'Mail sent to ' + [m].[entityname],
													   'Batchemail_infos', [tt].[BatchID]
				FROM user_detail(NOLOCK) AS u JOIN EmailsfiltercampaignexecutionTEST2(NOLOCK) AS m
				ON m.Mail_UserID = u.User_ID JOIN UserCampaignMaster(NOLOCK) AS c
				ON c.ID = m.CampaignID LEFT JOIN campaignmessages(NOLOCK) AS cm
				ON cm.campaignid = m.campaignid AND cm.jobid = m.jobid LEFT JOIN usermailtemplate(NOLOCK) AS umt
				ON umt.id = cm.templateid JOIN #tempTable AS tt
				ON tt.CampaignID = m.CampaignID
				WHERE [m].[entityname] ='Lead'
					  AND ISNULL([m].[entityid], 0) <> 0
					  AND [m].[jobid] = @jobid
					  AND [m].[CampaignID] = @c_id;

				EXEC UspSaveEntityActivity_withMultipleValue_withid_bulk @tbl_activity;
			end

			delete from @tbl_activity

			if exists (select 1 from EmailsfiltercampaignexecutionTEST2(NOLOCK) m WHERE [m].[entityname] ='Enquiry' AND ISNULL([m].[entityid], 0) <> 0 AND [m].[jobid] = @jobid AND [m].[CampaignID] = @c_id)
			begin
				INSERT INTO @tbl_activity([LeadID], [UserID], [ParentID], [EventDescription], [EventName],
				[RefTable], [refid])
				SELECT [m].[entityid], [m].[Mail_UserID], [m].[ParentID], CAST([u].[user_login] AS NVARCHAR(100))
				+ ' sent ' + CASE
							 WHEN NULLIF([cm].[TemplateID], 0) IS NOT NULL
								 THEN ' template with name"' + ISNULL([umt].[Name], 'no name') + '"'
							 ELSE ' a mail '
							 END + ' with subject "' + CASE
													   WHEN NULLIF([cm].[TemplateID], 0) IS NOT NULL
														   THEN [umt].[MailSubject]
													   WHEN [cm].[Mail_Subject] IS NOT NULL
														   THEN [cm].[Mail_Subject]
													   ELSE ISNULL(replace([m].[mail_subject], '''', '"'), '')
													   END + '" to emailid ' + CAST([m].[Mail_ToEmail] AS
													   NVARCHAR(100)) + ' through automated campaign named ' +
													   [c].[CampaignName], 'Mail sent to ' + [m].[entityname],
													   'Batchemail_infos', [tt].[BatchID]
				FROM user_detail(NOLOCK) AS u JOIN EmailsfiltercampaignexecutionTEST2(NOLOCK) AS m
				ON m.Mail_UserID = u.User_ID JOIN UserCampaignMaster(NOLOCK) AS c
				ON c.ID = m.CampaignID LEFT JOIN campaignmessages(NOLOCK) AS cm
				ON cm.campaignid = m.campaignid AND cm.jobid = m.jobid LEFT JOIN usermailtemplate(NOLOCK) AS umt
				ON umt.id = cm.templateid JOIN #tempTable AS tt
				ON tt.CampaignID = m.CampaignID
				WHERE [m].[entityname] = 'Enquiry'
					  AND ISNULL([m].[entityid], 0) <> 0
					  AND [m].[jobid] = @jobid
					  AND [m].[CampaignID] = @c_id;

				EXEC UspSaveEntityActivity_withMultipleValue_withid_bulk @tbl_activity;
			End

			SET @dis_parentid=@dis_parentid - 1;

			TRUNCATE TABLE #clonet;
			DELETE FROM @tbl_activity;
		END;

		UPDATE Kd SET [Executiontime]=GETDATE(), [Noofrecipients]=[Tt].[Cnt], [Batchid]=[Tt].[BatchID],
		[Isexecuted]=CASE
					 WHEN [tm].[Validentries] = 1
						 THEN 1
					 ELSE 0
					 END
		FROM [Usercampaignexecutionhistory] [Kd] INNER JOIN [#tempTable] [Tt]
		ON [Tt].[CampaignID] = [Kd].[CampaignID] INNER JOIN [#tempMobile3] [Tm]
		ON [Tm].[userID] = [Tt].[userID] AND [Tm].[CampaignID] = [Tt].[CampaignID]
		WHERE [Jobid] = @jobId;

		CREATE TABLE #batch3
		(
			[batchid]    BIGINT,
			[parentid]   BIGINT,
			[campaignid] BIGINT
		);
		INSERT INTO Getbatchrecord([User_id], [RandNum])
		OUTPUT [inserted].[batchid], [inserted].user_id, [inserted].[RandNum]
		SELECT [ParentID], [CampaignID] FROM #tempTable;
		DELETE g FROM [Getbatchrecord] [g] JOIN [#batch3] [b]
				 ON [g].[batchid] = [b].[batchid];

		INSERT INTO cloneemailsfilter([Mail_GUID], [Mail_FromEmail], [Mail_ToEmail], [Mail_Subject],
		[Mail_TempleteName], [Messages], [Mail_InsertedDate], [Mail_UserID], [mail_Parentid], [ReplyTo],
		[Mail_BatchID], [Mail_Priority], [Mail_ScheduleDate], [Mail_Attechement], [Mail_TempleteBody],
		[IsMonitor], [TemplateId], Count, [Source], [mailroute])
		SELECT NEWID(), 'contactus@email19.in', [ucm].[NotificationMail],
		CASE
		WHEN [TM].[ValidEntries] = 0
			THEN 'Failure: Your campaign "' + +[UCM].
			[CampaignName] + '" failed due to insufficient credits'
		ELSE 'Success : Your campaign "' + [UCM].[CampaignName]
		+ '" executed successfully'
		END AS [Mail_subject], '',
		CASE
		WHEN [TM].[ValidEntries] = 0
			THEN
			'Oops, you don''t have sufficient mail credits to run your mail campaign "' + [UCM].
			[CampaignName] + '" scheduled for ' + CAST(GETDATE()
			AS VARCHAR(50)) +
			'. Pl refill your credit balance & rerun the campaign '
		ELSE
		'As promised , Your Mail campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST
		(GETDATE() AS VARCHAR(50)) +
		' is executed successfully. You can log in to your account & check the delivery report in the campaign history'
		END AS [Messages], GETDATE(),
		335, 335, 'contactus@kit19.com',
		[B].[BatchId], 1, GETDATE(), 0,
		CASE
		WHEN [TM].[ValidEntries] = 0
			THEN 'Oops, you don''t have sufficient mail credits to run your mail campaign "' +
			[UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE()
			AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '
		ELSE
		'As promised , Your Mail campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE()
		AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the campaign history'
		END
		AS [Messages],1,NULL,(SELECT COUNT(DISTINCT [campaignid]) FROM [#tempTable]),'Internal Notification','T'
		FROM #tempTable AS Tt INNER JOIN Usercampaignmaster AS Ucm
		ON Ucm.ID = Tt.CampaignID AND Ucm.IsScheduled = 1 AND Ucm.ParentID = Tt.ParentID INNER JOIN #tempMobile3 AS TM
		ON TM.CampaignID = Ucm.ID INNER JOIN #Batch3 AS B
		ON B.CampaignId = Tt.CampaignId;

		DECLARE @emailcount BIGINT=(SELECT COUNT(1)
									FROM EmailsfiltercampaignexecutionTEST2 AS Kd(NOLOCK) INNER JOIN
									#tempTable AS Tt
									ON Tt.CampaignID = Kd.CampaignID
									   AND jobid = @jobid);
		WHILE @emailcount > 0
		BEGIN
			DELETE TOP (1000) Kd
			FROM [EmailsfiltercampaignexecutionTEST2] [Kd] INNER JOIN [#tempTable] [Tt]
			ON [Tt].[CampaignID] = [Kd].[CampaignID] AND [jobid] = @jobid;
			SET @emailcount=@emailcount - 1000;
		END;

		UPDATE Kd SET [Kd].[step3]=1, [Step3DateTime]=GETDATE(), 
		[Step3Recipients]=CASE WHEN [ValidEntries] = 1 THEN [TT].[cnt] ELSE 0 END
		FROM [usercampaignhistory] [Kd] INNER JOIN [#tempTable] [TT]
		ON [TT].[CampaignID] = [Kd].[CampaignID] INNER JOIN [#tempMobile3] [TM]
		ON [TM].[CampaignID] = [Kd].[CampaignID]
		WHERE [Kd].[JobId] = @jobId;

		PRINT 'Step 3 complete';

		UPDATE u SET [executeddatetime]=GETDATE()
		FROM [usercampaignmaster] [u] JOIN [usercampaignhistory] [Kd]
		ON [kd].[campaignid] = [u].[id] AND [Kd].[JobId] = @jobId and KD.CampaignID=@Campaignid;

		SELECT [campaignid]
		INTO [#FindCampaignsNextExecution3]
		FROM #tempTable AS t JOIN UserCampaignMaster AS ucm
		ON t.CampaignID = ucm.id LEFT JOIN userschedules AS us
		ON us.id = ucm.scheduleid
		WHERE [ucm].[IsActive] = 1 AND [ucm].[IsSchedule] = 1 AND [ucm].[IsScheduled] = 1 AND [us].[IsOnce] = 0;

		DECLARE @count3 INT=ISNULL((SELECT COUNT(1) FROM #FindCampaignsNextExecution3), 0);
		IF @count3 > 0
		BEGIN
			CREATE TABLE #nextexec13
			(
				[campaignid]    BIGINT,
				[nextexecution] DATETIME
			);
			WHILE @Count3 > 0
			BEGIN
				DECLARE @Campaignid3 BIGINT=(SELECT TOP 1 [campaignid] FROM #FindCampaignsNextExecution3);

				INSERT INTO #nextexec13([campaignid], [nextexecution])
				EXEC Usp_getnextscheduledate @Campaignid3;

				DELETE FROM #FindCampaignsNextExecution3 WHERE [campaignid] = @Campaignid3;
				SET @Count3=@Count3 - 1;
			END;

			UPDATE u SET [NextExecuteDateTime]=[nextexecution]
			FROM [usercampaignmaster] [u] JOIN [#nextexec13] [n]
			ON [n].[campaignid] = [u].[id]
			WHERE [u].[ExpiryDate] > [nextexecution] OR [u].[ExpiryDate] IS NULL;

			DROP TABLE IF EXISTS #nextexec13;
			DROP TABLE IF EXISTS #FindCampaignsNextExecution3;
		END;

		--Code added to update nextexecutiondate in usercampaignhistory end--                                           
		DROP TABLE IF EXISTS #tempMobile3;
		DROP TABLE IF EXISTS #tempTable;
		DROP TABLE IF EXISTS #tempMobileVirtual;
		DROP TABLE IF EXISTS #tempTableVirtual;
		DROP TABLE IF EXISTS #Insufficientresellerbalance;
		DROP TABLE IF EXISTS #TempTableRunningTotal3;
		DROP TABLE IF EXISTS #TempTableRunningTotalVirtual;
		DROP TABLE IF EXISTS #output;
		DROP TABLE IF EXISTS #batch3;
		DROP TABLE IF EXISTS #EmailsfiltercampaignexecutionTEST2;
		DROP TABLE IF EXISTS #clonet;
		DROP TABLE IF EXISTS #outputb;

		IF EXISTS(SELECT 1 FROM UserCampaignHistory WHERE [JobId] = @jobId AND [IsEventBased]=0 AND [isSMS] = 0)
		BEGIN
			UPDATE usercampaignexecution SET [CampaignEnddatetime]=GETDATE(), [isrunning]=0
			WHERE [isevent] = 0 AND [isSMS] = 0;
			--select 'updated'                            
		END;
End Try
Begin Catch
	Exec Usp_insertErrorInfo
End Catch

END



GO

/* ============================================================
   Procedure: [dbo].[usp_ProcessEnquiryImportData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--Dependency of this usp_ProcessEnquiryImportData

--1.[MySMSConversations].[dbo].[tbl_imp_ImportRequest]       -- called by clr
--2. [MySMSConversations].[dbo].[tbl_ims_ImportSlot]  -- called by clr 

-------------------------------------
 --Exec usp_ProcessEnquiryImportData 0, 'P'            
 --Exec usp_ProcessEnquiryImportData 1, 'P'            
 --Exec usp_ProcessEnquiryImportData 1, 'P', 3401           

CREATE   PROC [dbo].[usp_ProcessEnquiryImportData] 
(              
    @BatchSize int=1,  -- 0 ('All')              
    @Mode varchar(1)='P',    -- 'P'riority, 'F'ifo    
	@IPRId bigint=0    
)              
AS 
BEGIN              
 
     --declare @BatchSize int=1, @Mode varchar(1)='P', @IPRId bigint = 9285 --8529  

	 declare @nEnquiryCustomFieldRows_p bigint=0, @nLeadCustomFieldRows_p bigint = 0
			 ,@nEnquiriesInserted_p bigint=0 , @nLeadInserted_p bigint = 0, @ImportRow_id_p bigint = 0;  					 
			 

    DECLARE @sqlquery NVARCHAR(MAX);
	if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end              
	if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end              
	if object_id('tempdb..#tblAgentList') is not null begin drop table #tblAgentList end              
	if object_id('tempdb..#tmptblAgentList') is not null begin drop table #tmptblAgentList end              
	if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end              
	if object_id('tempdb..#tblAllEnquiryFields') is not null begin drop table #tblAllEnquiryFields end              
	if object_id('tempdb..#tmpEnquirySrc') is not null begin drop table #tmpEnquirySrc end              
	if object_id('tempdb..#tmpUserEnquiry') is not null begin drop table #tmpUserEnquiry end              
	if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end              
	if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end              
	if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end              
	if object_id('tempdb..#outputEnquiry') is not null begin drop table #outputEnquiry end              
	if object_id('tempdb..#outputLead') is not null begin drop table #outputLead end              
	if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end              
	if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end              
              
	Create table #tblImportRowId
	(              
		RowId int identity,              
		ImportRow_id bigint,              
		[User_Id] bigint,              
		IsAutoLeadGeneration bit              
	)              
              
	create table #tmpConstraintChk
	(              
		Sno int,              
		Remarks varchar(200)              
	)              
              
	create table #tmptblAgentList
	(              
		Sno int IDENTITY(1,1),               
		AgentId bigint              
	)              
              
	create table #tblAgentList
	(              
		Sno int IDENTITY(1,1),               
		AgentId bigint              
	)              
              
	create table #tblCustomFields
	(              
		RowId int identity(1,1),              
		fieldId bigint,              
		fieldName varchar(50)              
	)              
              
	create table #tblAllEnquiryFields
	(            
	 RowId int identity(1,1),            
	 fieldName varchar(50),            
	 FieldType varchar(10)            
	)            
            
	create table #tmpMobileNoList
	(              
		RowId int identity,              
		MobileNo varchar(100)              
	)              
              
	create table #tmpEmailIdList
	(              
		RowId int identity,              
		EmailId varchar(100)              
	)              
              
	CREATE TABLE #tmpUserEnquiry
	(              
	 [EnquiryID] [bigint] IDENTITY(1,1) NOT NULL,              
	 [Sno] [int] NOT NULL,              
	 [PersonName] [nvarchar](400) NULL,              
	 [CompanyName] [nvarchar](1000) NULL,              
	 [MobileNo] [varchar](100) NULL,              
	 [MobileNo1] [varchar](100) NULL,              
	 [MobileNo2] [varchar](100) NULL,              
	 [EmailID] [varchar](100) NULL,              
	 [EmailID1] [varchar](100) NULL,              
	 [EmailID2] [varchar](100) NULL,              
	 [City] [varchar](100) NULL,              
	 [State] [varchar](100) NULL,              
	 [Country] [varchar](100) NULL,              
	 [CountryCode] [varchar](50) NULL,              
	 [CountryCode1] [varchar](50) NULL,              
	 [CountryCode2] [varchar](50) NULL,              
	 [PinCode] [bigint] NULL,              
	 [ResidentialAddress] [varchar](500) NULL,          
	 [OfficeAddress] [varchar](500) NULL,              
	 [SourceName] [varchar](100) NOT NULL,              
	 [MediumName] [varchar](100) NOT NULL,              
	 [CampaignName] [varchar](100) NOT NULL,              
	 [InitialRemarks] [varchar](1000) NULL,              
	 [ParentID] [bigint] NOT NULL,              
	 [CreatedDate] [datetime] NOT NULL,              
	 [CreatedBy] [bigint] NULL,              
	 [IsOpen] [bit] NOT NULL DEFAULT ((1)),              
	 [LeadNo] [int] NULL,    
	 [WhatsAppNoColName] varchar(10)    
	)              
              
	CREATE TABLE #tmpUserLeads 
	(         
	 [LeadNo] [bigint] IDENTITY(1,1) NOT NULL,              
	 [EnquiryID] [bigint] NOT NULL,              
	 [Sno] [int] NOT NULL,              
	 [PersonName] [nvarchar](400) NULL,              
	 [CompanyName] [nvarchar](1000) NULL,              
	 [MobileNo] [varchar](100) NULL,              
	 [MobileNo1] [varchar](100) NULL,              
	 [MobileNo2] [varchar](100) NULL,              
	 [EmailID] [varchar](100) NULL,              
	 [EmailID1] [varchar](100) NULL,              
	 [EmailID2] [varchar](100) NULL,              
	 [City] [varchar](100) NULL,              
	 [State] [varchar](100) NULL,              
	 [Country] [varchar](100) NULL,              
	 [CountryCode] [varchar](50) NULL,              
	 [CountryCode1] [varchar](50) NULL,              
	 [CountryCode2] [varchar](50) NULL,              
	 [PinCode] [bigint] NULL,              
	 [ResidentialAddress] [varchar](500) NULL,              
	 [OfficeAddress] [varchar](500) NULL,              
	 [AssignedTo] [bigint] NOT NULL,              
	 [SourceName] [bigint] DEFAULT ((0)) NOT NULL,              
	 [MediumName] [bigint] DEFAULT ((0)) NULL,              
	 [CampaignName] [bigint] DEFAULT ((0)) NULL,              
	 [InitialRemarks] [varchar](1000) NULL,              
	 [ParentID] [bigint] NOT NULL,              
	 [FollowUpStatus] [int] NULL,              
	 [NextStatusDate] [varchar](50) NULL,              
	 [Remarks] [varchar](1000) NULL,              
	 [Products] [varchar](1000) NULL,              
	 [AmountPaid] [numeric](18, 2) NOT NULL DEFAULT ((0)),              
	 [CreatedOn] [datetime] NULL,              
	 [CreatedBy] [bigint] NULL,              
	 [FollowupDate] [datetime] NULL,    
	 [WhatsAppNoColName] varchar(10)    
	)              

	SET XACT_ABORT ON;

	BEGIN TRY              
		--BEGIN TRANSACTION              
    
		If(isnull(@IPRId,0) > 0)    
		Begin    
			insert into #tblImportRowId    
			Select ImportRow_id,[User_Id],IsAutoLeadGeneration From tbl_EnquiryImportSummary(nolock) where ImportRow_id=@IPRId    
		End    
		Else    
		Begin    
			If(@Mode = 'P')
			Begin              
				If(@BatchSize != 0)
				Begin              
					insert into #tblImportRowId              
					Select top (@BatchSize) ImportRow_id,[User_Id],IsAutoLeadGeneration 
					From tbl_EnquiryImportSummary(nolock) where IsProcessed=0 order by [Priority]              
				End              
				Else              
				Begin              
					insert into #tblImportRowId              
					Select ImportRow_id,[User_Id],IsAutoLeadGeneration     
					From tbl_EnquiryImportSummary(nolock) where IsProcessed=0 order by [Priority]              
				End
			End    
			Else -- Fifo    
			Begin              
				If(@BatchSize != 0)
				Begin    
					insert into #tblImportRowId    
					Select top (@BatchSize) ImportRow_id,[User_Id],IsAutoLeadGeneration From tbl_EnquiryImportSummary(nolock) where IsProcessed=0    
				End    
				Else    
				Begin    
					insert into #tblImportRowId    
					Select ImportRow_id,[User_Id],IsAutoLeadGeneration From tbl_EnquiryImportSummary(nolock) where IsProcessed=0    
				End    
			End              
		End    
              
		declare @iRow int=1, @jRow int=1, @ImportRow_id bigint=0, @UnProcessedRowCnt int=0, @User_Id bigint=0, @LastEnquiryId bigint=0, @nEnquiriesInserted bigint=0, @LastLeadId bigint=0, @nLeadInserted bigint=0, @fieldId bigint=0, @nEnquiryCustomFieldRows bigint=0, @nLeadCustomFieldRows bigint=0, @ParentId bigint=0, @CreatedOn datetime, @CsvID nvarchar(max), @enquiryCsv nvarchar(max)
		declare @ImportData nvarchar(max), @RowData nvarchar(max), @FieldNames nvarchar(max)='', @SQLString nvarchar(max)='', @ParmDefinition nvarchar(500), @fieldName varchar(50)='',@fieldtype nvarchar(20);
		declare @IsAutoLeadGeneration bit=0, @strAgentlst nvarchar(max), @LastAssignedUser int, @NextLeadNo bigint=0, @AgentCnt int=0, @CustomFieldsCnt int=0, @ImportRequestId bigint=0, @RecCnt int =0, @Pagesize int=500, @Pageno int=1, @Start int=0, @End int=0    
              
		select @UnProcessedRowCnt=Count(*) from #tblImportRowId              
              
		While(@iRow <= @UnProcessedRowCnt)              
		Begin
		  print '@iRow: ' + cast(@iRow as varchar)              
		  Select @ImportRow_id=ImportRow_id,@User_Id=[User_Id],@IsAutoLeadGeneration=IsAutoLeadGeneration From #tblImportRowId Where RowId=@iRow    
		  print '@ImportRow_id: ' + cast(@ImportRow_id as varchar)  
		  
		  set @ImportRow_id_p = @ImportRow_id

		  Select @ImportData=ImportData from tbl_EnquiryImportSummary(nolock) where ImportRow_Id=@ImportRow_id              
		  print '@ImportData: ' + @ImportData              
		  select top 1 @RowData=value from openjson(@ImportData)              
		  print '@RowData: ' + @RowData              
		  select @FieldNames=@FieldNames+'['+[Key]+'] nvarchar(2000),' from openjson(@RowData)              
		  print '@FieldNames1: ' + @FieldNames

		  If (CHARINDEX('WhatsAppNoColName',@FieldNames,0) > 0)    
		  Begin    
			print 'WhatsAppNoColName found'    
			set @FieldNames=SUBSTRING(@FieldNames,1,len(@FieldNames)-1)          
		  End    
		  Else    
		  Begin    
			print 'WhatsAppNoColName not found, adding dummy'    
			select @FieldNames=@FieldNames+' [WhatsAppNoColName] varchar(10)'    
			select @RowData=replace(@RowData,'}',',"WhatsAppNoColName":null}')    
		  End    
		  print '@FieldNames2: ' + @FieldNames              
              
		  Select @ParentId = dbo.ufn_GetUserParentId(@User_Id)              
            
		  insert into #tblAllEnquiryFields
		  values ('Sno','Main'),('PersonName','Main'),('CompanyName','Main'),('MobileNo','Main'),('MobileNo1','Main'),('MobileNo2','Main'), ('EmailID','Main'),('EmailID1','Main'),('EmailID2','Main'),('City','Main'),('State','Main'),('Country','Main'), ('CountryCode','Main'),('CountryCode1','Main'),('CountryCode2','Main'),('PinCode','Main'),('ResidentialAddress','Main'), ('OfficeAddress','Main'),('SourceName','Main'),('MediumName','Main'),('CampaignName','Main'),('InitialRemarks','Main'), ('WhatsAppNoColName','Main')    
         
		  insert into #tblAllEnquiryFields
		  select fieldname,'Custom'            
		  from customfields(nolock)                 
		  where parentId=@ParentId and isActive=1            
            
		  Update tbl_EnquiryImportSummary Set IsProcessed=1, Remarks='[{"Sno":0,"Remarks":"Under Process Queue"}]' Where ImportRow_Id = @ImportRow_id    
    
		  if exists(select [Key] from openjson(@RowData) where [Key] COLLATE SQL_Latin1_General_CP1_CI_AS not in (Select FieldName From #tblAllEnquiryFields))    
		  Begin            
			print 'Invalid Field found in Import Data'    
			Update tbl_EnquiryImportSummary Set IsProcessed=1, Remarks='[{"Sno":0,"Remarks":"Invalid Field found in Import Data"}]'     
			Where ImportRow_Id = @ImportRow_id    
			goto Iter    
		  End            
		  Else            
		  Begin    
			If exists(Select FieldName From #tblAllEnquiryFields Where FieldName COLLATE SQL_Latin1_General_CP1_CI_AS not in (select [Key] from openjson(@RowData)))    
			Begin    
				print 'Required Field Missing in Import Data'
				
				--Select FieldName From #tblAllEnquiryFields Where FieldName COLLATE SQL_Latin1_General_CP1_CI_AS not in (select [Key] from openjson(@RowData))

				Update tbl_EnquiryImportSummary Set IsProcessed=1, Remarks='[{"Sno":0,"Remarks":"Required Field Missing in Import Data"}]'     
				Where ImportRow_Id = @ImportRow_id    
				goto Iter    
			End            
		  End            
            
		  create table #tmpEnquirySrc (id int identity);              
		  print 'alter table #tmpEnquirySrc add ' + @FieldNames              
		  exec('alter table #tmpEnquirySrc add ' + @FieldNames)              
              
		  --Set @SQLString = N'select * into ##tmpEnquirySrc from openjson(''' + @ImportData + ''') with (''' + @FieldNames + ''')'              
		  --Set @SQLString = N'select * into ##tmpEnquirySrc from openjson(@ImptData) with (@FldNames)'               
              
		  Set @SQLString = N'insert into #tmpEnquirySrc select * from openjson(@ImptData) with (' + @FieldNames + ')'               
		  --Set @SQLString = N'insert into #tmpEnquirySrc select * from openjson(@ImptData) with (' + @FieldNames + ') where [Sno] is not null'               
		  --Set @SQLString = N'insert into #tmpEnquirySrc select * from openjson(@ImptData) with (' + @FieldNames + ') where [PersonName] is not null and ([MobileNo] is not null and [CountryCode] is not null or [EmailID] is not null) and [CountryCode] is not null and [SourceName] is not null'               
              
		  --SET @ParmDefinition = N'@ImptData nvarchar(max), @FldNames nvarchar(max)';                
		  SET @ParmDefinition = N'@ImptData nvarchar(max)';                
                
		  print @SQLString              
              
		  --EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData, @FldNames=@FieldNames                
		  EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData                
              
		  update #tmpEnquirySrc    
		  set MobileNo=rtrim(ltrim(case when isnull(MobileNo,'')='' and isnull(MobileNo1,'')!='' then MobileNo1 else Isnull(MobileNo,'') end)),    
		  MobileNo1=rtrim(ltrim(case when isnull(MobileNo1,'')='' and isnull(MobileNo2,'')!='' then MobileNo2 else Isnull(MobileNo1,'') end)),    
		  MobileNo2=rtrim(ltrim(isnull(MobileNo2,''))),              
		  CountryCode=rtrim(ltrim(case when isnull(CountryCode,'')='' and isnull(CountryCode1,'')!='' then iif(left(ltrim(CountryCode1),1) != '+','+'+ltrim(CountryCode1),CountryCode1) else iif(left(ltrim(Isnull(CountryCode,'')),1) != '+'       
		  and ltrim(Isnull(CountryCode,'')) != '', '+' + ltrim(Isnull(CountryCode,'')),Isnull(CountryCode,'')) end)),              
		  CountryCode1=rtrim(ltrim(case when isnull(CountryCode1,'')='' and isnull(CountryCode2,'')!='' then iif(left(ltrim(CountryCode2),1) != '+','+'+ltrim(CountryCode2),CountryCode2) else iif(left(ltrim(Isnull(CountryCode1,'')),1) != '+'       
		  and ltrim(Isnull(CountryCode1,'')) != '', '+' + ltrim(Isnull(CountryCode1,'')),Isnull(CountryCode1,'')) end)),              
		  CountryCode2=rtrim(ltrim(iif(left(ltrim(isnull(CountryCode2,'')),1) != '+' and ltrim(isnull(CountryCode2,'')) != '','+' + ltrim(isnull(CountryCode2,'')),Isnull(CountryCode2,'')))),              
		  EmailID=rtrim(ltrim(case when isnull(EmailID,'')='' and isnull(EmailID1,'')!='' then EmailID1 else Isnull(EmailID,'') end)),              
		  EmailID1=rtrim(ltrim(case when isnull(EmailID1,'')='' and isnull(EmailID2,'')!='' then EmailID2 else Isnull(EmailID1,'') end)),    
		  EmailID2=rtrim(ltrim(isnull(EmailID2,''))),              
		  PersonName=rtrim(ltrim(isnull(PersonName,''))),              
		  InitialRemarks=rtrim(ltrim(isnull(InitialRemarks,''))),              
		  SourceName=rtrim(ltrim(isnull(SourceName,''))),              
		  MediumName=rtrim(ltrim(isnull(MediumName,''))),              
		  CampaignName=rtrim(ltrim(isnull(CampaignName,''))),              
		  WhatsAppNoColName=rtrim(ltrim(isnull(WhatsAppNoColName,''))),              
		  Sno=rtrim(ltrim(isnull(Sno,0)))              
              
			 --EXEC('select * from #tmpEnquirySrc')              
              
		  insert into #tmpConstraintChk              
		  Select  Sno, 'Duplicate Records' as Remarks              
		  From              
		  (              
		  select ROW_NUMBER()over(partition by PersonName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, InitialRemarks order by cast(Sno as int)) as Rid, *              
		  from #tmpEnquirySrc              
		  ) B              
		  Where B.Rid > 1              
                                
		  insert into #tblCustomFields              
		  select field_ID, fieldname               
		  from customfields(nolock)               
		  where parentId=@ParentId and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select FieldName from #tblAllEnquiryFields where [FieldType] = 'Custom')              
			 /*where parentId=dbo.ufn_GetUserParentId(@User_Id) and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select [Key]    
			from openjson(@RowData) where [Key] not in ('Sno', 'PersonName', 'CompanyName', 'MobileNo', 'MobileNo1', 'MobileNo2', 'EmailID', 'EmailID1', 'EmailID2', 'City', 'State', 'Country', 'CountryCode', 'CountryCode1', 'CountryCode2', 'PinCode', 'ResidentialAddress', 'OfficeAddress', 'SourceName', 'MediumName', 'CampaignName', 'InitialRemarks', 'ProfileImgFileName'))*/              
              
		  Select @CustomFieldsCnt=count(*) From #tblCustomFields              
              
		  insert into #tmpConstraintChk              
		  Select  Sno, 'Sno missing' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   ISNULL(ltrim(Sno),'') = '' or ISNULL(ltrim(Sno),'0') = '0'              
		  union              
		  Select  Sno, 'Sno Duplicate' as Remarks              
		  From    #tmpEnquirySrc              
		  group by Sno              
		  having  Count(*) > 1              
		  union              
		  Select  Sno, 'PersonName missing' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   ISNULL(ltrim(PersonName),'') = ''              
		  union              
		  Select  Sno, 'Contact details missing' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   ISNULL(ltrim(MobileNo),'') = '' and ISNULL(ltrim(MobileNo1),'') = '' and ISNULL(ltrim(MobileNo2),'') = '' and               
		  ISNULL(ltrim(EmailID),'') = '' and ISNULL(ltrim(EmailID1),'') = '' and ISNULL(ltrim(EmailID2),'') = ''              
		  union              
		  Select  Sno, 'MobileNo or CountryCode missing' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   ((ISNULL(ltrim(MobileNo),'')!='' and ISNULL(ltrim(CountryCode),'')='') or (ISNULL(ltrim(MobileNo),'')='' and ISNULL(ltrim(CountryCode),'')!=''))              
			 or              
		  ((ISNULL(ltrim(MobileNo1),'')!='' and ISNULL(ltrim(CountryCode1),'')='') or (ISNULL(ltrim(MobileNo1),'')='' and ISNULL(ltrim(CountryCode1),'')!='')) or              
		  ((ISNULL(ltrim(MobileNo2),'')!='' and ISNULL(ltrim(CountryCode2),'')='') or (ISNULL(ltrim(MobileNo2),'')='' and ISNULL(ltrim(CountryCode2),'')!=''))              
		  union              
		  Select  Sno, 'SourceName missing' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   ISNULL(ltrim(SourceName),'') = ''              
		  union              
		  Select  Sno, 'PersonName Length exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(PersonName)>100              
		  union              
		  Select  Sno, 'CompanyName exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(CompanyName)>100              
		  union              
		  Select  Sno, 'MobileNo exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(MobileNo)>100              
		  union              
		  Select  Sno, 'MobileNo1 exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(MobileNo1)>100              
		  union              
		  Select  Sno, 'MobileNo2 exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(MobileNo2)>100              
		  union              
		  Select  Sno, 'EmailID exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(EmailID)>100              
		  union              
		  Select  Sno, 'EmailID1 exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(EmailID1)>100              
		  union              
		  Select  Sno, 'City exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(City)>100              
		  union              
		  Select  Sno, 'State exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(State)>100              
		  union              
		  Select  Sno, 'Country exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(Country)>100              
		union              
		  Select  Sno, 'CountryCode exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(CountryCode)>100              
		  union              
		  Select  Sno, 'CountryCode1 exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(CountryCode1)>100              
		  union              
		  Select  Sno, 'CountryCode2 exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(CountryCode2)>100              
		  union              
		  Select  Sno, 'ResidentialAddress exceeds specified limit(500)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(ResidentialAddress)>500              
		  union              
		  Select  Sno, 'OfficeAddress exceeds specified limit(500)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(OfficeAddress)>500              
		  union              
		  Select  Sno, 'SourceName exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(SourceName)>100              
		  union              
		  Select  Sno, 'MediumName exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(MediumName)>100              
		  union              
		  Select  Sno, 'CampaignName exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(CampaignName)>100              
		  union              
		  Select  Sno, 'InitialRemarks exceeds specified limit(1000)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(InitialRemarks)>1000              
			/*              
			union              
			Select  Sno, 'Invalid DateOfBirth' as Remarks              
			From    #tmpEnquirySrc              
			Where   isnull(ltrim(DateOfBirth),'') != '' and ISDate(DateOfBirth) = 0              
			*/              
              
			--select count(*) as ConstraintChkCnt1 from #tmpConstraintChk              
              
			 INSERT INTO #tmpUserEnquiry              
			   ([Sno],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],[WhatsAppNoColName])              
			Select  Sno,PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,EmailID2,City,[State],Country,CountryCode,CountryCode1,CountryCode2,case when ISNUMERIC(PinCode) != 1 then cast(0 as bigint) else PinCode end, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, dbo.ufn_GetUserParentId(@User_Id) as ParentID, getdate(), @User_Id as CreatedBy, WhatsAppNoColName    
			From   #tmpEnquirySrc              
			Where   Sno not in (Select distinct Sno from #tmpConstraintChk)              
              
		  --Select count(*) as ValidRecCnt from #tmpUserEnquiry              
              
		  INSERT INTO UserSourceSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)       
		  Select distinct SourceName, @ParentId, 1,  1, GETDATE(), GETDATE(), @ParentId                
		  From  #tmpUserEnquiry               
		  Where   SourceName not in (Select [Name] from UserSourceSettings(nolock) Where IsActive=1 and Userid=@ParentId)              
              
		  INSERT INTO UserMediumSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)       
		  Select distinct MediumName, @ParentId, 1,  1, GETDATE(), GETDATE(), @ParentId                
		  From  #tmpUserEnquiry               
		  Where   MediumName not in (Select [Name] from UserMediumSettings(nolock) Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(MediumName),'') != ''              
              
		  INSERT INTO UserCampaignSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)     
		  Select distinct CampaignName, @ParentId, 1,  1, GETDATE(), GETDATE(), @ParentId                
		  From  #tmpUserEnquiry               
		  Where   CampaignName not in (Select [Name] from UserCampaignSettings(nolock) Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(CampaignName),'') != ''              
              
		  Update #tmpUserEnquiry               
		  Set SourceName=(Select top 1 SourceId From UserSourceSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=SourceName),        
		  MediumName=isnull((Select top 1 MediumID From UserMediumSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=MediumName),0),    
		  CampaignName=isnull((Select top 1 CampaignID From UserCampaignSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=CampaignName),0)              
              
		  create table #outputEnquiry(enquiryid bigint,leadno bigint)  
		  create table #outputLead(leadid bigint)  
		  create table #outputLeadInteraction(id bigint)  
		  create table #outputMergeLeadEnquiry(id bigint)  
  
		  SELECT @LastLeadId=IDENT_CURRENT('UserLeads')
		  SET Context_Info 0x55555
           
		  If(@IsAutoLeadGeneration = 1)              
		  Begin              
			   print 'AutoLeadGeneration true'    
			   Select top 1 @strAgentlst=Agents, @LastAssignedUser=isnull(LastUserAssigned,UserID) From CRMCampaignSettings(nolock) Where IsActive=1 and UserID=@ParentId              
            
			   insert into #tmptblAgentList           
			   Select value From dbo.fn_Split(@strAgentlst,'#')              
            
			   insert into #tblAgentList              
			   select AgentId from #tmptblAgentList where Sno >= isnull((Select B.Sno from #tmptblAgentList B Where B.AgentId = @LastAssignedUser),0)          
            
			   insert into #tblAgentList              
			   select AgentId from #tmptblAgentList where Sno < isnull((Select B.Sno from #tmptblAgentList B Where B.AgentId = @LastAssignedUser),0)            
            
			   Select @AgentCnt=count(*) from #tblAgentList              
              
			   print '@AgentCnt: ' + cast(@AgentCnt as varchar)               
              
			  /*
			   insert into #tmpMobileNoList              
			   select MobileNo              
			   From UserLeads(nolock)              
			   Where ParentID in (@ParentId) and isnull(ltrim(MobileNo),'') != ''              
			   union              
			   select MobileNo1              
			   From UserLeads (nolock)             
			   Where ParentID in (@ParentId) and isnull(ltrim(MobileNo1),'') != ''              
			   union              
			   select MobileNo2              
			   From UserLeads(nolock)              
			   Where ParentID in (@ParentId) and isnull(ltrim(MobileNo2),'') != ''              
              
			   insert into #tmpEmailIdList              
			   select EmailID              
			   From UserLeads (nolock)             
			   Where ParentID in (@ParentId) and isnull(ltrim(EmailID),'') != ''              
			   union              
			   select EmailID1              
			   From UserLeads   (nolock)           
			   Where ParentID in (@ParentId) and isnull(ltrim(EmailID1),'') != ''              
			   union              
			   select EmailID2              
			   From UserLeads (nolock)             
			   Where ParentID in (@ParentId) and isnull(ltrim(EmailID2),'') != ''              
              */
			   insert into #tmpConstraintChk              
			   Select  distinct Sno, 'MobileNo already present in Leads' as Remarks              
			   From              
			   (              
			   Select  Sno, ltrim(MobileNo) Mobileno             
			   From  #tmpUserEnquiry              
			   Where   ISNULL(ltrim(MobileNo),'') != ''              
			   union              
			   Select  Sno, ltrim(MobileNo1) Mobileno             
			   From  #tmpUserEnquiry              
			   Where   ISNULL(ltrim(MobileNo1),'') != ''              
			   union              
			   Select  Sno, ltrim(MobileNo2) Mobileno             
			   From  #tmpUserEnquiry              
			   Where   ISNULL(ltrim(MobileNo2),'') != ''              
			   ) A              
			   Where A.MobileNo in (Select ltrim(Mobile) From Userleads_Mobile_Email(nolock) where parentid=@ParentId and mobile<>'0')              
              
			   insert into #tmpConstraintChk              
			   Select  distinct Sno, 'EmailID already present in Leads' as Remarks              
			   From              
			   (              
			   Select  Sno, ltrim(EmailID) EmailID              
			   From  #tmpUserEnquiry              
			   Where   ISNULL(ltrim(EmailID),'') != ''              
			   union              
			   Select  Sno, ltrim(EmailID1)              
			   From  #tmpUserEnquiry              
			   Where   ISNULL(ltrim(EmailID1),'') != ''              
			   union              
			   Select  Sno, ltrim(EmailID2)              
			   From  #tmpUserEnquiry              
			   Where   ISNULL(ltrim(EmailID2),'') != ''              
			   ) A              
			   Where A.EmailID in (Select ltrim(email) From Userleads_Mobile_Email(nolock) where parentid=@ParentId and email<>'1')
                           
			   Select @NextLeadNo=Isnull(max(LeadNo),0) From UserLeads(nolock) Where ParentID=@ParentId              
			   print '@NextLeadNo: ' + cast(@NextLeadNo as varchar)    
  
			   Select @CreatedOn=getdate()      
              
			   INSERT INTO #tmpUserLeads              
				([EnquiryID], [Sno], [PersonName], [CompanyName], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], [City], [State], [Country], [CountryCode], [CountryCode1], [CountryCode2], [PinCode], [ResidentialAddress], [OfficeAddress], [AssignedTo], [SourceName], [MediumName], [CampaignName], [InitialRemarks], [ParentID], [FollowUpStatus], [NextStatusDate], [Remarks], [Products], [AmountPaid], [CreatedOn], [CreatedBy], [FollowupDate], [WhatsAppNoColName])    
			   Select  EnquiryID, Sno, PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, City, [State], Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, 0 as AssignedTo, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, 0 /*dafault*/ as FollowUpStatus, DATEADD(day,1,getdate()) as NextStatusDate, '' as Remarks, '' as Products, 0 as AmountPaid, @CreatedOn as CreatedOn, @User_Id as CreatedBy, getdate() as FollowupDate, WhatsAppNoColName
			   From  #tmpUserEnquiry              
			   Where  Sno not in (Select distinct Sno From #tmpConstraintChk)              
          
			   If(@ParentId = @User_Id)          
			   begin          
					Update A Set A.AssignedTo=B.AgentId, @LastAssignedUser=B.AgentId    
					From #tmpUserLeads A , #tblAgentList B    
					Where A.Sno%@AgentCnt=B.Sno%@AgentCnt    
					--Select top 10 * from #tmpUserLeads              
    
					If(isnull(@LastAssignedUser,0) !=0)              
					Begin              
						Update CRMCampaignSettings Set LastUserAssigned=@LastAssignedUser Where IsActive=1 and UserID=@ParentId              
					End              
			   end          
			   else          
			   begin          
					update #tmpUserLeads set AssignedTo = @User_Id;          
			   end          
          
			   If exists(Select * from #tmpUserLeads)    
			   Begin    
					declare @iStart bigint=0, @iFinish bigint=500
					While exists (select * from #tmpUserLeads where LeadNo between @iStart and @iFinish)
					Begin
					INSERT INTO [dbo].[UserLeads]              
						([LeadNo],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City], [State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo], [SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks], [Products],[AmountPaid],[CreatedOn],[CreatedBy],[FollowupDate],[enquirysource],[WhatsAppNoColName])    
						output inserted.ID as leadid into #outputLead
					Select              
						@NextLeadNo+LeadNo,[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City], [State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo], [SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks], [Products],[AmountPaid],[CreatedOn],[CreatedBy],[FollowupDate],20 as [enquirysource], [WhatsAppNoColName]    
					From    #tmpUserLeads
              
					Select @nLeadInserted+=@@ROWCOUNT
					print cast(@nLeadInserted as varchar) + ' Leads inserted'

					set @nLeadInserted_p = @nLeadInserted


					Select @iStart+=500,@iFinish+=500
					End

					If exists(Select * from #tmpUserLeads)    
					Begin    
						set @jRow = 1

						while(@jRow <= @CustomFieldsCnt)              
						begin              
							select @fieldId=t.fieldId,@fieldName=t.fieldName,@fieldtype=c.datatype 
							from #tblCustomFields t join customfields c (nolock) on c.field_ID=t.fieldId and c.ParentID=@ParentId 
							Where t.RowId=@jRow              
              
							 set @SQLString = 'insert into customfieldLeadvalue(LeadID, fieldID, fieldvalue, CreatedDate)  
							 select distinct A.ID, ' + cast(@fieldId as varchar) +     
							 ', case when '''+ cast(@fieldtype as nvarchar) +'''=''d'' and IsDate(D.[' + @fieldName + ']) = 1 then Format(cast(D.[' + @fieldName + 
							 '] as datetime),''dd-MMM-yyyy hh:mm:ss tt'') else D.[' + @fieldName + '] end, getdate() 
							 From [UserLeads](nolock) A inner join #tmpUserEnquiry B    
							 ON   A.LeadNo = B.LeadNo inner join UserEnquiry C (nolock)   
							 On  B.LeadNo = C.LeadNo inner join #tmpEnquirySrc D    
							 On  B.Sno = D.Sno    
							 Where A.[ParentID] = ' + cast(@ParentId as varchar) + ' and isnull(D.[' + @fieldName + '],'''') != '''' '    
                  
							 print 'custom field Lead @SQLString: ' + @SQLString    
              
							 exec (@SQLString)    
							 Select @nLeadCustomFieldRows+=@@ROWCOUNT    
              
							 set @jRow = @jRow + 1    
						end

						print cast(@nLeadCustomFieldRows as varchar) + ' Lead Custom Fields inserted'

						set @nLeadCustomFieldRows_p = @nLeadCustomFieldRows 

				   End    

					select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),leadid),',') From #outputLead
					declare @tli int=(select count(1) from #outputlead)
					print concat('Total leads inserted: ',@tli)
					Exec usp_ExecLeadTriggerTasks @CsvID
      
					insert into leadinteractionhistory(LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID, CreatedOn,CreatedBy,followupdate,IsAutoEntry)
					output inserted.ID into #outputLeadInteraction
					select LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID, CreatedOn,CreatedBy,followupdate,1 as IsAutoEntry
					from userleads(nolock)
					where parentid=@ParentId and createdon=@CreatedOn
             
			        select @tli=(select count(1) from #outputLeadInteraction)
			        print concat('Total lead Interactions inserted: ',@tli)
					select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),ID),',') From #outputLeadInteraction

					Exec usp_ExecLeadInteractionTriggerTasks @CsvID
              
					Update C Set C.LeadNo = B.LeadNo              
					From #tmpUserLeads A inner join [UserLeads] B  (nolock)            
					ON   A.LeadNo + @NextLeadNo = B.LeadNo inner join #tmpUserEnquiry C              
					ON   A.Sno = C.Sno              
					Where B.[ParentID] = @ParentId      
    
					Set @RowData = isnull((Select  SNo=ROW_NUMBER()Over(order by B.ID), B.PersonName, CountryCode=Case B.WhatsAppNoColName When 'MobileNo' then B.CountryCode when 'MobileNo1' then B.CountryCode1 when 'MobileNo2' then B.CountryCode2 Else '' End, MobileNo=Case B.WhatsAppNoColName When 'MobileNo' then B.MobileNo when 'MobileNo1' then B.MobileNo1 when 'MobileNo2' then B.MobileNo2 Else '' End    
					From #tmpUserLeads A inner join [UserLeads] B (nolock)    
					ON   A.LeadNo + @NextLeadNo = B.LeadNo    
					Where B.[ParentID] = @ParentId and B.WhatsAppNoColName in ('MobileNo','MobileNo1','MobileNo2') for json auto, INCLUDE_NULL_VALUES),'')    
    
					If(len(@RowData)>1)    
					Begin    
						/*INSERT INTO [MySMSConversations].[dbo].[tbl_imp_ImportRequest]    
						([FileName],[FileSizeByte],[CreatedOn],[Status],[NoOfRecord],[IsProcessed]    
						,[ImportJSON],[SourceName],[CreatedBy],[ParentId])    
						VALUES    
						('FromEnquiryAutoLead.xls',LEN(@RowData),Getdate(),'pending',0,0    
						,@RowData,0,@User_Id,@ParentId)  
						Select @ImportRequestId=SCOPE_IDENTITY()    
						*/

                            -- Build dynamic SQL query
                           SET @sqlquery = '
                              INSERT INTO [tbl_imp_ImportRequest]    
                                  ([FileName], [FileSizeByte], [CreatedOn], [Status], [NoOfRecord], [IsProcessed],    
                                   [ImportJSON], [SourceName], [CreatedBy], [ParentId])    
                              VALUES    
                                  (''FromEnquiryAutoLead.xls'', ' + CAST(LEN(@RowData) AS NVARCHAR) + ', GETDATE(), ''pending'', 0, 0,    
                                  ''' + REPLACE(@RowData, '''', '''''') + ''', 0, ' + CAST(@User_Id AS NVARCHAR) + ', ' + CAST(@ParentId AS NVARCHAR) + ');
                              ';
                              
                              -- Get the inserted ID back
                              EXEC usp_clr_InsertAndReturnId @sqlquery, @retid = @ImportRequestId OUTPUT;

						
						print N'@RowData: ' + @RowData    
						select @RecCnt=count(*) from openjson(@RowData)        
    
						While(1=1)    
						Begin    
							set @Start=@End+1    
							set @End=@Pagesize*@Pageno    
    
							Set @RowData = isnull((Select * from (Select  SNo=ROW_NUMBER()Over(order by B.ID), B.PersonName, CountryCode=Case B.WhatsAppNoColName When 'MobileNo' then B.CountryCode when 'MobileNo1' then B.CountryCode1 when 'MobileNo2' then B.CountryCode2 Else '' End, MobileNo=Case B.WhatsAppNoColName When 'MobileNo' then B.MobileNo when 'MobileNo1' then B.MobileNo1 when 'MobileNo2' then B.MobileNo2 Else '' End
							From #tmpUserLeads A inner join [UserLeads] B (nolock)    
							ON   A.LeadNo + @NextLeadNo = B.LeadNo    
							Where B.[ParentID] = @ParentId and B.WhatsAppNoColName in ('MobileNo','MobileNo1','MobileNo2')) T    
							Where T.SNo between @Start and @End    
							for json auto, INCLUDE_NULL_VALUES),'')    
    
							/*INSERT INTO [MySMSConversations].[dbo].[tbl_ims_ImportSlot]    
								([requestid],[createdon],[contactjson],[isprocessed])    
							VALUES    
								(@ImportRequestId,Getdate(),@RowData,0)   */ 
                               SET @sqlquery = '
                           INSERT INTO [tbl_ims_ImportSlot]    
                               ([requestid], [createdon], [contactjson], [isprocessed])    
                           VALUES    
                               (' + CAST(@ImportRequestId AS NVARCHAR) + ', GETDATE(), ''' + REPLACE(@RowData, '''', '''''') + ''', 0)';
                           
                           -- Execute the dynamic SQL on the remote server
                           EXEC usp_clr_ExecuteRemoteQuery @sqlquery;
                           	
							
							If(@RecCnt < (@Pageno*@Pagesize))    
							Begin    
								break    
							End    
							Else    
							Begin    
								Set @Pageno=@Pageno+1    
							End    
						End    
    
						Set @RowData = null    
					End    
			   End    
                       
			   If exists(Select * from #tmpUserEnquiry)    
			   Begin    
					SELECT @LastEnquiryId=IDENT_CURRENT('UserEnquiry')              
					
					SET Context_Info 0x77777

					INSERT INTO UserEnquiry              
					 ([PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country]    
					 ,[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName]          
					 ,[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],IsOpen,LeadNo    
					 ,[enquirysource],[WhatsAppNoColName]) 
					 output inserted.EnquiryID as enquiryid,inserted.LeadNo as leadno into #outputEnquiry              
					Select [PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country]    
					 ,[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName]          
					 ,[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],IIf(isnull(LeadNo,0)>0,0,1),LeadNo
					 ,20 as [enquirysource], [WhatsAppNoColName]    
					From #tmpUserEnquiry    
	
					Select @nEnquiriesInserted=@@ROWCOUNT
	
					print cast(@nEnquiriesInserted as varchar) + ' Enquiries inserted'

					set @nEnquiriesInserted_p = @nEnquiriesInserted

					
					-- By passing UserEnquiry Insert trigger					 
					select @enquiryCsv = STRING_AGG(Convert(NVARCHAR(MAX),enquiryid), ',') from  #outputEnquiry 					
					exec usp_ExecEnquiryTriggerTasks @enquiryCsv


					insert into tbl_MergeLeadsEnquiry(EnquiryNo,LeadNo,IsOpen)
					output inserted.ID into #outputMergeLeadEnquiry
					select enquiryid,leadno,1 as IsOpen from #outputEnquiry o
					where isnull(leadno,0)>0 and not exists
					(select 1 from tbl_MergeLeadsEnquiry(nolock) where EnquiryNo=o.enquiryid and leadno=o.leadno)
             
					select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),ID),',') From #outputMergeLeadEnquiry

					Exec usp_ExecMergeLeadEnquiryTriggerTasks @CsvID
                
			   End    
              
			  
               
		  End              
		  Else              
		  Begin    
			   print 'AutoLeadGeneration false'    
    
			   If exists(Select * from #tmpUserEnquiry)    
			   Begin    
					SELECT @LastEnquiryId=IDENT_CURRENT('UserEnquiry')              
					SET Context_Info 0x77777

					INSERT INTO UserEnquiry              
					 ([PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],[enquirysource],[WhatsAppNoColName])
					  output inserted.EnquiryID as enquiryid,0 as leadno into #outputEnquiry
					Select [PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],20 as [enquirysource], [WhatsAppNoColName]    
					From #tmpUserEnquiry              
					Select @nEnquiriesInserted=@@ROWCOUNT        
  
					print cast(@nEnquiriesInserted as varchar) + ' Enquiries inserted'

					-- By passing UserEnquiry Insert trigger					 
					select @enquiryCsv = STRING_AGG(CONVERT(NVARCHAR(max), enquiryid) , ',') from  #outputEnquiry 					
					exec usp_ExecEnquiryTriggerTasks @enquiryCsv

			   End    
		  End              
              
		  set @jRow = 1              
    
		  If exists(Select * from #tmpUserEnquiry)    
		  Begin    
			while(@jRow <= @CustomFieldsCnt)    
			begin    
				select @fieldId=t.fieldId,@fieldName=t.fieldName,@fieldtype=c.datatype 
				from #tblCustomFields t join customfields c (nolock) on c.field_ID=t.fieldId and c.ParentID=@ParentId 
				Where t.RowId=@jRow
     
    
				set @SQLString = 'insert into customfieldEnquiryvalue (EnquiryID,fieldID,fieldvalue)
				select distinct C.EnquiryID, ' + cast(@fieldId as varchar) + ', case when '''+ cast(@fieldtype as nvarchar) +'''=''d'' and IsDate(A.[' + @fieldName + ']) = 1 then Format(cast(A.[' + @fieldName + '] as datetime),''dd-MMM-yyyy hh:mm:ss tt'') else A.[' + @fieldName + '] end    
				from #tmpEnquirySrc A inner join #tmpUserEnquiry B    
				on A.Sno=B.Sno inner join UserEnquiry C (nolock)    
				on B.PersonName = C.PersonName and isnull(B.MobileNo,'''') = isnull(C.MobileNo,'''') and isnull(B.MobileNo1,'''') = isnull(C.MobileNo1,'''') and isnull(B.MobileNo2,'''') = isnull(C.MobileNo2,'''') and isnull(B.EmailID,'''') = isnull(C.EmailID,'''')    
				and isnull(B.EmailID1,'''') = isnull(C.EmailID1,'''') and isnull(B.EmailID2,'''') = isnull(C.EmailID2,'''')    
				Where C.EnquiryID > ' + cast(@LastEnquiryId as varchar) + ' and C.EnquiryID <= ' + cast(@LastEnquiryId as varchar) + ' + ' + cast(@nEnquiriesInserted as varchar) + ' and isnull(A.[' + @fieldName + '],'''') != '''' '    
    
				print 'custom field enquiry @SQLString: ' + @SQLString    
    
				exec (@SQLString)    
				select @nEnquiryCustomFieldRows+=@@ROWCOUNT    
    
				set @jRow = @jRow + 1    
			end              
			print cast(@nEnquiryCustomFieldRows as varchar) + ' Enquiry Custom Fields inserted'

		    set @nEnquiryCustomFieldRows_p = @nEnquiryCustomFieldRows


		 End    
			
		 --declare @RowData varchar(max)
		 Set @RowData = isnull((Select * From #tmpConstraintChk order by Sno for json auto, INCLUDE_NULL_VALUES),'')    
		 --select @RowData
		 print 'Final @RowData: ' + cast(@RowData as varchar(max))    
              
		 update tbl_EnquiryImportSummary    
		 set IsProcessed=1, Remarks=@RowData, EnquiryCnt=@nEnquiriesInserted, EnquiryCustomFieldCnt=@nEnquiryCustomFieldRows,
		  LeadCnt=@nLeadInserted, LeadCustomFieldCnt=@nLeadCustomFieldRows    
		 where ImportRow_Id=@ImportRow_id    
            
		 Iter:              
			Set @iRow = @iRow + 1              
			Set @ImportRow_id=0              
			Set @ImportData=null              
			Set @RowData=null              
			Set @FieldNames=''              
			Set @SQLString=null              
			Set @User_Id=0              
			Set @LastEnquiryId=0              
			Set @LastLeadId=0              
			Set @nEnquiriesInserted=0              
			Set @nEnquiryCustomFieldRows=0              
			Set @nLeadInserted=0              
			Set @nLeadCustomFieldRows=0              
			Set @jRow=1              
			Set @fieldId=0              
			Set @fieldName=''              
			Set @CustomFieldsCnt = 0              
			Set @ImportRequestId = 0     
			Set @RecCnt = 0              
			Set @Start = 0              
			Set @End = 0              
			Set @Pagesize = 500              
			Set @Pageno = 1              
              
		 truncate table #tmpUserEnquiry              
		 truncate table #tmpConstraintChk              
		 truncate table #tmpUserLeads              
		 truncate table #tmpMobileNoList              
		 truncate table #tmpEmailIdList              
		 truncate table #tblAgentList              
		 truncate table #tblCustomFields              
              
		 if object_id('tempdb..#tmpEnquirySrc') is not null begin drop table #tmpEnquirySrc end              
		 if object_id('tempdb..#outputEnquiry') is not null begin drop table #outputEnquiry end              
		 if object_id('tempdb..#outputLead') is not null begin drop table #outputLead end              
		 if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end
		 if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end
              
		End              
              
		--COMMIT TRANSACTION   
		SET Context_Info 0x 
	END TRY                  
	BEGIN CATCH                 
		SET Context_Info 0x 

		IF (XACT_STATE()) = -1  
		BEGIN  
			PRINT 'The transaction is in an uncommittable state. Rolling back transaction.'  
			ROLLBACK TRANSACTION;  
			declare @error int, @message varchar(4000)
			select @error = ERROR_NUMBER(), @message = ERROR_MESSAGE()
			raiserror ('usp_ProcessEnquiryImportData: %d: %s', 16, 1, @error, @message) 
		END;  
  
		-- Test whether the transaction is active and valid.  
		IF (XACT_STATE()) = 1  
		BEGIN  
			PRINT 'The transaction is committable. Committing transaction.'  
			COMMIT TRANSACTION;     
		END;  
   
		insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)  
		output inserted.*
		SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()    
         
		 
		 Declare @RowData1 nvarchar(max) = ''

		insert into #tmpConstraintChk              
	    Select distinct '1111111' as Sno, Concat('Contact support team Error_Number ', ERROR_NUMBER(),' ',ERROR_MESSAGE()
		                     , ' ',GETDATE()) as Remarks 
      	 Set @RowData1 = isnull((Select * From #tmpConstraintChk order by Sno for json auto, INCLUDE_NULL_VALUES),'')    
		 --select @RowData
		 print 'Final @RowData: ' + cast(@RowData1 as varchar(max))    
              
	    update tbl_EnquiryImportSummary    
		   set IsProcessed=1, Remarks=@RowData1, EnquiryCnt=@nEnquiriesInserted_p, EnquiryCustomFieldCnt=@nEnquiryCustomFieldRows_p,
		    LeadCnt=@nLeadInserted_p, LeadCustomFieldCnt=@nLeadCustomFieldRows_p    
		  where ImportRow_Id=@ImportRow_id_p   

 	END CATCH                  
              
	if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end              
	if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end              
	if object_id('tempdb..#tmptblAgentList') is not null begin drop table #tmptblAgentList end              
	if object_id('tempdb..#tblAgentList') is not null begin drop table #tblAgentList end              
	if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end      
	if object_id('tempdb..#tblAllEnquiryFields') is not null begin drop table #tblAllEnquiryFields end              
	if object_id('tempdb..#tmpEnquirySrc') is not null begin drop table #tmpEnquirySrc end              
	if object_id('tempdb..#tmpUserEnquiry') is not null begin drop table #tmpUserEnquiry end              
	if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end              
	if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end              
	if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end
	if object_id('tempdb..#outputEnquiry') is not null begin drop table #outputEnquiry end              
	if object_id('tempdb..#outputLead') is not null begin drop table #outputLead end              
	if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end
	if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end

END



GO

