     INSERT INTO [dbo].[UserLeads]                
      ([LeadNo],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City], [State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo], [SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks], [Products],[AmountPaid],[CreatedOn],[CreatedBy],[FollowupDate],[enquirysource],[WhatsAppNoColName])      
      output inserted.ID as leadid,inserted.leadno as leadno into #outputLead  
     Select                
      @NextLeadNo+LeadNo,[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City], [State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo], [SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks], [Products],[AmountPaid],[CreatedOn],[CreatedBy],[NextStatusDate],20 as [enquirysource], [WhatsAppNoColName]      
     From    #tmpUserLeads where LeadNo between @iStart and @iFinish  
     
	-- SET NOCOUNT ON;
     Select @nLeadInserted+=isnull(@@ROWCOUNT,0)  
     print cast(@nLeadInserted as varchar) + ' Leads inserted' + ' -------' + convert(varchar, getdate(), 113) + '------- '  
  
