     select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),leadid),',') From #outputLead  
     declare @tli int=(select count(1) from #outputlead),@ol_id bigint=(select min(leadid) from #outputlead)  
     print concat('Total leads inserted: ',@tli) + ' -------' + convert(varchar, getdate(), 113) + '------- '  
  
     Exec usp_ExecLeadTriggerTasks @CsvID  
  
           print ' A9 -------' + convert(varchar, getdate(), 113) + '------- '  
     
