     output inserted.ID into #outputLeadInteraction  
     select u.LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID, CreatedOn,CreatedBy,NextStatusDate,1 as IsAutoEntry,id  
