     print concat('lead interaction records added: ',@ol_id) + ' -------' + convert(varchar, getdate(), 113) + '------- '  
  
                    end  
           select @tli=(select count(1) from #outputLeadInteraction)  
           print concat('Total lead Interactions inserted: ',@tli) + ' -------' + convert(varchar, getdate(), 113) + '------- '  
  
     --select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),ID),',') From #outputLeadInteraction  
  
     print ' A11 -------' + convert(varchar, getdate(), 113) + '------- '  
  
     --Exec usp_ExecLeadInteractionTriggerTasks @CsvID  
