     declare @e_cnt int=(select count(1) from #tmpUserEnquiry),@ts_snomin int,@ts_snomax int  
     select @ts_snomin=min(sno),@ts_snomax=max(sno) from #tmpUserEnquiry  

	 SET NOCOUNT ON;
     while @e_cnt>0 or @ts_snomin<@ts_snomax  
     begin  
      print ' A18 -------' + convert(varchar, getdate(), 113) + '------- ' + cast(@e_cnt as varchar)  
      print concat('Before insert: @e_cnt: ',@e_cnt,', @ts_snomin: ',@ts_snomin,', @ts_snomax: ',@ts_snomax)
     INSERT INTO UserEnquiry                
      ([PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],IsOpen,LeadNo,[enquirysource],[WhatsAppNoColName])   
      output inserted.EnquiryID as enquiryid,inserted.LeadNo as leadno into #outputEnquiry                
     Select top 500 [PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],IIf(isnull(u.LeadNo,0)>0,0,1),u.LeadNo,20 as [enquirysource], [WhatsAppNoColName]      
     From #tmpUserEnquiry u where u.sno>=@ts_snomin order by sno  
     
	 --SET NOCOUNT ON;
