     while(@jRow <= @CustomFieldsCnt)                
     begin                
      print ' A24 -------' + convert(varchar, getdate(), 113) + '------- for ' + cast(@jRow as varchar)  
      select @fieldId=t.fieldId,@fieldName=t.fieldName,@fieldtype=c.datatype   
      from #tblCustomFields t join customfields c (nolock) on c.field_ID=t.fieldId and c.ParentID=@ParentId   
      Where t.RowId=@jRow                
                
       set @SQLString = 'insert into customfieldLeadvalue(LeadID,EnquiryID,fieldID,fieldvalue,CreatedDate)    
       select distinct A.ID, C.EnquiryID, ' + cast(@fieldId as varchar) +       
       ', case when '''+ cast(@fieldtype as nvarchar) +'''=''d'' and IsDate(D.[' + @fieldName + ']) = 1 then Format(cast(D.[' + @fieldName +   
       '] as datetime),''dd-MMM-yyyy hh:mm:ss tt'') else D.[' + @fieldName + '] end, getdate()   
       From [UserLeads](nolock) A inner join #tmpUserEnquiry B      
       ON   A.LeadNo = B.LeadNo inner join UserEnquiry C (nolock)     
       On  B.LeadNo = C.LeadNo inner join #tmpEnquirySrc D      
       On  B.Sno = D.Sno      
       Where A.[ParentID] = ' + cast(@ParentId as varchar) + ' and isnull(D.[' + @fieldName + '],'''') != '''' '      
                    
       print 'custom field Lead @SQLString: ' + @SQLString      
                
       exec (@SQLString)
	   --SET NOCOUNT ON;
       Select @nLeadCustomFieldRows+=isnull(@@ROWCOUNT ,0)     
                
       set @jRow = @jRow + 1      
     end  
  
     print cast(@nLeadCustomFieldRows as varchar) + ' Lead Custom Fields inserted' + ' -------' + convert(varchar, getdate(), 113) + '------- '  
  
     --- Changin as per is_processed status to 0   
     update lr set lr.is_processed = 0   
     from UserLeads(nolock)  ul   
      inner join #tmpUserLeads tl on ul.LeadNo = tl.LeadNo and ul.ParentID = tl.ParentID  
      inner join tbl_las_LeadRequest(nolock) lr on ul.ID = lr.leadid and ul.ParentID = lr.parentid  
     where ul.ID = lr.leadid and lr.is_processed = 10  
  
      End      
                 
    End                
    Else                
    Begin      
      print 'AutoLeadGeneration false' + ' -------' + convert(varchar, getdate(), 113) + '------- '  
    
      
      If exists(Select * from #tmpUserEnquiry)      
      Begin      
     SELECT @LastEnquiryId=IDENT_CURRENT('UserEnquiry')                
    -- declare @et_cnt int=(select count(1) from #tmpUserEnquiry),@se_no int=0  
      declare @et_cnt int,@se_no int=0  
	  select @et_cnt=count(1),@se_no=min(sno) from #tmpUserEnquiry
     while @et_cnt>0  
     begin  
     SET Context_Info 0x77777  
  
  print concat(' A25 -------' + convert(varchar, getdate(), 113) + '-------  Importing enquiries from ',isnull(@se_no,0),' to ', isnull(@se_no,0)+499, ', to be imported yet: ',isnull(@et_cnt,0))   
    
	--Select top 10 *
 --    From #tmpUserEnquiry t (nolock) where t.sno between @se_no and @se_no+499               
     
  SET NOCOUNT ON;
     INSERT INTO UserEnquiry                
      ([PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],[enquirysource],[WhatsAppNoColName])  
       output inserted.EnquiryID as enquiryid,0 as leadno into #outputEnquiry  
     Select  [PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],20 as [enquirysource], [WhatsAppNoColName]      
     From #tmpUserEnquiry t (nolock) where t.sno between @se_no and @se_no+499             
     
	 --SET NOCOUNT ON;
	 Select @nEnquiriesInserted=isnull(@@ROWCOUNT,0)          
     select @tEnquiriesInserted+=@nEnquiriesInserted  
     print cast(@nEnquiriesInserted as varchar) + ' Enquiries inserted' + ' -------' + convert(varchar, getdate(), 113) + '------- '  
     set @se_no=@se_no+500  
     set @et_cnt=@et_cnt-500
	 SET NOCOUNT OFF;
     end  
     -- By passing UserEnquiry Insert trigger        
     select @enquiryCsv = STRING_AGG(CONVERT(NVARCHAR(max), enquiryid) , ',') from  #outputEnquiry  
  
     print ' A26 -------' + convert(varchar, getdate(), 113) + '------- '  
       
     exec usp_ExecEnquiryTriggerTasks_multi_bulk_DBA @enquiryCsv  
  
     print ' A27 -------' + convert(varchar, getdate(), 113) + '------- '  
  
      End      
    End                
                
    set @jRow = 1                
  
    print ' A28 -------' + convert(varchar, getdate(), 113) + '------- '  
      
    If exists(Select * from #tmpUserEnquiry)      
    Begin      
     print ' A29 -------' + convert(varchar, getdate(), 113) + '------- '  
  
   while(@jRow <= @CustomFieldsCnt)      
   begin      
     print ' A30 -------' + convert(varchar, getdate(), 113) + '------- for ' + cast(@jRow as varchar)  
  
    select @fieldId=t.fieldId,@fieldName=t.fieldName,@fieldtype=c.datatype   
    from #tblCustomFields t join customfields c (nolock) on c.field_ID=t.fieldId and c.ParentID=@ParentId   
    Where t.RowId=@jRow  
       
      
    set @SQLString = 'insert into customfieldEnquiryvalue (EnquiryID,fieldID,fieldvalue)  
    select distinct C.EnquiryID, ' + cast(@fieldId as varchar) + ', case when '''+ cast(@fieldtype as nvarchar) +'''=''d'' and IsDate(A.[' + @fieldName + ']) = 1 then Format(cast(A.[' + @fieldName + '] as datetime),''dd-MMM-yyyy hh:mm:ss tt'') else A.[' + @fieldName + '] end      
    from #tmpEnquirySrc A inner join #tmpUserEnquiry B      
    on A.Sno=B.Sno inner join UserEnquiry C (nolock)      
    on B.PersonName = C.PersonName and isnull(B.MobileNo,'''') = isnull(C.MobileNo,'''') and isnull(B.MobileNo1,'''') = isnull(C.MobileNo1,'''') and isnull(B.MobileNo2,'''') = isnull(C.MobileNo2,'''') and isnull(B.EmailID,'''') = isnull(C.EmailID,'''')
    and isnull(B.EmailID1,'''') = isnull(C.EmailID1,'''') and isnull(B.EmailID2,'''') = isnull(C.EmailID2,'''')
    Where C.EnquiryID > ' + cast(@LastEnquiryId as varchar) + ' and C.EnquiryID <= ' + cast(@LastEnquiryId as varchar) + ' + ' + cast(@tEnquiriesInserted as varchar) + ' and isnull(A.[' + @fieldName + '],'''') != '''' '      
      
    print 'custom field enquiry @SQLString: ' + @SQLString      
      
    exec (@SQLString)      
	--SET NOCOUNT ON;
    select @nEnquiryCustomFieldRows+=isnull(@@ROWCOUNT,0)      
      
    set @jRow = @jRow + 1      
   end                
   print cast(@nEnquiryCustomFieldRows as varchar) + ' Enquiry Custom Fields inserted' + ' -------' + convert(varchar, getdate(), 113) + '------- '  
  
   End      
  
   print ' A31 -------' + convert(varchar, getdate(), 113) + '------- '  
     
   --declare @RowData varchar(max)  
   Set @RowData = isnull((Select * From #tmpConstraintChk order by Sno for json auto, INCLUDE_NULL_VALUES),'')      
   --select @RowData  
   print 'Final @RowData: ' + cast(@RowData as varchar(max))      
  
   print ' A32 -------' + convert(varchar, getdate(), 113) + '------- '  
                
   update tbl_EnquiryImportSummary      
   set IsProcessed=1,importend=getdate(), Remarks=@RowData, EnquiryCnt=@tEnquiriesInserted, EnquiryCustomFieldCnt=@nEnquiryCustomFieldRows,  
    LeadCnt=@nLeadInserted, LeadCustomFieldCnt=@nLeadCustomFieldRows      
   where ImportRow_Id=@ImportRow_id      
  
    print ' A33 -------' + convert(varchar, getdate(), 113) + '------- '  
             
   Iter:                
   Set @iRow = @iRow + 1                
   Set @ImportRow_id=0                
   Set @ImportData=null                
   Set @RowData=null                
   Set @FieldNames=''                
   Set @SQLString=null                
   Set @User_Id=0                
   Set @LastEnquiryId=0                
   Set @LastLeadId=0                
   Set @nEnquiriesInserted=0                
   Set @nEnquiryCustomFieldRows=0                
   Set @nLeadInserted=0                
   Set @nLeadCustomFieldRows=0                
   Set @jRow=1                
   Set @fieldId=0                
   Set @fieldName=''                
   Set @CustomFieldsCnt = 0                
   Set @ImportRequestId = 0       
   Set @RecCnt = 0                
   Set @Start = 0                
   Set @End = 0                
   Set @Pagesize = 500                
   Set @Pageno = 1                
                
   truncate table #tmpUserEnquiry                
   truncate table #tmpConstraintChk                
   truncate table #tmpUserLeads                
   truncate table #tmpMobileNoList                
   truncate table #tmpEmailIdList                
   truncate table #tblAgentList      
   truncate table #tblCustomFields                
                
   if object_id('tempdb..#tmpEnquirySrc') is not null begin drop table #tmpEnquirySrc end                
   if object_id('tempdb..#outputEnquiry') is not null begin drop table #outputEnquiry end                
   if object_id('tempdb..#outputLead') is not null begin drop table #outputLead end                
   if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end  
   if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end  
  
   print ' A34 -------' + convert(varchar, getdate(), 113) + '------- '  
                
  End                
                
  --COMMIT TRANSACTION     
  SET Context_Info 0x   
 END TRY                    
 BEGIN CATCH                   
  SET Context_Info 0x   
  
  IF (XACT_STATE()) = -1    
  BEGIN    
   PRINT 'The transaction is in an uncommittable state. Rolling back transaction.'    
   ROLLBACK TRANSACTION;    
   declare @error int, @message varchar(4000)  
   select @error = ERROR_NUMBER(), @message = ERROR_MESSAGE()  
   raiserror ('usp_ProcessEnquiryImportData: %d: %s', 16, 1, @error, @message)   
  END;    
    
  -- Test whether the transaction is active and valid.    
  IF (XACT_STATE()) = 1    
  BEGIN    
   PRINT 'The transaction is committable. Committing transaction.'    
   COMMIT TRANSACTION;       
  END;    
     
  insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)    
  output inserted.*  
  SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()      
  END CATCH                    
                
 if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end                
 if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end                
 if object_id('tempdb..#tmptblAgentList') is not null begin drop table #tmptblAgentList end                
 if object_id('tempdb..#tblAgentList') is not null begin drop table #tblAgentList end                
 if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end        
 if object_id('tempdb..#tblAllEnquiryFields') is not null begin drop table #tblAllEnquiryFields end                
 if object_id('tempdb..#tmpEnquirySrc') is not null begin drop table #tmpEnquirySrc end                
 if object_id('tempdb..#tmpUserEnquiry') is not null begin drop table #tmpUserEnquiry end                
 if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end                
 if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end                
 if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end  
 if object_id('tempdb..#outputEnquiry') is not null begin drop table #outputEnquiry end                
 if object_id('tempdb..#outputLead') is not null begin drop table #outputLead end                
 if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end  
 if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end  
  
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ProcessEnquiryImportData_PM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--Dependency of this usp_ProcessEnquiryImportData_PM

--1.[MySMSConversations].[dbo].[tbl_imp_ImportRequest]       -- called by clr
--2. usp_ProcessEnquiryImportData_corrected  -- called by clr 

-------------------------------------




-- Exec usp_ProcessEnquiryImportData 0, 'P'            
-- Exec usp_ProcessEnquiryImportData 1, 'P'            
-- Exec usp_ProcessEnquiryImportData 1, 'P', 1743           
CREATE   PROC [dbo].[usp_ProcessEnquiryImportData_PM]              
(              
    @BatchSize int=1,  -- 0 ('All')              
    @Mode varchar(1)='P',    -- 'P'riority, 'F'ifo    
	@IPRId bigint=0    
)              
AS              
BEGIN              
-- declare @BatchSize int=1,@Mode varchar(1)='P', @IPRId bigint=1742    
        DECLARE @sqlquery NVARCHAR(MAX);        
	if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end              
	if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end              
	if object_id('tempdb..#tblAgentList') is not null begin drop table #tblAgentList end              
	if object_id('tempdb..#tmptblAgentList') is not null begin drop table #tmptblAgentList end              
	if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end              
	if object_id('tempdb..#tblAllEnquiryFields') is not null begin drop table #tblAllEnquiryFields end              
	if object_id('tempdb..#tmpEnquirySrc') is not null begin drop table #tmpEnquirySrc end              
	if object_id('tempdb..#tmpUserEnquiry') is not null begin drop table #tmpUserEnquiry end              
	if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end              
	if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end              
	if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end              
	if object_id('tempdb..#outputEnquiry') is not null begin drop table #outputEnquiry end              
	if object_id('tempdb..#outputLead') is not null begin drop table #outputLead end              
	if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end              
	if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end              
              
	Create table #tblImportRowId
	(              
		RowId int identity,              
		ImportRow_id bigint,              
		[User_Id] bigint,              
		IsAutoLeadGeneration bit              
	)              
              
	create table #tmpConstraintChk
	(              
		Sno int,              
		Remarks varchar(200)              
	)              
              
	create table #tmptblAgentList
	(              
		Sno int IDENTITY(1,1),               
		AgentId bigint              
	)              
              
	create table #tblAgentList
	(              
		Sno int IDENTITY(1,1),               
		AgentId bigint              
	)              
              
	create table #tblCustomFields
	(              
		RowId int identity(1,1),              
		fieldId bigint,              
		fieldName varchar(50)              
	)              
              
	create table #tblAllEnquiryFields
	(            
	 RowId int identity(1,1),            
	 fieldName varchar(50),            
	 FieldType varchar(10)            
	)            
            
	create table #tmpMobileNoList
	(              
		RowId int identity,              
		MobileNo varchar(100)              
	)              
              
	create table #tmpEmailIdList
	(              
		RowId int identity,              
		EmailId varchar(100)              
	)              
              
	CREATE TABLE #tmpUserEnquiry
	(              
	 [EnquiryID] [bigint] IDENTITY(1,1) NOT NULL,              
	 [Sno] [int] NOT NULL,              
	 [PersonName] [nvarchar](200) NULL,              
	 [CompanyName] [nvarchar](500) NULL,              
	 [MobileNo] [varchar](100) NULL,              
	 [MobileNo1] [varchar](100) NULL,              
	 [MobileNo2] [varchar](100) NULL,              
	 [EmailID] [varchar](100) NULL,              
	 [EmailID1] [varchar](100) NULL,              
	 [EmailID2] [varchar](100) NULL,              
	 [City] [varchar](100) NULL,              
	 [State] [varchar](100) NULL,              
	 [Country] [varchar](100) NULL,              
	 [CountryCode] [varchar](50) NULL,              
	 [CountryCode1] [varchar](50) NULL,              
	 [CountryCode2] [varchar](50) NULL,              
	 [PinCode] [bigint] NULL,              
	 [ResidentialAddress] [varchar](500) NULL,          
	 [OfficeAddress] [varchar](500) NULL,              
	 [SourceName] [varchar](100) NOT NULL,              
	 [MediumName] [varchar](100) NOT NULL,              
	 [CampaignName] [varchar](100) NOT NULL,              
	 [InitialRemarks] [varchar](1000) NULL,              
	 [ParentID] [bigint] NOT NULL,              
	 [CreatedDate] [datetime] NOT NULL,              
	 [CreatedBy] [bigint] NULL,              
	 [IsOpen] [bit] NOT NULL DEFAULT ((1)),              
	 [LeadNo] [int] NULL,    
	 [WhatsAppNoColName] varchar(10)    
	)              
              
	CREATE TABLE #tmpUserLeads 
	(         
	 [LeadNo] [bigint] IDENTITY(1,1) NOT NULL,              
	 [EnquiryID] [bigint] NOT NULL,              
	 [Sno] [int] NOT NULL,              
	 [PersonName] [nvarchar](200) NULL,              
	 [CompanyName] [nvarchar](500) NULL,              
	 [MobileNo] [varchar](100) NULL,              
	 [MobileNo1] [varchar](100) NULL,              
	 [MobileNo2] [varchar](100) NULL,              
	 [EmailID] [varchar](100) NULL,              
	 [EmailID1] [varchar](100) NULL,              
	 [EmailID2] [varchar](100) NULL,              
	 [City] [varchar](100) NULL,              
	 [State] [varchar](100) NULL,              
	 [Country] [varchar](100) NULL,              
	 [CountryCode] [varchar](50) NULL,              
	 [CountryCode1] [varchar](50) NULL,              
	 [CountryCode2] [varchar](50) NULL,              
	 [PinCode] [bigint] NULL,              
	 [ResidentialAddress] [varchar](500) NULL,              
	 [OfficeAddress] [varchar](500) NULL,              
	 [AssignedTo] [bigint] NOT NULL,              
	 [SourceName] [bigint] DEFAULT ((0)) NOT NULL,              
	 [MediumName] [bigint] DEFAULT ((0)) NULL,              
	 [CampaignName] [bigint] DEFAULT ((0)) NULL,              
	 [InitialRemarks] [varchar](1000) NULL,              
	 [ParentID] [bigint] NOT NULL,              
	 [FollowUpStatus] [int] NULL,              
	 [NextStatusDate] [varchar](50) NULL,              
	 [Remarks] [varchar](1000) NULL,              
	 [Products] [varchar](1000) NULL,              
	 [AmountPaid] [numeric](18, 2) NOT NULL DEFAULT ((0)),              
	 [CreatedOn] [datetime] NULL,              
	 [CreatedBy] [bigint] NULL,              
	 [FollowupDate] [datetime] NULL,    
	 [WhatsAppNoColName] varchar(10)    
	)              

	SET XACT_ABORT ON;

	BEGIN TRY              
		--BEGIN TRANSACTION              
    
		If(isnull(@IPRId,0) > 0)    
		Begin    
			insert into #tblImportRowId    
			Select ImportRow_id,[User_Id],IsAutoLeadGeneration From tbl_EnquiryImportSummary(nolock) where ImportRow_id=@IPRId    
		End    
		Else    
		Begin    
			If(@Mode = 'P')
			Begin              
				If(@BatchSize != 0)
				Begin              
					insert into #tblImportRowId              
					Select top (@BatchSize) ImportRow_id,[User_Id],IsAutoLeadGeneration 
					From tbl_EnquiryImportSummary(nolock) where IsProcessed=0 order by [Priority]              
				End              
				Else              
				Begin              
					insert into #tblImportRowId              
					Select ImportRow_id,[User_Id],IsAutoLeadGeneration     
					From tbl_EnquiryImportSummary(nolock) where IsProcessed=0 order by [Priority]              
				End
			End    
			Else -- Fifo    
			Begin              
				If(@BatchSize != 0)
				Begin    
					insert into #tblImportRowId    
					Select top (@BatchSize) ImportRow_id,[User_Id],IsAutoLeadGeneration From tbl_EnquiryImportSummary(nolock) where IsProcessed=0    
				End    
				Else    
				Begin    
					insert into #tblImportRowId    
					Select ImportRow_id,[User_Id],IsAutoLeadGeneration From tbl_EnquiryImportSummary(nolock) where IsProcessed=0    
				End    
			End              
		End    
              
		declare @iRow int=1, @jRow int=1, @ImportRow_id bigint=0, @UnProcessedRowCnt int=0, @User_Id bigint=0, @LastEnquiryId bigint=0, @nEnquiriesInserted bigint=0, @LastLeadId bigint=0, @nLeadInserted bigint=0, @fieldId bigint=0, @nEnquiryCustomFieldRows bigint=0, @nLeadCustomFieldRows bigint=0, @ParentId bigint=0, @CreatedOn datetime, @CsvID nvarchar(max)
		declare @ImportData nvarchar(max), @RowData nvarchar(max), @FieldNames nvarchar(max)='', @SQLString nvarchar(max)='', @ParmDefinition nvarchar(500), @fieldName varchar(50)='',@fieldtype nvarchar(20);
		declare @IsAutoLeadGeneration bit=0, @strAgentlst nvarchar(max), @LastAssignedUser int, @NextLeadNo bigint=0, @AgentCnt int=0, @CustomFieldsCnt int=0, @ImportRequestId bigint=0, @RecCnt int =0, @Pagesize int=500, @Pageno int=1, @Start int=0, @End int=0    
              
		select @UnProcessedRowCnt=Count(*) from #tblImportRowId              
              
		While(@iRow <= @UnProcessedRowCnt)              
		Begin
		  print '@iRow: ' + cast(@iRow as varchar)              
		  Select @ImportRow_id=ImportRow_id,@User_Id=[User_Id],@IsAutoLeadGeneration=IsAutoLeadGeneration From #tblImportRowId Where RowId=@iRow    
		  print '@ImportRow_id: ' + cast(@ImportRow_id as varchar)              
		  Select @ImportData=ImportData from tbl_EnquiryImportSummary(nolock) where ImportRow_Id=@ImportRow_id              
		  print '@ImportData: ' + @ImportData              
		  select top 1 @RowData=value from openjson(@ImportData)              
		  print '@RowData: ' + @RowData              
		  select @FieldNames=@FieldNames+'['+[Key]+'] nvarchar(1000),' from openjson(@RowData)              
		  print '@FieldNames1: ' + @FieldNames

		  If (CHARINDEX('WhatsAppNoColName',@FieldNames,0) > 0)    
		  Begin    
			print 'WhatsAppNoColName found'    
			set @FieldNames=SUBSTRING(@FieldNames,1,len(@FieldNames)-1)          
		  End    
		  Else    
		  Begin    
			print 'WhatsAppNoColName not found, adding dummy'    
			select @FieldNames=@FieldNames+' [WhatsAppNoColName] varchar(10)'    
			select @RowData=replace(@RowData,'}',',"WhatsAppNoColName":null}')    
		  End    
		  print '@FieldNames2: ' + @FieldNames              
              
		  Select @ParentId = dbo.ufn_GetUserParentId(@User_Id)              
            
		  insert into #tblAllEnquiryFields
		  values ('Sno','Main'),('PersonName','Main'),('CompanyName','Main'),('MobileNo','Main'),('MobileNo1','Main'),('MobileNo2','Main'), ('EmailID','Main'),('EmailID1','Main'),('EmailID2','Main'),('City','Main'),('State','Main'),('Country','Main'), ('CountryCode','Main'),('CountryCode1','Main'),('CountryCode2','Main'),('PinCode','Main'),('ResidentialAddress','Main'), ('OfficeAddress','Main'),('SourceName','Main'),('MediumName','Main'),('CampaignName','Main'),('InitialRemarks','Main'), ('WhatsAppNoColName','Main')    
         
		  insert into #tblAllEnquiryFields
		  select fieldname,'Custom'            
		  from customfields(nolock)                 
		  where parentId=@ParentId and isActive=1            
            
		  Update tbl_EnquiryImportSummary Set IsProcessed=1, Remarks='[{"Sno":0,"Remarks":"Under Process Queue"}]' Where ImportRow_Id = @ImportRow_id    
    
		  if exists(select [Key] from openjson(@RowData) where [Key] COLLATE SQL_Latin1_General_CP1_CI_AS not in (Select FieldName From #tblAllEnquiryFields))    
		  Begin            
			print 'Invalid Field found in Import Data'    
			Update tbl_EnquiryImportSummary Set IsProcessed=1, Remarks='[{"Sno":0,"Remarks":"Invalid Field found in Import Data"}]'     
			Where ImportRow_Id = @ImportRow_id    
			goto Iter    
		  End            
		  Else            
		  Begin    
			If exists(Select FieldName From #tblAllEnquiryFields Where FieldName COLLATE SQL_Latin1_General_CP1_CI_AS not in (select [Key] from openjson(@RowData)))    
			Begin    
				print 'Required Field Missing in Import Data'    
				Update tbl_EnquiryImportSummary Set IsProcessed=1, Remarks='[{"Sno":0,"Remarks":"Required Field Missing in Import Data"}]'     
				Where ImportRow_Id = @ImportRow_id    
				goto Iter    
			End            
		  End            
            
		  create table #tmpEnquirySrc (id int identity);              
		  print 'alter table #tmpEnquirySrc add ' + @FieldNames              
		  exec('alter table #tmpEnquirySrc add ' + @FieldNames)              
              
		  --Set @SQLString = N'select * into ##tmpEnquirySrc from openjson(''' + @ImportData + ''') with (''' + @FieldNames + ''')'              
		  --Set @SQLString = N'select * into ##tmpEnquirySrc from openjson(@ImptData) with (@FldNames)'               
              
		  Set @SQLString = N'insert into #tmpEnquirySrc select * from openjson(@ImptData) with (' + @FieldNames + ')'               
		  --Set @SQLString = N'insert into #tmpEnquirySrc select * from openjson(@ImptData) with (' + @FieldNames + ') where [Sno] is not null'               
		  --Set @SQLString = N'insert into #tmpEnquirySrc select * from openjson(@ImptData) with (' + @FieldNames + ') where [PersonName] is not null and ([MobileNo] is not null and [CountryCode] is not null or [EmailID] is not null) and [CountryCode] is not null and [SourceName] is not null'               
              
		  --SET @ParmDefinition = N'@ImptData nvarchar(max), @FldNames nvarchar(max)';                
		  SET @ParmDefinition = N'@ImptData nvarchar(max)';                
                
		  print @SQLString              
              
		  --EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData, @FldNames=@FieldNames                
		  EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData                
              
		  update #tmpEnquirySrc    
		  set MobileNo=rtrim(ltrim(case when isnull(MobileNo,'')='' and isnull(MobileNo1,'')!='' then MobileNo1 else Isnull(MobileNo,'') end)),    
		  MobileNo1=rtrim(ltrim(case when isnull(MobileNo1,'')='' and isnull(MobileNo2,'')!='' then MobileNo2 else Isnull(MobileNo1,'') end)),    
		  MobileNo2=rtrim(ltrim(isnull(MobileNo2,''))),              
		  CountryCode=rtrim(ltrim(case when isnull(CountryCode,'')='' and isnull(CountryCode1,'')!='' then iif(left(ltrim(CountryCode1),1) != '+','+'+ltrim(CountryCode1),CountryCode1) else iif(left(ltrim(Isnull(CountryCode,'')),1) != '+'       
		  and ltrim(Isnull(CountryCode,'')) != '', '+' + ltrim(Isnull(CountryCode,'')),Isnull(CountryCode,'')) end)),              
		  CountryCode1=rtrim(ltrim(case when isnull(CountryCode1,'')='' and isnull(CountryCode2,'')!='' then iif(left(ltrim(CountryCode2),1) != '+','+'+ltrim(CountryCode2),CountryCode2) else iif(left(ltrim(Isnull(CountryCode1,'')),1) != '+'       
		  and ltrim(Isnull(CountryCode1,'')) != '', '+' + ltrim(Isnull(CountryCode1,'')),Isnull(CountryCode1,'')) end)),              
		  CountryCode2=rtrim(ltrim(iif(left(ltrim(isnull(CountryCode2,'')),1) != '+' and ltrim(isnull(CountryCode2,'')) != '','+' + ltrim(isnull(CountryCode2,'')),Isnull(CountryCode2,'')))),              
		  EmailID=rtrim(ltrim(case when isnull(EmailID,'')='' and isnull(EmailID1,'')!='' then EmailID1 else Isnull(EmailID,'') end)),              
		  EmailID1=rtrim(ltrim(case when isnull(EmailID1,'')='' and isnull(EmailID2,'')!='' then EmailID2 else Isnull(EmailID1,'') end)),    
		  EmailID2=rtrim(ltrim(isnull(EmailID2,''))),              
		  PersonName=rtrim(ltrim(isnull(PersonName,''))),              
		  InitialRemarks=rtrim(ltrim(isnull(InitialRemarks,''))),              
		  SourceName=rtrim(ltrim(isnull(SourceName,''))),              
		  MediumName=rtrim(ltrim(isnull(MediumName,''))),              
		  CampaignName=rtrim(ltrim(isnull(CampaignName,''))),              
		  WhatsAppNoColName=rtrim(ltrim(isnull(WhatsAppNoColName,''))),              
		  Sno=rtrim(ltrim(isnull(Sno,0)))              
              
			 --EXEC('select * from #tmpEnquirySrc')              
              
		  insert into #tmpConstraintChk              
		  Select  Sno, 'Duplicate Records' as Remarks              
		  From              
		  (              
		  select ROW_NUMBER()over(partition by PersonName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, InitialRemarks order by cast(Sno as int)) as Rid, *              
		  from #tmpEnquirySrc              
		  ) B              
		  Where B.Rid > 1              
                                
		  insert into #tblCustomFields              
		  select field_ID, fieldname               
		  from customfields(nolock)               
		  where parentId=@ParentId and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select FieldName from #tblAllEnquiryFields where [FieldType] = 'Custom')              
			 /*where parentId=dbo.ufn_GetUserParentId(@User_Id) and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select [Key]    
			from openjson(@RowData) where [Key] not in ('Sno', 'PersonName', 'CompanyName', 'MobileNo', 'MobileNo1', 'MobileNo2', 'EmailID', 'EmailID1', 'EmailID2', 'City', 'State', 'Country', 'CountryCode', 'CountryCode1', 'CountryCode2', 'PinCode', 'ResidentialAddress', 'OfficeAddress', 'SourceName', 'MediumName', 'CampaignName', 'InitialRemarks', 'ProfileImgFileName'))*/              
              
		  Select @CustomFieldsCnt=count(*) From #tblCustomFields              
              
		  insert into #tmpConstraintChk              
		  Select  Sno, 'Sno missing' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   ISNULL(ltrim(Sno),'') = '' or ISNULL(ltrim(Sno),'0') = '0'              
		  union              
		  Select  Sno, 'Sno Duplicate' as Remarks              
		  From    #tmpEnquirySrc              
		  group by Sno              
		  having  Count(*) > 1              
		  union              
		  Select  Sno, 'PersonName missing' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   ISNULL(ltrim(PersonName),'') = ''              
		  union              
		  Select  Sno, 'Contact details missing' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   ISNULL(ltrim(MobileNo),'') = '' and ISNULL(ltrim(MobileNo1),'') = '' and ISNULL(ltrim(MobileNo2),'') = '' and               
		  ISNULL(ltrim(EmailID),'') = '' and ISNULL(ltrim(EmailID1),'') = '' and ISNULL(ltrim(EmailID2),'') = ''              
		  union              
		  Select  Sno, 'MobileNo or CountryCode missing' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   ((ISNULL(ltrim(MobileNo),'')!='' and ISNULL(ltrim(CountryCode),'')='') or (ISNULL(ltrim(MobileNo),'')='' and ISNULL(ltrim(CountryCode),'')!=''))              
			 or              
		  ((ISNULL(ltrim(MobileNo1),'')!='' and ISNULL(ltrim(CountryCode1),'')='') or (ISNULL(ltrim(MobileNo1),'')='' and ISNULL(ltrim(CountryCode1),'')!='')) or              
		  ((ISNULL(ltrim(MobileNo2),'')!='' and ISNULL(ltrim(CountryCode2),'')='') or (ISNULL(ltrim(MobileNo2),'')='' and ISNULL(ltrim(CountryCode2),'')!=''))              
		  union              
		  Select  Sno, 'SourceName missing' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   ISNULL(ltrim(SourceName),'') = ''              
		  union              
		  Select  Sno, 'PersonName Length exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(PersonName)>100              
		  union              
		  Select  Sno, 'CompanyName exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(CompanyName)>100              
		  union              
		  Select  Sno, 'MobileNo exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(MobileNo)>100              
		  union              
		  Select  Sno, 'MobileNo1 exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(MobileNo1)>100              
		  union              
		  Select  Sno, 'MobileNo2 exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(MobileNo2)>100              
		  union              
		  Select  Sno, 'EmailID exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(EmailID)>100              
		  union              
		  Select  Sno, 'EmailID1 exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(EmailID1)>100              
		  union              
		  Select  Sno, 'City exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(City)>100              
		  union              
		  Select  Sno, 'State exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(State)>100              
		  union              
		  Select  Sno, 'Country exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(Country)>100              
		union              
		  Select  Sno, 'CountryCode exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(CountryCode)>100              
		  union              
		  Select  Sno, 'CountryCode1 exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(CountryCode1)>100              
		  union              
		  Select  Sno, 'CountryCode2 exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(CountryCode2)>100              
		  union              
		  Select  Sno, 'ResidentialAddress exceeds specified limit(500)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(ResidentialAddress)>500              
		  union              
		  Select  Sno, 'OfficeAddress exceeds specified limit(500)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(OfficeAddress)>500              
		  union              
		  Select  Sno, 'SourceName exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(SourceName)>100              
		  union              
		  Select  Sno, 'MediumName exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(MediumName)>100              
		  union              
		  Select  Sno, 'CampaignName exceeds specified limit(100)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(CampaignName)>100              
		  union              
		  Select  Sno, 'InitialRemarks exceeds specified limit(1000)' as Remarks              
		  From    #tmpEnquirySrc              
		  Where   len(InitialRemarks)>1000              
			/*              
			union              
			Select  Sno, 'Invalid DateOfBirth' as Remarks              
			From    #tmpEnquirySrc              
			Where   isnull(ltrim(DateOfBirth),'') != '' and ISDate(DateOfBirth) = 0              
			*/              
              
			--select count(*) as ConstraintChkCnt1 from #tmpConstraintChk              
              
			 INSERT INTO #tmpUserEnquiry              
			   ([Sno],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],[WhatsAppNoColName])              
			Select  Sno,PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,EmailID2,City,[State],Country,CountryCode,CountryCode1,CountryCode2,case when ISNUMERIC(PinCode) != 1 then cast(0 as bigint) else PinCode end, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, dbo.ufn_GetUserParentId(@User_Id) as ParentID, getdate(), @User_Id as CreatedBy, WhatsAppNoColName    
			From   #tmpEnquirySrc              
			Where   Sno not in (Select distinct Sno from #tmpConstraintChk)              
              
		  --Select count(*) as ValidRecCnt from #tmpUserEnquiry              
              
		  INSERT INTO UserSourceSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)       
		  Select distinct SourceName, @ParentId, 1,  1, GETDATE(), GETDATE(), @ParentId                
		  From  #tmpUserEnquiry               
		  Where   SourceName not in (Select [Name] from UserSourceSettings(nolock) Where IsActive=1 and Userid=@ParentId)              
              
		  INSERT INTO UserMediumSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)       
		  Select distinct MediumName, @ParentId, 1,  1, GETDATE(), GETDATE(), @ParentId                
		  From  #tmpUserEnquiry               
		  Where   MediumName not in (Select [Name] from UserMediumSettings(nolock) Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(MediumName),'') != ''              
              
		  INSERT INTO UserCampaignSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)     
		  Select distinct CampaignName, @ParentId, 1,  1, GETDATE(), GETDATE(), @ParentId                
		  From  #tmpUserEnquiry               
		  Where   CampaignName not in (Select [Name] from UserCampaignSettings(nolock) Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(CampaignName),'') != ''              
              
		  Update #tmpUserEnquiry               
		  Set SourceName=(Select top 1 SourceId From UserSourceSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=SourceName),        
		  MediumName=isnull((Select top 1 MediumID From UserMediumSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=MediumName),0),    
		  CampaignName=isnull((Select top 1 CampaignID From UserCampaignSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=CampaignName),0)              
              
		  create table #outputEnquiry(enquiryid bigint,leadno bigint)  
		  create table #outputLead(leadid bigint)  
		  create table #outputLeadInteraction(id bigint)  
		  create table #outputMergeLeadEnquiry(id bigint)  
  
		  SELECT @LastLeadId=IDENT_CURRENT('UserLeads')
		  SET Context_Info 0x55555
           
		  If(@IsAutoLeadGeneration = 1)              
		  Begin              
			   print 'AutoLeadGeneration true'    
			   Select top 1 @strAgentlst=Agents, @LastAssignedUser=isnull(LastUserAssigned,UserID) From CRMCampaignSettings(nolock) Where IsActive=1 and UserID=@ParentId              
            
			   insert into #tmptblAgentList           
			   Select value From dbo.fn_Split(@strAgentlst,'#')              
            
			   insert into #tblAgentList              
			   select AgentId from #tmptblAgentList where Sno >= (Select B.Sno from #tmptblAgentList B Where B.AgentId = @LastAssignedUser)            
            
			   insert into #tblAgentList              
			   select AgentId from #tmptblAgentList where Sno < (Select B.Sno from #tmptblAgentList B Where B.AgentId = @LastAssignedUser)            
            
			   Select @AgentCnt=count(*) from #tblAgentList              
              
			   print '@AgentCnt: ' + cast(@AgentCnt as varchar)               
              
			   insert into #tmpMobileNoList              
			   select MobileNo              
			   From UserLeads(nolock)              
			   Where ParentID in (@ParentId) and isnull(ltrim(MobileNo),'') != ''              
			   union              
			   select MobileNo1              
			   From UserLeads (nolock)             
			   Where ParentID in (@ParentId) and isnull(ltrim(MobileNo1),'') != ''              
			   union              
			   select MobileNo2              
			   From UserLeads(nolock)              
			   Where ParentID in (@ParentId) and isnull(ltrim(MobileNo2),'') != ''              
              
			   insert into #tmpEmailIdList              
			   select EmailID              
			   From UserLeads (nolock)             
			   Where ParentID in (@ParentId) and isnull(ltrim(EmailID),'') != ''              
			   union              
			   select EmailID1              
			   From UserLeads   (nolock)           
			   Where ParentID in (@ParentId) and isnull(ltrim(EmailID1),'') != ''              
			   union              
			   select EmailID2              
			   From UserLeads (nolock)             
			   Where ParentID in (@ParentId) and isnull(ltrim(EmailID2),'') != ''              
              
			   insert into #tmpConstraintChk              
			   Select  distinct Sno, 'MobileNo already present in Leads' as Remarks              
			   From              
			   (              
			   Select  Sno, MobileNo              
			   From  #tmpUserEnquiry              
			   Where   ISNULL(ltrim(MobileNo),'') != ''              
			   union              
			   Select  Sno, MobileNo1              
			   From  #tmpUserEnquiry              
			   Where   ISNULL(ltrim(MobileNo1),'') != ''              
			   union              
			   Select  Sno, MobileNo2              
			   From  #tmpUserEnquiry              
			   Where   ISNULL(ltrim(MobileNo2),'') != ''              
			   ) A              
			   Where A.MobileNo in (Select MobileNo From #tmpMobileNoList)              
              
			   insert into #tmpConstraintChk              
			   Select  distinct Sno, 'EmailID already present in Leads' as Remarks              
			   From              
			   (              
			   Select  Sno, EmailID              
			   From  #tmpUserEnquiry              
			   Where   ISNULL(ltrim(EmailID),'') != ''              
			   union              
			   Select  Sno, EmailID1              
			   From  #tmpUserEnquiry              
			   Where   ISNULL(ltrim(EmailID1),'') != ''              
			   union              
			   Select  Sno, EmailID2              
			   From  #tmpUserEnquiry              
			   Where   ISNULL(ltrim(EmailID2),'') != ''              
			   ) A              
			   Where A.EmailID in (Select EmailID From #tmpEmailIdList)              
                           
			   Select @NextLeadNo=Isnull(max(LeadNo),0) From UserLeads(nolock) Where ParentID=@ParentId              
			   print '@NextLeadNo: ' + cast(@NextLeadNo as varchar)    
  
			   Select @CreatedOn=getdate()      
              
			   INSERT INTO #tmpUserLeads              
				([EnquiryID], [Sno], [PersonName], [CompanyName], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], [City], [State], [Country], [CountryCode], [CountryCode1], [CountryCode2], [PinCode], [ResidentialAddress], [OfficeAddress], [AssignedTo], [SourceName], [MediumName], [CampaignName], [InitialRemarks], [ParentID], [FollowUpStatus], [NextStatusDate], [Remarks], [Products], [AmountPaid], [CreatedOn], [CreatedBy], [FollowupDate], [WhatsAppNoColName])    
			   Select  EnquiryID, Sno, PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, City, [State], Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, 0 as AssignedTo, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, 1/*Call-Back*/ as FollowUpStatus, DATEADD(day,1,getdate()) as NextStatusDate, '' as Remarks, '' as Products, 0 as AmountPaid, @CreatedOn as CreatedOn, @User_Id as CreatedBy, getdate() as FollowupDate, WhatsAppNoColName
			   From  #tmpUserEnquiry              
			   Where  Sno not in (Select distinct Sno From #tmpConstraintChk)              
          
			   If(@ParentId = @User_Id)          
			   begin          
					Update A Set A.AssignedTo=B.AgentId, @LastAssignedUser=B.AgentId    
					From #tmpUserLeads A , #tblAgentList B    
					Where A.Sno%@AgentCnt=B.Sno%@AgentCnt    
					--Select top 10 * from #tmpUserLeads              
    
					If(isnull(@LastAssignedUser,0) !=0)              
					Begin              
						Update CRMCampaignSettings Set LastUserAssigned=@LastAssignedUser Where IsActive=1 and UserID=@ParentId              
					End              
			   end          
			   else          
			   begin          
					update #tmpUserLeads set AssignedTo = @User_Id;          
			   end          
          
			   If exists(Select * from #tmpUserLeads)    
			   Begin    
					INSERT INTO [dbo].[UserLeads]              
						([LeadNo],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City], [State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo], [SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks], [Products],[AmountPaid],[CreatedOn],[CreatedBy],[FollowupDate],[enquirysource],[WhatsAppNoColName])    
						output inserted.ID as leadid into #outputLead
					Select              
						@NextLeadNo+LeadNo,[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City], [State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo], [SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks], [Products],[AmountPaid],[CreatedOn],[CreatedBy],[FollowupDate],20 as [enquirysource], [WhatsAppNoColName]    
					From    #tmpUserLeads
              
					Select @nLeadInserted=@@ROWCOUNT              
					print cast(@nLeadInserted as varchar) + ' Leads inserted'

					select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),leadid),',') From #outputLead

					Exec usp_ExecLeadTriggerTasks @CsvID
      
					insert into leadinteractionhistory(LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID, CreatedOn,CreatedBy,followupdate,IsAutoEntry)
					output inserted.ID into #outputLeadInteraction
					select LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID, CreatedOn,CreatedBy,followupdate,1 as IsAutoEntry
					from userleads(nolock)
					where parentid=@ParentId and createdon=@CreatedOn
             
					select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),ID),',') From #outputLeadInteraction

					Exec usp_ExecLeadInteractionTriggerTasks @CsvID
              
					Update C Set C.LeadNo = B.LeadNo              
					From #tmpUserLeads A inner join [UserLeads] B  (nolock)            
					ON   A.LeadNo + @NextLeadNo = B.LeadNo inner join #tmpUserEnquiry C              
					ON   A.Sno = C.Sno              
					Where B.[ParentID] = @ParentId      
    
					Set @RowData = isnull((Select  SNo=ROW_NUMBER()Over(order by B.ID), B.PersonName, CountryCode=Case B.WhatsAppNoColName When 'MobileNo' then B.CountryCode when 'MobileNo1' then B.CountryCode1 when 'MobileNo2' then B.CountryCode2 Else '' End, MobileNo=Case B.WhatsAppNoColName When 'MobileNo' then B.MobileNo when 'MobileNo1' then B.MobileNo1 when 'MobileNo2' then B.MobileNo2 Else '' End    
					From #tmpUserLeads A inner join [UserLeads] B (nolock)    
					ON   A.LeadNo + @NextLeadNo = B.LeadNo    
					Where B.[ParentID] = @ParentId and B.WhatsAppNoColName in ('MobileNo','MobileNo1','MobileNo2') for json auto, INCLUDE_NULL_VALUES),'')    
    
					If(len(@RowData)>1)    
					Begin    
						/*INSERT INTO [MySMSConversations].[dbo].[tbl_imp_ImportRequest]    
						([FileName],[FileSizeByte],[CreatedOn],[Status],[NoOfRecord],[IsProcessed]    
						,[ImportJSON],[SourceName],[CreatedBy],[ParentId])    
						VALUES    
						('FromEnquiryAutoLead.xls',LEN(@RowData),Getdate(),'pending',0,0    
						,@RowData,0,@User_Id,@ParentId)    
    
						Select @ImportRequestId=SCOPE_IDENTITY()   */

			SET @sqlquery = '
            
            INSERT INTO [tbl_imp_ImportRequest]    
                ([FileName], [FileSizeByte], [CreatedOn], [Status], [NoOfRecord], [IsProcessed],    
                 [ImportJSON], [SourceName], [CreatedBy], [ParentId])    
            VALUES    
                (''FromEnquiryAutoLead.xls'', ' + CAST(LEN(@RowData) AS NVARCHAR) + ', GETDATE(), ''pending'', 0, 0,    
                ''' + REPLACE(@RowData, '''', '''''') + ''', 0, ' + CAST(@User_Id AS NVARCHAR) + ', ' + CAST(@ParentId AS NVARCHAR) + ');
            ';
            
            -- Get the inserted ID back
            EXEC usp_clr_InsertAndReturnId @sqlquery, @retid = @ImportRequestId OUTPUT;

						print N'@RowData: ' + @RowData    
						select @RecCnt=count(*) from openjson(@RowData)        
    
						While(1=1)    
						Begin    
							set @Start=@End+1    
							set @End=@Pagesize*@Pageno    
    
							Set @RowData = isnull((Select * from (Select  SNo=ROW_NUMBER()Over(order by B.ID), B.PersonName, CountryCode=Case B.WhatsAppNoColName When 'MobileNo' then B.CountryCode when 'MobileNo1' then B.CountryCode1 when 'MobileNo2' then B.CountryCode2 Else '' End, MobileNo=Case B.WhatsAppNoColName When 'MobileNo' then B.MobileNo when 'MobileNo1' then B.MobileNo1 when 'MobileNo2' then B.MobileNo2 Else '' End
							From #tmpUserLeads A inner join [UserLeads] B (nolock)    
							ON   A.LeadNo + @NextLeadNo = B.LeadNo    
							Where B.[ParentID] = @ParentId and B.WhatsAppNoColName in ('MobileNo','MobileNo1','MobileNo2')) T    
							Where T.SNo between @Start and @End    
							for json auto, INCLUDE_NULL_VALUES),'')    
    
							/*INSERT INTO [MySMSConversations].[dbo].[tbl_ims_ImportSlot]    
								([requestid],[createdon],[contactjson],[isprocessed])    
							VALUES    
								(@ImportRequestId,Getdate(),@RowData,0)  */  
    
	                         SET @sqlquery = '
                             INSERT INTO [tbl_ims_ImportSlot]    
                                 ([requestid], [createdon], [contactjson], [isprocessed])    
                             VALUES    
                                 (' + CAST(@ImportRequestId AS NVARCHAR) + ', GETDATE(), ''' + REPLACE(@RowData, '''', '''''') + ''', 0);
                             ';
                             
                             -- Execute remotely
                             EXEC usp_clr_ExecuteRemoteQuery @sqlquery;

							If(@RecCnt < (@Pageno*@Pagesize))    
							Begin    
								break    
							End    
							Else    
							Begin    
								Set @Pageno=@Pageno+1    
							End    
						End    
    
						Set @RowData = null    
					End    
			   End    
                       
			   If exists(Select * from #tmpUserEnquiry)    
			   Begin    
					SELECT @LastEnquiryId=IDENT_CURRENT('UserEnquiry')              
              
					INSERT INTO UserEnquiry              
					 ([PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country]    
					 ,[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName]          
					 ,[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],IsOpen,LeadNo    
					 ,[enquirysource],[WhatsAppNoColName]) 
					 output inserted.EnquiryID as enquiryid,inserted.LeadNo as leadno into #outputEnquiry              
					Select [PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country]    
					 ,[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName]          
					 ,[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],IIf(isnull(LeadNo,0)>0,0,1),LeadNo
					 ,20 as [enquirysource], [WhatsAppNoColName]    
					From #tmpUserEnquiry    
	
					Select @nEnquiriesInserted=@@ROWCOUNT
	
					print cast(@nEnquiriesInserted as varchar) + ' Enquiries inserted'

					insert into tbl_MergeLeadsEnquiry(EnquiryNo,LeadNo,IsOpen)
					output inserted.ID into #outputMergeLeadEnquiry
					select enquiryid,leadno,1 as IsOpen from #outputEnquiry o
					where isnull(leadno,0)>0 and not exists
					(select 1 from tbl_MergeLeadsEnquiry(nolock) where EnquiryNo=o.enquiryid and leadno=o.leadno)
             
					select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),ID),',') From #outputMergeLeadEnquiry

					Exec usp_ExecMergeLeadEnquiryTriggerTasks @CsvID
                
			   End    
              
			   If exists(Select * from #tmpUserLeads)    
			   Begin    
					set @jRow = 1

					while(@jRow <= @CustomFieldsCnt)              
					begin              
						select @fieldId=t.fieldId,@fieldName=t.fieldName,@fieldtype=c.datatype 
						from #tblCustomFields t join customfields c (nolock) on c.field_ID=t.fieldId and c.ParentID=@ParentId 
						Where t.RowId=@jRow              
              
						 set @SQLString = 'insert into customfieldLeadvalue(LeadID,EnquiryID,fieldID,fieldvalue,CreatedDate)  
						 select distinct A.ID, C.EnquiryID, ' + cast(@fieldId as varchar) +     
						 ', case when '''+ cast(@fieldtype as nvarchar) +'''=''d'' and IsDate(D.[' + @fieldName + ']) = 1 then Format(cast(D.[' + @fieldName + 
						 '] as datetime),''dd-MMM-yyyy hh:mm:ss tt'') else D.[' + @fieldName + '] end, getdate() 
						 From [UserLeads](nolock) A inner join #tmpUserEnquiry B    
						 ON   A.LeadNo = B.LeadNo inner join UserEnquiry C (nolock)   
						 On  B.LeadNo = C.LeadNo inner join #tmpEnquirySrc D    
						 On  B.Sno = D.Sno    
						 Where A.[ParentID] = ' + cast(@ParentId as varchar) + ' and isnull(D.[' + @fieldName + '],'''') != '''' '    
                  
						 print 'custom field Lead @SQLString: ' + @SQLString    
              
						 exec (@SQLString)    
						 Select @nLeadCustomFieldRows+=@@ROWCOUNT    
              
						 set @jRow = @jRow + 1    
					end

					print cast(@nLeadCustomFieldRows as varchar) + ' Lead Custom Fields inserted'
			   End    
               
		  End              
		  Else              
		  Begin    
			   print 'AutoLeadGeneration false'    
    
			   If exists(Select * from #tmpUserEnquiry)    
			   Begin    
					SELECT @LastEnquiryId=IDENT_CURRENT('UserEnquiry')              
              
					INSERT INTO UserEnquiry              
					 ([PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],[enquirysource],[WhatsAppNoColName])
					  output inserted.EnquiryID as enquiryid,0 as leadno into #outputEnquiry
					Select [PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],20 as [enquirysource], [WhatsAppNoColName]    
					From #tmpUserEnquiry              
					Select @nEnquiriesInserted=@@ROWCOUNT        
  
					print cast(@nEnquiriesInserted as varchar) + ' Enquiries inserted'
			   End    
		  End              
              
		  set @jRow = 1              
    
		  If exists(Select * from #tmpUserEnquiry)    
		  Begin    
			while(@jRow <= @CustomFieldsCnt)    
			begin    
				select @fieldId=t.fieldId,@fieldName=t.fieldName,@fieldtype=c.datatype 
				from #tblCustomFields t join customfields c (nolock) on c.field_ID=t.fieldId and c.ParentID=@ParentId 
				Where t.RowId=@jRow
     
    
				set @SQLString = 'insert into customfieldEnquiryvalue (EnquiryID,fieldID,fieldvalue)
				select distinct C.EnquiryID, ' + cast(@fieldId as varchar) + ', case when '''+ cast(@fieldtype as nvarchar) +'''=''d'' and IsDate(A.[' + @fieldName + ']) =
				1 then Format(cast(A.[' + @fieldName + '] as datetime),''dd-MMM-yyyy hh:mm:ss tt'') else A.[' + @fieldName + '] end    
				from #tmpEnquirySrc A inner join #tmpUserEnquiry B    
				on A.Sno=B.Sno inner join UserEnquiry C (nolock)    
				on B.PersonName = C.PersonName and isnull(B.MobileNo,'''') = isnull(C.MobileNo,'''') and isnull(B.MobileNo1,'''') = isnull(C.MobileNo1,'''') and isnull(B.MobileNo2,'''') = isnull(C.MobileNo2,'''') and isnull(B.EmailID,'''') = isnull(C.EmailID,'''')    
				and isnull(B.EmailID1,'''') = isnull(C.EmailID1,'''') and isnull(B.EmailID2,'''') = isnull(C.EmailID2,'''')    
				Where C.EnquiryID > ' + cast(@LastEnquiryId as varchar) + ' and C.EnquiryID <= ' + cast(@LastEnquiryId as varchar) + ' + ' + cast(@nEnquiriesInserted as varchar) + ' and isnull(A.[' + @fieldName + '],'''') != '''' '    
    
				print 'custom field enquiry @SQLString: ' + @SQLString    
    
				exec (@SQLString)    
				select @nEnquiryCustomFieldRows+=@@ROWCOUNT    
    
				set @jRow = @jRow + 1    
			end              
			print cast(@nEnquiryCustomFieldRows as varchar) + ' Enquiry Custom Fields inserted'
		 End    
			
		 --declare @RowData varchar(max)
		 Set @RowData = isnull((Select * From #tmpConstraintChk order by Sno for json auto, INCLUDE_NULL_VALUES),'')    
		 --select @RowData
		 print 'Final @RowData: ' + cast(@RowData as varchar(max))    
              
		 update tbl_EnquiryImportSummary    
		 set IsProcessed=1, Remarks=@RowData, EnquiryCnt=@nEnquiriesInserted, EnquiryCustomFieldCnt=@nEnquiryCustomFieldRows,
		  LeadCnt=@nLeadInserted, LeadCustomFieldCnt=@nLeadCustomFieldRows    
		 where ImportRow_Id=@ImportRow_id    
            
		 Iter:              
			Set @iRow = @iRow + 1              
			Set @ImportRow_id=0              
			Set @ImportData=null              
			Set @RowData=null              
			Set @FieldNames=''              
			Set @SQLString=null              
			Set @User_Id=0              
			Set @LastEnquiryId=0              
			Set @LastLeadId=0              
			Set @nEnquiriesInserted=0              
			Set @nEnquiryCustomFieldRows=0              
			Set @nLeadInserted=0              
			Set @nLeadCustomFieldRows=0              
			Set @jRow=1              
			Set @fieldId=0              
			Set @fieldName=''              
			Set @CustomFieldsCnt = 0              
			Set @ImportRequestId = 0     
			Set @RecCnt = 0              
			Set @Start = 0              
			Set @End = 0              
			Set @Pagesize = 500              
			Set @Pageno = 1              
              
		 truncate table #tmpUserEnquiry              
		 truncate table #tmpConstraintChk              
		 truncate table #tmpUserLeads              
		 truncate table #tmpMobileNoList              
		 truncate table #tmpEmailIdList              
		 truncate table #tblAgentList              
		 truncate table #tblCustomFields              
              
		 if object_id('tempdb..#tmpEnquirySrc') is not null begin drop table #tmpEnquirySrc end              
		 if object_id('tempdb..#outputEnquiry') is not null begin drop table #outputEnquiry end              
		 if object_id('tempdb..#outputLead') is not null begin drop table #outputLead end              
		 if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end
		 if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end
              
		End              
              
		--COMMIT TRANSACTION   
		SET Context_Info 0x 
	END TRY                  
	BEGIN CATCH                 
		SET Context_Info 0x 

		IF (XACT_STATE()) = -1  
		BEGIN  
			PRINT 'The transaction is in an uncommittable state. Rolling back transaction.'  
			ROLLBACK TRANSACTION;  
			declare @error int, @message varchar(4000)
			select @error = ERROR_NUMBER(), @message = ERROR_MESSAGE()
			raiserror ('usp_ProcessEnquiryImportData: %d: %s', 16, 1, @error, @message) 
		END;  
  
		-- Test whether the transaction is active and valid.  
		IF (XACT_STATE()) = 1  
		BEGIN  
			PRINT 'The transaction is committable. Committing transaction.'  
			COMMIT TRANSACTION;     
		END;  
   
		insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)  
		output inserted.*
		SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()    
 	END CATCH                  
              
	if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end              
	if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end              
	if object_id('tempdb..#tmptblAgentList') is not null begin drop table #tmptblAgentList end              
	if object_id('tempdb..#tblAgentList') is not null begin drop table #tblAgentList end              
	if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end      
	if object_id('tempdb..#tblAllEnquiryFields') is not null begin drop table #tblAllEnquiryFields end              
	if object_id('tempdb..#tmpEnquirySrc') is not null begin drop table #tmpEnquirySrc end              
	if object_id('tempdb..#tmpUserEnquiry') is not null begin drop table #tmpUserEnquiry end              
	if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end              
	if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end              
	if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end
	if object_id('tempdb..#outputEnquiry') is not null begin drop table #outputEnquiry end              
	if object_id('tempdb..#outputLead') is not null begin drop table #outputLead end              
	if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end
	if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end

END     



GO

/* ============================================================
   Procedure: [dbo].[usp_ProcessEnquiryImportDataspecific]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_ProcessEnquiryImportData 0, 'P'      
-- Exec usp_ProcessEnquiryImportData 1, 'P'      
CREATE   PROC usp_ProcessEnquiryImportDataspecific        
(   
    @rrid bigint,     
    @BatchSize int=1,  -- 0 ('All')        
    @Mode varchar(1)='P'    -- 'P'riority, 'F'ifo        
)        
AS        
BEGIN        
  
-- declare @BatchSize int=1,@Mode varchar(1)='P'  
        
if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end        
if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end        
if object_id('tempdb..#tblAgentList') is not null begin drop table #tblAgentList end        
if object_id('tempdb..#tmptblAgentList') is not null begin drop table #tmptblAgentList end        
if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end        
if object_id('tempdb..#tblAllEnquiryFields') is not null begin drop table #tblAllEnquiryFields end        
if object_id('tempdb..#tmpEnquirySrc') is not null begin drop table #tmpEnquirySrc end        
if object_id('tempdb..#tmpUserEnquiry') is not null begin drop table #tmpUserEnquiry end        
if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end        
if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end        
if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end        
        
        
Create table #tblImportRowId        
(        
    RowId int identity,        
    ImportRow_id bigint,        
    [User_Id] bigint,        
    IsAutoLeadGeneration bit        
)        
        
create table #tmpConstraintChk        
(        
    Sno int,        
    Remarks varchar(200)        
)        
        
create table #tmptblAgentList         
(        
    Sno int IDENTITY(1,1),         
    AgentId bigint        
)        
        
create table #tblAgentList         
(        
    Sno int IDENTITY(1,1),         
    AgentId bigint        
)        
        
create table #tblCustomFields        
(        
    RowId int identity(1,1),        
    fieldId bigint,        
    fieldName varchar(50)        
)        
        
create table #tblAllEnquiryFields      
(      
 RowId int identity(1,1),      
 fieldName varchar(50),      
 FieldType varchar(10)      
)      
      
create table #tmpMobileNoList        
(        
    RowId int identity,        
    MobileNo varchar(100)        
)        
        
create table #tmpEmailIdList        
(        
    RowId int identity,        
    EmailId varchar(100)        
)        
        
CREATE TABLE #tmpUserEnquiry (        
 [EnquiryID] [bigint] IDENTITY(1,1) NOT NULL,        
 [Sno] [int] NOT NULL,        
 [PersonName] [varchar](100) NULL,        
 [CompanyName] [varchar](100) NULL,        
 [MobileNo] [varchar](100) NULL,        
 [MobileNo1] [varchar](100) NULL,        
 [MobileNo2] [varchar](100) NULL,        
 [EmailID] [varchar](100) NULL,        
 [EmailID1] [varchar](100) NULL,        
 [EmailID2] [varchar](100) NULL,        
 [City] [varchar](100) NULL,        
 [State] [varchar](100) NULL,        
 [Country] [varchar](100) NULL,        
 [CountryCode] [varchar](50) NULL,        
 [CountryCode1] [varchar](50) NULL,        
 [CountryCode2] [varchar](50) NULL,        
 [PinCode] [bigint] NULL,        
 [ResidentialAddress] [varchar](500) NULL,        
 [OfficeAddress] [varchar](500) NULL,        
 [SourceName] [varchar](100) NOT NULL,        
 [MediumName] [varchar](100) NOT NULL,        
 [CampaignName] [varchar](100) NOT NULL,        
 [InitialRemarks] [varchar](1000) NULL,        
 [ParentID] [bigint] NOT NULL,        
 [CreatedDate] [datetime] NOT NULL,        
 [CreatedBy] [bigint] NULL,        
 [IsOpen] [bit] NOT NULL DEFAULT ((1)),        
 [LeadNo] [int] NULL        
)        
        
CREATE TABLE #tmpUserLeads (        
 [LeadNo] [bigint] IDENTITY(1,1) NOT NULL,        
 [EnquiryID] [bigint] NOT NULL,        
 [Sno] [int] NOT NULL,        
 [PersonName] [varchar](100) NULL,        
 [CompanyName] [varchar](100) NULL,        
 [MobileNo] [varchar](100) NULL,        
 [MobileNo1] [varchar](100) NULL,        
 [MobileNo2] [varchar](100) NULL,        
 [EmailID] [varchar](100) NULL,        
 [EmailID1] [varchar](100) NULL,        
 [EmailID2] [varchar](100) NULL,        
 [City] [varchar](100) NULL,        
 [State] [varchar](100) NULL,        
 [Country] [varchar](100) NULL,        
 [CountryCode] [varchar](50) NULL,        
 [CountryCode1] [varchar](50) NULL,        
 [CountryCode2] [varchar](50) NULL,        
 [PinCode] [bigint] NULL,        
 [ResidentialAddress] [varchar](500) NULL,        
 [OfficeAddress] [varchar](500) NULL,        
 [AssignedTo] [bigint] NOT NULL,        
 [SourceName] [bigint] DEFAULT ((0)) NOT NULL,        
 [MediumName] [bigint] DEFAULT ((0)) NULL,        
 [CampaignName] [bigint] DEFAULT ((0)) NULL,        
 [InitialRemarks] [varchar](1000) NULL,        
 [ParentID] [bigint] NOT NULL,        
 [FollowUpStatus] [int] NULL,        
 [NextStatusDate] [varchar](50) NULL,        
 [Remarks] [varchar](1000) NULL,        
 [Products] [varchar](1000) NULL,        
 [AmountPaid] [numeric](18, 2) NOT NULL DEFAULT ((0)),        
 [CreatedOn] [datetime] NULL,        
 [CreatedBy] [bigint] NULL,        
 [FollowupDate] [datetime] NULL        
)        
        
BEGIN TRY        
    BEGIN TRANSACTION        
   insert into #tblImportRowId        
   Select ImportRow_id,[User_Id],IsAutoLeadGeneration From tbl_EnquiryImportSummary(nolock) where IsProcessed=0 and ImportRow_Id=@rrid        
   /*
    If(@Mode = 'P')        
    Begin        
  If(@BatchSize != 0)        
  Begin        
   insert into #tblImportRowId        
   Select top (@BatchSize) ImportRow_id,[User_Id],IsAutoLeadGeneration From tbl_EnquiryImportSummary(nolock) where IsProcessed=0 order by [Priority]        
  End        
  Else        
  Begin        
   insert into #tblImportRowId        
   Select ImportRow_id,[User_Id],IsAutoLeadGeneration From tbl_EnquiryImportSummary(nolock) where IsProcessed=0 order by [Priority]        
  End        
 End        
 Else -- Fifo        
 Begin        
  If(@BatchSize != 0)        
  Begin        
   insert into #tblImportRowId        
   Select top (@BatchSize) ImportRow_id,[User_Id],IsAutoLeadGeneration From tbl_EnquiryImportSummary(nolock) where IsProcessed=0        
  End        
  Else        
  Begin        
   insert into #tblImportRowId        
   Select ImportRow_id,[User_Id],IsAutoLeadGeneration From tbl_EnquiryImportSummary(nolock) where IsProcessed=0        
  End        
    End        
    --select * from #tblImportRowId        
    */
	    
    declare @iRow int=1, @jRow int=1, @ImportRow_id bigint=0, @UnProcessedRowCnt int=0, @User_Id bigint=0, @LastEnquiryId bigint=0, @nEnquiriesInserted bigint=0, @LastLeadId bigint=0, @nLeadInserted bigint=0, @fieldId bigint=0, @nEnquiryCustomFieldRows 
	bigint=0, @nLeadCustomFieldRows bigint=0, @ParentId bigint=0       
    declare @ImportData nvarchar(max), @RowData nvarchar(max), @FieldNames nvarchar(max)='', @SQLString nvarchar(max)='', @ParmDefinition nvarchar(500), @fieldName varchar(50)='';          
    declare @IsAutoLeadGeneration bit=0, @strAgentlst nvarchar(max), @LastAssignedUser int, @NextLeadNo bigint=0, @AgentCnt int=0, @CustomFieldsCnt int=0        
        
    select @UnProcessedRowCnt=Count(*) from #tblImportRowId        
        
    While(@iRow <= @UnProcessedRowCnt)        
    Begin        
    print '@iRow: ' + cast(@iRow as varchar)        
    Select @ImportRow_id=ImportRow_id,@User_Id=[User_Id],@IsAutoLeadGeneration=IsAutoLeadGeneration From #tblImportRowId Where RowId=@iRow        
    print '@ImportRow_id: ' + cast(@ImportRow_id as varchar)        
    Select @ImportData=ImportData from tbl_EnquiryImportSummary(nolock) where ImportRow_Id=@ImportRow_id        
    print '@ImportData: ' + @ImportData        
    select top 1 @RowData=value from openjson(@ImportData)        
    print '@RowData: ' + @RowData        
    select @FieldNames=@FieldNames+'['+[Key]+'] varchar(1000),' from openjson(@RowData)        
    print '@FieldNames1: ' + @FieldNames        
    set @FieldNames= SUBSTRING(@FieldNames,1,len(@FieldNames)-1)        
    print '@FieldNames2: ' + @FieldNames        
        
 Select @ParentId = dbo.ufn_GetUserParentId(@User_Id)        
      
 insert into #tblAllEnquiryFields      
 values ('Sno','Main'),('PersonName','Main'),('CompanyName','Main'),('MobileNo','Main'),('MobileNo1','Main'),('MobileNo2','Main'),('EmailID','Main'),('EmailID1','Main'),('EmailID2','Main'),('City','Main'),('State','Main'),('Country','Main'),('CountryCode'
,'Main'),('CountryCode1','Main'),('CountryCode2','Main'),('PinCode','Main'),('ResidentialAddress','Main'),('OfficeAddress','Main'),('SourceName','Main'),('MediumName','Main'),('CampaignName','Main'),('InitialRemarks','Main')--,('ProfileImgFileName','Main')      
      
 insert into #tblAllEnquiryFields      
 select fieldname,'Custom'      
 from customfields           
 where parentId=@ParentId and isActive=1      
      
 if exists(select [Key] from openjson(@RowData) where [Key] COLLATE SQL_Latin1_General_CP1_CI_AS not in (Select FieldName From #tblAllEnquiryFields))      
 Begin      
  print 'Invalid Field found in Import Data'      
  Update tbl_EnquiryImportSummary Set IsProcessed=1,Remarks='[{"Sno":0,"Remarks":"Invalid Field found in Import Data"}]' Where ImportRow_Id = @ImportRow_id      
  goto Iter      
 End      
  Else      
  Begin      
 If exists(Select FieldName From #tblAllEnquiryFields Where FieldName COLLATE SQL_Latin1_General_CP1_CI_AS not in (select [Key] from openjson(@RowData)))      
 Begin      
  print 'Required Field Missing in Import Data'      
  Update tbl_EnquiryImportSummary Set IsProcessed=1,Remarks='[{"Sno":0,"Remarks":"Required Field Missing in Import Data"}]' Where ImportRow_Id = @ImportRow_id      
  goto Iter      
 End      
  End      
      
    create table #tmpEnquirySrc (id int identity);        
    print 'alter table #tmpEnquirySrc add ' + @FieldNames        
    exec('alter table #tmpEnquirySrc add ' + @FieldNames)        
        
    --Set @SQLString = N'select * into ##tmpEnquirySrc from openjson(''' + @ImportData + ''') with (''' + @FieldNames + ''')'        
    --Set @SQLString = N'select * into ##tmpEnquirySrc from openjson(@ImptData) with (@FldNames)'         
        
    Set @SQLString = N'insert into #tmpEnquirySrc select * from openjson(@ImptData) with (' + @FieldNames + ')'         
        
    --SET @ParmDefinition = N'@ImptData nvarchar(max), @FldNames nvarchar(max)';          
    SET @ParmDefinition = N'@ImptData nvarchar(max)';          
          
    print @SQLString        
        
   --EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData, @FldNames=@FieldNames          
    EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData          
        
    update #tmpEnquirySrc         
    set MobileNo=rtrim(ltrim(case when isnull(MobileNo,'')='' and isnull(MobileNo1,'')!='' then MobileNo1 else Isnull(MobileNo,'') end)),        
    MobileNo1=rtrim(ltrim(case when isnull(MobileNo1,'')='' and isnull(MobileNo2,'')!='' then MobileNo2 else Isnull(MobileNo1,'') end)),        
    MobileNo2=rtrim(ltrim(isnull(MobileNo2,''))),        
    CountryCode=rtrim(ltrim(case when isnull(CountryCode,'')='' and isnull(CountryCode1,'')!='' then iif(left(ltrim(CountryCode1),1) != '+','+'+ltrim(CountryCode1),CountryCode1) else iif(left(ltrim(Isnull(CountryCode,'')),1) != '+' 
	and ltrim(Isnull(CountryCode,'')) != '', '+' + ltrim(Isnull(CountryCode,'')),Isnull(CountryCode,'')) end)),        
    CountryCode1=rtrim(ltrim(case when isnull(CountryCode1,'')='' and isnull(CountryCode2,'')!='' then iif(left(ltrim(CountryCode2),1) != '+','+'+ltrim(CountryCode2),CountryCode2) else iif(left(ltrim(Isnull(CountryCode1,'')),1) != '+' 
	and ltrim(Isnull(CountryCode1,'')) != '', '+' + ltrim(Isnull(CountryCode1,'')),Isnull(CountryCode1,'')) end)),        
    CountryCode2=rtrim(ltrim(iif(left(ltrim(isnull(CountryCode2,'')),1) != '+' and ltrim(isnull(CountryCode2,'')) != '','+' + ltrim(isnull(CountryCode2,'')),Isnull(CountryCode2,'')))),        
    EmailID=rtrim(ltrim(case when isnull(EmailID,'')='' and isnull(EmailID1,'')!='' then EmailID1 else Isnull(EmailID,'') end)),        
    EmailID1=rtrim(ltrim(case when isnull(EmailID1,'')='' and isnull(EmailID2,'')!='' then EmailID2 else Isnull(EmailID1,'') end)),        
    EmailID2=rtrim(ltrim(isnull(EmailID2,''))),        
    PersonName=rtrim(ltrim(isnull(PersonName,''))),        
    InitialRemarks=rtrim(ltrim(isnull(InitialRemarks,''))),        
    SourceName=rtrim(ltrim(isnull(SourceName,''))),        
    MediumName=rtrim(ltrim(isnull(MediumName,''))),        
    CampaignName=rtrim(ltrim(isnull(CampaignName,''))),        
    Sno=rtrim(ltrim(isnull(Sno,0)))        
        
    --EXEC('select * from #tmpEnquirySrc')        
        
    insert into #tmpConstraintChk        
    Select  Sno, 'Duplicate Records' as Remarks        
    From        
    (        
    select ROW_NUMBER()over(partition by PersonName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, InitialRemarks order by cast(Sno as int)) as Rid, *        
    from #tmpEnquirySrc        
    ) B        
    Where B.Rid > 1        
                          
    insert into #tblCustomFields        
    select field_ID, fieldname         
    from customfields(nolock)         
    where parentId=@ParentId and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select FieldName from #tblAllEnquiryFields where [FieldType] = 'Custom')        
    /*where parentId=dbo.ufn_GetUserParentId(@User_Id) and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select [Key]        
    from openjson(@RowData) where [Key] not in ('Sno', 'PersonName', 'CompanyName', 'MobileNo', 'MobileNo1', 'MobileNo2', 'EmailID', 'EmailID1', 'EmailID2', 'City', 'State', 'Country', 'CountryCode', 'CountryCode1', 'CountryCode2', 'PinCode', 'Residential
  
    
Address', 'OfficeAddress', 'SourceName', 'MediumName', 'CampaignName', 'InitialRemarks', 'ProfileImgFileName'))*/        
        
    Select @CustomFieldsCnt=count(*) From #tblCustomFields        
        
    insert into #tmpConstraintChk        
    Select  Sno, 'Sno missing' as Remarks        
    From    #tmpEnquirySrc        
    Where   ISNULL(ltrim(Sno),'') = '' or ISNULL(ltrim(Sno),'0') = '0'        
    union        
    Select  Sno, 'Sno Duplicate' as Remarks        
    From    #tmpEnquirySrc        
    group by Sno        
    having  Count(*) > 1        
    union        
    Select  Sno, 'PersonName missing' as Remarks        
    From    #tmpEnquirySrc        
    Where   ISNULL(ltrim(PersonName),'') = ''        
    union        
    Select  Sno, 'Contact details missing' as Remarks        
    From    #tmpEnquirySrc        
    Where   ISNULL(ltrim(MobileNo),'') = '' and ISNULL(ltrim(MobileNo1),'') = '' and ISNULL(ltrim(MobileNo2),'') = '' and         
    ISNULL(ltrim(EmailID),'') = '' and ISNULL(ltrim(EmailID1),'') = '' and ISNULL(ltrim(EmailID2),'') = ''        
    union        
    Select  Sno, 'MobileNo or CountryCode missing' as Remarks        
    From    #tmpEnquirySrc        
    Where   ((ISNULL(ltrim(MobileNo),'')!='' and ISNULL(ltrim(CountryCode),'')='') or (ISNULL(ltrim(MobileNo),'')='' and ISNULL(ltrim(CountryCode),'')!=''))        
       or        
    ((ISNULL(ltrim(MobileNo1),'')!='' and ISNULL(ltrim(CountryCode1),'')='') or (ISNULL(ltrim(MobileNo1),'')='' and ISNULL(ltrim(CountryCode1),'')!='')) or        
    ((ISNULL(ltrim(MobileNo2),'')!='' and ISNULL(ltrim(CountryCode2),'')='') or (ISNULL(ltrim(MobileNo2),'')='' and ISNULL(ltrim(CountryCode2),'')!=''))        
    union        
    Select  Sno, 'SourceName missing' as Remarks        
    From    #tmpEnquirySrc        
    Where   ISNULL(ltrim(SourceName),'') = ''        
    union        
    Select  Sno, 'PersonName Length exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(PersonName)>100        
    union        
    Select  Sno, 'CompanyName exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(CompanyName)>100        
    union        
    Select  Sno, 'MobileNo exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(MobileNo)>100        
    union        
    Select  Sno, 'MobileNo1 exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(MobileNo1)>100        
    union        
    Select  Sno, 'MobileNo2 exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(MobileNo2)>100        
    union        
    Select  Sno, 'EmailID exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(EmailID)>100        
    union        
    Select  Sno, 'EmailID1 exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(EmailID1)>100        
    union        
    Select  Sno, 'City exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(City)>100        
    union        
    Select  Sno, 'State exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(State)>100        
    union        
    Select  Sno, 'Country exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(Country)>100        
    union        
    Select  Sno, 'CountryCode exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(CountryCode)>100        
    union        
    Select  Sno, 'CountryCode1 exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(CountryCode1)>100        
    union        
    Select  Sno, 'CountryCode2 exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(CountryCode2)>100        
    union        
    Select  Sno, 'ResidentialAddress exceeds specified limit(500)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(ResidentialAddress)>500        
    union        
    Select  Sno, 'OfficeAddress exceeds specified limit(500)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(OfficeAddress)>500        
    union        
    Select  Sno, 'SourceName exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(SourceName)>100        
    union        
    Select  Sno, 'MediumName exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(MediumName)>100        
    union        
    Select  Sno, 'CampaignName exceeds specified limit(100)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(CampaignName)>100        
    union        
    Select  Sno, 'InitialRemarks exceeds specified limit(1000)' as Remarks        
    From    #tmpEnquirySrc        
    Where   len(InitialRemarks)>1000        
    /*        
    union        
    Select  Sno, 'Invalid DateOfBirth' as Remarks        
    From    #tmpEnquirySrc        
    Where   isnull(ltrim(DateOfBirth),'') != '' and ISDate(DateOfBirth) = 0        
    */        
        
    --select count(*) as ConstraintChkCnt1 from #tmpConstraintChk        
        
    INSERT INTO #tmpUserEnquiry        
       ([Sno],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country]        
       ,[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress]  
    ,[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy])        
    Select  Sno,PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,EmailID2,City,[State],Country        
       ,CountryCode,CountryCode1,CountryCode2,case when ISNUMERIC(PinCode) != 1 then 0 else PinCode end,ResidentialAddress,OfficeAddress  
    ,SourceName,MediumName,CampaignName,InitialRemarks,dbo.ufn_GetUserParentId(@User_Id) as ParentID,dbo.[fn_getusertimefromindiantime](@User_Id,getdate()) as CreatedDate,@User_Id as CreatedBy        
    From   #tmpEnquirySrc        
    Where   Sno not in (Select distinct Sno from #tmpConstraintChk)        
        
    --Select count(*) as ValidRecCnt from #tmpUserEnquiry        
        
    INSERT INTO UserSourceSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)          
    Select distinct SourceName, @ParentId, 1,  1, GETDATE(), GETDATE(), @ParentId          
    From  #tmpUserEnquiry         
    Where   SourceName not in (Select [Name] from UserSourceSettings(nolock) Where IsActive=1 and Userid=@ParentId)        
        
    INSERT INTO UserMediumSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)          
    Select distinct MediumName, @ParentId, 1,  1, GETDATE(), GETDATE(), @ParentId          
    From  #tmpUserEnquiry         
    Where   MediumName not in (Select [Name] from UserMediumSettings(nolock) Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(MediumName),'') != ''        
        
    INSERT INTO UserCampaignSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)          
    Select distinct CampaignName, @ParentId, 1,  1, GETDATE(), GETDATE(), @ParentId          
    From  #tmpUserEnquiry         
    Where   CampaignName not in (Select [Name] from UserCampaignSettings(nolock) Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(CampaignName),'') != ''        
        
    Update #tmpUserEnquiry         
    Set SourceName=(Select top 1 SourceId From UserSourceSettings Where IsActive=1 and UserID=@ParentId and [Name]=SourceName),  
    MediumName=isnull((Select top 1 MediumID From UserMediumSettings Where IsActive=1 and UserID=@ParentId and [Name]=MediumName),0),        
    CampaignName=isnull((Select top 1 CampaignID From UserCampaignSettings Where IsActive=1 and UserID=@ParentId and [Name]=CampaignName),0)        
        
    If(@IsAutoLeadGeneration = 1)        
    Begin        
    Select top 1 @strAgentlst=Agents, @LastAssignedUser=isnull(LastUserAssigned,UserID) From CRMCampaignSettings Where IsActive=1 and UserID=@ParentId        
      
 insert into #tmptblAgentList        
    Select value From dbo.fn_Split(@strAgentlst,'#')        
      
    insert into #tblAgentList        
 select AgentId from #tmptblAgentList where Sno >= (Select B.Sno from #tmptblAgentList B Where B.AgentId = @LastAssignedUser)      
      
    insert into #tblAgentList        
 select AgentId from #tmptblAgentList where Sno < (Select B.Sno from #tmptblAgentList B Where B.AgentId = @LastAssignedUser)      
      
    Select @AgentCnt=count(*) from #tblAgentList        
        
    print '@AgentCnt: ' + cast(@AgentCnt as varchar)         
        
    insert into #tmpMobileNoList        
    select MobileNo        
    From UserLeads(nolock)        
    Where ParentID in (@ParentId) and isnull(ltrim(MobileNo),'') != ''        
    union        
    select MobileNo1        
    From UserLeads (nolock)       
    Where ParentID in (@ParentId) and isnull(ltrim(MobileNo1),'') != ''        
    union        
    select MobileNo2        
    From UserLeads(nolock)        
    Where ParentID in (@ParentId) and isnull(ltrim(MobileNo2),'') != ''        
        
    insert into #tmpEmailIdList        
    select EmailID        
    From UserLeads (nolock)       
    Where ParentID in (@ParentId) and isnull(ltrim(EmailID),'') != ''        
    union        
    select EmailID1        
    From UserLeads   (nolock)     
    Where ParentID in (@ParentId) and isnull(ltrim(EmailID1),'') != ''        
    union        
    select EmailID2        
    From UserLeads (nolock)       
    Where ParentID in (@ParentId) and isnull(ltrim(EmailID2),'') != ''        
        
    insert into #tmpConstraintChk        
    Select  distinct Sno, 'MobileNo already present in Leads' as Remarks        
    From        
    (        
    Select  Sno, MobileNo        
    From  #tmpUserEnquiry        
    Where   ISNULL(ltrim(MobileNo),'') != ''        
    union        
    Select  Sno, MobileNo1        
    From  #tmpUserEnquiry        
    Where   ISNULL(ltrim(MobileNo1),'') != ''        
    union        
    Select  Sno, MobileNo2        
    From  #tmpUserEnquiry        
    Where   ISNULL(ltrim(MobileNo2),'') != ''        
    ) A        
    Where A.MobileNo in (Select MobileNo From #tmpMobileNoList)        
        
    insert into #tmpConstraintChk        
    Select  distinct Sno, 'EmailID already present in Leads' as Remarks        
    From        
    (        
    Select  Sno, EmailID        
    From  #tmpUserEnquiry        
    Where   ISNULL(ltrim(EmailID),'') != ''        
    union        
    Select  Sno, EmailID1        
    From  #tmpUserEnquiry        
    Where   ISNULL(ltrim(EmailID1),'') != ''        
    union        
    Select  Sno, EmailID2        
    From  #tmpUserEnquiry        
    Where   ISNULL(ltrim(EmailID2),'') != ''        
    ) A        
    Where A.EmailID in (Select EmailID From #tmpEmailIdList)        
        
    --select count(*) as ConstraintChkCnt1 from #tmpConstraintChk        
        
    Select @NextLeadNo=Isnull(max(LeadNo),0) From UserLeads(nolock) Where ParentID=@ParentId        
        
    INSERT INTO #tmpUserLeads        
       ([EnquiryID], [Sno], [PersonName], [CompanyName], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], [City], [State],        
        [Country], [CountryCode], [CountryCode1], [CountryCode2], [PinCode], [ResidentialAddress], [OfficeAddress], [AssignedTo], [SourceName],        
        [MediumName], [CampaignName], [InitialRemarks], [ParentID], [FollowUpStatus], [NextStatusDate],         
        [Remarks], [Products], [AmountPaid], [CreatedOn], [CreatedBy],         
        [FollowupDate])        
    Select  EnquiryID, Sno, PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,EmailID2,City,[State],        
        Country ,CountryCode,CountryCode1,CountryCode2,PinCode,ResidentialAddress,OfficeAddress, 0 as AssignedTo,SourceName,        
        MediumName ,CampaignName,InitialRemarks,/*@User_Id as*/ ParentID, 1/*Call-Back*/ as FollowUpStatus, DATEADD(day,1,dbo.[fn_getusertimefromindiantime](@User_Id,getdate())) as NextStatusDate,         
        '' as Remarks, '' as Products, 0 as AmountPaid, dbo.[fn_getusertimefromindiantime](@User_Id,getdate()) as CreatedOn, @User_Id as CreatedBy,        
        dbo.[fn_getusertimefromindiantime](@User_Id,getdate()) as FollowupDate        
    From  #tmpUserEnquiry        
    Where  Sno not in (Select distinct Sno From #tmpConstraintChk)        
      
    
  If(@ParentId = @User_Id)    
  begin    
  Update A Set A.AssignedTo=B.AgentId, @LastAssignedUser=B.AgentId      
  From #tmpUserLeads A , #tblAgentList B      
  Where A.Sno%@AgentCnt=B.Sno%@AgentCnt      
  --Select top 10 * from #tmpUserLeads        
   If(isnull(@LastAssignedUser,0) !=0)        
   Begin        
   Update CRMCampaignSettings Set LastUserAssigned=@LastAssignedUser Where IsActive=1 and UserID=@ParentId        
   End        
   end    
    
  else    
  begin    
  update #tmpUserLeads set AssignedTo = @User_Id;    
  end    
    
    
    SELECT @LastLeadId=IDENT_CURRENT('UserLeads')        
        
    INSERT INTO [dbo].[UserLeads]        
       ([LeadNo],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country]        
       ,[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo],[SourceName],[MediumName]        
       ,[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks],[Products],[AmountPaid]        
       ,[CreatedOn],[CreatedBy],[FollowupDate])        
    Select        
       @NextLeadNo+LeadNo, [PersonName], [CompanyName], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], [City], [State], [Country]        
       ,[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo],[SourceName],[MediumName]        
       ,[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks],[Products],[AmountPaid]        
       ,[CreatedOn],[CreatedBy],[FollowupDate]        
    From    #tmpUserLeads        
        
    Select @nLeadInserted=@@ROWCOUNT        
        
       
    Update C Set C.LeadNo = B.LeadNo        
    From #tmpUserLeads A inner join [UserLeads] B  (nolock)      
    ON   A.LeadNo + @NextLeadNo = B.LeadNo inner join #tmpUserEnquiry C        
    ON   A.Sno = C.Sno        
    Where B.[ParentID] = @ParentId        
     
	 /*       
 --   Update TUE set TUE.LeadNo = (Select top 1 UL.LeadNo From UserLeads(nolock) UL where UL.ParentID=TUE.ParentID and (Iif(isnull(UL.MobileNo,'') = '', 'm',UL.MobileNo) in (TUE.MobileNo,TUE.MobileNo1,TUE.MobileNo2) or Iif(isnull(UL.MobileNo1,'') = '', 'm', UL.MobileNo1) in (TUE.MobileNo,TUE.MobileNo1,TUE.MobileNo2) or Iif(isnull(UL.MobileNo2,'') = '', 'm',UL.MobileNo2) in (TUE.MobileNo,TUE.MobileNo1,TUE.MobileNo2) or Iif(isnull(UL.EmailID,'') = '', 'e', UL.EmailID) in (TUE.EmailID,TUE.EmailID1,TUE.EmailID2) or Iif(isnull(UL.EmailID1,'') = '', 'e', UL.EmailID1) in (TUE.EmailID,TUE.EmailID1,TUE.EmailID2) or Iif(isnull(UL.EmailID2,'') = '', 'e', UL.EmailID2) in (TUE.EmailID,TUE.EmailID1,TUE.EmailID2) ))      
 --From #tmpUserEnquiry TUE      
 --Where TUE.Sno in (Select distinct TCC.Sno From #tmpConstraintChk TCC where TCC.Remarks like '%already present in Leads')      
     */ 
       
    SELECT @LastEnquiryId=IDENT_CURRENT('UserEnquiry')        
        
    INSERT INTO UserEnquiry        
       ([PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country]        
       ,[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName]        
       ,[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],/*IsOpen,*/LeadNo)        
    Select [PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country]        
       ,[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName]        
       ,[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy],/*IIf(isnull(LeadNo,0)>0,0,1),*/LeadNo        
    From #tmpUserEnquiry        
        
    Select @nEnquiriesInserted=@@ROWCOUNT        
        
    set @jRow = 1        
    while(@jRow <= @CustomFieldsCnt)        
    begin        
    select @fieldId=fieldId,@fieldName=fieldName from #tblCustomFields Where RowId=@jRow        
        
    set @SQLString = 'insert into customfieldLeadvalue select distinct A.ID, C.EnquiryID, ' + cast(@fieldId as varchar) + ', D.[' + @fieldName + ']        
    From [UserLeads] A inner join #tmpUserEnquiry B        
    ON   A.LeadNo = B.LeadNo inner join UserEnquiry C        
    On  B.LeadNo = C.LeadNo inner join #tmpEnquirySrc D        
    On  B.Sno = D.Sno        
    Where A.[ParentID] = ' + cast(@ParentId as varchar) + ' and isnull(D.[' + @fieldName + '],'''') != '''' '        
            
    print 'custom field Lead @SQLString: ' + @SQLString        
        
    exec (@SQLString)        
    Select @nLeadCustomFieldRows+=@@ROWCOUNT        
        
    set @jRow = @jRow + 1        
    end        
         
    End        
    Else        
    Begin        
    SELECT @LastEnquiryId=IDENT_CURRENT('UserEnquiry')        
        
    INSERT INTO UserEnquiry        
       ([PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country]        
       ,[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName]        
       ,[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy])        
    Select [PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country]        
       ,[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName]        
       ,[CampaignName],[InitialRemarks],[ParentID],[CreatedDate],[CreatedBy]        
    From #tmpUserEnquiry        
        
    Select @nEnquiriesInserted=@@ROWCOUNT        
    End        
        
 set @jRow = 1        
    while(@jRow <= @CustomFieldsCnt)        
    begin        
    select @fieldId=fieldId,@fieldName=fieldName from #tblCustomFields Where RowId=@jRow        
        
    set @SQLString = 'insert into customfieldEnquiryvalue select distinct C.EnquiryID, ' + cast(@fieldId as varchar) + ', A.[' + @fieldName + ']         
    from    #tmpEnquirySrc A inner join #tmpUserEnquiry B        
    on    A.Sno=B.Sno inner join UserEnquiry C (nolock)        
    on    B.PersonName = C.PersonName and isnull(B.MobileNo,'''') = isnull(C.MobileNo,'''') and isnull(B.MobileNo1,'''') = isnull(C.MobileNo1,'''') and isnull(B.MobileNo2,'''') = isnull(C.MobileNo2,'''') and isnull(B.EmailID,'''') = isnull(C.EmailID,'''')
        
 and isnull(B.EmailID1,'''') = isnull(C.EmailID1,'''') and isnull(B.EmailID2,'''') = isnull(C.EmailID2,'''')        
    Where   C.EnquiryID > ' + cast(@LastEnquiryId as varchar) + ' and C.EnquiryID <= ' + cast(@LastEnquiryId  as varchar) + ' + ' +  cast(@nEnquiriesInserted as varchar) + ' and isnull(A.[' + @fieldName + '],'''') != '''' '        
            
    print 'custom field enquiry @SQLString: ' + @SQLString        
        
    exec (@SQLString)        
    select @nEnquiryCustomFieldRows+=@@ROWCOUNT        
        
    set @jRow = @jRow + 1        
    end        
        
    Set @RowData = isnull((Select * From #tmpConstraintChk order by Sno for json auto, INCLUDE_NULL_VALUES),'')        
        
    update tbl_EnquiryImportSummary         
    set IsProcessed=1, Remarks=@RowData, EnquiryCnt=@nEnquiriesInserted, EnquiryCustomFieldCnt=@nEnquiryCustomFieldRows, LeadCnt=@nLeadInserted, LeadCustomFieldCnt=@nLeadCustomFieldRows        
    where ImportRow_Id=@ImportRow_id        
      
 Iter:        
    Set @iRow = @iRow + 1        
    Set @ImportRow_id=0        
    Set @ImportData=null        
    Set @RowData=null        
    Set @FieldNames=''        
    Set @SQLString=null        
    Set @User_Id=0        
    Set @LastEnquiryId=0        
    Set @LastLeadId=0        
    Set @nEnquiriesInserted=0        
    Set @nEnquiryCustomFieldRows=0        
    Set @nLeadInserted=0        
    Set @nLeadCustomFieldRows=0        
    Set @jRow=1        
    Set @fieldId=0        
    Set @fieldName=''        
    Set @CustomFieldsCnt = 0        
        
    truncate table #tmpUserEnquiry        
    truncate table #tmpConstraintChk        
    truncate table #tmpUserLeads        
    truncate table #tmpMobileNoList        
    truncate table #tmpEmailIdList        
    truncate table #tblAgentList        
    truncate table #tblCustomFields        
        
    if object_id('tempdb..#tmpEnquirySrc') is not null begin drop table #tmpEnquirySrc end        
        
    End        
        
    COMMIT TRANSACTION          
END TRY            
BEGIN CATCH           
    IF @@TRANCOUNT > 0          
    ROLLBACK TRANSACTION          
 DECLARE  @ErrorMessage  NVARCHAR(4000),          
             @ErrorSeverity INT,            
             @ErrorState    INT;            
          
    SELECT             
        @ErrorMessage  = ERROR_MESSAGE(),            
        @ErrorSeverity = ERROR_SEVERITY(),           
        @ErrorState    = ERROR_STATE();           
                   
    SET @ErrorMessage=@ErrorMessage           
          
    RAISERROR (@ErrorMessage, -- Message text.            
                 @ErrorSeverity, -- Severity.            
                 @ErrorState -- State.            
               );            
END CATCH            
        
if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end        
if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end        
if object_id('tempdb..#tmptblAgentList') is not null begin drop table #tmptblAgentList end        
if object_id('tempdb..#tblAgentList') is not null begin drop table #tblAgentList end        
if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end        
if object_id('tempdb..#tblAllEnquiryFields') is not null begin drop table #tblAllEnquiryFields end        
if object_id('tempdb..#tmpEnquirySrc') is not null begin drop table #tmpEnquirySrc end        
if object_id('tempdb..#tmpUserEnquiry') is not null begin drop table #tmpUserEnquiry end        
if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end        
if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end        
if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end        
        
END   


GO

/* ============================================================
   Procedure: [dbo].[usp_processeventcampaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_processeventcampaign]                        
as                        
begin                        
--exec [usp_processeventcampaign_opt]  
--Commented earlier proc and used optimized proc by Krishna  
drop table if exists #upec                        
select top 50 s.id,activityid,s.eventid,tcampaignid,s.std_trgid,s.std_entity_id,s.scheduledaction,s.bot_type,s.bot_campaignid, u.MailBotId

into #upec from scheduledtodos(nolock) s                    
left join UserCampaignMaster (nolock) u on s.tcampaignid=u.id and u.IsActive=1 
left join voice_bot_campaigns (nolock) v on s.bot_campaignid=v.id and v.IsActive=1 and s.bot_type='voice'                    
left join triggeredcampaigns(nolock) t on u.id in (t.smscampaignid,t.mailcampaignid,t.whatsappcampaignid,t.voicecampaignid)                    
and t.isactive=1     
left join triggeredcampaigns(nolock) t1 on v.id =t1.bot_campaignid and t1.botType='voice' and t1.isactive=1
where scheduledaction in ('Botcampaign','campaign') --and s.parentid<>46329        
and                   
1= case when u.id is null and datediff(mi,scheduledfor,getdate()) between 0  and 180 then 1               
--1= case when u.id is null and cast(scheduledfor as date)=cast(getdate() as date) then 1                    
--when isnull(u.TimeBeforeEvent,0)=0 and cast(scheduledfor as date)=cast(getdate() as date) then 1                  
when isnull(u.TimeBeforeEvent,0)=0 and datediff(mi,scheduledfor,getdate()) between 0  and 180 then 1                  
when getdate() >=                    
case when u.TimeBeforeEvent=0 then scheduledfor                         
when u.timeunit='day' then dateadd(dd,0-u.timebeforeevent,scheduledfor)                        
when u.timeunit='hour' then dateadd(hh,0-u.timebeforeevent,scheduledfor)                        
when u.timeunit='minute' then dateadd(mi,0-u.timebeforeevent,scheduledfor)                        
when u.timeunit='second' then dateadd(ss,0-u.timebeforeevent,scheduledfor) end                     
then 1 else 0 end                    
and (isnotified=0 or (isnotified=2 and datediff(mi,scheduledfor,getdate())<=180               
--and (isnotified=0 or (isnotified=2 and cast(scheduledfor as date)=cast(getdate() as date)               
and datediff(mi,processedat,getdate())>10)) and (tcampaignid is not null or s.bot_campaignid is not null)                  
--and (s.eventid not in (10,37))-- or s.id <=2398371)              
order by s.id              
--order by case when s.parentid=41556 then 0 else 1 end              
              
update s set isnotified=2,processedat=getdate() from scheduledtodos s join #upec u on s.id=u.id                
--select * from #upec                  
declare @c int=(select count(1) from #upec),@id bigint=0,@context nvarchar(20),@eventid int,@activityid bigint ,@cid bigint,@entityid bigint,@campaigntype nvarchar(100)  ,@botcampaignid bigint,@bot_type varchar(20), @mailbotId bigint = 0     
         
,@errormessage nvarchar(2000)=null   ,@stg_id bigint                   
while @c>0                        
begin                        
select @id=min(id) from #upec where id>@id                        
select @activityid=activityid,@eventid=eventid,@cid=tcampaignid,@stg_id=@stg_id, @errormessage=null,@entityid=std_entity_id,@campaigntype=scheduledaction
,@botcampaignid=bot_campaignid,@bot_type=bot_type, @mailbotId = MailBotId

from #upec where id=@id         
select @context=context from ActivityMaster(nolock) where id=@eventid            
        
if dbo.fn_getentityactivitycount_opt(@context,@entityid,@eventid,@campaigntype,isnull(@cid,@stg_id))>99        
begin        
set @errormessage='Max day limit for the execution of this campaign for given entity reached'        
update scheduledtodos set isnotified=1,processedat=getdate(),s_errormessage=isnull(nullif(s_errormessage,''),'')+' '+isnull(@errormessage,'') where id=@id                      
end        
else        
begin  
if @campaigntype='Campaign'
begin
    if(isnull(@mailbotId,0) > 0)
    begin
        exec usp_executeeventcampaign_mailbot @context,@activityid,@cid,@stg_id,@errormessage output
    end
    else
    begin
      exec usp_executeeventcampaign @context,@activityid,@cid,@stg_id,@errormessage output   
    end
end
else if @campaigntype='Botcampaign'
begin
if @bot_type='voice'
begin
--select @context,@activityid,@botcampaignid,@stg_id,@errormessage output 
exec usp_executevoiceeventcampaign @context,@activityid,@botcampaignid,@errormessage output 
end
end
--set @errormessage=@errormessage        
update scheduledtodos set isnotified=1,processedat=getdate(),s_errormessage=isnull(nullif(s_errormessage,''),'')+' '+isnull(@errormessage,'') where id=@id                     
end        
set @c=@c-1                      
end   

end 


GO

/* ============================================================
   Procedure: [dbo].[usp_processeventcampaign_opt]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_processeventcampaign_opt]                      
as                      
begin                      
drop table if exists #upec    
  
  /*  
  Added : DBA  
  Date : 2025-05-22  
  */  
  
  DECLARE @current_dt AS DATETIME;  
  SELECT @current_dt = GETDATE();  
  
  CREATE TABLE #ScheduledFor (ParentID BIGINT, CutoffDate DATETIME);  
  
  /*  
  The temp. table #ScheduledFor find maximum number of days  
  for each ParentID  
  */  
  ;with CTE_cutoff_days1  
  AS  
  (  
  SELECT ParentID, TimeUnit,    
   CASE UPPER(isnull(TimeUnit,'second'))  
    WHEN 'SECOND' THEN CAST(MAX(isnull(TimeBeforeEvent,0)) / 86400.0 AS NUMERIC (18, 9))  
    WHEN 'MINUTE' THEN CAST(MAX(isnull(TimeBeforeEvent,0)) / 1440.0 AS NUMERIC (18, 9))  
    WHEN 'HOUR' THEN CAST(MAX(isnull(TimeBeforeEvent,0)) / 24.0 AS NUMERIC (18, 9))  
    WHEN 'DAY' THEN CAST(MAX(isnull(TimeBeforeEvent,0)) / 1.0 AS NUMERIC (18, 9))  
    ELSE 365  
   END AS Max_Days  
  FROM UserCampaignMaster a WITH (NOLOCK)  
  --WHERE TimeUnit IS NOT NULL AND TimeUnit != ''  
  GROUP BY ParentID, TimeUnit  
  ),  
  CTE_cutoff_days2  
  AS  
  (  
  SELECT  
   ParentID, CAST(CEILING(MAX(Max_Days)) AS INT) cut_off_days  
  FROM CTE_cutoff_days1  
  GROUP BY ParentID  
  )  
  INSERT INTO #ScheduledFor (ParentID, CutoffDate)  
  SELECT ParentID, DATEADD(DAY, -1 * IIF(cut_off_days=0.00, 1, cut_off_days), @current_dt)  
  FROM CTE_cutoff_days2;  
  
  -- Populate #s with data from scheduledtodos on or after CutoffDate  
  SELECT s.id, s.parentid, s.eventid, s.activityid, s.scheduledfor,   
    s.isnotified, s.isvalid,s.tcampaignid  
    ,s.std_trgid,s.std_entity_id,s.scheduledaction, s.processedat  
  INTO #s  
  FROM scheduledtodos s WITH (NOLOCK)  
    join #ScheduledFor ts   
     on s.parentid=ts.parentid  
    WHERE s.scheduledfor >= ts.CutoffDate  
    OPTION (MAXDOP 1);  
  
select top 50 s.id,activityid,s.eventid,tcampaignid,s.std_trgid,s.std_entity_id,s.scheduledaction into #upec   
from #s s                  
left join UserCampaignMaster (nolock) u on s.tcampaignid=u.id and u.IsActive=1                  
left join triggeredcampaigns(nolock) t on u.id in (t.smscampaignid,t.mailcampaignid,t.whatsappcampaignid,t.voicecampaignid)                  
and t.isactive=1                  
where scheduledaction='campaign' --and s.parentid<>46329      
and                 
1= case when u.id is null and datediff(mi,scheduledfor,@current_dt) between 0  and 180 then 1             
--1= case when u.id is null and cast(scheduledfor as date)=cast(getdate() as date) then 1                  
--when isnull(u.TimeBeforeEvent,0)=0 and cast(scheduledfor as date)=cast(getdate() as date) then 1                
when isnull(u.TimeBeforeEvent,0)=0 and datediff(mi,scheduledfor,@current_dt) between 0  and 180 then 1                
when getdate() >=                  
case when u.TimeBeforeEvent=0 then scheduledfor                       
when u.timeunit='day' then dateadd(dd,0-u.timebeforeevent,scheduledfor)                      
when u.timeunit='hour' then dateadd(hh,0-u.timebeforeevent,scheduledfor)                      
when u.timeunit='minute' then dateadd(mi,0-u.timebeforeevent,scheduledfor)                      
when u.timeunit='second' then dateadd(ss,0-u.timebeforeevent,scheduledfor) end                   
then 1 else 0 end                  
and (isnotified=0 or (isnotified=2 and datediff(mi,scheduledfor,@current_dt)<=180             
--and (isnotified=0 or (isnotified=2 and cast(scheduledfor as date)=cast(getdate() as date)             
and datediff(mi,processedat,@current_dt)>10)) and tcampaignid is not null                
--and (s.eventid not in (10,37))-- or s.id <=2398371)            
order by s.id            
--order by case when s.parentid=41556 then 0 else 1 end            
            
update s set isnotified=2,processedat=getdate() from scheduledtodos s join #upec u on s.id=u.id              
--select * from #upec                
declare @c int=(select count(1) from #upec),@id bigint=0,@context nvarchar(20),@eventid int,@activityid bigint ,@cid bigint,@entityid bigint,@campaigntype nvarchar(100)    
       
,@errormessage nvarchar(2000)=null   ,@stg_id bigint                 
while @c>0                      
begin                      
select @id=min(id) from #upec where id>@id                      
select @activityid=activityid,@eventid=eventid,@cid=tcampaignid,@stg_id=@stg_id, @errormessage=null,@entityid=std_entity_id,@campaigntype=scheduledaction from #upec where id=@id       
select @context=context from ActivityMaster(nolock) where id=@eventid          
      
if dbo.fn_getentityactivitycount_opt(@context,@entityid,@eventid,@campaigntype,isnull(@cid,@stg_id))>99      
begin      
set @errormessage='Max day limit for the execution of this campaign for given entity reached'      
update scheduledtodos set isnotified=1,processedat=getdate(),s_errormessage=isnull(nullif(s_errormessage,''),'')+' '+isnull(@errormessage,'') where id=@id                    
end      
else      
begin      
exec usp_executeeventcampaign @context,@activityid,@cid,@stg_id,@errormessage output      
--set @errormessage=@errormessage      
update scheduledtodos set isnotified=1,processedat=getdate(),s_errormessage=isnull(nullif(s_errormessage,''),'')+' '+isnull(@errormessage,'') where id=@id                   
end      
set @c=@c-1                    
end                      
end 


GO

/* ============================================================
   Procedure: [dbo].[usp_ProcessLeadImportData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--Dependency of this usp_ProcessLeadImportData

--1.[MySMSConversations].[dbo].[tbl_imp_ImportRequest]       -- called by clr
--2. usp_ProcessEnquiryImportData_corrected  -- called by clr 

-------------------------------------


 
-- Exec usp_ProcessLeadImportData 0, 'P'              
-- Exec usp_ProcessLeadImportData 1, 'P'              
-- Exec usp_ProcessLeadImportData 1, 'P', 1814              
CREATE  PROC [dbo].[usp_ProcessLeadImportData] --1,'p', 3233             
(                
 @BatchSize int=1,  -- 0 ('All')                
 @Mode varchar(1)='P',    -- 'P'riority, 'F'ifo          
 @IPRId bigint=0          
)                
AS                
BEGIN                
                
 --  declare @BatchSize int=1,@Mode varchar(1)='P', @IPRId bigint=3233  
  DECLARE @sqlquery NVARCHAR(MAX);      
 if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end                
 if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end                
 if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end                
 if object_id('tempdb..#tblAllLeadFields') is not null begin drop table #tblAllLeadFields end                
 if object_id('tempdb..#tmpLeadSrc') is not null begin drop table #tmpLeadSrc end                
 if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end                
 if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end                
 if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end                
 if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end  
 if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end  
 if object_id('tempdb..#tmpTblPrdct2') is not null begin drop table #tmpTblPrdct2 end  
 if object_id('tempdb..#outputLead') is not null begin drop table #outputLead end  

  
 Create table #tblImportRowId  
 (                
  RowId int identity,                
  ImportRow_id bigint,                
  [User_Id] bigint                
 )                
                
 create table #tmpConstraintChk  
 (                
  Sno int,                
  Remarks varchar(200)                
 )                
                
 create table #tblCustomFields  
 (                
  RowId int identity(1,1),                
  fieldId bigint,                
  fieldName varchar(50)                
 )                
                
 create table #tblAllLeadFields  
 (                
  RowId int identity(1,1),                
  fieldName varchar(50),            
  FieldType varchar(10)            
 )                
                
 create table #tmpMobileNoList  
 (                
  RowId int identity,                
  MobileNo varchar(100)                
 )                
                
 create table #tmpEmailIdList  
 (                
  RowId int identity,                
  EmailId varchar(100)                
 )                
                
 CREATE TABLE #tmpUserLeads   
 (  
  [LeadNo] [bigint] IDENTITY(1,1) NOT NULL,                
  [Sno] [int] NOT NULL,                
  [PersonName] [nvarchar](400) NULL,                
  [CompanyName] [nvarchar](1000) NULL,                
  [MobileNo] [varchar](100) NULL,                
  [MobileNo1] [varchar](100) NULL,                
  [MobileNo2] [varchar](100) NULL,                
  [EmailID] [varchar](100) NULL,                
  [EmailID1] [varchar](100) NULL,                
  [EmailID2] [varchar](100) NULL,                
  [City] [varchar](100) NULL,                
  [State] [varchar](100) NULL,                
  [Country] [varchar](100) NULL,                
  [CountryCode] [varchar](50) NULL,                
  [CountryCode1] [varchar](50) NULL,                
  [CountryCode2] [varchar](50) NULL,                
  [PinCode] [bigint] NULL,                
  [ResidentialAddress] [nvarchar](500) NULL,                
  [OfficeAddress] [nvarchar](500) NULL,                
  [AssignedTo] [bigint] NOT NULL,                
  [SourceName] [bigint] DEFAULT ((0)) NOT NULL,                
  [MediumName] [bigint] DEFAULT ((0)) NULL,                
  [CampaignName] [bigint] DEFAULT ((0)) NULL,                
  [InitialRemarks] [nvarchar](1000) NULL,                
  [ParentID] [bigint] NOT NULL,                
  [FollowUpStatus] [bigint] NULL,                
  [NextStatusDate] [varchar](50) NULL,                
  [Remarks] [nvarchar](1000) NULL,                
  [Products] [varchar](1000) NULL,  
 -- [ProductsJson] [nvarchar](max) NULL,  
  [AmountPaid] [numeric](18, 2) NOT NULL DEFAULT ((0)),                
  [CreatedOn] [datetime] NULL,                
  [CreatedBy] [bigint] NULL,        
  [FollowupDate] [datetime] NULL,          
  [WhatsAppNoColName] varchar(10)          
 )                
                
 BEGIN TRY  
  --BEGIN TRANSACTION                
          
   If(isnull(@IPRId,0) > 0)          
   Begin          
    insert into #tblImportRowId          
    Select ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where ImportRow_id=@IPRId          
   End          
   Else          
   Begin          
    If(@Mode = 'P')            
    Begin                
     If(@BatchSize != 0)                
     Begin                
      insert into #tblImportRowId                
      Select top (@BatchSize) ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where IsProcessed=0 order by [Priority]                
     End                
     Else                
     Begin                
      insert into #tblImportRowId                
      Select ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where IsProcessed=0 order by [Priority]                
     End                
    End                
    Else -- Fifo                
    Begin                
     If(@BatchSize != 0)                
     Begin                
      insert into #tblImportRowId                
      Select top (@BatchSize) ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where IsProcessed=0                
     End                
     Else                
     Begin                
      insert into #tblImportRowId                
      Select ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where IsProcessed=0                
     End                
    End              
   End          
  
   select * from #tblImportRowId                
                
   declare @iRow int=1, @jRow int=1, @ImportRow_id bigint=0, @UnProcessedRowCnt int=0, @User_Id bigint=0, @LastLeadId bigint=0, @nLeadInserted bigint=0, @fieldId bigint=0, @nLeadCustomFieldRows bigint=0, @CsvID nvarchar(max), @nFollowupInserted bigint=0  
   declare @ImportData nvarchar(max), @RowData nvarchar(max), @FieldNames nvarchar(max)='', @SQLString nvarchar(max)='', @ParmDefinition nvarchar(500), @fieldName varchar(50)='',@fieldtype nvarchar(20);                  
   declare @NextLeadNo bigint=0, @CustomFieldsCnt int=0, @ParentId bigint=0, @CreatedOn datetime, @ImportRequestId bigint=0, @RecCnt int =0, @Pagesize int=500, @Pageno int=1, @Start int=0, @End int=0               
   declare @eventname nvarchar(100),@eventdescription nvarchar(500),@userlogin nvarchar(100),@tic int            
   select @UnProcessedRowCnt=Count(*) from #tblImportRowId                
                
   While(@iRow <= @UnProcessedRowCnt)                
   Begin                
      print '@iRow: ' + cast(@iRow as varchar)                
      Select @ImportRow_id=ImportRow_id,@User_Id=[User_Id] From #tblImportRowId Where RowId=@iRow                
      print '@ImportRow_id: ' + cast(@ImportRow_id as varchar)                
      Select @ImportData=ImportData from tbl_LeadImportSummary(nolock) where ImportRow_Id=@ImportRow_id                
      print '@ImportData: ' + @ImportData                
      select top 1 @RowData=value from openjson(@ImportData)                
      print '@RowData: ' + @RowData                
      select @FieldNames=@FieldNames+'['+[Key]+'] nvarchar(2000),' from openjson(@RowData)                
      print '@FieldNames1: ' + @FieldNames                
  
      If (CHARINDEX('WhatsAppNoColName',@FieldNames,0) > 0)          
      Begin          
      print 'WhatsAppNoColName found'          
      set @FieldNames=SUBSTRING(@FieldNames,1,len(@FieldNames)-1)                
      End          
      Else          
      Begin          
        print 'WhatsAppNoColName not found, adding dummy'          
        select @FieldNames=@FieldNames+' [WhatsAppNoColName] varchar(10)'          
        select @RowData=replace(@RowData,'}',',"WhatsAppNoColName":null}')          
      End          
      print '@FieldNames2: ' + @FieldNames                
              
      Select @ParentId=parentid,@userlogin=User_Login from user_detail(nolock) where user_id= @User_Id    
            
      insert into #tblAllLeadFields            
      values ('Sno','Main'),('PersonName','Main'),('CompanyName','Main'),('MobileNo','Main'),('MobileNo1','Main'),('MobileNo2','Main'),('EmailID','Main'),('EmailID1','Main'),('EmailID2','Main'),('City','Main'),('State','Main'),('Country','Main'),('CountryCode','Main'),('CountryCode1','Main'),('CountryCode2','Main'),('PinCode','Main'),('ResidentialAddress','Main'),('OfficeAddress','Main'),('AssignedTo','Main'),('SourceName','Main'),('MediumName','Main'),('CampaignName','Main'),('InitialRemarks','Main'),('FollowupStatus','Main'),('NextStatusDate','Main'),('Remarks','Main'),('Products','Main'),('AmountPaid','Main'),('FollowupDate','Main'), ('WhatsAppNoColName','Main')           
            
      insert into #tblAllLeadFields            
      select fieldname,'Custom' from customfields(nolock) where parentId=@ParentId and isActive=1            
            
      Update tbl_LeadImportSummary Set IsProcessed=1,importstart=getdate(),Remarks='[{"Sno":0,"Remarks":"Under Process Queue"}]'           
      Where ImportRow_Id = @ImportRow_id          
          
      if exists(select [Key] from openjson(@RowData) where [Key] COLLATE SQL_Latin1_General_CP1_CI_AS not in (Select FieldName From #tblAllLeadFields))          
      Begin          
      print 'Invalid Field found in Import Data'          
      Update tbl_LeadImportSummary Set IsProcessed=1,importend=getdate(),Remarks='[{"Sno":0,"Remarks":"Invalid Field found in Import Data"}]'  
      Where ImportRow_Id = @ImportRow_id    
  
      select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@tic as nvarchar) +' leads for importing. The request failed. Pl check Import summary for details'     
      exec UspSaveEntityActivity_withid 'user',@user_id,@user_id,@ParentID,@EventDescription,@EventName,'tbl_LeadImportSummary',@ImportRow_id  
      exec Usp_InsertUserEventDetails 'Lead Import failed',@parentid,@eventdescription, 'tbl_LeadImportSummary',@ImportRow_id  
   
      goto Iter          
      End  
      Else          
      Begin          
        If exists(Select FieldName From #tblAllLeadFields Where FieldName COLLATE SQL_Latin1_General_CP1_CI_AS not in (select [Key] from openjson(@RowData)))          
        Begin          
       print 'Required Field Missing in Import Data'          
       Update tbl_LeadImportSummary Set IsProcessed=1,importend=getdate(),Remarks='[{"Sno":0,"Remarks":"Required Field Missing in Import Data"}]'          
       Where ImportRow_Id = @ImportRow_id          
  
       select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@tic as nvarchar) +' leads for importing.     
         The request failed. Pl check Import summary for details'     
       exec UspSaveEntityActivity_withid 'user', @user_id, @user_id, @ParentID, @EventDescription, @EventName, 'tbl_LeadImportSummary', @ImportRow_id  
       exec Usp_InsertUserEventDetails 'Lead Import failed',@parentid,@eventdescription, 'tbl_LeadImportSummary',@ImportRow_id  
   
       goto Iter          
        End          
      End          
            
      create table #tmpLeadSrc (id int identity);                
      print 'alter table #tmpLeadSrc add ' + @FieldNames                
      exec('alter table #tmpLeadSrc add ' + @FieldNames)                
                
      --Set @SQLString = N'insert into #tmpLeadSrc select * from openjson(@ImptData) with (' + @FieldNames + ') where [PersonName] is not null and [MobileNo] is not null and [CountryCode] is not null and [ResidentialAddress] is not null and [SourceName] is not null and [InitialRemarks] is not null and [FollowupStatus] is not null'                 
      Set @SQLString = N'insert into #tmpLeadSrc select * from openjson(@ImptData) with (' + @FieldNames + ')'    
                 --Set @SQLString = N'insert into #tmpLeadSrc select * from openjson(@ImptData) with (' + @FieldNames + ') where [Sno] is not null'    
                
      --SET @ParmDefinition = N'@ImptData nvarchar(max), @FldNames nvarchar(max)';                  
      SET @ParmDefinition = N'@ImptData nvarchar(max)';      
    
      if object_id('tempdb..#tmpLeadSrc') is not null     
      begin     
      select @tic=count(1) from #tmpLeadSrc    
      end                
   
      print @SQLString                
                
      --EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData, @FldNames=@FieldNames                  
      EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData                  
              
      --select * from openjson(@RowData)                
            
      update #tmpLeadSrc                 
      set MobileNo=rtrim(ltrim(case when isnull(MobileNo,'')='' and isnull(MobileNo1,'')!='' then MobileNo1 else Isnull(MobileNo,'') end)),          
      MobileNo1=rtrim(ltrim(case when isnull(MobileNo1,'')='' and isnull(MobileNo2,'')!='' then MobileNo2 else Isnull(MobileNo1,'') end)),          
      MobileNo2=rtrim(ltrim(isnull(MobileNo2,''))),                
      CountryCode=rtrim(ltrim(case when isnull(CountryCode,'')='' and isnull(CountryCode1,'')!=''      
      then iif(left(ltrim(CountryCode1),1) != '+','+'+ltrim(CountryCode1),CountryCode1) else iif(left(ltrim(Isnull(CountryCode,'')),1) != '+' and ltrim(Isnull(CountryCode,'')) != '', '+'         
      + ltrim(Isnull(CountryCode,'')),Isnull(CountryCode,'')) end)),                
      CountryCode1=rtrim(ltrim(case when isnull(CountryCode1,'')='' and isnull(CountryCode2,'')!=''    
      then iif(left(ltrim(CountryCode2),1) != '+','+'+ltrim(CountryCode2),CountryCode2) else iif(left(ltrim(Isnull(CountryCode1,'')),1) != '+' and ltrim(Isnull(CountryCode1,'')) != '', '+'        
      + ltrim(Isnull(CountryCode1,'')),Isnull(CountryCode1,'')) end)),                
      CountryCode2=rtrim(ltrim(iif(left(ltrim(isnull(CountryCode2,'')),1) != '+' and ltrim(isnull(CountryCode2,'')) != '','+' + ltrim(isnull(CountryCode2,'')),Isnull(CountryCode2,'')))),      
      EmailID=rtrim(ltrim(case when isnull(EmailID,'')='' and isnull(EmailID1,'')!='' then EmailID1 else Isnull(EmailID,'') end)),                
      EmailID1=rtrim(ltrim(case when isnull(EmailID1,'')='' and isnull(EmailID2,'')!='' then EmailID2 else Isnull(EmailID1,'') end)),                
      EmailID2=rtrim(ltrim(isnull(EmailID2,''))),                
      PersonName=rtrim(ltrim(isnull(PersonName,''))),                
      InitialRemarks=rtrim(ltrim(isnull(InitialRemarks,''))),                
      AssignedTo=rtrim(ltrim(isnull(REPLACE(AssignedTo,CHAR(160),''),''))),                
      SourceName=rtrim(ltrim(isnull(SourceName,''))),                
      MediumName=rtrim(ltrim(isnull(MediumName,''))),                
      CampaignName=rtrim(ltrim(isnull(CampaignName,''))),                
      FollowupStatus=rtrim(ltrim(isnull(FollowupStatus,''))),                
      NextStatusDate=rtrim(ltrim(isnull(NextStatusDate,''))),                
      Remarks=rtrim(ltrim(isnull(Remarks,''))),                
      Products=rtrim(ltrim(isnull(Products,''))),                
      AmountPaid=rtrim(ltrim(isnull(AmountPaid,'0'))),                
      FollowupDate=rtrim(ltrim(isnull(FollowupDate,'0'))),                
      WhatsAppNoColName=rtrim(ltrim(isnull(WhatsAppNoColName,''))),                
      Sno=rtrim(ltrim(isnull(Sno,0)))                
                
      --EXEC('select * from #tmpLeadSrc')                
  
      insert into #tmpConstraintChk                
      Select  Sno, 'Duplicate Records' as Remarks                
      From                
      (                
       select ROW_NUMBER()over(partition by PersonName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, InitialRemarks           
       order by cast(Sno as int)) as Rid, *                
       from #tmpLeadSrc                
      ) B                
      Where B.Rid > 1                
                    
              
      insert into #tblCustomFields                
      select field_ID, fieldname                 
      from customfields(nolock)                 
      where parentId=@ParentId and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select FieldName from #tblAllLeadFields where [FieldType] = 'Custom')                
      /*where parentId=@ParentId and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select [Key]                
      from openjson(@RowData) where [Key] not in ('Sno', 'PersonName', 'CompanyName', 'MobileNo', 'MobileNo1', 'MobileNo2', 'EmailID', 'EmailID1', 'EmailID2', 'City', 'State', 'Country', 'CountryCode', 'CountryCode1', 'CountryCode2', 'PinCode', 'ResidentialAddress', 'OfficeAddress', 'AssignedTo', 'SourceName', 'MediumName', 'CampaignName', 'InitialRemarks', 'FollowupStatus', 'NextStatusDate', 'Remarks', 'Products', 'AmountPaid', 'FollowupDate', 'ProfileImgFileName')) */               
                
      Select @CustomFieldsCnt=count(*) From #tblCustomFields                
                
      insert into #tmpConstraintChk                
      Select  Sno, 'Sno missing' as Remarks                
      From    #tmpLeadSrc                
      Where   ISNULL(ltrim(Sno),'') = '' or ISNULL(ltrim(Sno),'0') = '0'                
      union                
      Select  Sno, 'Sno Duplicate' as Remarks                
      From    #tmpLeadSrc                
      group by Sno                
      having  Count(*) > 1                
      union                
      Select  Sno, 'PersonName missing' as Remarks                
      From    #tmpLeadSrc                
      Where   ISNULL(ltrim(PersonName),'') = ''                
      union                
      Select  Sno, 'Contact details missing' as Remarks                
      From    #tmpLeadSrc                
      Where   ISNULL(ltrim(MobileNo),'') = '' and ISNULL(ltrim(MobileNo1),'') = '' and ISNULL(ltrim(MobileNo2),'') = '' and                 
      ISNULL(ltrim(EmailID),'') = '' and ISNULL(ltrim(EmailID1),'') = '' and ISNULL(ltrim(EmailID2),'') = ''                
      union                
      Select  Sno, 'MobileNo or CountryCode missing' as Remarks                
      From    #tmpLeadSrc                
      Where   ((ISNULL(ltrim(MobileNo),'')!='' and ISNULL(ltrim(CountryCode),'')='') or (ISNULL(ltrim(MobileNo),'')='' and ISNULL(ltrim(CountryCode),'')!=''))                
       or                
      ((ISNULL(ltrim(MobileNo1),'')!='' and ISNULL(ltrim(CountryCode1),'')='') or (ISNULL(ltrim(MobileNo1),'')='' and ISNULL(ltrim(CountryCode1),'')!='')) or                
      ((ISNULL(ltrim(MobileNo2),'')!='' and ISNULL(ltrim(CountryCode2),'')='') or (ISNULL(ltrim(MobileNo2),'')='' and ISNULL(ltrim(CountryCode2),'')!=''))                
      union                
      Select  Sno, 'AssignedTo missing' as Remarks                
      From    #tmpLeadSrc                
      Where   ISNULL(ltrim(AssignedTo),'') = ''                
      union                
      Select  Sno, 'AssignedTo Invalid' as Remarks                
      From    #tmpLeadSrc                
      Where   ISNULL(ltrim(AssignedTo),'') not in (Select [User_Login] from User_Detail(nolock) Where Status=1)                
      union                
      Select  Sno, 'SourceName missing' as Remarks                
      From    #tmpLeadSrc                
      Where   ISNULL(ltrim(SourceName),'') = ''                
      union                
      Select  Sno, 'FollowupStatus missing' as Remarks                
      From    #tmpLeadSrc                
      Where   ISNULL(ltrim(FollowupStatus),'') = ''                
      union                
      Select  Sno, 'FollowupStatus missing' as Remarks                
      From    #tmpLeadSrc                
      Where   ISNULL(ltrim(FollowupStatus),'') not in (Select FollowupStatus from FollowUp_Status(nolock) Where IsActive=1)                
      union                
      Select  Sno, 'FollowupDate missing' as Remarks                
      From    #tmpLeadSrc                
      Where   ISNULL(ltrim(FollowupDate),'') = ''                
      union                
      Select  Sno, 'Invalid FollowupDate' as Remarks                
      From    #tmpLeadSrc                
      Where   ISNULL(ltrim(FollowupDate),'') != '' and ISDATE(FollowupDate) != 1                
      union                
      Select  Sno, 'Invalid NextStatusDate' as Remarks                
      From    #tmpLeadSrc                
      Where   ISNULL(ltrim(NextStatusDate),'') != '' and ISDATE(NextStatusDate) != 1                
      union                
        
      --Select  Sno, 'Invalid Products' as Remarks                
      --From    #tmpLeadSrc                
      --Where   ISNULL(ltrim(Products),'') != '' and Products not like '%#%' and Products not in (select [Name] from ProductMaster(nolock) Where IsActive=1 and UserID=@ParentId)                
      --union  
                      
      --Select  Sno, 'Invalid Products' as Remarks                
      --From    #tmpLeadSrc                
      --Where   Products like '%#%' and dbo.ufn_GetProductId(Products,@ParentId,'#')=''                
      --union                
        
      Select  Sno, 'PersonName Length exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(PersonName)>100                
      union                
      Select  Sno, 'CompanyName exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(CompanyName)>100                
      union                
      Select  Sno, 'MobileNo exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(MobileNo)>100                
      union                
      Select  Sno, 'MobileNo1 exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(MobileNo1)>100                
      union                
      Select  Sno, 'MobileNo2 exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(MobileNo2)>100                
      union                
      Select  Sno, 'EmailID exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(EmailID)>100                
      union                
      Select  Sno, 'EmailID1 exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(EmailID1)>100                
      union                
      Select  Sno, 'City exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(City)>100                
      union                
      Select  Sno, 'State exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(State)>100                
      union                
      Select Sno, 'Country exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(Country)>100                
      union                
      Select  Sno, 'CountryCode exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(CountryCode)>100                
      union                
      Select  Sno, 'CountryCode1 exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(CountryCode1)>100                
      union                
      Select  Sno, 'CountryCode2 exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(CountryCode2)>100                
      union                
      Select  Sno, 'ResidentialAddress exceeds specified limit(500)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(ResidentialAddress)>500                
      union                
      Select  Sno, 'OfficeAddress exceeds specified limit(500)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(OfficeAddress)>500                
      union                
      Select  Sno, 'SourceName exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(SourceName)>100                
      union                
      Select  Sno, 'MediumName exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(MediumName)>100                
      union                
      Select  Sno, 'CampaignName exceeds specified limit(100)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(CampaignName)>100                
      union                
      Select  Sno, 'InitialRemarks exceeds specified limit(1000)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(InitialRemarks)>1000                
      union                
      Select  Sno, 'Remarks exceeds specified limit(1000)' as Remarks                
      From    #tmpLeadSrc                
      Where   len(Remarks)>1000                
      union                
      Select  Sno, 'Invalid Character found in AmountPaid' as Remarks  
      From    #tmpLeadSrc                
      Where   isnull(AmountPaid,'')!='' and try_cast(AmountPaid as numeric(18,2)) is null  
        
        
       exec Usp_createProductMasterTable @ParentID  
  
      Declare @Query1 nvarchar(max) = N'Select  Sno, ''Invalid Products'' as Remarks into #tmpConstraintChk               
      From    #tmpLeadSrc                
      Where   ISNULL(ltrim(Products),'''') != '''' and Products not like ''%#%''   
      and exists ( select value from fn_split(Products, ''#'')    
               where value not in (select [Name] from tbl_ProductMaster_'+ cast(@ParentID as nvarchar(20))+' (nolock)   
      Where IsActive=1 and UserID= '+ cast( @ParentId as nvarchar(20) )+ ' ))'                
       
  
      print 'dynamic query1'  
      print  @Query1  
  
                  exec sp_executesql @Query1      
        
  
      --select * from #tmpConstraintChk  
  
      --Select  Sno, 'Invalid Products' as Remarks                
      --From    #tmpLeadSrc                
      --Where   Products like '%#%' and dbo.ufn_GetProductId(Products,@ParentId,'#')=''                
      --union  
  
       Select ROW_NUMBER() over(order by Sno asc) as RowNum, Sno, Products into #tmpTblPrdct2 from #tmpLeadSrc  where Products like '%#%'  
       Declare @Row_Num1 int = 1  
       DEclare @Count_Prdct2 int = (select count(1) from #tmpTblPrdct2)     
  
       while(@Count_Prdct2 >= @Row_Num1)   
          begin  
            Declare @Sno1 int  
         Declare @ProductsJson_2 nvarchar(500)  
         select @Sno1 = Sno , @ProductsJson_2 = isnull(Products,'') from  #tmpTblPrdct2 where RowNum = @Row_Num1  
  
         declare @Outtemp nvarchar(500) = ''   
                           exec usp_GetProductId @ProductsJson_2, @ParentID,'#' , @Outtemp output  
                        -- select @Outtemp  
        
              if(isnull(@Outtemp,'') = '')  
          begin  
             insert into #tmpConstraintChk    
          Select  Sno, 'Invalid Products' as Remarks                
                      From   #tmpLeadSrc where Sno = @Sno1               
            end   
         set  @Row_Num1 = @Row_Num1 + 1      
       End  
        
        
      /*                
      union                
      Select  Sno, 'Invalid DateOfBirth' as Remarks                
      From    #tmpLeadSrc                
      Where   isnull(ltrim(DateOfBirth),'') != '' and ISDate(DateOfBirth) = 0                
      */                
                
      insert into #tmpMobileNoList                
       select MobileNo                
       From UserLeads(nolock)                
       Where ParentID in (@ParentId) and isnull(ltrim(MobileNo),'') != ''                
       union                
       select MobileNo1                
       From UserLeads(nolock)                
       Where ParentID in (@ParentId) and isnull(ltrim(MobileNo1),'') != ''                
       union                
       select MobileNo2                
       From UserLeads(nolock)                
       Where ParentID in (@ParentId) and isnull(ltrim(MobileNo2),'') != ''                
                
      insert into #tmpEmailIdList                
       select EmailID                
       From UserLeads(nolock)                
       Where ParentID in (@ParentId) and isnull(ltrim(EmailID),'') != ''            
       union                
       select EmailID1                
       From UserLeads(nolock)                
       Where ParentID in (@ParentId) and isnull(ltrim(EmailID1),'') != ''                
       union                
       select EmailID2                
       From UserLeads(nolock)                
       Where ParentID in (@ParentId) and isnull(ltrim(EmailID2),'') != ''                
                
      insert into #tmpConstraintChk                
       Select  distinct Sno, 'MobileNo already present in Leads' as Remarks                
       From                
       (                
       Select  Sno, MobileNo                
       From  #tmpLeadSrc                
       Where   ISNULL(ltrim(MobileNo),'') != ''                
       union                
       Select  Sno, MobileNo1                
       From  #tmpLeadSrc                
       Where   ISNULL(ltrim(MobileNo1),'') != ''                
       union                
       Select Sno, MobileNo2                
       From  #tmpLeadSrc                
       Where   ISNULL(ltrim(MobileNo2),'') != ''                
       ) A                
       Where A.MobileNo in (Select MobileNo From #tmpMobileNoList)                
                
      insert into #tmpConstraintChk                
      Select  distinct Sno, 'MobileNo found Duplicate in Upload' as Remarks                
      From (  
       Select  ROW_NUMBER()over(partition by MobileNo order by Sno) rno,*  
       From                
       (                
       Select  Sno, MobileNo                
       From  #tmpLeadSrc                
       Where   ISNULL(ltrim(MobileNo),'') != ''                
       union                
       Select  Sno, MobileNo1                
       From  #tmpLeadSrc                
       Where   ISNULL(ltrim(MobileNo1),'') != ''                
       union                
       Select Sno, MobileNo2                
       From  #tmpLeadSrc                
       Where   ISNULL(ltrim(MobileNo2),'') != ''                
       ) A                
       ) M  
       where M.rno>1  
                
    insert into #tmpConstraintChk                
       Select  distinct Sno, 'EmailID already present in Leads' as Remarks                
       From                
       (                
       Select  Sno, EmailID                
       From  #tmpLeadSrc                
       Where   ISNULL(ltrim(EmailID),'') != ''                
       union                
       Select  Sno, EmailID1                
       From  #tmpLeadSrc                
       Where   ISNULL(ltrim(EmailID1),'') != ''                
       union                
       Select  Sno, EmailID2                
       From  #tmpLeadSrc                
       Where   ISNULL(ltrim(EmailID2),'') != ''                
       ) A   
       Where A.EmailID in (Select EmailID From #tmpEmailIdList)                
  
      insert into #tmpConstraintChk                
       Select  distinct Sno, 'EmailID found Duplicate in Upload' as Remarks                
       From (  
       Select  ROW_NUMBER()over(partition by EmailID order by Sno) rno,*  
       From                
       (                
       Select  Sno, EmailID                
       From  #tmpLeadSrc                
       Where   ISNULL(ltrim(EmailID),'') != ''                
       union                
       Select  Sno, EmailID1                
       From  #tmpLeadSrc                
       Where   ISNULL(ltrim(EmailID1),'') != ''                
       union                
       Select  Sno, EmailID2                
       From  #tmpLeadSrc                
       Where   ISNULL(ltrim(EmailID2),'') != ''                
       ) A                
       ) M  
       where M.rno>1  
         
      select count(*) as ConstraintChkCnt1 from #tmpConstraintChk                
                
      INSERT INTO UserSourceSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)                  
       Select distinct SourceName, @ParentId, 1,  1, GETDATE(), GETDATE(), @User_Id                  
     From  #tmpLeadSrc                 
       Where   SourceName not in (Select [Name] from UserSourceSettings(nolock) Where IsActive=1 and Userid=@ParentId) and Sno not in (Select distinct Sno from #tmpConstraintChk)                
                
      INSERT INTO UserMediumSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)                  
       Select distinct MediumName, @ParentId, 1,  1, GETDATE(), GETDATE(), @User_Id                  
       From  #tmpLeadSrc                 
       Where   MediumName not in (Select [Name] from UserMediumSettings(nolock) Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(MediumName),'') != '' and Sno not in (Select distinct Sno from #tmpConstraintChk)                
                
      INSERT INTO UserCampaignSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)                  
       Select distinct CampaignName, @ParentId, 1,  1, GETDATE(), GETDATE(), @User_Id                  
       From  #tmpLeadSrc                 
       Where   CampaignName not in (Select [Name] from UserCampaignSettings(nolock) Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(CampaignName),'') != ''and Sno not in (Select distinct Sno from #tmpConstraintChk)                
                
      Update #tmpLeadSrc                 
      Set SourceName=(Select top 1 SourceId From UserSourceSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=SourceName),               
       MediumName=(Select top 1 MediumID From UserMediumSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=MediumName),                
       CampaignName=(Select top 1 CampaignID From UserCampaignSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=CampaignName),          
       AssignedTo=(Select top 1 [User_ID] From User_Detail(nolock) Where [Status]=1 and [User_Login]=AssignedTo),                
       FollowUpStatus=(Select top 1 ID From FollowUp_Status(nolock) Where IsActive=1 and FollowUp_Status.FollowupStatus=#tmpLeadSrc.FollowUpStatus and (ParentId=@ParentId or ParentId is null))  
       --,Products= case when Products!= '' then dbo.ufn_GetProductId(Products,@ParentId,'#') else Products end                
       Where Sno not in (Select distinct Sno from #tmpConstraintChk)                
                
        drop table if exists  #tempPRD1   
        select ROW_NUMBER() over(order by Sno asc) as RowNum,Sno,Products into #tempPRD1 from  #tmpLeadSrc   
      Where Sno not in (Select distinct Sno from #tmpConstraintChk)                  
                   and Products!= ''  
      Declare @RowNum int = 1  
      Declare @CountProduct1 int = ( select count(1) from #tempPRD1)  
       
      exec Usp_createProductMasterTable @ParentID  
      while(@CountProduct1 >= @RowNum)  
        Begin  
        declare @ProductsJson nvarchar(max)  
        declare @Sno int    
        select top 1 @Sno = Sno , @ProductsJson = Products from  #tempPRD1 where RowNum = @RowNum  
        
         select  @productsJson  = (            
          select value as ProductName      
          from fn_split(@ProductsJson,'#')      
         FOR JSON AUTO            
        ,INCLUDE_NULL_VALUES            
          )     
  
      -- declare @Outtemp1 nvarchar(500) = ''   
                        -- exec usp_GetProductId @Products, @ParentID,'#' , @Outtemp1 output  
                       -- select @Outtemp  
       --Update #tmpLeadSrc set Products = isnull(@Outtemp1,'') where Sno = @Sno  
         
       Update #tmpLeadSrc set products = isnull(@productsJson,'') where Sno = @Sno  
         
        set @RowNum = @RowNum + 1             
     End  
                     
                   drop table if exists  #tempPRD1                          
  
  
      Select @CreatedOn=getdate()              
                
      INSERT INTO #tmpUserLeads                
       ([Sno], [PersonName], [CompanyName], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], [City], [State], [Country], [CountryCode], [CountryCode1], [CountryCode2], [PinCode], [ResidentialAddress], [OfficeAddress], [AssignedTo], [SourceName], [MediumName], [CampaignName], [InitialRemarks], [ParentID], [FollowUpStatus], [NextStatusDate], [Remarks], [Products], [AmountPaid], [CreatedOn], [CreatedBy], [FollowupDate], [WhatsAppNoColName])          
       Select  Sno, PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, City, [State], Country ,CountryCode,CountryCode1,CountryCode2,case when ISNUMERIC(PinCode) != 1 then 0 else PinCode end, ResidentialAddress, OfficeAddress, AssignedTo, SourceName, MediumName, CampaignName, InitialRemarks, @ParentId as ParentID, FollowUpStatus, NextStatusDate, Remarks, Products, iif(isnull(AmountPaid,'') = '', '0', AmountPaid), @CreatedOn as CreatedOn, @User_Id as CreatedBy, FollowupDate, WhatsAppNoColName          
       From #tmpLeadSrc                
       Where Sno not in (Select distinct Sno from #tmpConstraintChk)    
                
      Select @NextLeadNo=Isnull(max(LeadNo),0) From UserLeads(nolock) Where ParentID=@ParentId                 
          
      print '@NextLeadNo: ' + cast(@NextLeadNo as varchar)          
                
      Update CRMCampaignSettings                 
       Set LastUserAssigned=isnull((Select top 1 AssignedTo From #tmpLeadSrc Where ISNULL(AssignedTo,'') != '' and Sno not in (Select distinct Sno from #tmpConstraintChk) order by sno desc),LastUserAssigned)                
       Where IsActive=1 and UserID=@ParentId                
           
		   
      if object_id('tempdb..#outputLead') is not null begin drop table #outputLead end  

      create table #outputLead(leadid bigint,LeadNo bigint, FollowUpStatus bigint, NextStatusDate nvarchar(50),   
      ProductsJson varchar(1000), AmountPaid numeric(18,2), Remarks nvarchar(1000), AssignedTo bigint, 
	  ParentID bigint, CreatedOn datetime, CreatedBy bigint, followupdate datetime)    
      create table #outputLeadInteraction(id bigint,leadno bigint)    
  
      SELECT @LastLeadId=IDENT_CURRENT('UserLeads')  
      SET Context_Info 0x55555  
      declare @le_cnt int=(select count(1) from #tmpuserleads),@r_id int=0  
      
	  If exists(select * from #tmpUserLeads)          
      Begin          
        SELECT @LastLeadId=IDENT_CURRENT('UserLeads')                
        while @le_cnt>0  
		begin  
       INSERT INTO [dbo].[UserLeads]                
       ([LeadNo],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo]          
       ,[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks],[ProductsJson],[AmountPaid],[CreatedOn],[CreatedBy],[FollowupDate],[enquirysource],[WhatsAppNoColName],LastFollowupCreatedBy,LastFollowupCreatedOn)  
       output inserted.ID as leadid,inserted.LeadNo as leadno, inserted.FollowUpStatus FollowUpStatus, inserted.NextStatusDate NextStatusDate,   
       inserted.[ProductsJson] [ProductsJson], inserted.AmountPaid AmountPaid, inserted.Remarks Remarks, inserted.AssignedTo AssignedTo, inserted.ParentID ParentID,  
       inserted.CreatedOn CreatedOn, inserted.CreatedBy CreatedBy, inserted.followupdate followupdate into #outputLead  
       Select                
       @NextLeadNo+LeadNo, [PersonName], [CompanyName], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], [City],[State], [Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],case when [NextStatusDate]='' then '' else FORMAT(cast(NextStatusDate as Datetime),'dd-MMM-yyyy hh:mm:ss tt') end, [Remarks],[Products],[AmountPaid],[CreatedOn], [CreatedBy],case when [NextStatusDate]='' then '' else FORMAT(cast(NextStatusDate as Datetime),'dd-MMM-yyyy hh:mm:ss tt') end, 21 as [enquirysource], WhatsAppNoColName,[CreatedBy],getdate()          
       From    #tmpUserLeads t 
	   where t.sno between @r_id+1 and @r_id+500
                
       Select @nLeadInserted+=@@ROWCOUNT         
                    
       print cast(@nLeadInserted as varchar) + ' Leads inserted' +'-----------'+cast(getdate() as nvarchar)+'-------'  
       set @le_cnt=@le_cnt-500  
       set @r_id=@r_id+500  
       end  
       select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),leadid),',') From #outputLead  
  
       Exec usp_ExecLeadTriggerTasks @CsvID  
                       
      select @le_cnt=count(1) from #outputlead  
  
      while @le_cnt>0  
      begin  
       insert into leadinteractionhistory(LeadNo,FollowUpStatus,NextStatusDate,[ProductsJson],AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,followupdate,  
       IsAutoEntry,id_lead)              
       output inserted.ID as ID,inserted.leadno as leadno into #outputLeadInteraction  
       select top 500 LeadNo, FollowUpStatus, NextStatusDate, [ProductsJson], AmountPaid, Remarks, AssignedTo, ParentID, CreatedOn, CreatedBy, NextStatusDate, 1 as IsAutoEntry,leadid  
       from #outputlead(nolock) o where   
       not exists (select 1 from #outputLeadInteraction where leadno=o.leadno)  
                      Select @nFollowupInserted+=@@ROWCOUNT         
                    
       print cast(@nFollowupInserted as varchar) + ' Lead interactions inserted' +'-----------'+cast(getdate() as nvarchar)+'-------'  
     set @le_cnt=@le_cnt-500  
  
       end  
       select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),ID),',') From #outputLeadInteraction  
  
       declare @multi_lih as Multiactivity_lih  
  
       insert into @multi_lih(leadno,parentid)  
       select leadno,parentid from #outputLead  
         
       Exec usp_ExecLeadInteractionTriggerTasks_multi @multi_lih  
               
       set @jRow = 1                
       while(@jRow <= @CustomFieldsCnt)                
       begin                
         select @fieldId=t.fieldId,@fieldName=t.fieldName,@fieldtype=c.datatype         
         from #tblCustomFields t join customfields c (nolock) on c.field_ID=t.fieldId and c.ParentID=@ParentId         
         Where t.RowId=@jRow                
                
         set @SQLString = 'insert into customfieldLeadvalue(LeadID,EnquiryID,fieldID,fieldvalue,CreatedDate)         
         select distinct A.ID, 0, ' + cast(@fieldId as varchar) + ', case when '''+ cast(@fieldtype as nvarchar) +'''=''d'' and IsDate(C.[' + @fieldName + ']) = 1 then Format(cast(C.[' + @fieldName + '] as datetime),''dd-MMM-yyyy hh:mm:ss tt'') else C.[' + @fieldName + '] end, getdate()    
         From [UserLeads] A(nolock) inner join #tmpUserLeads B                
         ON   A.LeadNo = B.LeadNo+' + cast(@NextLeadNo as varchar) + ' inner join #tmpLeadSrc C  
         On  B.Sno = C.Sno                
         Where A.[ParentID] = ' + cast(@ParentId as varchar) + ' and A.LeadNo <= ' + cast(@NextLeadNo as varchar) + '+' + cast(@nLeadInserted as varchar)                
                    
         print 'custom field Lead @SQLString: ' + @SQLString + ' and isnull(C.[' + @fieldName + '],'''') != '''' '                
                
         exec (@SQLString)                
         select @nLeadCustomFieldRows+=@@ROWCOUNT                
                
         set @jRow = @jRow + 1                
       end           
            
       SET DATEFORMAT dmy;            
       UPDATE cflv set cflv.fieldvalue=case when isnull(cflv.fieldvalue,'') != '' then FORMAT(cast(cflv.fieldvalue as Datetime),'dd-MMM-yyyy hh:mm:ss tt') else cflv.fieldvalue end              
       --select *              
       FROM userleads ul inner join customfieldleadvalue cflv              
       ON ul.id=cflv.leadid inner join customfields cf              
       ON cflv.fieldid=cf.field_id              
       WHERE ul.parentid=@ParentId and ul.createdon=@CreatedOn and cf.datatype='d'              
          
       Set @RowData = isnull((Select  SNo=ROW_NUMBER()Over(order by B.ID), B.PersonName, CountryCode=Case B.WhatsAppNoColName When 'MobileNo' then B.CountryCode         
       when 'MobileNo1' then B.CountryCode1 when 'MobileNo2' then B.CountryCode2 Else '' End, MobileNo=Case B.WhatsAppNoColName When 'MobileNo' then B.MobileNo         
       when 'MobileNo1' then B.MobileNo1 when 'MobileNo2' then B.MobileNo2 Else '' End          
       From #tmpUserLeads A inner join [UserLeads] B (nolock)          
       ON   A.LeadNo + @NextLeadNo = B.LeadNo          
       Where B.[ParentID] = @ParentId and B.WhatsAppNoColName in ('MobileNo','MobileNo1','MobileNo2')          
        for json auto, INCLUDE_NULL_VALUES),'')          
          
       If(len(@RowData)>1)          
       Begin          
         /*INSERT INTO [MySMSConversations].[dbo].[tbl_imp_ImportRequest]          
         ([FileName],[FileSizeByte],[CreatedOn],[Status],[NoOfRecord],[IsProcessed]          
         ,[ImportJSON],[SourceName],[CreatedBy],[ParentId])          
        VALUES          
         ('FromLead.xls',LEN(@RowData),Getdate(),'pending',0,0          
         ,@RowData,0,@User_Id,@ParentId)          
          
         Select @ImportRequestId=SCOPE_IDENTITY() */   
		 SET @sqlquery = '
            INSERT INTO [tbl_imp_ImportRequest]    
                ([FileName], [FileSizeByte], [CreatedOn], [Status], [NoOfRecord], [IsProcessed],    
                 [ImportJSON], [SourceName], [CreatedBy], [ParentId])    
            VALUES    
                (''FromLead.xls'', ' + CAST(LEN(@RowData) AS NVARCHAR) + ', GETDATE(), ''pending'', 0, 0,    
                ''' + REPLACE(@RowData, '''', '''''') + ''', 0, ' + CAST(@User_Id AS NVARCHAR) + ', ' + CAST(@ParentId AS NVARCHAR) + ');
             ';
            
            -- Get the inserted ID back
            EXEC usp_clr_InsertAndReturnId @sqlquery, @retid = @ImportRequestId OUTPUT;

         select @RecCnt=count(*) from openjson(@RowData)              
          
         While(1=1)          
         Begin          
       set @Start=@End+1          
       set @End=@Pagesize*@Pageno          
          
       Set @RowData = isnull((Select * from (Select  SNo=ROW_NUMBER()Over(order by B.ID), B.PersonName, CountryCode=Case B.WhatsAppNoColName When 'MobileNo' then B.CountryCode when 'MobileNo1' then B.CountryCode1 when 'MobileNo2' then B.CountryCode2 Else '' End, MobileNo=Case B.WhatsAppNoColName When 'MobileNo' then B.MobileNo when 'MobileNo1' then B.MobileNo1 when 'MobileNo2' then B.MobileNo2 Else '' End          
       From #tmpUserLeads A inner join [UserLeads] B (nolock)          
       ON   A.LeadNo + @NextLeadNo = B.LeadNo          
       Where B.[ParentID] = @ParentId and B.WhatsAppNoColName in ('MobileNo','MobileNo1','MobileNo2')) T          
       Where T.SNo between @Start and @End          
        for json auto, INCLUDE_NULL_VALUES),'')          
          
      /*NSERT INTO [MySMSConversations].[dbo].[tbl_ims_ImportSlot]          
          ([requestid],[createdon],[contactjson],[isprocessed])          
         VALUES          
          (@ImportRequestId,Getdate(),@RowData,0)  */        
            SET @sqlquery = '
                             INSERT INTO [tbl_ims_ImportSlot]    
                                 ([requestid], [createdon], [contactjson], [isprocessed])    
                             VALUES    
                                 (' + CAST(@ImportRequestId AS NVARCHAR) + ', GETDATE(), ''' + REPLACE(@RowData, '''', '''''') + ''', 0);
                             ';
                             
                             -- Execute remotely
                             EXEC usp_clr_ExecuteRemoteQuery @sqlquery;

       If(@RecCnt < (@Pageno*@Pagesize))          
       Begin          
        break          
       End          
       Else          
       Begin          
        Set @Pageno=@Pageno+1          
       End          
         End          
          
         Set @RowData = null          
       End          
          
       End          
           
      Set @RowData = isnull((Select Sno, Remarks From #tmpConstraintChk order by Sno for json auto, INCLUDE_NULL_VALUES),'')                
           
      print 'Final @RowData: ' + cast(@RowData as varchar(max))          
              
      update tbl_LeadImportSummary                 
       set IsProcessed=1,importend=getdate(), Remarks=@RowData, LeadCnt=@nLeadInserted, LeadCustomFieldCnt=@nLeadCustomFieldRows                 
       where ImportRow_Id=@ImportRow_id       
       
      select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@tic as nvarchar) +' leads for importing.     
       The request is processed and leads imported are '+cast( @nLeadInserted as nvarchar)     
      exec UspSaveEntityActivity_withid 'user',@user_id,@user_id,@ParentID,@EventDescription,@EventName,'tbl_LeadImportSummary',@ImportRow_id    
      exec Usp_InsertUserEventDetails 'Lead Import successful',@parentid,@eventdescription, 'tbl_LeadImportSummary',@ImportRow_id  
  
      update lr set lr.is_processed = 0   
     from UserLeads(nolock)  ul   
      inner join #tmpUserLeads tl on ul.LeadNo = tl.LeadNo and ul.ParentID = tl.ParentID  
      inner join tbl_las_LeadRequest(nolock) lr on ul.ID = lr.leadid and ul.ParentID = lr.parentid  
     where ul.ID = lr.leadid and lr.is_processed = 10  
  
             
      Iter:            
     Set @iRow = @iRow + 1  
     Set @ImportRow_id=0  
     Set @ImportData=null  
     Set @RowData=null  
     Set @FieldNames=''  
     Set @SQLString=null  
     Set @User_Id=0  
     Set @LastLeadId=0  
     Set @nLeadInserted=0  
     Set @nFollowupInserted=0  
     Set @nLeadCustomFieldRows=0  
     Set @jRow=1  
     Set @fieldId=0  
     Set @fieldName=''  
     Set @CustomFieldsCnt = 0  
     Set @ImportRequestId = 0  
     Set @RecCnt = 0  
     Set @Start = 0  
     Set @End = 0  
     Set @Pagesize = 500  
     Set @Pageno = 1  
                
       truncate table #tmpConstraintChk                
       truncate table #tmpUserLeads                
       truncate table #tmpMobileNoList                
       truncate table #tmpEmailIdList                
       truncate table #tblCustomFields                
                
       if object_id('tempdb..#tmpLeadSrc') is not null begin drop table #tmpLeadSrc end                              
       if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end  
       if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end  
       if object_id('tempdb..#tmpTblPrdct2') is not null begin drop table #tmpTblPrdct2 end  
	   if object_id('tempdb..#outputLead') is not null begin drop table #outputLead end  

   End                
                
--  COMMIT TRANSACTION       
  SET Context_Info 0x  
    
 END TRY                    
 BEGIN CATCH                   
  --While @@TRANCOUNT > 0  
  -- ROLLBACK TRANSACTION  
                  
  SET Context_Info 0x  
   
  insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)          
  SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()    
     
	  Update tbl_LeadImportSummary Set IsProcessed=1,importstart=getdate(),Remarks='[{"Sno":0,"Remarks":"Contact Admin Support Team, Error is: ' + ERROR_MESSAGE() + '"}]'           
      Where ImportRow_Id = @ImportRow_id    

  select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@tic as nvarchar) +' leads for importing.     
    The request failed. Pl check Import summary for details'     
  exec UspSaveEntityActivity_withid 'user',@user_id,@user_id,@ParentID,@EventDescription,@EventName,'tbl_LeadImportSummary',@ImportRow_id  
  exec Usp_InsertUserEventDetails 'Lead Import failed',@parentid,@eventdescription, 'tbl_LeadImportSummary',@ImportRow_id  
          
 END CATCH                    
                
 if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end                
 if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end                
 if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end                
 if object_id('tempdb..#tblAllLeadFields') is not null begin drop table #tblAllLeadFields end                
 if object_id('tempdb..#tmpLeadSrc') is not null begin drop table #tmpLeadSrc end                
 if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end                
 if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end                
 if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end                
 if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end  
 if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end 
 if object_id('tempdb..#outputLead') is not null begin drop table #outputLead end
                
END   



GO

/* ============================================================
   Procedure: [dbo].[usp_ProcessLeadImportData_PM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--Dependency of this usp_ProcessLeadImportData_PM

--1.[MySMSConversations].[dbo].[tbl_imp_ImportRequest]       -- called by clr
--2. usp_ProcessEnquiryImportData_corrected  -- called by clr 

-------------------------------------


 
        
-- Exec usp_ProcessLeadImportData 0, 'P'            
-- Exec usp_ProcessLeadImportData 1, 'P'            
-- Exec usp_ProcessLeadImportData 1, 'P', 3            
CREATE   PROC [dbo].[usp_ProcessLeadImportData_PM] --1,'p', 1765           
(              
    @BatchSize int=1,  -- 0 ('All')              
    @Mode varchar(1)='P',    -- 'P'riority, 'F'ifo        
	@IPRId bigint=0        
)              
AS              
BEGIN              
              
	-- declare @BatchSize int=1,@Mode varchar(1)='P', @IPRId bigint=1155   
	
	  DECLARE @sqlquery NVARCHAR(MAX);      

	if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end              
	if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end              
	if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end              
	if object_id('tempdb..#tblAllLeadFields') is not null begin drop table #tblAllLeadFields end              
	if object_id('tempdb..#tmpLeadSrc') is not null begin drop table #tmpLeadSrc end              
	if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end              
	if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end              
	if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end              
	if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end
	if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end
              
	Create table #tblImportRowId
	(              
		RowId int identity,              
		ImportRow_id bigint,              
		[User_Id] bigint              
	)              
              
	create table #tmpConstraintChk
	(              
		Sno int,              
		Remarks varchar(200)              
	)              
              
	create table #tblCustomFields
	(              
		RowId int identity(1,1),              
		fieldId bigint,              
		fieldName varchar(50)              
	)              
              
	create table #tblAllLeadFields
	(              
		RowId int identity(1,1),              
		fieldName varchar(50),          
		FieldType varchar(10)          
	)              
              
	create table #tmpMobileNoList
	(              
		RowId int identity,              
		MobileNo varchar(100)              
	)              
              
	create table #tmpEmailIdList
	(              
		RowId int identity,              
		EmailId varchar(100)              
	)              
              
	CREATE TABLE #tmpUserLeads 
	(
	 [LeadNo] [bigint] IDENTITY(1,1) NOT NULL,              
	 [Sno] [int] NOT NULL,              
	 [PersonName] [varchar](100) NULL,              
	 [CompanyName] [varchar](100) NULL,              
	 [MobileNo] [varchar](100) NULL,              
	 [MobileNo1] [varchar](100) NULL,              
	 [MobileNo2] [varchar](100) NULL,              
	 [EmailID] [varchar](100) NULL,              
	 [EmailID1] [varchar](100) NULL,              
	 [EmailID2] [varchar](100) NULL,              
	 [City] [varchar](100) NULL,              
	 [State] [varchar](100) NULL,              
	 [Country] [varchar](100) NULL,              
	 [CountryCode] [varchar](50) NULL,              
	 [CountryCode1] [varchar](50) NULL,              
	 [CountryCode2] [varchar](50) NULL,              
	 [PinCode] [bigint] NULL,              
	 [ResidentialAddress] [varchar](500) NULL,              
	 [OfficeAddress] [varchar](500) NULL,              
	 [AssignedTo] [bigint] NOT NULL,              
	 [SourceName] [bigint] DEFAULT ((0)) NOT NULL,              
	 [MediumName] [bigint] DEFAULT ((0)) NULL,              
	 [CampaignName] [bigint] DEFAULT ((0)) NULL,              
	 [InitialRemarks] [varchar](1000) NULL,              
	 [ParentID] [bigint] NOT NULL,              
	 [FollowUpStatus] [int] NULL,              
	 [NextStatusDate] [varchar](50) NULL,              
	 [Remarks] [varchar](1000) NULL,              
	 [Products] [varchar](1000) NULL,              
	 [AmountPaid] [numeric](18, 2) NOT NULL DEFAULT ((0)),              
	 [CreatedOn] [datetime] NULL,              
	 [CreatedBy] [bigint] NULL,      
	 [FollowupDate] [datetime] NULL,        
	 [WhatsAppNoColName] varchar(10)        
	)              
              
	BEGIN TRY
		BEGIN TRANSACTION              
        
			If(isnull(@IPRId,0) > 0)        
			Begin        
				insert into #tblImportRowId        
				Select ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where ImportRow_id=@IPRId        
			End        
			Else        
			Begin        
				If(@Mode = 'P')          
				Begin              
					If(@BatchSize != 0)              
					Begin              
						insert into #tblImportRowId              
						Select top (@BatchSize) ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where IsProcessed=0 order by [Priority]              
					End              
					Else              
					Begin              
						insert into #tblImportRowId              
						Select ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where IsProcessed=0 order by [Priority]              
					End              
				End              
				Else -- Fifo              
				Begin              
					If(@BatchSize != 0)              
					Begin              
						insert into #tblImportRowId              
						Select top (@BatchSize) ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where IsProcessed=0              
					End              
					Else              
					Begin              
						insert into #tblImportRowId              
						Select ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where IsProcessed=0              
					End              
				End            
			End        

			select * from #tblImportRowId              
              
			declare @iRow int=1, @jRow int=1, @ImportRow_id bigint=0, @UnProcessedRowCnt int=0, @User_Id bigint=0, @LastLeadId bigint=0, @nLeadInserted bigint=0, @fieldId bigint=0, @nLeadCustomFieldRows bigint=0, @CsvID nvarchar(max)              
			declare @ImportData nvarchar(max), @RowData nvarchar(max), @FieldNames nvarchar(max)='', @SQLString nvarchar(max)='', @ParmDefinition nvarchar(500), @fieldName varchar(50)='',@fieldtype nvarchar(20);                
			declare @NextLeadNo bigint=0, @CustomFieldsCnt int=0, @ParentId bigint=0, @CreatedOn datetime, @ImportRequestId bigint=0, @RecCnt int =0, @Pagesize int=500, @Pageno int=1, @Start int=0, @End int=0             
			declare @eventname nvarchar(100),@eventdescription nvarchar(500),@userlogin nvarchar(100),@tic int          
			select @UnProcessedRowCnt=Count(*) from #tblImportRowId              
              
			While(@iRow <= @UnProcessedRowCnt)              
			Begin              
				  print '@iRow: ' + cast(@iRow as varchar)              
				  Select @ImportRow_id=ImportRow_id,@User_Id=[User_Id] From #tblImportRowId Where RowId=@iRow              
				  print '@ImportRow_id: ' + cast(@ImportRow_id as varchar)              
				  Select @ImportData=ImportData from tbl_LeadImportSummary(nolock) where ImportRow_Id=@ImportRow_id              
				  print '@ImportData: ' + @ImportData              
				  select top 1 @RowData=value from openjson(@ImportData)              
				  print '@RowData: ' + @RowData              
				  select @FieldNames=@FieldNames+'['+[Key]+'] varchar(1000),' from openjson(@RowData)              
				  print '@FieldNames1: ' + @FieldNames              

				  If (CHARINDEX('WhatsAppNoColName',@FieldNames,0) > 0)        
				  Begin        
						print 'WhatsAppNoColName found'        
						set @FieldNames=SUBSTRING(@FieldNames,1,len(@FieldNames)-1)              
				  End        
				  Else        
				  Begin        
					   print 'WhatsAppNoColName not found, adding dummy'        
					   select @FieldNames=@FieldNames+' [WhatsAppNoColName] varchar(10)'        
					   select @RowData=replace(@RowData,'}',',"WhatsAppNoColName":null}')        
				  End        
				  print '@FieldNames2: ' + @FieldNames              
            
				  Select @ParentId=parentid,@userlogin=User_Login from user_detail(nolock) where user_id= @User_Id  
          
				  insert into #tblAllLeadFields          
				  values ('Sno','Main'),('PersonName','Main'),('CompanyName','Main'),('MobileNo','Main'),('MobileNo1','Main'),('MobileNo2','Main'),('EmailID','Main'),('EmailID1','Main'),('EmailID2','Main'),('City','Main'),('State','Main'),('Country','Main'),('CountryCode','Main'),('CountryCode1','Main'),('CountryCode2','Main'),('PinCode','Main'),('ResidentialAddress','Main'),('OfficeAddress','Main'),('AssignedTo','Main'),('SourceName','Main'),('MediumName','Main'),('CampaignName','Main'),('InitialRemarks','Main'),('FollowupStatus','Main'),('NextStatusDate','Main'),('Remarks','Main'),('Products','Main'),('AmountPaid','Main'),('FollowupDate','Main'), ('WhatsAppNoColName','Main')         
          
				  insert into #tblAllLeadFields          
				  select fieldname,'Custom' from customfields(nolock) where parentId=@ParentId and isActive=1          
          
				  Update tbl_LeadImportSummary Set IsProcessed=1,Remarks='[{"Sno":0,"Remarks":"Under Process Queue"}]'         
				  Where ImportRow_Id = @ImportRow_id        
        
				  if exists(select [Key] from openjson(@RowData) where [Key] COLLATE SQL_Latin1_General_CP1_CI_AS not in (Select FieldName From #tblAllLeadFields))        
				  Begin        
						print 'Invalid Field found in Import Data'        
						Update tbl_LeadImportSummary Set IsProcessed=1,Remarks='[{"Sno":0,"Remarks":"Invalid Field found in Import Data"}]'
						Where ImportRow_Id = @ImportRow_id  

						select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@tic as nvarchar) +' leads for importing. The request failed. Pl check Import summary for details'   
						exec UspSaveEntityActivity_withid 'user',@user_id,@user_id,@ParentID,@EventDescription,@EventName,'tbl_LeadImportSummary',@ImportRow_id
						exec Usp_InsertUserEventDetails 'Lead Import failed',@parentid,@eventdescription, 'tbl_LeadImportSummary',@ImportRow_id
 
						goto Iter        
				  End
				  Else        
				  Begin        
					   If exists(Select FieldName From #tblAllLeadFields Where FieldName COLLATE SQL_Latin1_General_CP1_CI_AS not in (select [Key] from openjson(@RowData)))        
					   Begin        
							print 'Required Field Missing in Import Data'        
							Update tbl_LeadImportSummary Set IsProcessed=1,Remarks='[{"Sno":0,"Remarks":"Required Field Missing in Import Data"}]'        
							Where ImportRow_Id = @ImportRow_id        

							select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@tic as nvarchar) +' leads for importing.   
						   The request failed. Pl check Import summary for details'   
							exec UspSaveEntityActivity_withid 'user', @user_id, @user_id, @ParentID, @EventDescription, @EventName, 'tbl_LeadImportSummary', @ImportRow_id
							exec Usp_InsertUserEventDetails 'Lead Import failed',@parentid,@eventdescription, 'tbl_LeadImportSummary',@ImportRow_id
 
							goto Iter        
					   End        
				  End        
          
				  create table #tmpLeadSrc (id int identity);              
				  print 'alter table #tmpLeadSrc add ' + @FieldNames              
				  exec('alter table #tmpLeadSrc add ' + @FieldNames)              
              
				  --Set @SQLString = N'insert into #tmpLeadSrc select * from openjson(@ImptData) with (' + @FieldNames + ') where [PersonName] is not null and [MobileNo] is not null and [CountryCode] is not null and [ResidentialAddress] is not null and [SourceName] is not null and [InitialRemarks] is not null and [FollowupStatus] is not null'               
				  Set @SQLString = N'insert into #tmpLeadSrc select * from openjson(@ImptData) with (' + @FieldNames + ')'  
              	  --Set @SQLString = N'insert into #tmpLeadSrc select * from openjson(@ImptData) with (' + @FieldNames + ') where [Sno] is not null'  
              
				  --SET @ParmDefinition = N'@ImptData nvarchar(max), @FldNames nvarchar(max)';                
				  SET @ParmDefinition = N'@ImptData nvarchar(max)';    
  
				  if object_id('tempdb..#tmpLeadSrc') is not null   
				  begin   
					 select @tic=count(1) from #tmpLeadSrc  
				  end              
	
				  print @SQLString              
              
				  --EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData, @FldNames=@FieldNames                
				  EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData                
            
				  --select * from openjson(@RowData)              
          
				  update #tmpLeadSrc               
				  set MobileNo=rtrim(ltrim(case when isnull(MobileNo,'')='' and isnull(MobileNo1,'')!='' then MobileNo1 else Isnull(MobileNo,'') end)),        
				  MobileNo1=rtrim(ltrim(case when isnull(MobileNo1,'')='' and isnull(MobileNo2,'')!='' then MobileNo2 else Isnull(MobileNo1,'') end)),        
				  MobileNo2=rtrim(ltrim(isnull(MobileNo2,''))),              
				  CountryCode=rtrim(ltrim(case when isnull(CountryCode,'')='' and isnull(CountryCode1,'')!=''    
				  then iif(left(ltrim(CountryCode1),1) != '+','+'+ltrim(CountryCode1),CountryCode1) else iif(left(ltrim(Isnull(CountryCode,'')),1) != '+' and ltrim(Isnull(CountryCode,'')) != '', '+'       
				  + ltrim(Isnull(CountryCode,'')),Isnull(CountryCode,'')) end)),              
				  CountryCode1=rtrim(ltrim(case when isnull(CountryCode1,'')='' and isnull(CountryCode2,'')!=''  
				  then iif(left(ltrim(CountryCode2),1) != '+','+'+ltrim(CountryCode2),CountryCode2) else iif(left(ltrim(Isnull(CountryCode1,'')),1) != '+' and ltrim(Isnull(CountryCode1,'')) != '', '+'      
				  + ltrim(Isnull(CountryCode1,'')),Isnull(CountryCode1,'')) end)),              
				  CountryCode2=rtrim(ltrim(iif(left(ltrim(isnull(CountryCode2,'')),1) != '+' and ltrim(isnull(CountryCode2,'')) != '','+' + ltrim(isnull(CountryCode2,'')),Isnull(CountryCode2,'')))),    
				  EmailID=rtrim(ltrim(case when isnull(EmailID,'')='' and isnull(EmailID1,'')!='' then EmailID1 else Isnull(EmailID,'') end)),              
				  EmailID1=rtrim(ltrim(case when isnull(EmailID1,'')='' and isnull(EmailID2,'')!='' then EmailID2 else Isnull(EmailID1,'') end)),              
				  EmailID2=rtrim(ltrim(isnull(EmailID2,''))),              
				  PersonName=rtrim(ltrim(isnull(PersonName,''))),              
				  InitialRemarks=rtrim(ltrim(isnull(InitialRemarks,''))),              
				  AssignedTo=rtrim(ltrim(isnull(AssignedTo,''))),              
				  SourceName=rtrim(ltrim(isnull(SourceName,''))),              
				  MediumName=rtrim(ltrim(isnull(MediumName,''))),              
				  CampaignName=rtrim(ltrim(isnull(CampaignName,''))),              
				  FollowupStatus=rtrim(ltrim(isnull(FollowupStatus,''))),              
				  NextStatusDate=rtrim(ltrim(isnull(NextStatusDate,''))),              
				  Remarks=rtrim(ltrim(isnull(Remarks,''))),              
				  Products=rtrim(ltrim(isnull(Products,''))),              
				  AmountPaid=rtrim(ltrim(isnull(AmountPaid,'0'))),              
				  FollowupDate=rtrim(ltrim(isnull(FollowupDate,'0'))),              
				  WhatsAppNoColName=rtrim(ltrim(isnull(WhatsAppNoColName,''))),              
				  Sno=rtrim(ltrim(isnull(Sno,0)))              
              
				  --EXEC('select * from #tmpLeadSrc')              
              
				  insert into #tmpConstraintChk              
				  Select  Sno, 'Duplicate Records' as Remarks              
				  From              
				  (              
				   select ROW_NUMBER()over(partition by PersonName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, InitialRemarks         
				   order by cast(Sno as int)) as Rid, *              
				   from #tmpLeadSrc              
				  ) B              
				  Where B.Rid > 1              
                  
            
				  insert into #tblCustomFields              
				  select field_ID, fieldname               
				  from customfields(nolock)               
				  where parentId=@ParentId and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select FieldName from #tblAllLeadFields where [FieldType] = 'Custom')              
				  /*where parentId=@ParentId and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select [Key]              
				  from openjson(@RowData) where [Key] not in ('Sno', 'PersonName', 'CompanyName', 'MobileNo', 'MobileNo1', 'MobileNo2', 'EmailID', 'EmailID1', 'EmailID2', 'City', 'State', 'Country', 'CountryCode', 'CountryCode1', 'CountryCode2', 'PinCode', 'ResidentialAddress', 'OfficeAddress', 'AssignedTo', 'SourceName', 'MediumName', 'CampaignName', 'InitialRemarks', 'FollowupStatus', 'NextStatusDate', 'Remarks', 'Products', 'AmountPaid', 'FollowupDate', 'ProfileImgFileName')) */             
              
				  Select @CustomFieldsCnt=count(*) From #tblCustomFields              
              
				  insert into #tmpConstraintChk              
				  Select  Sno, 'Sno missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(Sno),'') = '' or ISNULL(ltrim(Sno),'0') = '0'              
				  union              
				  Select  Sno, 'Sno Duplicate' as Remarks              
				  From    #tmpLeadSrc              
				  group by Sno              
				  having  Count(*) > 1              
				  union              
				  Select  Sno, 'PersonName missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(PersonName),'') = ''              
				  union              
				  Select  Sno, 'Contact details missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(MobileNo),'') = '' and ISNULL(ltrim(MobileNo1),'') = '' and ISNULL(ltrim(MobileNo2),'') = '' and               
				  ISNULL(ltrim(EmailID),'') = '' and ISNULL(ltrim(EmailID1),'') = '' and ISNULL(ltrim(EmailID2),'') = ''              
				  union              
				  Select  Sno, 'MobileNo or CountryCode missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ((ISNULL(ltrim(MobileNo),'')!='' and ISNULL(ltrim(CountryCode),'')='') or (ISNULL(ltrim(MobileNo),'')='' and ISNULL(ltrim(CountryCode),'')!=''))              
				   or              
				  ((ISNULL(ltrim(MobileNo1),'')!='' and ISNULL(ltrim(CountryCode1),'')='') or (ISNULL(ltrim(MobileNo1),'')='' and ISNULL(ltrim(CountryCode1),'')!='')) or              
				  ((ISNULL(ltrim(MobileNo2),'')!='' and ISNULL(ltrim(CountryCode2),'')='') or (ISNULL(ltrim(MobileNo2),'')='' and ISNULL(ltrim(CountryCode2),'')!=''))              
				  union              
				  Select  Sno, 'AssignedTo missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(AssignedTo),'') = ''              
				  union              
				  Select  Sno, 'AssignedTo Invalid' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(AssignedTo),'') not in (Select [User_Login] from User_Detail(nolock) Where Status=1)              
				  union              
				  Select  Sno, 'SourceName missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(SourceName),'') = ''              
				  union              
				  Select  Sno, 'FollowupStatus missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(FollowupStatus),'') = ''              
				  union              
				  Select  Sno, 'FollowupStatus missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(FollowupStatus),'') not in (Select FollowupStatus from FollowUp_Status(nolock) Where IsActive=1)              
				  union              
				  Select  Sno, 'FollowupDate missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(FollowupDate),'') = ''              
				  union              
				  Select  Sno, 'Invalid FollowupDate' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(FollowupDate),'') != '' and ISDATE(FollowupDate) != 1              
				  union              
				  Select  Sno, 'Invalid NextStatusDate' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(NextStatusDate),'') != '' and ISDATE(NextStatusDate) != 1              
				  union              
				  
				  --Select  Sno, 'Invalid Products' as Remarks              
				  --From    #tmpLeadSrc              
				  --Where   ISNULL(ltrim(Products),'') != '' and Products not like '%#%' and Products not in (select [Name] from ProductMaster(nolock) Where IsActive=1 and UserID=@ParentId)              
				  --union
				                
				  --Select  Sno, 'Invalid Products' as Remarks              
				  --From    #tmpLeadSrc              
				  --Where   Products like '%#%' and dbo.ufn_GetProductId(Products,@ParentId,'#')=''              
				  --union              
				  
				  Select  Sno, 'PersonName Length exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(PersonName)>100              
				  union              
				  Select  Sno, 'CompanyName exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(CompanyName)>100              
				  union              
				  Select  Sno, 'MobileNo exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(MobileNo)>100              
				  union              
				  Select  Sno, 'MobileNo1 exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(MobileNo1)>100              
				  union              
				  Select  Sno, 'MobileNo2 exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(MobileNo2)>100              
				  union              
				  Select  Sno, 'EmailID exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(EmailID)>100              
				  union              
				  Select  Sno, 'EmailID1 exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(EmailID1)>100              
				  union              
				  Select  Sno, 'City exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(City)>100              
				  union              
				  Select  Sno, 'State exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(State)>100              
				  union              
				  Select Sno, 'Country exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(Country)>100              
				  union              
				  Select  Sno, 'CountryCode exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(CountryCode)>100              
				  union              
				  Select  Sno, 'CountryCode1 exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(CountryCode1)>100              
				  union              
				  Select  Sno, 'CountryCode2 exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(CountryCode2)>100              
				  union              
				  Select  Sno, 'ResidentialAddress exceeds specified limit(500)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(ResidentialAddress)>500              
				  union              
				  Select  Sno, 'OfficeAddress exceeds specified limit(500)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(OfficeAddress)>500              
				  union              
				  Select  Sno, 'SourceName exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(SourceName)>100              
				  union              
				  Select  Sno, 'MediumName exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(MediumName)>100              
				  union              
				  Select  Sno, 'CampaignName exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(CampaignName)>100              
				  union              
				  Select  Sno, 'InitialRemarks exceeds specified limit(1000)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(InitialRemarks)>1000              
				  union              
				  Select  Sno, 'Remarks exceeds specified limit(1000)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(Remarks)>1000              
				  
				  
				   exec Usp_createProductMasterTable @ParentID

				  Declare @Query1 nvarchar(max) = N'Select  Sno, ''Invalid Products'' as Remarks into #tmpConstraintChk             
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(Products),'''') != '''' and Products not like ''%#%'' 
				  and Products not in (select [Name] from tbl_ProductMaster_'+ cast(@ParentID as nvarchar(20))+' (nolock) 
				  Where IsActive=1 and UserID= '+ cast( @ParentId as nvarchar(20) )+ ')'              
				 

				  print 'dynamic query1'
				  print  @Query1

                  exec sp_executesql @Query1    
				  

				  --select * from #tmpConstraintChk

				  --Select  Sno, 'Invalid Products' as Remarks              
				  --From    #tmpLeadSrc              
				  --Where   Products like '%#%' and dbo.ufn_GetProductId(Products,@ParentId,'#')=''              
				  --union

				   Select ROW_NUMBER() over(order by Sno asc) as RowNum, Sno, Products into #tmpTblPrdct2 from #tmpLeadSrc  where Products like '%#%'
				   Declare @Row_Num1 int = 1
				   DEclare @Count_Prdct2 int = (select count(1) from #tmpTblPrdct2)   

				   while(@Count_Prdct2 >= @Row_Num1) 
				      begin
					       Declare @Sno1 int
						   Declare @Products_2 nvarchar(500)
						   select @Sno1 = Sno , @Products_2 = isnull(Products,'') from  #tmpTblPrdct2 where RowNum = @Row_Num1

						   declare @Outtemp nvarchar(500) = '' 
                           exec usp_GetProductId @Products_2, @ParentID,'#' , @Outtemp output
                        -- select @Outtemp
					 
     				     if(isnull(@Outtemp,'') = '')
							   begin
							      insert into #tmpConstraintChk  
								  Select  Sno, 'Invalid Products' as Remarks              
				                  From   #tmpLeadSrc where Sno = @Sno1             
				  			   end 
						   set  @Row_Num1 = @Row_Num1 + 1    
					  End
				  
				  
				  /*              
				  union              
				  Select  Sno, 'Invalid DateOfBirth' as Remarks              
				  From    #tmpLeadSrc              
				  Where   isnull(ltrim(DateOfBirth),'') != '' and ISDate(DateOfBirth) = 0              
				  */              
              
				  insert into #tmpMobileNoList              
				   select MobileNo              
				   From UserLeads(nolock)              
				   Where ParentID in (@ParentId) and isnull(ltrim(MobileNo),'') != ''              
				   union              
				   select MobileNo1              
				   From UserLeads(nolock)              
				   Where ParentID in (@ParentId) and isnull(ltrim(MobileNo1),'') != ''              
				   union              
				   select MobileNo2              
				   From UserLeads(nolock)              
				   Where ParentID in (@ParentId) and isnull(ltrim(MobileNo2),'') != ''              
              
				  insert into #tmpEmailIdList              
				   select EmailID              
				   From UserLeads(nolock)              
				   Where ParentID in (@ParentId) and isnull(ltrim(EmailID),'') != ''          
				   union              
				   select EmailID1              
				   From UserLeads(nolock)              
				   Where ParentID in (@ParentId) and isnull(ltrim(EmailID1),'') != ''              
				   union              
				   select EmailID2              
				   From UserLeads(nolock)              
				   Where ParentID in (@ParentId) and isnull(ltrim(EmailID2),'') != ''              
              
				  insert into #tmpConstraintChk              
				   Select  distinct Sno, 'MobileNo already present in Leads' as Remarks              
				   From              
				   (              
				   Select  Sno, MobileNo              
				   From  #tmpLeadSrc              
				   Where   ISNULL(ltrim(MobileNo),'') != ''              
				   union              
				   Select  Sno, MobileNo1              
				   From  #tmpLeadSrc              
				   Where   ISNULL(ltrim(MobileNo1),'') != ''              
				   union              
				   Select Sno, MobileNo2              
				   From  #tmpLeadSrc              
				   Where   ISNULL(ltrim(MobileNo2),'') != ''              
				   ) A              
				   Where A.MobileNo in (Select MobileNo From #tmpMobileNoList)              
              
				  insert into #tmpConstraintChk              
				   Select  distinct Sno, 'EmailID already present in Leads' as Remarks              
				   From              
				   (              
				   Select  Sno, EmailID              
				   From  #tmpLeadSrc              
				   Where   ISNULL(ltrim(EmailID),'') != ''              
				   union              
				   Select  Sno, EmailID1              
				   From  #tmpLeadSrc              
				   Where   ISNULL(ltrim(EmailID1),'') != ''              
				   union              
				   Select  Sno, EmailID2              
				   From  #tmpLeadSrc              
				   Where   ISNULL(ltrim(EmailID2),'') != ''              
				   ) A              
				   Where A.EmailID in (Select EmailID From #tmpEmailIdList)              
              
				  select count(*) as ConstraintChkCnt1 from #tmpConstraintChk              
              
				  INSERT INTO UserSourceSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)                
				   Select distinct SourceName, @ParentId, 1,  1, GETDATE(), GETDATE(), @User_Id                
					From  #tmpLeadSrc               
				   Where   SourceName not in (Select [Name] from UserSourceSettings(nolock) Where IsActive=1 and Userid=@ParentId) and Sno not in (Select distinct Sno from #tmpConstraintChk)              
              
				  INSERT INTO UserMediumSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)                
				   Select distinct MediumName, @ParentId, 1,  1, GETDATE(), GETDATE(), @User_Id                
				   From  #tmpLeadSrc               
				   Where   MediumName not in (Select [Name] from UserMediumSettings(nolock) Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(MediumName),'') != '' and Sno not in (Select distinct Sno from #tmpConstraintChk)              
              
				  INSERT INTO UserCampaignSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)                
				   Select distinct CampaignName, @ParentId, 1,  1, GETDATE(), GETDATE(), @User_Id                
				   From  #tmpLeadSrc               
				   Where   CampaignName not in (Select [Name] from UserCampaignSettings(nolock) Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(CampaignName),'') != ''and Sno not in (Select distinct Sno from #tmpConstraintChk)              
              
				  Update #tmpLeadSrc               
				  Set SourceName=(Select top 1 SourceId From UserSourceSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=SourceName),             
				   MediumName=(Select top 1 MediumID From UserMediumSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=MediumName),              
				   CampaignName=(Select top 1 CampaignID From UserCampaignSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=CampaignName),        
				   AssignedTo=(Select top 1 [User_ID] From User_Detail(nolock) Where [Status]=1 and [User_Login]=AssignedTo),              
				   FollowUpStatus=(Select top 1 ID From FollowUp_Status(nolock) Where IsActive=1 and FollowUp_Status.FollowupStatus=#tmpLeadSrc.FollowUpStatus)
				   --,Products= case when Products!= '' then dbo.ufn_GetProductId(Products,@ParentId,'#') else Products end              
				   Where Sno not in (Select distinct Sno from #tmpConstraintChk)              
              
			     drop table if exists  #tempPRD1 
			     select ROW_NUMBER() over(order by Sno asc) as RowNum,Sno,Products into #tempPRD1 from  #tmpLeadSrc 
				  Where Sno not in (Select distinct Sno from #tmpConstraintChk)                
				               and Products!= ''
				  Declare @RowNum int = 1
				  Declare @CountProduct1 int = ( select count(1) from #tempPRD1)
				 
				  exec Usp_createProductMasterTable @ParentID
				  while(@CountProduct1 >= @RowNum)
				    Begin
					     declare @Products nvarchar(500)
						 declare @Sno int  
						 select top 1 @Sno = Sno , @Products = Products from  #tempPRD1 where RowNum = @RowNum
					 
						 declare @Outtemp1 nvarchar(500) = '' 
                         exec usp_GetProductId @Products, @ParentID,'#' , @Outtemp1 output
                        -- select @Outtemp
						 Update #tmpLeadSrc set Products = isnull(@Outtemp1,'') where Sno = @Sno
						 set @RowNum = @RowNum + 1           
					End
				  												 
                   drop table if exists  #tempPRD1    																    


				  Select @CreatedOn=getdate()            
              
				  INSERT INTO #tmpUserLeads              
				   ([Sno], [PersonName], [CompanyName], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], [City], [State], [Country], [CountryCode], [CountryCode1], [CountryCode2], [PinCode], [ResidentialAddress], [OfficeAddress], [AssignedTo], [SourceName], [MediumName], [CampaignName], [InitialRemarks], [ParentID], [FollowUpStatus], [NextStatusDate], [Remarks], [Products], [AmountPaid], [CreatedOn], [CreatedBy], [FollowupDate], [WhatsAppNoColName])        
				   Select  Sno, PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, City, [State], Country ,CountryCode,CountryCode1,CountryCode2,case when ISNUMERIC(PinCode) != 1 then 0 else PinCode end, ResidentialAddress, OfficeAddress, AssignedTo, SourceName, MediumName, CampaignName, InitialRemarks, @ParentId as ParentID, FollowUpStatus, NextStatusDate, Remarks, Products, iif(isnull(AmountPaid,'') = '', '0', AmountPaid), @CreatedOn as CreatedOn, @User_Id as CreatedBy, FollowupDate, WhatsAppNoColName        
				   From #tmpLeadSrc              
				   Where Sno not in (Select distinct Sno from #tmpConstraintChk)  
              
				  Select @NextLeadNo=Isnull(max(LeadNo),0) From UserLeads(nolock) Where ParentID=@ParentId               
        
				  print '@NextLeadNo: ' + cast(@NextLeadNo as varchar)        
              
				  Update CRMCampaignSettings               
				   Set LastUserAssigned=isnull((Select top 1 AssignedTo From #tmpLeadSrc Where ISNULL(AssignedTo,'') != '' and Sno not in (Select distinct Sno from #tmpConstraintChk) order by sno desc),LastUserAssigned)              
				   Where IsActive=1 and UserID=@ParentId              
              
				  create table #outputLead(leadid bigint)  
				  create table #outputLeadInteraction(id bigint)  

				  SELECT @LastLeadId=IDENT_CURRENT('UserLeads')
				  SET Context_Info 0x55555
           
				  If exists(select * from #tmpUserLeads)        
				  Begin        
 					  SELECT @LastLeadId=IDENT_CURRENT('UserLeads')              
              
					  INSERT INTO [dbo].[UserLeads]              
					  ([LeadNo],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo]        
					  ,[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks],[Products],[AmountPaid],[CreatedOn],[CreatedBy],[FollowupDate],[enquirysource],[WhatsAppNoColName])
					  output inserted.ID as leadid into #outputLead
					  Select              
					  @NextLeadNo+LeadNo, [PersonName], [CompanyName], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], [City],[State], [Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo]
					  ,[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],case when [NextStatusDate]='' then '' else FORMAT(cast(NextStatusDate as Datetime),'dd-MMM-yyyy hh:mm:ss tt') end, [Remarks],[Products],[AmountPaid],[CreatedOn], [CreatedBy],[FollowupDate] , 21 as [enquirysource], WhatsAppNoColName        
					  From    #tmpUserLeads              
              
					  Select @nLeadInserted=@@ROWCOUNT       
  
					  print cast(@nLeadInserted as varchar) + ' Leads inserted'

					  select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),leadid),',') From #outputLead

					  Exec usp_ExecLeadTriggerTasks @CsvID
             
					  insert into leadinteractionhistory(LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,followupdate,IsAutoEntry)            
					  output inserted.ID into #outputLeadInteraction
					  select LeadNo, FollowUpStatus, NextStatusDate, Products, AmountPaid, Remarks, AssignedTo, ParentID, CreatedOn, CreatedBy, followupdate, 1 as IsAutoEntry
					  from userleads(nolock) where parentid=@ParentId and createdon=@CreatedOn            
             
					  select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),ID),',') From #outputLeadInteraction

					  Exec usp_ExecLeadInteractionTriggerTasks @CsvID
             
					  set @jRow = 1              
					  while(@jRow <= @CustomFieldsCnt)              
					  begin              
						   select @fieldId=t.fieldId,@fieldName=t.fieldName,@fieldtype=c.datatype       
						   from #tblCustomFields t join customfields c (nolock) on c.field_ID=t.fieldId and c.ParentID=@ParentId       
						   Where t.RowId=@jRow              
              
						   set @SQLString = 'insert into customfieldLeadvalue(LeadID,EnquiryID,fieldID,fieldvalue,CreatedDate)       
						   select distinct A.ID, 0, ' + cast(@fieldId as varchar) + ', case when '''+ cast(@fieldtype as nvarchar) +'''=''d'' and IsDate(C.[' + @fieldName + ']) =      
							1 then Format(cast(C.[' + @fieldName + '] as datetime),''dd-MMM-yyyy hh:mm:ss tt'') else C.[' + @fieldName + '] end, getdate()  
						   From [UserLeads] A(nolock) inner join #tmpUserLeads B              
						   ON   A.LeadNo = B.LeadNo+' + cast(@NextLeadNo as varchar) + ' inner join #tmpLeadSrc C
						   On  B.Sno = C.Sno              
						   Where A.[ParentID] = ' + cast(@ParentId as varchar) + ' and A.LeadNo <= ' + cast(@NextLeadNo as varchar) + '+' + cast(@nLeadInserted as varchar)              
                  
						   print 'custom field Lead @SQLString: ' + @SQLString + ' and isnull(C.[' + @fieldName + '],'''') != '''' '              
              
						   exec (@SQLString)              
						   select @nLeadCustomFieldRows+=@@ROWCOUNT              
              
						   set @jRow = @jRow + 1              
					  end         
          
					  SET DATEFORMAT dmy;          
					  UPDATE cflv set cflv.fieldvalue=case when isnull(cflv.fieldvalue,'') != '' then FORMAT(cast(cflv.fieldvalue as Datetime),'dd-MMM-yyyy hh:mm:ss tt') else cflv.fieldvalue end            
					  --select *            
					  FROM userleads ul inner join customfieldleadvalue cflv            
					  ON ul.id=cflv.leadid inner join customfields cf            
					  ON cflv.fieldid=cf.field_id            
					  WHERE ul.parentid=@ParentId and ul.createdon=@CreatedOn and cf.datatype='d'            
        
					  Set @RowData = isnull((Select  SNo=ROW_NUMBER()Over(order by B.ID), B.PersonName, CountryCode=Case B.WhatsAppNoColName When 'MobileNo' then B.CountryCode       
					  when 'MobileNo1' then B.CountryCode1 when 'MobileNo2' then B.CountryCode2 Else '' End, MobileNo=Case B.WhatsAppNoColName When 'MobileNo' then B.MobileNo       
					  when 'MobileNo1' then B.MobileNo1 when 'MobileNo2' then B.MobileNo2 Else '' End        
					  From #tmpUserLeads A inner join [UserLeads] B (nolock)        
					  ON   A.LeadNo + @NextLeadNo = B.LeadNo        
					  Where B.[ParentID] = @ParentId and B.WhatsAppNoColName in ('MobileNo','MobileNo1','MobileNo2')        
					   for json auto, INCLUDE_NULL_VALUES),'')        
        
					  If(len(@RowData)>1)        
					  Begin        
						  /* INSERT INTO [MySMSConversations].[dbo].[tbl_imp_ImportRequest]        
							  ([FileName],[FileSizeByte],[CreatedOn],[Status],[NoOfRecord],[IsProcessed]        
							  ,[ImportJSON],[SourceName],[CreatedBy],[ParentId])        
							 VALUES        
							  ('FromLead.xls',LEN(@RowData),Getdate(),'pending',0,0        
							  ,@RowData,0,@User_Id,@ParentId)        
        
						   Select @ImportRequestId=SCOPE_IDENTITY() */
						   SET @sqlquery = '
            INSERT INTO [tbl_imp_ImportRequest]    
                ([FileName], [FileSizeByte], [CreatedOn], [Status], [NoOfRecord], [IsProcessed],    
                 [ImportJSON], [SourceName], [CreatedBy], [ParentId])    
            VALUES    
                (''FromLead.xls'', ' + CAST(LEN(@RowData) AS NVARCHAR) + ', GETDATE(), ''pending'', 0, 0,    
                ''' + REPLACE(@RowData, '''', '''''') + ''', 0, ' + CAST(@User_Id AS NVARCHAR) + ', ' + CAST(@ParentId AS NVARCHAR) + ');
            ';
            
            -- Get the inserted ID back
            EXEC usp_clr_InsertAndReturnId @sqlquery, @retid = @ImportRequestId OUTPUT;
						   select @RecCnt=count(*) from openjson(@RowData)            
        
						   While(1=1)        
						   Begin        
							set @Start=@End+1        
							set @End=@Pagesize*@Pageno        
        
							Set @RowData = isnull((Select * from (Select  SNo=ROW_NUMBER()Over(order by B.ID), B.PersonName, CountryCode=Case B.WhatsAppNoColName When 'MobileNo' then B.CountryCode when 'MobileNo1' then B.CountryCode1 when 'MobileNo2' then B.CountryCode2 Else '' End, MobileNo=Case B.WhatsAppNoColName When 'MobileNo' then B.MobileNo when 'MobileNo1' then B.MobileNo1 when 'MobileNo2' then B.MobileNo2 Else '' End        
							From #tmpUserLeads A inner join [UserLeads] B (nolock)        
							ON   A.LeadNo + @NextLeadNo = B.LeadNo        
							Where B.[ParentID] = @ParentId and B.WhatsAppNoColName in ('MobileNo','MobileNo1','MobileNo2')) T        
							Where T.SNo between @Start and @End        
							 for json auto, INCLUDE_NULL_VALUES),'')        
        
							/*INSERT INTO [MySMSConversations].[dbo].[tbl_ims_ImportSlot]        
							   ([requestid],[createdon],[contactjson],[isprocessed])        
							  VALUES        
							   (@ImportRequestId,Getdate(),@RowData,0) */ 
							    SET @sqlquery = '
                             INSERT INTO [tbl_ims_ImportSlot]    
                                 ([requestid], [createdon], [contactjson], [isprocessed])    
                             VALUES    
                                 (' + CAST(@ImportRequestId AS NVARCHAR) + ', GETDATE(), ''' + REPLACE(@RowData, '''', '''''') + ''', 0);
                             ';
                             
                             -- Execute remotely
                             EXEC usp_clr_ExecuteRemoteQuery @sqlquery;
        
							If(@RecCnt < (@Pageno*@Pagesize))        
							Begin        
							 break        
							End        
							Else        
							Begin        
							 Set @Pageno=@Pageno+1        
							End        
						   End        
        
						   Set @RowData = null        
					  End        
        
				   End        
         
				  Set @RowData = isnull((Select Sno, Remarks From #tmpConstraintChk order by Sno for json auto, INCLUDE_NULL_VALUES),'')              
         
				  print 'Final @RowData: ' + cast(@RowData as varchar(max))        
            
				  update tbl_LeadImportSummary               
				   set IsProcessed=1, Remarks=@RowData, LeadCnt=@nLeadInserted, LeadCustomFieldCnt=@nLeadCustomFieldRows               
				   where ImportRow_Id=@ImportRow_id     
     
				  select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@tic as nvarchar) +' leads for importing.   
				   The request is processed and leads imported are '+cast( @nLeadInserted as nvarchar)   
				  exec UspSaveEntityActivity_withid 'user',@user_id,@user_id,@ParentID,@EventDescription,@EventName,'tbl_LeadImportSummary',@ImportRow_id  
				  exec Usp_InsertUserEventDetails 'Lead Import successful',@parentid,@eventdescription, 'tbl_LeadImportSummary',@ImportRow_id
           
				  Iter:          
					Set @iRow = @iRow + 1
					Set @ImportRow_id=0
					Set @ImportData=null
					Set @RowData=null
					Set @FieldNames=''
					Set @SQLString=null
					Set @User_Id=0
					Set @LastLeadId=0
					Set @nLeadInserted=0
					Set @nLeadCustomFieldRows=0
					Set @jRow=1
					Set @fieldId=0
					Set @fieldName=''
					Set @CustomFieldsCnt = 0
					Set @ImportRequestId = 0
					Set @RecCnt = 0
					Set @Start = 0
					Set @End = 0
					Set @Pagesize = 500
					Set @Pageno = 1
              
				   truncate table #tmpConstraintChk              
				   truncate table #tmpUserLeads              
				   truncate table #tmpMobileNoList              
				   truncate table #tmpEmailIdList              
				   truncate table #tblCustomFields              
              
				   if object_id('tempdb..#tmpLeadSrc') is not null begin drop table #tmpLeadSrc end                            
				   if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end
				   if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end
			End              
              
		COMMIT TRANSACTION     
		SET Context_Info 0x
		
	END TRY                  
	BEGIN CATCH                 
		While @@TRANCOUNT > 0
			ROLLBACK TRANSACTION
                
		SET Context_Info 0x
	
		insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)        
		SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()  
   
		select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@tic as nvarchar) +' leads for importing.   
	   The request failed. Pl check Import summary for details'   
		exec UspSaveEntityActivity_withid 'user',@user_id,@user_id,@ParentID,@EventDescription,@EventName,'tbl_LeadImportSummary',@ImportRow_id
		exec Usp_InsertUserEventDetails 'Lead Import failed',@parentid,@eventdescription, 'tbl_LeadImportSummary',@ImportRow_id
        
	END CATCH                  
              
	if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end              
	if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end              
	if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end              
	if object_id('tempdb..#tblAllLeadFields') is not null begin drop table #tblAllLeadFields end              
	if object_id('tempdb..#tmpLeadSrc') is not null begin drop table #tmpLeadSrc end              
	if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end              
	if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end              
	if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end              
	if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end
	if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end
              
END 



GO

/* ============================================================
   Procedure: [dbo].[usp_ProcessLeadImportData_Replication]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--Dependency of this usp_ProcessLeadImportData_Replication

--1.[MySMSConversations].[dbo].[tbl_imp_ImportRequest]       -- called by clr
--2. usp_ProcessEnquiryImportData_corrected  -- called by clr 

-------------------------------------


 
    
-- Exec usp_ProcessLeadImportData 0, 'P'            
-- Exec usp_ProcessLeadImportData 1, 'P'            
-- Exec usp_ProcessLeadImportData 1, 'P', 1814            
CREATE   PROC [dbo].[usp_ProcessLeadImportData_Replication] --1,'p', 2628           
(              
    @BatchSize int=1,  -- 0 ('All')              
    @Mode varchar(1)='P',    -- 'P'riority, 'F'ifo        
	@IPRId bigint=0        
)              
AS              
BEGIN              
     
	   DECLARE @sqlquery NVARCHAR(MAX);      
	-- declare @BatchSize int=1,@Mode varchar(1)='P', @IPRId bigint=1814         
	if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end              
	if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end              
	if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end              
	if object_id('tempdb..#tblAllLeadFields') is not null begin drop table #tblAllLeadFields end              
	if object_id('tempdb..#tmpLeadSrc') is not null begin drop table #tmpLeadSrc end              
	if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end              
	if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end              
	if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end              
	if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end
	if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end
	if object_id('tempdb..#tmpTblPrdct2') is not null begin drop table #tmpTblPrdct2 end

	Create table #tblImportRowId
	(              
		RowId int identity,              
		ImportRow_id bigint,              
		[User_Id] bigint              
	)              
              
	create table #tmpConstraintChk
	(              
		Sno int,              
		Remarks varchar(200)              
	)              
              
	create table #tblCustomFields
	(              
		RowId int identity(1,1),              
		fieldId bigint,              
		fieldName varchar(50)              
	)              
              
	create table #tblAllLeadFields
	(              
		RowId int identity(1,1),              
		fieldName varchar(50),          
		FieldType varchar(10)          
	)              
              
	create table #tmpMobileNoList
	(              
		RowId int identity,              
		MobileNo varchar(100)              
	)              
              
	create table #tmpEmailIdList
	(              
		RowId int identity,              
		EmailId varchar(100)              
	)              
              
	CREATE TABLE #tmpUserLeads 
	(
	 [LeadNo] [bigint] IDENTITY(1,1) NOT NULL,              
	 [Sno] [int] NOT NULL,              
	 [PersonName] [nvarchar](400) NULL,              
	 [CompanyName] [nvarchar](1000) NULL,              
	 [MobileNo] [varchar](100) NULL,              
	 [MobileNo1] [varchar](100) NULL,              
	 [MobileNo2] [varchar](100) NULL,              
	 [EmailID] [varchar](100) NULL,              
	 [EmailID1] [varchar](100) NULL,              
	 [EmailID2] [varchar](100) NULL,              
	 [City] [varchar](100) NULL,              
	 [State] [varchar](100) NULL,              
	 [Country] [varchar](100) NULL,              
	 [CountryCode] [varchar](50) NULL,              
	 [CountryCode1] [varchar](50) NULL,              
	 [CountryCode2] [varchar](50) NULL,              
	 [PinCode] [bigint] NULL,              
	 [ResidentialAddress] [nvarchar](500) NULL,              
	 [OfficeAddress] [nvarchar](500) NULL,              
	 [AssignedTo] [bigint] NOT NULL,              
	 [SourceName] [bigint] DEFAULT ((0)) NOT NULL,              
	 [MediumName] [bigint] DEFAULT ((0)) NULL,              
	 [CampaignName] [bigint] DEFAULT ((0)) NULL,              
	 [InitialRemarks] [nvarchar](1000) NULL,              
	 [ParentID] [bigint] NOT NULL,              
	 [FollowUpStatus] [int] NULL,              
	 [NextStatusDate] [varchar](50) NULL,              
	 [Remarks] [nvarchar](1000) NULL,              
	 [Products] [varchar](1000) NULL,
	-- [ProductsJson] [nvarchar](max) NULL,
	 [AmountPaid] [numeric](18, 2) NOT NULL DEFAULT ((0)),              
	 [CreatedOn] [datetime] NULL,              
	 [CreatedBy] [bigint] NULL,      
	 [FollowupDate] [datetime] NULL,        
	 [WhatsAppNoColName] varchar(10)        
	)              
              
	BEGIN TRY
		BEGIN TRANSACTION              
        
			If(isnull(@IPRId,0) > 0)        
			Begin        
				insert into #tblImportRowId        
				Select ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where ImportRow_id=@IPRId        
			End        
			Else        
			Begin        
				If(@Mode = 'P')          
				Begin              
					If(@BatchSize != 0)              
					Begin              
						insert into #tblImportRowId              
						Select top (@BatchSize) ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where IsProcessed=0 order by [Priority]              
					End              
					Else              
					Begin              
						insert into #tblImportRowId              
						Select ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where IsProcessed=0 order by [Priority]              
					End              
				End              
				Else -- Fifo              
				Begin              
					If(@BatchSize != 0)              
					Begin              
						insert into #tblImportRowId              
						Select top (@BatchSize) ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where IsProcessed=0              
					End              
					Else              
					Begin              
						insert into #tblImportRowId              
						Select ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where IsProcessed=0              
					End              
				End            
			End        

			select * from #tblImportRowId              
              
			declare @iRow int=1, @jRow int=1, @ImportRow_id bigint=0, @UnProcessedRowCnt int=0, @User_Id bigint=0, @LastLeadId bigint=0, @nLeadInserted bigint=0, @fieldId bigint=0, @nLeadCustomFieldRows bigint=0, @CsvID nvarchar(max)              
			declare @ImportData nvarchar(max), @RowData nvarchar(max), @FieldNames nvarchar(max)='', @SQLString nvarchar(max)='', @ParmDefinition nvarchar(500), @fieldName varchar(50)='',@fieldtype nvarchar(20);                
			declare @NextLeadNo bigint=0, @CustomFieldsCnt int=0, @ParentId bigint=0, @CreatedOn datetime, @ImportRequestId bigint=0, @RecCnt int =0, @Pagesize int=500, @Pageno int=1, @Start int=0, @End int=0             
			declare @eventname nvarchar(100),@eventdescription nvarchar(500),@userlogin nvarchar(100),@tic int          
			select @UnProcessedRowCnt=Count(*) from #tblImportRowId              
              
			While(@iRow <= @UnProcessedRowCnt)              
			Begin              
				  print '@iRow: ' + cast(@iRow as varchar)              
				  Select @ImportRow_id=ImportRow_id,@User_Id=[User_Id] From #tblImportRowId Where RowId=@iRow              
				  print '@ImportRow_id: ' + cast(@ImportRow_id as varchar)              
				  Select @ImportData=ImportData from tbl_LeadImportSummary(nolock) where ImportRow_Id=@ImportRow_id              
				  print '@ImportData: ' + @ImportData              
				  select top 1 @RowData=value from openjson(@ImportData)              
				  print '@RowData: ' + @RowData              
				  select @FieldNames=@FieldNames+'['+[Key]+'] nvarchar(2000),' from openjson(@RowData)              
				  print '@FieldNames1: ' + @FieldNames              

				  If (CHARINDEX('WhatsAppNoColName',@FieldNames,0) > 0)        
				  Begin        
						print 'WhatsAppNoColName found'        
						set @FieldNames=SUBSTRING(@FieldNames,1,len(@FieldNames)-1)              
				  End        
				  Else        
				  Begin        
					   print 'WhatsAppNoColName not found, adding dummy'        
					   select @FieldNames=@FieldNames+' [WhatsAppNoColName] varchar(10)'        
					   select @RowData=replace(@RowData,'}',',"WhatsAppNoColName":null}')        
				  End        
				  print '@FieldNames2: ' + @FieldNames              
            
				  Select @ParentId=parentid,@userlogin=User_Login from user_detail(nolock) where user_id= @User_Id  
          
				  insert into #tblAllLeadFields          
				  values ('Sno','Main'),('PersonName','Main'),('CompanyName','Main'),('MobileNo','Main'),('MobileNo1','Main'),('MobileNo2','Main'),('EmailID','Main'),('EmailID1','Main'),('EmailID2','Main'),('City','Main'),('State','Main'),('Country','Main'),('CountryCode','Main'),('CountryCode1','Main'),('CountryCode2','Main'),('PinCode','Main'),('ResidentialAddress','Main'),('OfficeAddress','Main'),('AssignedTo','Main'),('SourceName','Main'),('MediumName','Main'),('CampaignName','Main'),('InitialRemarks','Main'),('FollowupStatus','Main'),('NextStatusDate','Main'),('Remarks','Main'),('Products','Main'),('AmountPaid','Main'),('FollowupDate','Main'), ('WhatsAppNoColName','Main')         
          
				  insert into #tblAllLeadFields          
				  select fieldname,'Custom' from customfields(nolock) where parentId=@ParentId and isActive=1          
          
				  Update tbl_LeadImportSummary Set IsProcessed=1,importstart=getdate(),Remarks='[{"Sno":0,"Remarks":"Under Process Queue"}]'         
				  Where ImportRow_Id = @ImportRow_id        
        
				  if exists(select [Key] from openjson(@RowData) where [Key] COLLATE SQL_Latin1_General_CP1_CI_AS not in (Select FieldName From #tblAllLeadFields))        
				  Begin        
						print 'Invalid Field found in Import Data'        
						Update tbl_LeadImportSummary Set IsProcessed=1,importend=getdate(),Remarks='[{"Sno":0,"Remarks":"Invalid Field found in Import Data"}]'
						Where ImportRow_Id = @ImportRow_id  

						select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@tic as nvarchar) +' leads for importing. The request failed. Pl check Import summary for details'   
						exec UspSaveEntityActivity_withid 'user',@user_id,@user_id,@ParentID,@EventDescription,@EventName,'tbl_LeadImportSummary',@ImportRow_id
						exec Usp_InsertUserEventDetails 'Lead Import failed',@parentid,@eventdescription, 'tbl_LeadImportSummary',@ImportRow_id
 
						goto Iter        
				  End
				  Else        
				  Begin        
					   If exists(Select FieldName From #tblAllLeadFields Where FieldName COLLATE SQL_Latin1_General_CP1_CI_AS not in (select [Key] from openjson(@RowData)))        
					   Begin        
							print 'Required Field Missing in Import Data'        
							Update tbl_LeadImportSummary Set IsProcessed=1,importend=getdate(),Remarks='[{"Sno":0,"Remarks":"Required Field Missing in Import Data"}]'        
							Where ImportRow_Id = @ImportRow_id        

							select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@tic as nvarchar) +' leads for importing.   
						   The request failed. Pl check Import summary for details'   
							exec UspSaveEntityActivity_withid 'user', @user_id, @user_id, @ParentID, @EventDescription, @EventName, 'tbl_LeadImportSummary', @ImportRow_id
							exec Usp_InsertUserEventDetails 'Lead Import failed',@parentid,@eventdescription, 'tbl_LeadImportSummary',@ImportRow_id
 
							goto Iter        
					   End        
				  End        
          
				  create table #tmpLeadSrc (id int identity);              
				  print 'alter table #tmpLeadSrc add ' + @FieldNames              
				  exec('alter table #tmpLeadSrc add ' + @FieldNames)              
              
				  --Set @SQLString = N'insert into #tmpLeadSrc select * from openjson(@ImptData) with (' + @FieldNames + ') where [PersonName] is not null and [MobileNo] is not null and [CountryCode] is not null and [ResidentialAddress] is not null and [SourceName] is not null and [InitialRemarks] is not null and [FollowupStatus] is not null'               
				  Set @SQLString = N'insert into #tmpLeadSrc select * from openjson(@ImptData) with (' + @FieldNames + ')'  
              	  --Set @SQLString = N'insert into #tmpLeadSrc select * from openjson(@ImptData) with (' + @FieldNames + ') where [Sno] is not null'  
              
				  --SET @ParmDefinition = N'@ImptData nvarchar(max), @FldNames nvarchar(max)';                
				  SET @ParmDefinition = N'@ImptData nvarchar(max)';    
  
				  if object_id('tempdb..#tmpLeadSrc') is not null   
				  begin   
					 select @tic=count(1) from #tmpLeadSrc  
				  end              
	
				  print @SQLString              
              
				  --EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData, @FldNames=@FieldNames                
				  EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData                
            
				  --select * from openjson(@RowData)              
          
				  update #tmpLeadSrc               
				  set MobileNo=rtrim(ltrim(case when isnull(MobileNo,'')='' and isnull(MobileNo1,'')!='' then MobileNo1 else Isnull(MobileNo,'') end)),        
				  MobileNo1=rtrim(ltrim(case when isnull(MobileNo1,'')='' and isnull(MobileNo2,'')!='' then MobileNo2 else Isnull(MobileNo1,'') end)),        
				  MobileNo2=rtrim(ltrim(isnull(MobileNo2,''))),              
				  CountryCode=rtrim(ltrim(case when isnull(CountryCode,'')='' and isnull(CountryCode1,'')!=''    
				  then iif(left(ltrim(CountryCode1),1) != '+','+'+ltrim(CountryCode1),CountryCode1) else iif(left(ltrim(Isnull(CountryCode,'')),1) != '+' and ltrim(Isnull(CountryCode,'')) != '', '+'       
				  + ltrim(Isnull(CountryCode,'')),Isnull(CountryCode,'')) end)),              
				  CountryCode1=rtrim(ltrim(case when isnull(CountryCode1,'')='' and isnull(CountryCode2,'')!=''  
				  then iif(left(ltrim(CountryCode2),1) != '+','+'+ltrim(CountryCode2),CountryCode2) else iif(left(ltrim(Isnull(CountryCode1,'')),1) != '+' and ltrim(Isnull(CountryCode1,'')) != '', '+'      
				  + ltrim(Isnull(CountryCode1,'')),Isnull(CountryCode1,'')) end)),              
				  CountryCode2=rtrim(ltrim(iif(left(ltrim(isnull(CountryCode2,'')),1) != '+' and ltrim(isnull(CountryCode2,'')) != '','+' + ltrim(isnull(CountryCode2,'')),Isnull(CountryCode2,'')))),    
				  EmailID=rtrim(ltrim(case when isnull(EmailID,'')='' and isnull(EmailID1,'')!='' then EmailID1 else Isnull(EmailID,'') end)),              
				  EmailID1=rtrim(ltrim(case when isnull(EmailID1,'')='' and isnull(EmailID2,'')!='' then EmailID2 else Isnull(EmailID1,'') end)),              
				  EmailID2=rtrim(ltrim(isnull(EmailID2,''))),              
				  PersonName=rtrim(ltrim(isnull(PersonName,''))),              
				  InitialRemarks=rtrim(ltrim(isnull(InitialRemarks,''))),              
				  AssignedTo=rtrim(ltrim(isnull(AssignedTo,''))),              
				  SourceName=rtrim(ltrim(isnull(SourceName,''))),              
				  MediumName=rtrim(ltrim(isnull(MediumName,''))),              
				  CampaignName=rtrim(ltrim(isnull(CampaignName,''))),              
				  FollowupStatus=rtrim(ltrim(isnull(FollowupStatus,''))),              
				  NextStatusDate=rtrim(ltrim(isnull(NextStatusDate,''))),              
				  Remarks=rtrim(ltrim(isnull(Remarks,''))),              
				  Products=rtrim(ltrim(isnull(Products,''))),              
				  AmountPaid=rtrim(ltrim(isnull(AmountPaid,'0'))),              
				  FollowupDate=rtrim(ltrim(isnull(FollowupDate,'0'))),              
				  WhatsAppNoColName=rtrim(ltrim(isnull(WhatsAppNoColName,''))),              
				  Sno=rtrim(ltrim(isnull(Sno,0)))              
              
				  --EXEC('select * from #tmpLeadSrc')              
              
				  insert into #tmpConstraintChk              
				  Select  Sno, 'Duplicate Records' as Remarks              
				  From              
				  (              
				   select ROW_NUMBER()over(partition by PersonName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, InitialRemarks         
				   order by cast(Sno as int)) as Rid, *              
				   from #tmpLeadSrc              
				  ) B              
				  Where B.Rid > 1              
                  
            
				  insert into #tblCustomFields              
				  select field_ID, fieldname               
				  from customfields(nolock)               
				  where parentId=@ParentId and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select FieldName from #tblAllLeadFields where [FieldType] = 'Custom')              
				  /*where parentId=@ParentId and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select [Key]              
				  from openjson(@RowData) where [Key] not in ('Sno', 'PersonName', 'CompanyName', 'MobileNo', 'MobileNo1', 'MobileNo2', 'EmailID', 'EmailID1', 'EmailID2', 'City', 'State', 'Country', 'CountryCode', 'CountryCode1', 'CountryCode2', 'PinCode', 'ResidentialAddress', 'OfficeAddress', 'AssignedTo', 'SourceName', 'MediumName', 'CampaignName', 'InitialRemarks', 'FollowupStatus', 'NextStatusDate', 'Remarks', 'Products', 'AmountPaid', 'FollowupDate', 'ProfileImgFileName')) */             
              
				  Select @CustomFieldsCnt=count(*) From #tblCustomFields              
              
				  insert into #tmpConstraintChk              
				  Select  Sno, 'Sno missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(Sno),'') = '' or ISNULL(ltrim(Sno),'0') = '0'              
				  union              
				  Select  Sno, 'Sno Duplicate' as Remarks              
				  From    #tmpLeadSrc              
				  group by Sno              
				  having  Count(*) > 1              
				  union              
				  Select  Sno, 'PersonName missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(PersonName),'') = ''              
				  union              
				  Select  Sno, 'Contact details missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(MobileNo),'') = '' and ISNULL(ltrim(MobileNo1),'') = '' and ISNULL(ltrim(MobileNo2),'') = '' and               
				  ISNULL(ltrim(EmailID),'') = '' and ISNULL(ltrim(EmailID1),'') = '' and ISNULL(ltrim(EmailID2),'') = ''              
				  union              
				  Select  Sno, 'MobileNo or CountryCode missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ((ISNULL(ltrim(MobileNo),'')!='' and ISNULL(ltrim(CountryCode),'')='') or (ISNULL(ltrim(MobileNo),'')='' and ISNULL(ltrim(CountryCode),'')!=''))              
				   or              
				  ((ISNULL(ltrim(MobileNo1),'')!='' and ISNULL(ltrim(CountryCode1),'')='') or (ISNULL(ltrim(MobileNo1),'')='' and ISNULL(ltrim(CountryCode1),'')!='')) or              
				  ((ISNULL(ltrim(MobileNo2),'')!='' and ISNULL(ltrim(CountryCode2),'')='') or (ISNULL(ltrim(MobileNo2),'')='' and ISNULL(ltrim(CountryCode2),'')!=''))              
				  union              
				  Select  Sno, 'AssignedTo missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(AssignedTo),'') = ''              
				  union              
				  Select  Sno, 'AssignedTo Invalid' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(AssignedTo),'') not in (Select [User_Login] from User_Detail(nolock) Where Status=1)              
				  union              
				  Select  Sno, 'SourceName missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(SourceName),'') = ''              
				  union              
				  Select  Sno, 'FollowupStatus missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(FollowupStatus),'') = ''              
				  union              
				  Select  Sno, 'FollowupStatus missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(FollowupStatus),'') not in (Select FollowupStatus from FollowUp_Status(nolock) Where IsActive=1)              
				  union              
				  Select  Sno, 'FollowupDate missing' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(FollowupDate),'') = ''              
				  union              
				  Select  Sno, 'Invalid FollowupDate' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(FollowupDate),'') != '' and ISDATE(FollowupDate) != 1              
				  union              
				  Select  Sno, 'Invalid NextStatusDate' as Remarks              
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(NextStatusDate),'') != '' and ISDATE(NextStatusDate) != 1              
				  union              
				  
				  --Select  Sno, 'Invalid Products' as Remarks              
				  --From    #tmpLeadSrc              
				  --Where   ISNULL(ltrim(Products),'') != '' and Products not like '%#%' and Products not in (select [Name] from ProductMaster(nolock) Where IsActive=1 and UserID=@ParentId)              
				  --union
				                
				  --Select  Sno, 'Invalid Products' as Remarks              
				  --From    #tmpLeadSrc              
				  --Where   Products like '%#%' and dbo.ufn_GetProductId(Products,@ParentId,'#')=''              
				  --union              
				  
				  Select  Sno, 'PersonName Length exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(PersonName)>100              
				  union              
				  Select  Sno, 'CompanyName exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(CompanyName)>100              
				  union              
				  Select  Sno, 'MobileNo exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(MobileNo)>100              
				  union              
				  Select  Sno, 'MobileNo1 exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(MobileNo1)>100              
				  union              
				  Select  Sno, 'MobileNo2 exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(MobileNo2)>100              
				  union              
				  Select  Sno, 'EmailID exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(EmailID)>100              
				  union              
				  Select  Sno, 'EmailID1 exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(EmailID1)>100              
				  union              
				  Select  Sno, 'City exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(City)>100              
				  union              
				  Select  Sno, 'State exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(State)>100              
				  union              
				  Select Sno, 'Country exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(Country)>100              
				  union              
				  Select  Sno, 'CountryCode exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(CountryCode)>100              
				  union              
				  Select  Sno, 'CountryCode1 exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(CountryCode1)>100              
				  union              
				  Select  Sno, 'CountryCode2 exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(CountryCode2)>100              
				  union              
				  Select  Sno, 'ResidentialAddress exceeds specified limit(500)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(ResidentialAddress)>500              
				  union              
				  Select  Sno, 'OfficeAddress exceeds specified limit(500)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(OfficeAddress)>500              
				  union              
				  Select  Sno, 'SourceName exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(SourceName)>100              
				  union              
				  Select  Sno, 'MediumName exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(MediumName)>100              
				  union              
				  Select  Sno, 'CampaignName exceeds specified limit(100)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(CampaignName)>100              
				  union              
				  Select  Sno, 'InitialRemarks exceeds specified limit(1000)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(InitialRemarks)>1000              
				  union              
				  Select  Sno, 'Remarks exceeds specified limit(1000)' as Remarks              
				  From    #tmpLeadSrc              
				  Where   len(Remarks)>1000              
				  union              
				  Select  Sno, 'Invalid Character found in AmountPaid' as Remarks
				  From    #tmpLeadSrc              
				  Where   isnull(AmountPaid,'')!='' and try_cast(AmountPaid as numeric(18,2)) is null
				  
				  
				   exec Usp_createProductMasterTable @ParentID

				  Declare @Query1 nvarchar(max) = N'Select  Sno, ''Invalid Products'' as Remarks into #tmpConstraintChk             
				  From    #tmpLeadSrc              
				  Where   ISNULL(ltrim(Products),'''') != '''' and Products not like ''%#%'' 
				  and exists ( select value from fn_split(Products, ''#'')  
		             where value not in (select [Name] from tbl_ProductMaster_'+ cast(@ParentID as nvarchar(20))+' (nolock) 
				  Where IsActive=1 and UserID= '+ cast( @ParentId as nvarchar(20) )+ ' ))'              
				 

				  print 'dynamic query1'
				  print  @Query1

                  exec sp_executesql @Query1    
				  

				  --select * from #tmpConstraintChk

				  --Select  Sno, 'Invalid Products' as Remarks              
				  --From    #tmpLeadSrc              
				  --Where   Products like '%#%' and dbo.ufn_GetProductId(Products,@ParentId,'#')=''              
				  --union

				   Select ROW_NUMBER() over(order by Sno asc) as RowNum, Sno, Products into #tmpTblPrdct2 from #tmpLeadSrc  where Products like '%#%'
				   Declare @Row_Num1 int = 1
				   DEclare @Count_Prdct2 int = (select count(1) from #tmpTblPrdct2)   

				   while(@Count_Prdct2 >= @Row_Num1) 
				      begin
					       Declare @Sno1 int
						   Declare @ProductsJson_2 nvarchar(500)
						   select @Sno1 = Sno , @ProductsJson_2 = isnull(Products,'') from  #tmpTblPrdct2 where RowNum = @Row_Num1

						   declare @Outtemp nvarchar(500) = '' 
                           exec usp_GetProductId @ProductsJson_2, @ParentID,'#' , @Outtemp output
                        -- select @Outtemp
					 
     				     if(isnull(@Outtemp,'') = '')
							   begin
							      insert into #tmpConstraintChk  
								  Select  Sno, 'Invalid Products' as Remarks              
				                  From   #tmpLeadSrc where Sno = @Sno1             
				  			   end 
						   set  @Row_Num1 = @Row_Num1 + 1    
					  End
				  
				  
				  /*              
				  union              
				  Select  Sno, 'Invalid DateOfBirth' as Remarks              
				  From    #tmpLeadSrc              
				  Where   isnull(ltrim(DateOfBirth),'') != '' and ISDate(DateOfBirth) = 0              
				  */              
              
				  insert into #tmpMobileNoList              
				   select MobileNo              
				   From UserLeads(nolock)              
				   Where ParentID in (@ParentId) and isnull(ltrim(MobileNo),'') != ''              
				   union              
				   select MobileNo1              
				   From UserLeads(nolock)              
				   Where ParentID in (@ParentId) and isnull(ltrim(MobileNo1),'') != ''              
				   union              
				   select MobileNo2              
				   From UserLeads(nolock)              
				   Where ParentID in (@ParentId) and isnull(ltrim(MobileNo2),'') != ''              
              
				  insert into #tmpEmailIdList              
				   select EmailID              
				   From UserLeads(nolock)              
				   Where ParentID in (@ParentId) and isnull(ltrim(EmailID),'') != ''          
				   union              
				   select EmailID1              
				   From UserLeads(nolock)              
				   Where ParentID in (@ParentId) and isnull(ltrim(EmailID1),'') != ''              
				   union              
				   select EmailID2              
				   From UserLeads(nolock)              
				   Where ParentID in (@ParentId) and isnull(ltrim(EmailID2),'') != ''              
              
				  insert into #tmpConstraintChk              
				   Select  distinct Sno, 'MobileNo already present in Leads' as Remarks              
				   From              
				   (              
				   Select  Sno, MobileNo              
				   From  #tmpLeadSrc              
				   Where   ISNULL(ltrim(MobileNo),'') != ''              
				   union              
				   Select  Sno, MobileNo1              
				   From  #tmpLeadSrc              
				   Where   ISNULL(ltrim(MobileNo1),'') != ''              
				   union              
				   Select Sno, MobileNo2              
				   From  #tmpLeadSrc              
				   Where   ISNULL(ltrim(MobileNo2),'') != ''              
				   ) A              
				   Where A.MobileNo in (Select MobileNo From #tmpMobileNoList)              
              
				  insert into #tmpConstraintChk              
				   Select  distinct Sno, 'EmailID already present in Leads' as Remarks              
				   From              
				   (              
				   Select  Sno, EmailID              
				   From  #tmpLeadSrc              
				   Where   ISNULL(ltrim(EmailID),'') != ''              
				   union              
				   Select  Sno, EmailID1              
				   From  #tmpLeadSrc              
				   Where   ISNULL(ltrim(EmailID1),'') != ''              
				   union              
				   Select  Sno, EmailID2              
				   From  #tmpLeadSrc              
				   Where   ISNULL(ltrim(EmailID2),'') != ''              
				   ) A              
				   Where A.EmailID in (Select EmailID From #tmpEmailIdList)              
              
				  select count(*) as ConstraintChkCnt1 from #tmpConstraintChk              
              
				  INSERT INTO UserSourceSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)                
				   Select distinct SourceName, @ParentId, 1,  1, GETDATE(), GETDATE(), @User_Id                
					From  #tmpLeadSrc               
				   Where   SourceName not in (Select [Name] from UserSourceSettings(nolock) Where IsActive=1 and Userid=@ParentId) and Sno not in (Select distinct Sno from #tmpConstraintChk)              
              
				  INSERT INTO UserMediumSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)                
				   Select distinct MediumName, @ParentId, 1,  1, GETDATE(), GETDATE(), @User_Id                
				   From  #tmpLeadSrc               
				   Where   MediumName not in (Select [Name] from UserMediumSettings(nolock) Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(MediumName),'') != '' and Sno not in (Select distinct Sno from #tmpConstraintChk)              
              
				  INSERT INTO UserCampaignSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)                
				   Select distinct CampaignName, @ParentId, 1,  1, GETDATE(), GETDATE(), @User_Id                
				   From  #tmpLeadSrc               
				   Where   CampaignName not in (Select [Name] from UserCampaignSettings(nolock) Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(CampaignName),'') != ''and Sno not in (Select distinct Sno from #tmpConstraintChk)              
              
				  Update #tmpLeadSrc               
				  Set SourceName=(Select top 1 SourceId From UserSourceSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=SourceName),             
				   MediumName=(Select top 1 MediumID From UserMediumSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=MediumName),              
				   CampaignName=(Select top 1 CampaignID From UserCampaignSettings(nolock) Where IsActive=1 and UserID=@ParentId and [Name]=CampaignName),        
				   AssignedTo=(Select top 1 [User_ID] From User_Detail(nolock) Where [Status]=1 and [User_Login]=AssignedTo),              
				   FollowUpStatus=(Select top 1 ID From FollowUp_Status(nolock) Where IsActive=1 and FollowUp_Status.FollowupStatus=#tmpLeadSrc.FollowUpStatus and ParentId=@ParentId)
				   --,Products= case when Products!= '' then dbo.ufn_GetProductId(Products,@ParentId,'#') else Products end              
				   Where Sno not in (Select distinct Sno from #tmpConstraintChk)              
              
			     drop table if exists  #tempPRD1 
			     select ROW_NUMBER() over(order by Sno asc) as RowNum,Sno,Products into #tempPRD1 from  #tmpLeadSrc 
				  Where Sno not in (Select distinct Sno from #tmpConstraintChk)                
				               and Products!= ''
				  Declare @RowNum int = 1
				  Declare @CountProduct1 int = ( select count(1) from #tempPRD1)
				 
				  exec Usp_createProductMasterTable @ParentID
				  while(@CountProduct1 >= @RowNum)
				    Begin
					   declare @ProductsJson nvarchar(max)
					   declare @Sno int  
					   select top 1 @Sno = Sno , @ProductsJson = Products from  #tempPRD1 where RowNum = @RowNum
					 
					    select  @productsJson  = (          
							   select value as ProductName    
								  from fn_split(@ProductsJson,'#')    
								 FOR JSON AUTO          
								,INCLUDE_NULL_VALUES          
							   )   

						-- declare @Outtemp1 nvarchar(500) = '' 
                        -- exec usp_GetProductId @Products, @ParentID,'#' , @Outtemp1 output
                       -- select @Outtemp
						 --Update #tmpLeadSrc set Products = isnull(@Outtemp1,'') where Sno = @Sno
						 
						 Update #tmpLeadSrc set products = isnull(@productsJson,'') where Sno = @Sno
						 
						  set @RowNum = @RowNum + 1           
					End
				  												 
                   drop table if exists  #tempPRD1    																    


				  Select @CreatedOn=getdate()            
              
				  INSERT INTO #tmpUserLeads              
				   ([Sno], [PersonName], [CompanyName], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], [City], [State], [Country], [CountryCode], [CountryCode1], [CountryCode2], [PinCode], [ResidentialAddress], [OfficeAddress], [AssignedTo], [SourceName], [MediumName], [CampaignName], [InitialRemarks], [ParentID], [FollowUpStatus], [NextStatusDate], [Remarks], [Products], [AmountPaid], [CreatedOn], [CreatedBy], [FollowupDate], [WhatsAppNoColName])        
				   Select  Sno, PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, City, [State], Country ,CountryCode,CountryCode1,CountryCode2,case when ISNUMERIC(PinCode) != 1 then 0 else PinCode end, ResidentialAddress, OfficeAddress, AssignedTo, SourceName, MediumName, CampaignName, InitialRemarks, @ParentId as ParentID, FollowUpStatus, NextStatusDate, Remarks, Products, iif(isnull(AmountPaid,'') = '', '0', AmountPaid), @CreatedOn as CreatedOn, @User_Id as CreatedBy, FollowupDate, WhatsAppNoColName        
				   From #tmpLeadSrc              
				   Where Sno not in (Select distinct Sno from #tmpConstraintChk)  
              
				  Select @NextLeadNo=Isnull(max(LeadNo),0) From UserLeads(nolock) Where ParentID=@ParentId               
        
				  print '@NextLeadNo: ' + cast(@NextLeadNo as varchar)        
              
				  Update CRMCampaignSettings               
				   Set LastUserAssigned=isnull((Select top 1 AssignedTo From #tmpLeadSrc Where ISNULL(AssignedTo,'') != '' and Sno not in (Select distinct Sno from #tmpConstraintChk) order by sno desc),LastUserAssigned)              
				   Where IsActive=1 and UserID=@ParentId              
              
				  create table #outputLead(leadid bigint,LeadNo bigint, FollowUpStatus int, NextStatusDate nvarchar(50), 
				  ProductsJson varchar(1000), AmountPaid numeric(18,2), Remarks nvarchar(1000), AssignedTo bigint, ParentID bigint, CreatedOn datetime
				  , CreatedBy bigint, followupdate datetime)  
				  create table #outputLeadInteraction(id bigint,leadno bigint)  

				  SELECT @LastLeadId=IDENT_CURRENT('UserLeads')
				  SET Context_Info 0x55555
                  declare @le_cnt int=(select count(1) from #tmpuserleads),@r_id int=0
				  If exists(select * from #tmpUserLeads)        
				  Begin        
 					  SELECT @LastLeadId=IDENT_CURRENT('UserLeads')              
                  while @le_cnt>0
				  begin
					  INSERT INTO [dbo].[UserLeads]              
					  ([LeadNo],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo]        
					  ,[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks],[ProductsJson],[AmountPaid],[CreatedOn],[CreatedBy],[FollowupDate],[enquirysource],[WhatsAppNoColName],LastFollowupCreatedBy,LastFollowupCreatedOn)
					  output inserted.ID as leadid,inserted.LeadNo as leadno, inserted.FollowUpStatus FollowUpStatus, inserted.NextStatusDate NextStatusDate, 
					  inserted.[ProductsJson] [ProductsJson], inserted.AmountPaid AmountPaid, inserted.Remarks Remarks, inserted.AssignedTo AssignedTo, inserted.ParentID ParentID,
					  inserted.CreatedOn CreatedOn, inserted.CreatedBy CreatedBy, inserted.followupdate followupdate into #outputLead
					  Select              
					  @NextLeadNo+LeadNo, [PersonName], [CompanyName], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], [City],[State], [Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo]
					  ,[SourceName],[MediumName],[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],case when [NextStatusDate]='' then '' else FORMAT(cast(NextStatusDate as Datetime),'dd-MMM-yyyy hh:mm:ss tt') end, [Remarks],[Products],[AmountPaid],[CreatedOn], [CreatedBy],[FollowupDate] , 21 as [enquirysource], WhatsAppNoColName,[CreatedBy],getdate()        
					  From    #tmpUserLeads t where t.sno between @r_id and @r_id+500            
              
					  Select @nLeadInserted+=@@ROWCOUNT       
                  
					  print cast(@nLeadInserted as varchar) + ' Leads inserted' +'-----------'+cast(getdate() as nvarchar)+'-------'
					  set @le_cnt=@le_cnt-500
					  set @r_id=@r_id+500
					  end
					  select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),leadid),',') From #outputLead

					  Exec usp_ExecLeadTriggerTasks @CsvID
                     
					 select @le_cnt=count(1) from #outputlead

					 while @le_cnt>0
					 begin
					  insert into leadinteractionhistory(LeadNo,FollowUpStatus,NextStatusDate,[ProductsJson],AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,followupdate,IsAutoEntry)            
					  output inserted.ID as ID,inserted.leadno as leadno into #outputLeadInteraction
					  select top 500 LeadNo, FollowUpStatus, NextStatusDate, [ProductsJson], AmountPaid, Remarks, AssignedTo, ParentID, CreatedOn, CreatedBy, followupdate, 1 as IsAutoEntry
					  from #outputlead(nolock) o where 
					  not exists (select 1 from #outputLeadInteraction where leadno=o.leadno)
                      Select @nLeadInserted+=@@ROWCOUNT       
                  
					  print cast(@nLeadInserted as varchar) + ' Lead interactions inserted' +'-----------'+cast(getdate() as nvarchar)+'-------'
					set @le_cnt=@le_cnt-500

					  end
					  select @CsvID=STRING_AGG(CONVERT(NVARCHAR(max),ID),',') From #outputLeadInteraction

					  declare @multi_lih as Multiactivity_lih

					  insert into @multi_lih(leadno,parentid)
					  select leadno,parentid from #outputLead
					  
					  Exec usp_ExecLeadInteractionTriggerTasks_multi @multi_lih
             
					  set @jRow = 1              
					  while(@jRow <= @CustomFieldsCnt)              
					  begin              
						   select @fieldId=t.fieldId,@fieldName=t.fieldName,@fieldtype=c.datatype       
						   from #tblCustomFields t join customfields c (nolock) on c.field_ID=t.fieldId and c.ParentID=@ParentId       
						   Where t.RowId=@jRow              
              
						   set @SQLString = 'insert into customfieldLeadvalue(LeadID,EnquiryID,fieldID,fieldvalue,CreatedDate)       
						   select distinct A.ID, 0, ' + cast(@fieldId as varchar) + ', case when '''+ cast(@fieldtype as nvarchar) +'''=''d'' and IsDate(C.[' + @fieldName + ']) =      
							1 then Format(cast(C.[' + @fieldName + '] as datetime),''dd-MMM-yyyy hh:mm:ss tt'') else C.[' + @fieldName + '] end, getdate()  
						   From [UserLeads] A(nolock) inner join #tmpUserLeads B              
						   ON   A.LeadNo = B.LeadNo+' + cast(@NextLeadNo as varchar) + ' inner join #tmpLeadSrc C
						   On  B.Sno = C.Sno              
						   Where A.[ParentID] = ' + cast(@ParentId as varchar) + ' and A.LeadNo <= ' + cast(@NextLeadNo as varchar) + '+' + cast(@nLeadInserted as varchar)              
                  
						   print 'custom field Lead @SQLString: ' + @SQLString + ' and isnull(C.[' + @fieldName + '],'''') != '''' '              
              
						   exec (@SQLString)              
						   select @nLeadCustomFieldRows+=@@ROWCOUNT              
              
						   set @jRow = @jRow + 1              
					  end         
          
					  SET DATEFORMAT dmy;          
					  UPDATE cflv set cflv.fieldvalue=case when isnull(cflv.fieldvalue,'') != '' then FORMAT(cast(cflv.fieldvalue as Datetime),'dd-MMM-yyyy hh:mm:ss tt') else cflv.fieldvalue end            
					  --select *            
					  FROM userleads ul inner join customfieldleadvalue cflv            
					  ON ul.id=cflv.leadid inner join customfields cf            
					  ON cflv.fieldid=cf.field_id            
					  WHERE ul.parentid=@ParentId and ul.createdon=@CreatedOn and cf.datatype='d'            
        
					  Set @RowData = isnull((Select  SNo=ROW_NUMBER()Over(order by B.ID), B.PersonName, CountryCode=Case B.WhatsAppNoColName When 'MobileNo' then B.CountryCode       
					  when 'MobileNo1' then B.CountryCode1 when 'MobileNo2' then B.CountryCode2 Else '' End, MobileNo=Case B.WhatsAppNoColName When 'MobileNo' then B.MobileNo       
					  when 'MobileNo1' then B.MobileNo1 when 'MobileNo2' then B.MobileNo2 Else '' End        
					  From #tmpUserLeads A inner join [UserLeads] B (nolock)        
					  ON   A.LeadNo + @NextLeadNo = B.LeadNo        
					  Where B.[ParentID] = @ParentId and B.WhatsAppNoColName in ('MobileNo','MobileNo1','MobileNo2')        
					   for json auto, INCLUDE_NULL_VALUES),'')        
        
					  If(len(@RowData)>1)        
					  Begin        
						   /*INSERT INTO [MySMSConversations].[dbo].[tbl_imp_ImportRequest]        
							  ([FileName],[FileSizeByte],[CreatedOn],[Status],[NoOfRecord],[IsProcessed]        
							  ,[ImportJSON],[SourceName],[CreatedBy],[ParentId])        
							 VALUES        
							  ('FromLead.xls',LEN(@RowData),Getdate(),'pending',0,0        
							  ,@RowData,0,@User_Id,@ParentId)        
        
						   Select @ImportRequestId=SCOPE_IDENTITY() */      
						   
						    SET @sqlquery = '
            INSERT INTO [tbl_imp_ImportRequest]    
                ([FileName], [FileSizeByte], [CreatedOn], [Status], [NoOfRecord], [IsProcessed],    
                 [ImportJSON], [SourceName], [CreatedBy], [ParentId])    
            VALUES    
                (''FromLead.xls'', ' + CAST(LEN(@RowData) AS NVARCHAR) + ', GETDATE(), ''pending'', 0, 0,    
                ''' + REPLACE(@RowData, '''', '''''') + ''', 0, ' + CAST(@User_Id AS NVARCHAR) + ', ' + CAST(@ParentId AS NVARCHAR) + ');
            ';
            
            -- Get the inserted ID back
            EXEC usp_clr_InsertAndReturnId @sqlquery, @retid = @ImportRequestId OUTPUT;
						   select @RecCnt=count(*) from openjson(@RowData)            
        
						   While(1=1)        
						   Begin        
							set @Start=@End+1        
							set @End=@Pagesize*@Pageno        
        
							Set @RowData = isnull((Select * from (Select  SNo=ROW_NUMBER()Over(order by B.ID), B.PersonName, CountryCode=Case B.WhatsAppNoColName When 'MobileNo' then B.CountryCode when 'MobileNo1' then B.CountryCode1 when 'MobileNo2' then B.CountryCode2 Else '' End, MobileNo=Case B.WhatsAppNoColName When 'MobileNo' then B.MobileNo when 'MobileNo1' then B.MobileNo1 when 'MobileNo2' then B.MobileNo2 Else '' End        
							From #tmpUserLeads A inner join [UserLeads] B (nolock)        
							ON   A.LeadNo + @NextLeadNo = B.LeadNo        
							Where B.[ParentID] = @ParentId and B.WhatsAppNoColName in ('MobileNo','MobileNo1','MobileNo2')) T        
							Where T.SNo between @Start and @End        
							 for json auto, INCLUDE_NULL_VALUES),'')        
        
							/* INSERT INTO [MySMSConversations].[dbo].[tbl_ims_ImportSlot]        
							   ([requestid],[createdon],[contactjson],[isprocessed])        
							  VALUES        
							   (@ImportRequestId,Getdate(),@RowData,0)  */     
							   
							    SET @sqlquery = '
                             INSERT INTO [tbl_ims_ImportSlot]    
                                 ([requestid], [createdon], [contactjson], [isprocessed])    
                             VALUES    
                                 (' + CAST(@ImportRequestId AS NVARCHAR) + ', GETDATE(), ''' + REPLACE(@RowData, '''', '''''') + ''', 0);
                             ';
                             
                             -- Execute remotely
                             EXEC usp_clr_ExecuteRemoteQuery @sqlquery;
        
							If(@RecCnt < (@Pageno*@Pagesize))        
							Begin        
							 break        
							End        
							Else        
							Begin        
							 Set @Pageno=@Pageno+1        
							End        
						   End        
        
						   Set @RowData = null        
					  End        
        
				   End        
         
				  Set @RowData = isnull((Select Sno, Remarks From #tmpConstraintChk order by Sno for json auto, INCLUDE_NULL_VALUES),'')              
         
				  print 'Final @RowData: ' + cast(@RowData as varchar(max))        
            
				  update tbl_LeadImportSummary               
				   set IsProcessed=1,importend=getdate(), Remarks=@RowData, LeadCnt=@nLeadInserted, LeadCustomFieldCnt=@nLeadCustomFieldRows               
				   where ImportRow_Id=@ImportRow_id     
     
				  select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@tic as nvarchar) +' leads for importing.   
				   The request is processed and leads imported are '+cast( @nLeadInserted as nvarchar)   
				  exec UspSaveEntityActivity_withid 'user',@user_id,@user_id,@ParentID,@EventDescription,@EventName,'tbl_LeadImportSummary',@ImportRow_id  
				  exec Usp_InsertUserEventDetails 'Lead Import successful',@parentid,@eventdescription, 'tbl_LeadImportSummary',@ImportRow_id
           
				  Iter:          
					Set @iRow = @iRow + 1
					Set @ImportRow_id=0
					Set @ImportData=null
					Set @RowData=null
					Set @FieldNames=''
					Set @SQLString=null
					Set @User_Id=0
					Set @LastLeadId=0
					Set @nLeadInserted=0
					Set @nLeadCustomFieldRows=0
					Set @jRow=1
					Set @fieldId=0
					Set @fieldName=''
					Set @CustomFieldsCnt = 0
					Set @ImportRequestId = 0
					Set @RecCnt = 0
					Set @Start = 0
					Set @End = 0
					Set @Pagesize = 500
					Set @Pageno = 1
              
				   truncate table #tmpConstraintChk              
				   truncate table #tmpUserLeads              
				   truncate table #tmpMobileNoList              
				   truncate table #tmpEmailIdList              
				   truncate table #tblCustomFields              
              
				   if object_id('tempdb..#tmpLeadSrc') is not null begin drop table #tmpLeadSrc end                            
				   if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end
				   if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end
				   if object_id('tempdb..#tmpTblPrdct2') is not null begin drop table #tmpTblPrdct2 end
			End              
              
		COMMIT TRANSACTION     
		SET Context_Info 0x
		
	END TRY                  
	BEGIN CATCH                 
		While @@TRANCOUNT > 0
			ROLLBACK TRANSACTION
                
		SET Context_Info 0x
	
		insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)        
		SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()  
   
		select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@tic as nvarchar) +' leads for importing.   
	   The request failed. Pl check Import summary for details'   
		exec UspSaveEntityActivity_withid 'user',@user_id,@user_id,@ParentID,@EventDescription,@EventName,'tbl_LeadImportSummary',@ImportRow_id
		exec Usp_InsertUserEventDetails 'Lead Import failed',@parentid,@eventdescription, 'tbl_LeadImportSummary',@ImportRow_id
        
	END CATCH                  
              
	if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end              
	if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end              
	if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end              
	if object_id('tempdb..#tblAllLeadFields') is not null begin drop table #tblAllLeadFields end              
	if object_id('tempdb..#tmpLeadSrc') is not null begin drop table #tmpLeadSrc end              
	if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end              
	if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end              
	if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end              
	if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end
	if object_id('tempdb..#outputMergeLeadEnquiry') is not null begin drop table #outputMergeLeadEnquiry end
              
END 



GO

/* ============================================================
   Procedure: [dbo].[usp_ProcessLeadImportDataspecific]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_ProcessLeadImportData 0, 'P'      
-- Exec usp_ProcessLeadImportData 1, 'P'      
CREATE   PROC usp_ProcessLeadImportDataspecific        
(       
	@rrid bigint,   
    @BatchSize int=1,  -- 0 ('All')        
    @Mode varchar(1)='P' -- 'P'riority, 'F'ifo        
)        
AS        
BEGIN        
        
-- declare @BatchSize int=1,@Mode varchar(1)='P'      
if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end        
if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end        
if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end        
if object_id('tempdb..#tblAllLeadFields') is not null begin drop table #tblAllLeadFields end        
if object_id('tempdb..#tmpLeadSrc') is not null begin drop table #tmpLeadSrc end        
if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end        
if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end        
if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end        
        
Create table #tblImportRowId        
(        
    RowId int identity,        
    ImportRow_id bigint,        
    [User_Id] bigint        
)        
        
create table #tmpConstraintChk        
(        
    Sno int,        
    Remarks varchar(200)        
)        
        
create table #tblCustomFields        
(        
    RowId int identity(1,1),        
    fieldId bigint,        
    fieldName varchar(50)        
)        
        
create table #tblAllLeadFields        
(        
    RowId int identity(1,1),        
    fieldName varchar(50),    
    FieldType varchar(10)    
)        
        
create table #tmpMobileNoList        
(        
    RowId int identity,        
    MobileNo varchar(100)        
)        
        
create table #tmpEmailIdList        
(        
    RowId int identity,        
    EmailId varchar(100)        
)        
        
CREATE TABLE #tmpUserLeads (        
 [LeadNo] [bigint] IDENTITY(1,1) NOT NULL,        
 [Sno] [int] NOT NULL,        
 [PersonName] [varchar](100) NULL,        
 [CompanyName] [varchar](100) NULL,        
 [MobileNo] [varchar](100) NULL,        
 [MobileNo1] [varchar](100) NULL,        
 [MobileNo2] [varchar](100) NULL,        
 [EmailID] [varchar](100) NULL,        
 [EmailID1] [varchar](100) NULL,        
 [EmailID2] [varchar](100) NULL,        
 [City] [varchar](100) NULL,        
 [State] [varchar](100) NULL,        
 [Country] [varchar](100) NULL,        
 [CountryCode] [varchar](50) NULL,        
 [CountryCode1] [varchar](50) NULL,        
 [CountryCode2] [varchar](50) NULL,        
 [PinCode] [bigint] NULL,        
 [ResidentialAddress] [varchar](500) NULL,        
 [OfficeAddress] [varchar](500) NULL,        
 [AssignedTo] [bigint] NOT NULL,        
 [SourceName] [bigint] DEFAULT ((0)) NOT NULL,        
 [MediumName] [bigint] DEFAULT ((0)) NULL,        
 [CampaignName] [bigint] DEFAULT ((0)) NULL,        
 [InitialRemarks] [varchar](1000) NULL,        
 [ParentID] [bigint] NOT NULL,        
 [FollowUpStatus] [int] NULL,        
 [NextStatusDate] [varchar](50) NULL,        
 [Remarks] [varchar](1000) NULL,        
 [Products] [varchar](1000) NULL,        
 [AmountPaid] [numeric](18, 2) NOT NULL DEFAULT ((0)),        
 [CreatedOn] [datetime] NULL,        
 [CreatedBy] [bigint] NULL,        
 [FollowupDate] [datetime] NULL        
)        
        
BEGIN TRY            
    BEGIN TRANSACTION    
 insert into #tblImportRowId          
   Select ImportRow_id,[User_Id] From tbl_LeadImportSummary(nolock) where IsProcessed=0 and ImportRow_Id=@rrid          
   /*      
    If(@Mode = 'P')        
    Begin        
  If(@BatchSize != 0)        
  Begin        
   insert into #tblImportRowId        
   Select top (@BatchSize) ImportRow_id,[User_Id] From tbl_LeadImportSummary where IsProcessed=0 order by [Priority]        
  End        
  Else        
  Begin        
   insert into #tblImportRowId        
   Select ImportRow_id,[User_Id] From tbl_LeadImportSummary where IsProcessed=0 order by [Priority]        
  End        
    End        
    Else -- Fifo        
    Begin        
  If(@BatchSize != 0)        
  Begin        
   insert into #tblImportRowId        
   Select top (@BatchSize) ImportRow_id,[User_Id] From tbl_LeadImportSummary where IsProcessed=0        
  End        
  Else        
  Begin        
   insert into #tblImportRowId        
   Select ImportRow_id,[User_Id] From tbl_LeadImportSummary where IsProcessed=0        
  End        
    End        
    select * from #tblImportRowId        
*/        
    declare @iRow int=1, @jRow int=1, @ImportRow_id bigint=0, @UnProcessedRowCnt int=0, @User_Id bigint=0, @LastLeadId bigint=0, @nLeadInserted bigint=0, @fieldId bigint=0, @nLeadCustomFieldRows bigint=0        
    declare @ImportData nvarchar(max), @RowData nvarchar(max), @FieldNames nvarchar(max)='', @SQLString nvarchar(max)='', @ParmDefinition nvarchar(500), @fieldName varchar(50)='';          
    declare @NextLeadNo bigint=0, @CustomFieldsCnt int=0, @ParentId bigint=0, @CreatedOn datetime       
        
    select @UnProcessedRowCnt=Count(*) from #tblImportRowId        
        
    While(@iRow <= @UnProcessedRowCnt)        
    Begin        
  print '@iRow: ' + cast(@iRow as varchar)        
  Select @ImportRow_id=ImportRow_id,@User_Id=[User_Id] From #tblImportRowId Where RowId=@iRow        
  print '@ImportRow_id: ' + cast(@ImportRow_id as varchar)        
  Select @ImportData=ImportData from tbl_LeadImportSummary where ImportRow_Id=@ImportRow_id        
  print '@ImportData: ' + @ImportData        
  select top 1 @RowData=value from openjson(@ImportData)        
  print '@RowData: ' + @RowData        
  select @FieldNames=@FieldNames+'['+[Key]+'] varchar(1000),' from openjson(@RowData)        
  print '@FieldNames1: ' + @FieldNames        
  set @FieldNames= SUBSTRING(@FieldNames,1,len(@FieldNames)-1)        
  print '@FieldNames2: ' + @FieldNames        
      
  Select @ParentId=dbo.ufn_GetUserParentId(@User_Id)      
    
  insert into #tblAllLeadFields    
  values ('Sno','Main'),('PersonName','Main'),('CompanyName','Main'),('MobileNo','Main'),('MobileNo1','Main'),('MobileNo2','Main'),('EmailID','Main'),('EmailID1','Main'),('EmailID2','Main'),('City','Main'),('State','Main'),('Country','Main'),('CountryCode','Main'),('CountryCode1','Main'),('CountryCode2','Main'),('PinCode','Main'),('ResidentialAddress','Main'),('OfficeAddress','Main'),('AssignedTo','Main'),('SourceName','Main'),('MediumName','Main'),('CampaignName','Main'),('InitialRemarks','Main'),('FollowupStatus','Main'),('NextStatusDate','Main'),('Remarks','Main'),('Products','Main'),('AmountPaid','Main'),('FollowupDate','Main')--,('ProfileImgFileName','Main')    
    
  insert into #tblAllLeadFields    
  select fieldname,'Custom'    
  from customfields         
  where parentId=@ParentId and isActive=1    
    
  if exists(select [Key] from openjson(@RowData) where [Key] COLLATE SQL_Latin1_General_CP1_CI_AS not in (Select FieldName From #tblAllLeadFields))    
  Begin    
 print 'Invalid Field found in Import Data'    
 Update tbl_LeadImportSummary Set IsProcessed=1,Remarks='[{"Sno":0,"Remarks":"Invalid Field found in Import Data"}]' Where ImportRow_Id = @ImportRow_id    
 goto Iter    
  End    
  Else    
  Begin    
 If exists(Select FieldName From #tblAllLeadFields Where FieldName COLLATE SQL_Latin1_General_CP1_CI_AS not in (select [Key] from openjson(@RowData)))    
 Begin    
  print 'Required Field Missing in Import Data'    
  Update tbl_LeadImportSummary Set IsProcessed=1,Remarks='[{"Sno":0,"Remarks":"Required Field Missing in Import Data"}]' Where ImportRow_Id = @ImportRow_id    
  goto Iter    
 End    
  End    
    
  create table #tmpLeadSrc (id int identity);        
  print 'alter table #tmpLeadSrc add ' + @FieldNames        
  exec('alter table #tmpLeadSrc add ' + @FieldNames)        
        
  Set @SQLString = N'insert into #tmpLeadSrc select * from openjson(@ImptData) with (' + @FieldNames + ')'         
        
  --SET @ParmDefinition = N'@ImptData nvarchar(max), @FldNames nvarchar(max)';          
  SET @ParmDefinition = N'@ImptData nvarchar(max)';          
          
  print @SQLString        
        
    --EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData, @FldNames=@FieldNames          
  EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData          
      
  --select * from openjson(@RowData)        
    
  update #tmpLeadSrc         
  set MobileNo=rtrim(ltrim(case when isnull(MobileNo,'')='' and isnull(MobileNo1,'')!='' then MobileNo1 else Isnull(MobileNo,'') end)),        
  MobileNo1=rtrim(ltrim(case when isnull(MobileNo1,'')='' and isnull(MobileNo2,'')!='' then MobileNo2 else Isnull(MobileNo1,'') end)),        
  MobileNo2=rtrim(ltrim(isnull(MobileNo2,''))),        
  CountryCode=rtrim(ltrim(case when isnull(CountryCode,'')='' and isnull(CountryCode1,'')!='' then iif(left(ltrim(CountryCode1),1) != '+','+'+ltrim(CountryCode1),CountryCode1) else iif(left(ltrim(Isnull(CountryCode,'')),1) != '+'   
  and ltrim(Isnull(CountryCode,'')) != '', '+' + ltrim(Isnull(CountryCode,'')),Isnull(CountryCode,'')) end)),        
  CountryCode1=rtrim(ltrim(case when isnull(CountryCode1,'')='' and isnull(CountryCode2,'')!='' then iif(left(ltrim(CountryCode2),1) != '+','+'+ltrim(CountryCode2),CountryCode2) else iif(left(ltrim(Isnull(CountryCode1,'')),1) != '+'   
  and ltrim(Isnull(CountryCode1,'')) != '', '+' + ltrim(Isnull(CountryCode1,'')),Isnull(CountryCode1,'')) end)),        
  CountryCode2=rtrim(ltrim(iif(left(ltrim(isnull(CountryCode2,'')),1) != '+' and ltrim(isnull(CountryCode2,'')) != '','+' + ltrim(isnull(CountryCode2,'')),Isnull(CountryCode2,'')))),        
  EmailID=rtrim(ltrim(case when isnull(EmailID,'')='' and isnull(EmailID1,'')!='' then EmailID1 else Isnull(EmailID,'') end)),        
  EmailID1=rtrim(ltrim(case when isnull(EmailID1,'')='' and isnull(EmailID2,'')!='' then EmailID2 else Isnull(EmailID1,'') end)),        
  EmailID2=rtrim(ltrim(isnull(EmailID2,''))),        
  PersonName=rtrim(ltrim(isnull(PersonName,''))),        
  InitialRemarks=rtrim(ltrim(isnull(InitialRemarks,''))),        
  AssignedTo=rtrim(ltrim(isnull(AssignedTo,''))),        
  SourceName=rtrim(ltrim(isnull(SourceName,''))),        
  MediumName=rtrim(ltrim(isnull(MediumName,''))),        
  CampaignName=rtrim(ltrim(isnull(CampaignName,''))),        
  FollowupStatus=rtrim(ltrim(isnull(FollowupStatus,''))),        
  NextStatusDate=rtrim(ltrim(isnull(NextStatusDate,''))),        
  Remarks=rtrim(ltrim(isnull(Remarks,''))),        
  Products=rtrim(ltrim(isnull(Products,''))),        
  AmountPaid=rtrim(ltrim(isnull(AmountPaid,'0'))),        
  FollowupDate=rtrim(ltrim(isnull(FollowupDate,'0'))),        
  Sno=rtrim(ltrim(isnull(Sno,0)))        
        
  --EXEC('select * from #tmpLeadSrc')        
        
  insert into #tmpConstraintChk        
  Select  Sno, 'Duplicate Records' as Remarks        
  From        
  (        
  select ROW_NUMBER()over(partition by PersonName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, InitialRemarks order by cast(Sno as int)) as Rid, *        
  from #tmpLeadSrc        
  ) B        
  Where B.Rid > 1        
                          
      
  insert into #tblCustomFields        
  select field_ID, fieldname         
  from customfields         
  where parentId=@ParentId and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select FieldName from #tblAllLeadFields where [FieldType] = 'Custom')        
  /*where parentId=@ParentId and isActive=1 and fieldname  COLLATE SQL_Latin1_General_CP1_CI_AS in (select [Key]        
  from openjson(@RowData) where [Key] not in ('Sno', 'PersonName', 'CompanyName', 'MobileNo', 'MobileNo1', 'MobileNo2', 'EmailID', 'EmailID1', 'EmailID2', 'City', 'State', 'Country', 'CountryCode', 'CountryCode1', 'CountryCode2', 'PinCode', 'ResidentialAd
  
dress', 'OfficeAddress', 'AssignedTo', 'SourceName', 'MediumName', 'CampaignName', 'InitialRemarks', 'FollowupStatus', 'NextStatusDate', 'Remarks', 'Products', 'AmountPaid', 'FollowupDate', 'ProfileImgFileName')) */       
        
  Select @CustomFieldsCnt=count(*) From #tblCustomFields        
        
  insert into #tmpConstraintChk        
  Select  Sno, 'Sno missing' as Remarks        
  From    #tmpLeadSrc        
  Where   ISNULL(ltrim(Sno),'') = '' or ISNULL(ltrim(Sno),'0') = '0'        
  union        
  Select  Sno, 'Sno Duplicate' as Remarks        
  From    #tmpLeadSrc        
  group by Sno        
  having  Count(*) > 1        
  union        
  Select  Sno, 'PersonName missing' as Remarks        
  From    #tmpLeadSrc        
  Where   ISNULL(ltrim(PersonName),'') = ''        
  union        
  Select  Sno, 'Contact details missing' as Remarks        
  From    #tmpLeadSrc        
  Where   ISNULL(ltrim(MobileNo),'') = '' and ISNULL(ltrim(MobileNo1),'') = '' and ISNULL(ltrim(MobileNo2),'') = '' and         
  ISNULL(ltrim(EmailID),'') = '' and ISNULL(ltrim(EmailID1),'') = '' and ISNULL(ltrim(EmailID2),'') = ''        
  union        
  Select  Sno, 'MobileNo or CountryCode missing' as Remarks        
  From    #tmpLeadSrc        
  Where   ((ISNULL(ltrim(MobileNo),'')!='' and ISNULL(ltrim(CountryCode),'')='') or (ISNULL(ltrim(MobileNo),'')='' and ISNULL(ltrim(CountryCode),'')!=''))        
     or        
  ((ISNULL(ltrim(MobileNo1),'')!='' and ISNULL(ltrim(CountryCode1),'')='') or (ISNULL(ltrim(MobileNo1),'')='' and ISNULL(ltrim(CountryCode1),'')!='')) or        
  ((ISNULL(ltrim(MobileNo2),'')!='' and ISNULL(ltrim(CountryCode2),'')='') or (ISNULL(ltrim(MobileNo2),'')='' and ISNULL(ltrim(CountryCode2),'')!=''))        
  union        
  Select  Sno, 'AssignedTo missing' as Remarks        
  From    #tmpLeadSrc        
  Where   ISNULL(ltrim(AssignedTo),'') = ''        
  union        
  Select  Sno, 'AssignedTo Invalid' as Remarks        
  From    #tmpLeadSrc        
  Where   ISNULL(ltrim(AssignedTo),'') not in (Select [User_Login] from User_Detail Where Status=1)        
  union        
  Select  Sno, 'SourceName missing' as Remarks        
  From    #tmpLeadSrc        
  Where   ISNULL(ltrim(SourceName),'') = ''        
  union        
  Select  Sno, 'FollowupStatus missing' as Remarks        
  From    #tmpLeadSrc        
  Where   ISNULL(ltrim(FollowupStatus),'') = ''        
  union        
  Select  Sno, 'FollowupStatus missing' as Remarks        
  From    #tmpLeadSrc        
  Where   ISNULL(ltrim(FollowupStatus),'') not in (Select FollowupStatus from FollowUp_Status Where IsActive=1)        
  union        
  Select  Sno, 'FollowupDate missing' as Remarks        
  From    #tmpLeadSrc        
  Where   ISNULL(ltrim(FollowupDate),'') = ''        
  union        
  Select  Sno, 'Invalid FollowupDate' as Remarks        
  From    #tmpLeadSrc        
  Where   ISNULL(ltrim(FollowupDate),'') != '' and ISDATE(FollowupDate) != 1        
  union        
  Select  Sno, 'Invalid NextStatusDate' as Remarks        
  From    #tmpLeadSrc        
  Where   ISNULL(ltrim(NextStatusDate),'') != '' and ISDATE(NextStatusDate) != 1        
  union        
  Select  Sno, 'Invalid Products' as Remarks        
  From    #tmpLeadSrc        
  Where   ISNULL(ltrim(Products),'') != '' and Products not like '%#%' and Products not in (select [Name] from ProductMaster Where IsActive=1 and UserID=@ParentId)        
  union        
  Select  Sno, 'Invalid Products' as Remarks        
  From    #tmpLeadSrc        
  Where   Products like '%#%' and dbo.ufn_GetProductId(Products,@ParentId,'#')=''        
  union        
  Select  Sno, 'PersonName Length exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(PersonName)>100        
  union        
  Select  Sno, 'CompanyName exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(CompanyName)>100        
  union        
  Select  Sno, 'MobileNo exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(MobileNo)>100        
  union        
  Select  Sno, 'MobileNo1 exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(MobileNo1)>100        
  union        
  Select  Sno, 'MobileNo2 exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(MobileNo2)>100        
  union        
  Select  Sno, 'EmailID exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(EmailID)>100        
  union        
  Select  Sno, 'EmailID1 exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(EmailID1)>100        
  union        
  Select  Sno, 'City exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(City)>100        
  union        
  Select  Sno, 'State exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(State)>100        
  union        
  Select Sno, 'Country exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(Country)>100        
  union        
  Select  Sno, 'CountryCode exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(CountryCode)>100        
  union        
  Select  Sno, 'CountryCode1 exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(CountryCode1)>100        
  union        
  Select  Sno, 'CountryCode2 exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(CountryCode2)>100        
  union        
  Select  Sno, 'ResidentialAddress exceeds specified limit(500)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(ResidentialAddress)>500        
  union        
  Select  Sno, 'OfficeAddress exceeds specified limit(500)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(OfficeAddress)>500        
  union        
  Select  Sno, 'SourceName exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(SourceName)>100        
  union        
  Select  Sno, 'MediumName exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(MediumName)>100        
  union        
  Select  Sno, 'CampaignName exceeds specified limit(100)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(CampaignName)>100        
  union        
  Select  Sno, 'InitialRemarks exceeds specified limit(1000)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(InitialRemarks)>1000        
  union        
  Select  Sno, 'Remarks exceeds specified limit(1000)' as Remarks        
  From    #tmpLeadSrc        
  Where   len(Remarks)>1000        
  /*        
  union        
  Select  Sno, 'Invalid DateOfBirth' as Remarks        
  From    #tmpLeadSrc        
  Where   isnull(ltrim(DateOfBirth),'') != '' and ISDate(DateOfBirth) = 0        
  */        
        
  insert into #tmpMobileNoList        
  select MobileNo        
  From UserLeads        
  Where ParentID in (@ParentId) and isnull(ltrim(MobileNo),'') != ''        
  union        
  select MobileNo1        
  From UserLeads        
  Where ParentID in (@ParentId) and isnull(ltrim(MobileNo1),'') != ''        
  union        
  select MobileNo2        
  From UserLeads        
  Where ParentID in (@ParentId) and isnull(ltrim(MobileNo2),'') != ''        
        
  insert into #tmpEmailIdList        
  select EmailID        
  From UserLeads        
  Where ParentID in (@ParentId) and isnull(ltrim(EmailID),'') != ''    
  union        
  select EmailID1        
  From UserLeads        
  Where ParentID in (@ParentId) and isnull(ltrim(EmailID1),'') != ''        
  union        
  select EmailID2        
  From UserLeads        
  Where ParentID in (@ParentId) and isnull(ltrim(EmailID2),'') != ''        
        
  insert into #tmpConstraintChk        
  Select  distinct Sno, 'MobileNo already present in Leads' as Remarks        
  From        
  (        
  Select  Sno, MobileNo        
  From  #tmpLeadSrc        
  Where   ISNULL(ltrim(MobileNo),'') != ''        
  union        
  Select  Sno, MobileNo1       
  From  #tmpLeadSrc        
  Where   ISNULL(ltrim(MobileNo1),'') != ''        
  union        
  Select  Sno, MobileNo2        
  From  #tmpLeadSrc        
  Where   ISNULL(ltrim(MobileNo2),'') != ''        
  ) A        
  Where A.MobileNo in (Select MobileNo From #tmpMobileNoList)        
        
  insert into #tmpConstraintChk        
  Select  distinct Sno, 'EmailID already present in Leads' as Remarks        
  From        
  (        
  Select  Sno, EmailID        
  From  #tmpLeadSrc        
  Where   ISNULL(ltrim(EmailID),'') != ''        
  union        
  Select  Sno, EmailID1        
  From  #tmpLeadSrc        
  Where   ISNULL(ltrim(EmailID1),'') != ''        
  union        
  Select  Sno, EmailID2        
  From  #tmpLeadSrc        
  Where   ISNULL(ltrim(EmailID2),'') != ''        
  ) A        
  Where A.EmailID in (Select EmailID From #tmpEmailIdList)        
        
  select count(*) as ConstraintChkCnt1 from #tmpConstraintChk        
        
  INSERT INTO UserSourceSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)          
  Select distinct SourceName, @ParentId, 1,  1, GETDATE(), GETDATE(), @User_Id          
  From  #tmpLeadSrc         
  Where   SourceName not in (Select [Name] from UserSourceSettings Where IsActive=1 and Userid=@ParentId) and Sno not in (Select distinct Sno from #tmpConstraintChk)        
        
  INSERT INTO UserMediumSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)          
  Select distinct MediumName, @ParentId, 1,  1, GETDATE(), GETDATE(), @User_Id          
  From  #tmpLeadSrc         
  Where   MediumName not in (Select [Name] from UserMediumSettings Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(MediumName),'') != '' and Sno not in (Select distinct Sno from #tmpConstraintChk)        
        
  INSERT INTO UserCampaignSettings ([Name], UserID, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)          
  Select distinct CampaignName, @ParentId, 1,  1, GETDATE(), GETDATE(), @User_Id          
  From  #tmpLeadSrc         
  Where   CampaignName not in (Select [Name] from UserCampaignSettings Where IsActive=1 and Userid=@ParentId) and isnull(ltrim(CampaignName),'') != ''and Sno not in (Select distinct Sno from #tmpConstraintChk)        
        
  Update #tmpLeadSrc         
  Set SourceName=(Select top 1 SourceId From UserSourceSettings Where IsActive=1 and UserID=@ParentId and [Name]=SourceName),        
  MediumName=(Select top 1 MediumID From UserMediumSettings Where IsActive=1 and UserID=@ParentId and [Name]=MediumName),        
  CampaignName=(Select top 1 CampaignID From UserCampaignSettings Where IsActive=1 and UserID=@ParentId and [Name]=CampaignName),        
  AssignedTo=(Select top 1 [User_ID] From User_Detail Where [Status]=1 and [User_Login]=AssignedTo),        
  FollowUpStatus=(Select top 1 ID From FollowUp_Status Where IsActive=1 and FollowUp_Status.FollowupStatus=#tmpLeadSrc.FollowUpStatus),        
  Products=case when Products!= '' then dbo.ufn_GetProductId(Products,@ParentId,'#') else Products end        
  Where Sno not in (Select distinct Sno from #tmpConstraintChk)        
        
  Select @CreatedOn=dbo.[fn_getusertimefromindiantime](@User_Id,getdate())      
        
  INSERT INTO #tmpUserLeads        
  ([Sno], [PersonName], [CompanyName], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], [City], [State],        
  [Country], [CountryCode], [CountryCode1], [CountryCode2], [PinCode], [ResidentialAddress], [OfficeAddress],         
  [AssignedTo], [SourceName], [MediumName], [CampaignName], [InitialRemarks], [ParentID], [FollowUpStatus], [NextStatusDate],         
  [Remarks], [Products], [AmountPaid], [CreatedOn],         
  [CreatedBy], [FollowupDate])        
  Select  Sno, PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,EmailID2,City,[State],        
  Country ,CountryCode,CountryCode1,CountryCode2,case when ISNUMERIC(PinCode) != 1 then 0 else PinCode end,ResidentialAddress,OfficeAddress,        
  AssignedTo,SourceName, MediumName ,CampaignName,InitialRemarks,@ParentId as ParentID, FollowUpStatus, NextStatusDate,         
  Remarks, Products, iif(isnull(AmountPaid,'') = '', '0', AmountPaid), @CreatedOn as CreatedOn,         
  @User_Id as CreatedBy, FollowupDate        
  From #tmpLeadSrc        
  Where Sno not in (Select distinct Sno from #tmpConstraintChk)        
        
  Select @NextLeadNo=Isnull(max(LeadNo),0) From UserLeads Where ParentID=@ParentId         
        
  Update CRMCampaignSettings         
  Set LastUserAssigned=isnull((Select top 1 AssignedTo From #tmpLeadSrc Where ISNULL(AssignedTo,'') != '' and Sno not in (Select distinct Sno from #tmpConstraintChk) order by sno desc),LastUserAssigned)        
  Where IsActive=1 and UserID=@ParentId        
        
  SELECT @LastLeadId=IDENT_CURRENT('UserLeads')        
        
  INSERT INTO [dbo].[UserLeads]        
  ([LeadNo],[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],[EmailID2],[City],[State],[Country]        
  ,[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo],[SourceName],[MediumName]        
  ,[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],[NextStatusDate],[Remarks],[Products],[AmountPaid]        
  ,[CreatedOn],[CreatedBy],[FollowupDate])        
  Select        
  @NextLeadNo+LeadNo, [PersonName], [CompanyName], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], [City], [State], [Country]        
  ,[CountryCode],[CountryCode1],[CountryCode2],[PinCode],[ResidentialAddress],[OfficeAddress],[AssignedTo],[SourceName],[MediumName]        
  ,[CampaignName],[InitialRemarks],[ParentID],[FollowUpStatus],case when [NextStatusDate]='' then '' else FORMAT(cast(NextStatusDate as Datetime),'dd-MMM-yyyy hh:mm:ss tt') end,[Remarks],[Products],[AmountPaid]        
  ,[CreatedOn],[CreatedBy],[FollowupDate]        
  From    #tmpUserLeads        
        
  Select @nLeadInserted=@@ROWCOUNT        
       
  insert into leadinteractionhistory(LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,followupdate)      
  select LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,followupdate       
  from userleads where parentid=@ParentId and createdon=@CreatedOn      
       
  set @jRow = 1        
  while(@jRow <= @CustomFieldsCnt)        
  begin        
   select @fieldId=fieldId,@fieldName=fieldName from #tblCustomFields Where RowId=@jRow        
        
   set @SQLString = 'insert into customfieldLeadvalue select distinct A.ID, 0, ' + cast(@fieldId as varchar) + ', case when IsDate(C.[' + @fieldName + ']) = 1 then Format(cast(C.[' + @fieldName + '] as datetime),''dd-MMM-yyyy hh:mm:ss tt'')   
   else C.[' + @fieldName + '] end          
     From [UserLeads] A inner join #tmpUserLeads B        
   ON   A.LeadNo = B.LeadNo+' + cast(@NextLeadNo as varchar) + ' inner join #tmpLeadSrc C        
   On  B.Sno = C.Sno        
   Where A.[ParentID] = ' + cast(@ParentId as varchar) + ' and A.LeadNo <= ' + cast(@NextLeadNo as varchar) + '+' + cast(@nLeadInserted as varchar)        
            
   print 'custom field Lead @SQLString: ' + @SQLString + ' and isnull(C.[' + @fieldName + '],'''') != '''' '        
        
   exec (@SQLString)        
   select @nLeadCustomFieldRows+=@@ROWCOUNT        
        
   set @jRow = @jRow + 1        
  end        
  SET DATEFORMAT dmy;    
  UPDATE cflv set cflv.fieldvalue=case when isnull(cflv.fieldvalue,'') != '' then FORMAT(cast(cflv.fieldvalue as Datetime),'dd-MMM-yyyy hh:mm:ss tt') else cflv.fieldvalue end      
  --select *      
  FROM userleads ul inner join customfieldleadvalue cflv      
  ON ul.id=cflv.leadid inner join customfields cf      
  ON cflv.fieldid=cf.field_id      
  WHERE ul.parentid=@ParentId and ul.createdon=@CreatedOn and cf.datatype='d'      
      
  Set @RowData = isnull((Select Sno, Remarks From #tmpConstraintChk order by Sno for json auto, INCLUDE_NULL_VALUES),'')        
      
  update tbl_LeadImportSummary         
  set IsProcessed=1, Remarks=@RowData, LeadCnt=@nLeadInserted, LeadCustomFieldCnt=@nLeadCustomFieldRows         
  where ImportRow_Id=@ImportRow_id        
        
  Iter:    
  Set @iRow = @iRow + 1        
  Set @ImportRow_id=0        
  Set @ImportData=null        
  Set @RowData=null        
  Set @FieldNames=''        
  Set @SQLString=null        
  Set @User_Id=0        
  Set @LastLeadId=0        
  Set @nLeadInserted=0        
  Set @nLeadCustomFieldRows=0        
  Set @jRow=1        
  Set @fieldId=0        
  Set @fieldName=''        
  Set @CustomFieldsCnt = 0        
        
  truncate table #tmpConstraintChk        
  truncate table #tmpUserLeads        
  truncate table #tmpMobileNoList        
  truncate table #tmpEmailIdList        
  truncate table #tblCustomFields        
        
  if object_id('tempdb..#tmpLeadSrc') is not null begin drop table #tmpLeadSrc end        
        
    End        
        
    COMMIT TRANSACTION          
END TRY            
BEGIN CATCH           
  IF @@TRANCOUNT > 0          
  ROLLBACK TRANSACTION          
    DECLARE  @ErrorMessage  NVARCHAR(4000),          
             @ErrorSeverity INT,            
             @ErrorState    INT;            
          
    SELECT             
        @ErrorMessage  = ERROR_MESSAGE(),            
        @ErrorSeverity = ERROR_SEVERITY(),           
        @ErrorState    = ERROR_STATE();           
                   
    SET @ErrorMessage=@ErrorMessage           
          
    RAISERROR (@ErrorMessage, -- Message text.            
                 @ErrorSeverity, -- Severity.            
                 @ErrorState -- State.            
               );            
END CATCH            
        
if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end        
if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end        
if object_id('tempdb..#tblCustomFields') is not null begin drop table #tblCustomFields end        
if object_id('tempdb..#tblAllLeadFields') is not null begin drop table #tblAllLeadFields end        
if object_id('tempdb..#tmpLeadSrc') is not null begin drop table #tmpLeadSrc end        
if object_id('tempdb..#tmpUserLeads') is not null begin drop table #tmpUserLeads end        
if object_id('tempdb..#tmpMobileNoList') is not null begin drop table #tmpMobileNoList end        
if object_id('tempdb..#tmpEmailIdList') is not null begin drop table #tmpEmailIdList end        
        
END 



GO

/* ============================================================
   Procedure: [dbo].[usp_processleadmatchingenquiryactivity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_processleadmatchingenquiryactivity  
as  
begin  
drop table if exists #tpla  
select top 50 * into #tpla from enquiryprocessleadactivity(nolock) where (isprocessed=0 or (isprocessed=2 and processedon<dateadd(mi,-20,getdate())))  
and createdon>dateadd(HH,-3,getdate())  
  
update e set isprocessed=2,processedon=getdate() from enquiryprocessleadactivity e join #tpla t on t.id=e.id  
declare @parentid bigint,@createdby bigint,@enquiryid bigint,@id bigint=0,@count int  
  
DECLARE @tbl AS LeadActivitywithid_Tbltype            
select @count=count(1) from #tpla  
  
while @count>0  
begin  
begin try  
select @id=min(id) from #tpla where id>@id  
select @parentid=parentid,@enquiryid=enquiryid from #tpla where id=@id  
drop table if exists #inserted  
select * into #inserted from userenquiry(nolock) where enquiryid=@enquiryid  
  
 INSERT INTO @tbl (          
  LeadID            
  ,UserID            
  ,ParentID            
  ,EventDescription            
  ,EventName            
  ,reftable            
  ,Refid            
  )            
   SELECT ulme_id            
  ,CreatedBy            
  ,i.ParentID            
  ,'Lead with ' + isnull('name ' + isnull(nullif(personname, ''),''), 'no name') + ' expressed a new interest through enquiryno ' + cast(i.enquiryid as        
  nvarchar)        
  ,'Lead generated new enquiry'            
  ,'Userenquiry'            
  ,EnquiryID            
 FROM #inserted i            
 JOIN userleads_mobile_email(NOLOCK) u ON i.parentid=u.parentid and        
((u.mobile <>'0' and u.mobile in (isnull(i.MobileNo,'1'),isnull(i.MobileNo2,'1'),isnull(i.MobileNo1,'1')))            
 or         
 (u.email<>'0' and u.email in (isnull(i.emailid,'2'),isnull(i.emailid1,'2'),isnull(emailid2,'2')) )) 
 and datediff(mi,u.leadcreateddate ,i.CreatedDate)>5
 and not exists        
 (select 1 from tbl_leadeventhistory(nolock) where eventid=28 and refids=i.enquiryid and leadid=ulme_id)        
         
 EXEC UspSaveentityActivity_withMultipleValue_withid @tbl            
  
 delete from @tbl  
 delete from #inserted  
  update enquiryprocessleadactivity set isprocessed=1,processedon=getdate(), errdesc=null where id=@id  
  
 end try  
 begin catch  
 delete from @tbl  
 update enquiryprocessleadactivity set errdesc=ERROR_MESSAGE() where id=@id  
 exec usp_inserterrorinfo  
 end catch  
  
 set @count=@count-1  
 end  
  
end


--select top 10 * from enquiryprocessleadactivity(nolock) order by 1 desc


GO

/* ============================================================
   Procedure: [dbo].[usp_processmktseq]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_processmktseq  
as  
begin  
drop table if exists #run  
create table #run(rno int identity(1,1),batchid bigint,sequenceactionid bigint)
if exists(select 1 from tbl_mass_mktgsequence(nolock) where isprocessed=0 and scheduledfor between   
dateadd(d,-1,getdate()) and getdate())  
begin  
insert into #run(batchid,sequenceactionid)
select distinct batchid,sequenceactionid from tbl_mass_mktgsequence(nolock) where isprocessed=0 and scheduledfor between   dateadd(d,-1,getdate()) and getdate()
  
declare @id bigint=0,@count int,@batchid bigint,@actionid bigint  
select @count=count(1) from #run  
while @count>0  
begin  
select @id=min(rno) from #run where rno>@id  
select @batchid=batchid,@actionid=sequenceactionid from #run where rno=@id  
exec [usp_execute_massmktgsequence_id] @batchid,@actionid  
select @count=@count-1   
end  
end  
end  
  


GO

