   Procedure: [dbo].[usp_processnotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_processnotification 34594 ,3866718, 102    
CREATE   PROCEDURE [dbo].[usp_processnotification] --32222,87321834--34594,39045520,1   --39699,9299899,1    
(@parentid bigint,@activityid bigint,@eventid int)                                
as                                
begin         
--Declare @parentid bigint = 34594,@activityid bigint = 39045520,@eventid int = 1    
    
declare @entityname nvarchar(20),@ename nvarchar(100),@edescription nvarchar(2000),@entityid bigint
,@eventtype nvarchar(200),@encrypt_a varbinary(200),@e_n nvarchar(500),@servicetype varchar(50),@credit_typeid int,@pagecode varchar(50)
,@reftable nvarchar(250),@refid nvarchar(250)
declare @mid bigint,@partner_userid bigint,@url nvarchar(255),@fblink nvarchar(1000),@twlink nvarchar(1000),@wa nvarchar(1000),@lin nvarchar(1000),@chat nvarchar(1000),
@add1 nvarchar(2000),@add nvarchar(2000),@ph1 nvarchar(50),@ph2 nvarchar(50),@displayname nvarchar(1000),@signature nvarchar(4000),@logo nvarchar(1000),@jsonpartner nvarchar(max),
@jsonpartneremail nvarchar(max),@from_mail nvarchar(200),@r_id bigint,@type int,@partner_type int

select @mid=m_id,@type=Type from user_detail(nolock) where user_id=@parentid
select @partner_userid=user_id,@r_id=reseller_id,@partner_type=partner_type from reseller_detail(nolock) where Reseller_ID=@mid
select @displayname=CompnayName,@add=Address,@ph1=str(mobile) from user_detail(nolock) where user_id=@partner_userid

if @partner_type in (2,3) and @type=0 and @parentid<>335--Silver and Gold (white labelled partner)
begin
select @r_id=reseller_id from reseller_detail(nolock) where Reseller_ID=@mid
select @displayname=CompnayName,@add=Address,@ph1=str(mobile) from user_detail(nolock) where user_id=@partner_userid
end
else if @partner_type in (2,3) or @type=3 or @parentid=335
begin
select @r_id=reseller_id,@partner_userid=user_id from reseller_detail(nolock) where user_ID=@parentid
select @displayname=CompnayName,@add=Address,@ph1=str(mobile) from user_detail(nolock) where user_id=@partner_userid
end
else if  @partner_type=1--Bronze (Non white labelled partner)
begin
select @mid=m_id from user_detail(nolock) where user_id=@partner_userid
--Partner_userid and @r_id will be the reseller_id of the immediate white labelled partner above bronze partner whose branding will apply
select @partner_userid=user_id ,@r_id=reseller_id from reseller_detail(nolock) where Reseller_ID=@mid
select @displayname=CompnayName,@add=Address,@ph1=str(mobile) from user_detail(nolock) where user_id=@partner_userid
end




SELECT @jsonpartner=jsondata,@jsonpartneremail=jsonemaildata  FROM tbl_pt_CustomizationMetadata(nolock) WHERE userid=@partner_userid
drop table if exists #partnerjson     
    --select fgg like '%123%'  
  
select * into #partnerjson from
(select * from openjson(@jsonpartner)
union
select * from openjson(@jsonpartneremail)
)
a

select @url =dbo.fn_userdomain(@partner_userid)
select @fblink =isnull(nullif((select [value] from #partnerjson where [key]='Fburl'),''),dbo.fn_userdomain(@partner_userid))
select @twlink =isnull(nullif((select [value] from #partnerjson where [key]='TwtUrl'),''),dbo.fn_userdomain(@partner_userid))
select @lin =isnull(nullif((select [value] from #partnerjson where [key]='LnkUrl'),''),dbo.fn_userdomain(@partner_userid))
select @chat =isnull(nullif((select [value] from #partnerjson where [key]='Fburl'),''),dbo.fn_userdomain(@partner_userid))
select @add1 =isnull(nullif((select [value] from #partnerjson where [key]='Address1'),''),dbo.fn_userdomain(@partner_userid))
select @add =isnull(nullif((select [value] from #partnerjson where [key]='Address'),''),isnull(@add,''))
select @ph1 =isnull(nullif((select [value] from #partnerjson where [key]='AltNm'),''),@ph1)
select @ph2 =isnull(nullif((select [value] from #partnerjson where [key]='Mobile2'),''),'')
select @from_mail =isnull(nullif((select [value] from #partnerjson where [key]='Email'),''),'noreply@email19.in')
select @signature =isnull(nullif((select [value] from #partnerjson where [key]='SignatureEditor'),''),'Team '+ isnull(@displayname,dbo.fn_userdomain(@partner_userid)))
select @logo =isnull(nullif((select [value] from #partnerjson where [key]='logourl'),''),'')
select @wa =isnull(nullif((select [value] from #partnerjson where [key]='waurl'),''),dbo.fn_userdomain(@partner_userid))

/*
@twlink =case when [key]='TwtUrl' then [value] else dbo.fn_userdomain(@partner_userid) end,
@wa =case when [key]='waurl' then [value] else dbo.fn_userdomain(@partner_userid) end,
@lin =case when [key]='LnkUrl' then [value] else dbo.fn_userdomain(@partner_userid) end,
@chat =case when [key]='Fburl' then [value] else dbo.fn_userdomain(@partner_userid) end,
@add1 =case when [key]='Address1' then [value] else '' end,
@add =case when [key]='Address' then [value] else isnull(@add,'') end,
@ph1 =case when [key]='AltNm' then [value] else @ph1 end,
@ph2 =case when [key]='Mobile2' then [value] else '' end,
@from_mail =case when [key]='Email' then [value] else 'noreply@email19.in' end,
@signature =case when [key]='SignatureEditor' then [value] else 'Team '+ isnull(@displayname,dbo.fn_userdomain(@partner_userid)) end,
@logo =case when [key]='logourl' then [value] else '' end
from #partnerjson
*/
select @logo=case when @r_id <>10043 then 'https://'+replace(replace(@url,'https://',''),'http://','')+'/assets/custom/partner/resource/'+cast(@r_id as nvarchar)+'/'+[value] 
else 'https://kit19.com/assets/custom/img/logobig.png' end
from 
#partnerjson where [key] = 'LogoUrl' 
select @logo=isnull(@logo,'https://kit19.com/assets/custom/img/logobig.png')

select @encrypt_a= EncryptByPassPhrase('EncryptActivityID', cast(@activityid as varchar(100) ))
select @e_n='0x'+convert(varchar(max),@encrypt_a,2)   

select @entityname=context,@ename=eventname,@eventtype=eventtype,@pagecode=modulecode from activitymaster(nolock) where id=@eventid        
DECLARE @nid TABLE                                    
  (                                    
   [modeid]         INT,                                    
   [notificationid] BIGINT,                                    
   [roleid]         INT,                                    
   [activityid]     INT                                  
  );                                   
                              
INSERT INTO @nid([modeid], [notificationid], [roleid], [activityid])                                    
SELECT [modeid], n.[id], n.[roleid], [activityid]                                     
FROM   notificationsmaster(NOLOCK) n join adminnotificationsettings(nolock) a on a.notificationid=n.id and a.parentid=@parentid      
and a.isactive=1 
and 1 =case when @r_id<>10043 and modeid not in (1,5,3) then 0 else 1 end
WHERE  [activityid] = @eventid;                              
  
drop table if exists #nusers                        
create table #nusers(nuserids nvarchar(max),nroleid int)                        
declare @t int=(select count(1) from @nid),@rolename nvarchar(50),@rid int=0                        
while @t>0                        
begin                        
select @rid=min(roleid) from @nid where roleid>@rid                        
select @rolename=s.rolename from systemroles(nolock) s where s.id=@rid                        
insert into #nusers(nuserids,nroleid)                        
select f.value,@rid from dbo.fn_split(dbo.fn_GetUseridFromRole(@entityname,@activityid,@rolename),',') f where f.value<>'0'                        
set @t=@t-1                        
end                        
                              
begin try                                 
if exists(select 1 from @nid n where n.modeid=2) and @parentid<>34594 --demo account so many messages                             
begin                        
drop table if exists #a                          
declare @allrole nvarchar(max)                  
select @allrole=coalesce(@allrole+',','')+s.rolename from adminnotificationsettings (nolock) a                   
join @nid n on n.notificationid=a.notificationid and n.modeid=2 and a.parentid=@parentid and a.isactive=1                            
join systemroles s on s.id=a.roleid                            
                  
select distinct str(mobile,10) mobile into #a                             
from                   
user_detail(nolock) u where u.user_id in                             
(select roleuserid from dbo.fn_GetTBLUseridFromRole(@entityname,@activityid,@allrole) where roleuserid<>0)                  
                  
                              
declare @smsn nvarchar(2000),@dltid nvarchar(100)       
/*Commented as composing dynamic text takes computing time    
select @smsn=smscontent,@dltid=DLTTemplateID from DLTMappedEvent(nolock) where eventid=@eventid     
*/    
    
    
if @smsn is null    
begin    
if @entityname='lead'     
begin    
select @dltid='1707163185631378512',@edescription=eventdescription,@entityid=leadid from tbl_leadeventhistory(nolock) where historyid=@activityid    
select @smsn='New event for lead: '+cast(l.LeadNo as nvarchar)+', Name: '+isnull(personname,' ')+'.Event:'    
+left(@ename,30)+ '.Details:'+left(isnull(@edescription,''),120)+': Team Kit19'    
from userleads(nolock) l where l.id=@entityID    
end    
else  if @entityname='enquiry'    
begin     
select @dltid='1707163185643541025',@edescription=eventdescription,@entityid=enquiryid from tbl_enquiryeventhistory(nolock) where historyid=@activityid    
select @smsn='New event for enquiry: '+cast(l.enquiryid as nvarchar)+', Name: '+isnull(personname,' ')+'.Event:'    
+left(@ename,30)+ '.Details:'+left(isnull(@edescription,''),120)+': Team Kit19'    
 from userenquiry(nolock) l where l.enquiryid=@entityID    
end  
else  if @entityname='user'    
begin     
select @dltid='1707163185643541025',@edescription=eventdescription,@entityid=userid from tbl_usereventhistory(nolock) where historyid=@activityid    
select @smsn='New event for user: '+cast(l.user_login as nvarchar)+'.Event:'    
+left(@ename,30)+ '.Details:'+left(isnull(@edescription,''),120)+': Team Kit19'    
 from user_detail(nolock) l where l.user_id=@entityID    
end    
  
GOTO RESUME    
end    
    
  
  
RESUME:      
declare @sms_n_c int,@sms_bal numeric(18,4),@sms_cost numeric(18,4),@InsertedCreditID bigINT
set @servicetype='DomesticSMS';
select @credit_typeid= CreditTypeID from Price_Master_TypeCredit(nolock) where creditname='DomesticSMS'

drop table if exists #b                    
select distinct mobile into #b from #a    
--commented code to be activate when sms notification is to be applied
select @sms_n_c=count(1),@sms_bal=dbo.GetAvailableBalanceForService(@ParentID,21) from #b
select @sms_cost= 
case when len(@smsn)<=160 and dbo.fn_isunicode(@smsn)=0 then (@sms_n_c)*(PTrns)
when len(@smsn)>160 and dbo.fn_isunicode(@smsn)=0 then cast((ceiling(LEN(@smsn) / cast(153 AS FLOAT))) as int)*(@sms_n_c)*(PTrns)
when len(@smsn)<=70 and dbo.fn_isunicode(@smsn)=1 then (@sms_n_c)*(PTrns)
when len(@smsn)>70 and dbo.fn_isunicode(@smsn)=1 then cast((ceiling(LEN(@smsn) / cast(67 AS FLOAT))) as int)*(@sms_n_c)*(PTrns) else (@sms_n_c)*(PTrns) end
from Price_Base_SMS_RateDeduction(nolock) where DestinationCountryCode='+91'
if @sms_bal>=@sms_cost and @sms_cost>0
begin
declare @mobile nvarchar(max)                      
select @mobile=coalesce(@mobile+',','')+cast(mobile as nvarchar) from #b where isnull(nullif(cast(mobile as nvarchar),'0'),'')<>''                            
                            
if @smsn is not null and @mobile<>''                              
begin                              
exec usp_sendmessage_withdlt 335,@smsn,@mobile,'KitApp',0,2,@dltid                              
INSERT INTO IntCredit_Details
        (
            FromUser_ID, M_ID, User_ID, Debits, Credits, Balance,Validity, BatchID, ICD_CreatedBy,typecredit,Remarks
        )
        VALUES
        (
            @parentid, @mid, @ParentID, @sms_cost, 0, dbo.fn_getmoneybalance(@parentid)-@sms_cost, 99999, null, @parentid,@credit_typeid,'Credits utilized for sending notification sms to mobiles: '+
			isnull(@mobile,'')+ ' for '+ isnull(@entityname,'')+ ' activity '+
			isnull(@ename,'')+ ' , activityid: '+cast(@activityid as nvarchar)
        );

		SET @InsertedCreditID = SCOPE_IDENTITY();

		exec usp_rf_UpdateReserveFundTransaction @InsertedCreditID
end 
end
end                              
  
if 1=2--exists(select 1 from @nid n where n.modeid=3)                              
begin 
print 'entered email'
drop table if exists #ae                          
select @allrole=coalesce(@allrole+',','')+s.rolename from adminnotificationsettings (nolock) a                   
join @nid n on n.notificationid=a.notificationid and n.modeid=3 and a.parentid=@parentid and a.isactive=1                            
join systemroles s on s.id=a.roleid                            
 
 

select distinct email into #ae                             
from                   
user_detail(nolock) u where u.user_id in                             
(select roleuserid from dbo.fn_GetTBLUseridFromRole(@entityname,@activityid,@allrole) where roleuserid<>0)                  
--select * from #ae
declare @emailn nvarchar(max)  =''
  
select top 1 @emailn=  
