   Procedure: [dbo].[usp_processnotification_withemail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_processnotification 34594 ,3866718, 102    
CREATE   PROCEDURE [dbo].[usp_processnotification_withemail]    --39699,9299899,1    
(@parentid bigint,@activityid bigint,@eventid int)                                
as                                
begin         
--Declare @parentid bigint = 34594,@activityid bigint = 3867233,@eventid int = 102    
    
declare @entityname nvarchar(20),@ename nvarchar(100),@edescription nvarchar(2000),@entityid bigint,@eventtype nvarchar(200),@encrypt_a varbinary(200),@e_n nvarchar(500)
select @encrypt_a= EncryptByPassPhrase('EncryptActivityID', cast(@activityid as varchar(100) ))
select @e_n='0x'+convert(varchar(max),@encrypt_a,2)

select @entityname=context,@ename=eventname,@eventtype=eventtype from activitymaster(nolock) where id=@eventid        
DECLARE @nid TABLE                                    
  (                                    
   [modeid]         INT,                                    
   [notificationid] BIGINT,                                    
   [roleid]         INT,                                    
   [activityid]     INT                                  
  );                                   
                              
INSERT INTO @nid([modeid], [notificationid], [roleid], [activityid])                                    
SELECT [modeid], n.[id], n.[roleid], [activityid]                                     
FROM   notificationsmaster(NOLOCK) n join adminnotificationsettings(nolock) a on a.notificationid=n.id and a.parentid=@parentid      
and a.isactive=1      
WHERE  [activityid] = @eventid;                              
  
drop table if exists #nusers                        
create table #nusers(nuserids nvarchar(max),nroleid int)                        
declare @t int=(select count(1) from @nid),@rolename nvarchar(50),@rid int=0                        
while @t>0                        
begin                        
select @rid=min(roleid) from @nid where roleid>@rid                        
select @rolename=s.rolename from systemroles(nolock) s where s.id=@rid                        
insert into #nusers(nuserids,nroleid)                        
select f.value,@rid from dbo.fn_split(dbo.fn_GetUseridFromRole(@entityname,@activityid,@rolename),',') f where f.value<>'0'                        
set @t=@t-1                        
end                        
  
declare @allrole nvarchar(max)                  
  
begin try                                 
if exists(select 1 from adminnotificationsettings (nolock) a join @nid n on n.notificationid=a.notificationid and n.modeid=2                               
and a.parentid=@parentid and a.isactive=1)                              
begin                        
drop table if exists #a   
select @allrole=null  
--declare @allrole nvarchar(max)                  
select @allrole=coalesce(@allrole+',','')+s.rolename from adminnotificationsettings (nolock) a                   
join @nid n on n.notificationid=a.notificationid and n.modeid=2 and a.parentid=@parentid and a.isactive=1                            
join systemroles s on s.id=a.roleid                            
                  
select distinct str(mobile,10) mobile into #a                             
from                   
user_detail(nolock) u where u.user_id in                             
(select roleuserid from dbo.fn_GetTBLUseridFromRole(@entityname,@activityid,@allrole) where roleuserid<>0)                  
                  
                              
declare @smsn nvarchar(2000),@dltid nvarchar(100)       
    
    
if @smsn is null    
begin    
if @entityname='lead'     
