/* ============================================================
   Procedure: [dbo].[Usp_ProcessPipelineInfo_ForCRMDB]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_ProcessPipelineInfo_ForCRMDB(@id bigint =null)      
as      
begin      
drop table if Exists #temp1       
drop table if Exists #tempWithRowNum       
      
  select ID,EnqNo,EnqPipelineID,ClientResponse,CreatedOn into #temp1 from tbl_PipelineJsonInfo with(nolock) 
  where  isnull(ClientResponse,'') != ''  and isnull(IsProcess,0) = 0 
  and 1=case when @id is null then 1 when id=@id then 1 else 0 end
  order by id asc      
        
  select ROW_NUMBER() over(order by id asc) as RowNum,ID,EnqNo,EnqPipelineID,ClientResponse,createdon into #tempWithRowNum  from #temp1        
  declare @Count int = 0 , @RowNum int = 1      
      
  select @Count = count(1) from #tempWithRowNum      
  declare @Enqno bigint = 0 , @EnqPipelineID bigint = 0 ,@createdon datetime     
  declare @ClientResponse nvarchar(500) = '' ,@eventid int     
      
           BEGIN TRY          
          --First Server Connection (Server1) 192.168.1.x          
          --If the connection isn't available it will raise an exception          
      declare @servername nvarchar(50) = 'CRM'          
      exec sp_testlinkedserver  @servername --= Server1          
          --SQL statement here          
          
      
  while(@Count > 0)      
    begin      
      
       
   select top 1 @Enqno = isnull(Enqno,0) ,@EnqPipelineID = isnull(EnqPipelineID,0) ,@ClientResponse = isnull(ClientResponse,''),
   @id=id,@createdon=createdon 
   from #tempWithRowNum where RowNum = @RowNum      
     
	 exec [crm].[CRMDB].[dbo].usp_updatejsonpipelineInfo @enqno ,@clientresponse,@EnqPipelineID,@id,@createdon
    --  update  [crm].[CRMDB].[dbo].tbl_PipelineJsonInfo set ClientResponse = @ClientResponse  --, ModifiedOn = getdate() , ModifiedBy = 0           
    --      where id=@id
        
    --select @eventid=case when @ClientResponse='Accepted' then 92 when @ClientResponse='Declined' then 93     
    --when @ClientResponse='Revised' then 94    
    --else 0 end    
    
    --exec [crm].[CRMDB].[dbo].usp_insertenqscore @eventid,@enqno,@id    
          
    --  if(@ClientResponse = 'Accepted' or @ClientResponse = 'Revised' )        
    --   begin        
    --  update  [crm].[CRMDB].[dbo].EnqPipelineMapping set isverified = 1  
    --         where EnqNo = @EnqNo and ID = @EnqPipelineID          
            
    --   end        
    --  else if(@ClientResponse = 'Declined')        
    --   begin        
    --  update  [crm].[CRMDB].[dbo].EnqPipelineMapping set isverified = 2 
    --         where EnqNo = @EnqNo and ID = @EnqPipelineID          
            
    --   end        
                
        
      update tbl_PipelineJsonInfo set IsProcess = 1          
           where 
		   id=@id      
          
       set  @RowNum = @RowNum + 1      
       set  @Count = @Count -1      
      
    end      
      
   END TRY          
      BEGIN CATCH          
          --SELECT ERROR_MESSAGE()       
    exec usp_inserterrorinfo    
      END CATCH          
         
      
  drop table if Exists #temp1      
  drop table if Exists #tempWithRowNum      
end


GO

/* ============================================================
   Procedure: [dbo].[usp_ProcessProductImportData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_ProcessProductImportData] --59--57--49  --new latestsp
(                
	@IPRId bigint
)                
AS                
BEGIN                
               

    --declare @IPRId bigint= 359 ;  --333
 
 
 if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end                
 if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end                
 if object_id('tempdb..#tblAllProductFields') is not null begin drop table #tblAllProductFields end
 if object_id('tempdb..#tblProductCustomFields') is not null begin drop table #tblProductCustomFields end
 if object_id('tempdb..#tmpProductSrc') is not null begin drop table #tmpProductSrc end                
                
 Create table #tblImportRowId  
 (                
  RowId int identity,                
  ImportRow_id bigint,                
  [User_Id] bigint,
  Mode varchar(1)
 )                
                
 create table #tmpConstraintChk  
 (                
  Sno int,                
  Remarks varchar(200)                
 )                
                
 create table #tblAllProductFields  
 (                
  RowId int identity(1,1),                
  fieldName varchar(50),            
  DataType varchar(10)            
 )                
                
 create table #tblProductCustomFields
 (
  RowId int identity(1,1),
  fieldName varchar(50),
  DataType varchar(10)
 )

 BEGIN TRY  
          
   If(isnull(@IPRId,0) > 0)          
   Begin          
    insert into #tblImportRowId          
    Select ImportRow_id,[User_Id],Mode From tbl_ProductImportSummary(nolock) where ImportRow_id=@IPRId          
   End          
  
   select * from #tblImportRowId                
                
   declare @iRow int=1, @ImportRow_id bigint=0, @UnProcessedRowCnt int=0, @User_Id bigint=0, @Mode varchar(1)
   declare @ImportData nvarchar(max), @RowData nvarchar(max), @FieldNames nvarchar(max)='', @SQLString nvarchar(max)='', @ParmDefinition nvarchar(500), @fieldName varchar(50)='',@fieldtype nvarchar(20);
   declare @CustomFieldsCnt int=0, @ParentId bigint=0, @CreatedOn datetime, @nProdInserted bigint=0, @nProdUpdated bigint=0
   Declare @ir int=1, @DataType varchar(100), @DefaultValue nvarchar(max), @Mandatory bit, @MaxValue nvarchar(max), @MinValue nvarchar(max), @Choices nvarchar(max), @ProdValJson nvarchar(max), @CustFieldValCnt int=0, @ProdTableName varchar(50)=''
  declare @strFieldList nvarchar(max), @strFieldListOrg nvarchar(max)
               
   select @UnProcessedRowCnt=Count(*) from #tblImportRowId

   print concat('@UnProcessedRowCnt',@UnProcessedRowCnt)

   While(@iRow <= @UnProcessedRowCnt)
   Begin

      print '@iRow: ' + cast(@iRow as varchar)                
      Select @ImportRow_id=ImportRow_id,@User_Id=[User_Id],@Mode=Mode From #tblImportRowId Where RowId=@iRow
      print '@ImportRow_id: ' + cast(@ImportRow_id as varchar)                
      Select @ImportData=ImportData from tbl_ProductImportSummary(nolock) where ImportRow_Id=@ImportRow_id  
      print '@ImportData: ' + @ImportData                
