      Set CategoryName =(Select top 1 PC.Id From Product_Category(nolock)PC Where PC.CategoryName collate Latin1_General_CI_AI =#tmpProductSrc.CategoryName and PC.ParentId in (@ParentId,0)),   
       UnitName =(Select top 1 U.id From unit(nolock)U Where U.unitname collate Latin1_General_CI_AI =#tmpProductSrc.UnitName and U.ParentId in (@ParentId,0))
       Where Sno  not in (Select distinct Sno from #tmpConstraintChk)

	   -- Select STRING_AGG( id, ',') from MySMSInvoicing.dbo.taxes(nolock) Where ParentId in (@ParentId,0) and name in (select item from dbo.SplitString(ISNULL(ltrim(@HomeTaxes),''),','))

	   --Select * from MySMSInvoicing.dbo.taxes(nolock) Where ParentId in (@ParentId,0) and name in (select item from dbo.SplitString(ISNULL(ltrim(A.HomeTaxName),''),','))
	   Update #tmpProductSrc
         Set HomeTaxName=(Select STRING_AGG( id, ',') from MySMSInvoicing.dbo.taxes(nolock) Where ParentId in (@ParentId,0) and name in (select item from dbo.SplitString(ISNULL(ltrim(HomeTaxName),''),',')))
          Where Sno not in (Select distinct Sno from #tmpConstraintChk)
