				 set @strFieldListInsert = @strFieldListInsert +', '+ ' @CreatedDate '
				 set @blflag = 1;
			end
					   

		Set @SQLString = N'insert into ' + @ProdTableName + N'(' + @strFieldListOrg + N',
		--CreatedOn
