		Select '+ @strFieldListInsert + N'--,@CreatedDate
		,@UserId From #tmpProductSrc Where Sno not in (Select distinct Sno from #tmpConstraintChk); Select @nProdCnt=@@RowCount'
		SET @ParmDefinition = N'@CreatedDate datetime,@UserId bigint, @nProdCnt int output';
		print @SQLString  
		begin try
		EXECUTE sp_executesql @SQLString, @ParmDefinition, @CreatedDate = @CreatedOn, @UserId=@User_Id, @nProdCnt=@nProdInserted output
