		From ' + @ProdTableName + N' PT inner join #tmpProductSrc TT
		On PT.Name=TT.Name
		Where	TT.Sno not in (Select distinct Sno from #tmpConstraintChk); Select @nProdCnt=@@RowCount'

		SET @ParmDefinition = N'@ModifiedDate datetime, @nProdCnt int output';
		print @SQLString                
		EXECUTE sp_executesql @SQLString, @ParmDefinition, @ModifiedDate = @CreatedOn, @nProdCnt=@nProdUpdated output

