     Set @RowData=null  
     Set @FieldNames=''  
     Set @SQLString=null  
     Set @User_Id=0  
     Set @nProdInserted=0  
     Set @fieldName=''  
     Set @CustomFieldsCnt = 0  
                
       truncate table #tmpConstraintChk
       truncate table #tblProductCustomFields
                
       if object_id('tempdb..#tmpProductSrc') is not null begin drop table #tmpProductSrc end
   End                
 
  SET Context_Info 0x  
    
 END TRY                    
 BEGIN CATCH           
		select 'error'
  --insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)
  SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()

 END CATCH                    
                
 if object_id('tempdb..#tblImportRowId') is not null begin drop table #tblImportRowId end
 if object_id('tempdb..#tmpConstraintChk') is not null begin drop table #tmpConstraintChk end
 if object_id('tempdb..#tblProductCustomFields') is not null begin drop table #tblProductCustomFields end
 if object_id('tempdb..#tblAllProductFields') is not null begin drop table #tblAllProductFields end
 if object_id('tempdb..#tmpProductSrc') is not null begin drop table #tmpProductSrc end

END   



