/* ============================================================
   Procedure: [dbo].[usp_processschedulednotifications]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_processschedulednotifications]            
as            
begin 


/*
		Added	: DBA
		Date	: 2025-03-05
		*/

		DECLARE @current_dt AS DATETIME;
		SELECT @current_dt = GETDATE();

		CREATE TABLE #ScheduledFor (ParentID BIGINT, CutoffDate DATETIME);

		/*
		The temp. table #ScheduledFor find maximum number of days
		that has been configured for each ParentID
		*/
		;with CTE_cutoff_days1
		AS
		(
		SELECT ParentID, TimeUnit,  
			CASE UPPER(TimeUnit)
				WHEN 'SECOND' THEN CAST(MAX(TimeBeforeEvent) / 86400.0 AS NUMERIC (18, 9))
				WHEN 'MINUTE' THEN CAST(MAX(TimeBeforeEvent) / 1440.0 AS NUMERIC (18, 9))
				WHEN 'HOUR' THEN CAST(MAX(TimeBeforeEvent) / 24.0 AS NUMERIC (18, 9))
				WHEN 'DAY' THEN CAST(MAX(TimeBeforeEvent) / 1.0 AS NUMERIC (18, 9))
				ELSE 365
			END AS Max_Days
		FROM adminnotificationsettings a WITH (NOLOCK)
		WHERE a.isactive=1
		GROUP BY ParentID, TimeUnit
		),
		CTE_cutoff_days2
		AS
		(
		SELECT
			ParentID, CAST(CEILING(MAX(Max_Days)) AS INT) cut_off_days
		FROM CTE_cutoff_days1
		GROUP BY ParentID
		)
		INSERT INTO #ScheduledFor (ParentID, CutoffDate)
		SELECT ParentID, DATEADD(DAY, -1 * IIF(cut_off_days=0, 1, cut_off_days), @current_dt)
		FROM CTE_cutoff_days2;

		-- Populate #s with data from scheduledtodos on or after CutoffDate
		SELECT s.id, s.parentid, s.eventid, s.activityid, s.scheduledfor, 
		s.isnotified, s.isvalid,s.tcampaignid
		INTO #s FROM scheduledtodos s WITH (NOLOCK)
		join #ScheduledFor ts 
			on s.parentid=ts.parentid
		WHERE s.scheduledfor >= ts.CutoffDate and s.scheduledaction='notify'
		OPTION (MAXDOP 1);

		select TOP 10 s.* into #tbp      
		from #s s     
		/* Subquery with DISTINCT to eliminate CROSS PRODUCT */
		join 
			(SELECT DISTINCT parentid, ans_eventid, timeunit, timebeforeevent, isactive 
			FROM adminnotificationsettings a WITH (NOLOCK)
			) a 
			on s.parentid=a.parentid and s.eventid=a.ans_eventid            
		where  isnotified=0 and isvalid=1 and isnull(s.tcampaignid,0)=0  and a.isactive=1         
		and @current_dt >=case when TimeBeforeEvent=0 then scheduledfor             
		when a.timeunit='day' then dateadd(dd,0-timebeforeevent,scheduledfor)            
		when a.timeunit='hour' then dateadd(hh,0-timebeforeevent,scheduledfor)            
		when a.timeunit='minute' then dateadd(mi,0-timebeforeevent,scheduledfor)            
		when a.timeunit='second' then dateadd(ss,0-timebeforeevent,scheduledfor)            
		end
		ORDER BY s.id;

/*
select distinct s.* into #tbpd         
from scheduledtodos(nolock) s            
join adminnotificationsettings a (nolock) on s.parentid=a.parentid and s.eventid=a.ans_eventid            
where isnotified=0 and isvalid=1 and isnull(s.tcampaignid,0)=0  and a.isactive=1         
and getdate() >=case when TimeBeforeEvent=0 then scheduledfor             
when a.timeunit='day' then dateadd(dd,0-timebeforeevent,scheduledfor)            
when a.timeunit='hour' then dateadd(hh,0-timebeforeevent,scheduledfor)            
when a.timeunit='minute' then dateadd(mi,0-timebeforeevent,scheduledfor)            
when a.timeunit='second' then dateadd(ss,0-timebeforeevent,scheduledfor)            
end            
select top 10 * into #tbp from #tbpd order by id  
*/     

update s set isnotified=2,processedat=getdate() from scheduledtodos s join #tbp t on s.id=t.id        
        
declare @c int=(select count(1) from #tbp),@id bigint=0,@activityid bigint,@entity nvarchar(20),@eventid int,@parentid bigint            
while @c>0            
begin            
select @id=min(id) from #tbp where id>@id            
select @activityid=activityid,@eventid=eventid,@parentid=parentid from #tbp where id=@id            
select @entity=context from ActivityMaster(nolock) where id=@eventid            
begin try      
exec usp_processnotification @parentid,@activityid,@eventid            
update scheduledtodos set isnotified=1,processedat=getdate() where id=@id            
end try      
begin catch      
exec usp_InsertErrorInfo      
update scheduledtodos set isnotified=0,processedat=getdate() where id=@id            
end catch      
set @c=@c-1            
end            
drop table if exists #tbpd        
drop table if exists #tbp        
end 



GO

/* ============================================================
   Procedure: [dbo].[usp_processsmallimports]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_processsmallimports    
CREATE   PROCEDURE usp_processsmallimports      
@recordslimit numeric(18,2)=null      
as      
begin      
    
 set @recordslimit=coalesce(@recordslimit,5.0)      
 select ImportRow_Id id into #tobeimported From tbl_EnquiryImportSummary(nolock) where IsProcessed=0 and priority<=@recordslimit      
 declare @count int=(select count(1) From #tobeimported),@id bigint=0      
    
 while @count>0      
 begin      
  select @id=min(id) from #tobeimported where id>@id      
  --exec usp_ProcessEnquiryImportDataspecific @id,1,'P'      
  Update tbl_EnquiryImportSummary Set IsProcessed=1,Remarks='[{"Sno":0,"Remarks":"Under Process Queue"}]'     
  Where ImportRow_Id = @id    
    
  Exec usp_ProcessEnquiryImportData_corrected 1, 'P', @id    
  set @count=@count-1      
 end      
    
 drop table if exists #tobeimported      
    
end 




GO

