/* ============================================================
   Procedure: [dbo].[usp_ProcessTableService_FilterClientNumber]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/****************************************************************************                                        SP_Name        : usp_ProcessTableServiceUpdateProcesOperator                                                         Author         : ragh
wendra                                                                                          Created ON     : 17/07/2010                                                                                          Version        : 1                        
                                                                           
Alter BY       : Raghwendra (Transaction)                                                                            Alter Date     :                                                                            
Location       : PELSOFT                                                                                             SP Description : This SP is Used to Update all process table OPERATOR field from Operator Series                             
****************************************************************************/                   
CREATE   PROC [dbo].[usp_ProcessTableService_FilterClientNumber]   -- 11009,1                   
           @BATCHID      BIGINT,                   
           @PROCESSTABLE TINYINT                   
AS                   
  BEGIN                   
 set nocount on                   
    DECLARE  @RowcountTemp BIGINT                   
                       
 SET @RowcountTemp=0 ------                
    --DECLARE VAR AS REQIRED                   
    DECLARE  @fromid    BIGINT,                   
             @maxid     BIGINT,                   
             @toid      BIGINT,                   
             @batchsize BIGINT                   
                       
    SET @batchsize = 500--0 -- Batchsize can be changed   -S                   
                       
   DECLARE @TableNAMECLONE VARCHAR(50)          
  DECLARE @queryFORID nvarchar(max)             
   IF  @PROCESSTABLE=1      
  BEGIN                   
   SET @TableNAMECLONE ='processtablefirst'      
  END      
  ELSE IF @PROCESSTABLE=2      
  BEGIN                   
   SET @TableNAMECLONE ='processtableTWO'      
  END      
  ELSE IF @PROCESSTABLE=3      
  BEGIN                   
   SET @TableNAMECLONE ='processtableTHREE'      
  END      
  ELSE IF @PROCESSTABLE=4      
  BEGIN                   
   SET @TableNAMECLONE ='processtableFOUR'      
  END      
                                
    --Get Min and max ID table name (CloneMessageDeliveryStatus)              
 SET @queryFORID=' SELECT @fromid = Min(ProcessID) , @maxid = Max(ProcessID)                
    FROM   '+@TableNAMECLONE+'                               
    WHERE  batchid = '+convert(nvarchar,@BatchID,100 )+''              
-- select @queryFORID          
 exec sp_executesql @queryFORID,N'@fromid bigint OUTPUT,@maxid bigint OUTPUT', @fromid OUTPUT,@maxid OUTPUT;           
 --select   @fromid,@maxid          
            
 --SET @TableNAMECLONE='clonemessagedeliverystatus'            
            
    SET @batchsize = 500 -- Batchsize can be changed                                
                                   
    SET @RowcountTemp = 0                          
                        
 SET TRANSACTION ISOLATION LEVEL SNAPSHOT ;                              
 SET XACT_ABORT ON ;                              
                        
    SET @toid = @fromid + @batchsize                               
                                   
    IF @toid > @maxid  -- Check Condition                               
      SET @toid = @maxid  -- Set To ID                               
                                   
    WHILE @fromid < = @maxid -- Used While Loop                               
      BEGIN                               
        BEGIN TRY           
          BEGIN TRAN                      
                         
                
     IF @PROCESSTABLE = 1                   
    BEGIN                   
     
       UPDATE pt                   
       SET    Priority = 2               
       FROM   processtablefirst pt --With (tablockx, holdlock)                  
        JOIN ClientMobile opr                   
          ON pt.mobile = opr.mobile                   
    WHERE  pt.batchid = @BatchID         
        AND pt.messagestatus=''                   
        AND pt.ProcessID >= @fromid                   
        AND pt.ProcessID <= @toid                   
                                                              
                     
              
    END                   
                  
     IF @PROCESSTABLE = 2                   
    BEGIN                   
                 
       UPDATE pt                   
       SET    Priority = 2                   
       FROM   processtabletwo pt --With (tablockx, holdlock)                  
         JOIN ClientMobile opr                   
          ON pt.mobile = opr.mobile                   
    WHERE  pt.batchid = @BatchID         
        AND pt.messagestatus=''                   
        AND pt.ProcessID >= @fromid                   
        AND pt.ProcessID <= @toid                   
                                               
             
    END                   
     -------------------------------------------------                
     IF @PROCESSTABLE = 3                   
    BEGIN                   
                  
       UPDATE pt                   
       SET   Priority = 2                    
       FROM   processtablethree pt-- With (tablockx, holdlock)                  
        JOIN ClientMobile opr                   
          ON pt.mobile = opr.mobile                
    WHERE  pt.batchid = @BatchID         
        AND pt.messagestatus=''                   
        AND pt.ProcessID >= @fromid                   
        AND pt.ProcessID <= @toid                   
                                            
                                   
                         
    END                   
     ----------------------------------------------------                      
     IF @PROCESSTABLE = 4                   
     BEGIN                   
                        
                        
        UPDATE pt                   
        SET    Priority = 2               
        FROM   processtablefour pt --With (tablockx, holdlock)                  
        JOIN ClientMobile opr                   
          ON pt.mobile = opr.mobile               
     WHERE  pt.batchid = @BatchID         
         AND pt.messagestatus=''                   
         AND pt.ProcessID >= @fromid                   
         AND pt.ProcessID <= @toid                   
                                                               
                      
                
    END           
         
          IF @@TRANCOUNT > 0                               
            COMMIT                               
        END TRY                               
                                       
        BEGIN CATCH                               
          PRINT 'Insert and Delete Error'                          
                                         
          IF @@TRANCOUNT > 0                               
            ROLLBACK                               
   EXEC Usp_inserterrorinfo                               
        END CATCH                               
                                       
        IF @toid >= @maxid                               
          BREAK                               
                                       
        SET @fromid = @toid + 1                               
        SET @toid = @fromid + @batchsize                               
        IF @toid > @maxid                               
          SET @toid = @maxid                               
      END              
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_ProcessTableServicedeliveryreport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_ProcessTableServicedeliveryreport]  -- 12511,2                         
           @BatchID      BIGINT,                       
           @ProcessTable INT                       
AS                       
  BEGIN                       
 SET NOCOUNT ON                       
    DECLARE  @countrow BIGINT                
    DECLARE  @fromid    BIGINT,                               
             @maxid     BIGINT,                               
             @toid      BIGINT,                               
             @batchsize BIGINT                               
 DECLARE @TABLE_NAME VARCHAR(20)              
 DECLARE @queryFORID NVARCHAR(MAX)              
               
 SET @batchsize = 50000 -- Batchsize can be changed                                  
                                   
    SET @countrow = 0                       
                     
 IF @ProcessTable=1                    
  BEGIN                    
   SET @TABLE_NAME='ProcessTableFirst'                     
  END                    
 ELSE IF @ProcessTable=2                    
  BEGIN                    
   SET @TABLE_NAME='ProcessTableTwo'                     
  END                        
 ELSE IF @ProcessTable=3                    
  BEGIN                    
   SET @TABLE_NAME='ProcessTableThree'                     
  END                        
 ELSE IF @ProcessTable=4                    
  BEGIN                    
   SET @TABLE_NAME='ProcessTableFour'                     
  END                        
                    
SET @queryFORID=' SELECT @fromid = Min(ProcessID) , @maxid = Max(ProcessID)                        
    FROM   '+@TABLE_NAME+'                                       
    WHERE  batchid = '+cast(@BatchID as varchar(20))+''                      
                    
exec sp_executesql @queryFORID,N'@fromid bigint OUTPUT,@maxid bigint OUTPUT', @fromid OUTPUT,@maxid OUTPUT;                     
    
declare @count int=(select (@maxid-@fromid)+1)    
                    
 SET TRANSACTION ISOLATION LEVEL SNAPSHOT ;                                      
 SET XACT_ABORT ON ;                          
                    
                    
     SET @toid = @fromid + @batchsize                                       
                                           
    IF @toid > @maxid  -- Check Condition                                       
      SET @toid = @maxid  -- Set To ID                                       
                                           
WHILE @fromid < = @maxid and @count>0-- Used While Loop                                       
BEGIN                                       
RETRY:
BEGIN TRY                                       
BEGIN TRAN                                       
     IF (@ProcessTable = 1)                       
       BEGIN                       
      INSERT INTO messagedeliverystatus                       
           (messageid,                       
         batchid,                       
         mobile,                       
         MESSAGE,                       
         senderid,                       
         messageinsertdate,                       
         smppid,                       
         u_id,                       
         isunicode,                       
         isdnd,                       
         operator,                       
         messagestatus,                       
         isallowdnd,            
         Priority,DbType )                       
      SELECT top 1000 messageid,                       
          batchid,                       
          mobile,                       
          [message],                       
          senderid,                       
          messageinsertdate,                       
          smppid,                       
          u_id,                       
          isunicode,                       
          isdnd,                       
          operator,                       
          messagestatus,                       
          isallowdnd,            
          Priority,isnull(DbType,0)                          
      FROM   processtablefirst                       
      WHERE  batchid = @BatchID  and processid between @fromid and @fromid+1000                     
         --AND ProcessID >=@fromid                   
         --AND ProcessID <=@toid      
   order by processid    
   set @fromid=@fromid+1000    
   set @count=@count-1000    
       
                    
           END                       
     ELSE                       
       IF (@ProcessTable = 2)                       
      BEGIN                       
        INSERT INTO messagedeliverystatus                       
          (messageid,                       
           batchid,                       
           mobile,                       
           MESSAGE,             
           senderid,                       
           messageinsertdate,                       
           smppid,                       
           u_id,                       
           isunicode,                       
           isdnd,                  
           operator,                       
           messagestatus,                       
           isallowdnd,            
           Priority,DbType )                       
        SELECT top 1000 messageid,                       
         batchid,                       
         mobile,                      
         [message],                       
         senderid,                       
         messageinsertdate,                       
         smppid,                       
         u_id,                       
         isunicode,                       
         isdnd,                       
         operator,                       
         messagestatus,                       
         isallowdnd,            
         Priority ,isnull(DbType,0)                         
        FROM   processtabletwo                       
        WHERE  batchid = @BatchID and processid between @fromid and @fromid+1000                     
         --AND ProcessID >=@fromid                   
         --AND ProcessID <=@toid      
   order by processid    
   set @fromid=@fromid+1000    
   set @count=@count-1000              
      END                       
       ELSE                       
      IF (@ProcessTable = 3)                       
        BEGIN                       
       INSERT INTO messagedeliverystatus                       
          (messageid,                       
          batchid,                       
          mobile,                       
          MESSAGE,                       
          senderid,                       
        messageinsertdate,                       
          smppid,                       
       u_id,                       
          isunicode,                       
          isdnd,                       
          operator,                       
          messagestatus,                       
          isallowdnd,            
          Priority,DbType )                       
       SELECT top 1000 messageid,                       
      batchid,                       
           mobile,                       
           [message],                       
           senderid,                       
           messageinsertdate,                       
           smppid,                       
           u_id,                       
           isunicode,                       
         isdnd,                       
           operator,                       
           messagestatus,                       
           isallowdnd,            
            Priority,isnull(DbType,0)                          
       FROM   processtablethree                       
       WHERE  batchid = @BatchID and processid between @fromid and @fromid+1000                     
         --AND ProcessID >=@fromid                   
         --AND ProcessID <=@toid      
   order by processid    
   set @fromid=@fromid+1000    
   set @count=@count-1000                        
                           
        END                 
      ELSE                       
        IF (@ProcessTable = 4)                       
       BEGIN                       
         INSERT INTO messagedeliverystatus                       
           (messageid,                       
            batchid,                       
            mobile,                       
            MESSAGE,                                 senderid,                       
            messageinsertdate,                       
            smppid,                       
            u_id,                       
            isunicode,                       
            isdnd,                       
            operator,                       
            messagestatus,                       
            isallowdnd,            
            Priority,DbType )                       
         SELECT top 1000 messageid,                       
          batchid,                       
          mobile,                       
          [message],                       
          senderid,                       
          messageinsertdate,                       
          smppid,                       
          u_id,                       
          isunicode,                       
          isdnd,                       
          operator,            
          messagestatus,                       
          isallowdnd,            
          Priority,isnull(DbType,0)                       
         FROM   processtablefour                       
         WHERE  batchid = @BatchID  and processid between @fromid and @fromid+1000                     
         --AND ProcessID >=@fromid                   
         --AND ProcessID <=@toid      
   order by processid    
   set @fromid=@fromid+1000    
   set @count=@count-1000            
                     
         END                                
IF @@TRANCOUNT > 0                                       
COMMIT                                       
END TRY                                       
BEGIN CATCH                                       
PRINT 'Insert and Delete Error'                                  
IF @@TRANCOUNT > 0                                       
ROLLBACK             
EXEC Usp_inserterrorinfo
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number  
			BEGIN  
				WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms  
				GOTO RETRY -- Go to Label RETRY  
			END                                        
END CATCH                                       
                                               
        /*IF @toid >= @maxid                                       
          BREAK                                       
                                               
        SET @fromid = @toid + 1                                       
                                               
        SET @toid = @fromid + @batchsize                                       
                                               
    IF @toid > @maxid                                       
          SET @toid = @maxid*/                                       
 ENd                                      
exec USP_INVALIDNUMBER_DELETE_IN_PROCESSTABLE @BatchID, @ProcessTable                                                    
END 


