/* ============================================================
   Procedure: [dbo].[usp_ProcessTableServiceinsert_messagednd]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_ProcessTableServiceinsert_messagednd]           
           @BatchID      BIGINT,           
           @Priority     TINYINT,           
           @AllowDND     BIT,           
           @ProcessTable INT           
AS           
  DECLARE  @RowcountTemp BIGINT           
             
  BEGIN           
  set nocount on           
    DECLARE  @fromid    BIGINT,           
             @maxid     BIGINT,           
             @toid      BIGINT,           
             @batchsize BIGINT           
               
    SET @batchsize = 50000 -- Batchsize can be changed              
               
    SET @RowcountTemp=0      
    BEGIN TRY           
--SET TRANSACTION ISOLATION LEVEL SNAPSHOT          
          
      BEGIN TRAN           
                 
      IF (@ProcessTable = 1)           
        BEGIN           
          SELECT @fromid = Min(ProcessID),           
                 @maxid = Max(ProcessID)           
          FROM   processtablefirst           
          WHERE  batchid = @BATCHID           
                     
          SET @toid = @fromid + @batchsize           
                     
          IF @toid > @maxid           
            SET @toid = @maxid           
                     
          WHILE @fromid < = @maxid           
            BEGIN           
              IF (@AllowDND = 1)           
                BEGIN           
                  INSERT INTO messagednd           
                             (messageid,           
                              batchid,           
                              mobile,           
                              [message],           
                              senderid,           
                              smppid,           
                              u_id,           
                              priority,           
                              isunicode,           
                              isdnd,           
                              operator,           
                              isallowdnd)           
                  SELECT messageid,           
                         batchid,           
                         mobile,           
                         [message],           
                         senderid,           
                         smppid,           
                         u_id,           
                         @Priority,           
                         isunicode,           
                         isdnd,           
                         operator,           
                         isallowdnd           
                  FROM   processtablefirst           
                  WHERE  batchid = @BatchID  --S    
                         AND priority <> 2           
                         AND messagestatus=''           
                         AND Isnull(spam,0) = 0           
                         AND ProcessID >= @fromid           
                         AND ProcessID <= @toid           
                             
                  SET @RowcountTemp = @@ROWCOUNT           
                             
                  EXEC Usp_inserbatchtrachrecord           
                    @BatchID ,           
                    1 ,           
                    'usp_ProcessTableServiceInsert_MESSAGEDND' ,           
                    1 ,           
                    'ProcessTableFirst' ,           
                    'MessageDND' ,           
                    'INSERT' ,           
                    @RowcountTemp           
                END           
              ELSE           
                IF (@AllowDND = 0)           
                  BEGIN           
                    INSERT INTO messagednd           
                               (messageid,           
                    batchid,           
                                mobile,           
                                [message],          
                                senderid,           
                                smppid,           
                 u_id,           
                                priority,           
                                isunicode,           
             isdnd,           
               operator,           
                                isallowdnd)           
                    SELECT messageid,           
                           batchid,           
                           mobile,           
                     [message],           
                           senderid,           
                           smppid,           
                           u_id,           
                           @Priority,           
                           isunicode,           
                           isdnd,           
                           operator,           
                           isallowdnd           
                    FROM   processtablefirst           
                    WHERE  batchid = @BatchID           
                          AND isdnd = 1           
                           AND priority <> 2           
                           AND messagestatus=''           
                           AND Isnull(spam,0) = 0           
                           AND ProcessID >= @fromid           
                           AND ProcessID <= @toid           
                               
                    SET @RowcountTemp = @@ROWCOUNT           
                               
                    EXEC Usp_inserbatchtrachrecord           
                      @BatchID ,           
                      1 ,           
                      'usp_ProcessTableServiceInsert_MESSAGEDND' ,           
                      1 ,           
                      'ProcessTableFirst' ,           
                      'MessageDND' ,           
                      'INSERT' ,           
                      @RowcountTemp           
                  END           
                         
               --WAITFOR delay '00:00:02' -- wait for 2 seconds             
                         
              IF @toid >= @maxid           
                BREAK           
                         
              SET @fromid = @toid + 1           
                         
              SET @toid = @fromid + @batchsize           
                         
              IF @toid > @maxid           
                SET @toid = @maxid           
            END           
        END           
                 
      IF (@ProcessTable = 2)           
        BEGIN           
          SELECT @fromid = Min(ProcessID),           
                 @maxid = Max(ProcessID)           
          FROM   processtabletwo           
          WHERE  batchid = @BATCHID           
                     
          SET @toid = @fromid + @batchsize           
                     
          IF @toid > @maxid           
            SET @toid = @maxid           
                     
