/* ============================================================
   Procedure: [dbo].[usp_ProcessTableServiceinsert_smsoutbox]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--select top 1000 * from clonemessagedeliverystatus(nolock) where batchid=153364786 order by 1 desc                 
--select top 100 * from errorreportnew(nolock) order by 1 desc  
--select left(payload,40000),right(payload,30408),* from smsoutbox  
--update smsoutbox set processed=0  
--ALTER TABLE smsoutbox  
--ADD CONSTRAINT DF_smsoutbox_Messageid DEFAULT NEWID() FOR Messageid;  
  
--select batchid,count(1),max(messageinsertdate) from clonemessagedeliverystatus(nolock) group by batchid having count(1)>1 order by count(1) desc                 
CREATE   PROC [dbo].[usp_ProcessTableServiceinsert_smsoutbox] --153364786,0,0,1 --1148,0,0,2                                                           
           @BatchID      BIGINT,                                 
           @Priority     TINYINT,                                 
           @AllowDND     BIT,                                 
           @ProcessTable INT                                 
AS    
 print 'entered [usp_ProcessTableServiceinsert_smsoutbox]' 
--declare  @BatchID      BIGINT,                                 
--           @Priority     TINYINT=0,                                 
--           @AllowDND     BIT=0,                                 
--           @ProcessTable INT =1       
  
--     select @BatchID=153364786  
  --set nocount on                          
  BEGIN                                 
                       
 DECLARE  @countrow BIGINT                        
 DECLARE  @TABLE_NAME VARCHAR(50)                        
 DECLARE  @queryFORID NVARCHAR(MAX)                      
 DECLARE  @QUERY NVARCHAR(MAX) ,@personalized int=0 ,@queryForPersonalization  nvarchar(max),@samemessage int,@error nvarchar(1000) ,@messagetext nvarchar(4000) =''                
                                         
    DECLARE  @fromid    BIGINT,                                 
             @maxid     BIGINT,                                 
             @toid      BIGINT,                                 
             @batchsize BIGINT ,@u_id bigint,@dlt_id nvarchar(50),@pe_id nvarchar(50),@route varchar(20),@isflash int=0  
      
select @u_id=dbo.ufn_getuserparentid(userid) from batchinfo(nolock) where batchid=@batchid  
select @dlt_id=DLT_TemplateID,@isflash=flash,@route=[dbo].[fn_getuserfilter_real](@u_id) from DLT_Template_MSG(nolock)  where batchid=@batchid  
select @pe_id=pe_id from DLTdetails (nolock)  where parentid=@u_id  
  
if isnull(@pe_id,'')='' or isnull(@dlt_id,'')=''  
begin
print 'no dlt_id or pe_id'
select @error=case when isnull(@pe_id,'')='' then 'PE_Id ' else 'DLT_ID ' end+ 'is invalid.'   
update MessageDeliveryStatus set MessageStatus='Not Sent' ,StatusDescription=@error,StatusCompletedTime=getdate() where batchid=@batchid  
return;  
end  
  
  
  
if exists(select 1 from Link_smsUrl_dtl(nolock) where batchid=@BatchID)  
begin  
select @personalized=1  
end  
else  
begin  
SET @queryForPersonalization=' SELECT @personalized=CASE WHEN COUNT(DISTINCT message) > 1 THEN 1 ELSE 0 END  
    FROM   '+@TABLE_NAME+'                                       
    WHERE  batchid = '+cast(@BatchID as varchar(20))+''                      
print '@queryForPersonalization: '+@queryForPersonalization                    
exec sp_executesql @queryForPersonalization,N'@personalized int OUTPUT', @personalized OUTPUT;     
end  
  
if @personalized=0  
begin  
set @queryFORID =' select top 1 @messagetext=message from '+@TABLE_NAME+'                                       
    WHERE  batchid = '+cast(@BatchID as varchar(20))+''                      
 print '@queryFORID: '+@queryFORID                    
                   
exec sp_executesql @queryFORID,N'@messagetext nvarchar(4000) OUTPUT', @messagetext OUTPUT;     
end  
  
  
print concat('@u_id:',@u_id,',@dlt_id: ',@dlt_id,',@route: ', @route,',@pe_id: ',@pe_id)  
  
    SET @batchsize = 50000 -- Batchsize can be changed                                    
                                     
    SET @countrow = 0                         
                       
 IF @ProcessTable=1                      
  BEGIN                      
   SET @TABLE_NAME='ProcessTableFirst'                       
  END                      
 ELSE IF @ProcessTable=2                      
BEGIN                      
   SET @TABLE_NAME='ProcessTableTwo'                       
  END                          
 ELSE IF @ProcessTable=3                      
  BEGIN                      
   SET @TABLE_NAME='ProcessTableThree'                       
  END                          
 ELSE IF @ProcessTable=4                      
  BEGIN                      
   SET @TABLE_NAME='ProcessTableFour'                       
  END                          
  
--set @TABLE_NAME='clonemessagedeliverystatus'  
                      
SET @queryFORID=' SELECT @countrow = count(1)  
    FROM   '+@TABLE_NAME+'                                         
    WHERE  batchid = '+cast(@BatchID as varchar(20))                        
  
print  @queryFORID                     
exec sp_executesql @queryFORID,N'@countrow bigint OUTPUT', @countrow OUTPUT;                       
   
  
 select @countrow=@countrow-(select count(1) from MessageDeliveryStatus(nolock) where batchid=@batchid and     
 isnull(messagestatus,'') <> '')    
  
 print concat('@countrow: ',@countrow)  
  
 SET TRANSACTION ISOLATION LEVEL SNAPSHOT ;                                        
 SET XACT_ABORT ON ;                            
      
--WHILE @maxid-@fromid>=0 -- Used While Loop                                         
BEGIN                                         
BEGIN TRY                                         
BEGIN TRAN                                         
                                
SElecT @QUERY = concat(
' DECLARE @payload NVARCHAR(MAX);  
SELECT @payload = 
cast((     
SELECT TOP 1   
batchid,         
rtrim(ltrim(SenderID)) as senderid,         
2 smppid,         
u_id,'
,isnull(@PE_ID,''),' PE_ID,'
,isnull(@DLT_ID,'0'),' DLT_TemplateID,'''
,@route ,''' Route,         
Priority priority,         
IsAllowDND isdnd,'
,@isflash,' isflash,'
,@messagetext,' Message,         
'''' operator,'
,   case when @personalized=0 then 1 else 0 end,' SameMessage,         
isallowdnd,
cast((SELECT      
right(MessageID,9) usertag,     
messageid,                 
''91'' + rtrim(ltrim(Mobile)) Mobile,                 
Replace( replace(dbo.fn_getmessagewithshorturl_m(Message,batchid,mobile,MessageID),char(13),'' ''),
''{#var#}'','''') message,     
dbo.fn_IsUnicode(Replace( replace(dbo.fn_getmessagewithshorturl_m(Message,batchid,mobile,MessageID),char(13),'' ''),
''{#var#}'','''')) IsUnicode             
FROM   ' , @TABLE_NAME , ' WHERE  batchid = ' , CAST(@BatchID AS NVARCHAR(20)) , 
' AND ISNULL(messagestatus, '''') = ''''               
FOR JSON PATH         ) as nvarchar(max)) AS recipients     
FROM ' , @TABLE_NAME , '     WHERE batchid = ' , CAST(@BatchID AS NVARCHAR(20)) , 
'  FOR JSON PATH, WITHOUT_ARRAY_WRAPPER) as nvarchar(max));  
INSERT INTO smsoutbox (QueueName,batchid, payload) 
VALUES (''SMS_RMQ1'',', CAST(@BatchID AS NVARCHAR(20)) , ', @payload); ');   
print @query    
exec sp_executesql @QUERY  
IF @@TRANCOUNT > 0                                         
COMMIT     
  
END TRY                                         
BEGIN CATCH                                         
IF @@TRANCOUNT > 0                                         
ROLLBACK                 
--select ERROR_MESSAGE()  
EXEC Usp_inserterrorinfo                                         
END CATCH                                         
ENd    
exec Usp_InsertMessageDetail_process @batchid,@countrow    
END 


GO

