                         AND Isnull(spam,0) = 0   AND ProcessID  between @fromid and @fromid+1000        
     set @fromid=@fromid+1000                
            IF @@TRANCOUNT > 0                 
       COMMIT                 
    END TRY                 
                     
    BEGIN CATCH                 
      PRINT 'Insert and Delete Error'                 
                       
      IF @@TRANCOUNT > 0                 
        ROLLBACK                 
                       
      EXEC Usp_inserterrorinfo                 
    END CATCH                 
            END                 
        END                 
                       
 -- exec Usp_InsertMessageDetail_process @batchid,@countrow
    
  END 


GO

/* ============================================================
   Procedure: [dbo].[usp_ProcessTableServiceInsertInQueueAirtelThree]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Created on 02 Nov 2011 for OPEN DND(Insert into mesageQueueAirtelThree with userfilter OPEN)
CREATE   PROC [dbo].usp_ProcessTableServiceInsertInQueueAirtelThree         
@Batchid BIGINT,         
@ProcessTable TINYINT        
AS         
  DECLARE  @RowcountTemp BIGINT         
  BEGIN         
	set nocount on         
    DECLARE  @fromid    BIGINT,         
             @maxid     BIGINT,         
             @toid      BIGINT,         
             @batchsize BIGINT         
    SET @batchsize = 50000 -- Batchsize can be changed            
    SET @RowcountTemp = 0      
    BEGIN TRY         
	--SET TRANSACTION ISOLATION LEVEL SNAPSHOT        
      BEGIN TRAN         
      IF (@ProcessTable = 1)         
        BEGIN         
          SELECT @fromid = Min(ProcessID),@maxid = Max(ProcessID)FROM processtablefirst WHERE  batchid = @BATCHID              SET @toid = @fromid + @batchsize         
          IF @toid > @maxid         
          SET @toid = @maxid         
          WHILE @fromid < = @maxid         
            BEGIN         
					INSERT INTO MessageQueueAirtelThree(messageid,batchid,mobile,[message],senderid,smppid,u_id,						priority,isunicode,isdnd,operator,isallowdnd)         
					SELECT messageid,batchid,mobile,[message],senderid,smppid,u_id,0,isunicode,isdnd,operator,							isallowdnd FROM processtablefirst         
					WHERE  batchid = @BatchID         
                         AND priority <> 2         
                         AND messagestatus=''        
                         AND ProcessID >= @fromid         
                         AND ProcessID <= @toid         
                  SET @RowcountTemp = @@ROWCOUNT         
                  EXEC Usp_inserbatchtrachrecord         
                    @BatchID ,         
                    1 ,         
                    'usp_InsertInQueueAirtelThree' ,         
                    1 ,         
                    'ProcessTableFirst' ,         
                    'MessageQueue' ,         
                    'Update' ,         
                    @RowcountTemp         
                         
              IF @toid >= @maxid         
              BREAK         
              SET @fromid = @toid + 1         
              SET @toid = @fromid + @batchsize         
              IF @toid > @maxid         
              SET @toid = @maxid         
            END         
        END         
               
      IF (@ProcessTable = 2)         
        BEGIN         
          SELECT @fromid = Min(ProcessID),@maxid = Max(ProcessID)FROM processtabletwo WHERE batchid = @BATCHID                 SET @toid = @fromid + @batchsize         
          IF @toid > @maxid         
          SET @toid = @maxid         
          WHILE @fromid < = @maxid         
            BEGIN         
				    INSERT INTO MessageQueueAirtelThree(messageid,batchid,mobile,[message],senderid,smppid,u_id,						priority,isunicode,isdnd,operator,isallowdnd)         
					SELECT messageid,batchid,mobile,[message],senderid,smppid,u_id,0,isunicode,isdnd,operator,					isallowdnd FROM processtabletwo         
					WHERE  batchid = @BatchID         
                    AND priority <> 2         
                    AND messagestatus=''        
                    AND ProcessID >= @fromid         
                    AND ProcessID <= @toid         
                          
                  SET @RowcountTemp = @@ROWCOUNT         
                           
                  EXEC Usp_inserbatchtrachrecord         
                    @BatchID ,        
                    1 ,         
                    'usp_InsertInQueueAirtelThree' ,         
					1 ,         
                    'ProcessTableTwo' ,         
                    'MessageQueue' ,         
                    'Update' ,         
           @RowcountTemp         
              
              IF @toid >= @maxid         
                BREAK         
                       
              SET @fromid = @toid + 1         
                       
              SET @toid = @fromid + @batchsize         
                       
              IF @toid > @maxid         
                SET @toid = @maxid         
            END         
        END         
               
      IF (@ProcessTable = 3)         
        BEGIN         
          SELECT @fromid = Min(ProcessID),         
                 @maxid = Max(ProcessID)         
          FROM   processtablethree         
          WHERE  batchid = @BATCHID         
                   
          SET @toid = @fromid + @batchsize         
                   
          IF @toid > @maxid         
            SET @toid = @maxid         
                   
          WHILE @fromid < = @maxid         
            BEGIN         
             INSERT INTO MessageQueueAirtelThree(messageid,batchid,mobile,[message],senderid,smppid,u_id,						priority,isunicode,isdnd,operator,isallowdnd)         
					SELECT messageid,batchid,mobile,[message],senderid,smppid,u_id,0,isunicode,isdnd,operator,					isallowdnd FROM processtablethree         
                  WHERE  batchid = @BatchID         
                         AND priority <> 2         
                         AND messagestatus=''        
                         AND ProcessID >= @fromid         
                         AND ProcessID <= @toid         
                           
                  SET @RowcountTemp = @@ROWCOUNT         
                           
                  EXEC Usp_inserbatchtrachrecord         
                    @BatchID ,         
                    1 ,         
                    'usp_InsertInQueueAirtelThree' ,         
                    1 ,         
                    'ProcessTableThree' ,         
                    'MessageQueue' ,         
                    'Update' ,         
                    @RowcountTemp         
                         
              IF @toid >= @maxid         
                BREAK         
                       
              SET @fromid = @toid + 1         
                       
              SET @toid = @fromid + @batchsize         
                       
              IF @toid > @maxid         
                SET @toid = @maxid         
            END         
        END         
               
      IF (@ProcessTable = 4)         
        BEGIN         
          SELECT @fromid = Min(ProcessID),@maxid = Max(ProcessID)FROM processtablefour WHERE  batchid = @BATCHID     			SET @toid = @fromid + @batchsize         
			IF @toid > @maxid         
            SET @toid = @maxid         
			WHILE @fromid < = @maxid         
            BEGIN         
            INSERT INTO MessageQueueAirtelThree(messageid,batchid,mobile,[message],senderid,smppid,u_id,						priority,isunicode,isdnd,operator,isallowdnd)         
			SELECT messageid,batchid,mobile,[message],senderid,smppid,u_id,0,isunicode,isdnd,operator,							isallowdnd FROM processtablefour         
                  WHERE  batchid = @BatchID         
                         AND priority <> 2         
                         AND messagestatus=''        
                         AND ProcessID >= @fromid         
                         AND ProcessID <= @toid         
                  SET @RowcountTemp = @@ROWCOUNT         
                  EXEC Usp_inserbatchtrachrecord         
                    @BatchID ,         
                    1 ,         
                    'usp_InsertInQueueAirtelThree' ,         
                    1 ,         
                    'ProcessTableFour' ,         
                    'MessageQueue' ,         
                    'Update' ,         
                    @RowcountTemp         
              IF @toid >= @maxid         
                BREAK         
              SET @fromid = @toid + 1         
              SET @toid = @fromid + @batchsize         
              IF @toid > @maxid         
                SET @toid = @maxid         
            END         
        END         
      IF @@TRANCOUNT > 0         
        COMMIT         
    END TRY         
    BEGIN CATCH         
      PRINT 'Insert and Delete Error'         
      IF @@TRANCOUNT > 0         
        ROLLBACK         
      EXEC Usp_inserterrorinfo         
    END CATCH         
  END         


GO

