/* ============================================================
   Procedure: [dbo].[usp_ProcessTableServicetopfiveandbottomfiveno]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

     
CREATE   PROC [dbo].[usp_ProcessTableServicetopfiveandbottomfiveno] --123,1                             
           @BATCHID   BIGINT,             
           @TABLENAME TINYINT             
AS             
  BEGIN             
    set nocount on             
    DECLARE  @RowcountTemp BIGINT             
    SET @RowcountTemp = 0             
    BEGIN TRY             
SET TRANSACTION ISOLATION LEVEL SNAPSHOT            
      BEGIN TRAN             
                   
      --- pROCESS TABLE oNE             
      IF @TABLENAME = 1             
        BEGIN             
          WITH q             
               AS (SELECT   TOP ( 5 ) *             
                   FROM     processtablefirst             
                   WHERE    isdnd = 0             
                            AND messagestatus=''            
                            AND Isnull(spam,0) = 0 
                            AND batchid=@BATCHID           
                   ORDER BY ProcessID DESC)   --S          
          UPDATE q             
          SET    priority = 2 ;            
                       
          SET @RowcountTemp = @@ROWCOUNT;             
                       
          WITH r             
               AS (SELECT   TOP ( 5 ) *             
                   FROM     processtablefirst             
                   WHERE    isdnd = 0             
                            AND messagestatus=''            
                            AND Isnull(spam,0) = 0
                            AND batchid=@BATCHID             
                   ORDER BY ProcessID ASC)             
          UPDATE r             
          SET    priority = 2;             
                       
          SET @RowcountTemp = @RowcountTemp + @@ROWCOUNT  
		  
if exists(select top 1 'x' from Link_smsUrl_dtl where BatchID =@BATCHID)
begin
;WITH cte AS (SELECT mobile,batchid,ROW_NUMBER() OVER (PARTITION BY mobile,batchid ORDER BY mobile) row_num
FROM processtablefirst where batchid=@batchid)
DELETE FROM cte WHERE row_num > 1;
;WITH cte1 AS (SELECT mobile,batchid,ROW_NUMBER() OVER (PARTITION BY mobile,batchid ORDER BY mobile) row_num
FROM link_smsmobile where batchid=@batchid)
DELETE FROM cte1 WHERE row_num > 1;
end           
                       
          EXEC Usp_inserbatchtrachrecord             
            @BatchID ,             
            1 ,             
            'usp_ProcessTableServicetopfiveandbottomfiveno' ,             
            1 ,             
            'ProcessTableFirst' ,             
            'ProcessTableFirst' ,             
            'Update' ,             
            @RowcountTemp             
        END             
      --- pROCESS TABLE TWO             
      ELSE             
        IF @TABLENAME = 2             
          BEGIN             
            WITH q             
                 AS (SELECT   TOP ( 5 ) *             
                     FROM     processtabletwo             
                     WHERE    isdnd = 0             
                              AND messagestatus=''            
                              AND Isnull(spam,0) = 0 
                              AND batchid=@BATCHID            
                     ORDER BY ProcessID DESC)             
            UPDATE q             
            SET    priority = 2;             
                         
            SET @RowcountTemp = @@ROWCOUNT;             
                         
            WITH r             
                 AS (SELECT   TOP ( 5 ) *             
                     FROM     processtabletwo             
                     WHERE    isdnd = 0             
                              AND messagestatus=''            
                              AND Isnull(spam,0) = 0
                              AND batchid=@BATCHID             
                     ORDER BY ProcessID ASC)             
            UPDATE r             
            SET    priority = 2 ;            
                         
            SET @RowcountTemp = @RowcountTemp + @@ROWCOUNT   
			
if exists(select top 1 'x' from Link_smsUrl_dtl where BatchID =@BATCHID)
begin
;WITH cte AS (SELECT mobile,batchid,ROW_NUMBER() OVER (PARTITION BY mobile,batchid ORDER BY mobile) row_num
FROM ProcessTableTwo where batchid=@batchid)
DELETE FROM cte WHERE row_num > 1;
;WITH cte1 AS (SELECT mobile,batchid,ROW_NUMBER() OVER (PARTITION BY mobile,batchid ORDER BY mobile) row_num
FROM link_smsmobile where batchid=@batchid)
DELETE FROM cte1 WHERE row_num > 1;
end           

			          
                         
            EXEC Usp_inserbatchtrachrecord             
              @BatchID ,             
