                         FROM     processtablefour             
                         WHERE    isdnd = 0             
                                  AND messagestatus=''            
                                  AND Isnull(spam,0) = 0 
                                  AND batchid=@BATCHID            
                         ORDER BY ProcessID DESC)             
                UPDATE q             
