                SET @RowcountTemp = @@ROWCOUNT;             
                             
                WITH r             
                     AS (SELECT   TOP ( 5 ) *             
                         FROM     processtablefour             
                         WHERE    isdnd = 0             
                                  AND messagestatus=''            
                                  AND Isnull(spam,0) = 0 
                                  AND batchid=@BATCHID            
                         ORDER BY ProcessID ASC)             
                UPDATE r             
                SET    priority = 2             
                             
                SET @RowcountTemp = @RowcountTemp + @@ROWCOUNT             

if exists(select top 1 'x' from Link_smsUrl_dtl where BatchID =@BATCHID)
begin
;WITH cte AS (SELECT mobile,batchid,ROW_NUMBER() OVER (PARTITION BY mobile,batchid ORDER BY mobile) row_num
FROM processtablefour where batchid=@batchid)
DELETE FROM cte WHERE row_num > 1;
;WITH cte1 AS (SELECT mobile,batchid,ROW_NUMBER() OVER (PARTITION BY mobile,batchid ORDER BY mobile) row_num
FROM link_smsmobile where batchid=@batchid)
DELETE FROM cte1 WHERE row_num > 1;
end           

                             
                EXEC Usp_inserbatchtrachrecord             
                  @BatchID ,             
                  1 ,             
                  'usp_ProcessTableServicetopfiveandbottomfiveno' ,             
                  1 ,             
                  'ProcessTableFour' ,             
                  'ProcessTableFour' ,             
                  'Update' ,             
                  @RowcountTemp             
              END             
                   
      IF @@TRANCOUNT > 0             
        COMMIT             
    END TRY             
                 
    BEGIN CATCH             
      PRINT 'Insert and Delete Error'             
                   
      IF @@TRANCOUNT > 0             
        ROLLBACK             
                   
      EXEC Usp_inserterrorinfo             
    END CATCH             
  END             


