/* ============================================================
   Procedure: [dbo].[usp_ProcessTableServicetruncatetable]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_ProcessTableServicetruncatetable]  --12511,2     
           @batchid      BIGINT,   
           @ProcessTable INT   
AS   
  BEGIN  
 set nocount on    
    DECLARE  @countrow BIGINT   
       
    IF (@ProcessTable = 1)   
      BEGIN   
        TRUNCATE TABLE processtablefirst   
           
        SET @countrow = @@ROWCOUNT   
           
        EXEC Usp_inserbatchtrachrecord   
          @batchid ,   
          1 ,   
          'USP_TruncateTable' ,   
          1 ,   
          'ProcessTableFirst' ,   
          '' ,   
          'TruncateTable' ,   
          @countrow   
      END   
    ELSE   
      IF (@ProcessTable = 2)   
        BEGIN   
          TRUNCATE TABLE processtabletwo   
             
          SET @countrow = @@ROWCOUNT   
             
          EXEC Usp_inserbatchtrachrecord   
            @batchid ,   
            1 ,   
            'USP_TruncateTable' ,   
            1 ,   
            'ProcessTableTwo' ,   
            '' ,   
            'TruncateTable' ,   
            @countrow   
        END   
      ELSE   
        IF (@ProcessTable = 3)   
          BEGIN   
            TRUNCATE TABLE processtablethree   
               
            SET @countrow = @@ROWCOUNT   
               
            EXEC Usp_inserbatchtrachrecord   
              @batchid ,   
              1 ,   
              'USP_TruncateTable' ,   
              1 ,   
              'ProcessTableThree' ,   
              '' ,   
              'TruncateTable' ,   
              @countrow   
          END   
        ELSE   
          IF (@ProcessTable = 4)   
            BEGIN   
              TRUNCATE TABLE processtablefour   
                 
              SET @countrow = @@ROWCOUNT   
                 
              EXEC Usp_inserbatchtrachrecord   
                @batchid ,   
                1 ,   
                'USP_TruncateTable' ,   
                1 ,   
                'ProcessTableFour' ,   
                '' ,   
                'TruncateTable' ,   
                @countrow   
            END   
  END   
  
  
  
  


GO

/* ============================================================
   Procedure: [dbo].[usp_ProcessTableServiceupdatespamfiltermessage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_ProcessTableServiceupdatespamfiltermessage]       
           @BATCHID BIGINT,       
           @TABLENO TINYINT       
AS       
  BEGIN       
    set nocount on       
    DECLARE  @fromid    BIGINT,       
             @maxid     BIGINT,       
             @toid      BIGINT,       
             @batchsize BIGINT       
           
    SET @batchsize = 50000 -- Batchsize can be changed        
           
    BEGIN TRY       
--SET TRANSACTION ISOLATION LEVEL SNAPSHOT      
      BEGIN TRAN       
             
      -- PROCESS TABLE ONE       
      IF @TABLENO = 1       
        BEGIN       
          SELECT @fromid = Min(ProcessID),       
                 @maxid = Max(ProcessID)       
          FROM   processtablefirst       
          WHERE  batchid = @BATCHID       
                 
          SET @toid = @fromid + @batchsize       
                 
          IF @toid > @maxid       
            SET @toid = @maxid       
                 
          WHILE @fromid < = @maxid       
            BEGIN       
              /*UPDATE processtablefirst With (tablockx, holdlock)      
              SET    spam = 1       
              WHERE  Isnull(dbo.Fn_findspam(MESSAGE),0) <> 0       
                     AND batchid = @BatchID       
                     AND ProcessID >= @fromid       
                     AND ProcessID <= @toid */      
                     
              -- --WAITFOR delay '00:00:02' -- wait for 02 second       
                     
              IF @toid >= @maxid       
                BREAK       
                     
              SET @fromid = @toid + 1       
                     
              SET @toid = @fromid + @batchsize       
                     
              IF @toid > @maxid       
                SET @toid = @maxid       
            END       
        END       
      -- PROCESS TABLE TWO       
      ELSE       
        IF @TABLENO = 2       
          BEGIN       
            SELECT @fromid = Min(ProcessID),       
                   @maxid = Max(ProcessID)       
            FROM   processtabletwo       
            WHERE  batchid = @BATCHID       
                   
            SET @toid = @fromid + @batchsize       
                   
            IF @toid > @maxid       
              SET @toid = @maxid       
                   
            WHILE @fromid < = @maxid       
              BEGIN       
                /*UPDATE processtabletwo With (tablockx, holdlock)      
                SET    spam = 1       
                WHERE  Isnull(dbo.Fn_findspam(MESSAGE),0) <> 0       
                       AND batchid = @BatchID       
                       AND ProcessID >= @fromid       
                       AND ProcessID <= @toid*/       
                       
                -- --WAITFOR delay '00:00:02' -- wait for 02 second       
                       
                IF @toid >= @maxid       
                  BREAK       
                       
                SET @fromid = @toid + 1       
                       
                SET @toid = @fromid + @batchsize       
                       
                IF @toid > @maxid       
                  SET @toid = @maxid       
              END       
          END       
        -- PROCESS TABLE THREE       
        ELSE       
          IF @TABLENO = 3       
            BEGIN       
              SELECT @fromid = Min(ProcessID),       
                     @maxid = Max(ProcessID)       
              FROM   processtablethree       
              WHERE  batchid = @BATCHID       
                     
              SET @toid = @fromid + @batchsize       
                     
              IF @toid > @maxid       
                SET @toid = @maxid       
                     
              WHILE @fromid < = @maxid       
                BEGIN       
                  /*UPDATE processtablethree With (tablockx, holdlock)      
                  SET    spam = 1       
                  WHERE  Isnull(dbo.Fn_findspam(MESSAGE),0) <> 0       
                         AND batchid = @BatchID      
         AND ProcessID >= @fromid       
                         AND ProcessID <= @toid */      
                         
                  -- --WAITFOR delay '00:00:02' -- wait for 02 second       
                         
                  IF @toid >= @maxid       
                    BREAK       
                                       SET @fromid = @toid + 1       
                         
                  SET @toid = @fromid + @batchsize       
                         
                  IF @toid > @maxid       
                    SET @toid = @maxid       
                END       
            END       
          -- PROCESS TABLE FOUR       
          ELSE       
            IF @TABLENO = 4       
              BEGIN       
                SELECT @fromid = Min(ProcessID),       
                       @maxid = Max(ProcessID)       
                FROM   processtablefour       
                WHERE  batchid = @BATCHID       
                       
                SET @toid = @fromid + @batchsize       
                       
                IF @toid > @maxid       
                  SET @toid = @maxid       
                       
                WHILE @fromid < = @maxid       
                  BEGIN       
                    /*UPDATE processtablefour With (tablockx, holdlock)      
                    SET    spam = 1       
                    WHERE  Isnull(dbo.Fn_findspam(MESSAGE),0) <> 0       
                           AND batchid = @BatchID       
                           AND ProcessID >= @fromid       
                           AND ProcessID <= @toid  */     
                           
                    -- --WAITFOR delay '00:00:02' -- wait for 02 second       
                           
                    IF @toid >= @maxid       
                      BREAK       
                           
                    SET @fromid = @toid + 1       
                           
                    SET @toid = @fromid + @batchsize       
                           
                    IF @toid > @maxid       
                      SET @toid = @maxid       
                  END       
              END       
             
      IF @@TRANCOUNT > 0       
        COMMIT       
    END TRY       
           
    BEGIN CATCH       
      PRINT 'Insert and Delete Error'       
             
      IF @@TRANCOUNT > 0       
        ROLLBACK       
             
      EXEC Usp_inserterrorinfo       
    END CATCH -- Alter by raghwendra END           
  END       
      
    
    


GO

/* ============================================================
   Procedure: [dbo].[Usp_ProcessUpdateEnquiryImportData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--Usp_ProcessUpdateEnquiryImportData @ImpID=46, @mode='P', @Batchsize=0
CREATE   PROCEDURE [dbo].[Usp_ProcessUpdateEnquiryImportData]
@ImpID bigint =0,
@mode nvarchar(2)='P',
@Batchsize int =1 
as

begin
	              
	BEGIN TRY
	--BEGIN TRANSACTION     

	Drop Table if exists #ProcessImportData
	drop table if exists #DetailsTable 
	drop table if exists #ColTable 
	drop table if exists #UpdateDetails 
	drop table if exists #CustdataTable
	declare @sqls nvarchar(max)='', @TblColName nvarchar (max) , @CustColName nvarchar(max) , @CustFileName nvarchar(max), @CustName nvarchar(max), @custSqls nvarchar(max) = '', @FieldNames nvarchar(max)
	,@params nvarchar(500) = '', @altTable nvarchar(max),@min int=0 , @max int =0, @Importdata nvarchar(max), @Userid bigint, @Parentid bigint, @rowData nvarchar(2000)
	,@upmin bigint , @upmax bigint , @pagesize bigint = 500,@UpdateFields nvarchar(max)='',@row int = 1  , @custcount int, @fieldid bigint  , @fieldtype nvarchar(1), @fieldname nvarchar(100), @totaldata int,
	@Remarks nvarchar(max) , @Enquirycount int  , @ImportId bigint,@eventname nvarchar(100),@eventdescription nvarchar(max),@userlogin nvarchar(50)



	Create Table #ProcessImportData (RowID int identity , 
				ImportID bigint ,
				UserID bigint , 
				) 
	if(ISNULL(@ImpID,0) >0)
	BEGIN
		Insert into #ProcessImportData (ImportID, UserID)
		Select ImportRow_ID, User_id from Tbl_Enquiry_EnquiryUpdateImportData (NOLOCK) where ImportRow_Id=@ImpID
	END
	else 
	begin
		if @mode='P'
		BEGIN
			if(@Batchsize<>0)
			begin
				Insert into #ProcessImportData (ImportID, UserID)
				Select top (@Batchsize) ImportRow_ID, User_id from Tbl_Enquiry_EnquiryUpdateImportData (NOLOCK) where IsProcessed=0 Order by Priority Asc
			end
			else
			begin
				Insert into #ProcessImportData (ImportID, UserID)
				Select ImportRow_ID, User_id from Tbl_Enquiry_EnquiryUpdateImportData (NOLOCK) where IsProcessed=0 Order by Priority Asc
			end
		END
		else
		begin
			if(@Batchsize<>0)
			begin
				Insert into #ProcessImportData (ImportID, UserID)
				Select top (@Batchsize) ImportRow_ID, User_id from Tbl_Enquiry_EnquiryUpdateImportData (NOLOCK) where IsProcessed=0 
			end
			else
			begin
				Insert into #ProcessImportData (ImportID, UserID)
				Select ImportRow_ID, User_id from Tbl_Enquiry_EnquiryUpdateImportData (NOLOCK) where IsProcessed=0 
			end
		end
	end
	
	--select 'processdata', * from #ProcessImportData 

	Select  @max = Count (*)  from #ProcessImportdata

	select @TblColName= '''SNo'''+','+ STRING_AGG(''''+Column_name+'''',',') from INFORMATION_SCHEMA.COLUMNS (Nolock) where TABLE_NAME='Userenquiry'
	
	While (@min < @max)
	BEGIN
		drop table if exists #DetailsTable 
		drop table if exists #ColTable 
		drop table if exists #UpdateDetails 
		drop table if exists #FieldResTemp
		drop table if exists #CustdataTable
		drop table if exists #CustomData
		drop table if exists #UpdateCustomfields
		create table #UpdateCustomfields (RowNo int,SNo int, Fieldid bigint, FieldName nvarchar(100), enquiryid bigint, FieldValue nvarchar(2000))
		 Create table #FieldResTemp (SNo int, Field nvarchar(100), Remarks nvarchar(2000))
		declare @start bigint = 0 , @end bigint = 499

		Select   @userid= UserID, @ImportId = ImportID from #ProcessImportdata where RowID = @min +1
		Update Tbl_Enquiry_EnquiryUpdateImportData set IsProcessed=0, Remarks ='[{"SNo":0,"Status":"Under Process","Remarks":"Under Process"}]', importstart = GETDATE() where ImportRow_ID=@ImportId
		select @Importdata = Importdata from Tbl_Enquiry_EnquiryUpdateImportData (Nolock) where ImportRow_Id=@ImportId

		Select @Parentid = ParentID from User_detail (NoLock)  where User_id= @userid
		--select @Importdata,@ImportId
		select top 1 @rowData = [value] from openJson(@Importdata)
		Create  Table #ColTable (id int identity, [Key] nvarchar(200), [Value] nvarchar(max)) 
		Create  Table #CustomData (rowid int identity, FieldID bigint, FieldName nvarchar(200)) 
		--select @Importdata, @rowData, @TblColName

		set @params = N'@rowData nvarchar(max)'
		set @sqls='insert into #ColTable ([Key],[Value]) select [Key],[Value]  from openJson(@rowData)' 
		print @sqls
		execute sp_executesql @sqls , @params, @rowData=@rowData

		--select * from #ColTable
		
		insert into #CustomData (FieldID, FieldName)
		select field_ID,fieldname from customfields (NoLock) where ParentID=@parentid and isActive=1 and datatype<>'f' and  fieldname in (Select [Key] from #ColTable) 
	
		select @UpdateFields= STRING_AGG('ul.'+[key]+' = dt.'+[key],', ') from #ColTable where  [key] not in ('SNo','EnquiryID','CountryCode','MobileNo','EmailID') and [KEY] not in (Select fieldname from customfields (nolock) where parentid=@parentid)

		select @FieldNames = STRING_agg([key] +' nvarchar(2000)',', ') from #ColTable where [KEY] not in (Select fieldname from customfields (nolock) where parentid=@parentid)
		select @CustColName = STRING_agg([key] +' nvarchar(2000)',', ') from #ColTable where [KEY]  in  (Select fieldname from customfields (nolock) where parentid=@parentid) or  [key] in ('SNo','EnquiryID','CountryCode','MobileNo','EmailID')
		select @CustFileName = String_agg([key],',') from #ColTable where [KEY]  in (Select fieldname from customfields (nolock) where parentid=@parentid)

		--select @FieldNames 
		Create table #DetailsTable (parentid bigint)
		 Create table #CustdataTable (parentid bigint)
		

		set @altTable = 'alter table #DetailsTable add ' + @FieldNames  
		execute sp_executesql @altTable
		
		set @altTable = 'alter table #CustdataTable add ' + @CustColName  
		execute sp_executesql @altTable

		set @params = N'@Impdata nvarchar(max)'
		set @sqls  ='insert into #DetailsTable select '+cast(@parentid as varchar)+', * from openJson(@Impdata) with ('+@FieldNames+')'
		print @sqls
		execute sp_executesql @sqls, @params, @Impdata= @Importdata
		
		set @params = N'@Impdata nvarchar(max)'
		set @sqls  ='insert into #CustdataTable select '+cast(@parentid as varchar)+', * from openJson(@Impdata) with ('+@CustColName+')'
		print @sqls
		execute sp_executesql @sqls, @params, @Impdata= @Importdata
	
		select @totaldata=count(1)  from #detailstable 
		--select *  from #detailstable
		set @sqls ='if exists (select 1 from #DetailsTable where ISnull(Enquiryid,'''')='''')
		begin
			Insert into #FieldResTemp (SNo,Field,Remarks)
			select Sno, ''EnquiryID'' Field,  ''Please enter Enquiryid'' Remarks from #detailstable where ISnull(Enquiryid,'''')=''''
		ENd

		if exists (select 1 from #DetailsTable where ISNULL(MobileNO,'''')<>'''' AND ISNULL(CountryCode,'''')='''')
		BEGIN
			Insert into #FieldResTemp (SNo,Field,Remarks) 
			Select Sno, ''CountryCode'' Field, ''Enter CountryCode is mandatory with MobileNO'' from #DetailsTable where ISNULL(MobileNO,'''')<>'''' AND ISNULL(CountryCode,'''')=''''
		END
		'
		print @sqls
		execute sp_executesql @sqls

		if exists (select 1 from #ColTable where [Key]='PinCode')
		begin
			set @sqls= 'Insert into #FieldResTemp (SNo,Field,Remarks)select Sno,''Pincode'' Field,  ''Invalid Pincode'' Remarks from #detailstable where ISNUMERIC(PinCode)=0'
				execute sp_executesql @sqls
		end

	
		
		set @row = 1
		set  @custcount = (select count(1) from #CustomData)
		--select * from #CustomData
		--select * from #CustdataTable

		while(@row<=@custcount)
		begin
			drop table if exists #customdetails
			drop table if exists #customdetails1
			create table #customdetails (Rowid int identity,SNo bigint, fieldid bigint, fieldname nvarchar(100) , fieldtype varchar(1), FieldValue nvarchar(2000), Enquiryid bigint )

			Select @fieldid= fieldid ,@fieldname=cf.Fieldname, @fieldtype=cf.datatype from #CustomData cd join customfields cf on cf.field_id = cd.fieldid    where rowid=@row
			
			set @sqls= 'insert into #customdetails (SNo, fieldid,fieldname,fieldtype,FieldValue, Enquiryid)
			select dt.SNo, '+cast(@fieldid as varchar)+' fieldid , '''+@fieldname+''' fieldname, '''+@fieldtype+''' fieldtype , '+@fieldname+' as FieldValue, ul.EnquiryID Enquiryid from #CustdataTable dt
						join userEnquiry (NoLock) ul
			on  ul.EnquiryID=  dt.EnquiryID

			AND ((ul.CountryCode = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode
								else ul.CountryCode
								end
			AND ul.MobileNo = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno
								else ul.MobileNo
								end
				)	
			OR (ul.CountryCode1 = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode
								else ul.CountryCode1
								end
			AND ul.MobileNo1 = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno
								else ul.MobileNo1
								end
								)
			OR (ul.CountryCode2 = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode
								else ul.CountryCode2
								end
			AND ul.MobileNo2 = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno
								else ul.MobileNo2
								end
								))
			AND ( Ul.EmailID = case when isnull(dt.emailid,'''')<>'''' then dt.emailid
								else ul.EmailID
								end
			or Ul.EmailID1 = case when isnull(dt.emailid,'''')<>'''' then dt.emailid
								else ul.EmailID1
								end
			or Ul.EmailID2 = case when isnull(dt.emailid,'''')<>'''' then dt.emailid
								else ul.EmailID2
								end )
			Where ul.parentid = '+cast(@parentid as varchar)  
				print @sqls
				execute sp_executesql @sqls
				
			select cd.*, case
						when  cd.fieldtype ='f' 
						Then IIF(CAST(cd.fieldvalue AS BIGINT) >= ISNULL(CAST(cf.minvalue as  BIGINT),-2222222222222222) AND CAST(cd.fieldvalue AS BIGINT) <= ISNULL (CAST(cf.maxvalue as BIGINT),2222222222222222),
							'0','Number not in Custom Field Range')              
						when  cd.fieldtype='D' 
						Then IIF(CAST(cd.fieldvalue AS date) >= CAST(ISNULL (cf.minvalue,'') as date) and              
								 CAST(cd.fieldvalue AS date) <= IIF ( ISNULL(cf.maxvalue,'') <> '', cast(cf.maxvalue as date),cast ('9999-01-01'as date)) ,'0','Date not in Custom Field Range')  
						when cf.datatype in ('r','s','l') and cf.choices is not null               
						then IIF(cast(1 as varchar) = (select distinct 1 from dbo.fn_Split(cf.choices,',') splt 
														where CAST(splt.value AS nvarchar(max)) in (select distinct VALUE from dbo.fn_Split(cf.choices,','))),'0','Value not matches with Custom Field Choices')              
						when cf.datatype in ('r','s','l') and  cf.choices IS NULL              
						then '0'
						ELSE '0'
			end Error INTO #customdetails1
			from #customdetails cd 
			join customfields (NoLock) cf on cd.fieldid = cf.field_id

			Insert into  #FieldResTemp (SNo,Field,Remarks)
			Select SNo, FieldName , Error from #customdetails1 where Error <> '0'

			insert  into #UpdateCustomfields (RowNo ,SNo, Fieldid, FieldName, enquiryid, FieldValue ) 
			Select  ROW_NUMBER () over (Order by Sno) RowNo, SNo, Fieldid, FieldName, Enquiryid, FieldValue from #customdetails1 where Sno not in (Select Sno from #FieldResTemp )

			--select * from #customdetails
			--Select * from #customdetails1


				set @row=@row+1 
		end
		select ROW_NUMBER () over (Order by Sno) RowID,* into #UpdateDetails from #detailstable where SNo not in (select SNo from #FieldResTemp )
		
		--Select * from #FieldresTemp
		--select * from #UpdateDetails
		
		 if(exists (select 1 from #ColTable where [Key] = 'SourceName' ))
           begin
		     drop table if exists #TempSource
			 drop table if exists #TempSourceWithRow

			 select distinct SourceName, ParentID into  #TempSource from #UpdateDetails order by SourceName desc 
			 select row_number() over(order by SourceName asc) as RowNum, SourceName, ParentID into #TempSourceWithRow from #TempSource --order by SourceName desc
			 declare @CountSource int = isnull((select count(1) from #TempSourceWithRow) ,0)
			 declare @RowNumSource int = 1

			 declare @Source_NameTemp nvarchar(200) = ''
		     declare @Source_IDTemp bigint = 0
			 declare @Source_ParentIDTemp bigint = 0


			 alter table #TempSourceWithRow
			 add SourceID nvarchar(200) 

			 while(@CountSource > 0)
			   begin

			      select top 1 @Source_NameTemp = SourceName, @Source_ParentIDTemp = ParentID from #TempSourceWithRow where RowNum = @RowNumSource
				  
				 if(exists( select 1 from UserSourceSettings with(nolock) where Name = @Source_NameTemp and  UserID = @Source_ParentIDTemp ))
				       begin
					     select top 1  @Source_IDTemp = SourceID from UserSourceSettings with(nolock) where Name = @Source_NameTemp and  UserID = @Source_ParentIDTemp  
					  end
                   else
				      begin
					    insert into UserSourceSettings 
						 (Name,UserID,IsEditable,IsActive,CreatedDate,ModifiedDate,ModifiedBy)
                        select @Source_NameTemp,@Source_ParentIDTemp, 1,1,getdate(),getdate(), @Source_ParentIDTemp  

						  select  @Source_IDTemp = SCOPE_IDENTITY()
					  end

                   if(isnull(@Source_IDTemp,0) > 0 )
				      begin
					      update #TempSourceWithRow set SourceID =  cast(@Source_IDTemp as nvarchar)  where RowNum = @RowNumSource 
					  end
                         
                   set  @Source_IDTemp = 0    
				   set @RowNumSource = @RowNumSource +1 
				   set @CountSource = @CountSource - 1  

			   end
             
			  update t set t.SourceName =  s.SourceID from #UpdateDetails as t
			           join #TempSourceWithRow as s
					   on t.sourceName = s.SourceName

             -- select * from  #UpdateDetails 
			 drop table if exists #TempSource
			 drop table if exists #TempSourceWithRow
		   end
          
		  if(exists (select 1 from #ColTable where [Key] = 'MediumName' ))
           begin
		     drop table if exists #TempMedium
			 drop table if exists #TempMediumWithRow

			 select distinct MediumName, ParentID into  #TempMedium from #UpdateDetails order by MediumName desc 
			 select row_number() over(order by MediumName asc) as RowNum, MediumName, ParentID into #TempMediumWithRow from #TempMedium --order by SourceName desc
			 declare @CountMedium int = isnull((select count(1) from #TempMediumWithRow) ,0)
			 declare @RowNumMedium int = 1

			 declare @Medium_NameTemp nvarchar(200) = ''
		     declare @Medium_IDTemp bigint = 0
			 declare @Medium_ParentIDTemp bigint = 0


			 alter table #TempMediumWithRow
			 add MediumID nvarchar(200) 

			 while(@CountMedium > 0)
			   begin

			      select top 1 @Medium_NameTemp = MediumName, @Medium_ParentIDTemp = ParentID from #TempMediumWithRow where RowNum = @RowNumMedium
				  
				 if(exists( select 1 from UserMediumSettings with(nolock) where Name = @Medium_NameTemp and  UserID = @Medium_ParentIDTemp ))
				       begin
					     select top 1  @Medium_IDTemp = MediumID from UserMediumSettings with(nolock) where Name = @Medium_NameTemp and  UserID = @Medium_ParentIDTemp  
					  end
                   else
				      begin
					    insert into UserMediumSettings 
						 (Name,UserID,IsEditable,IsActive,CreatedDate,ModifiedDate,ModifiedBy)
                        select @Medium_NameTemp,@Medium_ParentIDTemp, 1,1,getdate(),getdate(), @Medium_ParentIDTemp  

						  select  @Medium_IDTemp = SCOPE_IDENTITY()
					  end

                   if(isnull(@Medium_IDTemp,0) > 0 )
				      begin
					      update #TempMediumWithRow set MediumID =  cast(@Medium_IDTemp as nvarchar)  where RowNum = @RowNumMedium 
					  end
                         
                   set  @Medium_IDTemp = 0    
				   set @RowNumMedium = @RowNumMedium +1 
				   set @CountMedium = @CountMedium - 1  

			   end
             
			  update t set t.MediumName =  s.MediumID from #UpdateDetails as t
			           join #TempMediumWithRow as s
					   on t.MediumName = s.MediumName

             -- select * from  #UpdateDetails 
			 drop table if exists #TempMedium
			 drop table if exists #TempMediumWithRow
		   end
		   
		  if(exists (select 1 from #ColTable where [Key] = 'CampaignName' ))
           begin
		     drop table if exists #TempCampaign
			 drop table if exists #TempCampaignWithRow

			 select distinct CampaignName, ParentID into  #TempCampaign from #UpdateDetails order by CampaignName desc 
			 select row_number() over(order by CampaignName asc) as RowNum, CampaignName, ParentID into #TempCampaignWithRow from #TempCampaign --order by SourceName desc
			 declare @CountCampaign int = isnull((select count(1) from #TempCampaignWithRow) ,0)
			 declare @RowNumCampaign int = 1

			 declare @Campaign_NameTemp nvarchar(200) = ''
		     declare @Campaign_IDTemp bigint = 0
			 declare @Campaign_ParentIDTemp bigint = 0


			 alter table #TempCampaignWithRow
			 add CampaignID nvarchar(200) 

			 while(@CountCampaign > 0)
			   begin

			      select top 1 @Campaign_NameTemp = CampaignName, @Campaign_ParentIDTemp = ParentID from #TempCampaignWithRow where RowNum = @RowNumCampaign
				  
				 if(exists( select 1 from UserCampaignSettings with(nolock) where Name = @Campaign_NameTemp and  UserID = @Campaign_ParentIDTemp ))
				       begin
					     select top 1  @Campaign_IDTemp = CampaignID from UserCampaignSettings with(nolock) where Name = @Campaign_NameTemp and  UserID = @Campaign_ParentIDTemp  
					  end
                   else
				      begin
					    insert into UserCampaignSettings 
						 (Name,UserID,IsEditable,IsActive,CreatedDate,ModifiedDate,ModifiedBy)
                        select @Campaign_NameTemp,@Campaign_ParentIDTemp, 1,1,getdate(),getdate(), @Campaign_ParentIDTemp  

						  select  @Campaign_IDTemp = SCOPE_IDENTITY()
					  end

                   if(isnull(@Campaign_IDTemp,0) > 0 )
				      begin
					      update #TempCampaignWithRow set CampaignID =  cast(@Campaign_IDTemp as nvarchar)  where RowNum = @RowNumCampaign 
					  end
                         
                   set  @Campaign_IDTemp = 0    
				   set @RowNumCampaign = @RowNumCampaign +1 
				   set @CountCampaign = @CountCampaign - 1  

			   end
             
			  update t set t.CampaignName =  s.CampaignID from #UpdateDetails as t
			           join #TempCampaignWithRow as s
					   on t.CampaignName = s.CampaignName

             -- select * from  #UpdateDetails 
			 drop table if exists #TempCampaign
			 drop table if exists #TempCampaignWithRow
		   end
		  -- select * from #UpdateDetails  


		while exists (select 1 from #UpdateDetails where Rowid between @start and @end )
		BEGIN
			/*
			set @sqls=	'update ul 
			set '+@UpdateFields+'
			from #UpdateDetails  dt join userEnquiry (NoLock) ul
			on  ul.EnquiryID =  dt.EnquiryID
		
			AND ((ul.CountryCode = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode
								else ul.CountryCode
								end
			AND ul.MobileNo = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno
								else ul.MobileNo
								end
				)	
			OR (ul.CountryCode1 = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode
								else ul.CountryCode1
								end
			AND ul.MobileNo1 = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno
								else ul.MobileNo1
								end
								)
			OR (ul.CountryCode2 = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode
								else ul.CountryCode2
								end
			AND ul.MobileNo2 = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno
								else ul.MobileNo2
								end
								))
			AND ( Ul.EmailID = case when isnull(dt.emailid,'''')<>'''' then dt.emailid
								else ul.EmailID
								end
			or Ul.EmailID1 = case when isnull(dt.emailid,'''')<>'''' then dt.emailid
								else ul.EmailID1
								end
			or Ul.EmailID2 = case when isnull(dt.emailid,'''')<>'''' then dt.emailid
								else ul.EmailID2
								end )
			Where ul.parentid = '+cast(@parentid as varchar)+' and Rowid between '+cast(@start as varchar)+' and '+cast( @end as varchar)
			
			*/
			
		    	set @sqls=	'update ul 
			set '+@UpdateFields+'
			from #UpdateDetails  dt join userEnquiry (NoLock) ul
					on  ul.EnquiryID =  dt.EnquiryID 
    
			   AND 1= case when 
			   isnull(dt.mobileno,'''')<>'''' and 
			   rtrim(ltrim(replace(isnull(dt.countrycode,''''),''+'','''')))+isnull(dt.mobileno,'''')
			   in
			   (rtrim(ltrim(replace(isnull(ul.CountryCode,''''),''+'','''')))+rtrim(ltrim(isnull(ul.MobileNo,''''))),
			   rtrim(ltrim(replace(isnull(ul.CountryCode2,''''),''+'','''')))+rtrim(ltrim(isnull(ul.MobileNo2,''''))),
			   rtrim(ltrim(replace(isnull(ul.CountryCode1,''''),''+'','''')))+rtrim(ltrim(isnull(ul.MobileNo1,'''')))) then 1

			   when isnull(dt.emailid,'''')<>'''' and 
			   isnull(dt.emailid,'''') in (isnull(Ul.EmailID,''''),isnull(Ul.EmailID2,''''),isnull(Ul.EmailID1,'''')) then 1 else 0 end 
			Where ul.parentid = '+cast(@parentid as varchar)+' and Rowid between '+cast(@start as varchar)+' and '+cast( @end as varchar)
		
		

			print @sqls
	
			Execute sp_executesql @sqls
			
			Update cflv 
			set cflv.fieldvalue=ucf.fieldvalue
			from customfieldenquiryvalue (NoLock) cflv 
			join #UpdateCustomfields ucf on cflv.EnquiryID = ucf.Enquiryid and cflv.fieldid =ucf.fieldid 
			where ucf.RowNo Between @start and @end

			Insert into customfieldEnquiryvalue (EnquiryID,fieldID,fieldvalue) 
			select ucf.Enquiryid,ucf.Fieldid,ucf.FieldValue from customfieldEnquiryvalue (NoLock) cflv 
				right join #UpdateCustomfields ucf on cflv.Enquiryid = ucf.Enquiryid and cflv.fieldid =ucf.fieldid 
			where cflv.recordID is null AND  ucf.RowNo Between @start and @end

			--Select Enquiryid,Fieldid,Fieldvalue from #UpdateCustomfields 
			--where  RowNo Between @start and @end and  Enquiryid not in (select Enquiryid from customfieldEnquiryvalue (NoLock) ) and fieldid not in (select fieldid from customfieldEnquiryvalue (NoLock))

			set @start = @start +500 
			Set @end = @end+500
		end
		
		set @Remarks = (select * from #FieldresTemp for Json auto, include_null_values)
		set @Enquirycount = (select count (1) from #UpdateDetails)
		set @custcount = (select count(1) from #UpdateCustomfields)
		set @userlogin = (select User_login from User_detail (NoLock) where user_id= @userid)

		update Tbl_enquiry_enquiryUpdateImportData set Remarks=@Remarks , enquiryCnt = @enquirycount ,enquiryCustomFieldCnt=@custcount,  IsProcessed=1, importend=getdate()   where ImportRow_Id= @ImportId

		  select @eventname='User imported enquiry',@eventdescription=@userlogin +' uploaded ' +cast(@totaldata as nvarchar) +' enquiry for Updating.   
				   The request is processed and enquiry imported are '+cast( @enquirycount as nvarchar)   
				  exec UspSaveEntityActivity_withid 'user',@userid,@userid,@ParentID,@EventDescription,@EventName,'Tbl_enquiry_enquiryUpdateImportData',@ImportId  
				  exec Usp_InsertUserEventDetails 'Enquiry Import successful',@parentid,@eventdescription, 'Tbl_enquiry_enquiryUpdateImportData',@ImportId
           
		Select  @min= @min + 1
	END
		--Commit Transaction
		SET Context_Info 0x
	END TRY
		
	BEGIN CATCH
		--While @@TRANCOUNT > 0
			--ROLLBACK TRANSACTION
                
		SET Context_Info 0x
		insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)        
		SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()  
   
	END CATCH

end





GO

/* ============================================================
   Procedure: [dbo].[Usp_ProcessUpdateLeadImportData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ProcessUpdateLeadImportData] --131 , 'p',1    
@ImpID bigint =0,    
@mode nvarchar(2)='P',    
@Batchsize int =1    
as    
begin    
           
      --declare  @ImpID bigint = 251,    
      --@mode nvarchar(2)='P',    
      --@Batchsize int =1    
      
     
 Drop Table if exists #ProcessImportData    
 drop table if exists #DetailsTable     
 drop table if exists #ColTable     
 drop table if exists #UpdateDetails     
 drop table if exists #CustdataTable    
 declare @sqls nvarchar(max)='', @TblColName nvarchar (max) , @CustColName nvarchar(max) , @CustFileName nvarchar(max), @CustName nvarchar(max), @custSqls nvarchar(max) = '', @FieldNames nvarchar(max)    
 ,@params nvarchar(500) = '', @altTable nvarchar(max),@min int =0 , @max int =0, @Importdata nvarchar(max), @Userid bigint, @Parentid bigint, @rowData nvarchar(2000)    
 ,@upmin bigint , @upmax bigint , @pagesize bigint = 500,@UpdateFields nvarchar(max)='',@row int = 1  , @custcount int, @fieldid bigint  , @fieldtype nvarchar(1), @fieldname nvarchar(100), @totaldata int,    
 @Remarks nvarchar(max) , @Leadcount int  , @ImportId bigint,@eventname nvarchar(100),@eventdescription nvarchar(max),@userlogin nvarchar(50)    
    
 BEGIN TRY    
 --BEGIN TRANSACTION         
        
    
 Create Table #ProcessImportData (RowID int identity ,     
    ImportID bigint ,    
    UserID bigint ,     
    )     
 if(ISNULL(@ImpID,0) >0)    
 BEGIN    
  Insert into #ProcessImportData (ImportID, UserID)    
  Select ImportRow_ID, User_id from Tbl_Lead_LeadUpdateImportData (NOLOCK) where ImportRow_Id=@ImpID    
 END    
 else     
 begin    
  if @mode='P'    
  BEGIN    
   if(@Batchsize<>0)    
   begin    
    Insert into #ProcessImportData (ImportID, UserID)    
    Select top (@Batchsize) ImportRow_ID, User_id from Tbl_Lead_LeadUpdateImportData (NOLOCK) where IsProcessed=0 Order by Priority Asc    
   end    
   else    
   begin    
    Insert into #ProcessImportData (ImportID, UserID)    
    Select ImportRow_ID, User_id from Tbl_Lead_LeadUpdateImportData (NOLOCK) where IsProcessed=0 Order by Priority Asc    
   end    
  END    
  else    
  begin    
   if(@Batchsize<>0)    
   begin    
    Insert into #ProcessImportData (ImportID, UserID)    
    Select top (@Batchsize) ImportRow_ID, User_id from Tbl_Lead_LeadUpdateImportData (NOLOCK) where IsProcessed=0     
   end    
   else    
   begin    
    Insert into #ProcessImportData (ImportID, UserID)    
    Select ImportRow_ID, User_id from Tbl_Lead_LeadUpdateImportData (NOLOCK) where IsProcessed=0     
   end    
  end    
 end    
 --select 'processdata', * from #ProcessImportData     
    
 Select @max = count(*) from #ProcessImportdata    
    
 select @TblColName= '''SNo'''+','+ STRING_AGG(''''+Column_name+'''',',') from INFORMATION_SCHEMA.COLUMNS (Nolock) where TABLE_NAME='Userleads'    
     
 While (@min < @max)    
 BEGIN    
  drop table if exists #DetailsTable     
  drop table if exists #ColTable     
  drop table if exists #UpdateDetails     
  drop table if exists #FieldResTemp    
  drop table if exists #CustdataTable    
  drop table if exists #CustomData    
  drop table if exists #UpdateCustomfields    
  create table #UpdateCustomfields (RowNo int,SNo int, Fieldid bigint, FieldName nvarchar(100), Leadid bigint, FieldValue nvarchar(2000))    
   Create table #FieldResTemp (SNo int, Field nvarchar(100), Remarks nvarchar(2000))    
  declare @start bigint = 0 , @end bigint = 499    
    
  Select   @userid= UserID, @ImportId = ImportID from #ProcessImportdata where RowID = @min +1    
  select @Importdata = Importdata from Tbl_Lead_LeadUpdateImportData (Nolock) where ImportRow_Id=@ImportId    
  Select @Parentid = ParentID from User_detail (NoLock)  where User_id= @userid    
  Update Tbl_Lead_LeadUpdateImportData set IsProcessed=0, Remarks ='[{"SNo":0,"Status":"Under Process","Remarks":"Under Process"}]', importstart = GETDATE() where ImportRow_ID=@ImportId    
  select top 1 @rowData = [value] from openJson(@Importdata)    
  Create  Table #ColTable (id int identity, [Key] nvarchar(200), [Value] nvarchar(max))     
  Create  Table #CustomData (rowid int identity, FieldID bigint, FieldName nvarchar(200))     
      
  --select @Importdata, @rowData, @TblColName    
    
  set @params = N'@rowData nvarchar(max)'    
  set @sqls='insert into #ColTable ([Key],[Value]) select [Key],[Value]  from openJson(@rowData)'     
  print @sqls    
  execute sp_executesql @sqls , @params, @rowData=@rowData    
    
  --select * from #ColTable    
      
  insert into #CustomData (FieldID, FieldName)    
  select field_ID,fieldname from customfields (NoLock) where ParentID=@parentid and isActive=1 and datatype<>'f' and  fieldname in (Select [Key] from #ColTable)     
     
  select @UpdateFields= STRING_AGG('ul.'+[key]+' = dt.'+[key],', ') from #ColTable where  [key] not in ('SNo','LeadNo','CountryCode','MobileNo','EmailID') and [KEY] not in (Select fieldname from customfields (nolock) where parentid=@parentid)    
    
  select @FieldNames = STRING_agg([key] +' nvarchar(2000)',', ') from #ColTable where [KEY] not in (Select fieldname from customfields (nolock) where parentid=@parentid)    
  select @CustColName = STRING_agg([key] +' nvarchar(2000)',', ') from #ColTable where [KEY]  in  (Select fieldname from customfields (nolock) where parentid=@parentid) or  [key] in ('SNo','LeadNo','CountryCode','MobileNo','EmailID')    
  select @CustFileName = String_agg([key],',') from #ColTable where [KEY]  in (Select fieldname from customfields (nolock) where parentid=@parentid)    
    
  --select @FieldNames     
  Create table #DetailsTable (parentid bigint)    
   Create table #CustdataTable (parentid bigint)    
      
    
  set @altTable = 'alter table #DetailsTable add ' + @FieldNames      
  print @altTable    
  execute sp_executesql @altTable    
      
  set @altTable = 'alter table #CustdataTable add ' + @CustColName      
  print @altTable    
  execute sp_executesql @altTable    
    
  set @params = N'@Impdata nvarchar(max)'    
  set @sqls  ='insert into #DetailsTable select '+cast(@parentid as varchar)+', * from openJson(@Impdata) with ('+@FieldNames+')'    
  print @sqls    
  execute sp_executesql @sqls, @params, @Impdata= @Importdata    
      
  set @params = N'@Impdata nvarchar(max)'    
  set @sqls  ='insert into #CustdataTable select '+cast(@parentid as varchar)+', * from openJson(@Impdata) with ('+@CustColName+')'    
  print @sqls    
  execute sp_executesql @sqls, @params, @Impdata= @Importdata    
     
  select @totaldata=count(1)  from #detailstable     
  --select *  from #detailstable     
      
  set @sqls ='if exists (select 1 from #DetailsTable where ISNULL(LeadNo,'''')='''' AND ISNULL(MobileNO,'''')='''' AND ISNULL(EmailID,'''')='''' and ISNULL(CountryCode,'''')='''')    
  BEGIN    
   Insert into #FieldResTemp (SNo,Field,Remarks)     
   Select Sno, ''LeadNo, MobileNO, EmailID'' Field, ''Enter atleast one field from LeadNo, MobileNO, EmailID'' from #DetailsTable where ISNULL(LeadNo,'''')='''' AND ISNULL(MobileNO,'''')='''' AND ISNULL(EmailID,'''')=''''    
  END    
    
  if exists (select 1 from #DetailsTable where ISNULL(MobileNO,'''')<>'''' AND ISNULL(CountryCode,'''')='''')    
  BEGIN    
   Insert into #FieldResTemp (SNo,Field,Remarks)     
   Select Sno, ''CountryCode'' Field, ''Enter CountryCode is mandatory with MobileNO'' from #DetailsTable where ISNULL(MobileNO,'''')<>'''' AND ISNULL(CountryCode,'''')=''''    
  END'    
    
  print @sqls    
  execute sp_executesql @sqls    
  if exists (select 1 from #ColTable where [Key]='PinCode')    
  begin    
   set @sqls= 'Insert into #FieldResTemp (SNo,Field,Remarks)select Sno,''Pincode'' Field,  ''Invalid Pincode'' Remarks from #detailstable where ISNUMERIC(PinCode)=0'    
    execute sp_executesql @sqls    
  end    
    
      
      
      
  set @row = 1    
  set  @custcount = (select count(1) from #CustomData)    
  --select * from #CustomData    
  --select * from #CustdataTable    
    
  while(@row<=@custcount)    
  begin    
   drop table if exists #customdetails    
   drop table if exists #customdetails1    
      
   create table #customdetails (Rowid int identity,SNo bigint, fieldid bigint, fieldname nvarchar(100) , fieldtype varchar(1), FieldValue nvarchar(2000), Leadid bigint )    
    
   Select @fieldid= fieldid ,@fieldname=cf.Fieldname, @fieldtype=cf.datatype from #CustomData cd join customfields cf on cf.field_id = cd.fieldid    where rowid=@row    
   
   
set @sqls= 'insert into #customdetails (SNo, fieldid,fieldname,fieldtype,FieldValue, Leadid)    
   select dt.SNo, '+cast(@fieldid as varchar)+' fieldid , '''+@fieldname+''' fieldname, '''+@fieldtype+''' fieldtype , '+@fieldname+' as FieldValue, ul.id Leadid from #CustdataTable dt    
      join userleads (NoLock) ul    

   on  isnull(ul.LeadNo,'''')=  Case   
       when isnull(dt.leadno,'''')<>'''' then   dt.leadno  
       else isnull(ul.LeadNo,'''')  
       END  

     
   AND ((isnull(ul.CountryCode,'''') = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode  
        else isnull(ul.CountryCode,'''')  
        end  
   AND isnull(ul.MobileNo,'''') = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno  
        else isnull(ul.MobileNo,'''')  
        end  
    )   
   OR (isnull(ul.CountryCode1,'''') = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode  
        else isnull(ul.CountryCode1,'''')  
        end  
   AND isnull(ul.MobileNo1,'''') = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno  
        else isnull(ul.MobileNo1,'''')  
        end  
        )  
   OR (isnull(ul.CountryCode2,'''') = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode  
        else isnull(ul.CountryCode2,'''')  
        end  
   AND isnull(ul.MobileNo2,'''') = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno  
        else isnull(ul.MobileNo2,'''')  
        end  
        ))  
   AND ( isnull(Ul.EmailID,'''') = case when isnull(dt.emailid,'''')<>'''' then dt.emailid  
        else isnull(Ul.EmailID,'''')  
        end  
   or isnull(Ul.EmailID1,'''') = case when isnull(dt.emailid,'''')<>'''' then dt.emailid  
        else isnull(Ul.EmailID1,'''')  
        end  
   or isnull(Ul.EmailID2,'''') = case when isnull(dt.emailid,'''')<>'''' then dt.emailid  
        else isnull(Ul.EmailID2,'''')  
        end )  
   Where ul.parentid = '+cast(@parentid as varchar)      


/*
   set @sqls= 'insert into #customdetails (SNo, fieldid,fieldname,fieldtype,FieldValue, Leadid)    
   select dt.SNo, '+cast(@fieldid as varchar)+' fieldid , '''+@fieldname+''' fieldname, '''+@fieldtype+''' fieldtype , '+@fieldname+' as FieldValue, ul.id Leadid from #CustdataTable dt    
      join userleads (NoLock) ul    
   on  ul.LeadNo=  Case     
       when isnull(dt.leadno,'''')<>'''' then   dt.leadno    
       else ul.LeadNo    
       END    
       
   AND ((ul.CountryCode = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode    
        else ul.CountryCode    
        end    
   AND ul.MobileNo = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno    
        else ul.MobileNo    
        end    
    )     
   OR (ul.CountryCode1 = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode    
        else ul.CountryCode1    
        end    
   AND ul.MobileNo1 = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno    
        else ul.MobileNo1    
        end    
        )    
   OR (ul.CountryCode2 = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode    
        else ul.CountryCode2    
        end    
   AND ul.MobileNo2 = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno    
        else ul.MobileNo2    
        end    
        ))    
   AND ( Ul.EmailID = case when isnull(dt.emailid,'''')<>'''' then dt.emailid    
        else ul.EmailID    
        end    
   or Ul.EmailID1 = case when isnull(dt.emailid,'''')<>'''' then dt.emailid    
        else ul.EmailID1    
        end    
   or Ul.EmailID2 = case when isnull(dt.emailid,'''')<>'''' then dt.emailid    
        else ul.EmailID2    
        end )    
   Where ul.parentid = '+cast(@parentid as varchar)  
   
   */
    print @sqls    
    execute sp_executesql @sqls    
        
   select cd.*, case    
      when  cd.fieldtype ='f'     
      Then IIF(CAST(cd.fieldvalue AS BIGINT) >= ISNULL(CAST(cf.minvalue as  BIGINT),-2222222222222222) AND CAST(cd.fieldvalue AS BIGINT) <= ISNULL (CAST(cf.maxvalue as BIGINT),2222222222222222),    
       '0','Number not in Custom Field Range')                  
      when  cd.fieldtype='D'     
      Then IIF(CAST(cd.fieldvalue AS date) >= CAST(ISNULL (cf.minvalue,'') as date) and                  
         CAST(cd.fieldvalue AS date) <= IIF ( ISNULL(cf.maxvalue,'') <> '', cast(cf.maxvalue as date),cast ('9999-01-01'as date)) ,'0','Date not in Custom Field Range')      
      when cf.datatype in ('r','s','l') and cf.choices is not null                   
      then IIF(cast(1 as varchar) = (select distinct 1 from dbo.fn_Split(cf.choices,',') splt     
              where CAST(splt.value AS nvarchar(max)) in (select distinct VALUE from dbo.fn_Split(cf.choices,','))),'0','Value not matches with Custom Field Choices')                  
      when cf.datatype in ('r','s','l') and  cf.choices IS NULL                  
      then '0'    
      ELSE '0'    
   end Error INTO #customdetails1    
   from #customdetails cd     
   join customfields (NoLock) cf on cd.fieldid = cf.field_id    
    
   Insert into  #FieldResTemp (SNo,Field,Remarks)    
   Select SNo, FieldName , Error from #customdetails1 where Error <> '0'    
    
       
   insert  into #UpdateCustomfields (RowNo ,SNo, Fieldid, FieldName, Leadid, FieldValue )     
   Select  ROW_NUMBER () over (Order by Sno) RowNo, SNo, Fieldid, FieldName, Leadid, FieldValue from #customdetails1 where Sno not in (Select Sno from #FieldResTemp )    
    
   --select * from #customdetails    
   --Select * from #customdetails1    
   --Select * from #FieldresTemp    
    
    set @row=@row+1     
  end    
  select ROW_NUMBER () over (Order by Sno) RowID,* into #UpdateDetails from #detailstable where SNo not in (select SNo from #FieldResTemp )    
      
  --select * from #UpdateDetails    
               
  if(exists (select 1 from #ColTable where [Key] = 'SourceName' ))    
           begin    
       drop table if exists #TempSource    
    drop table if exists #TempSourceWithRow    
    
    select distinct SourceName, ParentID into  #TempSource from #UpdateDetails order by SourceName desc     
    select row_number() over(order by SourceName asc) as RowNum, SourceName, ParentID into #TempSourceWithRow from #TempSource --order by SourceName desc    
    declare @CountSource int = isnull((select count(1) from #TempSourceWithRow) ,0)    
    declare @RowNumSource int = 1    
    
    declare @Source_NameTemp nvarchar(200) = ''    
       declare @Source_IDTemp bigint = 0    
    declare @Source_ParentIDTemp bigint = 0    
    
    
    alter table #TempSourceWithRow    
    add SourceID nvarchar(200)     
    
    while(@CountSource > 0)    
      begin    
    
         select top 1 @Source_NameTemp = SourceName, @Source_ParentIDTemp = ParentID from #TempSourceWithRow where RowNum = @RowNumSource    
          
     if(exists( select 1 from UserSourceSettings with(nolock) where Name = @Source_NameTemp and  UserID = @Source_ParentIDTemp ))    
           begin    
          select top 1  @Source_IDTemp = SourceID from UserSourceSettings with(nolock) where Name = @Source_NameTemp and  UserID = @Source_ParentIDTemp      
       end    
                   else    
          begin    
         insert into UserSourceSettings     
       (Name,UserID,IsEditable,IsActive,CreatedDate,ModifiedDate,ModifiedBy)    
                        select @Source_NameTemp,@Source_ParentIDTemp, 1,1,getdate(),getdate(), @Source_ParentIDTemp      
    
        select  @Source_IDTemp = SCOPE_IDENTITY()    
       end    
    
                   if(isnull(@Source_IDTemp,0) > 0 )    
          begin    
           update #TempSourceWithRow set SourceID =  cast(@Source_IDTemp as nvarchar)  where RowNum = @RowNumSource     
       end    
                             
                   set  @Source_IDTemp = 0        
       set @RowNumSource = @RowNumSource +1     
       set @CountSource = @CountSource - 1      
    
      end    
                 
     update t set t.SourceName =  s.SourceID from #UpdateDetails as t    
              join #TempSourceWithRow as s    
        on t.sourceName = s.SourceName    
    
             -- select * from  #UpdateDetails     
    drop table if exists #TempSource    
    drop table if exists #TempSourceWithRow    
     end    
              
    if(exists (select 1 from #ColTable where [Key] = 'MediumName' ))    
           begin    
       drop table if exists #TempMedium    
    drop table if exists #TempMediumWithRow    
    
    select distinct MediumName, ParentID into  #TempMedium from #UpdateDetails order by MediumName desc     
    select row_number() over(order by MediumName asc) as RowNum, MediumName, ParentID into #TempMediumWithRow from #TempMedium --order by SourceName desc    
    declare @CountMedium int = isnull((select count(1) from #TempMediumWithRow) ,0)    
    declare @RowNumMedium int = 1    
    
    declare @Medium_NameTemp nvarchar(200) = ''    
       declare @Medium_IDTemp bigint = 0    
    declare @Medium_ParentIDTemp bigint = 0    
    
    
    alter table #TempMediumWithRow    
    add MediumID nvarchar(200)     
    
    while(@CountMedium > 0)    
      begin    
    
         select top 1 @Medium_NameTemp = MediumName, @Medium_ParentIDTemp = ParentID from #TempMediumWithRow where RowNum = @RowNumMedium    
          
     if(exists( select 1 from UserMediumSettings with(nolock) where Name = @Medium_NameTemp and  UserID = @Medium_ParentIDTemp ))    
           begin    
          select top 1  @Medium_IDTemp = MediumID from UserMediumSettings with(nolock) where Name = @Medium_NameTemp and  UserID = @Medium_ParentIDTemp      
       end    
                   else    
          begin    
         insert into UserMediumSettings     
       (Name,UserID,IsEditable,IsActive,CreatedDate,ModifiedDate,ModifiedBy)    
                        select @Medium_NameTemp,@Medium_ParentIDTemp, 1,1,getdate(),getdate(), @Medium_ParentIDTemp      
    
        select  @Medium_IDTemp = SCOPE_IDENTITY()    
       end    
    
                   if(isnull(@Medium_IDTemp,0) > 0 )    
          begin    
           update #TempMediumWithRow set MediumID =  cast(@Medium_IDTemp as nvarchar)  where RowNum = @RowNumMedium     
       end    
                             
                   set  @Medium_IDTemp = 0        
       set @RowNumMedium = @RowNumMedium +1     
       set @CountMedium = @CountMedium - 1      
    
      end    
                 
     update t set t.MediumName =  s.MediumID from #UpdateDetails as t    
              join #TempMediumWithRow as s    
        on t.MediumName = s.MediumName    
    
             -- select * from  #UpdateDetails     
    drop table if exists #TempMedium    
    drop table if exists #TempMediumWithRow    
     end    
         
    if(exists (select 1 from #ColTable where [Key] = 'CampaignName' ))    
           begin    
       drop table if exists #TempCampaign    
    drop table if exists #TempCampaignWithRow    
    
    select distinct CampaignName, ParentID into  #TempCampaign from #UpdateDetails order by CampaignName desc     
    select row_number() over(order by CampaignName asc) as RowNum, CampaignName, ParentID into #TempCampaignWithRow from #TempCampaign --order by SourceName desc    
    declare @CountCampaign int = isnull((select count(1) from #TempCampaignWithRow) ,0)    
    declare @RowNumCampaign int = 1    
    
    declare @Campaign_NameTemp nvarchar(200) = ''    
       declare @Campaign_IDTemp bigint = 0    
    declare @Campaign_ParentIDTemp bigint = 0    
    
    
    alter table #TempCampaignWithRow    
    add CampaignID nvarchar(200)     
    
    while(@CountCampaign > 0)    
      begin    
    
         select top 1 @Campaign_NameTemp = CampaignName, @Campaign_ParentIDTemp = ParentID from #TempCampaignWithRow where RowNum = @RowNumCampaign    
          
     if(exists( select 1 from UserCampaignSettings with(nolock) where Name = @Campaign_NameTemp and  UserID = @Campaign_ParentIDTemp ))    
           begin    
          select top 1  @Campaign_IDTemp = CampaignID from UserCampaignSettings with(nolock) where Name = @Campaign_NameTemp and  UserID = @Campaign_ParentIDTemp      
       end    
                   else    
          begin    
         insert into UserCampaignSettings     
       (Name,UserID,IsEditable,IsActive,CreatedDate,ModifiedDate,ModifiedBy)    
                        select @Campaign_NameTemp,@Campaign_ParentIDTemp, 1,1,getdate(),getdate(), @Campaign_ParentIDTemp      
    
        select  @Campaign_IDTemp = SCOPE_IDENTITY()    
       end    
    
                   if(isnull(@Campaign_IDTemp,0) > 0 )    
          begin    
           update #TempCampaignWithRow set CampaignID =  cast(@Campaign_IDTemp as nvarchar)  where RowNum = @RowNumCampaign     
       end    
                             
                   set  @Campaign_IDTemp = 0        
       set @RowNumCampaign = @RowNumCampaign +1     
       set @CountCampaign = @CountCampaign - 1      
    
      end    
                 
     update t set t.CampaignName =  s.CampaignID from #UpdateDetails as t    
              join #TempCampaignWithRow as s    
        on t.CampaignName = s.CampaignName    
    
             -- select * from  #UpdateDetails     
    drop table if exists #TempCampaign    
    drop table if exists #TempCampaignWithRow    
     end    
    --select * from #UpdateDetails    
         
    
  while exists (select 1 from #UpdateDetails where Rowid between @start and @end )    
  BEGIN    
  
  /*
    set @sqls= 'update ul     
   set '+@UpdateFields+'    
   from #UpdateDetails  dt join userleads (NoLock) ul    
   on  ul.LeadNo=  Case     
       when isnull(dt.leadno,'''')<>'''' then   dt.leadno    
       else ul.LeadNo    
       END    
     
   AND (( isnull(rtrim(ltrim(replace(ul.CountryCode,''+'',''''))),'''') = case when isnull(dt.CountryCode,'''')<> ''''     
                 then rtrim(ltrim(replace(dt.CountryCode,''+'','''')))    
        else  isnull(rtrim(ltrim(replace(ul.CountryCode,''+'',''''))),'''')    
        end    
   AND  isnull(rtrim(ltrim(ul.MobileNo)),'''') = case when isnull(dt.MobileNo,'''')<> '''' then rtrim(ltrim(dt.mobileno))    
        else isnull(rtrim(ltrim(ul.MobileNo)),'''')    
        end    
    )     
   OR (  isnull(rtrim(ltrim(replace(ul.CountryCode1,''+'',''''))),'''') = case when isnull(dt.CountryCode,'''')<> ''''     
               then  rtrim(ltrim(replace(dt.CountryCode,''+'','''')))    
        else isnull(rtrim(ltrim(replace(ul.CountryCode1,''+'',''''))),'''')    
        end    
   AND isnull(rtrim(ltrim(ul.MobileNo1)),'''') = case when isnull(dt.MobileNo,'''')<> '''' then  ltrim(rtrim(dt.mobileno))    
        else isnull(rtrim(ltrim(ul.MobileNo1)),'''')    
        end    
        )    
   OR ( isnull(rtrim(ltrim(replace(ul.CountryCode2,''+'',''''))),'''') = case when isnull(dt.CountryCode,'''')<> ''''     
                 then rtrim(ltrim(replace(dt.CountryCode,''+'','''')))    
        else isnull(rtrim(ltrim(replace(ul.CountryCode2,''+'',''''))),'''')    
        end    
   AND isnull(rtrim(ltrim(ul.MobileNo2)),'''') = case when isnull(dt.MobileNo,'''')<> '''' then rtrim(ltrim(dt.mobileno))    
        else isnull(rtrim(ltrim(ul.MobileNo2)),'''')    
        end    
        ))    
   AND ( isnull(Ul.EmailID,'''') = case when isnull(dt.emailid,'''')<>'''' then dt.emailid    
        else isnull(Ul.EmailID,'''')    
        end    
   or isnull(Ul.EmailID1,'''') = case when isnull(dt.emailid,'''')<>'''' then dt.emailid    
        else isnull(Ul.EmailID1,'''')    
        end    
   or isnull(Ul.EmailID2,'''') = case when isnull(dt.emailid,'''')<>'''' then dt.emailid    
        else isnull(Ul.EmailID2,'''')    
        end )    
   Where ul.parentid = '+cast(@parentid as varchar)+' and Rowid between '+cast(@start as varchar)+' and '+cast( @end as varchar)    
    */
  
/*        
    set @sqls= 'update ul     
   set '+@UpdateFields+'    
   from #UpdateDetails  dt join userleads (NoLock) ul    
   on  ul.LeadNo=  Case     
       when isnull(dt.leadno,'''')<>'''' then   dt.leadno    
       else ul.LeadNo    
       END    
      
   AND (( rtrim(ltrim(replace(ul.CountryCode,''+'',''''))) = case when isnull(dt.CountryCode,'''')<> ''''     
                 then rtrim(ltrim(replace(dt.CountryCode,''+'','''')))    
        else  rtrim(ltrim(replace(ul.CountryCode,''+'','''')))    
        end    
   AND  rtrim(ltrim(ul.MobileNo)) = case when isnull(dt.MobileNo,'''')<> '''' then rtrim(ltrim(dt.mobileno))    
        else rtrim(ltrim(ul.MobileNo))    
        end    
    )     
   OR (  rtrim(ltrim(replace(ul.CountryCode1,''+'',''''))) = case when isnull(dt.CountryCode,'''')<> ''''     
               then  rtrim(ltrim(replace(dt.CountryCode,''+'','''')))    
        else rtrim(ltrim(replace(ul.CountryCode1,''+'','''')))    
        end    
   AND rtrim(ltrim(ul.MobileNo1)) = case when isnull(dt.MobileNo,'''')<> '''' then  ltrim(rtrim(dt.mobileno))    
        else ltrim(rtrim(ul.MobileNo1))    
        end    
        )    
   OR ( rtrim(ltrim(replace(ul.CountryCode2,''+'',''''))) = case when isnull(dt.CountryCode,'''')<> ''''     
                 then rtrim(ltrim(replace(dt.CountryCode,''+'','''')))    
        else rtrim(ltrim(replace(ul.CountryCode2,''+'','''')))    
        end    
   AND rtrim(ltrim(ul.MobileNo2)) = case when isnull(dt.MobileNo,'''')<> '''' then rtrim(ltrim(dt.mobileno))    
        else rtrim(ltrim(ul.MobileNo2))    
        end    
        ))    
   AND ( Ul.EmailID = case when isnull(dt.emailid,'''')<>'''' then dt.emailid    
        else ul.EmailID    
        end    
   or Ul.EmailID1 = case when isnull(dt.emailid,'''')<>'''' then dt.emailid    
        else ul.EmailID1    
        end    
   or Ul.EmailID2 = case when isnull(dt.emailid,'''')<>'''' then dt.emailid    
        else ul.EmailID2    
        end )    
   Where ul.parentid = '+cast(@parentid as varchar)+' and Rowid between '+cast(@start as varchar)+' and '+cast( @end as varchar)    
    */   
    
  
     set @sqls = 'update ul     
   set '+@UpdateFields+'    
   from #UpdateDetails  dt join userleads (NoLock) ul    
     on ul.LeadNo =  Case       
       when isnull(dt.leadno,'''')<>'''' then   dt.leadno      
       else ul.LeadNo      
       END      
        
      AND 1= case when     
      isnull(dt.mobileno,'''')<>'''' and     
      rtrim(ltrim(replace(isnull(dt.countrycode,''''),''+'','''')))+isnull(dt.mobileno,'''')    
      in    
      (rtrim(ltrim(replace(isnull(ul.CountryCode,''''),''+'','''')))+rtrim(ltrim(isnull(ul.MobileNo,''''))),    
      rtrim(ltrim(replace(isnull(ul.CountryCode2,''''),''+'','''')))+rtrim(ltrim(isnull(ul.MobileNo2,''''))),    
      rtrim(ltrim(replace(isnull(ul.CountryCode1,''''),''+'','''')))+rtrim(ltrim(isnull(ul.MobileNo1,'''')))) then 1    
    
      when isnull(dt.emailid,'''')<>'''' and     
      isnull(dt.emailid,'''') in (isnull(Ul.EmailID,''''),isnull(Ul.EmailID2,''''),isnull(Ul.EmailID1,'''')) then 1 else 0 end     
      Where ul.parentid = '+cast(@parentid as varchar)+' and Rowid between '+cast(@start as varchar)+' and '+cast( @end as varchar)    
    
  
  
    /*
      set @sqls = 'update ul     
   set '+@UpdateFields+'    
   from #UpdateDetails  dt join userleads (NoLock) ul    
     on ul.LeadNo =  isnull(dt.leadno,0)  
  OR  
      (isnull(dt.mobileno,'''')<>'''' and     
      rtrim(ltrim(replace(isnull(dt.countrycode,''''),''+'','''')))+isnull(dt.mobileno,'''')    
      in    
      (rtrim(ltrim(replace(isnull(ul.CountryCode,''''),''+'','''')))+rtrim(ltrim(isnull(ul.MobileNo,''''))),    
      rtrim(ltrim(replace(isnull(ul.CountryCode2,''''),''+'','''')))+rtrim(ltrim(isnull(ul.MobileNo2,''''))),    
      rtrim(ltrim(replace(isnull(ul.CountryCode1,''''),''+'','''')))+rtrim(ltrim(isnull(ul.MobileNo1,'''')))))  
   OR  
   (isnull(dt.emailid,'''')<>'''' and     
      isnull(dt.emailid,'''') in (isnull(Ul.EmailID,''''),isnull(Ul.EmailID2,''''),isnull(Ul.EmailID1,'''')))     
   Where ul.parentid = '+cast(@parentid as varchar)+' and Rowid between '+cast(@start as varchar)+' and '+cast( @end as varchar)    
  */  
   print @sqls    
      
   Execute sp_executesql @sqls    
    
   Update cflv     
   set cflv.fieldvalue=ucf.fieldvalue    
   from customfieldleadvalue (NoLock) cflv     
   join #UpdateCustomfields ucf on cflv.leadid = ucf.leadid and cflv.fieldid =ucf.fieldid     
   where ucf.RowNo Between @start and @end    
    
   Insert into customfieldleadvalue (LeadID,fieldID,fieldvalue,CreatedDate)    
   select ucf.Leadid,ucf.Fieldid,ucf.FieldValue, GetDate() from customfieldleadvalue (NoLock) cflv     
   right join #UpdateCustomfields ucf on cflv.leadid = ucf.leadid and cflv.fieldid =ucf.fieldid     
   where cflv.recordID is null AND  ucf.RowNo Between @start and @end    
    
   --Select Leadid,Fieldid,Fieldvalue, GetDate() from #UpdateCustomfields     
   --where  RowNo Between @start and @end and  Leadid not in (select Leadid from customfieldleadvalue (NoLock) ) and fieldid not in (select fieldid from customfieldleadvalue (NoLock))    
    
   set @start = @start +500     
   Set @end = @end+500    
  end    
      
  set @Remarks = (select * from #FieldresTemp for Json auto, include_null_values)    
  set @Leadcount = (select count (1) from #UpdateDetails)    
  set @custcount = (select count(1) from #UpdateCustomfields)    
  set @userlogin = (select User_login from User_detail (NoLock) where user_id= @userid)    
    
  update Tbl_Lead_LeadUpdateImportData set Remarks=@Remarks , LeadCnt = @Leadcount ,LeadCustomFieldCnt=@custcount,  IsProcessed=1 ,importend=getdate()  where ImportRow_Id= @ImportId    
    
    select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@totaldata as nvarchar) +' leads for Updating.       
       The request is processed and leads imported are '+cast( @Leadcount as nvarchar)       
      exec UspSaveEntityActivity_withid 'user',@userid,@userid,@ParentID,@EventDescription,@EventName,'Tbl_Lead_LeadUpdateImportData',@ImportId      
      exec Usp_InsertUserEventDetails 'Lead Import successful',@parentid,@eventdescription, 'Tbl_Lead_LeadUpdateImportData',@ImportId    
               
  Select  @min= @min+1    
 END    
  --Commit Transaction    
  SET Context_Info 0x    
 END TRY    
      
 BEGIN CATCH    
  --While @@TRANCOUNT > 0    
   --ROLLBACK TRANSACTION    
      
	  Declare @Json nvarchar(max) = ''
	  
	  SELECT @Json = (
    SELECT  
         0 AS SNo,  
        'Exception' AS Field,  
        ERROR_MESSAGE() AS Remarks  
        FOR JSON PATH
       );

    update Tbl_Lead_LeadUpdateImportData set Remarks=@Json, IsValid = 0 , LeadCnt = 0 ,LeadCustomFieldCnt= 0,  IsProcessed = 1 ,importend=getdate()  where ImportRow_Id= @ImportId    
    
  SET Context_Info 0x    
  print 'Error occured'  
  insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)            
  SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()      
       
 END CATCH    
end    


GO

/* ============================================================
   Procedure: [dbo].[Usp_ProcessUpdateLeadImportData_Replication]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ProcessUpdateLeadImportData_Replication]
@ImpID bigint =0,
@mode nvarchar(2)='P',
@Batchsize int =1
as

begin
      /*  
      declare  @ImpID bigint = 0,
      @mode nvarchar(2)='P',
      @Batchsize int =1
	  */
 
	Drop Table if exists #ProcessImportData
	drop table if exists #DetailsTable 
	drop table if exists #ColTable 
	drop table if exists #UpdateDetails 
	drop table if exists #CustdataTable
	declare @sqls nvarchar(max)='', @TblColName nvarchar (max) , @CustColName nvarchar(max) , @CustFileName nvarchar(max), @CustName nvarchar(max), @custSqls nvarchar(max) = '', @FieldNames nvarchar(max)
	,@params nvarchar(500) = '', @altTable nvarchar(max),@min int =0 , @max int =0, @Importdata nvarchar(max), @Userid bigint, @Parentid bigint, @rowData nvarchar(2000)
	,@upmin bigint , @upmax bigint , @pagesize bigint = 500,@UpdateFields nvarchar(max)='',@row int = 1  , @custcount int, @fieldid bigint  , @fieldtype nvarchar(1), @fieldname nvarchar(100), @totaldata int,
	@Remarks nvarchar(max) , @Leadcount int  , @ImportId bigint,@eventname nvarchar(100),@eventdescription nvarchar(max),@userlogin nvarchar(50)

	BEGIN TRY
	BEGIN TRANSACTION     
	   

	Create Table #ProcessImportData (RowID int identity , 
				ImportID bigint ,
				UserID bigint , 
				) 
	if(ISNULL(@ImpID,0) >0)
	BEGIN
		Insert into #ProcessImportData (ImportID, UserID)
		Select ImportRow_ID, User_id from Tbl_Lead_LeadUpdateImportData (NOLOCK) where ImportRow_Id=@ImpID
	END
	else 
	begin
		if @mode='P'
		BEGIN
			if(@Batchsize<>0)
			begin
				Insert into #ProcessImportData (ImportID, UserID)
				Select top (@Batchsize) ImportRow_ID, User_id from Tbl_Lead_LeadUpdateImportData (NOLOCK) where IsProcessed=0 Order by Priority Asc
			end
			else
			begin
				Insert into #ProcessImportData (ImportID, UserID)
				Select ImportRow_ID, User_id from Tbl_Lead_LeadUpdateImportData (NOLOCK) where IsProcessed=0 Order by Priority Asc
			end
		END
		else
		begin
			if(@Batchsize<>0)
			begin
				Insert into #ProcessImportData (ImportID, UserID)
				Select top (@Batchsize) ImportRow_ID, User_id from Tbl_Lead_LeadUpdateImportData (NOLOCK) where IsProcessed=0 
			end
			else
			begin
				Insert into #ProcessImportData (ImportID, UserID)
				Select ImportRow_ID, User_id from Tbl_Lead_LeadUpdateImportData (NOLOCK) where IsProcessed=0 
			end
		end
	end
	--select 'processdata', * from #ProcessImportData 

	Select @max = count(*) from #ProcessImportdata

	select @TblColName= '''SNo'''+','+ STRING_AGG(''''+Column_name+'''',',') from INFORMATION_SCHEMA.COLUMNS (Nolock) where TABLE_NAME='Userleads'
	
	While (@min < @max)
	BEGIN
		drop table if exists #DetailsTable 
		drop table if exists #ColTable 
		drop table if exists #UpdateDetails 
		drop table if exists #FieldResTemp
		drop table if exists #CustdataTable
		drop table if exists #CustomData
		drop table if exists #UpdateCustomfields
		create table #UpdateCustomfields (RowNo int,SNo int, Fieldid bigint, FieldName nvarchar(100), Leadid bigint, FieldValue nvarchar(2000))
		 Create table #FieldResTemp (SNo int, Field nvarchar(100), Remarks nvarchar(2000))
		declare @start bigint = 0 , @end bigint = 499

		Select   @userid= UserID, @ImportId = ImportID from #ProcessImportdata where RowID = @min +1
		select @Importdata = Importdata from Tbl_Lead_LeadUpdateImportData (Nolock) where ImportRow_Id=@ImportId
		Select @Parentid = ParentID from User_detail (NoLock)  where User_id= @userid
		Update Tbl_Lead_LeadUpdateImportData set IsProcessed=0, Remarks ='[{"SNo":0,"Status":"Under Process","Remarks":"Under Process"}]', importstart = GETDATE() where ImportRow_ID=@ImportId
		select top 1 @rowData = [value] from openJson(@Importdata)
		Create  Table #ColTable (id int identity, [Key] nvarchar(200), [Value] nvarchar(max)) 
		Create  Table #CustomData (rowid int identity, FieldID bigint, FieldName nvarchar(200)) 
		
		--select @Importdata, @rowData, @TblColName

		set @params = N'@rowData nvarchar(max)'
		set @sqls='insert into #ColTable ([Key],[Value]) select [Key],[Value]  from openJson(@rowData)' 
		print @sqls
		execute sp_executesql @sqls , @params, @rowData=@rowData

		--select * from #ColTable
		
		insert into #CustomData (FieldID, FieldName)
		select field_ID,fieldname from customfields (NoLock) where ParentID=@parentid and isActive=1 and datatype<>'f' and  fieldname in (Select [Key] from #ColTable) 
	
		select @UpdateFields= STRING_AGG('ul.'+[key]+' = dt.'+[key],', ') from #ColTable where  [key] not in ('SNo','LeadNo','CountryCode','MobileNo','EmailID') and [KEY] not in (Select fieldname from customfields (nolock) where parentid=@parentid)

		select @FieldNames = STRING_agg([key] +' nvarchar(2000)',', ') from #ColTable where [KEY] not in (Select fieldname from customfields (nolock) where parentid=@parentid)
		select @CustColName = STRING_agg([key] +' nvarchar(2000)',', ') from #ColTable where [KEY]  in  (Select fieldname from customfields (nolock) where parentid=@parentid) or  [key] in ('SNo','LeadNo','CountryCode','MobileNo','EmailID')
		select @CustFileName = String_agg([key],',') from #ColTable where [KEY]  in (Select fieldname from customfields (nolock) where parentid=@parentid)

		--select @FieldNames 
		Create table #DetailsTable (parentid bigint)
		 Create table #CustdataTable (parentid bigint)
		

		set @altTable = 'alter table #DetailsTable add ' + @FieldNames  
		print @altTable
		execute sp_executesql @altTable
		
		set @altTable = 'alter table #CustdataTable add ' + @CustColName  
		print @altTable
		execute sp_executesql @altTable

		set @params = N'@Impdata nvarchar(max)'
		set @sqls  ='insert into #DetailsTable select '+cast(@parentid as varchar)+', * from openJson(@Impdata) with ('+@FieldNames+')'
		print @sqls
		execute sp_executesql @sqls, @params, @Impdata= @Importdata
		
		set @params = N'@Impdata nvarchar(max)'
		set @sqls  ='insert into #CustdataTable select '+cast(@parentid as varchar)+', * from openJson(@Impdata) with ('+@CustColName+')'
		print @sqls
		execute sp_executesql @sqls, @params, @Impdata= @Importdata
	
		select @totaldata=count(1)  from #detailstable 
		--select *  from #detailstable 
		
		set @sqls ='if exists (select 1 from #DetailsTable where ISNULL(LeadNo,'''')='''' AND ISNULL(MobileNO,'''')='''' AND ISNULL(EmailID,'''')='''' and ISNULL(CountryCode,'''')='''')
		BEGIN
			Insert into #FieldResTemp (SNo,Field,Remarks) 
			Select Sno, ''LeadNo, MobileNO, EmailID'' Field, ''Enter atleast one field from LeadNo, MobileNO, EmailID'' from #DetailsTable where ISNULL(LeadNo,'''')='''' AND ISNULL(MobileNO,'''')='''' AND ISNULL(EmailID,'''')=''''
		END

		if exists (select 1 from #DetailsTable where ISNULL(MobileNO,'''')<>'''' AND ISNULL(CountryCode,'''')='''')
		BEGIN
			Insert into #FieldResTemp (SNo,Field,Remarks) 
			Select Sno, ''CountryCode'' Field, ''Enter CountryCode is mandatory with MobileNO'' from #DetailsTable where ISNULL(MobileNO,'''')<>'''' AND ISNULL(CountryCode,'''')=''''
		END'

		print @sqls
		execute sp_executesql @sqls
		if exists (select 1 from #ColTable where [Key]='PinCode')
		begin
			set @sqls= 'Insert into #FieldResTemp (SNo,Field,Remarks)select Sno,''Pincode'' Field,  ''Invalid Pincode'' Remarks from #detailstable where ISNUMERIC(PinCode)=0'
				execute sp_executesql @sqls
		end

		
		
		
		set @row = 1
		set  @custcount = (select count(1) from #CustomData)
		--select * from #CustomData
		--select * from #CustdataTable

		while(@row<=@custcount)
		begin
			drop table if exists #customdetails
			drop table if exists #customdetails1
		
			create table #customdetails (Rowid int identity,SNo bigint, fieldid bigint, fieldname nvarchar(100) , fieldtype varchar(1), FieldValue nvarchar(2000), Leadid bigint )

			Select @fieldid= fieldid ,@fieldname=cf.Fieldname, @fieldtype=cf.datatype from #CustomData cd join customfields cf on cf.field_id = cd.fieldid    where rowid=@row
			
			set @sqls= 'insert into #customdetails (SNo, fieldid,fieldname,fieldtype,FieldValue, Leadid)
			select dt.SNo, '+cast(@fieldid as varchar)+' fieldid , '''+@fieldname+''' fieldname, '''+@fieldtype+''' fieldtype , '+@fieldname+' as FieldValue, ul.id Leadid from #CustdataTable dt
						join userleads (NoLock) ul
			on  ul.LeadNo=  Case 
							when isnull(dt.leadno,'''')<>'''' then   dt.leadno
							else ul.LeadNo
							END
			
			AND ((ul.CountryCode = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode
								else ul.CountryCode
								end
			AND ul.MobileNo = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno
								else ul.MobileNo
								end
				)	
			OR (ul.CountryCode1 = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode
								else ul.CountryCode1
								end
			AND ul.MobileNo1 = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno
								else ul.MobileNo1
								end
								)
			OR (ul.CountryCode2 = case when isnull(dt.CountryCode,'''')<> '''' then dt.CountryCode
								else ul.CountryCode2
								end
			AND ul.MobileNo2 = case when isnull(dt.MobileNo,'''')<> '''' then dt.mobileno
								else ul.MobileNo2
								end
								))
			AND ( Ul.EmailID = case when isnull(dt.emailid,'''')<>'''' then dt.emailid
								else ul.EmailID
								end
			or Ul.EmailID1 = case when isnull(dt.emailid,'''')<>'''' then dt.emailid
								else ul.EmailID1
								end
			or Ul.EmailID2 = case when isnull(dt.emailid,'''')<>'''' then dt.emailid
								else ul.EmailID2
								end )
			Where ul.parentid = '+cast(@parentid as varchar)  
				print @sqls
				execute sp_executesql @sqls
				
			select cd.*, case
						when  cd.fieldtype ='f' 
						Then IIF(CAST(cd.fieldvalue AS BIGINT) >= ISNULL(CAST(cf.minvalue as  BIGINT),-2222222222222222) AND CAST(cd.fieldvalue AS BIGINT) <= ISNULL (CAST(cf.maxvalue as BIGINT),2222222222222222),
							'0','Number not in Custom Field Range')              
						when  cd.fieldtype='D' 
						Then IIF(CAST(cd.fieldvalue AS date) >= CAST(ISNULL (cf.minvalue,'') as date) and              
								 CAST(cd.fieldvalue AS date) <= IIF ( ISNULL(cf.maxvalue,'') <> '', cast(cf.maxvalue as date),cast ('9999-01-01'as date)) ,'0','Date not in Custom Field Range')  
						when cf.datatype in ('r','s','l') and cf.choices is not null               
						then IIF(cast(1 as varchar) = (select distinct 1 from dbo.fn_Split(cf.choices,',') splt 
														where CAST(splt.value AS nvarchar(max)) in (select distinct VALUE from dbo.fn_Split(cf.choices,','))),'0','Value not matches with Custom Field Choices')              
						when cf.datatype in ('r','s','l') and  cf.choices IS NULL              
						then '0'
						ELSE '0'
			end Error INTO #customdetails1
			from #customdetails cd 
			join customfields (NoLock) cf on cd.fieldid = cf.field_id

			Insert into  #FieldResTemp (SNo,Field,Remarks)
			Select SNo, FieldName , Error from #customdetails1 where Error <> '0'

			
			insert  into #UpdateCustomfields (RowNo ,SNo, Fieldid, FieldName, Leadid, FieldValue ) 
			Select  ROW_NUMBER () over (Order by Sno) RowNo, SNo, Fieldid, FieldName, Leadid, FieldValue from #customdetails1 where Sno not in (Select Sno from #FieldResTemp )

			--select * from #customdetails
			--Select * from #customdetails1
			--Select * from #FieldresTemp

				set @row=@row+1 
		end
		select ROW_NUMBER () over (Order by Sno) RowID,* into #UpdateDetails from #detailstable where SNo not in (select SNo from #FieldResTemp )
		--select * from #UpdateDetails
		while exists (select 1 from #UpdateDetails where Rowid between @start and @end )
		BEGIN
		  set @sqls=	'update ul 
			set '+@UpdateFields+'
			from #UpdateDetails  dt join userleads (NoLock) ul
			on  ul.LeadNo=  Case 
							when isnull(dt.leadno,'''')<>'''' then   dt.leadno
							else ul.LeadNo
							END
		
			AND (( rtrim(ltrim(replace(ul.CountryCode,''+'',''''))) = case when isnull(dt.CountryCode,'''')<> '''' 
			              then rtrim(ltrim(replace(dt.CountryCode,''+'','''')))
								else  rtrim(ltrim(replace(ul.CountryCode,''+'','''')))
								end
			AND  rtrim(ltrim(ul.MobileNo)) = case when isnull(dt.MobileNo,'''')<> '''' then rtrim(ltrim(dt.mobileno))
								else rtrim(ltrim(ul.MobileNo))
								end
				)	
			OR (  rtrim(ltrim(replace(ul.CountryCode1,''+'',''''))) = case when isnull(dt.CountryCode,'''')<> '''' 
			            then  rtrim(ltrim(replace(dt.CountryCode,''+'','''')))
								else rtrim(ltrim(replace(ul.CountryCode1,''+'','''')))
								end
			AND rtrim(ltrim(ul.MobileNo1)) = case when isnull(dt.MobileNo,'''')<> '''' then  ltrim(rtrim(dt.mobileno))
								else ltrim(rtrim(ul.MobileNo1))
								end
								)
			OR ( rtrim(ltrim(replace(ul.CountryCode2,''+'',''''))) = case when isnull(dt.CountryCode,'''')<> '''' 
			              then rtrim(ltrim(replace(dt.CountryCode,''+'','''')))
								else rtrim(ltrim(replace(ul.CountryCode2,''+'','''')))
								end
			AND rtrim(ltrim(ul.MobileNo2)) = case when isnull(dt.MobileNo,'''')<> '''' then rtrim(ltrim(dt.mobileno))
								else rtrim(ltrim(ul.MobileNo2))
								end
								))
			AND ( Ul.EmailID = case when isnull(dt.emailid,'''')<>'''' then dt.emailid
								else ul.EmailID
								end
			or Ul.EmailID1 = case when isnull(dt.emailid,'''')<>'''' then dt.emailid
								else ul.EmailID1
								end
			or Ul.EmailID2 = case when isnull(dt.emailid,'''')<>'''' then dt.emailid
								else ul.EmailID2
								end )
			Where ul.parentid = '+cast(@parentid as varchar)+' and Rowid between '+cast(@start as varchar)+' and '+cast( @end as varchar)
			print @sqls
		
			Execute sp_executesql @sqls

			Update cflv 
			set cflv.fieldvalue=ucf.fieldvalue
			from customfieldleadvalue (NoLock) cflv 
			join #UpdateCustomfields ucf on cflv.leadid = ucf.leadid and cflv.fieldid =ucf.fieldid 
			where ucf.RowNo Between @start and @end

			Insert into customfieldleadvalue (LeadID,fieldID,fieldvalue,CreatedDate)
			select ucf.Leadid,ucf.Fieldid,ucf.FieldValue, GetDate() from customfieldleadvalue (NoLock) cflv 
			right join #UpdateCustomfields ucf on cflv.leadid = ucf.leadid and cflv.fieldid =ucf.fieldid 
			where cflv.recordID is null AND  ucf.RowNo Between @start and @end

			--Select Leadid,Fieldid,Fieldvalue, GetDate() from #UpdateCustomfields 
			--where  RowNo Between @start and @end and  Leadid not in (select Leadid from customfieldleadvalue (NoLock) ) and fieldid not in (select fieldid from customfieldleadvalue (NoLock))

			set @start = @start +500 
			Set @end = @end+500
		end
		
		set @Remarks = (select * from #FieldresTemp for Json auto, include_null_values)
		set @Leadcount = (select count (1) from #UpdateDetails)
		set @custcount = (select count(1) from #UpdateCustomfields)
		set @userlogin = (select User_login from User_detail (NoLock) where user_id= @userid)

		update Tbl_Lead_LeadUpdateImportData set Remarks=@Remarks , LeadCnt = @Leadcount ,LeadCustomFieldCnt=@custcount,  IsProcessed=1 ,importend=getdate()  where ImportRow_Id= @ImportId

		  select @eventname='User imported leads',@eventdescription=@userlogin +' uploaded ' +cast(@totaldata as nvarchar) +' leads for Updating.   
				   The request is processed and leads imported are '+cast( @Leadcount as nvarchar)   
				  exec UspSaveEntityActivity_withid 'user',@userid,@userid,@ParentID,@EventDescription,@EventName,'Tbl_Lead_LeadUpdateImportData',@ImportId  
				  exec Usp_InsertUserEventDetails 'Lead Import successful',@parentid,@eventdescription, 'Tbl_Lead_LeadUpdateImportData',@ImportId
           
		Select  @min= @min+1
	END
		Commit Transaction
		SET Context_Info 0x
	END TRY
		
	BEGIN CATCH
		While @@TRANCOUNT > 0
			ROLLBACK TRANSACTION
           
	   update Tbl_Lead_LeadUpdateImportData set Remarks=ERROR_MESSAGE() , IsValid = 0 , LeadCnt = 0 ,LeadCustomFieldCnt= 0,  IsProcessed = 1 ,importend=getdate()  where ImportRow_Id= @ImportId

		SET Context_Info 0x
		insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)        
		SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()  
   
	END CATCH
end




GO

/* ============================================================
   Procedure: [dbo].[usp_processvoicebotdemo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROCEDURE [dbo].[usp_processvoicebotdemo]
@id bigint=null
as
begin
if datepart(hh,getdate()) between 9 and 20
begin
drop table if exists #audienceid 
drop table if exists #t 
create table #audienceid(id bigint,campaignid bigint,recipient_mobile nvarchar(20))
select id,name,mobile,botid,cast(0 as bigint) as campaignid,cast(0 as bigint) as demoid into #t from tbl_Voice_bot_demorequest(nolock) where IsProcessed=0 and botid is not null
and id=case when @id is null then id else @id end
update t set campaignid=v.id from voice_bot_campaigns(nolock) v join #t t 
on t.botid=json_value(v.campaign_settings,'$.botId') and v.isdemo=1
INSERT INTO dbo.voice_bot_campaign_audience (
    parentid,
    vb_campaignid,
    created_on,
    recipient_mobile,
    recipient_countrycode,
    recipient_has_countrycode,
    entity_context,priority
    
)
OUTPUT INSERTED.id,inserted.vb_campaignid,inserted.recipient_mobile INTO #audienceid
SELECT
    34594,
    campaignid, -- point to cloned campaign
    GETDATE(), -- new created_on
    Mobile,
    '+91',
    0,
    '{"entity_name":"'+name+'"}',10
    FROM #t;

    update t set demoid=a.id from #t t join #audienceid a on t.campaignid=a.campaignid and t.mobile=a.recipient_mobile
    update v set audienceid=t.demoid,isprocessed=2,processedon=getdate() from tbl_Voice_bot_demorequest v join #t t on t.id=v.id
end



end



