as
begin

  --declare @ID BIGINT = 1397

if 1=1--datepart(hh,getdate()) between 9 and 21
begin
declare @botid bigint,@campaignid bigint,@greeting nvarchar(400),@parentid bigint
drop table if exists #audienceid 
drop table if exists #t 
create table #audienceid(id bigint,campaignid bigint,recipient_mobile nvarchar(20),recipient_countrycode nvarchar(10),greeting nvarchar(400),parentid bigint)
select id,name,countrycode,mobile,botid,cast(0 as bigint) as campaignid,cast(0 as bigint) as demoid , greeting,parentid
into #t from tbl_Voice_bot_demorequest(nolock) where IsProcessed=0 and 
botid is not null
and id=case when @id is null then id else @id end
--if 1=1-- @id is not null
--begin
