--select * from #t
INSERT INTO dbo.voice_bot_campaigns (parentid,created_by,    created_on,    campaign_name,    isactive,    campaign_settings,    last_run,    next_run,    total_reach,    campaign_end_date,    campaign_start_date)
Select    distinct parentid,    parentid,    GETDATE(),    'Demo_campaign',    1,
    N'{ "fromNumber": "'+case when isnull(countrycode,'+91')='+91' and mobile<>'9315028217' then '7965092406' else '18653446319' end+'",
  "campaignGoal": "demo",
  "botId": '+cast(botid as nvarchar)+',
