      "fromtime": "00:00",
      "totime": "23:59"
    },
    {
      "day": "Saturday",
      "fromtime": "00:00",
      "totime": "23:59"
    },
    {
      "day": "Sunday",
      "fromtime": "00:00",
      "totime": "23:59"
    }
  ],
  "is_followup": false,
