  "followup_depth_count": 0,
  "is_activities": false,
  "activities_depth_days": 0,
  "activities_depth_count": 0,
  "max_execution": 1000}',
    null,    null,    0,    null,    getdate() FROM #t v WHERE
    not exists(select 1 from voice_bot_campaigns where v.botId=json_value(campaign_settings,'$.botId')
    and v.greeting=json_value(campaign_settings,'$.pre_generated_opening') and json_value(campaign_settings,'$.fromNumber')=case when isnull(countrycode,'+91')='+91' and mobile<>'9315028217' then '7965092406' else '18653446319' end)
    
    
    ;


--select @CampaignId =SCOPE_IDENTITY()
--select * from voice_bot_campaigns(nolock) where id=@campaignid
--end
update t set campaignid=v.id from voice_bot_campaigns(nolock) v join #t t 

on t.botid=json_value(v.campaign_settings,'$.botId') and t.greeting=json_value(campaign_settings,'$.pre_generated_opening') --and v.isdemo=1

--select * from #t
INSERT INTO dbo.voice_bot_campaign_audience (
    parentid,
    vb_campaignid,
    created_on,
    recipient_mobile,
    recipient_countrycode,
    recipient_has_countrycode,
    entity_context,priority
    
)
OUTPUT
--INSERTED.id,inserted.vb_campaignid,inserted.recipient_mobile
 INSERTED.id,inserted.vb_campaignid,inserted.recipient_mobile, inserted.recipient_countrycode,inserted.entity_context ,inserted.parentid
INTO #audienceid
SELECT
    parentid,
    campaignid, -- point to cloned campaign
    GETDATE(), -- new created_on
    case when isnull(countrycode,'+91')='+91' and mobile<>'9315028217' then Mobile else countrycode+mobile end,
    isnull(countrycode,'+91'),
    0,
    isnull('{"entity_name":"'+name+'"}','{}'),10
    FROM #t;

    --select * from #audienceid
    --select * from voice_bot_campaign_audience where id in (select id from #audienceid)

    update t set demoid=a.id from #t t join #audienceid a on t.campaignid=a.campaignid and case when isnull(t.countrycode,'+91')='+91' and mobile<>'9315028217' then t.Mobile else t.countrycode+t.mobile end=a.recipient_mobile
    update v set audienceid=t.demoid,isprocessed=2,processedon=getdate() from tbl_Voice_bot_demorequest v join #t t on t.id=v.id
end

--select * from tbl_Voice_bot_demorequest(nolock) where id=@id

end



