/* ============================================================
   Procedure: [dbo].[Usp_ProcSelectWithoutAirtelNoAndAirtelCount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
--SP_HELPTEXT Usp_ProcSelectWithoutAirtelNoAndAirtelCount      
    
CREATE   PROC [dbo].[Usp_ProcSelectWithoutAirtelNoAndAirtelCount]            
@batchID bigint            
as        
Declare @CreditCount int    
select @CreditCount=count(Messages) from TempStorageAirtel tmp inner join AirTelSeries Air on tmp.MobileSubSet=Air.MobileSubSet where tmp.BatchID=@batchID            
 insert into MessageDeliveryStatus(MessageID,Mobile,Message,SenderID,U_ID,Priority,MessageRefID,MessageStatus,      
SmppID,ProviderReference,IsUniCode,LastError,StatusCode,MessageInsertDate,messagesubmitdate,messagedelivereddate)   
  select Msg_id,'91'+MobileNos,Messages,SenderID,userID,Priority,3,3,0,0,0,0,0,getdate(),getdate(),getdate() from TempStorageAirtel            
  join DNDDirectory                        
  on                         
  DNDDirectory.DNDMobileNo=TempStorageAirtel.MobileNos                 
  WHERE TempStorageAirtel.BatchID=@batchID            
          
--  Declare @DNDAirtelCount bigint    
--      
--  select @DNDAirtelCount= count(MobileNos) FROM  TempStorageAirtel JOIN DNDDirectory                     
--  ON DNDDirectory.DNDMobileNo=TempStorageAirtel.MobileNos              
--  WHERE TempStorageAirtel.BatchID=@batchID             
--                
  DELETE TempStorageAirtel FROM  TempStorageAirtel JOIN DNDDirectory                     
  ON DNDDirectory.DNDMobileNo=TempStorageAirtel.MobileNos              
  WHERE TempStorageAirtel.BatchID=@batchID             
       
select * from TempStorageAirtel  WHERE TempStorageAirtel.BatchID=@batchID       
insert into [AirtelMsgStorage] (UserID,Mobile,[Message],SenderID,Priority,BatchID) select tmp.userID,tmp.MobileNos,tmp.Messages,tmp.SenderID,tmp.Priority,tmp.BatchID from TempStorageAirtel tmp inner join AirTelSeries Air on tmp.MobileSubSet=Air.MobileSubSet where tmp.BatchID=@batchID            
delete TempStorageAirtel from  TempStorageAirtel tmp inner join AirTelSeries Air on tmp.MobileSubSet=Air.MobileSubSet where tmp.BatchID=@batchID            
            
--select             
--M_ID,             
--userID,             
--MobileNos,             
--Messages  ,                  
--SenderID ,                  
--Priority  from  TempStorageAirtel where BatchID=@batchID            
delete from TempStorageAirtel  where BatchID=@batchID         
select @CreditCount     
--select @DNDAirtelCount    
--delete from AirtelMsgStorage where BatchID=@batchID





GO

/* ============================================================
   Procedure: [dbo].[Usp_ProductMassUpdate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.Usp_ProductMassUpdate  
(  
 @strProductIDs nvarchar(max),  
 @letActiveStatus bit,  
 @letInactiveStatus bit,  
 @letPublishedStatus bit,  
 @letUnpublishedStatus bit,  
 @letFeaturedStatus bit,  
 @letNotFeaturedStatus bit,  
 @letCategoryStatus bit,  
 @letCategoryValue int,  
 @letHSNStatus bit,  
 @letHSNValue nvarchar(50),  
 @letSACStatus bit,  
 @letSACValue nvarchar(50),  
 @letUnitStatus bit,  
 @letUnitValue int,  
 @letSellingPriceStatus bit,  
 @letSellingPriceValue numeric(18,2),  
 @letCostPriceStatus bit,  
 @letCostPriceValue numeric(18,2)  
)  
as  
Begin  
  
     select  cast(isnull(value,0) as bigint)  as ProductID into #TBL_ProductIDs  from fn_split(@strProductIDs,',')    
  
  if(@letActiveStatus = 1)  
    Begin  
       update ProductMaster set IsActive = 1 where ProductID  
         in (select ProductID from #TBL_ProductIDs)  
    End  
  
   if(@letInactiveStatus = 1)  
    Begin  
       update ProductMaster set IsActive = 0 where ProductID  
         in (select ProductID from #TBL_ProductIDs)  
    End  
  
   if(@letPublishedStatus = 1)  
    Begin  
       update ProductMaster set IsPublished = 1 where ProductID  
         in (select ProductID from #TBL_ProductIDs)  
    End  
      
    if(@letUnpublishedStatus = 1)  
    Begin  
       update ProductMaster set IsPublished = 0 where ProductID  
         in (select ProductID from #TBL_ProductIDs)  
    End  
  
    if(@letFeaturedStatus = 1)  
    Begin  
       update ProductMaster set IsFeatured = 1 where ProductID  
         in (select ProductID from #TBL_ProductIDs)  
    End  
  
    if(@letNotFeaturedStatus = 1)  
    Begin  
       update ProductMaster set IsFeatured = 0 where ProductID  
         in (select ProductID from #TBL_ProductIDs)  
    End  
  
    if(@letCategoryStatus = 1)  
    Begin  
       update ProductMaster set category_id = @letCategoryValue where ProductID  
         in (select ProductID from #TBL_ProductIDs)  
    End  
      
    if(@letHSNStatus = 1)  
    Begin  
       update ProductMaster set HSNCode = @letHSNValue where ProductID  
         in (select ProductID from #TBL_ProductIDs)  
      and isnull(IsGoods,0) = 1  
    End  
  
    if(@letSACStatus = 1)  
    Begin  
       update ProductMaster set SACCode = @letSACValue where ProductID  
         in (select ProductID from #TBL_ProductIDs)  
      and isnull(IsServices,0) = 1  
    End  
      
    if(@letUnitStatus = 1)  
    Begin  
       update ProductMaster set UnitID = @letUnitValue where ProductID  
         in (select ProductID from #TBL_ProductIDs)  
    End  
  
    if(@letSellingPriceStatus = 1)  
    Begin  
           declare @salepricePRM numeric(18,2) = 100  
     set @salepricePRM =   (@salepricePRM + @letSellingPriceValue)  
       
       update ProductMaster set Price = ((isnull(price,0) * @salepricePRM)/100) where ProductID  
         in (select ProductID from #TBL_ProductIDs)  
    End  
  
    if(@letCostPriceStatus = 1)  
    Begin  
           declare @costpricePRM numeric(18,2) = 100  
     set @costpricePRM =   (@costpricePRM + @letCostPriceValue)  
       
       update ProductMaster set Cast_Price = ((isnull(Cast_Price,0) * @costpricePRM)/100) where ProductID  
         in (select ProductID from #TBL_ProductIDs)  
    End  
  
  
       
  select 'Data Updated' as msg  
  
  drop table #TBL_ProductIDs     
End




GO

/* ============================================================
   Procedure: [dbo].[Usp_ProductMassUpdate_WithParentID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[Usp_ProductMassUpdate_WithParentID]    
(    
 @strProductIDs nvarchar(max),    
 @letActiveStatus bit,    
 @letInactiveStatus bit,    
 @letPublishedStatus bit,    
 @letUnpublishedStatus bit,    
 @letFeaturedStatus bit,    
 @letNotFeaturedStatus bit,    
 @letCategoryStatus bit,    
 @letCategoryValue int,    
 @letHSNStatus bit,    
 @letHSNValue nvarchar(50),    
 @letSACStatus bit,    
 @letSACValue nvarchar(50),    
 @letUnitStatus bit,    
 @letUnitValue int,    
 @letSellingPriceStatus bit,    
 @letSellingPriceValue numeric(18,2),    
 @letCostPriceStatus bit,    
 @letCostPriceValue numeric(18,2),
 @ParentID bigint     
)    
as    
Begin    
    
	  exec Usp_createProductMasterTable @ParentID

     select  cast(isnull(value,0) as bigint)  as ProductID into #TBL_ProductIDs  from fn_split(@strProductIDs,',')      
    
  if(@letActiveStatus = 1)    
    Begin    
      Declare @Q1 nvarchar(max) = N' update tbl_ProductMaster_' + cast(@ParentID as nvarchar(20))+ ' set IsActive = 1 where ProductID    
            in (select ProductID from #TBL_ProductIDs) '
	   exec sp_executesql @Q1    		
			    
    End    
    
   if(@letInactiveStatus = 1)    
    Begin    
       
	  Declare @Q2 nvarchar(max) = N' 
	   update tbl_ProductMaster_' + cast(@ParentID as nvarchar(20))+ ' set IsActive = 0 where ProductID    
         in (select ProductID from #TBL_ProductIDs) ' 
		 exec sp_executesql @Q2
		    
    End    
    
   if(@letPublishedStatus = 1)    
    Begin    
    
	Declare @Q3 nvarchar(max) = N'   update tbl_ProductMaster_' + cast(@ParentID as nvarchar(20))+ ' set IsPublished = 1 where ProductID    
         in (select ProductID from #TBL_ProductIDs) '
		 exec sp_executesql @Q3    
    
	End    
        
    if(@letUnpublishedStatus = 1)    
    Begin    
      declare @Q4 nvarchar(max) = N' 
	   update tbl_ProductMaster_' + cast(@ParentID as nvarchar(20))+ ' set IsPublished = 0 where ProductID    
         in (select ProductID from #TBL_ProductIDs) '
		 
		 exec sp_executesql @Q4
		     
    End    
    
    if(@letFeaturedStatus = 1)    
    Begin    
       declare @Q5 nvarchar(max) = N'
	     update tbl_ProductMaster_' + cast(@ParentID as nvarchar(20))+ ' set IsFeatured = 1 where ProductID    
         in (select ProductID from #TBL_ProductIDs) '
		 
		 exec sp_executesql @Q5
		     
    End    
    
    if(@letNotFeaturedStatus = 1)    
    Begin    
       declare @Q6 nvarchar(max) = N'
	   update tbl_ProductMaster_' + cast(@ParentID as nvarchar(20))+ ' set IsFeatured = 0 where ProductID    
         in (select ProductID from #TBL_ProductIDs) '
	    exec sp_executesql @Q6     	 
		     
    End    
    
    if(@letCategoryStatus = 1)    
    Begin    
      declare @Q7 nvarchar(max) = N'
	   update tbl_ProductMaster_' + cast(@ParentID as nvarchar(20))+ ' set category_id = '+ cast(@letCategoryValue as nvarchar(20))+ ' where ProductID    
         in (select ProductID from #TBL_ProductIDs) '    
      exec sp_executesql @Q7 
	End    
        
    if(@letHSNStatus = 1)    
    Begin  
	  declare @Q8 nvarchar(max) = N'	    
       update tbl_ProductMaster_' + cast(@ParentID as nvarchar(20))+ ' set HSNCode = '+ cast( @letHSNValue as nvarchar(20)) +' where ProductID    
         in (select ProductID from #TBL_ProductIDs)    
      and isnull(IsGoods,0) = 1  '  

	  exec sp_executesql @Q8

    End    
    
    if(@letSACStatus = 1)    
    Begin    
     declare @Q9 nvarchar(max) = N'
	   update tbl_ProductMaster_' + cast(@ParentID as nvarchar(20))+ ' set SACCode = ' + cast(@letSACValue as nvarchar(20)) + ' where ProductID    
         in (select ProductID from #TBL_ProductIDs)    
      and isnull(IsServices,0) = 1 '   
	  exec sp_executesql @Q9

    End    
        
    if(@letUnitStatus = 1)    
    Begin    
       declare @Q10 nvarchar(max) = N'
	   update tbl_ProductMaster_' + cast(@ParentID as nvarchar(20))+ ' set UnitID = '+ cast(@letUnitValue as nvarchar(20)) + ' where ProductID    
         in (select ProductID from #TBL_ProductIDs) '
		 exec sp_executesql @Q10    
    End    
    
    if(@letSellingPriceStatus = 1)    
    Begin    
           declare @salepricePRM numeric(18,2) = 100    
     set @salepricePRM =   (@salepricePRM + @letSellingPriceValue)    
     
	 declare @Q11 nvarchar(max) = N'	     
       update tbl_ProductMaster_' + cast(@ParentID as nvarchar(20))+ ' set Price = ((isnull(price,0) * '+ cast(@salepricePRM as nvarchar(max)) +')/100) where ProductID    
         in (select ProductID from #TBL_ProductIDs) ' 
		 
		 exec sp_executesql @Q11   
    End    
    
    if(@letCostPriceStatus = 1)    
    Begin    
           declare @costpricePRM numeric(18,2) = 100    
     set @costpricePRM =   (@costpricePRM + @letCostPriceValue)    
       declare @Q12 nvarchar(max) =N'   
       update tbl_ProductMaster_' + cast(@ParentID as nvarchar(20))+ ' set CostPrice = ((isnull(CostPrice,0) * '+ cast( @costpricePRM as nvarchar(20)) + ' )/100) where ProductID    
         in (select ProductID from #TBL_ProductIDs)  '

		exec sp_executesql @Q12       
    End    
    
    
         
  select 'Data Updated' as msg    
    
  drop table #TBL_ProductIDs       
End  
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_ProductMasterByParentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_ProductMasterByParentId] @userid BIGINT
	,@oldCustomfield NVARCHAR(max) = NULL
	,@customfield NVARCHAR(max) = NULL
	,@datatype NVARCHAR(max) = NULL
	,@default NVARCHAR(max) = NULL
	,@maxvalue NVARCHAR(max) = NULL
	,@minvalue NVARCHAR(max) = NULL
	,@ismandatory BIT = 0
	,@choices NVARCHAR(max) = NULL
	,@fieldtype NVARCHAR(max) = NULL
	,@displayJson NVARCHAR(max) = NULL
	,@jchoice NVARCHAR(max) = NULL
	,@mode VARCHAR(20) = ''
AS
BEGIN
	DECLARE @parentid BIGINT = (
			SELECT ParentID
			FROM User_Detail
			WHERE user_id = @userid
			)
	DECLARE @sqls NVARCHAR(max) = ''
		,@status INT
		,@tableName NVARCHAR(max) = ''

	DROP TABLE

	IF EXISTS #temp
		CREATE TABLE #temp (
			FieldName NVARCHAR(max)
			,DataType NVARCHAR(Max)
			,DefaultValue NVARCHAR(Max)
			,Mandatory BIT
			,FieldType NVARCHAR(Max)
			,MaxValue NVARCHAR(Max)
			,MinValue NVARCHAR(MAX)
			,Choices NVARCHAR(MAX)
			)

	EXEC @status = Usp_CreateProductTableByParentID @userid
		,@tableName OUTPUT

	IF (@status = 1)
	BEGIN
		IF @mode = 'Save'
		BEGIN
			IF @customfield IS NOT NULL
			BEGIN
				IF EXISTS (
						SELECT 1
						FROM INFORMATION_SCHEMA.COLUMNS
						WHERE TABLE_NAME = @tableName
							AND TABLE_CATALOG = db_name()
							AND COLUMN_NAME = @customfield
						)
				BEGIN
					SELECT 'Field Name Already Exists'
				END
				ELSE
				BEGIN
					SET @sqls = 'alter table ' + @tableName + ' add ' + @customfield + ' ' + @datatype

					PRINT @sqls

					EXECUTE sp_executesql @sqls

					IF @ismandatory = 1
					BEGIN
						SET @sqls = 'update ' + @tableName + ' set ' + @customfield + ' = 0 where ' + @customfield + ' IS NULL ;'

						--print @sqls      
						EXECUTE sp_executesql @sqls

						SET @sqls = 'alter table ' + @tableName + ' Alter column ' + @customfield + '  ' + @datatype + '  NULL'

						--print @sqls      
						EXECUTE sp_executesql @sqls
					END

					IF @default IS NOT NULL
					BEGIN
						IF @default = 'getdate()'
						BEGIN
							SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @customfield + 'DateCurr Default ' + @default + ' for ' + @customfield
						END
						ELSE IF @datatype = 'DateTime'
							AND @default <> 'getdate()'
						BEGIN
							SET @sqls = CONCAT (
									'alter table '
									,@tableName
									,' add CONSTRAINT pm' + @customfield + 'DateDef Default cast('
									,@default
									,'as datetime)   for '
									,@customfield
									)
						END
						ELSE IF @datatype = 'bigint'
						BEGIN
							SET @sqls = CONCAT (
									'alter table '
									,@tableName
									,' add CONSTRAINT pm' + @customfield + 'NumDef Default '
									,@default
									,'  for '
									,@customfield
									)
						END
						ELSE
						BEGIN
							SET @sqls = CONCAT (
									'alter table '
									,@tableName
									,' add CONSTRAINT pm' + @customfield + 'Def Default '''
									,@default
									,'''  for '
									,@customfield
									)
						END

						PRINT @sqls

						EXECUTE sp_executesql @sqls
					END

					IF @maxvalue IS NOT NULL
					BEGIN
						IF @datatype = 'DateTime'
						BEGIN
							SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @customfield + 'DateMax Check (' + @customfield + ' <= cast(' + @maxvalue + '  as datetime))'

							--print @sqls      
							EXECUTE sp_executesql @sqls
						END
						ELSE
						BEGIN
							SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @customfield + 'NumMax Check (' + @customfield + ' <= ' + @maxvalue + ' )'

							--print @sqls      
							EXECUTE sp_executesql @sqls
						END
					END

					IF @minvalue IS NOT NULL
					BEGIN
						IF @datatype = 'DateTime'
						BEGIN
							SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @customfield + 'DateMin Check (' + @customfield + ' >= cast(' + @minvalue + 'as datetime) )'

							--print @sqls      
							EXECUTE sp_executesql @sqls
						END
						ELSE
						BEGIN
							SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @customfield + 'NumMin Check (' + @customfield + ' >= ' + @minvalue + ' )'

							--print @sqls      
							EXECUTE sp_executesql @sqls
						END
					END

					IF @choices IS NOT NULL
						AND @fieldtype <> 'multiselect'
					BEGIN
						SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @customfield + 'choice Check (' + @customfield + ' ' + @choices + ')'

						--print @sqls    
						EXECUTE sp_executesql @sqls
					END

					IF @fieldtype IS NOT NULL
					BEGIN
						INSERT INTO #temp (
							FieldName
							,DataType
							,DefaultValue
							,Mandatory
							,FieldType
							,MaxValue
							,MinValue
							,Choices
							)
						VALUES (
							@customfield
							,@datatype
							,ISNULL(Replace(@default, '''', ''), '')
							,@ismandatory
							,@fieldtype
							,ISNULL(Replace(@maxvalue, '''', ''), '')
							,ISNULL(Replace(@minvalue, '''', ''), '')
							,ISNULL(@jchoice, '')
							)

						SET @displayJson = (
								SELECT *
								FROM #temp
								FOR json Auto
									,INCLUDE_NULL_VALUES
								)

						EXECUTE Usp_InsertProductFieldDisplayJson @displayJson = @displayJson
							,@parentid = @parentid
							,@mode = @mode
					END

					SELECT 'Field Added Successfully '
				END
			END
		END
		ELSE IF @mode = 'Update'
		BEGIN
			IF @customfield IS NOT NULL
			BEGIN
				IF EXISTS (
						SELECT 1
						FROM sys.tables t
						JOIN sys.default_constraints d ON d.parent_object_id = t.object_id
						JOIN sys.columns c ON c.object_id = t.object_id
							AND c.column_id = d.parent_column_id
						WHERE t.name = @tableName
							AND c.name = @oldCustomfield
						)
				BEGIN
					SELECT @sqls = 'ALTER TABLE ' + @tableName + ' drop constraint ' + d.name + CHAR(10) + CHAR(13)
					FROM sys.tables t
					JOIN sys.default_constraints d ON d.parent_object_id = t.object_id
					JOIN sys.columns c ON c.object_id = t.object_id
						AND c.column_id = d.parent_column_id
					WHERE t.name = @tableName
						AND c.name = @oldCustomfield

					PRINT @sqls

					EXECUTE sp_executesql @sqls
				END

				IF EXISTS (
						SELECT 1
						FROM sys.tables t
						JOIN sys.check_constraints d ON d.parent_object_id = t.object_id
						JOIN sys.columns c ON c.object_id = t.object_id
							AND c.column_id = d.parent_column_id
						WHERE t.name = @tableName
							AND c.name = @oldCustomfield
						)
				BEGIN
					SELECT @sqls = 'ALTER TABLE ' + @tableName + ' drop constraint ' + d.name + CHAR(10) + CHAR(13)
					FROM sys.tables t
					JOIN sys.check_constraints d ON d.parent_object_id = t.object_id
					JOIN sys.columns c ON c.object_id = t.object_id
						AND c.column_id = d.parent_column_id
					WHERE t.name = @tableName
						AND c.name = @oldCustomfield

					PRINT @sqls

					EXECUTE sp_executesql @sqls
				END

				SET @sqls = CONCAT (
						'EXEC sp_rename @objname = '''
						,@tableName
						,'.'
						,@oldCustomfield
						,''', @newname = '''
						,@customfield
						,''', @objtype = '
						,'''COLUMN'''
						);

				PRINT @sqls

				EXECUTE sp_executesql @sqls
			END

			IF @choices IS NOT NULL
				AND @fieldtype <> 'multiselect'
			BEGIN
				SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @customfield + 'choice Check (' + @customfield + ' ' + @choices + ')'

				--print @sqls      
				EXECUTE sp_executesql @sqls
			END

			IF @default IS NOT NULL
			BEGIN
				IF @default = 'getdate()'
				BEGIN
					SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @customfield + 'DateCurr Default ' + @default + ' for ' + @customfield

					PRINT @sqls

					EXECUTE sp_executesql @sqls
				END
				ELSE IF @datatype = 'DateTime'
					AND @default <> 'getdate()'
				BEGIN
					SET @sqls = CONCAT (
							'alter table '
							,@tableName
							,' add CONSTRAINT pm' + @customfield + 'DateDef Default cast('
							,@default
							,'as datetime)   for '
							,@customfield
							)

					PRINT @sqls

					EXECUTE sp_executesql @sqls
				END
				ELSE IF @datatype = 'bigint'
				BEGIN
					SET @sqls = CONCAT (
							'alter table '
							,@tableName
							,' add CONSTRAINT pm' + @customfield + 'NumDef Default '
							,@default
							,'  for '
							,@customfield
							)

					PRINT @sqls

					EXECUTE sp_executesql @sqls
				END
				ELSE
				BEGIN
					SET @sqls = CONCAT (
							'alter table '
							,@tableName
							,' add CONSTRAINT pm' + @customfield + 'Def Default '''
							,@default
							,'''  for '
							,@customfield
							)

					PRINT @sqls

					EXECUTE sp_executesql @sqls
				END
			END

			EXECUTE Usp_InsertProductFieldDisplayJson @displayJson = @displayJson
				,@parentid = @parentid
				,@mode = @mode
				,@customField = @customfield
				,@isman = @ismandatory
				,@default = @default
				,@choices = @jchoice
				,@oldcustomField = @oldcustomField

			SELECT 'Field Updated'
		END
	END
	ELSE
	BEGIN
		SELECT @tableName
	END

	IF @mode = 'Select'
	BEGIN
		--Select COLUMN_NAME, DATA_TYPE,COLUMN_DEFAULT From INFORMATION_SCHEMA.COLUMNS where TABLE_NAME=@tableName and TABLE_CATALOG='mysms_dev' and COLUMN_NAME not in ('ProductID','Name',      
		--  'UserID','Image','Description','Price','IsPublished','IsActive','CreatedOn','CreatedBy','FullPath','IsFeatured','sku','sale_priceNoUSE',      
		--  'quantity','category_id','HomeTaxIDs','OtherTaxIDs','tax_idNoUSE','UpdatedAt','DeletedAt','SellingAccount','Cast_Price','Cast_Account',      
		--  'IsDigitalService','IsGoods','IsServices','SACCode','HSNCode','IsTaxable','DecimalRateItemQuantity','UnitID','IsSaleable','Color')      
		SELECT @displayJson = DisplayJson
		FROM tbL_ProductCustomFieldDisplayJson
		WHERE ParentId = @parentid  and isnull(iscatalogue,0) = 1 --null  

		DROP TABLE

		IF EXISTS #temp
			CREATE TABLE #temp2 (
				FieldName NVARCHAR(max)
				,DataType NVARCHAR(Max)
				,DefaultValue NVARCHAR(Max)
				,Mandatory BIT
				,FieldType NVARCHAR(Max)
				,MaxValue NVARCHAR(Max)
				,MinValue NVARCHAR(MAX)
				,Choices NVARCHAR(MAX)
				)

		INSERT INTO #temp2 (
			FieldName
			,DataType
			,DefaultValue
			,Mandatory
			,FieldType
			,MaxValue
			,MinValue
			,Choices
			)
		SELECT FieldName
			,DataType
			,DefaultValue
			,Mandatory
			,FieldType
			,MaxValue
			,MinValue
			,Choices
		FROM OPENJSON(@displayJson) WITH (
				FieldName NVARCHAR(max) '$.FieldName'
				,DataType NVARCHAR(Max) '$.DataType'
				,DefaultValue NVARCHAR(Max) '$.DefaultValue'
				,Mandatory NVARCHAR(Max) '$.Mandatory'
				,FieldType NVARCHAR(Max) '$.FieldType'
				,MaxValue NVARCHAR(Max) '$.MaxValue'
				,MinValue NVARCHAR(MAX) '$.MinValue'
				,Choices NVARCHAR(MAX) '$.Choices'
				)

		SELECT *
		FROM #temp2
	END
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_ProductMasterColumnByParentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ProductMasterColumnByParentId] 
(
 @userid bigint ,     
 @oldCustomfield nvarchar(max)=null,    
 @customfield nvarchar(max)=null,        
 @datatype nvarchar(max)=null,        
 @default nvarchar(max)=null,      
 @maxvalue nvarchar (max)=null,      
 @minvalue nvarchar(max)=null,      
 @ismandatory bit=0,      
 @choices nvarchar(max)=null,    
 @fieldtype nvarchar(max)=null,    
 @displayJson nvarchar(max) =Null,    
 @jchoice nvarchar(max)=null,    
 @mode varchar(20)=''      
)   
 AS         
 BEGIN        
      
  declare @parentid bigint = (Select ParentID from User_Detail where user_id = @userid)        
  declare @sqls nvarchar(max) = '',   @status int ,    
  @tableName nvarchar(max)= ''      
     DROP TABLE IF EXISTS #temp    
     CREATE TABLE #temp (              
    FieldName NVARCHAR(max),              
    DataType NVARCHAR(Max),     
    DefaultValue NVARCHAR(Max),    
    Mandatory bit,    
    FieldType NVARCHAR(Max),    
    MaxValue NVARCHAR(Max),    
    MinValue NVARCHAR(MAX),    
    Choices NVARCHAR (MAX)    
    )       
   EXEC @status = Usp_CreateProductTableByParentID @userid, @tableName output    
   if(@status=1)    
   BegiN    
     declare @Query nvarchar(max), @Query2 nvarchar(max)
   --set @Query = 'Select * from ' + @tableName +' where UserId = '+ cast(@userid as varchar(100));

   set @Query = 'SELECT TABLE_NAME, ORDINAL_POSITION COLUMN_Id, COLUMN_NAME, DATA_TYPE, CHARACTER_MAXIMUM_LENGTH, COLUMN_DEFAULT,
(case when IS_NULLABLE = ''NO'' then 0 else 1 end) IS_NULLABLE FROM INFORMATION_SCHEMA.COLUMNS where TABLE_NAME =''' + @tableName + '''';
   print @Query
   exec sp_executesql @Query

   set @Query2 = 'select distinct tbl.TABLE_NAME, sc.column_id COLUMN_Id, sc.name COLUMN_NAME, sty.name DATA_TYPE, 
   sc.max_length CHARACTER_MAXIMUM_LENGTH, sc.default_object_id COLUMN_DEFAULT, sc.IS_NULLABLE, sep.value [DESCRIPTION]
from sys.tables st
inner join information_schema.tables tbl on st.object_id=object_id(tbl.table_schema + ''.'' + tbl.table_name) and tbl.TABLE_NAME = ''tbl_WA_CommerceFields''
inner join sys.columns sc on st.object_id = sc.object_id
inner join sys.types sty on sc.system_type_id = sty.system_type_id and sty.name != ''sysname''
left join sys.extended_properties sep on st.object_id = sep.major_id
                                         and sc.column_id = sep.minor_id
                                         and sep.name = ''MS_Description''';

--   set @Query2 = 'SELECT TABLE_NAME, ORDINAL_POSITION COLUMN_Id, COLUMN_NAME, DATA_TYPE, CHARACTER_MAXIMUM_LENGTH, COLUMN_DEFAULT, IS_NULLABLE, CHARACTER_MAXIMUM_LENGTH FROM INFORMATION_SCHEMA.COLUMNS where TABLE_NAME =''tbl_WA_CommerceFields''';

   print @Query2
   exec sp_executesql @Query2 
 
 END 
 END 



GO

/* ============================================================
   Procedure: [dbo].[Usp_ProductRemoval]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_ProductRemoval --40898
(
  @ParentID bigint    
)
as
 begin
         --declare @ParentID bigint = 40898   

        drop table if exists #tempProductIDTbl 
		
		create table #tempProductIDTbl
		    (
			  ProductID nvarchar(50) 
			)


       declare @QUERY1 nvarchar(max) =
	     ' insert into #tempProductIDTbl (ProductID)
		    select ProductID from tbl_productmaster_' + cast(@ParentID as nvarchar(50)) + ' with(nolock)
            where Name in (
           select
		      (  select ProductName from openjson (ProductsJson) with (ProductName nvarchar(200)))
		         from UserLeads with(nolock) 
	             where ParentID = ' + cast(@ParentID as nvarchar(50)) + ' and isnull(ProductsJson,'''') != ''''  
			  ) '

        exec sp_executesql @QUERY1
 		

        declare @QUERY2 nvarchar(max) = '  
        insert into #tempProductIDTbl (ProductID)  
         select ProductID from tbl_productmaster_' + cast(@ParentID as nvarchar(50)) + ' with(nolock)
            where Name in (
        select
		      (  select ProductName from openjson (ProductsJson) with (ProductName nvarchar(200)))
		         from LeadInteractionHistory with(nolock) 
	             where ParentID = ' + cast(@ParentID as nvarchar(50)) + ' and isnull(ProductsJson,'''') != ''''  
			  ) '
        
		 exec sp_executesql @QUERY2
		-- select distinct ProductID from #tempProductIDTbl


		insert into #tempProductIDTbl (ProductID)  
		SELECT product_id FROM [MySMSInvoicing].[dbo].[quote_items] with(nolock) where ParentId  = @ParentID and isnull(product_id,0) <> 0
		
		insert into #tempProductIDTbl (ProductID)  
		SELECT product_id FROM [MySMSInvoicing].[dbo].[invoice_items] with(nolock) where ParentId  = @ParentID and isnull(product_id,0) <> 0
		 
		--select distinct ProductID from #tempProductIDTbl

		Declare @QueryFinal1 nvarchar(max) = '
		         delete from tbl_productmaster_' + cast(@ParentID as nvarchar(50)) + ' 
				 where productId not in ( 
				             select distinct ProductID from #tempProductIDTbl
				          ) '
		 
		 print @QueryFinal1
		 exec sp_executesql @QueryFinal1	 

		 Declare @QueryFinal2 nvarchar(max) = '
		         update t set t.Isactive = 0 from tbl_productmaster_' + cast(@ParentID as nvarchar(50)) + '  as t
				 where productId in ( 
				             select distinct ProductID from #tempProductIDTbl
				          ) '
		 
		 print @QueryFinal2
		 exec sp_executesql @QueryFinal2


	    drop table if exists #tempProductIDTbl     
  end





GO

