SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ProductSearchCriteriaConditions_CriteriaName]   
(
 @CriteriaName varchar(30) = null, 
 @UserId [bigint] = NULL 
) 
AS 
  SET NOCOUNT ON   
  BEGIN TRY   
  begin   
  Declare @ParentId bigint = (Select top 1 ParentId from Mysms.dbo.User_Detail(nolock) where User_ID = @UserId)   

  Select pc.Id, pc.CriteriaName, pc.CriteriaType, pc.ProductIDs, pc.AllProductDefault, pc.SearchApplyTo, pc.OrderBy 
  from ProductSearchCriteria pc 
  where pc.ParentID = @parentId and pc.CriteriaName like '%'+ @CriteriaName +'%' 
  end 
 END TRY 
BEGIN CATCH 
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR (@ErrorMessage, 16, 1); 
END CATCH 



