/* ============================================================
   Procedure: [dbo].[usp_pt_AddRemoveLicensesAnnually]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_pt_AddRemoveLicensesAnnually]
(
    @P_userId BIGINT,
    @P_ReceiverUID BIGINT,
    @P_No_Of_Licenses INT,
	@AddRemoveLicence varchar(50)=null
)
AS
BEGIN
   -- Declare variables
    DECLARE @InsertedLicenseId VARCHAR(MAX) = '0';
    DECLARE @LicenseMetadata VARCHAR(MAX);
	Declare @ParentID  bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @P_ReceiverUID )--456        
      --Declare @MID_P  bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID ) --1
	   Declare @MID_P  bigint = ( select top 1 isnull(reseller_id,0) from reseller_detail with(nolock) where User_ID = @P_userId )
	declare @balance bigint,@default_credit bigint,@rmid bigint,@ruid bigint,@rbal bigint,@rcid bigint,@MIDUser bigint;
	declare @rvalidity nvarchar(300),@rdefault_credit nvarchar(300),@temp nvarchar(800),@finalbalance2 bigint,@finalbalance bigint,@creditup bigint,@rCredit bigint,@uCredits bigint;
	Declare @PartnerType int =0;

    BEGIN TRY
	select top(1) @MIDUser=  m_id  from User_Detail with(nolock) where user_id=@P_userId  --null         
	--select top(1) @rmid=m_id, @ruid=user_id from reseller_detail where reseller_id=@MIDUser --null         
	select top(1) @rbal=Balance from tbl_pt_ParnerAnnualLicence with(nolock) where ToUserId=@P_userId order by Id  desc -- balace of parent partner(335)                             
	select top(1) @balance=balance from tbl_pt_ParnerAnnualLicence with(nolock) where ToUserId=@P_ReceiverUID order by Id desc  -- balace of chld partner(456)         
       

		IF @AddRemoveLicence = 'Add Licence'
        BEGIN
            -- Calculate balances for 'Add Licence'
            --SET @NewBalance = ISNULL(@balance, 0) + @P_No_Of_Licenses;
            --SET @NewBalanceFromUser = ISNULL(@rbal, 0) - @P_No_Of_Licenses;
			 DECLARE @NewBalance INT = ISNULL(@balance, 0) + @P_No_Of_Licenses;  --balace of child partner after addition

		 DECLARE @NewBalanceFromUser INT = ISNULL(@rbal, 0) - @P_No_Of_Licenses; --balace of parent partner after addition


            BEGIN TRANSACTION;

            -- Insert for child partner (credit)
            INSERT INTO tbl_pt_ParnerAnnualLicence (Mid, FromUserId, ToUserId, LicenceExpiryDate, CreatedOn, CreatedBy, Credit, Debit, Balance, Remarks, TypeCredit)
            VALUES (@MIDUser, @P_userId, @P_ReceiverUID, DATEADD(YEAR, 1, GETDATE()), GETDATE(), @P_userId, @P_No_Of_Licenses, 0, @NewBalance, 'License Received', 0);

            SELECT @InsertedLicenseId = SCOPE_IDENTITY();

            -- Insert for parent partner (debit)
            INSERT INTO tbl_pt_ParnerAnnualLicence (Mid, FromUserId, ToUserId, LicenceExpiryDate, CreatedOn, CreatedBy, Credit, Debit, Balance, Remarks, TypeCredit)
            VALUES (@MID_P, @P_ReceiverUID, @P_userId, DATEADD(YEAR, 1, GETDATE()), GETDATE(), @P_userId, 0, @P_No_Of_Licenses, @NewBalanceFromUser, 'License Debited', 0);



			-----  activity    -----
			SELECT @InsertedLicenseId = SCOPE_IDENTITY();
			SELECT @PartnerType = TYPE FROM User_Detail(nolock)  where USER_ID = @P_ReceiverUID;

			Declare @Eventdata varchar(max), @UserName varchar(255), @PartnerUserName varchar(255) , @ChildPartnerName varchar(255);
			
			select @UserName = User_login from User_Detail with(nolock) where User_ID = @P_userid;
			select @PartnerUserName = User_login from User_Detail with(nolock) where User_ID = @MID_P;
			select @ChildPartnerName = User_login from User_Detail with(nolock) where User_ID = @P_ReceiverUID;
		
			SET @Eventdata = '{"#parentpartnername#":"'+ @PartnerUserName +'","#childpartnername#":"'+ @ChildPartnerName +'"}';

			IF (@PartnerType = 3)
			BEGIN
				
				---select * from ActivityMaster  where EventName like '%partner%' 
					--#parentpartnername# assigned a license to white-labeled partner #childpartnername# 
			    exec usp_pm_PartnerActivity @P_userid,@P_userid,@P_ReceiverUID,'Partner Assigned License to White-Labeled Partner',@Eventdata,'tbl_pt_ParnerAnnualLicence',@InsertedLicenseId; 
 
			END
			ELSE BEGIN
				exec usp_pm_PartnerActivity @P_userid,@P_userid,@P_ReceiverUID,
				'Partner Assigned License to Non-White-Labeled Partner',@Eventdata,'tbl_pt_ParnerAnnualLicence',@InsertedLicenseId; ;
			END
			----- activity end  ---

            COMMIT;

            SELECT 1 AS Status, 'License creation successful!' AS Message;
        END
        ELSE IF @AddRemoveLicence = 'Remove Licence'
        BEGIN
            -- Calculate balances for 'Remove Licence'
            --SET @NewBalance = ISNULL(@balance, 0) - @P_No_Of_Licenses;
            --SET @NewBalanceFromUser = ISNULL(@rbal, 0) + @P_No_Of_Licenses;
			DECLARE @NewBalance1 INT = ISNULL(@balance, 0) - @P_No_Of_Licenses;  --balace of child partner after addition

		 DECLARE @NewBalanceFromUser1 INT = ISNULL(@rbal, 0) + @P_No_Of_Licenses; --balace of parent partner after addition

            BEGIN TRANSACTION;

            -- Insert for child partner (debit)
            INSERT INTO tbl_pt_ParnerAnnualLicence (Mid, FromUserId, ToUserId, LicenceExpiryDate, CreatedOn, CreatedBy, Credit, Debit, Balance, Remarks, TypeCredit)
            VALUES (@MID_P, @P_userId, @P_ReceiverUID, DATEADD(YEAR, 1, GETDATE()), GETDATE(), @P_userId, 0, @P_No_Of_Licenses, @NewBalance1, 'License Debited', 0);

            SELECT @InsertedLicenseId = SCOPE_IDENTITY();

            -- Insert for parent partner (credit)
            INSERT INTO tbl_pt_ParnerAnnualLicence (Mid, FromUserId, ToUserId, LicenceExpiryDate, CreatedOn, CreatedBy, Credit, Debit, Balance, Remarks, TypeCredit)
            VALUES (@MID_P, @P_ReceiverUID, @P_userId, DATEADD(YEAR, 1, GETDATE()), GETDATE(), @P_userId, @P_No_Of_Licenses, 0, @NewBalanceFromUser1, 'License Credited', 0);


            COMMIT;


				-----  activity    -----
				begin try
			
								-- Fetch Partner Type
					SELECT @PartnerType = [TYPE] 
					FROM User_Detail with(nolock)
					WHERE USER_ID = @P_ReceiverUID;

					-- Fetch User Logins
					SELECT 
						@UserName = ISNULL(User_login, ''), 
						@PartnerUserName = ISNULL(User_login, '') 
					FROM User_Detail with(nolock)
					WHERE User_ID = @P_userId;

					SELECT @ChildPartnerName = ISNULL(User_login, '') 
					FROM User_Detail with(nolock)
					WHERE User_ID = @P_ReceiverUID;

					-- Construct JSON-formatted event data
					SET @Eventdata = '{"#parentpartner#":"' + @UserName 
									+ '","#licenseremoved#":"' + CONVERT(VARCHAR, @P_No_Of_Licenses) 
									+ '","#licensetype#":"' + 'Partner license' 
									+ '","#childpartner#":"' + @ChildPartnerName 
									+ '"}';

					PRINT @Eventdata;

					--#parentpartner# removed a total of #licenseremoved# of type #licensetype# from the account of #childpartner#
					-- Partner removed licenses from a partner
					EXEC usp_pm_PartnerActivity  
						@P_userId, 
						@P_userId, 
						@P_ReceiverUID,
						'Partner removed licenses from partner',
						@Eventdata,
						'tbl_pt_PartnerMonthlyLicence',
						@InsertedLicenseId;
			
					end try
			begin catch
				exec usp_InsertErrorInfo
			end catch
				----- activity end  ---


            SELECT 1 AS Status, 'License removal successful!' AS Message;
        END
        ELSE
        BEGIN
           -- Handle invalid @AddRemoveLicence value
            --THROW 50000, 'Invalid value for @AddRemoveLicence. Allowed values: Add Licence, Remove Licence.', 1;
		 	 select 50000, 'Invalid value for @AddRemoveLicence. Allowed values: Add Licence, Remove Licence.', 1;
 		END

    END TRY
    BEGIN CATCH
        -- Log error details
        EXEC usp_InsertErrorInfo;
    END CATCH
END;



GO

