/* ============================================================
   Procedure: [dbo].[USP_pt_CheckDomain]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



--------------------------------------------------------------


CREATE   PROCEDURE USP_pt_CheckDomain --'https://kitqa.sms19.com'
(  
    @UserID bigint 
)  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    BEGIN TRY  
        -- Variables to store existence checks  
        DECLARE @ExistsInResellerDetail BIT = 0;  
  
        -- Check if @Domain exists in reseller_detail table  
        IF EXISTS (  
            SELECT 1   
            FROM reseller_detail  
            WHERE User_ID = @UserID  
        )  
        BEGIN  
            SET @ExistsInResellerDetail = 1;  
        END  
  
        -- Return existence information  
        SELECT   
            --@ExistsInResellerDetail AS ExistsInResellerDetail,  
            --@ExistsInSetting AS ExistsInSetting,  
            CASE   
                WHEN @ExistsInResellerDetail = 1 THEN 1  
                ELSE 0  
            END AS ExistsInAnyTable;  
    END TRY  
    BEGIN CATCH  
        -- Handle errors  
        EXEC usp_InsertErrorInfo; -- Custom error logging procedure  
    END CATCH  
END;


GO

/* ============================================================
   Procedure: [dbo].[USP_pt_CheckDomainExistence]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  CREATE   PROCEDURE USP_pt_CheckDomainExistence  
(  
    @Domain NVARCHAR(255) -- Input domain to check  
)  
AS  
BEGIN  
    SET NOCOUNT ON;  
  

    BEGIN TRY  
        -- Variables to store existence checks  
        DECLARE @ExistsInResellerDetail BIT = 0;  
        DECLARE @ExistsInSetting BIT = 0;  
  
        -- Check if @Domain exists in reseller_detail table  
        IF EXISTS (  
            SELECT 1   
            FROM reseller_detail with(nolock)  
            WHERE dbo.fn_removewww(Domain) = dbo.fn_removewww(@Domain)  
        )  
        BEGIN  
            SET @ExistsInResellerDetail = 1;  
        END  
  
        -- Check if @Domain exists in setting table  
        IF EXISTS (  
            SELECT 1   
            FROM MYSMSInvoicing.dbo.settings  
            WHERE [key] = 'CustomiseDomain' and dbo.fn_removewww(value) = dbo.fn_removewww(@Domain)
        )  
        BEGIN  
            SET @ExistsInSetting = 1;  
        END  
  
        -- Return existence information  
        SELECT   
            --@ExistsInResellerDetail AS ExistsInResellerDetail,  
            --@ExistsInSetting AS ExistsInSetting,  
            CASE   
                WHEN @ExistsInResellerDetail = 1 OR @ExistsInSetting = 1 THEN 1  
                ELSE 0  
            END AS ExistsInAnyTable;  
    END TRY  
    BEGIN CATCH  
        -- Handle errors  
        EXEC usp_InsertErrorInfo; -- Custom error logging procedure  
    END CATCH  
END;  



GO

