CREATE   PROCEDURE [dbo].[usp_pt_CreateLicensesAnnually]
(
    @P_userId BIGINT,---335
    @P_ReceiverUID BIGINT,--456
    @P_No_Of_Licenses INT,
    @Mid BIGINT
)
AS
BEGIN
    -- Declare variables
    DECLARE @InsertedLicenseId VARCHAR(MAX) = '0';
    DECLARE @LicenseMetadata VARCHAR(MAX);
	 Declare @ParentID  bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @P_ReceiverUID )--456        
      Declare @MID_P  bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID ) --1
	declare @balance bigint,@default_credit bigint,@rmid bigint,@ruid bigint,@rbal bigint,@rcid bigint,@MIDUser bigint          
	declare @rvalidity nvarchar(300),@rdefault_credit nvarchar(300),@temp nvarchar(800),@finalbalance2 bigint,@finalbalance bigint,@creditup bigint,@rCredit bigint,@uCredits bigint                
 
    BEGIN TRY
	select top(1) @MIDUser=  m_id  from User_Detail with(nolock) where user_id=@P_userId  --null            
	--select top(1) @rmid=m_id, @ruid=user_id from reseller_detail where reseller_id=@MIDUser --null         
	select top(1) @rbal=Balance from tbl_pt_ParnerAnnualLicence with(nolock) where ToUserId=@P_userId order by Id  desc -- balace of parent partner(335)                             
	select top(1) @balance=balance from tbl_pt_ParnerAnnualLicence with(nolock)  where ToUserId=@P_ReceiverUID order by Id desc  -- balace of chld partner(456)         
       
        DECLARE @NewBalance INT = ISNULL(@balance, 0) + @P_No_Of_Licenses;  --balace of child partner after addition

		 DECLARE @NewBalanceFromUser INT = ISNULL(@rbal, 0) - @P_No_Of_Licenses; --balace of parent partner after addition

		 begin tran

		 INSERT INTO tbl_pt_ParnerAnnualLicence( Mid, FromUserId, ToUserId,LicenceExpiryDate, CreatedOn, CreatedBy, Credit, Debit, Balance, Remarks,TypeCredit)
        values( 
        @MIDUser ,  @P_userId, @P_ReceiverUID, DATEADD(YEAR, 1, GETDATE()), GETDATE(), @P_userId, @P_No_Of_Licenses,  0, @NewBalance,'License Received', 0);                           
        

        -- Retrieve the inserted license IDs
        SELECT @InsertedLicenseId = SCOPE_IDENTITY();
      
		 INSERT INTO tbl_pt_ParnerAnnualLicence ( Mid, FromUserId, ToUserId,LicenceExpiryDate, CreatedOn, CreatedBy, Credit, Debit, Balance, Remarks,TypeCredit)
       values( 
           @MID_P ,  @P_ReceiverUID,@P_userId, DATEADD(YEAR, 1, GETDATE()), GETDATE(), @P_userId, 0,@P_No_Of_Licenses, @NewBalanceFromUser,'License Debited', 0                           
       ); 
	   select 1 as status, 'License creation successful!' AS Message
	   commit
	   if @@TRANCOUNT >0
	   begin
	   rollback
        select 0 as status, 'License creation failed!' AS Message
		end

    END TRY
    BEGIN CATCH
        -- Log error details
        EXEC usp_InsertErrorInfo;
    END CATCH
END;


