/* ============================================================
   Procedure: [dbo].[usp_pt_GetBalanceByLicenseTypeFromUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_pt_GetBalanceByLicenseTypeFromUser
    @FromUserId bigint,
    @MID bigint,
    @LicenseType NVARCHAR(50) -- 'Monthly' or 'Annual'
AS
BEGIN
    BEGIN TRY
        SET NOCOUNT ON;

        -- Declare a variable to store the balance
        DECLARE @Balance bigint;

        -- Validate LicenseType and fetch balance
        IF @LicenseType = 'Monthly'
        BEGIN
            SELECT @Balance = Balance
            FROM tbl_pt_PartnerMonthlyLicence with (nolock)
            WHERE FromUserId = @FromUserId order by createdon desc;

            IF @Balance IS NULL
                THROW 50001, 'No record found in tbl_pt_PartnerMonthlyLicence for the given UserId and MID.', 1;
        END
        ELSE IF @LicenseType = 'Annual'
        BEGIN
            SELECT @Balance = Balance
            FROM tbl_pt_ParnerAnnualLicence with (nolock)
            WHERE FromUserId = @FromUserId order by createdon desc;

            IF @Balance IS NULL
                THROW 50002, 'No record found in tbl_pt_ParnerAnnualLicence for the given UserId and MID.', 1;
        END
        ELSE
        BEGIN
            THROW 50003, 'Invalid LicenseType provided. Use ''Monthly'' or ''Annual''.', 1;
        END

        -- Return the balance
        SELECT @Balance AS Balance;
    END TRY
    BEGIN CATCH
         EXEC usp_InsertErrorInfo
    END CATCH
END;
