/* ============================================================
   Procedure: [dbo].[usp_pt_GetLicenceStatsByUserIdAnnual]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE usp_pt_GetLicenceStatsByUserIdAnnual  
    @UserId BIGINT  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    BEGIN TRY  
        -- Declare variables to store total debit, pending licenses, and latest monthly balance  
        DECLARE @TotalDebit INT, @PendingLicence INT, @LatestAnnualBalance INT;  

        -- Calculate total debit  
        SELECT @TotalDebit = ISNULL(SUM(Debit), 0)  
        FROM tbl_pt_ParnerAnnualLicence with(nolock) 
        --WHERE ToUserId = @UserId;  
		where FromUserId=ToUserId and ToUserId=@UserId;

        -- Fetch the latest balance from tbl_pt_PartnerMonthlyLicence  
        SELECT TOP 1  
            @LatestAnnualBalance = ISNULL(pm.Balance, 0)  
        FROM [dbo].tbl_pt_ParnerAnnualLicence pm with(nolock) 
        WHERE pm.ToUserId = @UserId  
        ORDER BY pm.CreatedOn DESC;  

        -- Set Pending Licenses as the latest monthly balance (if exists)  
        SET @PendingLicence = ISNULL(@LatestAnnualBalance, 0);  

        -- If Pending Licence is less than 0, reset it to zero  
        IF @PendingLicence < 0  
        BEGIN  
            SET @PendingLicence = 0;  
        END  

        -- Return the results  
        SELECT   
            @PendingLicence AS PendingLicence,  -- Latest balance as Pending Licenses  
            @TotalDebit AS ActiveLicence;       -- Total Debit as Active Licenses  
          
    END TRY  
    BEGIN CATCH  
        -- Handle errors and log them  
        EXEC usp_InsertErrorInfo;  
    END CATCH  
END;  



------------------------------------------------------



