/* ============================================================
   Procedure: [dbo].[usp_pt_GetLicenceStatsByUserIdMonthly]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_pt_GetLicenceStatsByUserIdMonthly
    @UserId BIGINT
AS
BEGIN

    SET NOCOUNT ON;

    BEGIN TRY
        
        -- Calculate total credit and debit
        DECLARE @TotalCredit INT, @TotalDebit INT,@PendingLicence INT, @LatestMonthlyBalance INT;
        SELECT 
            --@TotalCredit = SUM(Credit),
            @TotalDebit = SUM(Debit)
        FROM tbl_pt_PartnerMonthlyLicence with(nolock)
        --WHERE ToUserId = @UserId;
		where FromUserId=ToUserId and ToUserId=@UserId;

		 SELECT TOP 1  
            @LatestMonthlyBalance = ISNULL(pm.Balance, 0)  
        FROM [dbo].[tbl_pt_PartnerMonthlyLicence] pm with(nolock)  
        WHERE pm.ToUserId = @UserId  
        ORDER BY pm.CreatedOn DESC; 

        SET @PendingLicence = ISNULL(@LatestMonthlyBalance, 0);  

        -- If Pending Licence is less than 0, reset it to zero  
        IF @PendingLicence < 0  
        BEGIN  
            SET @PendingLicence = 0;  
        END  

        -- Return the results  
        SELECT   
            @PendingLicence AS PendingLicence, 
            @TotalDebit AS ActiveLicence;
           
    END TRY
    BEGIN CATCH
        -- Handle errors and log them
        EXEC usp_InsertErrorInfo;
    END CATCH
END;

