/* ============================================================
   Procedure: [dbo].[usp_pt_ManagePartnerByMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_pt_ManagePartnerByMode](
	@Mode nvarchar(255),
	@OperationJSON nvarchar(max),
	@UserId bigint
)
AS
BEGIN
	

	--declare @Mode nvarchar(255) =N'UPDATE_SUBSCRIPTION_DETAILS',@OperationJSON nvarchar(max) =N'{"YourLicence":969,"LicenceRequired":4,"AfterUpdateLicence":965,"LicenseType":"monthly","IsSubscriptionActive":true,"SubsriptionAction":"updateSubcriptions","MonthToAdd":1,"AddUserCount":0,"Description":"","ActualEndDate":"2025-02-17","SubsriptionEndDate":"2025-03-17","toUserId":62633}',@UserId bigint =335


	declare @responseStatus int = 0, @responseMessage nvarchar(255)  = 'Invalid Opeations', @responseDetails nvarchar(max)

	--activity vars
	DECLARE @UserName varchar(255), @PartnerUserName varchar(255) , @ChildPartnerName varchar(255);
	Declare @Eventdata varchar(max);
	---activity vars

	if(isnull(@OperationJSON, '') <> '')
	begin
		
		declare 
			@uUserId bigint = json_value(@OperationJSON, '$.UserId'),
			@Mid bigint = json_value(@OperationJSON, '$.MID'),
			@Status bit = isnull(json_value(@OperationJSON, '$.Status'), 1)


		begin try		
			if(@Mode = 'UPDATE_USER_STATUS')
			begin
			
				update User_Detail set [Status] = @Status where User_ID = @uUserId and M_ID = @Mid
				select @responseStatus = 1, @responseMessage = 'Status changed successfully'

					-----  activity start   -----
						 
						select @UserName = User_login from User_Detail where User_ID = @UserId;
						select @PartnerUserName = User_login from User_Detail where User_ID = @UserId;
						select @ChildPartnerName = User_login from User_Detail where User_ID = @uUserId;
						SET @Eventdata = '{"#partner#":"'+ @UserName +'","#username#":"'+@ChildPartnerName+'"}';
						---select * from ActivityMaster  where EventName like '%partner%' 
						-- #partner# has activated user with login #username#.
						if @Status =1 begin
							exec usp_pm_PartnerActivity  @UserId, @UserId,@uUserId, 'Partner activated user',@Eventdata, 'User_Detail',@uUserId;
						end
						else begin
							exec usp_pm_PartnerActivity  @UserId, @UserId,@uUserId, 'Partner deactivated user',@Eventdata, 'User_Detail',@uUserId;
						end
						----- activity end  ---
			end

			if(@Mode = 'GET_SUBSCRIPTION_DETAILS')
			begin
			
				
				declare @MontlyLicence int = 0, @AnnualyLicence int = 0, @GracePeriodDays int = 0, @TotalActiveUsers int = 0

				select top 1 @MontlyLicence = Balance from tbl_pt_PartnerMonthlyLicence(nolock) where ToUserId = @UserId order by id desc
				select top 1 @AnnualyLicence = Balance from tbl_pt_ParnerAnnualLicence(nolock) where ToUserId = @UserId order by id desc

				select top 1 @GracePeriodDays = no_of_days from tbl_pt_GracePeriodDays(nolock) where parentid in (0, @uUserId) order by parentid desc

				select @TotalActiveUsers = count(1) from User_Detail(nolock) where ParentID = @uUserId and [Status] = 1


				set @responseDetails = ( 
					select 
						trim(sd.PlanId) as [PlanId], sd.PlanStartDate, sd.PlanEndDate, sd.Cost, sd.IsKYCRequired, sd.IsTrailPlan, sd.IsNewPlan,
						au.LicenceType, au.IsActive, isnull(au.AllowUserCount, 1) [AllowUserCount], au.SubscriptionId, au.TransactionId, 
						concat(ud.User_Login, ' (', ud.FName, ' ', ud.LName, ')') as UserLoginName, @AnnualyLicence as [AnnualyLicence],
						@MontlyLicence as [MontlyLicence], @GracePeriodDays as [GracePeriodDays], isnull(AllowUserCount, @TotalActiveUsers) as [TotalActiveUsers]
					from ( select top 1 
						UserID, PlanId, PlanStartDate, PlanEndDate, Cost, IsTrailPlan, IsNewPlan, IsKYCRequired, id, created_date
							from Price_UserSubscriptionDetails(nolock) where UserID = @uUserId order by id desc ) sd 
					left join ( select top 1 
						Id, UserId, CreatedOn, CreatedBy, ModifiedOn, IsActive, AllowUserCount, SubscriptionId, TransactionId, UserAdded, LicenceType 
							from tbl_pt_AllowUserTransactions(nolock) where UserId = @uUserId order by id desc 
					) au on sd.UserID = au.UserId 
					inner join User_Detail(nolock) ud on sd.UserID = ud.User_ID
				for json path, without_array_wrapper)

				select @responseStatus = 1, @responseMessage = 'Success'

			end

			if(@Mode = 'UPDATE_SUBSCRIPTION_DETAILS')
			begin
				print 'UPDATE_SUBSCRIPTION_DETAILS'

				declare 
					@YourLicence int = json_value(@OperationJSON, '$.YourLicence'),
					@LicenceRequired int = json_value(@OperationJSON, '$.LicenceRequired'), 
					@AfterUpdateLicence int = json_value(@OperationJSON, '$.AfterUpdateLicence'),
					@LicenseType nvarchar(25) = json_value(@OperationJSON, '$.LicenseType'),
					@IsSubscriptionActive bit = json_value(@OperationJSON, '$.IsSubscriptionActive'),
					@SubsriptionAction nvarchar(25) = json_value(@OperationJSON, '$.SubsriptionAction'),
					@MonthToAdd int  = json_value(@OperationJSON, '$.MonthToAdd'),
					@AddUserCount int = json_value(@OperationJSON, '$.AddUserCount'),
					@Description nvarchar(max) = json_value(@OperationJSON, '$.Description'),
					@ActualEndDate date = json_value(@OperationJSON, '$.ActualEndDate'),
					@SubsriptionEndDate date = json_value(@OperationJSON, '$.SubsriptionEndDate'),
					@toUserId bigint = json_value(@OperationJSON, '$.toUserId')

				/*
					select @YourLicence as [@YourLicence], @LicenceRequired as [@LicenceRequired], @AfterUpdateLicence as [@AfterUpdateLicence], 
						@LicenseType as [@LicenseType], @IsSubscriptionActive as [@IsSubscriptionActive], @SubsriptionAction as [@SubsriptionAction], 
						@MonthToAdd as [@MonthToAdd], @AddUserCount as [@AddUserCount], @Description as [@Description], @ActualEndDate as [@ActualEndDate],
						@SubsriptionEndDate as [@SubsriptionEndDate], @toUserId as [@toUserId]
				*/
				
				declare @isValid bit = 1, @vYourLicence int = 0, @vRequiredLicence int = 0, @vsCalculatedLicence int = 0, @yearCount int = 0, 
                    @vTotalActiveUsers int = 0;

                if(@LicenseType = 'monthly')
                begin
                    select top 1 @vYourLicence = Balance from tbl_pt_PartnerMonthlyLicence(nolock) where ToUserId = @UserId order by id desc
                end

                IF(@LicenseType = 'annual')
                BEGIN
                    SELECT TOP 1 @vYourLicence = Balance FROM tbl_pt_ParnerAnnualLicence(NOLOCK) WHERE ToUserId = @UserId order by id desc
                END

                SELECT TOP 1 @vTotalActiveUsers = AllowUserCount  FROM tbl_pt_AllowUserTransactions(NOLOCK) WHERE UserId = @toUserId order by Id  desc

                IF(isnull(@vTotalActiveUsers, 0) = 0 )
                BEGIN
                    select @vTotalActiveUsers = count(1) FROM User_Detail(nolock) where ParentID = @toUserId and [Status] = 1
                END

                PRINT concat('@vTotalActiveUsers => ', @vTotalActiveUsers)

                IF(@LicenceRequired <= @vYourLicence)
                BEGIN
					PRINT CONCAT('VALIDATION => => ', @SubsriptionAction)

                    IF(@SubsriptionAction = 'addUser')
                    BEGIN
                        SET @MonthToAdd = 0;
                        DECLARE @addUserMonthCount float = dbo.fn_MonthsRemaining(@ActualEndDate)
                        IF(@LicenseType = 'monthly')
                        BEGIN
                            SELECT  @vRequiredLicence = ceiling(@addUserMonthCount) * @AddUserCount
                        END
                        if(@LicenseType = 'annual')
                        BEGIN
                            SELECT @yearCount = ceiling(@addUserMonthCount / 12.0)
                            select @vRequiredLicence = @yearCount * @AddUserCount
                            PRINT CONCAT('@yearCount => ', @yearCount)
                        END
                    END

                    IF(@SubsriptionAction = 'updateSubcriptions')
                    BEGIN
                        set @AddUserCount = 0;
                        IF(@LicenseType = 'monthly')
                        BEGIN
                            select @vRequiredLicence = ( @MonthToAdd * @vTotalActiveUsers)
                        END
                        if(@LicenseType = 'annual')
                        BEGIN
                            set @yearCount = ceiling(@MonthToAdd / 12.0)
                            print concat('@yearCount => ', @yearCount)
                            select @vRequiredLicence = @yearCount * @vTotalActiveUsers
                        END                       
                    END

					PRINT CONCAT('@vRequiredLicence => ', @vRequiredLicence)
					IF(@LicenceRequired <> @vRequiredLicence)
                    BEGIN
                        select @responseStatus = 0, @responseMessage = 'Licence required is not matching with calculated licence'
                        SET @isValid = 0
                        PRINT CONCAT('@LicenceRequired => ', @LicenceRequired)
                    END
                END
                ELSE
                BEGIN
                    select @responseStatus = 0, @responseMessage = 'Insufficient licence balance'
                    SET @isValid = 0        
                END
               
                if(@isValid = 1)
                BEGIN
				
					print concat (' @SubsriptionAction => ', @SubsriptionAction)

					if(isnull(@Mid, 0) = 0)
					begin	
						select @Mid = Reseller_ID from reseller_detail (nolock) where User_ID = @UserId
					end

					declare @subcriptionId bigint = 0, @partnerBalanceLicence int = 0, @actualPlanStartDate date = getdate()
					begin try

						begin transaction
						
						declare @refTable nvarchar(255) = '', @refTableId bigint = 0
						declare @tran_remarks nvarchar(max) = ''
						declare @toUserLogin nvarchar(255)
						select @toUserLogin = User_Login from User_Detail(nolock) where User_ID = @toUserId

						if(@SubsriptionAction = 'updateSubcriptions')
						begin
							print 'SECTION => updateSubcriptions '
							if(exists (select 1 from Price_UserSubscriptionDetails(nolock) where UserID = @toUserId and PlanEndDate > getdate() and IsNewPlan = 1))
							begin
								select top 1 @actualPlanStartDate = PlanStartDate, @subcriptionId = id  from  Price_UserSubscriptionDetails(nolock) 
									where UserID = @toUserId and PlanEndDate > getdate() and IsNewPlan = 1 order by id desc
								--set @subcriptionId = SCOPE_IDENTITY();
								print 'Having active subscription'

							end
							else 
							begin
								set @actualPlanStartDate = @ActualEndDate
							end

							PRINT CONCAT('@MonthToAdd => ', @MonthToAdd)
							PRINT CONCAT('@actualPlanStartDate => ', @actualPlanStartDate)
							PRINT CONCAT('@SubsriptionEndDate => ', @SubsriptionEndDate)
						
							insert into Price_UserSubscriptionDetails(UserID, PlanId, PlanStartDate, PlanEndDate, Cost, IsTrailPlan, IsNewPlan, IsKYCRequired, created_date, created_by)
								select @toUserId, 1, @actualPlanStartDate, @SubsriptionEndDate, 0, 0, 1, 0, getdate(), @UserId

							set @subcriptionId = SCOPE_IDENTITY()
							if(@subcriptionId > 0)
							begin						
								update Price_UserSubscriptionDetails set IsNewPlan = 0 where UserID = @toUserId and IsNewPlan = 1 and id < @subcriptionId
							end

							set @tran_remarks =  concat('License(s) consumed for updating subscription tenure by ',
															@MonthToAdd, ' months  to account ', @toUserLogin)

							select @refTable = 'Price_UserSubscriptionDetails', @refTableId = @subcriptionId

 

								-- Fetching user login for the given UserId
								SELECT @UserName = User_login FROM User_Detail with(nolock) WHERE User_ID = @UserId;
								SELECT @PartnerUserName = User_login FROM User_Detail with(nolock) WHERE User_ID = @UserId; -- Assuming @PartnerId is defined elsewhere

								-- Fetching user login for the toUserId
								SELECT @ChildPartnerName = User_login FROM User_Detail with(nolock) WHERE User_ID = @toUserId;

								-- Constructing JSON string correctly
								SET @Eventdata = '{"#partner#":"' + @PartnerUserName 
												+ '","#username#":"' + @ChildPartnerName 
												+ '","#users_allowed_in_subscription#":"' + CAST(@AddUserCount AS NVARCHAR(10)) 
												+ '"}';

								-- Printing the final event data
								PRINT CONCAT('Eventdata : ', @Eventdata);

								---select * from ActivityMaster  where EventName like '%partner%' 
								-- #partner# updated subscription of #username#. Updated users #users_allowed_in_subscription#
								exec usp_pm_PartnerActivity  @UserId, @UserId,@toUserId, 'Partner updated users no. to subscription',@Eventdata, 'Price_UserSubscriptionDetails',@subcriptionId;

							----- activity end  ---


						end

						if(@SubsriptionAction = 'addUser')
						begin
							PRINT 'SECTION => addUser '

							declare @allowedUserCount int = 0, @aUId bigint = 0;

							select top 1 @allowedUserCount = AllowUserCount from tbl_pt_AllowUserTransactions(nolock) where  UserId = @toUserId order by id desc

							PRINT CONCAT('@allowedUserCount => ', @allowedUserCount)
    
							if(isnull(@allowedUserCount, 0) = 0 )
							begin
    							select @allowedUserCount = count(1) from User_Detail(nolock) where ParentId = @toUserId and [Status] = 1
							end

							select top 1 @subcriptionId = id from Price_UserSubscriptionDetails(nolock)  where UserID = @toUserId and IsNewPlan = 1 order by id desc

							PRINT CONCAT('@subcriptionId => ', @subcriptionId)
							PRINT CONCAT('@AddUserCount => ', @AddUserCount)
							PRINT CONCAT('@totalAllowedUser => ', @allowedUserCount + @AddUserCount)


							insert into tbl_pt_AllowUserTransactions (UserId, CreatedOn, CreatedBy, ModifiedOn, IsActive, AllowUserCount, SubscriptionId, TransactionId, UserAdded, LicenceType)
								select @toUserId, getdate(), @UserId, getdate(), 1, (@allowedUserCount + @AddUserCount), @subcriptionId, 0,  @AddUserCount, @LicenseType
							set @aUId = SCOPE_IDENTITY()

							set @tran_remarks =  concat('License(s) consumed for adding ', @AddUserCount, ' users  to account ', @toUserLogin)

							select @refTable = 'tbl_pt_AllowUserTransactions', @refTableId = @aUId
						end

						declare @mlTranId bigint  = 0, @ylTranId bigint = 0

						if(@LicenseType = 'monthly')
						begin
							declare @tml int = 0, @leDate date = getdate()
							select top 1 @tml = Balance, @leDate = LicenceExpiryDate 
								from tbl_pt_PartnerMonthlyLicence(nolock) where ToUserId = @UserId order by id desc

								insert into tbl_pt_PartnerMonthlyLicence(Mid, FromUserId, ToUserId, LicenceExpiryDate, CreatedOn, CreatedBy, Credit, Debit, Balance, Remarks, TypeCredit, SubTransId, RefTable, RefId)
								select @Mid, @UserId, @UserId, @leDate, getdate(), @UserId, 0, @LicenceRequired, ( @tml- @LicenceRequired ), @tran_remarks, 0,  0, @refTable, @refTableId

							set @mlTranId = SCOPE_IDENTITY()


								-----  activity start   -----
						
							-- Fetch user login details based on IDs
							SELECT @UserName = User_login FROM User_Detail with(nolock) WHERE User_ID = @UserId;
							SELECT @PartnerUserName = User_login FROM User_Detail with(nolock) WHERE User_ID = @UserId;
							SELECT @ChildPartnerName = User_login FROM User_Detail with(nolock) WHERE User_ID = @toUserId; -- Assuming @toUserId is correct

							-- Construct JSON-formatted event data
							SET @Eventdata = '{"#partner#":"' + @PartnerUserName 
											+ '","#username#":"' + @ChildPartnerName 
											+ '","#subscription_end_date#":"' + CONVERT(VARCHAR, @leDate, 105) 
											+ '"}';

							-- Print the final event data
							PRINT CONCAT('Eventdata : ', @Eventdata);

							---select * from ActivityMaster  where EventName like '%partner%' 
							-- #partner# updated subscription of #username#. Updated subscriptionenddate #subscription_end_date#
							exec usp_pm_PartnerActivity  @UserId, @toUserId,@toUserId, 'Partner updated subscription tenure',@Eventdata, 'tbl_pt_PartnerMonthlyLicence',@mlTranId;

							----- activity end  ---

						end

							if(@LicenseType = 'annual')
							begin
								declare @tyl int = 0, @lyeDate date = getdate()
								select top 1 @tyl = Balance, @lyeDate = LicenceExpiryDate 
									from tbl_pt_ParnerAnnualLicence(nolock) where ToUserId = @UserId order by id desc

								insert into tbl_pt_ParnerAnnualLicence(Mid, FromUserId, ToUserId, LicenceExpiryDate, CreatedOn, CreatedBy, Credit, Debit,  Balance, Remarks, TypeCredit, SubTransId, RefTable, RefId)
								select @Mid, @UserId, @UserId, @lyeDate, getdate(), @UserId, 0, @LicenceRequired, ( @tyl- @LicenceRequired ),  @tran_remarks, 0,  0, @refTable, @refTableId

								set @ylTranId = SCOPE_IDENTITY();

									-----  activity start   -----
									select @UserName = User_login from User_Detail with(nolock) where User_ID = @UserId;
									select @PartnerUserName = User_login from User_Detail with(nolock) where User_ID = @Mid;
									select @ChildPartnerName = User_login from User_Detail with(nolock) where User_ID = @UserId;
									SET @Eventdata = '{"#partner#":"'+ @PartnerUserName +'","#username#":"'+@ChildPartnerName+'","#subscription_end_date#":"'+ format( @lyeDate ,'dd-MM-yyyy') +'"}';
									---select * from ActivityMaster  where EventName like '%partner%' 
									-- #partner# updated subscription of #username#. Updated subscriptionenddate #subscription_end_date#
									exec usp_pm_PartnerActivity  @UserId, @UserId,@toUserId, 'Partner updated subscription tenure',@Eventdata, 'tbl_pt_ParnerAnnualLicence',@ylTranId;

									----- activity end  ---
							end

						commit transaction	

						end try 
						begin catch
							rollback transaction	
							select @responseStatus = 0, @responseMessage = 'Error in saving data'
						end catch
                    select @responseStatus = 1, @responseMessage = 'Data saved successfully'
                END
			end

            if(@Mode = 'GET_USER_STATSTICS')
            BEGIN
                declare 
                    @ActiveUserCount int = 0, @SubsriptionAge int = 0, @LastLoginDate nvarchar(25) = ''
                select top 1 @LastLoginDate = format(Datecreated, 'dd-MMM-yyyy HH:mm:ss', 'en-us')   from loginhistory(nolock) where user_id = @uUserId order by id desc
                select @ActiveUserCount = count(1) from User_Detail(nolock) where User_ID = @uUserId and [Status] = 1
                declare @gracePeriod int = 0
                select top 1 @gracePeriod = no_of_days from tbl_pt_GracePeriodDays(nolock) where parentid in (@uUserId, 0) order by parentid desc
                DROP TABLE IF EXISTS #tempUserSub
                SELECT id, PlanStartDate, PlanEndDate, 0 as IsProcessed INTO #tempUserSub 
                    FROM Price_UserSubscriptionDetails(NOLOCK) WHERE UserID = @uUserId order by id desc
                declare @tStartDate datetime, @tEndDate datetime, @lastPlanStartDate datetime, @lastPlanEndDate datetime, @subId bigint
                WHILE(EXISTS(SELECT 1 FROM #tempUserSub WHERE IsProcessed = 0))
                BEGIN
                    select top 1 @subId = id, @tStartDate = PlanStartDate, @tEndDate = PlanEndDate 
                            from #tempUserSub where IsProcessed = 0 order by id desc
                    declare  @daydiff int  = DATEDIFF(DAY, @tStartDate, @tEndDate)
                    IF(isnull(@lastPlanEndDate, '') <> '' AND isnull(@tStartDate, '') <> '')
                    BEGIN
                        if(datediff(day, @tStartDate, @lastPlanEndDate ) > @gracePeriod)
                        BEGIN
                            update #tempUserSub set IsProcessed = 1
                        END
                    END
                    set @SubsriptionAge += @daydiff
                    update #tempUserSub set IsProcessed = 1 where id = @subId
                    select @lastPlanEndDate = @tStartDate, @lastPlanEndDate = @tEndDate, @subId = 0
                END

                SELECT @responseStatus = 1, @responseMessage = 'Success',  @responseDetails = ( SELECT 
                                            'ActiveUserCount' = @ActiveUserCount,
                                            'SubsriptionAge' = @SubsriptionAge,
                                            'LastLoginDate' = @LastLoginDate
                                        FOR JSON PATH)
            END
		END TRY
		BEGIN CATCH
			exec usp_InsertErrorInfo
		END CATCH
	END
	ELSE 
	BEGIN
		select @responseMessage  = 'Payload is empoty or null'
	END

    print concat('@responseDetails => ', @responseDetails)

	select @responseStatus as [ResponseStatus], @responseMessage as [ResponseMessage], @responseDetails as [ResponseDetails]
END



GO

