/* ============================================================
   Procedure: [dbo].[usp_pt_select_user_detailbyEmail_Mobile1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


   --------------------------------------------------------------------
   CREATE   PROCEDURE [dbo].[usp_pt_select_user_detailbyEmail_Mobile1]
    @Email NVARCHAR(MAX),
    @Mobile NVARCHAR(30)
AS
BEGIN
    SET NOCOUNT ON;

    -- Variables to store existence status
    DECLARE @EmailExists BIT = 0;
    DECLARE @MobileExists BIT = 0;

    -- Check if email exists
    SELECT @EmailExists = 1
    FROM user_detail (NOLOCK)
    WHERE EMail = @Email;

    -- Check if mobile exists
    SELECT @MobileExists = 1
    FROM user_detail (NOLOCK)
    WHERE Mobile = @Mobile;

    -- Return the appropriate status and message
    IF @EmailExists = 1 AND @MobileExists = 1
    BEGIN
        SELECT 
            1 AS Status,
            'Both Email and Mobile already exist' AS Message;
    END
    ELSE IF @EmailExists = 1
    BEGIN
        SELECT 
            1 AS Status,
            'Email already exists' AS Message;
    END
    ELSE IF @MobileExists = 1
    BEGIN
        SELECT 
            1 AS Status,
            'Mobile already exists' AS Message;
    END
    ELSE
    BEGIN
        SELECT 
            0 AS Status,
            'Neither Email nor Mobile exists' AS Message;
    END
END;



GO

/* ============================================================
   Procedure: [dbo].[USP_pt_ShowPartnerDetailWeb_1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[USP_pt_ShowPartnerDetailWeb_1] --335,'mobile'
(
    @P_USERID BIGINT,
    @Mode NVARCHAR(50) -- Parameter to determine the mode
)
AS
BEGIN

    SET NOCOUNT ON;

    BEGIN TRY
        -- Declare variables to store the output values
        DECLARE @Result NVARCHAR(MAX);

        -- Determine the JSON column and values to return based on @Mode
        IF @Mode = 'web'
       BEGIN
            -- Check if data exists in tbl_pt_CustomizationMetadata
            IF EXISTS (
                SELECT 1
                FROM tbl_pt_CustomizationMetadata with(nolock)
                WHERE JSON_VALUE(JsonData, '$.USERID') = CAST(@P_USERID AS NVARCHAR)
            )
            BEGIN
                -- Fetch data from tbl_pt_CustomizationMetadata
                SELECT 
                    COALESCE(JSON_VALUE(JsonData, '$.DomainName'), 'https://') AS DomainName,
					COALESCE(JSON_VALUE(JsonData, '$.TDomainName'), 'https://') AS TDomainName,
					COALESCE(JSON_VALUE(JsonData, '$.MDomainName'), 'https://') AS MDomainName,
    COALESCE(JSON_VALUE(JsonData, '$.LogoUrl'), '') AS LogoUrl,
    COALESCE(JSON_VALUE(JsonData, '$.HyperlinkLogo'), '') AS HyperlinkLogo,
    COALESCE(JSON_VALUE(JsonData, '$.favicon'), '') AS Favicon,
    COALESCE(JSON_VALUE(JsonData, '$.Theme'), '') AS Theme,
    COALESCE(JSON_VALUE(JsonData, '$.Background_ImageUrl'), '') AS Background_ImageUrl,
    COALESCE(JSON_VALUE(JsonData, '$.TermUrl'), 'https://') AS TermUrl,
    COALESCE(JSON_VALUE(JsonData, '$.PolicyUrl'), 'https://') AS PolicyUrl
                FROM tbl_pt_CustomizationMetadata
                WHERE JSON_VALUE(JsonData, '$.USERID') = CAST(@P_USERID AS NVARCHAR);
            END
            ELSE
            BEGIN
                -- Fetch DomainName from reseller_details and return NULL for other values
                SELECT 
                    Domain AS DomainName,
                    NULL AS LogoUrl,
                    'https://' AS HyperlinkLogo,
                    NULL AS Favicon,
                    NULL AS Theme,
                    NULL AS Background_ImageUrl,
                    'https://' AS TermUrl,
                    'https://' AS PolicyUrl
                FROM reseller_detail with(nolock)
                WHERE User_ID = @P_USERID;
            END
        END
        ELSE IF @Mode = 'email'
			BEGIN
				SELECT 
					JSON_VALUE(jsonEmailData, '$.Email') AS Email,
					JSON_VALUE(jsonEmailData, '$.Personalisation') AS Personalisation,
					JSON_VALUE(jsonEmailData, '$.Signature') AS Signature,
					 JSON_VALUE(jsonEmailData, '$.SignatureEditor') AS SignatureDetails,
					  JSON_VALUE(jsonEmailData, '$.Title') AS Title,
					   JSON_VALUE(jsonEmailData, '$.Subtitle') AS Subtitle,
						JSON_VALUE(jsonEmailData, '$.Description') AS Description,
						 JSON_VALUE(jsonEmailData, '$.Address') AS Address,
						  JSON_VALUE(jsonEmailData, '$.Address1') AS Address1,
						   JSON_VALUE(jsonEmailData, '$.AltNm') AS Mobile1,
					  JSON_VALUE(jsonEmailData, '$.Mobile2') AS Mobile2,
					 COALESCE(JSON_VALUE(jsonEmailData, '$.FbUrl'), 'https://') AS Facebok,
								COALESCE(JSON_VALUE(jsonEmailData, '$.TwtUrl'), 'https://') AS Twiter,
								COALESCE(JSON_VALUE(jsonEmailData, '$.LnkUrl'), 'https://') AS Linkd,
								COALESCE(JSON_VALUE(jsonEmailData, '$.Whatsapp'), 'https://') AS Whatsapp,
				   /* JSON_VALUE(jsonEmailData, '$.SignatureDetails.SignatureName') AS SignatureName,
					JSON_VALUE(jsonEmailData, '$.SignatureDetails.SignatureCompany') AS SignatureCompany,
					JSON_VALUE(jsonEmailData, '$.SignatureDetails.AddressLine1') AS AddressLine1,
					JSON_VALUE(jsonEmailData, '$.SignatureDetails.AddressLine2') AS AddressLine2,
					JSON_VALUE(jsonEmailData, '$.SignatureDetails.Country') AS Country,
					JSON_VALUE(jsonEmailData, '$.SignatureDetails.Addrs') AS Regards*/
					 REPLACE(REPLACE(JSON_VALUE(jsonEmailData, '$.SignatureDetails.SignatureName'), '<p>', ''), '</p>', '') AS SignatureName,
					REPLACE(REPLACE(JSON_VALUE(jsonEmailData, '$.SignatureDetails.SignatureCompany'), '<p>', ''), '</p>', '') AS SignatureCompany,
					REPLACE(REPLACE(JSON_VALUE(jsonEmailData, '$.SignatureDetails.AddressLine1'), '<p>', ''), '</p>', '') AS AddressLine1,
					REPLACE(REPLACE(JSON_VALUE(jsonEmailData, '$.SignatureDetails.AddressLine2'), '<p>', ''), '</p>', '') AS AddressLine2,
					REPLACE(REPLACE(JSON_VALUE(jsonEmailData, '$.SignatureDetails.Country'), '<p>', ''), '</p>', '') AS Country,
					REPLACE(REPLACE(JSON_VALUE(jsonEmailData, '$.SignatureDetails.Addrs'), '<p>', ''), '</p>', '') AS Regards
				FROM tbl_pt_CustomizationMetadata with(nolock)
				WHERE JSON_VALUE(jsonEmailData, '$.USERID') = CAST(@P_USERID AS NVARCHAR);
			END
        ELSE IF @Mode = 'mobile'
        BEGIN
            SELECT 
			JSON_VALUE(jsonMobileData, '$.MobileAppLogo') AS LogoUrl,
                JSON_VALUE(jsonMobileData, '$.DisplayNmae') AS DisplayName,
				 JSON_VALUE(jsonMobileData, '$.ColorCode') AS ColorCode,
				 JSON_VALUE(jsonMobileData, '$.MobileNm') AS MobileNo,
                JSON_VALUE(jsonMobileData, '$.EmailId') AS EmailId,
				 JSON_VALUE(jsonMobileData, '$.Whatsapp') AS WhatsappNo
            FROM tbl_pt_CustomizationMetadata with(nolock)
            WHERE JSON_VALUE(jsonMobileData, '$.USERID') = CAST(@P_USERID AS NVARCHAR);
        END
        ELSE
        BEGIN
            -- Return an error message for invalid mode
            --THROW 
		  select 50000, 'Invalid mode specified. Allowed values are: web, email, mobile.', 1;
        END
    END TRY
    BEGIN CATCH
        -- Handle errors
        EXEC usp_InsertErrorInfo; -- Log the error (custom error logging procedure)
    END CATCH
END;




