CREATE   PROCEDURE usp_pt_UpdateDomainVerificationStatus  
    @userid BIGINT,  
    @domain NVARCHAR(200) = NULL,   
    @createdby BIGINT  
AS  
BEGIN  
    -- Declare variables  
    DECLARE @record_value NVARCHAR(256);  
    DECLARE @rowCount INT;    
      
    -- Start of TRY block  
    BEGIN TRY  
        UPDATE tbl_pt_DomainVerification  
        SET   
            isverified = 0,   
            LastverificationAttempted = GETDATE(),   
            verifiedon =  null 
        WHERE   
            userid = @userid AND domain = @domain ;  
  
    
  
        SET @rowCount = @@ROWCOUNT;  
        SELECT @rowCount AS RowsAffected;  
  
    END TRY  
  
    BEGIN CATCH  
        EXEC usp_InsertErrorInfo;  
    END CATCH  
END;  


