/* ============================================================
   Procedure: [dbo].[usp_pt_UpdateUserAndResellerDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE usp_pt_UpdateUserAndResellerDetails
    @UserId BIGINT,
    @Domain NVARCHAR(255) = '',
    @PartnerType INT
AS
BEGIN
    BEGIN TRY
        -- Start a transaction
        BEGIN TRANSACTION;

        -- Check the user's type
        DECLARE @Type INT;

        SELECT @Type = [Type]
        FROM user_details (nolock)
        WHERE Id = @UserId;

        DECLARE @NewType INT;

        IF @PartnerType = 1
            SET @NewType = 4;
        ELSE IF @PartnerType IN (2, 3)
            SET @NewType = 3;

        -- Perform operations based on the user's type
        IF @Type = 0
        BEGIN
            -- Update user_details table
            UPDATE user_details
            SET [Type] = @NewType
            WHERE Id = @UserId;

            -- Insert a new row into reseller_details table
            INSERT INTO reseller_details (m_id, user_id, domain, partner_type)
            VALUES (@UserId, @UserId, @Domain, @PartnerType);
        END
        ELSE IF @Type = 3
        BEGIN
            -- Update reseller_details table
            UPDATE reseller_details
            SET partner_type = @PartnerType, domain = @Domain
            WHERE user_id = @UserId;
        END
        ELSE IF @Type = 4
        BEGIN
            -- Update user_details table
            UPDATE user_details
            SET [Type] = @NewType
            WHERE Id = @UserId;

            -- Update reseller_details table
            UPDATE reseller_details
            SET partner_type = @PartnerType, domain = @Domain
            WHERE user_id = @UserId;
        END
        ELSE
        BEGIN
            -- Return failure if the user's type is not 0, 3, or 4
            RAISERROR ('User type is not 0, 3, or 4. Operation aborted.', 16, 1);
            ROLLBACK TRANSACTION;
            RETURN 0;
        END

        -- Commit the transaction if everything is successful
        COMMIT TRANSACTION;

        -- Return success
        RETURN 1;
    END TRY
    BEGIN CATCH
        -- Rollback the transaction in case of an error
        IF @@TRANCOUNT > 0
        BEGIN
            ROLLBACK TRANSACTION;
        END;

        -- Re-throw the error
        THROW;

        -- Return failure
        RETURN 0;
    END CATCH
END;

