CREATE   PROCEDURE usp_purge_trace_updatems
as
begin
declare @c bigint=(select count(1) from trace_updatems(nolock) where createdon<dateadd(d,-1,getdate()))
while @c>0
begin
delete top (10000 )  from trace_updatems where createdon<dateadd(d,-1,getdate())
set @c=@c-10000
end
end


