as
begin
declare @c bigint=(select count(1) from errorreportnew(nolock)  where Date<dateadd(mm,-3,getdate()))
while @c>0
begin
delete e from (select top 1000 * from errorreportnew(nolock)  where Date<dateadd(mm,-3,getdate()) order by id) e
set @c=@c-1000
end
end


