/* ============================================================
   Procedure: [dbo].[usp_ReferContact]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_ReferContact] --2,'sdfs','','+91','7840049991','new',''    
@referid int,
@Name nvarchar(100),
@EMail nvarchar(250),
@CountryCode nchar(10),
@Mobile nvarchar(20),
@Company nvarchar(200), 
@Designation nvarchar(200)
as    
begin 
if exists(select 1 from ReferredContacts where isnull(nullif(email,''),'1')=@email or @CountryCode=isnull(nullif(CountryCode,''),'1') and isnull(nullif(mobile,''),'1')=@mobile)
begin
Select 'This contact is already referred by someone !'
end
else
begin
insert into referredcontacts(ReferrerID,Name,EMail,CountryCode,Mobile,Company,Country,Source,DateCreated,Designation)
select @referid,@Name,@EMail,@CountryCode,@Mobile,@Company,country_name,'Direct',GETDATE(),@Designation from m_country1 where CountryCode=@CountryCode
Select 1,'Contact Referred!'
exec usp_UpdateUserActivity @referid,'ReferredContact',0
end
end


