/* ============================================================
   Procedure: [dbo].[usp_Referrersignin]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_Referrersignin] --'9620','merefer'   
@password nvarchar(20),    
@username nvarchar(50)    
as    
begin    
declare @referid int= (select ID from Referrer_Details where user_login=@username and pwd COLLATE SQL_Latin1_General_CP1_CS_AS=@password )
if @referid is not null
begin    
if exists(select 1 from referrer_details where id=@referid and status=1)
begin
Select 1 as Loginstatus,@referid as referid 
update referrer_details set lastlogin=getdate(),ismobileverified=1 where ID=@referid
declare @activityid int =(select ID from ActivitiesToRecord where activity='signin')  
Insert into referrer_activity(Referrerid,ActivityId,DateCreated)  
select @referid,@activityid,GETDATE()   
end
else
begin
Select 0 as loginstatus,'Account disabled' as Reason
end
end
else
begin
Select 0 as loginstatus,'Invalid username or password' as Reason
end
end  


GO

/* ============================================================
   Procedure: [dbo].[usp_Referrersignup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_Referrersignup    
@name nvarchar(150),    
@countrycode nchar(10),    
@mobile nvarchar(50),    
@email nvarchar(250),    
@password nvarchar(20),    
@username nvarchar(50)    
as    
begin    
if exists(select 1 from user_detail where ((CountryCode=@countrycode and str(mobile,10,0)=@mobile) or email=@email) and M_ID=10043)    
begin    
Select 'You are already a Kit19 user, pl login with your kit19 credentials'    
end    
else if exists(select 1 from referrer_details where (CountryCode=@countrycode and str(mobile,10,0)=@mobile))    
begin    
Select 'Mobile no. already exists, pl try again  with a different mobile no.'    
end 
else if exists(select 1 from referrer_details where email=@email)    
begin    
Select 'EmailId already exists, pl try again  with a different EmailId'    
end 
else if exists(select 1 from referrer_details where User_Login=@username union select 1 from user_detail where User_Login=@username and M_ID=10043)    
begin    
Select 'Username already exists, pl try again with a different Username'    
end     
else    
begin    
declare @country nvarchar(100)=(select country_name from m_country1 where CountryCode=@countrycode)  
declare @newreferrerid bigint    
insert into referrer_details(User_Login,Pwd,Name,EMail,Mobile,Country,Source,Status,DateCreated,CountryCode)    
select @username,@password,@name,@email,@mobile,@country,'Direct',1,GETDATE(),@countrycode   
set @newreferrerid=SCOPE_IDENTITY()  
declare @activityid int =(select ID from ActivitiesToRecord where activity='signup')  
Insert into referrer_activity(Referrerid,ActivityId,DateCreated)  
select @newreferrerid,@activityid,GETDATE()   
Select 'Account created successfully. Password has been sent on your Mobile, Login to continue'    
end    
end  


GO

