@userid bigint
as
begin
if exists(select 1 from user_detail where (USER_ID=@userid and M_ID=10043) or USER_ID=335)
begin
if not exists(select 1 from referrer_details where kit19userid=@userid)
begin
declare @newreferrerid bigint
declare @activityid int 
insert into referrer_details(User_Login,Pwd,Name,EMail,Mobile,Country,Source,Status,DateCreated,CountryCode,ismobileverified,kit19userid)
select User_Login,Pwd,isnull(fName,'')+ ' ' +ISNULL(lname,''),EMail,Mobile,Country,'kit19',Status,GETDATE(),CountryCode,1,user_id from User_Detail where 
User_ID=@userid
	set @newreferrerid=SCOPE_IDENTITY()
	set @activityid =(select ID from ActivitiesToRecord where activity='signup')
	Insert into referrer_activity(Referrerid,ActivityId,DateCreated,Otherdetails)
	select @newreferrerid,@activityid,GETDATE(),'Kit19user'
Select @newreferrerid
update referrer_details set lastlogin=GETDATE() where ID=@newreferrerid
set @activityid =(select ID from ActivitiesToRecord where activity='signin')
Insert into referrer_activity(Referrerid,ActivityId,DateCreated,Otherdetails)
select @newreferrerid,@activityid,GETDATE(),'Kit19user'
end
else
begin
declare @referid int=
(select id from referrer_details where kit19userid=@userid)
update referrer_details set lastlogin=GETDATE() where ID=@referid
set @activityid =(select ID from ActivitiesToRecord where activity='signin')
Insert into referrer_activity(Referrerid,ActivityId,DateCreated,Otherdetails)
select @newreferrerid,@activityid,GETDATE(),'Kit19user'
select @referid
end
end
else
begin
Select 'Please signup to continue'
end
end


