/* ============================================================
   Procedure: [dbo].[usp_remote_deduct_or_refund_int_bal]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_remote_deduct_or_refund_int_bal]  
(@parentid bigint,@m_id bigint,@cost_in_inr_credit numeric(18,4),@cost_in_inr_debit numeric(18,4),@credit_type int,@remarks nvarchar(1000))  
as  
begin  
declare @intid bigint 

INSERT INTO IntCredit_Details   
(FromUser_ID, M_ID, User_ID, Debits, Credits, Balance, Validity, typecredit, Remarks)  
VALUES (  
    @parentid,  
    @m_id,  
    @parentid,  
    @cost_in_inr_debit,  
    @cost_in_inr_credit,  
	dbo.fn_GetMoneyBalance(@parentid)+ @cost_in_inr_credit-@cost_in_inr_debit,  
    99999,  
    @credit_type,  
	@remarks
    --'Balance deducted for whatsapp conversation of type "'+@template_category+'" with user '+cast(@recipientid as nvarchar)+' under conversationid '+cast(@pcid as nvarchar)+', on date '+cast(@createdon as nvarchar)  
);  
select @intid=SCOPE_IDENTITY()  
  
Exec usp_rf_UpdateReserveFundTransaction @CreditId=@intid  
select @intid--=@intid  
  
end


GO

/* ============================================================
   Procedure: [dbo].[usp_remote_deduct_or_refund_int_bal_withOutput]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_remote_deduct_or_refund_int_bal_withOutput]   
(  
    @parentid bigint,  
    @m_id bigint,  
    @cost_in_inr_credit numeric(18,4),  
    @cost_in_inr_debit numeric(18,4),  
    @credit_type int,  
    @remarks nvarchar(1000),  
    @intCredId bigint OUTPUT  
)  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    DECLARE @intid bigint;  
  select @m_id=coalesce(@m_id,10043)

    INSERT INTO IntCredit_Details  
    (  
        FromUser_ID,   
        M_ID,   
        User_ID,   
        Debits,   
        Credits,   
        Balance,   
        Validity,   
        typecredit,   
        Remarks  
    )  
    VALUES   
    (   
        @parentid,  
        @m_id, 
        @parentid,  
        @cost_in_inr_debit,  
        @cost_in_inr_credit,  
        dbo.fn_GetMoneyBalance(@parentid) + @cost_in_inr_credit - @cost_in_inr_debit,  
        99999,  
        @credit_type,  
        @remarks  
    );  
  
    SELECT @intid = SCOPE_IDENTITY();  
  
    -- update reserve fund transaction  
    EXEC usp_rf_UpdateReserveFundTransaction @CreditId = @intid;  
  
    -- set output parameter  
    SET @intCredId = @intid;  
END  


GO

