/* ============================================================
   Procedure: [dbo].[usp_RemoveAllLeadByParentID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_RemoveAllLeadByParentID @ParentID=39655
CREATE   PROC usp_RemoveAllLeadByParentID    
(@ParentID bigint)    
AS    
BEGIN    
-- declare @ParentID bigint=36593    
    
 update UE set UE.IsOpen = 1, UE.LeadNo = NULL    
 From UserEnquiry UE inner join UserLeads UL    
 ON UE.LeadNo = UL.LeadNo AND UE.ParentID = UL.ParentID    
 Where UL.ParentID=@ParentID    
    
 delete from customfieldLeadvalue where LeadId in (Select ID from UserLeads Where ParentID=@ParentID)    
    
 DELETE LIH    
 FROM LeadInteractionHistory LIH inner join UserLeads UL    
 ON LIH.LeadNo = UL.LeadNo AND LIH.ParentID = UL.ParentID    
 Where UL.ParentID=@ParentID    
   
   delete LPM from LeadPipelineMapping LPM inner join  UserLeads UL  
   ON LPM.LeadID = UL.ID   
   where UL.ParentID = @ParentID   
      
   delete LPH from LeadScoreHistory_Pipeline LPH inner join  UserLeads UL  
   ON LPH.LeadID = UL.ID   
   where UL.ParentID = @ParentID   
  
   delete TSKH from tbl_tsk_taskhistory TSKH inner join  UserLeads UL  
   ON TSKH.LeadID = UL.ID   
   where UL.ParentID = @ParentID   
     
   delete LN from tbl_LeadNotes LN inner join  UserLeads UL  
   ON LN.LeadID = UL.ID   
   where UL.ParentID = @ParentID  
  
   update LD set LD.ISDeleted = 1 from tbl_LeadDocumentUpload LD inner join  UserLeads UL  
   ON LD.LeadID = UL.ID   
   where UL.ParentID = @ParentID  
  
    delete LEH from tbl_LeadEventHistory LEH inner join  UserLeads UL  
   ON LEH.LeadID = UL.ID   
   where UL.ParentID = @ParentID  
  
   delete LSH from lead_score_history LSH inner join  UserLeads UL  
   ON LSH.LeadID = UL.ID   
   where UL.ParentID = @ParentID  
     
   delete FLP from FinalLeadScores_Pipeline FLP inner join  UserLeads UL  
   ON FLP.LeadID = UL.ID   
   where UL.ParentID = @ParentID  
  
  
   Delete from UserLeads Where ParentID=@ParentID    
     
  
End



GO

