/* ============================================================
   Procedure: [dbo].[Usp_RemoveQueryStringData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_RemoveQueryStringData
as
begin

     Declare @MaxID bigint = 0 
	 Declare @MinID bigint = 0 
	 select @MaxID = max(ID) from tbl_QueryString with(nolock) where datediff(day,CreatedOn,getdate()) > 30  
     select @MinID = min(ID) from tbl_QueryString with(nolock) where datediff(day,CreatedOn,getdate()) > 30                   

	 Declare @ID bigint = @MinID 
	 Declare @MinIDTemp bigint =  @MinID
	 Declare @MaxIDTemp bigint =  @MinID + 1000
	 
	 while(@MinIDTemp >= @MinID and @MinIDTemp <= @MaxID)
	   begin
	       Set @MaxIDTemp =  @MinIDTemp + 1000
           --select     
		   delete t from tbl_QueryString as t where t.ID >= @MinIDTemp and  t.ID <= @MaxIDTemp and t.id <= @MaxID  
		   set @MinIDTemp = @MaxIDTemp
       end
end	   


GO

