   Procedure: [dbo].[usp_removetempmailtables]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_removetempmailtables
as
begin
declare @sql nvarchar(2000),@c int,@id int=0
select @c=count(1) from TablesToBeRemoved where dateofdeletion>getdate() and isprocessed=0
while @c>0
begin
select @id=min(id) from TablesToBeRemoved where dateofdeletion>getdate() and isprocessed=0 and id>@id
select @sql= 'drop table '+tablename+ '; drop table '+tablename+'_tbd' from TablesToBeRemoved where id=@id
print @sql
exec sp_executesql @sql
set @c=@c-1
end
end



GO

/* ============================================================
   Procedure: [dbo].[usp_Rep_GetCallDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- Exec usp_Rep_GetCallDetail 32222, '01-Jan-2020', '02-Jan-2020'      
-- Exec usp_Rep_GetCallDetail 32222, '01-Dec-2019', '10-Dec-2019','8447070969'      
-- Exec usp_Rep_GetCallDetail 32222, '01-Dec-2019', '10-Dec-2019','','1204862606'      
-- Exec usp_Rep_GetCallDetail 32222, '01-Dec-2019', '10-Dec-2019','9313943059','1204862606'      
CREATE   PROC [dbo].[usp_Rep_GetCallDetail]      
(      
@UserId bigint,      
@FromDate varchar(12)='',      
@ToDate varchar(12)='',      
@Callerid varchar(50)='',      
@Dnid varchar(50)=''      
)      
As      
Begin      
  
 DECLARE @ParentId BIGINT = 0;                
 DECLARE @IsAdmin bit = 0;                
 DECLARE @RoleType varchar(10);                
 Declare @TeamCode VARCHAR(20)                              
  
SELECT @ParentId = ParentID, @IsAdmin = IsAdmin FROM User_Detail(nolock) WHERE User_ID = @UserId;                
  
if object_id('tempdb..#tblUserIds') is not null begin drop table #tblUserIds end  
  
CREATE TABLE #tblUserIds(  
   UserId bigint  NOT NULL)  
  
select @TeamCode = tum.TeamCode from TBL_UA_TeamUserMappingMaster(nolock) tum  
inner join TBL_UA_TeamMaster(nolock) tm on tm.TeamCode = tum.TeamCode  
where tum.UserId = @UserId  
   
if((@TeamCode is null) and ( @ParentId = @UserId or @IsAdmin = 1))  
Begin  
--set @RoleType = 'Global'  
Insert into #tblUserIds (UserId)  
Select User_Id UserId FROM User_Detail(nolock) where ParentId = @ParentId   
End  
Else if(@TeamCode != null)   
Begin  
---set @RoleType = 'Team'  
Insert into #tblUserIds (UserId)  
Select UserId FROM TBL_UA_TeamUserMappingMaster(nolock) where TeamCode = @TeamCode  
End  
Else   
Begin  
--set @RoleType = 'User'  
Insert into #tblUserIds (UserId)  
select @UserId   
End  
  
  
-- declare @UserId bigint=32222,@FromDate varchar(12)='01-Nov-2019',@ToDate varchar(12)='30-Dec-2019',@Callerid varchar(50)='', @Dnid varchar(50)=''      
      
declare @DateFrom datetime, @DateTo datetime      
      
if(@FromDate = '')      
Begin      
    Set @DateFrom='01-Jan-1900'      
End      
Else      
Begin      
    Set @DateFrom=@FromDate      
End      
      
if(@ToDate = '')      
Begin      
    Set @DateTo=dateadd(dd,1,getdate())--'31-Jan-2100'      
End      
Else      
Begin      
    Set @DateTo=@ToDate      
End      
      
Select *      
From      
(      
      
select FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') as [CallDate], KC.callerid, KC.dnid, recordurl=isnull(KC.recordurl,''), UD.User_ID, UD.FName + isnull(' ' + UD.LName,'') as [User], isnull(DC.Disposition,'') as Disposition, 
(case when DC.Disposition='ANSWER' then 'CONNECTED' else 'MISSED' end) as CallStatus, (case when KC.context='DialerCalls' then 'Out' else 'In' end) as CallDirection,CallPeriod=CONVERT(VARCHAR(8), 
DATEADD(SECOND,isnull(DATEDIFF(second,DC.call_start_time,DC.call_end_time),0),'19000101'), 8)--,*      
from Kit19Calls(nolock) KC inner join User_Detail(nolock) UD      
on  KC.accountcode = UD.User_ID inner join DiallerCalls(nolock) DC      
on KC.Id = DC.kit19callsid      
where KC.context='DialerCalls'      
      
union      
      
Select A.CallDate,A.callerid,A.dnid,A.recordurl,UD.User_ID, UD.FName + isnull(' ' + UD.LName,'') as [User],A.Disposition,A.CallStatus,A.CallDirection,A.CallPeriod      
From      
(      
select FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') as [CallDate], KC.CallerId, KC.dnid, recordurl=isnull(KC.recordurl,''), Disposition=(case when KCD.call_answer_time is not null then 'ANSWER' ELSE isnull(KCD.dialstatus,'') End), CallStatus=Case
  
    
 when KCD.call_answer_time is not null then 'CONNECTED' ELSE 'MISSED' End, (case KC.context when 'inbound' then 'In' when 'outbound' then 'Out' else 'In' end) as CallDirection, CONVERT(VARCHAR(8), DATEADD(SECOND,isnull(DATEDIFF(second,KCD.call_answer_time
  
    
,KCD.call_end_time),0), '19000101'), 8) as CallPeriod, AgentNo=replace(KCD.callerid,'Sip/4862600/',''),KC.clientid--,*       
-- Select distinct KC.context       
from Kit19Calls(nolock) KC inner join Kit19CallsDialled(nolock) KCD      
on  KC.uniqueid = KCD.puniqueid      
where   KC.context!='DialerCalls'      
) A      
inner join User_Detail(nolock) UD      
on    trim(A.AgentNo)=str(UD.mobile) and A.clientid = UD.ParentID      
    
    
UNION    
    
SELECT FORMAT(DP.CreateOn, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate],       
                  CAST(DP.MobileNo AS NVARCHAR) AS [callerid],       
                   'Sim Call' AS [dnid],       
                   DP.CallRecordPath AS [recordurl],       
                   UD.User_ID AS [User_ID],       
                   UD.FName + ISNULL(' ' + UD.LName, '') AS [User],       
                   --UD.ProfilePicturePath,       
                   (CASE      
                        WHEN ISNULL(DP.CallStartDateTime, '') = ''      
                        THEN 'MISSED'      
                        ELSE 'CONNECTED'      
                    END) AS [Disposition],       
                   (CASE      
                        WHEN ISNULL(DP.CallStartDateTime, '') = ''      
                        THEN 'MISSED'      
                        ELSE 'CONNECTED'      
                    END) AS [CallStatus],       
                   'Out' AS CallDirection,       
    CAST(DP.CallEndDateTime - DP.CallStartDateTime AS TIME) AS [CallPeriod] --,       
                   --UD.ParentID      
            FROM tbl_DailPaidCallDetails DP (nolock)     
      INNER JOIN User_Detail UD(nolock) ON DP.UserId = UD.User_ID    
    
    
      
) tblDetail      
Where (User_ID = case when @UserId=0 then User_ID else @UserId end
or
User_ID in (select UserId From #tblUserIds))  
and       
  -- REPLACE(CONVERT(VARCHAR(11), CallDate, 106), ' ', '-') >= @DateFrom and REPLACE(CONVERT(VARCHAR(11), CallDate, 106), ' ', '-') <= @DateTo and      
  --REPLACE(CONVERT(VARCHAR(11), CallDate, 106), ' ', '-') between @DateFrom and @DateTo and      
  Convert(datetime,CONVERT(VARCHAR(11), CallDate, 106)) between @DateFrom and @DateTo and      
  callerid = case when @Callerid='' then callerid else @Callerid end and      
  dnid = case when @Dnid='' then dnid else @Dnid end      
order by cast(CallDate as datetime)      
      
End   


GO

/* ============================================================
   Procedure: [dbo].[usp_Rep_GetCallSummary]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_Rep_GetCallSummary     
-- Exec usp_Rep_GetCallSummary 0, '01-Dec-2019', '10-Dec-2019'    
-- Exec usp_Rep_GetCallSummary 32222, '01-Jul-2020', '19-Aug-2020'    
CREATE   PROC dbo.usp_Rep_GetCallSummary (
	@UserId BIGINT
	,@FromDate VARCHAR(12) = ''
	,@ToDate VARCHAR(12) = ''
	)
AS
BEGIN
	DECLARE @DateFrom DATETIME
		,@DateTo DATETIME

	IF (@FromDate = '')
	BEGIN
		SET @DateFrom = '01-Jan-1900'
	END
	ELSE
	BEGIN
		SET @DateFrom = @FromDate
	END

	IF (@ToDate = '')
	BEGIN
		SET @DateTo = '31-Jan-2100'
	END
	ELSE
	BEGIN
		SET @DateTo = @ToDate
	END

	SELECT *
	FROM (
		SELECT User_ID
			,[User]
			,[CallDate]
			,TotalCalls
			,CONNECTED = Sum(CONNECTED)
			,MISSED = Sum(MISSED)
			,CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, Sum(CallPeriod), '19000101'), 8)
			,'ClickToCall' AS CallType
		FROM (
			SELECT A.User_ID
				,A.[User]
				,A.[CallDate]
				,A.TotalCalls
				,B.CONNECTED
				,B.MISSED
				,CallPeriod
			FROM (
				SELECT UD.User_ID
					,UD.FName + isnull(' ' + UD.LName, '') AS [User]
					,FORMAT(KC.call_start_time, 'dd-MMM-yyyy') AS [CallDate]
					,count(*) AS TotalCalls
				FROM Kit19Calls(NOLOCK) KC
				INNER JOIN User_Detail(NOLOCK) UD ON KC.accountcode = UD.User_ID
				WHERE KC.context = 'DialerCalls'
				GROUP BY UD.User_ID
					,UD.FName + isnull(' ' + LName, '')
					,FORMAT(KC.call_start_time, 'dd-MMM-yyyy')
				) A
			INNER JOIN (
				SELECT User_Id
					,CallDate
					,CallPeriod
					,isnull([CONNECTED], 0) AS [CONNECTED]
					,isnull([MISSED], 0) AS [MISSED]
				FROM (
					SELECT User_Id
						,CallDate
						,CallStatus
						,count(*) AS CallCnt
						,Sum(CallPeriod) AS CallPeriod
					FROM (
						SELECT User_Id
							,FORMAT(call_start_time, 'dd-MMM-yyyy') AS CallDate
							,(
								CASE 
									WHEN Disposition = 'ANSWER'
										THEN 'CONNECTED'
									ELSE 'MISSED'
									END
								) AS CallStatus
							,isnull(DATEDIFF(second, call_start_time, call_end_time), 0) AS CallPeriod
						FROM DiallerCalls(NOLOCK)
						) A
					GROUP BY A.User_Id
						,A.CallDate
						,A.CallStatus
					) A1
				pivot(sum(CallCnt) FOR CallStatus IN (
							[CONNECTED]
							,[MISSED]
							)) AS pv
				) B ON A.User_ID = B.User_Id
				AND A.CallDate = B.CallDate
			) C
		GROUP BY User_ID
			,[User]
			,[CallDate]
			,TotalCalls
		
		UNION
		
		SELECT User_ID
			,[User]
			,[CallDate]
			,TotalCalls = sum(TotalCalls)
			,sum([CONNECTED]) AS [CONNECTED]
			,sum([MISSED]) AS [MISSED]
			,CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, Sum(CallPeriod), '19000101'), 8)
			,'IVR' AS CallType
		FROM (
			SELECT User_ID
				,[User]
				,[CallDate]
				,TotalCalls
				,(isnull([CONNECTED], 0)) AS [CONNECTED]
				,(isnull([MISSED], 0)) AS [MISSED]
				,CallPeriod
			FROM (
				SELECT B.User_ID
					,B.[User]
					,B.[CallDate]
					,B.CallStatus
					,Count(*) AS TotalCalls
					,Count(*) AS CntCalls
					,Sum(B.CallPeriod) AS CallPeriod
				FROM (
					SELECT A.CallDate
						,A.CallPeriod
						,A.AgentNo
						,A.CallStatus
						,A.clientid
						,UD.User_ID
						,UD.FName + isnull(' ' + UD.LName, '') AS [User]
					FROM (
						SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy') AS [CallDate]
							,isnull(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0) AS CallPeriod
							,AgentNo = agentnumber
							,--replace(KCD.callerid,'Sip/4862600/','') ,    
							--case when CHARINDEX('/', KCD.callerid) > 0 then RIGHT(KCD.callerid,CHARINDEX('/',REVERSE(KCD.callerid))-1) else KCD.callerid end, KCD.callerid,    
							CallStatus = CASE 
								WHEN KCD.call_answer_time IS NOT NULL
									THEN 'CONNECTED'
								ELSE 'MISSED'
								END
							,KC.clientid --,*     
						FROM Kit19Calls(NOLOCK) KC
						INNER JOIN Kit19CallsDialled(NOLOCK) KCD ON KC.uniqueid = KCD.puniqueid
						WHERE KC.context != 'DialerCalls'
						) A
					INNER JOIN User_Detail(NOLOCK) UD ON trim(A.AgentNo) = str(UD.mobile)
						AND A.clientid = UD.ParentID
					) B
				GROUP BY B.User_ID
					,B.[User]
					,B.CallDate
					,B.CallStatus
				) C
			pivot(sum(C.CntCalls) FOR C.CallStatus IN (
						[CONNECTED]
						,[MISSED]
						)) AS pv
			) D
		GROUP BY User_ID
			,[User]
			,[CallDate]
		-- SimCall Summary Added Section Start  
		
		UNION
		
		SELECT User_ID
			,[User]
			,[CallDate]
			,TotalCalls = sum(TotalCalls)
			,sum([CONNECTED]) AS [CONNECTED]
			,sum([MISSED]) AS [MISSED]
			,CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, Sum(CallPeriod), '19000101'), 8)
			,'SimCall' AS CallType
		FROM (
			SELECT User_ID
				,[User]
				,[CallDate]
				,TotalCalls
				,(isnull([CONNECTED], 0)) AS [CONNECTED]
				,(isnull([MISSED], 0)) AS [MISSED]
				,CallPeriod
			FROM (
				SELECT B.User_ID
					,B.[User]
					,B.[CallDate]
					,B.CallStatus
					,Count(*) AS TotalCalls
					,Count(*) AS CntCalls
					,Sum(B.CallPeriod) AS CallPeriod
				FROM (
					SELECT FORMAT(DP.CreateOn, 'dd-MMM-yyyy') AS [CallDate]
						,ISNULL(DATEDIFF(SECOND, DP.CallStartDateTime, DP.CallEndDateTime), 0) AS [CallPeriod]
						,CAST(DP.MobileNo AS NVARCHAR) AS [callerid]
						,(
							CASE 
								WHEN ISNULL(DP.CallStartDateTime, '') = ''
									THEN 'MISSED'
								ELSE 'CONNECTED'
								END
							) AS [CallStatus]
						,UD.ParentID AS [clientid]
						,UD.User_ID AS [User_ID]
						,UD.FName + ISNULL(' ' + UD.LName, '') AS [User]
					FROM tbl_DailPaidCallDetails DP
					INNER JOIN User_Detail UD ON DP.UserId = UD.User_ID
					) B
				GROUP BY B.User_ID
					,B.[User]
					,B.CallDate
					,B.CallStatus
				) C
			pivot(sum(C.CntCalls) FOR C.CallStatus IN (
						[CONNECTED]
						,[MISSED]
						)) AS pv
			) D
		GROUP BY User_ID
			,[User]
			,[CallDate]
		) tblSummary
	WHERE User_ID = CASE 
			WHEN @UserId = 0
				THEN User_ID
			ELSE @UserId
			END
		AND CallDate BETWEEN @DateFrom
			AND @DateTo
	ORDER BY 1
		,3

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_sumry_Call'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'Kit19Calls'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_Rep_GetCallSummaryAgentwise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_Rep_GetCallSummaryAgentwise --33819, '05-Nov-2020', '06-Nov-2020'      
(    
    @UserId bigint,    
    @FromDate varchar(12)='',    
    @ToDate varchar(12)=''    
)    
As    
Begin    
/*
create table #calldates(Calldates nvarchar(20))

insert into #calldates(Calldates)
select FORMAT(start_dts, 'dd-MMM-yyyy') from Calendar where start_dts between convert(datetime,@FromDate,104) and dateadd(dd,-1,convert(datetime,@ToDate,104))    
*/

select user_id,isnull(fname,'')+isnull(' ' +lname,'') as [User],FORMAT(start_dts, 'dd-MMM-yyyy') Calldates into #users from User_Detail(nolock) u
join Calendar c on start_dts between convert(datetime,@FromDate,104) and dateadd(dd,-1,convert(datetime,@ToDate,104))    
 where parentid=(select parentid from User_Detail(nolock) where user_id=@userid)    
and status=1 and isnull(Cloudrole,0)<>0
--select * from #users
declare @c int= (select count(1) from #users)
create table #allcalls(User_ID bigint, [User] nvarchar(100), [CallDate] nvarchar(20), TotalCalls int, CONNECTED int, MISSED int, CallPeriod nvarchar(100) , CallType nvarchar(50))
declare @DateFrom datetime, @DateTo datetime    
while @c>0
begin
select @userid=min(user_id) from #users where user_id>@UserId   
if(@FromDate = '')    
Begin    
    Set @DateFrom='01-Jan-1900'    
End    
Else    
Begin    
    Set @DateFrom=@FromDate    
End    
    
if(@ToDate = '')    
Begin    
    Set @DateTo='31-Jan-2100'    
End    
Else    
Begin    
    Set @DateTo=@ToDate    
End    
/*
select @UserId

select 1,* from 
(    
select UD.User_ID, UD.FName + isnull(' ' + UD.LName,'') as [User],FORMAT(KC.call_start_time, 'dd-MMM-yyyy') as [CallDate],count(kc.id) as TotalCalls     
from Kit19Calls(nolock) KC right join User_Detail(nolock) UD    
on  KC.accountcode = UD.User_ID and kc.call_start_time between  convert(datetime,@FromDate,104) and dateadd(dd,1,convert(datetime,@ToDate,104))    
where (kc.id is null or KC.context='DialerCalls' )  and ud.User_ID=@UserId 
Group by UD.User_ID, UD.FName + isnull(' ' + LName,''), FORMAT(KC.call_start_time, 'dd-MMM-yyyy')    
) A    

select 2,* from 
(    
select d.User_Id,FORMAT(call_start_time, 'dd-MMM-yyyy') as CallDate,(case when Disposition='ANSWER' then 'CONNECTED' else 'MISSED' end) as CallStatus,isnull(DATEDIFF(second,call_start_time,call_end_time),0) as CallPeriod    
from DiallerCalls(nolock) d right join user_detail(nolock) ud on ud.user_id=d.user_id where ud.user_id=@UserId  and call_start_time between  convert(datetime,@FromDate,104) and dateadd(dd,1,convert(datetime,@ToDate,104))
) A    


select 3,* from 
(    
select  FORMAT(KC.call_start_time, 'dd-MMM-yyyy') as [CallDate], isnull(DATEDIFF(second,KCD.call_answer_time,KCD.call_end_time),0) as CallPeriod,     
    AgentNo=agentnumber,agenttype,--replace(KCD.callerid,'Sip/4862600/','') ,    
    --case when CHARINDEX('/', KCD.callerid) > 0 then RIGHT(KCD.callerid,CHARINDEX('/',REVERSE(KCD.callerid))-1) else KCD.callerid end, KCD.callerid,    
    CallStatus=Case when KCD.call_answer_time is not null then 'CONNECTED' ELSE 'MISSED' End,KC.clientid--,*     
from    Kit19Calls(nolock) KC inner join Kit19CallsDialled(nolock) KCD    
on    KC.uniqueid = KCD.puniqueid    
where   KC.context!='DialerCalls' and kc.call_start_time between  convert(datetime,@FromDate,104) and dateadd(dd,1,convert(datetime,@ToDate,104))     
) A    
right join User_Detail(nolock) UD    
on trim(A.AgentNo)=case when AgentType='Mobile' then str(UD.mobile) else cast(ud.user_id as nvarchar) end and A.clientid = UD.ParentID    
where ud.User_ID=@UserId

select 4,* from 
( 
SELECT   
 FORMAT(DP.CreateOn, 'dd-MMM-yyyy') AS [CallDate],  
 ISNULL(DATEDIFF(SECOND, DP.CallStartDateTime, DP.CallEndDateTime), 0) AS [CallPeriod],  
 CAST(DP.MobileNo AS NVARCHAR) AS [callerid],     
  (CASE    
  WHEN ISNULL(DP.CallStartDateTime, '') = ''    
  THEN 'MISSED'    
  ELSE 'CONNECTED'    
   END) AS [CallStatus],  
 UD.ParentID AS [clientid],     
 UD.User_ID AS [User_ID],     
 UD.FName + ISNULL(' ' + UD.LName, '') AS [User]  
  FROM tbl_DailPaidCallDetails DP    
  right JOIN User_Detail UD ON DP.UserId = UD.User_ID and DP.CallStartDateTime between  convert(datetime,@FromDate,104) and dateadd(dd,1,convert(datetime,@ToDate,104)) where ud.user_id=@UserId
  ) B   
   
   */


insert into #allcalls(User_ID, [User], [CallDate], TotalCalls, CONNECTED, MISSED, CallPeriod , CallType)
Select User_ID, [User], [CallDate], TotalCalls, CONNECTED, MISSED, CallPeriod , CallType     
From    
(    
select User_ID, [User], [CallDate], TotalCalls, CONNECTED=Sum(CONNECTED), MISSED=Sum(MISSED), 
CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, Sum(CallPeriod), '19000101'), 8), 'ClickToCall' as CallType    
From    
(    
select A.User_ID, A.[User],A.[CallDate],A.TotalCalls, B.CONNECTED, B.MISSED, CallPeriod    
From    
(    
select UD.User_ID, UD.FName + isnull(' ' + UD.LName,'') as [User],FORMAT(KC.call_start_time, 'dd-MMM-yyyy') as [CallDate],count(kc.id) as TotalCalls     
from Kit19Calls(nolock) KC right join User_Detail(nolock) UD    
on  KC.accountcode = UD.User_ID and kc.call_start_time between  convert(datetime,@FromDate,104) and dateadd(dd,1,convert(datetime,@ToDate,104))    
where (kc.id is null or KC.context='DialerCalls' )  and ud.User_ID=@UserId 
Group by UD.User_ID, UD.FName + isnull(' ' + LName,''), FORMAT(KC.call_start_time, 'dd-MMM-yyyy')    
) A    
inner join     
(select User_Id, CallDate, CallPeriod, isnull([CONNECTED],0) as [CONNECTED], isnull([MISSED],0) as [MISSED]    
From    
(    
select User_Id, CallDate, CallStatus, count(*) as CallCnt, Sum(CallPeriod) as CallPeriod    
From    
(    
select d.User_Id,FORMAT(call_start_time, 'dd-MMM-yyyy') as CallDate,(case when Disposition='ANSWER' then 'CONNECTED' else 'MISSED' end) as CallStatus,isnull(DATEDIFF(second,call_start_time,call_end_time),0) as CallPeriod    
from DiallerCalls(nolock) d right join user_detail(nolock) ud on ud.user_id=d.user_id where ud.user_id=@UserId and call_start_time between  convert(datetime,@FromDate,104) and dateadd(dd,1,convert(datetime,@ToDate,104))
) A    
group by A.User_Id,A.CallDate,A.CallStatus    
)A1    
pivot(    
    sum(CallCnt) for CallStatus in ([CONNECTED],[MISSED])    
) as pv    
) B    
on  A.User_ID = B.User_Id and A.CallDate=B.CallDate    
) C    
group by User_ID, [User], [CallDate], TotalCalls    
    
union    
    
select User_ID, [User], [CallDate], TotalCalls=sum(TotalCalls), sum([CONNECTED]) as [CONNECTED], sum([MISSED]) as [MISSED], 
CallPeriod=CONVERT(VARCHAR(8), DATEADD(SECOND,Sum(CallPeriod), '19000101'), 8),'IVR' as CallType    
From    
(    
Select User_ID, [User], [CallDate], TotalCalls, (isnull([CONNECTED],0)) as [CONNECTED], (isnull([MISSED],0)) as [MISSED], CallPeriod     
From    
(    
Select B.User_ID, B.[User], B.[CallDate], B.CallStatus, Count(AgentNo) as TotalCalls, Count(AgentNo) as CntCalls, Sum(B.CallPeriod) as CallPeriod    
From    
(    
Select A.CallDate,A.CallPeriod,A.AgentNo,A.CallStatus,A.clientid,UD.User_ID, UD.FName + isnull(' ' + UD.LName,'') as [User]    
From    
(    
select  FORMAT(KC.call_start_time, 'dd-MMM-yyyy') as [CallDate], isnull(DATEDIFF(second,KCD.call_answer_time,KCD.call_end_time),0) as CallPeriod,     
    AgentNo=agentnumber,agenttype,--replace(KCD.callerid,'Sip/4862600/','') ,    
    --case when CHARINDEX('/', KCD.callerid) > 0 then RIGHT(KCD.callerid,CHARINDEX('/',REVERSE(KCD.callerid))-1) else KCD.callerid end, KCD.callerid,    
    CallStatus=Case when KCD.call_answer_time is not null then 'CONNECTED' ELSE 'MISSED' End,KC.clientid--,*     
from    Kit19Calls(nolock) KC inner join Kit19CallsDialled(nolock) KCD    
on    KC.uniqueid = KCD.puniqueid    
where   KC.context!='DialerCalls' and kc.call_start_time between  convert(datetime,@FromDate,104) and dateadd(dd,1,convert(datetime,@ToDate,104))     
) A    
right join User_Detail(nolock) UD    
on trim(A.AgentNo)=case when AgentType='Mobile' then str(UD.mobile) else cast(ud.user_id as nvarchar) end and A.clientid = UD.ParentID    
where ud.User_ID=@UserId
) B    
Group By B.User_ID, B.[User], B.CallDate, B.CallStatus    
) C    
pivot(    
    sum(C.CntCalls) for C.CallStatus in ([CONNECTED],[MISSED])    
) as pv    
) D    
group by User_ID, [User], [CallDate]    
  
-- SimCall Summary Added Section Start  
UNION  
select User_ID, [User], [CallDate], TotalCalls=sum(TotalCalls), sum([CONNECTED]) as [CONNECTED], sum([MISSED]) as [MISSED], CallPeriod=CONVERT(VARCHAR(8), DATEADD(SECOND,Sum(CallPeriod), '19000101'), 8),'SimCall' as CallType    
From    
(    
Select User_ID, [User], [CallDate], TotalCalls, (isnull([CONNECTED],0)) as [CONNECTED], (isnull([MISSED],0)) as [MISSED], CallPeriod     
From    
(  
Select B.User_ID, B.[User], B.[CallDate], B.CallStatus, Count(callerid) as TotalCalls, Count(*) as CntCalls, Sum(B.CallPeriod) as CallPeriod   
from  
(  
  
SELECT   
 FORMAT(DP.CreateOn, 'dd-MMM-yyyy') AS [CallDate],  
 ISNULL(DATEDIFF(SECOND, DP.CallStartDateTime, DP.CallEndDateTime), 0) AS [CallPeriod],  
 CAST(DP.MobileNo AS NVARCHAR) AS [callerid],     
                   (CASE    
                        WHEN ISNULL(DP.CallStartDateTime, '') = ''    
                        THEN 'MISSED'    
                        ELSE 'CONNECTED'    
                    END) AS [CallStatus],  
 UD.ParentID AS [clientid],     
 UD.User_ID AS [User_ID],     
 UD.FName + ISNULL(' ' + UD.LName, '') AS [User]  
  FROM tbl_DailPaidCallDetails DP    
  right JOIN User_Detail UD ON DP.UserId = UD.User_ID and DP.CallStartDateTime between  convert(datetime,@FromDate,104) and dateadd(dd,1,convert(datetime,@ToDate,104)) where ud.user_id=@UserId) B   
  
   Group By B.User_ID, B.[User], B.CallDate, B.CallStatus    
  ) C    
  pivot (    
   sum(C.CntCalls) for C.CallStatus in ([CONNECTED],[MISSED])    
  ) as pv    
 ) D    
group by User_ID, [User], [CallDate]   
) tblSummary    
Where User_ID= case when @UserId=0 then User_ID else @UserId end and CallDate between @DateFrom and @DateTo    
Order by 1,3    

/*
if not exists(select 1 from #allcalls where USER_ID=@UserId)
begin
select 1 from #allcalls where USER_ID=@UserId
insert into #allcalls(User_ID, [User], [CallDate], TotalCalls, CONNECTED, MISSED, CallPeriod , CallType)
select User_id,u.[User],calldates,0,0,0,0,'' from #calldates c join #users u on 1=1
end
*/
--select * from #allcalls
--delete from #users where user_id=@UserId
set @c=@c-1
end
select u.User_ID, u.[User], u.[CallDates] CallDate, isnull(TotalCalls,0) as TotalCalls, isnull(CONNECTED,0) CONNECTED, isnull(MISSED,0) MISSED, isnull(CallPeriod,0) CallPeriod , isnull(CallType,'') CallType
from #users u left join #allcalls a  on a.calldate=u.Calldates and u.User_ID=a.User_ID
order by User_ID
 
 drop table #users
 drop table #allcalls
-- drop table #calldates
End 


GO

/* ============================================================
   Procedure: [dbo].[usp_rep_GetData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_rep_GetData @ParentId = 33819,@UserId = 33819,@FromDate = '01-Jan-2021', @ToDate = '10-Jun-2021',@Param1 ='37',@Mode ='LeadSource'
-- exec usp_rep_GetData @ParentId = 26023,@UserId = 26023,@FromDate = '06-Feb-2020', @ToDate = '07-Feb-2020',@Param1 ='2046',@Mode ='CallByAgentCallPeriod'
-- exec usp_rep_GetData @ParentId = 32222,@UserId = 32222,@FromDate = '01-Jan-2019', @ToDate = '19-Jun-2021',@Param1 ='',@Mode ='OwnerConversionProductCount'
CREATE   PROCEDURE [dbo].[usp_rep_GetData]
(
	@ParentId BIGINT = 0,
	@UserId BIGINT = 0,
	@FromDate Datetime = null,
	@ToDate Datetime = null,
	@Param1 varchar(100)='',
	@Mode varchar(50)=''
)
AS
BEGIN

	-- declare @ParentId BIGINT = 39698,@UserId BIGINT = 39698,@FromDate Datetime = '20-Mar-2022', @ToDate Datetime = '24-Mar-2022',@Param1 varchar(100)='',@Mode varchar(50)='CallByAgentOutbound'

	select @FromDate=iif(isnull(@FromDate,'')='1900-01-01','1900-01-01',@FromDate)
	select @ToDate=iif(isnull(@ToDate,'')='1900-01-01','3000-01-01',@ToDate) 

	set @ParentId=isnull(@ParentId,0)
	set @UserId=isnull(@UserId,0)
		
	IF(@Mode = 'EnquirySource')
	BEGIN
		If(@ParentId > 0)
		Begin
			Select	UE.SourceName as SourceID, ES.Name as SourceName, Count(*) as RecCnt
			From	Userenquiry(nolock) UE Left Join Usersourcesettings(NOLOCK) ES
			ON		UE.SourceName=ES.SourceID and ES.IsActive=1
			Where	UE.ParentId=@ParentId and UE.CreatedBy=Case when @UserId=0 then UE.CreatedBy else @UserId end 
					AND [UE].[CreatedDate] between @FromDate AND @ToDate
			Group By  UE.SourceName, ES.Name
		End
	END

	IF(@Mode = 'EnquirySourceDetail')
	BEGIN
		If(@ParentId > 0)
		Begin
			SELECT	[UE].[Enquiryid], [UE].[Personname], [UE].[Companyname],[EmailId1] = [UE].[Emailid], [EmailId2] = [UE].[Emailid1],
					[EmailId3] = [UE].[Emailid2], [Mobileno1] = isnull([UE].[Countrycode],'') + ' ' + isnull([UE].[Mobileno],''), 
					[MobileNo2] = isnull([UE].[Countrycode1],'') + ' ' + isnull([UE].[Mobileno1],''),
					[MobileNo3] = isnull([UE].[Countrycode2],'') + ' ' + isnull([UE].[Mobileno2],''), 
					[UE].[Residentialaddress], [UE].[Officeaddress], [Ud].[User_login], [UE].[CreatedDate], [UE].[City], [UE].[State], 
					[UE].[Country], IIF([UE].[Pincode] = 0, '', STR([UE].[Pincode])) AS [Pincode],
					CASE WHEN [UE].[Companyname] <> '' THEN ISNULL([UE].[Officeaddress], '') ELSE ISNULL([UE].[Residentialaddress], '') END + 
					' ' + IIF([UE].[Pincode] = 0, '', STR([UE].[Pincode])) + ' ' + ISNULL([UE].[City], '') + ' ' + ISNULL([UE].State, '') + 
					' ' + ISNULL([UE].[Country], '') AS [ADDRESS], [UE].[Initialremarks], ISNULL([Uss].[Name], '') AS [SourceName], 
					ISNULL([Ums].[Name], '') AS [MediumName], ISNULL([Ucs].[Name], '') AS [CampaignName], [UE].[Parentid], [UE].[Createdby],
					[LeadNo] = ISNULL([UE].[LeadNo], 0), [UE].[img_ext], (CASE WHEN [UE].[Isopen] = '1' THEN 'open' ELSE (CASE WHEN 
					[UE].[Isopen] = '0' THEN 'close' ELSE 'lead' END) END) AS [Isopen], [UE].[ProfileImgFileName]
			FROM	Userenquiry(NOLOCK) AS UE INNER JOIN Usersourcesettings(NOLOCK) AS Uss
			ON		UE.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings(NOLOCK) AS Ums
			ON		UE.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings(NOLOCK) AS Ucs
			ON		UE.Campaignname = Ucs.Campaignid LEFT JOIN User_detail(NOLOCK) AS Ud
			ON		UE.Createdby = Ud.User_id
			WHERE	[UE].[Parentid] = @ParentId AND [UE].[CreatedDate] between @FromDate AND @ToDate AND [UE].[SourceName]=@Param1;
		End
	END

	IF(@Mode = 'LeadSource')
	BEGIN
		Select	UL.SourceName as SourceID, ES.Name as SourceName, Count(*) as RecCnt
		From	UserLeads(nolock) UL Left Join Usersourcesettings(NOLOCK) ES
		ON		UL.SourceName=ES.SourceID and ES.IsActive=1
		Where	UL.ParentId=@ParentId and UL.AssignedTo=Case when @UserId=0 then UL.AssignedTo else @UserId end 
				AND ((UL.CreatedOn between @FromDate AND @ToDate) OR (UL.FollowupDate between @FromDate AND @ToDate))
		Group By  UL.SourceName, ES.Name
	END

	IF(@Mode = 'LeadSourceDetail')
	BEGIN
		SELECT LeadId=[UL].[ID], [UL].[LeadNo], [UL].[PersonName], img_ext=isnull([UL].[img_ext],''), 
		CompanyName=isnull([UL].[CompanyName],''), CountryCode1=ISNULL([UL].[CountryCode], ''), CountryCode2=ISNULL([UL].[Countrycode1], '') ,
		CountryCode3=ISNULL([UL].[Countrycode2], ''), MobileNo1=ISNULL([UL].[MobileNo], ''), MobileNo2=ISNULL([UL].[Mobileno1], ''),
		MobileNo3=ISNULL([UL].[Mobileno2], ''), EmailId1=ISNULL([UL].[Emailid], ''), EmailId2=ISNULL([UL].[EmailID1], ''), 
		EmailId3= ISNULL([UL].[EmailID2], ''), [City]=isnull([UL].City,''), [State]=isnull([UL].State,''), [Country]=isnull([UL].Country,''),
		PinCode=isnull([UL].[PinCode],0), [ResidentialAddress]=isnull([UL].Residentialaddress,''), 
		[OfficeAddress]=isnull([UL].OfficeAddress,''), [ADDRESS]=CASE WHEN isnull([UL].Companyname,'') <> '' THEN isnull(UL.Officeaddress,'') ELSE isnull(UL.Residentialaddress,'') END  + ' ' + (case when [UL].Pincode=0 then '' else cast(isnull([UL].Pincode,'') as varchar(10)) end) + ' ' + isnull([UL].City,'') + ' ' + isnull([UL].State,'') +  ' ' + isnull([UL].Country,''), [UL].[AssignedTo], isnull([USS].[Name],'') AS [SourceName], isnull([UMS].[Name],'') AS [MediumName], isnull([UCS].[Name],'') AS [CampaignName],
		InitialRemarks=isnull([UL].[InitialRemarks],''), [UL].[ParentID], FUS.[FollowupStatus], [dbo].[fn_getusertimefromindiantime](@ParentId, [UL].[FollowupDate]) AS [FollowupDate],  [UL].[Remarks], ISNULL([UL].[AmountPaid], 0) AS [AmountPaid], 
		[dbo].[fn_getusertimefromindiantime](@ParentId, [UL].[CreatedOn]) AS [CreatedOn], [UL].[CreatedBy], [UL].[ModifiedOn], 
		[UL].[ModifiedBy], [UD].[User_Login], ProfileImgFileName = ISNULL([UL].[ProfileImgFileName], ''),   
	 ( SELECT STUFF( (SELECT N', ' + [ss].[Name] FROM [ProductMaster](nolock) AS [ss] INNER JOIN [dbo].[fn_Split]([ul].[Products], '#') AS [fs] ON [ss].[ProductID] = [fs].[value] FOR XML PATH(''), TYPE).value('text()[1]', 'nvarchar(max)'), 1, 2, N'')) AS [Products], 
		[UD].[User_Login] AS [assigneduser],CASE WHEN ISNULL([UL].[FollowupStatus], '') <> '' THEN '<p><b>FollowUpStatus:&nbsp;&nbsp;</b>' +   
	   CAST(ISNULL([UL].[FollowupStatus], '') AS VARCHAR(50)) + '</p>' ELSE '' END +   
	   CASE WHEN ISNULL([UL].[FollowupDate], '') <> '' THEN '<p><b>Next Status Date:&nbsp;&nbsp;</b>' +   
	   CAST([UL].[FollowupDate] AS VARCHAR(50)) + '</p>' ELSE '' END + CASE WHEN ISNULL([UL].[Products], '') <> '' THEN '<p><b>Next Status Date:&nbsp;&nbsp;</b>' +   
	   CAST([UL].[Products] AS VARCHAR(50)) + '</p>' ELSE '' END + CASE WHEN ISNULL([UL].[AmountPaid], 0) <> 0 THEN '<p><b>Amount Paid:&nbsp;&nbsp;</b>' +   
	   CAST(CAST(ISNULL([UL].[AmountPaid], 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + '</p>' ELSE '' END  +  
	   CASE WHEN ISNULL([UL].[Remarks], '') <> ''THEN '<p><b>Remarks:&nbsp;&nbsp;</b>' + ISNULL([UL].[Remarks], '') + '</p>' ELSE '' END AS [FollowUp], CASE WHEN cast([UL].[FollowupDate] as date) = cast(getdate() as date)  then  'Due today ' WHEN [UL].[FollowupDate] > getdate()  then  'Scheduled' WHEN [UL].[FollowupDate] < getdate()  then  'Overdue' ELSE ''  end as StatusHtml
		FROM UserLeads AS UL(NOLOCK) INNER JOIN UserSourceSettings AS USS(NOLOCK)                                    
		ON UL.SourceName = USS.SourceID LEFT JOIN UserMediumSettings AS UMS(NOLOCK)                                    
		ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)                                    
		ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)                                    
		ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)                                    
		ON UL.CreatedBy = UD1.User_ID left join [FollowUp_Status] AS FUS(NOLOCK)               
		ON UL.[FollowUpStatus] = FUS.[id]  
		WHERE [UL].[ParentID] = @ParentId AND [UL].[AssignedTo] = CASE WHEN @UserId = 0 THEN [UL].[AssignedTo] ELSE @UserId END AND 
		((UL.CreatedOn between @FromDate AND @ToDate) OR (UL.FollowupDate between @FromDate AND @ToDate))  AND [UL].[SourceName]=@Param1
		Order By  case when cast(UL.followupdate as date) = cast(getdate() as date) then 0       
		  when UL.followupdate < getdate()  then 1      
		  when UL.followupdate > getdate() then 2      
		  when UL.followupdate is null then 3      
		   end,UL.followupdate  ;
	END

	IF(@Mode = 'EnquiryCreator')
	BEGIN
		If(@ParentId > 0)
		Begin
			Select	UE.CreatedBy as CreatorID, UD.User_Login as CreatorName, Count(*) as RecCnt
			From	Userenquiry(nolock) UE Left Join User_Detail(NOLOCK) UD
			ON		UE.CreatedBy=UD.User_ID
			Where	UE.ParentId=@ParentId AND [UE].[CreatedDate] between @FromDate AND @ToDate
			Group By  UE.CreatedBy, UD.User_Login
		End
	END

	IF(@Mode = 'EnquiryCreatorDetail')
	BEGIN
		If(@ParentId > 0)
		Begin
			SELECT	[UE].[Enquiryid], [UE].[Personname], [UE].[Companyname],[EmailId1] = [UE].[Emailid], [EmailId2] = [UE].[Emailid1],
					[EmailId3] = [UE].[Emailid2], [Mobileno1] = isnull([UE].[Countrycode],'') + ' ' + isnull([UE].[Mobileno],''), 
					[MobileNo2] = isnull([UE].[Countrycode1],'') + ' ' + isnull([UE].[Mobileno1],''),
					[MobileNo3] = isnull([UE].[Countrycode2],'') + ' ' + isnull([UE].[Mobileno2],''), 
					[UE].[Residentialaddress], [UE].[Officeaddress], [Ud].[User_login], [UE].[CreatedDate], [UE].[City], [UE].[State], 
					[UE].[Country], IIF([UE].[Pincode] = 0, '', STR([UE].[Pincode])) AS [Pincode],
					CASE WHEN [UE].[Companyname] <> '' THEN ISNULL([UE].[Officeaddress], '') ELSE ISNULL([UE].[Residentialaddress], '') END + 
					' ' + IIF([UE].[Pincode] = 0, '', STR([UE].[Pincode])) + ' ' + ISNULL([UE].[City], '') + ' ' + ISNULL([UE].State, '') + 
					' ' + ISNULL([UE].[Country], '') AS [ADDRESS], [UE].[Initialremarks], ISNULL([Uss].[Name], '') AS [SourceName], 
					ISNULL([Ums].[Name], '') AS [MediumName], ISNULL([Ucs].[Name], '') AS [CampaignName], [UE].[Parentid], [UE].[Createdby],
					[LeadNo] = ISNULL([UE].[LeadNo], 0), [UE].[img_ext], (CASE WHEN [UE].[Isopen] = '1' THEN 'open' ELSE (CASE WHEN 
					[UE].[Isopen] = '0' THEN 'close' ELSE 'lead' END) END) AS [Isopen], [UE].[ProfileImgFileName]
			FROM	Userenquiry(NOLOCK) AS UE INNER JOIN Usersourcesettings(NOLOCK) AS Uss
			ON		UE.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings(NOLOCK) AS Ums
			ON		UE.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings(NOLOCK) AS Ucs
			ON		UE.Campaignname = Ucs.Campaignid LEFT JOIN User_detail(NOLOCK) AS Ud
			ON		UE.Createdby = Ud.User_id
