	IF(@Mode = 'EnquiryOpenStatus')
	BEGIN
		If(@ParentId > 0)
		Begin
			Select	Case when UE.IsOpen=1 then 'Open' else 'Closed' End as OpenStatus, UE.IsOpen, Count(*) as RecCnt
			From	Userenquiry(nolock) UE
			Where	UE.ParentId=@ParentId AND [UE].[CreatedDate] between @FromDate AND @ToDate
			Group By  UE.IsOpen
		End
	END

	IF(@Mode = 'EnquiryOpenStatusDetail')
	BEGIN
