					ISNULL([Ums].[Name], '') AS [MediumName], ISNULL([Ucs].[Name], '') AS [CampaignName], [UE].[Parentid], [UE].[Createdby],
					[LeadNo] = ISNULL([UE].[LeadNo], 0), [UE].[img_ext], (CASE WHEN [UE].[Isopen] = '1' THEN 'open' ELSE (CASE WHEN 
					[UE].[Isopen] = '0' THEN 'close' ELSE 'lead' END) END) AS [Isopen], [UE].[ProfileImgFileName]
			FROM	Userenquiry(NOLOCK) AS UE INNER JOIN Usersourcesettings(NOLOCK) AS Uss
