	IF(@Mode = 'CallByAgentInbound')
	BEGIN
		SELECT User_ID, [User], Count(*) AS RecCnt
		FROM      
		(      
			SELECT	FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.callerid, KC.dnid, 
					recordurl = ISNULL(KC.recordurl, ''), UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], UD.ProfilePicturePath AS [ProfilePicturePath], ISNULL(DC.Disposition, '') AS Disposition, (CASE WHEN DC.Disposition = 'ANSWER' THEN 'CONNECTED' ELSE 'MISSED' END) AS CallStatus, (CASE WHEN KC.context = 'DialerCalls' THEN 'Out' ELSE 'In' END) AS CallDirection, CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, DC.call_start_time, DC.call_end_time), 0), '19000101'), 8), UD.ParentID      
			FROM	Kit19Calls(NOLOCK) AS KC INNER JOIN User_Detail(NOLOCK) AS UD 
			ON		KC.accountcode = UD.User_ID INNER JOIN DiallerCalls(NOLOCK) AS DC 
			ON		KC.Id = DC.kit19callsid
			WHERE	KC.context = 'DialerCalls' and kc.call_start_time between @FromDate and @ToDate and kc.clientid=@ParentId  
		
			UNION      
        
			SELECT A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], UD.ProfilePicturePath AS [ProfilePicturePath], A.Disposition, A.CallStatus, A.CallDirection, A.CallPeriod, UD.ParentID
			FROM      
			(      
				SELECT	FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''), Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END), CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END, (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection, CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod, case when isnull(agenttype,'Mobile')='Mobile' then isnull(dbo.fn_trim0prefix(KCD.agentnumber),replace(KCD.callerid, 'Sip/4862600/', '')) else str(u.mobile) end AgentNo, KC.clientid
				FROM	Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD 
				ON		KC.uniqueid = KCD.puniqueid left join user_detail u 
				on		u.parentid=KC.clientid and KCD.agentnumber=cast(User_ID as nvarchar)  
				WHERE	KC.context != 'DialerCalls' and kc.call_start_time between @FromDate and @ToDate 
				and kc.clientid=@ParentId     
			) AS A      
			INNER JOIN User_Detail(NOLOCK) AS UD 
			ON TRIM(A.AgentNo) = TRIM(STR(UD.mobile)) AND A.clientid = UD.ParentID      
        
			UNION      
        
			SELECT A.CallDate, A.callerid,A.dnid,A.recordurl,UD.User_ID,UD.FName + ISNULL(' ' + UD.LName, '') AS [User], UD.ProfilePicturePath AS [ProfilePicturePath], A.Disposition, A.CallStatus, A.CallDirection, A.CallPeriod, UD.ParentID      
			FROM      
			(      
				SELECT	FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate],KC.CallerId,KC.dnid, 
						recordurl = ISNULL(KC.recordurl, ''), Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END), CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END, (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection, CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod, AgentNo = replace(KCD.callerid, 'Sip/', ''), KC.clientid
				FROM	Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD 
				ON		KC.uniqueid = KCD.puniqueid      
				WHERE	KC.context != 'DialerCalls' AND KCD.callerid NOT LIKE '%Sip/4862600/%' AND KCD.dialstatus != 'INVALIDARGS' and kc.call_start_time between @FromDate and @ToDate and kc.clientid=@ParentId  
			) AS A      
			INNER JOIN User_Detail(NOLOCK) AS UD 
			ON TRIM(A.AgentNo) = TRIM(STR(UD.User_ID)) AND A.clientid = UD.ParentID      
        
			UNION      
        
			SELECT	FORMAT(DP.CreateOn, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], CAST(DP.MobileNo AS NVARCHAR) AS [callerid], 'Sim Call' AS [dnid], DP.CallRecordPath AS [recordurl], UD.User_ID AS [User_ID], 
					UD.FName + ISNULL(' ' + UD.LName, '') AS [User],  UD.ProfilePicturePath, (CASE WHEN ISNULL(DP.CallStartDateTime, '') = '' THEN 'MISSED' ELSE 'CONNECTED' END) AS [Disposition], (CASE WHEN ISNULL(DP.CallStartDateTime, '') = '' THEN 'MISSED' ELSE 'CONNECTED' END) AS [CallStatus], 'Out' AS CallDirection, CAST(DP.CallEndDateTime - DP.CallStartDateTime AS TIME) AS [CallPeriod],UD.ParentID      
			FROM	tbl_DailPaidCallDetails(nolock) DP INNER JOIN User_Detail(nolock) UD 
			ON		DP.UserId = UD.User_ID    
			where	DP.CreateOn between @FromDate and @ToDate and Ud.ParentID = @ParentId
		) AS tblDetail      
		WHERE	User_ID IN (SELECT User_Id FROM User_Detail(nolock) WHERE User_id = @UserId OR ParentID = @UserId) AND CallDirection='In'
		Group By User_ID, [User]
		--ORDER BY CAST(CallDate AS DATETIME) DESC; 
	END

	IF(@Mode = 'CallByAgentOutbound')
	BEGIN
		SELECT User_ID, [User], Count(*) AS RecCnt
		FROM      
		(      
			SELECT	FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.callerid, KC.dnid, 
					recordurl = ISNULL(KC.recordurl, ''), UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], UD.ProfilePicturePath AS [ProfilePicturePath], ISNULL(DC.Disposition, '') AS Disposition, (CASE WHEN DC.Disposition = 'ANSWER' THEN 'CONNECTED' ELSE 'MISSED' END) AS CallStatus, (CASE WHEN KC.context = 'DialerCalls' THEN 'Out' ELSE 'In' END) AS CallDirection, CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, DC.call_start_time, DC.call_end_time), 0), '19000101'), 8), UD.ParentID      
			FROM	Kit19Calls(NOLOCK) AS KC INNER JOIN User_Detail(NOLOCK) AS UD 
			ON		KC.accountcode = UD.User_ID INNER JOIN DiallerCalls(NOLOCK) AS DC 
			ON		KC.Id = DC.kit19callsid
			WHERE	KC.context = 'DialerCalls' and kc.call_start_time between @FromDate and @ToDate and kc.clientid=@ParentId  
		
			UNION      
        
			SELECT A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], UD.ProfilePicturePath AS [ProfilePicturePath], A.Disposition, A.CallStatus, A.CallDirection, A.CallPeriod, UD.ParentID
			FROM      
			(      
				SELECT	FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''), Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END), CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END, (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection, CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod, case when isnull(agenttype,'Mobile')='Mobile' then isnull(dbo.fn_trim0prefix(KCD.agentnumber),replace(KCD.callerid, 'Sip/4862600/', '')) else str(u.mobile) end AgentNo,  KC.clientid
				FROM	Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD 
				ON		KC.uniqueid = KCD.puniqueid left join user_detail u 
				on		u.parentid=KC.clientid and KCD.agentnumber=cast(User_ID as nvarchar)  
				WHERE	KC.context != 'DialerCalls' and kc.call_start_time between @FromDate and @ToDate and kc.clientid=@ParentId     
			) AS A      
			INNER JOIN User_Detail(NOLOCK) AS UD 
			ON TRIM(A.AgentNo) = TRIM(STR(UD.mobile)) AND A.clientid = UD.ParentID      
        
			UNION      
        
			SELECT A.CallDate, A.callerid,A.dnid,A.recordurl,UD.User_ID,UD.FName + ISNULL(' ' + UD.LName, '') AS [User], UD.ProfilePicturePath AS [ProfilePicturePath], A.Disposition, A.CallStatus, A.CallDirection, A.CallPeriod, UD.ParentID      
			FROM      
			(      
				SELECT	FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate],KC.CallerId,KC.dnid, 
						recordurl = ISNULL(KC.recordurl, ''), Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END), CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END, (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection, CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod, AgentNo = replace(KCD.callerid, 'Sip/', ''), KC.clientid
				FROM	Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD 
				ON		KC.uniqueid = KCD.puniqueid      
				WHERE	KC.context != 'DialerCalls' AND KCD.callerid NOT LIKE '%Sip/4862600/%' AND KCD.dialstatus != 'INVALIDARGS' and kc.call_start_time between @FromDate and @ToDate and kc.clientid=@ParentId  
			) AS A      
			INNER JOIN User_Detail(NOLOCK) AS UD 
			ON TRIM(A.AgentNo) = TRIM(STR(UD.User_ID)) AND A.clientid = UD.ParentID      
        
			UNION      
        
			SELECT	FORMAT(DP.CreateOn, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], CAST(DP.MobileNo AS NVARCHAR) AS [callerid], 'Sim Call' AS [dnid], DP.CallRecordPath AS [recordurl], UD.User_ID AS [User_ID], 
					UD.FName + ISNULL(' ' + UD.LName, '') AS [User],  UD.ProfilePicturePath, (CASE WHEN ISNULL(DP.CallStartDateTime, '') = '' THEN 'MISSED' ELSE 'CONNECTED' END) AS [Disposition],
					(CASE WHEN ISNULL(DP.CallStartDateTime, '') = '' THEN 'MISSED' ELSE 'CONNECTED' END) AS [CallStatus], 'Out' AS CallDirection, CAST(DP.CallEndDateTime - DP.CallStartDateTime AS TIME) AS [CallPeriod],UD.ParentID      
			FROM	tbl_DailPaidCallDetails(nolock) DP INNER JOIN User_Detail(nolock) UD 
			ON		DP.UserId = UD.User_ID    
			where	DP.CreateOn between @FromDate and @ToDate and Ud.ParentID = @ParentId
        
			UNION      

			select FORMAT(VEI.created_on, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], VEI.ToMobileNo as callerid, '' as dnid, recordurl = ISNULL(VEI.RecordingUrl, ''), UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], UD.ProfilePicturePath AS [ProfilePicturePath], Case ISNULL(VEI.CallStatus, '') When 'ANSWERED' then 'ANSWER' else 'NOANSWER' END AS Disposition, (CASE WHEN VEI.CallStatus in ('ANSWER','ANSWERED') THEN 'CONNECTED' ELSE 'MISSED' END) AS CallStatus, 'Out' AS CallDirection, CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, coalesce(JSON_VALUE(VW.request_body,'$.duration'), JSON_VALUE(VW.request_body,'$[1].Value'),0), '19000101'), 8), UD.ParentID
			From tbl_voip_endpointInteraction(nolock) VEI inner join User_Detail(NOLOCK) AS UD
			ON VEI.AgentId = UD.User_ID left join tbl_voip_Webhook(nolock) VW
			ON cast(VEI.Id as varchar)=VW.UniqueIdentity or VEI.refNumber=VW.UniqueIdentity
			Where UD.ParentID=@ParentId and VEI.created_on between @FromDate and @ToDate
			
		) AS tblDetail      
		WHERE	User_ID IN (SELECT User_Id FROM User_Detail(nolock) WHERE User_id = @UserId OR ParentID = @UserId) AND CallDirection='Out'
		Group By User_ID, [User]
		--ORDER BY CAST(CallDate AS DATETIME) DESC; 
	END

	IF(@Mode = 'CallByAgent')
	BEGIN
		SELECT User_ID, [User], Count(*) AS RecCnt
		FROM      
		(      
			SELECT	FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.callerid, KC.dnid, 
					recordurl = ISNULL(KC.recordurl, ''), UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], UD.ProfilePicturePath AS [ProfilePicturePath], ISNULL(DC.Disposition, '') AS Disposition, (CASE WHEN DC.Disposition = 'ANSWER' THEN 'CONNECTED' ELSE 'MISSED' END) AS CallStatus, (CASE WHEN KC.context = 'DialerCalls' THEN 'Out' ELSE 'In' END) AS CallDirection, CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, DC.call_start_time, DC.call_end_time), 0), '19000101'), 8), UD.ParentID      
			FROM	Kit19Calls(NOLOCK) AS KC INNER JOIN User_Detail(NOLOCK) AS UD 
			ON		KC.accountcode = UD.User_ID INNER JOIN DiallerCalls(NOLOCK) AS DC 
			ON		KC.Id = DC.kit19callsid
			WHERE	KC.context = 'DialerCalls' and kc.call_start_time between @FromDate and @ToDate and kc.clientid=@ParentId  
		
			UNION      
        
			SELECT A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], UD.ProfilePicturePath AS [ProfilePicturePath], A.Disposition, A.CallStatus, A.CallDirection, A.CallPeriod, UD.ParentID
			FROM      
			(      
				SELECT	FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''), Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END), CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END, (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection, CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod, case when isnull(agenttype,'Mobile')='Mobile' then isnull(dbo.fn_trim0prefix(KCD.agentnumber),replace(KCD.callerid, 'Sip/4862600/', '')) else str(u.mobile) end AgentNo,  KC.clientid
				FROM	Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD 
				ON		KC.uniqueid = KCD.puniqueid left join user_detail u 
				on		u.parentid=KC.clientid and KCD.agentnumber=cast(User_ID as nvarchar)  
				WHERE	KC.context != 'DialerCalls' and kc.call_start_time between @FromDate and @ToDate and kc.clientid=@ParentId     
			) AS A      
			INNER JOIN User_Detail(NOLOCK) AS UD 
			ON TRIM(A.AgentNo) = TRIM(STR(UD.mobile)) AND A.clientid = UD.ParentID      
        
			UNION      
        
			SELECT A.CallDate, A.callerid,A.dnid,A.recordurl,UD.User_ID,UD.FName + ISNULL(' ' + UD.LName, '') AS [User], UD.ProfilePicturePath AS [ProfilePicturePath], A.Disposition, A.CallStatus, A.CallDirection, A.CallPeriod, UD.ParentID      
			FROM      
			(      
				SELECT	FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate],KC.CallerId,KC.dnid, 
						recordurl = ISNULL(KC.recordurl, ''), Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END), CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END, (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection, CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod, AgentNo = replace(KCD.callerid, 'Sip/', ''), KC.clientid
				FROM	Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD 
				ON		KC.uniqueid = KCD.puniqueid      
				WHERE	KC.context != 'DialerCalls' AND KCD.callerid NOT LIKE '%Sip/4862600/%' AND KCD.dialstatus != 'INVALIDARGS' and kc.call_start_time between @FromDate and @ToDate and kc.clientid=@ParentId  
			) AS A      
			INNER JOIN User_Detail(NOLOCK) AS UD 
			ON TRIM(A.AgentNo) = TRIM(STR(UD.User_ID)) AND A.clientid = UD.ParentID      
        
			UNION      
        
			SELECT	FORMAT(DP.CreateOn, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], CAST(DP.MobileNo AS NVARCHAR) AS [callerid], 'Sim Call' AS [dnid], DP.CallRecordPath AS [recordurl], UD.User_ID AS [User_ID], 
					UD.FName + ISNULL(' ' + UD.LName, '') AS [User],  UD.ProfilePicturePath, (CASE WHEN ISNULL(DP.CallStartDateTime, '') = '' THEN 'MISSED' ELSE 'CONNECTED' END) AS [Disposition], (CASE WHEN ISNULL(DP.CallStartDateTime, '') = '' THEN 'MISSED' ELSE 'CONNECTED' END) AS [CallStatus], 'Out' AS CallDirection, CAST(DP.CallEndDateTime - DP.CallStartDateTime AS TIME) AS [CallPeriod],UD.ParentID      
			FROM	tbl_DailPaidCallDetails(nolock) DP INNER JOIN User_Detail(nolock) UD 
			ON		DP.UserId = UD.User_ID    
			where	DP.CreateOn between @FromDate and @ToDate and Ud.ParentID = @ParentId
        
			UNION      

			select FORMAT(VEI.created_on, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], VEI.ToMobileNo as callerid, '' as dnid, recordurl = ISNULL(VEI.RecordingUrl, ''), UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], UD.ProfilePicturePath AS [ProfilePicturePath], Case ISNULL(VEI.CallStatus, '') When 'ANSWERED' then 'ANSWER' else 'NOANSWER' END AS Disposition, (CASE WHEN VEI.CallStatus in ('ANSWER','ANSWERED') THEN 'CONNECTED' ELSE 'MISSED' END) AS CallStatus, 'Out' AS CallDirection, CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, coalesce(JSON_VALUE(VW.request_body,'$.duration'), JSON_VALUE(VW.request_body,'$[1].Value'),0), '19000101'), 8), UD.ParentID
			From tbl_voip_endpointInteraction(nolock) VEI inner join User_Detail(NOLOCK) AS UD
			ON VEI.AgentId = UD.User_ID left join tbl_voip_Webhook(nolock) VW
			ON cast(VEI.Id as varchar)=VW.UniqueIdentity or VEI.refNumber=VW.UniqueIdentity
			Where UD.ParentID=@ParentId and VEI.created_on between @FromDate and @ToDate
			
			) AS tblDetail      
		WHERE	User_ID IN (SELECT User_Id FROM User_Detail(nolock) WHERE User_id = @UserId OR ParentID = @UserId)
		Group By User_ID, [User]
	END

	IF(@Mode = 'CallByAgentDisposition')
	BEGIN
		SELECT User_ID, [User], Disposition, Count(*) AS RecCnt
		FROM      
		(      
			SELECT	FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.callerid, KC.dnid, 
					recordurl = ISNULL(KC.recordurl, ''), UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], 
					UD.ProfilePicturePath AS [ProfilePicturePath], ISNULL(DC.Disposition, '') AS Disposition,       
					(CASE WHEN DC.Disposition = 'ANSWER' THEN 'CONNECTED' ELSE 'MISSED' END) AS CallStatus,       
					(CASE WHEN KC.context = 'DialerCalls' THEN 'Out' ELSE 'In' END) AS CallDirection,       
					CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, DC.call_start_time, DC.call_end_time), 0), '19000101'), 8), UD.ParentID      
			FROM	Kit19Calls(NOLOCK) AS KC INNER JOIN User_Detail(NOLOCK) AS UD 
			ON		KC.accountcode = UD.User_ID INNER JOIN DiallerCalls(NOLOCK) AS DC 
			ON		KC.Id = DC.kit19callsid
			WHERE	KC.context = 'DialerCalls' and kc.call_start_time between @FromDate and @ToDate and kc.clientid=@ParentId  
		
			UNION      
        
			SELECT A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User],       
					UD.ProfilePicturePath AS [ProfilePicturePath], A.Disposition, A.CallStatus, A.CallDirection, A.CallPeriod, UD.ParentID
			FROM      
			(      
				SELECT	FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, 
						recordurl = ISNULL(KC.recordurl, ''), 
						Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END),       
						CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END,       
						(CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection,       
						CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,       
						case when isnull(agenttype,'Mobile')='Mobile' then isnull(dbo.fn_trim0prefix(KCD.agentnumber),replace(KCD.callerid, 'Sip/4862600/', '')) else str(u.mobile) end AgentNo,  KC.clientid
				FROM	Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD 
				ON		KC.uniqueid = KCD.puniqueid left join user_detail u 
				on		u.parentid=KC.clientid and KCD.agentnumber=cast(User_ID as nvarchar)  
				WHERE	KC.context != 'DialerCalls' and kc.call_start_time between @FromDate and @ToDate and kc.clientid=@ParentId     
			) AS A      
			INNER JOIN User_Detail(NOLOCK) AS UD 
			ON TRIM(A.AgentNo) = TRIM(STR(UD.mobile)) AND A.clientid = UD.ParentID      
        
			UNION      
        
			SELECT A.CallDate, A.callerid,A.dnid,A.recordurl,UD.User_ID,UD.FName + ISNULL(' ' + UD.LName, '') AS [User],       
					UD.ProfilePicturePath AS [ProfilePicturePath],A.Disposition,A.CallStatus,A.CallDirection,A.CallPeriod,UD.ParentID      
			FROM      
			(      
				SELECT	FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate],KC.CallerId,KC.dnid, 
						recordurl = ISNULL(KC.recordurl, ''),       
						Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END),       
						CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END,       
						(CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection,       
						CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,       
						AgentNo = replace(KCD.callerid, 'Sip/', ''), KC.clientid
				FROM	Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD 
				ON		KC.uniqueid = KCD.puniqueid      
				WHERE	KC.context != 'DialerCalls' AND KCD.callerid NOT LIKE '%Sip/4862600/%' AND KCD.dialstatus != 'INVALIDARGS'
						and kc.call_start_time between @FromDate and @ToDate and kc.clientid=@ParentId  
			) AS A      
			INNER JOIN User_Detail(NOLOCK) AS UD 
			ON TRIM(A.AgentNo) = TRIM(STR(UD.User_ID)) AND A.clientid = UD.ParentID      
        
			UNION      
        
			SELECT	FORMAT(DP.CreateOn, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], CAST(DP.MobileNo AS NVARCHAR) AS [callerid], 
					'Sim Call' AS [dnid], DP.CallRecordPath AS [recordurl], UD.User_ID AS [User_ID], 
					UD.FName + ISNULL(' ' + UD.LName, '') AS [User],  UD.ProfilePicturePath,       
					(CASE WHEN ISNULL(DP.CallStartDateTime, '') = '' THEN 'MISSED' ELSE 'CONNECTED' END) AS [Disposition],       
					(CASE WHEN ISNULL(DP.CallStartDateTime, '') = '' THEN 'MISSED' ELSE 'CONNECTED' END) AS [CallStatus],       
					'Out' AS CallDirection, CAST(DP.CallEndDateTime - DP.CallStartDateTime AS TIME) AS [CallPeriod],UD.ParentID      
			FROM	tbl_DailPaidCallDetails(nolock) DP INNER JOIN User_Detail(nolock) UD 
			ON		DP.UserId = UD.User_ID    
			where	DP.CreateOn between @FromDate and @ToDate and Ud.ParentID = @ParentId
        
			UNION      

			select FORMAT(VEI.created_on, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], VEI.ToMobileNo as callerid, '' as dnid, recordurl = ISNULL(VEI.RecordingUrl, ''), UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], UD.ProfilePicturePath AS [ProfilePicturePath], Case ISNULL(VEI.CallStatus, '') When 'ANSWERED' then 'ANSWER' else 'NOANSWER' END AS Disposition, (CASE WHEN VEI.CallStatus in ('ANSWER','ANSWERED') THEN 'CONNECTED' ELSE 'MISSED' END) AS CallStatus, 'Out' AS CallDirection, CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, coalesce(JSON_VALUE(VW.request_body,'$.duration'), JSON_VALUE(VW.request_body,'$[1].Value'),0), '19000101'), 8), UD.ParentID
			From tbl_voip_endpointInteraction(nolock) VEI inner join User_Detail(NOLOCK) AS UD
			ON VEI.AgentId = UD.User_ID left join tbl_voip_Webhook(nolock) VW
			ON cast(VEI.Id as varchar)=VW.UniqueIdentity or VEI.refNumber=VW.UniqueIdentity
			Where UD.ParentID=@ParentId and VEI.created_on between @FromDate and @ToDate
			
			) AS tblDetail      
		WHERE	User_ID IN (SELECT User_Id FROM User_Detail(nolock) WHERE User_id = @UserId OR ParentID = @UserId)
		Group By User_ID, [User], Disposition
	END

	IF(@Mode = 'CallByAgentCallPeriod')
	BEGIN
		SELECT User_ID, [User], cast(Sum([CallPeriod]) as int)/60 AS TotalCallPeriod
		FROM      
		(      
			SELECT	FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.callerid, KC.dnid, 
					recordurl = ISNULL(KC.recordurl, ''), UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], UD.ProfilePicturePath AS [ProfilePicturePath], ISNULL(DC.Disposition, '') AS Disposition,    
					(CASE WHEN DC.Disposition = 'ANSWER' THEN 'CONNECTED' ELSE 'MISSED' END) AS CallStatus, 
