		group by format([CallDate],'dd-MMM-yyyy')
	END

	IF(@Mode = 'OwnerConversionCount')
	BEGIN
		Select CreatedBy,UD.User_Login, count(*) as RecCnt
		From LeadInteractionHistory(nolock) LIH left join User_Detail(nolock) UD
		ON	LIH.CreatedBy=UD.User_ID
		Where LIH.followupstatus=5 and LIH.ParentID=@ParentId and LIH.CreatedOn between @FromDate AND @ToDate
		group by LIH.CreatedBy,UD.User_Login
	END

	IF(@Mode = 'OwnerConversionAmount')
	BEGIN
		Select CreatedBy,UD.User_Login, Sum(LIH.AmountPaid) as ConversionAmount
		From LeadInteractionHistory(nolock) LIH left join User_Detail(nolock) UD
		ON	LIH.CreatedBy=UD.User_ID
		Where LIH.followupstatus=5 and LIH.ParentID=@ParentId and LIH.CreatedOn between @FromDate AND @ToDate
		group by LIH.CreatedBy,UD.User_Login
	END

	IF(@Mode = 'OwnerConversionProductCount')
	BEGIN
		select A.CreatedBy,A.User_Login, Sum(A.NProdCnt) as NConvertedProducts
		from 
		(
			Select CreatedBy,UD.User_Login, (select count(*) from dbo.fn_Split(LIH.Products,'#')) as NProdCnt
			From LeadInteractionHistory(nolock) LIH left join User_Detail(nolock) UD
			ON	LIH.CreatedBy=UD.User_ID
			Where LIH.followupstatus=5 and LIH.ParentID=@ParentId and LIH.CreatedOn between @FromDate AND @ToDate
		) A
		group by A.CreatedBy,A.User_Login
	END

	IF(@Mode = 'ConversionProductAmount')
	BEGIN
		Select  SP.value, PM.Name, Sum(LIH.AmountPaid) as TotalAmount
		From LeadInteractionHistory(nolock) LIH cross apply dbo.fn_Split(LIH.Products,'#') SP
		left join [ProductMaster](nolock) PM	On		SP.value=PM.ProductID
		Where LIH.ParentID=@ParentId and isnull(LIH.Products,'') != '' and LIH.CreatedOn between @FromDate AND @ToDate
		and LIH.AmountPaid > 0
		group by SP.value, PM.Name
	END

	If(@Mode = 'ConversionCustomerCountAmount')
	BEGIN
		Select  UL.ID, UL.LeadNo, UL.PersonName, Count(LIH.ID) as RecCnt, Sum(LIH.AmountPaid) as TotalAmount
		From UserLeads(nolock) UL left join LeadInteractionHistory(nolock) LIH
		On	UL.ParentID=LIH.ParentID and UL.LeadNo=LIH.LeadNo
		Where LIH.ParentID=@ParentId and LIH.FollowUpStatus=5 and LIH.CreatedOn between @FromDate AND @ToDate
		Group By UL.ID, UL.LeadNo, UL.PersonName
	END

	If(@Mode = 'FollowupByAssignedTo')
	BEGIN
		Select AssignedTo,UD.User_Login, count(*) as RecCnt
		From LeadInteractionHistory(nolock) LIH left join User_Detail(nolock) UD
		ON	LIH.AssignedTo=UD.User_ID
		Where LIH.ParentID=@ParentId and LIH.CreatedOn between @FromDate AND @ToDate
		group by LIH.AssignedTo,UD.User_Login
	END

	If(@Mode = 'FollowupOverdue')
	BEGIN
		Select  UL.AssignedTo, UD.User_Login, Count(*) as RecCnt
		From UserLeads(nolock) UL left join User_Detail(nolock) UD
		ON	UL.AssignedTo=UD.User_ID
		Where UL.ParentID=@ParentId and UL.FollowUpStatus=1 and dbo.[fn_getISTtimefromusertime](UL.ParentID,UL.FollowupDate) < GETDATE() AND (UL.CreatedOn between @FromDate AND @ToDate)
		Group By UL.AssignedTo, UD.User_Login
	END

	If(@Mode = 'FollowupByCompleted')
	BEGIN
		Select A.AssignedTo, UD.User_Login, Count(*) as RecCnt
		From
		(
			Select ROW_NUMBER()over(partition by LeadNo order by ID desc) SNo, *
			From LeadInteractionHistory(nolock) LIH
			Where LIH.ParentID=@ParentId and LIH.CreatedOn between @FromDate AND @ToDate
		)A left join User_Detail(nolock) UD 
		ON	A.AssignedTo=UD.User_ID
		Where A.SNo=2 and A.FollowUpStatus=1
		Group By A.AssignedTo, UD.User_Login
	END

	If(@Mode = 'FollowupByStatusCreator')
	BEGIN
		Select	LIH.AssignedTo, UD.User_Login, LIH.FollowUpStatus as FollowUpStatusID, FS.FollowupStatus as FollowupStatusName, 
				Count(*) as RecCnt
		From	LeadInteractionHistory(nolock) LIH left join User_Detail(nolock) UD 
		ON		LIH.AssignedTo=UD.User_ID left join FollowUp_Status(nolock) FS
		On		LIH.FollowUpStatus=FS.ID
		Where	LIH.ParentID=@ParentId and LIH.CreatedOn between @FromDate AND @ToDate
		Group By LIH.AssignedTo, UD.User_Login, LIH.FollowUpStatus, FS.FollowupStatus
		order by 1
	END




END



