/* ============================================================
   Procedure: [dbo].[usp_ReplaceAttributes]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_ReplaceAttributes](@notificationid int)
as
begin
--declare @notificationid int=1
/*
CREATE TABLE #Alertsdata(
	[ReportDate] [datetime] NULL,
	[DaySMSConsumption] [bigint] NULL,
	[DayMailConsumption] [bigint] NULL,
	[MonthSMSConsumption] [bigint] NULL,
	[MonthMailConsumption] [bigint] NULL,
	[AverageSMSConsumption] [bigint] NULL,
	[AverageMailConsumption] [bigint] NULL,
	[CurrentSMSBalance] [bigint] NULL,
	[CurrentMailBalance] [bigint] NULL,
	[NewEnquiries] [int] NULL,
	[NewLeads] [int] NULL,
	[NewConversions] [int] NULL,
	[Dayorderamount] [money] NULL,
	[MonthEnquiries] [int] NULL,
	[MonthLeads] [int] NULL,
	[MonthConversions] [int] NULL,
	[OrderAmount] [money] NULL,
	[TotalSMSCampaigns] [int] NULL,
	[TotalMailCampaigns] [int] NULL,
	[TotalLandingPages] [int] NULL,
	[LandingPageDayLeads] [int] NULL,
	[LandingPageMonthLeads] [int] NULL,
	[TotalWebforms] [int] NULL,
	[WebformDayLeads] [int] NULL,
	[WebformMonthLeads] [int] NULL,
	[DayEshopOrders] [int] NULL,
	[DayEshopOrderAmount] [money] NULL,
	[EshopMonthOrders] [int] NULL,
	[EshopMonthOrderAmount] [money] NULL,
	[user_id] [bigint] NULL
)*/

select getdate()
select * into #Alertsdata from Alertsdata
--insert into #Alertsdata select * from Alertsdata
--select * from #Alertsdata
declare @ucount int=(select COUNT(distinct User_id) from #Alertsdata)
--select @ucount
declare @user_id bigint
declare @content nvarchar(max)=(select content from notifications where id=@notificationid)
--select @content
create table #final(user_id bigint,content text COLLATE SQL_Latin1_General_CP1_CI_AS)

while @ucount>0

	begin
		select @user_id=MIN(USER_ID) from #Alertsdata --where user_id=1687
		--select @user_id
		declare @replacements int=(select COUNT(1) from replaceableAttributes where tablename='#AlertsData')
		--select @replacements
		declare @ovalue nvarchar(100),@fvalue nvarchar(100),@fcvalue nvarchar(100)
		declare @id int=0,@q1 nvarchar(max)

		--while @replacements >0
			begin
				--set @id=(select min(ID) from replaceableAttributes where tablename='#AlertsData' and id>@id)
				--select @id
				
				--create table #replaceableAttributes (ValueToBeReplaced nvarchar(200),ColumnName nvarchar(200))
				
				--insert into #replaceableAttributes
				--select ValueToBeReplaced , ColumnName
				--from replaceableAttributes where tablename='#AlertsData';
				
				/*Chakri Code Start*/
				
				DECLARE 
				  @table         NVARCHAR(257) = N'dbo.Alertsdata', 
				  @key_column    SYSNAME       = N'User_ID';
				DECLARE 
				  @colNames  NVARCHAR(MAX) = N'',
				  @colValues NVARCHAR(MAX) = N'',
				  @sql       NVARCHAR(MAX) = N'';
				SELECT 
				  @colNames += ', 
					' + QUOTENAME(name), 
				  @colValues += ', 
					' + QUOTENAME(name) 
				   + ' = CONVERT(VARCHAR(320), ' + QUOTENAME(name) + ')'
				FROM sys.columns
				WHERE [object_id] = OBJECT_ID(@table)
				AND name <> @key_column;
				SET @sql = N'SELECT User_ID, ColumnName, Value
				FROM
				(
				  SELECT ' + @key_column + @colValues + '
				   FROM ' + @table + '
				   where User_id=  '+cast(@user_id as varchar)+'
				) AS t
				UNPIVOT
				(
				  Value FOR ColumnName IN (' + STUFF(@colNames, 1, 1, '') + ')
				) AS up;';
				
				--PRINT @sql;
				
				if OBJECT_ID('tempdb..#ColumnValues',N'U') IS NOT NULL drop table #ColumnValues;
				
				CREATE TABLE #ColumnValues (User_id bigint,ColumnName nvarchar(200) COLLATE SQL_Latin1_General_CP1_CI_AS,
				ColumnValue nvarchar(200) COLLATE SQL_Latin1_General_CP1_CI_AS)
				
				INSERT INTO #ColumnValues
				exec sp_executesql @sql;
				
				/*Chakri Code end*/					
				
				/*select @ovalue=ValueToBeReplaced,@fvalue=ColumnName from replaceableAttributes where ID=@id
				--select @ovalue,@fvalue
				set @q1='select @fcvalue=isnull(' +@fvalue + ','''') from #Alertsdata where user_id='+ cast(@user_id as nvarchar) +' '
				execute sp_executesql @q1,N'@fcvalue nvarchar(max) OUTPUT', 
					@fcvalue = @fcvalue output;
				--select @q1
				--select @fcvalue
				set @content = replace(@content,@ovalue,@fcvalue)
				--select @content
				set @replacements=@replacements-1
				--select @replacements*/
			end
		--insert into #final
		--select @user_id,@content
		
		insert into #final
		select @user_id,replace(@content COLLATE DATABASE_DEFAULT,r.ValueToBeReplaced,c.ColumnValue)
		from replaceableAttributes r
		inner join #ColumnValues c on r.ColumnName COLLATE DATABASE_DEFAULT =c.ColumnName COLLATE DATABASE_DEFAULT 
		
		select @content=content from notifications where id=@notificationid
		
		delete From #alertsdata where user_id=@user_id
		
		set @ucount=@ucount-1
	end
select user_id,content from #final
select getdate()
end



GO

/* ============================================================
   Procedure: [dbo].[usp_ReplaceAttributes1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_ReplaceAttributes1](@notificationid int)
as
begin
--declare @notificationid int=1
select * into #process from alertsdata a cross join ReplaceableAttributes r  
declare @ucount int=(select COUNT(distinct user_id) from #process)
--select @ucount
declare @user_id bigint
declare @content nvarchar(max)=(select content from notifications where id=@notificationid)
--select @content
create table #final(user_id bigint,content text)
while @ucount>0
begin
select @user_id=MIN(USER_ID) from #process
--select @user_id
declare @replacements int=(select COUNT(1) from replaceableAttributes where tablename='#AlertsData')
--select @replacements
declare @ovalue nvarchar(100),@fvalue nvarchar(100),@fcvalue nvarchar(100)
declare @id int=0,@q1 nvarchar(max)
while @replacements >0
begin
set @id=(select min(ID) from replaceableAttributes where tablename='#AlertsData' and id>@id)
--select @id
select @ovalue=ValueToBeReplaced,@fvalue=ColumnName from replaceableAttributes where ID=@id
--select @ovalue,@fvalue
set @q1='select @fcvalue=isnull(' +@fvalue + ','''') from Alertsdata where user_id='+ cast(@user_id as nvarchar) +' '
execute sp_executesql @q1,N'@fcvalue nvarchar(max) OUTPUT', 
    @fcvalue = @fcvalue output;
--select @q1
--select @fcvalue
set @content = replace(@content,@ovalue,@fcvalue)
--select @content
set @replacements=@replacements-1
--select @replacements
if @replacements=0
begin
insert into #final
select @user_id,@content
delete From #process where user_id=@user_id
select @content=content from notifications where id=@notificationid
end
end
set @ucount=@ucount-1
end
select user_id,content from #final
end


