CREATE   PROCEDURE usp_replacecustomplaceholders-- 1199427, 'lead',
--   'Dear customer, your details are Load_KW: #Load_KW#,Day_Load: #Day_Load#,Night_load: #Night_load#,meter_type_description: #meter_type_description#,Noof_DG: #Noof_DG#,
--DG_Total_Capacity_KVA: #DG_Total_Capacity_KVA#,Total_Roof_Area_Sq_Mtr: #Total_Roof_Area_Sq_Mtr#,Roof_Type_Description: #Roof_Type_Description#,Structure_Type: #Structure_Type#,
--Distance_Mtrs: #Distance_Mtrs#,Subsidy_Entitled: #Subsidy_Entitled#,Solar_Capacity_KW: #Solar_Capacity_KW#,Entry_Date: #Entry_Date#,Modify_Date: #Modify_Date#,Survey_No: #Survey_No#,
--Segment_Description: #Segment_Description#,id_: #id_#,Contact_1: #Contact_1#,Contact_2: #Contact_2#,Contact3: #Contact3#'
(@entityid bigint,@entity nvarchar(20),@string nvarchar(max))  
as  
begin  
declare @parentid bigint,@ad nvarchar(max)  
drop table if exists #activitydata_withevent_rc
create table #activitydata_withevent_rc(displaykey nvarchar(100),valuev nvarchar(max))
if @entity='lead'
begin
select @parentid=parentid from userleads(nolock) where id=@entityid
insert into #activitydata_withevent_rc(displaykey,valuev)
select fieldname,cast(isnull(fieldvalue,'') as nvarchar(max)) as valuev from customfieldLeadvalue c(nolock) join customfields f (nolock) on f.field_ID=c.fieldID
where c.LeadID=@entityid and f.isActive=1

;WITH TranslationTable  
AS (  
    SELECT FindValue = '#' + displaykey + '#' ,ReplaceValue = valuev,ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS rn  
    FROM #activitydata_withevent_rc where displaykey is not null  
    )  
--Recursive CTE to loop through the TranslationTable and replace FindValue with ReplaceValue  
,RecursiveCte as  
(  
SELECT cast(@string as nvarchar(max)) AS StrValue  
    ,(  
        SELECT count(*)  
        FROM TranslationTable  
        ) AS cnt  
  
UNION ALL  
  
SELECT cast(replace(StrValue, tt.FindValue, tt.Replacevalue) as nvarchar(max))  
    ,cnt - 1  
FROM RecursiveCte  
JOIN TranslationTable tt  
    ON tt.rn = cnt )  
  
SELECT StrValue ,cnt FROM RecursiveCte where cnt = 0  

end
else if @entity='enquiry'
begin
truncate table #activitydata_withevent_rc
select @parentid=parentid from userenquiry(nolock) where EnquiryID=@entityid
insert into #activitydata_withevent_rc(displaykey,valuev)
select fieldname,cast(isnull(fieldvalue,'') as nvarchar(max)) as valuev from customfieldEnquiryvalue c(nolock) join customfields f (nolock) on f.field_ID=c.fieldID
where c.EnquiryID=@entityid and f.isActive=1

;WITH TranslationTable  
AS (  
    SELECT FindValue = '#' + displaykey + '#' ,ReplaceValue = valuev,ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS rn  
    FROM #activitydata_withevent_rc where displaykey is not null  
    )  
--Recursive CTE to loop through the TranslationTable and replace FindValue with ReplaceValue  
,RecursiveCte as  
(  
SELECT cast(@string as nvarchar(max)) AS StrValue  
    ,(  
        SELECT count(*)  
        FROM TranslationTable  
        ) AS cnt  
  
UNION ALL  
  
SELECT cast(replace(StrValue, tt.FindValue, tt.Replacevalue) as nvarchar(max))  
    ,cnt - 1  
FROM RecursiveCte  
JOIN TranslationTable tt  
    ON tt.rn = cnt )  
  
SELECT StrValue ,cnt FROM RecursiveCte where cnt = 0  

end
  
end  
  
  
  
  
--   'Dear customer, your details are Load_KW: #Load_KW#,Day_Load: #Day_Load#,Night_load: #Night_load#,meter_type_description: #meter_type_description#,Noof_DG: #Noof_DG#,
--DG_Total_Capacity_KVA: #DG_Total_Capacity_KVA#,Total_Roof_Area_Sq_Mtr: #Total_Roof_Area_Sq_Mtr#,Roof_Type_Description: #Roof_Type_Description#,Structure_Type: #Structure_Type#,
--Distance_Mtrs: #Distance_Mtrs#,Subsidy_Entitled: #Subsidy_Entitled#,Solar_Capacity_KW: #Solar_Capacity_KW#,Entry_Date: #Entry_Date#,Modify_Date: #Modify_Date#,Survey_No: #Survey_No#,
--Segment_Description: #Segment_Description#,id_: #id_#,Contact_1: #Contact_1#,Contact_2: #Contact_2#,Contact3: #Contact3#'
  
  
  
  
  
  
  
--select fieldname+': #'+fieldname+'#,',cast(isnull(fieldvalue,'') as nvarchar(max)) as valuev from customfieldleadvalue c(nolock) join customfields f (nolock) on f.field_ID=c.fieldID
