CREATE  PROCEDURE [dbo].[usp_replaceentityplaceholders]        
@entityid bigint,@entity nvarchar(50),@string nvarchar(max) ,@strvalue nvarchar(max) OUTPUT       
as        
begin        
/*    
--declare @entity nvarchar(50)='enquiry',@entityid bigint=4524534,@string nvarchar(max)='Dear, your details are: enquiry.CampaignName: #enquiry.CampaignName# enquiry.City: #enquiry.City# enquiry.CompanyName: #enquiry.CompanyName#       
--enquiry.Country: #enquiry.Country# enquiry.CountryCode: #enquiry.CountryCode# enquiry.CountryCode1: #enquiry.CountryCode1# enquiry.CountryCode2: #enquiry.CountryCode2# enquiry.CreatedBy: #enquiry.CreatedBy# enquiry.CreatedDate: #enquiry.CreatedDate# enq
  
uiry.EmailID:       
--#enquiry.EmailID# enquiry.EmailID1: #enquiry.EmailID1# enquiry.EmailID2: #enquiry.EmailID2# enquiry.EnquiryID: #enquiry.EnquiryID# enquiry.InitialRemarks: #enquiry.InitialRemarks# enquiry.IsOpen: #enquiry.IsOpen# enquiry.LeadNo: #enquiry.LeadNo# enquiry
  
.MediumName:       
--#enquiry.MediumName# enquiry.MobileNo: #enquiry.MobileNo# enquiry.MobileNo1: #enquiry.MobileNo1# enquiry.MobileNo2: #enquiry.MobileNo2# enquiry.OfficeAddress: #enquiry.OfficeAddress# enquiry.PersonName: #enquiry.PersonName# enquiry.PinCode:       
--#enquiry.PinCode# enquiry.ResidentialAddress: #enquiry.ResidentialAddress# enquiry.SourceName: #enquiry.SourceName# enquiry.State: #enquiry.State# enquiry.test_date: #enquiry.test_date# enquiry.Load_KW: #enquiry.Load_KW# enquiry.Day_Load: #enquiry.Day_L
  
oad#       
--enquiry.Night_load: #enquiry.Night_load# enquiry.meter_type_description: #enquiry.meter_type_description# enquiry.Noof_DG: #enquiry.Noof_DG# enquiry.DG_Total_Capacity_KVA: #enquiry.DG_Total_Capacity_KVA# enquiry.Total_Roof_Area_Sq_Mtr: #enquiry.Total_Ro
  
of_Area_Sq_Mtr#      
-- enquiry.Roof_Type_Description: #enquiry.Roof_Type_Description# enquiry.Structure_Type: #enquiry.Structure_Type# enquiry.Distance_Mtrs: #enquiry.Distance_Mtrs# enquiry.Subsidy_Entitled: #enquiry.Subsidy_Entitled# enquiry.Solar_Capacity_KW:       
-- #enquiry.Solar_Capacity_KW# enquiry.Entry_Date: #enquiry.Entry_Date# enquiry.Modify_Date: #enquiry.Modify_Date# enquiry.Survey_No: #enquiry.Survey_No# enquiry.Segment_Description: #enquiry.Segment_Description# enquiry.id_: #enquiry.id_# enquiry.Contact
  
_1:       
-- #enquiry.Contact_1# enquiry.Contact_2: #enquiry.Contact_2# enquiry.Contact3: #enquiry.Contact3#'        
*/    
declare @parentid bigint        
if @entity='lead'        
select @parentid=parentid from userleads(nolock) where id=@entityid        
else        
select @parentid=parentid from userenquiry(nolock) where enquiryid=@entityid        
        
drop table if exists #epht        
drop table if exists #entitydata_replace        
create table #epht(fieldnameexposed nvarchar(200),fieldnameactual nvarchar(200),fieldtype nvarchar(10))        
insert into #epht(fieldnameexposed,fieldnameactual,fieldtype)        
exec usp_getentityplaceholders @parentid,@entity        
        
alter table #epht add fieldvalue nvarchar(max)        
    
if @entity='enquiry'  
begin  
update e set fieldvalue=coalesce(cast(c.fieldvalue as nvarchar(max)),cast(l.fieldvalue as nvarchar(max)),'') from #epht e         
left join         
 (select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue from customfields(nolock) f       
 left join customfieldEnquiryvalue c on c.fieldID=f.field_ID and c.EnquiryID=@entityid  where f.parentid=@parentid)       
 c on @entity+'.'+c.fieldname=e.fieldnameactual and e.fieldtype='custom'   
    left join         
 (select 'calculatedfield.'+calculatedfield_name fieldname,isnull(cast(f.field_value as nvarchar(max)),'') fieldvalue from calculated_fields f (nolock)  join calculated_fields_master m 
(nolock) on f.calculatedfield_id=m.id where isnull(f.parentid,@parentid)=@parentid and entity=@entity and entityid=@entityid  
 )       
 l on @entity+'.'+l.fieldname=e.fieldnameactual and e.fieldtype='calculated'   
   
/*  
join         
(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue from customfields(nolock) f       
left join customfieldEnquiryvalue c on c.fieldID=f.field_ID and c.EnquiryID=@entityid  where f.parentid=@parentid)        
c on @entity+'.'+c.fieldname=e.fieldnameactual and e.fieldtype='custom'        
*/  
end  
if @entity='lead'  
begin  
update e set fieldvalue=coalesce(cast(c.fieldvalue as nvarchar(max)),cast(l.fieldvalue as nvarchar(max)),'') from #epht e         
left join         
 (select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue from customfields(nolock) f       
 left join customfieldleadvalue c on c.fieldID=f.field_ID and c.LeadID=@entityid  where f.parentid=@parentid)        
 c on @entity+'.'+c.fieldname=e.fieldnameactual and e.fieldtype='custom'    
 left join         
 (select 'calculatedfield.'+calculatedfield_name fieldname,isnull(cast(f.field_value as nvarchar(max)),'') fieldvalue from calculated_fields f (nolock)  join calculated_fields_master m 
(nolock) on f.calculatedfield_id=m.id where isnull(f.parentid,@parentid)=@parentid and entity=@entity and entityid=@entityid  
 )       
 l on @entity+'.'+l.fieldname=e.fieldnameactual and e.fieldtype='calculated'   
   
/*  
join         
(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue from customfields(nolock) f       
left join customfieldleadvalue c on c.fieldID=f.field_ID and c.LeadID=@entityid  where f.parentid=@parentid)        
c on @entity+'.'+c.fieldname=e.fieldnameactual and e.fieldtype='custom'        
*/  
  
end  
        
declare @entitydata nvarchar(max)        
if @entity='lead'        
set @entitydata=(select * from (select u.*,isnull(str(d.mobile),'') as AssignedToPhone,isnull(d.email,'') as AssignedToEmail  
,dbo.fn_getentityfullname('user',d.user_id) as AssignedToName  
from Userleads u(nolock) left join user_detail d(nolock) on d.user_id=u.assignedto where u.id=@entityid) a for json auto,INCLUDE_NULL_VALUES)        
else  if @entity='enquiry'      
set @entitydata=(select * from (select u.*,isnull(str(d.mobile),'') as CreatedByPhone,isnull(d.email,'') as CreatedByEmail  
,dbo.fn_getentityfullname('user',d.user_id) as CreatedByName  
from UserEnquiry u(nolock)  left join user_detail d(nolock) on d.user_id=u.CreatedBy  where enquiryid=@entityid) a for json auto,INCLUDE_NULL_VALUES)        
    else  if @entity='user'      
set @entitydata=(select * from (select u.* from vw_userdetails u(nolock) where user_id=@entityid) a for json auto,INCLUDE_NULL_VALUES)        
   else  if @entity='partner'      
set @entitydata=(select * from (select u.* from vw_partnerdetails u(nolock) where reseller_id=@entityid) a for json auto,INCLUDE_NULL_VALUES)        
   
        
create table #entitydata_replace(k nvarchar(200),v nvarchar(max),t nvarchar(20))        
insert into #entitydata_replace        
select * from openjson(replace(replace(@entitydata,'[',''),']',''))       
      
update  #entitydata_replace set v='' where v is null      
        
update ed set v=case         
when k in ('createdby','assignedto','LastFollowupcreatedby') then dbo.fn_getuserlogins(v)         
when k='sourcename' then s.name        
when k='mediumname' then m.name        
when k='campaignname' then c.name 
when k='Followupstatus' then f.FollowupStatus
else v end        
from #entitydata_replace ed         
left join UserSourceSettings s on ed.v=cast(s.SourceID as nvarchar)        
left join UsermediumSettings m on ed.v=cast(m.MediumID as nvarchar)        
left join UserCampaignSettings c on ed.v=cast(c.CampaignID as nvarchar) 
left join FollowUp_Status f on ed.v=cast(f.id as nvarchar)
         
         
update e set fieldvalue=cast(isnull(c.v,'') as nvarchar(max)) from #epht e         
join #entitydata_replace c on @entity+'.'+c.k=e.fieldnameactual        
      
declare @tbl as recursivereplace      
      
insert into @tbl(displaykey,[value])      
select fieldnameexposed,fieldvalue from #epht      
      
      
select @Strvalue=dbo.fn_recursivereplace(@tbl,@string) --as Strvalue      
      
        
--;WITH TranslationTable          
--AS (          
--    SELECT FindValue = '#' + fieldnameexposed + '#' ,ReplaceValue = fieldvalue,ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS rn          
--    FROM #epht where fieldnameexposed is not null          
--    )          
----Recursive CTE to loop through the TranslationTable and replace FindValue with ReplaceValue          
--,RecursiveCte as          
--(          
--SELECT cast(@string as nvarchar(max)) AS StrValue          
--    ,(          
--        SELECT count(*)          
--        FROM TranslationTable          
--        ) AS cnt          
          
--UNION ALL          
          
--SELECT cast(replace(StrValue, tt.FindValue, tt.Replacevalue) as nvarchar(max))          
--    ,cnt - 1          
--FROM RecursiveCte          
--JOIN TranslationTable tt          
--    ON tt.rn = cnt )          
          
--SELECT StrValue ,cnt FROM RecursiveCte where cnt = 0          
        
        
drop table if exists #epht        
drop table if exists #entitydata_replace        
        
end        


GO

