/* ============================================================
   Procedure: [dbo].[usp_replaceentityplaceholders_bulk]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*    
select top 10 * from userenquiry(nolock) where parentid =34594 and enquiryid in (select enquiryid from customfieldEnquiryvalue(nolock))    
order by enquiryid desc    
select top 80 c.fieldname,f.* from customfieldEnquiryvalue(nolock) f join customfields(nolock) c on f.fieldID=c.field_ID where parentid=34594 and enquiryid in (10748289,10697957,10697823) order by recordid desc    
    
declare @entities as entities,@entityplaceholders nvarchar(max)='#enquiry.personname#,#enquiry.DOB#,#enquiry.FamilyHistory#',@bigtemplatetext nvarchar(max)    
=(select replace(eventnotification,'#Activity.description#','Hello #enquiry.personname#, custom field is #enquiry.DOB# and #enquiry.FamilyHistory#') from eventnotification (nolockhinsert into @entities(entity,entityid,actiondetails)    
select top 10000 'enquiry',enquiryid,'Hello #enquiry.personname#, custom field is #enquiry.DOB# and #enquiry.FamilyHistory#' from     
userenquiry(nolock) where parentid =34594 and enquiryid in (select enquiryid from customfieldEnquiryvalue(nolock))    
order by enquiryid desc    
exec [usp_replaceentityplaceholders_bulk] @entities,@entityplaceholders    
*/    
   
--declare @entities as [entities_withcontent] ,@entityplaceholders nvarchar(max) ='#user.user_login#,#user.firstname#'
--insert into @entities(entity,entityid,actiondetails)
--select 'user',user_id,'The user_login is #user.user_login#, first name is user.firstname#' from user_detail(nolock) where user_id in (335,34594,32222,33819)
--exec [usp_replaceentityplaceholders_bulk] @entities,@entityplaceholders


CREATE   PROCEDURE [dbo].[usp_replaceentityplaceholders_bulk]            
@entities as [entities_withcontent] readonly,@entityplaceholders nvarchar(max)    
as            
begin        
if isnull(@entityplaceholders,'')<>''    
begin    
declare @parentid bigint,@entity nvarchar(50) ,@entityid bigint,@fieldname nvarchar(100),@count int,@sql nvarchar(max),@p_id int=0,    
@c_count int,@c_id int=0    
select top 1 @entity=entity,@entityid=entityid from @entities    
if @entity='lead'            
select top 1 @parentid=parentid from userleads(nolock) where id=@entityid            
else            
select top 1 @parentid=parentid from userenquiry(nolock) where enquiryid=@entityid            
            
drop table if exists #epht            
drop table if exists #entitydata_replace       
drop table if exists #entitydata        
drop table if exists #predefined        
drop table if exists #custom        
    
create table #epht(fieldnameexposed nvarchar(200),fieldnameactual nvarchar(200),fieldtype nvarchar(10))            
insert into #epht(fieldnameexposed,fieldnameactual,fieldtype)            
exec usp_getentityplaceholders @parentid,@entity      
    
/*for debugging    
select * from #epht    
select * from SplitString(@entityplaceholders,',')    
*/    
create table #entitydata(entityid bigint,fieldvalue nvarchar(max), fieldnameexposed nvarchar(200),fieldnameactual     
nvarchar(200),fieldtype nvarchar(10),actiondetails nvarchar(max))            
        
insert into #entitydata(entityid,fieldnameexposed,fieldnameactual,fieldtype,fieldvalue,actiondetails)    
select entityid,fieldnameexposed,fieldnameactual,fieldtype,null,actiondetails from #epht e join @entities t on 1=1    
where '#'+fieldnameexposed+'#' in (select item from SplitString(@entityplaceholders,','))    
    
create table #predefined(id int identity(1,1),fieldnameactual nvarchar(100))    
insert into #predefined(fieldnameactual)    
select distinct fieldnameactual from #entitydata where fieldtype='predefined'    
select @count=count(1) from #predefined    
    
create table #custom(id int identity(1,1),fieldnameactual nvarchar(100))    
insert into #custom(fieldnameactual)    
select distinct fieldnameactual from #entitydata where fieldtype='custom'    
select @c_count=count(1) from #custom    
    
/*for debugging    
select * from #predefined    
select * from #custom    
*/    
    
    
if @entity='enquiry'  and @c_count>0    
begin    
while @c_count>0    
begin    
select @c_id=min(id) from #custom where id>@c_id    
select @fieldname=fieldnameactual from #custom where id=@c_id    
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),'count:',@c_count,', fieldname:',@fieldname,', id:',@c_id)    
update e set fieldvalue=case when @entity+'.'+c.fieldname=e.fieldnameactual then isnull(cast(c.fieldvalue as nvarchar(max)),'') 
when @entity+'.calculatedfield.'+l.fieldname=e.fieldnameactual then isnull(cast(l.fieldvalue as nvarchar(max)),'') 
else e.fieldvalue end,    
actiondetails=replace(actiondetails,'#'+@fieldname+'#', isnull(cast(c.fieldvalue as nvarchar(max)),'')) from #entitydata e       
left join             
(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue,c.EnquiryID from customfields(nolock) f           
left join customfieldEnquiryvalue c on c.fieldID=f.field_ID where f.parentid=@parentid and 'enquiry.'+f.fieldname=@fieldname)            
c on  c.EnquiryID=e.entityid 
left join       
(select 'calculatedfield.'+calculatedfield_name fieldname,isnull(cast(f.field_value as nvarchar(max)),'') fieldvalue from calculated_fields f (nolock) 
join calculated_fields_master m (nolock) on f.calculatedfield_id=m.id where isnull(f.parentid,@parentid)=@parentid	
and entity=@entity and entityid=@entityid
)     
l on @entity+'.'+l.fieldname=e.fieldnameactual and e.fieldtype='calculated' 

set @c_count=@c_count-1    
end    
end      

if @entity='lead'   and @c_count>0    
begin    
while @c_count>0    
begin    
select @c_id=min(id) from #custom where id>@c_id    
select @fieldname=fieldnameactual from #custom where id=@c_id    
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),'count:',@c_count,', fieldname:',@fieldname,', id:',@c_id)    
update e set fieldvalue=case when @entity+'.'+c.fieldname=e.fieldnameactual  then isnull(cast(c.fieldvalue as nvarchar(max)),'') 
when @entity+'.calculatedfield.'+l.fieldname=e.fieldnameactual then isnull(cast(l.fieldvalue as nvarchar(max)),'') 
else     
e.fieldvalue end,actiondetails=replace(actiondetails,'#'+@fieldname+'#', isnull(cast(c.fieldvalue as nvarchar(max)),'')) from     
#entitydata e             
left join             
(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue,c.LeadID from customfields(nolock) f           
left join customfieldleadvalue c on c.fieldID=f.field_ID where f.parentid=@parentid and 'lead.'+f.fieldname=@fieldname)            
c on c.leadID=e.entityid 
left join       
	(select 'calculatedfield.'+calculatedfield_name fieldname,isnull(cast(f.field_value as nvarchar(max)),'') fieldvalue from calculated_fields f (nolock)  join calculated_fields_master m (nolock) on f.calculatedfield_id=m.id where isnull(f.parentid,@parentid)=@parentid	and entity=@entity and entityid=@entityid
	)     
	l on @entity+'.'+l.fieldname=e.fieldnameactual and e.fieldtype='calculated' 
	


set @c_count=@c_count-1    
end    
end      
    
--select * from #entitydata    
            
if @entity='lead' and @count>0    
begin  
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entered predefined replace')  
drop table if exists #v_userleads  
select u.* into #v_userleads from v_ul u join #entitydata e on u.ID=e.entityid  
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entering predefined while loop')  
while @count>0    
begin    
set @sql=''    
select @p_id=min(id) from #predefined where id>@p_id    
select @fieldname=cast(replace(fieldnameactual,'lead.','') as nvarchar) from #predefined where id=@p_id    
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),'Predefined: ',@fieldname  )  
select @sql='update e set fieldvalue=case when e.fieldnameactual=''lead.'+@fieldname+''' then '+quotename(@fieldname)+' else e.fieldnameactual end,actiondetails=replace(actiondetails,''#lead.'+@fieldname+'#'','+    
quotename(@fieldname)+ ') from #entitydata e join #v_userleads u on e.entityid=u.id'-- where e.fieldnameactual=''lead.'+@fieldname+''''    
print @sql    
exec sp_executesql @sql    
set @count=@count-1    
end    
end    
else if @entity='enquiry' and @count>0    
begin   
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entered predefined replace')  
  
drop table if exists #v_userenquiry  
select u.* into #v_userenquiry from v_userenquiry u join #entitydata e on u.enquiryID=e.entityid  
  
while @count>0    
begin    
set @sql=''    
select @p_id=min(id) from #predefined where id>@p_id    
select @fieldname=replace(fieldnameactual,'enquiry.','') from #predefined where id=@p_id    
print @fieldname    
select @sql='update e set fieldvalue=case when e.fieldnameactual=''enquiry.'+@fieldname+''' then '+quotename(@fieldname)+' else e.fieldnameactual end,actiondetails=replace(actiondetails,''#enquiry.'+@fieldname+'#'','+    
quotename(@fieldname)+ ') from #entitydata e join #v_userenquiry u on e.entityid=u.enquiryid' --where e.fieldnameactual=''enquiry.'+@fieldname+''''    
print @sql    
exec sp_executesql @sql    
set @count=@count-1    
end    
    
end    
else if @entity='user' and @count>0    
begin  
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entered predefined replace for user')  
drop table if exists #v_userdetails  
select u.* into #v_userdetails from vw_userdetails u join #entitydata e on u.user_ID=e.entityid  
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entering predefined while loop')  
while @count>0    
begin    
set @sql=''    
select @p_id=min(id) from #predefined where id>@p_id    
select @fieldname=cast(replace(fieldnameactual,'user.','') as nvarchar) from #predefined where id=@p_id    
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),'Predefined: ',@fieldname  )  
select @sql='update e set fieldvalue=case when e.fieldnameactual=''user.'+@fieldname+''' then '+quotename(@fieldname)+' else e.fieldnameactual end,actiondetails=replace(actiondetails,''#user.'+@fieldname+'#'','+    
quotename(@fieldname)+ ') from #entitydata e join #v_userdetails u on e.entityid=u.user_id'-- where e.fieldnameactual=''lead.'+@fieldname+''''    
print @sql    
exec sp_executesql @sql    
set @count=@count-1    
end    
end    
else if @entity='partner' and @count>0    
begin  
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entered predefined replace for user')  
drop table if exists #v_partnerdetails  
select u.* into #v_partnerdetails from vw_partnerdetails u join #entitydata e on u.reseller_ID=e.entityid  
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entering predefined while loop')  
while @count>0    
begin    
set @sql=''    
select @p_id=min(id) from #predefined where id>@p_id    
select @fieldname=cast(replace(fieldnameactual,'user.','') as nvarchar) from #predefined where id=@p_id    
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),'Predefined: ',@fieldname  )  
select @sql='update e set fieldvalue=case when e.fieldnameactual=''partner.'+@fieldname+''' then '+quotename(@fieldname)+' else e.fieldnameactual end,actiondetails=replace(actiondetails,''#partner.'+@fieldname+'#'','+    
quotename(@fieldname)+ ') from #entitydata e join #v_partnerdetails u on e.entityid=u.reseller_id'-- where e.fieldnameactual=''lead.'+@fieldname+''''    
print @sql    
exec sp_executesql @sql    
set @count=@count-1    
end    
end    

drop table if exists #epht            
drop table if exists #entitydata_replace            
    
select distinct entityid,actiondetails from #entitydata            
end    
else    
begin    
select entityid,actiondetails from @entities            
    
end    
end 


GO

/* ============================================================
   Procedure: [dbo].[usp_replaceentityplaceholders_bulk_singlecontent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*            
select top 10 * from userenquiry(nolock) where parentid =34594 and enquiryid in (select enquiryid from customfieldEnquiryvalue(nolock))            
order by enquiryid desc            
select top 80 c.fieldname,f.* from customfieldEnquiryvalue(nolock) f join customfields(nolock) c on f.fieldID=c.field_ID where parentid=34594 and enquiryid in (10748289,10697957,10697823) order by recordid desc            
            
declare @entities as entities,@entityplaceholders nvarchar(max)='#enquiry.personname#,#enquiry.DOB#,#enquiry.FamilyHistory#',@bigtemplatetext nvarchar(max)            
=(select replace(eventnotification,'#Activity.description#','Hello #enquiry.personname#, custom field is #enquiry.DOB# and #enquiry.FamilyHistory#') from eventnotification (nolockhinsert into @entities(entity,entityid,actiondetails)            
select top 10000 'enquiry',enquiryid,'Hello #enquiry.personname#, custom field is #enquiry.DOB# and #enquiry.FamilyHistory#' from             
userenquiry(nolock) where parentid =34594 and enquiryid in (select enquiryid from customfieldEnquiryvalue(nolock))            
order by enquiryid desc            
exec [usp_replaceentityplaceholders_bulk] @entities,@entityplaceholders            
*/            
            
CREATE   PROCEDURE [dbo].[usp_replaceentityplaceholders_bulk_singlecontent]                    
@entities as [entities] readonly,@actiondetails nvarchar(max),@entityplaceholders nvarchar(max)            
as                    
begin                
if isnull(@entityplaceholders,'')<>''            
begin            
declare @parentid bigint,@entity nvarchar(50) ,@entityid bigint,@fieldname nvarchar(100),@count int,@sql nvarchar(max),@p_id int=0,            
@c_count int,@c_id int=0            
select top 1 @entity=entity,@entityid=entityid from @entities            
if @entity='lead'                    
select top 1 @parentid=parentid from userleads(nolock) where id=@entityid                    
else                    
select top 1 @parentid=parentid from userenquiry(nolock) where enquiryid=@entityid                    
                    
drop table if exists #epht                    
drop table if exists #entitydata_replace               
drop table if exists #entitydata                
drop table if exists #predefined                
drop table if exists #custom                
            
create table #epht(fieldnameexposed nvarchar(200),fieldnameactual nvarchar(200),fieldtype nvarchar(10))                    
      
      
/*Commented below code and added the usp_getentityplaceholders logic here as it was sometimes returning insert exec error      
insert into #epht(fieldnameexposed,fieldnameactual,fieldtype)                    
exec usp_getentityplaceholders @parentid,@entity              
*/       
      
insert into #epht(fieldnameexposed,fieldnameactual,fieldtype)                    
select * from                    
(                    
select cast(@entity+'.'+name as nvarchar(200)) fieldnameexposed,cast(@entity+'.'+name as nvarchar(200)) fieldnameactual,'predefined' fieldtype from sys.all_columns (nolock)                
where object_id=(select object_id from sys.tables where name=case when @entity='lead' then 'userleads'                     
when @entity='enquiry' then 'userenquiry' when @entity='Entity' then 'TBL_ET_PhysicalAppointment' when @entity='Scoring' then 'tbl_SM_ScoringCondition'  end)                    
and name not in ('id','PhysicalAppointmentId','OutcomesId','GeoEntitySiteId','TaskTypeId','gCalendarId','GeoEntityId','ModifiedOn','ModifiedBy','FollowupDate','LeadImage','temp_id','img_ext','ProfileImgFileName','enquirysource','WhatsAppNoColName',       
 
'LastFollowupCreatedBy','parentid',                
     'IsOpen','IsduplicateEmail','IsduplicateMobile','EnquiryID','isscoreeligible')   and @entity<>'user'                 
union all                    
select cast(@entity+'.'+fieldname as nvarchar(200)) fieldnameexposed,cast(@entity+'.'+fieldname as nvarchar(200)) fieldnameactual,'custom' fieldtype from customfields(nolock) where parentid=@parentid and isActive = 1    and @entity<>'user'                  
union all                    
select cast(@entity+'.calculatedfield.'+calculatedfield_name as nvarchar(200)) fieldnameexposed,cast(@entity+'.calculatedfield.'+calculatedfield_name as nvarchar(200)) fieldnameactual,'calculated' fieldtype   
from calculated_fields_master(nolock) where isnull(parentid,@parentid)=@parentid and applicable_entities like '%'+@entity+'%' and @entity<>'user' 
union all
select cast(@entity+'.'+name as nvarchar(200)) fieldnameexposed,cast(@entity+'.'+name as nvarchar(200)) fieldnameactual,'predefined' fieldtype from sys.all_columns (nolock)          
where object_id=(select object_id from sys.views where name='vw_userdetails') and @entity='user' 



) a                     
            
      
/*for debugging        
select * from #epht            
select * from SplitString(@entityplaceholders,',')            
*/            
create table #entitydata(entityid bigint,fieldvalue nvarchar(max), fieldnameexposed nvarchar(200),fieldnameactual             
nvarchar(200),fieldtype nvarchar(10),actiondetails nvarchar(max))                    
                
insert into #entitydata(entityid,fieldnameexposed,fieldnameactual,fieldtype,fieldvalue,actiondetails)            
select entityid,fieldnameexposed,fieldnameactual,fieldtype,null,@actiondetails from #epht e join @entities t on 1=1            
where '#'+fieldnameexposed+'#' in (select item from SplitString(@entityplaceholders,','))            
            
create table #predefined(id int identity(1,1),fieldnameactual nvarchar(100))            
insert into #predefined(fieldnameactual)            
select distinct fieldnameactual from #entitydata where fieldtype='predefined'            
select @count=count(1) from #predefined            
            
create table #custom(id int identity(1,1),fieldnameactual nvarchar(100))            
insert into #custom(fieldnameactual)            
select distinct fieldnameactual from #entitydata where fieldtype in ('custom','calculated')
select @c_count=count(1) from #custom            
            
/*for debugging            
select * from #predefined            
select * from #custom            
*/            
            
            
if @entity='enquiry'  and @c_count>0            
begin            
while @c_count>0            
begin            
select @c_id=min(id) from #custom where id>@c_id            
select @fieldname=fieldnameactual from #custom where id=@c_id            
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),'count:',@c_count,', fieldname:',@fieldname,', id:',@c_id)            

update e set fieldvalue=case when @entity+'.'+c.fieldname=e.fieldnameactual then isnull(cast(c.fieldvalue as nvarchar(max)),'')   
--when @entity+'.'+l.fieldname=e.fieldnameactual then isnull(cast(l.fieldvalue as nvarchar(max)),'')   
else e.fieldvalue end,            
actiondetails=replace(actiondetails,'#'+@fieldname+'#', isnull(cast(c.fieldvalue as nvarchar(max)),'')) from #entitydata e               
left join                     
(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue,c.EnquiryID from customfields(nolock) f                   
left join customfieldEnquiryvalue c on c.fieldID=f.field_ID where f.parentid=@parentid and 'enquiry.'+f.fieldname=@fieldname
union
--)                    
--c on  c.EnquiryID=e.entityid                  
--left join         
--(
select 'calculatedfield.'+calculatedfield_name fieldname,isnull(cast(f.field_value as nvarchar(max)),'') fieldvalue,entityid from calculated_fields f (nolock)   
join calculated_fields_master m (nolock) on f.calculatedfield_id=m.id where isnull(f.parentid,@parentid)=@parentid    
and entity=@entity and @entity+'.calculatedfield.'+calculatedfield_name=@fieldname
)     
c on  c.EnquiryID=e.entityid                  
--l on l.EntityID=e.entityid   and e.fieldtype='calculated'   
  
set @c_count=@c_count-1            
end            
end              
if @entity='lead'   and @c_count>0            
begin            
while @c_count>0            
begin            
select @c_id=min(id) from #custom where id>@c_id            
select @fieldname=fieldnameactual from #custom where id=@c_id            
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),'count:',@c_count,', fieldname:',@fieldname,', id:',@c_id)            
update e set fieldvalue=case when @entity+'.'+c.fieldname=e.fieldnameactual  then isnull(cast(c.fieldvalue as nvarchar(max)),'')   
--when @entity+'.'+l.fieldname=e.fieldnameactual then isnull(cast(l.fieldvalue as nvarchar(max)),'')   
else             
e.fieldvalue end,actiondetails=replace(actiondetails,'#'+@fieldname+'#', isnull(cast(c.fieldvalue as nvarchar(max)),'')) from             
#entitydata e                     
left join                     
(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue,c.LeadID from customfields(nolock) f                   
left join customfieldleadvalue c on c.fieldID=f.field_ID where f.parentid=@parentid and 'lead.'+f.fieldname=@fieldname
--)                    
--c on c.leadID=e.entityid       
--left join         
--(
union
select 'calculatedfield.'+calculatedfield_name fieldname,isnull(cast(f.field_value as nvarchar(max)),'') fieldvalue,entityid from calculated_fields f (nolock)   
join calculated_fields_master m (nolock) on f.calculatedfield_id=m.id where isnull(f.parentid,@parentid)=@parentid   
and entity=@entity and @entity+'.calculatedfield.'+calculatedfield_name=@fieldname
)       
c on c.leadID=e.entityid       
--l on l.EntityID=e.entityid   and e.fieldtype='calculated'   
  
set @c_count=@c_count-1            
end            
end              
            
--select * from #entitydata            
                    
if @entity='lead' and @count>0            
begin          
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entered predefined replace')          
drop table if exists #v_userleads          
select u.* into #v_userleads from v_ul u join #entitydata e on u.ID=e.entityid      
EXEC tempdb.sys.sp_rename N'#v_userleads.LeadCreatedOn', N'CreatedOn', N'Column';        
      
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entering predefined while loop')          
while @count>0            
begin            
set @sql=''            
select @p_id=min(id) from #predefined where id>@p_id            
select @fieldname=cast(replace(fieldnameactual,'lead.','') as nvarchar) from #predefined where id=@p_id            
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),'Predefined: ',@fieldname  )          
select @sql='update e set fieldvalue=case when e.fieldnameactual=''lead.'+@fieldname+''' 
then isnull(cast('+quotename(@fieldname)+' as nvarchar(max)),'''') else e.fieldnameactual end,actiondetails=replace(actiondetails,''#lead.'+@fieldname+'#'',
isnull(cast('+quotename(@fieldname)+' as nvarchar(max)),'''')) from #entitydata e join #v_userleads u on e.entityid=u.id'-- where e.fieldnameactual=''lead.'+@fieldname+''''            
print @sql            
exec sp_executesql @sql            
set @count=@count-1            
end            
end            
else if @entity='enquiry' and @count>0            
begin           
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entered predefined replace')          
          
drop table if exists #v_userenquiry          
select u.* into #v_userenquiry from v_userenquiry u join #entitydata e on u.enquiryID=e.entityid          
          
while @count>0            
begin            
set @sql=''            
select @p_id=min(id) from #predefined where id>@p_id            
select @fieldname=replace(fieldnameactual,'enquiry.','') from #predefined where id=@p_id            
print @fieldname            
select @sql='update e set fieldvalue=case when e.fieldnameactual=''enquiry.'+@fieldname+''' then isnull(cast('+quotename(@fieldname)+' as nvarchar(max)),'''') 
else e.fieldnameactual end,actiondetails=replace(actiondetails,''#enquiry.'+@fieldname+'#'',
isnull(cast('+quotename(@fieldname)+' as nvarchar(max)),'''')) from #entitydata e join #v_userenquiry u on e.entityid=u.enquiryid' --where e.fieldnameactual=''enquiry.'+@fieldname+''''            
print @sql            
exec sp_executesql @sql            
set @count=@count-1            
end            
            
end  
else if @entity='user' and @count>0            
begin           
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entered predefined replace')          
          
drop table if exists #v_userdetails          
select u.* into #v_userdetails from vw_userdetails u join #entitydata e on u.user_id=e.entityid          
          
while @count>0            
begin            
set @sql=''            
select @p_id=min(id) from #predefined where id>@p_id            
select @fieldname=replace(fieldnameactual,'user.','') from #predefined where id=@p_id            
print @fieldname            
select @sql='update e set fieldvalue=case when e.fieldnameactual=''user.'+@fieldname+''' then isnull(cast('+quotename(@fieldname)+' as nvarchar(max)),'''') 
else e.fieldnameactual end,actiondetails=replace(actiondetails,''#user.'+@fieldname+'#'',
isnull(cast('+quotename(@fieldname)+' as nvarchar(max)),'''')) from #entitydata e join #v_userdetails u on e.entityid=u.user_id' --where e.fieldnameactual=''enquiry.'+@fieldname+''''            
print @sql            
exec sp_executesql @sql            
set @count=@count-1            
end            
            
end            
else if @entity='partner' and @count>0            
begin           
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entered predefined replace')          
          
drop table if exists #v_partnerdetails          
select u.* into #v_partnerdetails from vw_partnerdetails u join #entitydata e on u.reseller_id=e.entityid          
          
while @count>0            
begin            
set @sql=''            
select @p_id=min(id) from #predefined where id>@p_id            
select @fieldname=replace(fieldnameactual,'user.','') from #predefined where id=@p_id            
print @fieldname            
select @sql='update e set fieldvalue=case when e.fieldnameactual=''partner.'+@fieldname+''' then isnull(cast('+quotename(@fieldname)+' as nvarchar(max)),'''') 
else e.fieldnameactual end,actiondetails=replace(actiondetails,''#partner.'+@fieldname+'#'',
isnull(cast('+quotename(@fieldname)+' as nvarchar(max)),'''')) from #entitydata e join #v_partnerdetails u on e.entityid=u.reseller_id' --where e.fieldnameactual=''enquiry.'+@fieldname+''''            
print @sql            
exec sp_executesql @sql            
set @count=@count-1            
end            
            
end            

drop table if exists #epht                    
drop table if exists #entitydata_replace                    
            
select distinct entityid,actiondetails from #entitydata                    
end      else            
begin            
select entityid,@actiondetails actiondetails from @entities                    
            
end            
end 


GO

/* ============================================================
   Procedure: [dbo].[usp_replaceentityplaceholders_bulk_singlecontent_tableinsert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*            
select top 10 * from userenquiry(nolock) where parentid =34594 and enquiryid in (select enquiryid from customfieldEnquiryvalue(nolock))            
order by enquiryid desc            
select top 80 c.fieldname,f.* from customfieldEnquiryvalue(nolock) f join customfields(nolock) c on f.fieldID=c.field_ID where parentid=34594 and enquiryid in (10748289,10697957,10697823) order by recordid desc            
            
declare @entities as entities,@entityplaceholders nvarchar(max)='#enquiry.personname#,#enquiry.DOB#,#enquiry.FamilyHistory#',@bigtemplatetext nvarchar(max)            
=(select replace(eventnotification,'#Activity.description#','Hello #enquiry.personname#, custom field is #enquiry.DOB# and #enquiry.FamilyHistory#') from eventnotification (nolockhinsert into @entities(entity,entityid,actiondetails)            
select top 10000 'enquiry',enquiryid,'Hello #enquiry.personname#, custom field is #enquiry.DOB# and #enquiry.FamilyHistory#' from             
userenquiry(nolock) where parentid =34594 and enquiryid in (select enquiryid from customfieldEnquiryvalue(nolock))            
order by enquiryid desc            
exec [usp_replaceentityplaceholders_bulk] @entities,@entityplaceholders            
*/            
            
CREATE  PROCEDURE [dbo].[usp_replaceentityplaceholders_bulk_singlecontent_tableinsert]                    
@entities as [entities] readonly,@actiondetails nvarchar(max),@entityplaceholders nvarchar(max),@batchid bigint,      
@type varchar(100),@sequenceactionid bigint      
as                    
begin      
      
if 1=1--not exists(select 1 from mass_replaced_content(nolock) where batchid=@batchid and sequenceactionid=@sequenceactionid and type=@type )      
begin      
if isnull(@entityplaceholders,'')<>''            
begin            
declare @parentid bigint,@entity nvarchar(50) ,@entityid bigint,@fieldname nvarchar(100),@count int,@sql nvarchar(max),@p_id int=0,            
@c_count int,@c_id int=0            
select top 1 @entity=entity,@entityid=entityid from @entities            
if @entity='lead'                    
select top 1 @parentid=parentid from userleads(nolock) where id=@entityid                    
else                    
select top 1 @parentid=parentid from userenquiry(nolock) where enquiryid=@entityid                    
                    
drop table if exists #epht                    
drop table if exists #entitydata_replace               
drop table if exists #entitydata                
drop table if exists #predefined                
drop table if exists #custom                
            
create table #epht(fieldnameexposed nvarchar(200),fieldnameactual nvarchar(200),fieldtype nvarchar(10))                    
insert into #epht(fieldnameexposed,fieldnameactual,fieldtype)                    
exec usp_getentityplaceholders @parentid,@entity              
            
/*for debugging            
select * from #epht            
select * from SplitString(@entityplaceholders,',')            
*/            




create table #entitydata(entityid bigint,fieldvalue nvarchar(max), fieldnameexposed nvarchar(200),fieldnameactual             
nvarchar(200),fieldtype nvarchar(10),actiondetails nvarchar(max))                    
                
insert into #entitydata(entityid,fieldnameexposed,fieldnameactual,fieldtype,fieldvalue,actiondetails)            
select entityid,fieldnameexposed,fieldnameactual,fieldtype,null,@actiondetails from #epht e join @entities t on 1=1            
where '#'+fieldnameexposed+'#' in (select item from SplitString(@entityplaceholders,','))            
            
create table #predefined(id int identity(1,1),fieldnameactual nvarchar(100))            
insert into #predefined(fieldnameactual)            
select distinct fieldnameactual from #entitydata where fieldtype='predefined'            
select @count=count(1) from #predefined            
            
create table #custom(id int identity(1,1),fieldnameactual nvarchar(100))            
insert into #custom(fieldnameactual)            
select distinct fieldnameactual from #entitydata where fieldtype in ('custom','calculated')

select @c_count=count(1) from #custom            
          
/*for debugging            
select * from #predefined            
select * from #custom            
*/            
            
            
if @entity='enquiry'  and @c_count>0            
begin            
while @c_count>0            
begin            
select @c_id=min(id) from #custom where id>@c_id            
select @fieldname=fieldnameactual from #custom where id=@c_id            
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),'count:',@c_count,', fieldname:',@fieldname,', id:',@c_id)            
update e set fieldvalue=case when @entity+'.'+c.fieldname=e.fieldnameactual then isnull(cast(c.fieldvalue as nvarchar(max)),'') 
--when @entity+'.calculatedfield.'+l.fieldname=e.fieldnameactual then isnull(cast(l.fieldvalue as nvarchar(max)),'') 
else e.fieldvalue end,            
actiondetails=replace(actiondetails,'#'+@fieldname+'#', isnull(cast(c.fieldvalue as nvarchar(max)),'')) from #entitydata e               
left join                     
(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue,c.EnquiryID from customfields(nolock) f                   
left join customfieldEnquiryvalue c on c.fieldID=f.field_ID where f.parentid=@parentid and 'enquiry.'+f.fieldname=@fieldname
--)                    
--c on  c.EnquiryID=e.entityid  
--left join       
--(
union
select 'calculatedfield.'+calculatedfield_name fieldname,isnull(cast(f.field_value as nvarchar(max)),'') fieldvalue,entityid from calculated_fields f (nolock) 
join calculated_fields_master m (nolock) on f.calculatedfield_id=m.id where isnull(f.parentid,@parentid)=@parentid	
and @entity+'.calculatedfield.'+calculatedfield_name=@fieldname
)  
c on  c.EnquiryID=e.entityid  
--l on  l.entityid=e.entityid



set @c_count=@c_count-1            
end            
end              
if @entity='lead'   and @c_count>0            
begin            
while @c_count>0            
begin            
select @c_id=min(id) from #custom where id>@c_id            
select @fieldname=fieldnameactual from #custom where id=@c_id            
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),'count:',@c_count,', fieldname:',@fieldname,', id:',@c_id)            
update e set fieldvalue=case when @entity+'.'+c.fieldname=e.fieldnameactual  then isnull(cast(c.fieldvalue as nvarchar(max)),'') 
--when @entity+'.calculatedfield.'+l.fieldname=e.fieldnameactual then isnull(cast(l.fieldvalue as nvarchar(max)),'') 
else             
e.fieldvalue end,actiondetails=replace(actiondetails,'#'+@fieldname+'#', isnull(cast(c.fieldvalue as nvarchar(max)),'')) from             
#entitydata e                     
left join                     
(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue,c.LeadID from customfields(nolock) f                   
left join customfieldleadvalue c on c.fieldID=f.field_ID where f.parentid=@parentid and 'lead.'+f.fieldname=@fieldname
union
--)                    
--c on c.leadID=e.entityid 
--left join       
--(
select 'calculatedfield.'+calculatedfield_name fieldname,isnull(cast(f.field_value as nvarchar(max)),'') fieldvalue,entityid from calculated_fields f (nolock) 
join calculated_fields_master m (nolock) on f.calculatedfield_id=m.id where isnull(f.parentid,@parentid)=@parentid	
and @entity+'.calculatedfield.'+calculatedfield_name=@fieldname
)
c on c.leadID=e.entityid 
--l on  l.entityid=e.entityid

set @c_count=@c_count-1            
end            
end              
            
--select * from #entitydata            
                    
if @entity='lead' and @count>0            
begin          
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entered predefined replace')          
drop table if exists #v_userleads          
select u.* into #v_userleads from v_ul u join #entitydata e on u.ID=e.entityid
EXEC tempdb.sys.sp_rename N'#v_userleads.LeadCreatedOn', N'CreatedOn', N'Column';  
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entering predefined while loop')          
while @count>0            
begin            
set @sql=''            
select @p_id=min(id) from #predefined where id>@p_id        
--select * from #entitydata      
--select * from #v_userleads      
  
select @fieldname=cast(replace(fieldnameactual,'lead.','') as nvarchar) from #predefined where id=@p_id            
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),'Predefined: ',@fieldname  )          
select @sql='update e set fieldvalue=case when e.fieldnameactual=''lead.'+@fieldname+''' then isnull(cast('+quotename(@fieldname)+' as nvarchar),'''') else isnull(cast(e.fieldnameactual as nvarchar),'''') end,actiondetails=replace(actiondetails,''#lead.'+@fieldname+'#'',isnull(cast('+quotename(@fieldname)+' as nvarchar),'''')) from #entitydata e join #v_userleads u on e.entityid=u.id'-- where e.fieldnameactual=''lead.'+@fieldname+''''            
print @sql            
exec sp_executesql @sql            
set @count=@count-1            
end            
end            
else if @entity='enquiry' and @count>0            
begin           
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entered predefined replace')          
          
drop table if exists #v_userenquiry          
select u.* into #v_userenquiry from v_userenquiry u join #entitydata e on u.enquiryID=e.entityid          
          
while @count>0            
begin            
set @sql=''            
select @p_id=min(id) from #predefined where id>@p_id            
select @fieldname=replace(fieldnameactual,'enquiry.','') from #predefined where id=@p_id            
print @fieldname            
select @sql='update e set fieldvalue=case when e.fieldnameactual=''enquiry.'+@fieldname+''' then isnull(cast('+quotename(@fieldname)+' as nvarchar),'''') else cast(e.fieldnameactual as nvarchar) end,actiondetails=replace(actiondetails,''#enquiry.'+@fieldname+'#'',isnull(cast('+quotename(@fieldname)+' as nvarchar),'''')) from #entitydata e join #v_userenquiry u on e.entityid=u.enquiryid' --where e.fieldnameactual=''enquiry.'+@fieldname+''''            
print @sql            
exec sp_executesql @sql            
set @count=@count-1            
end            
            
end            
else if @entity='user' and @count>0            
begin           
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entered predefined replace')          
          
drop table if exists #v_userdetails
select u.* into #v_userdetails from vw_userdetails u(nolock) join #entitydata e on u.user_ID=e.entityid          
          
while @count>0            
begin            
set @sql=''            
select @p_id=min(id) from #predefined where id>@p_id            
select @fieldname=replace(fieldnameactual,'user.','') from #predefined where id=@p_id            
print @fieldname            
select @sql='update e set fieldvalue=case when e.fieldnameactual=''user.'+@fieldname+''' then isnull(cast('+quotename(@fieldname)+' as nvarchar(max),'''') else cast(e.fieldnameactual 
as nvarchar(max)) end,actiondetails=replace(actiondetails,''#user.'+@fieldname+'#'',isnull(cast('+quotename(@fieldname)+' as nvarchar(max)),'''')) from #entitydata e join 
#vw_userdetails u on e.entityid=u.user_id' --where e.fieldnameactual=''enquiry.'+@fieldname+''''            
print @sql            
exec sp_executesql @sql            
set @count=@count-1            
end            
            
end            
else if @entity='partner' and @count>0            
begin           
print concat('Date: ',FORMAT(getdate(), 'dd-MM-yyyy hh:m:ss'),' Entered predefined replace')          
          
drop table if exists #v_partnerdetails
select u.* into #v_partnerdetails from vw_userdetails u(nolock) join #entitydata e on u.reseller_ID=e.entityid          
          
while @count>0            
begin            
set @sql=''            
select @p_id=min(id) from #predefined where id>@p_id            
select @fieldname=replace(fieldnameactual,'partner.','') from #predefined where id=@p_id            
print @fieldname            
select @sql='update e set fieldvalue=case when e.fieldnameactual=''partner.'+@fieldname+''' then isnull(cast('+quotename(@fieldname)+' as nvarchar(max),'''') else cast(e.fieldnameactual 
as nvarchar(max)) end,actiondetails=replace(actiondetails,''#partner.'+@fieldname+'#'',isnull(cast('+quotename(@fieldname)+' as nvarchar(max)),'''')) from #entitydata e join 
#vw_partnerdetails u on e.entityid=u.reseller_id' --where e.fieldnameactual=''enquiry.'+@fieldname+''''            
print @sql            
exec sp_executesql @sql            
set @count=@count-1            
end            
            
end            

drop table if exists #epht                    
drop table if exists #entitydata_replace         
  
print 'inserting into mass_replaced_content'  
--select distinct @entity,entityid,@actiondetails,@batchid,@entityplaceholders,actiondetails,@sequenceactionid,@type from #entitydata    
  
begin try  
insert into mass_replaced_content(entity,entityid,actiondetails,batchid,entityplaceholders,replacedcontent,sequenceactionid,type)      
select distinct @entity,entityid,@actiondetails,@batchid,@entityplaceholders,actiondetails,@sequenceactionid,@type from #entitydata     
end try  
begin catch  
exec usp_inserterrorinfo  
end catch  
  
end            
--else            
--begin          
      
--insert into mass_replaced_content(entity,entityid,actiondetails,batchid,entityplaceholders,replacedcontent)      
--select @entity,entityid,@actiondetails,@batchid,@entityplaceholders,@actiondetails from @entities                    
            
--end      
end      
end 


GO

/* ============================================================
   Procedure: [dbo].[usp_replaceentityplaceholders_withoutentityname]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_replaceentityplaceholders_withoutentityname]          
@entityid bigint,@entity nvarchar(50),@string nvarchar(max) ,@strvalue nvarchar(max) OUTPUT         
as          
begin          
/*      
--declare @entity nvarchar(50)='enquiry',@entityid bigint=4524534,@string nvarchar(max)='Dear, your details are: enquiry.CampaignName: #enquiry.CampaignName# enquiry.City: #enquiry.City# enquiry.CompanyName: #enquiry.CompanyName#         
--enquiry.Country: #enquiry.Country# enquiry.CountryCode: #enquiry.CountryCode# enquiry.CountryCode1: #enquiry.CountryCode1# enquiry.CountryCode2: #enquiry.CountryCode2# enquiry.CreatedBy: #enquiry.CreatedBy# enquiry.CreatedDate: #enquiry.CreatedDate# enq
  
    
uiry.EmailID:         
--#enquiry.EmailID# enquiry.EmailID1: #enquiry.EmailID1# enquiry.EmailID2: #enquiry.EmailID2# enquiry.EnquiryID: #enquiry.EnquiryID# enquiry.InitialRemarks: #enquiry.InitialRemarks# enquiry.IsOpen: #enquiry.IsOpen# enquiry.LeadNo: #enquiry.LeadNo# enquiry
  
    
.MediumName:         
--#enquiry.MediumName# enquiry.MobileNo: #enquiry.MobileNo# enquiry.MobileNo1: #enquiry.MobileNo1# enquiry.MobileNo2: #enquiry.MobileNo2# enquiry.OfficeAddress: #enquiry.OfficeAddress# enquiry.PersonName: #enquiry.PersonName# enquiry.PinCode:         
--#enquiry.PinCode# enquiry.ResidentialAddress: #enquiry.ResidentialAddress# enquiry.SourceName: #enquiry.SourceName# enquiry.State: #enquiry.State# enquiry.test_date: #enquiry.test_date# enquiry.Load_KW: #enquiry.Load_KW# enquiry.Day_Load: #enquiry.Day_L
  
    
oad#         
--enquiry.Night_load: #enquiry.Night_load# enquiry.meter_type_description: #enquiry.meter_type_description# enquiry.Noof_DG: #enquiry.Noof_DG# enquiry.DG_Total_Capacity_KVA: #enquiry.DG_Total_Capacity_KVA# enquiry.Total_Roof_Area_Sq_Mtr: #enquiry.Total_Ro
  
    
of_Area_Sq_Mtr#        
-- enquiry.Roof_Type_Description: #enquiry.Roof_Type_Description# enquiry.Structure_Type: #enquiry.Structure_Type# enquiry.Distance_Mtrs: #enquiry.Distance_Mtrs# enquiry.Subsidy_Entitled: #enquiry.Subsidy_Entitled# enquiry.Solar_Capacity_KW:         
-- #enquiry.Solar_Capacity_KW# enquiry.Entry_Date: #enquiry.Entry_Date# enquiry.Modify_Date: #enquiry.Modify_Date# enquiry.Survey_No: #enquiry.Survey_No# enquiry.Segment_Description: #enquiry.Segment_Description# enquiry.id_: #enquiry.id_# enquiry.Contact
  
    
_1:         
-- #enquiry.Contact_1# enquiry.Contact_2: #enquiry.Contact_2# enquiry.Contact3: #enquiry.Contact3#'          
*/      
declare @parentid bigint          
if @entity='lead'          
select @parentid=parentid from userleads(nolock) where id=@entityid          
else          
select @parentid=parentid from userenquiry(nolock) where enquiryid=@entityid          
          
drop table if exists #epht          
drop table if exists #entitydata_replace          
create table #epht(fieldnameexposed nvarchar(200),fieldnameactual nvarchar(200),fieldtype nvarchar(10))          
insert into #epht(fieldnameexposed,fieldnameactual,fieldtype)          
exec [usp_getentityplaceholders_withouentityname] @parentid,@entity          
          
alter table #epht add fieldvalue nvarchar(max)          
      
if @entity='enquiry'    
begin    
update e set fieldvalue=coalesce(cast(c.fieldvalue as nvarchar(max)),cast(l.fieldvalue as nvarchar(max)),'') from #epht e           
left join           
 (select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue from customfields(nolock) f         
 left join customfieldEnquiryvalue c on c.fieldID=f.field_ID and c.EnquiryID=@entityid  where f.parentid=@parentid)         
 c on @entity+'.'+c.fieldname=e.fieldnameactual and e.fieldtype='custom'     
    left join           
 (select 'calculatedfield.'+calculatedfield_name fieldname,isnull(cast(f.field_value as nvarchar(max)),'') fieldvalue from calculated_fields f (nolock)  join calculated_fields_master m   
(nolock) on f.calculatedfield_id=m.id where isnull(f.parentid,@parentid)=@parentid and entity=@entity and entityid=@entityid    
 )         
 l on @entity+'.'+l.fieldname=e.fieldnameactual and e.fieldtype='calculated'     
     
/*    
join           
(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue from customfields(nolock) f         
left join customfieldEnquiryvalue c on c.fieldID=f.field_ID and c.EnquiryID=@entityid  where f.parentid=@parentid)          
c on @entity+'.'+c.fieldname=e.fieldnameactual and e.fieldtype='custom'          
*/    
end    
if @entity='lead'    
begin    
update e set fieldvalue=coalesce(cast(c.fieldvalue as nvarchar(max)),cast(l.fieldvalue as nvarchar(max)),'') from #epht e           
left join           
 (select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue from customfields(nolock) f         
 left join customfieldleadvalue c on c.fieldID=f.field_ID and c.LeadID=@entityid  where f.parentid=@parentid)          
 c on @entity+'.'+c.fieldname=e.fieldnameactual and e.fieldtype='custom'      
 left join           
 (select 'calculatedfield.'+calculatedfield_name fieldname,isnull(cast(f.field_value as nvarchar(max)),'') fieldvalue from calculated_fields f (nolock)  join calculated_fields_master m   
(nolock) on f.calculatedfield_id=m.id where isnull(f.parentid,@parentid)=@parentid and entity=@entity and entityid=@entityid    
 )         
 l on @entity+'.'+l.fieldname=e.fieldnameactual and e.fieldtype='calculated'     
     
/*    
join           
(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue from customfields(nolock) f         
left join customfieldleadvalue c on c.fieldID=f.field_ID and c.LeadID=@entityid  where f.parentid=@parentid)          
c on @entity+'.'+c.fieldname=e.fieldnameactual and e.fieldtype='custom'          
*/    
    
end    
          
declare @entitydata nvarchar(max)          
if @entity='lead'          
set @entitydata=(select * from (select u.*,isnull(str(d.mobile),'') as AssignedToPhone,isnull(d.email,'') as AssignedToEmail    
,dbo.fn_getentityfullname('user',d.user_id) as AssignedToName    
from Userleads u(nolock) left join user_detail d(nolock) on d.user_id=u.assignedto where u.id=@entityid) a for json auto,INCLUDE_NULL_VALUES)          
else  if @entity='enquiry'        
set @entitydata=(select * from (select u.*,isnull(str(d.mobile),'') as CreatedByPhone,isnull(d.email,'') as CreatedByEmail    
,dbo.fn_getentityfullname('user',d.user_id) as CreatedByName    
from UserEnquiry u(nolock)  left join user_detail d(nolock) on d.user_id=u.CreatedBy  where enquiryid=@entityid) a for json auto,INCLUDE_NULL_VALUES)          
    else  if @entity='user'        
set @entitydata=(select * from (select u.* from vw_userdetails u(nolock) where user_id=@entityid) a for json auto,INCLUDE_NULL_VALUES)          
   else  if @entity='partner'        
set @entitydata=(select * from (select u.* from vw_partnerdetails u(nolock) where reseller_id=@entityid) a for json auto,INCLUDE_NULL_VALUES)          
     
          
create table #entitydata_replace(k nvarchar(200),v nvarchar(max),t nvarchar(20))          
insert into #entitydata_replace          
select * from openjson(replace(replace(@entitydata,'[',''),']',''))         
        
update  #entitydata_replace set v='' where v is null        
          
update ed set v=case           
when k in ('createdby','assignedto','LastFollowupcreatedby') then dbo.fn_getuserlogins(v)           
when k='sourcename' then s.name          
when k='mediumname' then m.name          
when k='campaignname' then c.name   
when k='Followupstatus' then f.FollowupStatus  
else v end          
from #entitydata_replace ed           
left join UserSourceSettings s on ed.v=cast(s.SourceID as nvarchar)          
left join UsermediumSettings m on ed.v=cast(m.MediumID as nvarchar)          
left join UserCampaignSettings c on ed.v=cast(c.CampaignID as nvarchar)   
left join FollowUp_Status f on ed.v=cast(f.id as nvarchar)  
           
           
update e set fieldvalue=cast(isnull(c.v,'') as nvarchar(max)) from #epht e           
join #entitydata_replace c on @entity+'.'+c.k=e.fieldnameactual          
        
declare @tbl as recursivereplace        
     
insert into @tbl(displaykey,[value])        
select fieldnameexposed,fieldvalue from #epht        
        
        
select @Strvalue=dbo.fn_recursivereplace(@tbl,@string) --as Strvalue        
        
          
--;WITH TranslationTable            
--AS (            
--    SELECT FindValue = '#' + fieldnameexposed + '#' ,ReplaceValue = fieldvalue,ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS rn            
--    FROM #epht where fieldnameexposed is not null            
--    )            
----Recursive CTE to loop through the TranslationTable and replace FindValue with ReplaceValue            
--,RecursiveCte as            
--(            
--SELECT cast(@string as nvarchar(max)) AS StrValue            
--    ,(            
--        SELECT count(*)            
--        FROM TranslationTable            
--        ) AS cnt            
            
--UNION ALL            
            
--SELECT cast(replace(StrValue, tt.FindValue, tt.Replacevalue) as nvarchar(max))            
--    ,cnt - 1            
--FROM RecursiveCte            
--JOIN TranslationTable tt            
--    ON tt.rn = cnt )            
            
--SELECT StrValue ,cnt FROM RecursiveCte where cnt = 0            
          
          
drop table if exists #epht          
drop table if exists #entitydata_replace          
          
end 


GO

/* ============================================================
   Procedure: [dbo].[usp_replaceplaceholders]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROCEDURE [dbo].[usp_replaceplaceholders] --890087, 'lead','sms sent on #SMS Sent Date# with message #SMS text# , short #SMS text substring# through campaign #SMS Campaign Name#',1  
(@activityid bigint,@entity nvarchar(20),@string nvarchar(max),@eventid int,@strvalue nvarchar(max) OUTPUT )  
as  
begin  
select @string=REPLACE(@string,'#bot_slot.','#')

declare @ad nvarchar(max),@event_type varchar(50) ,@bot_id bigint,@call_logid bigint
select @event_type =eventtype from activitymaster(nolock) where id=@eventid
if @entity='lead'
begin
select @call_logid=refids from tbl_LeadEventHistory(nolock) where Historyid=@activityid and reftables='calllog'
end
else if @entity='enquiry'
begin
select @call_logid=refids from tbl_enquiryEventHistory(nolock) where Historyid=@activityid and reftables='calllog'
end

if @call_logid is not null
begin
select @bot_id=bot_id from CallLog(nolock) where id=@call_logid
end  
  
drop table if exists #activitydata_r  
create table #activitydata_r(entitydata nvarchar(max),activitydata nvarchar(max),userdata nvarchar(max))  
insert into #activitydata_r(entitydata,activitydata,userdata)  
exec usp_getmetadata_foractivity @activityid,@entity  
  
select top 1 @ad=activitydata from #activitydata_r  
select @ad=replace(replace(@ad,'[',''),']','')  
  
drop table if exists #activitydata_withevent_r  
create table #activitydata_withevent_r(eventid int,keyv nvarchar(max),valuev nvarchar(max),typev nvarchar(max),displaykey nvarchar(100))  
  
insert into #activitydata_withevent_r(keyv,valuev,typev)  
select [key],[value],[type] from  
(  
select [key],isnull([value],'') value,[type] from openjson(@ad)  
) A  
  
update #activitydata_withevent_r set displaykey=exposedname,valuev=case when e.datatype='datetime' and valuev<>''
then try_convert(nvarchar,try_cast(replace(a.valuev,'T',' ') as smalldatetime),100) else valuev end
from #activitydata_withevent_r a join eventplaceholders e on a.keyv=e.alias  
and e.eventid=@eventid and e.isexposed=1  

if @event_type='AI Bot'
begin
update #activitydata_withevent_r set displaykey=label,valuev=case when isnull(json_value(detailsjson,'$.datatype'),'string')='date' and valuev<>''        
then try_convert(nvarchar,try_cast(replace(a.valuev,'T',' ') as smalldatetime),100) else valuev end        
from #activitydata_withevent_r a join tbl_ai_goalslots e on a.keyv=e.name          
and e.GoalId=@bot_id 
end

declare @tbl as recursivereplace

insert into @tbl(displaykey,[value])
select displaykey,valuev from #activitydata_withevent_r


select @strvalue=dbo.fn_recursivereplace(@tbl,@string) --as Strvalue

  
--;WITH TranslationTable  
--AS (  
--    SELECT FindValue = '#' + displaykey + '#' ,ReplaceValue = valuev,ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS rn  
--    FROM #activitydata_withevent_r where displaykey is not null  
--    )  
----Recursive CTE to loop through the TranslationTable and replace FindValue with ReplaceValue  
--,RecursiveCte as  
--(  
--SELECT cast(@string as nvarchar(max)) AS StrValue  
--    ,(  
--        SELECT count(*)  
--        FROM TranslationTable  
--        ) AS cnt  
  
--UNION ALL  
  
--SELECT cast(replace(StrValue, tt.FindValue, tt.Replacevalue) as nvarchar(max))  
--    ,cnt - 1  
--FROM RecursiveCte  
--JOIN TranslationTable tt  
--    ON tt.rn = cnt )  
  
--SELECT StrValue ,cnt FROM RecursiveCte where cnt = 0  
  
end  
  
  
  
  
  
  
  
  
  
  
  
  

  


GO

/* ============================================================
   Procedure: [dbo].[usp_replaceplaceholders_withrules]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*    
declare @strvalue nvarchar(max) ,@st int     
exec [usp_replaceplaceholders_withrules] 2235,null,52288558,'enquiry','',10,@strvalue output,@st output    
select @strvalue,@st    
*/    
CREATE  PROCEDURE [dbo].[usp_replaceplaceholders_withrules] --2235,null,52288558,'enquiry','',115,'','',115,    
    
--1255,null,--890087, 'lead','sms sent on #SMS Sent Date# with message #SMS text# , short #SMS text substring# through campaign #SMS Campaign Name#',1          
(@trigid bigint,@campid bigint,@activityid bigint,@entity nvarchar(20),@string nvarchar(max),      
@eventid int,@strvalue nvarchar(max) OUTPUT,@st int output )          
as          
begin      
      
if not exists (select 1 from triggeredcampaignrules(nolock) where triggeredcampaignid=@trigid and isnull(campaignid,0)=      
isnull(@campid,isnull(campaignid,0))      
and isactive=1 and isdeleted=0)            
begin      
set @st=1      
print 'St: '+cast(@st as nvarchar) +', Next: Selectstatus'    
GOTO SELECTSTATUS      
end       
      
      
declare @ad nvarchar(max)  ,@event_type varchar(50) ,@bot_id bigint,@call_logid bigint
select @event_type =eventtype from activitymaster(nolock) where id=@eventid
if @entity='lead'
begin
select @call_logid=refids from tbl_LeadEventHistory(nolock) where Historyid=@activityid and reftables='calllog'
end
else if @entity='enquiry'
begin
select @call_logid=refids from tbl_enquiryEventHistory(nolock) where Historyid=@activityid and reftables='calllog'
end

if @call_logid is not null
begin
select @bot_id=bot_id from CallLog(nolock) where id=@call_logid
end

drop table if exists #activitydata_rp          
create table #activitydata_rp(entitydata nvarchar(max),activitydata nvarchar(max),userdata nvarchar(max))          
insert into #activitydata_rp(entitydata,activitydata,userdata)          
exec usp_getmetadata_foractivity @activityid,@entity          
          
select top 1 @ad=activitydata from #activitydata_rp          
select @ad=replace(replace(@ad,'[',''),']','')          
          
drop table if exists #activitydata_withevent_rp          
create table #activitydata_withevent_rp(eventid int,keyv nvarchar(max),valuev nvarchar(max),typev nvarchar(max),displaykey nvarchar(100))          
          
insert into #activitydata_withevent_rp(eventid,keyv,valuev,typev)          
select @eventid,[key],[value],[type] from          
(          
select [key],isnull([value],'') value,[type] from openjson(@ad)          
) A          
      
--select * from #activitydata_withevent_rp 

if 1=1 --@event_type<>'Botactivities'
begin
update #activitydata_withevent_rp set displaykey=exposedname,valuev=case when e.datatype='datetime' and valuev<>''        
then try_convert(nvarchar,try_cast(replace(a.valuev,'T',' ') as smalldatetime),100) else valuev end        
from #activitydata_withevent_rp a join eventplaceholders e on a.keyv=e.alias          
and e.eventid=@eventid and e.isexposed=1 
end
if @event_type='AI Bot'
begin
update #activitydata_withevent_rp set displaykey=label,valuev=case when isnull(json_value(detailsjson,'$.datatype'),'string')='date' and valuev<>''        
then try_convert(nvarchar,try_cast(replace(a.valuev,'T',' ') as smalldatetime),100) else valuev end        
from #activitydata_withevent_rp a join tbl_ai_goalslots e on a.keyv=e.name          
and e.GoalId=@bot_id 
end
        
declare @tbl_r as recursivereplace        
        
insert into @tbl_r(displaykey,[value])        
select displaykey,valuev from #activitydata_withevent_rp        
      
--select * from #activitydata_withevent_rp          
--select * from @tbl_r      
if exists (select 1 from triggeredcampaignrules(nolock) where triggeredcampaignid=@trigid and isnull(campaignid,0)=      
isnull(@campid,isnull(campaignid,0))      
and isactive=1 and isdeleted=0)                
begin                
drop table if exists #rules_rp                
drop table if exists #ruleconditions_rp                
select * into #rules_rp from triggeredcampaignrules(nolock) where triggeredcampaignid=@trigid and isnull(campaignid,0)=      
isnull(@campid,isnull(campaignid,0))      
      
and isactive=1 and isdeleted=0      
--select * from #rules_rp      
select t.* into #ruleconditions_rp from triggeredcampaignruleconditions(nolock) t join #rules_rp r on t.ruleid=r.id        
where t.isactive=1 and t.isdeleted=0       
--select * from #ruleconditions_rp      
declare @c int=(select count(1) from #rules_rp),@ruleid bigint=0,@condition nvarchar(10),@match int=1,@rc int,@rcid int=0,      
@field nvarchar(100),@value nvarchar(max),@matchtype nvarchar(20),@rulename nvarchar(100) ,@message nvarchar(max),      
@value2 nvarchar(max)      
,@fieldtype nvarchar(20)      
print 'Total Rules: '+cast(@c as nvarchar)  

if @c=0              
begin              
set @match=1              
end              
while @c>0                
begin                
select @match=1,@rcid=0      
select @ruleid=min(id) from #rules_rp where Id>@ruleid                
select @condition=conditiontype,@rulename=RuleName from #rules_rp where id=@ruleid  and isactive=1 and isdeleted=0     
print 'Conditiontype: '+@condition+', rulename: '+@rulename      
if @condition='And'                
begin                
print 'Testing rule: '+@rulename            
select @rc=count(1) from #ruleconditions_rp where ruleid=@ruleid                
if @rc=0              
begin              
set @match=1              
print @rulename + ' has no condition. Hence, no need to match'              
end              
else              
begin              
print 'Ruleid: '+cast(@ruleid as nvarchar)+ ',Rulename: '+@rulename + ' Conditions to match: '+cast(@rc as nvarchar)              
end              
print '@rc : '+ cast(@rc as nvarchar)+ ', @match: '+ cast(@match as nvarchar)         

while @rc>0 and @match=1                
begin                
select @rcid=min(id) from #ruleconditions_rp where ruleid=@ruleid and Id>@rcid                
select @field=fieldname,@value=valuematch,@matchtype=matchtype from #ruleconditions_rp where Id=@rcid  

if 1=1--@event_type<>'botactivities'
begin
select @fieldtype=datatype from eventplaceholders(nolock) where exposedname=@field and eventid=@eventid  
end
if @event_type='AI Bot'
begin
select @fieldtype=isnull(json_value(detailsjson,'$.datatype'),'string') from tbl_ai_goalslots(nolock) where label=replace(@field,'bot_slot.','') and goalid=@bot_id  
end

if @fieldtype='nvarchar'  
begin  
select @fieldtype='string'  
end  
else if @fieldtype in ('int','bigint','number') or @fieldtype like 'numeric%'  
begin  
select @fieldtype='numeric'  
end  
else if @fieldtype in ('date','datetime') 
begin  
select @fieldtype='datetime'  
end

select @fieldtype=isnull(@fieldtype,'string')      
if @matchtype='Between'      
begin      
select @value2=replace(value,'and ','') from dbo.fn_split(@value,' and ') where position=2      
select @value=replace(value,'and ','') from dbo.fn_split(@value,' and ') where position=1      
end      

--print concat('message: ',(select top 1 [value] from @tbl_r where rtrim(ltrim(displaykey))=ltrim(rtrim(@field))      ))
--select [value] from @tbl_r where rtrim(ltrim(displaykey))=ltrim(rtrim(@field))
select top 1 @message=[value] from @tbl_r where rtrim(ltrim(displaykey)) = ltrim(rtrim(@field))

print concat('Matching rule condition for field: ',isnull(@field,'@field null') ,' with fieldtype: ',isnull(@fieldtype,'@fieldtype null'), ' . Condition ',
isnull(@message,'@message null') ,' ',isnull(@matchtype,'@matchtype null'), ' ' ,isnull(@value,'@value null'))               

select @match=case      
when @matchtype in ('equals','=','Equal To') and @fieldtype='string' and @message=cast(@value as nvarchar(max)) then 1  
when @matchtype in ('equals','=','Equal To') and @fieldtype='numeric' and try_parse(@message as numeric(18,4))=  
try_parse(@value as numeric(18,4)) then 1  
when @matchtype in ('equals','=','Equal To') and @fieldtype='datetime'  and try_parse(@message as datetime)=  
try_parse(@value as datetime) then 1   
when @matchtype in ('Doesn''t Equal To','Does not equal','Not equal to','<>') and @fieldtype='string' and @message<>cast(@value as nvarchar(max)) then 1  
when @matchtype in ('Doesn''t Equal To','Does not equal','Not equal to','<>') and @fieldtype='numeric' and try_parse(@message as numeric(18,4))<>  
try_parse(@value as numeric(18,4)) then 1  
when @matchtype in ('Doesn''t Equal To','Does not equal','Not equal to','<>') and @fieldtype='datetime'  and try_parse(@message as datetime)<>  
try_parse(@value as datetime) then 1    
when @matchtype in ('contain','contains','like') and @message like '%'+cast(@value as nvarchar(max))+'%' then 1                
when @matchtype in ('Does''nt contain','DoesNotContain','Does not contain','not like') and @message not like '%'+cast(@value as nvarchar(max))+'%' then 1                
when @matchtype in ('Starts with','Begin With') and @message like cast(@value as nvarchar(max))+'%' then 1                
when @matchtype in ('Doesn''t Begin With','Does not start with') and @message not like cast(@value as nvarchar(max))+'%' then 1                
when @matchtype in ('Ends with','EndWith', 'End with') and @message like '%'+cast(@value as nvarchar(max)) then 1                
when @matchtype in ('Doesn''t End With','Does not end with') and @message not like '%'+cast(@value as nvarchar(max)) then 1      
when @matchtype in ('>=','Greater than equals to')  and @fieldtype='numeric' and try_parse(@message as numeric(18,4))>=  
try_parse(@value as numeric(18,4)) then 1  
when @matchtype in ('>=','Greater than equals to') and @fieldtype='datetime'  and try_parse(@message as datetime)>=  
try_parse(@value as datetime) then 1        
when @matchtype in ('<=','Less than equals to')  and @fieldtype='numeric' and try_parse(@message as numeric(18,4))<=  
try_parse(@value as numeric(18,4)) then 1  
when @matchtype in ('<=','Less than equals to') and @fieldtype='datetime'  and try_parse(@message as datetime)<=  
try_parse(@value as datetime) then 1            
when @matchtype in ('>','Greater than') and  @fieldtype='numeric' and try_parse(@message as numeric(18,4))>  
try_parse(@value as numeric(18,4)) then 1  
when @matchtype in ('>','Greater than') and @fieldtype='datetime'  and try_parse(@message as datetime)>  
try_parse(@value as datetime) then 1        
when @matchtype in ('<','Less than')  and @fieldtype='numeric' and try_parse(@message as numeric(18,4))<  
try_parse(@value as numeric(18,4)) then 1  
when @matchtype in ('<','Less than') and @fieldtype='datetime'  and try_parse(@message as datetime)<  
try_parse(@value as datetime) then 1        
when @matchtype in ('Between') and @fieldtype='numeric' and try_parse(@message as numeric(18,4)) between try_parse(@value as numeric(18,4))  
and try_parse(@value2 as numeric(18,4)) then 1   
when @matchtype in ('Between') and @fieldtype='datetime' and try_parse(@message as datetime) between try_parse(@value as datetime)  
and try_parse(@value2 as datetime) then 1       
else 0 end              

print concat('Match: ',@match)          

print concat('Rule condition for field: ',@field , '. Condition "',@message ,'" ',@matchtype, ' "' ,@value+ '"',case when @match=0 then ' does not match'  else ' matches' end)              
      
select @rc=@rc-1                 
end                
end                
else if @condition='Or'                
begin        
print 'Testing rule: '+@rulename              
select @rc=count(1) from #ruleconditions_rp where ruleid=@ruleid      
select @rcid=0

if @rc=0              
begin              
set @match=1              
print 'Ruleid: '+cast(@ruleid as nvarchar)+ ',Rulename: '+@rulename + ' has no condition. Hence, no need to match'              
end       
print 'Ruleid: '+cast(@ruleid as nvarchar)+ ',Rulename: '+@rulename + ' Conditions(Any) to match: '+cast(@rc as nvarchar)              
print '@rc : '+ cast(@rc as nvarchar)+ ', @match: '+ cast(@match as nvarchar)         
while @rc>0                
begin                
select @rcid=min(id) from #ruleconditions_rp where Id>@rcid and ruleid=@ruleid               
select @field=fieldname,@value=valuematch,@matchtype=matchtype from #ruleconditions_rp where Id=@rcid                
if 1=1--@event_type<>'botactivities'
begin
select @fieldtype=datatype from eventplaceholders(nolock) where exposedname=@field and eventid=@eventid  
end
if @event_type='AI Bot' and @fieldtype is null
begin
select @fieldtype=isnull(json_value(detailsjson,'$.datatype'),'string') from tbl_ai_goalslots(nolock) where label=replace(@field,'bot_slot.','') and goalid=@bot_id  
end

if @fieldtype='nvarchar'  
begin  
select @fieldtype='string'  
end  
else if @fieldtype in ('int','bigint','number') or @fieldtype like 'numeric%'  
begin  
select @fieldtype='numeric'  
end  
else if @fieldtype in ('date','datetime') 
begin  
select @fieldtype='datetime'  
end

select @fieldtype=isnull(@fieldtype,'string')      
if @matchtype='Between'      
begin      
select @value2=replace(value,'and ','') from dbo.fn_split(@value,' and ') where position=2      
select @value=replace(value,'and ','') from dbo.fn_split(@value,' and ') where position=1      
end      
      
      
select @message=[value] from @tbl_r where displaykey=@field      
      
print 'Matching rule condition for field: '+@field + ' with fieldtype: '+@fieldtype+ '. Condition '+@message +' '+@matchtype+ ' ' +@value               
/*      
select @match=case when @matchtype in ('equals','=') and @message=@value then 1        
when @matchtype='Does not equal' and @message <> @value then 1                 
when @matchtype='contains' and @message like '%'+@value+'%' then 1                
when @matchtype in ('Does not contain','DoesNotContain') and @message not like '%'+@value+'%' then 1                
when @matchtype='Starts with' and @message like @value+'%' then 1                
when @matchtype='Does not start with' and @message not like @value+'%' then 1                
when @matchtype in ('Ends with','EndWith') and @message like '%'+@value then 1                
when @matchtype='Does not end with' and @message not like '%'+@value then 1                
else 0 end      
*/ 
SELECT @match =      
CASE 
    WHEN @matchtype IN ('equals', '=', 'Equal To') 
         AND (   (@fieldtype = 'string' AND @message = @value)
              OR (@fieldtype = 'numeric' AND TRY_PARSE(@message AS NUMERIC(18, 2)) = TRY_PARSE(@value AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' AND TRY_PARSE(@message AS DATETIME) = TRY_PARSE(@value AS DATETIME))
             ) THEN 1     
    WHEN @matchtype IN ('Doesn''t Equal To', 'Does not equal', 'Not equal to', '<>') 
         AND (   (@fieldtype = 'string' AND @message <> @value)
              OR (@fieldtype = 'numeric' AND TRY_PARSE(@message AS NUMERIC(18, 2)) <> TRY_PARSE(@value AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' AND TRY_PARSE(@message AS DATETIME) <> TRY_PARSE(@value AS DATETIME))
             ) THEN 1                 
    WHEN @matchtype IN ('contain', 'contains','like') AND ltrim(rtrim(lower(@message))) LIKE '%' + ltrim(rtrim(lower(@value))) + '%' THEN 1                
    WHEN @matchtype IN ('Does''nt contain', 'DoesNotContain', 'Does not contain') AND @message NOT LIKE '%' + @value + '%' THEN 1                
    WHEN @matchtype IN ('Starts with', 'Begin With') AND @message LIKE @value + '%' THEN 1                
    WHEN @matchtype IN ('Doesn''t Begin With', 'Does not start with') AND @message NOT LIKE @value + '%' THEN 1                
    WHEN @matchtype IN ('Ends with', 'EndWith', 'End with') AND @message LIKE '%' + @value THEN 1                
    WHEN @matchtype IN ('Doesn''t End With', 'Does not end with') AND @message NOT LIKE '%' + @value THEN 1      
    WHEN @matchtype IN ('>=', 'Greater than equals to') 
         AND (   (@fieldtype = 'numeric' AND TRY_PARSE(@message AS NUMERIC(18, 2)) >= TRY_PARSE(@value AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' AND TRY_PARSE(@message AS DATETIME) >= TRY_PARSE(@value AS DATETIME))
             ) THEN 1      
    WHEN @matchtype IN ('<=', 'Less than equals to') 
         AND (   (@fieldtype = 'numeric' AND TRY_PARSE(@message AS NUMERIC(18, 2)) <= TRY_PARSE(@value AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' AND TRY_PARSE(@message AS DATETIME) <= TRY_PARSE(@value AS DATETIME))
             ) THEN 1      
    WHEN @matchtype IN ('>', 'Greater than') 
         AND (   (@fieldtype = 'numeric' AND TRY_PARSE(@message AS NUMERIC(18, 2)) > TRY_PARSE(@value AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' AND TRY_PARSE(@message AS DATETIME) > TRY_PARSE(@value AS DATETIME))
             ) THEN 1      
    WHEN @matchtype IN ('<', 'Less than') 
         AND (   (@fieldtype = 'numeric' AND TRY_PARSE(@message AS NUMERIC(18, 2)) < TRY_PARSE(@value AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' AND TRY_PARSE(@message AS DATETIME) < TRY_PARSE(@value AS DATETIME))
             ) THEN 1      
    WHEN @matchtype IN ('Between') 
         AND (   (@fieldtype = 'numeric' 
                      AND TRY_PARSE(@message AS NUMERIC(18, 2)) BETWEEN TRY_PARSE(@value AS NUMERIC(18, 2)) 
                                                               AND TRY_PARSE(@value2 AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' 
                      AND TRY_PARSE(@message AS DATETIME) BETWEEN TRY_PARSE(@value AS DATETIME) 
                                                               AND TRY_PARSE(@value2 AS DATETIME))
             ) THEN 1      
    ELSE 0 
END;

SELECT @match =      
CASE WHEN @matchtype IN ('contain', 'contains') AND ltrim(rtrim(lower(@message))) LIKE '%' + ltrim(rtrim(lower(@value))) + '%' THEN 1  
else @match end 
print @match          
print 'Rule condition for field:'+@field + '. Condition '+@message +' '+@matchtype+ ' ' +@value      
+ case when @match=0 then ' does not match'  else ' matches' end              
--print @rulename + ' ' + @ctype + case when @match=1 then ' condition matches' else ' condition does not match' end              
select @rc=case when @match=1 then 0 else @rc-1 end                 
end                
end            
          
print 'Ruleid: '+cast(@ruleid as nvarchar)+ ',Rulename: '+@rulename +case when @match=0 then ' does not match' else ' matches' end              
select @c=case when @match=1 then 0 else @c-1 end           
print '@C: '+cast(@c as nvarchar)+' @match: '+cast(@match as nvarchar)          
end                
end        
else      
begin      
select @match=1      
end      
      
select @st=case when @match=1 then 1 else 0 end      
print 'st: '+cast(@st as nvarchar)      
--if @st=1      
--select @strvalue=dbo.fn_recursivereplace(@tbl_r,@string) --as Strvalue        
      
--print 'st: '+cast(@st as nvarchar)      
SELECTSTATUS:      
print 'Select status'    
     
select @st=isnull(@st,0),@strvalue=isnull(@strvalue,'')      
--print 'st: '+cast(@st as nvarchar)+' strvalue:'+@strvalue      
      
        
--;WITH TranslationTable          
--AS (          
--    SELECT FindValue = '#' + displaykey + '#' ,ReplaceValue = valuev,ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS rn          
--    FROM #activitydata_withevent_rp where displaykey is not null          
--    )          
----Recursive CTE to loop through the TranslationTable and replace FindValue with ReplaceValue          
--,RecursiveCte as          
--(          
--SELECT cast(@string as nvarchar(max)) AS StrValue          
--    ,(          
--        SELECT count(*)          
--        FROM TranslationTable          
--        ) AS cnt          
          
--UNION ALL          
          
--SELECT cast(replace(StrValue, tt.FindValue, tt.Replacevalue) as nvarchar(max))          
--    ,cnt - 1          
--FROM RecursiveCte          
--JOIN TranslationTable tt          
--    ON tt.rn = cnt )          
          
--SELECT StrValue ,cnt FROM RecursiveCte where cnt = 0          
          
end          
          
          
          
          
          
          
          
          
          
          
          


GO

