insert into @tbl_r(displaykey,[value])        
select displaykey,valuev from #activitydata_withevent_rp        
      
--select * from @tbl_r      
if exists (select 1 from triggeredcampaignrules(nolock) where triggeredcampaignid=@trigid and isnull(campaignid,0)=      
isnull(@campid,isnull(campaignid,0))      
and isactive=1 and isdeleted=0)                
begin                
drop table if exists #rules_rp                
drop table if exists #ruleconditions_rp                
select * into #rules_rp from triggeredcampaignrules(nolock) where triggeredcampaignid=@trigid and isnull(campaignid,0)=      
isnull(@campid,isnull(campaignid,0))      
      
and isactive=1 and isdeleted=0      
--select * from #rules_rp      
select t.* into #ruleconditions_rp from triggeredcampaignruleconditions(nolock) t join #rules_rp r on t.ruleid=r.id        
where t.isactive=1 and t.isdeleted=0       
--select * from #ruleconditions_rp      
declare @c int=(select count(1) from #rules_rp),@ruleid bigint=0,@condition nvarchar(10),@match int=1,@rc int,@rcid int=0,      
@field nvarchar(100),@value nvarchar(max),@matchtype nvarchar(20),@rulename nvarchar(100) ,@message nvarchar(max),      
@value2 nvarchar(max)      
,@fieldtype nvarchar(20)      
print 'Total Rules: '+cast(@c as nvarchar)      
if @c=0              
begin              
set @match=1              
end              
while @c>0                
begin                
select @match=1,@rcid=0      
select @ruleid=min(id) from #rules_rp where Id>@ruleid                
select @condition=conditiontype,@rulename=RuleName from #rules_rp where id=@ruleid  and isactive=1 and isdeleted=0     
print 'Conditiontype: '+@condition+', rulename: '+@rulename      
if @condition='And'                
begin                
print 'Testing rule: '+@rulename            select @rc=count(1) from #ruleconditions_rp where ruleid=@ruleid                
if @rc=0              
begin              
set @match=1              
print @rulename + ' has no condition. Hence, no need to match'              
end              
else              
begin              
print 'Ruleid: '+cast(@ruleid as nvarchar)+ ',Rulename: '+@rulename + ' Conditions to match: '+cast(@rc as nvarchar)              
end              
print '@rc : '+ cast(@rc as nvarchar)+ ', @match: '+ cast(@match as nvarchar)         
while @rc>0 and @match=1                
begin                
select @rcid=min(id) from #ruleconditions_rp where ruleid=@ruleid and Id>@rcid                
select @field=fieldname,@value=valuematch,@matchtype=matchtype from #ruleconditions_rp where Id=@rcid         
select @fieldtype=datatype from eventplaceholders(nolock) where exposedname=@field and eventid=@eventid   
if @fieldtype='nvarchar'  
begin  
select @fieldtype='string'  
end  
else if @fieldtype in ('int','bigint') or @fieldtype like 'numeric%'  
begin  
select @fieldtype='numeric'  
end  
select @fieldtype=isnull(@fieldtype,'string')      
if @matchtype='Between'      
begin      
select @value2=replace(value,'and ','') from dbo.fn_split(@value,' and ') where position=2      
select @value=replace(value,'and ','') from dbo.fn_split(@value,' and ') where position=1      
end      
select @message=[value] from @tbl_r where displaykey=@field      
print 'Matching rule condition for field: '+@field + ' with fieldtype: '+@fieldtype+ ' . Condition '+@message +' '+@matchtype+ ' ' +@value               
select @match=case      
when @matchtype in ('equals','=','Equal To') and @fieldtype='string' and @message=cast(@value as nvarchar(max)) then 1  
when @matchtype in ('equals','=','Equal To') and @fieldtype='numeric' and try_parse(@message as numeric(18,4))=  
try_parse(@value as numeric(18,4)) then 1  
when @matchtype in ('equals','=','Equal To') and @fieldtype='datetime'  and try_parse(@message as datetime)=  
try_parse(@value as datetime) then 1   
when @matchtype in ('Doesn''t Equal To','Does not equal','Not equal to','<>') and @fieldtype='string' and @message<>cast(@value as nvarchar(max)) then 1  
when @matchtype in ('Doesn''t Equal To','Does not equal','Not equal to','<>') and @fieldtype='numeric' and try_parse(@message as numeric(18,4))<>  
try_parse(@value as numeric(18,4)) then 1  
when @matchtype in ('Doesn''t Equal To','Does not equal','Not equal to','<>') and @fieldtype='datetime'  and try_parse(@message as datetime)<>  
try_parse(@value as datetime) then 1    
when @matchtype in ('contain','contains','like') and @message like '%'+cast(@value as nvarchar(max))+'%' then 1                
when @matchtype in ('Does''nt contain','DoesNotContain','Does not contain','not like') and @message not like '%'+cast(@value as nvarchar(max))+'%' then 1                
when @matchtype in ('Starts with','Begin With') and @message like cast(@value as nvarchar(max))+'%' then 1                
when @matchtype in ('Doesn''t Begin With','Does not start with') and @message not like cast(@value as nvarchar(max))+'%' then 1                
when @matchtype in ('Ends with','EndWith', 'End with') and @message like '%'+cast(@value as nvarchar(max)) then 1                
when @matchtype in ('Doesn''t End With','Does not end with') and @message not like '%'+cast(@value as nvarchar(max)) then 1      
when @matchtype in ('>=','Greater than equals to')  and @fieldtype='numeric' and try_parse(@message as numeric(18,4))>=  
try_parse(@value as numeric(18,4)) then 1  
when @matchtype in ('>=','Greater than equals to') and @fieldtype='datetime'  and try_parse(@message as datetime)>=  
try_parse(@value as datetime) then 1        
when @matchtype in ('<=','Less than equals to')  and @fieldtype='numeric' and try_parse(@message as numeric(18,4))<=  
try_parse(@value as numeric(18,4)) then 1  
when @matchtype in ('<=','Less than equals to') and @fieldtype='datetime'  and try_parse(@message as datetime)<=  
try_parse(@value as datetime) then 1            
when @matchtype in ('>','Greater than') and  @fieldtype='numeric' and try_parse(@message as numeric(18,4))>  
try_parse(@value as numeric(18,4)) then 1  
when @matchtype in ('>','Greater than') and @fieldtype='datetime'  and try_parse(@message as datetime)>  
try_parse(@value as datetime) then 1        
when @matchtype in ('<','Less than')  and @fieldtype='numeric' and try_parse(@message as numeric(18,4))<  
try_parse(@value as numeric(18,4)) then 1  
when @matchtype in ('<','Less than') and @fieldtype='datetime'  and try_parse(@message as datetime)<  
try_parse(@value as datetime) then 1        
when @matchtype in ('Between') and @fieldtype='numeric' and try_parse(@message as numeric(18,4)) between try_parse(@value as numeric(18,4))  
and try_parse(@value2 as numeric(18,4)) then 1   
when @matchtype in ('Between') and @fieldtype='datetime' and try_parse(@message as datetime) between try_parse(@value as datetime)  
and try_parse(@value2 as datetime) then 1       
else 0 end              
print @match          
print 'Rule condition for field'+@field + '. Condition "'+@message +'" '+@matchtype+ ' "' +@value+ '"'      
+case when @match=0 then ' does not match'  else ' matches' end              
      
select @rc=@rc-1                 
end                
end                
else if @condition='Or'                
begin        
print 'Testing rule: '+@rulename              
select @rc=count(1) from #ruleconditions_rp where ruleid=@ruleid      
select @rcid=0

if @rc=0              
begin              
set @match=1              
print 'Ruleid: '+cast(@ruleid as nvarchar)+ ',Rulename: '+@rulename + ' has no condition. Hence, no need to match'              
end       
print 'Ruleid: '+cast(@ruleid as nvarchar)+ ',Rulename: '+@rulename + ' Conditions(Any) to match: '+cast(@rc as nvarchar)              
print '@rc : '+ cast(@rc as nvarchar)+ ', @match: '+ cast(@match as nvarchar)         
while @rc>0                
begin                
select @rcid=min(id) from #ruleconditions_rp where Id>@rcid and ruleid=@ruleid               
select @field=fieldname,@value=valuematch,@matchtype=matchtype from #ruleconditions_rp where Id=@rcid                
select @fieldtype=datatype from eventplaceholders(nolock) where exposedname=@field and eventid=@eventid      
if @fieldtype='nvarchar'  
begin  
select @fieldtype='string'  
end  

select @fieldtype=isnull(@fieldtype,'string')      
if @matchtype='Between'      
begin      
select @value2=replace(value,'and ','') from dbo.fn_split(@value,' and ') where position=2      
select @value=replace(value,'and ','') from dbo.fn_split(@value,' and ') where position=1      
end      
      
      
select @message=[value] from @tbl_r where displaykey=@field      
      
print 'Matching rule condition for field: '+@field + ' with fieldtype: '+@fieldtype+ '. Condition '+@message +' '+@matchtype+ ' ' +@value               
/*      
select @match=case when @matchtype in ('equals','=') and @message=@value then 1        
when @matchtype='Does not equal' and @message <> @value then 1                 
when @matchtype='contains' and @message like '%'+@value+'%' then 1                
when @matchtype in ('Does not contain','DoesNotContain') and @message not like '%'+@value+'%' then 1                
when @matchtype='Starts with' and @message like @value+'%' then 1                
when @matchtype='Does not start with' and @message not like @value+'%' then 1                
when @matchtype in ('Ends with','EndWith') and @message like '%'+@value then 1                
when @matchtype='Does not end with' and @message not like '%'+@value then 1                
else 0 end      
*/ 
SELECT @match =      
CASE 
    WHEN @matchtype IN ('equals', '=', 'Equal To') 
         AND (   (@fieldtype = 'string' AND @message = @value)
              OR (@fieldtype = 'numeric' AND TRY_PARSE(@message AS NUMERIC(18, 2)) = TRY_PARSE(@value AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' AND TRY_PARSE(@message AS DATETIME) = TRY_PARSE(@value AS DATETIME))
             ) THEN 1     
    WHEN @matchtype IN ('Doesn''t Equal To', 'Does not equal', 'Not equal to', '<>') 
         AND (   (@fieldtype = 'string' AND @message <> @value)
              OR (@fieldtype = 'numeric' AND TRY_PARSE(@message AS NUMERIC(18, 2)) <> TRY_PARSE(@value AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' AND TRY_PARSE(@message AS DATETIME) <> TRY_PARSE(@value AS DATETIME))
             ) THEN 1                 
    WHEN @matchtype IN ('contain', 'contains','like') AND ltrim(rtrim(lower(@message))) LIKE '%' + ltrim(rtrim(lower(@value))) + '%' THEN 1                
    WHEN @matchtype IN ('Does''nt contain', 'DoesNotContain', 'Does not contain') AND @message NOT LIKE '%' + @value + '%' THEN 1                
    WHEN @matchtype IN ('Starts with', 'Begin With') AND @message LIKE @value + '%' THEN 1                
    WHEN @matchtype IN ('Doesn''t Begin With', 'Does not start with') AND @message NOT LIKE @value + '%' THEN 1                
    WHEN @matchtype IN ('Ends with', 'EndWith', 'End with') AND @message LIKE '%' + @value THEN 1                
    WHEN @matchtype IN ('Doesn''t End With', 'Does not end with') AND @message NOT LIKE '%' + @value THEN 1      
    WHEN @matchtype IN ('>=', 'Greater than equals to') 
         AND (   (@fieldtype = 'numeric' AND TRY_PARSE(@message AS NUMERIC(18, 2)) >= TRY_PARSE(@value AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' AND TRY_PARSE(@message AS DATETIME) >= TRY_PARSE(@value AS DATETIME))
             ) THEN 1      
    WHEN @matchtype IN ('<=', 'Less than equals to') 
         AND (   (@fieldtype = 'numeric' AND TRY_PARSE(@message AS NUMERIC(18, 2)) <= TRY_PARSE(@value AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' AND TRY_PARSE(@message AS DATETIME) <= TRY_PARSE(@value AS DATETIME))
             ) THEN 1      
    WHEN @matchtype IN ('>', 'Greater than') 
         AND (   (@fieldtype = 'numeric' AND TRY_PARSE(@message AS NUMERIC(18, 2)) > TRY_PARSE(@value AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' AND TRY_PARSE(@message AS DATETIME) > TRY_PARSE(@value AS DATETIME))
             ) THEN 1      
    WHEN @matchtype IN ('<', 'Less than') 
         AND (   (@fieldtype = 'numeric' AND TRY_PARSE(@message AS NUMERIC(18, 2)) < TRY_PARSE(@value AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' AND TRY_PARSE(@message AS DATETIME) < TRY_PARSE(@value AS DATETIME))
             ) THEN 1      
    WHEN @matchtype IN ('Between') 
         AND (   (@fieldtype = 'numeric' 
                      AND TRY_PARSE(@message AS NUMERIC(18, 2)) BETWEEN TRY_PARSE(@value AS NUMERIC(18, 2)) 
                                                               AND TRY_PARSE(@value2 AS NUMERIC(18, 2)))
              OR (@fieldtype = 'datetime' 
                      AND TRY_PARSE(@message AS DATETIME) BETWEEN TRY_PARSE(@value AS DATETIME) 
                                                               AND TRY_PARSE(@value2 AS DATETIME))
             ) THEN 1      
    ELSE 0 
END;

SELECT @match =      
CASE WHEN @matchtype IN ('contain', 'contains') AND ltrim(rtrim(lower(@message))) LIKE '%' + ltrim(rtrim(lower(@value))) + '%' THEN 1  
else @match end 
print @match          
print 'Rule condition for field:'+@field + '. Condition '+@message +' '+@matchtype+ ' ' +@value      
+ case when @match=0 then ' does not match'  else ' matches' end              
--print @rulename + ' ' + @ctype + case when @match=1 then ' condition matches' else ' condition does not match' end              
select @rc=case when @match=1 then 0 else @rc-1 end                 
end                
end            
          
print 'Ruleid: '+cast(@ruleid as nvarchar)+ ',Rulename: '+@rulename +case when @match=0 then ' does not match' else ' matches' end              
select @c=case when @match=1 then 0 else @c-1 end           
print '@C: '+cast(@c as nvarchar)+' @match: '+cast(@match as nvarchar)          
end                
end        
else      
begin      
select @match=1      
end      
      
select @st=case when @match=1 then 1 else 0 end      
print 'st: '+cast(@st as nvarchar)      
--if @st=1      
--select @strvalue=dbo.fn_recursivereplace(@tbl_r,@string) --as Strvalue        
      
--print 'st: '+cast(@st as nvarchar)      
SELECTSTATUS:      
print 'Select status'    
     
select @st=isnull(@st,0),@strvalue=isnull(@strvalue,'')      
--print 'st: '+cast(@st as nvarchar)+' strvalue:'+@strvalue      
      
        
--;WITH TranslationTable          
--AS (          
--    SELECT FindValue = '#' + displaykey + '#' ,ReplaceValue = valuev,ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS rn          
--    FROM #activitydata_withevent_rp where displaykey is not null          
