   Procedure: [dbo].[usp_replacetablename]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  /****************************************************************************                                  
SP_NAME        : usp_replacetablename                                                     
AUTHOR         : AJAY SINGH                                  
CREATED ON     : 30/06/2012 04:30 PM                                                      
LOCATION       :                                    
SP DESCRIPTION : THIS SP IS USED TO replace and drop table name                                               
****************************************************************************/    
 CREATE   PROCEDURE usp_replacetablename --'azq20120706'   
 @fristname nvarchar(20)   
 --@secondname nvarchar(20)  
 as   
 begin  
 
 declare @query varchar(50)  
  set @query=''; 
  begin tran
   
 set  @query = 'drop TABLE DndDirectory'  
 if(exists(select 'x' FROM sys.tables where name ='DndDirectory') and @fristname<>'DndDirectory')  
 begin  
   exec(@query)  
   exec sp_RENAME @fristname,'DndDirectory' 
   end
   else
   begin
      exec sp_RENAME @fristname,'DndDirectory' 
   end
    
    if(@@error=0)
    begin
    commit tran
    select 'Replace Successfully'  
    end
    else
    begin
    rollback tran
    select 'Record Not Replace'  
    end
     
  end 


