CREATE   PROCEDURE [dbo].[usp_reportissuevisibile]  
@url nvarchar(500),@userid bigint  
as  
begin  
declare @visible int=0  
if exists(select 1 from reseller_detail where domain=@url and user_id=@userid and USER_ID in (select USER_ID from user_Detail where TYPE=1))  
begin  
Declare @Immediatereseller bigint=(select r.user_id from reseller_detail r join user_detail  
u on r.Reseller_ID=u.M_ID where u.USER_ID=@userid and u.Type=1)  
declare @immediateresellerparentid bigint=(select parentid from user_detail where USER_ID=@Immediatereseller)  
if exists(select top 1 1 from serv_user_detail s   
join serv_source_setting_master ss  
on s.ParentId=ss.parentid  
where s.ParentId=@immediateresellerparentid and ss.website=1)  
begin  
set @visible=1  
end  
end  
else if exists(select top 1 r.user_id from reseller_detail r   
join serv_user_detail s   
on r.User_ID=s.ParentId   
join serv_source_setting_master ss  
on s.ParentId=ss.parentid  
where r.Domain =@url and ss.website=1 
and r.USER_ID in (select USER_ID from user_Detail where TYPE=1))  
begin  
set @visible=1  
end  
select @visible  
end   
  
  
  


