/* ============================================================
   Procedure: [dbo].[Usp_RequestMapping]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_RequestMapping (
	@Mobile NVARCHAR(50)
	,@LandLine NVARCHAR(50)
	,@Action NVARCHAR(200)
	,@Remarks NVARCHAR(max)
	,@UserID BIGINT
	,@ParentID BIGINT
	)
AS
BEGIN
	DECLARE @RequestID BIGINT = 0
	DECLARE @activity VARCHAR(MAX)=''

	IF (@Action = 'Requested')
	BEGIN
		UPDATE Cloud_User_Phone
		SET LandLine = @LandLine
			,STATUS = @Action
		WHERE PhoneNo = @Mobile
			AND Parentid = @ParentID

		IF (
				NOT EXISTS (
					SELECT 1
					FROM Cloud_MobileForwardingRequest
					WHERE Mobile = @Mobile
					)
				)
		BEGIN
			INSERT INTO Cloud_MobileForwardingRequest (
				[UserID]
				,[ParentID]
				,[Mobile]
				,[LandLine]
				,[RequestCreatedDate]
				)
			VALUES (
				@UserID
				,@ParentID
				,@Mobile
				,@LandLine
				,getdate()
				)

			SELECT @RequestID = SCOPE_IDENTITY()
		END
		ELSE
		BEGIN
			SELECT TOP 1 @RequestID = isnull(RequestID, 0)
			FROM Cloud_MobileForwardingRequest
			WHERE Mobile = @Mobile

			UPDATE Cloud_MobileForwardingRequest
			SET UserID = @UserID
				,ParentID = @ParentID
				,LandLine = @LandLine
				,RequestCreatedDate = GETDATE()
			WHERE RequestID = @RequestID
		END

		INSERT INTO Cloud_MobileForwardingRequestHistory (
			[RequestID]
			,[LandLine]
			,[Action]
			,[ActionDate]
			,[Remarks]
			,[CreatedBy]
			)
		VALUES (
			@RequestID
			,@LandLine
			,@Action
			,GETDATE()
			,@Remarks
			,@UserID
			)
		SET @activity='Updt_didphn_req'
	END

	IF (@Action = 'CancelledbyUser')
	BEGIN
		UPDATE Cloud_User_Phone
		SET LandLine = ''
			,STATUS = ''
		WHERE PhoneNo = @Mobile
			AND Parentid = @ParentID

		SELECT TOP 1 @RequestID = isnull(RequestID, 0)
		FROM Cloud_MobileForwardingRequest
		WHERE Mobile = @Mobile

		UPDATE Cloud_MobileForwardingRequest
		SET UserID = @UserID
			,ParentID = @ParentID
			,LandLine = @LandLine
		WHERE RequestID = @RequestID

		INSERT INTO Cloud_MobileForwardingRequestHistory (
			[RequestID]
			,[LandLine]
			,[Action]
			,[ActionDate]
			,[Remarks]
			,[CreatedBy]
			)
		VALUES (
			@RequestID
			,@LandLine
			,@Action
			,GETDATE()
			,@Remarks
			,@UserID
			)
		SET @activity='Updt_didphn_can'
	END

	IF (@Action = 'RequestedMappingRemoval')
	BEGIN
		UPDATE Cloud_User_Phone
		SET STATUS = @Action
		WHERE PhoneNo = @Mobile
			AND Parentid = @ParentID

		SELECT TOP 1 @RequestID = isnull(RequestID, 0)
		FROM Cloud_MobileForwardingRequest
		WHERE Mobile = @Mobile

		INSERT INTO Cloud_MobileForwardingRequestHistory (
			[RequestID]
			,[LandLine]
			,[Action]
			,[ActionDate]
			,[Remarks]
			,[CreatedBy]
			)
		VALUES (
			@RequestID
			,@LandLine
			,@Action
			,GETDATE()
			,@Remarks
			,@UserID
			)
			SET @activity='Updt_didphn_rem'
	END

	SELECT 'Record Saved'

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM Cloud_User_Phone
			WHERE Parentid = @ParentID
			AND PhoneNo = @Mobile
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = @activity
		,@ActionType = 'U'
		,@RowJson = @rowJson
		,@Table_name = 'Cloud_User_Phone'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_RequestPayment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_RequestPayment]    
@referid int,
@amountrequested numeric(18,2),
@Mop nvarchar(20)
as    
begin 
declare @paymentdue numeric(18,2)=(select top 1 ISNULL(commissiondueafterpayout,0) from PayoutStatus where Referrerid=@referid order by ID desc),@paymenteligible int=0
if @Mop='neft'
begin
if exists(select 1 from Referrer_Bank_Details where referrerid=@referid and @Mop='Neft') 
begin
set @paymenteligible=1
end
else 
begin
Select 'Please provide your bank details before requesting payment through NEFT or get 20% extra credits by requesting Kit19 credits against payment'  
end
end
else if exists (select 1 from Referrer_Details where isnull(kit19userid,0)<>0 and ID=@referid and @Mop<>'neft')
begin
set @paymenteligible=1
end
else
begin
Select 'Please sign up with Kit19 to cash in your payment as Kit19 credits'
end
if @paymenteligible=1
begin 
if @amountrequested <=@paymentdue
begin
if exists(select 1 from PayoutStatus where TYPE='Payment Requested' and PayoutStatus='Closed')
begin
Select 'We already have a pending payment request from your end, pl wait till the last payment is paid before raising a new request'
end
else
begin
insert into PayoutStatus(Referrerid,CommissionDue,PaymentRequested,CommissionDueAfterPayout,DateCreated,Type,PayoutStatus,ModeOfPayment)
select @referid,@paymentdue,@amountrequested,(@paymentdue-@amountrequested),GETDATE(),'Payment Requested','Open',@Mop
exec usp_UpdateUserActivity @referid,'RequestedPayout',0
/*if @Mop<>'neft'
begin
declare @kit19userid bigint=(select kit19userid from Referrer_Details where ID=@referid)
--Code for crediting kit19 sms goes here
end
else
begin*/
Select 'Payment request submitted, pl wait for 5-6 days to process'
/*end
end*/
end
end
end
end





 


GO

