 +'</p><p> has requested to activate   
tracking feature in his account on '+CAST(getdate() as nvarchar)+'</p></html>',@email='karuna@pelsoftlabs.in',@email2='animesh.shukla@pelsoftlabs.in' from user_detail(nolock) where USER_ID=@parentid    

