/* ============================================================
   Procedure: [dbo].[usp_ReSend_FailedMESSAGES]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[usp_ReSend_FailedMESSAGES]      
(    
  @BatchID bigint,    
  @UserID  bigint    
)    
as    
Begin    
declare @parentsuperresellerid bigint    
select @parentsuperresellerid =parentsuperresellerid from user_detail where USER_ID=@USERID    
select *,len(A.message) as len,case when A.isunicode=0 and len(A.message)<=160  then 1 when A.isunicode=0 and LEN(A.message)>160 then ceiling(LEN(A.message)/cast(153 as FLOat)) when A.IsUniCode=1 and len(A.message)<=70 then 1 else ceiling(LEN(A.message)/cast(67 as float)) end as Credits into #batchtobeprocessed from FailedMessages A where BatchID=@BATCHID    
declare @creditsreqd bigint= (select sum(Credits) from #batchtobeprocessed where batchid=@batchid)    
declare @balancecredits bigint = (select top 1 balance from SuperResellerCredit_Details where USER_ID=@parentsuperresellerid order by Credit_ID desc)    
if (@balancecredits>=@creditsreqd)    
begin    
insert into CloneMessageDeliveryStatus([BatchID],[Mobile],[Message],[MessageStatus],[SenderID],[MessageInsertDate],[ScheduledDate],[ScheduledTime],[SmppID],[U_ID],[IsUniCode],[IsDnd],[IsAirtel],[MobileSubSet],[ValidNo],[IsPrority],[IsAllowDND],[DBType],[campaignid],[Processed],[Hasvirtualcredits],[HasSufficientvirtualcredits],CMDS_CreatedBy)    
SELECT [BatchID],[Mobile],[Message],[MessageStatus],[SenderID],[MessageInsertDate],[ScheduledDate],[ScheduledTime],[SmppID],[U_ID],[IsUniCode],[IsDnd],[IsAirtel],[MobileSubSet],[ValidNo],[IsPrority],[IsAllowDND],[DBType],[campaignid],[Processed],[Hasvirtualcredits],1,@UserID    
FROM failedmessages where BatchID = @BatchID     
delete FROM failedmessages where BatchID = @BatchID    
     
 --declare @m_id bigint    
 --select @m_id= m_id from user_detail where USER_ID=@parentsuperresellerid    
     
 --insert into SuperResellerCredit_Details(M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified)    
 --values(@M_ID,@parentsuperresellerid,@parentsuperresellerid,@creditsreqd,0,(@balancecredits-@creditsreqd),9999,GETDATE(),GETDATE(),GETDATE(),GETDATE(),'shekhar',GETDATE())        
 select 'Success'      
 drop table #batchtobeprocessed      
 end    
 else    
 begin    
 Select 'You don''t have sufficient credits to resend these SMS'    
 end    
 End        
        
  
  
  


GO

/* ============================================================
   Procedure: [dbo].[USP_ResendAirtelMessageTmpToQueue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
/*************************************************  
created by :-raghwendra  
Date :-12072010  
*************************************************/  
CREATE   PROC [dbo].[USP_ResendAirtelMessageTmpToQueue]   -- 'ESME_RINVSRCADR'  
@refError nvarchar(100)    
as    
BEGIN    
BEGIN TRY    
 SELECT SubReference INTO #TemptableMove FROM airtelSubmitDetail  WHERE  IsNull(subreference,'') != '' and          
  Resultcode=@refError and isnull(IsSent,0)=0  AND datediff(d,createddate, getdate()) = 0            
            
 INSERT INTO [Server2].[TestFilterDB].dbo.MessageSource(MessageID,Mobile,[Message],SenderID,SmppID,MessageInsertDate,priority,U_ID,IsUniCode,IsDND,Operator,MessageBatchID,Isallowdnd)            
 SELECT Messageid, Substring(Mobile,3,10) ,[Message],SenderID,1,MessageInsertDate,1, IsNull(U_ID,1),isnull(IsUniCode,0) ,0,IsNull(Operator,'UI'),BatchID,1           
 FROM MessageDeliveryStatusTemp md JOIN  #temptableMove tmp           
 ON md.MessageRefID=tmp.SubReference            
      
insert into MessageDeliveryStatusTemp401Move      
Select * FROM MessageDeliveryStatusTemp md JOIN airtelSubmitDetail  tmp           
 ON md.MessageRefID=tmp.SubReference  WHERE  IsNull(tmp.subreference,'') != ''           
 AND tmp.Resultcode=@refError and isnull(tmp.IsSent,0)=0  AND datediff(d,tmp.createddate, getdate()) = 0         
      
      
 delete md FROM MessageDeliveryStatusTemp md JOIN airtelSubmitDetail  tmp           
 ON md.MessageRefID=tmp.SubReference  WHERE  IsNull(tmp.subreference,'') != ''           
 AND tmp.Resultcode=@refError and isnull(tmp.IsSent,0)=0  AND datediff(d,tmp.createddate, getdate()) = 0         
      
 UPDATE airtelSubmitDetail          
 SET issent=1          
 where Resultcode=@refError and isnull(IsSent,0)=0 AND datediff(d,createddate, getdate()) = 0        
    
END TRY    
BEGIN CATCH    
 EXEC USP_InsertErrorInfo            
END CATCH    
END 




GO

