   Procedure: [dbo].[usp_ResendMessagesFromMessageStopped]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_ResendMessagesFromMessageStopped]  --'128346','MessageSource'                    
@MessageID BIGINT=1,                                                                                              
@AllType varchar(50)                        
as                      
begin                     
declare @tmptable table                      
(                      
                  
MessageSpamID int,                  
Mobile varchar(20),                  
[Message] varchar(2500),                  
SenderID nchar(20),                  
SmppID tinyint,                  
Priority tinyint,                  
U_ID int,                  
MessageID bigint,                  
BatchID bigint,                  
IsDnd bit,                  
IsUniCode int,                  
Operator char(6),      
Isallowdnd tinyint                  
                   
)            
if(@AllType='All')             
Begin                 
insert into @tmptable (BatchID,[Message],Mobile,Priority ,SenderID,SmppID,IsUniCode,U_ID,MessageID, IsDnd,Operator,Isallowdnd)                      
Select top(10000)MessageBatchID,[Message],Mobile,Priority ,SenderID,SmppID,0,U_ID,MessageID, IsDnd,Operator,Isallowdnd from MessageStopped                   
End          
else          
Begin          
insert into @tmptable (BatchID,[Message],Mobile,Priority ,SenderID,SmppID,IsUniCode,U_ID,MessageID, IsDnd,Operator,Isallowdnd)                      
Select top(10000)MessageBatchID,[Message],Mobile,Priority ,SenderID,SmppID,0,U_ID,MessageID, IsDnd,Operator,Isallowdnd from MessageStopped                   
WHERE MessageID=@MessageID                   
End          
--select * from @tmptable                  
-- Insert record in MessageQueue table                  
INSERT  INTO MessageQueue                                    
   (                                    
    BatchID,[Message],Mobile,Priority ,SenderID,SmppID,IsUniCode,U_ID,MessageID, IsDnd,Operator,Isallowdnd                            
   )                    
select BatchID,[Message],Mobile,Priority ,SenderID,SmppID,IsUniCode,U_ID,MessageID, IsDnd,Operator,Isallowdnd                   
from @tmptable   where  Operator !='AD' and Priority=1;                          
        
INSERT  INTO MessageQueue                                    
   (                                    
    BatchID,[Message],Mobile,Priority ,SenderID,SmppID,IsUniCode,U_ID,MessageID, IsDnd,Operator,Isallowdnd                            
   )                    
select BatchID,[Message],Mobile,Priority ,SenderID,SmppID,IsUniCode,U_ID,MessageID, IsDnd,Operator,Isallowdnd                   
from @tmptable   where  Operator !='AD' and Priority=2;                               
             
-- Insert record in MessageQueueAirtel table                  
INSERT  INTO MessageQueueAirtelPri                                      
   (                                      
     BatchID,[Message],Mobile,Priority ,SenderID,SmppID,IsUniCode,U_ID,MessageID, IsDnd,Operator,Isallowdnd                                    
   )                      
select BatchID,[Message],Mobile,Priority ,SenderID,SmppID,IsUniCode,U_ID,MessageID, IsDnd,Operator,Isallowdnd                   
from @tmptable   where  Operator='AD' and (Priority=2 or Priority=1);                                 
--Insert  record  MessageSource                
 INSERT  INTO MessageSource                                      
   (                                      
     MessageBatchID,[Message],Mobile,Priority ,SenderID,SmppID,U_ID,MessageID, IsDnd,Operator,Isallowdnd                                    
   )                      
select BatchID,[Message],Mobile,Priority ,SenderID,SmppID,U_ID,MessageID, IsDnd,Operator,Isallowdnd                   
from @tmptable   where  Operator='AD' or Priority=0;                  
 --Delete record                 
delete MessageStopped from MessageStopped ms inner join @tmptable tmp on ms.MessageID=tmp.MessageID           
End 


GO

