/* ============================================================
   Procedure: [dbo].[usp_ResendMessagesFromSpamByUserID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC[dbo].[usp_ResendMessagesFromSpamByUserID]    --10000,1,'2134212344,' ,'your Login ID Is :ritusss Password Is :22807 URL : www.localhost,' ,'','','websms','','',1      
(           
---- CREATED BY RITU PARN SINGH -----------     
@ResselerID BIGINT=1,                                                                    
@userID INT=1,  -- from bigint 
@BATCHID BIGINT                                                                    
)              
As
BEGIN        
SET NOCOUNT ON      
BEGIN TRY
 
DECLARE @CNTTOP INT         
DECLARE @CNTBOTTOM INT        
SELECT @CNTTOP=CONFIGVALUE from SMSConfigurations where configname='UITopSMSCount'        
SELECT @CNTBOTTOM=CONFIGVALUE from SMSConfigurations where configname='UIBottomSMSCount'        
----------- ACCORDING TO THE USERID---------------------------------------                      

INSERT INTO MessageSource              
 (            
  MessageBatchID,Mobile,[Message],M_ID,U_ID,SenderID,SmppID,ScheduleDate,            
  ScheduleTime,Priority,MessageID           
  )            
 Select @BatchId,Mobile,Message,@ResselerID,U_ID,SenderID,SmppID,ScheduleDate,ScheduleTime,Priority,MessageID from MessageSpam WHERE  U_ID=@userID;     
  
if exists (select Message from MessageSpam where (ScheduleDate='' and ScheduleTime='') or (ScheduleDate is null  and ScheduleTime is null) ) 
begin
----- SEND TOP  messages from start and top  messages from last into messageque tables          
----IF THEY ARE NOT SCHEDUELED ONLY        
  INSERT  INTO MessageQueue            
   (            
     [Message],Mobile,SenderID,SmppID,Priority ,U_ID,MessageID           
   )Select top (@CNTTOP) Message,Mobile            
  ,SenderID,SmppID,0,U_ID,MessageID from MessageSpam 
   where U_ID=@userID and ((ScheduleDate='' and ScheduleTime='')or (ScheduleDate is null  and ScheduleTime is null))
     
  delete top(@CNTTOP) 
  From MessageSpam 
  Where U_ID=@userID   
   
  INSERT  INTO MessageQueue            
   (            
     [Message],Mobile,SenderID,SmppID,Priority ,U_ID,MessageID           
   )Select top (@CNTBOTTOM) Message,Mobile            
  ,SenderID,SmppID,0,U_ID,MessageID from MessageSpam 
   where U_ID=@userID and ((ScheduleDate='' and ScheduleTime='')or (ScheduleDate is null  and ScheduleTime is null))
   order by MessageSpamID desc
    
  ;With DelBottomMessageStorageTemp as  
  (  
   Select top (@CNTBOTTOM) Message,Mobile            
  ,SenderID,SmppID,ScheduleDate,ScheduleTime,Priority,U_ID,MessageID from MessageSpam 
   where U_ID=@userID and ((ScheduleDate='' and ScheduleTime='')or (ScheduleDate is null  and ScheduleTime is null))  order by MessageSpamID desc
  )  
  delete  DelBottomMessageStorageTemp;

-- print 'MSG TO storage Pass'   
   insert into MessageStorage            
   (            
    MessageBatchID,Mobile,[Message],SenderID,SmppID,Priority,U_ID,MessageID           
   )            
   Select @BatchId,Mobile,Message,            
  SenderID,SmppID,Priority,U_ID,MessageID from MessageSpam 
  where U_ID=@userID and ((ScheduleDate='' and ScheduleTime='')or (ScheduleDate is null  and ScheduleTime is null))
 END
delete MessageSpam WHERE  U_ID=@userID   
END TRY
BEGIN CATCH
If @@trancount > 0 
Rollback 
END CATCH       
END






GO

