   Select top (@CNTBOTTOM) Message,Mobile              
  ,SenderID,SmppID,ScheduleDate,ScheduleTime,Priority,U_ID,MessageID from MessageSpam   
   where U_ID=@userID and SenderID=@SenderId and ((ScheduleDate='' and ScheduleTime='')or (ScheduleDate is null  and ScheduleTime is null))  order by MessageSpamID desc  
  )    
  delete  DelBottomMessageStorageTemp;  
  
-- print 'MSG TO storage Pass'     
   insert into MessageStorage              
   (              
    MessageBatchID,Mobile,[Message],SenderID,SmppID,Priority,U_ID,MessageID             
   )              
   Select @BatchId,Mobile,Message,              
  SenderID,SmppID,Priority,U_ID,MessageID from MessageSpam   
  where U_ID=@userID and SenderID=@SenderId and ((ScheduleDate='' and ScheduleTime='')or (ScheduleDate is null  and ScheduleTime is null))  
 END  
delete MessageSpam WHERE  U_ID=@userID and SenderID=@SenderId    
END TRY  
BEGIN CATCH  
If @@trancount > 0   
Rollback   
END CATCH         
END  
  


GO

/* ============================================================
   Procedure: [dbo].[usp_ResendMessagesFromSpamByUserIDSenderIDPriortyOnlyBEQ]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_ResendMessagesFromSpamByUserIDSenderIDPriortyOnlyBEQ]  --10726,8670,'4834291','SALES'                        
@ResselerID BIGINT=1,                                                                                                  
@userID INT=1, -- from bigint                                
@BATCHID BIGINT,                              
@SenderId varchar(30)                              
as             
Begin            
BEGIN TRY            
BEGIN TRANSACTION                                   
                         
begin                         
declare @tmptable table                          
(                          
                      
MessageSpamID int,                      
Mobile char(20),                      
[Message] varchar(2500),                      
SenderID nchar(20),                      
SmppID tinyint,                      
Priority tinyint,                      
U_ID int,                      
MessageID bigint,                      
BatchID bigint,                      
IsDnd bit,                      
IsUniCode int,                      
Operator char(6),              
Isallowdnd tinyint                      
                       
)                          
insert into @tmptable (BatchID,[Message],Mobile,Priority ,SenderID,SmppID,IsUniCode,U_ID,MessageID, IsDnd,Operator,Isallowdnd)                          
Select top(10000)BatchID,[Message],Mobile,Priority ,SenderID,SmppID,0,U_ID,MessageID, IsDnd,Operator,Isallowdnd from MessageSpam                       
WHERE  U_ID=@userID and ltrim(rtrim(SenderID))=@SenderId                       
--select * from @tmptable                      
-- Insert record in MessageQueue table                      
INSERT  INTO MessageQueue                                        
   (                                        
    BatchID,[Message],Mobile,Priority ,SenderID,SmppID,IsUniCode,U_ID,MessageID, IsDnd,Operator,Isallowdnd                                
   )                        
select BatchID,[Message],Mobile,Priority ,SenderID,SmppID,IsUniCode,U_ID,MessageID, IsDnd,Operator,Isallowdnd                       
from @tmptable   where  Operator !='AD' and ( Priority=1 or  Priority=2);                                
-- Insert record in MessageQueueAirtel table                      
INSERT  INTO MessageQueueAirtelPri                                          
   (                                          
     BatchID,[Message],Mobile,Priority ,SenderID,SmppID,IsUniCode,U_ID,MessageID, IsDnd,Operator,Isallowdnd                                        
   )                          
select BatchID,[Message],Mobile,Priority ,SenderID,SmppID,IsUniCode,U_ID,MessageID, IsDnd,Operator,Isallowdnd                       
from @tmptable   where  Operator='AD' and ( Priority=1 or  Priority=2);                                     
--Insert  record  MessageSource                    
 INSERT  INTO MessageSource                                          
   (                                          
     MessageBatchID,[Message],Mobile,Priority ,SenderID,SmppID,U_ID,MessageID, IsDnd,Operator,Isallowdnd         
   )                          
select BatchID,[Message],Mobile,Priority ,SenderID,SmppID,U_ID,MessageID, IsDnd,Operator,Isallowdnd              
from @tmptable   where   Priority=0;                      
 --Delete record                     
delete MessageSpam from MessageSpam ms inner join @tmptable tmp on ms.u_id=tmp.U_ID and ltrim(rtrim(ms.SenderID))=ltrim(rtrim(tmp.SenderID))                      
and ms.Mobile=tmp.Mobile                      
                      
End             
COMMIT TRANSACTION                 
END TRY                    
BEGIN CATCH                      
    ROLLBACK TRANSACTION                      
    RAISERROR('There is problem in this transaction.Please try again..',16,1)                    
END CATCH             
End   
  
  


GO

/* ============================================================
   Procedure: [dbo].[USP_ResendSelectedRecordMessageMoitorePage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/****************************************************************************                                          
SP_Name        : USP_ResendSelectedRecordMessageMoitorePage                                                             
Author         : raghwendra                                       
Created ON     : 12/Feb/2010 01:30 PM                                                
Version        : 1                                          
Alter BY       :                                                  
Alter Date    :                                           
Location       : PELSOFT                                          
SP Description : This SP is Used to UPDATE MESSAGE DELIVERY STATUS IF NOTALLOW                                          
                                                 
****************************************************************************/                                            
CREATE   PROC [dbo].[USP_ResendSelectedRecordMessageMoitorePage]--  '  NIRALA            '                                               
@SENDerID VARCHAR(100)                                                        
AS                                           
SET NOCOUNT ON                                                     
DECLARE @InsertDND NVARCHAR(MAX)                                
DECLARE @InsertDNDPriority NVARCHAR(MAX)                      
DECLARE @InsertDNDPriorityQueue NVARCHAR(MAX)                   
DECLARE @InsertDNDPriorityAirtel NVARCHAR(MAX)                                   
DECLARE @InsertDNDDeleted NVARCHAR(MAX)                                                
DECLARE @sqlDelete NVARCHAR(MAX)                                                    
                                 
                                  
SET @InsertDNDPriority= 'insert into messagesource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                  
IsDND,Operator,MessageBatchID) SELECT MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                  
IsDND,Operator,BatchID FROM MessageMonitor WHERE isdnd=0 and Priority=0 and  ltrim(rtrim(SENDerID)) in '                                                        
SET @InsertDNDPriority=@InsertDNDPriority + '(''' + @SENDerID + ''')'                                  
                                
SET @InsertDNDPriorityQueue= 'insert into MessageQueue(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                    
IsDND,Operator,Isallowdnd,BatchID) SELECT MessageID,Mobile,[Message],SENDerID,1,1,U_ID,IsUniCode,                                                    
IsDND,Operator,Isallowdnd,BatchID FROM MessageMonitor WHERE  Priority=1 and  isdnd=0 and  ltrim(rtrim(SENDerID)) in '  --  and Operator=''UI''                                                        
SET @InsertDNDPriorityQueue=@InsertDNDPriorityQueue + '(''' + @SENDerID + ''')'                                  
                  
                                            
SET @InsertDND= 'insert into MessageDND(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                  
IsDND,Operator,BatchID) SELECT MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                  
IsDND,Operator,BatchID FROM MessageMonitor WHERE isdnd=1 and  ltrim(rtrim(SENDerID)) in '                                                        
SET @InsertDND=@InsertDND + '(''' + @SENDerID + ''')'                                                    
              
update messagedeliverystatus set messagestatus=3 where isdnd=1 and ltrim(rtrim(SENDerID))=@SENDerID          
                                             
SET @sqlDelete='DELETE FROM MessageMonitor WHERE ltrim(rtrim(SENDerID)) in '                                                    
SET @sqlDelete=@sqlDelete + '(''' + @SENDerID + ''')'                                                    
begin try     
begin transaction                                
exec (@InsertDNDPriority)                       
exec (@InsertDNDPriorityQueue)                           
--exec (@InsertDNDPriorityAirtel)                           
--exec(@InsertDNDDeleted)                                               
EXEC(@InsertDND)              
EXEC(@sqlDelete)                     
--print (@InsertDNDPriority)                  
--print (@InsertDNDPriorityQueue)                           
--print (@InsertDNDPriorityAirtel)                             
----print (@InsertDNDDeleted)                   
--print (@InsertDND)                            
--print (@sqlDelete)                            
--select * from MessageMonitor                            
--update top(10) MessageMonitor set senderi    
if @@TRANCOUNT > 0     
commit ;        
end try     
    
begin catch     
if @@TRANCOUNT > 0     
rollback ;       
exec usp_InsertErrorInfo          
     
end catch     
  


