/* ============================================================
   Procedure: [dbo].[USP_ReSendSpamMessage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_ReSendSpamMessage]   -- 10000,1,'919990872284,919990872284,919990872284,919990872284,919990872284,919990872284,919990872284,919990872284,919990872284,919990872284','win *Please do not copy and paste any content from any pages. Plea

(             
--- CREATED BY RITU PARN SINGH -----------             
@ResselerID BIGINT=1,                                                                    
@userID INT=1,                                                                    
@MobNos VARCHAR(max) = '91980000',      
@Message VARCHAR(8000)='RITU4 gbp',            
@SenderId varchar(30) =1234,                                                
@smppID SMALLINT =1,     --tiny int                 
@Priority SMALLINT =2    --tinyint            
)                
As            
SET NOCOUNT ON            
DECLARE  @CNTTOP INT           
DECLARE @CNTBOTTOM INT          
SELECT @CNTTOP=CONFIGVALUE from SMSConfigurations where configname='UITopSMSCount'          
SELECT @CNTBOTTOM=CONFIGVALUE from SMSConfigurations where configname='UIBottomSMSCount'          
Create table  #tmpMain                
(                
MessageBatchID bigint,              
MESSAGEID BIGINT,              
ResselerID int,                
userID int,                
MobileNos varchar(20),                
Messages varchar(8000) ,                
ScheduleDate datetime ,                
ScheduleTime datetime,                
SenderID varchar(40),                
SmppID int,                
Priority int,  
MsgID int identity primary key                
)                
  
  
DECLARE @CntMobileNOs int                                      
 SET  @CntMobileNOs=(select count(*) from [fn_Split] (@MobNos,','))           
 DECLARE @valueAt int                                      
 SET  @valueAt=1                   
  while (@valueAt<=@CntMobileNOs)                   
  Begin             
 DECLARE @mobileNoAt varchar(20)         
 SELECT  @mobileNoAt=value from   [fn_Split](@MobNos,',') where position=@valueAt              
 SET @mobileNoAt='91'+@mobileNoAt      
Declare @ScheduleDate VARCHAR(40)                                                                     
Declare @ScheduleTime VARCHAR(40)                                                            
DECLARE  @batchID int                
exec Usp_GetBatchID1 @batchID out      
DECLARE @MessageID BIGINT              
EXEC USP_GetRandomNumbers @MessageID out  
  
Select @ScheduleDate=ScheduleDate,@ScheduleTime=ScheduleTime  from MessageSpam where U_ID=@userID and Mobile=@MobNos and SenderID=@SenderId and Message=@Message     
INSERT  INTO #tmpMain                
  VALUES (@batchID,@MessageID,@ResselerID,@userID,@mobileNoAt,@Message,@ScheduleDate,@ScheduleTime,@SenderId,@smppID,@Priority)        
  SET  @valueAt=@valueAt+1          
  SET @mobileNoAt=''                
  End                   
-----IF MESSAGE IS NOT DND AND SPAM THEN INSERT INTO SOURCE,STORAGE AND QUE TABLES.-----------              
          
  INSERT INTO MessageSource                
  (              
  MessageID,MessageBatchID,Mobile,[Message],M_ID,U_ID,SenderID,SmppID,ScheduleDate,              
  ScheduleTime,Priority              
  )              
  Select MESSAGEID,MessageBatchID,MobileNos,Messages,              
  ResselerID,userID,SenderID,SmppID,ScheduleDate,ScheduleTime,Priority from #tmpMain              
----- SEND TOP  messages from start and top  messages from last into messageque tables            
----IF THEY ARE NOT SCHEDUELED ONLY          
             
 IF  (@ScheduleDate='' AND  @ScheduleTime='') or (@ScheduleDate is null AND  @ScheduleTime is null)  
  BEGIN         
  select * from #tmpMain  
      INSERT  INTO MessageQueue              
      (              
      MessageID,[Message],Mobile,SenderID,SmppID,Priority,U_ID              
      )              
     Select top (@CNTTOP)MESSAGEID,Messages,MobileNos,SenderID,SmppID,0,userID from #tmpMain              
       
    delete top(@CNTTOP) From #tmpMain   
      INSERT  INTO MessageQueue              
      (              
      MessageID,[Message],Mobile,SenderID,SmppID,Priority,U_ID              
      )              
     Select top (@CNTBOTTOM)MESSAGEID,Messages,MobileNos,SenderID,SmppID,0,userID from #tmpMain  order by MsgID desc   
           
        ;With DelBottomMessageStorageTemp as    
            (    
              Select top (@CNTBOTTOM)MESSAGEID,Messages,MobileNos,SenderID,SmppID,0 as p,userID from #tmpMain  order by MsgID desc   
             )    
         delete  DelBottomMessageStorageTemp;  
   
     ---To Delete message which has been send to the message que and send remains        
     --messages  to the MessageStorageTable              
      insert into MessageStorage              
      (              
      MessageID,MessageBatchID,Mobile,[Message],SenderID,SmppID,Priority,U_ID              
      )              
      SELECT  MessageID,MessageBatchID,MobileNos,Messages,SenderID,SmppID,Priority,userID              
      FROM #tmpMain            
  
--select * from messagequeue  
--select * from messagesource  
--select * from messagestorage  
  
    DROP TABLE #tmpMain                      
    END          
            
            
          


GO

