   Procedure: [dbo].[USP_REVERSECREDIT]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE   PROC [dbo].[USP_REVERSECREDIT]  
(  
@MID BIGINT,  
@UID INT ,  -- frm big int 19-08-2010
@BATCHID INT,
@STATUS TINYINT 
)  
AS  

-- IN CASE OF DISAPPROVED  REVERSE CREDIT OF THE USER----
IF @STATUS=0
BEGIN
		DECLARE @CNTVOICEMESSAGE INT  
		SELECT @CNTVOICEMESSAGE=COUNT(*) FROM TBL_VoiceSmsDetails WHERE M_ID=@MID AND   
		U_ID=@UID AND BatchID=@BATCHID  
		UPDATE tbl_VoiceSmsUsers SET VoiceSmsCredits=VoiceSmsCredits+@CNTVOICEMESSAGE WHERE   
		M_ID=@MID AND U_ID=@UID   
END





