/* ============================================================
   Procedure: [dbo].[usp_rf_UpdateReserveFundTransaction]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_rf_UpdateReserveFundTransaction](    
 @CreditId bigint   
)     
AS  
BEGIN  
  
 -- declare @CreditId bigint  = 1110219  
     
 declare   
  @DebitAmount decimal(18, 4), @TypeServiceId int = 0, @UserId bigint = 0, @ReserveFundId BIGINT, @WalletBalance DECIMAL(18,4),   
  @ServiceBalance DECIMAL(18,4),    @ReservedFunds DECIMAL(18,4), @CurrentDate DATETIME = GETDATE(),@ParentId bigint, @CreditTypeId bigint = 0,   
  @StartAmount DECIMAL(18,4), @setamount DECIMAL(18,4),    
  @reserveamount DECIMAL(18,4)   
     
 select @DebitAmount = Debits, @UserId = User_ID, @CreditTypeId = typecredit from IntCredit_Details(nolock) where Credit_ID  = @CreditId    
    
    PRINT CONCAT('@DebitAmount => ', @DebitAmount)  
    PRINT CONCAT('@UserId => ', @UserId)  
  
 if(@DebitAmount > 0 and @UserId > 0)    
 begin  
  select @ParentId=ParentID from User_Detail(nolock) where User_ID=@UserId      
  print concat('@CreditTypeId => ', @CreditTypeId)     
  select top 1 @ReserveFundId = Id, @reserveamount=amount  from tbl_IntCreditReserveFunds(nolock)    where ParentId = @ParentId and CreditTypeId = @CreditTypeId and Amount > 0 order by IsLock desc    
        print concat('@reserveamount => ', @reserveamount)    

        DECLARE @Cinfo VARBINARY(128);    
		SELECT @Cinfo=CONTEXT_INFO();    

		IF @Cinfo != 0x44444
		Begin
			begin transaction    
		End
        begin try    
            if(@DebitAmount > 0 AND @reserveamount > 0)    
            begin    
                set @setamount=(@reserveamount - (case when isnull(@reserveamount, 0) <= isnull(@DebitAmount, 0) then isnull(@reserveamount, 0) else isnull(@DebitAmount, 0) end ))    
  
                PRINT CONCAT('@setamount => ', @setamount)  
  
                update tbl_IntCreditReserveFunds set     Amount = @setamount   where Id = @ReserveFundId;      
                update IntCredit_Details set rf_Id = @ReserveFundId, ReserveAmount = @setamount where Credit_ID = @CreditId    
            end    

			IF @Cinfo != 0x44444
			Begin
				commit transaction    
			End
        end try    
        begin catch    
       		IF @Cinfo != 0x44444
			Begin
				rollback transaction    
			End
            print 'Error Occured. Transaction Rolled Back.'  
            EXEC usp_InsertErrorInfo  
        end catch    

 end    

	IF @Cinfo = 0x44444
	BEGIN    
	   SET Context_Info 0x;    
	End
end    



GO

/* ============================================================
   Procedure: [dbo].[usp_rpt_GetCallSummaryReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_rpt_GetCallSummaryReport (
	@UserId BIGINT
	,@OffsetValue INT = 0
	,@PagingSize INT = 20
	,@fromdate NVARCHAR(50) = NULL
	,@todate NVARCHAR(50) = NULL
	,@callDirection NVARCHAR(50) = ''
	)
AS
BEGIN
	--DECLARE @UserId BIGINT= 39020, @OffsetValue INT= 0, @PagingSize INT= 20, @fromdate NVARCHAR(50)= NULL, @todate NVARCHAR(50)= NULL;
	IF (@fromdate = '')
		SET @fromdate = NULL;

	IF (@todate = '')
		SET @todate = NULL;

	DECLARE @ParentId BIGINT
		,@isadmin INT;

	SELECT @parentid = ParentID
		,@isadmin = IsAdmin
	FROM MySMS.dbo.User_Detail(NOLOCK)
	WHERE User_ID = @UserId;

	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(500) = ''

	SELECT @TeamCode = TeamCode
		,@ScopeCode = ScopeCode
		,@UserIdTeamLst = UserIdTeamLst
	FROM MySMS.dbo.ufn_GetUserRoleScope(@UserId)

	SELECT @fromdate = COALESCE(@fromdate, (
				SELECT replace(first_day_of_month, '-', '')
				FROM calendar(NOLOCK)
				WHERE date_id = CAST(GETDATE() AS DATE)
				));

	SELECT @todate = COALESCE(@todate, DATEADD(dd, 1, CAST(GETDATE() AS DATE)));

	SELECT COUNT(a.User_Login) OVER () AS TotalRow
		,user_login
		,FName
		,lname
		,COUNT(1) AS TotalDialled
		,ISNULL(SUM(CAST(duration AS INT)), 0) AS Talktime
	FROM (
		SELECT u.user_login
			,u.FName
			,u.lname
			,t.callcreatedon
			,u.parentid
			,t.customercalldisposition AS STATUS
			,DATEDIFF(ss, t.callcreatedon, t.Callendtime) AS duration
		FROM calllog(NOLOCK) t
		JOIN user_detail(NOLOCK) u ON t.agentuserid = CAST(u.User_ID AS NVARCHAR)
		WHERE u.parentid = @parentid
			AND 1 = CASE 
				WHEN CAST(t.callcreatedon AS DATE) BETWEEN @fromdate
						AND @todate
					THEN 1
				ELSE 0
				END
			AND 1 = CASE 
				WHEN isnull(@callDirection, '') <> ''
					AND t.Direction = @callDirection
					THEN 1
				WHEN isnull(@callDirection, '') = ''
					THEN 1
				ELSE 0
				END
			AND 1 = (
				CASE 
					WHEN @isadmin = 1
						THEN 1
					WHEN isnull(t.agentuserid, 0) IN (
							SELECT [value]
							FROM dbo.fn_Split(@UserIdTeamLst, ',')
							)
						THEN 1
					WHEN isnull(t.agentuserid, 0) = @UserId
						THEN 1
					ELSE 0
					END
				)
		) a
	GROUP BY user_login
		,FName
		,lname
	ORDER BY user_login ASC OFFSET @OffsetValue ROWS

	FETCH NEXT @PagingSize ROWS ONLY;

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_Call_Smryrpt'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'calllog'
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_rpt_GetCallSummaryReport_agents]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_rpt_GetCallSummaryReport_agents (  
 @UserId BIGINT
 ,@OffsetValue INT = 0  
 ,@PagingSize INT = 20  
 ,@fromdate NVARCHAR(50) = NULL  
 ,@todate NVARCHAR(50) = NULL  
 ,@callDirection NVARCHAR(50) = ''  
 )  
AS  
BEGIN  
 --DECLARE @UserId BIGINT= 39020, @OffsetValue INT= 0, @PagingSize INT= 20, @fromdate NVARCHAR(50)= NULL, @todate NVARCHAR(50)= NULL;  
 IF (@fromdate = '')  
  SET @fromdate = NULL;  
  
 IF (@todate = '')  
  SET @todate = NULL;  
  
 DECLARE @ParentId BIGINT  
  ,@isadmin INT;  
  
 SELECT @parentid = ParentID  
  ,@isadmin = IsAdmin  
 FROM MySMS.dbo.User_Detail(NOLOCK)  
 WHERE User_ID = @UserId;  
  
 DECLARE @TeamCode VARCHAR(10) = ''  
 DECLARE @ScopeCode VARCHAR(10) = ''  
 DECLARE @UserIdTeamLst VARCHAR(500) = ''  
  
 SELECT @TeamCode = TeamCode  
  ,@ScopeCode = ScopeCode  
  ,@UserIdTeamLst = UserIdTeamLst  
 FROM MySMS.dbo.ufn_GetUserRoleScope(@UserId)  
  
 SELECT @fromdate = COALESCE(@fromdate, (  
    SELECT replace(first_day_of_month, '-', '')  
    FROM calendar(NOLOCK)  
    WHERE date_id = CAST(GETDATE() AS DATE)  
    ));  
  
 SELECT @todate = COALESCE(@todate, DATEADD(dd, 1, CAST(GETDATE() AS DATE)));  
  
 SELECT COUNT(a.AgentName) OVER () AS TotalRow  
    ,COUNT(1) AS TotalDialled  
  ,ISNULL(SUM(CAST(duration AS INT)), 0) AS Talktime  
 FROM (  
  SELECT u.Agentname  
   ,t.callcreatedon  
   ,u.parentid  
   ,t.customercalldisposition AS STATUS  
   ,DATEDIFF(ss, t.callcreatedon, t.Callendtime) AS duration  
  FROM calllog(NOLOCK) t  
  JOIN calling_agents(NOLOCK) u ON t.calling_agentid = CAST(u.ID AS NVARCHAR)  
  WHERE u.parentid = @parentid  
   AND 1 = CASE   
    WHEN CAST(t.callcreatedon AS DATE) BETWEEN @fromdate  
      AND @todate  
     THEN 1  
    ELSE 0  
    END  
   AND 1 = CASE   
    WHEN isnull(@callDirection, '') <> ''  
     AND t.Direction = @callDirection  
     THEN 1  
    WHEN isnull(@callDirection, '') = ''  
     THEN 1  
    ELSE 0  
    END  
   AND 1 = (  
    CASE   
     WHEN @isadmin = 1  
      THEN 1  
     WHEN isnull(u.kit19userid, 0) IN (  
       SELECT [value]  
       FROM dbo.fn_Split(@UserIdTeamLst, ',')  
       )  
      THEN 1  
     WHEN isnull(u.kit19userid, 0) = @UserId  
      THEN 1  
     ELSE 0  
     END  
    )  
  ) a  
 GROUP BY Agentname  
 ORDER BY Agentname ASC OFFSET @OffsetValue ROWS  
  
 FETCH NEXT @PagingSize ROWS ONLY;  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
  ,@Activity_type = 'View_Call_Smryrpt'  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'calllog'  
END;  


GO

/* ============================================================
   Procedure: [dbo].[usp_rpt_GetFollowupReports]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_rpt_GetFollowupReports] (
	@UserId bigint, 
	@OffsetValue int = 0,
	@PagingSize int = 20,
	@fromdate nvarchar(50) = NULL,
	@todate nvarchar(50) = NULL
)
as
begin
	--declare 
	--	@UserId bigint = 34594,
	--	@OffsetValue int = 0,
	--	@PagingSize int = 100,
	--	@fromdate nvarchar(50) = N'06-Dec-2022',
	--	@todate nvarchar(50) = N'13-Dec-2022';

	declare @ParentId bigint = 0;		
	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId;

	select @fromdate = COALESCE(@fromdate, (select replace(first_day_of_month, '-', '') 
						 from calendar(nolock) where date_id = CAST(GETDATE() as date) ));

	select @todate = COALESCE(@todate, DATEADD(dd, 1, CAST(GETDATE() AS DATE)));

	declare @StartPoint bigint = (@OffsetValue + 1), @EndPoint bigint = (@OffsetValue + @PagingSize)

	select l.TotalRow,
			s.name AS Source,
			isnull(c.name, '') AS Campaign,
			ul.Leadno,
			personName AS Name,
			MobileNo + isnull(', ' + nullif(MobileNo1, ''), '') + isnull(', ' + nullif(MobileNo2, ''), '') AS Mobile,
			isnull(EmailID, '') + isnull(', ' + nullif(emailid1, ''), '') + isnull(', ' + nullif(emailid1, ''), '') AS Email,
			f.FollowupStatus,
			l.CreatedOn AS LastFollowedOn,
			isnull(l.Remarks, '') AS Remarks,
			l.AmountPaid,
			cu.User_Login as [user_login]
		from ( select 
		row_number() over ( partition by lih.ParentId order by lih.ParentId asc ) AS LihSN,
		count(lih.ParentId) OVER() AS TotalRow,
		lih.ID, lih.LeadNo, lih.FollowUpStatus, lih.NextStatusDate, lih.Remarks, lih.Products, 
		lih.AmountPaid, lih.AssignedTo, lih.ParentID, lih.CreatedOn, lih.CreatedBy, lih.FollowupDate, 
		lih.IsReassign, lih.IsAutoEntry
	from ( select row_number() over(partition by LeadNo order by Id desc) as lrn, 
		ID, LeadNo, FollowUpStatus, NextStatusDate, Remarks, Products, 
		AmountPaid, AssignedTo, ParentID, CreatedOn, CreatedBy, FollowupDate, 
		IsReassign, IsAutoEntry from LeadInteractionHistory(nolock) il
		where ParentID = @ParentId and CreatedBy  <> ParentID  
			and 1 = ( case when isnull(@fromdate, '') = '' and isnull(@fromdate, '') = '' then 1
					when il.CreatedOn between @fromdate and @todate then 1
				else 0 end )
	) lih where lih.lrn = 1 ) l  
		left join UserLeads(nolock) ul on l.LeadNo = ul.LeadNo and l.ParentID = ul.ParentID
		left join UserSourceSettings(nolock) s ON s.SourceID = ul.SourceName
		left join UsercampaignSettings(nolock) c ON c.CampaignID = ul.CampaignName
		left join FollowUp_Status(nolock) f ON f.ID = l.FollowUpStatus and l.FollowUpStatus <> 6
		left join User_Detail(nolock) cu on l.CreatedBy = cu.User_ID
	where l.LihSN between @StartPoint and @EndPoint


	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_flwup_rpt'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'userleads'

end



GO

/* ============================================================
   Procedure: [dbo].[usp_rpt_GetFollowupReportsNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_rpt_GetFollowupReportsNew] (
	@UserId bigint, 
	@OffsetValue int = 0,
	@PagingSize int = 20,
	@FilterData nvarchar(max) = null
)
as
begin
	
	--declare 
	--	@UserId bigint = 41787,
	--	@OffsetValue int = 0,
	--	@PagingSize int = 10,
	--	@FilterData nvarchar(max) =  N'{"logicalOperator":"and","condtions":[{"data_type":"DATETIME","field_name":"LastFollowedOn","operator_value":"=","operator_text":"Equal To","operand_value":"31-Jul-2023","operand_text":"31-Jul-2023"}]}'

	--select @UserId=50251,@OffsetValue=0,@PagingSize=100,@FilterData=N'{"logicalOperator":"and","condtions":[{"data_type":"DATETIME","field_name":"LastFollowedOn","operator_value":">=","operator_text":"Greater Than Equal To","operand_value":"06-Jan-2026","operand_text":"06-Jan-2026"},{"data_type":"DATETIME","field_name":"LastFollowedOn","operator_value":"<=","operator_text":"Less Than Equal To","operand_value":"12-Jan-2026","operand_text":"12-Jan-2026"}]}'

	declare @logOp nvarchar(50), @conditionJSON nvarchar(max)
	select @logOp = logicalOperator,  @conditionJSON = condtions from openjson(@FilterData) with(
		logicalOperator nvarchar(50) '$.logicalOperator',
		condtions nvarchar(max) '$.condtions' as json
	)
	
	declare @filterString  nvarchar(max) = ''
	select 
		@filterString = (concat(@filterString,
			CONCAT( case when LEN(@filterString) > 0 then concat(' ', @logOp, ' ') else ' ' end,
				case when field_name = 'SourceName' then 'ul.SourceName'
					when field_name = 'CampaignName' then 'ul.CampaignName'
					when field_name = 'LastFollowedOn' then 'cast(ul.LastFollowupCreatedOn as date)'					
					when field_name = 'Remarks' then 'l.Remarks'
					when field_name = 'LastFollowedBy' then 'l.CreatedBy'
					when field_name = 'FollowUpStatus' then 'f.ID'
					when field_name = 'AmountPaid' then 'l.AmountPaid'
					when field_name = 'EmailId1' then 'ul.EmailID'
					when field_name = 'EmailId2' then 'ul.EmailID1'
					when field_name = 'EmailId3' then 'ul.EmailID2'
					when field_name = 'MobileNo1' then 'ul.MobileNo'
					when field_name = 'MobileNo2' then 'ul.MobileNo1'
					when field_name = 'MobileNo3' then 'ul.MobileNo2'
					when field_name = 'LeadNo' then 'ul.LeadNo'
					when field_name = 'PersonName' then 'ul.PersonName' 
					else '' end
				, ' ',  operator_value, ' ', 
				case 
					when data_type  = 'DATETIME' then concat(' CAST(''', operand_value, ''' AS date)')
					when data_type = 'VARCHAR' then ( case 
						when lower(operator_text) = lower('Contain') then concat('''%',operand_value,  '%''')	
						when lower(operator_text) = lower('Doesn''t Contain') then concat('''%',operand_value,  '%''')	
						when lower(operator_text) = lower('Begin With') then concat('''',operand_value,  '%''')	
						when lower(operator_text) = lower('Doesn''t Begin With') then concat('''',operand_value,  '%''')	
						when lower(operator_text) = lower('End With') then concat('''%',operand_value,  '''')	
						when lower(operator_text) = lower('Doesn''t End With') then concat('''%',operand_value,  '''')	
						when lower(operator_text) = lower('Equal To') then concat('''',operand_value,  '''')	
						when lower(operator_text) = lower('Doesn''t Equal To') then concat('''',operand_value,  '''')	
					end)
					when data_type = 'BIGINT' then  operand_value
				else ' ' end)
			)
		)
	from openjson( @conditionJSON) with (
		data_type nvarchar(255) '$.data_type',
		field_name nvarchar(255) '$.field_name',
		operator_value nvarchar(255) '$.operator_value',
		operator_text nvarchar(255) '$.operator_text',
		operand_value nvarchar(255) '$.operand_value',
		operand_text nvarchar(255) '$.operand_text'
	)
	print @filterString

	declare @ParentId bigint = 0;		
	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId;

	declare @StartPoint bigint = (@OffsetValue + 1), @EndPoint bigint = (@OffsetValue + @PagingSize)

	declare @reportSql nvarchar(max) = concat(N'select * from (select ',
			N'row_number() over ( partition by l.ParentId order by l.CreatedOn desc ) AS LihSN, ',
			N'count(l.ParentId) OVER() AS TotalRow, ',
			N's.name AS Source, ',
			N'isnull(c.name, '''') AS Campaign, ',
			N'ul.Leadno, ',
			N'personName AS Name, ',
			N'MobileNo + isnull('', '' + nullif(MobileNo1, ''''), '''') + isnull('', '' + nullif(MobileNo2, ''''), '''') AS Mobile, ',
			N'isnull(EmailID, '''') + isnull('', '' + nullif(emailid1, ''''), '''') + isnull('', '' + nullif(emailid1, ''''), '''') AS Email, ',
			N'f.FollowupStatus, ',
			N'l.CreatedOn AS LastFollowedOn, ',
			N'isnull(l.Remarks, '''') AS Remarks, ',
			N'l.AmountPaid, ',
			N'cu.User_Login as [user_login],  isnull(cu.FName,'''') + '' '' + isnull(cu.LName,'''')  as [User FullName] ',
		N'from ( select ',
		N'lih.ID, lih.LeadNo, lih.FollowUpStatus, lih.NextStatusDate, lih.Remarks, lih.Products,  ',
		N'lih.AmountPaid, lih.AssignedTo, lih.ParentID, lih.CreatedOn, lih.CreatedBy, lih.FollowupDate,  ',
		N'lih.IsReassign, lih.IsAutoEntry ',
	N'from ( select row_number() over(partition by LeadNo order by Id desc) as lrn,  ',
		N'ID, LeadNo, FollowUpStatus, NextStatusDate, Remarks, Products,  ',
		N'AmountPaid, AssignedTo, ParentID, CreatedOn, CreatedBy, FollowupDate,  ',
		N'IsReassign, IsAutoEntry from LeadInteractionHistory(nolock) il ',
		N'where ParentID = ', @ParentId, -- ' and CreatedBy <> ParentID ',
	N') lih where lih.lrn = 1 ) l   ',
		N'left join UserLeads(nolock) ul on l.LeadNo = ul.LeadNo and l.ParentID = ul.ParentID  ',
		N'left join UserSourceSettings(nolock) s ON s.SourceID = ul.SourceName ',
		N'left join UsercampaignSettings(nolock) c ON c.CampaignID = ul.CampaignName ',
		N'left join FollowUp_Status(nolock) f ON f.ID = l.FollowUpStatus and l.FollowUpStatus <> 6 ',
		N'left join User_Detail(nolock) cu on l.CreatedBy = cu.User_ID ',
		case when len(trim(@filterString)) > 0 then concat(N' where  ', @filterString) else '' end,
	 N' ) t where t.LihSN between ', @StartPoint, ' and ', @EndPoint)
	
	  
	print @reportSql

	execute sp_executesql  @reportSql


	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_flwup_rpt'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'userleads'

end



GO

/* ============================================================
   Procedure: [dbo].[usp_rpt_MobileCallLogList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_rpt_MobileCallLogList](
	@fromdate nvarchar(50) = N'', 
	@todate nvarchar(50) = N'', 
	@UserId bigint, 
	@FilterText nvarchar(max) = N'',  
	@OffsetValue INT = 0, 
	@PagingSize INT = 100 

)
as
begin

	--declare 
	--	@fromdate nvarchar(50) = N'20260504', 
	--	@todate nvarchar(50) = N'20260510', 
	--	@UserId bigint = 50285, 
	--	@FilterText nvarchar(max) = N'cast([Agent] as varchar ) like ''%Anmol%''',  
	--	@OffsetValue INT = 0, 
	--	@PagingSize INT = 20 



	declare @ParentId bigint,@isadmin int;                                                
	select @parentid=ParentID,@isadmin=IsAdmin  from Mysms.dbo.User_Detail(nolock) where User_ID = @UserId;                        
  
	declare @TeamCode varchar(10) = ''    
	declare @ScopeCode varchar(10) = ''     
	declare @UserIdTeamLst varchar(500) = ''     
	select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from MySMS.dbo.ufn_GetUserRoleScope(@UserId)     
  
	declare @StartPoint int = @OffsetValue + 1, @EndPoint int  = (@OffsetValue + @PagingSize )

	declare @finalSqlQuery nvarchar(max), @sqlQuery1 nvarchar(max), @sqlQuery2 nvarchar(max)

	print @UserIdTeamLst 

		set @sqlQuery1 = concat(N';with cteCallLog as ( select ',
		N'ROW_NUMBER() OVER( order by cl.parentid, cast(cl.callcreatedon as datetime) desc) AS sno, ',
		N'id, parentid, callerid, callstatus, context, customerentity, customerEntityId, CustomerName, ',
		N'Customernumber, dnid, Image, name, OutcomeName, Date, user_login, UserName, Gateway, IVRFlow, ',
		N'Agent, direction, CustomerDisposition, AgentDisposition, Callstarttime, CallEndTime, CustomerDuration, ',
		N'agentDuration, Callduration, Recording, AgentMode, Outcome, remarks, LastUserInput, callcreatedon, LeadNo ', 
		N'from ( select c.id, c.parentid, (case when c.Direction = ''incoming'' then c.Customernumber ',
		N'else isnull(dnid, c.agentnumber) end ) callerid, '''' as [callstatus], '''' as [context], ',
		N'c.customerentity, c.customerEntityId, ',
		N'isnull (dbo.fn_getentityfullname(customerentity, customerentityid),'''') as CustomerName, ',
		N'c.Customernumber, c.dnid, ',
		N'(case when c.customerentity = ''lead'' then ul.ProfileImgFileName ',
		N'	when c.customerentity = ''enquiry'' then en.ProfileImgFileName else '''' end ) as [Image], ',
		N'(case when c.customerentity = ''lead'' then ul.PersonName ',
		N'	when c.customerentity = ''enquiry'' then en.PersonName else '''' end ) as [name], ',
		N'isnull(o.OutcomeName, '''') OutcomeName, c.callcreatedon as Date, user_login, ',
		N'isnull(u.FName, '''') + '' '' + isnull(u.LName, '''') as UserName, ',
		N'(case when c.gatewayid = 0 then ''Sim'' else s.provider_name end) as Gateway, ',
		N'isnull(m.AppName, '''') IVRFlow, isnull( ',
		N'user_login, case when c.agentcalldisposition is null then '' '' else ''Agent No Changed'' end ) Agent, ',
		N'direction, isnull( c.customercalldisposition, ''Unknown'' ) as CustomerDisposition, ',
		N'isnull( c.agentcalldisposition, case when c.agentcalldisposition is null ',
		N'then ''NOT ATTEMPTED'' else ''Unknown'' end) as AgentDisposition, ',
		N'(case when isnull(c.Callstarttime, '''') = '''' then ''Unknown'' ',
		N'else format(c.Callstarttime, ''dd-MMM-yyyy HH:mm:ss'') end) as Callstarttime, ',
		N'(case when isnull(c.callendtime, '''') = '''' then ''Unknown'' ',
		N'else format(c.callendtime, ''dd-MMM-yyyy HH:mm:ss'') end) as CallEndTime, ',
		N'coalesce(customerduration, c.Calldurationseconds, 0) AS CustomerDuration, ',
		N'(case when c.agentcalldisposition is null then 0 when c.agentcalldisposition = ''NOANSWER'' then 0 ',
		N'else coalesce(agentduration, Calldurationseconds, 0) end) as agentDuration, ',
		N'(case when c.agentcalldisposition IS NULL then 0 ',
		N'else isnull (Calldurationseconds, 0) end) as Callduration, ',
		N'c.recordurl as Recording, isnull(c.agentmode, ''Mobile'') as AgentMode, ',
		N'isnull(o.outcomename, '''') as Outcome, c.remarks, isnull(c.lastdtmf, '''') LastUserInput, ',
		N'c.callcreatedon, (case when c.customerentity = ''lead'' then ul.LeadNo else en.LeadNo end) as [LeadNo] ')
	set @sqlQuery2 = concat(N'from calllog(nolock) c ',
		N'left join user_detail u (nolock) on c.agentuserid = u.User_ID ',
		N'left join UserLeads ul (nolock) on c.customerentity = ''lead'' and c.customerentityid = ul.ID ',
		N'left join UserEnquiry en (nolock) on c.customerentity = ''enquiry'' and c.customerentityid = en.EnquiryID ',
		N'left join tbl_voip_ServiceProvider s on s.id = c.gatewayid ',
		N'left join tbl_CallLogOutcomeMaster(nolock) o on o.id = c.outcomeid ',
		N'left join Cloud_app_master(nolock) m on m.AppId = c.appid ',
		N'where cast(c.Callstarttime as date) between cast(''',  @fromdate, ''' as date) ',
		N'and cast(''', @todate, ''' as date) ',
		N'and c.parentid=', @parentid, ' ',
		N'and 1 = (case when ' , @isadmin ,' = 1 then 1 ',
		N'when isnull(c.agentuserid, 0) in (select [value] from dbo.fn_Split(''', @UserIdTeamLst, ''', '','')) then 1 ',
		N'when isnull(c.agentuserid, 0) = ', @UserId, ' then 1 else 0 end ) ', 
		N') cl ', ( case when len(@FilterText) > 2 then concat('where ', @FilterText) else '' end),		
		N' ) select sno, (select COUNT(1) from cteCallLog) as TotalRow, ',
		N'id, parentid, callerid, callstatus, context, customerentity, customerEntityId, CustomerName, Customernumber, dnid, ',
		N'Image, name, OutcomeName, Date, user_login, UserName, Gateway, IVRFlow, Agent, direction, CustomerDisposition, ',
		N'AgentDisposition, Callstarttime, CallEndTime, CustomerDuration, agentDuration, Callduration, Recording, AgentMode, ',
		N'Outcome, remarks, LastUserInput, callcreatedon, LeadNo ',
		N'from cteCallLog  where  sno between ', @StartPoint, N' and ',  @EndPoint)

	print @sqlQuery1 
	print @sqlQuery2

	set @finalSqlQuery = @sqlQuery1 + @sqlQuery2
  
	execute sp_executesql @finalSqlQuery  

end



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetChurnSignals]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER OFF


CREATE   PROCEDURE usp_rt_GetChurnSignals
    @TopN INT = 50,
    @MinChurnProbability DECIMAL(5,2) = 0,
    @RetentionExecName NVARCHAR(100) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    SELECT TOP (@TopN)
        ud.User_ID AS CustomerId,
        ud.CompnayName AS CustomerName,
        ISNULL(aam.AM_Name, 'Not Available') AS RetentionExec,
        DATEDIFF(DAY, ud.LastLogin1, GETDATE()) AS DaysInactive,
        ISNULL(psd.Cost, 0) AS CurrentMRR,
        psd.PlanEndDate AS RenewalDate,
        CASE 
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) >= 60 THEN 85
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) >= 30 THEN 65
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) >= 14 THEN 45
            ELSE 25
        END AS ChurnProbability,
        CASE 
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) >= 60 THEN 'No login for 60+ days - High risk of churn'
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) >= 30 THEN 'No login for 30+ days - Medium risk'
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) >= 14 THEN 'Reduced activity - Early warning sign'
            ELSE 'Declining engagement pattern detected'
        END AS ChurnReason,
        'Immediate Follow-up' AS RecommendedAction
    FROM User_Detail ud
    INNER JOIN (
        SELECT 
            UserID,
            MAX(PlanEndDate) AS PlanEndDate,
            SUM(Cost) AS Cost
        FROM Price_UserSubscriptionDetails
        WHERE IsNewPlan = 1
          AND PlanEndDate >= GETDATE()  -- ACTIVE subscriptions only
        GROUP BY UserID
    ) psd ON ud.User_ID = psd.UserID
    -- Join to CRM to get Retention Executive
    LEFT JOIN CRM.CRMDB.dbo.LinkedAccount la ON ud.User_ID = la.User_ID
    LEFT JOIN CRM.CRMDB.dbo.Assign_accountmanager_Latest aam ON la.RefrenceNo = aam.Refrence_No
    WHERE ud.User_ID = ud.ParentID
      AND ud.Status = '1'
      AND ud.IsInternalUser = 0
      AND DATEDIFF(DAY, ud.LastLogin1, GETDATE()) BETWEEN 7 AND 90  -- 7-90 days inactive
      AND CASE 
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) >= 60 THEN 85
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) >= 30 THEN 65
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) >= 14 THEN 45
            ELSE 25
          END >= @MinChurnProbability
      AND (@RetentionExecName IS NULL OR ISNULL(aam.AM_Name, 'Not Available') = @RetentionExecName)
    ORDER BY DATEDIFF(DAY, ud.LastLogin1, GETDATE()) DESC;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetChurnSignalsCount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER OFF


CREATE   PROCEDURE usp_rt_GetChurnSignalsCount
    @MinChurnProbability DECIMAL(5,2) = 0,
    @RetentionExecName NVARCHAR(100) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    SELECT COUNT(*) AS TotalCount
    FROM User_Detail ud
    INNER JOIN (
        SELECT UserID, MAX(PlanEndDate) AS PlanEndDate
        FROM Price_UserSubscriptionDetails
        WHERE IsNewPlan = 1 AND PlanEndDate >= GETDATE()
        GROUP BY UserID
    ) psd ON ud.User_ID = psd.UserID
    LEFT JOIN CRM.CRMDB.dbo.LinkedAccount la ON ud.User_ID = la.User_ID
    LEFT JOIN CRM.CRMDB.dbo.Assign_accountmanager_Latest aam ON la.RefrenceNo = aam.Refrence_No
    WHERE ud.User_ID = ud.ParentID
      AND ud.Status = '1'
      AND ud.IsInternalUser = 0
      AND DATEDIFF(DAY, ud.LastLogin1, GETDATE()) BETWEEN 7 AND 90
      AND CASE 
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) >= 60 THEN 85
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) >= 30 THEN 65
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) >= 14 THEN 45
            ELSE 25
          END >= @MinChurnProbability
      AND (@RetentionExecName IS NULL OR ISNULL(aam.AM_Name, 'Not Available') = @RetentionExecName);
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetCustomer360Profile]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_rt_GetCustomer360Profile
    @CustomerId BIGINT
AS
BEGIN
    SET NOCOUNT ON;
    
    -- Result Set 1: Header Information (with LoginName added)
    SELECT 
        ud.User_ID AS CustomerId,
        ud.CompnayName AS CustomerName,
        ud.User_Login AS LoginName,  -- ADDED
        ud.EMail,
        ud.Mobile,
        ISNULL(aam.AM_Name, 'Not Assigned') AS CSM,
        ISNULL(psd.Cost, 0) AS MRR,
        psd.PlanEndDate AS RenewalDate,
        DATEDIFF(DAY, GETDATE(), psd.PlanEndDate) AS DaysToRenewal,
        ud.LastLogin1 AS LastLogin,
        DATEDIFF(DAY, ud.LastLogin1, GETDATE()) AS DaysSinceLastLogin,
        ud.DateCreated AS CustomerSince
    FROM User_Detail ud
    LEFT JOIN (
        SELECT UserID, MAX(PlanEndDate) AS PlanEndDate, SUM(Cost) AS Cost
        FROM Price_UserSubscriptionDetails
        WHERE IsNewPlan = 1
        GROUP BY UserID
    ) psd ON ud.User_ID = psd.UserID
    LEFT JOIN CRM.CRMDB.dbo.LinkedAccount la ON ud.User_ID = la.User_ID
    LEFT JOIN CRM.CRMDB.dbo.Assign_accountmanager_Latest aam ON la.RefrenceNo = aam.Refrence_No
    WHERE ud.User_ID = @CustomerId;
    
    -- Result Set 2: Module Usage Summary
    EXEC usp_rt_GetCustomerModuleUsage14Days @CustomerId;
    
    -- Result Set 3: Child Users
    SELECT 
        User_ID AS UserId,
        User_Login,
        EMail,
        LastLogin1 AS LastLogin,
        DATEDIFF(DAY, LastLogin1, GETDATE()) AS DaysSinceLastLogin
    FROM User_Detail
    WHERE ParentID = @CustomerId
      AND User_ID <> @CustomerId
      AND Status = '1'
    ORDER BY LastLogin1 DESC;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetCustomerModuleUsage14Days]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_rt_GetCustomerModuleUsage14Days
    @CustomerId BIGINT
AS
BEGIN
    SET NOCOUNT ON;
    
    WITH ModuleEngagement AS (
        SELECT 
            mm.ModuleId,
            mm.ModuleName,
            mm.ParentModuleId,
            CASE WHEN mm.ParentModuleId IS NULL OR mm.ParentModuleId = 0 
                 THEN mm.ModuleName 
                 ELSE (SELECT ModuleName FROM TBL_UA_ModuleMaster WHERE ModuleId = mm.ParentModuleId)
            END AS ParentModuleName,
            det.CreatedDate,
            det.SpendTime
        FROM tbl_user_engagement_track_master mast
        INNER JOIN tbl_user_engagement_track_details det ON mast.EngagementID = det.UserEngMasterId
        INNER JOIN TBL_UA_ModuleMaster mm ON (
            -- Match web URLs (remove ~ prefix from ModuleMaster)
            (mm.URL IS NOT NULL 
             AND mm.URL <> '' 
             AND mm.URL <> '#' 
             AND mast.PageURL LIKE '%' + REPLACE(mm.URL, '~', '') + '%')
            OR
            -- Match mobile URLs using StaticPath
            (mm.StaticPath IS NOT NULL 
             AND mm.StaticPath <> '' 
             AND (
                 -- Exact match for short mobile paths (e.g., PageURL="/Dashboard" matches StaticPath="/Dashboard")
                 mast.PageURL = mm.StaticPath
                 OR
                 -- Partial match for longer paths
                 mast.PageURL LIKE '%' + mm.StaticPath + '%'
                 OR 
                 -- Match without leading / and spaces (e.g., StaticPath="Sales/Follow-ups", PageURL="/SalesFollow-ups")
                 mast.PageURL LIKE '%' + REPLACE(REPLACE(mm.StaticPath, '/', ''), ' ', '') + '%'
                 OR
                 -- Match StaticPath with leading / removed (e.g., StaticPath="/Dashboard", PageURL="Dashboard")
                 mast.PageURL = REPLACE(mm.StaticPath, '/', '')
             ))
        )
        WHERE mast.UserID IN (
            -- Get customer and all child users
            SELECT User_ID FROM User_Detail 
            WHERE (User_ID = @CustomerId OR ParentID = @CustomerId)
              AND Status = '1'
        )
        AND det.CreatedDate >= DATEADD(DAY, -14, GETDATE())
        AND (det.ImpersonatorID IS NULL OR det.ImpersonatorID = 0)  -- Exclude support impersonation
        AND mm.Active = 1
        AND mm.ModuleName NOT LIKE '%BI Dashboard%'  -- Exclude BI Dashboard per user request
    ),
    AggregatedModules AS (
        SELECT 
            ModuleId,
            ModuleName,
            ParentModuleId,
            ParentModuleName,
            SUM(ISNULL(SpendTime, 0)) / 3600.0 AS TotalHours,  -- Convert seconds to hours
            COUNT(DISTINCT CAST(CreatedDate AS DATE)) AS DaysUsed,
            MAX(CreatedDate) AS LastUsedDate,
            -- Week 1 (last 7 days)
            SUM(CASE WHEN CreatedDate >= DATEADD(DAY, -7, GETDATE()) 
                     THEN ISNULL(SpendTime, 0) ELSE 0 END) / 3600.0 AS Week1Hours,
            -- Week 2 (days 8-14)
            SUM(CASE WHEN CreatedDate BETWEEN DATEADD(DAY, -14, GETDATE()) AND DATEADD(DAY, -8, GETDATE()) 
                     THEN ISNULL(SpendTime, 0) ELSE 0 END) / 3600.0 AS Week2Hours
        FROM ModuleEngagement
        GROUP BY 
            ModuleId,
            ModuleName,
            ParentModuleId,
            ParentModuleName
    )
    SELECT 
        ModuleId,
        ModuleName,
        ParentModuleName,
        CAST(TotalHours AS DECIMAL(10,2)) AS TotalHours,
        DaysUsed,
        CAST(Week1Hours AS DECIMAL(10,2)) AS Week1Hours,
        CAST(Week2Hours AS DECIMAL(10,2)) AS Week2Hours,
        -- Calculate trend
        CASE 
            WHEN Week2Hours = 0 AND Week1Hours > 0 THEN 'New'
            WHEN Week2Hours = 0 THEN 'Stable'
            WHEN ((Week1Hours - Week2Hours) / NULLIF(Week2Hours, 0)) >= 0.25 THEN 'Increasing'
            WHEN ((Week1Hours - Week2Hours) / NULLIF(Week2Hours, 0)) <= -0.25 THEN 'Decreasing'
            ELSE 'Stable'
        END AS Trend,
        -- Trend percentage
        CASE 
            WHEN Week2Hours = 0 THEN NULL
            ELSE CAST(((Week1Hours - Week2Hours) / NULLIF(Week2Hours, 0)) * 100 AS INT)
        END AS TrendPercentage
    FROM AggregatedModules
    WHERE TotalHours > 0  -- Only show modules actually used
    ORDER BY TotalHours DESC;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetCustomerParentModuleUsage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_rt_GetCustomerParentModuleUsage
    @CustomerId BIGINT,
    @Days INT = 14
AS
BEGIN
    SET NOCOUNT ON;
    
    WITH AllModuleEngagement AS (
        SELECT 
            mm.ModuleId,
            mm.ModuleName,
            mm.ParentModuleId,
            det.SpendTime
        FROM tbl_user_engagement_track_master mast
        INNER JOIN tbl_user_engagement_track_details det ON mast.EngagementID = det.UserEngMasterId
        INNER JOIN TBL_UA_ModuleMaster mm ON (
            -- Match web URLs (remove ~ prefix)
            (mm.URL IS NOT NULL 
             AND mm.URL <> '' 
             AND mm.URL <> '#' 
             AND mast.PageURL LIKE '%' + REPLACE(mm.URL, '~', '') + '%')
            OR
            -- Match mobile URLs using StaticPath
            (mm.StaticPath IS NOT NULL 
             AND mm.StaticPath <> '' 
             AND (
                 mast.PageURL = mm.StaticPath
                 OR
                 mast.PageURL LIKE '%' + mm.StaticPath + '%'
                 OR 
                 mast.PageURL LIKE '%' + REPLACE(REPLACE(mm.StaticPath, '/', ''), ' ', '') + '%'
                 OR
                 mast.PageURL = REPLACE(mm.StaticPath, '/', '')
             ))
        )
        WHERE mast.UserID IN (
            SELECT User_ID FROM User_Detail 
            WHERE (User_ID = @CustomerId OR ParentID = @CustomerId)
              AND Status = '1'
        )
        AND det.CreatedDate >= DATEADD(DAY, -@Days, GETDATE())
        AND (det.ImpersonatorID IS NULL OR det.ImpersonatorID = 0)
        AND mm.Active = 1
        AND mm.ModuleName NOT LIKE '%BI Dashboard%'
    ),
    -- Aggregate to parent level
    ParentAggregation AS (
        SELECT 
            CASE WHEN ParentModuleId IS NULL OR ParentModuleId = 0 
                 THEN ModuleId 
                 ELSE ParentModuleId 
            END AS ParentModuleId,
            SUM(ISNULL(SpendTime, 0)) / 3600.0 AS TotalHours
        FROM AllModuleEngagement
        GROUP BY 
            CASE WHEN ParentModuleId IS NULL OR ParentModuleId = 0 
                 THEN ModuleId 
                 ELSE ParentModuleId 
            END
    )
    SELECT 
        pa.ParentModuleId,
        mm.ModuleName AS ParentModuleName,
        CAST(pa.TotalHours AS DECIMAL(10,2)) AS TotalHours,
        CAST((pa.TotalHours / NULLIF(SUM(pa.TotalHours) OVER (), 0)) * 100 AS DECIMAL(5,2)) AS Percentage
    FROM ParentAggregation pa
    INNER JOIN TBL_UA_ModuleMaster mm ON pa.ParentModuleId = mm.ModuleId
    WHERE pa.TotalHours > 0
    ORDER BY pa.TotalHours DESC;
END;



