/* ============================================================
   Procedure: [dbo].[usp_rt_GetCustomerProfile]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER OFF

CREATE   PROCEDURE usp_rt_GetCustomerProfile
    @CustomerId BIGINT
AS
BEGIN
    SET NOCOUNT ON;
    SELECT 
        ud.User_ID AS CustomerId,
        ud.CompnayName AS CustomerName,
        ud.EMail AS Email,
        ud.Mobile AS Phone,
        ud.LastLogin1 AS LastLogin,
        DATEDIFF(DAY, ud.LastLogin1, GETDATE()) AS DaysSinceLogin,
        CASE 
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 7 THEN 85
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 30 THEN 70
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 60 THEN 50
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 90 THEN 30
            ELSE 10
        END AS HealthScore,
        'Not Available' AS RetentionExec,
        ISNULL(psd.Cost, 0) AS CurrentMRR,
        psd.PlanEndDate AS RenewalDate,
        DATEDIFF(DAY, GETDATE(), psd.PlanEndDate) AS DaysUntilRenewal,
        0 AS TotalUsers,
        0.0 AS AvgDailyMinutes,
        0 AS ModulesActive,
        0 AS TotalModules
    FROM User_Detail ud
    LEFT JOIN (
        SELECT UserID, MAX(PlanEndDate) AS PlanEndDate, SUM(Cost) AS Cost
        FROM Price_UserSubscriptionDetails
        WHERE IsNewPlan = 1 AND PlanEndDate >= GETDATE()
        GROUP BY UserID
    ) psd ON ud.User_ID = psd.UserID
    WHERE ud.User_ID = @CustomerId AND ud.User_ID = ud.ParentID AND ud.Status = '1';
END;
PRINT 'Fixed customer profile';



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetCustomerSubmoduleUsage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_rt_GetCustomerSubmoduleUsage
    @CustomerId BIGINT,
    @ParentModuleId BIGINT,
    @Days INT = 14
AS
BEGIN
    SET NOCOUNT ON;
    
    WITH SubmoduleEngagement AS (
        SELECT 
            mm.ModuleId,
            mm.ModuleName,
            det.CreatedDate,
            det.SpendTime
        FROM tbl_user_engagement_track_master mast
        INNER JOIN tbl_user_engagement_track_details det ON mast.EngagementID = det.UserEngMasterId
        INNER JOIN TBL_UA_ModuleMaster mm ON (
            -- Match web URLs (remove ~ prefix)
            (mm.URL IS NOT NULL 
             AND mm.URL <> '' 
             AND mm.URL <> '#' 
             AND mast.PageURL LIKE '%' + REPLACE(mm.URL, '~', '') + '%')
            OR
            -- Match mobile URLs using StaticPath
            (mm.StaticPath IS NOT NULL 
             AND mm.StaticPath <> '' 
             AND (
                 mast.PageURL = mm.StaticPath
                 OR
                 mast.PageURL LIKE '%' + mm.StaticPath + '%'
                 OR 
                 mast.PageURL LIKE '%' + REPLACE(REPLACE(mm.StaticPath, '/', ''), ' ', '') + '%'
                 OR
                 mast.PageURL = REPLACE(mm.StaticPath, '/', '')
             ))
        )
        WHERE mast.UserID IN (
            SELECT User_ID FROM User_Detail 
            WHERE (User_ID = @CustomerId OR ParentID = @CustomerId)
              AND Status = '1'
        )
        AND det.CreatedDate >= DATEADD(DAY, -@Days, GETDATE())
        AND (det.ImpersonatorID IS NULL OR det.ImpersonatorID = 0)
        AND mm.Active = 1
        AND mm.ParentModuleId = @ParentModuleId  -- Filter by parent module
        AND mm.ModuleName NOT LIKE '%BI Dashboard%'
    ),
    AggregatedSubmodules AS (
        SELECT 
            ModuleId,
            ModuleName,
            SUM(ISNULL(SpendTime, 0)) / 3600.0 AS TotalHours,
            COUNT(DISTINCT CAST(CreatedDate AS DATE)) AS DaysUsed,
            -- Week 1 (last 7 days)
            SUM(CASE WHEN CreatedDate >= DATEADD(DAY, -7, GETDATE()) 
                     THEN ISNULL(SpendTime, 0) ELSE 0 END) / 3600.0 AS Week1Hours,
            -- Week 2 (days 8-14)
            SUM(CASE WHEN CreatedDate BETWEEN DATEADD(DAY, -14, GETDATE()) AND DATEADD(DAY, -8, GETDATE()) 
                     THEN ISNULL(SpendTime, 0) ELSE 0 END) / 3600.0 AS Week2Hours
        FROM SubmoduleEngagement
        GROUP BY ModuleId, ModuleName
    )
    SELECT 
        ModuleId,
        ModuleName,
        CAST(TotalHours AS DECIMAL(10,2)) AS TotalHours,
        DaysUsed,
        CAST(Week1Hours AS DECIMAL(10,2)) AS Week1Hours,
        CAST(Week2Hours AS DECIMAL(10,2)) AS Week2Hours,
        -- Calculate trend
        CASE 
            WHEN Week2Hours = 0 AND Week1Hours > 0 THEN 'New'
            WHEN Week2Hours = 0 THEN 'Stable'
            WHEN ((Week1Hours - Week2Hours) / NULLIF(Week2Hours, 0)) >= 0.25 THEN 'Increasing'
            WHEN ((Week1Hours - Week2Hours) / NULLIF(Week2Hours, 0)) <= -0.25 THEN 'Decreasing'
            ELSE 'Stable'
        END AS Trend,
        -- Trend percentage
        CASE 
            WHEN Week2Hours = 0 THEN NULL
            ELSE CAST(((Week1Hours - Week2Hours) / NULLIF(Week2Hours, 0)) * 100 AS INT)
        END AS TrendPercentage,
        -- Trend icon for UI
        CASE 
            WHEN Week2Hours = 0 AND Week1Hours > 0 THEN '✨'
            WHEN ((Week1Hours - Week2Hours) / NULLIF(Week2Hours, 0)) >= 0.25 THEN '↑'
            WHEN ((Week1Hours - Week2Hours) / NULLIF(Week2Hours, 0)) <= -0.25 THEN '↓'
            ELSE '→'
        END AS TrendIcon
    FROM AggregatedSubmodules
    WHERE TotalHours > 0
    ORDER BY TotalHours DESC;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetExecutiveDashboard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER OFF


CREATE   PROCEDURE usp_rt_GetExecutiveDashboard
AS
BEGIN
    SET NOCOUNT ON;
    
    WITH CustomerHealth AS (
        SELECT 
            ud.User_ID,
            ISNULL(aam.AM_Name, 'Unassigned') AS RetentionExec,
            CASE 
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 7 THEN 85
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 30 THEN 70
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 60 THEN 50
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 90 THEN 30
                ELSE 10
            END AS HealthScore,
            DATEDIFF(DAY, ud.LastLogin1, GETDATE()) AS DaysSinceLogin,
            psd.Cost,
            psd.PlanEndDate
        FROM User_Detail ud
        INNER JOIN (
            SELECT UserID, MAX(PlanEndDate) AS PlanEndDate, SUM(Cost) AS Cost
            FROM Price_UserSubscriptionDetails
            WHERE IsNewPlan = 1 AND PlanEndDate >= GETDATE()
            GROUP BY UserID
        ) psd ON ud.User_ID = psd.UserID
        LEFT JOIN CRM.CRMDB.dbo.LinkedAccount la ON ud.User_ID = la.User_ID
        LEFT JOIN CRM.CRMDB.dbo.Assign_accountmanager_Latest aam ON la.RefrenceNo = aam.Refrence_No
        WHERE ud.User_ID = ud.ParentID AND ud.Status = '1' AND ud.IsInternalUser = 0
    ),
    ChurnedLast30d AS (
        SELECT 
            ISNULL(aam.AM_Name, 'Unassigned') AS RetentionExec,
            COUNT(DISTINCT psd.UserID) AS ChurnedCount
        FROM Price_UserSubscriptionDetails psd
        LEFT JOIN User_Detail ud ON psd.UserID = ud.User_ID
        LEFT JOIN CRM.CRMDB.dbo.LinkedAccount la ON ud.User_ID = la.User_ID
        LEFT JOIN CRM.CRMDB.dbo.Assign_accountmanager_Latest aam ON la.RefrenceNo = aam.Refrence_No
        WHERE psd.IsNewPlan = 1
          AND psd.PlanEndDate BETWEEN DATEADD(DAY, -30, GETDATE()) AND DATEADD(DAY, -1, GETDATE())
        GROUP BY aam.AM_Name
    )
    SELECT 
        ch.RetentionExec,
        COUNT(*) AS TotalAssigned,
        COUNT(CASE WHEN ch.HealthScore >= 70 THEN 1 END) AS HealthyAccounts,
        COUNT(CASE WHEN ch.HealthScore BETWEEN 40 AND 69 THEN 1 END) AS MediumRiskAccounts,
        COUNT(CASE WHEN ch.HealthScore < 40 THEN 1 END) AS HighRiskAccounts,
        COUNT(CASE WHEN ch.DaysSinceLogin BETWEEN 7 AND 90 THEN 1 END) AS AtRiskOfChurning,
        SUM(ch.Cost) AS TotalMRR,
        SUM(CASE WHEN ch.HealthScore < 40 THEN ch.Cost ELSE 0 END) AS MRRAtRisk,
        ISNULL(c30.ChurnedCount, 0) AS ChurnedLast30d,
        COUNT(CASE WHEN ch.DaysSinceLogin <= 7 THEN 1 END) AS HighUsage,
        COUNT(CASE WHEN ch.DaysSinceLogin BETWEEN 8 AND 30 THEN 1 END) AS MediumUsage,
        COUNT(CASE WHEN ch.DaysSinceLogin > 30 THEN 1 END) AS LowUsage
    FROM CustomerHealth ch
    LEFT JOIN ChurnedLast30d c30 ON ch.RetentionExec = c30.RetentionExec
    GROUP BY ch.RetentionExec, c30.ChurnedCount
    ORDER BY TotalAssigned DESC;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetHealthHeatmap]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER OFF


CREATE   PROCEDURE usp_rt_GetHealthHeatmap
    @SortBy NVARCHAR(50) = 'RenewalDate',
    @SortOrder NVARCHAR(4) = 'ASC',
    @MinHealthScore INT = 0,
    @MaxHealthScore INT = 100,
    @TopN INT = 100,
    @RetentionExecName NVARCHAR(100) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    WITH CustomerHealth AS (
        SELECT 
            ud.User_ID AS CustomerId,
            ud.CompnayName AS CustomerName,
            ISNULL(aam.AM_Name, 'Not Available') AS RetentionExec,
            CASE 
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 7 THEN 85
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 30 THEN 70
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 60 THEN 50
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 90 THEN 30
                ELSE 10
            END AS HealthScore,
            ISNULL(psd.Cost, 0) AS CurrentMRR,
            DATEDIFF(DAY, ud.LastLogin1, GETDATE()) AS DaysSinceLogin,
            ud.LastLogin1,
            psd.PlanEndDate AS RenewalDate,
            DATEDIFF(DAY, GETDATE(), psd.PlanEndDate) AS DaysUntilRenewal,
            0.0 AS AvgDailyMinutes
        FROM User_Detail ud
        INNER JOIN (
            -- Get only LATEST ACTIVE subscription
            SELECT 
                UserID,
                MAX(PlanEndDate) AS PlanEndDate,
                SUM(Cost) AS Cost
            FROM Price_UserSubscriptionDetails
            WHERE IsNewPlan = 1
              AND PlanEndDate >= GETDATE()  -- ACTIVE only
            GROUP BY UserID
        ) psd ON ud.User_ID = psd.UserID
        -- Join to CRM to get Retention Executive
        LEFT JOIN CRM.CRMDB.dbo.LinkedAccount la ON ud.User_ID = la.User_ID
        LEFT JOIN CRM.CRMDB.dbo.Assign_accountmanager_Latest aam ON la.RefrenceNo = aam.Refrence_No
        WHERE ud.User_ID = ud.ParentID
          AND ud.Status = '1'
          AND ud.IsInternalUser = 0
    )
    SELECT TOP (@TopN)
        CustomerId,
        CustomerName,
        RetentionExec,
        HealthScore,
        RenewalDate,
        CurrentMRR AS MRR,
        0 AS ModulesUsed,
        0 AS PremiumModulesUsed,
        LastLogin1 AS LastLogin,
        DaysSinceLogin AS DaysSinceLastLogin,
        AvgDailyMinutes,
        0.0 AS ChurnProbability,
        'null' AS ActionCTA
    FROM CustomerHealth
    WHERE HealthScore BETWEEN @MinHealthScore AND @MaxHealthScore
      AND (@RetentionExecName IS NULL OR RetentionExec = @RetentionExecName)
    ORDER BY 
        CASE WHEN @SortBy = 'RenewalDate' AND @SortOrder = 'ASC' THEN RenewalDate END ASC,
        CASE WHEN @SortBy = 'RenewalDate' AND @SortOrder = 'DESC' THEN RenewalDate END DESC,
        CASE WHEN @SortBy = 'HealthScore' AND @SortOrder = 'ASC' THEN HealthScore END ASC,
        CASE WHEN @SortBy = 'HealthScore' AND @SortOrder = 'DESC' THEN HealthScore END DESC,
        CASE WHEN @SortBy = 'CurrentMRR' AND @SortOrder = 'ASC' THEN CurrentMRR END ASC,
        CASE WHEN @SortBy = 'CurrentMRR' AND @SortOrder = 'DESC' THEN CurrentMRR END DESC,
        CASE WHEN @SortBy = 'CustomerName' AND @SortOrder = 'ASC' THEN CustomerName END ASC,
        CASE WHEN @SortBy = 'CustomerName' AND @SortOrder = 'DESC' THEN CustomerName END DESC;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetHealthHeatmap_v2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_rt_GetHealthHeatmap_v2
    @SortBy NVARCHAR(50) = 'RenewalDate',
    @SortOrder NVARCHAR(4) = 'ASC',
    @MinHealthScore INT = 0,
    @MaxHealthScore INT = 100,
    @TopN INT = 100,
    @RetentionExecName NVARCHAR(100) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    WITH 
    -- Get active users per parent (license utilization)
    ActiveUsersPerParent AS (
        SELECT 
            ParentID,
            COUNT(DISTINCT User_ID) AS ActiveChildUsers,
            MAX(LastLogin1) AS MostRecentChildLogin
        FROM User_Detail
        WHERE Status = '1' 
          AND IsInternalUser = 0
          AND ParentID <> User_ID
          AND DATEDIFF(DAY, LastLogin1, GETDATE()) <= 30
        GROUP BY ParentID
    ),
    -- Get licensed seat count
    LicensedSeats AS (
        SELECT 
            UserId,
            SUM(AllowUserCount) AS TotalLicenses
        FROM tbl_pt_AllowUserTransactions
        WHERE IsActive = 1
        GROUP BY UserId
    ),
    -- Get last 30 days usage data
    RecentUsage AS (
        SELECT 
            parentid,
            SUM(timeinMin) AS TotalMinutesLast30Days,
            COUNT(DISTINCT date_of_usage) AS DaysActiveLast30,
            AVG(CAST(timeinMin AS FLOAT)) AS AvgMinutesPerDay
        FROM user_daily_engagement
        WHERE date_of_usage >= DATEADD(DAY, -30, GETDATE())
        GROUP BY parentid
    ),
    -- Get previous 30 days for trend comparison
    PreviousUsage AS (
        SELECT 
            parentid,
            SUM(timeinMin) AS TotalMinutesPrev30Days
        FROM user_daily_engagement
        WHERE date_of_usage BETWEEN DATEADD(DAY, -60, GETDATE()) AND DATEADD(DAY, -31, GETDATE())
        GROUP BY parentid
    ),
    -- Calculate health scores
    CustomerHealth AS (
        SELECT 
            ud.User_ID AS CustomerId,
            ud.CompnayName AS CustomerName,
            ud.User_Login AS LoginName,
            ISNULL(aam.AM_Name, 'Not Available') AS RetentionExec,
            
            -- COMPONENT 1: Login Frequency (15 points max)
            CASE 
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 3 THEN 15
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 7 THEN 12
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 14 THEN 9
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 30 THEN 6
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 60 THEN 3
                ELSE 0
            END AS LoginFrequencyScore,
            
            -- COMPONENT 2: Usage Depth (30 points max)
            CASE 
                WHEN ISNULL(ru.TotalMinutesLast30Days, 0) >= 3000 THEN 30  -- 50+ hours/month
                WHEN ISNULL(ru.TotalMinutesLast30Days, 0) >= 1800 THEN 25  -- 30+ hours/month
                WHEN ISNULL(ru.TotalMinutesLast30Days, 0) >= 1200 THEN 20  -- 20+ hours/month
                WHEN ISNULL(ru.TotalMinutesLast30Days, 0) >= 600 THEN 15   -- 10+ hours/month
                WHEN ISNULL(ru.TotalMinutesLast30Days, 0) >= 300 THEN 10   -- 5+ hours/month
                WHEN ISNULL(ru.TotalMinutesLast30Days, 0) > 0 THEN 5
                ELSE 0
            END AS UsageDepthScore,
            
            -- COMPONENT 3: Module Adoption (20 points max) - will calculate based on distinct modules used
            CASE 
                WHEN ISNULL(ru.DaysActiveLast30, 0) >= 20 THEN 20  -- Used 20+ days
                WHEN ISNULL(ru.DaysActiveLast30, 0) >= 15 THEN 16  -- Used 15+ days
                WHEN ISNULL(ru.DaysActiveLast30, 0) >= 10 THEN 12  -- Used 10+ days
                WHEN ISNULL(ru.DaysActiveLast30, 0) >= 5 THEN 8    -- Used 5+ days
                WHEN ISNULL(ru.DaysActiveLast30, 0) > 0 THEN 4
                ELSE 0
            END AS ModuleAdoptionScore,
            
            -- COMPONENT 4: Engagement Trend (20 points max)
            CASE 
                WHEN ISNULL(pu.TotalMinutesPrev30Days, 0) = 0 AND ISNULL(ru.TotalMinutesLast30Days, 0) > 0 THEN 20  -- New/reactivated
                WHEN ISNULL(pu.TotalMinutesPrev30Days, 0) = 0 THEN 0  -- No usage at all
                WHEN (CAST(ISNULL(ru.TotalMinutesLast30Days, 0) AS FLOAT) / NULLIF(pu.TotalMinutesPrev30Days, 0)) >= 1.5 THEN 20  -- +50% growth
                WHEN (CAST(ISNULL(ru.TotalMinutesLast30Days, 0) AS FLOAT) / NULLIF(pu.TotalMinutesPrev30Days, 0)) >= 1.2 THEN 16  -- +20% growth
                WHEN (CAST(ISNULL(ru.TotalMinutesLast30Days, 0) AS FLOAT) / NULLIF(pu.TotalMinutesPrev30Days, 0)) >= 0.9 THEN 12  -- Stable
                WHEN (CAST(ISNULL(ru.TotalMinutesLast30Days, 0) AS FLOAT) / NULLIF(pu.TotalMinutesPrev30Days, 0)) >= 0.7 THEN 8   -- -30% decline
                WHEN (CAST(ISNULL(ru.TotalMinutesLast30Days, 0) AS FLOAT) / NULLIF(pu.TotalMinutesPrev30Days, 0)) >= 0.5 THEN 4   -- -50% decline
                ELSE 0  -- Severe decline
            END AS EngagementTrendScore,
            
            -- COMPONENT 5: License Utilization (15 points max)
            CASE 
                WHEN ISNULL(ls.TotalLicenses, 0) = 0 THEN 8  -- Trial users (no licenses) - neutral score
                WHEN (CAST(ISNULL(aup.ActiveChildUsers, 0) AS FLOAT) / NULLIF(ls.TotalLicenses, 0)) >= 0.8 THEN 15  -- 80%+ utilization
                WHEN (CAST(ISNULL(aup.ActiveChildUsers, 0) AS FLOAT) / NULLIF(ls.TotalLicenses, 0)) >= 0.6 THEN 12  -- 60%+ utilization
                WHEN (CAST(ISNULL(aup.ActiveChildUsers, 0) AS FLOAT) / NULLIF(ls.TotalLicenses, 0)) >= 0.4 THEN 9   -- 40%+ utilization
                WHEN (CAST(ISNULL(aup.ActiveChildUsers, 0) AS FLOAT) / NULLIF(ls.TotalLicenses, 0)) >= 0.2 THEN 6   -- 20%+ utilization
                WHEN ISNULL(aup.ActiveChildUsers, 0) > 0 THEN 3
                ELSE 0
            END AS LicenseUtilizationScore,
            
            -- Additional metrics
            ISNULL(psd.Cost, 0) AS CurrentMRR,
            DATEDIFF(DAY, ud.LastLogin1, GETDATE()) AS DaysSinceLogin,
            ud.LastLogin1,
            psd.PlanEndDate AS RenewalDate,
            DATEDIFF(DAY, GETDATE(), psd.PlanEndDate) AS DaysUntilRenewal,
            ISNULL(ru.AvgMinutesPerDay, 0) AS AvgDailyMinutes,
            ISNULL(ru.TotalMinutesLast30Days, 0) AS TotalMinutesLast30,
            ISNULL(ru.DaysActiveLast30, 0) AS DaysActiveLast30,
            ISNULL(aup.ActiveChildUsers, 0) AS ActiveUsers,
            ISNULL(ls.TotalLicenses, 0) AS LicensedSeats
        FROM User_Detail ud
        INNER JOIN (
            SELECT 
                UserID,
                MAX(PlanEndDate) AS PlanEndDate,
                SUM(Cost) AS Cost
            FROM Price_UserSubscriptionDetails
            WHERE IsNewPlan = 1
              AND PlanEndDate >= GETDATE()
            GROUP BY UserID
        ) psd ON ud.User_ID = psd.UserID
        LEFT JOIN CRM.CRMDB.dbo.LinkedAccount la ON ud.User_ID = la.User_ID
        LEFT JOIN CRM.CRMDB.dbo.Assign_accountmanager_Latest aam ON la.RefrenceNo = aam.Refrence_No
        LEFT JOIN ActiveUsersPerParent aup ON ud.User_ID = aup.ParentID
        LEFT JOIN LicensedSeats ls ON ud.User_ID = ls.UserId
        LEFT JOIN RecentUsage ru ON ud.User_ID = ru.parentid
        LEFT JOIN PreviousUsage pu ON ud.User_ID = pu.parentid
        WHERE ud.User_ID = ud.ParentID
          AND ud.Status = '1'
          AND ud.IsInternalUser = 0
    ),
    FinalHealthScore AS (
        SELECT 
            *,
            (LoginFrequencyScore + UsageDepthScore + ModuleAdoptionScore + 
             EngagementTrendScore + LicenseUtilizationScore) AS HealthScore,
            -- Churn probability based on health score
            CASE 
                WHEN (LoginFrequencyScore + UsageDepthScore + ModuleAdoptionScore + 
                      EngagementTrendScore + LicenseUtilizationScore) >= 80 THEN 10
                WHEN (LoginFrequencyScore + UsageDepthScore + ModuleAdoptionScore + 
                      EngagementTrendScore + LicenseUtilizationScore) >= 60 THEN 25
                WHEN (LoginFrequencyScore + UsageDepthScore + ModuleAdoptionScore + 
                      EngagementTrendScore + LicenseUtilizationScore) >= 40 THEN 50
                WHEN (LoginFrequencyScore + UsageDepthScore + ModuleAdoptionScore + 
                      EngagementTrendScore + LicenseUtilizationScore) >= 20 THEN 75
                ELSE 90
            END AS ChurnProbability
        FROM CustomerHealth
    )
    SELECT TOP (@TopN)
        CustomerId,
        CustomerName,
        LoginName,
        RetentionExec,
        HealthScore,
        ChurnProbability,
        RenewalDate,
        CurrentMRR AS MRR,
        DaysActiveLast30 AS ModulesUsed,  -- Approximate for now
        0 AS PremiumModulesUsed,
        LastLogin1 AS LastLogin,
        DaysSinceLogin AS DaysSinceLastLogin,
        AvgDailyMinutes,
        ActiveUsers,
        LicensedSeats,
        CAST((CAST(ActiveUsers AS FLOAT) / NULLIF(LicensedSeats, 0)) * 100 AS INT) AS LicenseUtilizationPct,
        TotalMinutesLast30,
        -- Action CTA based on health
        CASE 
            WHEN HealthScore < 40 THEN 'Urgent: Contact Now'
            WHEN HealthScore < 60 THEN 'Schedule Check-in'
            WHEN DaysUntilRenewal <= 30 THEN 'Renewal Follow-up'
            ELSE 'Monitor'
        END AS ActionCTA
    FROM FinalHealthScore
    WHERE HealthScore BETWEEN @MinHealthScore AND @MaxHealthScore
      AND (@RetentionExecName IS NULL OR RetentionExec = @RetentionExecName)
    ORDER BY 
        CASE WHEN @SortBy = 'RenewalDate' AND @SortOrder = 'ASC' THEN RenewalDate END ASC,
        CASE WHEN @SortBy = 'RenewalDate' AND @SortOrder = 'DESC' THEN RenewalDate END DESC,
        CASE WHEN @SortBy = 'HealthScore' AND @SortOrder = 'ASC' THEN HealthScore END ASC,
        CASE WHEN @SortBy = 'HealthScore' AND @SortOrder = 'DESC' THEN HealthScore END DESC,
        CASE WHEN @SortBy = 'CurrentMRR' AND @SortOrder = 'ASC' THEN CurrentMRR END ASC,
        CASE WHEN @SortBy = 'CurrentMRR' AND @SortOrder = 'DESC' THEN CurrentMRR END DESC,
        CASE WHEN @SortBy = 'CustomerName' AND @SortOrder = 'ASC' THEN CustomerName END ASC,
        CASE WHEN @SortBy = 'CustomerName' AND @SortOrder = 'DESC' THEN CustomerName END DESC;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetHealthHeatmap_v3]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER OFF


CREATE   PROCEDURE usp_rt_GetHealthHeatmap_v3
    @SortBy NVARCHAR(50) = 'RenewalDate',
    @SortOrder NVARCHAR(4) = 'ASC',
    @MinHealthScore INT = 0,
    @MaxHealthScore INT = 100,
    @TopN INT = 100,
    @RetentionExecName NVARCHAR(100) = NULL,
    @AccountType NVARCHAR(10) = 'ALL',  -- 'ALL', 'PAID', 'TRIAL'
    @CustomerId INT = NULL  -- NEW: Fetch single customer for fast 360 view
AS
BEGIN
    SET NOCOUNT ON;
    
    -- Create temp table for faster processing
    CREATE TABLE #CustomerHealth (
        CustomerId INT,
        CustomerName NVARCHAR(200),
        LoginName NVARCHAR(100),
        RetentionExec NVARCHAR(100),
        AccountType VARCHAR(10),
        LoginFrequencyScore INT,
        UsageDepthScore INT,
        ModuleAdoptionScore INT,
        EngagementTrendScore INT,
        LicenseUtilizationScore INT,
        HealthScore INT,
        ChurnProbability INT,
        RenewalDate DATETIME,
        MRR DECIMAL(18,2),
        ModulesUsed INT,
        LastLogin DATETIME,
        DaysSinceLastLogin INT,
        AvgDailyMinutes DECIMAL(10,2),
        ActiveUsers INT,
        LicensedSeats INT,
        TotalMinutesLast30 BIGINT,
        WebMinutesLast30 BIGINT,
        MobileMinutesLast30 BIGINT
    );

    -- Fast insert with simplified logic
    INSERT INTO #CustomerHealth
    SELECT 
        ud.User_ID AS CustomerId,
        ud.CompnayName AS CustomerName,
        ud.User_Login AS LoginName,
        ISNULL(aam.AM_Name, 'Not Available') AS RetentionExec,
        
        -- Account Type (TRIAL vs PAID)
        CASE 
            WHEN EXISTS (
                SELECT 1 FROM tbl_pt_AllowUserTransactions t 
                WHERE t.UserId = ud.User_ID AND t.IsActive = 1
            ) THEN 'PAID'
            ELSE 'TRIAL'
        END AS AccountType,
        
        -- COMPONENT 1: Login Frequency (15 points)
        CASE 
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 3 THEN 15
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 7 THEN 12
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 14 THEN 9
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 30 THEN 6
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 60 THEN 3
            ELSE 0
        END AS LoginFrequencyScore,
        
        -- COMPONENT 2: Usage Depth (30 points) - Simplified
        CASE 
            WHEN ISNULL(ru.TotalMins, 0) >= 3000 THEN 30
            WHEN ISNULL(ru.TotalMins, 0) >= 1800 THEN 25
            WHEN ISNULL(ru.TotalMins, 0) >= 1200 THEN 20
            WHEN ISNULL(ru.TotalMins, 0) >= 600 THEN 15
            WHEN ISNULL(ru.TotalMins, 0) >= 300 THEN 10
            WHEN ISNULL(ru.TotalMins, 0) > 0 THEN 5
            ELSE 0
        END AS UsageDepthScore,
        
        -- COMPONENT 3: Module Adoption (20 points)
        CASE 
            WHEN ISNULL(ru.DaysActive, 0) >= 20 THEN 20
            WHEN ISNULL(ru.DaysActive, 0) >= 15 THEN 16
            WHEN ISNULL(ru.DaysActive, 0) >= 10 THEN 12
            WHEN ISNULL(ru.DaysActive, 0) >= 5 THEN 8
            WHEN ISNULL(ru.DaysActive, 0) > 0 THEN 4
            ELSE 0
        END AS ModuleAdoptionScore,
        
        -- COMPONENT 4: Engagement Trend (20 points) - Simplified
        CASE 
            WHEN ISNULL(pu.PrevMins, 0) = 0 AND ISNULL(ru.TotalMins, 0) > 0 THEN 20
            WHEN ISNULL(pu.PrevMins, 0) = 0 THEN 0
            WHEN (CAST(ISNULL(ru.TotalMins, 0) AS FLOAT) / NULLIF(pu.PrevMins, 0)) >= 1.5 THEN 20
            WHEN (CAST(ISNULL(ru.TotalMins, 0) AS FLOAT) / NULLIF(pu.PrevMins, 0)) >= 1.2 THEN 16
            WHEN (CAST(ISNULL(ru.TotalMins, 0) AS FLOAT) / NULLIF(pu.PrevMins, 0)) >= 0.9 THEN 12
            WHEN (CAST(ISNULL(ru.TotalMins, 0) AS FLOAT) / NULLIF(pu.PrevMins, 0)) >= 0.7 THEN 8
            WHEN (CAST(ISNULL(ru.TotalMins, 0) AS FLOAT) / NULLIF(pu.PrevMins, 0)) >= 0.5 THEN 4
            ELSE 0
        END AS EngagementTrendScore,
        
        -- COMPONENT 5: License Utilization (15 points)
        CASE 
            WHEN ISNULL(ls.Licenses, 0) = 0 THEN 8  -- Trial (no licenses = 8 points)
            WHEN (CAST(ISNULL(au.ActiveCount, 0) AS FLOAT) / NULLIF(ls.Licenses, 0)) >= 0.8 THEN 15
            WHEN (CAST(ISNULL(au.ActiveCount, 0) AS FLOAT) / NULLIF(ls.Licenses, 0)) >= 0.6 THEN 12
            WHEN (CAST(ISNULL(au.ActiveCount, 0) AS FLOAT) / NULLIF(ls.Licenses, 0)) >= 0.4 THEN 9
            WHEN (CAST(ISNULL(au.ActiveCount, 0) AS FLOAT) / NULLIF(ls.Licenses, 0)) >= 0.2 THEN 6
            WHEN ISNULL(au.ActiveCount, 0) > 0 THEN 3
            ELSE 0
        END AS LicenseUtilizationScore,
        
        0 AS HealthScore,  -- Calculated below
        0 AS ChurnProbability,  -- Calculated below
        
        psd.PlanEndDate AS RenewalDate,
        ISNULL(psd.Cost, 0) AS MRR,
        ISNULL(ru.DaysActive, 0) AS ModulesUsed,
        ud.LastLogin1 AS LastLogin,
        DATEDIFF(DAY, ud.LastLogin1, GETDATE()) AS DaysSinceLastLogin,
        ISNULL(ru.AvgMins, 0) AS AvgDailyMinutes,
        ISNULL(au.ActiveCount, 0) AS ActiveUsers,
        ISNULL(ls.Licenses, 0) AS LicensedSeats,
        ISNULL(ru.TotalMins, 0) AS TotalMinutesLast30,
        ISNULL(ru.WebMins, 0) AS WebMinutesLast30,
        ISNULL(ru.MobileMins, 0) AS MobileMinutesLast30
        
    FROM User_Detail ud WITH (NOLOCK)
    
    -- Subscription data (optimized)
    INNER JOIN (
        SELECT UserID, MAX(PlanEndDate) AS PlanEndDate, SUM(Cost) AS Cost
        FROM Price_UserSubscriptionDetails WITH (NOLOCK)
        WHERE IsNewPlan = 1 AND PlanEndDate >= GETDATE()
        GROUP BY UserID
    ) psd ON ud.User_ID = psd.UserID
    
    -- Recent usage (optimized single query)
    LEFT JOIN (
        SELECT 
            parentid,
            SUM(timeinMin) AS TotalMins,
            SUM(CASE WHEN mode = 'Web' THEN timeinMin ELSE 0 END) AS WebMins,
            SUM(CASE WHEN mode = 'mobile' THEN timeinMin ELSE 0 END) AS MobileMins,
            COUNT(DISTINCT date_of_usage) AS DaysActive,
            AVG(CAST(timeinMin AS FLOAT)) AS AvgMins
        FROM user_daily_engagement WITH (NOLOCK)
        WHERE date_of_usage >= DATEADD(DAY, -30, GETDATE())
        GROUP BY parentid
    ) ru ON ud.User_ID = ru.parentid
    
    -- Previous period usage (optimized)
    LEFT JOIN (
        SELECT parentid, SUM(timeinMin) AS PrevMins
        FROM user_daily_engagement WITH (NOLOCK)
        WHERE date_of_usage BETWEEN DATEADD(DAY, -60, GETDATE()) AND DATEADD(DAY, -31, GETDATE())
        GROUP BY parentid
    ) pu ON ud.User_ID = pu.parentid
    
    -- Active users (optimized)
    LEFT JOIN (
        SELECT ParentID, COUNT(DISTINCT User_ID) AS ActiveCount
        FROM User_Detail WITH (NOLOCK)
        WHERE Status = '1' AND IsInternalUser = 0 AND ParentID <> User_ID
          AND DATEDIFF(DAY, LastLogin1, GETDATE()) <= 30
        GROUP BY ParentID
    ) au ON ud.User_ID = au.ParentID
    
    -- Licensed seats (optimized)
    LEFT JOIN (
        SELECT UserId, SUM(AllowUserCount) AS Licenses
        FROM tbl_pt_AllowUserTransactions WITH (NOLOCK)
        WHERE IsActive = 1
        GROUP BY UserId
    ) ls ON ud.User_ID = ls.UserId
    
    -- CSM assignment (optimized)
    LEFT JOIN CRM.CRMDB.dbo.LinkedAccount la WITH (NOLOCK) ON ud.User_ID = la.User_ID
    LEFT JOIN CRM.CRMDB.dbo.Assign_accountmanager_Latest aam WITH (NOLOCK) ON la.RefrenceNo = aam.Refrence_No
    
    WHERE ud.User_ID = ud.ParentID
      AND ud.Status = '1'
      AND ud.IsInternalUser = 0
      AND (@CustomerId IS NULL OR ud.User_ID = @CustomerId);  -- NEW: Single customer filter

    -- Update calculated fields
    UPDATE #CustomerHealth
    SET HealthScore = LoginFrequencyScore + UsageDepthScore + ModuleAdoptionScore + EngagementTrendScore + LicenseUtilizationScore;

    UPDATE #CustomerHealth
    SET ChurnProbability = CASE 
        WHEN HealthScore >= 70 THEN 10
        WHEN HealthScore >= 50 THEN 25
        WHEN HealthScore >= 30 THEN 60
        ELSE 90
    END;

    -- If fetching single customer, return immediately (fast path)
    IF @CustomerId IS NOT NULL
    BEGIN
        SELECT * FROM #CustomerHealth;
        DROP TABLE #CustomerHealth;
        RETURN;
    END;

    -- Apply filters (only for list view)
    DELETE FROM #CustomerHealth
    WHERE (@AccountType <> 'ALL' AND AccountType <> @AccountType)
       OR HealthScore < @MinHealthScore
       OR HealthScore > @MaxHealthScore;

    -- Return sorted results
    DECLARE @SQL NVARCHAR(MAX);
    SET @SQL = N'SELECT TOP (@TopN) * FROM #CustomerHealth ORDER BY ';
    
    IF @SortBy = 'HealthScore'
        SET @SQL = @SQL + N'HealthScore ' + @SortOrder;
    ELSE IF @SortBy = 'RenewalDate'
        SET @SQL = @SQL + N'RenewalDate ' + @SortOrder;
    ELSE IF @SortBy = 'MRR'
        SET @SQL = @SQL + N'MRR ' + @SortOrder;
    ELSE IF @SortBy = 'CustomerName'
        SET @SQL = @SQL + N'CustomerName ' + @SortOrder;
    ELSE
        SET @SQL = @SQL + N'RenewalDate ASC';

    EXEC sp_executesql @SQL, N'@TopN INT', @TopN = @TopN;

    DROP TABLE #CustomerHealth;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetHealthHeatmapCount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER OFF


CREATE   PROCEDURE usp_rt_GetHealthHeatmapCount
    @MinHealthScore INT = 0,
    @MaxHealthScore INT = 100,
    @RetentionExecName NVARCHAR(100) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    SELECT COUNT(*) AS TotalCount
    FROM User_Detail ud
    INNER JOIN (
        SELECT UserID, MAX(PlanEndDate) AS PlanEndDate
        FROM Price_UserSubscriptionDetails
        WHERE IsNewPlan = 1 AND PlanEndDate >= GETDATE()
        GROUP BY UserID
    ) psd ON ud.User_ID = psd.UserID
    LEFT JOIN CRM.CRMDB.dbo.LinkedAccount la ON ud.User_ID = la.User_ID
    LEFT JOIN CRM.CRMDB.dbo.Assign_accountmanager_Latest aam ON la.RefrenceNo = aam.Refrence_No
    WHERE ud.User_ID = ud.ParentID
      AND ud.Status = '1'
      AND ud.IsInternalUser = 0
      AND CASE 
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 7 THEN 85
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 30 THEN 70
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 60 THEN 50
            WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 90 THEN 30
            ELSE 10
          END BETWEEN @MinHealthScore AND @MaxHealthScore
      AND (@RetentionExecName IS NULL OR ISNULL(aam.AM_Name, 'Not Available') = @RetentionExecName);
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetModuleAdoptionMatrix]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- =============================================
-- SP 5: MODULE ADOPTION MATRIX  
-- =============================================
CREATE   PROCEDURE [dbo].[usp_rt_GetModuleAdoptionMatrix]
AS
BEGIN
    SET NOCOUNT ON;

    SELECT TOP 20
        ud.User_ID AS CustomerId,
        ISNULL(ud.CompnayName, 'Unknown') AS CustomerName,
        mm.ModuleName,
        CASE 
            WHEN COUNT(td.EngagementDetailID) >= 20 THEN 'Active'
            WHEN COUNT(td.EngagementDetailID) BETWEEN 5 AND 19 THEN 'Partial'
            ELSE 'Inactive'
        END AS AdoptionStatus,
        COUNT(td.EngagementDetailID) AS SessionCount
    FROM User_Detail ud
    CROSS JOIN TBL_UA_ModuleMaster mm
    LEFT JOIN tbl_user_engagement_track_master tm ON tm.PageURL LIKE '%' + mm.URL + '%'
    LEFT JOIN tbl_user_engagement_track_details td ON tm.EngagementID = td.UserEngMasterId
        AND td.CreatedDate >= DATEADD(DAY, -30, GETDATE())
        AND td.ImpersonatorID IS NULL
    INNER JOIN Price_UserSubscriptionDetails usd ON ud.User_ID = usd.UserID
    WHERE ud.User_ID = ud.ParentID
        AND ud.Status = '1'
        AND ud.IsInternalUser = 0
        AND usd.IsNewPlan = 1
        AND mm.Active = 1
    GROUP BY ud.User_ID, ud.CompnayName, mm.ModuleName
    ORDER BY ud.User_ID, mm.ModuleName;
END



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetTopKPIMetrics]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER OFF


CREATE   PROCEDURE usp_rt_GetTopKPIMetrics
    @RetentionExecName NVARCHAR(100) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    -- Get all customers with their latest active subscription
    WITH ActiveCustomers AS (
        SELECT 
            ud.User_ID,
            ud.CompnayName,
            ud.LastLogin1,
            DATEDIFF(DAY, ud.LastLogin1, GETDATE()) AS DaysSinceLogin,
            psd.PlanEndDate,
            psd.Cost,
            CASE 
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 7 THEN 85
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 30 THEN 70
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 60 THEN 50
                WHEN DATEDIFF(DAY, ud.LastLogin1, GETDATE()) <= 90 THEN 30
                ELSE 10
            END AS HealthScore
        FROM User_Detail ud
        INNER JOIN (
            -- Get only the LATEST ACTIVE subscription per user
            SELECT 
                UserID,
                MAX(PlanEndDate) AS PlanEndDate,
                SUM(Cost) AS Cost
            FROM Price_UserSubscriptionDetails
            WHERE IsNewPlan = 1
              AND PlanEndDate >= GETDATE()  -- ACTIVE subscriptions only
            GROUP BY UserID
        ) psd ON ud.User_ID = psd.UserID
        WHERE ud.User_ID = ud.ParentID
          AND ud.Status = '1'
          AND ud.IsInternalUser = 0
    ),
    ChurnedLast30d AS (
        -- Count subscriptions that expired in last 30 days
        SELECT COUNT(DISTINCT UserID) AS ChurnedCount
        FROM Price_UserSubscriptionDetails
        WHERE IsNewPlan = 1
          AND PlanEndDate BETWEEN DATEADD(DAY, -30, GETDATE()) AND DATEADD(DAY, -1, GETDATE())
    )
    SELECT 
        ISNULL(AVG(ac.HealthScore), 0) AS OverallHealthScore,
        COUNT(CASE WHEN ac.HealthScore < 40 THEN 1 END) AS AccountsAtRisk,
        ISNULL(SUM(CASE WHEN ac.HealthScore < 40 THEN ac.Cost ELSE 0 END), 0) AS MRRAtRisk,
        0 AS NRR,  -- Placeholder
        COUNT(CASE WHEN ac.DaysSinceLogin <= 30 THEN 1 END) AS ActiveAccounts30d,
        0 AS UpsellReadyAccounts,  -- Placeholder
        (SELECT ChurnedCount FROM ChurnedLast30d) AS ChurnedLast30d,
        0 AS TrialToPaidConversion,  -- Placeholder
        0 AS AvgChurnProbability,  -- Placeholder
        0 AS OpenHighPriorityTickets,  -- Placeholder
        GETDATE() AS CalculatedAt
    FROM ActiveCustomers ac;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_rt_GetUpsellOpportunities]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- ============================================
-- SIMPLIFIED UPSELL with AI - No Module_CustomerId dependency
-- ============================================
CREATE   PROCEDURE [dbo].[usp_rt_GetUpsellOpportunities]
    @TopN INT = 10,
    @RetentionExecName NVARCHAR(50) = NULL
AS
BEGIN
    SET NOCOUNT ON;

    -- Calculate engagement metrics and AI-based confidence
    WITH CustomerEngagement AS (
        SELECT 
            ud.User_ID,
            ud.CompnayName,
            ISNULL(usd.Cost, 0) AS CurrentMRR,
            DATEDIFF(DAY, ud.LastLogin1, GETDATE()) AS DaysSinceLogin,
            -- Daily engagement (last 30 days)
            ISNULL((SELECT AVG(timeinMin) 
             FROM user_daily_engagement ude 
             WHERE ude.parentid = ud.User_ID 
               AND ude.date_of_usage >= DATEADD(DAY, -30, GETDATE())), 0) AS AvgDailyMinutes,
            -- Session count (estimated from daily engagement)
            ISNULL((SELECT COUNT(DISTINCT date_of_usage) 
             FROM user_daily_engagement ude 
             WHERE ude.parentid = ud.User_ID 
               AND ude.date_of_usage >= DATEADD(DAY, -30, GETDATE())), 0) AS SessionsLast30d,
            -- Tenure
            DATEDIFF(MONTH, ISNULL(ud.DateCreated, usd.PlanStartDate), GETDATE()) AS TenureMonths,
            -- Account age
            DATEDIFF(DAY, usd.PlanStartDate, GETDATE()) AS AccountAgeDays
        FROM User_Detail ud
        INNER JOIN Price_UserSubscriptionDetails usd ON ud.User_ID = usd.UserID
        WHERE ud.User_ID = ud.ParentID
            AND ud.Status = '1'
            AND ud.IsInternalUser = 0
            AND usd.IsNewPlan = 1
            AND (
                usd.PlanEndDate >= CAST(GETDATE() AS DATE)
                OR usd.PlanEndDate >= DATEADD(DAY, -30, CAST(GETDATE() AS DATE))
            )
            AND usd.Cost > 2000
    )
    SELECT TOP (@TopN)
        ce.User_ID AS CustomerId,
        ISNULL(NULLIF(RTRIM(LTRIM(ce.CompnayName)), ''), 'Company-' + CAST(ce.User_ID AS NVARCHAR)) AS CustomerName,
        ISNULL(aam.AM_Name, 'Unassigned') AS RetentionExec,
        ce.CurrentMRR,
        'Sales, Marketing' AS ModulesUsed,
        -- Suggest upgrades based on MRR tier
        CASE 
            WHEN ce.CurrentMRR < 5000 THEN 'WhatsApp, Telephony'
            WHEN ce.CurrentMRR < 10000 THEN 'Advanced Analytics, Automation'
            ELSE 'Enterprise Suite, API Access'
        END AS MissingModules,
        -- AI-based estimated uplift (based on similar customer patterns)
        CASE 
            WHEN ce.CurrentMRR > 5000 AND ce.AvgDailyMinutes > 30 THEN ce.CurrentMRR * 0.45
            WHEN ce.CurrentMRR > 3000 AND ce.AvgDailyMinutes > 20 THEN ce.CurrentMRR * 0.35
            WHEN ce.CurrentMRR > 2000 AND ce.SessionsLast30d > 50 THEN ce.CurrentMRR * 0.30
            ELSE ce.CurrentMRR * 0.20
        END AS EstimatedUplift,
        -- AI-based confidence score (multiple factors)
        CAST(
            -- Base confidence (30 points)
            30.0
            -- Engagement factor (30 points max)
            + CASE 
                WHEN ce.AvgDailyMinutes > 30 THEN 30.0
                WHEN ce.AvgDailyMinutes > 15 THEN 20.0
                WHEN ce.AvgDailyMinutes > 5 THEN 10.0
                ELSE 0.0
              END
            -- Activity factor (20 points max)
            + CASE 
                WHEN ce.DaysSinceLogin <= 3 THEN 20.0
                WHEN ce.DaysSinceLogin <= 7 THEN 15.0
                WHEN ce.DaysSinceLogin <= 14 THEN 10.0
                ELSE 0.0
              END
            -- Tenure factor (10 points max)
            + CASE 
                WHEN ce.TenureMonths >= 12 THEN 10.0
                WHEN ce.TenureMonths >= 6 THEN 7.0
                WHEN ce.TenureMonths >= 3 THEN 4.0
                ELSE 0.0
              END
            -- MRR factor (10 points max) - higher paying customers more likely to upgrade
            + CASE 
                WHEN ce.CurrentMRR > 10000 THEN 10.0
                WHEN ce.CurrentMRR > 5000 THEN 7.0
                WHEN ce.CurrentMRR > 3000 THEN 4.0
                ELSE 0.0
              END
        AS DECIMAL(5,2)) AS ConfidenceScore,
        -- AI-generated justification (explains confidence)
        'Engagement: ' + 
        CASE 
            WHEN ce.AvgDailyMinutes > 30 THEN 'Excellent (' + CAST(CAST(ce.AvgDailyMinutes AS INT) AS NVARCHAR) + ' min/day)'
            WHEN ce.AvgDailyMinutes > 15 THEN 'Good (' + CAST(CAST(ce.AvgDailyMinutes AS INT) AS NVARCHAR) + ' min/day)'
            WHEN ce.AvgDailyMinutes > 5 THEN 'Moderate (' + CAST(CAST(ce.AvgDailyMinutes AS INT) AS NVARCHAR) + ' min/day)'
            ELSE 'Low (<5 min/day)'
        END +
        ' | Activity: ' + 
        CASE
            WHEN ce.DaysSinceLogin <= 3 THEN 'Very Active (logged in today)'
            WHEN ce.DaysSinceLogin <= 7 THEN 'Active (this week)'
            WHEN ce.DaysSinceLogin <= 14 THEN 'Moderate (2 weeks)'
            ELSE 'Low (14+ days)'
        END +
        ' | Sessions: ' + CAST(ce.SessionsLast30d AS NVARCHAR) + ' (30d)' +
        ' | Tenure: ' + CAST(ce.TenureMonths AS NVARCHAR) + ' months' +
        ' | MRR Tier: ' + 
        CASE
            WHEN ce.CurrentMRR > 10000 THEN 'Enterprise'
            WHEN ce.CurrentMRR > 5000 THEN 'Premium'
            WHEN ce.CurrentMRR > 3000 THEN 'Professional'
            ELSE 'Standard'
        END AS ConfidenceJustification,
        -- Personalized CTA based on profile
        CASE 
            WHEN ce.AvgDailyMinutes > 20 THEN 'Schedule premium demo - power user detected'
            WHEN ce.CurrentMRR > 5000 THEN 'Present enterprise tier - ready for upgrade'
            WHEN ce.SessionsLast30d > 50 THEN 'Introduce automation - frequent user'
            WHEN ce.TenureMonths >= 12 THEN 'Loyalty upgrade offer - long-term customer'
            ELSE 'Send feature discovery email'
        END AS SuggestedCTA
    FROM CustomerEngagement ce
    LEFT JOIN CRM.CRMDB.dbo.LinkedAccount la ON ce.User_ID = la.User_ID
    LEFT JOIN (
        SELECT Refrence_No, AM_Name, 
               ROW_NUMBER() OVER (PARTITION BY Refrence_No ORDER BY AM_ID DESC) AS RowNum
        FROM CRM.CRMDB.dbo.Assign_AccountManager
    ) aam ON la.RefrenceNo = aam.Refrence_No AND aam.RowNum = 1
    WHERE ce.DaysSinceLogin <= 14
        AND (@RetentionExecName IS NULL OR aam.AM_Name = @RetentionExecName)
    ORDER BY EstimatedUplift DESC;
END



GO

/* ============================================================
   Procedure: [dbo].[usp_rtp_CallReportDashboardCount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_rtp_CallReportDashboardCount] (
	@UserId BIGINT
	,@fromdate NVARCHAR(50)
	,@todate NVARCHAR(50)
	)
AS
BEGIN
	
	--DECLARE @UserId bigint = 40898, @fromdate DATE ='July 18, 2024', @todate DATE ='July 18, 2024'
	
	drop table if exists #tempUsers123
	create table #tempUsers123(User_ID bigint, Name nvarchar(255), Image nvarchar(255))
	insert into #tempUsers123(User_ID, Name, Image)
	exec Use_GetUserDetails @UserID = @UserId
	
	DECLARE @ParentId BIGINT, @isadmin INT;

	SELECT @parentid = ParentID
		,@isadmin = IsAdmin
	FROM MySMS.dbo.User_Detail(NOLOCK)
	WHERE User_ID = @UserId;

	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(500) = ''

	SELECT @TeamCode = TeamCode
		,@ScopeCode = ScopeCode
		,@UserIdTeamLst = UserIdTeamLst
	FROM MySMS.dbo.ufn_GetUserRoleScope(@UserId)

	DECLARE @OutgoingCount INT = 0
		,@IncomingCount INT = 0
		,@MissedByAgentCount INT = 0
		,@AnsweredByAgentCount INT = 0
		,@MissedByClientCount INT = 0
		,@AnsweredByClientCount INT = 0
		,@TimeoutCallCount INT = 0
		,@TotalAgentDurationOutgoing INT = 0
		,@TotalAgentDurationIncoming INT = 0


	SELECT @OutgoingCount = Count(*)
	FROM calendar(NOLOCK) ca
	LEFT JOIN CallLog(NOLOCK) c ON cast(c.callcreatedon AS DATE) = cast(ca.start_dts AS DATE)
	--inner JOIN #tempUsers123(nolock) u on c.agentuserid = u.User_Id
	WHERE cast(ca.start_dts as date) between cast(@fromdate as date) AND cast(@todate as date)
		AND c.parentid = @ParentId
		AND c.Direction IN ('Outgoing', 'out')
		AND 1 = (
			CASE 
				WHEN @isadmin = 1
					THEN 1
				WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from #tempUsers123)
					THEN 1
				WHEN isnull(c.agentuserid, 0) = @UserId
					THEN 1
				ELSE 0
				END
			)

	SELECT @IncomingCount = Count(*)
	FROM calendar(NOLOCK) ca
