/* ============================================================
   Procedure: [dbo].[usp_rtp_CallReportDashboardCount_Cache]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_rtp_CallReportDashboardCount_Cache] (
	@UserId BIGINT,
	@fromdate NVARCHAR(50),
	@todate NVARCHAR(50)
	)
AS
BEGIN

	DECLARE @MonthStart DATETIME;
	DECLARE @MonthEnd DATETIME;
	DECLARE @ParentID bigint = 0;		

			select @ParentID = ParentID from Mysms.[dbo].User_Detail(nolock) where User_ID = @UserId;

				-- Get the first and last date of the current month
				--SET @MonthStart = DATEADD(DAY, 1 - DAY(GETDATE()), CAST(GETDATE() AS DATE)); -- First day of current month
				--SET @MonthEnd = EOMONTH(GETDATE()); -- Last day of current month

				Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			    SET @MonthStart      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
				SET @MonthEnd  =  DATEADD(DAY, -1, @Currentdate);	

				-- Check conditions and select data
				IF (@FromDate Between @MonthStart AND @MonthEnd AND @ToDate Between @MonthStart AND @MonthEnd)
					BEGIN
						SELECT [CallReportDashboardCountId]
						  ,[OutgoingCount]
						  ,[IncomingCount]
						  ,[MissedByAgentCount]
						  ,[AnsweredByAgentCount]
						  ,[MissedByClientCount]
						  ,[AnsweredByClientCount]
						  ,[TimeoutCallCount]
						  ,[TotalAgentDurationOutgoing]
						  ,[TotalAgentDurationIncoming]
						  ,[UserId]
						  ,[ParentId]
					  FROM [dbo].[tbl_CallReportDashboardCount_Cache](nolock)
						WHERE [UserId] = @UserId
					END
				ELSE IF (@FromDate < @MonthStart OR @ToDate < @MonthStart)
					BEGIN
						SELECT [CallReportDashboardCountId]
						  ,[OutgoingCount]
						  ,[IncomingCount]
						  ,[MissedByAgentCount]
						  ,[AnsweredByAgentCount]
						  ,[MissedByClientCount]
						  ,[AnsweredByClientCount]
						  ,[TimeoutCallCount]
						  ,[TotalAgentDurationOutgoing]
						  ,[TotalAgentDurationIncoming]
						  ,[UserId]
						  ,[ParentId]
					  FROM [dbo].[tbl_CallReportDashboardCount_Archive](nolock)
						WHERE [UserId] = @UserId 
					END
				ELSE
					BEGIN
						EXEC [Mysms].[dbo].usp_rtp_CallReportDashboardCount @UserId, @FromDate, @ToDate;
					END

END



