/* ============================================================
   Procedure: [dbo].[usp_rtp_GetAgentCallSummaries]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_rtp_GetAgentCallSummaries]
(
	@fromdate NVARCHAR(50) = NULL, 
	@todate   NVARCHAR(50) = NULL, 
	@UserId   BIGINT
)
AS
    BEGIN

        -- declare @fromdate nvarchar(50)='20220513' , @todate nvarchar(50)='20220531', @UserId bigint=34225
		declare @ParentId bigint,@isadmin int;                                              
		select @parentid=ParentID,@isadmin=IsAdmin  from MySMS.dbo.User_Detail(nolock) where User_ID = @UserId;                      

		declare @TeamCode varchar(10) = ''  
		declare @ScopeCode varchar(10) = ''   
		declare @UserIdTeamLst varchar(500) = ''   
		select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from MySMS.dbo.ufn_GetUserRoleScope(@UserId)   


        select c.parentid, 
               CAST(callcreatedon AS DATE) AS Date, 
               ISNULL(user_login, 'Agent No changed') AS Agent, 
               SUM(CASE
                       WHEN direction = 'Outgoing'
                       THEN 1
                       ELSE 0
                   END) AS Outgoingcalls, 
               SUM(CASE
                       WHEN direction = 'Incoming'
                       THEN 1
                       ELSE 0
                   END) AS Incomingcalls, 
               SUM(CASE
                       WHEN direction = 'Outgoing'
                       THEN Calldurationseconds
                       ELSE 0
                   END) AS Outgoingduration, 
               SUM(CASE
                       WHEN direction = 'Incoming'
                       THEN Calldurationseconds
                       ELSE 0
                   END) AS Incomingduration, 
               SUM(CASE
                       WHEN ISNULL(agentcalldisposition, '') <> 'Answered'
                            AND direction = 'Incoming'
                       THEN 1
                       ELSE 0
                   END) MissedCalls, 
               SUM(calldurationseconds) TotalDuration
        FROM calendar(NOLOCK) ca
             LEFT JOIN calllog(NOLOCK) c ON CAST(c.callcreatedon AS DATE) = CAST(ca.start_dts AS DATE)
             LEFT JOIN user_detail u(NOLOCK) ON c.agentuserid = u.User_ID
        WHERE start_dts BETWEEN @fromdate AND @todate
              AND c.parentid = @parentid and 1 = (case when @isadmin=1 then 1
					when isnull(c.agentuserid, 0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ','))
						then 1
					when isnull(c.agentuserid, 0) = @UserId then 1
						else 0 end )
        GROUP BY CAST(callcreatedon AS DATE), 
                 user_login, 
                 c.parentid, 
                 CAST(ca.start_dts AS DATE)
        ORDER BY c.parentid, 
                 CAST(callcreatedon AS DATE) DESC;
    END;



GO

/* ============================================================
