 @UserId   BIGINT  
)  
AS  
    BEGIN  
  
        -- declare @fromdate nvarchar(50)='20220513' , @todate nvarchar(50)='20220531', @UserId bigint=34225  
  declare @ParentId bigint,@isadmin int;                                                
  select @parentid=ParentID,@isadmin=IsAdmin  from MySMS.dbo.User_Detail(nolock) where User_ID = @UserId;                        
  
  declare @TeamCode varchar(10) = ''    
  declare @ScopeCode varchar(10) = ''     
  declare @UserIdTeamLst varchar(500) = ''     
  select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from MySMS.dbo.ufn_GetUserRoleScope(@UserId)     
  
  
        select c.parentid,   
               CAST(callcreatedon AS DATE) AS Date,   
               ISNULL(AgentName, 'Agent No changed') AS Agent,   
               SUM(CASE  
                       WHEN direction = 'Outgoing'  
                       THEN 1  
                       ELSE 0  
                   END) AS Outgoingcalls,   
               SUM(CASE  
                       WHEN direction = 'Incoming'  
                       THEN 1  
                       ELSE 0  
                   END) AS Incomingcalls,   
               SUM(CASE  
                       WHEN direction = 'Outgoing'  
                       THEN Calldurationseconds  
                       ELSE 0  
                   END) AS Outgoingduration,   
               SUM(CASE  
                       WHEN direction = 'Incoming'  
                       THEN Calldurationseconds  
                       ELSE 0  
                   END) AS Incomingduration,   
               SUM(CASE  
                       WHEN ISNULL(agentcalldisposition, '') <> 'Answered'  
                            AND direction = 'Incoming'  
                       THEN 1  
                       ELSE 0  
                   END) MissedCalls,   
               SUM(calldurationseconds) TotalDuration  
        FROM calendar(NOLOCK) ca  
             LEFT JOIN calllog(NOLOCK) c ON CAST(c.callcreatedon AS DATE) = CAST(ca.start_dts AS DATE)  
             LEFT JOIN calling_agents u(NOLOCK) ON c.calling_agentid = u.ID  
        WHERE start_dts BETWEEN @fromdate AND @todate  
              AND c.parentid = @parentid and 1 = (case when @isadmin=1 then 1  
     when isnull(u.kit19userid, 0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ','))  
      then 1  
     when isnull(u.kit19userid, 0) = @UserId then 1  
      else 0 end )  
        GROUP BY CAST(callcreatedon AS DATE),   
                 Agentname,   
                 c.parentid,   
                 CAST(ca.start_dts AS DATE)  
        ORDER BY c.parentid,   
                 CAST(callcreatedon AS DATE) DESC;  
    END;  


GO

/* ============================================================
   Procedure: [dbo].[usp_rtp_GetAgentCallSummaryReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_rtp_GetAgentCallSummaryReport] (
	@fromdate NVARCHAR(50)
	,@todate NVARCHAR(50)
	,@CallDirection NVARCHAR(255) = ''
	,@AgentDisposition NVARCHAR(255) = ''
	,@CustomerDisposition NVARCHAR(255) = ''
	,@UserId BIGINT
	,@OffsetValue INT = 0
	,@PagingSize INT = 100
	,@OrderColumn INT = 0
	,@OrderDir NVARCHAR(10) = 'asc'
	)
AS
BEGIN

	--declare
	--	@fromdate nvarchar(50)='January 10, 2024' ,
	--	@todate nvarchar(50)='January 16, 2024',
	--	@UserId bigint=43740,
	--	@OffsetValue int = 0,
	--	@PagingSize int  = 100, 
	--	@CallDirection NVARCHAR(255) = '', 
	--	@AgentDisposition      NVARCHAR(255) = '', 
	--	@CustomerDisposition      NVARCHAR(255) = '', 
	--	@OrderColumn INT          = 0, 
	--	@OrderDir    NVARCHAR(10) = 'asc'


	DECLARE @parentid BIGINT = 0;
	SELECT @parentid = ParentID FROM User_Detail(NOLOCK) WHERE User_ID = @UserId;

	DECLARE @OrderColumnName NVARCHAR(255) = 'Date'

	SET @OrderColumnName = CASE @OrderColumn
			WHEN 0
				THEN 'Date'
			WHEN 1
				THEN 'Agent'
			WHEN 2
				THEN 'Outgoingcalls'
			WHEN 3
				THEN 'Incomingcalls'
			WHEN 4
				THEN 'Outgoingduration'
			WHEN 5
				THEN 'Incomingduration'
			WHEN 6
				THEN 'MissedCalls'
			WHEN 7
				THEN 'TotalDuration'
			ELSE 'Date'
			END
	SET @AgentDisposition = ( SELECT STRING_AGG(CONCAT ( '''', [value], ''''), ',') FROM fn_Split(@AgentDisposition, ','))
	SET @CustomerDisposition = (SELECT STRING_AGG(CONCAT ('''', [value], ''''), ',') FROM fn_Split(@CustomerDisposition, ','))

	drop table if exists #tempUsers  
	create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
	insert into #tempUsers(User_ID, Name, Image)  
	exec Use_GetUserDetails @UserID = @UserId  

	DECLARE @SqlQuery NVARCHAR(max) = CONCAT (
	--		' declare @ParentId bigint,@isadmin int;  select @parentid=ParentID,@isadmin=IsAdmin from MySMS.dbo.User_Detail(nolock) where User_ID = '
	--		,@UserId
	--		,';   declare @TeamCode varchar(10) = ''''  declare @ScopeCode varchar(10) = '''' declare @UserIdTeamLst varchar(500) = ''''   
	--select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from MySMS.dbo.ufn_GetUserRoleScope('
	--		,@UserId
	--		,
	--		')
	'SELECT * FROM ( SELECT COUNT(*) OVER() AS TotalRow,  c.parentid, 
            CAST(callcreatedon AS DATE) AS Date,  ISNULL(user_login, ''Agent not attempted'') AS Agent, 
            SUM(CASE WHEN direction = ''Outgoing'' THEN 1
                    ELSE 0  END) AS Outgoingcalls, 
            SUM(CASE WHEN direction = ''Incoming'' THEN 1
                    ELSE 0 END) AS Incomingcalls, 
            SUM(CASE WHEN direction = ''Outgoing'' THEN Calldurationseconds
                    ELSE 0  END) AS Outgoingduration, 
            SUM(CASE WHEN direction = ''Incoming'' THEN Calldurationseconds
                    ELSE 0 END) AS Incomingduration, 
            SUM(CASE WHEN ISNULL(agentcalldisposition, '''') <> ''Answered'' AND direction = ''Incoming''
                    THEN 1 ELSE 0 END) MissedCalls, 
            SUM(calldurationseconds) TotalDuration FROM calendar(NOLOCK) ca
        LEFT JOIN calllog(NOLOCK) c ON CAST(c.callcreatedon AS DATE) = CAST(ca.start_dts AS DATE)
		inner join #tempUsers(nolock) tl on c.agentuserid = tl.User_Id 
        LEFT JOIN user_detail u(NOLOCK) ON c.agentuserid = u.User_ID
        WHERE start_dts BETWEEN '''
			,@fromdate
			,''' AND '''
			,@todate
			,''' AND c.parentid = ', @parentid

			--,' and 1 = (case when @isadmin=1 then 1
			--		when isnull(c.agentuserid, 0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, '','')) then 1 when isnull(c.agentuserid, 0) = '
			--,@UserId ,' then 1 else 0 end )'

			,iif(isnull(@CustomerDisposition, '') <> '', CONCAT ( ' and c.customercalldisposition in (', @CustomerDisposition, ')' ), '')
			,iif(isnull(@AgentDisposition, '') <> '', CONCAT (
					' and c.agentcalldisposition in ('
					,@AgentDisposition
					,')'
					), '')
			,' GROUP BY CAST(callcreatedon AS DATE), user_login, c.parentid, CAST(ca.start_dts AS DATE) ) t  ORDER BY '
			,@OrderColumnName
			,' '
			,@OrderDir
			,' OFFSET '
			,@OffsetValue
			,' ROWS FETCH NEXT '
			,@PagingSize
			,' ROWS ONLY '
			) --c.parentid, 

	PRINT @SqlQuery

	EXEC sp_executesql @sqlQuery

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_Call_rpt'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'calendar'

END



GO

/* ============================================================
   Procedure: [dbo].[usp_rtp_GetAgentCallSummaryReport_Cache]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_rtp_GetAgentCallSummaryReport_Cache]
(
    @fromdate NVARCHAR(50),
    @todate NVARCHAR(50),
    @CallDirection NVARCHAR(255) = '',
    @AgentDisposition NVARCHAR(255) = '',
    @CustomerDisposition NVARCHAR(255) = '',
    @UserId BIGINT,
    @OffsetValue INT = 0,
    @PagingSize INT = 100,
    @OrderColumn INT = 0,
    @OrderDir NVARCHAR(10) = 'asc'
)
AS
BEGIN
    DECLARE @MonthStart DATE;
    DECLARE @MonthEnd DATE;
    DECLARE @ParentID BIGINT = 0;
    DECLARE @SqlQuery NVARCHAR(MAX);

    -- Get ParentID for the given UserId
    SELECT @ParentID = ParentID 
    FROM Mysms.[dbo].User_Detail WITH (NOLOCK) 
    WHERE User_ID = @UserId;

    -- Get the first and last date of the current month
    --SET @MonthStart = DATEADD(DAY, 1 - DAY(GETDATE()), CAST(GETDATE() AS DATE)); -- First day of current month
    --SET @MonthEnd = EOMONTH(GETDATE()); -- Last day of current month

	Declare @Currentdate  DATE  = GETDATE();  -- Today's date
	SET @MonthStart      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
	SET @MonthEnd  = DATEADD(DAY, -1, @Currentdate);	

    DECLARE @OrderColumnName NVARCHAR(255) = 'Date';

    -- Set OrderColumnName based on input value
    SET @OrderColumnName = CASE @OrderColumn
        WHEN 0 THEN 'Date'
        WHEN 1 THEN 'Agent'
        WHEN 2 THEN 'Outgoingcalls'
        WHEN 3 THEN 'Incomingcalls'
        WHEN 4 THEN 'Outgoingduration'
        WHEN 5 THEN 'Incomingduration'
        WHEN 6 THEN 'MissedCalls'
        WHEN 7 THEN 'TotalDuration'
        ELSE 'Date'
    END;

    -- Prepare the AgentDisposition and CustomerDisposition filters
    -- Split the input strings and concatenate properly
    SET @AgentDisposition = (
        SELECT STRING_AGG(CONCAT('''', [value], ''''), ',') 
        FROM [Mysms].[dbo].fn_Split(@AgentDisposition, ',')
    );

    SET @CustomerDisposition = (
        SELECT STRING_AGG(CONCAT('''', [value], ''''), ',') 
        FROM [Mysms].[dbo].fn_Split(@CustomerDisposition, ',')
    );

    -- Check conditions and select data
    IF (@FromDate Between @MonthStart AND @MonthEnd AND @ToDate Between @MonthStart AND @MonthEnd)
    BEGIN
        -- Construct the SQL query for the current data
        SET @SqlQuery = N'SELECT c.TotalRow, c.parentid, c.Date, 
                            ISNULL(user_login, ''Agent not attempted'') AS Agent, 
                            SUM(CASE WHEN direction = ''Outgoing'' THEN 1 ELSE 0 END) AS Outgoingcalls, 
                            SUM(CASE WHEN direction = ''Incoming'' THEN 1 ELSE 0 END) AS Incomingcalls, 
                            SUM(CASE WHEN direction = ''Outgoing'' THEN calldurationseconds ELSE 0 END) AS Outgoingduration, 
                            SUM(CASE WHEN direction = ''Incoming'' THEN calldurationseconds ELSE 0 END) AS Incomingduration, 
                            SUM(CASE WHEN ISNULL(agentcalldisposition, '''') <> ''Answered'' AND direction = ''Incoming'' THEN 1 ELSE 0 END) AS MissedCalls, 
                            SUM(calldurationseconds) TotalDuration
                        FROM tbl_CallReport_Cache c
                        LEFT JOIN Mysms.[dbo].user_detail u WITH (NOLOCK) ON c.UserId = u.User_ID
                        WHERE c.UserId = @UserId 
                        AND c.Date BETWEEN @fromdate AND @todate
                        AND c.parentid = @UserId';

        -- Add filters for CallDirection, AgentDisposition, and CustomerDisposition if provided
        IF (ISNULL(@CallDirection, '') <> '')
        BEGIN
            SET @SqlQuery = @SqlQuery + N' AND c.direction = @CallDirection';
        END;

        IF (ISNULL(@AgentDisposition, '') <> '')
        BEGIN
            SET @SqlQuery = @SqlQuery + N' AND c.agentcalldisposition IN (' + @AgentDisposition + ')';
        END;

        IF (ISNULL(@CustomerDisposition, '') <> '')
        BEGIN
            SET @SqlQuery = @SqlQuery + N' AND c.customercalldisposition IN (' + @CustomerDisposition + ')';
        END;

        -- Add GROUP BY, ORDER BY, and pagination clauses
        SET @SqlQuery = @SqlQuery + N' GROUP BY c.Date, user_login, c.parentid, c.TotalRow
                                     ORDER BY ' + @OrderColumnName + N' ' + @OrderDir + N'
                                     OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY';
    END
    ELSE IF (@FromDate < @MonthStart OR @ToDate < @MonthStart)
    BEGIN
        -- Similar query for archived data if the condition is not met
        SET @SqlQuery = N'SELECT c.TotalRow, c.parentid, c.Date, 
                            ISNULL(user_login, ''Agent not attempted'') AS Agent, 
                            SUM(CASE WHEN direction = ''Outgoing'' THEN 1 ELSE 0 END) AS Outgoingcalls, 
                            SUM(CASE WHEN direction = ''Incoming'' THEN 1 ELSE 0 END) AS Incomingcalls, 
                            SUM(CASE WHEN direction = ''Outgoing'' THEN calldurationseconds ELSE 0 END) AS Outgoingduration, 
                            SUM(CASE WHEN direction = ''Incoming'' THEN calldurationseconds ELSE 0 END) AS Incomingduration, 
                            SUM(CASE WHEN ISNULL(agentcalldisposition, '''') <> ''Answered'' AND direction = ''Incoming'' THEN 1 ELSE 0 END) AS MissedCalls, 
                           SUM(calldurationseconds) TotalDuration
                        FROM tbl_CallReport_Archive c
                        LEFT JOIN Mysms.[dbo].user_detail u WITH (NOLOCK) ON c.UserId = u.User_ID
                        WHERE c.UserId = @UserId 
                        AND c.Date BETWEEN @fromdate AND @todate
                        AND c.parentid = @UserId';

        -- Add filters for CallDirection, AgentDisposition, and CustomerDisposition if provided
        IF (ISNULL(@CallDirection, '') <> '')
        BEGIN
            SET @SqlQuery = @SqlQuery + N' AND c.direction = @CallDirection';
        END;

        IF (ISNULL(@AgentDisposition, '') <> '')
        BEGIN
            SET @SqlQuery = @SqlQuery + N' AND c.agentcalldisposition IN (' + @AgentDisposition + ')';
        END;

        IF (ISNULL(@CustomerDisposition, '') <> '')
        BEGIN
            SET @SqlQuery = @SqlQuery + N' AND c.customercalldisposition IN (' + @CustomerDisposition + ')';
        END;

        -- Add GROUP BY, ORDER BY, and pagination clauses
        SET @SqlQuery = @SqlQuery + N' GROUP BY c.Date, user_login, c.parentid, c.TotalRow
                                     ORDER BY ' + @OrderColumnName + N' ' + @OrderDir + N'
                                     OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY';
    END
	ELSE
		BEGIN
			 EXEC [Mysms].[dbo].usp_rtp_GetAgentCallSummaryReport @fromdate, @todate, @CallDirection, @AgentDisposition, @CustomerDisposition, @UserId, @OffsetValue, @PagingSize, @OrderColumn, @OrderDir;
		END
	

    -- Execute the dynamic SQL query
    EXEC sp_executesql @SqlQuery, 
                       N'@fromdate NVARCHAR(50), @todate NVARCHAR(50), @UserId BIGINT, @CallDirection NVARCHAR(255), 
                         @AgentDisposition NVARCHAR(255), @CustomerDisposition NVARCHAR(255), @OffsetValue INT, @PagingSize INT', 
                       @fromdate, @todate, @UserId, @CallDirection, @AgentDisposition, @CustomerDisposition, @OffsetValue, @PagingSize;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_rtp_GetBillingDataForChart]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_rtp_GetBillingDataForChart](  
	@UserId bigint,  
	@fromdate nvarchar(50),  
	@todate nvarchar(50)  
)  
as  
begin  



 --declare @UserId bigint = 43740, @fromdate nvarchar(50)='January 10, 2024' ,@todate nvarchar(50)='January 16, 2024'  
  
 declare @ParentId bigint,@isadmin int;                                                
 select @parentid=ParentID,@isadmin=IsAdmin  from MySMS.dbo.User_Detail(nolock) where User_ID = @UserId;                        
  
 --declare @TeamCode varchar(10) = ''    
 --declare @ScopeCode varchar(10) = ''     
 --declare @UserIdTeamLst varchar(500) = ''     
 --select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from MySMS.dbo.ufn_GetUserRoleScope(@UserId)     

 drop table if exists #tempUsers  
 create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
 insert into #tempUsers(User_ID, Name, Image)  
 exec Use_GetUserDetails @UserID = @UserId  

  
 select c.parentid,cast(callcreatedon as date) as Date,   
 sum(case when direction='Outgoing' then t.cost else 0 end) as Outgoing,   
 sum(case when direction='Incoming' then t.cost else 0 end) as Incoming  
 --,sum(case when direction='Outgoing' then Calldurationseconds else 0 end) as Outgoingduration,sum(case when direction='Incoming' then Calldurationseconds else 0 end) as Incomingduration  
 --,sum(case when isnull(agentcalldisposition,'') <>'Answered' and direction='Incoming' then 1 else 0 end) MissedCalls,sum(calldurationseconds) TotalDuration   
 from calendar(nolock) ca   
 left join calllog(nolock) c on cast(c.callcreatedon as date)=cast(ca.start_dts as date) 
 inner join #tempUsers(nolock) tl on c.agentuserid = tl.User_Id 
	and cast(c.callcreatedon as date) between cast(@fromdate as date) and cast(@todate as date)
	
 left join user_detail u (nolock) on c.parentid = u.User_ID  
 left join TelephonyCostDeducted(nolock) t on t.parentid=c.parentid 
	and cast(t.createdon as date) between cast(@fromdate as date) and cast(@todate as date)
  and 1=case when t.gatewaytype<>0 and t.kit19callsdialledid=c.refid then 1  
   when t.GatewayType=0 and t.uniqueid=c.uniqueid then 1 else 0 end  
 where  start_dts between @fromdate and @todate  
  and c.parentid=@parentid 
  
  --and 1 = (case when @isadmin=1 then 1  
  --   when isnull(c.agentuserid, 0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ','))  
  --    then 1  
  --   when isnull(c.agentuserid, 0) = @UserId then 1  
  --    else 0 end ) 
	  
 group by cast(callcreatedon as date), user_login,c.parentid,cast(ca.start_dts as date)  
  order by c.parentid,cast(callcreatedon as date) desc  

end



GO

