/* ============================================================
   Procedure: [dbo].[usp_rtp_GetCallCountForAgentChart]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_rtp_GetCallCountForAgentChart](
	@fromdate nvarchar(50),
	@todate nvarchar(50),
	@UserId bigint
)
as
begin

	--declare @UserId bigint = 43740, @fromdate nvarchar(50)='January 10, 2024' ,@todate nvarchar(50)='January 16, 2024'  

	--select @UserId=41181,@fromdate=N'December 30, 2025',@todate=N'January 4, 2026'

	declare @ParentId bigint,@isadmin int;                                              
	select @parentid=ParentID,@isadmin=IsAdmin  from MySMS.dbo.User_Detail(nolock) where User_ID = @UserId;                      

	--declare @TeamCode varchar(10) = ''  
	--declare @ScopeCode varchar(10) = ''   
	--declare @UserIdTeamLst varchar(500) = ''   
	--select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from MySMS.dbo.ufn_GetUserRoleScope(@UserId)   
	 
	drop table if exists #tempUsers  
	create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
	insert into #tempUsers(User_ID, Name, Image)  
	exec Use_GetUserDetails @UserID = @UserId  

	-- agent_outgoing_answered	total_outgoing_call	agent_incoming_answered	agent_incoming_not_answered
	
	select 
		user_login,	
		sum(case when c.Direction IN ('Outgoing', 'Out' ) and agentcalldisposition = 'ANSWERED' then 1 else  0 end) as [agent_outgoing_answered],
		sum(case when c.Direction IN ('Outgoing', 'Out' ) then 1 else  0 end) as [total_outgoing_call],
		sum(case when c.Direction IN ('Outgoing', 'Out' ) and isnull(customercalldisposition, '') <> 'ANSWERED' then 1 else  0 end) as [agent_outgoing_not_answered],
		sum(case when c.Direction = 'Incoming' and agentcalldisposition = 'ANSWERED' then 1 else  0 end) as [agent_incoming_answered],
		sum(case when c.Direction = 'Incoming' and customercalldisposition <> 'ANSWERED' then 1 else  0 end) as [agent_incoming_not_answered]
	from 
		calendar(nolock) ca left join
		calllog(nolock) c on cast(c.callcreatedon as date)=cast(ca.start_dts as date)
		inner join #tempUsers(nolock) tl on c.agentuserid = tl.User_Id 
		left join user_detail(nolock) u on c.agentuserid = u.User_ID
	where  cast(c.callcreatedon as date) between @fromdate and @todate
		and c.parentid=@parentid 
	group by u.User_Login

end



GO

/* ============================================================
   Procedure: [dbo].[usp_rtp_GetCallCountForAgentChart_agents]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_rtp_GetCallCountForAgentChart_agents](  
 @fromdate nvarchar(50),  
 @todate nvarchar(50),  
 @UserId bigint  
)  
as  
begin  
   
 -- declare @fromdate nvarchar(50)='20220513', @todate nvarchar(50)='20220531', @UserId bigint=34225  
  
 declare @ParentId bigint,@isadmin int;                                                
 select @parentid=ParentID,@isadmin=IsAdmin  from MySMS.dbo.User_Detail(nolock) where User_ID = @UserId;                        
  
 declare @TeamCode varchar(10) = ''    
 declare @ScopeCode varchar(10) = ''     
 declare @UserIdTeamLst varchar(500) = ''     
 select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from MySMS.dbo.ufn_GetUserRoleScope(@UserId)     
  
  
 select   
  AgentName,   
  [agent_outgoing_answered],  
  --[agent_outgoing_not_answered],   
  (  
   [agent_outgoing_answered] +  
   [agent_outgoing_not_answered]  
  ) as[total_outgoing_call],  
  [agent_incoming_answered],  
  [agent_incoming_not_answered]   
 from (  
  select logs.AgentName, logs.custom_disposition from (  
   select   
    AgentName,   
    case when c.Direction = 'Outgoing' and agentcalldisposition = 'ANSWERED' then 'agent_outgoing_answered'  
      when c.Direction = 'Outgoing' and customercalldisposition <> 'ANSWERED' then 'agent_outgoing_not_answered'  
      when c.Direction = 'Incoming' and agentcalldisposition = 'ANSWERED' then 'agent_incoming_answered'  
      when c.Direction = 'Incoming' and customercalldisposition <> 'ANSWERED' then 'agent_incoming_not_answered'  
      else 'agent_outgoing_not_answered'  
    end as [custom_disposition]  
   from   
   calendar(nolock) ca left join  
   calllog(nolock) c on cast(c.callcreatedon as date)=cast(ca.start_dts as date)  
   left join calling_agents(nolock) u on c.calling_agentid = u.ID  
   where  start_dts between @fromdate and @todate  
   and c.parentid=@parentid and 1 = (case when @isadmin=1 then 1  
     when isnull(u.kit19userid, 0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ','))  
      then 1  
     when isnull(u.kit19userid, 0) = @UserId then 1  
      else 0 end )  
  ) logs where logs.Agentname is not null  
 ) AS bc  
 PIVOT (  
  Count(custom_disposition)  
  for custom_disposition in ( [agent_outgoing_answered], [agent_outgoing_not_answered], [agent_incoming_answered], [agent_incoming_not_answered] )  
 ) AS PivotTable;  
end  


GO

/* ============================================================
   Procedure: [dbo].[usp_rtp_GetCallCountForAgentChart_Cache]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_rtp_GetCallCountForAgentChart_Cache](
	@fromdate nvarchar(50),
	@todate nvarchar(50),
	@UserId bigint
)
as
begin
				DECLARE @MonthStart DATETIME;
				DECLARE @MonthEnd DATETIME;
				declare @ParentID bigint = 0;		

			select @ParentID = ParentID from Mysms.[dbo].User_Detail(nolock) where User_ID = @UserId;

				-- Get the first and last date of the current month
				--SET @MonthStart = DATEADD(DAY, 1 - DAY(GETDATE()), CAST(GETDATE() AS DATE)); -- First day of current month
				--SET @MonthEnd = EOMONTH(GETDATE()); -- Last day of current month

				Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			    SET @MonthStart      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
				SET @MonthEnd  =  DATEADD(DAY, -1, @Currentdate);	

				-- Check conditions and select data
				IF (@FromDate Between @MonthStart AND @MonthEnd AND @ToDate Between @MonthStart AND @MonthEnd)
					BEGIN
							SELECT [AgentCallCountChartId]
							  ,[User_Login]
							  ,[agent_outgoing_answered]
							  ,[total_outgoing_call]
							  ,[agent_incoming_answered]
							  ,[agent_incoming_not_answered]
							  ,[UserId]
							  ,[ParentID]
							  ,[start_dts]
						  FROM [dbo].[tbl_AgentCallCountChart_Cache](nolock)
						  WHERE [UserId]= @UserId and [start_dts] between @fromdate and @todate
					END
				ELSE IF (@FromDate < @MonthStart OR @ToDate < @MonthStart)
					BEGIN
							SELECT [AgentCallCountChartId]
							  ,[User_Login]
							  ,[agent_outgoing_answered]
							  ,[total_outgoing_call]
							  ,[agent_incoming_answered]
							  ,[agent_incoming_not_answered]
							  ,[UserId]
							  ,[ParentID]
							  ,[start_dts]
						  FROM [dbo].[tbl_AgentCallCountChart_Archive](nolock)
						  WHERE [UserId]= @UserId  and [start_dts] between @fromdate and @todate
					END
				ELSE
					BEGIN
						EXEC [Mysms].[dbo].usp_rtp_GetCallCountForAgentChart @UserId, @FromDate, @ToDate;
					END	
end



GO

/* ============================================================
   Procedure: [dbo].[usp_rtp_GetCallLogDetailList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_rtp_GetCallLogDetailList]
(  
	@fromdate nvarchar(50) = '',  
	@todate nvarchar(50) = '',  
	@UserId bigint,  
	@FilterText nvarchar(max) = '',  
	@OffsetValue INT          = 0,   
	@PagingSize  INT          = 100  
)  
as  
begin

	--declare 
	--	@fromdate nvarchar(50) = N'20230901', 
	--	@todate nvarchar(50) = N'20230914', 
	--	@UserId bigint = 34594, 
	--	@FilterText nvarchar(max) = N'',  
	--	@OffsetValue INT = 0, 
	--	@PagingSize INT = 20 

	--select @UserId=47166,@fromdate=N'May 11, 2025',@todate=N'May 17, 2025',@FilterText=N'  Agent like ''''%Manisha%'''' ',@OffsetValue=0,@PagingSize=20
  
	declare @ParentId bigint,@isadmin int;                                                
	select @parentid=ParentID,@isadmin=IsAdmin  from Mysms.dbo.User_Detail(nolock) where User_ID = @UserId;                        
  
	drop table if exists #tempUsers  
	create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
	insert into #tempUsers(User_ID, Name, Image)  
	exec Use_GetUserDetails @UserID = @UserId  
	
	declare @StartPoint int = @OffsetValue + 1, @EndPoint int  = (@OffsetValue + @PagingSize )

	set @FilterText = REPLACE(@FilterText, 'Agent not attempted', '')

	--print @UserIdTeamLst 

	declare @sqlQuery nvarchar(max) = concat(N' select * from ( select ',  
		N' ROW_NUMBER() OVER(order by cl.parentid, cast(cl.callcreatedon as datetime) desc) AS sno, ',
		N' COUNT(*) OVER() AS TotalRow, ',
		N'* from ( ', ' select ',
		N' c.id, c.parentid, c.callcreatedon as Date,user_login,  isnull(u.FName,'''') + '' '' + isnull(u.LName,'''')  as UserName, ',
		N' Customernumber, customerentity, ',
		N' customerentityid, isnull (dbo.fn_getentityfullname(customerentity,customerentityid),'''') as CustomerName, ',
		N' isnull(dnid,'''') as DNID, ',
		N'( case when c.gatewayid = 0 then ''Sim'' else s.provider_name end ) as Gateway, ',
		N'isnull(m.AppName,'''') IVRFlow, ',
		N'isnull(user_login,case when c.agentcalldisposition is null then '' '' else ''Agent No Changed'' end) Agent, ',
		N'direction, ',
		N'isnull(c.customercalldisposition, ''Unknown'') as CustomerDisposition, ',
		N'isnull(c.agentcalldisposition, case when c.agentcalldisposition is null then ''NOT ATTEMPTED'' ',
			N'else ''Unknown'' end) as AgentDisposition, ',
		N'( case when isnull(c.Callstarttime, '''') = '''' then ''Unknown'' ',
			N' else format(c.Callstarttime, ''dd-MMM-yyyy HH:mm:ss'') end ) as Callstarttime, ',
		N'(case when isnull(c.callendtime, '''') = '''' then ''Unknown'' ',
			N'else format(c.callendtime, ''dd-MMM-yyyy HH:mm:ss'') end) as CallEndTime, ',
		N'coalesce(customerduration, c.Calldurationseconds, 0) AS CustomerDuration, ',
		N'(case when c.agentcalldisposition is null then 0 ',
			N'when c.agentcalldisposition = ''NOANSWER'' then 0 ',
			N'else coalesce(agentduration, Calldurationseconds, 0) end) as agentDuration, ',
		N'(case when c.agentcalldisposition IS NULL then 0 else isnull (Calldurationseconds, 0) end) as Callduration, ',
		N'c.recordurl as Recording, isnull(c.agentmode,''Mobile'') as AgentMode, isnull(o.outcomename,'''') as Outcome, ',
		N'c.remarks, isnull(c.lastdtmf,'''') LastUserInput, ',
		N'c.callcreatedon, (case when c.customerentity = ''lead'' then ul.LeadNo else en.LeadNo end )as [LeadNo]',
		N' from calendar(nolock) ca ',
		N'left join calllog(nolock) c on cast(c.callstarttime as date)=cast(ca.start_dts as date) ',
		N'left join user_detail u (nolock) on c.agentuserid = u.User_ID ',
		N'left join UserLeads ul (nolock) on c.customerentity = ''lead'' and c.customerentityid = ul.ID ',
		N'left join UserEnquiry en (nolock) on c.customerentity = ''enquiry'' and c.customerentityid = en.EnquiryID ',
		--N'left join TelephonyCostDeducted(nolock) t on t.parentid=c.parentid and 1=case ',
		--	N'when t.gatewaytype<>0 and t.kit19callsdialledid=c.refid then 1 ',
		--	N'when t.GatewayType=0 and t.uniqueid=c.uniqueid then 1 else 0 end ',
		N'left join tbl_voip_ServiceProvider s on s.id=c.gatewayid ',
		N'left join tbl_CallLogOutcomeMaster(nolock) o on o.id=c.outcomeid ',
		N'left join Cloud_app_master(nolock) m on m.AppId = c.appid ',
		N'where  cast(callcreatedon as date) between cast(''',  @fromdate, ''' as date) ',
			N'and cast(''', @todate, ''' as date) ',
			N'and c.parentid=', @parentid, ' ',
			N'and 1 = (case when ' , @isadmin ,' = 1 then 1 ',
				--N'when isnull(c.agentuserid, 0) in (select [value] from dbo.fn_Split(''', @UserIdTeamLst, ''', '','')) then 1 ',
				N'when isnull(c.agentuserid, 0) in (select [User_ID] from #tempUsers) then 1 ',
				N'when isnull(c.agentuserid, 0) = ', @UserId, ' then 1 else 0 end )',  
		--N'group by cast(callcreatedon as date), user_login,c.parentid,cast(ca.start_dts as date)  
		N' ) cl ',   
		iif(isnull(@FilterText, '') = '', ' ', concat(' where ', REPLACE(@FilterText,'''''',''''))),
		N' ) nt where nt.sno between ', @StartPoint, ' and ', @EndPoint 
	)  
  
	print @sqlQuery  
  
	execute sp_executesql @sqlQuery  
  
end 




GO

