/* ============================================================
   Procedure: [dbo].[usp_rtp_GetRpCallSummaries]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_rtp_GetRpCallSummaries
(
	@fromdate NVARCHAR(50) = NULL, 
	@todate   NVARCHAR(50) = NULL, 
	@UserId   BIGINT
)
AS
BEGIN
    --DECLARE @fromdate NVARCHAR(50)= '20220513', @todate NVARCHAR(50)= '20220531', @UserId BIGINT= 34115;
    DECLARE @parentid BIGINT= 0;
    SELECT @parentid = ParentID
    FROM User_Detail(NOLOCK)
    WHERE User_ID = @UserId;
    SELECT c.parentid, 
            u.user_login AS ParentUser, 
            CAST(callcreatedon AS DATE) AS Date, 
            SUM(CASE
                    WHEN direction = 'Outgoing'
                    THEN 1
                    ELSE 0
                END) AS Outgoingcalls, 
            SUM(CASE
                    WHEN direction = 'Incoming'
                    THEN 1
                    ELSE 0
                END) AS Incomingcalls, 
            SUM(CASE
                    WHEN ISNULL(customercalldisposition, '') = 'Answered'
                        AND direction = 'Outgoing'
                    THEN 1
                    ELSE 0
                END) OutgoingAnswered, 
            SUM(CASE
                    WHEN ISNULL(customercalldisposition, '') <> 'Answered'
                        AND direction = 'Outgoing'
                    THEN 1
                    ELSE 0
                END) OutgoingUnAnswered, 
            SUM(CASE
                    WHEN ISNULL(agentcalldisposition, '') = 'Answered'
                        AND direction = 'Incoming'
                    THEN 1
                    ELSE 0
                END) IncomingAnswered, 
            SUM(CASE
                    WHEN ISNULL(agentcalldisposition, '') <> 'Answered'
                        AND direction = 'Incoming'
                    THEN 1
                    ELSE 0
                END) IncomingMissed
    FROM calendar ca(NOLOCK)
            LEFT JOIN calllog c(NOLOCK) ON CAST(c.callcreatedon AS DATE) = CAST(ca.start_dts AS DATE)
            LEFT JOIN user_detail u(NOLOCK) ON c.parentid = u.User_ID
    WHERE start_dts BETWEEN @fromdate AND @todate
            AND c.parentid = @parentid
    GROUP BY CAST(callcreatedon AS DATE), 
                u.user_login, 
                c.parentid, 
                CAST(ca.start_dts AS DATE)
    ORDER BY c.parentid, 
                CAST(callcreatedon AS DATE) DESC;
END;



GO

