/* ============================================================
   Procedure: [dbo].[usp_runscheduledTcampaigns]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_runscheduledTcampaigns]  
as  
begin  
--exec [usp_get_dateisdue]
select top 10 * into #sc from scheduledtodos(nolock) where scheduledaction='Tcampaign' and   
(isnotified=0 or (isnotified=2 and datediff(mi,processedat,getdate())>10)) and datediff(hour,scheduledfor,getdate())<4   
update s set isnotified=2, processedat=getdate() from scheduledtodos s join #sc sc on sc.id=s.id  
declare @c int=(select count(1) from #sc),@activityid bigint,@entity varchar(20),@tcid bigint,@sid bigint=0,@eventid bigint  
,@sequenceid bigint  
while @c >0  
begin  
select @sid=min(id) from #sc where id>@sid  
select @tcid=std_trgid,@activityid=activityid,@eventid=eventid,@sequenceid=std_sequenceid from #sc where id=@sid  
select @entity=context from activitymaster(nolock) where id=@eventid  
begin try  
if isnull(@sequenceid,0)>0 and   
exists(select 1 from triggeredcampaigns(nolock) where id=@tcid and isactive=1 and isnull(sequenceid,0)=@sequenceid)  
begin  
print 'sequence'
exec usp_automationrulesapply_activity @activityid,@entity  
update scheduledtodos set isnotified=1, processedat=getdate() where id=@sid  
end  
else if exists(select 1 from triggeredcampaigns(nolock) where id=@tcid and isactive=1 and   
(isnull(smscampaignid,0)>0 or isnull(mailcampaignid,0)>0 or isnull(voicecampaignid,0)>0 or isnull(whatsappcampaignid,0)>0))  
begin
print 'SMS/Mail/Voice/Whatsapp'
exec [usp_executeeventcampaign_tid] @entity,@activityid,@tcid  
update scheduledtodos set isnotified=1, processedat=getdate() where id=@sid  
end  
end try  
begin catch  
exec usp_inserterrorinfo  
end catch  
set @c=@c-1  
end  
end  


GO

/* ============================================================
   Procedure: [dbo].[usp_runstuckcampaigns]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_runstuckcampaigns]
as
begin
if exists (select 1 from Usercampaignexecution(nolock) where isrunning=1 and campaignexecuteddatetime<dateadd(HH,-1,getdate()))
begin
declare @issms int,@c int,@id int=0,@jobid bigint,@isevent int
select @c=count(1) from Usercampaignexecution(nolock) where isrunning=1 and campaignexecuteddatetime<dateadd(HH,-1,getdate())
while @c>0
begin

select @id=min(id) from Usercampaignexecution(nolock) where isrunning=1 and campaignexecuteddatetime<dateadd(hh,-1,getdate())
and id>@id
select @issms=issms,@jobid=cjobid,@isevent=isevent from Usercampaignexecution(nolock) where id=@id
print concat('@c: ',@c,'Issms: ',@issms,', jobid: ',@jobid, ', isevent: ',@isevent)
begin try
if @issms=0
begin
exec [dbo].[Usp_insertclonedeliverycampaignmailsCorrected_segregatemail_withid21102020] @jobid
end
else if @issms=1
begin
exec [dbo].[Usp_insertclonedeliverycampaignCorrected_withid21102020] @jobid
end
else if @issms=2
begin
exec [dbo].[Usp_insertclonedeliverycampaignVoice_withid21102020] @jobid
end
end try
begin catch
exec usp_inserterrorinfo
end catch
set @c=@c-1
end
end
end


GO

/* ============================================================
   Procedure: [dbo].[usp_SalesActivityMaster_by_SalesTargetId_Date]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




/*

usp_SalesActivityMaster_by_SalesTargetId_Date  10141, '2024-07-18','2024-07-31'
exec usp_SalesActivityMaster_by_SalesTargetId_Date @SalesTargetId=10175,@FromDate='2024-08-01 00:00:00',@ToDate='2024-08-01 00:00:00'
exec usp_SalesActivityMaster_by_SalesTargetId_Date @SalesTargetId=10175,@FromDate='2024-08-01 00:00:00',@ToDate='2024-08-01 00:00:00'
exec usp_SalesActivityMaster_by_SalesTargetId_Date @SalesTargetId=20193,@FromDate='2024-12-06 00:00:00',@ToDate='2024-12-10 00:00:00'
*/


CREATE   PROCEDURE [dbo].[usp_SalesActivityMaster_by_SalesTargetId_Date]          
(      
	@SalesTargetId bigint,      
	@FromDate datetime,      
	@ToDate datetime
)       
AS       
SET NOCOUNT ON                     
BEGIN TRY                     
begin       
    
	--declare 
	--	@SalesTargetId bigint = 335,      
	--	@FromDate datetime = '2024-06-01 00:00:00',      
	--	@ToDate datetime = '2024-06-30 00:00:00' 

	declare @Invoices bit = 0    
	declare @Conversions bit = 0    
	declare @Pipelines bit = 0    
    

	declare @UserSplitDatails nvarchar(max) 
	declare @TargetFor nvarchar(25) = ''  , @TargetType int = 0;

	

	select @Invoices = Invoices, @Conversions = Conversions, @Pipelines = Pipelines, @TargetFor = TargetFor , @TargetType = TargetType
		from TBL_ST_SalesTargetSettingMaster(nolock) where SalesTargetId = @SalesTargetId     
     
--select distinct tss.Id, TblRefId,   
--Case When TblRefName = 'invoices' then 'Invoice'   
--When TblRefName = 'LeadInteractionHistory' then 'Conversion'   
--When TblRefName = 'LeadPipelineMapping' then 'Pipeline (' +plm.Name +')'    
--Else ''  
--End TblRefName, tss.Amount, RecordDate, InvoiceNo, tss.IsActive, tss.UserId, tss.ParentID, tss.PipelineId,  
--plm.Name PipeLineName,  
--ProductIds, LeadNo, tss.CreatedDate, tss.ModifiedDate, (Ud1.FName +' '+Ud1.LName) OwnerName from [dbo].[Tbl_ST_SalesActivityMaster] tss      
--inner join TBL_ST_SalesTargetSettingChild stsc on tss.UserId = stsc.UserId    
--inner join TBL_ST_SalesTargetSettingMaster stsm on stsc.SalesTargetId = stsm.SalesTargetId    
--left join Pipeline_Master plm on tss.PipelineId = plm.ID    
--inner join User_Detail Ud1 on tss.UserId = Ud1.User_ID      
--where stsc.SalesTargetId = @SalesTargetId    
--and Cast(RecordDate as Date) between Cast(@FromDate as Date) and Cast(@ToDate as Date)      
--and stsm.Invoices = @Invoices and stsm.Conversions = @Conversions and stsm.Pipelines = @Pipelines    
    

	--declare 
	--@SalesTargetId bigint = 276


	DROP TABLE IF EXISTS #tblSplitData
	CREATE TABLE #tblSplitData (
		id INT,
		SalesTargetId INT,
		TeamCode NVARCHAR(50),
		UserId INT,
		Target DECIMAL(18, 2),
		TargetNumber DECIMAL(18, 2),
		TargetPercentage DECIMAL(5, 2),
		TargetType INT,
		FromDate DATE,
		ToDate DATE,
		ParentId INT,
		IsActive BIT,
		CreatedOn DATETIME,
		SplitUserId INT,
		SplitFullName NVARCHAR(100),
		SplitTarget DECIMAL(18, 2),
		SplitPercentage DECIMAL(5, 2),
		SplitNumber DECIMAL(18, 2),
		SplitIsActive BIT
	);

	---	select * from #tblSplitData




	if(@TargetFor = 'user')
	begin
		INSERT INTO #tblSplitData ( id, SalesTargetId, TeamCode, UserId, Target, TargetNumber, TargetPercentage,
			TargetType, FromDate, ToDate,  ParentId, IsActive, CreatedOn, SplitUserId, SplitFullName, SplitTarget, 
			SplitPercentage, SplitNumber,  SplitIsActive )
			SELECT t.id, t.SalesTargetId, t.TeamCode, t.UserId, t.Target, t.TargetNumber, t.TargetPercentage,
			t.TargetType, t.FromDate, t.ToDate, t.ParentId, t.IsActive, t.CreatedOn, t.UserId AS SplitUserId, 
			'' AS SplitFullName, CAST(t.TargetNumber AS DECIMAL(18, 2)) AS SplitTarget, 
			CAST(t.TargetPercentage AS DECIMAL(5, 2)) AS SplitPercentage, CAST(t.TargetNumber AS DECIMAL(18, 2)) AS SplitNumber,
			t.IsActive AS SplitIsActive
		FROM  TBL_ST_SalesTargetSettingUserTarget(nolock) t 
			where t.SalesTargetId = @SalesTargetId 


	

	end
	begin
		INSERT INTO #tblSplitData ( id, SalesTargetId, TeamCode, UserId, Target, TargetNumber, TargetPercentage,
			TargetType, FromDate, ToDate,  ParentId, IsActive, CreatedOn, SplitUserId, SplitFullName, SplitTarget, 
			SplitPercentage, SplitNumber,  SplitIsActive )
		SELECT t.id, t.SalesTargetId, t.TeamCode, u.UserId, t.Target, t.TargetNumber, t.TargetPercentage,
			t.TargetType, t.FromDate, t.ToDate, t.ParentId, t.IsActive, t.CreatedOn, u.UserId AS SplitUserId, 
			u.FullName AS SplitFullName, CAST(u.Target AS DECIMAL(18, 2)) AS SplitTarget, 
			CAST(u.Percentage AS DECIMAL(5, 2)) AS SplitPercentage, CAST(u.Number AS DECIMAL(18, 2)) AS SplitNumber,
			u.IsActive AS SplitIsActive
		FROM  TBL_ST_SalesTargetSettingUserTarget(nolock) t 
			CROSS APPLY  OPENJSON(t.UserSplitDetail) WITH (
				IsActive BIT,
				UserId INT,
				FullName NVARCHAR(100),
				Target NVARCHAR(50),
				Percentage NVARCHAR(50),
				Number NVARCHAR(50)
			) u where t.SalesTargetId = @SalesTargetId;
	end

	

	if (@TargetType <> 3)
	begin



	select a.Id, TblRefId,   
		Case When TblRefName = 'invoices' then 'Invoice'   
		When TblRefName = 'LeadInteractionHistory' then 'Conversion'   
		When TblRefName = 'LeadPipelineMapping' then 'Pipeline (' +plm.Name +')'    
		Else ''  
		End TblRefName, a.Amount, RecordDate, InvoiceNo, a.IsActive, c.UserId, a.ParentID, a.PipelineId,  
		plm.Name PipeLineName,  
		a.ProductIds, a.ProductsJson, a.LeadNo, isnull(ul.PersonName, '[Lead Deleted]') as PersonName, a.CreatedDate, a.ModifiedDate, concat(ud.User_Login, '(', ud.FName, ' ', ud.LName ,')')  as [OwnerName] ,
		'' as Activity , @TargetType as SaleTargetType
	from TBL_ST_SalesTargetSettingMaster(nolock) m 
		inner join #tblSplitData(nolock) c on m.SalesTargetId = c.SalesTargetId
		left join Tbl_ST_SalesActivityMaster(nolock) a on m.SalesTargetId = a.SalesTargetId and c.SplitUserId = a.UserId 
				and Cast(a.RecordDate as Date) between Cast(m.TargetFromDate as Date) and Cast(m.TargetToDate as Date)
		left join UserLeads(nolock) ul on ul.ParentID = a.ParentId and ul.LeadNo = a.LeadNo
		left join User_Detail(nolock) ud on c.UserId = ud.User_ID 
		left join Pipeline_Master plm on a.PipelineId = plm.ID    
		where m.SalesTargetId = @SalesTargetId 
	and 1 =  ( case 
		when m.Invoices = 1 and a.TblRefName = 'invoices' then 1 
		when m.Conversions = 1 and a.TblRefName = 'LeadInteractionHistory' then 1 
		when m.Pipelines = 1 and a.TblRefName = 'LeadPipelineMapping' then 1 
		else 0 end 
	) order by a.CreatedDate desc ;

	end
	else if (@TargetType = 3)
	begin
	  
			-- select * from tbl_sm_ScoringRaw order by 1 desc
			--select * from tbl_SM_Employee_Points_History   order by 1 desc  where ref_tran_id = 966782  --58
			--select * from Tbl_ST_SalesActivityMaster  order by 1 desc  where   id  = 58   SalesTargetID = 10125
			--  tbl_LeadEventHistory where historyid=  966782
			-- tbl_LeadEventHistory eh on eh.HistoryID = ph.Tran_ID
			--  LeadInteractionHistory LH where leadno  = 1702275
			-- UserLeads where id = 1702275

			--select a.Id, TblRefId,   
			--	Case When TblRefName = 'invoices' then 'Invoice'   
			--	When TblRefName = 'LeadInteractionHistory' then 'Conversion'   
			--	When TblRefName = 'LeadPipelineMapping' then 'Pipeline (' +plm.Name +')'    
			--	Else ''  
			--	End TblRefName, ph.points as amount, RecordDate, InvoiceNo, a.IsActive, c.UserId, a.ParentID, a.PipelineId,  
			--	plm.Name PipeLineName,  
			--	a.ProductIds, a.ProductsJson, a.LeadNo, isnull(ul.PersonName, '[Lead Deleted]') as PersonName, a.CreatedDate, a.ModifiedDate, concat(ud.User_Login, '(', ud.FName, ' ', ud.LName ,')')  as [OwnerName] 
			--from TBL_ST_SalesTargetSettingMaster(nolock) m 
			--	inner join #tblSplitData(nolock) c on m.SalesTargetId = c.SalesTargetId
			--	left join Tbl_ST_SalesActivityMaster(nolock) a on m.SalesTargetId = a.SalesTargetId and c.SplitUserId = a.UserId 
			--			and Cast(a.RecordDate as Date) between Cast(m.TargetFromDate as Date) and Cast(m.TargetToDate as Date)
			--	left join UserLeads(nolock) ul on ul.ParentID = a.ParentId and ul.LeadNo = a.LeadNo
			--	left join User_Detail(nolock) ud on c.UserId = ud.User_ID 
			--	left join Pipeline_Master plm on a.PipelineId = plm.ID 
			--	left join tbl_SM_Employee_Points_History ph on ph.ref_tran_id = a.Id and ph.trandate between  m.TargetFromDate and m.TargetToDate
			--	where m.SalesTargetId = @SalesTargetId 
			--and 1 =  ( case 
			--	when m.Invoices = 1 and a.TblRefName = 'invoices' then 1 
			--	when m.Conversions = 1 and a.TblRefName = 'LeadInteractionHistory' then 1 
			--	when m.Pipelines = 1 and a.TblRefName = 'LeadPipelineMapping' then 1 
			--	else 0 end 
			--) order by a.CreatedDate desc ;


			--- select * from #tblSplitData(nolock)

			 create table #tempSalesTargetdata 
			 (
				Id int identity(1,1),
				SalestargetId int ,
				target_for varchar(100),
				Target_type int ,
				Teamcode int,
				Userids varchar(5000),
				Targetfromdate varchar(100),
				TargetTodate varchar(100),
				Total_target decimal(16,2)
			 )


			 insert into  #tempSalesTargetdata 
			 select @SalesTargetId ,TargetFor , TargetType , TeamCodes , UserIds, TargetFromDate , TargetToDate , TotalTarget  from  TBL_ST_SalesTargetSettingMaster(nolock) where SalesTargetId =  @SalesTargetId

			 ---  0 Id, 0  TblRefId,   ''as  TblRefName,  0  amount, RecordDate, InvoiceNo,  IsActive,  UserId,  ParentID,  PipelineId,   PipeLineName,   ProductIds,  ProductsJson,
			 --  LeadNo, ''  as PersonName,  '' CreatedDate,  '' ModifiedDate, concat(ud.User_Login, '(', ud.FName, ' ', ud.LName ,')')  as [OwnerName] 	
	
			 select 0 as Id, ph.ref_tran_id  as TblRefId ,  'tbl_LeadEventHistory' as TblRefName ,COALESCE (ph.Remarks,'') as Activity   ,sum(ph.points) as amount , ph.TranDate as RecordDate  ,
			  0 as InvoiceNo , ph.Isactive as  IsActive , ph.UserId  as UserId , ud.ParentID as ParentID, 0 as PipelineId, ''as  PipeLineName , 0 as ProductIds , '' as ProductsJson , 
			  0 as LeadNo , isnull(ul.PersonName, '[Lead Deleted]') as PersonName,  '' as CreatedDate , '' as  ModifiedDate  ,  concat(ud.User_Login,'(', ud.FName, ' ', ud.LName ,')')  as [OwnerName] ,
			  @TargetType as SaleTargetType
			  from #tempSalesTargetdata st  
			 left join tbl_SM_Employee_Points_History ph on ph.UserId in  (SELECT VALUE FROM STRING_SPLIT(COALESCE(st.Userids, ''), '#'))
			 left join tbl_LeadEventHistory eh on eh.HistoryID = ph.ref_tran_id
			 left join UserLeads ul on ul.ID = eh.LeadID
			 left join User_Detail(nolock) ud on ph.UserId = ud.User_ID 
			 where ph.TranDate between CONCAT(CONVERT(VARCHAR, @FromDate, 23), ' 00:00:00') and CONCAT(CONVERT(VARCHAR, @ToDate, 23), ' 23:59:59')
			 group by st.target_for ,  ph.Remarks , st.Total_target,  ud.User_Login , ud.FName , ud.LName, ul.PersonName , ph.TranDate , ph.ref_tran_id ,  ph.Isactive , ph.UserId , ud.ParentID   ---st.Target_type 


	end



 end         
 END TRY         
BEGIN CATCH         
 DECLARE @ErrorMessage NVARCHAR(4000);         
 SELECT @ErrorMessage = ERROR_MESSAGE();         
 RAISERROR (@ErrorMessage, 16, 1);         
END CATCH       



GO

/* ============================================================
   Procedure: [dbo].[usp_SalesTarget_by_Filter]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SalesTarget_by_Filter]          
(        
  @UserId bigint = 0 
 ,@FromDate varchar(50) =  null --'2023-11-01' --null,           
 ,@ToDate varchar(50) = null --'2023-12-13' -- null  
 ,@TargetPeriodId int = 0  
 ,@TargetType int = 0  
 ,@TargetFor varchar(10) = ''
 ,@SrchUserids nvarchar(50) =''
 ,@SrchTeamids nvarchar(50) =''
)       
AS       
SET NOCOUNT ON          
BEGIN


	--declare
	--	@UserId bigint = 43966 
	--	,@FromDate varchar(50) =  '2024-03-01' --'2023-11-01' --null,           
	--	,@ToDate varchar(50) = '2025-03-31' --'2023-12-13' -- null  
	--	,@TargetPeriodId int = 0  
	--	,@TargetType int = 0  
	--	,@TargetFor varchar(10) = ''	
	--	,@SrchUserids nvarchar(50) =''
	--	,@SrchTeamids nvarchar(50) =''


 declare @parseData datetime = try_convert(datetime, @ToDate)
 
 if( @parseData is null)
 begin
	select @ToDate = format(DATEADD(yy, 1, try_convert(datetime, @FromDate)), 'yyyy-MM-dd')
 end


  BEGIN TRY                     
  begin       
   DECLARE @ParentId BIGINT = 0
   ,@actUserID BIGINT = @UserId;  
   
 SELECT @ParentId = ParentID FROM User_Detail(nolock) WHERE User_ID = @UserId;                              
 Declare @IsAdmin bit = 0                  
            
 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100),TeamCode varchar(10))            
 select @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @UserId            
 if(@IsAdmin = 1)            
 begin            
  set @UserId = 0;            
  insert into @tbluser            
  exec Use_GetUserDetails_Team @ParentId            
 end            
 else            
 Begin            
  insert into @tbluser            
  exec Use_GetUserDetails_Team @UserId            
 End            
               
 Declare @TeamCode varchar(10) = ''            
 Declare @ScopeCode varchar(10) = ''             
 Declare @UserIdTeamLst varchar(Max) = ''             
 Declare @UserLoginTeamLst varchar(Max) = ''      
            
 --select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)             
-- select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser            
    
-- select *, cast(round( ((AchievedTarget/TotalTarget) * 100),2)as numeric(10,2)) Achievedpercent from (      
  
--select SalesTargetId, case when TargetType = '1' then 'Revenue' when TargetType = '2' then 'Conversions' else TargetType End TargetType, Conversions, Pipelines, Invoices, iInvoiceRaised, iInvoicePaid, TargetFor, TeamCodes, UserIds, TargetPeriodId, 
--Cast(TargetFromDate as varchar(20)) TargetFromDate, Cast(TargetToDate as varchar(20)) TargetToDate, convert(varchar, TargetFromDate, 23) TargetFromDate1, convert(varchar, TargetToDate, 23) TargetToDate1, TargetProductIds, TargetPipelineIds, TotalTarget, 
--dbo.GetTotalSalesActivity(SalesTargetId, TargetFromDate, TargetToDate) AchievedTarget, TargetUnit, Currency, tbs.UserId, tbs.ParentId, tbs.Status, IsActive, CreatedBy, Cast(CreatedDate as varchar(20)) CreatedDate, ModifiedBy, 
--Cast(ModifiedDate as varchar(20)) ModifiedDate, case when Cast(getdate() as date) < TargetFromDate then 'Upcoming' when Cast(getdate() as date) > TargetToDate then 'Completed' when Cast(getdate() as date) between TargetFromDate and TargetToDate then 'Current' else '' End Duration, (ud1.FName + ' ' + ud1.LName) CreatedByName, '' ModifiedByName from TBL_ST_SalesTargetSettingMaster tbs   
--inner join User_Detail ud1 on tbs.CreatedBy = ud1.User_ID   
--where tbs.Status = 1 and IsActive = 1 and UserId in (select User_ID from @tbluser) and 
--(tbs.TargetFromDate between Cast(@FromDate as datetime) and Cast(@ToDate as datetime) or tbs.TargetToDate between Cast(@FromDate as datetime) and Cast(@ToDate as datetime))  
--and tbs.TargetPeriodId in (case when @TargetPeriodId != '' then @TargetPeriodId else TargetPeriodId end)  
  
--and TargetFor in (Case when @TargetFor = 'User' then 'User'   
--when @TargetFor = 'Team' then 'Team' else TargetFor end)  
--and TargetType in (Case when @TargetType = 1 then 1   
--when @TargetType = 2 then @TargetType else TargetType end)  
--and  (@SrchUserids = '' OR tbs.UserIds= @SrchUserids )
--and  (@SrchTeamids = '' OR tbs.TeamCodes= @SrchTeamids )
  
--) t      

drop table if exists #tempAchievedData

select  c.SalesTargetId,
		SUM(case when a.TblRefName = 'invoices' then 1 else 0 end ) as InvoiceCount,
		SUM(case when a.TblRefName = 'LeadInteractionHistory' then 1 else 0 end ) as ConverstionCount,
		SUM(case when a.TblRefName = 'LeadPipelineMapping' then 1 else 0 end ) as PipelineCount,
		SUM(case when a.TblRefName = 'invoices' then a.Amount else 0 end ) as InvoiceAmount,
		SUM(case when a.TblRefName = 'LeadInteractionHistory' then a.Amount else 0 end ) as ConverstionAmount,
		SUM(case when a.TblRefName = 'LeadPipelineMapping' then a.Amount else 0 end ) as PipelineAmount
		 into #tempAchievedData
	from TBL_ST_SalesTargetSettingMaster(nolock) m 
		inner join TBL_ST_SalesTargetSettingChild(nolock) c on m.SalesTargetId = c.SalesTargetId
		inner join Tbl_ST_SalesActivityMaster(nolock) a on c.UserId = a.UserId 
			and Cast(a.RecordDate as Date) between Cast(m.TargetFromDate as Date) and Cast(m.TargetToDate as Date)
			group by c.SalesTargetId
	  
 select *, cast(round( ((AchievedTarget/TotalTarget) * 100),2)as numeric(10,2)) Achievedpercent from (

select c.date_id,cast(stsc.UserId as varchar) as TargetTeamUserid, t.SalesTargetId, case when TargetType = '1' then 'Revenue' when TargetType = '2' then 'Conversions' else TargetType End TargetType, TargetType TargetTypeSearch, Conversions, Pipelines, Invoices, 
iInvoiceRaised, iInvoicePaid, TargetFor, TeamCodes, UserIds, TargetPeriodId, Cast(TargetFromDate as varchar(20)) TargetFromDate, Cast(TargetToDate as varchar(20)) TargetToDate,TargetFromDate TargetFromDateSearch,
TargetToDate TargetToDateSearch, convert(varchar, TargetFromDate, 23) TargetFromDate1, convert(varchar, TargetToDate, 23) TargetToDate1, TargetProductIds, TargetPipelineIds, TotalTarget, 
isnull(( case when t.TargetType = 2  then ( 
				iif(t.Conversions = 1, v.ConverstionCount, 0) 
				+  iif(t.Invoices = 1, v.InvoiceCount, 0)
				+  iif(t.Pipelines = 1, v.PipelineCount	, 0)
				)
			when t.TargetType = 1  then ( 
				iif(t.Conversions = 1, v.ConverstionAmount, 0) 
				+  iif(t.Invoices = 1, v.InvoiceAmount, 0)
				+  iif(t.Pipelines = 1, v.PipelineAmount	, 0))
	else 0 end), 0) as [AchievedTarget],
--dbo.GetTotalSalesActivity(t.SalesTargetId, TargetFromDate, TargetToDate) AchievedTarget,
TargetUnit, Currency, t.UserId, t.ParentId, t.Status, t.IsActive, CreatedBy, Cast(CreatedDate as varchar(20)) CreatedDate,
ModifiedBy, Cast(ModifiedDate as varchar(20)) ModifiedDate, 
case when Cast(getdate() as date) < cast(TargetFromDate as date) then 'Upcoming' 
	 when Cast(getdate() as date) > cast(TargetToDate as date) then 'Completed' 
	 when Cast(getdate() as date) between cast(TargetFromDate as date) and cast(TargetToDate as date) then 'Current' 
	 else '' End Duration, (ud1.FName + ' ' + ud1.LName) CreatedByName, '' ModifiedByName from TBL_ST_SalesTargetSettingMaster t   
inner join User_Detail ud1 on t.CreatedBy = ud1.User_ID   
join TBL_ST_SalesTargetSettingChild stsc on stsc.SalesTargetId=t.SalesTargetId
left join #tempAchievedData v on t.SalesTargetId = v.SalesTargetId
join calendar c(nolock) on c.date_id between t.TargetFromDate and t.TargetToDate
where t.Status = 1 and t.IsActive = 1 
      
	  --and t.UserId in (select User_ID from @tbluser) 
	 and  exists (select p from (select value as p from
	      fn_Split(t.UserIds, ',') where isnull(t.UserIds,'') != '' and isnumeric(value) = 1 ) as tbl
	     where p in (    
          SELECT distinct User_ID    
         FROM @tbluser    
                    )
	         )
	  and TargetFor ='User' and targetperiodid=1 

UNION 

select c.date_id,cast(stsc.UserId as varchar) as TargetTeamUserid, t.SalesTargetId, case when TargetType = '1' then 'Revenue' when TargetType = '2' then 'Conversions' else TargetType End TargetType,TargetType TargetTypeSearch, Conversions, Pipelines, Invoices, 
iInvoiceRaised, iInvoicePaid, TargetFor, TeamCodes, UserIds, TargetPeriodId, Cast(TargetFromDate as varchar(20)) TargetFromDate, Cast(TargetToDate as varchar(20)) TargetToDate,TargetFromDate TargetFromDateSearch,
TargetToDate TargetToDateSearch, convert(varchar, TargetFromDate, 23) TargetFromDate1, convert(varchar, TargetToDate, 23) TargetToDate1, TargetProductIds, TargetPipelineIds, TotalTarget, 
isnull(( case when t.TargetType = 2  then ( 
				iif(t.Conversions = 1, v.ConverstionCount, 0) 
				+  iif(t.Invoices = 1, v.InvoiceCount, 0)
				+  iif(t.Pipelines = 1, v.PipelineCount	, 0)
				)
			when t.TargetType = 1  then ( 
				iif(t.Conversions = 1, v.ConverstionAmount, 0) 
				+  iif(t.Invoices = 1, v.InvoiceAmount, 0)
				+  iif(t.Pipelines = 1, v.PipelineAmount	, 0))
	else 0 end), 0) as [AchievedTarget],
--dbo.GetTotalSalesActivity(t.SalesTargetId, TargetFromDate, TargetToDate) AchievedTarget,
TargetUnit, Currency, t.UserId, t.ParentId, t.Status, t.IsActive, CreatedBy, Cast(CreatedDate as varchar(20)) CreatedDate,
ModifiedBy, Cast(ModifiedDate as varchar(20)) ModifiedDate, 
case when Cast(getdate() as date) < cast(TargetFromDate as date) then 'Upcoming' 
	 when Cast(getdate() as date) > cast(TargetToDate as date) then 'Completed' 
	 when Cast(getdate() as date) between cast(TargetFromDate as date) and cast(TargetToDate as date) then 'Current' 
	 else '' End Duration, (ud1.FName + ' ' + ud1.LName) CreatedByName, '' ModifiedByName from TBL_ST_SalesTargetSettingMaster t   
inner join User_Detail ud1 on t.CreatedBy = ud1.User_ID   
inner join TBL_ST_SalesTargetSettingChild stsc on stsc.SalesTargetId=t.SalesTargetId
left join #tempAchievedData v on t.SalesTargetId = v.SalesTargetId
join calendar c(nolock) on c.weekday_id = datepart(dw,t.TargetFromDate) and  c.date_id between t.TargetFromDate and t.TargetToDate 
where t.Status = 1 and t.IsActive = 1 
  --and t.UserId in (select User_ID from @tbluser)
  and  exists (select p from (select value as p from
	      fn_Split(t.UserIds, ',') where isnull(t.UserIds,'') != '' and isnumeric(value) = 1 ) as tbl
	     where p in (    
          SELECT distinct User_ID    
         FROM @tbluser    
                    )
	         )
  and TargetFor ='User' --and targetperiodid=2

UNION 

select c.date_id,cast(stsc.UserId as varchar) as TargetTeamUserid, t.SalesTargetId, case when TargetType = '1' then 'Revenue' when TargetType = '2' then 'Conversions' else TargetType End TargetType,TargetType TargetTypeSearch, Conversions, Pipelines, Invoices, 
iInvoiceRaised, iInvoicePaid, TargetFor, TeamCodes, UserIds, TargetPeriodId, Cast(TargetFromDate as varchar(20)) TargetFromDate, Cast(TargetToDate as varchar(20)) TargetToDate, TargetFromDate TargetFromDateSearch,
TargetToDate TargetToDateSearch, convert(varchar, TargetFromDate, 23) TargetFromDate1, convert(varchar, TargetToDate, 23) TargetToDate1, TargetProductIds, TargetPipelineIds, TotalTarget, 

isnull(( case when t.TargetType = 2  then ( 
				iif(t.Conversions = 1, v.ConverstionCount, 0) 
				+  iif(t.Invoices = 1, v.InvoiceCount, 0)
				+  iif(t.Pipelines = 1, v.PipelineCount	, 0)
				)
			when t.TargetType = 1  then ( 
				iif(t.Conversions = 1, v.ConverstionAmount, 0) 
				+  iif(t.Invoices = 1, v.InvoiceAmount, 0)
				+  iif(t.Pipelines = 1, v.PipelineAmount	, 0))
	else 0 end), 0) as [AchievedTarget],
--dbo.GetTotalSalesActivity(t.SalesTargetId, TargetFromDate, TargetToDate) AchievedTarget,
TargetUnit, Currency, t.UserId, t.ParentId, t.Status, t.IsActive, CreatedBy, Cast(CreatedDate as varchar(20)) CreatedDate,
ModifiedBy, Cast(ModifiedDate as varchar(20)) ModifiedDate, 
case when Cast(getdate() as date) < cast(TargetFromDate as date) then 'Upcoming' 
	 when Cast(getdate() as date) > cast(TargetToDate as date) then 'Completed' 
	 when Cast(getdate() as date) between cast(TargetFromDate as date) and cast(TargetToDate as date) then 'Current' 
	 else '' End Duration, (ud1.FName + ' ' + ud1.LName) CreatedByName, '' ModifiedByName from TBL_ST_SalesTargetSettingMaster t   
inner join User_Detail ud1 on t.CreatedBy = ud1.User_ID   
join TBL_ST_SalesTargetSettingChild stsc on stsc.SalesTargetId=t.SalesTargetId
left join #tempAchievedData v on t.SalesTargetId = v.SalesTargetId
join calendar c(nolock) on c.date_id between t.TargetFromDate and t.TargetToDate 
where t.Status = 1 and t.IsActive = 1 
    --and t.UserId in (select User_ID from @tbluser) 
  and  exists (select p from (select value as p from
	      fn_Split(t.UserIds, ',') where isnull(t.UserIds,'') != '' and isnumeric(value) = 1 ) as tbl
	     where p in (    
          SELECT distinct User_ID    
         FROM @tbluser    
                    )
	         )
and TargetFor ='User'  and targetperiodid=3  and day(c.date_id)=day(t.TargetFromDate)

UNION 

select distinct c.date_id,stsc.TeamCode as TargetTeamUserid, t.SalesTargetId, case when TargetType = '1' then 'Revenue' when TargetType = '2' then 'Conversions' else TargetType End TargetType,TargetType TargetTypeSearch, Conversions, Pipelines, Invoices, 
iInvoiceRaised, iInvoicePaid, TargetFor, TeamCodes, UserIds, TargetPeriodId, Cast(TargetFromDate as varchar(20)) TargetFromDate, Cast(TargetToDate as varchar(20)) TargetToDate, TargetFromDate TargetFromDateSearch,
TargetToDate TargetToDateSearch, convert(varchar, TargetFromDate, 23) TargetFromDate1, convert(varchar, TargetToDate, 23) TargetToDate1, TargetProductIds, TargetPipelineIds, TotalTarget, 

isnull(( case when t.TargetType = 2  then ( 
				iif(t.Conversions = 1, v.ConverstionCount, 0) 
				+  iif(t.Invoices = 1, v.InvoiceCount, 0)
				+  iif(t.Pipelines = 1, v.PipelineCount	, 0)
				)
			when t.TargetType = 1  then ( 
				iif(t.Conversions = 1, v.ConverstionAmount, 0) 
				+  iif(t.Invoices = 1, v.InvoiceAmount, 0)
				+  iif(t.Pipelines = 1, v.PipelineAmount	, 0))
	else 0 end), 0) as [AchievedTarget],
--dbo.GetTotalSalesActivity(t.SalesTargetId, TargetFromDate, TargetToDate) AchievedTarget, 
TargetUnit, Currency, t.UserId, t.ParentId, t.Status, t.IsActive, CreatedBy, Cast(CreatedDate as varchar(20)) CreatedDate,
ModifiedBy, Cast(ModifiedDate as varchar(20)) ModifiedDate, 
case when Cast(getdate() as date) < cast(TargetFromDate as date) then 'Upcoming' 
	 when Cast(getdate() as date) > cast(TargetToDate as date) then 'Completed' 
	 when Cast(getdate() as date) between cast(TargetFromDate as date) and cast(TargetToDate as date) then 'Current' 
	 else '' End Duration, (ud1.FName + ' ' + ud1.LName) CreatedByName, '' ModifiedByName from TBL_ST_SalesTargetSettingMaster t   
inner join User_Detail ud1 on t.CreatedBy = ud1.User_ID   
join TBL_ST_SalesTargetSettingChild stsc on stsc.SalesTargetId=t.SalesTargetId
left join #tempAchievedData v on t.SalesTargetId = v.SalesTargetId
join calendar c(nolock) on c.date_id between t.TargetFromDate and t.TargetToDate  
where t.Status = 1 and t.IsActive = 1 
  --and t.UserId in (select User_ID from @tbluser) 
  and ( t.TeamCodes in  
     (  
       select distinct teamcode from @tbluser where isnull(TeamCode,'') !=''
 	 ) or @IsAdmin = 1)
and TargetFor ='Team' and targetperiodid=1 

UNION 

select distinct c.date_id,stsc.TeamCode as TargetTeamUserid, t.SalesTargetId, case when TargetType = '1' then 'Revenue' when TargetType = '2' then 'Conversions' else TargetType End TargetType,TargetType TargetTypeSearch, Conversions, Pipelines, Invoices, 
iInvoiceRaised, iInvoicePaid, TargetFor, TeamCodes, UserIds, TargetPeriodId, Cast(TargetFromDate as varchar(20)) TargetFromDate, Cast(TargetToDate as varchar(20)) TargetToDate, TargetFromDate TargetFromDateSearch,
TargetToDate TargetToDateSearch, convert(varchar, TargetFromDate, 23) TargetFromDate1, convert(varchar, TargetToDate, 23) TargetToDate1, TargetProductIds, TargetPipelineIds, TotalTarget, 
isnull(( case when t.TargetType = 2  then ( 
				iif(t.Conversions = 1, v.ConverstionCount, 0) 
				+  iif(t.Invoices = 1, v.InvoiceCount, 0)
				+  iif(t.Pipelines = 1, v.PipelineCount	, 0)
				)
			when t.TargetType = 1  then ( 
				iif(t.Conversions = 1, v.ConverstionAmount, 0) 
				+  iif(t.Invoices = 1, v.InvoiceAmount, 0)
				+  iif(t.Pipelines = 1, v.PipelineAmount	, 0))
	else 0 end), 0) as [AchievedTarget],
--dbo.GetTotalSalesActivity(t.SalesTargetId, TargetFromDate, TargetToDate) AchievedTarget,
TargetUnit, Currency, t.UserId, t.ParentId, t.Status, t.IsActive, CreatedBy, Cast(CreatedDate as varchar(20)) CreatedDate,
ModifiedBy, Cast(ModifiedDate as varchar(20)) ModifiedDate, 
case when Cast(getdate() as date) < cast(TargetFromDate as date) then 'Upcoming' 
	 when Cast(getdate() as date) > cast(TargetToDate as date) then 'Completed' 
	 when Cast(getdate() as date) between cast(TargetFromDate as date) and cast(TargetToDate as date) then 'Current' 
	 else '' End Duration, (ud1.FName + ' ' + ud1.LName) CreatedByName, '' ModifiedByName from TBL_ST_SalesTargetSettingMaster t   
inner join User_Detail ud1 on t.CreatedBy = ud1.User_ID   
join TBL_ST_SalesTargetSettingChild stsc on stsc.SalesTargetId=t.SalesTargetId
left join #tempAchievedData v on t.SalesTargetId = v.SalesTargetId
join calendar c(nolock) on c.weekday_id = datepart(dw,t.TargetFromDate) and  c.date_id between t.TargetFromDate and t.TargetToDate 
where t.Status = 1 and t.IsActive = 1 
--and t.UserId in (select User_ID from @tbluser) 
 and ( t.TeamCodes in  
     (  
       select distinct teamcode from @tbluser where isnull(TeamCode,'') !=''
 	 ) or @IsAdmin = 1)
and TargetFor ='Team' and targetperiodid=2

UNION 

select distinct c.date_id,stsc.TeamCode as TargetTeamUserid, t.SalesTargetId, case when TargetType = '1' then 'Revenue' when TargetType = '2' then 'Conversions' else TargetType End TargetType,TargetType TargetTypeSearch, Conversions, Pipelines, Invoices, 
iInvoiceRaised, iInvoicePaid, TargetFor, TeamCodes, UserIds, TargetPeriodId, Cast(TargetFromDate as varchar(20)) TargetFromDate, Cast(TargetToDate as varchar(20)) TargetToDate,TargetFromDate TargetFromDateSearch,
TargetToDate TargetToDateSearch, convert(varchar, TargetFromDate, 23) TargetFromDate1, convert(varchar, TargetToDate, 23) TargetToDate1, TargetProductIds, TargetPipelineIds, TotalTarget, 

isnull(( case when t.TargetType = 2  then ( 
				iif(t.Conversions = 1, v.ConverstionCount, 0) 
				+  iif(t.Invoices = 1, v.InvoiceCount, 0)
				+  iif(t.Pipelines = 1, v.PipelineCount	, 0)
				)
			when t.TargetType = 1  then ( 
				iif(t.Conversions = 1, v.ConverstionAmount, 0) 
				+  iif(t.Invoices = 1, v.InvoiceAmount, 0)
				+  iif(t.Pipelines = 1, v.PipelineAmount	, 0))
	else 0 end), 0) as [AchievedTarget],

--dbo.GetTotalSalesActivity(t.SalesTargetId, TargetFromDate, TargetToDate) AchievedTarget,

TargetUnit, Currency, t.UserId, t.ParentId, t.Status, t.IsActive, CreatedBy, Cast(CreatedDate as varchar(20)) CreatedDate,
ModifiedBy, Cast(ModifiedDate as varchar(20)) ModifiedDate, 
case when Cast(getdate() as date) < cast(TargetFromDate as date) then 'Upcoming' 
	 when Cast(getdate() as date) > cast(TargetToDate as date) then 'Completed' 
	 when Cast(getdate() as date) between cast(TargetFromDate as date) and cast(TargetToDate as date) then 'Current' 
	 else '' End Duration, (ud1.FName + ' ' + ud1.LName) CreatedByName, '' ModifiedByName from TBL_ST_SalesTargetSettingMaster t   
inner join User_Detail(nolock) ud1 on t.CreatedBy = ud1.User_ID   
join TBL_ST_SalesTargetSettingChild(nolock) stsc on stsc.SalesTargetId=t.SalesTargetId
left join #tempAchievedData v on t.SalesTargetId = v.SalesTargetId
join calendar c(nolock) on c.date_id between t.TargetFromDate and t.TargetToDate     
where t.Status = 1 and t.IsActive = 1 
and t.UserId in (select User_ID from @tbluser) 
 and ( t.TeamCodes in  
     (  
       select distinct teamcode from @tbluser where isnull(TeamCode,'') !=''
 	 ) or @IsAdmin = 1)
and TargetFor ='Team'  and targetperiodid=3  and day(c.date_id)=day(t.TargetFromDate)
) Tbl 
WHERE 
	--( ( @FromDate IS NULL OR tbl.TargetFromDateSearch <= @FromDate ) AND 
	--  ( @ToDate IS NULL OR tbl.TargetToDateSearch >= @ToDate ) )
	  ( 
		cast(@FromDate as date) between CAST(tbl.TargetFromDateSearch as date) and CAST(tbl.TargetToDateSearch as date)
		or cast(@ToDate as date) between CAST(tbl.TargetFromDateSearch as date) and CAST(tbl.TargetToDateSearch as date)
	  )
	  And 
	  ( @TargetPeriodId =0 OR tbl.TargetPeriodId = @TargetPeriodId) AND 
	  (	@TargetType = 0 OR tbl.TargetTypeSearch = @TargetType ) And
	  ( @TargetFor='' OR tbl.TargetFor=@TargetFor) AND
	  ( @SrchUserids ='' OR Tbl.TargetTeamUserid in (Select value from dbo.fn_Split( @SrchUserids,'#'))) AND
	  ( @SrchTeamids='' OR Tbl.TargetTeamUserid in (Select value from dbo.fn_Split( @SrchUserids,'#')))
	  Order by tbl.SalesTargetId 

  end       
 END TRY         
BEGIN CATCH         
 DECLARE @ErrorMessage NVARCHAR(4000);         
 SELECT @ErrorMessage = ERROR_MESSAGE();         
 RAISERROR (@ErrorMessage, 16, 1);         
END CATCH       
  
EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @actUserID      
 ,@Activity_type = 'View_SaleTrgt'      
 ,@ActionType = 'S'      
 ,@RowJson = ''      
 ,@Table_name = 'TBL_ST_SalesTargetSettingMaster' 

END



