/* ============================================================
   Procedure: [dbo].[usp_SalesTarget_by_FilterMOB]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SalesTarget_by_FilterMOB] (    
 @UserId BIGINT = 0    
 ,@FromDate VARCHAR(50) = NULL    
 ,@ToDate VARCHAR(50) = NULL    
 ,@TargetPeriodId INT = 0    
 ,@TargetType INT = 0    
 ,@TargetFor VARCHAR(10) = ''    
 )    
AS    
SET NOCOUNT ON    
    
BEGIN TRY   

--declare 
--	@UserId BIGINT = 44000,
--	@FromDate VARCHAR(50) = N'2024-01-01',
--	@ToDate VARCHAR(50) = N'2024-12-31',
--	@TargetPeriodId INT = 0,
--	@TargetType INT = 1,
--	@TargetFor VARCHAR(10) = ''  

 BEGIN    
set @TargetType = 1  DECLARE @ParentId BIGINT = 0    
   ,@actUserID BIGINT = @UserId  
    
  SELECT @ParentId = ParentID    
  FROM User_Detail(NOLOCK)    
  WHERE User_ID = @UserId;    
    
  DECLARE @IsAdmin BIT = 0    
  DECLARE @tbluser TABLE (    
   User_ID BIGINT    
   ,Name VARCHAR(100)    
   ,IMAGE VARCHAR(100)    
   )    
    
  SELECT @IsAdmin = IsAdmin    
  FROM User_Detail(NOLOCK)    
  WHERE User_ID = @UserId    
    
  IF (@IsAdmin = 1)    
  BEGIN    
   SET @UserId = 0;    
    
   INSERT INTO @tbluser    
   EXEC Use_GetUserDetails @ParentId    
  END    
  ELSE    
  BEGIN    
   INSERT INTO @tbluser    
   EXEC Use_GetUserDetails @UserId    
  END    
    
  DECLARE @TeamCode VARCHAR(10) = ''    
  DECLARE @ScopeCode VARCHAR(10) = ''    
  DECLARE @UserIdTeamLst VARCHAR(Max) = ''    
  DECLARE @UserLoginTeamLst VARCHAR(Max) = ''    
    
  --select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)                 
  -- select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser    
 
	drop table if exists #tempAchievedData

	select  m.SalesTargetId, m.UserId,
		SUM(case when a.TblRefName = 'invoices' then 1 else 0 end ) as InvoiceCount,
		SUM(case when a.TblRefName = 'LeadInteractionHistory' then 1 else 0 end ) as ConverstionCount,
		SUM(case when a.TblRefName = 'LeadPipelineMapping' then 1 else 0 end ) as PipelineCount,
		SUM(case when a.TblRefName = 'invoices' then a.Amount else 0 end ) as InvoiceAmount,
		SUM(case when a.TblRefName = 'LeadInteractionHistory' then a.Amount else 0 end ) as ConverstionAmount,
		SUM(case when a.TblRefName = 'LeadPipelineMapping' then a.Amount else 0 end ) as PipelineAmount
			into #tempAchievedData
	from TBL_ST_SalesTargetSettingMaster(nolock) m 
		--inner join TBL_ST_SalesTargetSettingChild(nolock) c on m.SalesTargetId = c.SalesTargetId
		--inner join #tempUsers s on c.UserId = s.User_Id
		inner join Tbl_ST_SalesActivityMaster(nolock) a on a.ParentId = m.ParentId and m.SalesTargetId = a.SalesTargetId
			and Cast(a.RecordDate as Date) between Cast(m.TargetFromDate as Date) and Cast(m.TargetToDate as Date)
		where m.ParentId = @ParentId
			group by m.SalesTargetId, m.UserId


  print concat('@UserId => ', @UserId)

  SELECT top 1 t.*, 
	cast(round(((AchievedTarget / TotalTarget) * 100), 2) AS NUMERIC(10, 2)) Achievedpercent    
  FROM (    
   SELECT tbs.SalesTargetId    
    ,CASE     
     WHEN tbs.TargetType = '1'    
      THEN 'Revenue'    
     WHEN tbs.TargetType = '2'    
      THEN 'Conversions'    
     ELSE tbs.TargetType    
     END TargetType    
    ,tbs.Conversions    
    ,tbs.Pipelines    
    ,tbs.Invoices    
    ,tbs.iInvoiceRaised    
    ,tbs.iInvoicePaid    
    ,tbs.TargetFor    
    ,tbs.TeamCodes    
    ,tbs.UserIds    
    ,tbs.TargetPeriodId    
    ,Cast(tbs.TargetFromDate AS VARCHAR(20)) TargetFromDate    
    ,Cast(tbs.TargetToDate AS VARCHAR(20)) TargetToDate    
    ,convert(VARCHAR, tbs.TargetFromDate, 23) TargetFromDate1    
    ,convert(VARCHAR, tbs.TargetToDate, 23) TargetToDate1    
    ,tbs.TargetProductIds    
    ,tbs.TargetPipelineIds    
    --,tbs.TotalTarget    
	, tsc.stTarget as [TotalTarget],
	--, tbs.TotalTarget as [TotalTarget],
    --,dbo.GetTotalSalesActivity(tbs.SalesTargetId, tbs.TargetFromDate, tbs.TargetToDate) AchievedTarget    

	isnull(( case when tbs.TargetType = 2  then ( 
							iif(tbs.Conversions = 1, v.ConverstionCount, 0) 
							+  iif(tbs.Invoices = 1, v.InvoiceCount, 0)
							+  iif(tbs.Pipelines = 1, v.PipelineCount	, 0)
							)
						when tbs.TargetType = 1  then ( 
							iif(tbs.Conversions = 1, v.ConverstionAmount, 0) 
							+  iif(tbs.Invoices = 1, v.InvoiceAmount, 0)
							+  iif(tbs.Pipelines = 1, v.PipelineAmount	, 0))
					else 0 end), 0) as [AchievedTarget]

    ,tbs.TargetUnit    
    ,tbs.Currency    
    ,tbs.UserId    
    ,tbs.ParentId    
    ,tbs.STATUS    
    ,tbs.IsActive    
    ,tbs.CreatedBy    
    ,Cast(tbs.CreatedDate AS VARCHAR(20)) CreatedDate    
    ,tbs.ModifiedBy    
    ,Cast(tbs.ModifiedDate AS VARCHAR(20)) ModifiedDate    
    ,CASE     
     WHEN Cast(getdate() AS DATE) < tbs.TargetFromDate    
      THEN 'Upcoming'    
     WHEN Cast(getdate() AS DATE) > tbs.TargetToDate    
      THEN 'Completed'    
     WHEN Cast(getdate() AS DATE) BETWEEN TargetFromDate    
       AND tbs.TargetToDate    
      THEN 'Current'    
     ELSE ''    
     END Duration    
    ,(ud1.FName + ' ' + ud1.LName) CreatedByName    
    ,'' ModifiedByName 

	FROM TBL_ST_SalesTargetSettingMaster(nolock) tbs
	left join (
			select ts.*, jt.stIsActive, jt.stUserId, jt.stFullName, jt.stTarget, jt.stPercentage, jt.stNumber
			from TBL_ST_SalesTargetSettingUserTarget(nolock) ts
				left join ( select 
					ut.id as TargetId, st.IsActive as [stIsActive], st.UserId as [stUserId], st.FullName as [stFullName],
					st.[Target] as [stTarget], st.[Percentage] as [stPercentage], st.Number as[stNumber]
				from TBL_ST_SalesTargetSettingUserTarget(nolock) ut
					cross apply openjson(isnull(ut.UserSplitDetail, '[]')) with (
					IsActive bit '$.IsActive', 
					UserId bigint '$.UserId',
					FullName bigint '$.UserId',
					[Target] decimal(18,2) '$.Target',
					[Percentage] decimal(18,2) '$.Percentage',	
					Number decimal(18,2) '$.Number'
				) st where ut.ParentId = @ParentId 
			) jt on ts.id = jt.TargetId
	  
where ts.ParentId = @ParentId) tsc on tbs.SalesTargetId = tsc.SalesTargetId
inner join User_Detail(nolock) ud1 on ud1.ParentID = @ParentId 
left join #tempAchievedData v on tbs.SalesTargetId = v.SalesTargetId and tsc.stUserId = v.UserId 
					
--left join #tempAchievedData v on 1  = (case 
--					when tbs.TargetFor = 'team' and tbs.SalesTargetId = v.SalesTargetId then 1
--					when tbs.TargetFor = 'user' and tbs.SalesTargetId = v.SalesTargetId and tsc.UserId = v.UserId then 1
--					else 0 end  )

 --  FROM TBL_ST_SalesTargetSettingMaster(nolock) tbs
	--	left join (select ts.*, jt.stIsActive, jt.stUserId, jt.stFullName, jt.stTarget, jt.stPercentage, jt.stNumber
	--	from TBL_ST_SalesTargetSettingUserTarget(nolock) ts
	--		left join ( select 
	--			ut.id as TargetId, st.IsActive as [stIsActive], st.UserId as [stUserId], st.FullName as [stFullName],
	--			st.[Target] as [stTarget], st.[Percentage] as [stPercentage], st.Number as[stNumber]
	--		from TBL_ST_SalesTargetSettingUserTarget(nolock) ut
	--			cross apply openjson(isnull(ut.UserSplitDetail, '[]')) with (
	--			IsActive bit '$.IsActive', 
	--			UserId bigint '$.UserId',
	--			FullName bigint '$.UserId',
	--			[Target] decimal(18,2) '$.Target',
	--			[Percentage] decimal(18,2) '$.Percentage',	
	--			Number decimal(18,2) '$.Number'
	--		) st where ut.ParentId = @ParentId 
	--	) jt on ts.id = jt.TargetId 
	--where ts.ParentId = @ParentId) tsc on tbs.SalesTargetId = tsc.SalesTargetId

			-- and 1 =  ( case when tbs.TargetFor = 'team' and @actUserID in (select UserId from openjson(tsc.UserSplitDetail)  with (
			--	UserId bigint '$.UserId',
			--	TargetValue decimal(18, 2) '$.Number'
			-- )) then 1 else 0 end )
		--INNER JOIN TBL_ST_SalesTargetSettingChild(nolock) tsc on tbs.SalesTargetId = tsc.SalesTargetId 
		--INNER JOIN User_Detail ud1 ON isnull(tsc.stUserId, 0) = ud1.User_ID    
  WHERE tbs.STATUS = 1 and  tbs.IsActive = 1    
	and cast(getdate() AS DATE) BETWEEN  cast(tsc.FromDate as date) AND cast(tsc.ToDate as date)    
    AND coalesce(tsc.stUserId, tsc.UserId ) = @actUserID  -- IN ( SELECT User_ID FROM @tbluser )    
    --AND (    
    -- CAST(tsc.FromDate as date) BETWEEN Cast(@FromDate AS date) AND Cast(@ToDate AS date)    
    -- AND cast(tsc.ToDate as date) BETWEEN Cast(@FromDate AS date) AND Cast(@ToDate AS date)    
    -- )    
    --AND tbs.TargetPeriodId IN ( CASE  WHEN @TargetPeriodId != '' THEN @TargetPeriodId ELSE tbs.TargetPeriodId END )    
    --AND TargetFor IN ( CASE WHEN @TargetFor = 'User' THEN 'User' 
 	--WHEN @TargetFor = 'Team' THEN 'Team' ELSE tbs.TargetFor END )    
    --AND tbs.TargetType IN (  CASE WHEN @TargetType = 1 THEN 1    
    --  WHEN @TargetType = 2 THEN @TargetType ELSE tbs.TargetType END )    
   ) t   order by SalesTargetId desc
 END    

END TRY    
   
BEGIN CATCH    
 DECLARE @ErrorMessage NVARCHAR(4000);    
    
 SELECT @ErrorMessage = ERROR_MESSAGE();    
    
 RAISERROR (    
   @ErrorMessage    
   ,16    
   ,1    
   );    
END CATCH    
    
EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @actUserID    
 ,@Activity_type = 'View_SaleTrgt'    
 ,@ActionType = 'S'    
 ,@RowJson = ''    
 ,@Table_name = 'TBL_ST_SalesTargetSettingMaster' 



GO

/* ============================================================
   Procedure: [dbo].[usp_SalesTarget_by_SalesTargetId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SalesTarget_by_SalesTargetId]      
(  
 @SalesTargetId bigint = null  
)   
AS   
  SET NOCOUNT ON                 
  BEGIN TRY                 
  begin   
  select *, cast(round( ((AchievedTarget/TotalTarget) * 100),2)as numeric(10,2)) Achievedpercent from (  
 select tbs.SalesTargetId,  
 TargetType, Conversions, Pipelines, Invoices, iInvoiceRaised, iInvoicePaid, TargetFor,    
 TeamCodes, UserIds, TargetPeriodId, Cast(TargetFromDate as varchar(20)) TargetFromDate, Cast(TargetToDate as varchar(20)) TargetToDate,  
FORMAT (TargetFromDate, 'MM-dd-yyyy') TargetFromDate1, FORMAT (TargetToDate, 'MM-dd-yyyy') TargetToDate1,  
 TargetProductIds, TargetPipelineIds, TotalTarget, dbo.GetTotalSalesActivity(tbs.SalesTargetId, TargetFromDate, TargetToDate) AchievedTarget,   
 TargetUnit, Currency, tbs.UserId LoginUserId, tbs.ParentId, tbs.Status, tbs.IsActive, tbs.CreatedBy, Cast(tbs.CreatedDate as varchar(20)) CreatedDate, tbs.ModifiedBy, Cast(tbs.ModifiedDate as varchar(20)) ModifiedDate,    
 case when Cast(getdate() as date) < TargetFromDate then 'Upcoming'   
 when Cast(getdate() as date) > TargetToDate then 'Completed'   
 when Cast(getdate() as date) between TargetFromDate and TargetToDate then 'Current'   
 else ''   
 End Duration, (ud1.FName + ' ' + ud1.LName) CreatedByName,  '' ModifiedByName,  
 stsc1.TeamCode, stsc1.UserId, stsc1.Target, (ud2.FName + ' ' + ud2.LName) FullName, TeamName  
 from TBL_ST_SalesTargetSettingMaster(nolock) tbs   
 inner join User_Detail(nolock) ud1 on tbs.CreatedBy = ud1.User_ID   
 inner join TBL_ST_SalesTargetSettingChild(nolock) stsc1 on tbs.SalesTargetId = stsc1.SalesTargetId  
 inner join User_Detail(nolock) ud2 on stsc1.UserId = ud2.User_ID   
 inner join tbl_UA_TeamMaster(nolock) tm2 on stsc1.TeamCode = tm2.TeamCode   
  where tbs.Status = 1 and tbs.IsActive = 1 and tbs.SalesTargetId = @SalesTargetId   
 ) t  
  
--select * from TBL_ST_SalesTargetSettingChild(nolock) where SalesTargetId = @SalesTargetId  
  
 --order by TargetFromDate              
 --OFFSET  @OffsetValue Rows FETCH NEXT @PagingSize ROWS ONLY     
  end     
 END TRY     
BEGIN CATCH     
 DECLARE @ErrorMessage NVARCHAR(4000);     
 SELECT @ErrorMessage = ERROR_MESSAGE();     
 RAISERROR (@ErrorMessage, 16, 1);     
END CATCH   


GO

/* ============================================================
   Procedure: [dbo].[usp_SalesTargetPagination_by_Filter]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SalesTargetPagination_by_Filter]            
(          
 @UserId bigint = 0   
 ,@FromDate varchar(50) =  null --'2023-11-01' --null,             
 ,@ToDate varchar(50) = null --'2023-12-13' -- null    
 ,@TargetPeriodId int = 0    
 ,@TargetType int = 0    
 ,@TargetFor varchar(10) = ''  
 ,@SrchUserids nvarchar(50) =''  
 ,@SrchTeamids nvarchar(50) =''  
 ,@Offsets int = 0  
 ,@PageSize int = 20  
 ,@FilterText nvarchar(255) = null  
)         
AS                 
BEGIN  
  
 --declare  
	--@UserId bigint = 43468   
	--,@FromDate date =  N'27-May-2025' --'2023-11-01' --null,             
	--,@ToDate date = N'26-May-2026' --'2023-12-13' -- null    
	--,@TargetPeriodId int = 0    
	--,@TargetType int = 0    
	--,@TargetFor varchar(10) = ''   
	--,@SrchUserids nvarchar(50) =''  
	--,@SrchTeamids nvarchar(50) =''  
	--,@FilterText nvarchar(255) = ''  
	--,@Offsets int = 0  
	--,@PageSize int = 20  
   
   
  
 declare   
  @StartPoint int = (@Offsets + 1 ),  
  @EndPoint int = (@Offsets + @PageSize )  
  
  
 declare @parseData datetime = try_convert(datetime, @ToDate)  
   
 if( @parseData is null)  
 begin  
  select @ToDate = format(DATEADD(yy, 1, try_convert(datetime, @FromDate)), 'yyyy-MM-dd')  
 end  
  
 begin try  
   begin  
           
 declare @ParentId bigint = 0  
 select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId;                                
   
 drop table if exists #tempUsers  
 create table #tempUsers(  
  User_Id bigint, Name nvarchar(255), image nvarchar(255), TeamCode nvarchar(255)  
 )  
    insert into #tempUsers  
 exec Use_GetUserDetails_Team @UserId    
   
 drop table if exists #tempAchievedData  
  
	drop table if exists #agentUserId
	create table #agentUserId(
		SalesTargetId bigint,
		UserId bigint,
		StartDate datetime,
		EndDate datetime
	)

	insert into #agentUserId(SalesTargetId, UserId, StartDate, EndDate)
	select m.SalesTargetId, t.UserId, t.FromDate, t.ToDate from TBL_ST_SalesTargetSettingMaster(nolock) m inner join
		TBL_ST_SalesTargetSettingUserTarget(nolock) t on m.SalesTargetId = t.SalesTargetId
			where t.ParentId = @ParentId and m.TargetFor = 'user'

	;WITH SplitUserDetailCTE AS (
		SELECT id, SalesTargetId, FromDate, ToDate, ParentId,
			JSON_VALUE(value, '$.IsActive') AS SplitUserDetail_IsActive,
			JSON_VALUE(value, '$.UserId') AS SplitUserDetail_UserId
		FROM TBL_ST_SalesTargetSettingUserTarget(nolock)
		CROSS APPLY OPENJSON(UserSplitDetail) 
	)
	insert into #agentUserId(SalesTargetId, UserId, StartDate, EndDate)
	SELECT m.SalesTargetId, SplitUserDetail_UserId, FromDate, ToDate FROM SplitUserDetailCTE s
		inner join TBL_ST_SalesTargetSettingMaster(nolock) m on s.SalesTargetId = m.SalesTargetId
			where s.ParentId = @ParentId and m.TargetFor = 'team' and s.SplitUserDetail_IsActive = 'true'

 --select * from #agentUserId
  
 select  m.SalesTargetId, m.UserId, -- cast(a.RecordDate as date) as [RecoredDate], 

  SUM(case when a.TblRefName = 'invoices' then 1 else 0 end ) as InvoiceCount,  
  SUM(case when a.TblRefName = 'LeadInteractionHistory' then 1 else 0 end ) as ConverstionCount,  
  SUM(case when a.TblRefName = 'LeadPipelineMapping' then 1 else 0 end ) as PipelineCount,  
  SUM(case when a.TblRefName = 'invoices' then a.Amount else 0 end ) as InvoiceAmount,  
  SUM(case when a.TblRefName = 'LeadInteractionHistory' then a.Amount else 0 end ) as ConverstionAmount,  
  SUM(case when a.TblRefName = 'LeadPipelineMapping' then a.Amount else 0 end ) as PipelineAmount  
   into #tempAchievedData  
  --from TBL_ST_SalesTargetSettingMaster(nolock) m 
  from #agentUserId(nolock) m 
  --inner join TBL_ST_SalesTargetSettingChild(nolock) c on m.SalesTargetId = c.SalesTargetId  
  --inner join #tempUsers s on c.UserId = s.User_Id  
  inner join Tbl_ST_SalesActivityMaster(nolock) a on a.UserId = m.UserId and m.SalesTargetId = a.SalesTargetId  
   --and Cast(a.RecordDate as Date) between Cast(m.TargetFromDate as Date) and Cast(m.TargetToDate as Date)  
   and Cast(a.RecordDate as Date) between Cast(m.StartDate as Date) and Cast(m.EndDate as Date)  
  where a.ParentId = @ParentId  
  group by m.SalesTargetId, m.UserId --, cast(a.RecordDate as date)  
 
 --row_number() over(partition by (select null) order by SalesTargetId) AS [SNo],  
 --count(1) over( order by (select null)) AS [TotalRows],  
 --date_id, TargetTeamUserid, SalesTargetId, TargetType, TargetTypeSearch, Conversions, Pipelines, Invoices, iInvoiceRaised, iInvoicePaid, TargetFor, TeamCodes, UserIds, TargetPeriodId, TargetFromDate, TargetToDate, TargetFromDateSearch, TargetToDateSearch, TargetFromDate1, TargetToDate1, TargetProductIds, TargetPipelineIds, TotalTarget, AchievedTarget, TargetUnit, Currency, UserId, ParentId, Status, IsActive, CreatedBy, CreatedDate, ModifiedBy, ModifiedDate, Duration, CreatedByName, ModifiedByName,   
 --cast(round( ((AchievedTarget/TotalTarget) * 100),2)as numeric(10,2)) Achievedpercent   
 -----select 'test' , * from  #tempAchievedData   
  
  
  
  select *,  
   cast(round( ((AchievedTarget/NULLIF(TotalTarget, 0)) * 100),2)as numeric(10,2)) Achievedpercent  
  from (   
  select 
   ROW_NUMBER() over (PARTITION BY (SELECT NULL) Order BY m.SalesTargetId desc) as [SNo],   
   count(1) over( order by (select null)) AS [TotalRows],   
    m.SalesTargetName,  
    t.FromDate, cast(t.UserId as varchar) as TargetTeamUserid, t.SalesTargetId,   
    concat( (case when m.TargetType = '1' then 'Revenue' when m.TargetType = '2' then 'Conversions'  when m.TargetType = '3' then 'Points' else m.TargetType End),  
     '<br/>',  
     case when m.Conversions = 1 then '<b>Product</b> ' else '' end,  
     case when m.Pipelines = 1 then '<b>Pipeline</b> ' else '' end,  
     case when m.Invoices = 1 then '<b>Invoice</b> ' else '' end )  
    as [TargetType],   
    m.TargetType TargetTypeSearch, m.Conversions, m.Pipelines, m.Invoices, m.iInvoiceRaised, m.iInvoicePaid,
    concat(UPPER(m.TargetFor), ' ',  case when m.TargetFor = 'team' then z.TeamName  
     when m.TargetFor = 'user' then concat(u.User_Login, '(', u.FName, ' ', u.LName, ')') end, '' ) as [TargetFor],  
    m.TeamCodes, m.UserIds, m.TargetPeriodId, format(t.FromDate, 'dd-MMM-yyyy') as [TargetFromDate], format(t.ToDate, 'dd-MMM-yyyy') as [TargetToDate],   
     m.TargetFromDate TargetFromDateSearch,  m.TargetToDate TargetToDateSearch,   
     convert(varchar, m.TargetFromDate, 23) TargetFromDate1, convert(varchar, m.TargetToDate, 23) TargetToDate1, TargetProductIds, TargetPipelineIds,  
     case when m.TargetFor = 'team' then  coalesce(m.TotalTarget,0) else coalesce( t.Target,0) end as TotalTarget,  
     
	 m.TargetType as [TestingtTargetType],

	 isnull(
	 ( case when m.TargetType = 3  then (   
         CASE WHEN EXISTS ( SELECT 1   
          FROM tbl_SM_Employee_Points_History   
          WHERE TranDate BETWEEN CONCAT(CONVERT(VARCHAR, t.FromDate, 23), ' 00:00:00')   
                 AND CONCAT(CONVERT(VARCHAR, t.ToDate, 23), ' 23:59:59')  
         ) THEN    
          (  
           SELECT COALESCE(SUM(POINTS), 0)   
           FROM tbl_SM_Employee_Points_History PH   
           WHERE --PH.UserId IN (SELECT VALUE FROM STRING_SPLIT(COALESCE(m.UserIds, ''), '#'))  
		     (PH.UserId IN (  CASE WHEN m.TargetFor = 'user' THEN (t.UserId)  ELSE  (SELECT VALUE FROM STRING_SPLIT(COALESCE(m.UserIds, ''), '#')) END))
             AND PH.TranDate BETWEEN CONCAT(CONVERT(VARCHAR, t.FromDate, 23), ' 00:00:00')   
                  AND CONCAT(CONVERT(VARCHAR, t.ToDate, 23), ' 23:59:59')  
          )  
         ELSE 0 END ) 
	 when m.TargetType = 2  then 
		(  iif(m.Conversions = 1, v.ConverstionCount, 0)   
       +  iif(m.Invoices = 1, v.InvoiceCount, 0)  
       +  iif(m.Pipelines = 1, v.PipelineCount , 0))  

      when m.TargetType = 1  then (   
       iif(m.Conversions = 1, v.ConverstionAmount, 0)   
       +  iif(m.Invoices = 1, v.InvoiceAmount, 0)  
       +  iif(m.Pipelines = 1, v.PipelineAmount , 0))  
	   else 0 end
	 ), 0) as [AchievedTarget], 
	
     TargetUnit, Currency, t.UserId, m.ParentId, m.[Status], t.IsActive, m.CreatedBy,   
     format(m.CreatedDate, 'dd-MMM-yyyyy HH:mm:ss') as CreatedDate, m.ModifiedBy,    
     format(m.ModifiedDate, 'dd-MMM-yyyyy HH:mm:ss') as ModifiedDate,   
      ( case when cast(getdate() as date) < cast(t.FromDate as date) then 'Upcoming'   
      when cast(getdate() as date) > cast(t.ToDate as date) then 'Completed'    
      when cast(getdate() as date) between cast(t.FromDate as date) and cast(t.ToDate as date) then 'Current'   
      else '' end) Duration,  
     concat(ud1.FName, ' ', ud1.LName) as [CreatedByName],   
     '' as ModifiedByName,   
     t.id as UserTargetSettingId       
   from TBL_ST_SalesTargetSettingMaster(nolock) m  
    inner join TBL_ST_SalesTargetSettingUserTarget(nolock) t on m.SalesTargetId = t.SalesTargetId  
    --inner join #tempUsers ru on  m.ParentId = @ParentId  
    -- and 1 = ( case when @ParentId = @UserId then 1 when t.UserId = ru.User_Id then 1 else 0 end)  
    left join User_Detail ud1(nolock) on m.CreatedBy = ud1.User_ID     	

	
	left join #tempAchievedData v on 1  = (case   
     when m.TargetFor = 'team' and t.SalesTargetId = v.SalesTargetId then 1  
     when m.TargetFor = 'user' and t.SalesTargetId = v.SalesTargetId and t.UserId = v.UserId then 1  
     else 0 end  )    

    left join TBL_UA_TeamMaster(nolock) z on 1 = (case when m.TargetFor = 'team' then 1 else 0 end ) and z.TeamCode = m.TeamCodes and z.Active = 1  
    left join User_Detail(nolock) u on 1 = (case when m.TargetFor = 'user' then 1 else 0 end ) and u.User_ID = t.UserId  
  where m.ParentId = @ParentId   and ( case when @TargetType = 0 then '1' else m.TargetType  end = case when @TargetType = 0 then '1' else     @TargetType end )
   and 1 = ( case   
      when @ParentId = @UserId then 1   
      when t.UserId in (select User_Id from  #tempUsers)then 1   
     else 0 end)   
   and ( m.TargetFromDate between @FromDate and @ToDate or m.TargetToDate between @FromDate and @ToDate /*t.ToDate*/ )  
   and 1 = (case   
     when ISNULL(@FilterText, '')  = '' then 1   
     when m.TargetFor = 'team' and z.TeamName like '%'+ @FilterText+ '%' then 1   
     when m.TargetFor = 'user' and u.User_Login like '%'+ @FilterText+ '%' then 1   
     else 0 end  

    )  
 ) t where t.SNo between @StartPoint and @EndPoint 

 print concat('%', @FilterText, '%')  
  
   end     
  END TRY           
 BEGIN CATCH           
  DECLARE @ErrorMessage NVARCHAR(4000);           
  SELECT @ErrorMessage = ERROR_MESSAGE();           
  RAISERROR (@ErrorMessage, 16, 1);           
 END CATCH         
    
 EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId        
  ,@Activity_type = 'View_SaleTrgt'        
  ,@ActionType = 'S'        
  ,@RowJson = ''        
  ,@Table_name = 'TBL_ST_SalesTargetSettingMaster'   
  
END  



GO

/* ============================================================
   Procedure: [dbo].[usp_SalesTargetSettingChild_by_SalesTargetId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SalesTargetSettingChild_by_SalesTargetId]        
(    
	--@OffsetValue int = 0,                                          
	--@PagingSize int  = 20,                                          
	@SalesTargetId bigint,
	@TargetId bigint = 0
)     
AS 
BEGIN
	--DECLARE 
	--	@SalesTargetId BIGINT = 341,
	--	@TargetId bigint = 166

	SET NOCOUNT ON     
	BEGIN TRY 
		
		declare @UserSplitDatails nvarchar(max) 

		declare @TargetFor nvarchar(25) = ''

		select @TargetFor = TargetFor from TBL_ST_SalesTargetSettingMaster(nolock)
			where SalesTargetId = @SalesTargetId

		DROP TABLE IF EXISTS #tblSplitData
		CREATE TABLE #tblSplitData (
			id INT,
			SalesTargetId INT,
			TeamCode NVARCHAR(50),
			UserId INT,
			Target DECIMAL(18, 2),
			TargetNumber DECIMAL(18, 2),
			TargetPercentage DECIMAL(5, 2),
			TargetType INT,
			FromDate DATE,
			ToDate DATE,
			ParentId INT,
			IsActive BIT,
			CreatedOn DATETIME,
			SplitUserId INT,
			SplitFullName NVARCHAR(100),
			SplitTarget DECIMAL(18, 2),
			SplitPercentage DECIMAL(5, 2),
			SplitNumber DECIMAL(18, 2),
			SplitIsActive BIT
		);

		if(@TargetFor = 'user')
		begin
			INSERT INTO #tblSplitData ( id, SalesTargetId, TeamCode, UserId, Target, TargetNumber, TargetPercentage,
				TargetType, FromDate, ToDate,  ParentId, IsActive, CreatedOn, SplitUserId, SplitFullName, SplitTarget, 
				SplitPercentage, SplitNumber,  SplitIsActive )
			 SELECT t.id, t.SalesTargetId, t.TeamCode, t.UserId, t.Target, t.TargetNumber, t.TargetPercentage,
				t.TargetType, t.FromDate, t.ToDate, t.ParentId, t.IsActive, t.CreatedOn, t.UserId AS SplitUserId, 
				'' AS SplitFullName, CAST(t.TargetNumber AS DECIMAL(18, 2)) AS SplitTarget, 
				CAST(t.TargetPercentage AS DECIMAL(5, 2)) AS SplitPercentage, CAST(t.TargetNumber AS DECIMAL(18, 2)) AS SplitNumber,
				t.IsActive AS SplitIsActive
			FROM  TBL_ST_SalesTargetSettingUserTarget(nolock) t 
				where t.id = @TargetId and  t.SalesTargetId = @SalesTargetId 
		end
		begin
			INSERT INTO #tblSplitData ( id, SalesTargetId, TeamCode, UserId, Target, TargetNumber, TargetPercentage,
				TargetType, FromDate, ToDate,  ParentId, IsActive, CreatedOn, SplitUserId, SplitFullName, SplitTarget, 
				SplitPercentage, SplitNumber,  SplitIsActive )
			SELECT t.id, t.SalesTargetId, t.TeamCode, t.UserId, t.Target, t.TargetNumber, t.TargetPercentage,
				t.TargetType, t.FromDate, t.ToDate, t.ParentId, t.IsActive, t.CreatedOn, u.UserId AS SplitUserId, 
				u.FullName AS SplitFullName, CAST(u.Target AS DECIMAL(18, 2)) AS SplitTarget, 
				CAST(u.Percentage AS DECIMAL(5, 2)) AS SplitPercentage, CAST(u.Number AS DECIMAL(18, 2)) AS SplitNumber,
				u.IsActive AS SplitIsActive
			FROM  TBL_ST_SalesTargetSettingUserTarget(nolock) t 
				CROSS APPLY  OPENJSON(t.UserSplitDetail) WITH (
					IsActive BIT,
					UserId INT,
					FullName NVARCHAR(100),
					Target NVARCHAR(50),
					Percentage NVARCHAR(50),
					Number NVARCHAR(50)
				) u where t.SalesTargetId = @SalesTargetId;
		end

		SELECT 
			ROW_NUMBER() OVER (PARTITION BY tss.ParentId order by (select null)) as  [SalesTargetChildId],
			tss.SalesTargetId, tss.TeamCode, tss.SplitUserId as UserId, tss.SplitTarget as [Target], tss.SplitIsActive as [IsActive],
			(Ud1.FName +' '+Ud1.LName) UserName, tm1.TeamName, JSON_VALUE(SettingJSON, '$.CalculateBy') as [CalculateUnit],
			tss.SplitNumber, tss.SplitPercentage, st.TotalTarget
		FROM #tblSplitData tss
			INNER JOIN TBL_ST_SalesTargetSettingMaster(nolock) st on tss.SalesTargetId = st.SalesTargetId
			LEFT JOIN TBL_UA_TeamMaster tm1 on tss.TeamCode = tm1.TeamCode and @TargetFor = 'team'
			LEFT JOIN User_Detail Ud1 on tss.SplitUserId = Ud1.User_ID 

		--SELECT *
		--	--tss.*, (Ud1.FName +' '+Ud1.LName) UserName, tm1.TeamName 
		--FROM [dbo].[TBL_ST_SalesTargetSettingChild] tss    
		--	inner join User_Detail Ud1 on tss.UserId = Ud1.User_ID    
		--	inner join TBL_UA_TeamMaster tm1 on tss.TeamCode = tm1.TeamCode  
		--where tss.SalesTargetId = @SalesTargetId      
	END TRY       
	BEGIN CATCH       
	DECLARE @ErrorMessage NVARCHAR(4000);       
	SELECT @ErrorMessage = ERROR_MESSAGE();       
	RAISERROR (@ErrorMessage, 16, 1);       
	END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_Save_Acres99_Details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_Save_Acres99_Details (
	@Acres99UserName_Key NVARCHAR(500)
	,@Acress99_PWD NVARCHAR(200)
	,@Kit19UserID BIGINT
	)
AS
BEGIN
	DECLARE @Kit19ParentID BIGINT = 0
		,@flg BIT = 0

	SELECT @Kit19ParentID = ISNULL(ParentID, 0)
	FROM User_Detail
	WHERE User_ID = @Kit19UserID

	IF (
			EXISTS (
				SELECT 'x'
				FROM Acres99_Mapping
				WHERE Acres_UserName = @Acres99UserName_Key
				)
			)
	BEGIN
		--   select 'This key already exists'      
		IF EXISTS (
				SELECT 1
				FROM Acres99_Mapping(NOLOCK)
				WHERE Acres_UserName = @Acres99UserName_Key
					AND Kit19ParentId = @Kit19ParentID
				)
		BEGIN
			SELECT 'This Id is already mapped with your account'
		END
		ELSE IF EXISTS (
				SELECT 1
				FROM Acres99_Mapping(NOLOCK)
				WHERE Acres_UserName = @Acres99UserName_Key
					AND Kit19ParentId <> @Kit19ParentID
				)
		BEGIN
			SELECT 'Sorry ! This Id is mapped with some other account. If this 99acres id belongs to you, Please contact us'
		END
	END
	ELSE
	BEGIN
		INSERT INTO Acres99_Mapping (
			Acres_UserName
			,Acres_PWD
			,Kit19ParentID
			,STATUS
			,CreatedOn
			,CreatedBy
			)
		VALUES (
			@Acres99UserName_Key
			,@Acress99_PWD
			,@Kit19ParentID
			,0
			,GETDATE()
			,@Kit19UserID
			)

		SELECT 'This Id got mapped with your account'

		SET @flg = 1
	END

	IF @flg = 1
	BEGIN
		DECLARE @rowJson VARCHAR(MAX) = (
				SELECT *
				FROM Acres99_Mapping(NOLOCK)
				WHERE Acres_UserName = @Acres99UserName_Key
					AND Kit19ParentId = @Kit19ParentID
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)

		IF @rowJson IS NOT NULL
		BEGIN
			EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @Kit19UserID
				,@Activity_type = 'Inst_99acrsMppng'
				,@ActionType = 'I'
				,@RowJson = @rowJson
				,@Table_name = 'Acres99_Mapping'
		END
	END
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_Save_DLT_Entity_Details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




CREATE   PROCEDURE [dbo].[Usp_Save_DLT_Entity_Details] (
	@PE_ID NVARCHAR(100)
	,@EntityName NVARCHAR(200)
	,@UserID BIGINT
	)
AS
BEGIN
	DECLARE @ParentID BIGINT = 0
		,@dltid BIGINT

	SELECT @ParentID = isnull(ParentID, 0)
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserID

	IF (
			NOT EXISTS (
				SELECT 1
				FROM DLTdetails(NOLOCK)
				WHERE Parentid = @ParentID
				)
			)
	BEGIN
		INSERT INTO DLTdetails (
			[Parentid]
			,[PE_ID]
			,[createdon]
			,[createdby]
			,[Activestatus]
			,[expirydate]
			,[remarks]
			,[EntityName]
			)
		VALUES (
			@ParentID
			,@PE_ID
			,GETDATE()
			,@UserID
			,1
			,NULL
			,'DLT Entity ' + @PE_ID + ' Added'
			,@EntityName
			)

		SELECT @dltid = SCOPE_IDENTITY()

		SELECT 'DLT Added Successfully'

       /*  
		BEGIN TRY
			INSERT INTO dbo.DLTdetails (
				[Parentid]
				,[PE_ID]
				,[createdon]
				,[createdby]
				,[Activestatus]
				,[expirydate]
				,[remarks]
				,[EntityName]
				)
			SELECT [Parentid]
				,[PE_ID]
				,[createdon]
				,[createdby]
				,[Activestatus]
				,[expirydate]
				,[remarks]
				,[EntityName]
			FROM dltdetails WITH (NOLOCK)
			WHERE id = @dltid
		END TRY

		BEGIN CATCH
			EXEC usp_inserterrorinfo
		END CATCH
       */ 

		DECLARE @rowJson NVARCHAR(MAX) = (
				SELECT *
				FROM DLTdetails WITH(NOLOCK)
				WHERE id = @dltid
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)

		IF @rowJson IS NOT NULL
		BEGIN
			EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
				,@Activity_type = 'Inst_DLT_Reg'
				,@ActionType = 'I'
				,@RowJson = @rowJson
				,@Table_name = 'DLTdetails'
		END
	END
	ELSE
	BEGIN
		SELECT 'DLT Entity Already Exists for this ParentID'
	END
END




GO

