CREATE   PROCEDURE [dbo].[Usp_Save_DLTTemplateID_with_BatchID]   
(   
 @BatchID nvarchar(100),   
 @DLTTemplateID nvarchar(200)   
)   
as   
Begin   
 declare @did bigint,@scheduledate varchar(50) ,@flash int,@tr int,@is_stock bit=0   
 select top 1 @is_stock=is_stock from usermailtemplate(nolock) where DLT_TemplateID=@DLTTemplateID   
 insert into DLT_Template_MSG   
 (BatchID,DLT_TemplateID,dlt_is_stock)   
 values(@BatchID,@DLTTemplateID,@is_stock)   
 select @did=scope_identity()   
   
 if exists(select 1 from batchinfo(nolock) where batchid=@batchid)   
 begin   
 select top 1 @scheduledate=scheduleddate,@flash=IsFlash,@tr=TotalRecords from batchinfo(nolock) where batchid=@batchid   
 update [DLT_Template_MSG] set batchtime=cast(isnull(nullif(@scheduledate,''),getdate()) as varchar),flash=@flash,   
 total_records=@tr   
 where batchid=@batchid   
 end   
 
 --begin try   
   
