 ----select DTM.BatchID,DTM.DLT_TemplateID,DTM.dlt_is_stock,DTM.flash,DTM.batchtime,DTM.DLT_MSG_CreatedOn,DTM.total_processed,DTM.total_records,DTM.batch_completetime   
 ----from DLT_Template_MSG as DTM with(nolock) where id=@did   

 -- insert into dbo.DLT_Template_MSG(BatchID,DLT_TemplateID,dlt_is_stock,flash,batchtime,DLT_MSG_CreatedOn,total_processed,total_records,batch_completetime)   
 --select DTM.BatchID,DTM.DLT_TemplateID,DTM.dlt_is_stock,DTM.flash,DTM.batchtime,DTM.DLT_MSG_CreatedOn,DTM.total_processed,DTM.total_records,DTM.batch_completetime   
 --from DLT_Template_MSG as DTM with(nolock) where id=@did   
 -- end   
 --end try   
 --begin catch   
 --exec usp_inserterrorinfo   
 --end catch   
  
   
      
End  
  
  


