/* ============================================================
   Procedure: [dbo].[Usp_Save_MagicBricksKeyDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_Save_MagicBricksKeyDetails (
	@MagicBricks_Key NVARCHAR(500)
	,@Kit19ParentID BIGINT
	,@Kit19UserID BIGINT
	)
AS
BEGIN
	DECLARE @id BIT = 0

	IF (
			EXISTS (
				SELECT 'x'
				FROM MagicBricks
				WHERE MagicBrickKey = @MagicBricks_Key
				)
			)
	BEGIN
		--   select 'This key already exists'      
		IF EXISTS (
				SELECT 1
				FROM MagicBricks(NOLOCK)
				WHERE MagicBrickKey = @MagicBricks_Key
					AND Kit19ParentId = @Kit19ParentID
				)
		BEGIN
			SELECT 'This Id is already mapped with your account'
		END
		ELSE IF EXISTS (
				SELECT 1
				FROM MagicBricks(NOLOCK)
				WHERE MagicBrickKey = @MagicBricks_Key
					AND Kit19ParentId <> @Kit19ParentID
				)
		BEGIN
			SELECT 'Sorry ! This Id is mapped with some other account. If this TradeIndia id belongs to you, Please contact us'
		END
	END
	ELSE
	BEGIN
		INSERT INTO MagicBricks (
			MagicBrickKey
			,Kit19ParentID
			,STATUS
			,CreatedOn
			,ModifiedOn
			,CreatedBy
			)
		VALUES (
			@MagicBricks_Key
			,@Kit19ParentID
			,0
			,GETDATE()
			,GETDATE()
			,@Kit19UserID
			)

		SET @id = 1

		SELECT 'This Id got mapped with your account'
	END

	IF @id = 1
	BEGIN
		DECLARE @rowJson VARCHAR(MAX) = (
				SELECT *
				FROM MagicBricks(NOLOCK)
				WHERE MagicBrickKey = @MagicBricks_Key
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)

		IF @rowJson IS NOT NULL
		BEGIN
			EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @Kit19UserID
				,@Activity_type = 'Inst_MgcBrk_Mppng'
				,@ActionType = 'I'
				,@RowJson = @rowJson
				,@Table_name = 'MagicBricks'
		END
	END
END



GO

