/* ============================================================
   Procedure: [dbo].[usp_save_territory_details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_save_territory_details @Name='janak puri',@Description='vikas puri desc',@PersonDetail='34126`abhishek78`Manager|34127`abhishek79`User|34128`abhishek80`User|',@TID=37,@ParentID=32222,@CreatedBy=32222
CREATE   PROC dbo.usp_save_territory_details (
	@Name VARCHAR(100)
	,@Description VARCHAR(500)
	,@PersonDetail VARCHAR(max)
	,@TID BIGINT
	,@ParentID BIGINT
	,@CreatedBy BIGINT
	)
AS
BEGIN
	DECLARE @TerritoryID BIGINT
	DECLARE @OldTerritoryID BIGINT
		,@activity VARCHAR(MAX) = ''
		,@action VARCHAR(1)

	IF (@TID = 0) -- Insert
	BEGIN
		IF EXISTS (
				SELECT *
				FROM tbl_location_territory
				WHERE Name = @Name
					AND ParentID = @ParentID
				)
		BEGIN
			SELECT @TerritoryID = ID
			FROM tbl_location_territory
			WHERE Name = @Name
				AND ParentID = @ParentID

			DELETE
			FROM tbl_location_territory_mapping
			WHERE Territory_Id = @TerritoryID
		END
		ELSE
		BEGIN
			INSERT INTO tbl_location_territory (
				Name
				,Description
				,ParentID
				,CreatedBy
				,CreatedOn
				)
			VALUES (
				@Name
				,@Description
				,@ParentID
				,@CreatedBy
				,getdate()
				)

			SET @TerritoryID = SCOPE_IDENTITY()
			SET @action = 'I'
			SET @activity = 'Inst_Locatn_Tritory'
		END
	END
	ELSE -- Update
	BEGIN
		IF EXISTS (
				SELECT *
				FROM tbl_location_territory
				WHERE ID != @TID
					AND Name = @Name
					AND ParentID = @ParentID
				)
		BEGIN
			RETURN
		END

		BEGIN
			SET @TerritoryID = @TID

			DELETE
			FROM tbl_location_territory_mapping
			WHERE Territory_Id = @TerritoryID
		END

		UPDATE tbl_location_territory
		SET Name = @Name
			,Description = @Description
			,CreatedBy = @CreatedBy
			,CreatedOn = getdate()
		WHERE ID = @TID

		SET @action = 'U'
		SET @activity = 'Updt_Locatn_Tritory'
	END

	--if exists(select * from tbl_location_territory where Name = @Name and ParentID = @ParentID)          
	--begin   
	--select @OldTerritoryID=ID from tbl_location_territory where Name = @Name and ParentID = @ParentID
	--Delete from  tbl_location_territory_mapping where Territory_Id = @OldTerritoryID  
	--Delete from tbl_location_territory where Name = @Name and ParentID = @ParentID      
	--end      
	--insert into tbl_location_territory (Name, Description,ParentID,CreatedBy,CreatedOn)      
	--values(@Name, @Description,@ParentID,@CreatedBy,getdate())      
	--set @TerritoryID = SCOPE_IDENTITY()      
	CREATE TABLE #temp123 (columnname VARCHAR(500))

	INSERT INTO #temp123
	SELECT *
	FROM dbo.SplitString(@PersonDetail, '|')

	DECLARE @delimiter VARCHAR(50)

	SET @delimiter = '`';

	WITH CTE
	AS (
		SELECT CAST('<M>' + REPLACE(columnname, @delimiter, '</M><M>') + '</M>' AS XML) AS [columnname XML]
		FROM #temp123
		)
	INSERT INTO tbl_location_territory_mapping (
		Territory_Id
		,User_ID
		,PersonName
		,ROLE
		)
	SELECT @TerritoryID AS Territory_Id
		,[columnname XML].value('/M[1]', 'bigint') AS User_ID
		,[columnname XML].value('/M[2]', 'varchar(50)') AS PersonName
		,[columnname XML].value('/M[3]', 'varchar(50)') AS ROLE
	FROM CTE

	DROP TABLE #temp123

	DELETE
	FROM tbl_location_territory_mapping
	WHERE User_ID = 0
		AND Territory_Id = @TerritoryID

	SELECT @TerritoryID

	DECLARE @rowJson VARCHAR(MAX) = (
			SELECT *
			FROM tbl_location_territory(NOLOCK)
			WHERE id = @TerritoryID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy
			,@Activity_type = @activity
			,@ActionType = @action
			,@RowJson = @rowJson
			,@Table_name = 'tbl_location_territory'
	END
END



GO

