	,@Trade_UserID NVARCHAR(100)
	,@Trade_ProfileID NVARCHAR(100)
	,@Kit19ParentID BIGINT
	,@Kit19UserID BIGINT
	)
AS
BEGIN
	IF (
			EXISTS (
				SELECT 'x'
				FROM TradeIndia_Mapping
				WHERE TradeIndia_Key = @TradeIndia_Key
				)
			)
	BEGIN
		--   select 'This key already exists'    
		IF EXISTS (
				SELECT 1
				FROM TradeIndia_Mapping(NOLOCK)
				WHERE TradeIndia_Key = @TradeIndia_Key
					AND Kit19ParentId = @Kit19ParentID
				)
		BEGIN
			SELECT 'This Id is already mapped with your account'
		END
		ELSE IF EXISTS (
				SELECT 1
				FROM TradeIndia_Mapping(NOLOCK)
				WHERE TradeIndia_Key = @TradeIndia_Key
					AND Kit19ParentId <> @Kit19ParentID
				)
		BEGIN
			SELECT 'Sorry ! This Id is mapped with some other account. If this TradeIndia id belongs to you, Please contact us'
		END
	END
	ELSE
	BEGIN
		INSERT INTO TradeIndia_Mapping (
			TradeIndia_Key
			,Kit19ParentID
			,Trade_UserID
			,Trade_ProfileID
			,STATUS
			,CreatedOn
			,ModifiedOn
			,CreatedBy
			)
		VALUES (
			@TradeIndia_Key
			,@Kit19ParentID
			,@Trade_UserID
			,@Trade_ProfileID
			,0
			,GETDATE()
			,GETDATE()
			,@Kit19UserID
			)

		DECLARE @id BIGINT = SCOPE_IDENTITY()

		SELECT 'This Id got mapped with your account'
	END

	DECLARE @rowJson VARCHAR(MAX) = (
			SELECT *
			FROM TradeIndia_Mapping(NOLOCK)
			WHERE id = @id
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @Kit19UserID
			,@Activity_type = 'Inst_TrdInd_Mppng'
			,@ActionType = 'I'
			,@RowJson = @rowJson
			,@Table_name = 'TradeIndia_Mapping'
	END
END



