/* ============================================================
   Procedure: [dbo].[usp_save_voice_bot_sessionid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_save_voice_bot_sessionid
@calllogid bigint,@sessionid nvarchar(200),@bot_sp nvarchar(100)
as
begin
declare @caller nvarchar(20),@parentid bigint,@entity nvarchar(20),@entityid bigint,@botid bigint,@c_bot_sp nvarchar(100)
select @caller=customernumber,@parentid=parentid,@entity=customerentity,@entityid=customerentityid,@botid=bot_id from calllog(nolock) where id=@calllogid
if not exists(select 1 from voice_bot_sessions(nolock) where parentid=@parentid and entity=@entity and entityid=@entityid and isactive=1 
and bot_sp=@bot_sp)
begin
insert into voice_bot_sessions(callerid,parentid,entity,entityid,bot_sp,sessionid,isactive)
select @caller,@parentid,@entity,@entityid,@bot_sp,1,@sessionid
end
else
begin
update voice_bot_sessions set sessionid=@sessionid where sessionid<>@sessionid and parentid=@parentid and entity=@entity and entityid=@entityid and isactive=1 and bot_sp=@bot_sp
end 

end



GO

