(    
   @JsonData nvarchar(max),    
   --@ParentID  bigint     
   @UserKey  nvarchar(200)    
)    
as    
 begin    
       
     drop table if exists #tempAcrData  
       
     Declare @99AcreAPI_Id bigint = 0      
   
    if(not exists( select 1 from tbl_99acreJson with(nolock) where JsonData = @JsonData and UserKey = @UserKey    
            and isnull(@JsonData,'')  != '' and isnull(@UserKey,'') != ''           
      ))    
