/* ============================================================
   Procedure: [dbo].[Usp_SaveAccountSetupStageForKit19]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



 CREATE   PROCEDURE dbo.Usp_SaveAccountSetupStageForKit19                
  (                
    @Enqno bigint,                
    @Stage nvarchar(500),                
    @User Bigint,                
    @AssignedTo bigint,                
    @Remarks nvarchar(500),                
    @UserBy bigint,                
    @CreatedBy bigint                  
  )                
                  
  as                
  Begin                
               
  CREATE TABLE #TempLinked                                      
    (                                      
      Result VARCHAR(200)                                      
    )             
                        
     INSERT INTO #TempLinked                                      
     EXEC GetStatusofLinkedServer 'CRM'                                      
     IF NOT EXISTS(                                      
        SELECT 'x'                                      
       FROM   #TempLinked                                      
    )                           
    
   begin       
    
  if(not exists( select 1 from CRM.CRMDB.dbo.AccountSetup where EnqNo = @Enqno and UserBy = @UserBy and Stage = 'Customer Accepted Setup Request' ))  
    
  Begin  
  
  
    
   Declare @AssignedToVar bigint = 0            
            
  if(@Stage = 'Not Verified')              
  Begin              
                
             
            
 select top 1  @AssignedToVar = AssignedTo from  CRM.CRMDB.dbo.AccountSetup where EnqNo = @Enqno and Stage = 'Assigned' order by AccountSetupID desc            
            
  if(@AssignedTo = 0)            
    begin            
      set  @AssignedTo = @AssignedToVar            
    end            
                    
            
            
   insert into CRM.CRMDB.dbo.AccountSetup ( Enqno ,Stage ,[User] ,AssignedTo , Remarks ,UserBy , CreatedDate, CreatedBy )                
    values                
    (  @Enqno ,@Stage , @User ,@AssignedTo, @Remarks , @UserBy , GETDATE(),@CreatedBy )              
                  
                
    insert into CRM.CRMDB.dbo.AccountSetup ( Enqno ,Stage ,[User] ,AssignedTo , Remarks ,UserBy , CreatedDate, CreatedBy )                
    values                
    (  @Enqno ,'Assigned' , @User , @AssignedTo ,'Reassigned after not verified', @UserBy , GETDATE(),@CreatedBy )              
                  
     select 'Record Saved Successfully'                      
  End           
 else if(@Stage = 'Reassign')          
  Begin          
 insert into CRM.CRMDB.dbo.AccountSetup( Enqno ,Stage ,[User], AssignedTo , Remarks , UserBy ,CreatedDate,CreatedBy )                
     values                
       (  @Enqno , 'Assigned' , @User , @AssignedTo ,@Remarks ,@UserBy ,GETDATE(),@CreatedBy )                
                         
    select 'Record Saved Successfully'          
 End                      
 else              
    Begin            
             
 select top 1  @AssignedToVar = AssignedTo from CRM.CRMDB.dbo.AccountSetup where EnqNo = @Enqno and Stage = 'Assigned'            
  order by AccountSetupID desc            
            
  if(@AssignedTo = 0)            
    begin            
      set  @AssignedTo = @AssignedToVar            
    end            
            
               
   insert into CRM.CRMDB.dbo.AccountSetup( Enqno ,Stage ,[User], AssignedTo , Remarks , UserBy ,CreatedDate,CreatedBy )                
     values                
     (  @Enqno , @Stage , @User , @AssignedTo ,@Remarks ,@UserBy ,GETDATE(),@CreatedBy )            
          
  deClare @setupid bigint=SCOPE_IDENTITY()        
             
     if   @Stage='Requested'        
     begin        
     update CRM.CRMDB.dbo.AccountSetup set OTP=10000+CAST(RAND()*10000 as INT) WHERE AccountSetupID=@setupid        
     end          
                           
                         
    select 'Record Saved Successfully'                     
  end              
    
              
   end        
  end  
    
  drop table #TempLinked;                 
      
      
  End 





GO

/* ============================================================
   Procedure: [dbo].[usp_SaveActivityJson]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_SaveActivityJson
(     
	@ActivityType NVARCHAR(20), -- Lead, Enquiry
	@ActivityJson NVARCHAR(MAX) 
)
AS
BEGIN
begin try
-- declare @ActivityType NVARCHAR(20)='Lead',@ActivityJson NVARCHAR(MAX)='[{"Historyid":447117,"UserID":33819,"LeadID":400636,"ParentID":33819,"EventDescription":"parallel678633 sent a SMS with senderid PELSFT and message text Your customers prefer to communicate with whatsapp,So Kit19 integrates whatsapp api in your business to jump your sales & service.{#var#} to mobile 7840049991 through automated campaign named Task Added_40_SMS","EventID":1,"reftables":"Batchinfo","refids":"66754034"},{"Historyid":447134,"UserID":33819,"LeadID":400636,"ParentID":33819,"EventDescription":"parallel678633 sent a SMS with senderid PELSFT and message text Your customers prefer to communicate with whatsapp,So Kit19 integrates whatsapp api in your business to jump your sales & service.{#var#} to mobile 7840049991 through automated campaign named Task Added_40_SMS","EventID":1,"reftables":"Batchinfo","refids":"66754056"}]' 

	IF(@ActivityType = 'Lead')    
	BEGIN
		INSERT INTO tbl_LeadEventHistory([ParentID], [UserID], [LeadID], [EventDescription], [EventDate], [EventID], [reftables], [refids], [refColName], [refHistoryId], [WorkflowId])     
		Select [ParentID], [UserID], [LeadID], [EventDescription], [EventDate], [EventID], [reftables], [refids], [refColName], [refHistoryId], [WorkflowId]
		From Openjson(@ActivityJson)
		With
		(
			UserID					bigint				'$.UserID',
			LeadID					bigint				'$.LeadID',
			ParentID				bigint				'$.ParentId',
			EventDescription		nvarchar(max)		'$.EventDescription',
			EventDate				datetime			'$.EventDate',
			EventID					bigint				'$.EventID',
			reftables				nvarchar(1000)		'$.reftables',
			refids					nvarchar(1000)		'$.refids',
			refColName				varchar(100)		'$.refColName',
			refHistoryId			bigint				'$.refHistoryId',
			WorkflowId				bigint				'$.WorkflowId'
		);    
	END

	IF(@ActivityType = 'Enquiry')
	BEGIN
		INSERT INTO tbl_EnquiryEventHistory([ParentID], [UserID], [EnquiryID], [EventDescription], [EventDate], [EventID], [reftables], [refids])
		Select [ParentID], [UserID], [LeadID], [EventDescription], [EventDate], [EventID], [reftables], [refids]
		From Openjson(@ActivityJson)
		With
		(
			UserID					bigint				'$.UserID',
			LeadID					bigint				'$.LeadID',
			ParentID				bigint				'$.ParentId',
			EventDescription		nvarchar(max)		'$.EventDescription',
			EventDate				datetime			'$.EventDate',
			EventID					bigint				'$.EventID',
			reftables				nvarchar(1000)		'$.reftables',
			refids					nvarchar(1000)		'$.refids'
		);    
	END
end try
begin catch  
 exec usp_InsertErrorInfo  
end catch  
END;



GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveAdDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveAdDetails    
(    
  -- ad      
  @AdName nvarchar(500),      
  @Ad_Content nvarchar(max),      
  @Ad_Instruction nvarchar(max),      
  @Amount numeric(18,2),      
  @ScheduledDays nvarchar(max),      
  @StartDate nvarchar(50),      
  @EndDate nvarchar(50),      
  @AdDocTBL  as AdDocTBLType   readonly,         
  @Status nvarchar(500),      
    
 --page      
    
  @PageID  bigint,      
  @UserID bigint,      
  @ParentID bigint         
    
)    
as    
Begin    
     
  
  
  
  
  
  
   Declare @AdRequestID bigint = 0       
   Declare @EndDatetime datetime = null      
   Declare @StartDatetime datetime = null      
      
   if(@EndDate <> '')      
      Begin      
        select @EndDatetime = Convert(datetime,@EndDate)      
      End      
      
   if(@StartDate <> '')      
      Begin      
        select @StartDatetime = Convert(datetime,@StartDate)      
      End      
    
    
             
    insert into AdRequests      
    (      
    [PageID]      
      ,[AddName]      
      ,[RequestType]      
      ,[Content]      
      ,[Remarks]      
      ,[Amount]      
      ,[CreatedOn]      
      ,[CreatedBy]      
       )      
    values      
 (      
   @PageID,      
   @AdName,      
   @status,      
   @Ad_Content,      
   @Ad_Instruction,      
   @Amount,      
   getdate(),      
   @UserID      
 )      
      
    select @AdRequestID = SCOPE_IDENTITY()       
      
   insert into AdRequestHistory      
    (      
    [RequestID]      
      ,[URL]      
      ,[AssignedTo]      
      ,[Status]      
      ,[ScheduledDays]      
      ,[StartDate]      
      ,[EndDate]      
      ,[CreatedOn]      
      ,[CreatedBy]      
    )      
    values      
    (      
     @AdRequestID,      
     null,      
     null,      
     @Status,      
     @ScheduledDays,      
     @StartDatetime,      
     @EndDatetime,      
     getdate(),      
     @UserID      
    )      
          
   insert into AdDocs      
    (      
      RequestID,      
      DocPath      
    )      
    select @AdRequestID , DocPath from @AdDocTBL      
      
  
   
    Declare   @debits  DECIMAL = @Amount     
    Declare  @Balance decimal = 0  
  
 Declare @MID bigint = 0 ;          
 Select top 1 @MID = isnull(M_ID,0) from User_Detail with(nolock) where USER_ID = @ParentID  
  
 SELECT TOP 1 @Balance = cd.Balance FROM   IntCredit_Details AS cd with(nolock) WHERE  cd.[User_ID] = @ParentID ORDER BY cd.Credit_ID DESC     
  
 if(@Balance >= @debits)  
 Begin  
   INSERT INTO IntCredit_Details(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified,ICD_CreatedBy)                
  VALUES(NEWID(),@MID,@ParentID,@ParentID,@debits,0,ISNULL(@Balance, 0) -(@debits),'999999',GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),@UserID)      
 end  
  
  
  
    select 'Record Saved'      
    
    
    
End 


GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveAdRequestHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveAdRequestHistory (    
 @RequestID BIGINT    
 ,@URl NVARCHAR(max)    
 ,@AssignedTo BIGINT    
 ,@Status NVARCHAR(500)    
 ,@ScheduledDays NVARCHAR(max)    
 ,@StartDate NVARCHAR(25)    
 ,@EndDate NVARCHAR(25)    
 ,@UserID BIGINT    
 )    
AS    
BEGIN    
 DECLARE @EndDatetime DATETIME = NULL    
 DECLARE @StartDatetime DATETIME = NULL    
 DECLARE @id BIGINT = 0    
    
 IF (@EndDate <> '')    
 BEGIN    
  SELECT @EndDatetime = Convert(DATETIME, @EndDate)    
 END    
    
 IF (@StartDate <> '')    
 BEGIN    
  SELECT @StartDatetime = Convert(DATETIME, @StartDate)    
 END    
    
 INSERT INTO AdRequestHistory (    
  [RequestID]    
  ,[URL]    
  ,[AssignedTo]    
  ,[Status]    
  ,[ScheduledDays]    
  ,[StartDate]    
  ,[EndDate]    
  ,[CreatedOn]    
  ,[CreatedBy]    
  )    
 VALUES (    
  @RequestID    
  ,@URl    
  ,@AssignedTo    
  ,@Status    
  ,@ScheduledDays    
  ,@StartDatetime    
  ,@EndDatetime    
  ,GETDATE()    
  ,@UserID    
  )    
    
 SET @id = SCOPE_IDENTITY()    
    
 SELECT 'Record Saved'    
    
 DECLARE @rowJson VARCHAR(MAX) = (    
   SELECT *    
   FROM AdRequestHistory(NOLOCK)    
   WHERE Id = @id    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 IF @rowJson IS NOT NULL    
 BEGIN    
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
   ,@Activity_type = 'Inst_Hsty_FbAdReq'    
   ,@ActionType = 'I'    
   ,@RowJson = @rowJson    
   ,@Table_name = 'AdRequestHistory'    
 END    
END 


