/* ============================================================
   Procedure: [dbo].[usp_SaveAppNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_SaveAppNotification            
(            
    @csvUserId  varchar(max),            
    @Title  nvarchar(200),            
    @Content  nvarchar(max),            
    @ImageUrl  nvarchar(4000),            
    @ActionUrl  nvarchar(max),            
    @ScheduledTime  datetime,            
    @CutOffTime  datetime,            
    @UserID  bigint            
)            
AS            
BEGIN            
            
    Declare @TotalRecords int=0, @BatchNotification_Id bigint=0            
            
    select @TotalRecords=Count(*) from dbo.fn_Split(@csvUserId,',')            
            
	if(ISNULL(@ImageUrl,'')='')
	begin
		Set @ImageUrl='https://www.kit19.com/Kit19New/img/logo.jpg'
	end

    INSERT INTO [dbo].[tbl_APP_BatchNotification]            
   ([Title],[MessageText],[ImageUrl],[ClickActionUrl],[BatchSentTime],[TotalRecords],[ScheduledDate],[TotalProcessed],[BatchCompleteTime],[LastBatchProcessed],[IsProcessed],[CutOffTime],[CreatedOn],[CreatedBy])            
     VALUES            
   (@Title, @Content, @ImageUrl, @ActionUrl, null, @TotalRecords, @ScheduledTime, 0            
   , null, null, 0, isnull(@CutOffTime,dateadd(hh,6,@ScheduledTime)), GETDATE(), @UserID)            
            
    Select @BatchNotification_Id=SCOPE_IDENTITY()            
            
     select @csvUserId = REPLACE(@csvUserId , '#' , ',')       
            
    INSERT INTO [dbo].[tbl_APP_BatchNotificationDetail]            
   ([BatchNotification_Id],[User_ID],[LastAttemptedTime],[Retries],[LastStatus],[IsProcessed])            
     Select @BatchNotification_Id, [value], null, 0, '', 0            
     From  dbo.fn_Split(@csvUserId,',')            
            
    Select @BatchNotification_Id            
            
END   



