/* ============================================================
   Procedure: [dbo].[usp_SaveAuthKey]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SaveAuthKey](   
    @Id bigint,  
 @authKey  nvarchar(255)= NULL,    
 @vendorName  nvarchar(255)= NULL,    
 @UserId  bigint,    
 @IsActive  bit     
)     
as    
begin  
  
 --declare   
 --  @Id  bigint=20190,  
 --@authKey  nvarchar(255)= NULL,    
 --@vendorName  nvarchar(255)= NULL,    
 --@UserId  bigint,    
 --@IsActive  bit     
  
 declare @ParentId bigint = 0  
 select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId  
 begin try  
 begin transaction  
  if EXISTS (select * from  tbl_AuthKey where id=@id )  
   begin  
   update tbl_AuthKey set isActive=@IsActive,authkey=@authKey,vendorName=@vendorName,updatedBy=@UserId,updatedOn=getdate()  where id=@id   
         if(@vendorName = 'MagicBricksAPI')
		   begin
		      update MagicBricks set MagicBrickKey = @authKey,Status = @IsActive,ModifiedOn = getdate() where Kit19ParentID = @ParentId
		   end
            
   end  
  else  
   begin  
   Insert into tbl_AuthKey(authkey,vendorName,isactive,createdby,ParentId)  
    select  @authKey,@vendorName, @IsActive,  @UserId,@ParentId  
      
   set @id = scope_identity()  

         if(@vendorName = 'MagicBricksAPI')
		   begin
			  INSERT INTO MagicBricks (  
			    MagicBrickKey  
			   ,Kit19ParentID  
			   ,STATUS  
			   ,CreatedOn  
			   ,ModifiedOn  
			   ,CreatedBy  
			   )  
			  VALUES (  
			    @authKey  
			   ,@ParentId  
			   ,1  
			   ,GETDATE()  
			   ,GETDATE()  
			   ,@UserId  
			   )  
		   end

   end  
  
  commit transaction  
 end try  
 begin catch  
  rollback transaction  
  exec usp_InsertErrorInfo  
 end catch  
end   
  


