CREATE   PROC usp_saveC2CSetting ( 
	@uid bigint,     
	@url varchar(500),    
	@header nvarchar(max) = null,    
	@param nvarchar(max) = null,     
	@type nvarchar(max) = null,  
	@method nvarchar(max) = null,  
	@content_type nvarchar(max) = null  
)
as      
begin      
    if(exists(select * from tbl_c2c_setting where user_id = @uid and call_type = @type))      
    begin      
  update tbl_c2c_setting set   
