    headers = @header,  
    params = @param,  
    method = @method,  
    content_type = @content_type  
   where user_id = @uid and call_type = @type  
 end      
 else      
 begin      
  insert into tbl_c2c_setting(user_id, c2c_setting_url, call_type, headers, params, method, content_type)    
   values( @uid, @url, @type, @header, @param, @method, @content_type)      
    end      
end



