CREATE   PROCEDURE [dbo].[usp_SaveCarWaleWebhooks](            
 @RequestJson nvarchar(max),            
 @ParentId bigint            
)            
as            
begin           
        
  begin try      
      
   declare @Mobile nvarchar(50) = '' , @CountryCode nvarchar(50) = ''    
   declare @TimeStamp nvarchar(50) = ''
   declare @CarWaleUniqueID nvarchar(200) = ''
    
  Select @Mobile = MobileNo, @CountryCode = CountryCode, @TimeStamp = convert(datetime, EnquiryDate + ' ' + EnquiryTime ,  104)
         , @CarWaleUniqueID = CarWaleUniqueID 
    from OpenJson(@RequestJson)       
  With    
   (      
	MobileNo nvarchar(max) '$.MobileNo',      
    CountryCode nvarchar(max) '$.CountryCode',    
    EnquiryDate nvarchar(max) '$.EnquiryDate',
	EnquiryTime nvarchar(max) '$.EnquiryTime',
	CarWaleUniqueID nvarchar(max) '$.CarWaleUniqueID'
   )      
      
   if(exists( select top 1 ID from tbl_CarWaleWebhooks with(nolock) where ( ( RequestJson like '%"MobileNo":"'+ @Mobile +'"%'     
                                                     and RequestJson like '%"CountryCode":"'+ @CountryCode +'"%'      
                                                     )    
												    or
													 (
													    RequestJson like '%"CarWaleUniqueID":"'+ @CarWaleUniqueID +'"%'
													 ))
			  
			       and ParentID = @ParentId 
              order by ID desc ))    
    
        Begin    
            declare @RequestJsonDataMatched nvarchar(max) = ''    
   select top 1 @RequestJsonDataMatched = RequestJson from tbl_CarWaleWebhooks with(nolock) where
                                                     ( ( RequestJson like '%"MobileNo":"'+ @Mobile +'"%'     
                                                        and RequestJson like '%"CountryCode":"'+ @CountryCode +'"%'      
													    )
													   or
													   (
													     RequestJson like '%"CarWaleUniqueID":"'+ @CarWaleUniqueID +'"%'
													   )
													 )
              and ParentID = @ParentId      
              order by ID desc     
                  
     Select @TimeStamp = convert(datetime, EnquiryDate + ' ' + EnquiryTime ,  104) from OpenJson(@RequestJsonDataMatched)       
    With    
     (      
        EnquiryDate nvarchar(max) '$.EnquiryDate',
  	    EnquiryTime nvarchar(max) '$.EnquiryTime'    
     )     
       
        select top 1 cast(ID as nvarchar(50)) as CarWalePrimaryID , cast(0 as nvarchar(50)) as Status, isnull(EnquiryID,0)  as  CarWaleEnqID    
     ,@TimeStamp as [Timestamp] , 'Duplicate Request Found' as RequestStatus    
     from tbl_CarWaleWebhooks with(nolock)     
     where
	        (  ( RequestJson like '%"MobileNo":"'+ @Mobile +'"%'     
                 and RequestJson like '%"CountryCode":"'+ @CountryCode +'"%'      
			   )
			   or
			   (
			     RequestJson like '%"CarWaleUniqueID":"'+ @CarWaleUniqueID +'"%'
			   )
			 )
		
		and ParentID = @ParentId      
     order by ID desc              
  End         
    else    
   Begin     
           insert into tbl_CarWaleWebhooks(RequestJson, ParentId)            
     values(@RequestJson, @ParentId)            
          DECLARE @ID BIGINT = SCOPE_IDENTITY()     
              
    begin try     
       exec Usp_TransferLeadDatatoCustomFieldMapping @apiname='CarWale',@rawleadid=@ID  
    end try    
    begin catch     
      exec usp_inserterrorInfo     
    end catch    
    
    Select  cast(ID as nvarchar(50)) as CarWalePrimaryID , cast(1 as nvarchar(50)) as Status, isnull(EnquiryID,0) as  CarWaleEnqID    
     ,@TimeStamp as [Timestamp],'Valid Request Found' as RequestStatus     
    from tbl_CarWaleWebhooks with(nolock) where ID = @ID and ParentID = @ParentId           
       end     
    
  end try      
  begin catch      
    exec usp_inserterrorInfo      
  end catch        
      
end 


