/* ============================================================
   Procedure: [dbo].[Usp_SaveCategory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveCategory (
	@CategoryName NVARCHAR(500)
	,@Description NVARCHAR(max)
	,@UserID BIGINT
	)
AS
BEGIN
	DECLARE @ParentID BIGINT = 0
		,@id BIGINT = 0

	SELECT TOP 1 @ParentID = ISNULL(ParentID, USER_ID)
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserID

	IF (
			NOT EXISTS (
				SELECT 1
				FROM Product_Category(NOLOCK)
				WHERE CategoryName = @CategoryName
					AND ParentID = @ParentID
				)
			)
	BEGIN
		INSERT INTO Product_Category (
			CategoryName
			,Description
			,IsDeleted
			,DeletedOn
			,CreatedDate
			,CreatedBy
			,ParentID
			)
		VALUES (
			@CategoryName
			,@Description
			,0
			,NULL
			,getdate()
			,@UserID
			,@ParentID
			)

		SET @id = SCOPE_IDENTITY()

		SELECT 'Data Saved' AS msg
	END
	ELSE
	BEGIN
		SELECT 'Category name already exists' AS msg
	END

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM Product_Category
			WHERE ID = @id
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	IF @RowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
			,@Activity_type = 'Inst_Prdct_Ctgry'
			,@ActionType = 'I'
			,@RowJson = @rowJson
			,@Table_name = 'Product_Category'
	END
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveCategoryEnquiryThresholds]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_SaveCategoryEnquiryThresholds]          
(          
  @Cold Numeric(18,2),          
  @Warm Numeric(18,2),          
  @Hot Numeric(18,2),          
  @UserID bigint         
)          
AS          
BEGIN          
    SET NOCOUNT ON;  -- Prevents extra result sets from interfering with SELECT statements      
      
    DECLARE @ParentID bigint = 0,      
            @Activity_type nvarchar(20),      
            @Actiontype varchar(1),      
            @rowjson nvarchar(max);      
      
    BEGIN TRY      
        SELECT TOP 1 @ParentID = ISNULL(ParentID, 0)       
        FROM User_Detail (NOLOCK)       
        WHERE User_ID = @UserID;          
             
        IF NOT EXISTS (SELECT 1 FROM enquiry_cateogy_thresholds (NOLOCK) WHERE parentid = @ParentID)          
        BEGIN          
            INSERT INTO enquiry_cateogy_thresholds          
            (          
                Hot,          
                Warm,          
                Cold,          
                isdefault,          
                parentid,          
                updatedon,          
                updatedby          
            )          
            VALUES          
            (          
                @Hot,          
                @Warm,          
                @Cold,          
                1,          
                @ParentID,          
                GETDATE(),          
                @UserID          
            );          
            SET @Activity_type = 'Inst_EnquiryScore_Sttng';          
            SET @Actiontype = 'I';          
            SET @rowjson = (SELECT * FROM enquiry_cateogy_thresholds (NOLOCK) WHERE parentid = @ParentID FOR JSON AUTO, INCLUDE_NULL_VALUES);          
        END          
        ELSE          
        BEGIN          
            DECLARE @ID bigint = 0;           
            SELECT TOP 1 @ID = ISNULL(id, 0)       
            FROM enquiry_cateogy_thresholds (NOLOCK)       
            WHERE parentid = @ParentID;          
                 
            UPDATE enquiry_cateogy_thresholds          
            SET Hot = @Hot,          
                Warm = @Warm,          
                Cold = @Cold,          
                updatedon = GETDATE(),          
                updatedby = @UserID         
            WHERE id = @ID;          
               
            SET @Activity_type = 'Inst_EnquiryScore_Sttng';          
            SET @Actiontype = 'I';          
            SET @rowjson = (SELECT * FROM enquiry_cateogy_thresholds (NOLOCK) WHERE parentid = @ParentID FOR JSON AUTO, INCLUDE_NULL_VALUES);          
        END          
      
        SELECT 'Record Saved';            
        IF (@rowjson IS NOT NULL)          
        BEGIN          
            EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId       
                @User_id = @UserID,          
                @Activity_type = @Activity_type,          
                @ActionType = @Actiontype,          
                @RowJson = @rowJson,          
                @Table_name = 'enquiry_cateogy_thresholds';           
        END          
    END TRY      
    BEGIN CATCH      
       exec usp_InsertErrorInfo        
    END CATCH      
END;   


GO

