   Procedure: [dbo].[Usp_SaveCategoryThresholds]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_SaveCategoryThresholds]
(
  @Cold Numeric(18,2),
  @Warm Numeric(18,2),
  @Hot Numeric(18,2),
  @UserID bigint , 
  @scoretype int
)
as
Begin
   declare @ParentID bigint = 0,@Activity_type nvarchar(20), @Actiontype varchar(1), @rowjson nvarchar(max)
   Select top 1  @ParentID = isnull(ParentID,0) from User_Detail(nolock) where User_ID = @UserID
   
   if(not exists(select 1 from lead_cateogy_thresholds(nolock) where parentid = @ParentID))
     Begin
	     insert into lead_cateogy_thresholds
		  (
		  Hot
         ,Warm
         ,Cold
         ,isdefault
         ,parentid
         ,updatedon
		 ,updatedby
		 ,ScoreSettingType
		  )
		  values
		  (
		   @Hot
         ,@Warm
         ,@Cold
         ,1
         ,@ParentID
         ,getdate()
		 ,@UserID
		 ,@scoretype
		  )
		  set @Activity_type = 'Inst_LeadScore_Sttng'
		  set @Actiontype='I'
		  set @rowjson= (select * from lead_cateogy_thresholds(nolock) where parentid = @ParentID for json auto, include_null_values )
	 End
     else
	   Begin

        declare @ID bigint = 0 
		  select top 1 @ID = isnull(id,0) from lead_cateogy_thresholds(nolock) where parentid = @ParentID
	      update lead_cateogy_thresholds
		   set Hot = @Hot,
		       Warm = @Warm,
			   Cold = @Cold,
			   updatedon = GETDATE(),
			   updatedby = @UserID,
			   ScoreSettingType=@scoretype
		   where id = @ID
		   
		  set @Activity_type = 'Inst_LeadScore_Sttng'
		  set @Actiontype='I'
		  set @rowjson= (select * from lead_cateogy_thresholds(nolock) where parentid = @ParentID for json auto, include_null_values )
	   End

   select 'Record Saved'  
   if(@rowjson is not null)
   begin
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
			,@Activity_type = @Activity_type
			,@ActionType = @Actiontype
			,@RowJson = @rowJson
			,@Table_name = 'lead_cateogy_thresholds' 
	end
End



