/* ============================================================
   Procedure: [dbo].[usp_SaveChecklistItems]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--------------------------------------  
  
CREATE   PROCEDURE [dbo].[usp_SaveChecklistItems]    
    @ParentId BIGINT,    
    @StageId BIGINT,    
    @ChecklistItem NVARCHAR(100),    
    @UserId BIGINT    
AS    
BEGIN    
    -- Start TRY block    
    BEGIN TRY    
        -- Check if the record already exists    
        IF NOT EXISTS (    
            SELECT 1     
            FROM tbl_ChecklistItms (nolock)     
            WHERE     
                ParentId = @ParentId AND    
                StageId = @StageId AND    
                ChecklistItem = @ChecklistItem AND    
                UserId = @UserId    
        )    
        BEGIN    
            -- If it doesn't exist, insert the new record    
            INSERT INTO tbl_ChecklistItms (ParentId, StageId, ChecklistItem, UserId)    
            VALUES (@ParentId, @StageId, @ChecklistItem, @UserId);    
                
            -- Prepare the JSON data (example placeholder, adjust according to actual row data)    
            DECLARE @rowJson NVARCHAR(MAX);    
            SET @rowJson = (SELECT * FROM tbl_ChecklistItms (nolock) WHERE ParentId = @ParentId AND StageId = @StageId AND ChecklistItem = @ChecklistItem FOR JSON AUTO);    
    
            -- Call the audit procedure after insertion    
            EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId     
                @User_id = @UserId,    
                @Activity_type = 'Checklist Item Insert',    
                @ActionType = 'I',    
                @RowJson = @rowJson,    
                @Table_name = 'tbl_ChecklistItms';    
        END    
    END TRY    
    
    -- Start CATCH block    
    BEGIN CATCH    
        -- Handle errors by logging them using the error handling procedure    
        EXEC usp_InsertErrorInfo;    
    END CATCH    
END;    
  


GO

