SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SaveCollegeDekhoWebhooks]
(            
   @RequestJson nvarchar(max),            
   @ParentId bigint            
)            
as            
begin           
        
  begin try      
      
   declare @Mobile nvarchar(50) = '' , @CountryCode nvarchar(50) = ''    
    
   Select @Mobile = MobileNo, @CountryCode = CountryCode  from OpenJson(@RequestJson)       
  With    
   (      
     MobileNo nvarchar(max) '$.MobileNo',      
     CountryCode nvarchar(max) '$.CountryCode'  
   )      
      
   if(exists( select top 1 ID from tbl_CollegeDekhoWebhooks with(nolock) where RequestJson like '%"MobileNo":"'+ @Mobile +'"%'     
                                                     and RequestJson like '%"CountryCode":"'+ @CountryCode +'"%'      
              and ParentID = @ParentId      
              order by ID desc ))    
    
        Begin    
            declare @RequestJsonDataMatched nvarchar(max) = ''    
   select top 1 @RequestJsonDataMatched = RequestJson from tbl_CollegeDekhoWebhooks with(nolock) where RequestJson like '%"MobileNo":"'+ @Mobile +'"%'     
                                                     and RequestJson like '%"CountryCode":"'+ @CountryCode +'"%'      
              and ParentID = @ParentId      
              order by ID desc     
       
      select top 1 cast(ID as nvarchar(50)) as CollegeDekhoPrimaryID , cast(0 as nvarchar(50)) as Status, isnull(EnquiryID,0)  as  CollegeDekhoEnqID    
     , 'Duplicate Request Found' as RequestStatus    
     from tbl_CollegeDekhoWebhooks with(nolock)     
     where RequestJson     
             like '%"MobileNo":"'+ @Mobile +'"%'     
                    and RequestJson like '%"CountryCode":"'+ @CountryCode +'"%'      
        and ParentID = @ParentId      
     order by ID desc              
  End         
    else    
   Begin     
           insert into tbl_CollegeDekhoWebhooks(RequestJson, ParentId)            
     values(@RequestJson, @ParentId)            
          DECLARE @ID BIGINT = SCOPE_IDENTITY()     
              
    begin try     
     EXEC Usp_TransferLeadDatatoCustomFieldMapping @apiname='CollegeDekho',@rawleadid=@ID 
	   --exec Usp_TransferLeadDatatoCustomFieldMapping_CarDekhoTesting @apiname='CollegeDekho',@rawleadid=@ID
    end try    
    begin catch    
      exec usp_inserterrorInfo     
    end catch    
    
    Select cast(ID as nvarchar(50)) as CollegeDekhoPrimaryID , cast(1 as nvarchar(50)) as Status, isnull(EnquiryID,0) as  CollegeDekhoEnqID    
          ,'Valid Request Found' as RequestStatus     
    from tbl_CollegeDekhoWebhooks with(nolock) where ID = @ID and ParentID = @ParentId           
       end     
    
  end try      
  begin catch      
    exec usp_inserterrorInfo      
  end catch        
      
end 


