/* ============================================================
   Procedure: [dbo].[usp_SaveDashboard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.usp_SaveDashboard (
	@DashboardName NVARCHAR(200)
	,@IsActive BIT
	,@IsDefault BIT
	,@UserId BIGINT
	,@DashboardId BIGINT = 0
	,@jsonDashboardReports NVARCHAR(max) = NULL
	,@jsonDashboardUsers NVARCHAR(max) = NULL
	)
AS
BEGIN
	DECLARE @ParentId BIGINT
		,@activity VARCHAR(MAX)
		,@action VARCHAR(1)

	SELECT @ParentId = ParentId
	FROM User_Detail(NOLOCK)
	WHERE User_Id = @UserId

	IF (@DashboardId = 0) --Insert
	BEGIN
		IF NOT EXISTS (
				SELECT *
				FROM tbl_Dashboard(NOLOCK)
				WHERE ParentId = @ParentId
					AND DashboardName = @DashboardName
				)
		BEGIN
			IF NOT EXISTS (
					SELECT *
					FROM tbl_Dashboard(NOLOCK)
					WHERE ParentId = @ParentId
						AND IsActive = 1
						AND IsDefault = 1
						AND @IsDefault = 1
					)
			BEGIN
				INSERT INTO tbl_Dashboard (
					DashboardName
					,IsDefault
					,IsActive
					,ParentId
					,CreatedBy
					)
				VALUES (
					@DashboardName
					,@IsDefault
					,@IsActive
					,@ParentId
					,@UserId
					)

				SELECT @DashboardId = SCOPE_IDENTITY()

				SET @activity = 'Inst_dsbrd'
				SET @action = 'I'

				INSERT INTO tbl_DashboardReportMapping (
					DashboardId
					,ReportId
					,SequenceNo
					,RangeCode
					,IsActive
					)
				SELECT @DashboardId
					,DRM.ReportId
					,DRM.SequenceNo
					,DRM.RangeCode
					,DRM.IsActive
				FROM openjson(@jsonDashboardReports) WITH (
						ReportId INT
						,SequenceNo NUMERIC(18, 2)
						,RangeCode NVARCHAR(40)
						,IsActive BIT
						) DRM

				INSERT INTO tbl_DashboardUserMapping (
					DashboardId
					,UserId
					,IsDefault
					)
				SELECT @DashboardId
					,DUM.UserId
					,DUM.IsDefault
				FROM openjson(@jsonDashboardUsers) WITH (
						UserId BIGINT
						,IsDefault BIT
						) DUM

				SELECT Msg = 'A New Dashboard created successfully'
					,MsgId = 1
			END
			ELSE
			BEGIN
				SELECT Msg = 'A Default Dashboard already exists'
					,MsgId = - 2
			END
		END
		ELSE
		BEGIN
			SELECT Msg = 'DashboardName already exists'
				,MsgId = - 1
		END
	END
	ELSE --Update
	BEGIN
		IF NOT EXISTS (
				SELECT *
				FROM tbl_Dashboard(NOLOCK)
				WHERE ParentId = @ParentId
					AND DashboardName = @DashboardName
					AND DashboardId != @DashboardId
				)
		BEGIN
			IF (
					@IsDefault = 1
					AND @IsActive = 1
					)
			BEGIN
				UPDATE tbl_Dashboard
				SET IsDefault = 0
				WHERE ParentId = @ParentId
					AND @IsActive = 1
			END

			UPDATE tbl_Dashboard
			SET DashboardName = @DashboardName
				,IsDefault = @IsDefault
				,IsActive = @IsActive
				,ModifiedBy = @UserId
				,ModifiedOn = GETDATE()
			WHERE DashboardId = @DashboardId

			DELETE
			FROM tbl_DashboardReportMapping
			WHERE DashboardId = @DashboardId

			INSERT INTO tbl_DashboardReportMapping (
				DashboardId
				,ReportId
				,SequenceNo
				,RangeCode
				,IsActive
				)
			SELECT @DashboardId
				,DRM.ReportId
				,DRM.SequenceNo
				,DRM.RangeCode
				,DRM.IsActive
			FROM openjson(@jsonDashboardReports) WITH (
					ReportId INT
					,SequenceNo NUMERIC(18, 2)
					,RangeCode NVARCHAR(40)
					,IsActive BIT
					) DRM

			DELETE
			FROM tbl_DashboardUserMapping
			WHERE DashboardId = @DashboardId

			INSERT INTO tbl_DashboardUserMapping (
				DashboardId
				,UserId
				,IsDefault
				)
			SELECT @DashboardId
				,DUM.UserId
				,DUM.IsDefault
			FROM openjson(@jsonDashboardUsers) WITH (
					UserId BIGINT
					,IsDefault BIT
					) DUM

			SELECT Msg = 'Dashboard modified successfully'
				,MsgId = 2

			SET @activity = 'Updt_dsbrd'
			SET @action = 'U'
		END
		ELSE
		BEGIN
			SELECT Msg = 'DashboardName already exists'
				,MsgId = - 1
		END
	END

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM tbl_Dashboard WITH (NOLOCK)
			WHERE DashboardId = @DashboardId
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	IF @RowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
			,@Activity_type = @activity
			,@ActionType = @action
			,@RowJson = @rowJson
			,@Table_name = 'tbl_Dashboard'
	END
END



GO

