/* ============================================================
   Procedure: [dbo].[Usp_SaveDataToBatchEmailInfo_WithTableName]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_SaveDataToBatchEmailInfo_WithTableName]    
(    
   @tblMailData tblType_MailTriggerReplacement readonly,
   @tblName nvarchar(200)
)    
as    
begin    
     /* 
   	 declare @tblMailData dbo.tblType_MailTriggerReplacement
     insert into @tblMailData values(N'135842231',34594,N'santosh.dev@pelsoftlabs.in',N'',N'',N'',N'sales@pelsoftlabs.in',N'0',N'0',N'sales@pelsoftlabs.in',34594,N'hi 123',N'7/25/2024 4:43:42 PM',N'True',N'',1,N'Emails',N'<p>hello 234</p>',N'T')

     declare  @tblName nvarchar(200) = N'CloneEmailsFilter'
	 */


  Declare @Mail_BatchID bigint,          
    @Mail_ParentID bigint,          
    @Mail_userID  bigint,          
    @TemplateID bigint,          
    @count int,          
    @actualcount int,          
    @parentsuperresellerid bigint,          
    @hassufficientvirtualcredits int,          
    @source nvarchar(20),          
    @scheduleddate nvarchar(50),          
    @frommail nvarchar(200),@ismonitor int,@mailroute nvarchar(20)          
    ,@BatchInfoID bigint = 0
	,@MailCreditID bigint = 0
  
  select top 1 @Mail_BatchID = mail_batchid,@Mail_ParentID=Mail_ParentID,@Mail_userID=Mail_userID,          
  @source=source,@scheduleddate=mail_scheduledate,@TemplateID=templateid,@frommail=Mail_FromEmail,@mailroute=isnull(mailroute,'T') from @tblMailData  
    
  select @count=count(1) from @tblMailData  
  declare @deductcredits int=1          
      
  select top 1 @ismonitor
        =  case when ismonitor = 'true'
		        then 1
				when ismonitor = 'false'
		        then 0
               else null
			  end
		from @tblMailData           
  if @ismonitor is null          
  begin          
  select @ismonitor=case when status=1 and plimit<=@actualcount and @mailroute='T' then 0 else 1 end from [MySMS].[DBO].ProcessMailLimit          
  end    
  
      
  IF @deductcredits=1            
  BEGIN           
  print 'E0'      
  select @actualcount = (select COUNT(1) from @tblMailData where @Mail_BatchID=Mail_BatchID)          
  print 'E1'      
  print '@actualcount: ' + cast(@actualcount as varchar)      
  RETRY:                                                     
  BEGIN TRY                                                  
  --BEGIN TRAN           
  print 'F1'      
  INSERT INTO [MySMS].[DBO].Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,BatchInsertTime,BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName          
  ,IsScheduled,Email_Subject,ReplyTo,ispersonalized,Mail_Source,mailroute,bmonitor,Tablename)            
  SELECT top 1 Mail_BatchID,Mail_UserID,coalesce(Mail_FromEmail,U.Email) as SenderName,          
  case  when isnull(s.templateid,0)<>0 then           
  (select MailContent from [MySMS].[DBO].UserMailTemplate where ID=s.TemplateID)           
  when isnull(cast(s.messages as nvarchar(max)),'')<>''           
  then cast(s.messages as nvarchar(max))           
  else cast(c.Messages as nvarchar(max)) end as Message,          
  @Count,0,0,0,          
  case when aws.user_id is not null then 2 when @count>10 then Mail_Priority when @count<=10 then 1 else 0 end,                                                  
  Getdate(),NULL,NULL,NULL,@TemplateID,0,0,0,          
  case when isnull(s.templateid,0)<>0           
  then (select mailsubject from [MySMS].[DBO].UserMailTemplate where ID=s.TemplateID)           
  when isnull(s.Mail_subject,'')='' then c.mail_subject else s.mail_subject end as Mail_Subject,          
  ReplyTo,0,s.source,s.mailroute,@ismonitor,@tblName           
  FROM @tblMailData s  join [MySMS].[DBO].user_detail u (nolock) on u.user_id=s.mail_UserID  
  left join [MySMS].[DBO].campaignmessages c on c.batchid=s.mail_batchid          
  left join           
  (select user_id,frommailid from [MySMS].[DBO].awsmailroute aws (nolock) join user_detail(nolock) u on aws.parentid=u.user_id where isactive=1) aws on aws.User_ID=Mail_UserID and aws.frommailid=Mail_FromEmail
  
   set @BatchInfoID = SCOPE_IDENTITY()

  print 'G1'      
      
  --COMMIT                                                  
  END TRY                                                  
                        
  BEGIN CATCH                                                                                                      
  --IF @@TRANCOUNT>0                                                  
  --ROLLBACK                                                  
  EXECUTE [MySMS].[DBO].USP_INSERTERRORINFO;             
  IF ERROR_NUMBER() = 1205 -- Deadlock Error Number            
  BEGIN            
  WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms            
  GOTO RETRY -- Go to Label RETRY            
  END                                                       
  END CATCH  


    select @actualcount = (select COUNT(1) from @tblMailData where @Mail_BatchID=Mail_BatchID)        
                                            
                 
    INSERT INTO  [MySMS].[DBO].Mailcreditdetails                                              
        (ID,                                              
         -- Credit_ID -- this column value is auto-generated                                              
         M_ID,                                              
         FromUser_ID,                                              
         [User_ID],                                              
         Debits,                                              
       Credits,                                              
       Balance,                                              
         Validity,                                              
         Default_Credit,                                              
         FromDate,                                              
         ToDate,                                              
         DateCreated,                                              
         DateUpdated,                                              
        EmpUpdated,                                              
         MachineName,                                              
         LastModified,                                  
         typecredit,            
         campaignid,batchid)                                              
     SELECT top 1 Newid(),                                              
      Ud.M_ID,                                              
      @Mail_ParentID,                                              
      @Mail_ParentID,                                              
      count,                                              
      0,                                              
      (SELECT TOP 1 Mcd.Balance                                   
       FROM   [MySMS].[DBO].Mailcreditdetails AS Mcd                                              
       WHERE  Mcd.[User_ID] = @Mail_ParentID                                              
       ORDER  BY Mcd.Credit_ID DESC) - count,                                              
      99999,                                              
      '',                                              
      Getdate(),                                              
      Getdate(),                                            
      Getdate(),                                              
      Getdate(),                                              
      '',                            
      '',                                              
      Getdate(),                                     
      '',            
      0,@Mail_BatchID                                              
     FROM   @tblMailData c  join user_detail ud (nolock) on ud.User_ID=c.mail_userid where  c.Mail_BatchID = @Mail_BatchID        
  
     set @MailCreditID = SCOPE_IDENTITY() 
  end  
    

	drop table if exists #tempTbl
	select * into #tempTbl from @tblMailData


	Declare @Query nvarchar(Max)
	 = N'
       insert into [10.0.0.135].[MysmsTrans].[dbo].' + @tblName + '
	       (
		     Mail_FromEmail
			,Mail_ToEmail
			,Mail_Subject
			,Mail_TempleteName
			,Messages
			,Mail_InsertedDate
			,Mail_UserID
			,Mail_ParentID
			,ReplyTo
			,Mail_BatchID
			,Mail_Priority
			,Mail_ScheduleDate
			,Mail_ScheduledTime
			--,Mail_Attechement
			,Mail_TempleteBody
			,IsMonitor
			,TemplateID
			,Count
			,Source
			,mailroute
			,EntityName
			,EntityID
			,IsMatched
			)
	    select
		     Mail_FromEmail
			,Mail_ToEmail
			,Mail_Subject
			,Mail_TempleteName
			,Messages
			,Mail_InsertedDate
			,Mail_UserID
			,Mail_ParentID
			,ReplyTo
			,Mail_BatchID
			,Mail_Priority
			,Mail_ScheduleDate
			,Mail_ScheduledTime
			--,Mail_Attechement
			,Mail_TempleteBody
			,IsMonitor
			,TemplateID
			,Count
			,Source
			,mailroute
			,isnull((select top 1 EntityName from [fn_GetEntityDetails](Mail_ToEmail,Mail_ParentID)),'''')
			,isnull((select top 1 EntityID from [fn_GetEntityDetails](Mail_ToEmail,Mail_ParentID)),0)
			,isnull((select top 1  1 from [fn_GetEntityDetails](Mail_ToEmail,Mail_ParentID)),null)

			from #tempTbl '  
	
	    print @Query  
	    exec sp_executesql @Query
    
	select @BatchInfoID as BatchInfoID , @MailCreditID as MailCreditID

	drop table if exists #tempTbl


end


