/* ============================================================
   Procedure: [dbo].[Usp_SaveDLTTemplate_New_ParentIDCheck]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveDLTTemplate_New_ParentIDCheck (
	@DLT_TemplateID NVARCHAR(200)
	,@MessageType NVARCHAR(500)
	,@TemplateText NVARCHAR(max)
	,@IsUnicode BIT
	,@ActiveStatus INT
	,@SenderIDs NVARCHAR(max)
	,@UserID BIGINT
	,@TemplateName NVARCHAR(100)
	,@Is_Stock BIT
	)
AS
BEGIN
	DECLARE @ParentID BIGINT = 0

	SELECT @ParentID = isnull(ParentID, User_ID)
	FROM User_Detail(NOLOCK)
	WHERE USER_ID = @UserID

	IF (
			NOT EXISTS (
				SELECT 1
				FROM UserMailTemplate(NOLOCK)
				WHERE DLT_TemplateID = @DLT_TemplateID
					AND ParentID = @ParentID
				)
			)
	BEGIN
		IF (
				NOT EXISTS (
					SELECT 1
					FROM UserMailTemplate(NOLOCK)
					WHERE Name = @TemplateName
						AND ParentID = @ParentID
					)
				)
		BEGIN
			INSERT INTO UserMailTemplate (
				Name
				,MailSubject
				,DLT_TemplateID
				,MessageType
				,MailContent
				,IsUnicode
				,ParentID
				,ActiveStatus
				,CreatedOn
				,CreatedBy
				,IsSMS
				,IsMail
				,MailContentEditable
				,body_disp
				,is_stock
				)
			VALUES (
				@TemplateName
				,''
				--,SUBSTRING(@TemplateText,1,30)        
				,@DLT_TemplateID
				,@MessageType
				,@TemplateText
				,@IsUnicode
				,@ParentID
				,@ActiveStatus
				,getdate()
				,@UserID
				,1
				,0
				,@TemplateText
				,@TemplateText
				,@Is_Stock
				)

			DECLARE @ID BIGINT = SCOPE_IDENTITY();

			INSERT INTO DLT_TemplateSenderMapping (
				DLT_TemplateID
				,SenderID
				,CreatedOn
				,CreatedBy
				)
			SELECT @DLT_TemplateID
				,value
				,getdate()
				,@UserID
			FROM dbo.fn_Split(@SenderIDs, '#')

			SELECT 'Template Saved'
		END
		ELSE
		BEGIN
			SELECT 'Template Name Already Exists'
		END
	END
	ELSE
	BEGIN
		SELECT 'This template id already in use'
	END

	--  Declare @ParentID bigint = 0            
	--  select @ParentID = isnull(ParentID,0) from User_Detail(nolock) where USER_ID = @UserID          
	-- if(not exists(select 1 from DLT_Template(nolock) where DLT_TemplateID = @DLT_TemplateID))          
	--   Begin          
	-- insert into DLT_Template          
	--   (          
	--   DLT_TemplateID          
	--     ,MessageType          
	--     ,TemplateText          
	--     ,IsUnicode          
	--     ,ParentID          
	--     ,ActiveStatus          
	--     ,CreatedOn          
	--     ,CreatedBy          
	--  )          
	--   values          
	--   (          
	--   @DLT_TemplateID          
	--     ,@MessageType          
	--     ,@TemplateText          
	--     ,@IsUnicode          
	--     ,@ParentID          
	--     ,@ActiveStatus          
	--     ,getdate()          
	--     ,@UserID          
	--   )          
	--   insert into DLT_TemplateSenderMapping          
	--   (          
	--     DLT_TemplateID          
	--       ,SenderID          
	--       ,CreatedOn          
	--       ,CreatedBy          
	--   )           
	--   select @DLT_TemplateID,value,getdate(),@UserID          
	--   from dbo.fn_Split(@SenderIDs,'#')          
	--   select 'Template Saved'          
	--End          
	-- else          
	--   Begin          
	--    select 'This template id already in use'          
	--End   
	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserMailTemplate(NOLOCK)
			WHERE ID = @ID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'Inst_DLT_Tmplt'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'UserMailTemplate'
END



