CREATE   PROCEDURE dbo.usp_SavedSearchDetails --1,''
	@IsActive BIT,
	@Search VARCHAR(50) 
	 --@Users  int
AS
BEGIN
	SELECT ss.ID,
	       ss.SearchName,
	       CASE ss.NewUser
	            WHEN 1 THEN 'New User'
	            ELSE 'Old User'
	       END 
	       + CASE ISNULL(ss.UserName, '')
	              WHEN '' THEN ''
	              ELSE ' , ' + ss.UserName
	         END 
	       + CASE ISNULL(ss.Mobile, 0)
	              WHEN 0 THEN ''
	              ELSE ' , ' + CAST(ss.Mobile AS VARCHAR)
	         END 
	       + CASE ISNULL(ss.EmailID, '')
	              WHEN '' THEN ''
	              ELSE ' , ' + ss.EmailID
	         END 
	       + CASE ISNULL(ut.Name, '')
	              WHEN '' THEN ''
	              ELSE ' , ' + ut.Name
	         END 
	       + CASE ISNULL(uf.Name, '')
	              WHEN '' THEN ''
	              ELSE ' , ' + uf.Name
	         END 
	       + CASE ISNULL(ss.LastLoginBefore, 0)
	              WHEN 0 THEN ''
	              ELSE ' , Last Login Before ' + CAST(ss.LastLoginBefore AS VARCHAR)
	                   + ' Days '
	         END 
	       + CASE ISNULL(ss.LastPurchase, 0)
	              WHEN 0 THEN ''
	              ELSE ' , Last Purchase ' + CAST(ss.LastPurchase AS VARCHAR) +
	                   ' Days '
	         END 
	       + CASE ISNULL(ss.LastLogin, 0)
	              WHEN 0 THEN ''
	              ELSE ' , Last Login ' + CAST(ss.LastLogin AS VARCHAR) +
	                   ' Days '
	         END                  AS OtherDetails,
	       ss.NewUser,
	       ss.UserName,
	       ss.Mobile,
	       ss.EmailID,
	       ut.Name                AS UserType,
	       uf.Name                AS UserFilter,
	       ss.IsActive,
	       ss.LastLoginBefore,
	       ss.LastPurchase,
	       ss.LastLogin
	FROM   SavedSearch            AS ss
	       LEFT JOIN User_Type    AS ut
	            ON  ut.ID = CASE 
	                             WHEN ss.UserType = '' THEN NULL
	                             ELSE ss.UserType
	                        END
	       LEFT JOIN User_Filter  AS uf
	            ON  uf.Code = ss.UserFilter
	WHERE  ss.IsActive = @IsActive
	       AND (
	               ISNULL(@Search, '') = ''
	               OR ss.ID = @Search
	               OR ss.SearchName LIKE '%' + @Search + '%'
	               OR ss.UserName LIKE '%' + @Search + '%'
	               OR ss.Mobile LIKE '%' + @Search + '%'
	               OR ss.EmailID LIKE '%' + @Search + '%'
	               OR ss.SearchName LIKE '%' + @Search + '%'
	               OR ss.SearchName LIKE '%' + @Search + '%'
	               OR ss.SearchName LIKE '%' + @Search + '%'
	           )
END 


GO

