CREATE   PROCEDURE dbo.Usp_SaveEmailSubscription  
(  
  @EmailID nvarchar(500),  
  @Subscribed bit,  
  @SubscriptionFor nvarchar(20),  
  @UserID bigint   
)  
as  
Begin  
   Declare @ParentID bigint = 0  
   select @ParentID = ISNULL(ParentID,USER_ID) from User_Detail(nolock) where User_ID = @UserID  
 if(not exists(select 1 from tbl_EmailSubscription(nolock) where EmailID = @EmailID and SubscriptionFor = @SubscriptionFor))  
   Begin  
    insert into tbl_EmailSubscription  
    (  
    [EmailID]  
      ,[Subscribed]  
      ,[SubscriptionFor]  
      ,[ParentID]  
      ,[CreatedOn]  
      ,[CreatedBy]  
      ,[ModifiedOn]  
      ,[ModifiedBy]  
   )  
   values(@EmailID,@Subscribed,@SubscriptionFor,@ParentID,GETDATE(),@UserID,getdate(),@UserID)  
     
   select 'Subscription data saved' as MSG   
             
   End  
     else  
   Begin  
     update tbl_EmailSubscription set Subscribed = @Subscribed , ModifiedOn = GETDATE(), ModifiedBy = @UserID  
     where EmailID = @EmailID and SubscriptionFor = @SubscriptionFor  
       
   select 'Subscription data saved' as MSG   
       
   End        
  
End 


