/* ============================================================
   Procedure: [dbo].[Usp_SaveEmailTrackingDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_SaveEmailTrackingDetails]   
(   
 @Mail_GUID nvarchar(500),   
 @Batch_ID bigint   
)   
as   
Begin   
 declare @email nvarchar(200) ='',@parentid bigint,@userid bigint,@eid bigint,@mailsubject nvarchar(200)   
   
 --select top 1 @email=mail_toemail,@userid=Mail_UserID,@mailsubject=Mail_Subject from mysmstrans.dbo.EmailsReportSent with (nolock)   
 --where @Batch_ID=mail_batchid and Mail_GUID=@mail_guid order by SentMail_ID desc  
 
    select top 1  @email=Email_Id, @userid=UserId from 
	   (
	     select BatchID, Email_Id, UserId from ClientEmails with (nolock) where GUID=@mail_guid and @Batch_ID = BatchID
	        union   
          select BatchID, Email_Id, UserId from ThirtyDaysClientEmails with (nolock) where GUID=@mail_guid and @Batch_ID = BatchID    
	   ) as tbl  

	    /*
	     if(isnull(@Batch_ID,'')='' or @Batch_ID='null')
	      begin
		       select  @Batch_ID = case when charindex('~',@mail_guid) <> 0
	                  then (select  value from fn_split(@mail_guid,'~') where Position = 2)
					  else
					     @mail_guid 
					  end 
           end
		*/

        select top 1 @mailsubject = Email_Subject from BatchEmail_Infos with(nolock) where batchID = @Batch_ID    





    select @parentid=parentid from user_detail with (nolock) where user_id=@userid   
   
 insert into EmailOpenTracker   
 (   
 [Mail_GUID]   
 ,[Batch_ID]   
 ,[Created_Date]   
 )   
 values   
 (   
 @Mail_GUID   
 ,@Batch_ID   
 ,getdate()   
 )   
 select @eid=scope_identity()   
   
 declare @mailsource nvarchar(50)   
 select @mailsource=mail_source from BatchEmail_Infos with (nolock) where batchid=@Batch_ID   
 if @mailsource='InternalCRM'   
 begin   
 declare @et datetime=getdate()   
 exec usp_insertcrmenagagementactivity @batch_id,@email,'mail','Opened','EmailOpenTracker',@eid,@et   
 end   
   
   
   
   
begin try   
if isnull(@email,'')<>''   
begin   
declare @entityname nvarchar(50)='',@entityid bigint=0,@eventdescription nvarchar(1000),@ename nvarchar(200) ,@entityno bigint  
if exists (select 1 from Userleads_Mobile_Email with (nolock) where parentid=@parentid and email=@email)   
begin   
select top 1 @entityname='lead',@entityid=leadno,@entityno=leadno from Userleads_Mobile_Email with (nolock) where parentid=@parentid and email=@email   
order by leadno desc   
select top 1 @entityid=id from userleads u with (nolock) where parentid=@parentid and leadno=@entityid order by id desc   
end   
else if exists (select 1 from Userenquiry_Mobile_Email with (nolock) where parentid=@parentid and email=@email)   
begin   
select top 1 @entityname='enquiry',@entityid=enquiryid,@entityno=enquiryid from Userenquiry_Mobile_Email with (nolock) where parentid=@parentid and email=@email   
order by enquiryid desc   
end   
if @entityname<>''   
begin   
select @eventdescription= @entityname + ' no.'+cast(@entityno as nvarchar(20)) + ', Name: '+dbo.fn_getentityfullname(@entityname,@entityid)   
+ ' has opened your mail with subject '+@mailsubject+' : Team Kit19'   
,@ename=@entityname +' opens mail'   
   
exec UspSaveEntityActivity_withid @entityname,@entityid,@userid,@parentid,@eventdescription,@ename,'EmailOpenTracker',@eid   
end   
end   
end try   
begin catch   
exec usp_InsertErrorInfo   
end catch   
   
 select 'Data Saved'   
   
End   




GO

/* ============================================================
   Procedure: [dbo].[usp_SaveEnquiryAttributes]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SaveEnquiryAttributes]    
    @ParentId BIGINT,    
    @StageId BIGINT,    
    @Condition NVARCHAR(50),    
    @Attribute NVARCHAR(100),    
    @Operator NVARCHAR(50),    
    @Value NVARCHAR(100),    
    @UserId BIGINT    
AS    
BEGIN    
    -- Start TRY block    
    BEGIN TRY    
        -- Check if the record already exists    
        IF NOT EXISTS (    
            SELECT 1     
            FROM tbl_EnquiryAttribute     
            WHERE     
                ParentId = @ParentId AND    
                StageId = @StageId AND    
                --Condition = @Condition AND    
                Attribute = @Attribute AND    
                Operator = @Operator AND    
                Value = @Value AND    
                UserId = @UserId    
        )    
        BEGIN    
            -- If it doesn't exist, insert the new record    
            INSERT INTO tbl_EnquiryAttribute (ParentId, StageId, Condition, Attribute, Operator, Value, UserId)    
            VALUES (@ParentId, @StageId, @Condition, @Attribute, @Operator, @Value, @UserId);    
                
            -- Prepare the JSON data (example placeholder, adjust according to actual row data)    
            DECLARE @rowJson NVARCHAR(MAX);    
            SET @rowJson = (SELECT * FROM tbl_EnquiryAttribute WHERE ParentId = @ParentId AND StageId = @StageId AND Attribute = @Attribute AND Operator = @Operator AND Value = @Value FOR JSON AUTO);    
    
            -- Call the audit procedure after insertion    
            EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId     
                @User_id = @UserId,    
                @Activity_type = 'User EnquiryAttribute Insert',    
                @ActionType = 'I',    
                @RowJson = @rowJson,    
                @Table_name = 'tbl_EnquiryAttribute';    
        END    
    END TRY    
    
    -- Start CATCH block    
    BEGIN CATCH    
        -- Handle errors by logging them using the error handling procedure    
        EXEC usp_InsertErrorInfo;    
    END CATCH    
END;    
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveFacebookPromotionalDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveFacebookPromotionalDetails (    
 -- ad          
 @AdName NVARCHAR(500)    
 ,@Ad_Content NVARCHAR(max)    
 ,@Ad_Instruction NVARCHAR(max)    
 ,@Amount NUMERIC(18, 2)    
 ,@ScheduledDays NVARCHAR(max)    
 ,@StartDate NVARCHAR(50)    
 ,@EndDate NVARCHAR(50)    
 ,@AdDocTBL AS AdDocTBLType readonly    
 ,    
 --page          
 @PageName NVARCHAR(500)    
 ,@Status NVARCHAR(500)    
 ,@Page_Content NVARCHAR(max)    
 ,@Page_Instruction NVARCHAR(max)    
 ,@TypeID INT    
 ,@PageDocTBL AS PageDocTBLType readonly    
 ,@UserID BIGINT    
 ,@ParentID BIGINT    
 )    
AS    
BEGIN    
 DECLARE @PageRequestID BIGINT = 0    
 DECLARE @AdRequestID BIGINT = 0    
 DECLARE @EndDatatime DATETIME = NULL    
 DECLARE @StartDatatime DATETIME = NULL    
    
 IF (@EndDate <> '')    
 BEGIN    
  SELECT @EndDatatime = Convert(DATETIME, @EndDate)    
 END    
    
 IF (@StartDate <> '')    
 BEGIN    
  SELECT @StartDatatime = Convert(DATETIME, @StartDate)    
 END    
    
 -- insert page details          
 INSERT INTO PageRequests (    
  [TypeID]    
  ,[PageName]    
  ,[Status]    
  ,[ParentID]    
  ,[Content]    
  ,[Remarks]    
  ,[CreatedOn]    
  ,[CreatedBy]    
  )    
 VALUES (    
  @TypeID    
  ,@PageName    
  ,@Status    
  ,@ParentID    
  ,@Page_Content    
  ,@Page_Instruction    
  ,getdate()    
  ,@UserID    
  )    
    
 SELECT @PageRequestID = SCOPE_IDENTITY()    
    
 --insert into DigitalMarketingEntities      
 --(      
 -- PageRequestID,       
 -- TypeID,      
 -- URL,      
 -- ParentID,      
 -- CreatedOn,      
 -- CreatedBy      
 --)      
 --values(@PageRequestID,@TypeID,'',@ParentID,GETDATE(),@UserID)      
 INSERT INTO PageRequestHistory (    
  [RequestID]    
  ,[AssignedTo]    
  ,[Status]    
  ,[CreatedOn]    
  ,[CreatedBy]    
  )    
 VALUES (    
  @PageRequestID    
  ,NULL    
  ,@status    
  ,getdate()    
  ,@UserID    
  )    
    
 INSERT INTO PageDocs (    
  RequestID    
  ,DocPath    
  )    
 SELECT @PageRequestID    
  ,DocPath    
 FROM @PageDocTBL    
    
 -- insert into Ad details          
 INSERT INTO AdRequests (    
  [PageID]    
  ,[AddName]    
  ,[RequestType]    
  ,[Content]    
  ,[Remarks]    
  ,[Amount]    
  ,[CreatedOn]    
  ,[CreatedBy]    
  )    
 VALUES (    
  @PageRequestID    
  ,@AdName    
  ,@status    
  ,@Ad_Content    
  ,@Ad_Instruction    
  ,@Amount    
  ,getdate()    
  ,@UserID    
  )    
    
 SELECT @AdRequestID = SCOPE_IDENTITY()    
    
 INSERT INTO AdRequestHistory (    
  [RequestID]    
  ,[URL]    
  ,[AssignedTo]    
  ,[Status]    
  ,[ScheduledDays]    
  ,[StartDate]    
  ,[EndDate]    
  ,[CreatedOn]    
  ,[CreatedBy]    
  )    
 VALUES (    
  @AdRequestID    
  ,NULL    
  ,NULL    
  ,@Status    
  ,@ScheduledDays    
  ,@StartDatatime    
  ,@EndDatatime    
  ,getdate()    
  ,@UserID    
  )    
    
 INSERT INTO AdDocs (    
  RequestID    
  ,DocPath    
  )    
 SELECT @AdRequestID    
  ,DocPath    
 FROM @AdDocTBL    
    
 DECLARE @debits DECIMAL = @Amount    
 DECLARE @Balance DECIMAL = 0    
 DECLARE @MID BIGINT = 0;    
    
 SELECT TOP 1 @MID = isnull(M_ID, 0)    
 FROM User_Detail    
 WHERE USER_ID = @ParentID    
    
 SELECT TOP 1 @Balance = cd.Balance    
 FROM IntCredit_Details AS cd    
 WHERE cd.[User_ID] = @ParentID    
 ORDER BY cd.Credit_ID DESC    
    
 IF (@Balance >= @debits)    
 BEGIN    
  INSERT INTO IntCredit_Details (    
   ID    
   ,M_ID    
   ,FromUser_ID    
   ,[User_ID]    
   ,Debits    
   ,Credits    
   ,Balance    
   ,Validity    
   ,FromDate    
   ,ToDate    
   ,DateCreated    
   ,DateUpdated    
   ,EmpUpdated    
   ,LastModified    
   )    
  VALUES (    
   NEWID()    
   ,@MID    
   ,@ParentID    
   ,@ParentID    
   ,@debits    
   ,0    
   ,ISNULL(@Balance, 0) - (@debits)    
   ,'999999'    
   ,GETDATE()    
   ,GETDATE()    
   ,GETDATE()    
   ,GETDATE()    
   ,GETDATE()    
   ,GETDATE()    
   )    
 END    
    
 SELECT 'Record Saved'    
    
 DECLARE @rowJson VARCHAR(MAX) = (    
   SELECT *   
   FROM PageRequests WITH(NOLOCK)    
   WHERE Id = @PageRequestID    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
  ,@Activity_type = 'Inst_fpage_prmotn'    
  ,@ActionType = 'I'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'PageRequests'    
END 


GO

