/* ============================================================
   Procedure: [dbo].[usp_SaveGoogleFormWebhook]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SaveGoogleFormWebhook]
(
    @RequestJson NVARCHAR(MAX),          
    @ParentId BIGINT,
    @FormGUID NVARCHAR(255)
)
AS
BEGIN
    BEGIN TRY
        DECLARE @LeadId NVARCHAR(50) = '', 
                @TimeStamp NVARCHAR(50) = '';
        
        SELECT @LeadId = LeadId, @TimeStamp = [Timestamp]
        FROM OpenJson(@RequestJson)
        WITH
        (
            LeadId NVARCHAR(MAX) '$.data.lead_id',
            [Timestamp] NVARCHAR(MAX) '$.data.Timestamp'
        );

        IF EXISTS (
            SELECT TOP 1 ID 
            FROM tbl_GoogleForm_Webhook 
            WHERE RequestJson LIKE '%"lead_id":"'+ @LeadId +'"%'
            AND ParentID = @ParentId
            AND FormGUID = @FormGUID 
            ORDER BY ID DESC
        )
        BEGIN
            -- Duplicate request logic
            DECLARE @RequestJsonDataMatched NVARCHAR(MAX) = '';

            -- Fetch matched RequestJson
            SELECT TOP 1 @RequestJsonDataMatched = RequestJson
            FROM tbl_GoogleForm_Webhook
            WHERE RequestJson LIKE '%"lead_id":"'+ @LeadId +'"%'
            AND ParentID = @ParentId
            AND FormGUID = @FormGUID
            ORDER BY ID DESC;

            SELECT @TimeStamp = [Timestamp]
            FROM OpenJson(@RequestJsonDataMatched)
            WITH
            (
                [Timestamp] NVARCHAR(MAX) '$.data.Timestamp'
            );

            SELECT TOP 1
                CAST(ID AS NVARCHAR(50)) AS GoogleFormPrimaryID,
                CAST(0 AS NVARCHAR(50)) AS Status,
                ISNULL(@LeadId, 0) AS GoogleFormEnqID,
                @TimeStamp AS [Timestamp],
                'Duplicate Request Found' AS RequestStatus
            FROM tbl_GoogleForm_Webhook
            WHERE RequestJson LIKE '%"lead_id":"'+ @LeadId +'"%'
            AND ParentID = @ParentId
            AND FormGUID = @FormGUID
            ORDER BY ID DESC;
        END
        ELSE
        BEGIN
            INSERT INTO tbl_GoogleForm_Webhook
            (
                RequestJson, 
                ParentId, 
                FormGUID,
                CreatedAt, 
                isprocessed
            )
            VALUES
            (
                @RequestJson, 
                @ParentId, 
                @FormGUID, 
                GETDATE(), 
                0
            );

            DECLARE @ID BIGINT = SCOPE_IDENTITY();

            BEGIN TRY
                EXEC usp_ConvertGoogleLeadgenToEnquiry @ID;
            END TRY
            BEGIN CATCH
                EXEC usp_inserterrorInfo;
            END CATCH;
            SELECT
                CAST(@ID AS NVARCHAR(50)) AS GoogleFormPrimaryID,
                CAST(1 AS NVARCHAR(50)) AS Status,
                ISNULL(@LeadId, 0) AS GoogleFormEnqID,
                @TimeStamp AS [Timestamp],
                'Valid Request Found' AS RequestStatus
            FROM tbl_GoogleForm_Webhook
            WHERE ID = @ID AND ParentID = @ParentId;
        END
    END TRY
    BEGIN CATCH
        EXEC usp_inserterrorInfo;
    END CATCH;
END;



GO

