/* ============================================================
   Procedure: [dbo].[Usp_SaveIndiaMartAPIJSON]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveIndiaMartAPIJSON     
(      
   @JsonData nvarchar(max),      
   @ParentID bigint       
)      
as      
 begin      
         
     drop table if exists #tempIndiamartData
    
    Declare @IndiamartAPI_Id bigint = 0        
    Declare @IndiaMartAPI_Key nvarchar(200) = ''
    
   select top 1 @IndiaMartAPI_Key = [IndiamartId] from [IndiamartMapping] as imp with(nolock)
                                where Kit19ParentID = @ParentID
     
     if(not exists( select 1 from tbl_IndiamartJson with(nolock) where JsonData = @JsonData and ParentID = @ParentID      
            and isnull(@JsonData,'')  != ''              
      ))      
         begin      
          
          insert into tbl_IndiamartJson      
             (      
               JsonData,      
               ParentID      
             )      
            select @JsonData, @ParentID      
                
          set @IndiamartAPI_Id = scope_identity()      
      
        end      
if(isnull(@IndiamartAPI_Id,0) > 0)      
  begin      
  SELECT     
     B.UNIQUE_QUERY_ID
    ,B.QUERY_TYPE
    ,B.QUERY_TIME
    ,B.SENDER_NAME
    ,B.SENDER_MOBILE
    ,B.SENDER_EMAIL
    ,B.SUBJECT
    ,B.SENDER_COMPANY
    ,B.SENDER_ADDRESS
    ,B.SENDER_CITY
    ,B.SENDER_STATE
    ,B.SENDER_PINCODE
    ,B.SENDER_COUNTRY_ISO
    ,B.SENDER_MOBILE_ALT
    ,B.SENDER_PHONE
    ,B.SENDER_PHONE_ALT
    ,B.SENDER_EMAIL_ALT
    ,B.QUERY_PRODUCT_NAME
    ,B.QUERY_MESSAGE
    ,B.QUERY_MCAT_NAME
    ,B.CALL_DURATION
    ,B.RECEIVER_MOBILE

INTO #tempIndiaMartData

FROM tbl_IndiaMartJson t
CROSS APPLY OPENJSON(t.JsonData)
WITH
(
    UNIQUE_QUERY_ID      NVARCHAR(100) '$.UNIQUE_QUERY_ID',
    QUERY_TYPE           NVARCHAR(100) '$.QUERY_TYPE',
    QUERY_TIME           NVARCHAR(100) '$.QUERY_TIME',
    SENDER_NAME          NVARCHAR(200) '$.SENDER_NAME',
    SENDER_MOBILE        NVARCHAR(20)  '$.SENDER_MOBILE',
    SENDER_EMAIL         NVARCHAR(200) '$.SENDER_EMAIL',
    SUBJECT              NVARCHAR(500) '$.SUBJECT',
    SENDER_COMPANY       NVARCHAR(200) '$.SENDER_COMPANY',
    SENDER_ADDRESS       NVARCHAR(500) '$.SENDER_ADDRESS',
    SENDER_CITY          NVARCHAR(100) '$.SENDER_CITY',
    SENDER_STATE         NVARCHAR(100) '$.SENDER_STATE',
    SENDER_PINCODE       NVARCHAR(20)  '$.SENDER_PINCODE',
    SENDER_COUNTRY_ISO   NVARCHAR(10)  '$.SENDER_COUNTRY_ISO',
    SENDER_MOBILE_ALT    NVARCHAR(20)  '$.SENDER_MOBILE_ALT',
    SENDER_PHONE         NVARCHAR(20)  '$.SENDER_PHONE',
    SENDER_PHONE_ALT     NVARCHAR(20)  '$.SENDER_PHONE_ALT',
    SENDER_EMAIL_ALT     NVARCHAR(200) '$.SENDER_EMAIL_ALT',
    QUERY_PRODUCT_NAME   NVARCHAR(300) '$.QUERY_PRODUCT_NAME',
    QUERY_MESSAGE        NVARCHAR(MAX) '$.QUERY_MESSAGE',
    QUERY_MCAT_NAME      NVARCHAR(300) '$.QUERY_MCAT_NAME',
    CALL_DURATION        NVARCHAR(50)  '$.CALL_DURATION',
    RECEIVER_MOBILE      NVARCHAR(20)  '$.RECEIVER_MOBILE'
) AS B
WHERE t.id = @IndiaMartAPI_Id;
       
 INSERT INTO IndiamartLeads
  (
    INDIAMARTKEY,
    DateReceived,
    QUERY_ID,
    QTYPE,
    SENDERNAME,
    SENDEREMAIL,
    MOB,
    GLUSR_USR_COMPANYNAME,
    ENQ_ADDRESS,
    ENQ_CITY,
    ENQ_STATE,
    COUNTRY_ISO,
    PRODUCT_NAME,
    ENQ_MESSAGE,
    DATE_R,
    DATE_TIME_RE,
    LOG_TIME,
    ENQ_CALL_DURATION,
    ENQ_RECEIVER_MOB,
    EMAIL_ALT,
    MOBILE_ALT,
    PHONE,
    PHONE_ALT,
    SUBJECT
)
SELECT
     @IndiaMartAPI_Key                    AS INDIAMARTKEY
    ,GETDATE()                          AS DateReceived
    ,UNIQUE_QUERY_ID                    AS QUERY_ID
    ,QUERY_TYPE                         AS QTYPE
    ,SENDER_NAME                        AS SENDERNAME
    ,SENDER_EMAIL                       AS SENDEREMAIL
    ,SENDER_MOBILE                      AS MOB
    ,SENDER_COMPANY                     AS GLUSR_USR_COMPANYNAME
    ,SENDER_ADDRESS                     AS ENQ_ADDRESS
    ,SENDER_CITY                        AS ENQ_CITY
    ,SENDER_STATE                       AS ENQ_STATE
    ,SENDER_COUNTRY_ISO                 AS COUNTRY_ISO
    ,QUERY_PRODUCT_NAME                 AS PRODUCT_NAME
    ,QUERY_MESSAGE                      AS ENQ_MESSAGE
    
    -- Date Handling
    ,TRY_CONVERT(DATE, QUERY_TIME)      AS DATE_R
    ,TRY_CONVERT(DATETIME, QUERY_TIME)  AS DATE_TIME_RE
    ,GETDATE()                          AS LOG_TIME

    ,CALL_DURATION                      AS ENQ_CALL_DURATION
    ,RECEIVER_MOBILE                    AS ENQ_RECEIVER_MOB
    ,SENDER_EMAIL_ALT                   AS EMAIL_ALT
    ,SENDER_MOBILE_ALT                  AS MOBILE_ALT
    ,SENDER_PHONE                       AS PHONE
    ,SENDER_PHONE_ALT                   AS PHONE_ALT
    ,SUBJECT                            AS SUBJECT

FROM #tempIndiaMartData;        
          
       declare @IndiamartleadID bigint = scope_identity()  
          
          begin try  
               exec [Usp_TransferLeadDatatoCustomFieldMapping] @IndiamartAPI_Id ,'IndiaMart'     
              end try   
              begin catch  
                 drop table if exists #tempIndiamartData    
                 exec usp_insertErrorInfo   
              end catch  
              end      
          
            select isnull(@IndiamartAPI_Id,0) as IndiamartAPI_Id  
          
             drop table if exists #tempIndiamartData    
            
        end    
    
    


GO

