CREATE   PROCEDURE dbo.Usp_SaveIndiaMartEnquiry  
(  
  @CName nvarchar(200),  
  @CountryCode nvarchar(20),  
  @MobileNo nvarchar(50),  
  @SourceName nvarchar(100),   
  @UserID bigint  
)  
as  
Begin  
     Declare @ParentID bigint = 0  
  Declare @SourceID bigint = 0  
  select @ParentID = ISNULL(ParentID,USER_ID) from User_Detail(nolock) where User_ID = @UserID  
     
  if(exists(select 1 from UserSourceSettings(nolock) where UserID = @UserID and Name = @SourceName))  
     Begin  
     select @SourceID = isnull(SourceID,0) from UserSourceSettings(nolock) where UserID = @UserID and Name = @SourceName  
  End   
     else  
    Begin   
         insert into UserSourceSettings(Name,UserID,IsEditable,IsActive,CreatedDate,ModifiedDate,ModifiedBy)         
         select @SourceName,@UserID,1,1,getdate(),getdate(),@UserID  
   Select @SourceID = SCOPE_IDENTITY()  
    End         
  
                 
  
  
End


