/* ============================================================
   Procedure: [dbo].[Usp_SaveInvalidEmailID_KarixAPI_WithBatchIDAndGUI]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_SaveInvalidEmailID_KarixAPI_WithBatchIDAndGUI]      
(      
  @invalidEmailIDJson nvarchar(max)       
)      
as      
Begin      
           
   Drop table if exists #temp                   
   Drop table if exists #tempRowtbl                         
  
  begin try      
      
   select * into #temp from openjson(@invalidEmailIDJson)              
     WITH              
      (              
       MAIL_USERID bigint '$.MAIL_USERID',              
       Mail_BatchID varchar(500) '$.Mail_BatchID',              
       Mail_ToEmail VARCHAR(500) '$.Mail_ToEmail'            
      );      
        
  insert into [tbl_InvalidEmailID_KarixAPI]      
   ( [MAIL_USERID], [Mail_BatchID], [Mail_ToEmail], [CreatedOn] )      
     select [MAIL_USERID], [Mail_BatchID], [Mail_ToEmail], getdate() from #temp           
              
  
     update t set t.[Mail_BatchID] = case when charindex('~',t.[Mail_BatchID]) <> 0      
                   then (select  value from fn_split(t.[Mail_BatchID],'~') where Position = 2)      
       else      
          t.[Mail_BatchID]       
       end       
      from #temp as t          
     
     select row_number() over(order by [Mail_BatchID] asc) as RowNum, * into #tempRowtbl from  #temp                
  declare @Count int = 0   
  declare @RowNum int = 1   
  declare @BatchID nvarchar(500) = '0'
  declare @MailToEmailVar nvarchar(500) = ''

    
  select @Count = count(1) from #tempRowtbl   
  
  while(@count > 0)  
   begin  
         
   select top 1 @BatchID = [Mail_BatchID] , @MailToEmailVar = [Mail_ToEmail]   from #tempRowtbl where RowNum = @RowNum  
     
   if( not exists( select 1 from EmailCounTracking (nolock) where batchid = @BatchID and tablename = 'tbl_InvalidEmailID_KarixAPI' ))  
      begin  
          insert into EmailCounTracking            
                (batchid, tablename, mailcount, createdon)            
                 select [Mail_BatchID] as batchid  
       , 'tbl_InvalidEmailID_KarixAPI' as tablename , 1 as mailcount, GETDATE()            
                    from #tempRowtbl  where RowNum = @RowNum   
   end  
         else  
      begin  
       update t set t.mailcount = isnull(t.mailcount,0) + 1 from  EmailCounTracking (nolock) as t where  batchid = @BatchID and tablename = 'tbl_InvalidEmailID_KarixAPI'    
  
   end  

        delete from emailsFilter where Mail_BatchID = @BatchID and Mail_ToEmail =  @MailToEmailVar
		update BatchEmail_Infos set TotalProcessed = isnull(TotalProcessed,0) - 1 where BatchID =  @BatchID and isnull(TotalProcessed,0) > 0 

  
          set @RowNum = @RowNum + 1  
    set @Count = @Count - 1  
   end  
     
        /*  
      insert into EmailCounTracking            
            (batchid, tablename, mailcount, createdon)            
         select   case when charindex('~',[Mail_BatchID]) <> 0    
                  then (select  value from fn_split([Mail_BatchID],'~') where Position = 2)  
      end as batchid  
       , 'tbl_InvalidEmailID_KarixAPI' as tablename , Count(1) as mailcount, GETDATE()            
         from #temp    
        group by   case when charindex('~',[Mail_BatchID]) <> 0    
                  then (select  value from fn_split([Mail_BatchID],'~') where Position = 2)  
      end      
        */  
    
  
   end try        
  begin catch      
    exec usp_insertErrorinfo       
  end catch      
      
      
  Drop table if exists #temp                   
  Drop table if exists #tempRowtbl  
    
End 


GO

