)  
AS   
BEGIN
	INSERT INTO SearchDetails
	  (
	    SearchName,
	    IsKitever,
	    IsUsers,
	    IsActive,
	    LoginDateFrom,
	    LoginDateTo,
	    TimeSpentOnApp,
	    TimeOperator,
	    ConsumptionFrom,
	    ConsumptionTo,
	    SMSConsumptionFrom,
	    SMSConsumptionTo,
	    MailConsumptionFrom,
	    MailConsumptionTo,
	    BalanceUsed,
	    Operator,
	    SMSBalanceUsed,
	    SMSOperator,
	    MailBalanceUsed,
	    MailOperator,
	    OrderFrom,
	    OrderTo,
	    LeadsFrom,
	    LeadsTo,
	    TopUpFrom,
	    TopUpTo,
	    TopUpOperator,
	    TopUpAmount,
	    RegistrationDateFrom,
	    RegistrationDateTo,
	    CreatedDate,
	    CreatedBy,
	    ModifiedDate,
	    ModifiedBy
	  )
	VALUES
	  (
	    @SearchName,
	    1,
	    1,
	    @IsActive,
	    @LoginDateFrom,
	    @LoginDateTo,
	    @TimeSpentOnApp,
	    @TimeOperator,
	    @ConsumptionFrom,
	    @ConsumptionTo,
	    @SMSConsumptionFrom,
	    @SMSConsumptionTo,
	    @MailConsumptionFrom,
	    @MailConsumptionTo,
	    @BalanceUsed,
	    @Operator,
	    @SMSBalanceUsed,
	    @SMSOperator,
	    @MailBalanceUsed,
	    @MailOperator,
	    @OrderFrom,
	    @OrderTo,
	    @LeadsFrom,
	    @LeadsTo,
	    @TopUpFrom,
	    @TopUpTo,
	    @TopUpOperator,
	    @TopUpAmount,
	    @RegistrationDateFrom,
	    @RegistrationDateTo,
	    GETDATE(),
	    @CreatedBy,
	    GETDATE(),
	    @CreatedBy
	  )   
	
	SELECT 'Record Inserted'
END  



