/* ============================================================
   Procedure: [dbo].[usp_SaveLeadCustomFieldValue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROC usp_SaveLeadCustomFieldValue  
(  
    @LeadID bigint,  
    @EnquiryID bigint,  
    @fieldID bigint,  
    @fieldvalue sql_variant  
)  
AS  
Begin  
   
   begin try
   
    Declare @recordID bigint=0  
  
    If exists(select recordID from customfieldLeadvalue where LeadID = @LeadID and fieldID = @fieldID)  
    Begin  
    update customfieldLeadvalue set fieldvalue=@fieldvalue, @recordID=recordID where LeadID = @LeadID and fieldID = @fieldID  
    End  
    Else  
    Begin  
    insert into customfieldLeadvalue(LeadID,EnquiryID,fieldID,fieldvalue) values(@LeadID, @EnquiryID, @fieldID, @fieldvalue)  
    Select @recordID=SCOPE_IDENTITY();  
    End  
  
   Select @recordID  

   end try
   begin catch

       exec usp_InsertErrorInfo

   End catch

End 



GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveLeadScoreValues]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  dbo.Usp_SaveLeadScoreValues
(
  @EventName nvarchar(200),
  @CategoryName nvarchar(200),
  @RuleDescription nvarchar(max),
  @Operation nvarchar(50) ,
  @Points int,
  @UserID bigint,
  @ParentID bigint  
)
as
Begin
    
	 /*
       id,	parentid,	cat_id,	event_id,
        rule_desc,	Operation,	points,	createdby,	createdon,	isdeleted,	lastupdatedon,	lastupdatedby 
     */
	 Declare @EventID bigint = 0
	 Declare @CatgID int = 0 

	 select top 1 @EventID = isnull(ID,0) from ActivityMaster(nolock) where EventName = @EventName
	 select top 1 @CatgID = isnull(ID,0) from lead_scoring_categories(nolock) where Category = @CategoryName

	 insert into lead_scoring_rules
	 (
	   parentid,
	   cat_id,
	   event_id,
       rule_desc,
	   Operation,
	   points,
	   createdby,
	   createdon,
	   isdeleted,
	   lastupdatedon,
	   lastupdatedby
	 )
	 values
	 ( 
	   @ParentID,
	   @CatgID,
	   @EventID,
	   @RuleDescription,
	   @Operation,
	   @Points,
	   @UserID,
	   getdate(),
	   0,
	   getdate(),
	   @UserID
	 )

	select 'Record Saved'

End



GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveLeadScoreValues_New_SingleOPR]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveLeadScoreValues_New_SingleOPR (
	@tblRules LeadScoreRules_TblType readonly
	,@UserID BIGINT
	,@OPR NVARCHAR(100)
	)
AS
BEGIN
	DECLARE @ParentID BIGINT = 0
		,@activity VARCHAR(MAX) = ''
		,@action VARCHAR(1) = ''
		,@id BIGINT = 0

	SELECT @ParentID = isnull(ParentID, 0)
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserID

	DECLARE @Count INT = 0
	DECLARE @SNo INT = 1;

	SELECT @Count = count(1)
	FROM @tblRules

	DECLARE @CategoryID INT = 0
	DECLARE @EventID BIGINT = 0

	SELECT TOP 1 @CategoryID = isnull(ID, 0)
	FROM lead_scoring_categories(NOLOCK)
	WHERE Category IN (
			SELECT TOP 1 isnull(CategoryName, 0)
			FROM @tblRules --where SNo = @SNo    
			)

	SELECT TOP 1 @EventID = isnull(ID, 0)
	FROM ActivityMaster(NOLOCK)
	WHERE EventName IN (
			SELECT TOP 1 isnull(EventName, 0)
			FROM @tblRules --where SNo = @SNo    
			)

	IF (@OPR = 'save')
