	--    isdeleted,      
	--    lastupdatedon,      
	--    lastupdatedby      
	--     )    
	--     select @ParentID ,@CategoryID,@EventID , RuleDescription, Operation    
	--     ,Points,@UserID,getdate(),0,getdate(),@UserID     
	--     from  @tblRules where SNo = @SNo    
	--    End        
	--       else    
