/* ============================================================
   Procedure: [dbo].[Usp_SaveMailAPIResponse]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveMailAPIResponse    
(    
  @ResponseJson nvarchar(max)      
)    
as    
Begin    
      Drop table if exists #temp         
       drop table if exists #tblMailCount  
  
   select * into #temp from openjson(@ResponseJson)    
       WITH    
     (    
           MailBatchID varchar(100) '$.MailBatchID',    
     MAIL_ID VARCHAR(100) '$.MAIL_ID',    
     To_Email VARCHAR(500) '$.To_Email',    
     MessageID VARCHAR(200) '$.MessageID',    
     IsPersonalized int '$.IsPersonalized',    
     SentStatus int '$.SentStatus',    
     Response VARCHAR(max) '$.Response'    
           );    
        
         
    
   insert into tbl_MailResponse    
   (    
    [MailBatchID]    
      ,[To_Email]    
      ,[MessageID]    
      ,[IsPersonalized]    
      ,[SentStatus]    
      ,[Response]    
      ,[CreatedOn]    
   )    
   select     
    [MailBatchID]    
      ,[To_Email]    
      ,[MessageID]    
      ,[IsPersonalized]    
      ,[SentStatus]    
      ,[Response]    
      ,getdate()    
        
    from #temp    
   
      
   select [MailBatchID] as batchid , count(1) as mailcount  
        into #tblMailCount  
    from #temp  
      group by  [MailBatchID]   
  
         insert into EmailCounTracking  
            (batchid, tablename, mailcount, createdon)  
         select batchid, 'tbl_MailResponse', mailcount, GETDATE()  
         from #tblMailCount     
       
   -- please dont delete commented portion     
         
   update EF set EF.IsProcess = 1 from emailsfilter as EF with(nolock)     
    join #temp as t    
    on Ef.Mail_ID = t.MAIL_ID    
       and EF.Mail_BatchID = t.[MailBatchID]     
     /*
    delete from emailsfilter    
   where Mail_GUID in    
   (     
      select EF.Mail_GUID from emailsfilter as EF with(nolock)     
         join #temp as t    
          on Ef.Mail_ID = t.MAIL_ID    
          and EF.Mail_BatchID = t.[MailBatchID]    
      where EF.IsProcess = 1           
    )    
    */    
    
       
     drop table if exists #tblMailCount  
   Drop table if exists #temp         
End


GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveMailAPIResponse_New_WithBatchIDAndGUICombined]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_SaveMailAPIResponse_New_WithBatchIDAndGUICombined]                 
(                
  @ResponseJson nvarchar(max)                  
)                
as                
Begin                
                
     Drop table if exists #temp                     
     drop table if exists #tblMailCount              
     Drop table if exists #tempRowTbl    
      
 begin try  
  
   select * into #temp from openjson(@ResponseJson)                
       WITH                
     (                
           MailBatchID varchar(500) '$.MailBatchID',                
     MAIL_ID VARCHAR(100) '$.MAIL_ID',                
     To_Email VARCHAR(500) '$.To_Email',                
     MessageID VARCHAR(200) '$.MessageID',                
     IsPersonalized int '$.IsPersonalized',                
     SentStatus int '$.SentStatus',                
     Response VARCHAR(max) '$.Response',                
     FromMailID Varchar(500) '$.FromMailID',          
     ReplyToEmailID Varchar(500) '$.ReplyToEmailID'          
  );                
                    
                     
                
   insert into tbl_MailResponse                
   (                
       [MailBatchID]                
      ,[To_Email]                
      ,[MessageID]                
      ,[IsPersonalized]                
      ,[SentStatus]                
      ,[Response]                
      ,[CreatedOn]          
   ,[FromMailID]          
   ,[ReplyToEmailID]          
   )                
   select                 
       [MailBatchID]                
      ,[To_Email]                
      ,[MessageID]                
      ,[IsPersonalized]                
      --,[SentStatus]   
   ,( case when isnull(p.SentStatus,0) = 0   
                 then 0  
        when p.SentStatus = 1   
                 then 1      
       end  
    )  SentStatus  
      ,[Response]                
      ,getdate()          
      ,[FromMailID]          
      ,[ReplyToEmailID]               
    from  #temp as p   
   
  
  update t set t.MailBatchID = case when charindex('~',t.MailBatchID) <> 0        
                   then (select  value from fn_split(t.MailBatchID,'~') where Position = 2)        
       else        
          t.MailBatchID         
       end         
      from #temp as t        
        
   begin try  
  
   update t set  t.Status = 'Failed' ,  
                 t.status_desc = p.Response,  
        t.SentFinalDatetime = getdate()  
       from ClientEmails as t with(nolock)   
                join #temp as p on t.BatchID = p.MailBatchID  
                    where isnull(p.SentStatus,0) = 0 and p.To_Email = t.Email_Id        
       end try  
    begin catch  
      exec usp_insertErrorInfo  
    end catch  
        
        
   select [MailBatchID]        
         as batchid        
      , count(1) as mailcount              
        into #tblMailCount              
    from #temp              
      group by  [MailBatchID]               
         
   select row_number() over(order by batchid asc) as RowNum , * into #tempRowTbl  from  #tblMailCount     
    
    
    declare @Count int = 0     
  declare @RowNum int = 1     
  declare @BatchID nvarchar(500) = '0'    
      
  select @Count = count(1) from #tempRowtbl     
    
  while(@count > 0)    
   begin    
           
   select top 1 @BatchID = batchid from #tempRowtbl where RowNum = @RowNum    
       
   if( not exists( select 1 from EmailCounTracking (nolock) where batchid = @BatchID and tablename = 'tbl_MailResponse' ))    
      begin    
          insert into EmailCounTracking              
                (batchid, tablename, mailcount, createdon)              
                 select batchid as batchid    
       , 'tbl_MailResponse' as tablename , mailcount as mailcount, GETDATE()              
                    from #tempRowtbl  where RowNum = @RowNum     
   end    
         else    
      begin    
      declare @MailCount int = 0;    
      select top 1 @MailCount = mailcount from #tempRowtbl where RowNum = @RowNum    
    
       update t set t.mailcount = isnull(t.mailcount,0) + @MailCount from  EmailCounTracking (nolock) as t where  batchid = @BatchID and tablename = 'tbl_MailResponse'      
    
   end    
    
          set @RowNum = @RowNum + 1    
    set @Count = @Count - 1    
   end    
    
    
        
     /*    
         insert into EmailCounTracking              
            (batchid, tablename, mailcount, createdon)              
         select batchid, 'tbl_MailResponse', mailcount, GETDATE()              
         from #tblMailCount                 
                 
     */       
     
    
    -- please dont delete commented portion                 
                     
   update EF set EF.IsProcess = 1 from emailsfilter as EF --with(nolock)                 
    join #temp as t                
    on Ef.Mail_ID = t.MAIL_ID                
       --and EF.Mail_BatchID = t.[MailBatchID]                 
                 
   delete from emailsfilter                
   where Mail_GUID in                
   (                 
      select EF.Mail_GUID from emailsfilter as EF --with(nolock)                 
         join #temp as t                
          on Ef.Mail_ID = t.MAIL_ID                
         -- and EF.Mail_BatchID = t.[MailBatchID]                
      where EF.IsProcess = 1                       
    )                
               
   end try  
   begin catch  
      exec usp_InsertErrorInfo       
   end catch  
                   
   drop table if exists #tblMailCount              
   Drop table if exists #temp                     
   Drop table if exists #tempRowTbl                     
      
End


GO

