CREATE   PROCEDURE dbo.Usp_SaveMOHFileToFlowAPI -- 'hold',4751,17534    
(      
   @FileName nvarchar(100),      
   @AppID  bigint,      
   @ParentID bigint      
)      
as      
Begin      
  if exists(select 1 from Cloud_audio_master c with (nolock) join cloud_playfile p with (nolock) on c.user_id=p.clientid 
  and c.path=p.R_url and p.name like filename +'%'  
  where filename=@filename  
  and user_id in (select user_id from user_detail(nolock) where parentid=@parentid))  
  begin  
  --declare @date nvarchar(20)
  --select top 1 @date=cast(FORMAT(createddate, 'ddMMyyyy') as nvarchar) from Cloud_audio_master(nolock) where filename=@filename  
  --and user_id in (select user_id from user_detail(nolock) where parentid=@parentid)  
  --order by libraryid desc  
  --select top 1 @filename=@filename+'_'+@date
  --from Cloud_audio_master(nolock) where filename=@filename  
  --and user_id in (select user_id from user_detail(nolock) where parentid=@parentid)  
  --order by libraryid desc  
  select top 1 @filename=name from Cloud_audio_master c with (nolock) join cloud_playfile p with (nolock) on c.user_id=p.clientid 
  and c.path=p.R_url and p.name like filename +'%' 
  where filename=@filename  
  and user_id in (select user_id from user_detail(nolock) where parentid=@parentid)  
  order by libraryid desc
  end  
  
    if(exists( select 1 from Cloud_flow_api with(nolock) where Appid = @AppID and Parentid = @ParentID ))    
    Begin          
    update [Cloud_flow_api] set moh = @FileName where Appid = @AppID and Parentid = @ParentID      
    select 'Updated Successfully'    
    end    
  else    
    Begin    
        select 'Please Create Applet of this App first'      
    end                 
End



