/* ============================================================
   Procedure: [dbo].[Usp_SaveMsgXMLAPIResp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveMsgXMLAPIResp               
(              
  @tbl tblType_MSG_XMLAPI_Resp_new2 readonly,              
  @tblName nvarchar(100)              
)              
as              
Begin              
                  
 insert into [MSG_XMLAPI_Resp]               
   (              
    [transactionId]              
      ,[state]              
      ,[description]              
      ,[pdu]              
      ,[corelationId]              
      ,[CreatedDate]            
   ,[SenderID]            
   ,[Mobile]        
   ,[DLT_TemplateID]        
   ,[DLT_PEID]         
   ,tbl_Name              
   )              
   select              
    [transactionId]              
      ,[state]              
      ,[description]              
      ,[pdu]              
      ,[corelationId]              
      ,getdate()             
   ,[SenderID]            
   ,[Mobile]            
   ,[DLT_TemplateID]        
   ,[DLT_PEID]         
   ,@tblName              
             from @tbl              
            
     /*** Please do not delete comemted part ****/               
             
          
    drop table if exists #TempTBL              
              
    select               
    ROW_NUMBER() over( order by [corelationId] asc ) as RowNum              
   , [transactionId]              
      ,[state]              
      ,[description]              
      ,[pdu]              
      ,[corelationId]              
    into #TempTBL               
   from @tbl              
              
    declare @Count int = isnull((select count(1) from #TempTBL),0)              
       declare @RowNum int = 1                             
       declare @Status nvarchar(100) = ''              
       declare @MessageID nvarchar(100) = ''              
       declare @StatusDescription nvarchar(max) = ''  
    declare @transactionId nvarchar(100) = ''  
    declare @corelationId nvarchar(100) = ''  
  
  
  
    while(@Count > 0)              
     begin              
     select top 1 @Status = isnull(State,''), @MessageID = isnull(corelationId,'0'), @StatusDescription = isnull([description],'')  
  ,@corelationId = isnull(corelationId,'0'),@transactionId = isnull(transactionId,'0')  
  from #TempTBL where RowNum = @RowNum                 
               
   declare @query nvarchar(max) = ''          
         
    begin try  
  
     if(@Status = 'SUBMIT_ACCEPTED')              
       Begin              
          -- delete from [MySMSTrans].[DBO].messagequeuenew where MessageID = @MessageID                      
        set @query = concat(' delete from [MySMSTrans].[DBO].[' , @tblName , '] where MessageID = ' , cast( @MessageID as nvarchar(100)),'')          
       exec sp_executesql @Query           
          
       End              
     else               
       Begin              
        --select @Query =                
       --  update t set t.isprocessed = 0 from [MySMSTrans].[DBO].messagequeuenew as t with(nolock)  where MessageID = @MessageID              
        -- set @query = CONCAT('update t set t.isprocessed = 2 from [MySMSTrans].[DBO].[' , @tblName , '] as t with(nolock)  where MessageID = '          
         --, cast( @MessageID as nvarchar(100)),'')           
         
    --set @query = concat('update [mysms].[dbo].MessageDeliveryStatus set messagestatus=''failed'', StatusDescription = ', @StatusDescription ,'   
      --           where MessageID = ', cast(@MessageID as nvarchar(100)))   
  
        --exec sp_executesql @Query                
  
   update [mysms].[dbo].MessageDeliveryStatus set messagestatus='failed', StatusDescription =  @StatusDescription    
                where MessageID = @MessageID   
  
      update  [MSG_XMLAPI_Resp] set DLR_Processed = 1 , DLR_ProcessedAt = getdate()  where corelationId = @corelationId   
        and transactionID = @transactionId    
     
    set @query = concat(' delete from [MySMSTrans].[DBO].[' , @tblName , '] where MessageID = ' , cast( @MessageID as nvarchar(100)),'')          
    exec sp_executesql @Query  
      
   
       End              
      end try  
   begin catch  
       exec usp_inserterrorInfo      
   end catch  
    
  
     set @RowNum = @RowNum + 1              
     set @Count = @Count -1              
  end              
              
         drop table if exists #TempTBL        
              
End 


GO

