/* ============================================================
   Procedure: [dbo].[usp_SaveNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROC usp_SaveNotification      
(      
    @csvUserId  varchar(max),      
    @Title  nvarchar(200),      
    @Content  nvarchar(max),      
    @ImageUrl  nvarchar(4000),      
    @ActionUrl  nvarchar(1000),      
    @ScheduledTime  datetime,      
    @CutOffTime  datetime,      
    @UserID  bigint      
)      
AS      
BEGIN      
      
    Declare @TotalRecords int=0, @BatchNotification_Id bigint=0      
      
    select @TotalRecords=Count(*) from dbo.fn_Split(@csvUserId,',')      
      
    INSERT INTO [dbo].[MK_BatchNotification]      
   ([Title],[MessageText],[ImageUrl],[ClickActionUrl],[BatchSentTime],[TotalRecords],[ScheduledDate],[TotalProcessed]      
   ,[BatchCompleteTime],[LastBatchProcessed],[IsProcessed],[CutOffTime],[CreatedOn],[CreatedBy])      
     VALUES      
   (@Title, @Content, @ImageUrl, @ActionUrl, null, @TotalRecords, @ScheduledTime, 0      
   , null, null, 0, isnull(@CutOffTime,dateadd(hh,6,@ScheduledTime)), GETDATE(), @UserID)      
      
    Select @BatchNotification_Id=SCOPE_IDENTITY()      
      
     select @csvUserId = REPLACE(@csvUserId , '#' , ',') 
      
    INSERT INTO [dbo].[MK_BatchNotificationDetail]      
   ([BatchNotification_Id],[User_ID],[LastAttemptedTime],[Retries],[LastStatus],[IsProcessed])      
     Select @BatchNotification_Id, [value], null, 0, '', 0      
     From  dbo.fn_Split(@csvUserId,',')      
      
    Select @BatchNotification_Id      
      
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_SavePipeline]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SavePipeline (    
 @PipelineName NVARCHAR(500)    
 ,@DealExpiry INT    
 ,@IsDefault BIT    
 ,@ParentID BIGINT    
 ,@CreatedBy BIGINT    
 ,    
 --@Owner bigint,       
 @tbl pipelineTbl_type readonly    
 ,@tblLostRe pipelinelostreasonTbl_type readonly    
 )    
AS    
BEGIN    
 DECLARE @PipeLineID BIGINT = 0;    
    
 IF (    
   NOT EXISTS (    
    SELECT 1    
    FROM Pipeline_Master    
    WHERE ParentID = @ParentID    
     AND Name = @PipelineName    
     AND IsDeleted = 0    
    )    
   )    
 BEGIN    
  INSERT INTO Pipeline_Master (    
   [ParentID]    
   ,[Name]    
   ,[DealExpiry]    
   ,[IsDefault]    
   ,[CreatedDate]    
   ,[CreatedBy]    
   ,[IsDeleted]    
   ,[Owner]    
   ,[DeletedDate]    
   )    
  VALUES (    
   @ParentID    
   ,@PipelineName    
   ,@DealExpiry    
   ,@IsDefault    
   ,GETDATE()    
   ,@CreatedBy    
   ,0    
   --,@Owner            
   ,NULL    
   ,NULL    
   )    
    
  SET @PipeLineID = SCOPE_IDENTITY()    
    
  INSERT INTO PipelineStages (    
   [PipelineID]    
   ,[Name]    
   ,[Probability]    
   ,[CreatedDate]    
   ,[Createdby]    
   ,[IsDefault]    
   ,[IsDeleted]    
   ,[Sequence]    
   ,[IsEditable]    
   ,[DeletedDate]    
   )    
  SELECT @PipeLineID    
   ,[Name]    
   ,Probability    
   ,getdate()    
   ,@CreatedBy    
   ,IsDefault    
   ,0    
   ,[Sequence]    
   ,IsEditable    
   ,NULL    
  FROM @tbl    
    
  INSERT INTO PipelineStages_Reason (    
   [PipelineID]    
   ,[Reason]    
   ,[ParentID]    
   ,[IsActive]    
   ,[CreatedDate]    
   ,[Createdby]    
   )    
  SELECT @PipeLineID    
   ,Reason    
   ,@ParentID    
   ,1    
   ,getdate()    
   ,@ParentID    
  FROM @tblLostRe    
    
  DECLARE @Count INT = 0    
    
  SELECT @Count = count(1)    
  FROM Pipeline_Master    
  WHERE ParentID = @ParentID    
    
  IF (@Count = 1)    
  BEGIN    
   UPDATE Pipeline_Master    
   SET IsDefault = 1    
   WHERE ID = @PipeLineID    
  END    
    
  IF (@IsDefault = 1)    
  BEGIN    
   UPDATE Pipeline_Master    
   SET IsDefault = 0    
   WHERE ID <> @PipeLineID    
    
   UPDATE Pipeline_Master    
   SET IsDefault = 1    
   WHERE ID = @PipeLineID    
  END    
    
  SELECT 'Record Saved'    
 END    
 ELSE    
 BEGIN    
  SELECT 'Pipeline already exists'    
 END    
    
 DECLARE @rowJson VARCHAR(MAX) = (    
   SELECT *    
   FROM Pipeline_Master(NOLOCK)    
   WHERE ID = @PipeLineID    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 IF @rowJson IS NOT NULL    
 BEGIN    
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy    
   ,@Activity_type = 'Inst_PipelnStge'    
   ,@ActionType = 'I'    
   ,@RowJson = @rowJson    
   ,@Table_name = 'Pipeline_Master'    
 END    
END 


GO

