  @IsPublished bit,  
  @IsFeatured bit,  
  @IsActive bit,  
  @ProductFileURL_Type_TBL  ProductFileURL_Type readonly,  
  @UserID bigint  
  
)  
as  
Begin  
    Declare @ParentID bigint = 0;  
 Declare @ProductID bigint = 0;  
 Select top 1 @ParentID = isnull(ParentID,User_ID) from User_Detail(nolock) where User_ID = @UserID  
    
  
  
    if(not exists (select 1 from ProductMaster(nolock) where sku = @SKU))  
  Begin  
  if(not exists(select 1 from ProductMaster(nolock) where UserID = @UserID and Name = @ProductName))   
   Begin  
     
  insert into ProductMaster  
  (  
     [Name]  
      ,[UserID]  
      ,[Image]  
      ,[Description]  
      ,[Price]  
      ,[IsPublished]  
      ,[IsActive]  
      ,[CreatedOn]  
      ,[CreatedBy]  
      ,[FullPath]  
      ,[IsFeatured]  
      ,[sku]  
      ,[quantity]  
      ,[category_id]  
      ,[HomeTaxIDs]  
      ,[OtherTaxIDs]  
      ,[UpdatedAt]  
      ,[DeletedAt]  
      ,[SellingAccount]  
      ,[Cast_Price]  
      ,[Cast_Account]  
      ,[IsDigitalService]  
      ,[IsGoods]  
      ,[IsServices]  
      ,[SACCode]  
      ,[HSNCode]  
      ,[IsTaxable]  
      ,[DecimalRateItemQuantity]  
      ,[UnitID]  
     )  
  values  
    (  
    @ProductName  
      ,@UserID  
      ,''  
      ,@Description  
      ,@SalesPrice  
      ,@IsPublished  
      ,@IsActive  
      ,getdate()  
      ,@UserID  
      ,''  
      ,@IsFeatured  
      ,@sku  
      ,@DecimalRateQuantity  
      ,@categoryid  
      ,@HomeStateTaxIDs  
      ,@OtherTaxIDs  
      ,getdate()  
      ,null  
      ,@SalesAccount  
      ,@CastPrice  
      ,@CastAccount  
      ,@IsDigitalService  
      ,@IsGoods  
      ,@IsServices  
      ,@SACCode  
      ,@HSNCode  
      ,@IsTaxable  
      ,@DecimalRateQuantity  
      ,@UnitID  
  )  
         
     select @ProductID = SCOPE_IDENTITY()  
          
   declare @Count int = 0;  
  select @Count = Count(1) from @ProductFileURL_Type_TBL   
  if(@Count > 0)  
    Begin  
       Declare @ImagePart nvarchar(100) = ''   
    Declare @FullPath nvarchar(max) = ''  
             Select @FullPath = FileURL From @ProductFileURL_Type_TBL where ID = 1    
  
     Declare @index int = 0  
              select @index = charindex('ProductImages',@FullPath)  
     if(@index <> 0)  
      Begin  
                  select @ImagePart = SUBSTRING(@FullPath,@index,len(@FullPath)- @index + 1)   
         update ProductMaster set Image = @ImagePart ,FullPath = @FullPath where ProductID = @ProductID   
                end  
   
           insert into ProductImageMapping  
      (ProductID,ImageURL,CreatedDate)  
      select @ProductID,FileUrl,getdate() from @ProductFileURL_Type_TBL   
  
     End  
        
    if(rtrim(ltrim(@ProductTagsIDs)) <> '')  
      Begin  
       insert into EntityTagMapping  
    (EntityID,Entity,CreatedDate,TagID)  
    select @ProductID,'Product',getdate(),cast(value as bigint) from fn_Split(@ProductTagsIDs,'#')    
   End     
             
   select 'Data Saved Successfully' as MSG     
              
   End  
  else  
    Begin  
    select 'Product Name Already Exists'  as MSG  
    End        
     End      
  else  
    Begin  
       select 'Shop Keeping Unit Already Exists' as MSG   
    End  
      
  
End  
  



GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveProductDetailsWithChanges_NEW]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


  
CREATE   PROCEDURE [dbo].[Usp_SaveProductDetailsWithChanges_NEW]     
(    
 @IsGoods BIT    
 ,@IsServices BIT    
 ,@IsDigitalService BIT    
 ,@ProductName NVARCHAR(100)    
 ,@SKU NVARCHAR(50)    
 ,@UnitID INT    
 ,@HSNCode NVARCHAR(50)    
 ,@SACCode NVARCHAR(50)    
 ,@IsTaxable BIT    
 ,@HomeStateTaxIDs NVARCHAR(max)    
 ,@OtherTaxIDs NVARCHAR(max)    
 ,@SalesPrice NUMERIC(18, 2)    
 ,@SalesAccount BIGINT    
 ,@CastPrice NUMERIC(18, 2)    
 ,@CastAccount BIGINT    
 ,@DecimalRateQuantity INT    
 ,@Description NVARCHAR(200)    
 ,@ProductTagsIDs NVARCHAR(max)    
 ,@CategoryID INT    
 ,@IsPublished BIT    
 ,@IsFeatured BIT    
 ,@IsActive BIT    
 ,@ProductFileURL_Type_TBL ProductFileURL_Type readonly    
 ,@UserID BIGINT    
 ,@IsSaleable BIT    
 ,@CustomFieldValueJson NVARCHAR(max) 
 ,@ThumbnailUrl nvarchar(1000)
 
 )    
AS    
BEGIN    
 DECLARE @ParentID BIGINT = 0;    
 DECLARE @ProductID BIGINT = 0    
 DECLARE @Count INT = 0    
  ,@check INT = '0'    
  ,@check2 INT = 0    
    
 SELECT TOP 1 @ParentID = isnull(ParentID, User_ID)    
 FROM User_Detail(NOLOCK)    
 WHERE User_ID = @UserID    
    
 DECLARE @sqls NVARCHAR(max) = ''    
  ,@status INT    
  ,@tableName NVARCHAR(max) = ''    
 DECLARE @min INT    
  ,@max INT    
  ,@fieldName VARCHAR(200)    
  ,@value NVARCHAR(max)    
   ,@customfieldlist nvarchar(max)
   ,@customfieldvalue nvarchar(max) 
 DROP TABLE    
    
 IF EXISTS #temp    
  DROP TABLE    
    
 IF EXISTS #temp2    
  CREATE TABLE #temp (    
   id INT identity(1, 1)    
   ,lbltxt NVARCHAR(max)    
   ,value NVARCHAR(Max)    
   )    
    
 SELECT @customfieldlist= string_agg(lbltxt,',')  
     ,@customfieldvalue= string_agg( case  when value is  NULL then 'NULL'
							else ''''+value+''''  end  ,' ,')
    FROM OPENJSON(@CustomFieldValueJson) WITH (  
      lbltxt NVARCHAR(max) '$.lbltxt'  
      ,value NVARCHAR(Max) '$.value '  
      )  
 EXEC @status = Usp_CreateProductTableByParentID @userid    
  ,@tableName OUTPUT    
    
 IF (@status = 1)    
 BEGIN    
  SET @sqls = 'select @check=1 from ' + @tablename + '(nolock) where sku = ''' + @SKU + ''''    
    
  --print @sqls          
  EXECUTE sp_executesql @sqls    
   ,N'@check int out'    
   ,@check OUT    
    
  SET @sqls = 'select @check2=1 from ' + @tablename + '(nolock) where UserID = ' + cast(@UserID AS VARCHAR) + ' and Name = ''' + @ProductName + ''''    
    
  --print @sqls          
  EXECUTE sp_executesql @sqls    
   ,N'@check2 int out'    
   ,@check2 OUT    
    
  IF @check = 0    
  BEGIN    
   IF @check2 = 0    
   BEGIN    
    SET @sqls = 'insert into ' + @tablename + ' ([Name],[UserID],[Image],[Description],[Price],[IsPublished],[IsActive]
	,[CreatedOn],[CreatedBy],[FullPath],[IsFeatured],[sku],[quantity],[category_id]          
   ,[HomeTaxIDs],[OtherTaxIDs],[UpdatedAt],[DeletedAt],[SellingAccount],[CostPrice],[Cast_Account],[IsDigitalService],[IsGoods],[IsServices],[SACCode],[HSNCode],[IsTaxable],          
   [DecimalRateItemQuantity],[UnitID],IsSaleable'+case when @customfieldlist is null then '' else ', '+@customfieldlist  end +',ThumbnailUrl)           
   values                        
      (''' + @ProductName + ''',' + cast(@ParentID AS VARCHAR) + ',''' + '' + ''',''' + @Description + ''',' + cast(@SalesPrice AS VARCHAR) + ',' + cast(@IsPublished AS VARCHAR) + ',' + cast(@IsActive AS VARCHAR) + '
	  , ''' + cast(getdate() AS VARCHAR) + ''',' + cast(@UserID AS VARCHAR) + ',''' + '' + ''',' + cast(@IsFeatured AS VARCHAR) + ',''' + @sku + ''',' + cast(@DecimalRateQuantity AS VARCHAR) + ',' + cast(@categoryid AS VARCHAR) + '
	  , ''' + @HomeStateTaxIDs + ''',''' + @OtherTaxIDs + ''' ,''' + cast(getdate() AS VARCHAR) +''' ,null,' + cast(@SalesAccount AS VARCHAR) + ',' + cast(@CastPrice AS VARCHAR) + ',' + cast(@CastAccount AS VARCHAR) + '                        
        , ' + cast(@IsDigitalService AS VARCHAR) + ',' + cast(@IsGoods AS VARCHAR) + '                        
        , ' + cast(@IsServices AS VARCHAR) + '                        
        , ''' + @SACCode + '''                        
        , ''' + @HSNCode + '''                        
        , ' + cast(@IsTaxable AS VARCHAR) + '                        
        , ' + cast(@DecimalRateQuantity AS VARCHAR) + '          
        , ' + cast(@UnitID AS VARCHAR) + '                   
		, ' + cast(@IsSaleable AS VARCHAR) + ' 
		 '+case when @customfieldvalue is null then '' else ', '+@customfieldvalue end +'
		, '''+@ThumbnailUrl+'''
    );          
    select @ProductID=SCOPE_IDENTITY()'    
    
	--Select @sqls,@customfieldlist          
	-- print @sqls          
    --exec (@sqls)          
  EXECUTE sp_executesql @sqls ,N'@ProductID BIGINT OUTPUT',@ProductID OUTPUT    
    
      
    
    --select @ProductID          
    SELECT @Count = Count(1)    
    FROM @ProductFileURL_Type_TBL    
    
    IF (@Count > 0)    
    BEGIN    
     DECLARE @ImagePart NVARCHAR(100) = ''    
     DECLARE @FullPath NVARCHAR(max) = ''    
    
     SELECT @FullPath = FileURL    
     FROM @ProductFileURL_Type_TBL    
     WHERE ID = 1    
    
     DECLARE @index INT = 0    
    
     SELECT @index = charindex('ProductImages', @FullPath)    
    
     IF (@index <> 0)    
     BEGIN    
      SELECT @ImagePart = SUBSTRING(@FullPath, @index, len(@FullPath) - @index + 1)    
    
      SET @sqls = '  update ' + @tableName + ' set Image = ''' + @ImagePart + ''' ,FullPath = ''' + @FullPath + ''' where ProductID = ' + cast(@ProductID AS VARCHAR) + ''    
    
		print @sqls
      EXECUTE sp_executesql @sqls    
     END    
    
     INSERT INTO ProductImageMapping (    
      ProductID    
      ,ImageURL    
      ,CreatedDate    
      )    
     SELECT @ProductID    
      ,FileUrl    
      ,getdate()    
     FROM @ProductFileURL_Type_TBL    
    END    
    
    IF (rtrim(ltrim(@ProductTagsIDs)) <> '')    
    BEGIN    
     INSERT INTO EntityTagMapping (    
      EntityID    
      ,Entity    
      ,CreatedDate    
      ,TagID    
      )    
     SELECT @ProductID    
      ,'Product'    
      ,getdate()    
      ,cast(value AS BIGINT)    
     FROM fn_Split(@ProductTagsIDs, '#')    
    END    
    
    SELECT 'Data Saved Successfully' AS MSG    
     ,'Success' AS STATUS    
    
    SET @sqls = ' select *,                    
   MySMSInvoicing.dbo.udf_inv_GetTaxJsonByProductIds(HomeTaxIDs) as [HomeTaxJson],                    
   MySMSInvoicing.dbo.udf_inv_GetTaxJsonByProductIds(OtherTaxIDs) as [OtherTaxJson]                    
  from (                    
  select top 10                    
   ProductID as Id,                    
   Name,                     
   FullPath as [Image],                     
   Description,       
   CostPrice as [PurchasePrice],                     
   Price as SalePrice,                    
   HomeTaxIDs,                    
   OtherTaxIDs,                
   sku,'''' as [ItemJSON]                
    from ' + @tablename + '(nolock) where ProductID = ' + cast(@ProductID AS VARCHAR) + '                    
     order by Name asc                    
   ) products'    
    
    EXECUTE sp_executesql @sqls    
   END    
   ELSE    
   BEGIN    
    SELECT 'Product Name Already Exists' AS MSG    
  ,'Faillure' AS STATUS    
    
    SELECT 'IMP'    
    WHERE 1 = 0    
   END    
  END    
  ELSE    
  BEGIN    
   SELECT 'Shop Keeping Unit Already Exists' AS MSG    
    ,'Faillure' AS STATUS    
    
   SELECT 'IMP'    
   WHERE 1 = 0    
  END    
 END    
    
 DECLARE @rowJson NVARCHAR(MAX) = 'Select @rowJson =(SELECT * FROM ' + @tableName + ' WHERE ProductId=' + cast(@ProductID AS VARCHAR) + '    
    FOR JSON AUTO , INCLUDE_NULL_VALUES)'    
    
 --PRINT @rowJson    
    
 EXECUTE sp_executesql @rowJson    
  ,N'@rowJson Varchar(max) OUTPUT'    
  ,@rowJson OUTPUT    
    
 IF @rowJson IS NOT NULL    
 BEGIN    
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @parentid = @ParentID    
   ,@Activity_type = 'Inst_Prdct'    
   ,@ActionType = 'I'    
   ,@RowJson = @rowJson    
   ,@Table_name = @tableName    
 END    
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveProductDetailsWithChanges_NEW_Bulk]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveProductDetailsWithChanges_NEW_Bulk              
(                  
@ProductImport_TBL  ProductImport readonly
)              
as              
Begin              
drop table if exists #productimport_tbl
select *,0 as importstatus,cast(null as nvarchar(100)) as reason into #productimport_tbl from @ProductImport_TBL

declare @IsGoods bit,               
  @IsServices bit,              
  @IsDigitalService bit,              
  @ProductName nvarchar(100),              
  @SKU nvarchar(50),              
  @Unit nvarchar(50),              
  @HSNCode nvarchar(50),              
  @SACCode nvarchar(50),              
  @IsTaxable bit,              
  @HomeStateTax nvarchar(max),              
  @OtherTax nvarchar(max),              
  @SalesPrice numeric(18,2),              
  @SalesAccount bigint=13,              
  @CastPrice numeric(18,2),              
  @CastAccount bigint=115,              
  @DecimalRateQuantity int,              
  @Description nvarchar(200),              
  @ProductTags nvarchar(max),              
  @Category nvarchar(200),              
  @IsPublished bit,              
  @IsFeatured bit,              
  @IsActive bit,              
  @UserID bigint,        
  @IsSaleable bit,@unitid int,@hometaxids nvarchar(max),@othertaxids nvarchar(max),@categoryid bigint              

 Declare @ParentID bigint = 0,@c int,@imported int,@id int=0;              
 Declare @ProductID bigint = 0;              

 select @c=count(1) from #ProductImport_TBL

 while @c>0
 begin
 select @id=min(id) from #ProductImport_TBL where id>@id
 select @IsGoods=IsGoods,               
  @IsServices=IsServices,              
  @IsDigitalService=IsDigitalService,
  @ProductName=ProductName,
  @SKU=SKU,
  @Unit=Unit,
  @HSNCode=HSNCode,
  @SACCode=SACCode,
  @IsTaxable=IsTaxable,
  @HomeStateTax=HomeStateTax,
  @OtherTax=OtherTax,
  @SalesPrice=SalesPrice,
  @CastPrice=CastPrice,
  @DecimalRateQuantity=DecimalRateQuantity,
  @Description=Description,
  @ProductTags=ProductTags,
  @Category=Category,
  @IsPublished=IsPublished,
  @IsFeatured=IsFeatured,
  @IsActive=IsActive,
  @UserID=UserID,
  @IsSaleable=IsSaleable from @ProductImport_TBL where id=@id
 

 Select top 1 @ParentID = isnull(ParentID,User_ID) from User_Detail(nolock) where User_ID = @UserID              
 
   select @productname,@id             
  if(not exists (select 1 from ProductMaster(nolock) where sku = @SKU))              
  Begin              
  if(not exists(select 1 from ProductMaster(nolock) where UserID = @ParentID and Name = @ProductName))               
   Begin             
   
   if exists( select 1 from [Product_Category](nolock)  where CategoryName =@Category and (parentid =0 or parentid=  @ParentID))
  begin
  select top 1 @categoryid= id from [Product_Category](nolock)  where CategoryName =@Category and (parentid =0 or parentid=  @ParentID)
  order by parentid desc
  end
  else
  begin
  insert into [Product_Category](CategoryName,description,parentid,createdby,CreatedDate,ispredefined,IsDeleted)    
  values(@Category,null,@ParentID,@UserID,getdate(),0,0)    
  select @categoryid=scope_identity()
  end

   
  if exists( select 1 from unit(nolock)  where unitname =@Unit and (parentid =0 or parentid=  @ParentID))
  begin
  select top 1 @unitid= id from unit(nolock)  where unitname =@Unit and (parentid =0 or parentid=  @ParentID)
  order by parentid desc
  end
  else
  begin
  insert into unit(unitname,unitdisplay,description,parentid,createdby,createdon)    
  values(@Unit,left(@Unit,3),null,@ParentID,@UserID,getdate())    
  select @unitid=scope_identity()
  end

  if @istaxable=1
  begin
  select @hometaxids=coalesce(@hometaxids+',','')+cast(isnull(taxid,'') as nvarchar) from
  (select t.id as taxid from MySMSInvoicing.dbo.taxes(nolock) t            
  where parentid = @parentid  and is_deleted = 0  and enabled = 1 and isnull(name,'') in
  (select value from dbo.fn_split(isnull(nullif(@HomeStateTax,''),''),','))) t

   select @othertaxids=coalesce(@hometaxids+',','')+cast(isnull(taxid,'') as nvarchar) from
  (select t.id as taxid from MySMSInvoicing.dbo.taxes(nolock) t            
  where parentid = @parentid  and is_deleted = 0  and enabled = 1 and isnull(name,'') in
  (select value from dbo.fn_split(isnull(nullif(@OtherTax,''),''),','))) t
   
 end                
  insert into ProductMaster              
  (              
     [Name]              
      ,[UserID]              
      ,[Image]              
      ,[Description]              
      ,[Price]              
      ,[IsPublished]              
      ,[IsActive]              
      ,[CreatedOn]              
      ,[CreatedBy]              
      ,[FullPath]              
      ,[IsFeatured]              
      ,[sku]              
      ,[quantity]              
      ,[category_id]              
      ,[HomeTaxIDs]              
      ,[OtherTaxIDs]              
      ,[UpdatedAt]              
      ,[DeletedAt]              
      ,[SellingAccount]              
      ,[Cast_Price]              
      ,[Cast_Account]              
      ,[IsDigitalService]              
      ,[IsGoods]              
      ,[IsServices]              
      ,[SACCode]              
      ,[HSNCode]              
      ,[IsTaxable]              
      ,[DecimalRateItemQuantity]              
      ,[UnitID]        
   ,IsSaleable              
     )              
  values              
    (              
    @ProductName              
      ,@UserID              
      ,''              
      ,@Description              
      ,@SalesPrice              
      ,@IsPublished              
      ,@IsActive              
      ,getdate()              
      ,@UserID              
      ,''              
      ,@IsFeatured              
      ,@sku              
      ,@DecimalRateQuantity              
      ,@categoryid              
      ,@HomeTaxIDs              
      ,@OtherTaxIDs              
      ,getdate()              
      ,null              
      ,@SalesAccount              
      ,@CastPrice              
      ,@CastAccount              
      ,@IsDigitalService              
      ,@IsGoods              
      ,@IsServices              
      ,@SACCode              
      ,@HSNCode              
      ,@IsTaxable              
      ,@DecimalRateQuantity              
      ,@UnitID         
   ,@IsSaleable             
  )              
                     
   select @ProductID = SCOPE_IDENTITY()              
                      
  -- declare @Count int = 0;              
  --select @Count = Count(1) from @ProductFileURL_Type_TBL               
  --if(@Count > 0)              
  --  Begin              
  --     Declare @ImagePart nvarchar(100) = ''               
  --  Declare @FullPath nvarchar(max) = ''              
  --    Select @FullPath = FileURL From @ProductFileURL_Type_TBL where ID = 1                
              
  --   Declare @index int = 0              
  --            select @index = charindex('ProductImages',@FullPath)              
  --   if(@index <> 0)              
  --    Begin              
  --                select @ImagePart = SUBSTRING(@FullPath,@index,len(@FullPath)- @index + 1)               
  --       update ProductMaster set Image = @ImagePart ,FullPath = @FullPath where ProductID = @ProductID               
  --              end              
               
  --         insert into ProductImageMapping              
  --    (ProductID,ImageURL,CreatedDate)              
  --    select @ProductID,FileUrl,getdate() from @ProductFileURL_Type_TBL               
              
  --   End              
                
    if(rtrim(ltrim(isnull(@ProductTags,''))) <> '')              
      Begin              
	  drop table if exists #ptags
	  select value as tags,0 as tagid,0 as isactive into #ptags from dbo.fn_Split(@ProductTags,'#')             
	 
	 insert into TagMaster(ParentID,Tag,CreatedBy,CreatedDate,IsActive)
	 select @parentid,tags,@userid,getdate(),1 from #ptags p where not exists 
	 (select 1 from TagMaster(nolock) where parentid=@parentid and Tag=p.tags)

	  update p set tagid=id,isactive=t.IsActive from #ptags p join tagmaster t on p.tags=t.Tag
	   where ParentID=@ParentID

     insert into EntityTagMapping              
    (EntityID,Entity,CreatedDate,TagID)              
    select @ProductID,'Product',getdate(),tagid from #ptags where isactive=1
	   
     End                 
   
   update #productimport_tbl set importstatus=1 where id=@id
             
  --  select *,           
  -- MySMSInvoicing.dbo.udf_inv_GetTaxJsonByProductIds(HomeTaxIDs) as [HomeTaxJson],          
  -- MySMSInvoicing.dbo.udf_inv_GetTaxJsonByProductIds(OtherTaxIDs) as [OtherTaxJson]          
  --from (          
  --select top 10          
  -- ProductID as Id,          
  -- Name,           
  -- FullPath as [Image],           
  -- Description,           
  -- Cast_Price as [PurchasePrice],           
  -- Price as SalePrice,          
  -- HomeTaxIDs,          
  -- OtherTaxIDs,      
  -- sku      
  --  from ProductMaster(nolock) where ProductID = @ProductID          
  --   order by Name asc          
  -- ) products           
            
             
   End              
  else              
    Begin      
	update #productimport_tbl set importstatus=0,reason='Product Name Already Exists'  where id=@id        
             
 End                    
     End                  
  else              
    Begin              
	update #productimport_tbl set importstatus=0,reason='Stock Keeping Unit (SKU) Already Exists'  where id=@id        
                  
    End              
set @c=@c-1                  
end 

select * from #productimport_tbl             
drop table if exists #productimport_tbl
End 


--select * from unit


GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveProductDetailsWithChanges_NEW_ProductTags]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_SaveProductDetailsWithChanges_NEW_ProductTags]     
	(    
	 @IsGoods BIT    
	 ,@IsServices BIT    
	 ,@IsDigitalService BIT    
	 ,@ProductName NVARCHAR(100)    
	 ,@SKU NVARCHAR(50)    
	 ,@UnitID INT    
	 ,@HSNCode NVARCHAR(50)    
	 ,@SACCode NVARCHAR(50)    
	 ,@IsTaxable BIT    
	 ,@HomeStateTaxIDs NVARCHAR(max)    
	 ,@OtherTaxIDs NVARCHAR(max)    
	 ,@SalesPrice NUMERIC(18, 2)    
	 ,@SalesAccount BIGINT    
	 ,@CastPrice NUMERIC(18, 2)    
	 ,@CastAccount BIGINT    
	 ,@DecimalRateQuantity INT    
	 ,@Description NVARCHAR(200)    
	 ,@ProductTagsIDs NVARCHAR(max) -- now with name included    
	 ,@CategoryID INT    
	 ,@IsPublished BIT    
	 ,@IsFeatured BIT    
	 ,@IsActive BIT    
	 ,@ProductFileURL_Type_TBL ProductFileURL_Type readonly    
	 ,@UserID BIGINT    
	 ,@IsSaleable BIT    
	 ,@CustomFieldValueJson NVARCHAR(max) 
	 ,@ThumbnailUrl nvarchar(1000)
	 ,@VariantsJson Nvarchar(MAX)
	  ,@VCombinationJson Nvarchar(MAX)
	 )    
	AS    
	BEGIN    
	 DECLARE @ParentID BIGINT = 0;    
	 DECLARE @ProductID BIGINT = 0    
	 DECLARE @Count INT = 0    
	  ,@check INT = 0    
	  ,@check2 INT = 0    
    
	 SELECT TOP 1 @ParentID = isnull(ParentID, User_ID)    
	 FROM User_Detail(NOLOCK)    
	 WHERE User_ID = @UserID    
    
	 DECLARE @sqls NVARCHAR(max) = ''    
	  ,@status INT    
	  ,@tableName NVARCHAR(max) = ''    
	 DECLARE @min INT    
	  ,@max INT    
	  ,@fieldName VARCHAR(200)    
	  ,@value NVARCHAR(max)    
	   ,@customfieldlist nvarchar(max)
	   ,@customfieldvalue nvarchar(max) 
	 DROP TABLE    
    
	 IF EXISTS #temp    
	  DROP TABLE    
    
	 IF EXISTS #temp2    
	  CREATE TABLE #temp (    
	   id INT identity(1, 1)    
	   ,lbltxt NVARCHAR(max)    
	   ,value NVARCHAR(Max)    
	   )    
    
	 SELECT @customfieldlist= string_agg(lbltxt,',')  
		 ,@customfieldvalue= string_agg( case  when value is  NULL then 'NULL'
								else ''''+value+''''  end  ,' ,')
		FROM OPENJSON(@CustomFieldValueJson) WITH (  
		  lbltxt NVARCHAR(max) '$.lbltxt'  
		  ,value NVARCHAR(Max) '$.value '  
		  )  
	 EXEC @status = Usp_CreateProductTableByParentID @userid    
	  ,@tableName OUTPUT    
   
	   print @tableName
   
	   print concat('table  status is--',@status)
	 IF (@status = 1)    
	 BEGIN  
	 print concat('Out put table name is :--',@tableName)
	  SET @sqls = 'select @check=1 from ' + @tablename + '(nolock) where sku = ''' + @SKU + ''''    
    
	  --print @sqls          
	  EXECUTE sp_executesql @sqls    
	   ,N'@check int out'    
	   ,@check OUT    
    
	  SET @sqls = 'select @check2=1 from ' + @tablename + '(nolock) where UserID = ' + cast(@UserID AS VARCHAR) + ' and Name = ''' + @ProductName + ''''    
    
	  --print @sqls          
	  EXECUTE sp_executesql @sqls    
	   ,N'@check2 int out'    
	   ,@check2 OUT    
    
	  IF @check = 0    
	  BEGIN    
	   IF @check2 = 0    
	   BEGIN 
	   print '2'
		SET @sqls = 'insert into ' + @tablename + ' ([Name],[UserID],[Image],[Description],[Price],[IsPublished],[IsActive]
		,[CreatedOn],[CreatedBy],[FullPath],[IsFeatured],[sku],[quantity],[category_id]          
	   ,[HomeTaxIDs],[OtherTaxIDs],[UpdatedAt],[DeletedAt],[SellingAccount],[CostPrice],[Cast_Account],[IsDigitalService],[IsGoods],[IsServices],[SACCode],[HSNCode],[IsTaxable],          
	   [DecimalRateItemQuantity],[UnitID],IsSaleable'+case when @customfieldlist is null or @customfieldlist='' then '' else ', '+@customfieldlist  end +',ThumbnailUrl,VariantsJson,VCombinationJson)           
	   values                        
		  (''' + @ProductName + ''',' + cast(@ParentID AS VARCHAR) + ',null,N''' + cast(@Description as nvarchar) + ''',' + cast(@SalesPrice AS VARCHAR) + ',' + cast(@IsPublished AS VARCHAR) + ',' + cast(@IsActive AS VARCHAR) + '
		  , ''' + cast(getdate() AS VARCHAR) + ''',' + cast(@UserID AS VARCHAR) + ',null,' + cast(@IsFeatured AS VARCHAR) + ',''' + @sku + ''',' + cast(@DecimalRateQuantity AS VARCHAR) + ',' + cast(@categoryid AS VARCHAR) + '
		  , ''' + @HomeStateTaxIDs + ''',''' + @OtherTaxIDs + ''' ,''' + cast(getdate() AS VARCHAR) +''' ,null,' + cast(@SalesAccount AS VARCHAR) + ',' + cast(@CastPrice AS VARCHAR) + ',' + cast(@CastAccount AS VARCHAR) + '                        
			, ' + cast(@IsDigitalService AS VARCHAR) + ',' + cast(@IsGoods AS VARCHAR) + '                        
			, ' + cast(@IsServices AS VARCHAR) + '                        
			, ''' + @SACCode + '''                        
			, ''' + @HSNCode + '''                        
			, ' + cast(@IsTaxable AS VARCHAR) + '                        
			, ' + cast(@DecimalRateQuantity AS VARCHAR) + '          
			, ' + cast(@UnitID AS VARCHAR) + '                   
			, ' + cast(@IsSaleable AS VARCHAR) + ' 
			 '+case when @customfieldlist is null or @customfieldlist='' then ''
			else  case when @customfieldvalue is null or @customfieldvalue='' then ''  else ', '+@customfieldvalue end end+'
			, '''+@ThumbnailUrl+'''
			,''' + @VariantsJson + '''  
			,''' + @VCombinationJson + ''' 
		);          
		select @ProductID=SCOPE_IDENTITY()'    
    
		print concat('Custom field list---',@customfieldlist)
		print concat('Custom field---',@customfieldvalue)
		print concat('Primary column id as---',@ProductID)
		--Select @sqls,@customfieldlist          
		-- print @sqls          
		--exec (@sqls)          
	  EXECUTE sp_executesql @sqls ,N'@ProductID BIGINT OUTPUT',@ProductID OUTPUT    
    
      
    
		--select @ProductID          
		SELECT @Count = Count(1)    
		FROM @ProductFileURL_Type_TBL    
    
		IF (@Count > 0)    
		BEGIN    
		 DECLARE @ImagePart NVARCHAR(100) = ''    
		 DECLARE @FullPath NVARCHAR(max) = ''    
    
		 SELECT @FullPath = FileURL    
		 FROM @ProductFileURL_Type_TBL    
		 WHERE ID = 0    
    
		 DECLARE @index INT = 0    
    
		 SELECT @index = charindex('ProductImages', @FullPath)    
    
		 IF (@index <> 0)    
		 BEGIN    
		  SELECT @ImagePart = SUBSTRING(@FullPath, @index, len(@FullPath) - @index + 1)    
    
		  SET @sqls = '  update ' + @tableName + ' set Image = ''' + @ImagePart + ''' ,FullPath = ''' + @FullPath + ''' where ProductID = ' + cast(@ProductID AS VARCHAR) + ''    
    
			print @sqls
		  EXECUTE sp_executesql @sqls    
		 END    
    
		 INSERT INTO ProductImageMapping (    
		  ProductID    
		  ,ImageURL    
		  ,CreatedDate
		  ,ParentID
		  )    
		 SELECT @ProductID    
		  ,FileUrl    
		  ,getdate()
		  ,@ParentID
		 FROM @ProductFileURL_Type_TBL    
		END    
    
	   IF(rtrim(ltrim(ISNULL(@ProductTagsIDs, ''))) <> '')            
		BEGIN            
		   DROP TABLE IF EXISTS #tempTagName;            
   
		  SELECT [tn].*            
		 ,[tm].[ID] AS [tagId]            
		 ,0 AS [isProcess]            
		INTO [#tempTagName]            
		FROM (            
		 SELECT [position] AS [id]            
		  ,LTRIM(RTRIM(IIF(CHARINDEX(':', [value], 1) = 0, [value], SUBSTRING([value], 1, CHARINDEX(':', [value], 1) - 1)))) AS [tagName]            
		 FROM fn_Split(@ProductTagsIDs, ',')            
		 ) AS tn            
		LEFT JOIN TagMaster(NOLOCK) AS tm ON tm.ParentID = @ParentID            
		 AND LOWER(tm.Tag) = LOWER(tagName);            
            
	   WHILE (            
		 EXISTS (            
		  SELECT *            
		  FROM #tempTagName            
		  WHERE [isProcess] = 0            
		  )            
		 )            
	   BEGIN            
		DECLARE @tId INT            
		 ,@tTagName NVARCHAR(255)            
		 ,@tagId BIGINT;            
            
		SELECT TOP 1 @tId = [id]            
		 ,@tTagName = [tagName]            
		 ,@tagId = [tagId]            
	   FROM #tempTagName            
		WHERE [isProcess] = 0;            
            
		PRINT @tTagName;            
            
		IF (@tagId IS NULL)            
		BEGIN            
		 INSERT INTO TagMaster (            
		  [Tag]            
		  ,[ParentID]            
		  ,[CreatedDate]            
		  ,[CreatedBy]            
		  )            
		 VALUES (            
		  @tTagName            
		  ,@ParentID            
		  ,GETDATE()            
		  ,@UserID            
		  );            
            
		 DECLARE @sId BIGINT = SCOPE_IDENTITY();            
            
		 UPDATE #tempTagName            
		 SET [tagId] = @sId            
		 WHERE [id] = @tId;            
		END;            
            
		UPDATE #tempTagName            
		SET [isProcess] = 1            
		WHERE [id] = @tId;            
	   END;            

	   DELETE EntityTagMapping            
	   WHERE [EntityID] = @ProductID and TM_ParentID = @ParentID             
		AND LOWER([Entity]) = 'Product';            
            
	   INSERT INTO EntityTagMapping (            
		[EntityID]            
		,[Entity]            
		,[TagID]            
		,[CreatedDate] 
		,TM_ParentID
		)            
	   SELECT @ProductID            
		,'Product'            
		,[tagId]            
		,GETDATE()
		,@ParentID
	   FROM #tempTagName;            
	  END;
  
		  drop table if exists #tempTagName 
    

		/*
		IF (rtrim(ltrim(@ProductTagsIDs)) <> '')    
		BEGIN    
		 INSERT INTO EntityTagMapping (    
		  EntityID    
		  ,Entity    
		  ,CreatedDate    
		  ,TagID    
		  )    
		 SELECT @ProductID    
		  ,'Product'    
		  ,getdate()    
		  ,cast(value AS BIGINT)    
		 FROM fn_Split(@ProductTagsIDs, '#')    
		END    
		*/



		SELECT 'Data Saved Successfully' AS MSG    
		 ,'Success' AS STATUS    
    
	

		SET @sqls = ' select *,                    
	   MySMSInvoicing.dbo.udf_inv_GetTaxJsonByProductIds(HomeTaxIDs) as [HomeTaxJson],                    
	   MySMSInvoicing.dbo.udf_inv_GetTaxJsonByProductIds(OtherTaxIDs) as [OtherTaxJson]                    
	  from (                    
	  select top 10                    
	   ProductID as Id,                    
	   Name,                     
	   FullPath as [Image],                     
	   Description,       
	   CostPrice as [PurchasePrice],                     
	   Price as SalePrice,                    
	   HomeTaxIDs,                    
	   OtherTaxIDs, 
	   VariantsJson,VCombinationJson,
	   sku,'''' as [ItemJSON] , '''' as [ProjectJSON]                 
		from ' + @tablename + '(nolock) where ProductID = ' + cast(@ProductID AS VARCHAR) + '                    
		 order by Name asc                    
	   ) products'    
    
		EXECUTE sp_executesql @sqls    
	   END    
	   ELSE    
	   BEGIN 
	   print '3'
		SELECT 'Product Name Already Exists' AS MSG    
	  ,'Faillure' AS STATUS    
    
		SELECT 'IMP'    
		WHERE 1 = 0    
	   END    
	  END    
	  ELSE    
	  BEGIN    
	   SELECT 'Shop Keeping Unit Already Exists' AS MSG    
		,'Faillure' AS STATUS    
    
	   SELECT 'IMP'    
	   WHERE 1 = 0    
	  END    
	 END    
    
	 DECLARE @rowJson NVARCHAR(MAX) = 'Select @rowJson =(SELECT * FROM ' + @tableName + ' WHERE ProductId=' + cast(@ProductID AS VARCHAR) + '    
		FOR JSON AUTO , INCLUDE_NULL_VALUES)'    
    
	 --PRINT @rowJson    
    
	 EXECUTE sp_executesql @rowJson    
	  ,N'@rowJson Varchar(max) OUTPUT'    
	  ,@rowJson OUTPUT    
    
	 IF @rowJson IS NOT NULL    
	 BEGIN    
	  EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @parentid = @ParentID    
	   ,@Activity_type = 'Inst_Prdct'    
	   ,@ActionType = 'I'    
	   ,@RowJson = @rowJson    
	   ,@Table_name = @tableName    
	 END    
	END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveQueryString]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




CREATE   PROCEDURE dbo.Usp_SaveQueryString    
(    
   @FormID bigint    
  ,@TotalControlsRows int    
  ,@QueryString nvarchar(200)    
  ,@Mapping nvarchar(200)    
  ,@MatchQuerySTR nvarchar(200)    
  ,@LeadFields nvarchar(200)    
  ,@WebFormFields nvarchar(200)    
  ,@ReadOnlyStatus bit    
    
)    
as    
Begin    
       
   Declare @tblRowCount int = 0    
   Declare @tblValueRowCount int = 0    
    
   if(not exists(select 1 from QuerySTR_tbl where FormID = @FormID))    
      begin    
       insert into QuerySTR_tbl    
    (    
     FormID    
    ,TotalControlsRows    
    ,QueryString    
    ,Mapping    
    ,MatchQuerySTR    
    ,LeadFields    
    ,WebFormFields    
    ,ReadOnlyStatus    
    ,CreatedDate    
    )    
    values    
    (    
     @FormID    
    ,@TotalControlsRows    
    ,@QueryString    
    ,@Mapping    
    ,@MatchQuerySTR    
    ,@LeadFields    
    ,@WebFormFields    
    ,@ReadOnlyStatus    
    ,GETDATE()    
        
    )    
         
   end    
   else    
     Begin    
    
    select @tblRowCount = Count(*)   from QuerySTR_tbl where FormID = @FormID    
    select @tblValueRowCount = isnull(TotalControlsRows,0)  from QuerySTR_tbl where FormID = @FormID    
    if((@tblRowCount < @tblValueRowCount) and (@tblValueRowCount = @TotalControlsRows ))    
       Begin    
    
    insert into QuerySTR_tbl    
    (    
     FormID    
    ,TotalControlsRows    
    ,QueryString    
    ,Mapping    
    ,MatchQuerySTR    
    ,LeadFields    
    ,WebFormFields    
    ,ReadOnlyStatus    
    ,CreatedDate    
    )    
    values    
    (    
     @FormID    
    ,@TotalControlsRows    
    ,@QueryString    
    ,@Mapping    
    ,@MatchQuerySTR    
    ,@LeadFields    
    ,@WebFormFields    
    ,@ReadOnlyStatus    
    ,GETDATE()    
        
    )    
    
    End    
    
   else    
      Begin    
   delete from QuerySTR_tbl where FormID = @FormID   
            insert into QuerySTR_tbl    
    (    
     FormID    
    ,TotalControlsRows    
    ,QueryString    
    ,Mapping    
    ,MatchQuerySTR    
    ,LeadFields    
    ,WebFormFields    
    ,ReadOnlyStatus    
    ,CreatedDate    
    )    
    values    
    (    
     @FormID    
    ,@TotalControlsRows    
    ,@QueryString    
    ,@Mapping    
    ,@MatchQuerySTR    
    ,@LeadFields    
    ,@WebFormFields    
    ,@ReadOnlyStatus    
    ,GETDATE()    
        
    )    
      End     
    
    
  End    
    
  select 'Success'  
  
  
  End





GO

