CREATE   PROCEDURE [dbo].[Usp_SaveRawMobileUserEngagement]
(
     @UserID bigint,
	 @Metadata nvarchar(max)
)
as
begin
     begin try

     insert into RawMobileUserEngagement
	  (
	      UserID
         ,MetaData
         ,CreatedDate
	  )
	  select @UserID,@Metadata,getdate();


	    Declare @ScreenName varchar(1000), @ScreenTime Float =0, @FromDate datetime, @ToDate datetime

		SELECT 
			@ScreenName = JSON_VALUE([value], '$.ScreenName') ,
			@ScreenTime =  JSON_VALUE([value], '$.ScreenTime') ,
			@FromDate =	JSON_VALUE([value], '$.FromDate') ,
			@ToDate = JSON_VALUE([value], '$.ToDate') 
		FROM OPENJSON(@metadata);

 
		exec [usp_SaveUserEngagementTrack_Extra]  @UserID, @ScreenName, @ScreenTime, 0, '', '', 'mobile';


	  select 'Data Saved' as MSG 

	  end try
	  begin catch
	      exec usp_InsertErrorInfo
	  end catch

end



