CREATE   PROC usp_SaveResponsiveAdDisplay
(
    @tblAds_Rad_Id int=0,
    @AdwordAdsId bigint=0,
    @Ref_AdsId int=0,
    @User_Id int,
    @CampaignId bigint,
    @AdwordGroupId varchar(50),
    @Status bit,
    @FinalUrl varchar(max),
    @ShortHeadline1 nvarchar(100),
    @ShortHeadline2 nvarchar(100)=NULL,
    @ShortHeadline3 nvarchar(100)=NULL,
    @ShortHeadline4 nvarchar(100)=NULL,
    @ShortHeadline5 nvarchar(100)=NULL,
    @LongHeadline nvarchar(200),
    @Description1 nvarchar(100),
    @Description2 nvarchar(100)=NULL,
    @Description3 nvarchar(100)=NULL,
    @Description4 nvarchar(100)=NULL,
    @Description5 nvarchar(100)=NULL,
    @BusinessName nvarchar(200),
    @MarketingImage1_AssetId bigint,
    @MarketingImage2_AssetId bigint=NULL,
    @MarketingImage3_AssetId bigint=NULL,
    @MarketingImage4_AssetId bigint=NULL,
    @MarketingImage5_AssetId bigint=NULL,
    @MarketingSquareImage1_AssetId bigint,
    @MarketingSquareImage2_AssetId bigint=NULL,
    @MarketingSquareImage3_AssetId bigint=NULL,
    @MarketingSquareImage4_AssetId bigint=NULL,
    @MarketingSquareImage5_AssetId bigint=NULL,
    @LogoImage1_AssetId bigint=NULL,
    @LogoImage2_AssetId bigint=NULL,
    @LogoImage3_AssetId bigint=NULL,
    @LogoImage4_AssetId bigint=NULL,
    @LogoImage5_AssetId bigint=NULL 
)
AS
BEGIN

    declare @AdsId int=0, @InProcess bit=0
    if(LEN(@campaignid)>8 and LEN(@AdwordAdsId)>8 and LEN(@AdwordGroupId)>8)
    begin
	    set @InProcess=1
    end
    
    If(@tblAds_Rad_Id = 0)
    Begin
	   INSERT INTO [dbo].[tblAds]
			    ([AdwordAdsId],[User_Id],[CampaignId],[AdwordGroupId],[Status],[InProcess],[CampaignSubType])
		   VALUES
			    (@AdwordAdsId,@User_Id,@CampaignId,@AdwordGroupId,@Status,@InProcess,'RAD')
	   SELECT @AdsId = isnull(SCOPE_IDENTITY(),0)
	    
	   INSERT INTO [dbo].[tblAds_ResponsiveAdForDisplay] 
	   ([Ref_AdsId], [FinalUrl], [ShortHeadline1], [ShortHeadline2], [ShortHeadline3], [ShortHeadline4], [ShortHeadline5], [LongHeadline], [Description1], [Description2], [Description3], [Description4], [Description5], [BusinessName], [MarketingImage1_AssetId], [MarketingImage2_AssetId], [MarketingImage3_AssetId], [MarketingImage4_AssetId], [MarketingImage5_AssetId], [MarketingSquareImage1_AssetId], [MarketingSquareImage2_AssetId], [MarketingSquareImage3_AssetId], [MarketingSquareImage4_AssetId], [MarketingSquareImage5_AssetId], [LogoImage1_AssetId], [LogoImage2_AssetId], [LogoImage3_AssetId], [LogoImage4_AssetId], [LogoImage5_AssetId])
	   VALUES 
	   (@AdsId, @FinalUrl, @ShortHeadline1, @ShortHeadline2, @ShortHeadline3, @ShortHeadline4, @ShortHeadline5, @LongHeadline, @Description1,
	    @Description2, @Description3, @Description4, @Description5, @BusinessName, @MarketingImage1_AssetId, @MarketingImage2_AssetId, 
	    @MarketingImage3_AssetId, @MarketingImage4_AssetId, @MarketingImage5_AssetId, @MarketingSquareImage1_AssetId, @MarketingSquareImage2_AssetId,
	    @MarketingSquareImage3_AssetId, @MarketingSquareImage4_AssetId, @MarketingSquareImage5_AssetId, @LogoImage1_AssetId, @LogoImage2_AssetId,
	    @LogoImage3_AssetId, @LogoImage4_AssetId, @LogoImage5_AssetId
	   )

	   Select isnull(@AdsId,0)
    End
    Else
    Begin

	   UPDATE [dbo].[tblAds_ResponsiveAdForDisplay]
		 SET [FinalUrl] = @FinalUrl
		    ,[ShortHeadline1] = @ShortHeadline1
		    ,[ShortHeadline2] = @ShortHeadline2
		    ,[ShortHeadline3] = @ShortHeadline3
		    ,[ShortHeadline4] = @ShortHeadline4
		    ,[ShortHeadline5] = @ShortHeadline5
		    ,[LongHeadline] = @LongHeadline
		    ,[Description1] = @Description1
		    ,[Description2] = @Description2
		    ,[Description3] = @Description3
		    ,[Description4] = @Description4
		    ,[Description5] = @Description5
		    ,[BusinessName] = @BusinessName
		    ,[MarketingImage1_AssetId] = @MarketingImage1_AssetId
		    ,[MarketingImage2_AssetId] = @MarketingImage2_AssetId
		    ,[MarketingImage3_AssetId] = @MarketingImage3_AssetId
		    ,[MarketingImage4_AssetId] = @MarketingImage4_AssetId
		    ,[MarketingImage5_AssetId] = @MarketingImage5_AssetId
		    ,[MarketingSquareImage1_AssetId] = @MarketingSquareImage1_AssetId
		    ,[MarketingSquareImage2_AssetId] = @MarketingSquareImage2_AssetId
		    ,[MarketingSquareImage3_AssetId] = @MarketingSquareImage3_AssetId
		    ,[MarketingSquareImage4_AssetId] = @MarketingSquareImage4_AssetId
		    ,[MarketingSquareImage5_AssetId] = @MarketingSquareImage5_AssetId
		    ,[LogoImage1_AssetId] = @LogoImage1_AssetId
		    ,[LogoImage2_AssetId] = @LogoImage2_AssetId
		    ,[LogoImage3_AssetId] = @LogoImage3_AssetId
		    ,[LogoImage4_AssetId] = @LogoImage4_AssetId
		    ,[LogoImage5_AssetId] = @LogoImage5_AssetId
	    WHERE Ref_AdsId = @Ref_AdsId or tblAds_Rad_Id = @tblAds_Rad_Id

	    Select @@ROWCOUNT
    End
END



