/* ============================================================
   Procedure: [dbo].[usp_SaveScoreAttributes]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


---------------------------  
  
CREATE   PROCEDURE [dbo].[usp_SaveScoreAttributes]    
    @ParentId BIGINT,    
    @StageId BIGINT,    
    @ScoreOperator NVARCHAR(50),    
    @ScoreValue NVARCHAR(100),    
    @FromValue NVARCHAR(100),    
    @ToValue NVARCHAR(100),    
    @UserId BIGINT    
AS    
BEGIN    
    -- Start TRY block    
    BEGIN TRY    
        -- Check if the record already exists    
        IF NOT EXISTS (    
            SELECT 1     
            FROM tbl_ScoreAttribute (nolock)    
            WHERE     
                ParentId = @ParentId AND    
                StageId = @StageId AND    
                ScoreOperator = @ScoreOperator AND    
                ScoreValue = @ScoreValue AND    
                --FromValue = @FromValue AND    
                --ToValue = @ToValue AND    
                UserId = @UserId    
        )    
        BEGIN    
            -- If it doesn't exist, insert the new record    
            INSERT INTO tbl_ScoreAttribute (ParentId, StageId, ScoreOperator, ScoreValue, FromValue, ToValue, UserId)    
            VALUES (@ParentId, @StageId, @ScoreOperator, @ScoreValue, @FromValue, @ToValue, @UserId);    
                
            -- Prepare the JSON data (example placeholder, adjust according to actual row data)    
            DECLARE @rowJson NVARCHAR(MAX);    
            SET @rowJson = (SELECT * FROM tbl_ScoreAttribute WHERE ParentId = @ParentId AND StageId = @StageId AND ScoreOperator = @ScoreOperator AND ScoreValue = @ScoreValue FOR JSON AUTO);    
    
            -- Call the audit procedure after insertion    
            EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId     
                @User_id = @UserId,    
                @Activity_type = 'User Score Insert',    
                @ActionType = 'I',    
                @RowJson = @rowJson,    
                @Table_name = 'tbl_ScoreAttribute';    
        END    
    END TRY    
    
    -- Start CATCH block    
    BEGIN CATCH    
        -- Handle errors by logging them using the error handling procedure    
        EXEC usp_InsertErrorInfo;    
    END CATCH    
END;  
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveSearchedUserDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/**  
Created by : Santosh Kumar  
Created Date: 17/05/2017 12:21 PM   
Alter Date:  
Alter by :  
SP for Savesearched details   
**/  
CREATE   PROC dbo.[Usp_SaveSearchedUserDetails] --53  
(  
  @SearchID Bigint  
)   
as  
Begin  
  Declare @NewUser bit  
  Declare @UserName nvarchar(150)  
  Declare @Mobile numeric(18,0)  
  Declare @EmailID nvarchar(150)  
  Declare @UserType nvarchar(150)  
  Declare @UserFilter nvarchar(150)  
  Declare @LastLoginBefore bigint  
  Declare @LastPurchase bigint  
  Declare @LastLogin bigint  
    
  Select @NewUser = NewUser,@UserName = ISNULL(USERNAME,''),@Mobile = ISNULL(Mobile,0),@EmailID = ISNULL(EmailID,''),@UserType = ISNULL(UserType,''),@UserFilter= ISNULL(UserFilter,''),@LastLoginBefore= ISNULL(LastLoginBefore,0),@LastPurchase = ISNULL(LastPurchase,0),@LastLogin = ISNULL(LastLogin,0) from SavedSearch where ID=@SearchID  
  if(@NewUser = 1)  
     Begin  
       select * From funcToGetNewUserIDWise()  
     End  
   else if(@NewUser = 0)  
     Begin  
         if(@UserName <> '')  
           Begin   
             select * From funcToGetUserForGivenUserName(@UserName)   
           End    
            
          if(@Mobile <> 0)  
             Begin  
               select * From funcToGetUserForGivenMobile(@Mobile)  
             End      
             
           if(@EmailID <> '')  
              Begin  
               select * From funcToGetUserForGivenEmail(@EmailID)  
              End              
             
            if(@UserType <> '')  
                Begin  
                  select * From funcToGetUserForGivenUserType(@UserType)  
                End          
               
             if(@UserFilter <> '')  
                Begin  
                  select * From funcToGetUserForGivenUserFilter(@UserFilter)  
                End     
              if(@LastLoginBefore <> 0)  
                Begin  
                  select * From funcToGetUserLastLoginBefore(@LastLoginBefore)  
                End   
                  
              if(@LastPurchase <> 0)  
                Begin  
                  select * From funcToGetUserLastPurchased(@LastPurchase)  
                End   
                
              if(@LastLogin <> 0)  
                Begin  
                  select * From funcToGetNewUserLastLogin(@LastLogin)  
                End   
                          
     End    
       
End


GO

