    CREATE   PROCEDURE dbo.Usp_SaveSMSAPIURL  --'tempghggh'          
     (          
        @sms_url nvarchar(max)          
     )          
     as          
       begin          
   --declare @sms_url nvarchar(1000)=    
   --'https://www.kit19.com/ComposeSMS.aspx?username=Premium351665&password=29046&sender=PRMIUM&to=7663944680&message=Your%20order%20of%20376%20birds%2cweight%201034.150%20KGs.%20supplied  
   --%20%40%--20Rs.%20120996.00%20by%20vehicle%20No.%20AS14C9507on%3a10.04.  
--2025%20from%201609.Thanks%20for%20your%20support%2fPCF.%20PREMIUM%20CHICK%20FEEDS%20PVT.LTD.&priority=1&dnd=1&unicode=0&dlttemplateid=1707173201393061701'    
        
    declare @status varchar(50),@id bigint=0,@username nvarchar(250),@password nvarchar(50),@balance numeric(18,4),@user_id bigint,@unicode int=0,@smscontent nvarchar(2000),@units int,@cost numeric (18,4)    
           
    select @username=dbo.GetQueryStringValue(@sms_url,'username'),@password=dbo.GetQueryStringValue(@sms_url,'password'),@smscontent=dbo.GetQueryStringValue(@sms_url,'message')    
    if @username<>'sms19' and ( @username is null or @password is null or not exists (select 1 from user_detail(nolock) where user_login=@username and pwd=@password and status=1)    )
    begin    
    set @status='Authorization failed.'    
    end    
    else    
    begin 
    if  @username<>'sms19' 
    begin
    select top 1 @user_id=parentid from user_detail(nolock) where user_login=@username and pwd=@password and status=1 
    end
    else
    begin
    select top 1 @user_id=335
    end
    --select @balance=dbo.GetAvailableBalanceForService(@user_id,21)    
    --select top 1 @cost=PTrns from Price_Base_SMS_RateDeduction(nolock) where DestinationCountryCode='+91'-- and isnull(parentid,@user_id)=@user_id order by isnull(parentid,0) desc    
    select @balance=dbo.fn_GetSMSBalance(@user_id)    
    
    select @unicode=dbo.fn_isunicode(@smscontent)    
    select @units=case when (len(@smscontent)<=160 and @unicode =0 ) or  (len(@smscontent)<=70 and @unicode =1 ) then 1    
    when (len(@smscontent)>160 and @unicode =0 ) then cast(ceiling(len(@smscontent)/cast(157 as float)) as int)    
    else  cast(ceiling(len(@smscontent)/cast(67 as float)) as int) end    
    if @balance<@units    
    begin    
    
    select @status='Insufficient Credits.'    
    end    
    else    
    begin    
        select @status='Sent.c'    
    
    end    
    
    end    
    
       insert into sms_api_urls(sms_url,isprocessed,response,processedon)          
       select @sms_url , case when @status='Sent.c' then 0 else 1 end ,case when @status<>'Sent.c' then   @status else null end,case when @status<>'Sent.c' then  getdate() else null end    
    select @id=SCOPE_IDENTITY()    
        
    
    
       select @id ID,@status as [Status]         
    end


GO

/* ============================================================
   Procedure: [dbo].[usp_SaveSnapshot]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_SaveSnapshot]  
	@UserId nvarchar(500),  
	@JsonSetting nvarchar(max)  
AS
BEGIN


	--DECLARE
	--	@UserId nvarchar(500),  
	--	@JsonSetting nvarchar(max)  

	--declare  @UserId nvarchar(255) =N'25320',
	--@JsonSetting   nvarchar(max) =N'{"SnapshotName":"snap122","Url":"https://localhost:44321","UserId":25320,"ModuleId":"1","UserName":"","ParentBy":"335"}'

	---print @JsonSetting;

	DECLARE @SnapshotName NVARCHAR(255), @UserName NVARCHAR(255), @NewModuleId NVARCHAR(500), @ParentBy bigint,
			@parentId BIGINT, @UId BIGINT, @Id BIGINT, @Guid NVARCHAR(255);



		--activity vars
	Declare @InsertedId int =0;
	DECLARE @Act_UserName varchar(255), @PartnerUserName varchar(255) , @ChildPartnerName varchar(255);
	Declare @Eventdata varchar(max);
	---activity vars


	BEGIN TRY
		
		SELECT @parentId = ParentID, @UId = User_ID FROM User_Detail WITH (NOLOCK) WHERE User_ID =  @UserId;

		SELECT @SnapshotName = SnapshotName, @UserName = UserName, @NewModuleId = SnapshotModuleId , @ParentBy = convert(bigint, ParentBy ) FROM OPENJSON(@JsonSetting)
		WITH (
			SnapshotName NVARCHAR(255) '$.SnapshotName',
			UserName NVARCHAR(255) '$.UserName',
			SnapshotModuleId NVARCHAR(500) '$.ModuleId',
			ParentBy NVARCHAR(500) '$.ParentBy'
		);

		print @UserName
	   -- SET @Url = CONCAT(@Url, 'UserCRMCampain/SnapshotAdd.aspx?Query=', @Guid);
	   declare @agentId bigint;
	   select @agentId=Id from CreditAgent where UserName=@UserName
	   SELECT @Id = Id FROM tbl_snapshot WITH (NOLOCK) WHERE SnapshotName = @SnapshotName AND ParentId = @parentId;

		IF (@Id IS NULL)
		BEGIN
			SET @Guid = REPLACE(LOWER(NEWID()), '-', '');
			INSERT INTO tbl_snapshot (Guid, SnapshotName,ImpersonatorId, createdBy, ParentId, isActive,ParentBy)   
			VALUES (@Guid, @SnapshotName, @agentId,@UId, @parentId, 1,@UId);    
			SET @Id = SCOPE_IDENTITY();

			print 'activity start'
			-- ----- Activity Start -----

			-- Retrieve usernames for the given User_IDs
			SELECT @Act_UserName = User_login FROM User_Detail WITH (NOLOCK)  WHERE User_ID = @ParentBy;
			SELECT @PartnerUserName = User_login FROM User_Detail WITH (NOLOCK)  WHERE User_ID = @ParentBy;
			SELECT @ChildPartnerName = User_login FROM User_Detail WITH (NOLOCK)  WHERE User_ID = @UId;

			-- Construct Event Data JSON
			SET @EventData = '{"#username#":"' + @ChildPartnerName + '"}';

			-- Execute stored procedure for logging partner activity
			EXEC usp_pm_PartnerActivity 
				@ParentBy, 
				@ParentBy, 
				@UId, 
				'Partner Created Snapshot', 
				@EventData, 
				'tbl_snapshot', 
				@Id;

			-- ----- Activity End -----




		END
		ELSE
		BEGIN
			DELETE FROM tbl_snapshotMapping
			WHERE snapshotId = @Id;
		END;

		DECLARE @TempModuleMapping AS TABLE (  
			MappingId INT PRIMARY KEY IDENTITY(1, 1),  
			ModuleId NVARCHAR(255),  
			Snapshot_meta_data NVARCHAR(MAX), 
			IsProccessed BIT DEFAULT 0 
		);  

		INSERT INTO @TempModuleMapping (ModuleId, Snapshot_meta_data)  
		SELECT value, (SELECT ModuleId, TableName,DisplayName, RowJson 
					   FROM dbo.udf_Get_ModuleSettingJSON(@parentId, value) 
					   FOR JSON PATH)
		FROM STRING_SPLIT(@NewModuleId, ',');

		WHILE EXISTS (SELECT 1 FROM @TempModuleMapping WHERE IsProccessed = 0)  
		BEGIN  
			DECLARE @tempMapId INT = 0;  

			SELECT TOP 1 @tempMapId = MappingId 
			FROM @TempModuleMapping 
			WHERE IsProccessed = 0;

			INSERT INTO tbl_snapshotMapping (parentid, userId, snapshotId, moduleId, snapshot_meta_data)  
			SELECT @parentId, @UId, @Id, ModuleId, Snapshot_meta_data 
			FROM @TempModuleMapping  
			WHERE MappingId = @tempMapId;

			UPDATE @TempModuleMapping  
			SET IsProccessed = 1  
			WHERE MappingId = @tempMapId;


			print 'activity start'
			-- ----- Activity Start -----

			-- Retrieve usernames for the given User_IDs
			SELECT @Act_UserName = User_login FROM User_Detail WITH (NOLOCK)  WHERE User_ID = @ParentBy;
			SELECT @PartnerUserName = User_login FROM User_Detail WITH (NOLOCK)  WHERE User_ID = @UId;
			SELECT @ChildPartnerName = User_login FROM User_Detail WITH (NOLOCK)  WHERE User_ID = @ParentBy;

			-- Construct Event Data JSON
			SET @EventData = '{"#username#":"' + @ChildPartnerName + '"}';

			-- Execute stored procedure for logging partner activity
			EXEC usp_pm_PartnerActivity 
				@ParentBy, 
				@ParentBy, 
				@UId, 
				'Partner Created Snapshot', 
				@EventData, 
				'tbl_snapshot', 
				@Id;

			------- Activity End -----

		END;

	END TRY
	BEGIN CATCH
		DECLARE @ErrorMessage NVARCHAR(4000), @ErrorSeverity INT, @ErrorState INT;
		SELECT 
			@ErrorMessage = ERROR_MESSAGE(), 
			@ErrorSeverity = ERROR_SEVERITY(), 
			@ErrorState = ERROR_STATE();
			RAISERROR(@ErrorMessage, @ErrorSeverity, @ErrorState);
	END CATCH;

	select @Id as SnapId, @Guid as Guid;
END;



GO

