CREATE   PROCEDURE [dbo].[usp_SaveSnapshotImport](
@UserId BIGINT,
@SnapshotId BIGINT,
@JsonSetting NVARCHAR(MAX)
)
as
BEGIN
       --DECLARE @UserId BIGINT = 34594,
       --     @SnapshotId BIGINT = 20057,
       --     @JsonSetting NVARCHAR(MAX) = N'[{"moduleName":"Quotation settings","snapshot_meta_data":[{"ModuleId":6,"TableName":"MysmsInvoicing.dbo.Settings","DisplayName":"Quotation Setting","RowJson":[{"DisplayRowName":"AcceptationAction","id":30670,"parentid":32222,"key":"AcceptationAction","value":"CreateQuotationManually","section":"quotation","IsRowSelected":true},{"DisplayRowName":"AllowEdition","id":30671,"parentid":32222,"key":"AllowEdition","value":"False","section":"quotation","IsRowSelected":true},{"DisplayRowName":"Append","id":30672,"parentid":32222,"key":"Append","value":"<p>&nbsp;<img src=\"https://docs.kit19.com/31871/Invoice/Picture1_638501644129139480.jpg\" /></p>\n\n<p>&nbsp;</p>\n\n<p><strong>SOLAR PERGOLA: A suggestion by Divy</strong></p>\n\n<p>&nbsp;</p>\n\n<ul>\n\t<li>A pergola is an Iron/ wooden made garden feature traditionally used to provide a shaded walkway, passageway, or seating area in a garden.</li>\n\t<li>A solar panel pergola is essentially a pergola with solar panels on top. The structure is one of the best decoration ideas for your outdoor space and is something simple yet provides amazing benefits.</li>\n\t<li>A pergola is a specific outdoor structure type that includes two main parts &ndash; supporting columns and the roofing grid that includes beams and rafters.</li>\n\t<li>The roofing grid itself might be left open or closed, depending on the owner&#39;s preferences.</li>\n\t<li>The usual pergola shape is a square or a rectangular roof that&#39;s supported by a set of vertical posts. Pergola&#39;s roof can be either fully covered or partially covered, there&#39;s no limitation.</li>\n</ul>\n\n<p><img src=\"https://docs.kit19.com/31871/Invoice/dv-7_638485307414067032.png\" /></p>\n\n<table align=\"left\" border=\"1\" cellpadding=\"3\" cellspacing=\"0\">\n\t<thead>\n\t\t<tr>\n\t\t\t<td colspan=\"3\"><strong>Bill of Material:<br />\n\t\t\tTechnical Specifications: &nbsp;#dc_capacity# ON Grid Rooftop Solar PV System.</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>S.No.</strong></td>\n\t\t\t<td><strong>Item Description</strong></td>\n\t\t\t<td><strong>Specifications</strong></td>\n\t\t</tr>\n\t</thead>\n\t<tbody>\n\t\t<tr>\n\t\t\t<td><strong>1</strong></td>\n\t\t\t<td><strong>Solar Modules </strong>(24V, #module_wp#) x as per design<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;#module_type#<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;2*IEC Testing certificates to ensure extremely high reliability of&nbsp;&nbsp;PV Modules<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;IEC 61701/IS 61701, IEC61215/IS14286, IEC61730 Part-2, &amp; ISO9001andISO14001<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Renewsys / Rayzon / Pahal/ Adani / Vikram / Savitr Make or&nbsp;Any MNRE Approved Make as per availability.</td>\n\t\t\t<td><strong>#dc_capacity#</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>2</strong></td>\n\t\t\t<td><strong>String Inverters &ndash; #inverter_capacity# - set.</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;IP 66 protection class<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;98.2% Energy Efficiency<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Polycab / Sungrow / Deye / Sofar / Solis or equivalent Make</td>\n\t\t\t<td><strong>#inverter_capacity#</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>3</strong></td>\n\t\t\t<td><strong>Module Mounting Structure</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;#structure_type#<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Height&nbsp;#structure_height#&nbsp;mm<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Wind Speed with standup to150KM/Hr.</td>\n\t\t\t<td><strong>As per design</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>4</strong></td>\n\t\t\t<td><strong>Hardware:</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;For Modules fixing &ndash; SS304 M8 X 25mm.<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;For Structure fixing - MS HDD M12 X 35mm, 40mm</td>\n\t\t\t<td><strong>As per requirement</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>5</strong></td>\n\t\t\t<td><strong>Civil Work:</strong><br />\n\t\t\t&nbsp; &nbsp; &nbsp;&bull; &nbsp; &nbsp; Will do civil work for each leg with 300 X 300 X 240mm&nbsp;concrete blocks.</td>\n\t\t\t<td><strong>As per drawings</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>6</strong></td>\n\t\t\t<td><strong>Earthing &amp; Lighting Protection- As per CEIG guidelines</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Earth Electrodes are 50mm Dia. pipe with 1 Mtrs Length/ for Module, structure &amp; Inverters &amp; as per IS3043:1987.<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Lighting Arrestors. Lightning protection to be provided</td>\n\t\t\t<td><strong>As per design</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>7</strong></td>\n\t\t\t<td><strong>Cables &ndash; As per MNRE Guidelines</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;#dc_cable_size# Solar DC Cable Type - I with UV protection for DC Cabling &nbsp;<br />\n\t\t\t<strong>AC Cable:</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;From Inverter to ACDB: Copper flexible Cable<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;From ACDC to local Panel Board&nbsp;<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Max AC Cable #ac_cable_length#Mtrs &amp; DC Cable #dc_cable_length#Mtrs<br />\n\t\t\t<strong>Earth Cable:</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Earth Cable Max #earth_cable_length#Mtrs for earthing.<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Additional Cable each Meter Rs. 120/- extra Applicable.</td>\n\t\t\t<td><strong>As per design</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>8</strong></td>\n\t\t\t<td><strong>ACDB &amp; DCDB:</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;As per design Fuses and SPDs provided.</td>\n\t\t\t<td><strong>1 Set</strong></td>\n\t\t</tr>\n\t</tbody>\n</table>\n","section":"quotation","IsRowSelected":true},{"DisplayRowName":"ColorFont","id":30673,"parentid":32222,"key":"ColorFont","value":"#f7f726","section":"quotation","IsRowSelected":true},{"DisplayRowName":"ColorTheme","id":30674,"parentid":32222,"key":"ColorTheme","value":"#f31260","section":"quotation","IsRowSelected":true},{"DisplayRowName":"DigitalSignatoryNote","id":30675,"parentid":32222,"key":"DigitalSignatoryNote","value":"This is a computer generated PI no signature required.","section":"quotation","IsRowSelected":true},{"DisplayRowName":"FinancialYearFormat","id":30676,"parentid":32222,"key":"FinancialYearFormat","value":"YY-YY","section":"quotation","IsRowSelected":true},{"DisplayRowName":"Footer","id":30677,"parentid":32222,"key":"Footer","value":"<p>This is footer test</p>\n\n<p>hgfhfg</p>\n\n<p>&nbsp;</p>\n\n<p>vvbvb</p>\n","section":"quotation","IsRowSelected":true},{"DisplayRowName":"HideAmount","id":30678,"parentid":32222,"key":"HideAmount","value":"False","section":"quotation","IsRowSelected":true},{"DisplayRowName":"HideItemDescription","id":30679,"parentid":32222,"key":"HideItemDescription","value":"False","section":"quotation","IsRowSelected":true},{"DisplayRowName":"HideItemGrid","id":30680,"parentid":32222,"key":"HideItemGrid","value":"True","section":"quotation","IsRowSelected":true},{"DisplayRowName":"HideItemName","id":30681,"parentid":32222,"key":"HideItemName","value":"False","section":"quotation","IsRowSelected":true},{"DisplayRowName":"HidePrice","id":30682,"p