#dc_capacity# ON Grid Rooftop Solar PV System.</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>S.No.</strong></td>\n\t\t\t<td><strong>Item Description</strong></td>\n\t\t\t<td><strong>Specifications</strong></td>\n\t\t</tr>\n\t</thead>\n\t<tbody>\n\t\t<tr>\n\t\t\t<td><strong>1</strong></td>\n\t\t\t<td><strong>Solar Modules </strong>(24V, #module_wp#) x as per design<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;#module_type#<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;2*IEC Testing certificates to ensure extremely high reliability of&nbsp;&nbsp;PV Modules<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;IEC 61701/IS 61701, IEC61215/IS14286, IEC61730 Part-2, &amp; ISO9001andISO14001<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Renewsys / Rayzon / Pahal/ Adani / Vikram / Savitr Make or&nbsp;Any MNRE Approved Make as per availability.</td>\n\t\t\t<td><strong>#dc_capacity#</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>2</strong></td>\n\t\t\t<td><strong>String Inverters &ndash; #inverter_capacity# - set.</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;IP 66 protection class<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;98.2% Energy Efficiency<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Polycab / Sungrow / Deye / Sofar / Solis or equivalent Make</td>\n\t\t\t<td><strong>#inverter_capacity#</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>3</strong></td>\n\t\t\t<td><strong>Module Mounting Structure</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;#structure_type#<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Height&nbsp;#structure_height#&nbsp;mm<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Wind Speed with standup to150KM/Hr.</td>\n\t\t\t<td><strong>As per design</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>4</strong></td>\n\t\t\t<td><strong>Hardware:</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;For Modules fixing &ndash; SS304 M8 X 25mm.<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;For Structure fixing - MS HDD M12 X 35mm, 40mm</td>\n\t\t\t<td><strong>As per requirement</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>5</strong></td>\n\t\t\t<td><strong>Civil Work:</strong><br />\n\t\t\t&nbsp; &nbsp; &nbsp;&bull; &nbsp; &nbsp; Will do civil work for each leg with 300 X 300 X 240mm&nbsp;concrete blocks.</td>\n\t\t\t<td><strong>As per drawings</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>6</strong></td>\n\t\t\t<td><strong>Earthing &amp; Lighting Protection- As per CEIG guidelines</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Earth Electrodes are 50mm Dia. pipe with 1 Mtrs Length/ for Module, structure &amp; Inverters &amp; as per IS3043:1987.<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Lighting Arrestors. Lightning protection to be provided</td>\n\t\t\t<td><strong>As per design</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>7</strong></td>\n\t\t\t<td><strong>Cables &ndash; As per MNRE Guidelines</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;#dc_cable_size# Solar DC Cable Type - I with UV protection for DC Cabling &nbsp;<br />\n\t\t\t<strong>AC Cable:</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;From Inverter to ACDB: Copper flexible Cable<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;From ACDC to local Panel Board&nbsp;<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Max AC Cable #ac_cable_length#Mtrs &amp; DC Cable #dc_cable_length#Mtrs<br />\n\t\t\t<strong>Earth Cable:</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Earth Cable Max #earth_cable_length#Mtrs for earthing.<br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;Additional Cable each Meter Rs. 120/- extra Applicable.</td>\n\t\t\t<td><strong>As per design</strong></td>\n\t\t</tr>\n\t\t<tr>\n\t\t\t<td><strong>8</strong></td>\n\t\t\t<td><strong>ACDB &amp; DCDB:</strong><br />\n\t\t\t&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&bull; &nbsp;&nbsp;&nbsp;&nbsp;As per design Fuses and SPDs provided.</td>\n\t\t\t<td><strong>1 Set</strong></td>\n\t\t</tr>\n\t</tbody>\n</table>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<p><strong>(Note: No of goods transporting day approx 4 days )<br />\nWe are awaiting for your valuable Work Order to serve you our best.<br />\nThanks &amp; Regards,<br />\nYours faithfully,</strong></p>\n\n<p><strong>(Manoj Kumar)<br />\nFor APNA PACKERS &amp; MOVERS</strong></p>\n","section":"quotation","IsRowSelected":true},{"DisplayRowName":"PriceName","id":30709,"parentid":32222,"key":"PriceName","value":"Price","section":"quotation","IsRowSelected":true},{"DisplayRowName":"QuantityName","id":30710,"parentid":32222,"key":"QuantityName","value":"Quantity","section":"quotation","IsRowSelected":true},{"DisplayRowName":"QuotationAcceptation","id":30711,"parentid":32222,"key":"QuotationAcceptation","value":"True","section":"quotation","IsRowSelected":true},{"DisplayRowName":"QuotationTo","id":30712,"parentid":32222,"key":"QuotationTo","value":"CompanyName","section":"quotation","IsRowSelected":true},{"DisplayRowName":"SalesOwner","id":30713,"parentid":32222,"key":"SalesOwner","value":"True","section":"quotation","IsRowSelected":true},{"DisplayRowName":"SellerTag","id":30714,"parentid":32222,"key":"SellerTag","value":"Seller Tag Testing","section":"quotation","IsRowSelected":true},{"DisplayRowName":"Subheading","id":30715,"parentid":32222,"key":"Subheading","value":"test","section":"quotation","IsRowSelected":true},{"DisplayRowName":"TermCondition","id":30716,"parentid":32222,"key":"TermCondition","value":"<p>PRICE:<strong><span style=\"font-size:16px\"> The price quoted in this Proposal is inclusive of design, manufacturing, sourcing, testing</span></strong>, supply, installation &amp; commissioning, as per the bill of materials &amp; ratings submitted by DIVY POWER. Any change in scope of work or addition to the bill of materials and/or ratings or any variation, whatsoever, shall be charged extra to Customer.</p>\n\n<p>VALIDITY OF OFFER: The price quoted by DIVY Power along with this Proposal is valid for fifteen (15) days from such communication to customer and there after the same shall be subject to reconfirmation by DIVY Power Solar.<br />\nTAXES, DUTIES AND RATES: DIVY at its sole discretion shall have the liberty to raise invoices from any location in India. All the applicable taxes shall be payable by the Customer at actual.<br />\nINCLUSION OF EXCLUDED ITEMS: Any items &amp; Service not mentioned in the bill of material / in contract shall be charged extra and will be in the customer&rsquo;s account.</p>\n\n<p>ACCESS AND PERMITS: The customer shall ensure the accuracy of all information and/or data to be supplied by the customer and shall be responsible for acquiring and providing legal and physical possession of the site and access there to, for preparation and maintenance of proper access roads to, and provide the right of way for, the site, and for providing possession of and access to all other areas reasonably required for the proper execution of the construction work.<br />\nDELIVERY &amp; HANDOVER: DIVY Power shall complete the project in &nbsp;the given time as discussed from date acceptance of order by DIVY if work is not interrupted due to any changes/ demand/ delay of payment.<br />\nDEEMED EXPORT OF POWER: The Project shall be termed as commissioned when DIVY Power evacuates the power generated to Customer&rsquo;s grid.&nbsp;However, in case where DIVY Power has completed its duties as per the scope of duties mentioned in the Purchase Order, and the Project cannot be commissioned due to any act/inaction on the part of Customer, or due to unavailability of Customer grid, then the Project shall be deemed to be commissioned and DIVY Power shall be deemed to have completed its part of obligations under the Purchase Order.</p>\n\n<p>INTERRUPTIONS IN WORK: The Customer must not interrupt the work, and/or shall&nbsp;abstain from any act or permission of which it can reasonably be expected that it may&nbsp;delay the works or make the works more difficult and or expensive for DIVY Power, in&nbsp;such circumstances the effective amount for such delay or interruption or any demand&nbsp;to change will be in account of customer.</p>\n\n<p>WARRANTY: The solar power plant carries a FIVE (5) year warranty against any manufacturing defects on behalf of component manufacturer.&nbsp;&nbsp;Solar photovoltaic modules carry a performance warranty against excess of 20% degradation in TWENTY-FIVE (25) years as per existing warranty policy of manufacturer. For other equipment and batteries (if part of solution) duration will be as per OEM policy. Inverter warranty carries 5years.</p>\n\n<p>SECURITY &amp; SAFETY: On delivery of supplies to Customer&#39;s site in good condition, Customer shall be responsible for safety &amp; security of the materials till handing over of the same to DIVY Power designated personnel for installation. In case there are public disturbances at site which are not exclusively attributable to DIVY Power, Customer shall resolve the same at its own risk &amp; cost, for smooth execution of the project by DIVY Power.<br />\nSTRUCTURAL WORK:<br />\nRCC Roof-<br />\nNon- Puncture solution- The structure mounts on fabricated civil cubicles on roof, this is limited to a normal height structure parallel to parapet walls of the roof. Divy limits itself to work as per customers request &amp; assumed that customer has assessed the structure load bearing suitability of the designated roof. In any case any damage or leakage/ repair or anything are not exclusively attributable to DIVY POWER.<br />\nPuncture solution- The structure gets punctured in roof through anchor fasteners. DIVY deemed assume that customer has assessed the designated roof&rsquo;s stability and strength for the same. Divy limits itself to work as per customers request &amp; assumed that customer has assessed the structure load bearing suitability of the designated roof. In any case any damage or leakage/ repair or anything are not exclusively attributable to DIVY POWER.<br />\nTin Shed-<br />\nThe structure gets penetrated with rivets/ screw with metal roof, DIVY deemed assume that customer has assessed the designated roof&rsquo;s stability and strength for the same. Divy limits itself to work as per customers request &amp; assumed that customer has assessed the structure load bearing suitability of the designated roof. In any case any damage or leakage/ repair or anything are not exclusively attributable to DIVY POWER.<br />\nCivil Work-<br />\nDIVY always recommends execute/ supervising the civil work on RCC roof wherever it is needed through customer only to take care quality in all aspects. DIVY limits itself to work as per customers request &amp; assumed that customer has assessed the structure load bearing suitability of the designated roof. In any case any damage or leakage/ repair or anything are not exclusively attributable to DIVY POWER.<br />\nLIMITATION OF LIABILITY: Not with standing anything contained in this Proposal, its appendices, any offer, or order to the contrary, with respect to any and all claims arising out of the performance or non-performance of obligations under this Proposal or resultant agreement or purchase orders, whether arising in contract, tort, warranty, strict liability or otherwise, total liability of DIVY POWER shall not exceed beyond 2% of the total contract value received from Customer. Not with standing anything contained anywhere else in this proposal, or in the resultant Agreement, or anywhere else, in present or in future, in no event shall DIVY POWER be liable, whether in contract, tort or otherwise, to the Customer for special, indirect or consequential loss or damage (such as, not exclusively, loss of production, loss of reputation, loss of income, loss of profit,etc.)</p>\n\n<p>INDEMNIFICATION: Customer shall fully Indemnify and hold harmless DIVY Power and its&nbsp;affiliates, associates, directors and employees from and against, any and all losses, costs,&nbsp;damages, injuries, liabilities, claims and causes of action, including without limitation arising out&nbsp;of or resulting from claims by third parties, acts, omissions or breach of any of the Customer&#39;s&nbsp;affiliates, suppliers, employees, agents or contractors in the performance of Customer&#39;s&nbsp;obligations under this Proposal or any resultant Agreement or otherwise arising out of the solar&nbsp;power system or its usage.<br />\nINSURANCE: Customer shall cover insurance for transit and storage up to and at s ite. Else Divy can arrange&nbsp;an chargeable basis.<br />\nPUBLICITY RIGHTS: The Customer agrees and gives its irrevocable and unconditional consent to<br />\nDIVY POWER to issue any press release or announcement relating to this Proposal, or any&nbsp;resultant Agreement, or use the data, photographs, designs, etc. of the solar power plant for its&nbsp;publicity and/or marketing activities or use the same for publication anywhere. DIVY POWER&nbsp;understands and agrees that no such usage shall be in a manner defamatory to the Customer.&nbsp;ARBITRATION: Any dispute, including claims seeking redress or asserting rights under applicable&nbsp;law, shall, be resolved and finally settled in accordance with the provisions of the Arbitration and&nbsp;Conciliation Act, 1996, as may be amended from time to time or its re-enactment. The arbitral<br />\ntribunal shall be composed of two arbitrators to be appointed by each of the parties and the third&nbsp;arbitrator shall be appointed by the arbitrators appointed by the parties and for such arbitration,&nbsp;the seat of arbitration shall be in Ghaziabad, UP, India. All proceedings of arbitration shall be&nbsp;held in English.<br />\nGOVERNING LAW AND JURISDICTION: All questions concerning the construction, validity and&nbsp;interpretation of this Proposal or any resultant Agreement will be governed by the laws of India,&nbsp;and the courts at Ghaziabad, India shall have exclusive jurisdiction with respect to any dispute&nbsp;that occurs hereof. No remedy described in this Proposal, or any resultant Agreement shall in&nbsp;any way limit the parties&#39; remedies available at law, in equity or otherwise in relation to any&nbsp;breach or threatened breach of the terms and condition of the Proposal by any defaulting&nbsp;party, and any party may seek a restrictive injunction from an appropriate court of law to&nbsp;safeguard its interests.&nbsp;Together we can&nbsp;Assuring you best service always.&nbsp;Thanking you for providing us an opportunity&nbsp; On Behalf of&nbsp;Team Divy Power</p>\n","section":"quotation","IsRowSelected":true},{"DisplayRowName":"Title","id":30717,"parentid":32222,"key":"Title","value":"Your Quotation test","section":"quotation","IsRowSelected":true},{"DisplayRowName":"ValidTill","id":30718,"parentid":32222,"key":"ValidTill","value":30,"section":"quotation","IsRowSelected":true}],"SnapshotModuleRadio":"all","IsSnapshotModuleSelected":true}],"ModuleRadioValue":"all","IsModuleSelected":true}]';

    DECLARE @ParentId BIGINT;

    DROP TABLE IF EXISTS #TempSnapshotImport;
    CREATE TABLE #TempSnapshotImport (
        Id BIGINT IDENTITY(1,1),
        SnapshotId BIGINT,
        ModuleName NVARCHAR(255),
        SnapshotMetaData NVARCHAR(MAX)
    );

    DROP TABLE IF EXISTS #TempRowJson;
    CREATE TABLE #TempRowJson (
        ParentId BIGINT,
        Field_Id BIGINT,
		Section nvarchar(255),
		DisplayRowName nvarchar(500),
		[Key] nvarchar(255),
        IsActive BIT,
		FieldsName nvarchar(255)
    );

    SELECT @ParentId = ParentID FROM User_Detail WHERE user_id = @UserId;

    INSERT INTO #TempSnapshotImport (SnapshotId, ModuleName, SnapshotMetaData)
    SELECT 
        @SnapshotId, 
        JSON_VALUE(value, '$.moduleName') AS ModuleName,
        JSON_QUERY(value, '$.snapshot_meta_data') AS SnapshotMetaData
    FROM OPENJSON(@JsonSetting, '$');
BEGIN TRY
    BEGIN TRANSACTION
    IF (@SnapshotId > 0)
    BEGIN
        --DELETE FROM tbl_snapshotMapping WHERE snapshotId = @SnapshotId;

        DECLARE @TempModuleMapping TABLE (
            MappingId INT PRIMARY KEY IDENTITY(1, 1),  
            ModuleId NVARCHAR(255), 
            TableName NVARCHAR(255),
            Snapshot_meta_data NVARCHAR(MAX), 
            IsProcessed BIT DEFAULT 0 
        );

        INSERT INTO @TempModuleMapping (ModuleId, TableName, Snapshot_meta_data)
        SELECT 
            JSON_VALUE(SnapshotMetaData, '$[0].ModuleId') AS ModuleId,
            JSON_VALUE(SnapshotMetaData, '$[0].TableName') AS TableName,
            SnapshotMetaData
        FROM #TempSnapshotImport;

        WHILE EXISTS (SELECT 1 FROM @TempModuleMapping WHERE IsProcessed = 0)
        BEGIN
            DECLARE @tempMapId INT;
            DECLARE @TableName NVARCHAR(255);
            SELECT TOP 1 @tempMapId = MappingId FROM @TempModuleMapping WHERE IsProcessed = 0;
            SELECT @TableName = TableName FROM @TempModuleMapping WHERE MappingId = @tempMapId;

            --INSERT INTO tbl_snapshotMapping (parentid, userId, snapshotId, moduleId, snapshot_meta_data)  
            --SELECT @ParentId, @UserId, @SnapshotId, ModuleId, Snapshot_meta_data 
            --FROM @TempModuleMapping
            --WHERE MappingId = @tempMapId;

			IF (@TableName = 'MySMS.dbo.customfields')
			BEGIN
				
				print 'I'

				drop table if exists #tempCustomFields

				select field_ID, ParentID, fieldname, datatype, sequence, minvalue, maxvalue, addedon, isActive, isMandatory, 
					defaultValue, quickAdd, currentDate, tooltip, choices, formulaId, ParentFieldId, DependencyJson, ParamList, timetype into #tempCustomFields 
				from openjson((SELECT Snapshot_meta_data 
					FROM @TempModuleMapping  WHERE MappingId = @tempMapId), '$[0].RowJson'
				) with (
					field_ID bigint '$.field_ID',
					ParentID bigint '$.ParentID',
					fieldname varchar(50) '$.fieldname',
					datatype char(2) '$.datatype',
					sequence smallint '$.sequence',
					minvalue nvarchar(max) '$.minvalue',
					maxvalue nvarchar(max) '$.maxvalue',
					addedon datetime '$.addedon',
					isActive bit '$.isActive',
					isMandatory bit '$.isMandatory',
					defaultValue nvarchar(max) '$.defaultValue',
					quickAdd bit '$.quickAdd',
					currentDate bit '$.currentDate',
					tooltip nvarchar(500) '$.tooltip',
					choices nvarchar(max) '$.choices',
					formulaId bigint '$.formulaId',
					ParentFieldId bigint '$.ParentFieldId',
					DependencyJson nvarchar(max) '$.DependencyJson',
					ParamList nvarchar(1000) '$.ParamList',
					timetype varchar(2) '$.timetype'
				)

				alter table #tempCustomFields add insertedFieldId bigint
				
				delete ic  from #tempCustomFields ic 
					inner join MySMS.dbo.customfields(nolock) c
					on ic.fieldname = c.fieldname and c.ParentID = @ParentId
		
				drop table if exists #InsertedRecords
				create table #InsertedRecords ( 
					insertedId bigint,
					fieldname nvarchar(255)
				);

				INSERT INTO MySMS.dbo.customfields ( 
					ParentID, fieldname, datatype, sequence, minvalue, maxvalue, addedon, isActive, isMandatory, 
					defaultValue, quickAdd, currentDate, tooltip, choices, formulaId, ParentFieldId, DependencyJson, ParamList, timetype
				)
				OUTPUT inserted.field_ID as  insertedId, inserted.fieldname as fieldname into #InsertedRecords
				SELECT  @ParentId, fieldname, datatype, sequence, cast(minvalue as varchar(255)), cast(maxvalue as varchar(255)), getdate(), isActive, isMandatory, 
					cast(defaultValue as varchar(255)), quickAdd, isnull(currentDate, 0), tooltip, choices, formulaId, ParentFieldId, DependencyJson, ParamList, timetype
				FROM #tempCustomFields cf


				update u set
					u.ParentFieldId = i.insertedId 
				from #tempCustomFields c 
					inner join MySMS.dbo.customfields t on c.ParentFieldId = t.field_ID and c.ParentFieldId is not null
					inner join #InsertedRecords i on i.fieldname = t.fieldname
					inner join MySMS.dbo.customfields u on u.ParentFieldId = t.field_ID and u.ParentID = @ParentId
				where isnull(c.ParentFieldId, 0) > 0


			END

			IF (@TableName = 'MySMS.dbo.UserSourceSettings')
            BEGIN
                INSERT INTO #TempRowJson (ParentId, Field_Id, IsActive,FieldsName)
                SELECT 
                    JSON_VALUE(value, '$.UserID'),
                    JSON_VALUE(value, '$.SourceID'),
                    JSON_VALUE(value, '$.IsActive'),
					JSON_VALUE(value, '$.Name')
                FROM OPENJSON(JSON_QUERY((SELECT Snapshot_meta_data FROM @TempModuleMapping WHERE MappingId = @tempMapId), '$[0].RowJson'))
				
              insert into Mysms.dbo.UserSourceSettings(Name, userId,IsEditable,IsActive, createdDate,ModifiedBy,ModifiedDate)
			  SELECT Name, @ParentId,IsEditable,	tr.IsActive, GetDate(),@ParentId, getdate() from Mysms.dbo.UserSourceSettings(nolock) us
			  inner join #TempRowJson tr on us.SourceID=tr.Field_Id and tr.IsActive=1
			  where NOT EXISTS (
						SELECT 1 FROM Mysms.dbo.UserSourceSettings(nolock) existing
						WHERE existing.Name = tr.FieldsName
							AND existing.UserID = @ParentId
							AND existing.isActive = 1
					)
    
            END
			IF (@TableName = 'Mysms.dbo.UserMediumSettings')
            BEGIN
                INSERT INTO #TempRowJson (ParentId, Field_Id, IsActive,FieldsName)
                SELECT 
                    JSON_VALUE(value, '$.UserID'),
                    JSON_VALUE(value, '$.MediumID'),
                    JSON_VALUE(value, '$.IsActive'),
					JSON_VALUE(value, '$.Name')
                FROM OPENJSON(JSON_QUERY((SELECT Snapshot_meta_data FROM @TempModuleMapping WHERE MappingId = @tempMapId), '$[0].RowJson')) 
				
              insert into Mysms.dbo.UserMediumSettings(	Name, UserId,	IsEditable,	tr.IsActive, CreatedDate,ModifiedBy,ModifiedDate)
			  SELECT 	Name, @ParentId,	IsEditable,	tr.IsActive, GetDate(),@ParentId,GETDATE() from Mysms.dbo.UserMediumSettings(nolock) us
			  inner join #TempRowJson tr on us.MediumID=tr.Field_Id and tr.IsActive=1
			  where NOT EXISTS (
						SELECT 1 FROM Mysms.dbo.UserMediumSettings(nolock) existing
						WHERE existing.Name = tr.FieldsName
							AND existing.UserID = @ParentId
							AND existing.isActive = 1
					)
    
            END

			IF (@TableName = 'Mysms.dbo.UserCampaignSettings')
            BEGIN
                INSERT INTO #TempRowJson (ParentId, Field_Id, IsActive,FieldsName)
                SELECT 
                    JSON_VALUE(value, '$.UserID'),
                    JSON_VALUE(value, '$.CampaignID'),
                    JSON_VALUE(value, '$.IsActive'),
					JSON_VALUE(value, '$.Name')
                FROM OPENJSON(JSON_QUERY((SELECT Snapshot_meta_data FROM @TempModuleMapping WHERE MappingId = @tempMapId), '$[0].RowJson'))
				
              insert into Mysms.dbo.UserCampaignSettings(Name, UserId, IsEditable,tr.IsActive, CreatedDate	,UserCampaignMasterID, ModifiedBy, ModifiedDate )
			  SELECT  Name, @ParentId, IsEditable,tr.IsActive, Getdate(),	UserCampaignMasterID,@ParentId,Getdate() from Mysms.dbo.UserCampaignSettings(nolock) uc
			  inner join #TempRowJson tr on uc.CampaignID=tr.Field_Id and tr.IsActive=1
			  where NOT EXISTS (
						SELECT 1 FROM Mysms.dbo.UserCampaignSettings(nolock) existing
						WHERE existing.Name = tr.FieldsName
							AND existing.UserID = @ParentId
							AND existing.isActive = 1
					)
    
            END
			IF (@TableName = 'MysmsInvoicing.dbo.Settings')
				BEGIN
					DROP TABLE IF EXISTS #TempValue;
					CREATE TABLE #TempValue (
						ParentId INT,
						[Key] NVARCHAR(255),
						Section NVARCHAR(255),
						Value NVARCHAR(MAX)
					);

					-- Insert values into the temporary table
					INSERT INTO #TempValue (ParentId, [Key], Section, Value)
					SELECT 
						JSON_VALUE(value, '$.parentid') AS ParentId,
						JSON_VALUE(value, '$.key') AS [Key],
						JSON_VALUE(value, '$.section') AS Section,
						JSON_VALUE(value, '$.value') AS Value       
					FROM OPENJSON(JSON_QUERY((SELECT Snapshot_meta_data 
												FROM @TempModuleMapping 
												WHERE MappingId = @tempMapId), '$[0].RowJson'));

					DELETE tv FROM #TempValue tv 
					INNER JOIN MysmsInvoicing.dbo.Settings s ON tv.[Key] = s.[Key] AND s.Section = tv.Section 
						AND tv.ParentId = s.ParentId;

					--SELECT @parentId, [Key], Section, Value FROM #TempValue;

					INSERT INTO MysmsInvoicing.dbo.Settings (ParentId, [Key], Section, Value)
					SELECT ParentId, [Key], Section, Value
					FROM #TempValue;

				END

			
			
			IF (@TableName = 'Mysms.dbo.tbl_CallLogOutcomeMaster')
				BEGIN
					-- Populate temporary table
					INSERT INTO #TempRowJson (Field_Id, ParentId, FieldsName)
					SELECT 
						JSON_VALUE(value, '$.Id'),
						JSON_VALUE(value, '$.ParentId'),
						JSON_VALUE(value, '$.OutcomeName')
					FROM OPENJSON(
						JSON_QUERY(
							(SELECT Snapshot_meta_data FROM @TempModuleMapping WHERE MappingId = @tempMapId), 
							'$[0].RowJson'
						)
					)

					-- Insert new records into the target table if they don't already exist
					INSERT INTO Mysms.dbo.tbl_CallLogOutcomeMaster 
						(OutcomeName, ParentId, CreatedOn, CreatedBy, IsDeleted, Indent, Sequence)
					SELECT tr.FieldsName,  @ParentId,  GETDATE(),  @ParentId,  s.IsDeleted,  s.Indent,  s.Sequence
					FROM Mysms.dbo.tbl_CallLogOutcomeMaster(nolock) s
					INNER JOIN #TempRowJson tr  ON tr.ParentId = s.ParentId  AND tr.Field_Id = s.Id
					WHERE NOT EXISTS (
						SELECT 1 FROM Mysms.dbo.tbl_CallLogOutcomeMaster(nolock) existing
						WHERE existing.OutcomeName = tr.FieldsName
							AND existing.ParentId = @ParentId
							AND existing.IsDeleted = 0
					)
				END

			IF (@TableName = 'Mysms.dbo.TBL_ET_ExpenseHead')
			BEGIN
				-- Populate temporary table
				INSERT INTO #TempRowJson (ParentId, Field_Id, FieldsName, IsActive)
				SELECT 
					JSON_VALUE(value, '$.ParentId'),
					JSON_VALUE(value, '$.ExpenseHeadId'),
					JSON_VALUE(value, '$.ExpenseHeadName'),
					JSON_VALUE(value, '$.IsActive')
				FROM OPENJSON(
					JSON_QUERY(
						(SELECT Snapshot_meta_data FROM @TempModuleMapping WHERE MappingId = @tempMapId), 
						'$[0].RowJson'
					)
				)
				-- Insert new records into the target table if they don't already exist
				INSERT INTO Mysms.dbo.TBL_ET_ExpenseHead 
					(ExpenseHeadName, Description, ExpenseBasis, ClaimUnder, MaxCap, IconClass, 
					 IsFixedRate, IsSuccessMeeting, IsFailureMeeting, MeetingSuccessReimbursement, 
					 MeetingFailureDeduction, IsOnActual, IsAsPerClaim, IsRate, Rate, ClaimedTime, 
					 ClaimedPerDay, IsHomeToSite, IsSiteToHome, ParentId, CreatedDate, CreatedBy, 
					 UpdatedDate, UpdatedBy, IsActive)
				SELECT  tr.FieldsName, s.Description, s.ExpenseBasis, s.ClaimUnder, s.MaxCap, s.IconClass,  s.IsFixedRate, s.IsSuccessMeeting, s.IsFailureMeeting,  s.MeetingSuccessReimbursement, s.MeetingFailureDeduction, s.IsOnActual, s.IsAsPerClaim, s.IsRate, s.Rate, s.ClaimedTime, s.ClaimedPerDay, s.IsHomeToSite, s.IsSiteToHome, @ParentId, GETDATE(), @ParentId, s.UpdatedDate, s.UpdatedBy, tr.IsActive
				FROM Mysms.dbo.TBL_ET_ExpenseHead(nolock) s
				INNER JOIN #TempRowJson tr ON tr.ParentId = s.ParentId  AND tr.Field_Id = s.ExpenseHeadId AND tr.IsActive = 1
				WHERE NOT EXISTS (
					SELECT 1
					FROM Mysms.dbo.TBL_ET_ExpenseHead(nolock) existing
					WHERE existing.ExpenseHeadName = tr.FieldsName
						AND existing.ParentId = @ParentId
						AND existing.IsActive = 1 ) 
			END
			IF (@TableName = 'Mysms.dbo.TBL_ET_HolidayMaster')
            BEGIN
               INSERT INTO #TempRowJson (ParentId,Field_Id, IsActive,FieldsName)
                SELECT 
                    JSON_VALUE(value, '$.ParentId'),
					JSON_VALUE(value, '$.HolidayId'),
					 JSON_VALUE(value, '$.IsActive'),
					 JSON_VALUE(value, '$.HolidayName')
                FROM OPENJSON(JSON_QUERY((SELECT Snapshot_meta_data FROM @TempModuleMapping WHERE MappingId = @tempMapId), '$[0].RowJson'))

               insert into Mysms.dbo.TBL_ET_HolidayMaster(HolidayName, HolidayDate,ParentId, Color,	CreatedDate, CreatedBy, tr.IsActive)
			  SELECT HolidayName, HolidayDate,@ParentId, Color,	getdate(), @ParentId, tr.IsActive
				from Mysms.dbo.TBL_ET_HolidayMaster(nolock) s
			  inner join #TempRowJson tr on  tr.IsActive=1 and s.ParentId=tr.ParentId and tr.Field_Id=s.HolidayId
			  where NOT EXISTS (SELECT 1 
			  FROM Mysms.dbo.TBL_ET_HolidayMaster(nolock) existing 
			  WHERE existing.HolidayName = tr.FieldsName AND existing.ParentId = @ParentId AND existing.IsActive = 1 ) 
    
            END
			IF (@TableName = 'Mysms.dbo.TBL_ET_ShiftMaster')
            BEGIN
                INSERT INTO #TempRowJson (ParentId,Field_Id, IsActive, FieldsName)
                SELECT 
                    JSON_VALUE(value, '$.ParentId'),
                    JSON_VALUE(value, '$.ShiftId'),
					 JSON_VALUE(value, '$.IsActive'),
					 JSON_VALUE(value, '$.ShiftName')
                FROM OPENJSON(JSON_QUERY((SELECT Snapshot_meta_data FROM @TempModuleMapping WHERE MappingId = @tempMapId), '$[0].RowJson'))
               insert into Mysms.dbo.TBL_ET_ShiftMaster(ShiftName,	StartTime,	EndTime, ParentId, CreatedDate,	CreatedBy,IsActive )
			  SELECT ShiftName,	StartTime,	EndTime, @ParentId, getdate(),	@ParentId, tr.IsActive
			 from Mysms.dbo.TBL_ET_ShiftMaster(nolock) s
			  inner join #TempRowJson tr on  tr.IsActive=s.IsActive and tr.Field_Id=s.ShiftId
			 where NOT EXISTS (SELECT 1 
			  FROM Mysms.dbo.TBL_ET_ShiftMaster(nolock) existing 
			  WHERE existing.ShiftName = tr.FieldsName AND existing.ParentId = @ParentId AND existing.IsActive = 1 ) 
    
            END
			
			IF (@TableName = 'Mysms.dbo.UserQuickLinks')
            BEGIN
                INSERT INTO #TempRowJson (ParentId, Field_Id,FieldsName)
                SELECT 
                    JSON_VALUE(value, '$.ParentId'),
                    JSON_VALUE(value, '$.ID'),
					JSON_VALUE(value, '$.QuickLinkName')
					FROM OPENJSON(JSON_QUERY((SELECT Snapshot_meta_data FROM @TempModuleMapping WHERE MappingId = @tempMapId), '$[0].RowJson'))

              insert into Mysms.dbo.UserQuickLinks(PageID,	QuickLinkName,	Path,	UserID,	CreatedDate,	IconUrl, ParentID,	LinkOrder)
			  SELECT 	PageID,	QuickLinkName,	Path,	UserID,	getdate(),	IconUrl, @ParentID,	LinkOrder
				 from Mysms.dbo.UserQuickLinks(nolock) s
			  inner join #TempRowJson tr on  tr.ParentId=s.ParentID and s.ID=tr.Field_Id
			  where  NOT EXISTS (SELECT 1 
			  FROM Mysms.dbo.TBL_ET_ShiftMaster(nolock) existing 
			  WHERE existing.ShiftName = tr.FieldsName AND existing.ParentId = @ParentId ) 
    
    
            END
			


            UPDATE @TempModuleMapping  
            SET IsProcessed = 1  
            WHERE MappingId = @tempMapId;
        END;

    END;
	COMMIT TRANSACTION
END TRY
BEGIN CATCH
    ROLLBACK TRANSACTION          
     exec usp_InsertErrorInfo                   
END CATCH
	--select * from Mysms.dbo.UserSourceSettings where UserId=32222 and isActive=1 order by SourceId desc
END;



GO

