/* ============================================================
   Procedure: [dbo].[Usp_SaveTriggerCampaignRules]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_SaveTriggerCampaignRules]   
@ruleid bigint =0  
,@rulename nvarchar(500) =NULL  
,@fieldname nvarchar(500)=NULL  
,@operatortype nvarchar(500)=NULL  
,@value nvarchar(max)=NULL  
,@conditiontype nvarchar(20)=NULL  
,@triggercampid bigint=NULL  
,@userid bigint=NULL  
,@conditions nvarchar(max)=NULL  
,@mode nvarchar(20)  
As   
  
BEGIN  
 Declare @parentid bigint= (Select parentid from User_Detail where User_ID=@userid)  
 Declare @sequenceid bigint = (select count(1)+1 from triggeredcampaignrules where [triggeredcampaignid] = @triggercampid)  
 Declare @conditionid bigint,@eventid bigint,@existingTriggerCampId BIGINT
 
 select @eventid=eventid from triggeredcampaigns(nolock) where id=@triggercampid
  
IF @mode = 'save'  
    BEGIN  
        IF @ruleid > 0  
        BEGIN  
            SELECT @existingTriggerCampId = triggeredcampaignid FROM triggeredcampaignrules WHERE id = @ruleid  

            IF @existingTriggerCampId = @triggercampid  
            BEGIN  
                -- UPDATE existing rule  
                UPDATE triggeredcampaignrules  
                SET rulename = @rulename,  
                    conditiontype = @conditiontype  
                WHERE id = @ruleid  

                DELETE FROM triggeredcampaignruleconditions WHERE ruleid = @ruleid  

                INSERT INTO triggeredcampaignruleconditions (ruleid, isactive, isdeleted, fieldname, matchtype, valuematch)  
                SELECT @ruleid, 1, 0, fieldname, operatortype, value  
                FROM OPENJSON(@conditions)  
                WITH (  
                    fieldname VARCHAR(MAX),  
                    operatortype VARCHAR(MAX),  
                    value VARCHAR(MAX)  
                )  

                SELECT @conditionid = SCOPE_IDENTITY()  
                IF (@conditionid > 0)  
                BEGIN  
                    SELECT 'Rule Updated Successfully'  
                END  
                RETURN  
            END  
            ELSE  
            BEGIN  
                SET @ruleid = 0 
            END  
        END  

        -- INSERT new rule  
        IF @ruleid = 0  
        BEGIN  
            INSERT INTO triggeredcampaignrules (rulename, isactive, conditiontype, createdon, createdby, parentid, isdeleted, triggeredcampaignid, sequenceid, datematch)  
            VALUES (@rulename, 1, @conditiontype, GETDATE(), @userid, @parentid, 0, @triggercampid, @sequenceid, CASE WHEN @eventid IN (680,681) THEN 1 ELSE 0 END)  

            SELECT @ruleid = SCOPE_IDENTITY()  

            INSERT INTO triggeredcampaignruleconditions (ruleid, isactive, isdeleted, fieldname, matchtype, valuematch)  
            SELECT @ruleid, 1, 0, fieldname, operatortype, value  
            FROM OPENJSON(@conditions)  
            WITH (  
                fieldname VARCHAR(MAX),  
                operatortype VARCHAR(MAX),  
                value VARCHAR(MAX)  
            )  

            SELECT @conditionid = SCOPE_IDENTITY()  
            IF (@conditionid > 0)  
            BEGIN  
                SELECT 'Rule Saved Successfully'  
            END  
        END  
    END 
  
 ELSE IF @mode = 'select'  
 Begin  
    
  set @conditions=( Select  [fieldname], [matchtype], [valuematch] from triggeredcampaignruleconditions where ruleid=@ruleid for json auto)  
  Select id , [rulename], [isactive], [conditiontype], [triggeredcampaignid], [sequenceid], @conditions conditions from triggeredcampaignrules where id=@ruleid   
  
 END  
END   


GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveUnit]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveUnit (
	@UnitName NVARCHAR(100)
	,@UnitDisplay NVARCHAR(5)
	,@UnitDescription NVARCHAR(100)
	,@UserID BIGINT
	)
AS
BEGIN
	DECLARE @ParentID BIGINT = 0
		,@id BIGINT = 0

	SELECT @ParentID = ISNULL(ParentID, USER_ID)
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserID

	IF (
			NOT EXISTS (
				SELECT 1
				FROM unit(NOLOCK)
				WHERE unitname = @UnitName
					AND parentid = @ParentID
				)
			)
	BEGIN
		IF (
				NOT EXISTS (
					SELECT 1
					FROM unit(NOLOCK)
					WHERE unitdisplay = @UnitDisplay
						AND parentid = @ParentID
					)
				)
		BEGIN
			INSERT INTO unit (
				unitname
				,unitdisplay
				,description
				,parentid
				,createdby
				,createdon
				)
			VALUES (
				@UnitName
				,@UnitDisplay
				,@UnitDescription
				,@ParentID
				,@UserID
				,getdate()
				)

			SET @id = SCOPE_IDENTITY()

			SELECT 'Data Saved' AS msg
		END
		ELSE
		BEGIN
			SELECT 'Unit display name already exists' AS msg
		END
	END
	ELSE
	BEGIN
		SELECT 'Unit name already exists' AS msg
	END

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM unit(NOLOCK)
			WHERE ID = @id
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	IF @RowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
			,@Activity_type = 'Inst_Prdct_Unit'
			,@ActionType = 'I'
			,@RowJson = @rowJson
			,@Table_name = 'unit'
	END
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveUpdate_DsBoardMailSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_SaveUpdate_DsBoardMailSetting]            
(            
   @ID bigint          
  ,@DashboardType nvarchar(200)            
  ,@Sections nvarchar(500)            
  ,@DashboardID bigint            
  ,@ReportID nvarchar(max)            
  ,@DataDateRange nvarchar(100)            
  ,@SendAtPeriod nvarchar(50)          
  ,@SendAtTime nvarchar(50)            
  ,@UserCollections nvarchar(max)            
  ,@IsActive bit            
  ,@UserID bigint      
        
  ,@SendAtWhichDay nvarchar(50)      
  ,@EmailIDs nvarchar(max)      
  ,@Scope nvarchar(100)      
              
)            
as            
Begin            
              
    Declare @ParentID bigint = 0            
    select top 1  @ParentID = isnull(ParentID,USER_ID) from User_Detail(nolock) where User_ID = @UserID            
               
  if(@DashboardType = 'MainDashboard')                      
 Begin          
   if(@ID = 0)    
    Begin    
  if(not exists(select 1 from tbl_dsboardMailSetting(nolock) where ParentID = @ParentID and Sections = @Sections and DashboardType = @DashboardType and SendAtPeriod = @SendAtPeriod and SendAtTime = @SendAtTime and SendAtWhichDay = @SendAtWhichDay and UserCollections = @UserCollections and EmailIDs = @EmailIDs and Scope = @Scope))            
     Begin            
     insert into  tbl_dsboardMailSetting            
     (            
       [DashboardType]          
      ,[Sections]          
      ,[DashboardID]          
      ,[ReportID]          
      ,[DataDateRange]          
      ,[SendAtPeriod]          
      ,[SendAtTime]          
      ,[ParentID]          
      ,[UserCollections]          
      ,[IsActive]          
      ,[CreatedOn]          
      ,[ModifiedOn]          
      ,[CreatedBy]          
      ,[LastDeliveredAt]      
               
      ,SendAtWhichDay       
   ,EmailIDs      
   ,Scope       
 )            
   values            
    (            
      @DashboardType            
     ,@Sections            
     ,@DashboardID            
     ,@ReportID            
     ,@DataDateRange            
     ,@SendAtPeriod          
  ,@SendAtTime            
     ,@ParentID            
     ,@UserCollections            
     ,@IsActive            
  ,GETDATE()            
     ,getdate()            
     ,@UserID            
     ,null      
        
  ,@SendAtWhichDay       
  ,@EmailIDs      
  ,@Scope          
    )            
     select 'Data Saved' as MSG            
    End  -- end of main dashboard insert    
 Else     
   Begin    
      select 'Data Already Exists' as MSG         
   end    
   end -- end of @id =0             
  else if(@ID <> 0)    
   Begin              
   if(not exists(select 1 from tbl_dsboardMailSetting(nolock) where ParentID = @ParentID and Sections = @Sections and DashboardType = @DashboardType and SendAtPeriod = @SendAtPeriod and SendAtTime = @SendAtTime and SendAtWhichDay = @SendAtWhichDay and UserCollections = @UserCollections and EmailIDs = @EmailIDs and Scope = @Scope and ID <> @ID ))            
    Begin            
      update tbl_dsboardMailSetting            
       set  DashboardType = @DashboardType            
           ,Sections = @Sections            
           ,DashboardID = @DashboardID            
           ,ReportID = @ReportID            
           ,DataDateRange = @DataDateRange            
     ,SendAtPeriod  = @SendAtPeriod          
     ,SendAtTime = @SendAtTime            
     ,UserCollections = @UserCollections     
  ,EmailIDs = @EmailIDs    
  ,SendAtWhichDay = @SendAtWhichDay    
  ,Scope = @Scope             
     ,ModifiedOn  = GETDATE()            
     ,IsActive = @IsActive
	 ,LastDeliveredAt = null             
     where ID = @ID    
  -- where ParentID = @ParentID and DashboardType = @DashboardType and Sections = @Sections             
            
           select 'Data Saved' as MSG               
            
      End  -- end of main dashboard  update               
    End  -- end of main dashboard    
   else     
     Begin    
    select 'Data Already Exists' as MSG         
  end     
   End --end of @id <> 0             
       
  else if(@DashboardType = 'BIDashBoard')            
    Begin   
 if(@ID = 0)  
  Begin         
   if(not exists(select 1 from tbl_dsboardMailSetting(nolock) where ParentID = @ParentID and DashboardID = @DashboardID and ReportID = @ReportID and SendAtPeriod = @SendAtPeriod and SendAtTime = @SendAtTime and SendAtWhichDay = @SendAtWhichDay and UserCollections = @UserCollections and  EmailIDs = @EmailIDs and Scope = @Scope ))          
    Begin          
      insert into  tbl_dsboardMailSetting            
    (            
      [DashboardType]          
     ,[Sections]          
     ,[DashboardID]          
     ,[ReportID]          
     ,[DataDateRange]          
     ,[SendAtPeriod]          
     ,[SendAtTime]          
     ,[ParentID]          
     ,[UserCollections]          
     ,[IsActive]          
     ,[CreatedOn]          
     ,[ModifiedOn]          
     ,[CreatedBy]          
     ,[LastDeliveredAt]  
       
     ,SendAtWhichDay            
     ,EmailIDs  
     ,Scope   
     
   )            
     values            
   (            
     @DashboardType            
    ,@Sections            
    ,@DashboardID            
    ,@ReportID            
    ,@DataDateRange            
    ,@SendAtPeriod          
    ,@SendAtTime            
    ,@ParentID            
    ,@UserCollections            
    ,@IsActive            
    ,GETDATE()            
    ,getdate()            
    ,@UserID            
    ,null  
    ,@SendAtWhichDay            
    ,@EmailIDs  
    ,@Scope  
              
   )            
    select 'Data Saved' as MSG          
    End -- end of bi dashboard insert    
      else   
     Begin  
        select 'Data Already Exists' as MSG  
     end       
          
     end  
    else if(@ID <> 0)           
     Begin   
    if(not exists(select 1 from tbl_dsboardMailSetting(nolock) where ParentID = @ParentID and DashboardID = @DashboardID and ReportID = @ReportID and SendAtPeriod = @SendAtPeriod and SendAtTime = @SendAtTime and SendAtWhichDay = @SendAtWhichDay and UserCollections = @UserCollections and  EmailIDs = @EmailIDs and Scope = @Scope and ID <> @ID ))  
     begin         
     update tbl_dsboardMailSetting            
       set  DashboardType = @DashboardType            
        ,Sections = @Sections            
        ,DashboardID = @DashboardID            
        ,ReportID = @ReportID            
        ,DataDateRange = @DataDateRange            
        ,SendAtPeriod  = @SendAtPeriod          
        ,SendAtTime = @SendAtTime            
        ,UserCollections = @UserCollections             
        ,ModifiedOn  = GETDATE()            
        ,IsActive = @IsActive             
          
  ,SendAtWhichDay = @SendAtWhichDay  
  ,EmailIDs = @EmailIDs  
  ,Scope = @Scope 
  ,LastDeliveredAt = null 
  where ID = @ID  
  --where ParentID = @ParentID and DashboardID = @DashboardID and DashboardType = @DashboardType          
       select 'Data Saved' as MSG  
    end   
    else  
     Begin  
     select 'Data Already Exists' as MSG  
  end  
       
                
    end -- end of bi dashboard Update          
                
   End -- end of bi dashboard           
                    
End




GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveUpdateCallDetailsReportSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveUpdateCallDetailsReportSetting (
	@ID BIGINT
	,@DashboardType NVARCHAR(200)
	,@ReportName NVARCHAR(500)
	,@SendAtPeriod NVARCHAR(50)
	,@SendAtTime NVARCHAR(50)
	,@UserCollections NVARCHAR(max)
	,@IsActive BIT
	,@UserID BIGINT
	,@SendAtWhichDay NVARCHAR(50)
	,@EmailIDs NVARCHAR(max)
	,@Scope NVARCHAR(100)
	,@FieldValueJson NVARCHAR(max)
	,@FilterText NVARCHAR(max)
	)
AS
BEGIN
	/* This report save/update is only for Enquiry Report/lead Report/CallReportDashboard  */
	DECLARE @ParentID BIGINT = 0
		,@activity VARCHAR(MAX)
		,@action VARCHAR(1)

	SELECT TOP 1 @ParentID = isnull(ParentID, USER_ID)
	FROM User_Detail WITH (NOLOCK)
	WHERE User_ID = @UserID

	IF (@DashboardType = 'CallDetailReport')
	BEGIN
		IF (isnull(@ID, 0) = 0)
		BEGIN
			IF (
					NOT EXISTS (
						SELECT 1
						FROM tbl_dsboardMailSetting WITH (NOLOCK)
						WHERE ParentID = @ParentID
							AND DashboardType = @DashboardType
							AND ReportName = @ReportName
						)
					)
			BEGIN
				INSERT INTO tbl_dsboardMailSetting (
					[DashboardType]
					,[ReportName]
					,[SendAtPeriod]
					,[SendAtTime]
					,[ParentID]
					,[UserCollections]
					,[IsActive]
					,[CreatedOn]
					,[ModifiedOn]
					,[CreatedBy]
					,[LastDeliveredAt]
					,SendAtWhichDay
					,EmailIDs
					,Scope
					,FieldValueJson
					,FilterText
					)
				VALUES (
					@DashboardType
					,@ReportName
					,@SendAtPeriod
					,@SendAtTime
					,@ParentID
					,@UserCollections
					,@IsActive
					,GETDATE()
					,getdate()
					,@UserID
					,NULL
					,@SendAtWhichDay
					,@EmailIDs
					,@Scope
					,@FieldValueJson
					,@FilterText
					)

				SET @ID = SCOPE_IDENTITY()
				SET @action = 'I'
				SET @activity = 'Inst_Dsbrd_calldtls'

				SELECT 'Report Saved Successfully' AS MSG
			END
			ELSE
			BEGIN
				SELECT 'This Report Setting Already Exists' AS MSG
			END
		END
		ELSE IF (isnull(@ID, 0) > 0)
		BEGIN
			UPDATE tbl_dsboardMailSetting
			SET [SendAtPeriod] = @SendAtPeriod
				,[SendAtTime] = @SendAtTime
				,[UserCollections] = @UserCollections
				,[IsActive] = @IsActive
				,[ModifiedOn] = GETDATE()
				,SendAtWhichDay = @SendAtWhichDay
				,EmailIDs = @EmailIDs
				,Scope = @Scope
				,FieldValueJson = @FieldValueJson
				,FilterText = @FilterText
				,LastDeliveredAt = NULL
			WHERE ID = @ID

			SET @action = 'U'
			SET @activity = 'Updt_Dsbrd_calldtls'

			SELECT 'Report Updated Successfully' AS MSG
		END
	END

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM tbl_dsboardMailSetting WITH(NOLOCK)
			WHERE ID = @ID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	IF @RowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
			,@Activity_type = @activity
			,@ActionType = @action
			,@RowJson = @rowJson
			,@Table_name = 'tbl_dsboardMailSetting'
	END
END



GO

