CREATE   PROCEDURE dbo.Usp_SaveUpdateEnquiryColPDFPreference          
(            
    @PDFPreference_Id int = null          
   ,@PreferenceTitle nvarchar(500)            
   ,@PDFColData varchar(5000)            
   ,@UserID int           
)            
as            
Begin            
   declare @PDFPreferenceID bigint = 0            
  set @PDFPreferenceID = (select count(User_Id) from tbl_Enquiry_Col_PDF_Preference where User_Id = @UserID)                
           
  if(@PDFPreferenceID = 0)            
    Begin            
       insert into tbl_Enquiry_Col_PDF_Preference            
    (            
       [Preference_Title]            
      ,[PDFColData]            
      ,[User_Id]            
   ,[CreatedOn]           
      ,[IsActive]           
   ,[IsDeleted]          
                  
    )            
    values(            
       @PreferenceTitle            
      ,@PDFColData            
      ,@UserID            
      ,getdate()          
      ,1            
      ,0          
      )            
            
      set @PDFPreferenceID = SCOPE_IDENTITY();            
                          
     select 'Record Saved'             
            
        end            
   else            
     Begin            
         update tbl_Enquiry_Col_PDF_Preference            
       set Preference_Title = @PreferenceTitle,            
           PDFColData = @PDFColData            
           --User_Id = @UserID           
        where User_Id = @UserID           
     End            
End 


