/* ============================================================
   Procedure: [dbo].[Usp_SaveUpdateEnquiryLeadReportSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveUpdateEnquiryLeadReportSetting (  
 @ID BIGINT  
 ,@DashboardType NVARCHAR(200)  
 ,@ReportName NVARCHAR(500)  
 ,@SendAtPeriod NVARCHAR(50)  
 ,@SendAtTime NVARCHAR(50)  
 ,@UserCollections NVARCHAR(max)  
 ,@IsActive BIT  
 ,@UserID BIGINT  
 ,@SendAtWhichDay NVARCHAR(50)  
 ,@EmailIDs NVARCHAR(max)  
 ,@Scope NVARCHAR(100)  
 )  
AS  
BEGIN  
 /* This report save/update is only for Enquiry Report/lead Report/CallReportDashboard  */  
 DECLARE @ParentID BIGINT = 0  
  ,@activity VARCHAR(MAX)  
  ,@action VARCHAR(1)  
  
 SELECT TOP 1 @ParentID = isnull(ParentID, USER_ID)  
 FROM User_Detail WITH (NOLOCK)  
 WHERE User_ID = @UserID  
  
 IF (  
   @DashboardType = 'EnquiryReport'  
   OR @DashboardType = 'LeadReport'  
   OR @DashboardType = 'CallReportDashboard'  
   OR @DashboardType = 'FollowupReport'  
   OR @DashboardType = 'WhatsAppReport'  
   OR @DashboardType = 'UserActivityReport'  
   )  
 BEGIN  
  IF (isnull(@ID, 0) = 0)  
  BEGIN  
   IF (  
     NOT EXISTS (  
      SELECT 1  
      FROM tbl_dsboardMailSetting WITH (NOLOCK)  
      WHERE ParentID = @ParentID  
       AND DashboardType = @DashboardType  
       AND ReportName = @ReportName  
      )  
     )  
   BEGIN  
    INSERT INTO tbl_dsboardMailSetting (  
     [DashboardType]  
     ,[ReportName]  
     ,[SendAtPeriod]  
     ,[SendAtTime]  
     ,[ParentID]  
     ,[UserCollections]  
     ,[IsActive]  
     ,[CreatedOn]  
     ,[ModifiedOn]  
     ,[CreatedBy]  
     ,[LastDeliveredAt]  
     ,SendAtWhichDay  
     ,EmailIDs  
     ,Scope  
     )  
    VALUES (  
     @DashboardType  
     ,@ReportName  
     ,@SendAtPeriod  
     ,@SendAtTime  
     ,@ParentID  
     ,@UserCollections  
     ,@IsActive  
     ,GETDATE()  
     ,getdate()  
     ,@UserID  
     ,NULL  
     ,@SendAtWhichDay  
     ,@EmailIDs  
     ,@Scope  
     )  
  
    SET @ID = SCOPE_IDENTITY()  
    SET @activity = 'Inst_Dsbrd_'+@DashboardType  
    SET @action = 'I'  
  
    SELECT 'Report Saved Successfully' AS MSG  
   END  
   ELSE  
   BEGIN  
    SELECT 'This Report Setting Already Exists' AS MSG  
   END  
  END  
  ELSE IF (isnull(@ID, 0) > 0)  
  BEGIN  
   UPDATE tbl_dsboardMailSetting  
   SET [SendAtPeriod] = @SendAtPeriod  
    ,[SendAtTime] = @SendAtTime  
    ,[UserCollections] = @UserCollections  
    ,[IsActive] = @IsActive  
    ,[ModifiedOn] = GETDATE()  
    ,SendAtWhichDay = @SendAtWhichDay  
    ,EmailIDs = @EmailIDs  
    ,Scope = @Scope  
    ,LastDeliveredAt = NULL  
   WHERE ID = @ID  
  
   SET @activity = 'Updt_Dsbrd_'+@DashboardType  
   SET @action = 'U'  
  
   SELECT 'Report Updated Successfully' AS MSG  
  END  
 END  
  
 DECLARE @rowJson NVARCHAR(MAX) = (  
   SELECT *  
   FROM tbl_dsboardMailSetting WITH(NOLOCK)  
   WHERE ID = @ID  
   FOR JSON AUTO  
    ,INCLUDE_NULL_VALUES  
   )  
  
 IF @RowJson IS NOT NULL  
 BEGIN  
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID  
   ,@Activity_type = @activity  
   ,@ActionType = @action  
   ,@RowJson = @rowJson  
   ,@Table_name = 'tbl_dsboardMailSetting'  
 END  
END  


GO

