				--,[MobileNo]    
				--,[EmailID]    
				--,[DIDNo]    
				--,[IVRNo]    
				--,[Media]    
				--,[Title]    
				--,[Subject]    
				--,[Message]    
				,[TotalityMessage_JSON]
				,[CreatedOn]
				,[ModifiedOn]
				,Isactive
				,ParentID
				)
			VALUES (
				@ClientPageID
				--,@Logo    
				--,@ActionID    
				--,@CountryCode    
				--,@MobileNo    
				--,@EmailID    
				--,@DIDNo    
				--,@IVRNo    
				--,@Media    
				--,@Title    
				--,@Subject    
				--,@Message    
				,@TotalityMessage_JSON
				,GETDATE()
				,GETDATE()
				,@Isactive
				,@ParentID
				)


			SELECT 'Data Saved' AS MSG

			DECLARE @rowJson NVARCHAR(MAX) = (
					SELECT *
					FROM tbl_FloaterActionSettings WITH(NOLOCK)
					WHERE ClientPageID = @ClientPageID
					FOR JSON AUTO
						,INCLUDE_NULL_VALUES
					)

			EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ParentID
				,@Activity_type = 'Inst_Float_Sttng'
				,@ActionType = 'I'
				,@RowJson = @rowJson
				,@Table_name = 'tbl_FloaterActionSettings'
		END
		ELSE
		BEGIN
			UPDATE tbl_FloaterActionSettings
			SET
				--[Logo] = @Logo    
				--,[CountryCode] = @CountryCode    
				--,[MobileNo] = @MobileNo    
				--,[EmailID] = @EmailID    
				--,[DIDNo] = @DIDNo    
				--,[IVRNo] = @IVRNo    
				--,[Media] = @Media    
				--,[Title] = @Title    
				--,[Subject] = @Subject     
				--,[Message] = @Message    
				[TotalityMessage_JSON] = @TotalityMessage_JSON
				,[ModifiedOn] = GETDATE()
				,Isactive = @Isactive
				,ParentID = @ParentID
