			SELECT 'Data Saved' AS MSG

			SET @rowJson = (
					SELECT *
					FROM tbl_FloaterActionSettings WITH(NOLOCK)
					WHERE ClientPageID = @ClientPageID
					FOR JSON AUTO
						,INCLUDE_NULL_VALUES
					)

			EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ParentID
