				,@ActionType = 'U'
				,@RowJson = @rowJson
				,@Table_name = 'tbl_FloaterActionSettings'
		END
	END
	ELSE
	BEGIN
		SELECT 'Sorry! this client page name does not exist' AS MSG
	END
			--else    
